-- Quest 5 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5, 'frFR', 'Oh, un envoi de mon frère ? Splendide ! La fortune me sourit vraiment aujourd\'hui !') ON DUPLICATE KEY UPDATE CompletionText='Oh, un envoi de mon frère ? Splendide ! La fortune me sourit vraiment aujourd\'hui !';
-- Quest 7 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7, 'frFR', 'Comment se passe la chasse, $N ? As-tu trouvé et vaincu ces vermines ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe la chasse, $N ? As-tu trouvé et vaincu ces vermines ?';
-- Quest 9 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9, 'frFR', 'Ah, je vois que tu es de retour ! J\'espère que tu as travaillé d\'arrache-pied pour nettoyer ces champs de ces Veilleurs de Récolte. En as-tu tué vingt déjà ?') ON DUPLICATE KEY UPDATE CompletionText='Ah, je vois que tu es de retour ! J\'espère que tu as travaillé d\'arrache-pied pour nettoyer ces champs de ces Veilleurs de Récolte. En as-tu tué vingt déjà ?';
-- Quest 12 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12, 'frFR', 'Peut-être que je ne me suis pas assez clairement exprimé, serment. Pour prouver ta valeur en tant que serviteur de la Milice du Peuple et de la Lumière, tu dois abattre 15 Trappeurs de Defias et 15 Marchands de Defias, puis revenir me voir lorsque le travail sera fait.') ON DUPLICATE KEY UPDATE CompletionText='Peut-être que je ne me suis pas assez clairement exprimé, serment. Pour prouver ta valeur en tant que serviteur de la Milice du Peuple et de la Lumière, tu dois abattre 15 Trappeurs de Defias et 15 Marchands de Defias, puis revenir me voir lorsque le travail sera fait.';
-- Quest 13 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13, 'frFR', 'Nous n\'avons pas le temps de discuter, $N. Les Pillagistes de Defias privent le peuple de Westfall de la paix et de la prospérité qu\'ils méritent. Assure-toi qu\'au moins 15 Pillagistes de Defias et 15 Pilleurs de Defias ont été tués. Cela enverra un message clair que la corruption n\'est pas la bienvenue ici.') ON DUPLICATE KEY UPDATE CompletionText='Nous n\'avons pas le temps de discuter, $N. Les Pillagistes de Defias privent le peuple de Westfall de la paix et de la prospérité qu\'ils méritent. Assure-toi qu\'au moins 15 Pillagistes de Defias et 15 Pilleurs de Defias ont été tués. Cela enverra un message clair que la corruption n\'est pas la bienvenue ici.';
-- Quest 14 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14, 'frFR', '$N, ce n\'est pas le moment de bavarder. Si tu souhaites toujours te prouver à la Milice du Peuple, tu dois abattre les Defias dont je t\'ai parlé plus tôt. Reviens me voir lorsque tu auras accompli ton devoir.') ON DUPLICATE KEY UPDATE CompletionText='$N, ce n\'est pas le moment de bavarder. Si tu souhaites toujours te prouver à la Milice du Peuple, tu dois abattre les Defias dont je t\'ai parlé plus tôt. Reviens me voir lorsque tu auras accompli ton devoir.';
-- Quest 15 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (15, 'frFR', 'Es-tu allé aux mines ? Es-tu prêt à faire un rapport ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé aux mines ? Es-tu prêt à faire un rapport ?';
-- Quest 16 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (16, 'frFR', 'Le travail agricole est un travail qui assoiffe, et je cherche toujours de l\'eau de source rafraîchissante.$B$BSi tu en as, alors je suis prêt à faire un échange.') ON DUPLICATE KEY UPDATE CompletionText='Le travail agricole est un travail qui assoiffe, et je cherche toujours de l\'eau de source rafraîchissante.$B$BSi tu en as, alors je suis prêt à faire un échange.';
-- Quest 16 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (16, 'frFR', 'Merci, <name> !  Et reviens si tu veux échanger à nouveau.') ON DUPLICATE KEY UPDATE RewardText='Merci, <name> !  Et reviens si tu veux échanger à nouveau.';
-- Quest 21 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (21, 'frFR', 'Je sais que c\'est un travail sanglant, $N, mais c\'est vital pour la sécurité de Northshire. Es-tu prêt à faire un rapport ?') ON DUPLICATE KEY UPDATE CompletionText='Je sais que c\'est un travail sanglant, $N, mais c\'est vital pour la sécurité de Northshire. Es-tu prêt à faire un rapport ?';
-- Quest 22 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (22, 'frFR', 'Tout ce dont j\'ai besoin pour ma célèbre tarte à la viande, ce sont 8 Foies de Goretusk !') ON DUPLICATE KEY UPDATE CompletionText='Tout ce dont j\'ai besoin pour ma célèbre tarte à la viande, ce sont 8 Foies de Goretusk !';
-- Quest 22 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (22, 'frFR', 'C\'est parfait, <name> !  Merci beaucoup.  Farmer Saldean et moi allons dîner ce soir.  Et voici un petit quelque chose pour toi, pour le travail acharné.  Tu ne pensais pas que je te laisserais mourir de faim, un <class> comme toi, si ?') ON DUPLICATE KEY UPDATE RewardText='C\'est parfait, <name> !  Merci beaucoup.  Farmer Saldean et moi allons dîner ce soir.  Et voici un petit quelque chose pour toi, pour le travail acharné.  Tu ne pensais pas que je te laisserais mourir de faim, un <class> comme toi, si ?';
-- Quest 23 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (23, 'frFR', 'Ah - $N - je pensais juste à toi ! Comment se passe ta chasse ?') ON DUPLICATE KEY UPDATE CompletionText='Ah - $N - je pensais juste à toi ! Comment se passe ta chasse ?';
-- Quest 23 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (23, 'frFR', 'La patte d\'Ursangous !$B$BAs-tu une idée du problème que cette bête nous a causé au fil des ans ? Ces jours sont révolus, grâce à toi.$B$BI transmettra ce trophée à Orgrimmar pour être exposé, ainsi que ton récit de sa mort.$B$BChéliculations !') ON DUPLICATE KEY UPDATE RewardText='La patte d\'Ursangous !$B$BAs-tu une idée du problème que cette bête nous a causé au fil des ans ? Ces jours sont révolus, grâce à toi.$B$BI transmettra ce trophée à Orgrimmar pour être exposé, ainsi que ton récit de sa mort.$B$BChéliculations !';
-- Quest 24 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24, 'frFR', 'Salutations encore, $N ! Es-tu venu me montrer la preuve de ta chasse ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations encore, $N ! Es-tu venu me montrer la preuve de ta chasse ?';

-- Quest 25 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25, 'frFR', 'Tu es revenu déjà ? Quelle est la situation là-bas - tout est réglé maintenant, grâce à toi ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es revenu déjà ? Quelle est la situation là-bas - tout est réglé maintenant, grâce à toi ?';
-- Quest 26 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (26, 'frFR', 'Salutations, jeune $c; le temps est venu pour que vous connaissiez notre forme aquatique. C\'est une forme qui vous permet de vous déplacer librement et indéfiniment dans l\'eau. Vous trouverez cet aspect un outil utile et une bénédiction... mais c\'est un aspect qui doit être gagné avant d\'être maîtrisé.$B$BVous ferez face à deux épreuves à surmonter. La première testera votre capacité à travailler dans l\'eau sous pression. La seconde testera votre résolution à comprendre les aspects de la forme elle-même.$B$BPréparez-vous, car le temps de l\'épreuve est arrivé.') ON DUPLICATE KEY UPDATE RewardText='Salutations, jeune $c; le temps est venu pour que vous connaissiez notre forme aquatique. C\'est une forme qui vous permet de vous déplacer librement et indéfiniment dans l\'eau. Vous trouverez cet aspect un outil utile et une bénédiction... mais c\'est un aspect qui doit être gagné avant d\'être maîtrisé.$B$BVous ferez face à deux épreuves à surmonter. La première testera votre capacité à travailler dans l\'eau sous pression. La seconde testera votre résolution à comprendre les aspects de la forme elle-même.$B$BPréparez-vous, car le temps de l\'épreuve est arrivé.';
-- Quest 27 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (27, 'frFR', 'Salutations, jeune $C; le temps est venu pour que vous connaissiez notre forme aquatique. C\'est une forme qui vous permet de vous déplacer librement et indéfiniment dans l\'eau. Vous trouverez cet aspect un outil utile et une bénédiction... mais c\'est un aspect qui doit être gagné avant d\'être maîtrisé.$B$BVous ferez face à deux épreuves à surmonter. La première testera votre capacité à travailler dans l\'eau sous pression. La seconde testera votre résolution à comprendre les aspects de la forme elle-même.$B$BPréparez-vous, car le temps de l\'épreuve est arrivé.') ON DUPLICATE KEY UPDATE RewardText='Salutations, jeune $C; le temps est venu pour que vous connaissiez notre forme aquatique. C\'est une forme qui vous permet de vous déplacer librement et indéfiniment dans l\'eau. Vous trouverez cet aspect un outil utile et une bénédiction... mais c\'est un aspect qui doit être gagné avant d\'être maîtrisé.$B$BVous ferez face à deux épreuves à surmonter. La première testera votre capacité à travailler dans l\'eau sous pression. La seconde testera votre résolution à comprendre les aspects de la forme elle-même.$B$BPréparez-vous, car le temps de l\'épreuve est arrivé.';
-- Quest 28 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (28, 'frFR', 'Eh bien, il semble qu\'un autre $C ait réussi l\'Épreuve du Lac ! Bien joué, mon jeune ami - bien joué.$B$BComme je l\'ai dit, je m\'appelle Tajarri. C\'est mon devoir et mon privilège de servir de gardien pour Moonglade, et spécifiquement ce sanctuaire. Le Gardien Remulos guide le Cercle de Cenarion dans la préservation de la nature et de l\'équilibre, et son sanctuaire est un hommage durable à cela. En utilisant la bague ici, cela sert d\'hommage à l\'importance de cet endroit au sein du Cercle.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, il semble qu\'un autre $C ait réussi l\'Épreuve du Lac ! Bien joué, mon jeune ami - bien joué.$B$BComme je l\'ai dit, je m\'appelle Tajarri. C\'est mon devoir et mon privilège de servir de gardien pour Moonglade, et spécifiquement ce sanctuaire. Le Gardien Remulos guide le Cercle de Cenarion dans la préservation de la nature et de l\'équilibre, et son sanctuaire est un hommage durable à cela. En utilisant la bague ici, cela sert d\'hommage à l\'importance de cet endroit au sein du Cercle.';
-- Quest 29 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (29, 'frFR', 'Eh bien, il semble qu\'un autre $C ait réussi l\'Épreuve du Lac ! Bien joué, mon jeune ami - bien joué.$B$BComme je l\'ai dit, je m\'appelle Tajarri. C\'est mon devoir et mon privilège de servir de gardien pour Moonglade, et spécifiquement ce sanctuaire. Le Gardien Remulos guide le Cercle de Cenarion dans la préservation de la nature et de l\'équilibre, et son sanctuaire est un hommage durable à cela. En utilisant la bague ici, cela sert d\'hommage à l\'importance de cet endroit au sein du Cercle.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, il semble qu\'un autre $C ait réussi l\'Épreuve du Lac ! Bien joué, mon jeune ami - bien joué.$B$BComme je l\'ai dit, je m\'appelle Tajarri. C\'est mon devoir et mon privilège de servir de gardien pour Moonglade, et spécifiquement ce sanctuaire. Le Gardien Remulos guide le Cercle de Cenarion dans la préservation de la nature et de l\'équilibre, et son sanctuaire est un hommage durable à cela. En utilisant la bague ici, cela sert d\'hommage à l\'importance de cet endroit au sein du Cercle.';
-- Quest 30 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (30, 'frFR', 'Avez-vous formé votre pendentif pour que je l\'inspecte, $N? Si vous avez besoin d\'aide pour trouver les pièces, essayez de demander des informations à la population locale. Non seulement vous trouverez ce que vous cherchez, mais cela vous donnera une raison d\'explorer cette glade merveilleuse et sacrée.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous formé votre pendentif pour que je l\'inspecte, $N? Si vous avez besoin d\'aide pour trouver les pièces, essayez de demander des informations à la population locale. Non seulement vous trouverez ce que vous cherchez, mais cela vous donnera une raison d\'explorer cette glade merveilleuse et sacrée.';
-- Quest 30 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (30, 'frFR', 'Vous avez terminé l\'Épreuve du Lion de Mer, $N - félicitations.$B$Chaque tâche dans l\'acquisition du pendentif montre que l\'agilité et l\'endurance sont nécessaires pour agir en harmonie avec ce que vous souhaitez faire sous l\'eau.  Aucune ne peut exister sans l\'autre, et les deux ne peuvent être faites sans votre volonté d\'embrasser l\'aspect du lion de mer.$B$BSouvenez-vous bien de ces leçons, et comptez sur elles une fois que vous aurez acquis votre forme aquatique.') ON DUPLICATE KEY UPDATE RewardText='Vous avez terminé l\'Épreuve du Lion de Mer, $N - félicitations.$B$Chaque tâche dans l\'acquisition du pendentif montre que l\'agilité et l\'endurance sont nécessaires pour agir en harmonie avec ce que vous souhaitez faire sous l\'eau.  Aucune ne peut exister sans l\'autre, et les deux ne peuvent être faites sans votre volonté d\'embrasser l\'aspect du lion de mer.$B$BSouvenez-vous bien de ces leçons, et comptez sur elles une fois que vous aurez acquis votre forme aquatique.';
-- Quest 31 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (31, 'frFR', 'Votre retour à Thunder Bluff n\'est pas sans annonce, bien que j\'aie besoin de preuves de vos leçons apprises à Moonglade avant de vous enseigner votre forme aquatique.$B$BAvez-vous le Pendentif du Lion de Mer ?') ON DUPLICATE KEY UPDATE CompletionText='Votre retour à Thunder Bluff n\'est pas sans annonce, bien que j\'aie besoin de preuves de vos leçons apprises à Moonglade avant de vous enseigner votre forme aquatique.$B$BAvez-vous le Pendentif du Lion de Mer ?';
-- Quest 31 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (31, 'frFR', 'Très impressionnant, $N. Vos ancêtres seraient fiers de votre progression ! Vous êtes prêt à apprendre votre forme aquatique, et c\'est un plaisir de vous l\'enseigner.$B$BDe plus, en reconnaissance de votre réussite lors des deux épreuves, je vous donne cet objet. J\'espère que vous le trouverez un ajout bienvenu à votre équipement en tant que protecteur de la nature et gardien de l\'équilibre.') ON DUPLICATE KEY UPDATE RewardText='Très impressionnant, $N. Vos ancêtres seraient fiers de votre progression ! Vous êtes prêt à apprendre votre forme aquatique, et c\'est un plaisir de vous l\'enseigner.$B$BDe plus, en reconnaissance de votre réussite lors des deux épreuves, je vous donne cet objet. J\'espère que vous le trouverez un ajout bienvenu à votre équipement en tant que protecteur de la nature et gardien de l\'équilibre.';
-- Quest 32 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (32, 'frFR', 'Je suis désolé. Je ne vous connais pas... mais à en juger par ce que vous avez entendu de moi. Maintenant, comment puis-je vous aider ? Avez-vous quelque chose pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Je suis désolé. Je ne vous connais pas... mais à en juger par ce que vous avez entendu de moi. Maintenant, comment puis-je vous aider ? Avez-vous quelque chose pour moi ?';
-- Quest 32 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (32, 'frFR', 'Ce rapport... J\'ai déjà traité avec ces bêtes. Fizzledowser a eu la sagesse de l\'envoyer. et vous, à moi.$b$bCes créatures consommeront le désert de Tanaris rapidement ; elles ne sont rien de moins qu\'une des plus grandes menaces que nous affronterons tous. Familiarisez-vous avec ce nom, $N: silithid. Les insectes mentionnés ici sont les silithid, et ils sont les outils de l\'une des plus grandes menaces auxquelles la Horde et l\'Alliance font face.$b$bSi seulement nous étions assez intelligents pour le voir avant.') ON DUPLICATE KEY UPDATE RewardText='Ce rapport... J\'ai déjà traité avec ces bêtes. Fizzledowser a eu la sagesse de l\'envoyer. et vous, à moi.$b$bCes créatures consommeront le désert de Tanaris rapidement ; elles ne sont rien de moins qu\'une des plus grandes menaces que nous affronterons tous. Familiarisez-vous avec ce nom, $N: silithid. Les insectes mentionnés ici sont les silithid, et ils sont les outils de l\'une des plus grandes menaces auxquelles la Horde et l\'Alliance font face.$b$bSi seulement nous étions assez intelligents pour le voir avant.';
-- Quest 48 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (48, 'frFR', 'Hoho ! Vous voulez un encore ?$B$BDans la terre au sud où les vignes se tordent et rampent$BLie un puits caché où l\'eau coule profond$BPure comme la Fille sacrée de la Lumière$BBapportez-moi maintenant de l\'Eau de Source Sainte.') ON DUPLICATE KEY UPDATE CompletionText='Hoho ! Vous voulez un encore ?$B$BDans la terre au sud où les vignes se tordent et rampent$BLie un puits caché où l\'eau coule profond$BPure comme la Fille sacrée de la Lumière$BBapportez-moi maintenant de l\'Eau de Source Sainte.';
-- Quest 49 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (49, 'frFR', 'Un encore ? Eh bien, bien sûr !$B$BL\'ambre est la teinte de l\'amour le plus long de ma vie$BL\'est comme les dernières braises du crépuscule dans le ciel au-dessus$BRetirez-moi afin que mon amour puisse naître$BUn sac de chaque : orge, seigle et maïs.') ON DUPLICATE KEY UPDATE CompletionText='Un encore ? Eh bien, bien sûr !$B$BL\'ambre est la teinte de l\'amour le plus long de ma vie$BL\'est comme les dernières braises du crépuscule dans le ciel au-dessus$BRetirez-moi afin que mon amour puisse naître$BUn sac de chaque : orge, seigle et maïs.';
-- Quest 50 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (50, 'frFR', 'Un encore pour vous ? Eh bien, bien sûr, ami !$B$BJe vais mélanger et mélanger jusqu\'à ce que nous ayons une bouillie$BCeci sera notre cachette privée$BAu moins qu\'il doive être fait de métal solide$BBringez-moi du Truesilver afin que je puisse finir cette chanson.') ON DUPLICATE KEY UPDATE CompletionText='Un encore pour vous ? Eh bien, bien sûr, ami !$B$BJe vais mélanger et mélanger jusqu\'à ce que nous ayons une bouillie$BCeci sera notre cachette privée$BAu moins qu\'il doive être fait de métal solide$BBringez-moi du Truesilver afin que je puisse finir cette chanson.';
-- Quest 51 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (51, 'frFR', 'Un encore ? Pourquoi pas, pour vous, n\'importe quoi !$B$BPas encore filtré mais fraîchement distillé$BL\'est comme une terre non semée attendant d\'être labourée.$BEnsuite, je fabriquerai notre tas de charbon$BDéliver une branche de sycomore, c\'est votre prochain objectif.') ON DUPLICATE KEY UPDATE CompletionText='Un encore ? Pourquoi pas, pour vous, n\'importe quoi !$B$BPas encore filtré mais fraîchement distillé$BL\'est comme une terre non semée attendant d\'être labourée.$BEnsuite, je fabriquerai notre tas de charbon$BDéliver une branche de sycomore, c\'est votre prochain objectif.';

-- Quest 52 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (52, 'frFR', 'As-tu tué ces loups et ces ours ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu tué ces loups et ces ours ?';
-- Quest 53 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (53, 'frFR', 'Bien sûr, je vais le chanter à nouveau pour toi, ami !$B$Un liquide mélodieux clair comme les larmes d\'un bébé$BDevient un ambre profond et charmant au fil des ans$BMais avant de passer à l\'acte jusqu\'au bout$Bil faut construire un fût de chêne carbonisé.') ON DUPLICATE KEY UPDATE CompletionText='Bien sûr, je vais le chanter à nouveau pour toi, ami !$B$Un liquide mélodieux clair comme les larmes d\'un bébé$BDevient un ambre profond et charmant au fil des ans$BMais avant de passer à l\'acte jusqu\'au bout$Bil faut construire un fût de chêne carbonisé.';
-- Quest 53 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (53, 'frFR', 'Vieilli dans le fût, filtré à travers le charbon$BIl passe par tes lèvres et droit à travers ton âme.$BAlors buvons maintenant, un toast à toi$BEt moi aussi, Grimbooze Thunderbrew !') ON DUPLICATE KEY UPDATE RewardText='Vieilli dans le fût, filtré à travers le charbon$BIl passe par tes lèvres et droit à travers ton âme.$BAlors buvons maintenant, un toast à toi$BEt moi aussi, Grimbooze Thunderbrew !';
-- Quest 56 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (56, 'frFR', 'As-tu tué ces guerriers et ces mages ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu tué ces guerriers et ces mages ?';
-- Quest 57 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (57, 'frFR', 'Reviens-moi une fois que tu as tué 15 Fiends Squelettiques et 15 Horreurs Squelettiques, $N.') ON DUPLICATE KEY UPDATE CompletionText='Reviens-moi une fois que tu as tué 15 Fiends Squelettiques et 15 Horreurs Squelettiques, $N.';
-- Quest 58 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (58, 'frFR', 'J\'ai besoin de ton aide, $N. Va au cimetière au nord-ouest et débarrasse le mausolée oriental de 20 Propulseurs de Plaie.$B$BReviens-moi quand ta tâche sera accomplie.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai besoin de ton aide, $N. Va au cimetière au nord-ouest et débarrasse le mausolée oriental de 20 Propulseurs de Plaie.$B$BReviens-moi quand ta tâche sera accomplie.';
-- Quest 62 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (62, 'frFR', 'Qu\'as-tu à me rapporter, $N? Es-tu allé à la Mine de Fargodeep ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'as-tu à me rapporter, $N? Es-tu allé à la Mine de Fargodeep ?';
-- Quest 63 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (63, 'frFR', 'Le brasero reflète toujours la lumière ambiante de la zone, et la flamme bouge légèrement lorsque tu t\'approches.$B$BLa corruption le long des collines semble s\'être tenue à distance, et en plus des composants manquants, le brasero semble préparé pour le rituel afin d\'invoquer une manifestation purifiée d\'eau.') ON DUPLICATE KEY UPDATE CompletionText='Le brasero reflète toujours la lumière ambiante de la zone, et la flamme bouge légèrement lorsque tu t\'approches.$B$BLa corruption le long des collines semble s\'être tenue à distance, et en plus des composants manquants, le brasero semble préparé pour le rituel afin d\'invoquer une manifestation purifiée d\'eau.';
-- Quest 63 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (63, 'frFR', 'Tu places les bracers sur le brasero puis tu verses les dernières gouttes de la potion de Brine dans la flamme. Les gouttes crépitent en touchant la flamme et tu commences à incanter les simples mots qu\'Islen t\'a appris....') ON DUPLICATE KEY UPDATE RewardText='Tu places les bracers sur le brasero puis tu verses les dernières gouttes de la potion de Brine dans la flamme. Les gouttes crépitent en touchant la flamme et tu commences à incanter les simples mots qu\'Islen t\'a appris....';
-- Quest 75 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (75, 'frFR', 'As-tu trouvé la page que j\'ai mentionnée, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé la page que j\'ai mentionnée, $N?';
-- Quest 76 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (76, 'frFR', 'Salut, $N. Qu\'as-tu à me rapporter ? As-tu exploré la Mine de Jasperlode ?') ON DUPLICATE KEY UPDATE CompletionText='Salut, $N. Qu\'as-tu à me rapporter ? As-tu exploré la Mine de Jasperlode ?';
-- Quest 80 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (80, 'frFR', 'De retour, $N? Qu\'as-tu cette fois ?') ON DUPLICATE KEY UPDATE CompletionText='De retour, $N? Qu\'as-tu cette fois ?';
-- Quest 80 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (80, 'frFR', 'Oui !  L\'écriture sur cette page correspond en effet à celle des signatures du registre.') ON DUPLICATE KEY UPDATE RewardText='Oui !  L\'écriture sur cette page correspond en effet à celle des signatures du registre.';
-- Quest 84 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (84, 'frFR', 'Ugh... Je meurs de faim ! As-tu cette tarte pour moi, $N?') ON DUPLICATE KEY UPDATE CompletionText='Ugh... Je meurs de faim ! As-tu cette tarte pour moi, $N?';
-- Quest 96 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (96, 'frFR', 'Tu es revenu. Splendide !$B$BComment s\'est passé ton voyage à Silverpine ? Est-ce que ça t\'a pris longtemps?$B$BIl m\'est difficile de dire si tu as réussi là-bas parce qu\'une grande partie du territoire est devenue corrompue. Son odeur submerge tout bien que tu aurais pu faire. Mais les petites réussites sont parfois aussi importantes que les grandes. La purification de l\'eau là-bas a été essentielle pour toi, et pour tous les chamans.') ON DUPLICATE KEY UPDATE CompletionText='Tu es revenu. Splendide !$B$BComment s\'est passé ton voyage à Silverpine ? Est-ce que ça t\'a pris longtemps?$B$BIl m\'est difficile de dire si tu as réussi là-bas parce qu\'une grande partie du territoire est devenue corrompue. Son odeur submerge tout bien que tu aurais pu faire. Mais les petites réussites sont parfois aussi importantes que les grandes. La purification de l\'eau là-bas a été essentielle pour toi, et pour tous les chamans.';

-- Quest 96 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (96, 'frFR', 'Voici la preuve que j\'ai demandée. Tu as bien fait, $N.$B$BI suis ravi d\'être le premier à te féliciter et à te donner ceci... ton totem d\'eau.$B$BUse-le bien, et bonne chance.$B$BTon prochain test n\'aura pas lieu avant un certain temps, alors apprends bien tes leçons. L\'eau pure ne donnera pas seulement la vie à ceux qui sont blessés, mais peut avoir de nombreux autres effets. Je te suggère de chercher un maître chaman quand tu auras le temps. Ils pourraient avoir d\'autres sorts pour toi à apprendre.') ON DUPLICATE KEY UPDATE RewardText='Voici la preuve que j\'ai demandée. Tu as bien fait, $N.$B$BI suis ravi d\'être le premier à te féliciter et à te donner ceci... ton totem d\'eau.$B$BUse-le bien, et bonne chance.$B$BTon prochain test n\'aura pas lieu avant un certain temps, alors apprends bien tes leçons. L\'eau pure ne donnera pas seulement la vie à ceux qui sont blessés, mais peut avoir de nombreux autres effets. Je te suggère de chercher un maître chaman quand tu auras le temps. Ils pourraient avoir d\'autres sorts pour toi à apprendre.';
-- Quest 98 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (98, 'frFR', 'Je sais, <name>: Stalvan est mort.  J\'ai senti une vague d\'espoir se propager à travers la forêt souillée.  Une fois pour toutes, Duskwood est libre de sa soif de sang.  Ma joie est entravée par les pensées de ceux qui sont tombés aux mains de la horrible bête.  Néanmoins, tu es un <class> brave et rusé.') ON DUPLICATE KEY UPDATE RewardText='Je sais, <name>: Stalvan est mort.  J\'ai senti une vague d\'espoir se propager à travers la forêt souillée.  Une fois pour toutes, Duskwood est libre de sa soif de sang.  Ma joie est entravée par les pensées de ceux qui sont tombés aux mains de la horrible bête.  Néanmoins, tu es un <class> brave et rusé.';
-- Quest 99 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (99, 'frFR', 'As-tu sécurisé les Menottes de Pyrewood, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu sécurisé les Menottes de Pyrewood, $N?';
-- Quest 100 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (100, 'frFR', 'Grâce à toi. Grâce aux shamans.$B$BLa corruption se retire mais la vie continue de décliner. C\'est aux shamans de protéger la vie.') ON DUPLICATE KEY UPDATE RewardText='Grâce à toi. Grâce aux shamans.$B$BLa corruption se retire mais la vie continue de décliner. C\'est aux shamans de protéger la vie.';
-- Quest 103 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (103, 'frFR', 'La flamme ne durera pas longtemps sans huile, $N.') ON DUPLICATE KEY UPDATE CompletionText='La flamme ne durera pas longtemps sans huile, $N.';
-- Quest 103 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (103, 'frFR', 'Je te loue, <class> brave.  Les rochers de la Côte de Westfall seront illuminés grâce à ton travail acharné.  De nombreuses vies seront épargnées tant que la torche restera allumée.$B$BI est mort inutilement sur cette même rive.  Mon destin dans l\'au-delà est de voir que personne d\'autre ne suivra ma destinée.') ON DUPLICATE KEY UPDATE RewardText='Je te loue, <class> brave.  Les rochers de la Côte de Westfall seront illuminés grâce à ton travail acharné.  De nombreuses vies seront épargnées tant que la torche restera allumée.$B$BI est mort inutilement sur cette même rive.  Mon destin dans l\'au-delà est de voir que personne d\'autre ne suivra ma destinée.';
-- Quest 111 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (111, 'frFR', 'J\'ai hâte d\'entendre comment mes amis vont réagir!$B$BIls ne s\'y attendront jamais') ON DUPLICATE KEY UPDATE CompletionText='J\'ai hâte d\'entendre comment mes amis vont réagir!$B$BIls ne s\'y attendront jamais';
-- Quest 113 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (113, 'frFR', 'Eh bien, Junior Surveyor $n, Pestlezugg a-t-il ce rapport prêt?') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, Junior Surveyor $n, Pestlezugg a-t-il ce rapport prêt?';
-- Quest 113 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (113, 'frFR', 'Merci d\'avoir livré le rapport, Junior Surveyor <name>; voici votre paiement pour votre service diligent à la Compagnie des Eaux de Gadgetzan.$B$Bien que je ne sois généralement pas ravi de remettre nos informations précieuses carte blanche à ceux qui paieraient autrement un bon prix pour elles, je connais Pestlezugg depuis plusieurs années maintenant.  S\'il recommande d\'en informer tout le monde, alors qu\'il en soit ainsi.  Donne-moi un instant et je vous ferai une copie.') ON DUPLICATE KEY UPDATE RewardText='Merci d\'avoir livré le rapport, Junior Surveyor <name>; voici votre paiement pour votre service diligent à la Compagnie des Eaux de Gadgetzan.$B$Bien que je ne sois généralement pas ravi de remettre nos informations précieuses carte blanche à ceux qui paieraient autrement un bon prix pour elles, je connais Pestlezugg depuis plusieurs années maintenant.  S\'il recommande d\'en informer tout le monde, alors qu\'il en soit ainsi.  Donne-moi un instant et je vous ferai une copie.';
-- Quest 124 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (124, 'frFR', 'Mes chevaux semblent encore nerveux, et j\'entends toujours ce cri de loup maudit la nuit. S\'il vous plaît, $N, faites quelque chose à propos de ces Gnolls!') ON DUPLICATE KEY UPDATE CompletionText='Mes chevaux semblent encore nerveux, et j\'entends toujours ce cri de loup maudit la nuit. S\'il vous plaît, $N, faites quelque chose à propos de ces Gnolls!';
-- Quest 134 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (134, 'frFR', 'As-tu ma caisse? Si oui, alors s\'il te plaît... donne-la-moi vite!') ON DUPLICATE KEY UPDATE CompletionText='As-tu ma caisse? Si oui, alors s\'il te plaît... donne-la-moi vite!';
-- Quest 134 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (134, 'frFR', 'Remercie le Néc-... eh bien, MERCI, <name>!  Tu as plus que mérité ta récompense.$B$Ahaha!  Heureux!  De bonnes nuits devant toi!!') ON DUPLICATE KEY UPDATE RewardText='Remercie le Néc-... eh bien, MERCI, <name>!  Tu as plus que mérité ta récompense.$B$Ahaha!  Heureux!  De bonnes nuits devant toi!!';
-- Quest 151 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (151, 'frFR', 'Old Blanchy est sur sa dernière jambe. As-tu trouvé des flocons pour elle?') ON DUPLICATE KEY UPDATE CompletionText='Old Blanchy est sur sa dernière jambe. As-tu trouvé des flocons pour elle?';
-- Quest 151 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (151, 'frFR', 'Merci beaucoup, <name>!  La pauvre Old Blanchy sera si heureuse!') ON DUPLICATE KEY UPDATE RewardText='Merci beaucoup, <name>!  La pauvre Old Blanchy sera si heureuse!';
-- Quest 152 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (152, 'frFR', 'Tue 7 Chasseurs de marée, 7 Guerriers, 7 Oracles et 7 Coureurs de côte et je veillerai à ce que tu sois récompensé.') ON DUPLICATE KEY UPDATE CompletionText='Tue 7 Chasseurs de marée, 7 Guerriers, 7 Oracles et 7 Coureurs de côte et je veillerai à ce que tu sois récompensé.';

-- Quest 155 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (155, 'frFR', 'Quel intérêt avez-vous avec moi ? Je suis un homme très occupé...') ON DUPLICATE KEY UPDATE CompletionText='Quel intérêt avez-vous avec moi ? Je suis un homme très occupé...';
-- Quest 163 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (163, 'frFR', 'Ah, $N! De retour si vite ? Sans aucun doute, tu as recommencé à chasser ? Ne t\'inquiète pas si tu as rencontré des revers, à long terme, ça te rendra meilleur !$B$B... Tu n\'aurais pas pu aller plus loin, de toute façon...') ON DUPLICATE KEY UPDATE CompletionText='Ah, $N! De retour si vite ? Sans aucun doute, tu as recommencé à chasser ? Ne t\'inquiète pas si tu as rencontré des revers, à long terme, ça te rendra meilleur !$B$B... Tu n\'aurais pas pu aller plus loin, de toute façon...';
-- Quest 169 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (169, 'frFR', 'Travail fantastique, <name>!  Gath\'Ilzogg a mené ces brutes au combat, tuant de nombreux humains innocents.  La vindication est nôtre.  C\'est le premier pas pour récupérer le château pour le royaume de Stormwind !') ON DUPLICATE KEY UPDATE RewardText='Travail fantastique, <name>!  Gath\'Ilzogg a mené ces brutes au combat, tuant de nombreux humains innocents.  La vindication est nôtre.  C\'est le premier pas pour récupérer le château pour le royaume de Stormwind !';
-- Quest 171 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (171, 'frFR', 'C\'est un plaisir de vous revoir, $N. Avez-vous rempli les devoirs pour lesquels vous vous êtes porté volontaire pendant la Semaine des enfants ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est un plaisir de vous revoir, $N. Avez-vous rempli les devoirs pour lesquels vous vous êtes porté volontaire pendant la Semaine des enfants ?';
-- Quest 181 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (181, 'frFR', 'Avez-vous réussi à convaincre Zzarc\'Vul de nous prêter son monocle pour notre expérience ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à convaincre Zzarc\'Vul de nous prêter son monocle pour notre expérience ?';
-- Quest 181 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (181, 'frFR', 'Enfin ! Le dispositif d\'observation des étoiles est terminé ! Merci, $N. Maintenant, je peux continuer mes recherches. . .') ON DUPLICATE KEY UPDATE RewardText='Enfin ! Le dispositif d\'observation des étoiles est terminé ! Merci, $N. Maintenant, je peux continuer mes recherches. . .';
-- Quest 184 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (184, 'frFR', 'Vous avez l\'acte de ma ferme?? C\'est une bonne nouvelle ! Des rustres l\'ont volé il y a des jours... Je pensais qu\'il était perdu à jamais !$b$bS\'il vous plaît, donnez-le-moi. Nous partons de Westfall et nous ne reviendrons pas de sitôt, mais si nous le faisons, nous aurons besoin de ces papiers...') ON DUPLICATE KEY UPDATE CompletionText='Vous avez l\'acte de ma ferme?? C\'est une bonne nouvelle ! Des rustres l\'ont volé il y a des jours... Je pensais qu\'il était perdu à jamais !$b$bS\'il vous plaît, donnez-le-moi. Nous partons de Westfall et nous ne reviendrons pas de sitôt, mais si nous le faisons, nous aurons besoin de ces papiers...';
-- Quest 185 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (185, 'frFR', 'Je ne me sens pas confiant pour vous former davantage, $n, tant que vous n\'aurez pas prouvé votre habileté à abattre le plus jeune des tigres en premier.') ON DUPLICATE KEY UPDATE CompletionText='Je ne me sens pas confiant pour vous former davantage, $n, tant que vous n\'aurez pas prouvé votre habileté à abattre le plus jeune des tigres en premier.';
-- Quest 186 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (186, 'frFR', 'Si vous aspirez à des défis plus grands, vous devez d\'abord vous prouver avec la tâche à accomplir. Revenez-moi après avoir tué 10 Tigres de Stranglethorn.') ON DUPLICATE KEY UPDATE CompletionText='Si vous aspirez à des défis plus grands, vous devez d\'abord vous prouver avec la tâche à accomplir. Revenez-moi après avoir tué 10 Tigres de Stranglethorn.';
-- Quest 187 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (187, 'frFR', 'Vous devez tuer 10 Tigres d\'Élite de Stranglethorn avant que je ne vous donne le défi final qui déterminera si vous êtes un maître chasseur de tigres.') ON DUPLICATE KEY UPDATE CompletionText='Vous devez tuer 10 Tigres d\'Élite de Stranglethorn avant que je ne vous donne le défi final qui déterminera si vous êtes un maître chasseur de tigres.';
-- Quest 188 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (188, 'frFR', 'Comment se passe la chasse à Sin\'Dall ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe la chasse à Sin\'Dall ?';
-- Quest 188 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (188, 'frFR', 'Très impressionnant, je le dis !  Je t\'envoie pour vaincre les chatons, et tu reviens avec une patte de la taille d\'un gnome !  Tu es un vrai Maître Chasseur de Tigres, <name> !') ON DUPLICATE KEY UPDATE RewardText='Très impressionnant, je le dis !  Je t\'envoie pour vaincre les chatons, et tu reviens avec une patte de la taille d\'un gnome !  Tu es un vrai Maître Chasseur de Tigres, <name> !';
-- Quest 191 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (191, 'frFR', 'Va tuer 10 panthères ! Montre-nous ce que tu as !') ON DUPLICATE KEY UPDATE CompletionText='Va tuer 10 panthères ! Montre-nous ce que tu as !';
-- Quest 192 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (192, 'frFR', 'Qu\'est-ce que tu fais ici, $n ! Tu devrais être en train de te faufiler dans les buissons, essayant de tuer 10 Panthères de Shadowmaw. Je pensais que tu te croyais un grand chasseur $c ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que tu fais ici, $n ! Tu devrais être en train de te faufiler dans les buissons, essayant de tuer 10 Panthères de Shadowmaw. Je pensais que tu te croyais un grand chasseur $c ?';

-- Quest 195 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (195, 'frFR', 'Un vrai chasseur concentre son attention sur sa proie. Toi, mon ami, tu sembles plus préoccupé par les bavardages autour du feu de camp. Maintenant, va dehors et tue 10 Lashtails avant que j\'aille éradiquer toute cette jungle maudite d\'entre eux en une seule chasse.') ON DUPLICATE KEY UPDATE CompletionText='Un vrai chasseur concentre son attention sur sa proie. Toi, mon ami, tu sembles plus préoccupé par les bavardages autour du feu de camp. Maintenant, va dehors et tue 10 Lashtails avant que j\'aille éradiquer toute cette jungle maudite d\'entre eux en une seule chasse.';
-- Quest 196 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (196, 'frFR', 'Bah ! Qu\'est-ce que tu fais là, $N ! Un vrai chasseur de gros gibier n\'abandonne jamais une fois que sa proie est dans son viseur. Ces Stalkers de la Jungle ne vont pas venir courir jusqu\'à ce feu de camp pour se jeter dessus. Quel imbécile.') ON DUPLICATE KEY UPDATE CompletionText='Bah ! Qu\'est-ce que tu fais là, $N ! Un vrai chasseur de gros gibier n\'abandonne jamais une fois que sa proie est dans son viseur. Ces Stalkers de la Jungle ne vont pas venir courir jusqu\'à ce feu de camp pour se jeter dessus. Quel imbécile.';
-- Quest 199 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (199, 'frFR', 'As-tu découvert des indices, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu découvert des indices, $N ?';
-- Quest 201 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (201, 'frFR', 'Alors ? As-tu eu de la chance à localiser le camp ?') ON DUPLICATE KEY UPDATE CompletionText='Alors ? As-tu eu de la chance à localiser le camp ?';
-- Quest 202 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (202, 'frFR', 'J\'ose espérer que Kurzen et ses défenseurs sont morts, $N ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ose espérer que Kurzen et ses défenseurs sont morts, $N ?';
-- Quest 203 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (203, 'frFR', 'J\'espère que tu as réussi ta chasse, $N. Nous ne tiendrons pas longtemps contre lui sans ton aide.') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que tu as réussi ta chasse, $N. Nous ne tiendrons pas longtemps contre lui sans ton aide.';
-- Quest 205 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (205, 'frFR', 'As-tu ces fétiches, $N ? Ils pourraient contenir le secret de la dégradation de Kurzen... Je dois le savoir !') ON DUPLICATE KEY UPDATE CompletionText='As-tu ces fétiches, $N ? Ils pourraient contenir le secret de la dégradation de Kurzen... Je dois le savoir !';
-- Quest 208 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (208, 'frFR', 'Je vois que tu es de retour, $g vieux bonhomme : lass;. King Bangalash m\'a fait revenir au camp de nombreuses fois. Tiens bon.') ON DUPLICATE KEY UPDATE CompletionText='Je vois que tu es de retour, $g vieux bonhomme : lass;. King Bangalash m\'a fait revenir au camp de nombreuses fois. Tiens bon.';
-- Quest 208 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (208, 'frFR', 'Bien joué !  Parfait !  Félicitations, <name>, pour avoir réussi là où d\'autres ont échoué.$B$Je suis honoré de te compter comme un camarade de notre grande équipe de chasse.  Personne ne doutera jamais de ton expertise en chasse et en traque !$B$À toi, je dis !  Santé !') ON DUPLICATE KEY UPDATE RewardText='Bien joué !  Parfait !  Félicitations, <name>, pour avoir réussi là où d\'autres ont échoué.$B$Je suis honoré de te compter comme un camarade de notre grande équipe de chasse.  Personne ne doutera jamais de ton expertise en chasse et en traque !$B$À toi, je dis !  Santé !';
-- Quest 212 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (212, 'frFR', '$N ! As-tu cette hanche ? Je dois commencer à la préparer bientôt, sinon le banquet sera gâché !') ON DUPLICATE KEY UPDATE CompletionText='$N ! As-tu cette hanche ? Je dois commencer à la préparer bientôt, sinon le banquet sera gâché !';
-- Quest 212 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (212, 'frFR', 'Ah, ça ira bien !  Merci beaucoup !$B$Maintenant, si vous voulez bien m\'excuser, je dois découper, mariner et garnir la hanche pour le banquet.') ON DUPLICATE KEY UPDATE RewardText='Ah, ça ira bien !  Merci beaucoup !$B$Maintenant, si vous voulez bien m\'excuser, je dois découper, mariner et garnir la hanche pour le banquet.';
-- Quest 214 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (214, 'frFR', 'As-tu récupéré notre terre de la bande des Defias ? Si oui, montre-moi 10 Bandanas en soie rouge comme preuve.') ON DUPLICATE KEY UPDATE CompletionText='As-tu récupéré notre terre de la bande des Defias ? Si oui, montre-moi 10 Bandanas en soie rouge comme preuve.';
-- Quest 214 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (214, 'frFR', 'Bien fait, <name> !  Au nom de la Milice du Peuple, je te salue pour tes efforts.  Bientôt, nous rendrons cette terre au peuple avec l\'aide d\'âmes courageuses comme toi.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, <name> !  Au nom de la Milice du Peuple, je te salue pour tes efforts.  Bientôt, nous rendrons cette terre au peuple avec l\'aide d\'âmes courageuses comme toi.';
-- Quest 216 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (216, 'frFR', 'As-tu mené le combat à Thistlefur ? Avec un chemin dégagé entre nos bases, nos chances de revendiquer tout Ashenvale augmentent considérablement.') ON DUPLICATE KEY UPDATE CompletionText='As-tu mené le combat à Thistlefur ? Avec un chemin dégagé entre nos bases, nos chances de revendiquer tout Ashenvale augmentent considérablement.';
-- Quest 220 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (220, 'frFR', 'Bonjour à nouveau, $N. Tu as l\'air bien.$B$Qu\'est-ce qui te ramène à moi si vite ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau, $N. Tu as l\'air bien.$B$Qu\'est-ce qui te ramène à moi si vite ?';

-- Quest 220 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (220, 'frFR', 'Une fiole d\'eau créée et bénie par Brine, et recueillie par vous, pas moins.$B$BLe liquide dans cette fiole sera essentiel pour créer un sapta pour vous, mais sera aussi utilisé dans une autre tâche.$B$BLe sapta que je crée pour vous doit être utilisé pour voir les esprits de l\'eau au sanctuaire dans la Forêt d\'Argentpine, au sud de la Cité Souterraine. Les gouttes restantes, eh bien, je vous parlerai des gouttes restantes si vous sentez que vous êtes prêt.$B$BÊtes-vous prêt pour un autre voyage, $N?') ON DUPLICATE KEY UPDATE RewardText='Une fiole d\'eau créée et bénie par Brine, et recueillie par vous, pas moins.$B$BLe liquide dans cette fiole sera essentiel pour créer un sapta pour vous, mais sera aussi utilisé dans une autre tâche.$B$BLe sapta que je crée pour vous doit être utilisé pour voir les esprits de l\'eau au sanctuaire dans la Forêt d\'Argentpine, au sud de la Cité Souterraine. Les gouttes restantes, eh bien, je vous parlerai des gouttes restantes si vous sentez que vous êtes prêt.$B$BÊtes-vous prêt pour un autre voyage, $N?';
-- Quest 221 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (221, 'frFR', 'De retour si vite, $N? J\'espère que vous ne venez pas me dire que vous avez abandonné.') ON DUPLICATE KEY UPDATE CompletionText='De retour si vite, $N? J\'espère que vous ne venez pas me dire que vous avez abandonné.';
-- Quest 235 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (235, 'frFR', 'Bienvenue dans la nouvelle frontière, $N. Ashenvale est une terre d\'opportunités, un endroit où un jeune <class> comme vous est capable de trouver des chances illimitées pour prouver son mérite. Regardez autour du poste ici, et assurez-vous de vous rendre au Rivage de Zoram, car la Horde a également un poste là-bas.$B$BVotre présence ici me dit que vous êtes venu en apprendre davantage sur la chasse. Écoutez attentivement, et je serai ravi de partager avec vous ce que vous devez savoir.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue dans la nouvelle frontière, $N. Ashenvale est une terre d\'opportunités, un endroit où un jeune <class> comme vous est capable de trouver des chances illimitées pour prouver son mérite. Regardez autour du poste ici, et assurez-vous de vous rendre au Rivage de Zoram, car la Horde a également un poste là-bas.$B$BVotre présence ici me dit que vous êtes venu en apprendre davantage sur la chasse. Écoutez attentivement, et je serai ravi de partager avec vous ce que vous devez savoir.';
-- Quest 237 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (237, 'frFR', 'Nous avons besoin de plus de temps, $r. Vos ordres sont de tuer 10 Stonesplinter Skullthumpers et 10 Stonesplinter Seers. Gardez l\'ennemi sous pression jusqu\'à ce que nous recevions des renforts. Ce n\'est pas le moment de l\'oisiveté.') ON DUPLICATE KEY UPDATE CompletionText='Nous avons besoin de plus de temps, $r. Vos ordres sont de tuer 10 Stonesplinter Skullthumpers et 10 Stonesplinter Seers. Gardez l\'ennemi sous pression jusqu\'à ce que nous recevions des renforts. Ce n\'est pas le moment de l\'oisiveté.';
-- Quest 246 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (246, 'frFR', 'Excusez-moi, $N, mais nous avons beaucoup de choses à garder à nous ici. Si vous n\'avez rien à signaler, alors je dois m\'occuper d\'autres affaires.') ON DUPLICATE KEY UPDATE CompletionText='Excusez-moi, $N, mais nous avons beaucoup de choses à garder à nous ici. Si vous n\'avez rien à signaler, alors je dois m\'occuper d\'autres affaires.';
-- Quest 247 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (247, 'frFR', '$N, vous avez abattu les trois bêtes qui composent la Chasse d\'Ashenvale. Vous m\'avez apporté une preuve adéquate de leur disparition ; il n\'y a aucun doute sur votre force et votre ténacité. Le sang d\'un chasseur coule dans vos veines, et vous devez être félicité !$B$BVeuillez accepter ce bibelot comme signe de félicitations pour vos exploits magnifiques accomplis dans Ashenvale pour la Horde aujourd\'hui. Que vos ancêtres veillent sur vous !') ON DUPLICATE KEY UPDATE RewardText='$N, vous avez abattu les trois bêtes qui composent la Chasse d\'Ashenvale. Vous m\'avez apporté une preuve adéquate de leur disparition ; il n\'y a aucun doute sur votre force et votre ténacité. Le sang d\'un chasseur coule dans vos veines, et vous devez être félicité !$B$BVeuillez accepter ce bibelot comme signe de félicitations pour vos exploits magnifiques accomplis dans Ashenvale pour la Horde aujourd\'hui. Que vos ancêtres veillent sur vous !';
-- Quest 249 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (249, 'frFR', 'Dépêchez-vous, $N, avant que mes craintes concernant la propagation du pouvoir de Morganth ne deviennent réelles !') ON DUPLICATE KEY UPDATE CompletionText='Dépêchez-vous, $N, avant que mes craintes concernant la propagation du pouvoir de Morganth ne deviennent réelles !';
-- Quest 249 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (249, 'frFR', 'Vous avez bien fait, <name>.  En battant le sorcier Morganth, Stormwind est sauvé d\'un danger grave.$B$BI vous offre cette récompense avec humilité.  Et je vous souhaite la paix, si c\'étaient des temps paisibles.$B$BMais au lieu de cela, je vous souhaite bonne chance dans vos épreuves, et la victoire dans les conflits à venir.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, <name>.  En battant le sorcier Morganth, Stormwind est sauvé d\'un danger grave.$B$BI vous offre cette récompense avec humilité.  Et je vous souhaite la paix, si c\'étaient des temps paisibles.$B$BMais au lieu de cela, je vous souhaite bonne chance dans vos épreuves, et la victoire dans les conflits à venir.';
-- Quest 254 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (254, 'frFR', 'Vous fouillez la terre semi-lâche au-dessus de la tombe... et trouvez les restes d\'un cercueil.$B$BÀ l\'intérieur du cercueil, vous sentez les griffes vibrantes des doigts et le grincement des dents pourries...$B$BVoulez-vous ouvrir le cercueil et récupérer le cœur de l\'Embalmeur ?') ON DUPLICATE KEY UPDATE RewardText='Vous fouillez la terre semi-lâche au-dessus de la tombe... et trouvez les restes d\'un cercueil.$B$BÀ l\'intérieur du cercueil, vous sentez les griffes vibrantes des doigts et le grincement des dents pourries...$B$BVoulez-vous ouvrir le cercueil et récupérer le cœur de l\'Embalmeur ?';
-- Quest 257 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (257, 'frFR', 'Pas de chance ? Ne soyez pas trop triste, $ner...$B$BTout le monde ne peut pas être moi.') ON DUPLICATE KEY UPDATE CompletionText='Pas de chance ? Ne soyez pas trop triste, $ner...$B$BTout le monde ne peut pas être moi.';
-- Quest 258 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (258, 'frFR', 'Il est naturel de se sentir malheureux quand on est dépassé par quelqu\'un de si nouveau dans ce monde. Vous ne devriez pas vous sentir mal, $nah.$B$BHm? Ai-je mal prononcé votre nom ?') ON DUPLICATE KEY UPDATE CompletionText='Il est naturel de se sentir malheureux quand on est dépassé par quelqu\'un de si nouveau dans ce monde. Vous ne devriez pas vous sentir mal, $nah.$B$BHm? Ai-je mal prononcé votre nom ?';
-- Quest 261 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (261, 'frFR', 'La Scourge grandit en puissance avec le passage de chaque jour. Si vous souhaitez vraiment arrêter son avance, alors montrez-le-moi.') ON DUPLICATE KEY UPDATE CompletionText='La Scourge grandit en puissance avec le passage de chaque jour. Si vous souhaitez vraiment arrêter son avance, alors montrez-le-moi.';
-- Quest 263 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (263, 'frFR', 'De retour si vite ? Au cas où je ne me serais pas éclairci que nous avons besoin que vous tuiez 10 Stonesplinter Shaman et 10 Stonesplinter Bonesnappers, $N. Maintenant, allez les chercher, Trogg-Slayer !') ON DUPLICATE KEY UPDATE CompletionText='De retour si vite ? Au cas où je ne me serais pas éclairci que nous avons besoin que vous tuiez 10 Stonesplinter Shaman et 10 Stonesplinter Bonesnappers, $N. Maintenant, allez les chercher, Trogg-Slayer !';
-- Quest 272 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (272, 'frFR', 'Avez-vous formé votre pendentif pour que je l\'inspecte, $N? Si vous avez besoin d\'aide pour localiser les pièces, essayez de demander des informations à la population locale. Non seulement vous trouverez ce que vous cherchez, mais cela vous donnera une raison d\'explorer cette clairière merveilleuse et sacrée.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous formé votre pendentif pour que je l\'inspecte, $N? Si vous avez besoin d\'aide pour localiser les pièces, essayez de demander des informations à la population locale. Non seulement vous trouverez ce que vous cherchez, mais cela vous donnera une raison d\'explorer cette clairière merveilleuse et sacrée.';
-- Quest 272 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (272, 'frFR', 'Vous avez terminé l\'Épreuve du Lion de Mer, $N - félicitations.$B$Chaque tâche dans l\'acquisition du pendentif montre que l\'agilité et l\'endurance sont nécessaires pour agir en harmonie avec ce que vous souhaitez faire sous l\'eau.  Aucune ne peut exister sans l\'autre, et les deux ne peuvent être faites sans votre volonté d\'embrasser l\'aspect du lion de mer.$B$BSouvenez-vous bien de ces leçons, et comptez sur elles une fois que vous aurez acquis votre forme aquatique.') ON DUPLICATE KEY UPDATE RewardText='Vous avez terminé l\'Épreuve du Lion de Mer, $N - félicitations.$B$Chaque tâche dans l\'acquisition du pendentif montre que l\'agilité et l\'endurance sont nécessaires pour agir en harmonie avec ce que vous souhaitez faire sous l\'eau.  Aucune ne peut exister sans l\'autre, et les deux ne peuvent être faites sans votre volonté d\'embrasser l\'aspect du lion de mer.$B$BSouvenez-vous bien de ces leçons, et comptez sur elles une fois que vous aurez acquis votre forme aquatique.';

-- Quest 275 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (275, 'frFR', 'Les Marais pleurent encore, et les Rampants des Marais rugissent encore. Reviens-moi quand ta tâche sera accomplie.') ON DUPLICATE KEY UPDATE CompletionText='Les Marais pleurent encore, et les Rampants des Marais rugissent encore. Reviens-moi quand ta tâche sera accomplie.';
-- Quest 276 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (276, 'frFR', 'Ta tâche est toujours en cours, jeune $C.') ON DUPLICATE KEY UPDATE CompletionText='Ta tâche est toujours en cours, jeune $C.';
-- Quest 278 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (278, 'frFR', 'As-tu les objets nécessaires ? Le temps presse !!') ON DUPLICATE KEY UPDATE CompletionText='As-tu les objets nécessaires ? Le temps presse !!';
-- Quest 279 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (279, 'frFR', 'Nos marchands ne seront pas en sécurité tant que nous ne nous serons débarrassés de Gobbler et de ces Murlocs.') ON DUPLICATE KEY UPDATE CompletionText='Nos marchands ne seront pas en sécurité tant que nous ne nous serons débarrassés de Gobbler et de ces Murlocs.';
-- Quest 279 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (279, 'frFR', 'Ah, bien joué <name>.$B$BAccepte ceci comme paiement pour l\'accomplissement de ton contrat avec les Marines Marchands.') ON DUPLICATE KEY UPDATE RewardText='Ah, bien joué <name>.$B$BAccepte ceci comme paiement pour l\'accomplissement de ton contrat avec les Marines Marchands.';
-- Quest 283 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (283, 'frFR', 'Merci beaucoup, $N!! Tu as sauvé le Barrage de Pierre ! Sans ton aide, les terroristes des Ferrailles Noires auraient sûrement vu le jour de ce mémorable monument. Tu as rendu le Royaume et l\'Alliance fiers, brave $c.$b$bLe Barrage est à nouveau en sécurité. . . pour le moment au moins. . . .') ON DUPLICATE KEY UPDATE RewardText='Merci beaucoup, $N!! Tu as sauvé le Barrage de Pierre ! Sans ton aide, les terroristes des Ferrailles Noires auraient sûrement vu le jour de ce mémorable monument. Tu as rendu le Royaume et l\'Alliance fiers, brave $c.$b$bLe Barrage est à nouveau en sécurité. . . pour le moment au moins. . . .';
-- Quest 287 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (287, 'frFR', 'Tu ne le trouves pas ? Mes indications étaient très claires ! Nous n\'avons pas beaucoup de temps, tu dois te dépêcher ! Ne reviens pas avant d\'avoir trouvé la grotte.') ON DUPLICATE KEY UPDATE CompletionText='Tu ne le trouves pas ? Mes indications étaient très claires ! Nous n\'avons pas beaucoup de temps, tu dois te dépêcher ! Ne reviens pas avant d\'avoir trouvé la grotte.';
-- Quest 294 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (294, 'frFR', 'Tue 10 Raptors Tachetés et 10 Criailleurs Tachetés, $N. Mes collègues ne méritaient pas le sort qui leur est arrivé. Il est temps de régler les comptes.') ON DUPLICATE KEY UPDATE CompletionText='Tue 10 Raptors Tachetés et 10 Criailleurs Tachetés, $N. Mes collègues ne méritaient pas le sort qui leur est arrivé. Il est temps de régler les comptes.';
-- Quest 295 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (295, 'frFR', 'Je veux que ces Griffes-Faucilles Tachetées et Mâchoires-Lames Tachetées paient pour ce qu\'ils ont fait. As-tu tué 10 de chacun jusqu\'à présent ?') ON DUPLICATE KEY UPDATE CompletionText='Je veux que ces Griffes-Faucilles Tachetées et Mâchoires-Lames Tachetées paient pour ce qu\'ils ont fait. As-tu tué 10 de chacun jusqu\'à présent ?';
-- Quest 295 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (295, 'frFR', 'Tu as fait un travail remarquable en éliminant ces Raptors, $N!') ON DUPLICATE KEY UPDATE RewardText='Tu as fait un travail remarquable en éliminant ces Raptors, $N!';
-- Quest 299 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (299, 'frFR', 'As-tu découvert les quatre fragments, $N ? Ados, Modr, Golm et Neru...') ON DUPLICATE KEY UPDATE CompletionText='As-tu découvert les quatre fragments, $N ? Ados, Modr, Golm et Neru...';
-- Quest 308 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (308, 'frFR', 'Hmph ! Il y a toute cette boisson ici, mais j\'ai des ordres stricts de ne pas y toucher. Si seulement je pouvais goûter un peu de notre Ale de Tonnerre... ça aiguiserait mon esprit, pas de mensonge !') ON DUPLICATE KEY UPDATE CompletionText='Hmph ! Il y a toute cette boisson ici, mais j\'ai des ordres stricts de ne pas y toucher. Si seulement je pouvais goûter un peu de notre Ale de Tonnerre... ça aiguiserait mon esprit, pas de mensonge !';
-- Quest 308 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (308, 'frFR', 'Pour moi ?  Tu es un vrai héros, <name>!') ON DUPLICATE KEY UPDATE RewardText='Pour moi ?  Tu es un vrai héros, <name>!';
-- Quest 311 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (311, 'frFR', 'Pas mal, <name>!  As-tu eu du mal à passer leur garde?$B$BPeu importe - merci beaucoup, et si tu as jamais besoin de stout avec un coup de fouet, n\'oublie pas les Barleybrews!') ON DUPLICATE KEY UPDATE RewardText='Pas mal, <name>!  As-tu eu du mal à passer leur garde?$B$BPeu importe - merci beaucoup, et si tu as jamais besoin de stout avec un coup de fouet, n\'oublie pas les Barleybrews!';
-- Quest 323 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (323, 'frFR', 'Battez fort, $Nn. Et ne désespère pas, car le désespoir est la plus grande arme du mal.') ON DUPLICATE KEY UPDATE CompletionText='Battez fort, $Nn. Et ne désespère pas, car le désespoir est la plus grande arme du mal.';

-- Quest 372 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (372, 'frFR', 'Tu n\'as pas encore accompli ton devoir, $c. Nous ne pouvons pas nous attendre à ce que nous menions le plan de Dame Noire avec la Croisade Écarlate harcelant nos soldats. Provoquez leur mort et accomplissez votre devoir envers Sylvanas !') ON DUPLICATE KEY UPDATE CompletionText='Tu n\'as pas encore accompli ton devoir, $c. Nous ne pouvons pas nous attendre à ce que nous menions le plan de Dame Noire avec la Croisade Écarlate harcelant nos soldats. Provoquez leur mort et accomplissez votre devoir envers Sylvanas !';
-- Quest 380 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (380, 'frFR', 'Méfiez-vous du venin des araignées, $N. Si vous ressentez une vive brûlure, vous voudrez peut-être qu\'on examine cela.') ON DUPLICATE KEY UPDATE CompletionText='Méfiez-vous du venin des araignées, $N. Si vous ressentez une vive brûlure, vous voudrez peut-être qu\'on examine cela.';
-- Quest 387 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (387, 'frFR', 'Le caserne est toujours envahie ! Ces Rats Defias doivent comprendre que leurs actions ne seront pas tolérées. Maintenant, retournez là-bas et montrez de la force !') ON DUPLICATE KEY UPDATE CompletionText='Le caserne est toujours envahie ! Ces Rats Defias doivent comprendre que leurs actions ne seront pas tolérées. Maintenant, retournez là-bas et montrez de la force !';
-- Quest 397 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (397, 'frFR', 'Le Maître dit de donner un cadeau à $N. Zggi veut garder un beau cadeau, mais Zggi sait mieux que de trahir le Maître.') ON DUPLICATE KEY UPDATE RewardText='Le Maître dit de donner un cadeau à $N. Zggi veut garder un beau cadeau, mais Zggi sait mieux que de trahir le Maître.';
-- Quest 409 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (409, 'frFR', 'J\'attends la preuve de votre allégeance, $c.') ON DUPLICATE KEY UPDATE CompletionText='J\'attends la preuve de votre allégeance, $c.';
-- Quest 410 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (410, 'frFR', 'Ceci est une table ancienne, usée et sanglante.') ON DUPLICATE KEY UPDATE CompletionText='Ceci est une table ancienne, usée et sanglante.';
-- Quest 421 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (421, 'frFR', 'Si vous souhaitez vous prouver à moi, vous devez tuer 5 Blancs de Moonrage. Accomplissez cette tâche, et je veillerai à ce que votre compétence soit mise à des missions plus dignes.') ON DUPLICATE KEY UPDATE CompletionText='Si vous souhaitez vous prouver à moi, vous devez tuer 5 Blancs de Moonrage. Accomplissez cette tâche, et je veillerai à ce que votre compétence soit mise à des missions plus dignes.';
-- Quest 431 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (431, 'frFR', 'Vous prenez une des bougies et la placez dans votre sac.') ON DUPLICATE KEY UPDATE RewardText='Vous prenez une des bougies et la placez dans votre sac.';
-- Quest 433 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (433, 'frFR', 'Si nous pouvons retirer les troggs de la carrière de Gol\'Bolar, ce sera la première étape de nombreuses que nous devrons entreprendre pour nous débarrasser de cette menace.') ON DUPLICATE KEY UPDATE CompletionText='Si nous pouvons retirer les troggs de la carrière de Gol\'Bolar, ce sera la première étape de nombreuses que nous devrons entreprendre pour nous débarrasser de cette menace.';
-- Quest 434 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (434, 'frFR', 'Oui, $N? Est-ce que les choses se passent bien avec Tyrion ? Il m\'a informé de la situation et je l\'ai aidé à piéger Marzon pour qu\'il aille au château.$B$BMarzon a été une épine dans le pied de beaucoup de gens à Stormwind ; beaucoup d\'entre eux sont de bons amis. Personne ne s\'amuse avec mes amis... pas s\'ils savent ce qui est bon pour eux.$B$BC\'est juste dommage que je fasse indirectement un cadeau à Shaw et SI:7 entre-temps. Oh là là, tous les plans ne sont pas parfaits.') ON DUPLICATE KEY UPDATE CompletionText='Oui, $N? Est-ce que les choses se passent bien avec Tyrion ? Il m\'a informé de la situation et je l\'ai aidé à piéger Marzon pour qu\'il aille au château.$B$BMarzon a été une épine dans le pied de beaucoup de gens à Stormwind ; beaucoup d\'entre eux sont de bons amis. Personne ne s\'amuse avec mes amis... pas s\'ils savent ce qui est bon pour eux.$B$BC\'est juste dommage que je fasse indirectement un cadeau à Shaw et SI:7 entre-temps. Oh là là, tous les plans ne sont pas parfaits.';
-- Quest 455 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (455, 'frFR', 'Vous venez de Loch Modan ? Comment se passe la situation des orcs à la Porte d\'Algaz ?') ON DUPLICATE KEY UPDATE CompletionText='Vous venez de Loch Modan ? Comment se passe la situation des orcs à la Porte d\'Algaz ?';
-- Quest 486 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (486, 'frFR', 'Nos frères ne peuvent être réveillés tant qu\'Ursal le Broyeur n\'a pas été tué, $N.') ON DUPLICATE KEY UPDATE CompletionText='Nos frères ne peuvent être réveillés tant qu\'Ursal le Broyeur n\'a pas été tué, $N.';
-- Quest 487 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (487, 'frFR', 'La route n\'est toujours pas sûre, $c. Partez et tuez 6 Chasseurs d\'Ambush de Gnarlpine et revenez me voir.') ON DUPLICATE KEY UPDATE CompletionText='La route n\'est toujours pas sûre, $c. Partez et tuez 6 Chasseurs d\'Ambush de Gnarlpine et revenez me voir.';

-- Quest 504 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (504, 'frFR', 'Vous avez encore des Warmongers à abattre, $N. Vous devriez être sur les montagnes pour votre tâche, pas ici avec votre arme rangée.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez encore des Warmongers à abattre, $N. Vous devriez être sur les montagnes pour votre tâche, pas ici avec votre arme rangée.';
-- Quest 505 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (505, 'frFR', 'Vous avez tué ces voyous du Syndicate, j\'imagine ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez tué ces voyous du Syndicate, j\'imagine ?';
-- Quest 518 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (518, 'frFR', 'Je note que votre tâche est inachevée, $N. Dois-je informer Sharlindra de votre incompétence ?') ON DUPLICATE KEY UPDATE CompletionText='Je note que votre tâche est inachevée, $N. Dois-je informer Sharlindra de votre incompétence ?';
-- Quest 526 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (526, 'frFR', 'Avez-vous trouvé le fer de forge de lumière dont vous avez besoin ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé le fer de forge de lumière dont vous avez besoin ?';
-- Quest 526 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (526, 'frFR', 'Ah, vous les avez trouvés ! Maintenant, allons forger ce fer de forge de lumière en quelque chose d\'utile, hein ?') ON DUPLICATE KEY UPDATE RewardText='Ah, vous les avez trouvés ! Maintenant, allons forger ce fer de forge de lumière en quelque chose d\'utile, hein ?';
-- Quest 527 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (527, 'frFR', 'En tant qu\'Exécuteur Principal de Tarren Mill, sous le commandement direct de Varimathras et de la Dame Noire, vous êtes soumis à suivre mon ordre.$B$BPeut-être prenez-vous ce conflit avec l\'Alliance à la légère ? Si tel est le cas, je devrais vous décapiter ici et maintenant. Sinon, voyagez à l\'ouest jusqu\'à la ville de Hillsbrad et menez la bataille contre les humains, comme ordonné.$B$BDéchargé.') ON DUPLICATE KEY UPDATE CompletionText='En tant qu\'Exécuteur Principal de Tarren Mill, sous le commandement direct de Varimathras et de la Dame Noire, vous êtes soumis à suivre mon ordre.$B$BPeut-être prenez-vous ce conflit avec l\'Alliance à la légère ? Si tel est le cas, je devrais vous décapiter ici et maintenant. Sinon, voyagez à l\'ouest jusqu\'à la ville de Hillsbrad et menez la bataille contre les humains, comme ordonné.$B$BDéchargé.';
-- Quest 528 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (528, 'frFR', 'Vous avez vos ordres, $c. Cessez de traîner ici à Tarren Mill quand il y a du travail à faire ailleurs.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez vos ordres, $c. Cessez de traîner ici à Tarren Mill quand il y a du travail à faire ailleurs.';
-- Quest 536 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (536, 'frFR', 'Une autre bière, s\'il vous plaît, la dernière semble avoir disparu !$B$BLight, combien de temps encore vais-je rester coincé ici ?$B$BOh, c\'est toi, $N. As-tu tué ces murlocs ?') ON DUPLICATE KEY UPDATE CompletionText='Une autre bière, s\'il vous plaît, la dernière semble avoir disparu !$B$BLight, combien de temps encore vais-je rester coincé ici ?$B$BOh, c\'est toi, $N. As-tu tué ces murlocs ?';
-- Quest 539 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (539, 'frFR', 'On vous a donné l\'ordre direct d\'attaquer la Mine d\'Azureload. Vos raisons de traîner à Tarren Mill doivent être bonnes ou je vous décapiterai pour trahison.') ON DUPLICATE KEY UPDATE CompletionText='On vous a donné l\'ordre direct d\'attaquer la Mine d\'Azureload. Vos raisons de traîner à Tarren Mill doivent être bonnes ou je vous décapiterai pour trahison.';
-- Quest 541 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (541, 'frFR', 'Dun Garok s\'avère être trop d\'obstacle pour vous, $C ? Et je pensais que vous vous étiez établi vaillamment à Hillsbrad.$B$BSi vous n\'êtes pas en mesure de gérer la mission qui vous a été assignée, je trouverai quelqu\'un d\'autre qui pourra donner de meilleurs résultats. Quant à vous, eh bien, je suis sûr que la Dame Noire pourrait toujours utiliser plus de fossoyeurs dans les Clairières de Tirisfal.') ON DUPLICATE KEY UPDATE CompletionText='Dun Garok s\'avère être trop d\'obstacle pour vous, $C ? Et je pensais que vous vous étiez établi vaillamment à Hillsbrad.$B$BSi vous n\'êtes pas en mesure de gérer la mission qui vous a été assignée, je trouverai quelqu\'un d\'autre qui pourra donner de meilleurs résultats. Quant à vous, eh bien, je suis sûr que la Dame Noire pourrait toujours utiliser plus de fossoyeurs dans les Clairières de Tirisfal.';
-- Quest 545 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (545, 'frFR', 'Avez-vous encore affaibli les patrouilles de Dalaran autour de leurs ruines ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous encore affaibli les patrouilles de Dalaran autour de leurs ruines ?';
-- Quest 549 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (549, 'frFR', 'N\'avez-vous rien de mieux à faire que de rester là devant moi, $c ? En tant qu\'Exécuteur Principal, j\'ai des affaires plus urgentes que de fixer votre visage pourrissant.') ON DUPLICATE KEY UPDATE CompletionText='N\'avez-vous rien de mieux à faire que de rester là devant moi, $c ? En tant qu\'Exécuteur Principal, j\'ai des affaires plus urgentes que de fixer votre visage pourrissant.';
-- Quest 558 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (558, 'frFR', 'Un jour, je veux être un héros comme Jaina... eh bien, un héros garçon.') ON DUPLICATE KEY UPDATE CompletionText='Un jour, je veux être un héros comme Jaina... eh bien, un héros garçon.';
-- Quest 562 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (562, 'frFR', 'J\'ai une lettre prête à être envoyée au Major Samuelson à Stormwind. Il me faut juste les résultats.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai une lettre prête à être envoyée au Major Samuelson à Stormwind. Il me faut juste les résultats.';
-- Quest 564 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (564, 'frFR', 'Les lions des montagnes tuent nos chevaux sans compter et vous êtes là à bavarder de la météo et tout le tralalala.$B$BIl faudrait aller trouver un vrai héros. Plus de tuer et moins de parler.') ON DUPLICATE KEY UPDATE CompletionText='Les lions des montagnes tuent nos chevaux sans compter et vous êtes là à bavarder de la météo et tout le tralalala.$B$BIl faudrait aller trouver un vrai héros. Plus de tuer et moins de parler.';

-- Quest 568 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (568, 'frFR', 'Nos efforts d\'approvisionnement sont toujours entravés par la population de raptors indigènes, $c.') ON DUPLICATE KEY UPDATE CompletionText='Nos efforts d\'approvisionnement sont toujours entravés par la population de raptors indigènes, $c.';
-- Quest 578 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (578, 'frFR', 'Les trolls possédaient vraiment des objets magiques incroyables, $N. Et maintenant, peut-être, j\'ai l\'occasion d\'en ajouter un à ma vaste collection. Avez-vous eu de la chance à trouver la source de la rumeur ?') ON DUPLICATE KEY UPDATE CompletionText='Les trolls possédaient vraiment des objets magiques incroyables, $N. Et maintenant, peut-être, j\'ai l\'occasion d\'en ajouter un à ma vaste collection. Avez-vous eu de la chance à trouver la source de la rumeur ?';
-- Quest 579 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (579, 'frFR', 'Le Roi Varian a accordé une grande importance à l\'apprentissage, et a ainsi fourni des fonds pour faire des copies de divers tomes et écrits accessibles au public. C\'est très simple. Vous m\'apportez un parchemin de bibliothèque, et je peux vous donner une copie de l\'un des livres disponibles.') ON DUPLICATE KEY UPDATE CompletionText='Le Roi Varian a accordé une grande importance à l\'apprentissage, et a ainsi fourni des fonds pour faire des copies de divers tomes et écrits accessibles au public. C\'est très simple. Vous m\'apportez un parchemin de bibliothèque, et je peux vous donner une copie de l\'un des livres disponibles.';
-- Quest 579 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (579, 'frFR', 'Est-ce que l\'un de ces titres vous intéresse, $N ?') ON DUPLICATE KEY UPDATE RewardText='Est-ce que l\'un de ces titres vous intéresse, $N ?';
-- Quest 593 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (593, 'frFR', 'Yenniku se tient stupéfait devant vous, son esprit est ailleurs...') ON DUPLICATE KEY UPDATE CompletionText='Yenniku se tient stupéfait devant vous, son esprit est ailleurs...';
-- Quest 633 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (633, 'frFR', 'Le cache d\'explosifs doit être détruit !') ON DUPLICATE KEY UPDATE CompletionText='Le cache d\'explosifs doit être détruit !';
-- Quest 660 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (660, 'frFR', 'Le temps des paroles est terminé. Protégez Kinelory si vous tenez aux habitants de Hillsbrad.') ON DUPLICATE KEY UPDATE CompletionText='Le temps des paroles est terminé. Protégez Kinelory si vous tenez aux habitants de Hillsbrad.';
-- Quest 664 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (664, 'frFR', 'Bah, peut-être que je devrais aller tuer ces déchets naga moi-même. Il est évident que tu ne vas pas le faire.$B$BPeut-être que je peux trouver des aiguilles à tricoter pour que tu puisses t\'occuper.') ON DUPLICATE KEY UPDATE CompletionText='Bah, peut-être que je devrais aller tuer ces déchets naga moi-même. Il est évident que tu ne vas pas le faire.$B$BPeut-être que je peux trouver des aiguilles à tricoter pour que tu puisses t\'occuper.';
-- Quest 665 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (665, 'frFR', 'Ce n\'est pas le moment de parler ! Les lunettes doivent être chargées par la puissance de la pierre !') ON DUPLICATE KEY UPDATE CompletionText='Ce n\'est pas le moment de parler ! Les lunettes doivent être chargées par la puissance de la pierre !';
-- Quest 676 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (676, 'frFR', 'Je n\'ai pas le temps d\'aiguiser mon axe, et encore moins de quitter le poste pour abattre ces bêtes qui essaieraient de tuer mes proches.$B$BTu ne sembles pas avoir l\'expérience d\'un soldat, et encore moins d\'un guerrier accompli, qu\'est-ce que tu veux, $N?') ON DUPLICATE KEY UPDATE CompletionText='Je n\'ai pas le temps d\'aiguiser mon axe, et encore moins de quitter le poste pour abattre ces bêtes qui essaieraient de tuer mes proches.$B$BTu ne sembles pas avoir l\'expérience d\'un soldat, et encore moins d\'un guerrier accompli, qu\'est-ce que tu veux, $N?';
-- Quest 677 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (677, 'frFR', 'Si vous n\'avez pas encore accompli ma tâche, alors vous êtes un lâche d\'âme autant qu\'un novice en guerre.') ON DUPLICATE KEY UPDATE CompletionText='Si vous n\'avez pas encore accompli ma tâche, alors vous êtes un lâche d\'âme autant qu\'un novice en guerre.';
-- Quest 678 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (678, 'frFR', 'Vous hésitez. Pourquoi ? Vous avez montré une grande force jusqu\'à présent, $N. Ne me décevez pas maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Vous hésitez. Pourquoi ? Vous avez montré une grande force jusqu\'à présent, $N. Ne me décevez pas maintenant.';
-- Quest 681 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (681, 'frFR', '$N, à chaque heure qui passe, notre emprise sur Stromgarde devient plus précaire. Vous devez vous dépêcher ou notre ville tombera certainement.') ON DUPLICATE KEY UPDATE CompletionText='$N, à chaque heure qui passe, notre emprise sur Stromgarde devient plus précaire. Vous devez vous dépêcher ou notre ville tombera certainement.';
-- Quest 686 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (686, 'frFR', 'Alors le Roi Magni Bronzebarbe vous l\'a envoyé?$B$BOh là là ! Ça doit être important !') ON DUPLICATE KEY UPDATE RewardText='Alors le Roi Magni Bronzebarbe vous l\'a envoyé?$B$BOh là là ! Ça doit être important !';
-- Quest 700 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (700, 'frFR', 'Le granit ne semble qu\'un petit gage comparé à la vie d\'un grand nain. Mais aucun nain ne durera sur cette planète pour l\'éternité.$B$BEspérons juste que le mémorial serve de rappel à ceux qui parcourront la grande Azeroth du futur. De peur que nous n\'oublions que c\'est pour eux que des soldats courageux comme Sully Balloo ont donné leur vie si vaillamment.') ON DUPLICATE KEY UPDATE RewardText='Le granit ne semble qu\'un petit gage comparé à la vie d\'un grand nain. Mais aucun nain ne durera sur cette planète pour l\'éternité.$B$BEspérons juste que le mémorial serve de rappel à ceux qui parcourront la grande Azeroth du futur. De peur que nous n\'oublions que c\'est pour eux que des soldats courageux comme Sully Balloo ont donné leur vie si vaillamment.';

-- Quest 734 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (734, 'frFR', 'Merveilleux, merveilleux.$B$BLotwil lève les yeux vers vous un instant avant de reprendre son travail.>$B$BAllez parler à Lucien, $n. J\'ai besoin d\'un rouage n° 5. Voulez-vous bien me l\'apporter ?') ON DUPLICATE KEY UPDATE `Details`='Merveilleux, merveilleux.$B$BLotwil lève les yeux vers vous un instant avant de reprendre son travail.>$B$BAllez parler à Lucien, $n. J\'ai besoin d\'un rouage n° 5. Voulez-vous bien me l\'apporter ?';
-- Quest 739 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (739, 'frFR', 'Avez-vous des nouvelles du sort d\'Agmond ? L\'avez-vous trouvé ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous des nouvelles du sort d\'Agmond ? L\'avez-vous trouvé ?';
-- Quest 754 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (754, 'frFR', 'Ne tardez pas, $n. La souillure du Puits de Winterhoof doit être éliminée !') ON DUPLICATE KEY UPDATE CompletionText='Ne tardez pas, $n. La souillure du Puits de Winterhoof doit être éliminée !';
-- Quest 758 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (758, 'frFR', 'Le Puits d\'eau de Thunderhorn est toujours souillé, $n. Vous devez effectuer le rituel !') ON DUPLICATE KEY UPDATE CompletionText='Le Puits d\'eau de Thunderhorn est toujours souillé, $n. Vous devez effectuer le rituel !';
-- Quest 763 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (763, 'frFR', 'Qu\'est-ce qui vous amène dans mon village, $C ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui vous amène dans mon village, $C ?';
-- Quest 764 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (764, 'frFR', 'La Venture Co. a vu ses droits miniers refusés ici à Mulgore, mais il semble qu\'ils n\'acceptent pas un refus. Nous, Tauren, ne sommes pas de ceux qui mâchent leurs mots, cependant, et nous avons d\'autres moyens de faire passer notre message.') ON DUPLICATE KEY UPDATE CompletionText='La Venture Co. a vu ses droits miniers refusés ici à Mulgore, mais il semble qu\'ils n\'acceptent pas un refus. Nous, Tauren, ne sommes pas de ceux qui mâchent leurs mots, cependant, et nous avons d\'autres moyens de faire passer notre message.';
-- Quest 768 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (768, 'frFR', 'Bonjour à nouveau. Avez-vous chassé ? Avez-vous des peaux pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau. Avez-vous chassé ? Avez-vous des peaux pour moi ?';
-- Quest 778 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (778, 'frFR', 'Pas tout à fait le résultat que j\'attendais. Pourriez-vous me rendre mes menottes ?') ON DUPLICATE KEY UPDATE CompletionText='Pas tout à fait le résultat que j\'attendais. Pourriez-vous me rendre mes menottes ?';
-- Quest 779 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (779, 'frFR', 'Le Sceau de la Terre est ici, avec trois alcôves en retrait pour la Pierre Runique Améthyste, la Pierre Runique Opale et la Pierre Runique Diamant.') ON DUPLICATE KEY UPDATE CompletionText='Le Sceau de la Terre est ici, avec trois alcôves en retrait pour la Pierre Runique Améthyste, la Pierre Runique Opale et la Pierre Runique Diamant.';
-- Quest 779 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (779, 'frFR', 'Lorsque vous placez les Pierres Runiques dans les cavités correspondantes, un grondement violent secoue la terre alors que le Sceau est brisé.') ON DUPLICATE KEY UPDATE RewardText='Lorsque vous placez les Pierres Runiques dans les cavités correspondantes, un grondement violent secoue la terre alors que le Sceau est brisé.';
-- Quest 784 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (784, 'frFR', 'Vous avez vos ordres, $N. La sécurité de Durotar est en jeu. Terminez la tâche avant de vous ou suspendez votre tête dans la honte.$B$BMontrez votre honneur et défiez les humains de Tiragarde Keep.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez vos ordres, $N. La sécurité de Durotar est en jeu. Terminez la tâche avant de vous ou suspendez votre tête dans la honte.$B$BMontrez votre honneur et défiez les humains de Tiragarde Keep.';
-- Quest 786 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (786, 'frFR', 'Les centaures se sont avérés être un nuisance constante pour la Horde. Leurs intentions de mettre au siège notre patrie ne peuvent être tolérées.') ON DUPLICATE KEY UPDATE CompletionText='Les centaures se sont avérés être un nuisance constante pour la Horde. Leurs intentions de mettre au siège notre patrie ne peuvent être tolérées.';
-- Quest 787 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (787, 'frFR', 'Un autre des recrues d\'Eitrigg, hein?$B$BJe suis désolé de la situation dans laquelle nous nous trouvons si c\'est le meilleur que la Horde puisse produire. Peu importe. Au moment où nous penserons que vous êtes prêt à quitter la Vallée, vous serez un guerrier fier de la Horde.') ON DUPLICATE KEY UPDATE RewardText='Un autre des recrues d\'Eitrigg, hein?$B$BJe suis désolé de la situation dans laquelle nous nous trouvons si c\'est le meilleur que la Horde puisse produire. Peu importe. Au moment où nous penserons que vous êtes prêt à quitter la Vallée, vous serez un guerrier fier de la Horde.';
-- Quest 788 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (788, 'frFR', 'J\'espère que vous ne suis pas revenu pour essayer de me convaincre que vous avez accompli votre tâche, $N ? Non, pas du tout. Je vous en voudrais.') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que vous ne suis pas revenu pour essayer de me convaincre que vous avez accompli votre tâche, $N ? Non, pas du tout. Je vous en voudrais.';
-- Quest 792 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (792, 'frFR', 'Pour vous prouver contre la Lame Ardente, vous devez d\'abord vaincre ses Familiars Vils. Revenez-moi lorsque vous aurez fait cela.') ON DUPLICATE KEY UPDATE CompletionText='Pour vous prouver contre la Lame Ardente, vous devez d\'abord vaincre ses Familiars Vils. Revenez-moi lorsque vous aurez fait cela.';

-- Quest 794 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (794, 'frFR', 'Votre tâche est-elle terminée, $N? Avez-vous le Médaillon de la Lame Ardente?') ON DUPLICATE KEY UPDATE CompletionText='Votre tâche est-elle terminée, $N? Avez-vous le Médaillon de la Lame Ardente?';
-- Quest 795 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (795, 'frFR', 'Le Sceau de la Terre se trouve ici, avec trois alcôves en retrait pour la Pierre Runique Améthyste, la Pierre Runique Opale et la Pierre Runique Diamant.') ON DUPLICATE KEY UPDATE CompletionText='Le Sceau de la Terre se trouve ici, avec trois alcôves en retrait pour la Pierre Runique Améthyste, la Pierre Runique Opale et la Pierre Runique Diamant.';
-- Quest 795 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (795, 'frFR', 'Lorsque vous placez les Pierres Runiques dans les réceptacles correspondants, un grondement violent secoue la terre tandis que le Sceau est brisé.') ON DUPLICATE KEY UPDATE RewardText='Lorsque vous placez les Pierres Runiques dans les réceptacles correspondants, un grondement violent secoue la terre tandis que le Sceau est brisé.';
-- Quest 806 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (806, 'frFR', 'Avez-vous trouvé Fizzle, $N? Lui, et le reste de la Lame Ardente, doivent être bannis de nos terres!') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé Fizzle, $N? Lui, et le reste de la Lame Ardente, doivent être bannis de nos terres!';
-- Quest 808 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (808, 'frFR', 'Avez-vous le crâne de mon frère, $N? Est-il enfin libre?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous le crâne de mon frère, $N? Est-il enfin libre?';
-- Quest 822 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (822, 'frFR', 'Vous travaillez dur à trouver ces ingrédients, $N?') ON DUPLICATE KEY UPDATE CompletionText='Vous travaillez dur à trouver ces ingrédients, $N?';
-- Quest 822 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (822, 'frFR', 'Haha! Je savais que vous ne pourriez pas résister à cette infusion. Revenez quand vous voulez en prendre plus, <name>. Apportez-moi juste plus des ingrédients que vous avez collectés.') ON DUPLICATE KEY UPDATE RewardText='Haha! Je savais que vous ne pourriez pas résister à cette infusion. Revenez quand vous voulez en prendre plus, <name>. Apportez-moi juste plus des ingrédients que vous avez collectés.';
-- Quest 827 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (827, 'frFR', 'Êtes-vous entré dans le Rocher Crânien, $N? Avez-vous les Colliers Ardents?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous entré dans le Rocher Crânien, $N? Avez-vous les Colliers Ardents?';
-- Quest 833 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (833, 'frFR', 'Les Intrus Bristleback doivent être chassés de notre lieu de sépulture sacré, $n.') ON DUPLICATE KEY UPDATE CompletionText='Les Intrus Bristleback doivent être chassés de notre lieu de sépulture sacré, $n.';
-- Quest 835 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (835, 'frFR', 'On ne s\'y attendrait pas d\'un gars comme mon patron Gazlowe, mais il semblait toujours connaître la situation. "N\'aie pas peur de faire ce grand pas", dit-il.$B$Les Harpies ne cessent de nous déranger et les caravanes ne cessent d\'être attaquées tant que nous n\'agissons pas, hein?') ON DUPLICATE KEY UPDATE CompletionText='On ne s\'y attendrait pas d\'un gars comme mon patron Gazlowe, mais il semblait toujours connaître la situation. "N\'aie pas peur de faire ce grand pas", dit-il.$B$Les Harpies ne cessent de nous déranger et les caravanes ne cessent d\'être attaquées tant que nous n\'agissons pas, hein?';
-- Quest 837 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (837, 'frFR', 'Bien qu\'ils possèdent une certaine intelligence et une certaine organisation, je trouve constamment étonnant que les quilboars aient pu capturer et contrôler autant de territoire dans Kalimdor. Peut-être sont-ils un ennemi plus rusé que je ne le leur donne...') ON DUPLICATE KEY UPDATE CompletionText='Bien qu\'ils possèdent une certaine intelligence et une certaine organisation, je trouve constamment étonnant que les quilboars aient pu capturer et contrôler autant de territoire dans Kalimdor. Peut-être sont-ils un ennemi plus rusé que je ne le leur donne...';
-- Quest 848 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (848, 'frFR', 'Avez-vous les spores, $N? Il y a une concoction que je dois envoyer à mon associé à Thunder Bluff, qui nécessite les spores...') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les spores, $N? Il y a une concoction que je dois envoyer à mon associé à Thunder Bluff, qui nécessite les spores...';
-- Quest 849 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (849, 'frFR', 'Une fois que la machine volante des nains aura été détruite, je ressentirai la douce satisfaction de la vengeance.') ON DUPLICATE KEY UPDATE CompletionText='Une fois que la machine volante des nains aura été détruite, je ressentirai la douce satisfaction de la vengeance.';
-- Quest 849 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (849, 'frFR', 'Vous avez bien fait, <name>! Que vous soyez vénéré à Thunder Bluff comme défenseur des terres sacrées des taurens et champion de la tribu perdue.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, <name>! Que vous soyez vénéré à Thunder Bluff comme défenseur des terres sacrées des taurens et champion de la tribu perdue.';
-- Quest 861 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (861, 'frFR', 'Salutations. Il y a quelque chose en vous qui me dit beaucoup. Avons-nous des affaires, vous et moi?') ON DUPLICATE KEY UPDATE CompletionText='Salutations. Il y a quelque chose en vous qui me dit beaucoup. Avons-nous des affaires, vous et moi?';

-- Quest 862 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (862, 'frFR', 'Normalement, je n\'aime pas manger ces rongeurs quand ils sont si... si... mûrs. J\'aime les laisser pourrir quelques semaines pour vraiment faire ressortir la saveur. Mais tu as l\'air affamé.$B$BLaisse-moi te préparer un ragoût de rats de fouille. Ah, voilà.$B$BTiens !') ON DUPLICATE KEY UPDATE RewardText='Normalement, je n\'aime pas manger ces rongeurs quand ils sont si... si... mûrs. J\'aime les laisser pourrir quelques semaines pour vraiment faire ressortir la saveur. Mais tu as l\'air affamé.$B$BLaisse-moi te préparer un ragoût de rats de fouille. Ah, voilà.$B$BTiens !';
-- Quest 864 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (864, 'frFR', 'Bienvenue de retour. Au moins, bienvenue de retour si tu es revenu avec un kit de test scellé. Sinon, je ferai semblant de ne pas remarquer ton incompétence totale et je m\'abstiendrai de te maudire jusqu\'à ce que tu fasses ce qui t\'a été demandé et accomplisses ma tâche.') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue de retour. Au moins, bienvenue de retour si tu es revenu avec un kit de test scellé. Sinon, je ferai semblant de ne pas remarquer ton incompétence totale et je m\'abstiendrai de te maudire jusqu\'à ce que tu fasses ce qui t\'a été demandé et accomplisses ma tâche.';
-- Quest 864 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (864, 'frFR', 'J\'analyserai ces données immédiatement.  Peut-être que la folie de Keever sera mon génie après tout.$B$BPour toi...  tu es utile pour moi, et je récompense très bien ceux qui restent utiles.  Prends cet objet, cette pièce, et surtout mes remerciements avec eux.$B$BReviens me voir de temps en temps - je parie que notre collaboration sur ce projet n\'est pas terminée.') ON DUPLICATE KEY UPDATE RewardText='J\'analyserai ces données immédiatement.  Peut-être que la folie de Keever sera mon génie après tout.$B$BPour toi...  tu es utile pour moi, et je récompense très bien ceux qui restent utiles.  Prends cet objet, cette pièce, et surtout mes remerciements avec eux.$B$BReviens me voir de temps en temps - je parie que notre collaboration sur ce projet n\'est pas terminée.';
-- Quest 865 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (865, 'frFR', 'As-tu récupéré les cornes, $N? Ces choses vont me rapporter une fortune !') ON DUPLICATE KEY UPDATE CompletionText='As-tu récupéré les cornes, $N? Ces choses vont me rapporter une fortune !';
-- Quest 870 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (870, 'frFR', 'Es-tu allé aux Bassins Oubliés, $n? As-tu trouvé quelque chose ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé aux Bassins Oubliés, $n? As-tu trouvé quelque chose ?';
-- Quest 871 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (871, 'frFR', 'Plus il faut de temps pour arrêter ces attaques, plus il sera difficile d\'approvisionner les gens de la Croisée.') ON DUPLICATE KEY UPDATE CompletionText='Plus il faut de temps pour arrêter ces attaques, plus il sera difficile d\'approvisionner les gens de la Croisée.';
-- Quest 876 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (876, 'frFR', 'Tu n\'auras rien tant que je n\'aurai pas vu la tête de Serena.') ON DUPLICATE KEY UPDATE CompletionText='Tu n\'auras rien tant que je n\'aurai pas vu la tête de Serena.';
-- Quest 876 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (876, 'frFR', 'HA ! Bien joué, <name> ! Très bien joué... Je n\'étais pas sûr que tu étais à la hauteur de la tâche, mais tu t\'es prouvé être un vrai prédateur. Merci encore de nous avoir aidés à supprimer l\'épidémie de harpies. Voici ta récompense, utilise-la bien.') ON DUPLICATE KEY UPDATE RewardText='HA ! Bien joué, <name> ! Très bien joué... Je n\'étais pas sûr que tu étais à la hauteur de la tâche, mais tu t\'es prouvé être un vrai prédateur. Merci encore de nous avoir aidés à supprimer l\'épidémie de harpies. Voici ta récompense, utilise-la bien.';
-- Quest 877 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (877, 'frFR', 'Es-tu allé à l\'Oasis Stagnante ? Y avait-il une fissure sous ses eaux ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé à l\'Oasis Stagnante ? Y avait-il une fissure sous ses eaux ?';
-- Quest 878 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (878, 'frFR', 'Plus d\'informations <snort> pour la Horde lorsque tu auras tué les sages du Bristleback, $R. <snort> Pas un instant plus tôt ! Mangletooth n\'est pas un sot.') ON DUPLICATE KEY UPDATE CompletionText='Plus d\'informations <snort> pour la Horde lorsque tu auras tué les sages du Bristleback, $R. <snort> Pas un instant plus tôt ! Mangletooth n\'est pas un sot.';
-- Quest 879 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (879, 'frFR', 'Comment se passe ta chasse, $R? <snort>$B$BThork pense savoir qui dirige les raids contre son peuple, <snort> mais il apprendra à quel point il a tort si tu réussis.$B$BMa mort est inévitable, mais tu as causé beaucoup de douleur à mes ennemis, donc Mangletooth ne regrette rien. <snort>') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe ta chasse, $R? <snort>$B$BThork pense savoir qui dirige les raids contre son peuple, <snort> mais il apprendra à quel point il a tort si tu réussis.$B$BMa mort est inévitable, mais tu as causé beaucoup de douleur à mes ennemis, donc Mangletooth ne regrette rien. <snort>';
-- Quest 887 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (887, 'frFR', 'Je ne veux même pas penser aux profits que j\'ai perdus en piraterie, et maintenant ils installent un camp à ma porte ? Ça devient excessif, Undermine doit faire quelque chose à ce sujet.') ON DUPLICATE KEY UPDATE CompletionText='Je ne veux même pas penser aux profits que j\'ai perdus en piraterie, et maintenant ils installent un camp à ma porte ? Ça devient excessif, Undermine doit faire quelque chose à ce sujet.';
-- Quest 889 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (889, 'frFR', 'Apporte à Mangletooth 10 éclats de sang et je te bénirai d\'une grande vitesse. Tu courras avec zhevra et le vent sera jaloux de toi.$B$BCela ne durera pas longtemps, mais cela devrait suffire pour t\'aider à voyager à travers les Barrens.') ON DUPLICATE KEY UPDATE CompletionText='Apporte à Mangletooth 10 éclats de sang et je te bénirai d\'une grande vitesse. Tu courras avec zhevra et le vent sera jaloux de toi.$B$BCela ne durera pas longtemps, mais cela devrait suffire pour t\'aider à voyager à travers les Barrens.';
-- Quest 889 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (889, 'frFR', 'Bien. Va avec l\'esprit d\'Agamaggan comme guide, $R. Reviens-moi si tu désires plus des magies d\'Agamaggan.') ON DUPLICATE KEY UPDATE RewardText='Bien. Va avec l\'esprit d\'Agamaggan comme guide, $R. Reviens-moi si tu désires plus des magies d\'Agamaggan.';
-- Quest 890 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (890, 'frFR', 'Des marchandises à envoyer sur le prochain navire, $N?') ON DUPLICATE KEY UPDATE CompletionText='Des marchandises à envoyer sur le prochain navire, $N?';

-- Quest 896 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (896, 'frFR', 'Si seulement nous savions quel mineur avait trouvé l\'émeraude, ce serait un jeu d\'enfant...') ON DUPLICATE KEY UPDATE CompletionText='Si seulement nous savions quel mineur avait trouvé l\'émeraude, ce serait un jeu d\'enfant...';
-- Quest 897 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (897, 'frFR', 'Tu as l\'air préoccupé, $N. Comment se passent tes leçons dans les Barrens? As-tu trouvé quelque chose qui te trouble?') ON DUPLICATE KEY UPDATE CompletionText='Tu as l\'air préoccupé, $N. Comment se passent tes leçons dans les Barrens? As-tu trouvé quelque chose qui te trouble?';
-- Quest 897 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (897, 'frFR', 'Je ne peux rien dire de la nature de cette bête, car son esprit s\'est enfui.  Mais comme tu l\'as deviné, elle n\'appartient pas aux Barrens.  Je crains qu\'elle n\'annonce un avenir sombre pour notre peuple...$B$BMais pour l\'instant, prépare-toi, et espérons que le temps démêlera le mystère de cette créature.') ON DUPLICATE KEY UPDATE RewardText='Je ne peux rien dire de la nature de cette bête, car son esprit s\'est enfui.  Mais comme tu l\'as deviné, elle n\'appartient pas aux Barrens.  Je crains qu\'elle n\'annonce un avenir sombre pour notre peuple...$B$BMais pour l\'instant, prépare-toi, et espérons que le temps démêlera le mystère de cette créature.';
-- Quest 900 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (900, 'frFR', 'Les lumières clignotantes sur la console de contrôle indiquent que les vannes de contrôle principales n\'ont pas été fermées.') ON DUPLICATE KEY UPDATE CompletionText='Les lumières clignotantes sur la console de contrôle indiquent que les vannes de contrôle principales n\'ont pas été fermées.';
-- Quest 902 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (902, 'frFR', 'Oh, tu es de retour, $N! Tu as la samophlange?') ON DUPLICATE KEY UPDATE CompletionText='Oh, tu es de retour, $N! Tu as la samophlange?';
-- Quest 903 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (903, 'frFR', 'Comment se passe ta chasse, $N? As-tu trouvé les prédateurs?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe ta chasse, $N? As-tu trouvé les prédateurs?';
-- Quest 905 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (905, 'frFR', 'Es-tu allé aux nids, $N?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé aux nids, $N?';
-- Quest 905 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (905, 'frFR', 'Tu es allé aux nids et y as placé les plumes de ta proie. Cela a demandé un courage considérable, sans aucun doute.$B$BTe sens-tu un peu plus fort, <name>? Parce que tu as l\'air plus fort maintenant que lorsque tu es arrivé ici.  J\'imagine que les Barrens font leur travail.') ON DUPLICATE KEY UPDATE RewardText='Tu es allé aux nids et y as placé les plumes de ta proie. Cela a demandé un courage considérable, sans aucun doute.$B$BTe sens-tu un peu plus fort, <name>? Parce que tu as l\'air plus fort maintenant que lorsque tu es arrivé ici.  J\'imagine que les Barrens font leur travail.';
-- Quest 906 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (906, 'frFR', 'Tu as trouvé le chef de Razormane et l\'as tué toi-même, $N? Incroyable.$B$BI suis sans voix, mais cela ne signifie pas que je ne suis pas reconnaissant. Les habitants de la Croix-Rousse devraient respecter ta force.$B$BI dois admettre que je pensais que le chef de ces raids sur nos lignes d\'approvisionnement était un autre quilboar. Merci encore, $N.') ON DUPLICATE KEY UPDATE RewardText='Tu as trouvé le chef de Razormane et l\'as tué toi-même, $N? Incroyable.$B$BI suis sans voix, mais cela ne signifie pas que je ne suis pas reconnaissant. Les habitants de la Croix-Rousse devraient respecter ta force.$B$BI dois admettre que je pensais que le chef de ces raids sur nos lignes d\'approvisionnement était un autre quilboar. Merci encore, $N.';
-- Quest 907 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (907, 'frFR', 'Les lézards tonnerre sont-ils vaincus, $N?') ON DUPLICATE KEY UPDATE CompletionText='Les lézards tonnerre sont-ils vaincus, $N?';
-- Quest 908 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (908, 'frFR', 'As-tu réussi à localiser le cœur de fathom? Sans lui, nous n\'aurons aucune idée de ce que fait exactement le Marteau du Crépuscule là-bas.') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à localiser le cœur de fathom? Sans lui, nous n\'aurons aucune idée de ce que fait exactement le Marteau du Crépuscule là-bas.';
-- Quest 908 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (908, 'frFR', 'C\'est exactement ce dont j\'ai besoin! Un cœur de fathom est une incroyable source d\'informations dont nous pourrons tirer beaucoup de bien. Quoi que le Marteau du Crépuscule fasse là-dedans - et crois-moi quand je dis que ce n\'est pas bon - mes camarades et moi allons maintenant le découvrir.$b$bTu as bien fait aujourd\'hui; l\'Anneau de la Terre te regarde avec bienveillance pour nous avoir aidés. Tu as également aidé la Horde dans son ensemble, et pour cela, tu devrais être fier.') ON DUPLICATE KEY UPDATE RewardText='C\'est exactement ce dont j\'ai besoin! Un cœur de fathom est une incroyable source d\'informations dont nous pourrons tirer beaucoup de bien. Quoi que le Marteau du Crépuscule fasse là-dedans - et crois-moi quand je dis que ce n\'est pas bon - mes camarades et moi allons maintenant le découvrir.$b$bTu as bien fait aujourd\'hui; l\'Anneau de la Terre te regarde avec bienveillance pour nous avoir aidés. Tu as également aidé la Horde dans son ensemble, et pour cela, tu devrais être fier.';
-- Quest 909 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (909, 'frFR', 'Ah, bonjour à nouveau $N. J\'étais en train de lire les vagues de la mer, comme je le fais toujours. Qu\'est-ce qui t\'amène à ce poste avancé?') ON DUPLICATE KEY UPDATE CompletionText='Ah, bonjour à nouveau $N. J\'étais en train de lire les vagues de la mer, comme je le fais toujours. Qu\'est-ce qui t\'amène à ce poste avancé?';
-- Quest 909 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (909, 'frFR', 'Ceci... c\'est une trouvaille remarquable, $N.$b$bTu l\'as obtenu de Baron Aquanis à Blackfathom, dis-tu? Baron Aquanis a longtemps été considéré comme une puissance élémentaire corrompue; ce globe prouvera ce qui l\'a exactement corrompu. Bien qu\'il ne soit pas surprenant qu\'il s\'agisse du Marteau du Crépuscule, nos études montreront également comment ils l\'ont fait.$b$bTu as bien fait de m\'apporter ceci. S\'il te plaît - prends ceci, avec les salutations les plus chaleureuses de l\'Anneau de la Terre.') ON DUPLICATE KEY UPDATE RewardText='Ceci... c\'est une trouvaille remarquable, $N.$b$bTu l\'as obtenu de Baron Aquanis à Blackfathom, dis-tu? Baron Aquanis a longtemps été considéré comme une puissance élémentaire corrompue; ce globe prouvera ce qui l\'a exactement corrompu. Bien qu\'il ne soit pas surprenant qu\'il s\'agisse du Marteau du Crépuscule, nos études montreront également comment ils l\'ont fait.$b$bTu as bien fait de m\'apporter ceci. S\'il te plaît - prends ceci, avec les salutations les plus chaleureuses de l\'Anneau de la Terre.';
-- Quest 911 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (911, 'frFR', 'Wow, Ashenvale est là que se passe la vraie aventure! As-tu déjà combattu dans Ashenvale, $N? Quand je deviendrai un héros quand je serai grand, je veux venir à Ashenvale et me battre pour la gloire de la Horde!$B$BMerci de m\'avoir emmené à la frontière, $N. Tu es le meilleur!') ON DUPLICATE KEY UPDATE RewardText='Wow, Ashenvale est là que se passe la vraie aventure! As-tu déjà combattu dans Ashenvale, $N? Quand je deviendrai un héros quand je serai grand, je veux venir à Ashenvale et me battre pour la gloire de la Horde!$B$BMerci de m\'avoir emmené à la frontière, $N. Tu es le meilleur!';

-- Quest 915 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (915, 'frFR', 'Je souhaite qu\'ils fassent plus de saveurs de crème glacée que la fraise, mais je suppose que j\'ai de la chance que la fraise soit ma préférée !') ON DUPLICATE KEY UPDATE CompletionText='Je souhaite qu\'ils fassent plus de saveurs de crème glacée que la fraise, mais je suppose que j\'ai de la chance que la fraise soit ma préférée !';
-- Quest 916 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (916, 'frFR', 'As-tu ramassé les sacs de venin, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu ramassé les sacs de venin, $N?';
-- Quest 917 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (917, 'frFR', 'Es-tu entré dans la Grotte du Fil d\'Ombre, $N? As-tu trouvé un œuf d\'araignée?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu entré dans la Grotte du Fil d\'Ombre, $N? As-tu trouvé un œuf d\'araignée?';
-- Quest 920 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (920, 'frFR', 'Ah, <name>. J\'espérais que vous répondriez promptement à mon appel. J\'ai une tâche importante que je voudrais que vous accomplissiez.') ON DUPLICATE KEY UPDATE RewardText='Ah, <name>. J\'espérais que vous répondriez promptement à mon appel. J\'ai une tâche importante que je voudrais que vous accomplissiez.';
-- Quest 923 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (923, 'frFR', 'Es-tu allé au Lac de la Source, $N? As-tu chassé les jeunes arbres là-bas?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé au Lac de la Source, $N? As-tu chassé les jeunes arbres là-bas?';
-- Quest 924 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (924, 'frFR', 'La Semence Démoniaque existe toujours. Je peux sentir son pouvoir...') ON DUPLICATE KEY UPDATE CompletionText='La Semence Démoniaque existe toujours. Je peux sentir son pouvoir...';
-- Quest 925 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (925, 'frFR', 'Quand les orcs étaient seuls et sans amis, les taurens les ont accueillis dans une étrange terre et ont partagé avec eux sans rien demander en retour. C\'est ça l\'honneur, $N.') ON DUPLICATE KEY UPDATE CompletionText='Quand les orcs étaient seuls et sans amis, les taurens les ont accueillis dans une étrange terre et ont partagé avec eux sans rien demander en retour. C\'est ça l\'honneur, $N.';
-- Quest 926 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (926, 'frFR', 'Ces pierres sont infusées d\'énergie magique, mais intentionnellement imparfaites. Elles sont très instables et une fois retirées de la table, elles s\'autodétruiront rapidement.') ON DUPLICATE KEY UPDATE RewardText='Ces pierres sont infusées d\'énergie magique, mais intentionnellement imparfaites. Elles sont très instables et une fois retirées de la table, elles s\'autodétruiront rapidement.';
-- Quest 934 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (934, 'frFR', 'Avec les druides, l\'Arbre Oracle et l\'Archidruide ont surveillé attentivement la croissance de Teldrassil. Mais même si nous avons un nouveau foyer, nos vies immortelles n\'ont pas été restaurées.') ON DUPLICATE KEY UPDATE CompletionText='Avec les druides, l\'Arbre Oracle et l\'Archidruide ont surveillé attentivement la croissance de Teldrassil. Mais même si nous avons un nouveau foyer, nos vies immortelles n\'ont pas été restaurées.';
-- Quest 934 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (934, 'frFR', 'Être en présence de l\'Arbre Oracle... c\'est presque sentir la sagesse prendre forme. Laissez-moi continuer le récit...$B$Avec Teldrassil en croissance, l\'Archidruide $c s\'est approché des dragons pour leurs bénédictions, comme les dragons avaient fait sur Nordrassil autrefois. Mais Nozdormu, Seigneur du Temps, a refusé de donner sa bénédiction, réprimandant le $c pour son arrogance. En accord avec Nozdormu, Alexstrasza a également refusé Staghelm, et sans sa bénédiction, la croissance de Teldrassil a été imparfaite et imprévisible...') ON DUPLICATE KEY UPDATE RewardText='Être en présence de l\'Arbre Oracle... c\'est presque sentir la sagesse prendre forme. Laissez-moi continuer le récit...$B$Avec Teldrassil en croissance, l\'Archidruide $c s\'est approché des dragons pour leurs bénédictions, comme les dragons avaient fait sur Nordrassil autrefois. Mais Nozdormu, Seigneur du Temps, a refusé de donner sa bénédiction, réprimandant le $c pour son arrogance. En accord avec Nozdormu, Alexstrasza a également refusé Staghelm, et sans sa bénédiction, la croissance de Teldrassil a été imparfaite et imprévisible...';
-- Quest 936 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (936, 'frFR', 'Salutations, $C; je suis heureux que vous soyez intéressé à aider nos recherches. Il y a beaucoup à faire, et je vous ferais un tort si je vous disais que le travail que cela implique n\'est pas dangereux. J\'espère que cela ne vous effrayera pas... mais à vous voir, je suppose que le danger est quelque chose avec quoi vous avez déjà fait affaire.') ON DUPLICATE KEY UPDATE RewardText='Salutations, $C; je suis heureux que vous soyez intéressé à aider nos recherches. Il y a beaucoup à faire, et je vous ferais un tort si je vous disais que le travail que cela implique n\'est pas dangereux. J\'espère que cela ne vous effrayera pas... mais à vous voir, je suppose que le danger est quelque chose avec quoi vous avez déjà fait affaire.';
-- Quest 938 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (938, 'frFR', 'Brume... C\'était ma faute ! Les sorcières m\'ont pris au dépourvu... Je ne devais pas les laisser vous prendre...') ON DUPLICATE KEY UPDATE CompletionText='Brume... C\'était ma faute ! Les sorcières m\'ont pris au dépourvu... Je ne devais pas les laisser vous prendre...';
-- Quest 938 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (938, 'frFR', 'Oh, merci, <name>! J\'avais peur de ne plus jamais revoir Mist, ne connaissant que sa mort dans mon cœur, jamais uni à mon fidèle compagnon. Je vous dois plus que vous ne pouvez le savoir, et vous avez ma gratitude éternelle.') ON DUPLICATE KEY UPDATE RewardText='Oh, merci, <name>! J\'avais peur de ne plus jamais revoir Mist, ne connaissant que sa mort dans mon cœur, jamais uni à mon fidèle compagnon. Je vous dois plus que vous ne pouvez le savoir, et vous avez ma gratitude éternelle.';
-- Quest 939 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (939, 'frFR', 'Qu\'y a-t-il, $C? Vous avez l\'air préoccupé.') ON DUPLICATE KEY UPDATE CompletionText='Qu\'y a-t-il, $C? Vous avez l\'air préoccupé.';
-- Quest 943 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (943, 'frFR', 'Avec la Pierre de Relu, je pourrai libérer les secrets cachés de mon fossile ainsi que celui de Remtravel de Darkshore, $N.') ON DUPLICATE KEY UPDATE CompletionText='Avec la Pierre de Relu, je pourrai libérer les secrets cachés de mon fossile ainsi que celui de Remtravel de Darkshore, $N.';

-- Quest 943 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (943, 'frFR', 'Excellent, <name>!$B$BMaintenant, voyons si je peux utiliser la pierre pour déchiffrer les pouvoirs des fossiles.') ON DUPLICATE KEY UPDATE RewardText='Excellent, <name>!$B$BMaintenant, voyons si je peux utiliser la pierre pour déchiffrer les pouvoirs des fossiles.';
-- Quest 944 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (944, 'frFR', 'La Glaive du Maître, $N.$B$BVa-y, puis parle-moi à nouveau.') ON DUPLICATE KEY UPDATE CompletionText='La Glaive du Maître, $N.$B$BVa-y, puis parle-moi à nouveau.';
-- Quest 947 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (947, 'frFR', 'As-tu mes champignons, $N? Es-tu allé dans la caverne?') ON DUPLICATE KEY UPDATE CompletionText='As-tu mes champignons, $N? Es-tu allé dans la caverne?';
-- Quest 953 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (953, 'frFR', 'Quand tu auras étudié les tablettes et appris de la chute d\'Ameth\'Aran, j\'emporterai la connaissance à Auberdine, et j\'informerai le Cercle des Anciens.') ON DUPLICATE KEY UPDATE CompletionText='Quand tu auras étudié les tablettes et appris de la chute d\'Ameth\'Aran, j\'emporterai la connaissance à Auberdine, et j\'informerai le Cercle des Anciens.';
-- Quest 957 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (957, 'frFR', 'En vérité, $N, j\'ai peur... Peur que ton arrivée--tout ceci--ne soit simplement un produit de l\'esprit d\'un esprit dérangé. Peux-tu connaître la torture que c\'est ? Je... S\'il te plaît, tu dois partir vite.') ON DUPLICATE KEY UPDATE CompletionText='En vérité, $N, j\'ai peur... Peur que ton arrivée--tout ceci--ne soit simplement un produit de l\'esprit d\'un esprit dérangé. Peux-tu connaître la torture que c\'est ? Je... S\'il te plaît, tu dois partir vite.';
-- Quest 957 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (957, 'frFR', 'Je suis libre, <name>! Je peux maintenant voir de mes propres yeux les changements qui sont venus à notre monde... Seulement des morceaux et des pièces j\'ai connus. Penser qu\'au moment où j\'ai marché librement pour la dernière fois, le Puits était toujours là et les Hauts-Nés tenaient cour avec Azshara, notre chère reine.$B$BJe sens que mon geôlier, mon ancien maître, Athrikus, vit toujours... Déjà mes sentiments de désespoir cèderont à des pensées de vengeance.') ON DUPLICATE KEY UPDATE RewardText='Je suis libre, <name>! Je peux maintenant voir de mes propres yeux les changements qui sont venus à notre monde... Seulement des morceaux et des pièces j\'ai connus. Penser qu\'au moment où j\'ai marché librement pour la dernière fois, le Puits était toujours là et les Hauts-Nés tenaient cour avec Azshara, notre chère reine.$B$BJe sens que mon geôlier, mon ancien maître, Athrikus, vit toujours... Déjà mes sentiments de désespoir cèderont à des pensées de vengeance.';
-- Quest 961 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (961, 'frFR', 'La découverte des cultistes de la Marteau du Crépuscule est troublante. Je dois méditer sur leurs intentions...$B$BQuand tu auras plus d\'informations, parle-moi à travers un bol de divination. Si tu as besoin d\'une fiole de divination pour créer un bol, alors... voici une autre.') ON DUPLICATE KEY UPDATE RewardText='La découverte des cultistes de la Marteau du Crépuscule est troublante. Je dois méditer sur leurs intentions...$B$BQuand tu auras plus d\'informations, parle-moi à travers un bol de divination. Si tu as besoin d\'une fiole de divination pour créer un bol, alors... voici une autre.';
-- Quest 964 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (964, 'frFR', 'Tue beaucoup et tue souvent, $C - nous aurons besoin d\'un bon approvisionnement de fragments squelettiques appropriés pour former la couche extérieure de la clé. Ils n\'appellent pas ça une Clé Squelette pour rien, tu sais.') ON DUPLICATE KEY UPDATE CompletionText='Tue beaucoup et tue souvent, $C - nous aurons besoin d\'un bon approvisionnement de fragments squelettiques appropriés pour former la couche extérieure de la clé. Ils n\'appellent pas ça une Clé Squelette pour rien, tu sais.';
-- Quest 964 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (964, 'frFR', 'Ça marchera, $N! Mon tour maintenant - je vais imprégner ceci d\'une trempe appropriée qui leur permettra de survivre au processus de forge intense qu\'ils subiront éventuellement.$b$bL\'étape suivante sera d\'obtenir un moule approprié pour la clé. Je connais un forgeron gobelin à Tanaris qui a fait par le passé des moules pour des objets tout aussi macabres. Il travaille pour qui les gobelins travaillent habituellement - le plus offrant.') ON DUPLICATE KEY UPDATE RewardText='Ça marchera, $N! Mon tour maintenant - je vais imprégner ceci d\'une trempe appropriée qui leur permettra de survivre au processus de forge intense qu\'ils subiront éventuellement.$b$bL\'étape suivante sera d\'obtenir un moule approprié pour la clé. Je connais un forgeron gobelin à Tanaris qui a fait par le passé des moules pour des objets tout aussi macabres. Il travaille pour qui les gobelins travaillent habituellement - le plus offrant.';
-- Quest 967 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (967, 'frFR', 'Tu as des affaires avec moi, $C?') ON DUPLICATE KEY UPDATE CompletionText='Tu as des affaires avec moi, $C?';
-- Quest 968 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (968, 'frFR', 'Bonjour, $Gsir:madam;.$B$BPuis-je vous intéresser à l\'un de mes tomes ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $Gsir:madam;.$B$BPuis-je vous intéresser à l\'un de mes tomes ?';
-- Quest 968 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (968, 'frFR', 'Ah, une copie de Les Pouvoirs Inférieurs. Un texte intéressant, c\'est ça. Et certains pourraient le trouver utile...$B$BMais celui-ci est en mauvais état. Et regarde ici ! Il y a des notes dans la marge de presque chaque page !$B$BHm... Je connais ce exemplaire. Je l\'ai vendu à Bolgar l\'année dernière. Es-tu... un ami de lui ? Oui, je pensais que tu l\'étais. Tu as ce même feu dans tes yeux !$B$BEh bien, par définition, un ami de Bolgar est un ami à moi. Et nous prenons soin des nôtres, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE RewardText='Ah, une copie de Les Pouvoirs Inférieurs. Un texte intéressant, c\'est ça. Et certains pourraient le trouver utile...$B$BMais celui-ci est en mauvais état. Et regarde ici ! Il y a des notes dans la marge de presque chaque page !$B$BHm... Je connais ce exemplaire. Je l\'ai vendu à Bolgar l\'année dernière. Es-tu... un ami de lui ? Oui, je pensais que tu l\'étais. Tu as ce même feu dans tes yeux !$B$BEh bien, par définition, un ami de Bolgar est un ami à moi. Et nous prenons soin des nôtres, n\'est-ce pas ?';
-- Quest 972 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (972, 'frFR', 'Prends la sève d\'eau sapta et trouve le bassin d\'eau corrompu à Silverpine, $N. J\'ai une grande foi en tes capacités.') ON DUPLICATE KEY UPDATE RewardText='Prends la sève d\'eau sapta et trouve le bassin d\'eau corrompu à Silverpine, $N. J\'ai une grande foi en tes capacités.';
-- Quest 976 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (976, 'frFR', 'Les Sentinelles ont un grand besoin de fournitures pour se renforcer dans Darkshore.') ON DUPLICATE KEY UPDATE CompletionText='Les Sentinelles ont un grand besoin de fournitures pour se renforcer dans Darkshore.';
-- Quest 978 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (978, 'frFR', 'D\'où pourraient provenir ces pouvoirs ? Je pense que nous sommes sur la bonne voie pour trouver la réponse, $N.') ON DUPLICATE KEY UPDATE CompletionText='D\'où pourraient provenir ces pouvoirs ? Je pense que nous sommes sur la bonne voie pour trouver la réponse, $N.';

-- Quest 985 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (985, 'frFR', 'Ne retiens pas ta main de ce qui doit être fait, enfant. Je sais à quel point l\'idée de tuer les créatures de la forêt doit être répugnante, mais dans ce cas, c\'est nécessaire. Aucune guérison n\'a été découverte pour la corruption qui s\'est répandue dans la forêt, et nous devons faire ce que nous pouvons pour en arrêter le progrès jusqu\'à ce qu\'une soit trouvée.') ON DUPLICATE KEY UPDATE CompletionText='Ne retiens pas ta main de ce qui doit être fait, enfant. Je sais à quel point l\'idée de tuer les créatures de la forêt doit être répugnante, mais dans ce cas, c\'est nécessaire. Aucune guérison n\'a été découverte pour la corruption qui s\'est répandue dans la forêt, et nous devons faire ce que nous pouvons pour en arrêter le progrès jusqu\'à ce qu\'une soit trouvée.';
-- Quest 992 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (992, 'frFR', 'Bienvenue de retour, Inspecteur Junior $n$ ! Avez-vous terminé votre mission ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue de retour, Inspecteur Junior $n$ ! Avez-vous terminé votre mission ?';
-- Quest 995 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (995, 'frFR', '<name>! Je suis ravi de voir que vous êtes revenu avec succès. Votre aide à Volcor m\'a donné l\'espoir que nous pouvons surmonter les défis qui nous attendent ici à Darkshore et au-delà.') ON DUPLICATE KEY UPDATE RewardText='<name>! Je suis ravi de voir que vous êtes revenu avec succès. Votre aide à Volcor m\'a donné l\'espoir que nous pouvons surmonter les défis qui nous attendent ici à Darkshore et au-delà.';
-- Quest 996 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (996, 'frFR', 'Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur de vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention pour être ramenée à la normale.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur de vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention pour être ramenée à la normale.';
-- Quest 996 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (996, 'frFR', 'Vous appliquez deux onguents de plante de Cenarion à la fleur de vent. Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez deux onguents de plante de Cenarion à la fleur de vent. Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
-- Quest 998 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (998, 'frFR', 'Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur de vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention pour être ramenée à la normale.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur de vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention pour être ramenée à la normale.';
-- Quest 998 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (998, 'frFR', 'Vous appliquez deux onguents de plante de Cenarion à la fleur de vent. Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez deux onguents de plante de Cenarion à la fleur de vent. Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
-- Quest 1000 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1000, 'frFR', 'Salutations, $C.$B$BI suis ravi de voir que des gens comme vous s\'intéressent au bien-être de la nature ; des récits de vos exploits héroïques vous précèdent, et vous êtes le bienvenu ici. Vous voir devant moi instille le sentiment de confiance que le Cercle de Cenarion recevra l\'aide appropriée dont il a besoin.$B$BNotre lien avec le Cercle de Cenarion à Moonglade transcende les divisions raciales et politiques. Souvenez-vous-en lorsque vous agissez au nom du Cercle, et vous réussirez bien.') ON DUPLICATE KEY UPDATE RewardText='Salutations, $C.$B$BI suis ravi de voir que des gens comme vous s\'intéressent au bien-être de la nature ; des récits de vos exploits héroïques vous précèdent, et vous êtes le bienvenu ici. Vous voir devant moi instille le sentiment de confiance que le Cercle de Cenarion recevra l\'aide appropriée dont il a besoin.$B$BNotre lien avec le Cercle de Cenarion à Moonglade transcende les divisions raciales et politiques. Souvenez-vous-en lorsque vous agissez au nom du Cercle, et vous réussirez bien.';
-- Quest 1004 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1004, 'frFR', 'Salutations, $C.$B$BI suis ravi de voir que des gens comme vous s\'intéressent au bien-être de la nature ; des récits de vos exploits héroïques vous précèdent, et vous êtes le bienvenu ici. Vous voir devant moi instille le sentiment de confiance que le Cercle de Cenarion recevra l\'aide appropriée dont il a besoin.$B$BNotre lien avec le Cercle de Cenarion à Moonglade transcende les divisions raciales et politiques. Souvenez-vous-en lorsque vous agissez au nom du Cercle, et vous réussirez bien.') ON DUPLICATE KEY UPDATE RewardText='Salutations, $C.$B$BI suis ravi de voir que des gens comme vous s\'intéressent au bien-être de la nature ; des récits de vos exploits héroïques vous précèdent, et vous êtes le bienvenu ici. Vous voir devant moi instille le sentiment de confiance que le Cercle de Cenarion recevra l\'aide appropriée dont il a besoin.$B$BNotre lien avec le Cercle de Cenarion à Moonglade transcende les divisions raciales et politiques. Souvenez-vous-en lorsque vous agissez au nom du Cercle, et vous réussirez bien.';
-- Quest 1007 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1007, 'frFR', 'Avez-vous trouvé la statuette, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé la statuette, $N$?';
-- Quest 1007 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1007, 'frFR', 'Vous l\'avez trouvée !  Merci, <name>!$B$BLa vieille ville de Zoram recèle de nombreux secrets, et cette statuette pourrait être la clé de beaucoup d\'entre eux.') ON DUPLICATE KEY UPDATE RewardText='Vous l\'avez trouvée !  Merci, <name>!$B$BLa vieille ville de Zoram recèle de nombreux secrets, et cette statuette pourrait être la clé de beaucoup d\'entre eux.';
-- Quest 1009 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1009, 'frFR', 'On dit que l\'Anneau de Zoram est la clé de tout verrou dans la ville. L\'avez-vous, $N$?') ON DUPLICATE KEY UPDATE CompletionText='On dit que l\'Anneau de Zoram est la clé de tout verrou dans la ville. L\'avez-vous, $N$?';
-- Quest 1009 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1009, 'frFR', 'Vous avez trouvé l\'anneau !  Merci, <name>.  Veuillez accepter ceci comme paiement, et sachez que vos actions d\'aujourd\'hui resteront à jamais dans ma mémoire.') ON DUPLICATE KEY UPDATE RewardText='Vous avez trouvé l\'anneau !  Merci, <name>.  Veuillez accepter ceci comme paiement, et sachez que vos actions d\'aujourd\'hui resteront à jamais dans ma mémoire.';
-- Quest 1011 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1011, 'frFR', 'Avez-vous trouvé le camp, $N$? Avez-vous une bouteille de maladie ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé le camp, $N$? Avez-vous une bouteille de maladie ?';
-- Quest 1012 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1012, 'frFR', 'L\'angoisse des druides de Dor\'danil hante toujours mes rêves, $N$. Vous devez détruire leurs chefs !') ON DUPLICATE KEY UPDATE CompletionText='L\'angoisse des druides de Dor\'danil hante toujours mes rêves, $N$. Vous devez détruire leurs chefs !';

-- Quest 1018 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1018, 'frFR', 'Je suis ravi de voir des gens comme vous s\'intéresser au bien-être de la nature ; des récits de vos exploits mûrs vous précèdent, et vous êtes le bienvenu ici. Vous voir devant moi me donne le sentiment que le Cercle de Cenarion recevra l\'aide qu\'il mérite.$B$BNotre lien avec le Cercle de Cenarion à Moonglade transcende les divisions raciales et politiques. Souvenez-vous-en lorsque vous agirez au nom du Cercle, et vous réussirez.') ON DUPLICATE KEY UPDATE RewardText='Je suis ravi de voir des gens comme vous s\'intéresser au bien-être de la nature ; des récits de vos exploits mûrs vous précèdent, et vous êtes le bienvenu ici. Vous voir devant moi me donne le sentiment que le Cercle de Cenarion recevra l\'aide qu\'il mérite.$B$BNotre lien avec le Cercle de Cenarion à Moonglade transcende les divisions raciales et politiques. Souvenez-vous-en lorsque vous agirez au nom du Cercle, et vous réussirez.';
-- Quest 1019 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1019, 'frFR', 'Qu\'est-ce qui vous fait penser que je souhaite être importuné par des gens comme vous, $C? Attendez - laissez-moi arrêter les devoirs importants auxquels j\'assiste quotidiennement pour pouvoir vous aider à localiser un bibelot quelque part. Soyez assuré que le bien-être de Darnassus - non, de tout Teldrassil - doit passer après l\'acquisition d\'un bibelot pour votre collection.$B$BLes imbéciles de Moonglade me font perdre mon temps avec leur appel à l\'aide, et je dois endurer ça maintenant ?') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce qui vous fait penser que je souhaite être importuné par des gens comme vous, $C? Attendez - laissez-moi arrêter les devoirs importants auxquels j\'assiste quotidiennement pour pouvoir vous aider à localiser un bibelot quelque part. Soyez assuré que le bien-être de Darnassus - non, de tout Teldrassil - doit passer après l\'acquisition d\'un bibelot pour votre collection.$B$BLes imbéciles de Moonglade me font perdre mon temps avec leur appel à l\'aide, et je dois endurer ça maintenant ?';
-- Quest 1022 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1022, 'frFR', 'Le tome du sanctuaire est un objet mystérieux. Ce n\'est pas un livre au sens traditionnel. Les feuilles du tome ont été bénies par Mel\'Thandris elle-même, et enregistrent des événements importants dans ses pages.$B$BIl m\'est difficile de l\'expliquer. Si vous allez au sanctuaire, vous comprendrez.') ON DUPLICATE KEY UPDATE CompletionText='Le tome du sanctuaire est un objet mystérieux. Ce n\'est pas un livre au sens traditionnel. Les feuilles du tome ont été bénies par Mel\'Thandris elle-même, et enregistrent des événements importants dans ses pages.$B$BIl m\'est difficile de l\'expliquer. Si vous allez au sanctuaire, vous comprendrez.';
-- Quest 1025 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1025, 'frFR', 'Les furbolg n\'ont pas toujours été notre ennemi, $N. Mais les temps changent, et ce n\'est plus une période de paix ici dans ces bois sombres.') ON DUPLICATE KEY UPDATE CompletionText='Les furbolg n\'ont pas toujours été notre ennemi, $N. Mais les temps changent, et ce n\'est plus une période de paix ici dans ces bois sombres.';
-- Quest 1027 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1027, 'frFR', 'As-tu trouvé la dernière pièce de la tige, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé la dernière pièce de la tige, $N?';
-- Quest 1027 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1027, 'frFR', 'Tu as trouvé la dernière pièce ? Merveilleux pour toi... et pour Raene.$B$BJe suppose qu\'on va devoir s\'occuper de la réparer, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE RewardText='Tu as trouvé la dernière pièce ? Merveilleux pour toi... et pour Raene.$B$BJe suppose qu\'on va devoir s\'occuper de la réparer, n\'est-ce pas ?';
-- Quest 1036 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1036, 'frFR', 'Avast ye, scallywag.  J\'entends que tu es le genre pour un peu de malfraternité.  Eh bien, si tu n\'es pas un ami de Booty Bay, alors tu pourrais avoir une place spéciale avec les Buccaneers de Bloodsail.$B$BArrrrr...') ON DUPLICATE KEY UPDATE RewardText='Avast ye, scallywag.  J\'entends que tu es le genre pour un peu de malfraternité.  Eh bien, si tu n\'es pas un ami de Booty Bay, alors tu pourrais avoir une place spéciale avec les Buccaneers de Bloodsail.$B$BArrrrr...';
-- Quest 1043 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1043, 'frFR', 'Les bois sont périlleux pour les non préparés. Gardez vos armes à portée de main et votre esprit encore plus près, sinon votre prochaine voyage dans la forêt hantée pourrait être votre dernier.') ON DUPLICATE KEY UPDATE CompletionText='Les bois sont périlleux pour les non préparés. Gardez vos armes à portée de main et votre esprit encore plus près, sinon votre prochaine voyage dans la forêt hantée pourrait être votre dernier.';
-- Quest 1045 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1045, 'frFR', 'As-tu tué Ran, mon ami?$B$Même les elfes de la nuit ne méritent pas vraiment sa colère. Sa haine brûle encore plus fort que la mienne, mais son esprit n\'est plus le sien. Il est une menace pour toutes les créatures naturelles de cette forêt.') ON DUPLICATE KEY UPDATE CompletionText='As-tu tué Ran, mon ami?$B$Même les elfes de la nuit ne méritent pas vraiment sa colère. Sa haine brûle encore plus fort que la mienne, mais son esprit n\'est plus le sien. Il est une menace pour toutes les créatures naturelles de cette forêt.';
-- Quest 1047 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1047, 'frFR', 'Qu\'est-ce qui vous fait penser que je souhaite être importuné par des gens comme vous, $C? Attendez - laissez-moi arrêter les devoirs importants auxquels j\'assiste quotidiennement pour pouvoir vous aider à localiser un bibelot quelque part. Soyez assuré que le bien-être de Darnassus - non, de tout Teldrassil - doit passer après l\'acquisition d\'un bibelot pour votre collection.$B$BLes imbéciles de Moonglade me font perdre mon temps avec leur appel à l\'aide, et je dois endurer ça maintenant ?') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce qui vous fait penser que je souhaite être importuné par des gens comme vous, $C? Attendez - laissez-moi arrêter les devoirs importants auxquels j\'assiste quotidiennement pour pouvoir vous aider à localiser un bibelot quelque part. Soyez assuré que le bien-être de Darnassus - non, de tout Teldrassil - doit passer après l\'acquisition d\'un bibelot pour votre collection.$B$BLes imbéciles de Moonglade me font perdre mon temps avec leur appel à l\'aide, et je dois endurer ça maintenant ?';
-- Quest 1048 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1048, 'frFR', 'Peut-être n\'ai-je pas été explicite dans mes ordres, $c. Je veux que l\'Inquisiteur en Chef Whitemane soit tué une fois pour toutes. Et pendant que tu y es, élimine son haut brassage aussi.$B$BTue ce zélote, le Commandant Scarlet Mograine. Fais disparaître Herod, le Champion Scarlet. Et massacre aussi Houndmaster Loksey et ses saletés.$B$BMaintenant, disparais !') ON DUPLICATE KEY UPDATE CompletionText='Peut-être n\'ai-je pas été explicite dans mes ordres, $c. Je veux que l\'Inquisiteur en Chef Whitemane soit tué une fois pour toutes. Et pendant que tu y es, élimine son haut brassage aussi.$B$BTue ce zélote, le Commandant Scarlet Mograine. Fais disparaître Herod, le Champion Scarlet. Et massacre aussi Houndmaster Loksey et ses saletés.$B$BMaintenant, disparais !';
-- Quest 1052 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1052, 'frFR', 'Qui va là ? Qu\'est-ce que tu veux de moi ?') ON DUPLICATE KEY UPDATE CompletionText='Qui va là ? Qu\'est-ce que tu veux de moi ?';
-- Quest 1053 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1053, 'frFR', 'La corruption dans le Monastère ne cessera pas tant que les plus hauts responsables n\'auront pas été retirés.$b$bAu nom de la Lumière, tue l\'Inquisiteur en Chef Whitemane, le Commandant Scarlet Mograine, Herod, le Champion Scarlet et Houndmaster Loksey. Une fois qu\'ils seront tombés, peut-être que la vraie cause pourra être rallumée. D\'ici là, quiconque croise le chemin de la Croisade est en danger.$b$bSors de Southshore et fais-le !') ON DUPLICATE KEY UPDATE CompletionText='La corruption dans le Monastère ne cessera pas tant que les plus hauts responsables n\'auront pas été retirés.$b$bAu nom de la Lumière, tue l\'Inquisiteur en Chef Whitemane, le Commandant Scarlet Mograine, Herod, le Champion Scarlet et Houndmaster Loksey. Une fois qu\'ils seront tombés, peut-être que la vraie cause pourra être rallumée. D\'ici là, quiconque croise le chemin de la Croisade est en danger.$b$bSors de Southshore et fais-le !';
-- Quest 1057 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1057, 'frFR', 'Il y a beaucoup de travail à faire avant que la Vallée des Brûlés puisse être restaurée à la forêt luxuriante qu\'elle était.$B$BNettoie la zone de ces menaces maudites, $N! Ce n\'est qu\'alors que nous pourrons commencer à récupérer ce qui appartient à la nature.') ON DUPLICATE KEY UPDATE CompletionText='Il y a beaucoup de travail à faire avant que la Vallée des Brûlés puisse être restaurée à la forêt luxuriante qu\'elle était.$B$BNettoie la zone de ces menaces maudites, $N! Ce n\'est qu\'alors que nous pourrons commencer à récupérer ce qui appartient à la nature.';
-- Quest 1062 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1062, 'frFR', 'La Vallée du Grand Bois se trouve au nord-ouest, $N. Pars. Inspire la peur à ceux qui voudraient piller cette terre !') ON DUPLICATE KEY UPDATE CompletionText='La Vallée du Grand Bois se trouve au nord-ouest, $N. Pars. Inspire la peur à ceux qui voudraient piller cette terre !';

-- Quest 1067 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1067, 'frFR', 'Vous êtes revenu, $N$. Apportez-vous une aide d\'Apothecary Lydon ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu, $N$. Apportez-vous une aide d\'Apothecary Lydon ?';
-- Quest 1067 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1067, 'frFR', 'Un toxine d\'Apothecary Lydon ? Très bien. Si je connais Lydon, alors ce toxine sera très efficace contre la Venture Company...') ON DUPLICATE KEY UPDATE RewardText='Un toxine d\'Apothecary Lydon ? Très bien. Si je connais Lydon, alors ce toxine sera très efficace contre la Venture Company...';
-- Quest 1068 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1068, 'frFR', 'Les esprits des arbres pleurent la perte de leurs frères, $N$. Vous devez détruire les shredders XT:4 et XT:9, sinon je crains que Stonetalon ne guérisse jamais.') ON DUPLICATE KEY UPDATE CompletionText='Les esprits des arbres pleurent la perte de leurs frères, $N$. Vous devez détruire les shredders XT:4 et XT:9, sinon je crains que Stonetalon ne guérisse jamais.';
-- Quest 1069 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1069, 'frFR', 'Avez-vous eu les œufs, $N$ ? J\'ai déjà fait un accord de livraison avec Wharfmaster Dizzywig !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous eu les œufs, $N$ ? J\'ai déjà fait un accord de livraison avec Wharfmaster Dizzywig !';
-- Quest 1071 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1071, 'frFR', 'Comment se passe la bataille de votre côté, $N$ ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe la bataille de votre côté, $N$ ?';
-- Quest 1077 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1077, 'frFR', 'Haha ! tu es de retour ! Tu l\'as ? Tu as le sort ?') ON DUPLICATE KEY UPDATE CompletionText='Haha ! tu es de retour ! Tu l\'as ? Tu as le sort ?';
-- Quest 1077 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1077, 'frFR', 'C\'est parfait, $N$ ! Bien joué.$B$BCe sort, mélangé avec le NG-5, fera un explosif à distance parfait.$B$BNous serons capables de créer la distraction parfaite pour que tu puisses te faufiler et voler les lettres et les plans d\'ingénierie de la Venture Co.$B$BCela ralentira certainement leurs actes de déforestation.') ON DUPLICATE KEY UPDATE RewardText='C\'est parfait, $N$ ! Bien joué.$B$BCe sort, mélangé avec le NG-5, fera un explosif à distance parfait.$B$BNous serons capables de créer la distraction parfaite pour que tu puisses te faufiler et voler les lettres et les plans d\'ingénierie de la Venture Co.$B$BCela ralentira certainement leurs actes de déforestation.';
-- Quest 1079 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1079, 'frFR', 'Vraiment incroyable ! C\'est un coup énorme porté à la Venture Co.$B$BNous serons capables de trouver des faiblesses dans leurs machines et d\'intégrer leurs conceptions dans nos propres créations. C\'est un jour merveilleux, en vérité.') ON DUPLICATE KEY UPDATE RewardText='Vraiment incroyable ! C\'est un coup énorme porté à la Venture Co.$B$BNous serons capables de trouver des faiblesses dans leurs machines et d\'intégrer leurs conceptions dans nos propres créations. C\'est un jour merveilleux, en vérité.';
-- Quest 1080 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1080, 'frFR', 'Incroyable, <name> ! Kaela et les Sentinelles seront si heureuses. Avec ton talent et mes créations, nous sommes imparables.') ON DUPLICATE KEY UPDATE RewardText='Incroyable, <name> ! Kaela et les Sentinelles seront si heureuses. Avec ton talent et mes créations, nous sommes imparables.';
-- Quest 1086 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1086, 'frFR', 'Tu dois trouver l\'aéroport de la Venture Company s\'il existe, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Tu dois trouver l\'aéroport de la Venture Company s\'il existe, $N$.';
-- Quest 1086 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1086, 'frFR', 'Tu as trouvé le port ? Bien joué, $N$ ! Je suis sûr que les gobelins ont été très surpris par ta livraison ! Espérons que ce toxine trouve son chemin jusqu\'à leur siège.$B$BTu as bien servi ton peuple, et je te conseille d\'ignorer toute culpabilité que tu pourrais ressentir d\'avoir empoisonné la Venture Company. Ils méritent bien pire.$B$BEt s\'il y a une seule parcelle de sagesse que les Forsaken puissent enseigner à leurs alliés, c\'est ceci:$B$BNe crains pas les chemins sombres... si ces chemins mènent à la victoire.') ON DUPLICATE KEY UPDATE RewardText='Tu as trouvé le port ? Bien joué, $N$ ! Je suis sûr que les gobelins ont été très surpris par ta livraison ! Espérons que ce toxine trouve son chemin jusqu\'à leur siège.$B$BTu as bien servi ton peuple, et je te conseille d\'ignorer toute culpabilité que tu pourrais ressentir d\'avoir empoisonné la Venture Company. Ils méritent bien pire.$B$BEt s\'il y a une seule parcelle de sagesse que les Forsaken puissent enseigner à leurs alliés, c\'est ceci:$B$BNe crains pas les chemins sombres... si ces chemins mènent à la victoire.';
-- Quest 1087 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1087, 'frFR', 'Ici, canaliser la magie est comme tirer de l\'eau d\'un puits avec un seau plein de trous.') ON DUPLICATE KEY UPDATE CompletionText='Ici, canaliser la magie est comme tirer de l\'eau d\'un puits avec un seau plein de trous.';
-- Quest 1088 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1088, 'frFR', 'Quand mon maître m\'a mené au sommet de Stonetalon, j\'attendais que tout ce dont j\'aurais besoin était de ravager les elfes de la nuit qui rampaient dans les ruines sacrées de notre ancien temple d\'Azshara, leur toucher désacralisant sa sainteté... mais Ordanus m\'a échappé.') ON DUPLICATE KEY UPDATE CompletionText='Quand mon maître m\'a mené au sommet de Stonetalon, j\'attendais que tout ce dont j\'aurais besoin était de ravager les elfes de la nuit qui rampaient dans les ruines sacrées de notre ancien temple d\'Azshara, leur toucher désacralisant sa sainteté... mais Ordanus m\'a échappé.';
-- Quest 1088 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1088, 'frFR', 'Je connaissais Ordanus autrefois, il y a longtemps. Il avait l\'arrogance de sa race, se considérant au-dessus même des Hauts-Nés.$B$BSa tête ne se dresse pas si haut maintenant, n\'est-ce pas, <name>?$B$Je t\'avais promis une récompense, et tu l\'auras. Attends-moi.') ON DUPLICATE KEY UPDATE RewardText='Je connaissais Ordanus autrefois, il y a longtemps. Il avait l\'arrogance de sa race, se considérant au-dessus même des Hauts-Nés.$B$BSa tête ne se dresse pas si haut maintenant, n\'est-ce pas, <name>?$B$Je t\'avais promis une récompense, et tu l\'auras. Attends-moi.';
-- Quest 1091 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1091, 'frFR', 'Oui, $N$ ? Que puis-je faire pour toi ?') ON DUPLICATE KEY UPDATE CompletionText='Oui, $N$ ? Que puis-je faire pour toi ?';

-- Quest 1091 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1091, 'frFR', 'C\'est intéressant en effet.$B$BVous et Gaxim avez fait un travail remarquable, $N. Merci.') ON DUPLICATE KEY UPDATE RewardText='C\'est intéressant en effet.$B$BVous et Gaxim avez fait un travail remarquable, $N. Merci.';
-- Quest 1100 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1100, 'frFR', 'À votre air inquiet, je peux dire que quelque chose ne va pas....') ON DUPLICATE KEY UPDATE CompletionText='À votre air inquiet, je peux dire que quelque chose ne va pas....';
-- Quest 1101 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1101, 'frFR', 'Tant que Charlga Razorflank rassemble des forces dans Razorfen Kraul, ces terres sont en grand danger.') ON DUPLICATE KEY UPDATE CompletionText='Tant que Charlga Razorflank rassemble des forces dans Razorfen Kraul, ces terres sont en grand danger.';
-- Quest 1101 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1101, 'frFR', 'La crone a été mise au repos. C\'est une nouvelle fantastique, <name>.$B$BEn ces temps de péril, c\'est rafraîchissant de voir quelqu\'un d\'aussi courageux que vous.$B$BAvec les sbires de Razorflank réglés, nos études dans la région peuvent continuer. Peut-être pouvons-nous maintenant en savoir plus sur ce qui est arrivé pour corrompre le lieu de repos d\'Agamaggan.$B$BCependant, je crains que la réponse à cette question ne réside également dans la trahison...') ON DUPLICATE KEY UPDATE RewardText='La crone a été mise au repos. C\'est une nouvelle fantastique, <name>.$B$BEn ces temps de péril, c\'est rafraîchissant de voir quelqu\'un d\'aussi courageux que vous.$B$BAvec les sbires de Razorflank réglés, nos études dans la région peuvent continuer. Peut-être pouvons-nous maintenant en savoir plus sur ce qui est arrivé pour corrompre le lieu de repos d\'Agamaggan.$B$BCependant, je crains que la réponse à cette question ne réside également dans la trahison...';
-- Quest 1103 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1103, 'frFR', 'Tu as le sapta, $G brotha:sista;?$B$Je connais un autre qui a eu des problèmes après avoir vaincu l\'esprit d\'eau corrompu -- il semble qu\'il ait attendu trop longtemps et qu\'il soit sorti du monde des esprits trop vite pour son goût. Je déteste voir ça arriver à quelqu\'un d\'autre, alors je vais juste attendre ici un moment pour m\'assurer que personne d\'autre n\'a besoin de mon aide.') ON DUPLICATE KEY UPDATE CompletionText='Tu as le sapta, $G brotha:sista;?$B$Je connais un autre qui a eu des problèmes après avoir vaincu l\'esprit d\'eau corrompu -- il semble qu\'il ait attendu trop longtemps et qu\'il soit sorti du monde des esprits trop vite pour son goût. Je déteste voir ça arriver à quelqu\'un d\'autre, alors je vais juste attendre ici un moment pour m\'assurer que personne d\'autre n\'a besoin de mon aide.';
-- Quest 1103 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1103, 'frFR', 'Ahhh, tu es prêt...$B$Je vais mettre mes objets dans le brasier, et tu peux parler avec l\'esprit aussi.$B$Et ne t\'inquiète pas pour voir dans le monde des esprits avec le sapta... vieux Tiev connaît quelques astuces sur le fonctionnement de la magie du sapta.$B$Viens maintenant, descends avec moi au sanctuaire et parlons aux esprits ensemble, brotha.') ON DUPLICATE KEY UPDATE RewardText='Ahhh, tu es prêt...$B$Je vais mettre mes objets dans le brasier, et tu peux parler avec l\'esprit aussi.$B$Et ne t\'inquiète pas pour voir dans le monde des esprits avec le sapta... vieux Tiev connaît quelques astuces sur le fonctionnement de la magie du sapta.$B$Viens maintenant, descends avec moi au sanctuaire et parlons aux esprits ensemble, brotha.';
-- Quest 1104 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1104, 'frFR', 'Hi hi hi! Tu as récupéré ce venin??') ON DUPLICATE KEY UPDATE CompletionText='Hi hi hi! Tu as récupéré ce venin??';
-- Quest 1104 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1104, 'frFR', 'Très bien!  Ce venin va fonctionner à merveille!  Merci, <name>!$B$BMaintenant, j\'ai juste besoin de le réduire, d\'appliquer skipper-otomer, d\'ajouter un nega-catalyseur, et... Zut!  Où sont mes notes!?') ON DUPLICATE KEY UPDATE RewardText='Très bien!  Ce venin va fonctionner à merveille!  Merci, <name>!$B$BMaintenant, j\'ai juste besoin de le réduire, d\'appliquer skipper-otomer, d\'ajouter un nega-catalyseur, et... Zut!  Où sont mes notes!?';
-- Quest 1105 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1105, 'frFR', 'Mon frère progresse avec sa nouvelle conception de carburant, et ça m\'inquiète. Je dois commencer à travailler sur un réservoir de carburant en carapace de tortue dès que possible!') ON DUPLICATE KEY UPDATE CompletionText='Mon frère progresse avec sa nouvelle conception de carburant, et ça m\'inquiète. Je dois commencer à travailler sur un réservoir de carburant en carapace de tortue dès que possible!';
-- Quest 1105 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1105, 'frFR', 'Tu les as!  Merci, <name>!$B$BWow, ces coquilles sont plus dures que je ne le pensais!  Heh, quand je travaille avec elles, je vais probablement plier une boîte entière d\'outils!') ON DUPLICATE KEY UPDATE RewardText='Tu les as!  Merci, <name>!$B$BWow, ces coquilles sont plus dures que je ne le pensais!  Heh, quand je travaille avec elles, je vais probablement plier une boîte entière d\'outils!';
-- Quest 1107 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1107, 'frFR', 'As-tu les nageoires caudales? Si je ne peux pas protéger notre voiture de sa propre vitesse, alors elle ne durera pas longtemps dans ces courses.') ON DUPLICATE KEY UPDATE CompletionText='As-tu les nageoires caudales? Si je ne peux pas protéger notre voiture de sa propre vitesse, alors elle ne durera pas longtemps dans ces courses.';
-- Quest 1107 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1107, 'frFR', 'Merci, <name>!  Après les avoir râpées et fusionnées avec quelques autres ingrédients, le composite sera prêt.  Et après cela, la voiture sera à l\'abri de sa propre vitesse.$B$Sûre, tant qu\'elle ne touche rien...') ON DUPLICATE KEY UPDATE RewardText='Merci, <name>!  Après les avoir râpées et fusionnées avec quelques autres ingrédients, le composite sera prêt.  Et après cela, la voiture sera à l\'abri de sa propre vitesse.$B$Sûre, tant qu\'elle ne touche rien...';
-- Quest 1108 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1108, 'frFR', 'As-tu trouvé des flocons d\'indurium, $N. J\'ai mon forge chauffée et prête à les tester.') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé des flocons d\'indurium, $N. J\'ai mon forge chauffée et prête à les tester.';
-- Quest 1113 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1113, 'frFR', 'Es-tu revenu du Monastère Écarlate? J\'aurai besoin de nombreux cœurs pour cette délicieuse expérience!$b$bSans aucun doute, Varimathras et la Dame Sombre seront ravis de se débarrasser de la Crème Écarlate aussi...') ON DUPLICATE KEY UPDATE CompletionText='Es-tu revenu du Monastère Écarlate? J\'aurai besoin de nombreux cœurs pour cette délicieuse expérience!$b$bSans aucun doute, Varimathras et la Dame Sombre seront ravis de se débarrasser de la Crème Écarlate aussi...';
-- Quest 1113 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1113, 'frFR', 'Mon Dieu, quelle abondance de sang tu m\'as apportée, <name>! Tes efforts ont été les plus excellents!') ON DUPLICATE KEY UPDATE RewardText='Mon Dieu, quelle abondance de sang tu m\'as apportée, <name>! Tes efforts ont été les plus excellents!';

-- Quest 1116 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1116, 'frFR', 'Si tôt ? Avez-vous ma poussière de rêve ?') ON DUPLICATE KEY UPDATE CompletionText='Si tôt ? Avez-vous ma poussière de rêve ?';
-- Quest 1116 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1116, 'frFR', 'Eh bien, regardez ça.  Vous avez trouvé la poussière de rêve !$B$BEt comment trouvez-vous le marais, <name>?  Ce n\'est pas facile de trouver un repas chaud là-bas, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE RewardText='Eh bien, regardez ça.  Vous avez trouvé la poussière de rêve !$B$BEt comment trouvez-vous le marais, <name>?  Ce n\'est pas facile de trouver un repas chaud là-bas, n\'est-ce pas ?';
-- Quest 1118 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1118, 'frFR', 'Bonjour bonjour. Et qu\'est-ce qui amène un noble $R comme vous à Booty Bay ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour bonjour. Et qu\'est-ce qui amène un noble $R comme vous à Booty Bay ?';
-- Quest 1118 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1118, 'frFR', 'Je vois. Kravel a un grand plan en tête. Il a un esprit sinistre -- j\'aime ça chez lui.$b$bAlors vous aurez besoin de quelque chose pour brouiller les idées, hein ? Quelque chose de puissant...$b$bJe me demande si le mélange que Zanzil donne à ses zombies pourrait être utilisé...') ON DUPLICATE KEY UPDATE RewardText='Je vois. Kravel a un grand plan en tête. Il a un esprit sinistre -- j\'aime ça chez lui.$b$bAlors vous aurez besoin de quelque chose pour brouiller les idées, hein ? Quelque chose de puissant...$b$bJe me demande si le mélange que Zanzil donne à ses zombies pourrait être utilisé...';
-- Quest 1119 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1119, 'frFR', 'Bonjour, $N. Fizzlebub a pu nous aider ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $N. Fizzlebub a pu nous aider ?';
-- Quest 1119 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1119, 'frFR', 'Merveilleux !  Fizzlebub a réussi !  Je m\'en souviendrai la prochaine fois que je le verrai.$B$BEt merci, <name>.  Vous faites un excellent travail, et nous deux nous pourrons gagner beaucoup d\'argent avec ça...') ON DUPLICATE KEY UPDATE RewardText='Merveilleux !  Fizzlebub a réussi !  Je m\'en souviendrai la prochaine fois que je le verrai.$B$BEt merci, <name>.  Vous faites un excellent travail, et nous deux nous pourrons gagner beaucoup d\'argent avec ça...';
-- Quest 1120 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1120, 'frFR', 'Salut ! Vous avez quelque chose pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Salut ! Vous avez quelque chose pour moi ?';
-- Quest 1120 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1120, 'frFR', 'Stout ? Quelle considération ! Merci !$b$bNous ne devrions pas boire avec la race qui arrive, mais... peut-être que mes gars pourraient apprécier un peu. Après tout, ça ne peut pas être aussi fort, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE RewardText='Stout ? Quelle considération ! Merci !$b$bNous ne devrions pas boire avec la race qui arrive, mais... peut-être que mes gars pourraient apprécier un peu. Après tout, ça ne peut pas être aussi fort, n\'est-ce pas ?';
-- Quest 1121 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1121, 'frFR', 'Qu\'avons-nous ici ? De l\'alcool, hein?$B$BEh bien, je ne m\'oppose pas à ce que nous en ayons un peu...') ON DUPLICATE KEY UPDATE RewardText='Qu\'avons-nous ici ? De l\'alcool, hein?$B$BEh bien, je ne m\'oppose pas à ce que nous en ayons un peu...';
-- Quest 1122 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1122, 'frFR', 'Bonjour $N. Comment s\'est passée cette stout ? C\'est une boisson forte, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour $N. Comment s\'est passée cette stout ? C\'est une boisson forte, n\'est-ce pas ?';
-- Quest 1122 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1122, 'frFR', 'Il est écrit ici que la stout du sot a été un succès.  C\'est une bonne nouvelle !$B$BSi vous voulez plus de cette substance, alors dites-le-moi et je vous ferai ramasser plus du Mélange de Zanzil.') ON DUPLICATE KEY UPDATE RewardText='Il est écrit ici que la stout du sot a été un succès.  C\'est une bonne nouvelle !$B$BSi vous voulez plus de cette substance, alors dites-le-moi et je vous ferai ramasser plus du Mélange de Zanzil.';
-- Quest 1125 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1125, 'frFR', 'Alliance ou Horde, peu importe - aucun être ne mérite d\'être piégé dans ce monde comme un esprit tourmenté. La libération de ces âmes rendra les choses justes, $N.') ON DUPLICATE KEY UPDATE CompletionText='Alliance ou Horde, peu importe - aucun être ne mérite d\'être piégé dans ce monde comme un esprit tourmenté. La libération de ces âmes rendra les choses justes, $N.';
-- Quest 1127 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1127, 'frFR', 'Avez-vous ces mélanges de Zanzil, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous ces mélanges de Zanzil, $N ?';
-- Quest 1127 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1127, 'frFR', 'Ah, très bien ! Voici votre paiement.$B$BEt voici quelque chose en plus... pour votre discrétion.') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien ! Voici votre paiement.$B$BEt voici quelque chose en plus... pour votre discrétion.';
-- Quest 1130 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1130, 'frFR', 'Alors, $N, vous êtes venu. Maintenant, êtes-vous prêt à voyager à travers des terres lointaines?$B$BSi oui, jeune $c, alors écoutez...') ON DUPLICATE KEY UPDATE RewardText='Alors, $N, vous êtes venu. Maintenant, êtes-vous prêt à voyager à travers des terres lointaines?$B$BSi oui, jeune $c, alors écoutez...';

-- Quest 1131 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1131, 'frFR', 'As-tu vaincu le Steelsnap maudit, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu vaincu le Steelsnap maudit, $N?';
-- Quest 1131 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1131, 'frFR', 'En vainquant la créature Steelsnap, tu as purifié les Mille Aiguilles d\'une horrible souillure.$B$BEt, <name>, c\'est ta leçon aujourd\'hui.') ON DUPLICATE KEY UPDATE RewardText='En vainquant la créature Steelsnap, tu as purifié les Mille Aiguilles d\'une horrible souillure.$B$BEt, <name>, c\'est ta leçon aujourd\'hui.';
-- Quest 1133 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1133, 'frFR', 'Es-tu ici pour offrir tes services à l\'Alliance, <name>? Nous accueillons l\'aide, car bien que sa beauté demeure... La Forêt d\'Ashenvale n\'est pas le lieu paisible qu\'elle était autrefois.') ON DUPLICATE KEY UPDATE RewardText='Es-tu ici pour offrir tes services à l\'Alliance, <name>? Nous accueillons l\'aide, car bien que sa beauté demeure... La Forêt d\'Ashenvale n\'est pas le lieu paisible qu\'elle était autrefois.';
-- Quest 1135 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1135, 'frFR', 'As-tu trouvé Highperch, $N? Des nouvelles des wyvernes là-bas?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé Highperch, $N? Des nouvelles des wyvernes là-bas?';
-- Quest 1135 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1135, 'frFR', 'Ah, la plupart d\'entre elles sont presque gorgées de venin, $N. On les récolte normalement uniquement sur de jeunes wyvernes, ou des femelles fertiles. Il doit y avoir eu un massacre pas rien là-haut à Highperch!') ON DUPLICATE KEY UPDATE RewardText='Ah, la plupart d\'entre elles sont presque gorgées de venin, $N. On les récolte normalement uniquement sur de jeunes wyvernes, ou des femelles fertiles. Il doit y avoir eu un massacre pas rien là-haut à Highperch!';
-- Quest 1136 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1136, 'frFR', 'Es-tu allé dans les Montagnes d\'Alterac, $N? As-tu affronté la furtive Frostmaw?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé dans les Montagnes d\'Alterac, $N? As-tu affronté la furtive Frostmaw?';
-- Quest 1136 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1136, 'frFR', 'La force et la ruse ont été nécessaires pour trouver et vaincre Frostmaw, $N. Tu as les deux.$b$bTon chemin t\'a mené aux vallées des Mille Aiguilles et aux hautes montagnes d\'Alterac. Il te mènera un jour à travers tous les territoires de la Mère-Terre, car tel est le chemin du chasseur.') ON DUPLICATE KEY UPDATE RewardText='La force et la ruse ont été nécessaires pour trouver et vaincre Frostmaw, $N. Tu as les deux.$b$bTon chemin t\'a mené aux vallées des Mille Aiguilles et aux hautes montagnes d\'Alterac. Il te mènera un jour à travers tous les territoires de la Mère-Terre, car tel est le chemin du chasseur.';
-- Quest 1139 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1139, 'frFR', 'La quête de Hammertoe doit être réalisée, $N. Je lui dois cela.$B$BTon retour à Uldaman est impératif non seulement pour cet objectif, mais aussi pour la sécurité de toute espèce naine. Avec la tablette entre les mains des Irons Noirs, qui sait à quel point leur armée de golems deviendrait puissante.') ON DUPLICATE KEY UPDATE CompletionText='La quête de Hammertoe doit être réalisée, $N. Je lui dois cela.$B$BTon retour à Uldaman est impératif non seulement pour cet objectif, mais aussi pour la sécurité de toute espèce naine. Avec la tablette entre les mains des Irons Noirs, qui sait à quel point leur armée de golems deviendrait puissante.';
-- Quest 1139 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1139, 'frFR', '$GAdvisor Belgrum secoue la tête avec incrédulité alors que tu lui remets l\'éclat de pierre.>$B<br :><name, c\'est incroyable. Je vais faire amener ceci aux mages du roi dès que possible. Ils voudront l\'étudier pour savoir si les légendes sont vraies. Mais c\'est une discussion pour un autre moment : tu as aidé notre peuple plus que je ne l\'aurais jamais imaginé -- merci.') ON DUPLICATE KEY UPDATE RewardText='$GAdvisor Belgrum secoue la tête avec incrédulité alors que tu lui remets l\'éclat de pierre.>$B<br :><name, c\'est incroyable. Je vais faire amener ceci aux mages du roi dès que possible. Ils voudront l\'étudier pour savoir si les légendes sont vraies. Mais c\'est une discussion pour un autre moment : tu as aidé notre peuple plus que je ne l\'aurais jamais imaginé -- merci.';
-- Quest 1140 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1140, 'frFR', 'J\'ai entendu un murmure disant que l\'histoire des satyres est en quelque sorte liée à celle des elfes de la nuit, mais j\'ai trouvé mes estimés hôtes réticents à en parler.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai entendu un murmure disant que l\'histoire des satyres est en quelque sorte liée à celle des elfes de la nuit, mais j\'ai trouvé mes estimés hôtes réticents à en parler.';
-- Quest 1142 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1142, 'frFR', 'Qu\'est-ce qui t\'amène chez moi, $R?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui t\'amène chez moi, $R?';
-- Quest 1142 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1142, 'frFR', 'Non!$B$BCe n\'est pas juste. Oh, monde cruel et intolérable!$B$BI dois maintenant porter ce fardeau de chagrin et ne pas laisser l\'œuvre de Heralath mourir avec lui.$B$BTu as été courageux de venir d\'un endroit aussi dangereux, <name>. Mais s\'il te plaît, laisse-moi maintenant.$B$BEn solitude, je pleurerai.') ON DUPLICATE KEY UPDATE RewardText='Non!$B$BCe n\'est pas juste. Oh, monde cruel et intolérable!$B$BI dois maintenant porter ce fardeau de chagrin et ne pas laisser l\'œuvre de Heralath mourir avec lui.$B$BTu as été courageux de venir d\'un endroit aussi dangereux, <name>. Mais s\'il te plaît, laisse-moi maintenant.$B$BEn solitude, je pleurerai.';
-- Quest 1147 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1147, 'frFR', 'Avec le nombre de voyageurs qui partent vers les Plaines pour ces races, je suis sûr que nous pouvons convaincre suffisamment de chercheurs d\'aventure pour aider à repousser ces insectes. Mon groupe et moi ne pourrons partir tant que ce ne sera pas fait.') ON DUPLICATE KEY UPDATE CompletionText='Avec le nombre de voyageurs qui partent vers les Plaines pour ces races, je suis sûr que nous pouvons convaincre suffisamment de chercheurs d\'aventure pour aider à repousser ces insectes. Mon groupe et moi ne pourrons partir tant que ce ne sera pas fait.';
-- Quest 1147 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1147, 'frFR', 'Ha! Cet ichor dont tu es couvert te rend en fait plus jolie, $Gname>! Cela te fait certainement aussi puer en même temps. Ne te tiens pas trop près du kodo; tu déclencheras soit une estampide, soit tu les feras entrer en chaleur.$B<br :>Je pense que mes compagnons seraient d\'accord que ton odeur seule est la preuve que tu as fait ta part pour nous aider contre ces créatures insectes. Merci, <name.') ON DUPLICATE KEY UPDATE RewardText='Ha! Cet ichor dont tu es couvert te rend en fait plus jolie, $Gname>! Cela te fait certainement aussi puer en même temps. Ne te tiens pas trop près du kodo; tu déclencheras soit une estampide, soit tu les feras entrer en chaleur.$B<br :>Je pense que mes compagnons seraient d\'accord que ton odeur seule est la preuve que tu as fait ta part pour nous aider contre ces créatures insectes. Merci, <name.';
-- Quest 1148 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1148, 'frFR', 'Ah, cela fait longtemps que tu ne viens me voir, $N. Qu\'est-ce que je peux faire pour toi aujourd\'hui? Tu as l\'air d\'avoir vu le visage du combat récemment. Bien... bien pour la Horde et bien pour toi. Plus tu as vu de combats, plus tu seras utile; plus fort aussi.') ON DUPLICATE KEY UPDATE CompletionText='Ah, cela fait longtemps que tu ne viens me voir, $N. Qu\'est-ce que je peux faire pour toi aujourd\'hui? Tu as l\'air d\'avoir vu le visage du combat récemment. Bien... bien pour la Horde et bien pour toi. Plus tu as vu de combats, plus tu seras utile; plus fort aussi.';

-- Quest 1148 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1148, 'frFR', 'As-tu vu Moktar récemment ? Il est toujours en train de veiller sur moi. Je suis désolé d\'apprendre qu\'il passe son temps à surveiller sa petite bande de guerriers au lieu de voir le combat, mais je suis sûr qu\'il prend un grand plaisir à tuer des membres de la Ligue des Explorateurs.$B$BTu as bien fait de m\'apporter ces spécimens, <name>. Avec les œufs que nous trouvons dans le Champ des Géants, cela devrait me donner un bon début pour comprendre ce que sont ces insectes, et ce qu\'ils veulent.') ON DUPLICATE KEY UPDATE RewardText='As-tu vu Moktar récemment ? Il est toujours en train de veiller sur moi. Je suis désolé d\'apprendre qu\'il passe son temps à surveiller sa petite bande de guerriers au lieu de voir le combat, mais je suis sûr qu\'il prend un grand plaisir à tuer des membres de la Ligue des Explorateurs.$B$BTu as bien fait de m\'apporter ces spécimens, <name>. Avec les œufs que nous trouvons dans le Champ des Géants, cela devrait me donner un bon début pour comprendre ce que sont ces insectes, et ce qu\'ils veulent.';
-- Quest 1149 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1149, 'frFR', 'La foi. C\'est bien plus important qu\'on ne le croit.$B$BÇa n\'a pas d\'importance ce que tu crois parfois. Il est juste important que tu croies en quelque chose.') ON DUPLICATE KEY UPDATE CompletionText='La foi. C\'est bien plus important qu\'on ne le croit.$B$BÇa n\'a pas d\'importance ce que tu crois parfois. Il est juste important que tu croies en quelque chose.';
-- Quest 1153 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1153, 'frFR', 'J\'ai revu les voyageurs - ceux qui ne m\'ont pas vendu d\'échantillon de minerai. Je leur ai craché dessus pour ne pas aider le chef de guerre.$B$BQu\'ils meurent au combat comme des lâches et non comme des guerriers, ce qui devrait être le droit de tous ceux qui s\'allient à la Horde.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai revu les voyageurs - ceux qui ne m\'ont pas vendu d\'échantillon de minerai. Je leur ai craché dessus pour ne pas aider le chef de guerre.$B$BQu\'ils meurent au combat comme des lâches et non comme des guerriers, ce qui devrait être le droit de tous ceux qui s\'allient à la Horde.';
-- Quest 1153 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1153, 'frFR', 'Un bon échantillon, $Gname>. Un bon échantillon en effet.$B$BCes voyageurs ne peuvent plus me dominer avec le minerai qu\'ils ont trouvé, maintenant que tu as réussi.$B$BJe vais m\'y mettre immédiatement. Si cela s\'avère assez solide, j\'enverrai une arme fabriquée à partir du matériau au chef de guerre pour lui montrer notre succès.$B<br :>Je n\'oublierai pas ton aide, <class.') ON DUPLICATE KEY UPDATE RewardText='Un bon échantillon, $Gname>. Un bon échantillon en effet.$B$BCes voyageurs ne peuvent plus me dominer avec le minerai qu\'ils ont trouvé, maintenant que tu as réussi.$B$BJe vais m\'y mettre immédiatement. Si cela s\'avère assez solide, j\'enverrai une arme fabriquée à partir du matériau au chef de guerre pour lui montrer notre succès.$B<br :>Je n\'oublierai pas ton aide, <class.';
-- Quest 1168 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1168, 'frFR', 'Mok\'Morokk dit à tous les ogres de rester et de garder cet endroit en sécurité. Je pense que les ogres doivent tuer l\'armée du dragon noir et récupérer leur maison.$b$bTu aides les ogres à rentrer chez eux. Aide les ogres à se venger.') ON DUPLICATE KEY UPDATE CompletionText='Mok\'Morokk dit à tous les ogres de rester et de garder cet endroit en sécurité. Je pense que les ogres doivent tuer l\'armée du dragon noir et récupérer leur maison.$b$bTu aides les ogres à rentrer chez eux. Aide les ogres à se venger.';
-- Quest 1172 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1172, 'frFR', 'Tu dois te dépêcher au Dragonmurk, $n$. Avec les œufs d\'Onyxia éparpillés autour du Wyrmbog, nous faisons face à des nombres écrasants à moins que quelque chose ne soit fait rapidement.$b$bDétruisez ses œufs ! Ne laissez pas la peste du dragon noir se répandre sur notre patrie !') ON DUPLICATE KEY UPDATE CompletionText='Tu dois te dépêcher au Dragonmurk, $n$. Avec les œufs d\'Onyxia éparpillés autour du Wyrmbog, nous faisons face à des nombres écrasants à moins que quelque chose ne soit fait rapidement.$b$bDétruisez ses œufs ! Ne laissez pas la peste du dragon noir se répandre sur notre patrie !';
-- Quest 1173 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1173, 'frFR', 'Je pensais que tu allais essayer d\'expulser Mok\'Morokk du village. Au lieu de cela, tu es venu me parler ?') ON DUPLICATE KEY UPDATE CompletionText='Je pensais que tu allais essayer d\'expulser Mok\'Morokk du village. Au lieu de cela, tu es venu me parler ?';
-- Quest 1175 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1175, 'frFR', 'C\'est déjà assez mauvais de devoir nettoyer les décombres des coureurs sans avoir à les sortir de morceaux d\'animaux brûlés.') ON DUPLICATE KEY UPDATE CompletionText='C\'est déjà assez mauvais de devoir nettoyer les décombres des coureurs sans avoir à les sortir de morceaux d\'animaux brûlés.';
-- Quest 1176 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1176, 'frFR', 'Tu as ces os pour moi ? J\'étais sur le point de commencer à travailler sur l\'allègement du dispositif de direction, mais je ne veux pas l\'ouvrir sans toutes les pièces dont j\'ai besoin.') ON DUPLICATE KEY UPDATE CompletionText='Tu as ces os pour moi ? J\'étais sur le point de commencer à travailler sur l\'allègement du dispositif de direction, mais je ne veux pas l\'ouvrir sans toutes les pièces dont j\'ai besoin.';
-- Quest 1176 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1176, 'frFR', 'Super ! Je peux faire travailler l\'équipage sur ça tout de suite. Merci, <name>!') ON DUPLICATE KEY UPDATE RewardText='Super ! Je peux faire travailler l\'équipage sur ça tout de suite. Merci, <name>!';
-- Quest 1179 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1179, 'frFR', 'Attention où tu mets les pieds ! Attention attention attention !! C\'est une affaire délicate que tu vois ici, et si nous voulons gagner, tout doit fonctionner parfaitement !') ON DUPLICATE KEY UPDATE CompletionText='Attention où tu mets les pieds ! Attention attention attention !! C\'est une affaire délicate que tu vois ici, et si nous voulons gagner, tout doit fonctionner parfaitement !';
-- Quest 1179 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1179, 'frFR', 'Ah ! Longbeard t\'a envoyé avec une cargaison de casques ! Hourra !$B$BMaintenant, peut-être qu\'on peut convaincre un pilote de conduire notre voiture...') ON DUPLICATE KEY UPDATE RewardText='Ah ! Longbeard t\'a envoyé avec une cargaison de casques ! Hourra !$B$BMaintenant, peut-être qu\'on peut convaincre un pilote de conduire notre voiture...';
-- Quest 1183 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1183, 'frFR', '$N! As-tu réussi à retrouver le régulateur de carburant ?') ON DUPLICATE KEY UPDATE CompletionText='$N! As-tu réussi à retrouver le régulateur de carburant ?';
-- Quest 1185 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1185, 'frFR', 'Hé, c\'est toi encore ! Enfin, je veux dire toi - comme celui qui est $N! Oui - toi !$B$BHé, laisse-moi recommencer !$B$BL\'objet que tu as trouvé dans Silithus - c\'était en fait un livre. C\'était un journal écrit dans un dialecte très ancien de ce que nous appelons aujourd\'hui la langue Darnassienne. Ça va prendre un moment, mais je vais l\'examiner très attentivement. Je pensais que tu devrais savoir que ce que tu as trouvé était extrêmement précieux pour le Cercle.$B$BLa mère de la tanière est toute excitée et tout !') ON DUPLICATE KEY UPDATE RewardText='Hé, c\'est toi encore ! Enfin, je veux dire toi - comme celui qui est $N! Oui - toi !$B$BHé, laisse-moi recommencer !$B$BL\'objet que tu as trouvé dans Silithus - c\'était en fait un livre. C\'était un journal écrit dans un dialecte très ancien de ce que nous appelons aujourd\'hui la langue Darnassienne. Ça va prendre un moment, mais je vais l\'examiner très attentivement. Je pensais que tu devrais savoir que ce que tu as trouvé était extrêmement précieux pour le Cercle.$B$BLa mère de la tanière est toute excitée et tout !';
-- Quest 1186 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1186, 'frFR', 'Tu es le $R qui aide Pozzik, c\'est ça ? J\'étais comme toi une fois, courant dans la zone du pit, aidant avec tout le travail que les mécaniciens me laissaient faire.$B$BRegarde-moi maintenant ! Le pilote extraordinaire de l\'équipe de course des gobelins !') ON DUPLICATE KEY UPDATE RewardText='Tu es le $R qui aide Pozzik, c\'est ça ? J\'étais comme toi une fois, courant dans la zone du pit, aidant avec tout le travail que les mécaniciens me laissaient faire.$B$BRegarde-moi maintenant ! Le pilote extraordinaire de l\'équipe de course des gobelins !';

-- Quest 1192 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1192, 'frFR', 'Vous pouvez trouver de l\'indurium dans l\'excavation d\'Uldaman dans les Badlands, de l\'autre côté de la mer à Khaz Modan.$B$BLes gnomes obtiennent leur propre approvisionnement, il est donc important que nous en obtenions un pour suivre leur rythme.') ON DUPLICATE KEY UPDATE CompletionText='Vous pouvez trouver de l\'indurium dans l\'excavation d\'Uldaman dans les Badlands, de l\'autre côté de la mer à Khaz Modan.$B$BLes gnomes obtiennent leur propre approvisionnement, il est donc important que nous en obtenions un pour suivre leur rythme.';
-- Quest 1192 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1192, 'frFR', 'Excellent ! Je vais faire travailler l\'équipage immédiatement sur les pièces dont nous aurons besoin pour la prochaine course.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Je vais faire travailler l\'équipage immédiatement sur les pièces dont nous aurons besoin pour la prochaine course.';
-- Quest 1193 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1193, 'frFR', 'Un piège large et brisé se trouve devant vous. D\'après ce qu\'on voit, les ogres ont essayé de réparer le piège, mais sans succès. Une note griffonnée à la hâte se trouve à côté du piège, et étrangement, elle détaille exactement ce qui est nécessaire pour le réparer : un widget de thorium et de l\'huile de givre. Si le piège était réparé, un ogre passant près de lui pourrait se faire piéger, et cela pourrait être évité.$b$bIl semble clairement fort fortuit que très peu d\'ogres sachent lire.$b$bClairement.') ON DUPLICATE KEY UPDATE CompletionText='Un piège large et brisé se trouve devant vous. D\'après ce qu\'on voit, les ogres ont essayé de réparer le piège, mais sans succès. Une note griffonnée à la hâte se trouve à côté du piège, et étrangement, elle détaille exactement ce qui est nécessaire pour le réparer : un widget de thorium et de l\'huile de givre. Si le piège était réparé, un ogre passant près de lui pourrait se faire piéger, et cela pourrait être évité.$b$bIl semble clairement fort fortuit que très peu d\'ogres sachent lire.$b$bClairement.';
-- Quest 1193 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1193, 'frFR', 'Le widget de thorium glisse sans effort en place, créant un conduit pour verser l\'huile de givre. Une fois les dernières gouttes d\'huile vidées dedans, le piège se referme.$B$BMalheur à tout ogre imprudent qui pourrait passer par là !') ON DUPLICATE KEY UPDATE RewardText='Le widget de thorium glisse sans effort en place, créant un conduit pour verser l\'huile de givre. Une fois les dernières gouttes d\'huile vidées dedans, le piège se referme.$B$BMalheur à tout ogre imprudent qui pourrait passer par là !';
-- Quest 1201 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1201, 'frFR', 'Avez-vous trouvé les infiltrateurs, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé les infiltrateurs, $N?';
-- Quest 1202 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1202, 'frFR', 'Avez-vous trouvé les documents, $N? Ils contiennent des informations vitales pour la stabilité de l\'Alliance et, par conséquent, pour la sécurité de la Horde.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé les documents, $N? Ils contiennent des informations vitales pour la stabilité de l\'Alliance et, par conséquent, pour la sécurité de la Horde.';
-- Quest 1205 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1205, 'frFR', 'Avez-vous le doigt de Deadmire, $N? Avez-vous mis fin à la souffrance de la créature ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous le doigt de Deadmire, $N? Avez-vous mis fin à la souffrance de la créature ?';
-- Quest 1205 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1205, 'frFR', 'Très bien, <name>.$B$BI suis sûr que la chasse n\'a pas été facile, mais c\'est bon de savoir que la douleur de la bête est enfin terminée.') ON DUPLICATE KEY UPDATE RewardText='Très bien, <name>.$B$BI suis sûr que la chasse n\'a pas été facile, mais c\'est bon de savoir que la douleur de la bête est enfin terminée.';
-- Quest 1221 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1221, 'frFR', 'Super, vous les avez !  Je peux vendre ça à mes contacts pour une fortune !$B$BMerci pour la livraison, <name>!  Vous êtes un excellent partenaire.') ON DUPLICATE KEY UPDATE RewardText='Super, vous les avez !  Je peux vendre ça à mes contacts pour une fortune !$B$BMerci pour la livraison, <name>!  Vous êtes un excellent partenaire.';
-- Quest 1222 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1222, 'frFR', 'Avez-vous vu M. Ignatz ? Je l\'ai envoyé dans le marais il y a quelque temps et il n\'est pas revenu !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous vu M. Ignatz ? Je l\'ai envoyé dans le marais il y a quelque temps et il n\'est pas revenu !';
-- Quest 1239 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1239, 'frFR', 'Vous avez un autre dossier à signaler, $N?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez un autre dossier à signaler, $N?';
-- Quest 1242 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1242, 'frFR', 'Bonjour, $N. Y a-t-il quelque chose que je puisse faire pour vous ? Peut-être aimeriez-vous goûter à notre cheddar Trias spécial ? Ou un morceau de bleu Darnassian ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $N. Y a-t-il quelque chose que je puisse faire pour vous ? Peut-être aimeriez-vous goûter à notre cheddar Trias spécial ? Ou un morceau de bleu Darnassian ?';
-- Quest 1242 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1242, 'frFR', 'Je suis désolé, une lettre pour moi ? Eh bien, je vais... pas souvent vous arrive une livraison qui n\'est pas une caisse ou un baril quand tout ce que vous faites, c\'est travailler. Voyons de quoi il s\'agit.$B$B$GElling vous regarde en levant les yeux en ouvrant la lettre.>$B<br :>Vous avez l\'air un peu tendu, ça va, <name?') ON DUPLICATE KEY UPDATE RewardText='Je suis désolé, une lettre pour moi ? Eh bien, je vais... pas souvent vous arrive une livraison qui n\'est pas une caisse ou un baril quand tout ce que vous faites, c\'est travailler. Voyons de quoi il s\'agit.$B$B$GElling vous regarde en levant les yeux en ouvrant la lettre.>$B<br :>Vous avez l\'air un peu tendu, ça va, <name?';
-- Quest 1248 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1248, 'frFR', 'Bienvenue, bienvenue, bienvenue, <name>. C\'est gentil de vous joindre à nous. Peut-être une bière aujourd\'hui ? Ou du mouton?$B$BNommez votre plaisir et je veillerai à ce que vous soyez pris en charge. Je m\'appelle Mikhail, et j\'ai hâte de vous servir.$B$BHmm ? Qu\'est-ce que c\'est ? Trias ? Gardez la voix basse, mon ami. Ce n\'est pas quelque chose dont toute la taverne doit entendre parler.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue, bienvenue, bienvenue, <name>. C\'est gentil de vous joindre à nous. Peut-être une bière aujourd\'hui ? Ou du mouton?$B$BNommez votre plaisir et je veillerai à ce que vous soyez pris en charge. Je m\'appelle Mikhail, et j\'ai hâte de vous servir.$B$BHmm ? Qu\'est-ce que c\'est ? Trias ? Gardez la voix basse, mon ami. Ce n\'est pas quelque chose dont toute la taverne doit entendre parler.';
-- Quest 1249 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1249, 'frFR', 'Est-ce qu\'il s\'est échappé ? Il avait l\'air un peu louche en nous regardant.') ON DUPLICATE KEY UPDATE CompletionText='Est-ce qu\'il s\'est échappé ? Il avait l\'air un peu louche en nous regardant.';

-- Quest 1251 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1251, 'frFR', 'Qu\'est-ce que tu as là, $N? Des preuves provenant des restes de l\'Auberge du Repos Sombre ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que tu as là, $N? Des preuves provenant des restes de l\'Auberge du Repos Sombre ?';
-- Quest 1258 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1258, 'frFR', 'Mes recherches avec les langues de Mudrock progressent bien. J\'espère que ta chasse aux crabes se passera bien ?') ON DUPLICATE KEY UPDATE CompletionText='Mes recherches avec les langues de Mudrock progressent bien. J\'espère que ta chasse aux crabes se passera bien ?';
-- Quest 1258 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1258, 'frFR', 'Ce sont des spécimens merveilleux, <name> !  Les coquilles sont en parfait état, et la chair est rose et tendre.  Le sang d\'un chef est dans tes veines, j\'en suis sûr !') ON DUPLICATE KEY UPDATE RewardText='Ce sont des spécimens merveilleux, <name> !  Les coquilles sont en parfait état, et la chair est rose et tendre.  Le sang d\'un chef est dans tes veines, j\'en suis sûr !';
-- Quest 1267 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1267, 'frFR', 'Permets-moi d\'être le premier à te remercier pour tout ce que tu as fait, $N. Tu as été une bénédiction incroyable pour mon peuple et pour le peuple de Stormwind. Je suis désolé de ne pas avoir pu faire ta connaissance dans de meilleures circonstances.$B$BComprends également que je ne peux pas te remercier ouvertement pour tes efforts, mais je te le confirme à nouveau, c\'est apprécié.$B$BLorsque tu visiteras Theramore à l\'avenir, viens me voir et j\'essaierai de te tenir au courant de la situation.$B$BMerci encore, $N.') ON DUPLICATE KEY UPDATE RewardText='Permets-moi d\'être le premier à te remercier pour tout ce que tu as fait, $N. Tu as été une bénédiction incroyable pour mon peuple et pour le peuple de Stormwind. Je suis désolé de ne pas avoir pu faire ta connaissance dans de meilleures circonstances.$B$BComprends également que je ne peux pas te remercier ouvertement pour tes efforts, mais je te le confirme à nouveau, c\'est apprécié.$B$BLorsque tu visiteras Theramore à l\'avenir, viens me voir et j\'essaierai de te tenir au courant de la situation.$B$BMerci encore, $N.';
-- Quest 1271 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1271, 'frFR', 'Mon neveu a dit que tu l\'avais aidé dans ses recherches à Dustwallow, et que tu avais aidé son associé dans une situation difficile. Eh bien, nous, les Sterns, nous nous soutenons et nous n\'ignorons pas nos amis !$B$BAlors lave-toi les mains, $N, parce que nous allons organiser une fête en ton honneur !') ON DUPLICATE KEY UPDATE RewardText='Mon neveu a dit que tu l\'avais aidé dans ses recherches à Dustwallow, et que tu avais aidé son associé dans une situation difficile. Eh bien, nous, les Sterns, nous nous soutenons et nous n\'ignorons pas nos amis !$B$BAlors lave-toi les mains, $N, parce que nous allons organiser une fête en ton honneur !';
-- Quest 1301 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1301, 'frFR', 'James ? Oh, il est parti il y a quite un moment.$B$BJ\'ai senti le second souffle du patriotisme, je suppose. Il n\'est pas difficile de voir pourquoi il l\'aurait fait. Avec toute la folie à Lordaeron, beaucoup de gens se sont joints à Jaina Proudmoore lorsqu\'elle est partie outre-mer.') ON DUPLICATE KEY UPDATE RewardText='James ? Oh, il est parti il y a quite un moment.$B$BJ\'ai senti le second souffle du patriotisme, je suppose. Il n\'est pas difficile de voir pourquoi il l\'aurait fait. Avec toute la folie à Lordaeron, beaucoup de gens se sont joints à Jaina Proudmoore lorsqu\'elle est partie outre-mer.';
-- Quest 1324 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1324, 'frFR', 'Bonjour à nouveau, $N. J\'espère que tu ne t\'opposeras pas à l\'aide, mais nous n\'aurions pas pu empêcher Hendel de s\'échapper, ou pire, finir morts.') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau, $N. J\'espère que tu ne t\'opposeras pas à l\'aide, mais nous n\'aurions pas pu empêcher Hendel de s\'échapper, ou pire, finir morts.';
-- Quest 1361 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1361, 'frFR', 'Je note que ta tâche est inachevée, $N. Dois-je informer Sharlindra de ton incompétence ?') ON DUPLICATE KEY UPDATE CompletionText='Je note que ta tâche est inachevée, $N. Dois-je informer Sharlindra de ton incompétence ?';
-- Quest 1364 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1364, 'frFR', 'Qu\'est-ce qui t\'amène au Fort Nethergarde, $R ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui t\'amène au Fort Nethergarde, $R ?';
-- Quest 1367 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1367, 'frFR', 'Pars ! Les Magram ne parlent pas aux faibles. Nous les tuons !$B$BSi tu veux me parler, alors montre-moi que tu es fort. Reviens après avoir abattu de nombreux Gelkis.') ON DUPLICATE KEY UPDATE CompletionText='Pars ! Les Magram ne parlent pas aux faibles. Nous les tuons !$B$BSi tu veux me parler, alors montre-moi que tu es fort. Reviens après avoir abattu de nombreux Gelkis.';
-- Quest 1368 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1368, 'frFR', 'Tes deux pieds foulent la terre des Gelkis. Tu n\'es pas le bienvenu ici !$B$BProuve que tu cherches l\'amitié des Gelkis. Tue le centaure Magram. Reviens quand le sol sera mouillé du sang de Magram.') ON DUPLICATE KEY UPDATE CompletionText='Tes deux pieds foulent la terre des Gelkis. Tu n\'es pas le bienvenu ici !$B$BProuve que tu cherches l\'amitié des Gelkis. Tue le centaure Magram. Reviens quand le sol sera mouillé du sang de Magram.';
-- Quest 1369 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1369, 'frFR', 'Si tu n\'es pas notre ennemi, alors tu feras ce que je demande !') ON DUPLICATE KEY UPDATE CompletionText='Si tu n\'es pas notre ennemi, alors tu feras ce que je demande !';
-- Quest 1369 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1369, 'frFR', 'Tu as les larmes !  Maintenant, les Gelkis sauront que Theradras ne les aidera pas.  Elle ne pleurera pas quand nous les écraserons !  Les Magram régneront !$B$BTu es malin de nous aider, <name>.  Nous sommes les plus forts.') ON DUPLICATE KEY UPDATE RewardText='Tu as les larmes !  Maintenant, les Gelkis sauront que Theradras ne les aidera pas.  Elle ne pleurera pas quand nous les écraserons !  Les Magram régneront !$B$BTu es malin de nous aider, <name>.  Nous sommes les plus forts.';
-- Quest 1371 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1371, 'frFR', 'Si tu n\'es pas notre ennemi, alors tu feras ce que je demande !') ON DUPLICATE KEY UPDATE CompletionText='Si tu n\'es pas notre ennemi, alors tu feras ce que je demande !';

-- Quest 1371 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1371, 'frFR', 'Oui, c\'est ce que j\'avais !  Je vais le faire bouger à nouveau.  Ça me fait rire !') ON DUPLICATE KEY UPDATE RewardText='Oui, c\'est ce que j\'avais !  Je vais le faire bouger à nouveau.  Ça me fait rire !';
-- Quest 1373 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1373, 'frFR', 'Montre-moi que tu es un ami des Gelkis, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Montre-moi que tu es un ami des Gelkis, $N$.';
-- Quest 1374 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1374, 'frFR', 'Montre-moi que tu es un ami des Gelkis, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Montre-moi que tu es un ami des Gelkis, $N$.';
-- Quest 1375 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1375, 'frFR', 'Fais des tâches pour le Magram, et je t\'aiderai.') ON DUPLICATE KEY UPDATE CompletionText='Fais des tâches pour le Magram, et je t\'aiderai.';
-- Quest 1375 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1375, 'frFR', 'Khan Shaka est mort !  Je vais placer sa tête sur une piquet, et la garder avec moi afin que Shaka puisse voir la force du Magram !') ON DUPLICATE KEY UPDATE RewardText='Khan Shaka est mort !  Je vais placer sa tête sur une piquet, et la garder avec moi afin que Shaka puisse voir la force du Magram !';
-- Quest 1381 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1381, 'frFR', 'Fais ce que je demande.  Prouve-moi que tu es un allié du Magram !') ON DUPLICATE KEY UPDATE CompletionText='Fais ce que je demande.  Prouve-moi que tu es un allié du Magram !';
-- Quest 1381 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1381, 'frFR', 'Khan Hratha est mort !  Maintenant, les Magram sont les plus forts des centaures !  Nous écraserons les autres, et nous régnerons sur Desolace !$B$BNous nous souviendrons, <name>, et tu seras épargné de nos sabots lorsque tous les autres seront piétinés.') ON DUPLICATE KEY UPDATE RewardText='Khan Hratha est mort !  Maintenant, les Magram sont les plus forts des centaures !  Nous écraserons les autres, et nous régnerons sur Desolace !$B$BNous nous souviendrons, <name>, et tu seras épargné de nos sabots lorsque tous les autres seront piétinés.';
-- Quest 1382 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1382, 'frFR', 'Disparais ! Les Gelkis ne veulent pas que tu sois ici. Pars maintenant !!$B$BReviens après avoir tué beaucoup de Magram, et alors je te parlerai.') ON DUPLICATE KEY UPDATE CompletionText='Disparais ! Les Gelkis ne veulent pas que tu sois ici. Pars maintenant !!$B$BReviens après avoir tué beaucoup de Magram, et alors je te parlerai.';
-- Quest 1383 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1383, 'frFR', 'Cet Infiltrateur à Stonard va sûrement... s\'ouvrir... après qu\'il ait bu mon sérum spécial. Haha!$b$bLes ingrédients requis ne sont en rien faciles à obtenir. Les Panthères d\'Ombre sont communes dans le Swamp, mais collecter assez de cœurs pour notre objectif peut être décourageant. Et le Seigneur des Marais peut être une bête si exigeante.$b$b') ON DUPLICATE KEY UPDATE CompletionText='Cet Infiltrateur à Stonard va sûrement... s\'ouvrir... après qu\'il ait bu mon sérum spécial. Haha!$b$bLes ingrédients requis ne sont en rien faciles à obtenir. Les Panthères d\'Ombre sont communes dans le Swamp, mais collecter assez de cœurs pour notre objectif peut être décourageant. Et le Seigneur des Marais peut être une bête si exigeante.$b$b';
-- Quest 1383 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1383, 'frFR', 'Splendide, <name> ! Et juste à temps. D\'après ce que Zraedus m\'a dit, l\'Infiltrateur s\'est rétabli de ses blessures et est prêt à être interrogé par les orcs.$B$BDonne-moi un instant pour préparer le pois-- je veux dire, préparer le sérum de vérité.') ON DUPLICATE KEY UPDATE RewardText='Splendide, <name> ! Et juste à temps. D\'après ce que Zraedus m\'a dit, l\'Infiltrateur s\'est rétabli de ses blessures et est prêt à être interrogé par les orcs.$B$BDonne-moi un instant pour préparer le pois-- je veux dire, préparer le sérum de vérité.';
-- Quest 1385 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1385, 'frFR', 'Tu vas maintenant, ou le Magram t\'écrasera ! Pour être notre ami, tu dois tuer des Gelkis.') ON DUPLICATE KEY UPDATE CompletionText='Tu vas maintenant, ou le Magram t\'écrasera ! Pour être notre ami, tu dois tuer des Gelkis.';
-- Quest 1385 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1385, 'frFR', 'Beaucoup de Gelkis tombent à tes mains.  J\'aime ça.  Peut-être que tu peux faire d\'autres choses que j\'aime.  Peut-être que toi et les Magram pouvez être amis.') ON DUPLICATE KEY UPDATE RewardText='Beaucoup de Gelkis tombent à tes mains.  J\'aime ça.  Peut-être que tu peux faire d\'autres choses que j\'aime.  Peut-être que toi et les Magram pouvez être amis.';
-- Quest 1386 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1386, 'frFR', 'As-tu peur des Kolkar ? Pourquoi ne les tues-tu pas ? Peut-être as-tu oublié comment tuer. Dépêche-toi de tuer les Kolkar avant qu\'ils ne soient morts !') ON DUPLICATE KEY UPDATE CompletionText='As-tu peur des Kolkar ? Pourquoi ne les tues-tu pas ? Peut-être as-tu oublié comment tuer. Dépêche-toi de tuer les Kolkar avant qu\'ils ne soient morts !';
-- Quest 1386 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1386, 'frFR', 'Les Kolkar te craignent maintenant !  J\'espère que tu as ri quand tu les as tués.  Il vaut mieux rire quand on tue, afin que l\'ennemi puisse voir qu\'il est faible.') ON DUPLICATE KEY UPDATE RewardText='Les Kolkar te craignent maintenant !  J\'espère que tu as ri quand tu les as tués.  Il vaut mieux rire quand on tue, afin que l\'ennemi puisse voir qu\'il est faible.';
-- Quest 1388 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1388, 'frFR', 'J\'espère que tu t\'es prouvé utile à notre cher ami, Apothicaire Faustin.') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que tu t\'es prouvé utile à notre cher ami, Apothicaire Faustin.';

-- Quest 1388 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1388, 'frFR', 'Je savais que le vieux Faustin trouverait quelque chose de bon ! Tu as été d\'une aide formidable, sans aucun doute.$B$BMaintenant, passons aux choses sérieuses, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE RewardText='Je savais que le vieux Faustin trouverait quelque chose de bon ! Tu as été d\'une aide formidable, sans aucun doute.$B$BMaintenant, passons aux choses sérieuses, n\'est-ce pas ?';
-- Quest 1391 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1391, 'frFR', 'Ayez pitié de moi ! J\'ai des informations qui dépassent les frontières de l\'Alliance. Bien que je ne sois pas sympathisant de la Horde, il y a une trahison politique qui doit être révélée !') ON DUPLICATE KEY UPDATE CompletionText='Ayez pitié de moi ! J\'ai des informations qui dépassent les frontières de l\'Alliance. Bien que je ne sois pas sympathisant de la Horde, il y a une trahison politique qui doit être révélée !';
-- Quest 1391 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1391, 'frFR', 'Un verre pour moi ? Quelle gentillesse. Cela fait des jours qu\'on ne m\'a pas permis de boire. Laissez-moi finir ça et je vous dirai ce que j\'ai appris....') ON DUPLICATE KEY UPDATE RewardText='Un verre pour moi ? Quelle gentillesse. Cela fait des jours qu\'on ne m\'a pas permis de boire. Laissez-moi finir ça et je vous dirai ce que j\'ai appris....';
-- Quest 1394 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1394, 'frFR', 'Ah, <name>. Cela fait longtemps que vous n\'êtes pas entré chez moi. Il semble que de longs mois se soient écoulés depuis que vous avez fait votre premier saut qui vous a mis sur votre chemin.$B$BEt maintenant, vous revenez vers moi plus fort qu\'avant... plus éclairé. Cela me plaît. Et vous devriez être justement récompensé d\'avoir tenu mes épreuves jusqu\'au bout.') ON DUPLICATE KEY UPDATE RewardText='Ah, <name>. Cela fait longtemps que vous n\'êtes pas entré chez moi. Il semble que de longs mois se soient écoulés depuis que vous avez fait votre premier saut qui vous a mis sur votre chemin.$B$BEt maintenant, vous revenez vers moi plus fort qu\'avant... plus éclairé. Cela me plaît. Et vous devriez être justement récompensé d\'avoir tenu mes épreuves jusqu\'au bout.';
-- Quest 1396 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1396, 'frFR', 'Les créatures des marais se rapprochent, $N. S\'il vous plaît, vous devez défendre le camp !') ON DUPLICATE KEY UPDATE CompletionText='Les créatures des marais se rapprochent, $N. S\'il vous plaît, vous devez défendre le camp !';
-- Quest 1398 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1398, 'frFR', 'Avez-vous trouvé du bois flotté, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé du bois flotté, $N ?';
-- Quest 1398 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1398, 'frFR', 'Ce bois est léger, mais solide. Merci, $N. Ça fonctionnera bien.') ON DUPLICATE KEY UPDATE RewardText='Ce bois est léger, mais solide. Merci, $N. Ça fonctionnera bien.';
-- Quest 1418 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1418, 'frFR', 'Helgrum veut un rapport, hein ? J\'ai envoyé un coursier à Stonard il y a moins de trois jours. A-t-il échoué à sa mission ? Si Stonard n\'a pas mon rapport, alors il semble qu\'il ait échoué.$b$bEspérons que le prochain coursier que j\'enverrai ait plus de talent, ou plus de chance.') ON DUPLICATE KEY UPDATE RewardText='Helgrum veut un rapport, hein ? J\'ai envoyé un coursier à Stonard il y a moins de trois jours. A-t-il échoué à sa mission ? Si Stonard n\'a pas mon rapport, alors il semble qu\'il ait échoué.$b$bEspérons que le prochain coursier que j\'enverrai ait plus de talent, ou plus de chance.';
-- Quest 1421 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1421, 'frFR', 'Avez-vous les réactifs du mage, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les réactifs du mage, $N?';
-- Quest 1421 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1421, 'frFR', 'Ah, vous les avez trouvés ! Avec ceux-ci, les mages de Nethergarde pourront continuer leur travail. Je ne sais pas ce qu\'ils font, mais c\'est lié au Portail Sombre dans les Terres Brûlées, et c\'est vital pour la sécurité de l\'Alliance.') ON DUPLICATE KEY UPDATE RewardText='Ah, vous les avez trouvés ! Avec ceux-ci, les mages de Nethergarde pourront continuer leur travail. Je ne sais pas ce qu\'ils font, mais c\'est lié au Portail Sombre dans les Terres Brûlées, et c\'est vital pour la sécurité de l\'Alliance.';
-- Quest 1423 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1423, 'frFR', 'Ah, merci $N ! Tant de fournitures sont perdues de Darkshire jusqu\'ici. C\'est bon de voir que certaines sont récupérées.') ON DUPLICATE KEY UPDATE RewardText='Ah, merci $N ! Tant de fournitures sont perdues de Darkshire jusqu\'ici. C\'est bon de voir que certaines sont récupérées.';
-- Quest 1426 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1426, 'frFR', 'Je suis patient. Patient et éternel comme un vieux caillou de Draenor. Les poissons ne passeront pas nos frontières -- pas tant que je tiendrai. Si nous avions une armée à notre disposition, j\'épurgerais ce monde et tous les autres de leur présence. Je sens ma haine bouillonner rien qu\'à en parler.') ON DUPLICATE KEY UPDATE CompletionText='Je suis patient. Patient et éternel comme un vieux caillou de Draenor. Les poissons ne passeront pas nos frontières -- pas tant que je tiendrai. Si nous avions une armée à notre disposition, j\'épurgerais ce monde et tous les autres de leur présence. Je sens ma haine bouillonner rien qu\'à en parler.';
-- Quest 1428 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1428, 'frFR', 'Pas tant que la mer et tous ses enfants ne seront pas réduits au silence... surtout ces dégoûtants poissons.') ON DUPLICATE KEY UPDATE CompletionText='Pas tant que la mer et tous ses enfants ne seront pas réduits au silence... surtout ces dégoûtants poissons.';
-- Quest 1434 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1434, 'frFR', 'Un compagnon tauren m\'a prévenu que les satyres n\'étaient pas tous ce qu\'ils semblaient être. Il croit qu\'il y a quelque chose de plus chez eux, que leur mal est une torsion de leur vraie nature. Mais je n\'ai rien vu de tel.$B$Je ne vois que le massacre impitoyable des faibles et la corruption de ceux qui recherchent le pouvoir sombre.$B$Je continuerai dans mon devoir d\'annihiler jusqu\'à ce que le chef de guerre ne me donne autre ordre. D\'ici là, je n\'ai pitié d\'eux.') ON DUPLICATE KEY UPDATE CompletionText='Un compagnon tauren m\'a prévenu que les satyres n\'étaient pas tous ce qu\'ils semblaient être. Il croit qu\'il y a quelque chose de plus chez eux, que leur mal est une torsion de leur vraie nature. Mais je n\'ai rien vu de tel.$B$Je ne vois que le massacre impitoyable des faibles et la corruption de ceux qui recherchent le pouvoir sombre.$B$Je continuerai dans mon devoir d\'annihiler jusqu\'à ce que le chef de guerre ne me donne autre ordre. D\'ici là, je n\'ai pitié d\'eux.';
-- Quest 1442 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1442, 'frFR', 'Je serais moins confiant en quelqu\'un qui n\'est pas sur un chemin sacré s\'il venait me demander une gemme de Kor. Mais je vous fais plus confiance que certains de mes semblables. Je ne juge pas votre ordre entier sur les actions d\'un seul de vos semblables tombés.') ON DUPLICATE KEY UPDATE CompletionText='Je serais moins confiant en quelqu\'un qui n\'est pas sur un chemin sacré s\'il venait me demander une gemme de Kor. Mais je vous fais plus confiance que certains de mes semblables. Je ne juge pas votre ordre entier sur les actions d\'un seul de vos semblables tombés.';

-- Quest 1442 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1442, 'frFR', 'C\'est bien le joyau que Stilwell désire, mais avant que je puisse vous permettre de le lui apporter, il doit être purifié de la corruption—les femelles naga imprègnent les gemmes de puissance, c\'est vrai, mais de leur propre espèce, maléfique.$B$Dites à Stilwell que sa puissance est intacte, et qu\'elle devrait bien fonctionner pour quel que soit le rituel qu\'il souhaite qu\'elle compose.$B$J\'espère que vous savez ce que vous faites, $c$, ce n\'est pas un simple objet que vous possédez.') ON DUPLICATE KEY UPDATE RewardText='C\'est bien le joyau que Stilwell désire, mais avant que je puisse vous permettre de le lui apporter, il doit être purifié de la corruption—les femelles naga imprègnent les gemmes de puissance, c\'est vrai, mais de leur propre espèce, maléfique.$B$Dites à Stilwell que sa puissance est intacte, et qu\'elle devrait bien fonctionner pour quel que soit le rituel qu\'il souhaite qu\'elle compose.$B$J\'espère que vous savez ce que vous faites, $c$, ce n\'est pas un simple objet que vous possédez.';
-- Quest 1447 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1447, 'frFR', 'Je ne voulais rien dire par le commentaire sur le fait que tu es un $C$ stupide. On est amis, non ? Pas de mauvaise intention ?') ON DUPLICATE KEY UPDATE CompletionText='Je ne voulais rien dire par le commentaire sur le fait que tu es un $C$ stupide. On est amis, non ? Pas de mauvaise intention ?';
-- Quest 1448 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1448, 'frFR', 'Le Temple d\'Atal\'Hakkar a été englouti sous le Bassin des Larmes ? Et entouré par la volée des dragons verts?$B$BUne découverte incroyable, <class>. Mais évidemment, quelque chose s\'est terriblement mal passé.') ON DUPLICATE KEY UPDATE RewardText='Le Temple d\'Atal\'Hakkar a été englouti sous le Bassin des Larmes ? Et entouré par la volée des dragons verts?$B$BUne découverte incroyable, <class>. Mais évidemment, quelque chose s\'est terriblement mal passé.';
-- Quest 1449 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1449, 'frFR', 'Qu\'est-ce que tu veux, laddy ? Tu ne vois pas que j\'ai des problèmes à régler ici ? Qui a le temps de traîner à bavarder avec une $R$ bavarde?$B$BDes trolls sortent de nulle part ! Dépêche-toi.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que tu veux, laddy ? Tu ne vois pas que j\'ai des problèmes à régler ici ? Qui a le temps de traîner à bavarder avec une $R$ bavarde?$B$BDes trolls sortent de nulle part ! Dépêche-toi.';
-- Quest 1452 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1452, 'frFR', 'Tu as déjà goûté un Rhapsody Malt ? L\'une de mes meilleures brasseries, si je puis me permettre. Hiccup!$B$Mais si je vais revivre les horreurs de ce vol fatidique au-dessus de... hiccup... la tourbière, eh bien, j\'aurai besoin de quelque chose un peu plus fort. Hiccup!$B$Tu ne crois pas m\'avoir trouvé ces gigots et ces foies dont j\'ai besoin pour donner cette touche supplémentaire à mon Kalimdor Kocktail?$B$Hiccup!') ON DUPLICATE KEY UPDATE CompletionText='Tu as déjà goûté un Rhapsody Malt ? L\'une de mes meilleures brasseries, si je puis me permettre. Hiccup!$B$Mais si je vais revivre les horreurs de ce vol fatidique au-dessus de... hiccup... la tourbière, eh bien, j\'aurai besoin de quelque chose un peu plus fort. Hiccup!$B$Tu ne crois pas m\'avoir trouvé ces gigots et ces foies dont j\'ai besoin pour donner cette touche supplémentaire à mon Kalimdor Kocktail?$B$Hiccup!';
-- Quest 1452 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1452, 'frFR', 'Je vois que tu n\'as eu aucun problème à m\'apporter ce dont j\'ai besoin ! Tu as dû passer un bon moment là-bas dans le lointain Kalimdor.$B$Il ne me faudra qu\'un instant pour extraire ce dont j\'ai besoin de ces gigots et de ces foies. Hiccup!$B$Alors je peux me distiller une boisson féroce et enfin te dire ce que tu veux savoir.$B$Hiccup!$B$J\'ai des frissons rien qu\'à penser à cette vieille tourbière.$B$Hiccup!$B$Laisse-moi me préparer une boisson très vite.') ON DUPLICATE KEY UPDATE RewardText='Je vois que tu n\'as eu aucun problème à m\'apporter ce dont j\'ai besoin ! Tu as dû passer un bon moment là-bas dans le lointain Kalimdor.$B$Il ne me faudra qu\'un instant pour extraire ce dont j\'ai besoin de ces gigots et de ces foies. Hiccup!$B$Alors je peux me distiller une boisson féroce et enfin te dire ce que tu veux savoir.$B$Hiccup!$B$J\'ai des frissons rien qu\'à penser à cette vieille tourbière.$B$Hiccup!$B$Laisse-moi me préparer une boisson très vite.';
-- Quest 1456 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1456, 'frFR', 'Sans vouloir offenser qui que soit Nijel, mais ce camp n\'est pas l\'endroit le plus confortable où j\'ai passé une nuit, si tu vois ce que je veux dire, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Sans vouloir offenser qui que soit Nijel, mais ce camp n\'est pas l\'endroit le plus confortable où j\'ai passé une nuit, si tu vois ce que je veux dire, $N$.';
-- Quest 1456 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1456, 'frFR', 'C\'est super, <name> ! Tu as trouvé les affaires de Karnitol!$B$Ces maudits naga, toujours à causer des problèmes. Je pense que je préférerais passer ma vie en guerre contre la Horde plutôt que d\'aller contre leur espèce.$B$Tu as rendu un grand service aux Récupérateurs. S\'il te plaît, accepte ceci avec nos remerciements !') ON DUPLICATE KEY UPDATE RewardText='C\'est super, <name> ! Tu as trouvé les affaires de Karnitol!$B$Ces maudits naga, toujours à causer des problèmes. Je pense que je préférerais passer ma vie en guerre contre la Horde plutôt que d\'aller contre leur espèce.$B$Tu as rendu un grand service aux Récupérateurs. S\'il te plaît, accepte ceci avec nos remerciements !';
-- Quest 1459 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1459, 'frFR', 'Désolé de ne pas pouvoir te dire où trouver le kodo ou le scorpashi. Je ne connais pas très bien la zone, et je n\'ai pas eu le temps d\'explorer.') ON DUPLICATE KEY UPDATE CompletionText='Désolé de ne pas pouvoir te dire où trouver le kodo ou le scorpashi. Je ne connais pas très bien la zone, et je n\'ai pas eu le temps d\'explorer.';
-- Quest 1459 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1459, 'frFR', 'Ton aide ici est une bénédiction, <name>. Tu réduis mon temps passé ici dans Desolace de moitié au moins. Je reviendrai à Ironforge me réchauffer les pieds en un rien de temps avec ton aide.$B$Quand nous aurons réglé cette liste, et que je serai rentré chez moi, cherche-moi, je t\'achèterai une ale à coup sûr.$B$Mais d\'ici là, rassemblons le reste de ces réactifs.') ON DUPLICATE KEY UPDATE RewardText='Ton aide ici est une bénédiction, <name>. Tu réduis mon temps passé ici dans Desolace de moitié au moins. Je reviendrai à Ironforge me réchauffer les pieds en un rien de temps avec ton aide.$B$Quand nous aurons réglé cette liste, et que je serai rentré chez moi, cherche-moi, je t\'achèterai une ale à coup sûr.$B$Mais d\'ici là, rassemblons le reste de ces réactifs.';
-- Quest 1462 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1462, 'frFR', 'Prends ceci et souviens-toi, c\'est sacré.') ON DUPLICATE KEY UPDATE RewardText='Prends ceci et souviens-toi, c\'est sacré.';
-- Quest 1463 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1463, 'frFR', 'Je te donne un en bonne foi. Tu t\'es déjà prouvé une fois, mais je pense que tu devrais être plus prudent à l\'avenir.') ON DUPLICATE KEY UPDATE CompletionText='Je te donne un en bonne foi. Tu t\'es déjà prouvé une fois, mais je pense que tu devrais être plus prudent à l\'avenir.';
-- Quest 1463 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1463, 'frFR', 'Je te donne un en bonne foi. Tu t\'es déjà prouvé une fois, mais je pense que tu devrais être plus prudent à l\'avenir.') ON DUPLICATE KEY UPDATE RewardText='Je te donne un en bonne foi. Tu t\'es déjà prouvé une fois, mais je pense que tu devrais être plus prudent à l\'avenir.';
-- Quest 1464 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1464, 'frFR', 'Parle à Telf Joolam pour un autre Fire Sapta.') ON DUPLICATE KEY UPDATE CompletionText='Parle à Telf Joolam pour un autre Fire Sapta.';
-- Quest 1464 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1464, 'frFR', 'Que le feu brûle dans ton cœur, $N.$B$Les éléments t\'attendent.') ON DUPLICATE KEY UPDATE RewardText='Que le feu brûle dans ton cœur, $N.$B$Les éléments t\'attendent.';

-- Quest 1466 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1466, 'frFR', 'Je ne savais même pas que ces choses démoniaques étaient à Desolace. Du temps en temps, le centaure dominait le territoire après que les elfes des bois soient partis il y a des années.$B$BI me demande pourquoi ils se sont installés ici, et comment.') ON DUPLICATE KEY UPDATE CompletionText='Je ne savais même pas que ces choses démoniaques étaient à Desolace. Du temps en temps, le centaure dominait le territoire après que les elfes des bois soient partis il y a des années.$B$BI me demande pourquoi ils se sont installés ici, et comment.';
-- Quest 1466 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1466, 'frFR', 'Honnêtement ? Je ne l\'aurais pas pensé. Tu es incroyable, <name>. Affronter des démons pour les expériences d\'un mage, et revenir en un morceau. Bon travail!$B$BI je vais personnellement en parler à Roetten quand je reviendrai à Ironforge.') ON DUPLICATE KEY UPDATE RewardText='Honnêtement ? Je ne l\'aurais pas pensé. Tu es incroyable, <name>. Affronter des démons pour les expériences d\'un mage, et revenir en un morceau. Bon travail!$B$BI je vais personnellement en parler à Roetten quand je reviendrai à Ironforge.';
-- Quest 1467 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1467, 'frFR', 'Bienvenue, $N. Le commerce est florissant, le son des enclumes résonne dans tout Ironforge, les soufflets chauffent les feux, et ma femme me prépare une tarte pour le dessert après le dîner de ce soir. Pourrait-il y avoir une vie plus grandiose ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue, $N. Le commerce est florissant, le son des enclumes résonne dans tout Ironforge, les soufflets chauffent les feux, et ma femme me prépare une tarte pour le dessert après le dîner de ce soir. Pourrait-il y avoir une vie plus grandiose ?';
-- Quest 1467 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1467, 'frFR', 'Ah, le colis pour Leftwitch depuis Desolace. Excellent. J\'apprécie le travail, et votre ponctualité, <class>. Je suis heureux de vous avoir à bord pour au moins ce petit travail.$B$BI voici votre paiement. Sachez que Reclaimers Inc. paie toujours bien pour une semaine de travail acharné.') ON DUPLICATE KEY UPDATE RewardText='Ah, le colis pour Leftwitch depuis Desolace. Excellent. J\'apprécie le travail, et votre ponctualité, <class>. Je suis heureux de vous avoir à bord pour au moins ce petit travail.$B$BI voici votre paiement. Sachez que Reclaimers Inc. paie toujours bien pour une semaine de travail acharné.';
-- Quest 1469 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1469, 'frFR', 'Enfin, vous êtes de retour, $N. Cela fait un certain temps depuis la dernière fois que nous avons parlé. Je pensais peut-être que vous aviez oublié ma quête.$B$BDiez-vous trouvé ce cavalier de griffon rusé ? A-t-il quelque chose à rapporter ?') ON DUPLICATE KEY UPDATE CompletionText='Enfin, vous êtes de retour, $N. Cela fait un certain temps depuis la dernière fois que nous avons parlé. Je pensais peut-être que vous aviez oublié ma quête.$B$BDiez-vous trouvé ce cavalier de griffon rusé ? A-t-il quelque chose à rapporter ?';
-- Quest 1469 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1469, 'frFR', 'Rhapsody Shindigger ! C\'est ça... comment pourrais-je oublier un tel nom?$B$BAlors il savait tout du naufrage du temple ? Eh bien, cela t\'aurait certainement épargné des démarches.$B$BMais cet artefact Atal\'ai ! Pourquoi, c\'est une trouvaille remarquable !') ON DUPLICATE KEY UPDATE RewardText='Rhapsody Shindigger ! C\'est ça... comment pourrais-je oublier un tel nom?$B$BAlors il savait tout du naufrage du temple ? Eh bien, cela t\'aurait certainement épargné des démarches.$B$BMais cet artefact Atal\'ai ! Pourquoi, c\'est une trouvaille remarquable !';
-- Quest 1475 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1475, 'frFR', 'Alors que le crépuscule descend lentement sur ma carrière, je me tourne vers vous, $N, pour m\'aider dans ma quête finale pour la Ligue des Explorateurs. Si mes vieux os pouvaient rassembler la force pour braver le Marais des Souffrances et le temple englouti, je serais au combat à vos côtés.$B$BLa fierté me rend difficile de demander votre aide pour recueillir les Tablettes d\'Atal\'ai. Mais la vieillesse impose la nécessité.$B$BS\'il vous plaît, aidez-moi, $N. Je veux prendre ma retraite de la Ligue des Explorateurs en ayant accompli son dernier engagement.') ON DUPLICATE KEY UPDATE CompletionText='Alors que le crépuscule descend lentement sur ma carrière, je me tourne vers vous, $N, pour m\'aider dans ma quête finale pour la Ligue des Explorateurs. Si mes vieux os pouvaient rassembler la force pour braver le Marais des Souffrances et le temple englouti, je serais au combat à vos côtés.$B$BLa fierté me rend difficile de demander votre aide pour recueillir les Tablettes d\'Atal\'ai. Mais la vieillesse impose la nécessité.$B$BS\'il vous plaît, aidez-moi, $N. Je veux prendre ma retraite de la Ligue des Explorateurs en ayant accompli son dernier engagement.';
-- Quest 1475 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1475, 'frFR', 'Les Tablettes d\'Atal\'ai ! Merci, <name>!$B$BUne fois que je les remettrai à la Ligue des Explorateurs, nos noms seront inscrits dans l\'histoire ensemble. Vous avez aidé un vieux nain à accomplir son dernier devoir dans la vie. Pour cela, je vous en suis éternellement reconnaissant.') ON DUPLICATE KEY UPDATE RewardText='Les Tablettes d\'Atal\'ai ! Merci, <name>!$B$BUne fois que je les remettrai à la Ligue des Explorateurs, nos noms seront inscrits dans l\'histoire ensemble. Vous avez aidé un vieux nain à accomplir son dernier devoir dans la vie. Pour cela, je vous en suis éternellement reconnaissant.';
-- Quest 1485 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1485, 'frFR', 'Il est important que vous puissiez contrôler les êtres que vous invoquez par votre magie. Il y a suffisamment de gens intéressés par l\'apprentissage des voies de la $C que je ne risquerais pas de gâcher votre vie en vous enseignant quelque chose avant que vous ne soyez prêt.') ON DUPLICATE KEY UPDATE CompletionText='Il est important que vous puissiez contrôler les êtres que vous invoquez par votre magie. Il y a suffisamment de gens intéressés par l\'apprentissage des voies de la $C que je ne risquerais pas de gâcher votre vie en vous enseignant quelque chose avant que vous ne soyez prêt.';
-- Quest 1485 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1485, 'frFR', 'Tout au long de votre entraînement en tant que $c, vous apprendrez à invoquer des êtres de toutes sortes. Certains peuvent ne pas le penser, mais tous sont des outils utiles.$B$BNe soyez pas dupé par la petite taille de l\'imp. Comme vous l\'avez sans doute remarqué, c\'est toujours un adversaire redoutable.') ON DUPLICATE KEY UPDATE RewardText='Tout au long de votre entraînement en tant que $c, vous apprendrez à invoquer des êtres de toutes sortes. Certains peuvent ne pas le penser, mais tous sont des outils utiles.$B$BNe soyez pas dupé par la petite taille de l\'imp. Comme vous l\'avez sans doute remarqué, c\'est toujours un adversaire redoutable.';
-- Quest 1486 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1486, 'frFR', 'Je suis très intéressé à examiner les peaux des créatures déviantes qui ont infesté ces grottes. Avez-vous eu de la chance à en collecter, $C?') ON DUPLICATE KEY UPDATE CompletionText='Je suis très intéressé à examiner les peaux des créatures déviantes qui ont infesté ces grottes. Avez-vous eu de la chance à en collecter, $C?';
-- Quest 1487 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1487, 'frFR', '$N, nous, les Disciples de Naralex, avons besoin de votre aide. Nos effectifs diminuent avec notre maître piégé dans son cauchemar tordu. Nous n\'avons pas les forces nécessaires pour faire face aux créatures corrompues qui hantent maintenant ces cavernes.$b$bJe vous en prie, entrez dans les grottes et menez la guerre contre les créatures déviantes !') ON DUPLICATE KEY UPDATE CompletionText='$N, nous, les Disciples de Naralex, avons besoin de votre aide. Nos effectifs diminuent avec notre maître piégé dans son cauchemar tordu. Nous n\'avons pas les forces nécessaires pour faire face aux créatures corrompues qui hantent maintenant ces cavernes.$b$bJe vous en prie, entrez dans les grottes et menez la guerre contre les créatures déviantes !';
-- Quest 1488 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1488, 'frFR', 'Gloire à la Horde, et mort à nos ennemis, $N!$B$BLes démons à Desolace représentent une menace plus grande que jamais. Mon espoir de retourner au Chef de Guerre diminue à mesure que plus et plus de créatures maudites semblent apparaître.$B$BI souhaite parfois que ce soit seulement le centaure avec lequel nous devions nous débrouiller.') ON DUPLICATE KEY UPDATE CompletionText='Gloire à la Horde, et mort à nos ennemis, $N!$B$BLes démons à Desolace représentent une menace plus grande que jamais. Mon espoir de retourner au Chef de Guerre diminue à mesure que plus et plus de créatures maudites semblent apparaître.$B$BI souhaite parfois que ce soit seulement le centaure avec lequel nous devions nous débrouiller.';
-- Quest 1489 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1489, 'frFR', 'Vos maîtres sont des fous de vous envoyer ici, car je ne serai plus jamais un esclave de Scourge !') ON DUPLICATE KEY UPDATE CompletionText='Vos maîtres sont des fous de vous envoyer ici, car je ne serai plus jamais un esclave de Scourge !';
-- Quest 1498 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1498, 'frFR', 'Avez-vous les écailles, $N? À moins que vous ne puissiez supporter les attaques des lézards-tonnerre, vous ne bénéficierez pas de mon enseignement.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les écailles, $N? À moins que vous ne puissiez supporter les attaques des lézards-tonnerre, vous ne bénéficierez pas de mon enseignement.';

-- Quest 1498 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1498, 'frFR', 'Ah. Je vois que vous avez vaincu les lézards-tonnerre, ce qui prouve votre trempe. Maintenant, je vais vous montrer comment la peau épaisse et les mouvements avisés peuvent former un mur de défense impénétrable.$b$bApprenez bien votre leçon, $N$. Et soyez prêt pour les instructions futures.') ON DUPLICATE KEY UPDATE RewardText='Ah. Je vois que vous avez vaincu les lézards-tonnerre, ce qui prouve votre trempe. Maintenant, je vais vous montrer comment la peau épaisse et les mouvements avisés peuvent former un mur de défense impénétrable.$b$bApprenez bien votre leçon, $N$. Et soyez prêt pour les instructions futures.';
-- Quest 1499 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1499, 'frFR', 'Vous avez bien fait, $N.$b$bBien que les familiers vilains n\'étaient que des bêtes de compagnie des puissances plus sombres de la Lame Ardente, votre succès contre eux annonce de plus grandes actions à venir.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, $N.$b$bBien que les familiers vilains n\'étaient que des bêtes de compagnie des puissances plus sombres de la Lame Ardente, votre succès contre eux annonce de plus grandes actions à venir.';
-- Quest 1501 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1501, 'frFR', 'Avez-vous la Tablette de Verga, $N$? Sinon, je ne souhaite pas vous parler tant que vous ne l\'aurez pas.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous la Tablette de Verga, $N$? Sinon, je ne souhaite pas vous parler tant que vous ne l\'aurez pas.';
-- Quest 1501 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1501, 'frFR', 'Bien. J\'espère que vous avez infligé d\'autres pertes à la Lame Ardente lorsque vous êtes allé récupérer ceci.$B$BIls ont été une source d\'ennui pour le Chef de Guerre, et une grande plaie pour les sorciers en général.') ON DUPLICATE KEY UPDATE RewardText='Bien. J\'espère que vous avez infligé d\'autres pertes à la Lame Ardente lorsque vous êtes allé récupérer ceci.$B$BIls ont été une source d\'ennui pour le Chef de Guerre, et une grande plaie pour les sorciers en général.';
-- Quest 1502 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1502, 'frFR', 'Mes yeux se sont longtemps asséchés en fixant la flamme de la forge, mais je peux encore voir certaines choses. Je vois que vous voulez quelque chose.$b$bEt si vous avez trouvé le chemin jusqu\'ici, alors je peux deviner ce que vous désirez.') ON DUPLICATE KEY UPDATE RewardText='Mes yeux se sont longtemps asséchés en fixant la flamme de la forge, mais je peux encore voir certaines choses. Je vois que vous voulez quelque chose.$b$bEt si vous avez trouvé le chemin jusqu\'ici, alors je peux deviner ce que vous désirez.';
-- Quest 1503 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1503, 'frFR', 'Vous les avez trouvés ! Et toutes les barres sont ici, ce qui ne me surprend pas. Je ne pensais pas que les Razormanes sauraient quoi faire d\'un acier fin comme celui-ci.$b$bMerci, $N$. Voici votre récompense. Qu\'elle vous serve bien.') ON DUPLICATE KEY UPDATE RewardText='Vous les avez trouvés ! Et toutes les barres sont ici, ce qui ne me surprend pas. Je ne pensais pas que les Razormanes sauraient quoi faire d\'un acier fin comme celui-ci.$b$bMerci, $N$. Voici votre récompense. Qu\'elle vous serve bien.';
-- Quest 1504 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1504, 'frFR', 'Le marcheur du vide est une créature puissante. Je me souviens quand j\'étais à votre place, $N$. Au fil des ans, mon propre marcheur du vide a cessé de me combattre, bien que je soupçonne que c\'est seulement parce qu\'il espère que je laisserai ma garde baisser.$B$BSouviens-toi de ça, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Le marcheur du vide est une créature puissante. Je me souviens quand j\'étais à votre place, $N$. Au fil des ans, mon propre marcheur du vide a cessé de me combattre, bien que je soupçonne que c\'est seulement parce qu\'il espère que je laisserai ma garde baisser.$B$BSouviens-toi de ça, $N$.';
-- Quest 1504 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1504, 'frFR', 'Vous avez bien fait, $N$. Je vais vous montrer comment invoquer le marcheur du vide similaire à celui que vous venez de vaincre.$B$BVous devez savoir que nous avons des attentes élevées pour vous, et vous avez, jusqu\'à présent, répondu à celles-ci.$B$BNe laissez pas cela vous monter à la tête, cependant, car les tâches qui vous attendent rendront cela aussi simple que se réveiller le matin.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, $N$. Je vais vous montrer comment invoquer le marcheur du vide similaire à celui que vous venez de vaincre.$B$BVous devez savoir que nous avons des attentes élevées pour vous, et vous avez, jusqu\'à présent, répondu à celles-ci.$B$BNe laissez pas cela vous monter à la tête, cependant, car les tâches qui vous attendent rendront cela aussi simple que se réveiller le matin.';
-- Quest 1506 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1506, 'frFR', 'Bien. J\'avais peur qu\'Ophek ne vous atteigne pas.$B$BIl est temps que j\'avance votre entraînement de sorcier. Toute affaire que vous avez actuellement devra attendre.$B$BJe crois qu\'il n\'y aura pas de problème avec cela ?') ON DUPLICATE KEY UPDATE RewardText='Bien. J\'avais peur qu\'Ophek ne vous atteigne pas.$B$BIl est temps que j\'avance votre entraînement de sorcier. Toute affaire que vous avez actuellement devra attendre.$B$BJe crois qu\'il n\'y aura pas de problème avec cela ?';
-- Quest 1507 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1507, 'frFR', 'Hm... $N$. Vous êtes encore nouveau sur votre chemin, mais je sens le potentiel de grandeur en vous.$B$BVous êtes né avec des dons, $N$. Assurez-vous qu\'ils ne soient pas gaspillés.') ON DUPLICATE KEY UPDATE RewardText='Hm... $N$. Vous êtes encore nouveau sur votre chemin, mais je sens le potentiel de grandeur en vous.$B$BVous êtes né avec des dons, $N$. Assurez-vous qu\'ils ne soient pas gaspillés.';
-- Quest 1508 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1508, 'frFR', 'Êtes-vous venu avec des nouvelles de Dogran ? Il était censé revenir il y a des jours, et je n\'ai rien entendu...') ON DUPLICATE KEY UPDATE RewardText='Êtes-vous venu avec des nouvelles de Dogran ? Il était censé revenir il y a des jours, et je n\'ai rien entendu...';
-- Quest 1509 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1509, 'frFR', 'Zankaja ? C\'est la compagne de Dogran, n\'est-ce pas?$B$BOui, j\'ai eu de ses nouvelles, mais ce n\'est pas le genre de nouvelle que nous devrions lui laisser parvenir...$B$BNon, il n\'est pas mort. Mais il est blessé et prisonnier des quilboar.') ON DUPLICATE KEY UPDATE RewardText='Zankaja ? C\'est la compagne de Dogran, n\'est-ce pas?$B$BOui, j\'ai eu de ses nouvelles, mais ce n\'est pas le genre de nouvelle que nous devrions lui laisser parvenir...$B$BNon, il n\'est pas mort. Mais il est blessé et prisonnier des quilboar.';
-- Quest 1510 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1510, 'frFR', 'Un autre $R, hein ? J\'espère que vous ne venez pas pour l\'autre. Il n\'a pas survécu. Ces gobelins l\'ont tué, c\'est bien.$B$BIl a dit qu\'il avait besoin d\'une potion de guérison, mais pas beaucoup plus.') ON DUPLICATE KEY UPDATE RewardText='Un autre $R, hein ? J\'espère que vous ne venez pas pour l\'autre. Il n\'a pas survécu. Ces gobelins l\'ont tué, c\'est bien.$B$BIl a dit qu\'il avait besoin d\'une potion de guérison, mais pas beaucoup plus.';
-- Quest 1511 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1511, 'frFR', 'Eh bien, il est temps ! Dogran est en train de mourir là-bas, attendant ceci.$B$BNous devons lui faire parvenir ceci immédiatement, mais la plupart des soldats stationnés ici sont en mission de recherche.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, il est temps ! Dogran est en train de mourir là-bas, attendant ceci.$B$BNous devons lui faire parvenir ceci immédiatement, mais la plupart des soldats stationnés ici sont en mission de recherche.';
-- Quest 1512 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1512, 'frFR', 'Vous êtes revenu. Êtes-vous prêt à combattre une succube ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu. Êtes-vous prêt à combattre une succube ?';

-- Quest 1512 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1512, 'frFR', 'Si vous me dites que cela suffira, alors je vous fais confiance, $N. Permettez-moi de le nettoyer cependant... Impeccable et brillant, cela peut être encore plus alléchant pour une succube.') ON DUPLICATE KEY UPDATE RewardText='Si vous me dites que cela suffira, alors je vous fais confiance, $N. Permettez-moi de le nettoyer cependant... Impeccable et brillant, cela peut être encore plus alléchant pour une succube.';
-- Quest 1513 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1513, 'frFR', 'Quand je contemple une succube, mon cœur s\'emballe... Mais en même temps, je peux presque sentir le reflux de mon âme, dérivant comme les marées.$B$BSoyez prudent, mon ami.') ON DUPLICATE KEY UPDATE CompletionText='Quand je contemple une succube, mon cœur s\'emballe... Mais en même temps, je peux presque sentir le reflux de mon âme, dérivant comme les marées.$B$BSoyez prudent, mon ami.';
-- Quest 1513 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1513, 'frFR', 'Succès ! Soyez sûr que je n\'attendais rien de moins de mon élève vedette.$B$BVous avez prouvé votre valeur, et je vous montrerai volontiers la méthode pour invoquer votre succube assujettie. Allez maintenant, vous avez beaucoup à apprendre, et lorsque je vous reverrai, j\'attendrai que vous ayez trouvé la maîtrise véritable de votre succube.$B$BLaissez le chagrin de Dogran et de Zankaja à ceux d\'entre nous qui sont plus âgés, mais souvenez-vous-en, et tenez-le comme protection contre les manœuvres du pouvoir sombre que vous avez appris à invoquer aujourd\'hui.') ON DUPLICATE KEY UPDATE RewardText='Succès ! Soyez sûr que je n\'attendais rien de moins de mon élève vedette.$B$BVous avez prouvé votre valeur, et je vous montrerai volontiers la méthode pour invoquer votre succube assujettie. Allez maintenant, vous avez beaucoup à apprendre, et lorsque je vous reverrai, j\'attendrai que vous ayez trouvé la maîtrise véritable de votre succube.$B$BLaissez le chagrin de Dogran et de Zankaja à ceux d\'entre nous qui sont plus âgés, mais souvenez-vous-en, et tenez-le comme protection contre les manœuvres du pouvoir sombre que vous avez appris à invoquer aujourd\'hui.';
-- Quest 1514 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1514, 'frFR', 'Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur de vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'une sorte d\'attention pour être ramenée à la normale.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur de vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'une sorte d\'attention pour être ramenée à la normale.';
-- Quest 1514 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1514, 'frFR', 'Vous appliquez deux onguents de plante de Cenarion à la fleur de vent. Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez deux onguents de plante de Cenarion à la fleur de vent. Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
-- Quest 1515 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1515, 'frFR', 'Breuvage au goût nauséabond...$B$Je sens la force en moi maintenant, assez pour marcher... Mais ma jambe, je l\'aurai perdue pour le reste de ma vie. Mon bras aussi.') ON DUPLICATE KEY UPDATE RewardText='Breuvage au goût nauséabond...$B$Je sens la force en moi maintenant, assez pour marcher... Mais ma jambe, je l\'aurai perdue pour le reste de ma vie. Mon bras aussi.';
-- Quest 1517 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1517, 'frFR', 'Ah... $N... la terre est heureuse de vous avoir ici.$B$Enchaînés corps et esprit, vous avancerez en sachant que les montagnes sont votre force ; les plaines, votre patience ; et le monde lui-même votre essence.$B$Se tenir humblement devant la terre est tout ce qui est requis de vous pour passer ce rite. Mais les autres ne sont pas aussi passifs. Ils peuvent être chaotiques et souvent violents, mais telle est la nature des éléments. Des natures duales s\'opposant, vous devez apprendre ces choses de manière complexe.') ON DUPLICATE KEY UPDATE RewardText='Ah... $N... la terre est heureuse de vous avoir ici.$B$Enchaînés corps et esprit, vous avancerez en sachant que les montagnes sont votre force ; les plaines, votre patience ; et le monde lui-même votre essence.$B$Se tenir humblement devant la terre est tout ce qui est requis de vous pour passer ce rite. Mais les autres ne sont pas aussi passifs. Ils peuvent être chaotiques et souvent violents, mais telle est la nature des éléments. Des natures duales s\'opposant, vous devez apprendre ces choses de manière complexe.';
-- Quest 1519 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1519, 'frFR', 'La terre est patiente, et attendra jusqu\'à ce que vous soyez prêt parce qu\'elle sait en temps que tout s\'érode et renaît. C\'est le cycle des choses. Les montagnes deviennent des déserts. Les rivières deviennent des canyons. La terre est la plus têtue et la plus sage de tous les éléments.$B$Vous devez apprendre la patience et l\'endurance avant toute chose. La terre vous appelle maintenant parce qu\'elle sent que vous êtes prêt. Considérez ceci comme votre renaissance si vous réussissez. Vous ne pourrez jamais revenir à l\'ignorance après.') ON DUPLICATE KEY UPDATE CompletionText='La terre est patiente, et attendra jusqu\'à ce que vous soyez prêt parce qu\'elle sait en temps que tout s\'érode et renaît. C\'est le cycle des choses. Les montagnes deviennent des déserts. Les rivières deviennent des canyons. La terre est la plus têtue et la plus sage de tous les éléments.$B$Vous devez apprendre la patience et l\'endurance avant toute chose. La terre vous appelle maintenant parce qu\'elle sent que vous êtes prêt. Considérez ceci comme votre renaissance si vous réussissez. Vous ne pourrez jamais revenir à l\'ignorance après.';
-- Quest 1519 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1519, 'frFR', 'Bien, $N. Votre retour ici signifie que vous êtes en effet préparé pour l\'étape suivante.$B$Parmi tous les éléments, la terre représente le fondement de toutes choses. C\'est votre force, votre endurance et votre patience. La Mère Terre vous protégera, mais seulement si vous lui témoignez le respect dû. Elle est la base de la vie, et en observant ses lois, vous acquerrez une sagesse plus grande. N\'oubliez jamais les secrets qu\'elle vous confie.$B$Je vais faire votre sapta pour vous maintenant, et en l\'acceptant, un nouveau chemin s\'ouvrira devant vous.') ON DUPLICATE KEY UPDATE RewardText='Bien, $N. Votre retour ici signifie que vous êtes en effet préparé pour l\'étape suivante.$B$Parmi tous les éléments, la terre représente le fondement de toutes choses. C\'est votre force, votre endurance et votre patience. La Mère Terre vous protégera, mais seulement si vous lui témoignez le respect dû. Elle est la base de la vie, et en observant ses lois, vous acquerrez une sagesse plus grande. N\'oubliez jamais les secrets qu\'elle vous confie.$B$Je vais faire votre sapta pour vous maintenant, et en l\'acceptant, un nouveau chemin s\'ouvrira devant vous.';
-- Quest 1520 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1520, 'frFR', 'Ah... $N... la terre est heureuse de vous avoir ici.$B$Enchaînés corps et esprit, vous avancerez en sachant que les montagnes sont votre force ; les plaines, votre patience ; et le monde lui-même votre essence.$B$Se tenir humblement devant la terre est tout ce qui est requis de vous pour passer ce rite. Mais les autres ne sont pas aussi passifs. Ils peuvent être chaotiques et souvent violents, mais telle est la nature des éléments. Des natures duales s\'opposant, vous devez apprendre ces choses de manière complexe.') ON DUPLICATE KEY UPDATE RewardText='Ah... $N... la terre est heureuse de vous avoir ici.$B$Enchaînés corps et esprit, vous avancerez en sachant que les montagnes sont votre force ; les plaines, votre patience ; et le monde lui-même votre essence.$B$Se tenir humblement devant la terre est tout ce qui est requis de vous pour passer ce rite. Mais les autres ne sont pas aussi passifs. Ils peuvent être chaotiques et souvent violents, mais telle est la nature des éléments. Des natures duales s\'opposant, vous devez apprendre ces choses de manière complexe.';
-- Quest 1521 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1521, 'frFR', 'Salutations, $N. Vous ne reviendriez pas me voir si vous n\'aviez pas accompli votre tâche. Puis-je être le premier à vous accueillir pleinement sur le premier des quatre chemins qui régneront à jamais sur vos voyages.$B$Si vous avez la pierre que la terre vous a donnée, je vous donnerai le totem qu\'elle a promis. Sinon, je vous plains. Il y a beaucoup de fierté à ressentir quand on s\'est entièrement consacré aux éléments.') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $N. Vous ne reviendriez pas me voir si vous n\'aviez pas accompli votre tâche. Puis-je être le premier à vous accueillir pleinement sur le premier des quatre chemins qui régneront à jamais sur vos voyages.$B$Si vous avez la pierre que la terre vous a donnée, je vous donnerai le totem qu\'elle a promis. Sinon, je vous plains. Il y a beaucoup de fierté à ressentir quand on s\'est entièrement consacré aux éléments.';
-- Quest 1521 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1521, 'frFR', 'Splendide.$B$Le totem que je vais fabriquer pour vous est plus qu\'un symbole--il possède des capacités au-delà de cela. Une utilisation du totem est un focus pour les sorts. Ces sorts sont liés à la terre, et à mesure que vous gagnez une sagesse de plus en plus grande, plus les capacités de la terre seront accessibles à vous. Les entraîneurs trouvés dans Kalimdor sauront quand vous êtes prêt pour une connaissance plus grande et vous le feront savoir lorsque vous les visiterez.$B$Mais pour l\'instant, prenez ce totem de terre, et un parchemin pour vous enseigner votre première capacité.') ON DUPLICATE KEY UPDATE RewardText='Splendide.$B$Le totem que je vais fabriquer pour vous est plus qu\'un symbole--il possède des capacités au-delà de cela. Une utilisation du totem est un focus pour les sorts. Ces sorts sont liés à la terre, et à mesure que vous gagnez une sagesse de plus en plus grande, plus les capacités de la terre seront accessibles à vous. Les entraîneurs trouvés dans Kalimdor sauront quand vous êtes prêt pour une connaissance plus grande et vous le feront savoir lorsque vous les visiterez.$B$Mais pour l\'instant, prenez ce totem de terre, et un parchemin pour vous enseigner votre première capacité.';
-- Quest 1522 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1522, 'frFR', 'Hmmm, Searn vous a envoyé chez moi, est-ce ça?$B$Eh bien, Searn pouvait toujours être fait confiance, donc cela doit signifier que vous êtes prêt à participer au prochain sapta--le sapta du feu.$B$Je le vois déjà dans vos yeux, le brûlant, le désir. Vous avez goûté au pouvoir, et maintenant vous êtes prêt pour plus. Patience, $N$. Souvenez-vous de ce que la terre vous a appris. Le pouvoir et la destruction viendront facilement, mais vous devez quand même savoir quand vous arrêter.') ON DUPLICATE KEY UPDATE RewardText='Hmmm, Searn vous a envoyé chez moi, est-ce ça?$B$Eh bien, Searn pouvait toujours être fait confiance, donc cela doit signifier que vous êtes prêt à participer au prochain sapta--le sapta du feu.$B$Je le vois déjà dans vos yeux, le brûlant, le désir. Vous avez goûté au pouvoir, et maintenant vous êtes prêt pour plus. Patience, $N$. Souvenez-vous de ce que la terre vous a appris. Le pouvoir et la destruction viendront facilement, mais vous devez quand même savoir quand vous arrêter.';
-- Quest 1523 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1523, 'frFR', 'Hmmm, Xanis vous a envoyé chez moi, est-ce ça?$B$Eh bien, Xanis pouvait toujours être fait confiance, donc cela doit signifier que vous êtes prêt à participer au prochain sapta--le sapta du feu.$B$Je le vois déjà dans vos yeux, le brûlant, le désir. Vous avez goûté au pouvoir, et maintenant vous êtes prêt pour plus. Patience, <name>. Souvenez-vous de ce que la terre vous a appris. Le pouvoir et la destruction viendront facilement, mais vous devez quand même savoir quand vous arrêter.') ON DUPLICATE KEY UPDATE RewardText='Hmmm, Xanis vous a envoyé chez moi, est-ce ça?$B$Eh bien, Xanis pouvait toujours être fait confiance, donc cela doit signifier que vous êtes prêt à participer au prochain sapta--le sapta du feu.$B$Je le vois déjà dans vos yeux, le brûlant, le désir. Vous avez goûté au pouvoir, et maintenant vous êtes prêt pour plus. Patience, <name>. Souvenez-vous de ce que la terre vous a appris. Le pouvoir et la destruction viendront facilement, mais vous devez quand même savoir quand vous arrêter.';
-- Quest 1524 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1524, 'frFR', 'Salutations, $N. Vous vous êtes retrouvé au Sanctuaire de la Flamme Dormante. Seuls ceux qui sont assez compétents dans les arts chamaniques apprendront les secrets de ce lieu et le pouvoir qu\'il renferme. Je suis désolé que vous ayez fait tout ce voyage, pour être renvoyé maintenant--le voyage jusqu\'ici est loin d\'être sûr--mais je suis le gardien du sanctuaire, et je ne peux pas laisser n\'importe qui rôder ici.') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $N. Vous vous êtes retrouvé au Sanctuaire de la Flamme Dormante. Seuls ceux qui sont assez compétents dans les arts chamaniques apprendront les secrets de ce lieu et le pouvoir qu\'il renferme. Je suis désolé que vous ayez fait tout ce voyage, pour être renvoyé maintenant--le voyage jusqu\'ici est loin d\'être sûr--mais je suis le gardien du sanctuaire, et je ne peux pas laisser n\'importe qui rôder ici.';

-- Quest 1524 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1524, 'frFR', 'Ah, mon erreur, $Gname>. Je m\'excuse. Je ne savais pas que vous possédiez la Torche. Je suis ravi de faire votre connaissance.$B<br :>De nombreux aventuriers trouvent leur chemin ici en quête de trésors perdus ou de la promesse de créatures mystiques à abattre, pour finalement être renvoyés d\'un sanctuaire apparemment vide. Mais nous connaissons la vérité, n\'est-ce pas, <name?$B$BCe sanctuaire renferme un secret plus grand pour les membres ordinaires de la Horde. Pour nous, il est sacré.') ON DUPLICATE KEY UPDATE RewardText='Ah, mon erreur, $Gname>. Je m\'excuse. Je ne savais pas que vous possédiez la Torche. Je suis ravi de faire votre connaissance.$B<br :>De nombreux aventuriers trouvent leur chemin ici en quête de trésors perdus ou de la promesse de créatures mystiques à abattre, pour finalement être renvoyés d\'un sanctuaire apparemment vide. Mais nous connaissons la vérité, n\'est-ce pas, <name?$B$BCe sanctuaire renferme un secret plus grand pour les membres ordinaires de la Horde. Pour nous, il est sacré.';
-- Quest 1525 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1525, 'frFR', 'J\'ai assez d\'ingrédients pour un sapta de feu si vous pouvez trouver le sac de réactifs et de la téré de feu. Les fanatiques de la Lame Ardente portent les composants appropriés pour la plupart de leurs sorts dans ces sacs, et ont généralement assez des objets dont j\'ai besoin pour que nous n\'ayons pas à chercher plus loin pour autre chose.$B$BLes saptas sont toujours fabriqués à partir d\'ingrédients étroitement liés à leurs éléments respectifs. Cela facilite notre travail grâce aux liens des sorciers avec le feu.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai assez d\'ingrédients pour un sapta de feu si vous pouvez trouver le sac de réactifs et de la téré de feu. Les fanatiques de la Lame Ardente portent les composants appropriés pour la plupart de leurs sorts dans ces sacs, et ont généralement assez des objets dont j\'ai besoin pour que nous n\'ayons pas à chercher plus loin pour autre chose.$B$BLes saptas sont toujours fabriqués à partir d\'ingrédients étroitement liés à leurs éléments respectifs. Cela facilite notre travail grâce aux liens des sorciers avec le feu.';
-- Quest 1525 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1525, 'frFR', 'Ceux-ci feront l\'affaire, $N.$B$BLe feu est plus qu\'un chaos et une destruction--faites bien attention à cela. Il est aussi lié à la vie et à la création. Toutes choses sont liées de cette manière. Les forces s\'opposent les unes aux autres, mais en même temps, on ne peut exister sans l\'autre. Elles s\'éteignent mutuellement, mais donnent aussi un sens l\'une à l\'autre. Souvenez-vous toujours de cela.$B$BUtiliser différents types de magie en conjonction les uns avec les autres montrera non seulement une vraie compétence, mais aussi une grande sagesse.') ON DUPLICATE KEY UPDATE RewardText='Ceux-ci feront l\'affaire, $N.$B$BLe feu est plus qu\'un chaos et une destruction--faites bien attention à cela. Il est aussi lié à la vie et à la création. Toutes choses sont liées de cette manière. Les forces s\'opposent les unes aux autres, mais en même temps, on ne peut exister sans l\'autre. Elles s\'éteignent mutuellement, mais donnent aussi un sens l\'une à l\'autre. Souvenez-vous toujours de cela.$B$BUtiliser différents types de magie en conjonction les uns avec les autres montrera non seulement une vraie compétence, mais aussi une grande sagesse.';
-- Quest 1526 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1526, 'frFR', 'Le brasero mesure environ un tiers de votre taille, et il a l\'air normal, à l\'exception des inscriptions le long de ses rails métalliques lisses. Le métal ne montre aucun signe d\'usure due aux intempéries, et le bol situé au sommet est frais au toucher.') ON DUPLICATE KEY UPDATE CompletionText='Le brasero mesure environ un tiers de votre taille, et il a l\'air normal, à l\'exception des inscriptions le long de ses rails métalliques lisses. Le métal ne montre aucun signe d\'usure due aux intempéries, et le bol situé au sommet est frais au toucher.';
-- Quest 1526 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1526, 'frFR', 'Une flamme blanche et vive s\'allume dans le bol lorsque vous placez la braise à l\'intérieur. Vous sentez les effets magiques du sapta couler dans votre corps et le feu danse rythmiquement devant vous.$B$BVous placez le sommet de la torche dans le bassin, et elle s\'enflamme immédiatement.') ON DUPLICATE KEY UPDATE RewardText='Une flamme blanche et vive s\'allume dans le bol lorsque vous placez la braise à l\'intérieur. Vous sentez les effets magiques du sapta couler dans votre corps et le feu danse rythmiquement devant vous.$B$BVous placez le sommet de la torche dans le bassin, et elle s\'enflamme immédiatement.';
-- Quest 1527 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1527, 'frFR', 'Oui, $N? Qu\'avez-vous là ?') ON DUPLICATE KEY UPDATE CompletionText='Oui, $N? Qu\'avez-vous là ?';
-- Quest 1527 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1527, 'frFR', 'Votre esprit brûle plus fort que n\'importe quelle torche que j\'aie jamais vue, $N, et pour cela, vous devriez être fier.$B$BSi vous continuez sur ce chemin, les éléments seront à votre commandement, et nos frères vous chercheront pour guidance et sagesse. Permettez-moi d\'être le premier à vous féliciter et à vous présenter votre nouveau totem.') ON DUPLICATE KEY UPDATE RewardText='Votre esprit brûle plus fort que n\'importe quelle torche que j\'aie jamais vue, $N, et pour cela, vous devriez être fier.$B$BSi vous continuez sur ce chemin, les éléments seront à votre commandement, et nos frères vous chercheront pour guidance et sagesse. Permettez-moi d\'être le premier à vous féliciter et à vous présenter votre nouveau totem.';
-- Quest 1528 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1528, 'frFR', 'Le vent vous approche rapidement depuis l\'horizon ; la terre est stable sous vos pieds ; et votre esprit est déjà réchauffé par le feu--je dirais qu\'il est temps pour vous d\'apprendre la pureté de l\'eau.$B$BVotre chemin vous a mené jusqu\'ici, et votre esprit vous donnera la force de continuer plus loin. Mais le premier pas vous appartient.') ON DUPLICATE KEY UPDATE RewardText='Le vent vous approche rapidement depuis l\'horizon ; la terre est stable sous vos pieds ; et votre esprit est déjà réchauffé par le feu--je dirais qu\'il est temps pour vous d\'apprendre la pureté de l\'eau.$B$BVotre chemin vous a mené jusqu\'ici, et votre esprit vous donnera la force de continuer plus loin. Mais le premier pas vous appartient.';
-- Quest 1529 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1529, 'frFR', 'Le vent vous approche rapidement depuis l\'horizon ; la terre est stable sous vos pieds ; et votre esprit est déjà réchauffé par le feu--je dirais qu\'il est temps pour vous d\'apprendre la pureté de l\'eau.$B$BVotre chemin vous a mené jusqu\'ici, et votre esprit vous donnera la force de continuer plus loin. Mais le premier pas vous appartient.') ON DUPLICATE KEY UPDATE RewardText='Le vent vous approche rapidement depuis l\'horizon ; la terre est stable sous vos pieds ; et votre esprit est déjà réchauffé par le feu--je dirais qu\'il est temps pour vous d\'apprendre la pureté de l\'eau.$B$BVotre chemin vous a mené jusqu\'ici, et votre esprit vous donnera la force de continuer plus loin. Mais le premier pas vous appartient.';
-- Quest 1530 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1530, 'frFR', 'Oui?$B$Mm. J\'ai le sentiment de savoir ce que vous allez me demander : qu\'est-ce qui pousserait quelqu\'un à vivre ici dans la partie la plus profonde des Terres Désolées, avec la menace des quilboar partout, et sans protection ? Eh bien, nous avons tous nos raisons pour justifier pourquoi nous agissons comme nous le faisons. La vraie question est : qu\'est-ce qui amène un humble $R aux confins les plus profonds des Terres Désolées pour parler à une femme qui n\'a manifestement aucun souci pour son propre bien-être?$B$Je parie que nous connaissons tous les deux la réponse à cela.') ON DUPLICATE KEY UPDATE RewardText='Oui?$B$Mm. J\'ai le sentiment de savoir ce que vous allez me demander : qu\'est-ce qui pousserait quelqu\'un à vivre ici dans la partie la plus profonde des Terres Désolées, avec la menace des quilboar partout, et sans protection ? Eh bien, nous avons tous nos raisons pour justifier pourquoi nous agissons comme nous le faisons. La vraie question est : qu\'est-ce qui amène un humble $R aux confins les plus profonds des Terres Désolées pour parler à une femme qui n\'a manifestement aucun souci pour son propre bien-être?$B$Je parie que nous connaissons tous les deux la réponse à cela.';
-- Quest 1531 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1531, 'frFR', 'Pour le moment. Je vais vous donner ce dont vous avez besoin pour concentrer vos sorts et invoquer les esprits de l\'air. Prenez ce totem, et quand vous serez prêt, entraînez-vous avec moi davantage.') ON DUPLICATE KEY UPDATE RewardText='Pour le moment. Je vais vous donner ce dont vous avez besoin pour concentrer vos sorts et invoquer les esprits de l\'air. Prenez ce totem, et quand vous serez prêt, entraînez-vous avec moi davantage.';
-- Quest 1532 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1532, 'frFR', 'Pour le moment, je vais vous donner ce dont vous avez besoin pour concentrer vos sorts et invoquer les esprits de l\'air. Prenez ce totem, et quand vous serez prêt, entraînez-vous avec moi davantage.') ON DUPLICATE KEY UPDATE RewardText='Pour le moment, je vais vous donner ce dont vous avez besoin pour concentrer vos sorts et invoquer les esprits de l\'air. Prenez ce totem, et quand vous serez prêt, entraînez-vous avec moi davantage.';
-- Quest 1534 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1534, 'frFR', 'Avez-vous l\'eau, $N? Les légendes disent que les ruines étaient protégées par de grandes créatures de la nature qui ne se soucient pas des visiteurs, mais ce pourraient être des mythes pour effrayer les ennemis des elfes de la nuit.$B$BQuoi qu\'il en soit, faites attention.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous l\'eau, $N? Les légendes disent que les ruines étaient protégées par de grandes créatures de la nature qui ne se soucient pas des visiteurs, mais ce pourraient être des mythes pour effrayer les ennemis des elfes de la nuit.$B$BQuoi qu\'il en soit, faites attention.';
-- Quest 1534 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1534, 'frFR', 'Merveilleux, $N. Avec les trois échantillons recueillis, je peux vous créer un flacon de l\'eau la plus pure que toute créature vivante trouvera. Il sera utilisé dans les étapes suivantes de votre rite de passage.$B$Je suis heureux de vous compter parmi les nôtres, $N. Vous faites tout $c fier, et j\'attends avec impatience d\'entendre vos exploits à l\'avenir.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux, $N. Avec les trois échantillons recueillis, je peux vous créer un flacon de l\'eau la plus pure que toute créature vivante trouvera. Il sera utilisé dans les étapes suivantes de votre rite de passage.$B$Je suis heureux de vous compter parmi les nôtres, $N. Vous faites tout $c fier, et j\'attends avec impatience d\'entendre vos exploits à l\'avenir.';
-- Quest 1535 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1535, 'frFR', 'Je suis presque prêt à vous envoyer dans vos autres tâches. Avez-vous rempli la peau ? $B$Je sais à quel point les quilboar peuvent être protecteurs. Même une si petite source d\'eau est un vaste trésor pour eux. Ils font de grands festins quand la moindre pluie tombe sur les Terres Désolées. L\'eau est sacrée pour leur espèce parce qu\'elle est si rare. Comprenez-vous ?') ON DUPLICATE KEY UPDATE CompletionText='Je suis presque prêt à vous envoyer dans vos autres tâches. Avez-vous rempli la peau ? $B$Je sais à quel point les quilboar peuvent être protecteurs. Même une si petite source d\'eau est un vaste trésor pour eux. Ils font de grands festins quand la moindre pluie tombe sur les Terres Désolées. L\'eau est sacrée pour leur espèce parce qu\'elle est si rare. Comprenez-vous ?';

-- Quest 1535 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1535, 'frFR', 'J\'ai pensé qu\'il y aurait un bain de sang si vous essayiez de prendre de l\'eau dans l\'étang. C\'est dommage que les quilboar ne réalisent pas que tous les êtres vivants sont liés ; que leur avidité ne fait que perpétuer la douleur et la souffrance de leur peuple. Combien pourraient-ils accomplir s\'ils mettaient de côté leurs différences et que leurs clans s\'unissaient.$B$BAinsi, dommage, mais plus probablement un cadeau pour les autres races des Barrens.') ON DUPLICATE KEY UPDATE RewardText='J\'ai pensé qu\'il y aurait un bain de sang si vous essayiez de prendre de l\'eau dans l\'étang. C\'est dommage que les quilboar ne réalisent pas que tous les êtres vivants sont liés ; que leur avidité ne fait que perpétuer la douleur et la souffrance de leur peuple. Combien pourraient-ils accomplir s\'ils mettaient de côté leurs différences et que leurs clans s\'unissaient.$B$BAinsi, dommage, mais plus probablement un cadeau pour les autres races des Barrens.';
-- Quest 1536 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1536, 'frFR', 'Le puits qui reste pur dans la ville me rappelle des histoires qui m\'ont été racontées quand j\'étais plus jeune, $N. Même dans les moments de grande douleur et de chagrin, on peut trouver un éclat d\'espoir, un petit symbole autour duquel se rassembler. Le peuple orc voit Thrall de cette façon. Il a survécu contre toute attente et s\'est levé pour mener notre peuple par sa force et son exemple.$B$BI\'m not sure any orc has suffered as much as he has, but at the same time, I\'m not sure any orc is as strong as he is either.') ON DUPLICATE KEY UPDATE CompletionText='Le puits qui reste pur dans la ville me rappelle des histoires qui m\'ont été racontées quand j\'étais plus jeune, $N. Même dans les moments de grande douleur et de chagrin, on peut trouver un éclat d\'espoir, un petit symbole autour duquel se rassembler. Le peuple orc voit Thrall de cette façon. Il a survécu contre toute attente et s\'est levé pour mener notre peuple par sa force et son exemple.$B$BI\'m not sure any orc has suffered as much as he has, but at the same time, I\'m not sure any orc is as strong as he is either.';
-- Quest 1536 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1536, 'frFR', 'C\'est bien, $N. Vous êtes dévoué à la tâche à accomplir et vous avez la capacité de rechercher ce qui est nécessaire.$B$BUn autre échantillon est tout ce dont j\'ai besoin pour créer le réactif nécessaire à votre sapta. Islen sera également ravi.') ON DUPLICATE KEY UPDATE RewardText='C\'est bien, $N. Vous êtes dévoué à la tâche à accomplir et vous avez la capacité de rechercher ce qui est nécessaire.$B$BUn autre échantillon est tout ce dont j\'ai besoin pour créer le réactif nécessaire à votre sapta. Islen sera également ravi.';
-- Quest 1559 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1559, 'frFR', 'Alors vous êtes ingénieur, hein ? Eh bien, pour votre aide à me procurer ces perles, voici la recette des bombes éclair.$b$bBonne chance, et essayez de ne pas vous aveugler !') ON DUPLICATE KEY UPDATE RewardText='Alors vous êtes ingénieur, hein ? Eh bien, pour votre aide à me procurer ces perles, voici la recette des bombes éclair.$b$bBonne chance, et essayez de ne pas vous aveugler !';
-- Quest 1578 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1578, 'frFR', 'Je n\'ai pas le temps de bavarder. Avez-vous des affaires avec moi ?') ON DUPLICATE KEY UPDATE CompletionText='Je n\'ai pas le temps de bavarder. Avez-vous des affaires avec moi ?';
-- Quest 1578 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1578, 'frFR', 'Ah, pardon !  Je ne savais pas que vous étiez là pour aider à réapprovisionner nos troupes.  Ce que vous avez fait sera d\'une grande aide !$B$BVoici des plans pour une armure.  J\'espère que vous les trouverez utiles.') ON DUPLICATE KEY UPDATE RewardText='Ah, pardon !  Je ne savais pas que vous étiez là pour aider à réapprovisionner nos troupes.  Ce que vous avez fait sera d\'une grande aide !$B$BVoici des plans pour une armure.  J\'espère que vous les trouverez utiles.';
-- Quest 1581 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1581, 'frFR', 'Bonjour, $N. Avez-vous des élixirs à échanger ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $N. Avez-vous des élixirs à échanger ?';
-- Quest 1582 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1582, 'frFR', 'Oui, ce sont de bonnes pièces. Vous avez une main habile et un œil pour les détails. Votre avenir en tant que cordonnier est prometteur.$B$BVoici, <name>. Laissez-moi vous montrer le patron pour faire le Gilet de Lumière de Lune.') ON DUPLICATE KEY UPDATE RewardText='Oui, ce sont de bonnes pièces. Vous avez une main habile et un œil pour les détails. Votre avenir en tant que cordonnier est prometteur.$B$BVoici, <name>. Laissez-moi vous montrer le patron pour faire le Gilet de Lumière de Lune.';
-- Quest 1598 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1598, 'frFR', 'Il était trop ostentatoire pour moi de voler le livre moi-même. Quelle chance qu\'un de leurs propres idiots ait fait le sale boulot pour moi.') ON DUPLICATE KEY UPDATE CompletionText='Il était trop ostentatoire pour moi de voler le livre moi-même. Quelle chance qu\'un de leurs propres idiots ait fait le sale boulot pour moi.';
-- Quest 1599 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1599, 'frFR', 'Ces charmes de plumes que portent les novices ont une sorte de pouvoir magique. Ce sera intéressant de les rechercher. Je ne m\'y attendrais pas des trolls.') ON DUPLICATE KEY UPDATE CompletionText='Ces charmes de plumes que portent les novices ont une sorte de pouvoir magique. Ce sera intéressant de les rechercher. Je ne m\'y attendrais pas des trolls.';
-- Quest 1599 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1599, 'frFR', 'Très bien, très bien ! Vous avez bien fait, $N. Peut-être que l\'intérêt qui est montré en vous est mérité, après tout.$B$BC\'est à eux de décider--en supposant que votre imp ne vous surpasse pas et ne mette pas fin à votre carrière. Pour l\'instant, je suis satisfait que vous survivrez probablement à vos premiers mois en tant que $c.$B$BA mot sur l\'imp, $N. Comme un $R sait, ne laissez pas sa taille vous tromper, sa magie peut être très dangereuse.') ON DUPLICATE KEY UPDATE RewardText='Très bien, très bien ! Vous avez bien fait, $N. Peut-être que l\'intérêt qui est montré en vous est mérité, après tout.$B$BC\'est à eux de décider--en supposant que votre imp ne vous surpasse pas et ne mette pas fin à votre carrière. Pour l\'instant, je suis satisfait que vous survivrez probablement à vos premiers mois en tant que $c.$B$BA mot sur l\'imp, $N. Comme un $R sait, ne laissez pas sa taille vous tromper, sa magie peut être très dangereuse.';
-- Quest 1618 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1618, 'frFR', 'J\'espère que vous êtes ici avec de bonnes nouvelles d\'Ironforge. Parce que je suis à bout !') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que vous êtes ici avec de bonnes nouvelles d\'Ironforge. Parce que je suis à bout !';
-- Quest 1618 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1618, 'frFR', 'Merci, <name>.  Cela m\'aidera énormément.  Avec les orcs de Blackrock qui attaquent depuis le Fort de Stonewatch et les gnolls de Redridge qui rôdent dans les contreforts au nord, je suis toujours en train de réparer des armures et de fabriquer de nouvelles armes pour nos troupes.$B$BLes fournitures que vous avez apportées me donneront un moment de paix.  J\'aurai le temps de vous apprendre quelque chose...') ON DUPLICATE KEY UPDATE RewardText='Merci, <name>.  Cela m\'aidera énormément.  Avec les orcs de Blackrock qui attaquent depuis le Fort de Stonewatch et les gnolls de Redridge qui rôdent dans les contreforts au nord, je suis toujours en train de réparer des armures et de fabriquer de nouvelles armes pour nos troupes.$B$BLes fournitures que vous avez apportées me donneront un moment de paix.  J\'aurai le temps de vous apprendre quelque chose...';
-- Quest 1638 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1638, 'frFR', 'Oh ho ! Prenez un verre avec moi, $N. Vous avez l\'air dur à l\'extérieur, mais voyons si votre estomac peut supporter les plus fortes bières du Pig and Whistle !!$B$BOu... étiez-vous ici pour un cours ?') ON DUPLICATE KEY UPDATE RewardText='Oh ho ! Prenez un verre avec moi, $N. Vous avez l\'air dur à l\'extérieur, mais voyons si votre estomac peut supporter les plus fortes bières du Pig and Whistle !!$B$BOu... étiez-vous ici pour un cours ?';
-- Quest 1639 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1639, 'frFR', 'Bonjour, fancy $gboy:girl;! Qu\'est-ce qu\'une chose aussi snob que toi fait au Pig and Whistle ? Fais attention, ou tu pourrais te casser un ongle...') ON DUPLICATE KEY UPDATE RewardText='Bonjour, fancy $gboy:girl;! Qu\'est-ce qu\'une chose aussi snob que toi fait au Pig and Whistle ? Fais attention, ou tu pourrais te casser un ongle...';

-- Quest 1641 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1641, 'frFR', 'Ici à Stormwind, je suis responsable de mettre les paladins sur le chemin de la vertu supérieure alors qu\'ils se consacrent à la Lumière et défendent Azeroth contre la Horde et d\'autres menaces.$B$BIl est temps pour vous de faire votre premier pas vers une vertu véritable. Si vous l\'acceptez, je vous donnerai un Livre de Divinité. En l\'étudiant, vous apprendrez des choses sur la Lumière et ce qui est attendu de vous. Si vous le comprenez, et que vous êtes capable, alors vous réussirez à atteindre des capacités supérieures.') ON DUPLICATE KEY UPDATE RewardText='Ici à Stormwind, je suis responsable de mettre les paladins sur le chemin de la vertu supérieure alors qu\'ils se consacrent à la Lumière et défendent Azeroth contre la Horde et d\'autres menaces.$B$BIl est temps pour vous de faire votre premier pas vers une vertu véritable. Si vous l\'acceptez, je vous donnerai un Livre de Divinité. En l\'étudiant, vous apprendrez des choses sur la Lumière et ce qui est attendu de vous. Si vous le comprenez, et que vous êtes capable, alors vous réussirez à atteindre des capacités supérieures.';
-- Quest 1644 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1644, 'frFR', 'J\'espère que mon John a plus de chance à Ironforge. Il déteste tellement ses voyages là-bas parce que cela me laisse seul avec les enfants, mais il sait que cela doit être fait. Il est si bon cœur.$B$BCertaines années ont été plus faciles que d\'autres, mais celle-ci a été bien plus difficile. C\'est presque comme si quelque chose dans l\'air signalait un énorme changement. Qui sait cependant ?') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que mon John a plus de chance à Ironforge. Il déteste tellement ses voyages là-bas parce que cela me laisse seul avec les enfants, mais il sait que cela doit être fait. Il est si bon cœur.$B$BCertaines années ont été plus faciles que d\'autres, mais celle-ci a été bien plus difficile. C\'est presque comme si quelque chose dans l\'air signalait un énorme changement. Qui sait cependant ?';
-- Quest 1644 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1644, 'frFR', 'Merci, $N, merci beaucoup !$B$BLes enfants seront tellement contents, et vous m\'avez fait gagner tellement de temps. Je pourrai maintenant me concentrer sur les autres besoins des enfants, et j\'espère que mon John pourra rentrer chez lui plus tôt que nous le pensions.$B$BMerci encore, $N. Je savais que je pouvais compter sur la charité des autres. Que la Lumière soit avec vous.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N, merci beaucoup !$B$BLes enfants seront tellement contents, et vous m\'avez fait gagner tellement de temps. Je pourrai maintenant me concentrer sur les autres besoins des enfants, et j\'espère que mon John pourra rentrer chez lui plus tôt que nous le pensions.$B$BMerci encore, $N. Je savais que je pouvais compter sur la charité des autres. Que la Lumière soit avec vous.';
-- Quest 1645 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1645, 'frFR', 'Ici à Ironforge, je suis responsable de mettre les paladins sur le chemin de la vertu supérieure alors qu\'ils se consacrent à la Lumière et défendent Azeroth contre la Horde et d\'autres menaces.$B$BIl est temps pour vous de faire votre premier pas vers une vertu véritable. Si vous l\'acceptez, je vous donnerai un Livre de Divinité. En l\'étudiant, vous apprendrez des choses sur la Lumière et ce qui est attendu de vous. Si vous le comprenez, et que vous êtes capable, alors vous réussirez à atteindre des capacités supérieures.') ON DUPLICATE KEY UPDATE RewardText='Ici à Ironforge, je suis responsable de mettre les paladins sur le chemin de la vertu supérieure alors qu\'ils se consacrent à la Lumière et défendent Azeroth contre la Horde et d\'autres menaces.$B$BIl est temps pour vous de faire votre premier pas vers une vertu véritable. Si vous l\'acceptez, je vous donnerai un Livre de Divinité. En l\'étudiant, vous apprendrez des choses sur la Lumière et ce qui est attendu de vous. Si vous le comprenez, et que vous êtes capable, alors vous réussirez à atteindre des capacités supérieures.';
-- Quest 1646 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1646, 'frFR', 'Bienvenue de retour, $N. Vous avez passé du temps à lire le livre, j\'espère?$B$BAlors vous devriez être prêt à être mis à l\'épreuve. Il y a toujours des tâches à accomplir dans la ville et sur nos terres ; des actes de compassion et de compréhension ; des gens qui ont besoin d\'aide ; des créatures à abattre.$B$BEn prouvant que vous avez la patience d\'aider les autres, surtout ceux qui sont moins fortunés, vous prouvez que vous êtes un serviteur de la Lumière et de l\'esprit sain.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue de retour, $N. Vous avez passé du temps à lire le livre, j\'espère?$B$BAlors vous devriez être prêt à être mis à l\'épreuve. Il y a toujours des tâches à accomplir dans la ville et sur nos terres ; des actes de compassion et de compréhension ; des gens qui ont besoin d\'aide ; des créatures à abattre.$B$BEn prouvant que vous avez la patience d\'aider les autres, surtout ceux qui sont moins fortunés, vous prouvez que vous êtes un serviteur de la Lumière et de l\'esprit sain.';
-- Quest 1647 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1647, 'frFR', 'L\'ORPHELINAT DE STOR... oh, pardon, je ne voulais pas vous crier dessus, monsieur.$B$BJe m\'appelle John Turner. Comment allez-vous?$B$BBien, bien, je suis heureux d\'apprendre que les choses vont bien pour vous. J\'ai déjà eu une longue journée de travail, et mon épouse me manque terriblement, mais c\'est le prix que vous devez payer quand il y a des bouches à nourrir et des dos à vêtir.') ON DUPLICATE KEY UPDATE RewardText='L\'ORPHELINAT DE STOR... oh, pardon, je ne voulais pas vous crier dessus, monsieur.$B$BJe m\'appelle John Turner. Comment allez-vous?$B$BBien, bien, je suis heureux d\'apprendre que les choses vont bien pour vous. J\'ai déjà eu une longue journée de travail, et mon épouse me manque terriblement, mais c\'est le prix que vous devez payer quand il y a des bouches à nourrir et des dos à vêtir.';
-- Quest 1648 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1648, 'frFR', 'Avec l\'afflux de marchands ici et dans tout Azeroth, il y a une plus petite quantité d\'articles que nous utilisons pour faire des vêtements pour les enfants de notre orphelinat. M\'aider à collecter du lin pour que mon épouse puisse faire de nouveaux vêtements pour eux est très noble de votre part, $N. Merci.$B$BJ\'espère pouvoir rentrer chez moi auprès de mon épouse bientôt.') ON DUPLICATE KEY UPDATE CompletionText='Avec l\'afflux de marchands ici et dans tout Azeroth, il y a une plus petite quantité d\'articles que nous utilisons pour faire des vêtements pour les enfants de notre orphelinat. M\'aider à collecter du lin pour que mon épouse puisse faire de nouveaux vêtements pour eux est très noble de votre part, $N. Merci.$B$BJ\'espère pouvoir rentrer chez moi auprès de mon épouse bientôt.';
-- Quest 1648 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1648, 'frFR', 'C\'est tellement gentil de votre part, $N. Merci encore.$B$BVous êtes un homme noble de faire cela pour moi. Il n\'est pas étonnant que vous ayez choisi de suivre la Lumière. J\'aimerais qu\'il y ait un moyen de vous récompenser pour tout ce que vous avez fait... c\'est quoi ? C\'est le moins que vous puissiez faire ? Voyez ? C\'est de ça dont je parle, $N, noble jusqu\'au bout.$B$BSoyez prudent, et que la Lumière vous protège dans vos voyages.') ON DUPLICATE KEY UPDATE RewardText='C\'est tellement gentil de votre part, $N. Merci encore.$B$BVous êtes un homme noble de faire cela pour moi. Il n\'est pas étonnant que vous ayez choisi de suivre la Lumière. J\'aimerais qu\'il y ait un moyen de vous récompenser pour tout ce que vous avez fait... c\'est quoi ? C\'est le moins que vous puissiez faire ? Voyez ? C\'est de ça dont je parle, $N, noble jusqu\'au bout.$B$BSoyez prudent, et que la Lumière vous protège dans vos voyages.';
-- Quest 1651 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1651, 'frFR', 'Nous y sommes parvenus, $N ! Merci pour votre aide. Vous avez été vraiment incroyable là-bas. Je n\'aurais jamais pensé qu\'un $c pourrait gérer autant d\'ennemis à la fois.$B$BVous avez vraiment fait preuve de courage face à des chances écrasantes.') ON DUPLICATE KEY UPDATE RewardText='Nous y sommes parvenus, $N ! Merci pour votre aide. Vous avez été vraiment incroyable là-bas. Je n\'aurais jamais pensé qu\'un $c pourrait gérer autant d\'ennemis à la fois.$B$BVous avez vraiment fait preuve de courage face à des chances écrasantes.';
-- Quest 1654 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1654, 'frFR', 'Les objets que vous recherchez seront difficiles à obtenir, mais je peux vous assurer que l\'arme que je vous fabriquerai en vaudra la peine.$B$BCe sera mon meilleur travail à ce jour, et un petit paiement pour le service que vous m\'avez rendu.') ON DUPLICATE KEY UPDATE CompletionText='Les objets que vous recherchez seront difficiles à obtenir, mais je peux vous assurer que l\'arme que je vous fabriquerai en vaudra la peine.$B$BCe sera mon meilleur travail à ce jour, et un petit paiement pour le service que vous m\'avez rendu.';
-- Quest 1654 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1654, 'frFR', 'C\'est merveilleux ! Vous avez obtenu tous les objets.$B$BJe ne devrais pas avoir de problème à vous forger une arme grandiose avec ceux-ci. J\'ai en fait eu les plans pour faire cela depuis un certain temps. Je n\'ai juste jamais eu l\'occasion de rassembler les marchandises. Merci, $N.$B$BC\'est bon d\'avoir à nouveau le marteau de mon père... et une gemme Kor. Je n\'aurais jamais pensé voir un de ceux-là moi-même.') ON DUPLICATE KEY UPDATE RewardText='C\'est merveilleux ! Vous avez obtenu tous les objets.$B$BJe ne devrais pas avoir de problème à vous forger une arme grandiose avec ceux-ci. J\'ai en fait eu les plans pour faire cela depuis un certain temps. Je n\'ai juste jamais eu l\'occasion de rassembler les marchandises. Merci, $N.$B$BC\'est bon d\'avoir à nouveau le marteau de mon père... et une gemme Kor. Je n\'aurais jamais pensé voir un de ceux-là moi-même.';
-- Quest 1657 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1657, 'frFR', 'Avez-vous livré notre "cadeau" aux habitants de Southshore?$B$B<Darkcaller Yanka rit malicieusement.>') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous livré notre "cadeau" aux habitants de Southshore?$B$B<Darkcaller Yanka rit malicieusement.>';
-- Quest 1661 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1661, 'frFR', 'Félicitations, et que la Lumière vous protège.') ON DUPLICATE KEY UPDATE RewardText='Félicitations, et que la Lumière vous protège.';
-- Quest 1682 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1682, 'frFR', 'Voici quelques armes, tout juste sorties de l\'enclume et faites avec le nouveau minerai umbrale que vous m\'avez apporté !$B$BS\'il vous plaît, $N, choisissez !') ON DUPLICATE KEY UPDATE RewardText='Voici quelques armes, tout juste sorties de l\'enclume et faites avec le nouveau minerai umbrale que vous m\'avez apporté !$B$BS\'il vous plaît, $N, choisissez !';
-- Quest 1683 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1683, 'frFR', 'Avez-vous la corne, $N? Notre puits lunaire est-il libre du fiend Vorlus ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous la corne, $N? Notre puits lunaire est-il libre du fiend Vorlus ?';

-- Quest 1683 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1683, 'frFR', 'Bien joué, $N$. C\'est une bonne nouvelle que Vorlus soit vaincu et que notre puits de lune soit purifié, et c\'est bon de voir de jeunes guerriers désireux de garder notre cher Teldrassil libre de corruption.$B$BMaintenant, commençons votre entraînement...') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N$. C\'est une bonne nouvelle que Vorlus soit vaincu et que notre puits de lune soit purifié, et c\'est bon de voir de jeunes guerriers désireux de garder notre cher Teldrassil libre de corruption.$B$BMaintenant, commençons votre entraînement...';
-- Quest 1684 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1684, 'frFR', 'Je vous adresse mes salutations, $N$. Votre nom résonne dans Darnassus, car vous montrez du potentiel. Mais nous verrons bientôt si vous possédez la force de volonté pour suivre le chemin de la $c$.') ON DUPLICATE KEY UPDATE RewardText='Je vous adresse mes salutations, $N$. Votre nom résonne dans Darnassus, car vous montrez du potentiel. Mais nous verrons bientôt si vous possédez la force de volonté pour suivre le chemin de la $c$.';
-- Quest 1685 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1685, 'frFR', 'Il était temps que vous apparaissiez. Bien que, peut-être, j\'aurais dû envoyer quelqu\'un de plus capable que Remen pour vous trouver.$B$BPeu importe.$B$BVous êtes resté trop longtemps sans vous entraîner, et un <class> sans entraînement n\'est pas apte à garder sa tête sur ses épaules pour longtemps.') ON DUPLICATE KEY UPDATE RewardText='Il était temps que vous apparaissiez. Bien que, peut-être, j\'aurais dû envoyer quelqu\'un de plus capable que Remen pour vous trouver.$B$BPeu importe.$B$BVous êtes resté trop longtemps sans vous entraîner, et un <class> sans entraînement n\'est pas apte à garder sa tête sur ses épaules pour longtemps.';
-- Quest 1686 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1686, 'frFR', 'Avez-vous vaincu l\'Ombre d\'Elura, $N$? Et avez-vous la minerai d\'elunite perdue?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous vaincu l\'Ombre d\'Elura, $N$? Et avez-vous la minerai d\'elunite perdue?';
-- Quest 1686 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1686, 'frFR', 'Bravely done, $N.$B$BVous avez donné à l\'Ombre d\'Elura une paix bien méritée, et nous utiliserons l\'elunite recueillie pour fabriquer une belle arme pour vous.') ON DUPLICATE KEY UPDATE RewardText='Bravely done, $N.$B$BVous avez donné à l\'Ombre d\'Elura une paix bien méritée, et nous utiliserons l\'elunite recueillie pour fabriquer une belle arme pour vous.';
-- Quest 1688 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1688, 'frFR', 'Même les plus âgés et sages peuvent être démunis par les manœuvres de la jeunesse et de la beauté, $N$. Un conseil que vous feriez bien de garder à l\'esprit tout au long de votre vie.') ON DUPLICATE KEY UPDATE CompletionText='Même les plus âgés et sages peuvent être démunis par les manœuvres de la jeunesse et de la beauté, $N$. Un conseil que vous feriez bien de garder à l\'esprit tout au long de votre vie.';
-- Quest 1688 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1688, 'frFR', 'Surena était talentueuse, mais pas assez pour maîtriser la magie $c$ par elle-même. C\'est dommage de voir un talent gaspillé, mais parfois c\'est nécessaire.$B$J\'espère que mon investissement en vous donnera des résultats différents.') ON DUPLICATE KEY UPDATE RewardText='Surena était talentueuse, mais pas assez pour maîtriser la magie $c$ par elle-même. C\'est dommage de voir un talent gaspillé, mais parfois c\'est nécessaire.$B$J\'espère que mon investissement en vous donnera des résultats différents.';
-- Quest 1689 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1689, 'frFR', 'Je ne peux pas vous montrer comment contrôler un marcheur du vide tant que vous n\'en avez pas maîtrisé un.') ON DUPLICATE KEY UPDATE CompletionText='Je ne peux pas vous montrer comment contrôler un marcheur du vide tant que vous n\'en avez pas maîtrisé un.';
-- Quest 1689 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1689, 'frFR', 'Vous avez mieux fait que je ne l\'espérais, $N$, mais comme je l\'avais espéré. Maintenant, vous pouvez apprendre à commander votre marcheur du vide asservi, un allié que vous trouverez précieux dans les épreuves qui vous attendent.$B$Je n\'ai rien de plus à vous enseigner pour l\'instant, mais je ne suis pas loin d\'avoir fini avec vous, $N$.') ON DUPLICATE KEY UPDATE RewardText='Vous avez mieux fait que je ne l\'espérais, $N$, mais comme je l\'avais espéré. Maintenant, vous pouvez apprendre à commander votre marcheur du vide asservi, un allié que vous trouverez précieux dans les épreuves qui vous attendent.$B$Je n\'ai rien de plus à vous enseigner pour l\'instant, mais je ne suis pas loin d\'avoir fini avec vous, $N$.';
-- Quest 1690 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1690, 'frFR', 'Si vite de retour ? J\'espère que vous avez réussi à apporter une justice de style gobelin à ces Bandits et Voleurs Vagabonds comme je vous l\'ai demandé !') ON DUPLICATE KEY UPDATE CompletionText='Si vite de retour ? J\'espère que vous avez réussi à apporter une justice de style gobelin à ces Bandits et Voleurs Vagabonds comme je vous l\'ai demandé !';
-- Quest 1691 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1691, 'frFR', 'Eh bien, avez-vous réussi à éliminer ces nomades comme je l\'ai demandé ? La Compagnie des Eaux de Gadgetzan développe des plans basés sur votre succès ici ! Ne nous décevez pas, maintenant...') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, avez-vous réussi à éliminer ces nomades comme je l\'ai demandé ? La Compagnie des Eaux de Gadgetzan développe des plans basés sur votre succès ici ! Ne nous décevez pas, maintenant...';
-- Quest 1691 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1691, 'frFR', 'Travail de premier ordre, <name>... de premier ordre !  Vous avez réduit la population nomade à un point où nous pouvons réellement leur faire face !$B$Si ce n\'est pas déjà fait, parlez à l\'Opérateur de Spigot Luglunket ici ; il donne une prime sur n\'importe quel sac d\'eau de Vagabond que vous avez pu trouver en mettant ces nomades à justice !') ON DUPLICATE KEY UPDATE RewardText='Travail de premier ordre, <name>... de premier ordre !  Vous avez réduit la population nomade à un point où nous pouvons réellement leur faire face !$B$Si ce n\'est pas déjà fait, parlez à l\'Opérateur de Spigot Luglunket ici ; il donne une prime sur n\'importe quel sac d\'eau de Vagabond que vous avez pu trouver en mettant ces nomades à justice !';
-- Quest 1692 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1692, 'frFR', 'Salutations, jeune $C$. Comment mes compétences peuvent-elles vous servir ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, jeune $C$. Comment mes compétences peuvent-elles vous servir ?';
-- Quest 1692 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1692, 'frFR', 'Ah, minerai d\'elunite. C\'est un métal fin pour travailler, car il est béni par la déesse Elune elle-même. Ce serait un honneur d\'en fabriquer des armes. $B$Veuillez patienter pendant que je travaille...') ON DUPLICATE KEY UPDATE RewardText='Ah, minerai d\'elunite. C\'est un métal fin pour travailler, car il est béni par la déesse Elune elle-même. Ce serait un honneur d\'en fabriquer des armes. $B$Veuillez patienter pendant que je travaille...';
-- Quest 1693 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1693, 'frFR', '$N, j\'ai fabriqué ces armes avec l\'elunite que vous m\'avez apporté. S\'il vous plaît, prenez celle qui vous convient le mieux.$B$Et je vous remercie. Travailler avec de l\'elunite est à la fois un honneur et un plaisir.') ON DUPLICATE KEY UPDATE RewardText='$N, j\'ai fabriqué ces armes avec l\'elunite que vous m\'avez apporté. S\'il vous plaît, prenez celle qui vous convient le mieux.$B$Et je vous remercie. Travailler avec de l\'elunite est à la fois un honneur et un plaisir.';

-- Quest 1698 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1698, 'frFR', 'Hah ! Alors vous avez entendu parler de mon défi, n\'est-ce pas ? $B$BAsse-toi et écoute. Bois un verre, et savoure-le... parce que ce pourrait être ton dernier.') ON DUPLICATE KEY UPDATE RewardText='Hah ! Alors vous avez entendu parler de mon défi, n\'est-ce pas ? $B$BAsse-toi et écoute. Bois un verre, et savoure-le... parce que ce pourrait être ton dernier.';
-- Quest 1700 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1700, 'frFR', 'Bonjour, et bienvenue. Comment puis-je vous être utile ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, et bienvenue. Comment puis-je vous être utile ?';
-- Quest 1700 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1700, 'frFR', 'Furen a écrit ça ? Comment ose-t-il ! Pourquoi, je lui ai tout appris ! Penser qu\'il pourrait m\'apprendre quelque chose est outrageant ! Outrageant !$B$BHm... mais il y a quelque chose dans ses notes que j\'aimerais essayer...') ON DUPLICATE KEY UPDATE RewardText='Furen a écrit ça ? Comment ose-t-il ! Pourquoi, je lui ai tout appris ! Penser qu\'il pourrait m\'apprendre quelque chose est outrageant ! Outrageant !$B$BHm... mais il y a quelque chose dans ses notes que j\'aimerais essayer...';
-- Quest 1701 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1701, 'frFR', 'Tu as tout ? Incroyable ! J\'avais peur que ces chimères ne te dévorent à coup sûr !$B$BEh bien, commençons par cette armure...') ON DUPLICATE KEY UPDATE RewardText='Tu as tout ? Incroyable ! J\'avais peur que ces chimères ne te dévorent à coup sûr !$B$BEh bien, commençons par cette armure...';
-- Quest 1703 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1703, 'frFR', 'Ce sont intéressants, très intéressants en effet. Mon collègue nain Furen a fait une découverte assez grandiose !$B$BMerci, $N. Ce sera un honneur d\'appliquer ses nouvelles techniques à mes propres créations.') ON DUPLICATE KEY UPDATE RewardText='Ce sont intéressants, très intéressants en effet. Mon collègue nain Furen a fait une découverte assez grandiose !$B$BMerci, $N. Ce sera un honneur d\'appliquer ses nouvelles techniques à mes propres créations.';
-- Quest 1704 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1704, 'frFR', 'Bonne journée, ou matin ou soir. Je ne peux pas le dire d\'ici en bas. Alors, avez-vous affaire pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Bonne journée, ou matin ou soir. Je ne peux pas le dire d\'ici en bas. Alors, avez-vous affaire pour moi ?';
-- Quest 1704 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1704, 'frFR', 'Oh là là ! Ces notes sont incroyables ! Et mieux encore... elles sont incroyables et elles sont stupéfiantes et elles me font vaciller les genoux !$B$BFuren a fait une percée ! Une vraie percée ! J\'ai hâte d\'essayer sa nouvelle technique !') ON DUPLICATE KEY UPDATE RewardText='Oh là là ! Ces notes sont incroyables ! Et mieux encore... elles sont incroyables et elles sont stupéfiantes et elles me font vaciller les genoux !$B$BFuren a fait une percée ! Une vraie percée ! J\'ai hâte d\'essayer sa nouvelle technique !';
-- Quest 1705 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1705, 'frFR', '$N, avez-vous le sang brûlant et la roche ? J\'en aurai besoin pour compléter l\'armure.') ON DUPLICATE KEY UPDATE CompletionText='$N, avez-vous le sang brûlant et la roche ? J\'en aurai besoin pour compléter l\'armure.';
-- Quest 1705 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1705, 'frFR', 'Bon travail ! Maintenant, si vous voulez bien m\'excuser, j\'ai du travail à faire moi-même...') ON DUPLICATE KEY UPDATE RewardText='Bon travail ! Maintenant, si vous voulez bien m\'excuser, j\'ai du travail à faire moi-même...';
-- Quest 1706 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1706, 'frFR', 'Je n\'arrive presque pas à le croire ! La technique de Furen a réussi, et cette armure devrait résister à des niveaux de stress énormes.$b$BVoici, $N. Et merci. Je n\'aurais pas cru la découverte de Furen si vous n\'aviez pas rassemblé les matériaux dont j\'avais besoin pour le tester moi-même.') ON DUPLICATE KEY UPDATE RewardText='Je n\'arrive presque pas à le croire ! La technique de Furen a réussi, et cette armure devrait résister à des niveaux de stress énormes.$b$BVoici, $N. Et merci. Je n\'aurais pas cru la découverte de Furen si vous n\'aviez pas rassemblé les matériaux dont j\'avais besoin pour le tester moi-même.';
-- Quest 1708 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1708, 'frFR', 'Bonjour bonjour, $N ! Avez-vous le corail ardent ? J\'ai hâte de commencer le travail !') ON DUPLICATE KEY UPDATE CompletionText='Bonjour bonjour, $N ! Avez-vous le corail ardent ? J\'ai hâte de commencer le travail !';
-- Quest 1708 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1708, 'frFR', 'C\'est ça ! Bien joué ! Maintenant, laisse-moi faire fondre et marteler ça pour pouvoir appliquer la technique de Furen avec la mienne, et ensuite nous verrons ce qui se passe !$B$Oh là là, oh là là ! Je sais que l\'armure sera très très très solide !') ON DUPLICATE KEY UPDATE RewardText='C\'est ça ! Bien joué ! Maintenant, laisse-moi faire fondre et marteler ça pour pouvoir appliquer la technique de Furen avec la mienne, et ensuite nous verrons ce qui se passe !$B$Oh là là, oh là là ! Je sais que l\'armure sera très très très solide !';
-- Quest 1709 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1709, 'frFR', 'Voici votre armure, $N. Le processus de Furen a fonctionné brillamment ! Parfaitement ! Marvelieusement, vraiment !$B$Vous pourriez faire rouler cette armure avec une pièce d\'artillerie et elle reviendrait immédiatement à sa forme !') ON DUPLICATE KEY UPDATE RewardText='Voici votre armure, $N. Le processus de Furen a fonctionné brillamment ! Parfaitement ! Marvelieusement, vraiment !$B$Vous pourriez faire rouler cette armure avec une pièce d\'artillerie et elle reviendrait immédiatement à sa forme !';
-- Quest 1710 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1710, 'frFR', 'Avez-vous les coquillages, $N ? Ils sont assez solides, et peuvent être transformés en une laque que j\'utiliserai pour recouvrir les maillons de ma nouvelle armure en maille.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les coquillages, $N ? Ils sont assez solides, et peuvent être transformés en une laque que j\'utiliserai pour recouvrir les maillons de ma nouvelle armure en maille.';
-- Quest 1710 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1710, 'frFR', 'Ah, merci. Ceux-ci fonctionneront splendidement !$B$Je commencerai à fabriquer l\'armure immédiatement...') ON DUPLICATE KEY UPDATE RewardText='Ah, merci. Ceux-ci fonctionneront splendidement !$B$Je commencerai à fabriquer l\'armure immédiatement...';

-- Quest 1711 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1711, 'frFR', 'J\'ai terminé votre pièce d\'armure, et je suis très satisfait. Les nouvelles techniques de Furen se sont parfaitement mariées avec les miennes et je suis sûr que cette armure s\'avérera très résiliente.$B$BMerci, $N. Et que ceci vous serve bien dans les batailles futures.') ON DUPLICATE KEY UPDATE RewardText='J\'ai terminé votre pièce d\'armure, et je suis très satisfait. Les nouvelles techniques de Furen se sont parfaitement mariées avec les miennes et je suis sûr que cette armure s\'avérera très résiliente.$B$BMerci, $N. Et que ceci vous serve bien dans les batailles futures.';
-- Quest 1712 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1712, 'frFR', 'Avez-vous les objets, $N? Les rassembler est la preuve dont j\'ai besoin que vous ayez la force d\'affronter Cyclonian.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les objets, $N? Les rassembler est la preuve dont j\'ai besoin que vous ayez la force d\'affronter Cyclonian.';
-- Quest 1712 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1712, 'frFR', 'Vous avez rassemblé les objets pour mon sort, et m\'avez montré votre force et votre ruse. Mais la prochaine étape de notre quête est encore plus périlleuse.$b$bEspérons que votre force ne faiblira pas.') ON DUPLICATE KEY UPDATE RewardText='Vous avez rassemblé les objets pour mon sort, et m\'avez montré votre force et votre ruse. Mais la prochaine étape de notre quête est encore plus périlleuse.$b$bEspérons que votre force ne faiblira pas.';
-- Quest 1713 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1713, 'frFR', '$N, je dois avoir le cœur du tourbillon !') ON DUPLICATE KEY UPDATE CompletionText='$N, je dois avoir le cœur du tourbillon !';
-- Quest 1713 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1713, 'frFR', 'Vous l\'avez fait ! Vous avez vaincu Cyclonian et obtenu le Cœur du Tourbillon !') ON DUPLICATE KEY UPDATE RewardText='Vous l\'avez fait ! Vous avez vaincu Cyclonian et obtenu le Cœur du Tourbillon !';
-- Quest 1714 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1714, 'frFR', 'Le chaudron bout. Ses vapeurs appellent...') ON DUPLICATE KEY UPDATE CompletionText='Le chaudron bout. Ses vapeurs appellent...';
-- Quest 1714 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1714, 'frFR', 'Les charmes s\'enfoncent lentement dans les profondeurs du chaudron...$B$BUne grande bulle monte à la surface du liquide et éclate...$B$B...Et un morceau de roche en fusion tourbillonnant est révélé.') ON DUPLICATE KEY UPDATE RewardText='Les charmes s\'enfoncent lentement dans les profondeurs du chaudron...$B$BUne grande bulle monte à la surface du liquide et éclate...$B$B...Et un morceau de roche en fusion tourbillonnant est révélé.';
-- Quest 1715 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1715, 'frFR', 'Envoyé par Blackwrench, c\'est vous ? Les warlocks d\'Ironforge doivent régler leurs affaires. Il n\'y a pas autant de place et autant de maîtres à Stormwind. Avec tout le trafic accru, nous allons certainement attirer l\'attention tôt ou tard.') ON DUPLICATE KEY UPDATE RewardText='Envoyé par Blackwrench, c\'est vous ? Les warlocks d\'Ironforge doivent régler leurs affaires. Il n\'y a pas autant de place et autant de maîtres à Stormwind. Avec tout le trafic accru, nous allons certainement attirer l\'attention tôt ou tard.';
-- Quest 1716 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1716, 'frFR', 'Votre traversée a-t-elle été difficile, $N? Vous êtes venu de loin pour me parler. Mais ne crains rien, je sais pourquoi Gakin vous a envoyé, et il a eu raison, car je peux vous aider dans votre recherche.') ON DUPLICATE KEY UPDATE RewardText='Votre traversée a-t-elle été difficile, $N? Vous êtes venu de loin pour me parler. Mais ne crains rien, je sais pourquoi Gakin vous a envoyé, et il a eu raison, car je peux vous aider dans votre recherche.';
-- Quest 1717 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1717, 'frFR', 'Il est temps que vous arriviez. Bien que, peut-être aurais-je dû envoyer quelqu\'un de plus capable que Remen pour vous trouver.$B$BPeu importe.$B$BVous êtes parti trop longtemps sans vous entraîner, et un warloc sans entraînement n\'a pas l\'intention de garder sa tête sur ses épaules longtemps.') ON DUPLICATE KEY UPDATE RewardText='Il est temps que vous arriviez. Bien que, peut-être aurais-je dû envoyer quelqu\'un de plus capable que Remen pour vous trouver.$B$BPeu importe.$B$BVous êtes parti trop longtemps sans vous entraîner, et un warloc sans entraînement n\'a pas l\'intention de garder sa tête sur ses épaules longtemps.';
-- Quest 1738 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1738, 'frFR', 'Oui, je peux dire que cela fonctionnera bien, laissez-moi juste travailler avec ça un moment...$B$BTakar est un compagnon ingénieux à avoir autour, n\'est-ce pas ? Si seulement je pouvais le persuader de retourner à la civilisation.') ON DUPLICATE KEY UPDATE RewardText='Oui, je peux dire que cela fonctionnera bien, laissez-moi juste travailler avec ça un moment...$B$BTakar est un compagnon ingénieux à avoir autour, n\'est-ce pas ? Si seulement je pouvais le persuader de retourner à la civilisation.';
-- Quest 1739 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1739, 'frFR', 'Parfois, je me demande si Surena n\'était pas une succube déguisée, envoyée pour déformer et tordre mon esprit... Ha ! Je lui donne trop de crédit, je crois.') ON DUPLICATE KEY UPDATE CompletionText='Parfois, je me demande si Surena n\'était pas une succube déguisée, envoyée pour déformer et tordre mon esprit... Ha ! Je lui donne trop de crédit, je crois.';
-- Quest 1739 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1739, 'frFR', 'Bien joué, bien joué, $N. Je vois que nous avons bien fait de décider de vous entraîner. Votre performance ne déçoit certainement pas.$B$BI n\'ai aucune réticence à vous montrer comment contrôler votre succube nouvellement liée. Observez attentivement.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, bien joué, $N. Je vois que nous avons bien fait de décider de vous entraîner. Votre performance ne déçoit certainement pas.$B$BI n\'ai aucune réticence à vous montrer comment contrôler votre succube nouvellement liée. Observez attentivement.';
-- Quest 1740 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1740, 'frFR', 'Il m\'a fallu de nombreuses années pour rassembler les morceaux de l\'orbe de Zargain, mais il m\'a bien servi, car je suis sûr que l\'orbe de Soran\'ruk vous servira.') ON DUPLICATE KEY UPDATE CompletionText='Il m\'a fallu de nombreuses années pour rassembler les morceaux de l\'orbe de Zargain, mais il m\'a bien servi, car je suis sûr que l\'orbe de Soran\'ruk vous servira.';
-- Quest 1740 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1740, 'frFR', 'Oui... L\'orbe n\'était pas très fragmenté, et presque tous les morceaux sont ici. C\'est une chose simple de les recréer, de rendre Soran\'ruk entier à nouveau.$B$BI ai consacré ma vie à l\'étude des orbes de la Légion Ardente et de leur recréation. Vous m\'avez rendu un service en collectant ces morceaux pour étudier, et je vous les rendrai - entièrement reconstruits - sous la forme de votre choix.') ON DUPLICATE KEY UPDATE RewardText='Oui... L\'orbe n\'était pas très fragmenté, et presque tous les morceaux sont ici. C\'est une chose simple de les recréer, de rendre Soran\'ruk entier à nouveau.$B$BI ai consacré ma vie à l\'étude des orbes de la Légion Ardente et de leur recréation. Vous m\'avez rendu un service en collectant ces morceaux pour étudier, et je vous les rendrai - entièrement reconstruits - sous la forme de votre choix.';

-- Quest 1758 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1758, 'frFR', 'Tome of Cabal ? Hmm...semble familier. Je ne l\'ai jamais vu ici, cependant--et croyez-moi, je me souviens de chaque livre que j\'ai lu. $B$BHmm... Ah, oui ! $B$BI ai vu une référence dans les livres de catalogage de la bibliothèque.') ON DUPLICATE KEY UPDATE RewardText='Tome of Cabal ? Hmm...semble familier. Je ne l\'ai jamais vu ici, cependant--et croyez-moi, je me souviens de chaque livre que j\'ai lu. $B$BHmm... Ah, oui ! $B$BI ai vu une référence dans les livres de catalogage de la bibliothèque.';
-- Quest 1778 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1778, 'frFR', 'Alors, tu es revenu si vite, hein ? Et qu\'as-tu accompli pendant ton absence ? $B$BAs-tu pu aider une noble cause ? Peut-être as-tu appris la valeur de la charité ou quelque chose de plus sur tes obligations envers les citoyens d\'Azeroth. Dis-moi, qui as-tu aidé et comment.... Impressionnant, $N$, ce sont certainement les actions de quelqu\'un qui suit la Lumière.$B$Ce sacrifice sera toujours récompensé avec le temps.') ON DUPLICATE KEY UPDATE RewardText='Alors, tu es revenu si vite, hein ? Et qu\'as-tu accompli pendant ton absence ? $B$BAs-tu pu aider une noble cause ? Peut-être as-tu appris la valeur de la charité ou quelque chose de plus sur tes obligations envers les citoyens d\'Azeroth. Dis-moi, qui as-tu aidé et comment.... Impressionnant, $N$, ce sont certainement les actions de quelqu\'un qui suit la Lumière.$B$Ce sacrifice sera toujours récompensé avec le temps.';
-- Quest 1779 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1779, 'frFR', '*tousse*$B$BBonne journée à toi, $c$. Ne t\'inquiète pas pour mes blessures, le bon prêtre ici s\'occupera de vieux Muiredon avec le temps. Pas besoin de la puissance de ce Symbole de Vie que tu as là tout de suite.$B$Alors, ma femme t\'a envoyé me parler, hein ? Ça va. Je prendrai le temps de te parler-Je te dirai exactement ce qui est arrivé à Muiredon et à son meilleur ami Narm, un $c$ comme toi.') ON DUPLICATE KEY UPDATE RewardText='*tousse*$B$BBonne journée à toi, $c$. Ne t\'inquiète pas pour mes blessures, le bon prêtre ici s\'occupera de vieux Muiredon avec le temps. Pas besoin de la puissance de ce Symbole de Vie que tu as là tout de suite.$B$Alors, ma femme t\'a envoyé me parler, hein ? Ça va. Je prendrai le temps de te parler-Je te dirai exactement ce qui est arrivé à Muiredon et à son meilleur ami Narm, un $c$ comme toi.';
-- Quest 1780 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1780, 'frFR', 'Tu es revenu si vite, $N$. Et qu\'as-tu accompli pendant ton absence de la Cathédrale ? $B$As-tu aidé une noble cause ? Peut-être as-tu appris la valeur de la charité ou quelque chose de plus sur tes obligations envers les citoyens d\'Azeroth. Dis-moi, qui as-tu aidé et comment... Eh bien, je suis impressionné, $N$, ce sont certainement les actions de quelqu\'un qui suit la Lumière et qui valorise les autres au-dessus de lui-même.$B$Ce sacrifice sera toujours récompensé avec le temps.') ON DUPLICATE KEY UPDATE RewardText='Tu es revenu si vite, $N$. Et qu\'as-tu accompli pendant ton absence de la Cathédrale ? $B$As-tu aidé une noble cause ? Peut-être as-tu appris la valeur de la charité ou quelque chose de plus sur tes obligations envers les citoyens d\'Azeroth. Dis-moi, qui as-tu aidé et comment... Eh bien, je suis impressionné, $N$, ce sont certainement les actions de quelqu\'un qui suit la Lumière et qui valorise les autres au-dessus de lui-même.$B$Ce sacrifice sera toujours récompensé avec le temps.';
-- Quest 1782 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1782, 'frFR', 'Voici ton armure, $N$. Cela résistera aux assauts les plus forts ou mon nom n\'est pas Furen Longbeard ! $B$Et je dois te remercier. J\'ai beaucoup appris en travaillant avec les matériaux que tu m\'as apportés. Je pense que j\'aurai une autre percée un jour ! $B$Je vais envoyer ce que j\'ai appris à d\'autres $Bforgerons de l\'Alliance.$B$Je leur dirai que tu as été d\'une grande aide, et peut-être qu\'ils voudront rendre la pareille.') ON DUPLICATE KEY UPDATE RewardText='Voici ton armure, $N$. Cela résistera aux assauts les plus forts ou mon nom n\'est pas Furen Longbeard ! $B$Et je dois te remercier. J\'ai beaucoup appris en travaillant avec les matériaux que tu m\'as apportés. Je pense que j\'aurai une autre percée un jour ! $B$Je vais envoyer ce que j\'ai appris à d\'autres $Bforgerons de l\'Alliance.$B$Je leur dirai que tu as été d\'une grande aide, et peut-être qu\'ils voudront rendre la pareille.';
-- Quest 1783 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1783, 'frFR', 'Je ne peux pas te remercier assez, $gbrother:sister;.$B$Je ne peux qu\'assumer que Tiza et Muiredon t\'ont envoyé pour m\'aider si tu portes le Symbole de Vie.$B$C\'est vrai, je suis tombé dans le Fer Noir en essayant d\'atteindre l\'un des scripts : j\'ai réussi à tenir assez longtemps pour permettre à Muiredon de s\'échapper, mais la Lumière m\'a presque complètement embrassé lorsque tu es arrivé. Le fait que tu aies été assez puissant pour utiliser le Symbole signifie de grandes choses pour toi, mais il y a du temps pour en parler plus tard.') ON DUPLICATE KEY UPDATE RewardText='Je ne peux pas te remercier assez, $gbrother:sister;.$B$Je ne peux qu\'assumer que Tiza et Muiredon t\'ont envoyé pour m\'aider si tu portes le Symbole de Vie.$B$C\'est vrai, je suis tombé dans le Fer Noir en essayant d\'atteindre l\'un des scripts : j\'ai réussi à tenir assez longtemps pour permettre à Muiredon de s\'échapper, mais la Lumière m\'a presque complètement embrassé lorsque tu es arrivé. Le fait que tu aies été assez puissant pour utiliser le Symbole signifie de grandes choses pour toi, mais il y a du temps pour en parler plus tard.';
-- Quest 1784 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1784, 'frFR', 'Tu es de retour ! Je suis content de le voir, $N$. Mes blessures sont guéries et je suis sur le point de retourner au lac de Helm\'s Bed dès que je pourrai convaincre ma femme que je vais bien.') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour ! Je suis content de le voir, $N$. Mes blessures sont guéries et je suis sur le point de retourner au lac de Helm\'s Bed dès que je pourrai convaincre ma femme que je vais bien.';
-- Quest 1784 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1784, 'frFR', 'Haha ! Tu l\'as fait ! Tu as sauvé Narm, et tu as trouvé la preuve que ma femme doit emmener au conseil. Tu es une bénédiction de la Lumière si j\'en ai jamais vu... sans inclure ma femme, bien sûr.$B$Merci encore, $N$.') ON DUPLICATE KEY UPDATE RewardText='Haha ! Tu l\'as fait ! Tu as sauvé Narm, et tu as trouvé la preuve que ma femme doit emmener au conseil. Tu es une bénédiction de la Lumière si j\'en ai jamais vu... sans inclure ma femme, bien sûr.$B$Merci encore, $N$.';
-- Quest 1785 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1785, 'frFR', 'Tu as fait un grand service à toute Ironforge aujourd\'hui, $N$. Je suis fier de te compter parmi nous, et si tu penses être prêt, j\'aimerais te bénir avec ce parchemin. Le Symbole de Vie n\'aurait fonctionné que s\'il était utilisé par un $c$ qui était prêt pour l\'un des plus grands bénédictions de la Lumière-le pouvoir de ramener les morts à la vie.$B$Je t\'apprendrai la capacité de ressusciter tes compagnons. Utilise-la avec sagesse, $N$, et merci, au nom de moi-même, de mon mari et d\'Ironforge.') ON DUPLICATE KEY UPDATE RewardText='Tu as fait un grand service à toute Ironforge aujourd\'hui, $N$. Je suis fier de te compter parmi nous, et si tu penses être prêt, j\'aimerais te bénir avec ce parchemin. Le Symbole de Vie n\'aurait fonctionné que s\'il était utilisé par un $c$ qui était prêt pour l\'un des plus grands bénédictions de la Lumière-le pouvoir de ramener les morts à la vie.$B$Je t\'apprendrai la capacité de ressusciter tes compagnons. Utilise-la avec sagesse, $N$, et merci, au nom de moi-même, de mon mari et d\'Ironforge.';
-- Quest 1787 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1787, 'frFR', 'Henze est-il en sécurité, $N$ ? As-tu réussi ? $B$Entre tes compétences avec une arme et la puissance de la Lumière, j\'imagine que la Veille des Héros est à l\'abri de toute menace Defias, mais c\'est au Roi et à ses conseillers de le dire.') ON DUPLICATE KEY UPDATE CompletionText='Henze est-il en sécurité, $N$ ? As-tu réussi ? $B$Entre tes compétences avec une arme et la puissance de la Lumière, j\'imagine que la Veille des Héros est à l\'abri de toute menace Defias, mais c\'est au Roi et à ses conseillers de le dire.';
-- Quest 1787 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1787, 'frFR', 'Merveilleux ! Tu y es arrivé, et tu as sauvé Henze. La Lumière est avec toi, $N$ !') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Tu y es arrivé, et tu as sauvé Henze. La Lumière est avec toi, $N$ !';
-- Quest 1789 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1789, 'frFR', 'Dépêche-toi, $N$, plus d\'une vie est en jeu si tu échoues.$B$Si pour une raison quelconque tu échoues à aider Muiredon et Narm, alors reviens-moi et je te donnerai un autre Symbole de Vie pour tes voyages.$B$Ne confonds pas mon aide avec une simple charité, tu dois te prouver digne comme tout autre $c$ et un échec continu peut te nuire plus tard.') ON DUPLICATE KEY UPDATE RewardText='Dépêche-toi, $N$, plus d\'une vie est en jeu si tu échoues.$B$Si pour une raison quelconque tu échoues à aider Muiredon et Narm, alors reviens-moi et je te donnerai un autre Symbole de Vie pour tes voyages.$B$Ne confonds pas mon aide avec une simple charité, tu dois te prouver digne comme tout autre $c$ et un échec continu peut te nuire plus tard.';
-- Quest 1790 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1790, 'frFR', 'Dépêche-toi, $N$, plus d\'une vie est en jeu si tu échoues.$B$Si pour une raison quelconque tu échoues à aider Gazin et Henze, alors reviens-moi et je te donnerai un autre Symbole de Vie pour tes voyages.$B$Ne confonds pas mon aide avec une simple charité, tu dois te prouver digne comme tout autre $c$ et un échec continu peut te nuire plus tard.') ON DUPLICATE KEY UPDATE RewardText='Dépêche-toi, $N$, plus d\'une vie est en jeu si tu échoues.$B$Si pour une raison quelconque tu échoues à aider Gazin et Henze, alors reviens-moi et je te donnerai un autre Symbole de Vie pour tes voyages.$B$Ne confonds pas mon aide avec une simple charité, tu dois te prouver digne comme tout autre $c$ et un échec continu peut te nuire plus tard.';
-- Quest 1791 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1791, 'frFR', 'Tu as beaucoup voyagé, jeune $c$. Je vois le feu dans tes yeux. Tu cherches une arme de grande puissance, n\'est-ce pas ? $B$Je peux t\'aider avec ta quête. Et tu peux m\'aider avec la mienne.') ON DUPLICATE KEY UPDATE RewardText='Tu as beaucoup voyagé, jeune $c$. Je vois le feu dans tes yeux. Tu cherches une arme de grande puissance, n\'est-ce pas ? $B$Je peux t\'aider avec ta quête. Et tu peux m\'aider avec la mienne.';
-- Quest 1792 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1792, 'frFR', 'J\'ai le cœur tourbillonnant, et je suis prêt à le placer dans ton vaisseau de choix.$B$Choisis ton arme, $N$, et sache que sa puissance est celle de Cyclonian.') ON DUPLICATE KEY UPDATE RewardText='J\'ai le cœur tourbillonnant, et je suis prêt à le placer dans ton vaisseau de choix.$B$Choisis ton arme, $N$, et sache que sa puissance est celle de Cyclonian.';

-- Quest 1793 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1793, 'frFR', 'Il a été prouvé que la Lumière est avec toi, $N, mais à mesure que les temps deviennent plus dangereux, il devient important de savoir quelle force se cache sous la chair. Lorsque des démons, des dragons ou tout autre mal se posent dans tes terres, ton courage sera mis à l\'épreuve. Seras-tu assez fort?$B$BBravoure, quelle que soit la situation, est une partie du paladinat aussi importante que la Lumière, ton armure et ton arme. Protéger les faibles et ne pas perdre la foi sont deux autres leçons que tu dois maîtriser en étudiant dans la Cathédrale de la Lumière.') ON DUPLICATE KEY UPDATE RewardText='Il a été prouvé que la Lumière est avec toi, $N, mais à mesure que les temps deviennent plus dangereux, il devient important de savoir quelle force se cache sous la chair. Lorsque des démons, des dragons ou tout autre mal se posent dans tes terres, ton courage sera mis à l\'épreuve. Seras-tu assez fort?$B$BBravoure, quelle que soit la situation, est une partie du paladinat aussi importante que la Lumière, ton armure et ton arme. Protéger les faibles et ne pas perdre la foi sont deux autres leçons que tu dois maîtriser en étudiant dans la Cathédrale de la Lumière.';
-- Quest 1794 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1794, 'frFR', 'Il a été prouvé que la Lumière est avec toi, $N, mais à mesure que les temps deviennent plus dangereux, il devient important de savoir quelle force se cache sous la chair. Lorsque des démons, des dragons ou tout autre mal se posent dans tes terres, ton courage sera mis à l\'épreuve. Seras-tu assez fort?$B$BBravoure, quelle que soit la situation, est une partie du paladinat aussi importante que la Lumière, ton armure et ton arme. Protéger les faibles et ne pas perdre la foi sont deux autres leçons que tu dois maîtriser en étudiant dans la Cathédrale de la Lumière.') ON DUPLICATE KEY UPDATE RewardText='Il a été prouvé que la Lumière est avec toi, $N, mais à mesure que les temps deviennent plus dangereux, il devient important de savoir quelle force se cache sous la chair. Lorsque des démons, des dragons ou tout autre mal se posent dans tes terres, ton courage sera mis à l\'épreuve. Seras-tu assez fort?$B$BBravoure, quelle que soit la situation, est une partie du paladinat aussi importante que la Lumière, ton armure et ton arme. Protéger les faibles et ne pas perdre la foi sont deux autres leçons que tu dois maîtriser en étudiant dans la Cathédrale de la Lumière.';
-- Quest 1795 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1795, 'frFR', 'Chaque $C devrait avoir un chasseur de fél. Bien qu\'il soit difficile à dompter, les pouvoirs qu\'il apporte à son maître dépassent de loin le coût.') ON DUPLICATE KEY UPDATE CompletionText='Chaque $C devrait avoir un chasseur de fél. Bien qu\'il soit difficile à dompter, les pouvoirs qu\'il apporte à son maître dépassent de loin le coût.';
-- Quest 1795 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1795, 'frFR', 'Je dois dire que je suis impressionné, $N. Quand j\'ai affronté mon chasseur de fél, j\'ai à peine échappé avec la vie. Je sens que tu as le potentiel pour devenir un des plus puissants warlocks de cette ère.') ON DUPLICATE KEY UPDATE RewardText='Je dois dire que je suis impressionné, $N. Quand j\'ai affronté mon chasseur de fél, j\'ai à peine échappé avec la vie. Je sens que tu as le potentiel pour devenir un des plus puissants warlocks de cette ère.';
-- Quest 1796 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1796, 'frFR', 'Comment se passe ta recherche de robes, $N? Les as-tu créées toi-même? Ces touches personnelles, je trouve, rendent l\'imprégnation de magie d\'autant plus douce. Cela te donne un plus grand sentiment d\'accomplissement. Mais je comprends si tu choisis la voie plus rapide et les fais faire pour toi - il y a quelque chose à dire pour une telle... ambition.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe ta recherche de robes, $N? Les as-tu créées toi-même? Ces touches personnelles, je trouve, rendent l\'imprégnation de magie d\'autant plus douce. Cela te donne un plus grand sentiment d\'accomplissement. Mais je comprends si tu choisis la voie plus rapide et les fais faire pour toi - il y a quelque chose à dire pour une telle... ambition.';
-- Quest 1796 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1796, 'frFR', 'Ceci fera l\'affaire, $N.$B$BTous les objets magiques doivent commencer par un objet de haute qualité. Plus on met d\'effort et de compétence dans un objet, plus il peut contenir de magie. Les composants rares et plus chers contiennent mieux la magie. Tu ne regretteras pas que les robes soient confectionnées comme celles que nous ferons plus tard.') ON DUPLICATE KEY UPDATE RewardText='Ceci fera l\'affaire, $N.$B$BTous les objets magiques doivent commencer par un objet de haute qualité. Plus on met d\'effort et de compétence dans un objet, plus il peut contenir de magie. Les composants rares et plus chers contiennent mieux la magie. Tu ne regretteras pas que les robes soient confectionnées comme celles que nous ferons plus tard.';
-- Quest 1798 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1798, 'frFR', '$N? Ah, bien sûr. Notre dernier prodige. Le vrai ne peut pas égaler la légende, j\'ai peur. $B$BPeu importe, tu es venu ici pour apprendre, pas pour m\'écouter faire des blagues à moi-même.') ON DUPLICATE KEY UPDATE RewardText='$N? Ah, bien sûr. Notre dernier prodige. Le vrai ne peut pas égaler la légende, j\'ai peur. $B$BPeu importe, tu es venu ici pour apprendre, pas pour m\'écouter faire des blagues à moi-même.';
-- Quest 1799 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1799, 'frFR', 'Et évidemment, ne pas être un mage, je me demande si je peux te faire confiance du tout. Je peux sentir la puissance de l\'arcane sur toi, mais tu sembles avoir échappé à l\'odeur de corruption qui vient si volontairement avec ton espèce.$B$BOui, un $C... un $C est venu demander mon aide.$B$BEh bien, qu\'est-ce que je peux faire pour toi, $N?') ON DUPLICATE KEY UPDATE CompletionText='Et évidemment, ne pas être un mage, je me demande si je peux te faire confiance du tout. Je peux sentir la puissance de l\'arcane sur toi, mais tu sembles avoir échappé à l\'odeur de corruption qui vient si volontairement avec ton espèce.$B$BOui, un $C... un $C est venu demander mon aide.$B$BEh bien, qu\'est-ce que je peux faire pour toi, $N?';
-- Quest 1799 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1799, 'frFR', 'Oh, donc Menara t\'a envoyé. C\'est juste... Je suppose que tu peux rester comme mon invité pour le moment. Mais tu dois avoir une affaire urgente - peut-être es-tu ici pour chercher un pouvoir perdu? Peut-être que je me trompe. Peut-être que la corruption n\'est pas si loin de toi après tout.') ON DUPLICATE KEY UPDATE RewardText='Oh, donc Menara t\'a envoyé. C\'est juste... Je suppose que tu peux rester comme mon invité pour le moment. Mais tu dois avoir une affaire urgente - peut-être es-tu ici pour chercher un pouvoir perdu? Peut-être que je me trompe. Peut-être que la corruption n\'est pas si loin de toi après tout.';
-- Quest 1800 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1800, 'frFR', 'Cette salle du trône était effrayante, $N! Même si elle était vide, on aurait dit qu\'un grand mal s\'y était passé. J\'ai senti de la rage... mais j\'ai aussi ressenti de la tristesse. Je comprends pourquoi les matrones nous racontent de telles histoires ; je ne trahirai jamais mon peuple comme ça!$B$BMerci de m\'avoir emmené dans la salle du trône, $N. J\'ai beaucoup appris.') ON DUPLICATE KEY UPDATE RewardText='Cette salle du trône était effrayante, $N! Même si elle était vide, on aurait dit qu\'un grand mal s\'y était passé. J\'ai senti de la rage... mais j\'ai aussi ressenti de la tristesse. Je comprends pourquoi les matrones nous racontent de telles histoires ; je ne trahirai jamais mon peuple comme ça!$B$BMerci de m\'avoir emmené dans la salle du trône, $N. J\'ai beaucoup appris.';
-- Quest 1801 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1801, 'frFR', 'Faire des cartes! Des dessins, des estimations de la réalité. Je n\'ai pas besoin de ces choses.$b$bDans les livres, le récit, la description! C\'est là que réside la vérité. J\'échangerais toutes les cartes de cette boutique contre un livre sur l\'essor de la nécromancie, ou une histoire du triomphe de la Dame Noire.') ON DUPLICATE KEY UPDATE RewardText='Faire des cartes! Des dessins, des estimations de la réalité. Je n\'ai pas besoin de ces choses.$b$bDans les livres, le récit, la description! C\'est là que réside la vérité. J\'échangerais toutes les cartes de cette boutique contre un livre sur l\'essor de la nécromancie, ou une histoire du triomphe de la Dame Noire.';
-- Quest 1802 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1802, 'frFR', 'Fantastique! Maintenant, je peux rejoindre le rang de ceux qui ont espionné son contenu.$B$BI ne peux pas attendre pour parcourir ce texte. C\'est un grand jour, $N! Si tu pouvais juste me laisser y jeter un coup d\'œil avant de partir. Je suis sûr que Strahad sera disposé à m\'envoyer une copie.') ON DUPLICATE KEY UPDATE RewardText='Fantastique! Maintenant, je peux rejoindre le rang de ceux qui ont espionné son contenu.$B$BI ne peux pas attendre pour parcourir ce texte. C\'est un grand jour, $N! Si tu pouvais juste me laisser y jeter un coup d\'œil avant de partir. Je suis sûr que Strahad sera disposé à m\'envoyer une copie.';
-- Quest 1803 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1803, 'frFR', 'Il se peut que tu sois à la poursuite de contes de fées, $N, mais la vérité peut être trouvée au centre des rumeurs les plus folles.') ON DUPLICATE KEY UPDATE CompletionText='Il se peut que tu sois à la poursuite de contes de fées, $N, mais la vérité peut être trouvée au centre des rumeurs les plus folles.';
-- Quest 1803 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1803, 'frFR', 'Eh bien, eh bien, eh bien! Qu\'avons-nous ici?$B$C\'est impressionnant, $N. Je n\'aurais pas cru cela possible, mais le voici dans mes mains, le Tome complet de la Cabale.$B$BPermets-moi de feuilleter ses pages un instant avant que tu ne partes à nouveau.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, eh bien, eh bien! Qu\'avons-nous ici?$B$C\'est impressionnant, $N. Je n\'aurais pas cru cela possible, mais le voici dans mes mains, le Tome complet de la Cabale.$B$BPermets-moi de feuilleter ses pages un instant avant que tu ne partes à nouveau.';
-- Quest 1804 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1804, 'frFR', 'Je ne t\'ai pas vu dans ces parages depuis un moment. As-tu trouvé le tome et les tiges?') ON DUPLICATE KEY UPDATE CompletionText='Je ne t\'ai pas vu dans ces parages depuis un moment. As-tu trouvé le tome et les tiges?';

-- Quest 1804 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1804, 'frFR', 'Bien joué ! Le Tome de la Cabale et trois perches de canalisation immaculées—légèrement éraflées, je suppose—.$B$BCe sera intéressant. Cela fait un moment que je n\'ai pas vu un jeune $c s\'attaquer à un chasseur de fel pour en fabriquer un.') ON DUPLICATE KEY UPDATE RewardText='Bien joué ! Le Tome de la Cabale et trois perches de canalisation immaculées—légèrement éraflées, je suppose—.$B$BCe sera intéressant. Cela fait un moment que je n\'ai pas vu un jeune $c s\'attaquer à un chasseur de fel pour en fabriquer un.';
-- Quest 1805 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1805, 'frFR', 'Oui, $N? En quoi puis-je vous être utile ?') ON DUPLICATE KEY UPDATE CompletionText='Oui, $N? En quoi puis-je vous être utile ?';
-- Quest 1805 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1805, 'frFR', 'Bien joué ! Le Tome de la Cabale et trois perches de canalisation immaculées—légèrement éraflées, je suppose—.$B$BCe sera intéressant. Cela fait un moment que je n\'ai pas vu un jeune $c s\'attaquer à un chasseur de fel pour en fabriquer un.') ON DUPLICATE KEY UPDATE RewardText='Bien joué ! Le Tome de la Cabale et trois perches de canalisation immaculées—légèrement éraflées, je suppose—.$B$BCe sera intéressant. Cela fait un moment que je n\'ai pas vu un jeune $c s\'attaquer à un chasseur de fel pour en fabriquer un.';
-- Quest 1806 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1806, 'frFR', 'La voici, $N. Une arme digne d\'un champion de la Lumière tel que vous. Je l\'ai nommée d\'après un grand paladin nain qui était un ami. Il s\'appelait Verigan... Bosch Verigan.$B$BVeuillez la prendre au nom de moi-même et de mon épouse. Nous vous devons une grande dette, et le monde sera un endroit plus sûr avec quelqu\'un de votre talent voyageant sur la terre.') ON DUPLICATE KEY UPDATE RewardText='La voici, $N. Une arme digne d\'un champion de la Lumière tel que vous. Je l\'ai nommée d\'après un grand paladin nain qui était un ami. Il s\'appelait Verigan... Bosch Verigan.$B$BVeuillez la prendre au nom de moi-même et de mon épouse. Nous vous devons une grande dette, et le monde sera un endroit plus sûr avec quelqu\'un de votre talent voyageant sur la terre.';
-- Quest 1818 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1818, 'frFR', 'Vous êtes ici pour une mission ? Bien. J\'en ai une importante, et une qui testera votre compétence au combat... et votre résolution dans la défense des Forsakés.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes ici pour une mission ? Bien. J\'en ai une importante, et une qui testera votre compétence au combat... et votre résolution dans la défense des Forsakés.';
-- Quest 1819 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1819, 'frFR', 'Votre tâche n\'est pas encore accomplie, $N. Il n\'est pas sage qu\'un $C montre de la peur...') ON DUPLICATE KEY UPDATE CompletionText='Votre tâche n\'est pas encore accomplie, $N. Il n\'est pas sage qu\'un $C montre de la peur...';
-- Quest 1819 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1819, 'frFR', 'Bien joué, <name>.  Ulag n\'était pas un agent mineur de la Horde.  Vous avez montré aux Gardes de la Mort, et par conséquent à la Dame Noire, que vous êtes un $lt;class> de compétence et de résolution, et que vous êtes digne d\'un enseignement supplémentaire.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name>.  Ulag n\'était pas un agent mineur de la Horde.  Vous avez montré aux Gardes de la Mort, et par conséquent à la Dame Noire, que vous êtes un $lt;class> de compétence et de résolution, et que vous êtes digne d\'un enseignement supplémentaire.';
-- Quest 1820 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1820, 'frFR', 'Oui, c\'est vrai.  J\'ai besoin de vos compétences au combat.  Mes moyens sont modestes, mais ma tâche aide à la fois moi et la cause des Forsakés.  Faites-le, et votre récompense sera double.') ON DUPLICATE KEY UPDATE RewardText='Oui, c\'est vrai.  J\'ai besoin de vos compétences au combat.  Mes moyens sont modestes, mais ma tâche aide à la fois moi et la cause des Forsakés.  Faites-le, et votre récompense sera double.';
-- Quest 1821 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1821, 'frFR', 'Ah !  Vous les avez récupérés !  Maintenant, la dernière semblance d\'honneur et de mémoire est arrachée aux terres maudites d\'Agamand.  La famille n\'est vraiment plus rien !') ON DUPLICATE KEY UPDATE RewardText='Ah !  Vous les avez récupérés !  Maintenant, la dernière semblance d\'honneur et de mémoire est arrachée aux terres maudites d\'Agamand.  La famille n\'est vraiment plus rien !';
-- Quest 1822 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1822, 'frFR', 'Je garderai trois des armes que vous m\'avez rendues, comme mémoriaux de ma douleur et de ma perte. Mais s\'il vous plaît, $N, choisissez votre favorite parmi les héritages et gardez-la pour vous.$B$BQu\'elle vous serve mieux qu\'elle n\'a servi ses anciens propriétaires maudits.') ON DUPLICATE KEY UPDATE RewardText='Je garderai trois des armes que vous m\'avez rendues, comme mémoriaux de ma douleur et de ma perte. Mais s\'il vous plaît, $N, choisissez votre favorite parmi les héritages et gardez-la pour vous.$B$BQu\'elle vous serve mieux qu\'elle n\'a servi ses anciens propriétaires maudits.';
-- Quest 1824 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1824, 'frFR', 'Avez-vous les antennes ? Si oui, donnez-les-moi rapidement, car les antennes qui tressautent ne tressautent pas pour toujours...') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les antennes ? Si oui, donnez-les-moi rapidement, car les antennes qui tressautent ne tressautent pas pour toujours...';
-- Quest 1824 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1824, 'frFR', 'Bien fait, $N! En passant l\'épreuve au Champ des Géants, vous faites un pas de plus sur le chemin du $c\'.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, $N! En passant l\'épreuve au Champ des Géants, vous faites un pas de plus sur le chemin du $c\'.';
-- Quest 1825 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1825, 'frFR', 'Oui, vous êtes venu. C\'est bien, car nous avons beaucoup à discuter, vous et moi.') ON DUPLICATE KEY UPDATE RewardText='Oui, vous êtes venu. C\'est bien, car nous avons beaucoup à discuter, vous et moi.';
-- Quest 1838 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1838, 'frFR', 'Avez-vous les objets sur mon parchemin, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les objets sur mon parchemin, $N?';
-- Quest 1838 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1838, 'frFR', 'Vous avez apporté tout ce que j\'ai demandé. Maintenant, je ferai ma part...') ON DUPLICATE KEY UPDATE RewardText='Vous avez apporté tout ce que j\'ai demandé. Maintenant, je ferai ma part...';

-- Quest 1839 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1839, 'frFR', 'Salutations, $N$. Le vieux Thun\'grim m\'a envoyé un message de votre venue, mais s\'il était resté silencieux, votre présence ici ne m\'aurait pas surpris.$B$BLes esprits suivent votre progression, jeune $c$, et ils me disent que de nombreux ennemis sont tombés devant vous.') ON DUPLICATE KEY UPDATE RewardText='Salutations, $N$. Le vieux Thun\'grim m\'a envoyé un message de votre venue, mais s\'il était resté silencieux, votre présence ici ne m\'aurait pas surpris.$B$BLes esprits suivent votre progression, jeune $c$, et ils me disent que de nombreux ennemis sont tombés devant vous.';
-- Quest 1840 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1840, 'frFR', 'Salutations, $c$. Je suis Orm, et Thun\'grim me dit que vous souhaitez un casque ?') ON DUPLICATE KEY UPDATE RewardText='Salutations, $c$. Je suis Orm, et Thun\'grim me dit que vous souhaitez un casque ?';
-- Quest 1842 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1842, 'frFR', 'Avez-vous les sabots, $N$? La magie en eux est forte.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les sabots, $N$? La magie en eux est forte.';
-- Quest 1842 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1842, 'frFR', 'Ah, vous les avez! Maintenant, tout comme les Satyres ont siphonné la force d\'Ashenvale, je vais siphonner le pouvoir contenu dans ces sabots et l\'utiliser pour mon artisanat...') ON DUPLICATE KEY UPDATE RewardText='Ah, vous les avez! Maintenant, tout comme les Satyres ont siphonné la force d\'Ashenvale, je vais siphonner le pouvoir contenu dans ces sabots et l\'utiliser pour mon artisanat...';
-- Quest 1843 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1843, 'frFR', 'Merci, $N$. Ces gantelets sont mon meilleur travail. Prenez-les. En les portant, vous m\'apportez un honneur à moi et à mes ancêtres.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N$. Ces gantelets sont mon meilleur travail. Prenez-les. En les portant, vous m\'apportez un honneur à moi et à mes ancêtres.';
-- Quest 1844 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1844, 'frFR', 'Avez-vous la corne ? La matriarche est-elle libre de douleur ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous la corne ? La matriarche est-elle libre de douleur ?';
-- Quest 1844 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1844, 'frFR', 'Vous avez accompli votre tâche, $N$, et m\'avez montré votre valeur et votre résolution. Le casque sera le vôtre...') ON DUPLICATE KEY UPDATE RewardText='Vous avez accompli votre tâche, $N$, et m\'avez montré votre valeur et votre résolution. Le casque sera le vôtre...';
-- Quest 1845 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1845, 'frFR', 'Je vous donne ce casque.$B$BDe grands actes vous ont mené jusqu\'à moi, $N$, et la Mère-Terre le veut... des actes encore plus grands vous attendent.') ON DUPLICATE KEY UPDATE RewardText='Je vous donne ce casque.$B$BDe grands actes vous ont mené jusqu\'à moi, $N$, et la Mère-Terre le veut... des actes encore plus grands vous attendent.';
-- Quest 1846 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1846, 'frFR', 'J\'attends ces os de tibia, $N$. Ils feront un joli cadre pour vos jambières.') ON DUPLICATE KEY UPDATE CompletionText='J\'attends ces os de tibia, $N$. Ils feront un joli cadre pour vos jambières.';
-- Quest 1846 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1846, 'frFR', 'Bien fait! Tout cela semble solide. Je pense qu\'ils feront très bien. Comment ces orcs ont-ils réagi à ce que vous preniez leurs tibias, $N$? Se sont-ils plaints beaucoup?$B$BC\'était une autre blague. Vous n\'êtes pas en train de rire.$B$BI ne suis pas très drôle ces jours-ci, si...') ON DUPLICATE KEY UPDATE RewardText='Bien fait! Tout cela semble solide. Je pense qu\'ils feront très bien. Comment ces orcs ont-ils réagi à ce que vous preniez leurs tibias, $N$? Se sont-ils plaints beaucoup?$B$BC\'était une autre blague. Vous n\'êtes pas en train de rire.$B$BI ne suis pas très drôle ces jours-ci, si...';
-- Quest 1847 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1847, 'frFR', 'Voici vos jambières, $N$. Faites-moi savoir comment elles vous vont ou si vous avez besoin de modifications. Je m\'efforce de satisfaire! Au moins, je le faisais avant.$B$BCes jours-ci, je ne me soucie pas beaucoup de mon artisanat. Mais c\'est mieux que d\'être un simple minion du Fléau!$B$BI suppose.') ON DUPLICATE KEY UPDATE RewardText='Voici vos jambières, $N$. Faites-moi savoir comment elles vous vont ou si vous avez besoin de modifications. Je m\'efforce de satisfaire! Au moins, je le faisais avant.$B$BCes jours-ci, je ne me soucie pas beaucoup de mon artisanat. Mais c\'est mieux que d\'être un simple minion du Fléau!$B$BI suppose.';
-- Quest 1848 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1848, 'frFR', 'Je suis sûr que vous avez enduré beaucoup de difficultés et versé beaucoup de sang pour ma tâche, $N$. Voici le produit de votre labeur.$B$BQue vous le portiez bien, et que vous reveniez un jour ici avec des histoires de son service pour vous.') ON DUPLICATE KEY UPDATE RewardText='Je suis sûr que vous avez enduré beaucoup de difficultés et versé beaucoup de sang pour ma tâche, $N$. Voici le produit de votre labeur.$B$BQue vous le portiez bien, et que vous reveniez un jour ici avec des histoires de son service pour vous.';
-- Quest 1858 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1858, 'frFR', 'N\'est-ce pas vexant d\'avoir le sujet de votre désir à portée de main, mais sans aucun moyen d\'y parvenir ?') ON DUPLICATE KEY UPDATE CompletionText='N\'est-ce pas vexant d\'avoir le sujet de votre désir à portée de main, mais sans aucun moyen d\'y parvenir ?';
-- Quest 1858 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1858, 'frFR', 'Hmmm, maintenant c\'est intéressant. Vous avez plus que prouvé votre valeur avec ceci, $N$. Je suis très impressionné. Considérez-vous le nouveau membre de la Main Brisée. Et prenez ceci, cela vous sera d\'une grande aide à l\'avenir, je crois.') ON DUPLICATE KEY UPDATE RewardText='Hmmm, maintenant c\'est intéressant. Vous avez plus que prouvé votre valeur avec ceci, $N$. Je suis très impressionné. Considérez-vous le nouveau membre de la Main Brisée. Et prenez ceci, cela vous sera d\'une grande aide à l\'avenir, je crois.';
-- Quest 1859 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1859, 'frFR', 'Très bien, je suis content que Kaplak ait pu vous trouver.$b$bNous avons des choses à discuter, pas la moindre desquelles est votre avenir avec la Main.') ON DUPLICATE KEY UPDATE RewardText='Très bien, je suis content que Kaplak ait pu vous trouver.$b$bNous avons des choses à discuter, pas la moindre desquelles est votre avenir avec la Main.';

-- Quest 1860 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1860, 'frFR', 'Vous avez été envoyé pour m\'aider dans ma tâche, $N? Bien. Il est réconfortant de voir de jeunes mages désireux d\'aider dans notre cause...$b$bQuelle cause, demandez-vous? Avec le temps, jeune one. Vous saurez... avec le temps.') ON DUPLICATE KEY UPDATE RewardText='Vous avez été envoyé pour m\'aider dans ma tâche, $N? Bien. Il est réconfortant de voir de jeunes mages désireux d\'aider dans notre cause...$b$bQuelle cause, demandez-vous? Avec le temps, jeune one. Vous saurez... avec le temps.';
-- Quest 1861 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1861, 'frFR', 'Avez-vous l\'échantillon, $N? Le flux de magie à Stormwind et Elwynn a été altéré, et je dois savoir s\'il s\'infiltre dans l\'eau.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous l\'échantillon, $N? Le flux de magie à Stormwind et Elwynn a été altéré, et je dois savoir s\'il s\'infiltre dans l\'eau.';
-- Quest 1861 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1861, 'frFR', 'Merci, $N. Je vais tester cette eau pour ses propriétés magiques. Espérons qu\'elle n\'en contienne aucune, sinon nous pourrions découvrir que ceux qui boivent de Mirror Lake trop longtemps seront affectés.$B$BVoici, $N. Prenez cet orbe ou ce bâton en guise de remerciement pour votre service. Qu\'il vous soit utile.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Je vais tester cette eau pour ses propriétés magiques. Espérons qu\'elle n\'en contienne aucune, sinon nous pourrions découvrir que ceux qui boivent de Mirror Lake trop longtemps seront affectés.$B$BVoici, $N. Prenez cet orbe ou ce bâton en guise de remerciement pour votre service. Qu\'il vous soit utile.';
-- Quest 1878 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1878, 'frFR', 'De retour, $n? Si vous avez cinq autres sachets d\'eau de Wastewander, alors j\'ai un colis cadeau avec votre nom dessus !') ON DUPLICATE KEY UPDATE CompletionText='De retour, $n? Si vous avez cinq autres sachets d\'eau de Wastewander, alors j\'ai un colis cadeau avec votre nom dessus !';
-- Quest 1878 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1878, 'frFR', 'Excellent - plus nous parvenons à récupérer de sachets d\'eau, plus nous serons éloignés du désastre ! Gardez-les, et je m\'assurerai de vous récompenser pour chaque cinq sachets d\'eau que vous m\'apportez.') ON DUPLICATE KEY UPDATE RewardText='Excellent - plus nous parvenons à récupérer de sachets d\'eau, plus nous serons éloignés du désastre ! Gardez-les, et je m\'assurerai de vous récompenser pour chaque cinq sachets d\'eau que vous m\'apportez.';
-- Quest 1879 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1879, 'frFR', 'Oh, je vois que vous avez du potentiel, oui vous l\'avez ! Mais il faut plus que du potentiel pour être un bon $c. Et si vous n\'êtes pas un bon $c, alors vous êtes un mauvais $c. Et les mages mauvais font partie du problème, oui ils le font !$b$bOups, je m\'emballe. Commençons au début !') ON DUPLICATE KEY UPDATE RewardText='Oh, je vois que vous avez du potentiel, oui vous l\'avez ! Mais il faut plus que du potentiel pour être un bon $c. Et si vous n\'êtes pas un bon $c, alors vous êtes un mauvais $c. Et les mages mauvais font partie du problème, oui ils le font !$b$bOups, je m\'emballe. Commençons au début !';
-- Quest 1880 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1880, 'frFR', 'Avez-vous trouvé le gizmonitor? Je dois l\'avoir avant que son alimentation en énergie ne s\'épuise !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé le gizmonitor? Je dois l\'avoir avant que son alimentation en énergie ne s\'épuise !';
-- Quest 1880 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1880, 'frFR', 'Oh, quelle belle journée ! Quand j\'ai fabriqué le gizmonitor, je n\'avais jamais réalisé à quel point je deviendrais dépendant de lui. Maintenant, je peux recommencer mes études !$b$bMerci, $N! Et voici--ce sont mes premiers outils en tant que $c. Ils sont un peu éraflés mais ils sont bien testés. Choisissez celui qui vous plaît--je suis sûr que vous trouverez l\'un ou l\'autre utile.') ON DUPLICATE KEY UPDATE RewardText='Oh, quelle belle journée ! Quand j\'ai fabriqué le gizmonitor, je n\'avais jamais réalisé à quel point je deviendrais dépendant de lui. Maintenant, je peux recommencer mes études !$b$bMerci, $N! Et voici--ce sont mes premiers outils en tant que $c. Ils sont un peu éraflés mais ils sont bien testés. Choisissez celui qui vous plaît--je suis sûr que vous trouverez l\'un ou l\'autre utile.';
-- Quest 1881 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1881, 'frFR', 'Salutations, $N. Vous avez eu la sagesse de répondre à mon appel, et encore plus sage si vous tenez compte de ce que je vais dire ensuite...') ON DUPLICATE KEY UPDATE RewardText='Salutations, $N. Vous avez eu la sagesse de répondre à mon appel, et encore plus sage si vous tenez compte de ce que je vais dire ensuite...';
-- Quest 1882 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1882, 'frFR', 'Avez-vous les digitales ? Cette variété de fleur est très réceptive aux énergies magiques, et étudier les digitales si près des Plaguelands peut nous dire si la peste est entrée dans les Clairières de Tirisfal.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les digitales ? Cette variété de fleur est très réceptive aux énergies magiques, et étudier les digitales si près des Plaguelands peut nous dire si la peste est entrée dans les Clairières de Tirisfal.';
-- Quest 1882 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1882, 'frFR', 'Ah, c\'est un spécimen remarquable. Je vais l\'envoyer être étudié par nos apothicaires pour déterminer l\'étendue de la souillure des Plaguelands.$B$BBien joué, $N. Pour vos services, je vous présente ce choix : un orbe ou un bâton. Quel que soit celui que vous choisissez, vous le trouverez très utile.') ON DUPLICATE KEY UPDATE RewardText='Ah, c\'est un spécimen remarquable. Je vais l\'envoyer être étudié par nos apothicaires pour déterminer l\'étendue de la souillure des Plaguelands.$B$BBien joué, $N. Pour vos services, je vous présente ce choix : un orbe ou un bâton. Quel que soit celui que vous choisissez, vous le trouverez très utile.';
-- Quest 1883 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1883, 'frFR', 'Salut, $N. Loué sois-tu, car mon appel à l\'aide est maintenant répondu. Espérons que vous êtes à la hauteur de la tâche...') ON DUPLICATE KEY UPDATE RewardText='Salut, $N. Loué sois-tu, car mon appel à l\'aide est maintenant répondu. Espérons que vous êtes à la hauteur de la tâche...';
-- Quest 1884 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1884, 'frFR', 'Vous devez vous dépêcher, $N. Détruisez les tas de ju-ju !') ON DUPLICATE KEY UPDATE CompletionText='Vous devez vous dépêcher, $N. Détruisez les tas de ju-ju !';
-- Quest 1884 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1884, 'frFR', 'Je sens que les tas de ju-ju de Zalazane ont été détruits, et avec le temps, et la chance, le flux de magie à Durotar retrouvera la normale.$b$bVous avez fait une grande œuvre pour votre peuple, $N. Et vous nous avez montré votre valeur, nous, les mages de la Horde.') ON DUPLICATE KEY UPDATE RewardText='Je sens que les tas de ju-ju de Zalazane ont été détruits, et avec le temps, et la chance, le flux de magie à Durotar retrouvera la normale.$b$bVous avez fait une grande œuvre pour votre peuple, $N. Et vous nous avez montré votre valeur, nous, les mages de la Horde.';
-- Quest 1885 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1885, 'frFR', 'Hm. Sans aucun doute, vous êtes venu ici dès la première mention de mon appel, n\'est-ce pas ? Bien sûr. Je ne m\'attendrais à rien de moins d\'un chasseur de morts potentiel.') ON DUPLICATE KEY UPDATE RewardText='Hm. Sans aucun doute, vous êtes venu ici dès la première mention de mon appel, n\'est-ce pas ? Bien sûr. Je ne m\'attendrais à rien de moins d\'un chasseur de morts potentiel.';

-- Quest 1886 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1886, 'frFR', 'Bien joué, $N$. Tu as réussi la première partie de ce test. J\'espère qu\'Andron n\'a pas entendu parler de tes activités, et que nous pourrons le convaincre que tu es, en fait, le messager qu\'il attend.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N$. Tu as réussi la première partie de ce test. J\'espère qu\'Andron n\'a pas entendu parler de tes activités, et que nous pourrons le convaincre que tu es, en fait, le messager qu\'il attend.';
-- Quest 1898 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1898, 'frFR', 'Bonjour. Puis-je faire quelque chose pour vous ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour. Puis-je faire quelque chose pour vous ?';
-- Quest 1898 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1898, 'frFR', 'Ah oui, je vous attendais. Je doute que nos connaissances mutuelles soient satisfaites par les informations que j\'ai fournies jusqu\'à présent?$B$BI suppose qu\'il n\'y a pas d\'intérêt de vous demander, je doute qu\'ils vous chargeraient de cette connaissance. Pourquoi accorder tant de confiance au messager, hein ?') ON DUPLICATE KEY UPDATE RewardText='Ah oui, je vous attendais. Je doute que nos connaissances mutuelles soient satisfaites par les informations que j\'ai fournies jusqu\'à présent?$B$BI suppose qu\'il n\'y a pas d\'intérêt de vous demander, je doute qu\'ils vous chargeraient de cette connaissance. Pourquoi accorder tant de confiance au messager, hein ?';
-- Quest 1899 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1899, 'frFR', 'Eh bien, c\'est certainement plus d\'informations que je ne le soupçonnais obtenir d\'Andron. Donnez-moi un instant pour les parcourir, avant de vous confier votre prochaine tâche.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, c\'est certainement plus d\'informations que je ne le soupçonnais obtenir d\'Andron. Donnez-moi un instant pour les parcourir, avant de vous confier votre prochaine tâche.';
-- Quest 1918 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1918, 'frFR', 'Vous trouvez une sale boule d\'eau et vous décidez de me l\'apporter ?  Qui suis-je, l\'Anneau de Terre ou quelque chose ? $B$BEn fait, cela me donne une idée... peut-être avez-vous besoin de l\'Anneau de Terre pour cela.  Je veux dire, si cela aide à régler la situation au lac définitivement, alors je suis partant.$B$BVous savez qui sont les Anneaux de Terre, <name> ?') ON DUPLICATE KEY UPDATE RewardText='Vous trouvez une sale boule d\'eau et vous décidez de me l\'apporter ?  Qui suis-je, l\'Anneau de Terre ou quelque chose ? $B$BEn fait, cela me donne une idée... peut-être avez-vous besoin de l\'Anneau de Terre pour cela.  Je veux dire, si cela aide à régler la situation au lac définitivement, alors je suis partant.$B$BVous savez qui sont les Anneaux de Terre, <name> ?';
-- Quest 1919 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1919, 'frFR', '$N, j\'ai une mission pour toi, ici dans le $c district. Écoute attentivement, car il n\'y a pas de temps à perdre.') ON DUPLICATE KEY UPDATE RewardText='$N, j\'ai une mission pour toi, ici dans le $c district. Écoute attentivement, car il n\'y a pas de temps à perdre.';
-- Quest 1920 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1920, 'frFR', 'Avez-vous capturé les créatures, $n ? Elles doivent être étudiées afin de déterminer la raison de leur arrivée.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous capturé les créatures, $n ? Elles doivent être étudiées afin de déterminer la raison de leur arrivée.';
-- Quest 1920 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1920, 'frFR', 'Très bien fait ! J\'étudierai ces créatures et, avec diligence et chance, je déterminerai comment elles ont infiltré notre monde.$B$BVotre valeur pour la société des mages grandit, $N$.') ON DUPLICATE KEY UPDATE RewardText='Très bien fait ! J\'étudierai ces créatures et, avec diligence et chance, je déterminerai comment elles ont infiltré notre monde.$B$BVotre valeur pour la société des mages grandit, $N$.';
-- Quest 1921 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1921, 'frFR', 'Bonjour, $N$. Jennea m\'a dit que tu viendrais. As-tu quelque chose pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $N$. Jennea m\'a dit que tu viendrais. As-tu quelque chose pour moi ?';
-- Quest 1921 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1921, 'frFR', 'Oui, ce sont de beaux morceaux de lin. Je peux en faire une robe fine avec eux. Et après avoir tissé les gemmes de rift dedans, nous aurons un vêtement digne d\'un $c !') ON DUPLICATE KEY UPDATE RewardText='Oui, ce sont de beaux morceaux de lin. Je peux en faire une robe fine avec eux. Et après avoir tissé les gemmes de rift dedans, nous aurons un vêtement digne d\'un $c !';
-- Quest 1938 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1938, 'frFR', 'As-tu le livre, $N$ ? Ses secrets ne sont pas destinés aux non-initiés, et son examen peut mener au désastre et à la ruine.') ON DUPLICATE KEY UPDATE CompletionText='As-tu le livre, $N$ ? Ses secrets ne sont pas destinés aux non-initiés, et son examen peut mener au désastre et à la ruine.';
-- Quest 1938 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1938, 'frFR', 'Je craignais que Morganth n\'ait caché le livre ailleurs, ou qu\'il ait trouvé un moyen de l\'ouvrir et de lire son contenu.$B$BC\'est une bonne chose qu\'il ne l\'ait pas fait, et que les sceaux que nous avons placés sur le Traité d\'Ur sur la magie des ombres tiennent toujours.') ON DUPLICATE KEY UPDATE RewardText='Je craignais que Morganth n\'ait caché le livre ailleurs, ou qu\'il ait trouvé un moyen de l\'ouvrir et de lire son contenu.$B$BC\'est une bonne chose qu\'il ne l\'ait pas fait, et que les sceaux que nous avons placés sur le Traité d\'Ur sur la magie des ombres tiennent toujours.';
-- Quest 1939 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1939, 'frFR', 'Salutations, $N$. Je suis heureux de vous voir, et j\'espère que vous avez le temps d\'écouter les paroles d\'un vieil homme...') ON DUPLICATE KEY UPDATE RewardText='Salutations, $N$. Je suis heureux de vous voir, et j\'espère que vous avez le temps d\'écouter les paroles d\'un vieil homme...';
-- Quest 1940 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1940, 'frFR', 'Ah oui. Les mages du Sanctuaire du Mage ont dit que vous viendriez me parler. Avez-vous la soie requise ?') ON DUPLICATE KEY UPDATE CompletionText='Ah oui. Les mages du Sanctuaire du Mage ont dit que vous viendriez me parler. Avez-vous la soie requise ?';
-- Quest 1940 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1940, 'frFR', 'De beaux spécimens, ceux-là. Je me mets au travail immédiatement !') ON DUPLICATE KEY UPDATE RewardText='De beaux spécimens, ceux-là. Je me mets au travail immédiatement !';

-- Quest 1941 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1941, 'frFR', 'Voici votre robe. C\'est l\'une des meilleures que j\'aie faites jusqu\'à présent ! Portez-la avec fierté, et quand les gens demanderont... dites-leur que vous l\'avez eue chez Larson Clothiers !') ON DUPLICATE KEY UPDATE RewardText='Voici votre robe. C\'est l\'une des meilleures que j\'aie faites jusqu\'à présent ! Portez-la avec fierté, et quand les gens demanderont... dites-leur que vous l\'avez eue chez Larson Clothiers !';
-- Quest 1942 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1942, 'frFR', 'Votre vêtement est prêt ! Et ce beau tissu que vous avez ramassé... vous ne voyez pas que je l\'ai un peu raccourci pour que je puisse garder un peu de soie pour moi, n\'est-ce pas?$B$Je plaisante. Il vous ira très bien, et sera parfait pour l\'aventure comme pour un dîner formel. Profitez-en !') ON DUPLICATE KEY UPDATE RewardText='Votre vêtement est prêt ! Et ce beau tissu que vous avez ramassé... vous ne voyez pas que je l\'ai un peu raccourci pour que je puisse garder un peu de soie pour moi, n\'est-ce pas?$B$Je plaisante. Il vous ira très bien, et sera parfait pour l\'aventure comme pour un dîner formel. Profitez-en !';
-- Quest 1943 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1943, 'frFR', 'Bien, vous êtes venu. Ma tâche n\'est pas facile, mais elle est vitale pour la société des mages. Si vous m\'aidez, je suis sûr que vous trouverez cela digne d\'être fait.') ON DUPLICATE KEY UPDATE RewardText='Bien, vous êtes venu. Ma tâche n\'est pas facile, mais elle est vitale pour la société des mages. Si vous m\'aidez, je suis sûr que vous trouverez cela digne d\'être fait.';
-- Quest 1944 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1944, 'frFR', 'Je suis ravi que vous soyez revenu indemne, $N. Avez-vous l\'échantillon d\'eau ? Je suis impatient d\'étudier ses propriétés.') ON DUPLICATE KEY UPDATE CompletionText='Je suis ravi que vous soyez revenu indemne, $N. Avez-vous l\'échantillon d\'eau ? Je suis impatient d\'étudier ses propriétés.';
-- Quest 1944 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1944, 'frFR', 'Ah, très bien. J\'espère que les satyres de Xavian ne vous ont pas trop dérangé?$B$Merci, $N. J\'étudierai immédiatement cet échantillon d\'eau de Xavian.') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien. J\'espère que les satyres de Xavian ne vous ont pas trop dérangé?$B$Merci, $N. J\'étudierai immédiatement cet échantillon d\'eau de Xavian.';
-- Quest 1945 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1945, 'frFR', 'Salutations, $N. Deino a dit que vous viendriez, et que vous apporteriez les cheveux des sœurs riantes. L\'avez-vous ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $N. Deino a dit que vous viendriez, et que vous apporteriez les cheveux des sœurs riantes. L\'avez-vous ?';
-- Quest 1945 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1945, 'frFR', 'Ah, ces cheveux tisseront une belle robe, $N. C\'est dommage que les sœurs riantes aient dû mourir pour s\'en séparer, même si je doute qu\'elles l\'aient jamais fait volontairement.$B$C\'est dommage, mais un petit peu.') ON DUPLICATE KEY UPDATE RewardText='Ah, ces cheveux tisseront une belle robe, $N. C\'est dommage que les sœurs riantes aient dû mourir pour s\'en séparer, même si je doute qu\'elles l\'aient jamais fait volontairement.$B$C\'est dommage, mais un petit peu.';
-- Quest 1946 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1946, 'frFR', 'Voici votre dentelle de bas, $N. Elle est à la fois confortable et durable, et elle contient la magie des cheveux des sœurs riantes.$B$Profitez-en, et si vous la trouvez agréable, veuillez en informer Deino. Elle est une $c dont je souhaite rester sur le bon côté...') ON DUPLICATE KEY UPDATE RewardText='Voici votre dentelle de bas, $N. Elle est à la fois confortable et durable, et elle contient la magie des cheveux des sœurs riantes.$B$Profitez-en, et si vous la trouvez agréable, veuillez en informer Deino. Elle est une $c dont je souhaite rester sur le bon côté...';
-- Quest 1947 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1947, 'frFR', 'Silence ! Je suis dans une situation délicate et je ne dois pas être dérangé !$B$Un instant...') ON DUPLICATE KEY UPDATE RewardText='Silence ! Je suis dans une situation délicate et je ne dois pas être dérangé !$B$Un instant...';
-- Quest 1948 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1948, 'frFR', 'Bonjour, $N. Avez-vous les objets dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $N. Avez-vous les objets dont j\'ai besoin ?';
-- Quest 1948 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1948, 'frFR', 'Aha ! Vous avez eu le jade et fait le ronce ! Bien joué !$B$Est-ce de la fumée que je vois s\'échapper de vos oreilles ? Vous avez peut-être été trop près quand la foudre a frappé les bâtons totems, mais ne vous inquiétez pas. Être frappé par la foudre est un bon présage !') ON DUPLICATE KEY UPDATE RewardText='Aha ! Vous avez eu le jade et fait le ronce ! Bien joué !$B$Est-ce de la fumée que je vois s\'échapper de vos oreilles ? Vous avez peut-être été trop près quand la foudre a frappé les bâtons totems, mais ne vous inquiétez pas. Être frappé par la foudre est un bon présage !';
-- Quest 1949 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1949, 'frFR', 'Quoi ? Parlez plus fort ! Ces vieilles oreilles ne sont pas aussi aiguisées qu\'avant.$B$Eh bien, j\'espère que vous êtes là avec une bonne chope de bière ou des conseils sur la prochaine course ! Sinon, vous feriez mieux de continuer votre chemin... parce que j\'ai une baguette de polymorph avec votre nom dessus !') ON DUPLICATE KEY UPDATE RewardText='Quoi ? Parlez plus fort ! Ces vieilles oreilles ne sont pas aussi aiguisées qu\'avant.$B$Eh bien, j\'espère que vous êtes là avec une bonne chope de bière ou des conseils sur la prochaine course ! Sinon, vous feriez mieux de continuer votre chemin... parce que j\'ai une baguette de polymorph avec votre nom dessus !';
-- Quest 1950 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1950, 'frFR', 'Qu\'attendez-vous ? J\'ai besoin de ma phrase magique !') ON DUPLICATE KEY UPDATE CompletionText='Qu\'attendez-vous ? J\'ai besoin de ma phrase magique !';
-- Quest 1950 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1950, 'frFR', 'Ah, maintenant je me souviens...$B$J\'avais oublié la petite malédiction que j\'ai mise sur Johnson. Je ne me souviens pas pourquoi je l\'ai fait, mais je suis sûr que ça lui a bien valu, ce petit ingrat !') ON DUPLICATE KEY UPDATE RewardText='Ah, maintenant je me souviens...$B$J\'avais oublié la petite malédiction que j\'ai mise sur Johnson. Je ne me souviens pas pourquoi je l\'ai fait, mais je suis sûr que ça lui a bien valu, ce petit ingrat !';
-- Quest 1951 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1951, 'frFR', 'Salutations, $N. Avez-vous trouvé le livre, Rituals of Power ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $N. Avez-vous trouvé le livre, Rituals of Power ?';

-- Quest 1951 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1951, 'frFR', 'C\'est tout ! C\'est exactement ce dont j\'ai besoin pour préparer le rituel afin de créer votre baguette ! J\'espère que ce n\'était pas trop de peine de trouver...') ON DUPLICATE KEY UPDATE RewardText='C\'est tout ! C\'est exactement ce dont j\'ai besoin pour préparer le rituel afin de créer votre baguette ! J\'espère que ce n\'était pas trop de peine de trouver...';
-- Quest 1952 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1952, 'frFR', 'Voici les baguettes que j\'ai faites. Choisissez la vôtre !') ON DUPLICATE KEY UPDATE RewardText='Voici les baguettes que j\'ai faites. Choisissez la vôtre !';
-- Quest 1953 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1953, 'frFR', 'Ah, oui. Vous êtes ici pour un orbe ou un bâton, $N ? Très bien. Je vous aiderai dans sa construction.$B$BMais prévenez-vous -- le processus est périlleux et pourrait signifier votre mort.$B$BOu ma mort. Définitivement la mort de quelqu\'un... $B$BMais espérons que ce soit la mort de quelqu\'un d\'autre, hein ?') ON DUPLICATE KEY UPDATE RewardText='Ah, oui. Vous êtes ici pour un orbe ou un bâton, $N ? Très bien. Je vous aiderai dans sa construction.$B$BMais prévenez-vous -- le processus est périlleux et pourrait signifier votre mort.$B$BOu ma mort. Définitivement la mort de quelqu\'un... $B$BMais espérons que ce soit la mort de quelqu\'un d\'autre, hein ?';
-- Quest 1954 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1954, 'frFR', 'Avez-vous un orbe infernal, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous un orbe infernal, $N ?';
-- Quest 1954 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1954, 'frFR', 'Oh, c\'est un joli ! Non, je ne veux pas dire qu\'il est "joli" comme le jus cool est bon par temps chaud.$B$BEn fait, il n\'est PAS joli maintenant que j\'y pense. Pas le jus. L\'orbe !$B$BConcentrez-vous, $N ! Nous aurons besoin que vous soyez concentré si nous voulons terminer notre tâche !') ON DUPLICATE KEY UPDATE RewardText='Oh, c\'est un joli ! Non, je ne veux pas dire qu\'il est "joli" comme le jus cool est bon par temps chaud.$B$BEn fait, il n\'est PAS joli maintenant que j\'y pense. Pas le jus. L\'orbe !$B$BConcentrez-vous, $N ! Nous aurons besoin que vous soyez concentré si nous voulons terminer notre tâche !';
-- Quest 1955 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1955, 'frFR', 'Vous devrez tuer ce démon pour enlever sa souillure de l\'orbe, $N.') ON DUPLICATE KEY UPDATE CompletionText='Vous devrez tuer ce démon pour enlever sa souillure de l\'orbe, $N.';
-- Quest 1955 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1955, 'frFR', 'Bien fait, $N ! Vous avez donné une leçon à ce démon qu\'il n\'oubliera pas.$B$BIl réfléchira à deux fois avant de remettre sa tête laide dans ce monde, à la recherche du stupide mortel qui l\'a battu. Probablement avec des amis cette fois. Des amis gros et écailleux qui ne voudraient rien de plus que vous déchirer en petits morceaux $R.$B$Je ne vous ai pas effrayé, si...$N?') ON DUPLICATE KEY UPDATE RewardText='Bien fait, $N ! Vous avez donné une leçon à ce démon qu\'il n\'oubliera pas.$B$BIl réfléchira à deux fois avant de remettre sa tête laide dans ce monde, à la recherche du stupide mortel qui l\'a battu. Probablement avec des amis cette fois. Des amis gros et écailleux qui ne voudraient rien de plus que vous déchirer en petits morceaux $R.$B$Je ne vous ai pas effrayé, si...$N?';
-- Quest 1956 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1956, 'frFR', 'Êtes-vous allé à Uldaman, $N ? Avez-vous vaincu le sentinelle d\'obsidienne ?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous allé à Uldaman, $N ? Avez-vous vaincu le sentinelle d\'obsidienne ?';
-- Quest 1956 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1956, 'frFR', 'Vous l\'avez fait ? Bien joué !$B$BI conversais avec certains de mes collègues et quand votre nom est sorti, ils ont dit : "Vous savez que $N fonctionne bien sous le stress !"$B$BMais quand je leur ai dit que je vous avais envoyé à Uldaman contre le sentinelle d\'obsidienne, ils ont dit que j\'étais folle ! Ils ont dit : "Tabetha, tu es folle ! Il n\'y a aucun moyen que $N puisse affronter ce sentinelle !"$B$BEt j\'ai dit : "Nous verrons", et puis ils ont dit "Oui, nous verrons..."$B$BEh bien, on leur a montré, n\'est-ce pas !') ON DUPLICATE KEY UPDATE RewardText='Vous l\'avez fait ? Bien joué !$B$BI conversais avec certains de mes collègues et quand votre nom est sorti, ils ont dit : "Vous savez que $N fonctionne bien sous le stress !"$B$BMais quand je leur ai dit que je vous avais envoyé à Uldaman contre le sentinelle d\'obsidienne, ils ont dit que j\'étais folle ! Ils ont dit : "Tabetha, tu es folle ! Il n\'y a aucun moyen que $N puisse affronter ce sentinelle !"$B$BEt j\'ai dit : "Nous verrons", et puis ils ont dit "Oui, nous verrons..."$B$BEh bien, on leur a montré, n\'est-ce pas !';
-- Quest 1957 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1957, 'frFR', 'Vous n\'avez pas tué le nombre requis de sursauts de mana, $N.') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas tué le nombre requis de sursauts de mana, $N.';
-- Quest 1957 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1957, 'frFR', 'Vous l\'avez fait ! Je ne vous ai jamais douté une seconde ! Ok, peut-être une seconde, ou deux... mais fondamentalement, je n\'avais pas beaucoup de doute.$B$BHonnêtement.') ON DUPLICATE KEY UPDATE RewardText='Vous l\'avez fait ! Je ne vous ai jamais douté une seconde ! Ok, peut-être une seconde, ou deux... mais fondamentalement, je n\'avais pas beaucoup de doute.$B$BHonnêtement.';
-- Quest 1958 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1958, 'frFR', 'Vous devriez être fier de vous, $N. Beaucoup de mages sont tombés aux créatures auxquelles vous avez fait face.$B$BL\'Orbe Céleste est prêt. Ou si vous préférez, je peux l\'installer sur un bâton. C\'est à vous. Je préfère l\'orbe, mais qui suis-je pour juger ?') ON DUPLICATE KEY UPDATE RewardText='Vous devriez être fier de vous, $N. Beaucoup de mages sont tombés aux créatures auxquelles vous avez fait face.$B$BL\'Orbe Céleste est prêt. Ou si vous préférez, je peux l\'installer sur un bâton. C\'est à vous. Je préfère l\'orbe, mais qui suis-je pour juger ?';
-- Quest 1959 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1959, 'frFR', 'C\'est vrai. Une perturbation magique a été détectée dans notre ville. Nous ne sommes pas encore sûrs de son origine, ou si elle est maligne ou bénigne. Nous devons d\'abord recueillir plus d\'informations...$B$BEt cela, $N, nous amène à votre tâche.') ON DUPLICATE KEY UPDATE RewardText='C\'est vrai. Une perturbation magique a été détectée dans notre ville. Nous ne sommes pas encore sûrs de son origine, ou si elle est maligne ou bénigne. Nous devons d\'abord recueillir plus d\'informations...$B$BEt cela, $N, nous amène à votre tâche.';
-- Quest 1960 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1960, 'frFR', 'Avez-vous enquêté sur la perturbation, $N ? Avez-vous capturé les créatures ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous enquêté sur la perturbation, $N ? Avez-vous capturé les créatures ?';
-- Quest 1960 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1960, 'frFR', 'Très bien, $N. Les créatures dans ces coffres de confinement seront étudiées par nos meilleurs esprits, et la raison de leur présence dans la Cité Souterraine sera déterminée.$B$BSi leur apparition est causée par une brèche dans le flux naturel de la magie, alors nous devons déterminer si la brèche était aléatoire. Si elle ne l\'était pas, mais plutôt une attaque d\'une force magique, alors nous devons nous préparer à de futures perturbations plus sérieuses.') ON DUPLICATE KEY UPDATE RewardText='Très bien, $N. Les créatures dans ces coffres de confinement seront étudiées par nos meilleurs esprits, et la raison de leur présence dans la Cité Souterraine sera déterminée.$B$BSi leur apparition est causée par une brèche dans le flux naturel de la magie, alors nous devons déterminer si la brèche était aléatoire. Si elle ne l\'était pas, mais plutôt une attaque d\'une force magique, alors nous devons nous préparer à de futures perturbations plus sérieuses.';

-- Quest 1961 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1961, 'frFR', 'Anastasia a dit que vous viendriez me voir, et je suis prêt à confectionner vos robes. Avez-vous les gemmes et le lin ?') ON DUPLICATE KEY UPDATE CompletionText='Anastasia a dit que vous viendriez me voir, et je suis prêt à confectionner vos robes. Avez-vous les gemmes et le lin ?';
-- Quest 1961 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1961, 'frFR', 'C\'est un très bon matériau, et bien que je manque du talent pour évaluer la qualité de ces gemmes de mana, nous saurons bientôt si elles possèdent la puissance nécessaire pour créer des robes de feu magique...') ON DUPLICATE KEY UPDATE RewardText='C\'est un très bon matériau, et bien que je manque du talent pour évaluer la qualité de ces gemmes de mana, nous saurons bientôt si elles possèdent la puissance nécessaire pour créer des robes de feu magique...';
-- Quest 1962 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1962, 'frFR', 'Voici vos robes, $N$. Portez-les bien.') ON DUPLICATE KEY UPDATE RewardText='Voici vos robes, $N$. Portez-les bien.';
-- Quest 1963 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1963, 'frFR', 'C\'est un imbécile qui croit qu\'une charge avec une hache à la main est plus dangereuse qu\'un couteau dans le noir.') ON DUPLICATE KEY UPDATE CompletionText='C\'est un imbécile qui croit qu\'une charge avec une hache à la main est plus dangereuse qu\'un couteau dans le noir.';
-- Quest 1963 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1963, 'frFR', 'Hm, bien que je sois heureux d\'apprendre que Tazan ne soit plus parmi nous, un sac verrouillé ne nous sert à rien. Nous avons besoin que l\'information reste à l\'intérieur.$b$bCeci devrait constituer un deuxième défi digne pour celui qui souhaite rejoindre la Main Brisée.') ON DUPLICATE KEY UPDATE RewardText='Hm, bien que je sois heureux d\'apprendre que Tazan ne soit plus parmi nous, un sac verrouillé ne nous sert à rien. Nous avons besoin que l\'information reste à l\'intérieur.$b$bCeci devrait constituer un deuxième défi digne pour celui qui souhaite rejoindre la Main Brisée.';
-- Quest 1978 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1978, 'frFR', 'Hmm, c\'est intéressant. Les Chasseurs de Mort ont rempli leurs devoirs admirablement en débusquant cela.$B$BD\'après ce que je comprends, vous méritez également des félicitations pour votre performance. J\'espère que cela deviendra une routine pour vous, $N$, mes Chasseurs de Mort ont toujours besoin d\'un bon homme.') ON DUPLICATE KEY UPDATE RewardText='Hmm, c\'est intéressant. Les Chasseurs de Mort ont rempli leurs devoirs admirablement en débusquant cela.$B$BD\'après ce que je comprends, vous méritez également des félicitations pour votre performance. J\'espère que cela deviendra une routine pour vous, $N$, mes Chasseurs de Mort ont toujours besoin d\'un bon homme.';
-- Quest 1998 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1998, 'frFR', 'J\'ai placé la plus grande confiance en vous pour accomplir ce service pour Lord Varimathras.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai placé la plus grande confiance en vous pour accomplir ce service pour Lord Varimathras.';
-- Quest 1998 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1998, 'frFR', 'Vous avez bien fait, $N$. Il me vient à l\'esprit que vous avez accompli de nombreux services pour les Chasseurs de Mort, prouvant votre valeur, et qu\'il est peut-être temps que nous approfondissions votre entraînement dans les arts de l\'ombre.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, $N$. Il me vient à l\'esprit que vous avez accompli de nombreux services pour les Chasseurs de Mort, prouvant votre valeur, et qu\'il est peut-être temps que nous approfondissions votre entraînement dans les arts de l\'ombre.';
-- Quest 1999 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1999, 'frFR', 'Avez-vous trouvé les documents, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé les documents, $N$?';
-- Quest 1999 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (1999, 'frFR', 'Très bien, $N$! Vous avez appris l\'art subtil du crochetage de serrures, et plus vite que je ne l\'aurais pu espérer.$B$Je vois que j\'avais raison de placer ma confiance en vous. Croyez-moi, garçon, j\'envisage que vous irez loin dans ce domaine.') ON DUPLICATE KEY UPDATE RewardText='Très bien, $N$! Vous avez appris l\'art subtil du crochetage de serrures, et plus vite que je ne l\'aurais pu espérer.$B$Je vois que j\'avais raison de placer ma confiance en vous. Croyez-moi, garçon, j\'envisage que vous irez loin dans ce domaine.';
-- Quest 2078 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2078, 'frFR', 'Où est mon premier équipier, $N$? Des chaînes et des requins pour vous bientôt si vous ne vous dépêchez pas!') ON DUPLICATE KEY UPDATE CompletionText='Où est mon premier équipier, $N$? Des chaînes et des requins pour vous bientôt si vous ne vous dépêchez pas!';
-- Quest 2118 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2118, 'frFR', 'M\'avez-vous apporté l\'animal malade, $N$?B$BSi vous échouez à déclencher le piège, ne vous inquiétez pas - l\'Espoir de Tharnariun est éternel. Si vous avez besoin d\'un autre piège, abandonnez votre tâche et revenez me voir.') ON DUPLICATE KEY UPDATE CompletionText='M\'avez-vous apporté l\'animal malade, $N$?B$BSi vous échouez à déclencher le piège, ne vous inquiétez pas - l\'Espoir de Tharnariun est éternel. Si vous avez besoin d\'un autre piège, abandonnez votre tâche et revenez me voir.';
-- Quest 2139 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2139, 'frFR', 'Avec la Mère des Puces infectée abattue, la population de Oursons de Bristle fous entrant dans notre terre est diminuée. Ne perdez pas de temps, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Avec la Mère des Puces infectée abattue, la population de Oursons de Bristle fous entrant dans notre terre est diminuée. Ne perdez pas de temps, $N$.';
-- Quest 2199 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2199, 'frFR', 'Avez-vous les cinq lingots d\'argent que j\'ai demandés ? Je partagerai mon triste récit de chagrin avec vous concernant le collier que vous possédez maintenant... mais seulement après avoir obtenu ces lingots ! S\'il vous plaît, aidez un gnome, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les cinq lingots d\'argent que j\'ai demandés ? Je partagerai mon triste récit de chagrin avec vous concernant le collier que vous possédez maintenant... mais seulement après avoir obtenu ces lingots ! S\'il vous plaît, aidez un gnome, n\'est-ce pas ?';
-- Quest 2199 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2199, 'frFR', 'Vous avez raison dans mon livre ; je me fiche de ce que tout le monde a dit... Je plaisante, je plaisante !  Sérieusement, merci mon ami.$B$Maintenant, le collier que vous avez est l\'un de mes plus beaux créations, mais il lui manque trois gemmes qui aident à lier la puissance magique.  Je l\'ai fabriqué pour un paladin il y a quelque temps.  Il était en quête auto-proclamée pour éliminer la "tache maléfique" présente sur un site d\'excavation dans les Terres Désolées appelé Uldaman.$B$Eh bien... ce paladin est mort à Uldaman, et ce n\'était que le début de mes malheurs.') ON DUPLICATE KEY UPDATE RewardText='Vous avez raison dans mon livre ; je me fiche de ce que tout le monde a dit... Je plaisante, je plaisante !  Sérieusement, merci mon ami.$B$Maintenant, le collier que vous avez est l\'un de mes plus beaux créations, mais il lui manque trois gemmes qui aident à lier la puissance magique.  Je l\'ai fabriqué pour un paladin il y a quelque temps.  Il était en quête auto-proclamée pour éliminer la "tache maléfique" présente sur un site d\'excavation dans les Terres Désolées appelé Uldaman.$B$Eh bien... ce paladin est mort à Uldaman, et ce n\'était que le début de mes malheurs.';

-- Quest 2201 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2201, 'frFR', 'L\'image de Talvash se dessine à travers les eaux du bol de divination.$b$b"Wow, tu es toujours en vie ! As-tu réussi à trouver les gemmes ? Es-tu vraiment le sauveur de la réputation que j\'espérais ? Dis-moi que tu n\'as pas gaspillé une charge sur le flacon juste pour bavarder ; ces choses ne sont PAS bon marché, et je suis déjà dans une situation financière critique') ON DUPLICATE KEY UPDATE CompletionText='L\'image de Talvash se dessine à travers les eaux du bol de divination.$b$b"Wow, tu es toujours en vie ! As-tu réussi à trouver les gemmes ? Es-tu vraiment le sauveur de la réputation que j\'espérais ? Dis-moi que tu n\'as pas gaspillé une charge sur le flacon juste pour bavarder ; ces choses ne sont PAS bon marché, et je suis déjà dans une situation financière critique';
-- Quest 2201 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2201, 'frFR', 'Oui, ce sont bien les trois gemmes.  Bon travail !  Malheureusement, ton travail n\'est pas encore terminé.$B$BNon, je ne cherche pas à te faire marcher, idiot <class>.  Il s\'agit de fabriquer des bijoux magiques - des bijoux de qualité Talvash del Kissel !  Tu as besoin d\'une source de puissance forte pour leur donner du pep.  Eh bien, ce collier n\'a plus de pep à donner.') ON DUPLICATE KEY UPDATE RewardText='Oui, ce sont bien les trois gemmes.  Bon travail !  Malheureusement, ton travail n\'est pas encore terminé.$B$BNon, je ne cherche pas à te faire marcher, idiot <class>.  Il s\'agit de fabriquer des bijoux magiques - des bijoux de qualité Talvash del Kissel !  Tu as besoin d\'une source de puissance forte pour leur donner du pep.  Eh bien, ce collier n\'a plus de pep à donner.';
-- Quest 2202 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2202, 'frFR', 'As-tu obtenu les chapeaux de champignons magenta dont j\'ai besoin pour mon travail alchimique ? Pas de chapeaux - pas de récompense !') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu les chapeaux de champignons magenta dont j\'ai besoin pour mon travail alchimique ? Pas de chapeaux - pas de récompense !';
-- Quest 2202 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2202, 'frFR', 'Bien joué <name>, tu as prouvé ta valeur une fois de plus !  Les chapeaux seront une étude intéressante, tu peux être sûre.$B$BEt maintenant, comme promis, savoure une gorgée de l\'un de mes élixirs réparateurs les plus puissants de mon stock personnel...$B$BSi tu es un alchimiste doué, alors nous pourrions avoir d\'autres affaires à régler.  Quoi qu\'il en soit, je te remercie de ton aide !') ON DUPLICATE KEY UPDATE RewardText='Bien joué <name>, tu as prouvé ta valeur une fois de plus !  Les chapeaux seront une étude intéressante, tu peux être sûre.$B$BEt maintenant, comme promis, savoure une gorgée de l\'un de mes élixirs réparateurs les plus puissants de mon stock personnel...$B$BSi tu es un alchimiste doué, alors nous pourrions avoir d\'autres affaires à régler.  Quoi qu\'il en soit, je te remercie de ton aide !';
-- Quest 2203 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2203, 'frFR', 'As-tu utilisé les récipients pour m\'obtenir le sang de dragon gardien brûlé dont j\'ai besoin ? Oui, je sais que c\'est une tâche dangereuse... mais la recette de mon élixir réparateur attend ton succès. Risque et récompense, mon ami... risque et récompense...') ON DUPLICATE KEY UPDATE CompletionText='As-tu utilisé les récipients pour m\'obtenir le sang de dragon gardien brûlé dont j\'ai besoin ? Oui, je sais que c\'est une tâche dangereuse... mais la recette de mon élixir réparateur attend ton succès. Risque et récompense, mon ami... risque et récompense...';
-- Quest 2203 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2203, 'frFR', 'D\'un alchimiste à un autre, je t\'honore. Tiens, prends cette recette et grave-la dans ta mémoire. Qu\'elle t\'apporte le succès et les récompenses qu\'elle m\'a apportés au fil des ans.') ON DUPLICATE KEY UPDATE RewardText='D\'un alchimiste à un autre, je t\'honore. Tiens, prends cette recette et grave-la dans ta mémoire. Qu\'elle t\'apporte le succès et les récompenses qu\'elle m\'a apportés au fil des ans.';
-- Quest 2204 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2204, 'frFR', 'Tu ne t\'es même pas arrêté pour te nettoyer après être sorti d\'Uldaman, n\'est-ce pas. Tu es venu directement ici, les odeurs de donjon qui persistent soient damnées. Eh bien, espérons que cette visite soit simplement odorante, et pas inutile en plus.$B$BAs-tu la source de puissance pour le collier ?') ON DUPLICATE KEY UPDATE CompletionText='Tu ne t\'es même pas arrêté pour te nettoyer après être sorti d\'Uldaman, n\'est-ce pas. Tu es venu directement ici, les odeurs de donjon qui persistent soient damnées. Eh bien, espérons que cette visite soit simplement odorante, et pas inutile en plus.$B$BAs-tu la source de puissance pour le collier ?';
-- Quest 2204 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2204, 'frFR', 'Eh bien, je suis ravi de te voir et cette source de puissance en état.  Il me faudra un moment pour fusionner magiquement la source de puissance avec le collier maintenant que les gemmes ont été réunies avec lui.  Une fois que ce sera fait, le collier sera le tien !$B$BTu es excité, n\'est-ce pas ?  Tout picote d\'anticipation ?  Maintenant, où ai-je mis ce focus de sortilège...') ON DUPLICATE KEY UPDATE RewardText='Eh bien, je suis ravi de te voir et cette source de puissance en état.  Il me faudra un moment pour fusionner magiquement la source de puissance avec le collier maintenant que les gemmes ont été réunies avec lui.  Une fois que ce sera fait, le collier sera le tien !$B$BTu es excité, n\'est-ce pas ?  Tout picote d\'anticipation ?  Maintenant, où ai-je mis ce focus de sortilège...';
-- Quest 2205 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2205, 'frFR', 'Tu m\'as trouvé - et en te regardant, je dirais que la course et la recherche subséquente ont pu être une grande épreuve pour ton système, mentalement et physiquement.$B$BVoudrais-tu que Renzik te montre le chemin vers une auberge ou es-tu prêt pour du travail ?') ON DUPLICATE KEY UPDATE RewardText='Tu m\'as trouvé - et en te regardant, je dirais que la course et la recherche subséquente ont pu être une grande épreuve pour ton système, mentalement et physiquement.$B$BVoudrais-tu que Renzik te montre le chemin vers une auberge ou es-tu prêt pour du travail ?';
-- Quest 2218 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2218, 'frFR', 'Alors, tu te crois un vrai scoundrel ? Destiné à être l\'un des élus de Blackbeard - un officier du Cercle Caché?$B$BSeul un bon fer nothin\' scallywag penserait si haut de lui.$B$BC\'est exactement ce que nous cherchons ! Bienvenue à bord, $N!') ON DUPLICATE KEY UPDATE RewardText='Alors, tu te crois un vrai scoundrel ? Destiné à être l\'un des élus de Blackbeard - un officier du Cercle Caché?$B$BSeul un bon fer nothin\' scallywag penserait si haut de lui.$B$BC\'est exactement ce que nous cherchons ! Bienvenue à bord, $N!';
-- Quest 2238 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2238, 'frFR', 'Chut ! Fais taire ce stupide imbécile. Ils vont nous entendre.') ON DUPLICATE KEY UPDATE RewardText='Chut ! Fais taire ce stupide imbécile. Ils vont nous entendre.';
-- Quest 2239 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2239, 'frFR', 'As-tu apprécié l\'odeur du gnome lépreux ? Je demande juste parce que tu as un sourire fou sur le visage.$B$BQuelles nouvelles apportes-tu d\'Onin ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apprécié l\'odeur du gnome lépreux ? Je demande juste parce que tu as un sourire fou sur le visage.$B$BQuelles nouvelles apportes-tu d\'Onin ?';
-- Quest 2239 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2239, 'frFR', 'Long voyage ? Au nom de ma propre barbe !$B$As-tu bien fait, $N. Prends ce poignard et pars. Le Cercle t\'appellera à nouveau lorsque l\'étape trois sera prête à être mise en œuvre.$B$BQuelle est l\'étape trois ? Elle vient juste après l\'étape deux - moi mettre mon bot sur ton derrière.$B$BIntéressé ?') ON DUPLICATE KEY UPDATE RewardText='Long voyage ? Au nom de ma propre barbe !$B$As-tu bien fait, $N. Prends ce poignard et pars. Le Cercle t\'appellera à nouveau lorsque l\'étape trois sera prête à être mise en œuvre.$B$BQuelle est l\'étape trois ? Elle vient juste après l\'étape deux - moi mettre mon bot sur ton derrière.$B$BIntéressé ?';
-- Quest 2240 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2240, 'frFR', 'As-tu quelque chose à rapporter ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu quelque chose à rapporter ?';
-- Quest 2241 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2241, 'frFR', 'Oh, n\'est-ce pas merveilleux. Tu as apporté des fleurs pour tes propres funérailles.') ON DUPLICATE KEY UPDATE CompletionText='Oh, n\'est-ce pas merveilleux. Tu as apporté des fleurs pour tes propres funérailles.';

-- Quest 2241 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2241, 'frFR', 'Si j\'avais conservé chaque fleur que dolt, Jannok, m\'a envoyée, j\'aurais eu les moyens d\'ouvrir une boutique. Quoi qu\'il en soit, il semble que le dernier coursier de Jannok puisse s\'avérer utile.Intéressé par du travail, $c?') ON DUPLICATE KEY UPDATE RewardText='Si j\'avais conservé chaque fleur que dolt, Jannok, m\'a envoyée, j\'aurais eu les moyens d\'ouvrir une boutique. Quoi qu\'il en soit, il semble que le dernier coursier de Jannok puisse s\'avérer utile.Intéressé par du travail, $c?';
-- Quest 2242 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2242, 'frFR', 'As-tu quelque chose à rapporter de Sethir l\'Ancien, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu quelque chose à rapporter de Sethir l\'Ancien, $N?';
-- Quest 2242 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2242, 'frFR', 'C\'est une nouvelle sombre, $N. Il semble que la maladie qui a saisi les forêts et les rivières de Darkshore ait commencé à souiller notre foyer.$B$BTu nous as bien servi, mais il n\'y a rien de plus que tu puisses faire ici. Prends cette lame comme récompense pour ton service à Teldrassil.') ON DUPLICATE KEY UPDATE RewardText='C\'est une nouvelle sombre, $N. Il semble que la maladie qui a saisi les forêts et les rivières de Darkshore ait commencé à souiller notre foyer.$B$BTu nous as bien servi, mais il n\'y a rien de plus que tu puisses faire ici. Prends cette lame comme récompense pour ton service à Teldrassil.';
-- Quest 2259 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2259, 'frFR', 'Il est temps de s\'étendre, $R - le monde attend.') ON DUPLICATE KEY UPDATE RewardText='Il est temps de s\'étendre, $R - le monde attend.';
-- Quest 2260 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2260, 'frFR', 'Tu as répondu à l\'appel de SI:7, $N et tu as voyagé de rivages lointains pour rejoindre nos rangs, cependant, il y a beaucoup de choses à apprendre pour toi.') ON DUPLICATE KEY UPDATE RewardText='Tu as répondu à l\'appel de SI:7, $N et tu as voyagé de rivages lointains pour rejoindre nos rangs, cependant, il y a beaucoup de choses à apprendre pour toi.';
-- Quest 2278 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2278, 'frFR', 'La voix du gardien de pierre semble résonner au plus profond de ton être:$b$b"Tu dois d\'abord satisfaire l\'exigence d\'assimilation des données des Disques de Norgannon; une fois que tu auras rempli cette exigence, tu seras alors autorisé à obtenir une version portable des données stockées. Assure-toi de bien avoir exploré les informations dans ce référentiel en premier."') ON DUPLICATE KEY UPDATE CompletionText='La voix du gardien de pierre semble résonner au plus profond de ton être:$b$b"Tu dois d\'abord satisfaire l\'exigence d\'assimilation des données des Disques de Norgannon; une fois que tu auras rempli cette exigence, tu seras alors autorisé à obtenir une version portable des données stockées. Assure-toi de bien avoir exploré les informations dans ce référentiel en premier."';
-- Quest 2281 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2281, 'frFR', 'Ah, donc tes doigts sont un peu gros, hein? Ne t\'inquiète pas, $N, j\'ai transformé plus de voleurs inutiles que toi en voleurs accomplis.') ON DUPLICATE KEY UPDATE RewardText='Ah, donc tes doigts sont un peu gros, hein? Ne t\'inquiète pas, $N, j\'ai transformé plus de voleurs inutiles que toi en voleurs accomplis.';
-- Quest 2282 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2282, 'frFR', 'Ai-je oublié de mentionner les orcs?$B$J\'entends qu\'ils rôdent près du moulin.') ON DUPLICATE KEY UPDATE CompletionText='Ai-je oublié de mentionner les orcs?$B$J\'entends qu\'ils rôdent près du moulin.';
-- Quest 2282 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2282, 'frFR', 'Tu l\'as ouvert, hein? Bon travail, $N.$B$BSi tu meurs maintenant, nous pouvons être tranquilles en sachant que c\'est dû à ta propre stupidité et non à ton inexpérience.') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as ouvert, hein? Bon travail, $N.$B$BSi tu meurs maintenant, nous pouvons être tranquilles en sachant que c\'est dû à ta propre stupidité et non à ton inexpérience.';
-- Quest 2283 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2283, 'frFR', 'Eh bien, as-tu le collier? Tu ne verras pas un cuivre de notre part si tu n\'as pas ce collier!') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, as-tu le collier? Tu ne verras pas un cuivre de notre part si tu n\'as pas ce collier!';
-- Quest 2283 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2283, 'frFR', 'Mmmm salvage!  Je peux sentir le collier d\'ici.  Maintenant, regardons cette beauté...$B$BHé, qu\'est-ce que tu essaies de faire ici?  Ce collier manque de pierres précieuses!  Tu penses qu\'on ne le remarquerait pas?  Même Malton pourrait voir que les pierres précieuses ont disparu.$B$BEh bien, peut-être ne les as-tu pas volées... mais ce collier ne vaut rien sans ces pierres précieuses!  Ton travail n\'est pas terminé ici, pas du tout!') ON DUPLICATE KEY UPDATE RewardText='Mmmm salvage!  Je peux sentir le collier d\'ici.  Maintenant, regardons cette beauté...$B$BHé, qu\'est-ce que tu essaies de faire ici?  Ce collier manque de pierres précieuses!  Tu penses qu\'on ne le remarquerait pas?  Même Malton pourrait voir que les pierres précieuses ont disparu.$B$BEh bien, peut-être ne les as-tu pas volées... mais ce collier ne vaut rien sans ces pierres précieuses!  Ton travail n\'est pas terminé ici, pas du tout!';
-- Quest 2298 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2298, 'frFR', 'C\'est toujours bon d\'avoir un des voleurs de Hulfdan parmi nos rangs!') ON DUPLICATE KEY UPDATE RewardText='C\'est toujours bon d\'avoir un des voleurs de Hulfdan parmi nos rangs!';
-- Quest 2299 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2299, 'frFR', 'Garde ta voix basse, $N, les gardes pourraient t\'entendre.') ON DUPLICATE KEY UPDATE RewardText='Garde ta voix basse, $N, les gardes pourraient t\'entendre.';
-- Quest 2300 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2300, 'frFR', 'Es-tu prêt à commencer le travail ou as-tu besoin de faire une sieste avant que nous commencions?') ON DUPLICATE KEY UPDATE RewardText='Es-tu prêt à commencer le travail ou as-tu besoin de faire une sieste avant que nous commencions?';
-- Quest 2338 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2338, 'frFR', 'Tu as réfléchi, n\'est-ce pas? Tu es un $C intelligent si tu acceptes cette affaire - toi et moi obtiendrons ce que nous voulons tous les deux, et Droffers et Son Salvage penseront obtenir ce qu\'ils veulent.') ON DUPLICATE KEY UPDATE CompletionText='Tu as réfléchi, n\'est-ce pas? Tu es un $C intelligent si tu acceptes cette affaire - toi et moi obtiendrons ce que nous voulons tous les deux, et Droffers et Son Salvage penseront obtenir ce qu\'ils veulent.';

-- Quest 2338 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2338, 'frFR', 'Tu connais une bonne affaire quand tu en vois une - je savais que je pouvais compter sur toi.$B$BCe ne sera qu\'un instant pendant que je lance un sort pour traduire rapidement la langue humaine en une forme que tu comprendras. Je suis un troll de ma parole ; demande à n\'importe qui dans la Horde à propos de Jarkal Mossmeld. Maintenant, commençons...') ON DUPLICATE KEY UPDATE RewardText='Tu connais une bonne affaire quand tu en vois une - je savais que je pouvais compter sur toi.$B$BCe ne sera qu\'un instant pendant que je lance un sort pour traduire rapidement la langue humaine en une forme que tu comprendras. Je suis un troll de ma parole ; demande à n\'importe qui dans la Horde à propos de Jarkal Mossmeld. Maintenant, commençons...';
-- Quest 2339 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2339, 'frFR', 'Tu as une autre excursion dans les profondeurs d\'Uldaman à faire si tu n\'as pas les gemmes et une source d\'énergie capable de canaliser la puissance magique dans le collier.$B$BTu récupéreras les gemmes pour les livrer aux gars d\'Orgrimmar ; je garderai la source d\'énergie, car c\'est ce qui fera fonctionner le collier en premier lieu...') ON DUPLICATE KEY UPDATE CompletionText='Tu as une autre excursion dans les profondeurs d\'Uldaman à faire si tu n\'as pas les gemmes et une source d\'énergie capable de canaliser la puissance magique dans le collier.$B$BTu récupéreras les gemmes pour les livrer aux gars d\'Orgrimmar ; je garderai la source d\'énergie, car c\'est ce qui fera fonctionner le collier en premier lieu...';
-- Quest 2339 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2339, 'frFR', 'Très bien fait, <class>. Maintenant, les fruits de notre redirection vont se payer très bien. J\'ai fini avec le collier lui-même, et je suis confiant de pouvoir dupliquer le processus de construction de manière constante.$B$BMais d\'abord, j\'utiliserai une incantation spécialement préparée pour analyser rapidement ces gemmes avant que tu ne les prennes et le collier pour Orgrimmar. Cela ne prendra qu\'un bref moment.') ON DUPLICATE KEY UPDATE RewardText='Très bien fait, <class>. Maintenant, les fruits de notre redirection vont se payer très bien. J\'ai fini avec le collier lui-même, et je suis confiant de pouvoir dupliquer le processus de construction de manière constante.$B$BMais d\'abord, j\'utiliserai une incantation spécialement préparée pour analyser rapidement ces gemmes avant que tu ne les prennes et le collier pour Orgrimmar. Cela ne prendra qu\'un bref moment.';
-- Quest 2340 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2340, 'frFR', 'Eh bien, regarde qui c\'est ! Tu as mis ton temps à arriver, je vois. Espérons que ce ne soit pas une perte de mon temps ! Tu ne seras pas payé à moins d\'avoir tout ce que j\'ai demandé. Et crois-moi sur ce point - nous allons tout vérifier deux et trois fois !') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, regarde qui c\'est ! Tu as mis ton temps à arriver, je vois. Espérons que ce ne soit pas une perte de mon temps ! Tu ne seras pas payé à moins d\'avoir tout ce que j\'ai demandé. Et crois-moi sur ce point - nous allons tout vérifier deux et trois fois !';
-- Quest 2340 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2340, 'frFR', 'Yep, c\'est tout là. Dis, ça te dérange si on garde aussi le sac ? Non ? Merci, j\'apprécie ! Har!$b$bCe collier sera notre plus grande prise jusqu\'à présent ! Ne te sens pas trop mal ; je suis sûr que le collier ne te conviendrait de toute façon. Har encore !$b$bUn accord est un accord, alors voici ton paiement pour le sauvetage. Nos affaires sont terminées ici pour l\'instant ; reviens plus tard pour voir si nous avons plus de travail. D\'ici là, dégage !') ON DUPLICATE KEY UPDATE RewardText='Yep, c\'est tout là. Dis, ça te dérange si on garde aussi le sac ? Non ? Merci, j\'apprécie ! Har!$b$bCe collier sera notre plus grande prise jusqu\'à présent ! Ne te sens pas trop mal ; je suis sûr que le collier ne te conviendrait de toute façon. Har encore !$b$bUn accord est un accord, alors voici ton paiement pour le sauvetage. Nos affaires sont terminées ici pour l\'instant ; reviens plus tard pour voir si nous avons plus de travail. D\'ici là, dégage !';
-- Quest 2358 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2358, 'frFR', 'As-tu les cornes du prince démon ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu les cornes du prince démon ?';
-- Quest 2358 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2358, 'frFR', 'Refuser à Ravenholdt l\'artefact, serait nier sa propre existence. Bien fait, $Gclass>. Tu pourrais marcher parmi les assassins de Ravenholdt. $B<br :>En tant que jeune <class> aventurier dans Darkshore, j\'ai découvert un thé qui régénère l\'énergie en combat. Il m\'a bien servi au fil des années et maintenant je te transmets un goût de thé de carde. Bois-en quand tu es fatigué, <name>, et combat avec vigueur une fois de plus !') ON DUPLICATE KEY UPDATE RewardText='Refuser à Ravenholdt l\'artefact, serait nier sa propre existence. Bien fait, $Gclass>. Tu pourrais marcher parmi les assassins de Ravenholdt. $B<br :>En tant que jeune <class> aventurier dans Darkshore, j\'ai découvert un thé qui régénère l\'énergie en combat. Il m\'a bien servi au fil des années et maintenant je te transmets un goût de thé de carde. Bois-en quand tu es fatigué, <name>, et combat avec vigueur une fois de plus !';
-- Quest 2359 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2359, 'frFR', 'Cela expliquerait les drones Defias que toi et Kearnen avez vus à l\'extérieur de la tour, $N. Cela expliquerait aussi l\'implication de la Venture Company avec les Defias et les étranges cargaisons en provenance de Duskwood.$B$BSelon ce livre, les trolls Zanzil dans Stranglethorn ont découvert un moyen de ressusciter les morts grâce à des potions... ou pour être plus précis : des poisons.$B$BTu ne seras d\'aucune utilité pour SI:7 sans une compréhension solide des poisons, $N -- surtout avec la recette pour créer l\'immortalité à portée de main.') ON DUPLICATE KEY UPDATE RewardText='Cela expliquerait les drones Defias que toi et Kearnen avez vus à l\'extérieur de la tour, $N. Cela expliquerait aussi l\'implication de la Venture Company avec les Defias et les étranges cargaisons en provenance de Duskwood.$B$BSelon ce livre, les trolls Zanzil dans Stranglethorn ont découvert un moyen de ressusciter les morts grâce à des potions... ou pour être plus précis : des poisons.$B$BTu ne seras d\'aucune utilité pour SI:7 sans une compréhension solide des poisons, $N -- surtout avec la recette pour créer l\'immortalité à portée de main.';
-- Quest 2361 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2361, 'frFR', 'Je te donne ce collier avec plaisir, puissant $c. Tu m\'as rendu un service inestimable, et pour cela, je te remercie. Porte-le avec fierté, et assure-toi de mentionner fort et souvent qui l\'a fait pour toi !$B$BAussi, si tu pouvais ajouter le fait qu\'il n\'est pas vraiment maudit, ce serait super.') ON DUPLICATE KEY UPDATE RewardText='Je te donne ce collier avec plaisir, puissant $c. Tu m\'as rendu un service inestimable, et pour cela, je te remercie. Porte-le avec fierté, et assure-toi de mentionner fort et souvent qui l\'a fait pour toi !$B$BAussi, si tu pouvais ajouter le fait qu\'il n\'est pas vraiment maudit, ce serait super.';
-- Quest 2378 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2378, 'frFR', 'Alors, tu es ce que nos alliés puissants ont envoyé Shenthul ? Quelle inspiration....') ON DUPLICATE KEY UPDATE RewardText='Alors, tu es ce que nos alliés puissants ont envoyé Shenthul ? Quelle inspiration....';
-- Quest 2379 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2379, 'frFR', 'Peut-être que Zando\'zan avait tort. Zando\'zan s\'excuse.') ON DUPLICATE KEY UPDATE RewardText='Peut-être que Zando\'zan avait tort. Zando\'zan s\'excuse.';
-- Quest 2380 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2380, 'frFR', 'Il est important que la Main Brisée reste vigilante face aux changements que Thrall souhaite apporter à la Horde. Nos seuls chiffres ne suffiront pas à vaincre son règne - la furtivité et la tromperie doivent être maîtrisées.') ON DUPLICATE KEY UPDATE RewardText='Il est important que la Main Brisée reste vigilante face aux changements que Thrall souhaite apporter à la Horde. Nos seuls chiffres ne suffiront pas à vaincre son règne - la furtivité et la tromperie doivent être maîtrisées.';
-- Quest 2381 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2381, 'frFR', 'Eh bien, au moins tu as encore toutes tes parties du corps. As-tu trouvé le trésor?$b$b') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, au moins tu as encore toutes tes parties du corps. As-tu trouvé le trésor?$b$b';
-- Quest 2381 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2381, 'frFR', 'Incroyable ! Improbable ! Simplement incroyable ! Tu as du talent, $N. Soit ça, soit tu es le $gman:woman; le plus chanceux d\'être en vie ! $b$bVoici ta part de l\'action. Je suis sûr que tu utiliserais mieux ce truc que moi.$b$b') ON DUPLICATE KEY UPDATE RewardText='Incroyable ! Improbable ! Simplement incroyable ! Tu as du talent, $N. Soit ça, soit tu es le $gman:woman; le plus chanceux d\'être en vie ! $b$bVoici ta part de l\'action. Je suis sûr que tu utiliserais mieux ce truc que moi.$b$b';
-- Quest 2382 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2382, 'frFR', 'Un autre ? Les cinq derniers que ce troll fou m\'a envoyés sont finis en nourriture de requin. Espérons que tu t\'en sortiras un peu mieux, hein?$b$b') ON DUPLICATE KEY UPDATE RewardText='Un autre ? Les cinq derniers que ce troll fou m\'a envoyés sont finis en nourriture de requin. Espérons que tu t\'en sortiras un peu mieux, hein?$b$b';

-- Quest 2383 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2383, 'frFR', 'Qu\'est-ce que c\'est que tu as là ? Un parchemin ? Tu n\'es pas un érudit, j\'espère...') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que c\'est que tu as là ? Un parchemin ? Tu n\'es pas un érudit, j\'espère...';
-- Quest 2399 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2399, 'frFR', 'Les frondes que Denalan a plantées dans son jardin ont poussé et grandi. Elles tremblent, impatientes d\'être cueillies....') ON DUPLICATE KEY UPDATE RewardText='Les frondes que Denalan a plantées dans son jardin ont poussé et grandi. Elles tremblent, impatientes d\'être cueillies....';
-- Quest 2418 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2418, 'frFR', 'As-tu les pierres de puissance, $N ? J\'ai un rongeur robotique qui a besoin d\'une alimentation...') ON DUPLICATE KEY UPDATE CompletionText='As-tu les pierres de puissance, $N ? J\'ai un rongeur robotique qui a besoin d\'une alimentation...';
-- Quest 2418 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2418, 'frFR', 'C\'est super, tu en as trouvé ! Merci beaucoup, <name>. Tu es le $R$ le plus fiable que j\'aie rencontré !$B$BI ne peut pas attendre pour essayer ceux-ci sur des appareils avec lesquels je bricole. Je parie que, dans les bonnes circonstances, les appareils alimentés par ces pierres continueront, et continueront, et continueront...') ON DUPLICATE KEY UPDATE RewardText='C\'est super, tu en as trouvé ! Merci beaucoup, <name>. Tu es le $R$ le plus fiable que j\'aie rencontré !$B$BI ne peut pas attendre pour essayer ceux-ci sur des appareils avec lesquels je bricole. Je parie que, dans les bonnes circonstances, les appareils alimentés par ces pierres continueront, et continueront, et continueront...';
-- Quest 2440 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2440, 'frFR', 'Salutations, $C! Es-tu ici pour un entraînement en alchimie, ou peut-être autre chose ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $C! Es-tu ici pour un entraînement en alchimie, ou peut-être autre chose ?';
-- Quest 2440 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2440, 'frFR', 'Eh bien $N, tu dois avoir beaucoup plu à Sage Truthseeker pour qu\'il te donne cet objet. Tu dois également recevoir un cadeau de son cache de potions ; tu peux choisir entre 5 potions de soin supérieures ou 5 potions de mana supérieures comme récompense.') ON DUPLICATE KEY UPDATE RewardText='Eh bien $N, tu dois avoir beaucoup plu à Sage Truthseeker pour qu\'il te donne cet objet. Tu dois également recevoir un cadeau de son cache de potions ; tu peux choisir entre 5 potions de soin supérieures ou 5 potions de mana supérieures comme récompense.';
-- Quest 2458 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2458, 'frFR', 'C\'est bon de voir un autre agent de la Main Brisée dans ces parages, cependant, l\'étincelle a peut-être été un peu trop forte !$B$BLa prochaine fois que tu as besoin de me parler, souffle dans ce sifflet deux fois et je saurai que tu es un allié.') ON DUPLICATE KEY UPDATE RewardText='C\'est bon de voir un autre agent de la Main Brisée dans ces parages, cependant, l\'étincelle a peut-être été un peu trop forte !$B$BLa prochaine fois que tu as besoin de me parler, souffle dans ce sifflet deux fois et je saurai que tu es un allié.';
-- Quest 2460 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2460, 'frFR', 'Bien joué, $N. Tu es maintenant prêt à continuer.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N. Tu es maintenant prêt à continuer.';
-- Quest 2478 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2478, 'frFR', 'Pauvre Fizzule, il était un bon agent -- l\'un de nos meilleurs. Hélas, c\'est le prix que nous payons, $N. Être un agent de terrain de la Main Brisée est un travail dangereux.$B$BTu as rempli ton devoir bien, $c. Ce serait dommage si tu ne vivais pas pour nous servir à nouveau.') ON DUPLICATE KEY UPDATE RewardText='Pauvre Fizzule, il était un bon agent -- l\'un de nos meilleurs. Hélas, c\'est le prix que nous payons, $N. Être un agent de terrain de la Main Brisée est un travail dangereux.$B$BTu as rempli ton devoir bien, $c. Ce serait dommage si tu ne vivais pas pour nous servir à nouveau.';
-- Quest 2479 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2479, 'frFR', 'Tu as l\'air délicieusement pâle, $c. Et quelle est cette odeur nauséabonde que tu dégages ? Je dois savoir !') ON DUPLICATE KEY UPDATE RewardText='Tu as l\'air délicieusement pâle, $c. Et quelle est cette odeur nauséabonde que tu dégages ? Je dois savoir !';
-- Quest 2480 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2480, 'frFR', 'Le remède est prêt ! Bois cet anti-toxine et la folie rampante cessera, cependant, je ne pourrai rien faire contre l\'odeur.') ON DUPLICATE KEY UPDATE RewardText='Le remède est prêt ! Bois cet anti-toxine et la folie rampante cessera, cependant, je ne pourrai rien faire contre l\'odeur.';
-- Quest 2499 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2499, 'frFR', 'As-tu trouvé Oakenscowl, $R ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé Oakenscowl, $R ?';
-- Quest 2500 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2500, 'frFR', 'As-tu eu les choses dont j\'ai besoin ? Tu ne seras pas payé à moins de m\'apporter ces réactifs.') ON DUPLICATE KEY UPDATE CompletionText='As-tu eu les choses dont j\'ai besoin ? Tu ne seras pas payé à moins de m\'apporter ces réactifs.';
-- Quest 2500 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2500, 'frFR', 'Ah, bien joué <name>. Ces-ci devraient me suffire un petit moment au moins. Voici ton paiement, comme promis.$B$BSi tu es intéressé, j\'ai d\'autres réactifs que je pourrais utiliser. Ceux-ci, cependant, ne se trouvent qu\'en profondeur de l\'excavation d\'Uldaman. Ils ne seront pas faciles à obtenir, mais je m\'assurerai que ça en vaille la peine si tu es intéressé à m\'aider à nouveau.$B$BPeut-être quelque chose de plus qu\'une pile de pièces brillantes, oui ?') ON DUPLICATE KEY UPDATE RewardText='Ah, bien joué <name>. Ces-ci devraient me suffire un petit moment au moins. Voici ton paiement, comme promis.$B$BSi tu es intéressé, j\'ai d\'autres réactifs que je pourrais utiliser. Ceux-ci, cependant, ne se trouvent qu\'en profondeur de l\'excavation d\'Uldaman. Ils ne seront pas faciles à obtenir, mais je m\'assurerai que ça en vaille la peine si tu es intéressé à m\'aider à nouveau.$B$BPeut-être quelque chose de plus qu\'une pile de pièces brillantes, oui ?';
-- Quest 2501 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2501, 'frFR', 'As-tu utilisé les récipients pour m\'obtenir le sang de dragon gardien brûlé dont j\'ai besoin ? Oui, je sais que c\'est une tâche dangereuse... mais la recette de mon infusion réparatrice attend ton succès. Risque et récompense, mon ami... risque et récompense...') ON DUPLICATE KEY UPDATE CompletionText='As-tu utilisé les récipients pour m\'obtenir le sang de dragon gardien brûlé dont j\'ai besoin ? Oui, je sais que c\'est une tâche dangereuse... mais la recette de mon infusion réparatrice attend ton succès. Risque et récompense, mon ami... risque et récompense...';

-- Quest 2501 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2501, 'frFR', 'De l\'un alchimiste à un autre, je vous salue.  Prenez ici cette recette et intégrez-la à vos connaissances.  Qu\'elle vous apporte le succès et les récompenses qu\'elle m\'a apportés au fil des années !') ON DUPLICATE KEY UPDATE RewardText='De l\'un alchimiste à un autre, je vous salue.  Prenez ici cette recette et intégrez-la à vos connaissances.  Qu\'elle vous apporte le succès et les récompenses qu\'elle m\'a apportés au fil des années !';
-- Quest 2520 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2520, 'frFR', 'Avez-vous placé le sacrifice à la fontaine, $n?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous placé le sacrifice à la fontaine, $n?';
-- Quest 2521 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2521, 'frFR', 'J\'ai consacré ma vie à la recherche de sphères de draenéthyste parfaites. Une vie entière, $r!') ON DUPLICATE KEY UPDATE CompletionText='J\'ai consacré ma vie à la recherche de sphères de draenéthyste parfaites. Une vie entière, $r!';
-- Quest 2521 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2521, 'frFR', 'Est-ce que mes yeux me jouent des tours ? Impossible ! Où avez-vous... Comment...$B$BPeut-être qu\'une fêlure peut être ouverte, nous ramenant à notre patrie.') ON DUPLICATE KEY UPDATE RewardText='Est-ce que mes yeux me jouent des tours ? Impossible ! Où avez-vous... Comment...$B$BPeut-être qu\'une fêlure peut être ouverte, nous ramenant à notre patrie.';
-- Quest 2522 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2522, 'frFR', 'Avez-vous trouvé une autre sphère de draenéthyste parfaite ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé une autre sphère de draenéthyste parfaite ?';
-- Quest 2522 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2522, 'frFR', 'Simplement incroyable. J\'avais douté que vous puissiez trouver une autre sphère, et pourtant, la voici, pulsant dans mes mains.$B$BBien joué, $N!$B$BSi vous en trouvez d\'autres -- et je crois cela impossible -- ramenez-les-moi et je vous récompenserai à nouveau.') ON DUPLICATE KEY UPDATE RewardText='Simplement incroyable. J\'avais douté que vous puissiez trouver une autre sphère, et pourtant, la voici, pulsant dans mes mains.$B$BBien joué, $N!$B$BSi vous en trouvez d\'autres -- et je crois cela impossible -- ramenez-les-moi et je vous récompenserai à nouveau.';
-- Quest 2523 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2523, 'frFR', 'Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur-chant. Une odeur âcre et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour être ramenée à la normale.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur-chant. Une odeur âcre et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour être ramenée à la normale.';
-- Quest 2523 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2523, 'frFR', 'Vous appliquez un baume de plante de Cenarion sur la fleur-chant. Elle commence immédiatement à perdre sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez un baume de plante de Cenarion sur la fleur-chant. Elle commence immédiatement à perdre sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
-- Quest 2561 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2561, 'frFR', '$N, soyez prudent en approchant de ma forme physique ; l\'enchantement dont elle est soumise est assez puissant.') ON DUPLICATE KEY UPDATE CompletionText='$N, soyez prudent en approchant de ma forme physique ; l\'enchantement dont elle est soumise est assez puissant.';
-- Quest 2583 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2583, 'frFR', 'L\'esprit du sanglier illumine votre être, <name>! Je me demande, croyez-vous être aussi invulnérable que ces bêtes ?') ON DUPLICATE KEY UPDATE RewardText='L\'esprit du sanglier illumine votre être, <name>! Je me demande, croyez-vous être aussi invulnérable que ces bêtes ?';
-- Quest 2584 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2584, 'frFR', 'Je dois vous prévenir, $N, n\'essayez pas de mélanger les formules que j\'ai créées. Les propriétés chimiques de la formule que vous avez ingérée le plus récemment prendront toujours le dessus sur les enchantements antérieurs ; rendant ainsi l\'autre formulation nulle.') ON DUPLICATE KEY UPDATE RewardText='Je dois vous prévenir, $N, n\'essayez pas de mélanger les formules que j\'ai créées. Les propriétés chimiques de la formule que vous avez ingérée le plus récemment prendront toujours le dessus sur les enchantements antérieurs ; rendant ainsi l\'autre formulation nulle.';
-- Quest 2586 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2586, 'frFR', 'Beau travail, $N. Voici un échantillon de l\'essai pour vous et les neuf autres seront utilisés dans mes recherches.$b$bDès que vous aurez besoin de plus d\'essai de scorpok broyé, revenez-moi et nous trouverons un accord.') ON DUPLICATE KEY UPDATE RewardText='Beau travail, $N. Voici un échantillon de l\'essai pour vous et les neuf autres seront utilisés dans mes recherches.$b$bDès que vous aurez besoin de plus d\'essai de scorpok broyé, revenez-moi et nous trouverons un accord.';
-- Quest 2601 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2601, 'frFR', 'Avez-vous ramené les organes demandés ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous ramené les organes demandés ?';
-- Quest 2601 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2601, 'frFR', 'C\'est merveilleux, <name>! Mon offrande à vous est un goût du fonctionnement interne du basilic rouge.$B$BSi le composé vous plaît, davantage peut toujours être fabriqué... moyennant un prix.') ON DUPLICATE KEY UPDATE RewardText='C\'est merveilleux, <name>! Mon offrande à vous est un goût du fonctionnement interne du basilic rouge.$B$BSi le composé vous plaît, davantage peut toujours être fabriqué... moyennant un prix.';
-- Quest 2602 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2602, 'frFR', 'Avez-vous ramené les organes demandés ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous ramené les organes demandés ?';

-- Quest 2602 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2602, 'frFR', 'Oui, oui, donnez-moi un instant et plus de la préparation sera prête pour votre consommation, $Gname>.$B<br :>Prenez-le... et <name, n\'essayez pas de consommer ces concoctions expérimentales en succession rapide. Les résultats pourraient être désastreux.') ON DUPLICATE KEY UPDATE RewardText='Oui, oui, donnez-moi un instant et plus de la préparation sera prête pour votre consommation, $Gname>.$B<br :>Prenez-le... et <name, n\'essayez pas de consommer ces concoctions expérimentales en succession rapide. Les résultats pourraient être désastreux.';
-- Quest 2603 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2603, 'frFR', 'Ne perdez pas mon temps, $N. Nous n\'avons rien à discuter, à moins que vous n\'ayez récupéré les objets que j\'ai demandés.') ON DUPLICATE KEY UPDATE CompletionText='Ne perdez pas mon temps, $N. Nous n\'avons rien à discuter, à moins que vous n\'ayez récupéré les objets que j\'ai demandés.';
-- Quest 2604 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2604, 'frFR', 'Ne perdez pas mon temps, $N. Nous n\'avons rien à discuter, à moins que vous n\'ayez récupéré les objets que j\'ai demandés.') ON DUPLICATE KEY UPDATE CompletionText='Ne perdez pas mon temps, $N. Nous n\'avons rien à discuter, à moins que vous n\'ayez récupéré les objets que j\'ai demandés.';
-- Quest 2604 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2604, 'frFR', 'Peut-être qu\'un jour je pourrai isoler les enzymes actives de ce test et produire un résultat beaucoup plus efficace. Malheureusement, vous devrez vous contenter de ce que je suis actuellement capable de produire. Revenez-moi si vous avez besoin de plus de gomme de gésier.') ON DUPLICATE KEY UPDATE RewardText='Peut-être qu\'un jour je pourrai isoler les enzymes actives de ce test et produire un résultat beaucoup plus efficace. Malheureusement, vous devrez vous contenter de ce que je suis actuellement capable de produire. Revenez-moi si vous avez besoin de plus de gomme de gésier.';
-- Quest 2607 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2607, 'frFR', 'Il est temps ! Mettez juste le fromage sur la table et fuyez. Osborne vous paiera en partant.') ON DUPLICATE KEY UPDATE RewardText='Il est temps ! Mettez juste le fromage sur la table et fuyez. Osborne vous paiera en partant.';
-- Quest 2608 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2608, 'frFR', 'Quand vous serez prêt pour l\'examen, /allongez-vous par terre et je commencerai la phlébotomie.') ON DUPLICATE KEY UPDATE CompletionText='Quand vous serez prêt pour l\'examen, /allongez-vous par terre et je commencerai la phlébotomie.';
-- Quest 2608 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2608, 'frFR', 'Donnez-moi un instant pour consulter mes collègues, $N. Dr. Montgomery, Mr. Noarm, consultons !') ON DUPLICATE KEY UPDATE RewardText='Donnez-moi un instant pour consulter mes collègues, $N. Dr. Montgomery, Mr. Noarm, consultons !';
-- Quest 2609 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2609, 'frFR', 'Si vous voulez que l\'\'itis\' soit guérie, vous allez devoir faire plus d\'efforts que ça, $n. Où sont les réactifs pour le remède ?') ON DUPLICATE KEY UPDATE CompletionText='Si vous voulez que l\'\'itis\' soit guérie, vous allez devoir faire plus d\'efforts que ça, $n. Où sont les réactifs pour le remède ?';
-- Quest 2609 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2609, 'frFR', 'Qu\'est-ce que je fais ? Qu\'est-ce que ça ressemble que je fasse ? Je suis en train de concevoir un remède pour votre \'\'itis\' ! Ne soyez pas indigné avec moi maintenant, $N!$b$bJuste quelques secondes de plus. Voilà ! Vaporisez ce, euh, médicament fantastiquement odorant sur vous et vous serez comme neuf.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que je fais ? Qu\'est-ce que ça ressemble que je fasse ? Je suis en train de concevoir un remède pour votre \'\'itis\' ! Ne soyez pas indigné avec moi maintenant, $N!$b$bJuste quelques secondes de plus. Voilà ! Vaporisez ce, euh, médicament fantastiquement odorant sur vous et vous serez comme neuf.';
-- Quest 2623 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2623, 'frFR', 'C\'est pire que ce que j\'imaginais. Dix-neuf de mes hommes auraient pu être épargnés de la douleur qu\'ils ont endurée. Si seulement je n\'avais pas agi de manière aussi irrationnelle.$B$BVous devez les aider, <name>! Je suis impuissant à agir.') ON DUPLICATE KEY UPDATE RewardText='C\'est pire que ce que j\'imaginais. Dix-neuf de mes hommes auraient pu être épargnés de la douleur qu\'ils ont endurée. Si seulement je n\'avais pas agi de manière aussi irrationnelle.$B$BVous devez les aider, <name>! Je suis impuissant à agir.';
-- Quest 2681 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2681, 'frFR', 'Vous avez réussi, $Gname>! Les pauvres âmes tourmentées peuvent enfin se reposer.$B<br :>Notre travail n\'est pas terminé, <name. Nous avons beaucoup à discuter et beaucoup plus à accomplir.') ON DUPLICATE KEY UPDATE RewardText='Vous avez réussi, $Gname>! Les pauvres âmes tourmentées peuvent enfin se reposer.$B<br :>Notre travail n\'est pas terminé, <name. Nous avons beaucoup à discuter et beaucoup plus à accomplir.';
-- Quest 2741 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2741, 'frFR', 'Le Super Œuf-O-Matic est la dernière invention de Curgle Cranklehop. C\'est une pièce d\'ingénierie assez impressionnante.$B$BLe Super Œuf-O-Matic crache sauvagement tandis que vous vous approchez du panneau de contrôle.') ON DUPLICATE KEY UPDATE CompletionText='Le Super Œuf-O-Matic est la dernière invention de Curgle Cranklehop. C\'est une pièce d\'ingénierie assez impressionnante.$B$BLe Super Œuf-O-Matic crache sauvagement tandis que vous vous approchez du panneau de contrôle.';
-- Quest 2741 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2741, 'frFR', 'Vous placez l\'œuf de hippogriffe dans la machine. Une série de bips suit avec quelques sons mécaniques étranges.$B$BIl semble que l\'Œufomètre ait pesé, mesuré et emballé votre œuf. Quelle rapidité !') ON DUPLICATE KEY UPDATE RewardText='Vous placez l\'œuf de hippogriffe dans la machine. Une série de bips suit avec quelques sons mécaniques étranges.$B$BIl semble que l\'Œufomètre ait pesé, mesuré et emballé votre œuf. Quelle rapidité !';
-- Quest 2747 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2747, 'frFR', 'J\'ai vu très peu d\'œufs récupérés de Feralas en condition extraordinaire. Ce sont des œufs de la plus rare espèce...') ON DUPLICATE KEY UPDATE CompletionText='J\'ai vu très peu d\'œufs récupérés de Feralas en condition extraordinaire. Ce sont des œufs de la plus rare espèce...';
-- Quest 2747 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2747, 'frFR', 'Eh bien, vous en avez un--incroyable !$B$BI espère que vous vous souviendrez toujours du bien que vous avez fait aujourd\'hui.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, vous en avez un--incroyable !$B$BI espère que vous vous souviendrez toujours du bien que vous avez fait aujourd\'hui.';

-- Quest 2748 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2748, 'frFR', 'Un bon œuf est un œuf qui, dans des conditions idéales, éclora sans les effets maléfiques des incantations des ogres de Gordun.') ON DUPLICATE KEY UPDATE CompletionText='Un bon œuf est un œuf qui, dans des conditions idéales, éclora sans les effets maléfiques des incantations des ogres de Gordun.';
-- Quest 2748 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2748, 'frFR', 'Très bien, <name>. Je vais envoyer cet œuf à Darnassus où j\'espère qu\'il éclor bientôt ! $B$BVeuillez accepter ceci comme un symbole de ma gratitude.') ON DUPLICATE KEY UPDATE RewardText='Très bien, <name>. Je vais envoyer cet œuf à Darnassus où j\'espère qu\'il éclor bientôt ! $B$BVeuillez accepter ceci comme un symbole de ma gratitude.';
-- Quest 2749 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2749, 'frFR', 'Les œufs d\'hippogryphe ordinaires éclosent environ la moitié du temps. Nous faisons de notre mieux pour les nourrir et avec un peu de chance, ils écloront.') ON DUPLICATE KEY UPDATE CompletionText='Les œufs d\'hippogryphe ordinaires éclosent environ la moitié du temps. Nous faisons de notre mieux pour les nourrir et avec un peu de chance, ils écloront.';
-- Quest 2749 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2749, 'frFR', 'Alors, vous avez trouvé un œuf ordinaire, <name> ? Veuillez me le donner... Et nous ne pouvons qu\'espérer le meilleur.$B$BI n\'ai pas beaucoup, mais veuillez accepter cette récompense. Si jamais vous vous retrouvez dans Feralas, sachez que je suis toujours là pour prendre les œufs que vous y trouvez.') ON DUPLICATE KEY UPDATE RewardText='Alors, vous avez trouvé un œuf ordinaire, <name> ? Veuillez me le donner... Et nous ne pouvons qu\'espérer le meilleur.$B$BI n\'ai pas beaucoup, mais veuillez accepter cette récompense. Si jamais vous vous retrouvez dans Feralas, sachez que je suis toujours là pour prendre les œufs que vous y trouvez.';
-- Quest 2750 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2750, 'frFR', 'Ce sont les œufs qui ne peuvent pas être sauvés -- ils ne s\'écloront jamais.') ON DUPLICATE KEY UPDATE CompletionText='Ce sont les œufs qui ne peuvent pas être sauvés -- ils ne s\'écloront jamais.';
-- Quest 2750 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2750, 'frFR', 'J\'ai peur d\'avoir de mauvaises nouvelles pour vous, <name>. Cet œuf est trop avancé. Je peux le prendre de vous afin qu\'il puisse être éliminé correctement.$B$BNe soyez pas découragé ; nous ne pouvons pas les sauver tous. Si vous vous retrouvez dans Feralas, veuillez réessayer. Apportez un autre œuf à la Super Œuf-O-Matic !') ON DUPLICATE KEY UPDATE RewardText='J\'ai peur d\'avoir de mauvaises nouvelles pour vous, <name>. Cet œuf est trop avancé. Je peux le prendre de vous afin qu\'il puisse être éliminé correctement.$B$BNe soyez pas découragé ; nous ne pouvons pas les sauver tous. Si vous vous retrouvez dans Feralas, veuillez réessayer. Apportez un autre œuf à la Super Œuf-O-Matic !';
-- Quest 2751 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2751, 'frFR', 'La lignée s\'estompera, mais peut-être que la légende d\'Omosh continuera !$B$BVous avez prouvé que vous êtes un forgeron, <name>. Pour le forgeron, la récompense est la satisfaction de voir ses armes et armures recouvertes du sang de ses ennemis !$B$BQue les plastrons que vous créez pour les générations futures soient baignés dans le sang de vos ennemis !') ON DUPLICATE KEY UPDATE RewardText='La lignée s\'estompera, mais peut-être que la légende d\'Omosh continuera !$B$BVous avez prouvé que vous êtes un forgeron, <name>. Pour le forgeron, la récompense est la satisfaction de voir ses armes et armures recouvertes du sang de ses ennemis !$B$BQue les plastrons que vous créez pour les générations futures soient baignés dans le sang de vos ennemis !';
-- Quest 2754 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2754, 'frFR', 'Montre à qui le fer est maître, $N!') ON DUPLICATE KEY UPDATE CompletionText='Montre à qui le fer est maître, $N!';
-- Quest 2754 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2754, 'frFR', 'Étonnant ! Vous avez appris la voie d\'Omosh, <name> !') ON DUPLICATE KEY UPDATE RewardText='Étonnant ! Vous avez appris la voie d\'Omosh, <name> !';
-- Quest 2755 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2755, 'frFR', '$GOrokk pants.>$B<br :>Il y a eu très longtemps qu\'Orokk dansait la danse de joie d\'Omosh. Apprenez maintenant, <name!') ON DUPLICATE KEY UPDATE RewardText='$GOrokk pants.>$B<br :>Il y a eu très longtemps qu\'Orokk dansait la danse de joie d\'Omosh. Apprenez maintenant, <name!';
-- Quest 2756 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2756, 'frFR', 'Aturk, comme le temps, n\'attend personne ! Dépêche-toi, imbécile !') ON DUPLICATE KEY UPDATE CompletionText='Aturk, comme le temps, n\'attend personne ! Dépêche-toi, imbécile !';
-- Quest 2756 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2756, 'frFR', 'Il semble que vous soyez un autre lemming complaisant du Warchief, <name>. Quelle déception.$B$BComme j\'aspire à une glorieuse mort sur le champ de bataille. Au lieu de cela, je suis coincé ici, sur ordre de Thrall, pour enseigner aux nourrissons comment fabriquer ! Regardez et apprenez, enfant !') ON DUPLICATE KEY UPDATE RewardText='Il semble que vous soyez un autre lemming complaisant du Warchief, <name>. Quelle déception.$B$BComme j\'aspire à une glorieuse mort sur le champ de bataille. Au lieu de cela, je suis coincé ici, sur ordre de Thrall, pour enseigner aux nourrissons comment fabriquer ! Regardez et apprenez, enfant !';
-- Quest 2757 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2757, 'frFR', 'Une race rare votre espèce, mon ami. Laissez-moi voir cet insigne.') ON DUPLICATE KEY UPDATE CompletionText='Une race rare votre espèce, mon ami. Laissez-moi voir cet insigne.';
-- Quest 2757 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2757, 'frFR', 'Par les poils du dos de Blackhoof -- enfin, quelqu\'un digne de l\'Ordre de Mithril !$b$b') ON DUPLICATE KEY UPDATE RewardText='Par les poils du dos de Blackhoof -- enfin, quelqu\'un digne de l\'Ordre de Mithril !$b$b';
-- Quest 2758 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2758, 'frFR', 'Pourriez-vous être le prochain protégé de Galvan ?') ON DUPLICATE KEY UPDATE CompletionText='Pourriez-vous être le prochain protégé de Galvan ?';

-- Quest 2758 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2758, 'frFR', 'Très bien, $N! Écoute et apprends.$B$La forge ne vient pas d\'ici ! <Hank pointe son marteau.>$B$La forge ne vient pas d\'ici ! <Hank pointe l\'enclume.>$B$La forge vient d\'ici ! <Hank pointe son cœur.>$B$Et maintenant, tu connais l\'origine de la forge.') ON DUPLICATE KEY UPDATE RewardText='Très bien, $N! Écoute et apprends.$B$La forge ne vient pas d\'ici ! <Hank pointe son marteau.>$B$La forge ne vient pas d\'ici ! <Hank pointe l\'enclume.>$B$La forge vient d\'ici ! <Hank pointe son cœur.>$B$Et maintenant, tu connais l\'origine de la forge.';
-- Quest 2759 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2759, 'frFR', 'Une race rare vous êtes, mon ami. Laissez-moi voir cet insigne.') ON DUPLICATE KEY UPDATE CompletionText='Une race rare vous êtes, mon ami. Laissez-moi voir cet insigne.';
-- Quest 2759 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2759, 'frFR', 'Par les poils de dos de Blackhoof -- enfin, quelqu\'un digne de l\'Ordre de Mithril !') ON DUPLICATE KEY UPDATE RewardText='Par les poils de dos de Blackhoof -- enfin, quelqu\'un digne de l\'Ordre de Mithril !';
-- Quest 2761 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2761, 'frFR', 'Après un tel minage, vos muscles se gonflent et votre corps vous fait mal !') ON DUPLICATE KEY UPDATE CompletionText='Après un tel minage, vos muscles se gonflent et votre corps vous fait mal !';
-- Quest 2761 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2761, 'frFR', 'Votre éthique de travail est impeccable, $N! Tu commences à comprendre les voies de la minéralogie de Galvan ! Prends ceci et apprends-en tout ce que tu peux.') ON DUPLICATE KEY UPDATE RewardText='Votre éthique de travail est impeccable, $N! Tu commences à comprendre les voies de la minéralogie de Galvan ! Prends ceci et apprends-en tout ce que tu peux.';
-- Quest 2762 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2762, 'frFR', 'Après un tel minage, vos muscles se gonflent et votre corps vous fait mal !') ON DUPLICATE KEY UPDATE CompletionText='Après un tel minage, vos muscles se gonflent et votre corps vous fait mal !';
-- Quest 2762 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2762, 'frFR', 'C\'est une maîtresse cruelle, n\'est-ce pas, $N? Je parle du truesilver, naturellement. Oui, Galvan a passé plus d\'une décennie dans les montagnes d\'Alterac à apprendre cette leçon. Prends ceci et apprends-en tout ce que tu peux !') ON DUPLICATE KEY UPDATE RewardText='C\'est une maîtresse cruelle, n\'est-ce pas, $N? Je parle du truesilver, naturellement. Oui, Galvan a passé plus d\'une décennie dans les montagnes d\'Alterac à apprendre cette leçon. Prends ceci et apprends-en tout ce que tu peux !';
-- Quest 2763 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2763, 'frFR', 'Après un tel minage, vos muscles se gonflent et votre corps vous fait mal !') ON DUPLICATE KEY UPDATE CompletionText='Après un tel minage, vos muscles se gonflent et votre corps vous fait mal !';
-- Quest 2767 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2767, 'frFR', 'Oui, je suis Oglethorpe Obnoticus, maître inventeur à votre service ! Maintenant, y a-t-il quelque chose avec quoi je pourrais vous aider ?') ON DUPLICATE KEY UPDATE CompletionText='Oui, je suis Oglethorpe Obnoticus, maître inventeur à votre service ! Maintenant, y a-t-il quelque chose avec quoi je pourrais vous aider ?';
-- Quest 2768 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2768, 'frFR', 'As-tu trouvé le sergent Bly ? As-tu récupéré ma tige divino-matic ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé le sergent Bly ? As-tu récupéré ma tige divino-matic ?';
-- Quest 2768 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2768, 'frFR', 'Tu l\'as trouvé !  Bien joué, <name>!  As-tu dû te battre contre Bly pour l\'obtenir ?  J\'espère que tu l\'as et sa bande mis hors d\'état de nuire !') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as trouvé !  Bien joué, <name>!  As-tu dû te battre contre Bly pour l\'obtenir ?  J\'espère que tu l\'as et sa bande mis hors d\'état de nuire !';
-- Quest 2771 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2771, 'frFR', 'As-tu terminé la fabrication des objets, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé la fabrication des objets, $N?';
-- Quest 2771 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2771, 'frFR', 'Excellent ! Un échange équitable, si je puis me permettre. Regarde et apprends, $N!') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Un échange équitable, si je puis me permettre. Regarde et apprends, $N!';
-- Quest 2772 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2772, 'frFR', 'As-tu terminé la fabrication des objets, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé la fabrication des objets, $N?';
-- Quest 2772 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2772, 'frFR', 'Le monde sera à tes pieds, $N! Qu\'ils viennent tous à tes pieds, car tu es maintenant insoupçonnable !') ON DUPLICATE KEY UPDATE RewardText='Le monde sera à tes pieds, $N! Qu\'ils viennent tous à tes pieds, car tu es maintenant insoupçonnable !';

-- Quest 2773 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2773, 'frFR', 'As-tu terminé la confection des objets, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé la confection des objets, $N?';
-- Quest 2782 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2782, 'frFR', 'Cette tablette... Très inhabituelle... Où l\'as-tu trouvée, <name>?') ON DUPLICATE KEY UPDATE RewardText='Cette tablette... Très inhabituelle... Où l\'as-tu trouvée, <name>?';
-- Quest 2801 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2801, 'frFR', 'Écoute ce que j\'ai à te dire, $N.') ON DUPLICATE KEY UPDATE CompletionText='Écoute ce que j\'ai à te dire, $N.';
-- Quest 2841 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2841, 'frFR', 'Je ne vois aucun plan. Tu les as cachés quelque part sur ton corps ou tu es juste là pour m\'énerver?$b$b') ON DUPLICATE KEY UPDATE CompletionText='Je ne vois aucun plan. Tu les as cachés quelque part sur ton corps ou tu es juste là pour m\'énerver?$b$b';
-- Quest 2841 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2841, 'frFR', 'Je savais que tu pouvais le faire, <name>! Sovik, en revanche, avait ses doutes.$B$B$B$BMaintenant que nous avons les plans en notre possession, il n\'y a plus qu\'une question de temps avant que nous ne découvrions toutes les innovations gnomiques qui ont servi à la création du dispositif et que nous les transformerons en innovations gobelines pour nos nouveaux modèles de déchiqueteuse.') ON DUPLICATE KEY UPDATE RewardText='Je savais que tu pouvais le faire, <name>! Sovik, en revanche, avait ses doutes.$B$B$B$BMaintenant que nous avons les plans en notre possession, il n\'y a plus qu\'une question de temps avant que nous ne découvrions toutes les innovations gnomiques qui ont servi à la création du dispositif et que nous les transformerons en innovations gobelines pour nos nouveaux modèles de déchiqueteuse.';
-- Quest 2846 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2846, 'frFR', 'As-tu la tiara, $N? Velratha a-t-elle appris le prix de m\'avoir affronté?') ON DUPLICATE KEY UPDATE CompletionText='As-tu la tiara, $N? Velratha a-t-elle appris le prix de m\'avoir affronté?';
-- Quest 2847 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2847, 'frFR', 'Comme je l\'ai dit, tu vas travailler pour moi pendant que tu apprends sur l\'armure de cuir sauvage. Parce que les lianes sauvages sont à la fois puissantes et chaotiques, elles donnent un bénéfice aléatoire mais fort à l\'armure déjà solide que tu vas fabriquer. Cependant, ce savoir ne m\'a pas été facile à obtenir.$B$BLe coût initial pour commencer ce processus est de dix pièces de cuir épais.$B$BUne fois cela fait, nous nous attacherons au travail que tu dois faire pour obtenir les patrons.') ON DUPLICATE KEY UPDATE CompletionText='Comme je l\'ai dit, tu vas travailler pour moi pendant que tu apprends sur l\'armure de cuir sauvage. Parce que les lianes sauvages sont à la fois puissantes et chaotiques, elles donnent un bénéfice aléatoire mais fort à l\'armure déjà solide que tu vas fabriquer. Cependant, ce savoir ne m\'a pas été facile à obtenir.$B$BLe coût initial pour commencer ce processus est de dix pièces de cuir épais.$B$BUne fois cela fait, nous nous attacherons au travail que tu dois faire pour obtenir les patrons.';
-- Quest 2847 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2847, 'frFR', 'Eh bien $N, je suis content de t\'avoir à bord. Tu as pris une décision intelligente en tant que travailleur du cuir ; ceux qui portent des armures en cuir seront avides de toi une fois que tu sauras fabriquer n\'importe quelle pièce de l\'armure de cuir sauvage.$B$BCommençons le travail - par où veux-tu commencer?') ON DUPLICATE KEY UPDATE RewardText='Eh bien $N, je suis content de t\'avoir à bord. Tu as pris une décision intelligente en tant que travailleur du cuir ; ceux qui portent des armures en cuir seront avides de toi une fois que tu sauras fabriquer n\'importe quelle pièce de l\'armure de cuir sauvage.$B$BCommençons le travail - par où veux-tu commencer?';
-- Quest 2848 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2848, 'frFR', 'As-tu les six kits d\'armure épaisse et la liane sauvage dont j\'ai besoin?$B$BNe considère pas la fabrication de kits d\'armure comme un travail monotone ; la méthode de confection régulière que tu développes en exerçant ton métier sur ces kits aide à développer tes compétences pour le travail complexe nécessaire à la fabrication de l\'armure de cuir sauvage.$B$BRegarde - il y a une vraie raison derrière ce que tu fabriques pour moi...') ON DUPLICATE KEY UPDATE CompletionText='As-tu les six kits d\'armure épaisse et la liane sauvage dont j\'ai besoin?$B$BNe considère pas la fabrication de kits d\'armure comme un travail monotone ; la méthode de confection régulière que tu développes en exerçant ton métier sur ces kits aide à développer tes compétences pour le travail complexe nécessaire à la fabrication de l\'armure de cuir sauvage.$B$BRegarde - il y a une vraie raison derrière ce que tu fabriques pour moi...';
-- Quest 2848 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2848, 'frFR', 'Ces kits d\'armure sont de qualité solide, $N. S\'il y a une chose que j\'exige non seulement dans mon travail, mais dans le travail de ceux qui sont à mon service, c\'est la qualité.$B$BTu as bien fait d\'obtenir ce patron ; j\'espère qu\'il t\'apportera les récompenses qu\'il m\'a apportées.') ON DUPLICATE KEY UPDATE RewardText='Ces kits d\'armure sont de qualité solide, $N. S\'il y a une chose que j\'exige non seulement dans mon travail, mais dans le travail de ceux qui sont à mon service, c\'est la qualité.$B$BTu as bien fait d\'obtenir ce patron ; j\'espère qu\'il t\'apportera les récompenses qu\'il m\'a apportées.';
-- Quest 2849 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2849, 'frFR', 'As-tu les deux plastrons et gants d\'écailles de tortue que j\'ai commandés? Aussi, n\'oublie pas la liane sauvage!$B$BMême avec les premiers patrons, nous apprenons que les fondamentaux de la forme se traduisent bien dans des vêtements plus difficiles. Bien que différents, la forme des plastrons d\'écailles de tortue te prépare au détail nécessaire pour fabriquer un gilet en cuir sauvage.$B$BEt les gants... eh bien, ils sont juste pour mon bénéfice. Souviens-toi, tu travailles pour moi!') ON DUPLICATE KEY UPDATE CompletionText='As-tu les deux plastrons et gants d\'écailles de tortue que j\'ai commandés? Aussi, n\'oublie pas la liane sauvage!$B$BMême avec les premiers patrons, nous apprenons que les fondamentaux de la forme se traduisent bien dans des vêtements plus difficiles. Bien que différents, la forme des plastrons d\'écailles de tortue te prépare au détail nécessaire pour fabriquer un gilet en cuir sauvage.$B$BEt les gants... eh bien, ils sont juste pour mon bénéfice. Souviens-toi, tu travailles pour moi!';
-- Quest 2849 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2849, 'frFR', 'Ce sont de très belles pièces ici, $N. Le savoir-faire et le soin mis dans la fabrication de celles-ci seuls valent plusieurs pièces d\'argent de plus que la pièce moyenne fabriquée.$B$BTu as rempli ma commande, et avec cela vient ta récompense. La connaissance de la fabrication de gilets en cuir sauvage est maintenant la tienne!') ON DUPLICATE KEY UPDATE RewardText='Ce sont de très belles pièces ici, $N. Le savoir-faire et le soin mis dans la fabrication de celles-ci seuls valent plusieurs pièces d\'argent de plus que la pièce moyenne fabriquée.$B$BTu as rempli ma commande, et avec cela vient ta récompense. La connaissance de la fabrication de gilets en cuir sauvage est maintenant la tienne!';
-- Quest 2850 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2850, 'frFR', 'J\'ai besoin que ces tuniques et bandeaux soient fabriqués, et j\'ai aussi besoin de cette pièce de liane sauvage avant de te partager la connaissance des casques en cuir sauvage.$B$BLes équipements de tête sont très convoités par les aventuriers, qu\'il s\'agisse d\'un bandeau d\'une simplicité désarmante ou d\'un casque qui couvre entièrement. Les fondamentaux de la création d\'équipements de tête de valeur restent constants, quel que soit l\'apparence cosmétique de l\'équipement.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai besoin que ces tuniques et bandeaux soient fabriqués, et j\'ai aussi besoin de cette pièce de liane sauvage avant de te partager la connaissance des casques en cuir sauvage.$B$BLes équipements de tête sont très convoités par les aventuriers, qu\'il s\'agisse d\'un bandeau d\'une simplicité désarmante ou d\'un casque qui couvre entièrement. Les fondamentaux de la création d\'équipements de tête de valeur restent constants, quel que soit l\'apparence cosmétique de l\'équipement.';
-- Quest 2850 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2850, 'frFR', 'Cet équipement de Nightscape que tu as fourni remplit parfaitement la commande, $N. Je n\'attends rien de moins d\'un travailleur du cuir de ton calibre.$B$BTu as certainement mérité ce patron. Je te le donne librement, et j\'espère que tu en tireras profit en conséquence.') ON DUPLICATE KEY UPDATE RewardText='Cet équipement de Nightscape que tu as fourni remplit parfaitement la commande, $N. Je n\'attends rien de moins d\'un travailleur du cuir de ton calibre.$B$BTu as certainement mérité ce patron. Je te le donne librement, et j\'espère que tu en tireras profit en conséquence.';
-- Quest 2851 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2851, 'frFR', 'La commande sur les pantalons, les bottes et les lianes sauvages doit être remplie avant que tu obtiennes le patron, $N. Tu as fini?$B$BÀ partir de la première paire de bottes que nous apprenons à fabriquer, nous commençons à comprendre qu\'une botte de qualité doit trouver un équilibre entre le confort et la fonction. Avec les deux, nous sommes capables de créer des objets qui permettent au porteur d\'ignorer la fatigue qui paralyserait ceux qui portent des biens de qualité inférieure.') ON DUPLICATE KEY UPDATE CompletionText='La commande sur les pantalons, les bottes et les lianes sauvages doit être remplie avant que tu obtiennes le patron, $N. Tu as fini?$B$BÀ partir de la première paire de bottes que nous apprenons à fabriquer, nous commençons à comprendre qu\'une botte de qualité doit trouver un équilibre entre le confort et la fonction. Avec les deux, nous sommes capables de créer des objets qui permettent au porteur d\'ignorer la fatigue qui paralyserait ceux qui portent des biens de qualité inférieure.';

-- Quest 2851 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2851, 'frFR', 'Encore une fois, vous avez rempli une commande complexe avec le savoir-faire d\'un professionnel aguerri. Vous avez gagné ce modèle, ainsi que mes remerciements.') ON DUPLICATE KEY UPDATE RewardText='Encore une fois, vous avez rempli une commande complexe avec le savoir-faire d\'un professionnel aguerri. Vous avez gagné ce modèle, ainsi que mes remerciements.';
-- Quest 2852 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2852, 'frFR', 'Avez-vous les brassards et les casques en Écaille de Tortue prêts ? N\'oubliez pas les deux lianes sauvages dont j\'ai besoin !$B$BMaintenant, vous commencez à réaliser le potentiel de puissance qui réside dans les armures en Cuir Sauvage. Une armure qui n\'a pas de limites d\'application est presque inestimable pour un travailleur du cuir. Les limites ne sont que dans les quantités de ressources pour fabriquer les objets - pas dans la qualité des produits finis !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les brassards et les casques en Écaille de Tortue prêts ? N\'oubliez pas les deux lianes sauvages dont j\'ai besoin !$B$BMaintenant, vous commencez à réaliser le potentiel de puissance qui réside dans les armures en Cuir Sauvage. Une armure qui n\'a pas de limites d\'application est presque inestimable pour un travailleur du cuir. Les limites ne sont que dans les quantités de ressources pour fabriquer les objets - pas dans la qualité des produits finis !';
-- Quest 2852 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2852, 'frFR', 'Encore une fois, vous avez rempli une commande sans faute. Peut-être qu\'un jour je viendrai CHEZ VOUS chercher des connaissances, hein $N?$B$BVoici le modèle pour les leggings, ainsi que mes remerciements. Imprégnez cette connaissance dans votre esprit, et laissez vos produits finis exploiter votre impressionnante habileté !') ON DUPLICATE KEY UPDATE RewardText='Encore une fois, vous avez rempli une commande sans faute. Peut-être qu\'un jour je viendrai CHEZ VOUS chercher des connaissances, hein $N?$B$BVoici le modèle pour les leggings, ainsi que mes remerciements. Imprégnez cette connaissance dans votre esprit, et laissez vos produits finis exploiter votre impressionnante habileté !';
-- Quest 2853 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2853, 'frFR', 'Salutations, $R... Je peux le voir à votre apparence que vous êtes un travailleur du cuir, comme moi. Êtes-vous venu puiser dans mes compétences, ou peut-être avez-vous une autre affaire avec moi ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $R... Je peux le voir à votre apparence que vous êtes un travailleur du cuir, comme moi. Êtes-vous venu puiser dans mes compétences, ou peut-être avez-vous une autre affaire avec moi ?';
-- Quest 2853 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2853, 'frFR', 'Ah oui, Pratt vous a envoyé. Bien qu\'il soit un humain, il me rappelle parfois nos elfes de la nuit. Son dévouement et ses talents avec le cuir sont impressionnants. Pour qu\'il vous complimente ainsi dans cette lettre, c\'est un signe de respect que j\'accorde.$B$Je sais qu\'il vous a appris l\'art du Cuir Sauvage. Permettez-moi de compléter votre formation avec ce modèle. Utilisez-le bien ; peu dans le monde connaissent les secrets des capes en Cuir Sauvage.') ON DUPLICATE KEY UPDATE RewardText='Ah oui, Pratt vous a envoyé. Bien qu\'il soit un humain, il me rappelle parfois nos elfes de la nuit. Son dévouement et ses talents avec le cuir sont impressionnants. Pour qu\'il vous complimente ainsi dans cette lettre, c\'est un signe de respect que j\'accorde.$B$Je sais qu\'il vous a appris l\'art du Cuir Sauvage. Permettez-moi de compléter votre formation avec ce modèle. Utilisez-le bien ; peu dans le monde connaissent les secrets des capes en Cuir Sauvage.';
-- Quest 2854 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2854, 'frFR', 'Nous devons être clairs ; vous serez mon apprenti pendant que vous apprenez l\'art de l\'armure en Cuir Sauvage. Parce que les lianes sauvages sont à la fois puissantes et chaotiques, elles donnent un bénéfice aléatoire mais fort à l\'armure déjà solide que vous allez fabriquer. Cette connaissance, cependant, n\'a pas été facile à acquérir pour moi.$b$bLe coût initial pour commencer ce processus est de dix pièces de cuir épais.$b$bUne fois cela fait, nous passerons au travail que vous devez faire pour obtenir les modèles.') ON DUPLICATE KEY UPDATE CompletionText='Nous devons être clairs ; vous serez mon apprenti pendant que vous apprenez l\'art de l\'armure en Cuir Sauvage. Parce que les lianes sauvages sont à la fois puissantes et chaotiques, elles donnent un bénéfice aléatoire mais fort à l\'armure déjà solide que vous allez fabriquer. Cette connaissance, cependant, n\'a pas été facile à acquérir pour moi.$b$bLe coût initial pour commencer ce processus est de dix pièces de cuir épais.$b$bUne fois cela fait, nous passerons au travail que vous devez faire pour obtenir les modèles.';
-- Quest 2854 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2854, 'frFR', 'Eh bien <name>, je suis heureux de vous avoir à bord en tant qu\'apprenti.  Vous avez pris une décision sage en tant que travailleur du cuir ; ceux qui utilisent des armures en cuir seront impatients de vous solliciter une fois que vous aurez appris à maîtriser l\'art du Cuir Sauvage.$B$BCommençons le travail - par où voulez-vous commencer ?') ON DUPLICATE KEY UPDATE RewardText='Eh bien <name>, je suis heureux de vous avoir à bord en tant qu\'apprenti.  Vous avez pris une décision sage en tant que travailleur du cuir ; ceux qui utilisent des armures en cuir seront impatients de vous solliciter une fois que vous aurez appris à maîtriser l\'art du Cuir Sauvage.$B$BCommençons le travail - par où voulez-vous commencer ?';
-- Quest 2855 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2855, 'frFR', 'Avez-vous les six kits d\'armure épaisse et la liane sauvage dont j\'ai besoin?$b$bConsidérez la fabrication de kits d\'armure comme une leçon de travail constant et fiable ; la méthode de confection cohérente que vous développez en exerçant votre métier sur ces kits aide à développer vos compétences pour le travail complexe nécessaire à la fabrication des armures en Cuir Sauvage.$b$bChaque leçon a un but, $N. Il est important d\'embrasser chacune d\'elles en conséquence.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les six kits d\'armure épaisse et la liane sauvage dont j\'ai besoin?$b$bConsidérez la fabrication de kits d\'armure comme une leçon de travail constant et fiable ; la méthode de confection cohérente que vous développez en exerçant votre métier sur ces kits aide à développer vos compétences pour le travail complexe nécessaire à la fabrication des armures en Cuir Sauvage.$b$bChaque leçon a un but, $N. Il est important d\'embrasser chacune d\'elles en conséquence.';
-- Quest 2855 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2855, 'frFR', 'Ces kits d\'armure sont de bonne qualité, $N. S\'il y a une chose que j\'exige non seulement dans mon travail, mais dans le travail de ceux dont j\'enseigne, c\'est la qualité.$b$bVous avez bien fait d\'avoir gagné ce modèle ; j\'espère qu\'il vous apportera les récompenses qu\'il m\'a apportées.') ON DUPLICATE KEY UPDATE RewardText='Ces kits d\'armure sont de bonne qualité, $N. S\'il y a une chose que j\'exige non seulement dans mon travail, mais dans le travail de ceux dont j\'enseigne, c\'est la qualité.$b$bVous avez bien fait d\'avoir gagné ce modèle ; j\'espère qu\'il vous apportera les récompenses qu\'il m\'a apportées.';
-- Quest 2856 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2856, 'frFR', 'Avez-vous les deux plastrons et gants en Écaille de Tortue ? Aussi, n\'oubliez pas la liane sauvage !$b$bMême avec les premiers modèles, nous apprenons que les fondamentaux de la forme se traduisent bien dans des vêtements plus difficiles. Bien que différents, la forme des plastrons en Écaille de Tortue vous prépare au détail nécessaire pour faire un gilet en Cuir Sauvage.$b$bAu fur et à mesure que vous progressez dans vos leçons, les compétences que j\'enseigne deviendront un art.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les deux plastrons et gants en Écaille de Tortue ? Aussi, n\'oubliez pas la liane sauvage !$b$bMême avec les premiers modèles, nous apprenons que les fondamentaux de la forme se traduisent bien dans des vêtements plus difficiles. Bien que différents, la forme des plastrons en Écaille de Tortue vous prépare au détail nécessaire pour faire un gilet en Cuir Sauvage.$b$bAu fur et à mesure que vous progressez dans vos leçons, les compétences que j\'enseigne deviendront un art.';
-- Quest 2856 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2856, 'frFR', 'Ce sont de très belles pièces ici, $N. Le savoir-faire et le soin apportés à leur fabrication montrent que vous avez choisi de vous consacrer entièrement à ces tâches.$b$bVous avez satisfait mes demandes, et avec cela vient votre récompense. La connaissance de la fabrication des gilets en Cuir Sauvage est maintenant la vôtre !') ON DUPLICATE KEY UPDATE RewardText='Ce sont de très belles pièces ici, $N. Le savoir-faire et le soin apportés à leur fabrication montrent que vous avez choisi de vous consacrer entièrement à ces tâches.$b$bVous avez satisfait mes demandes, et avec cela vient votre récompense. La connaissance de la fabrication des gilets en Cuir Sauvage est maintenant la vôtre !';
-- Quest 2857 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2857, 'frFR', 'J\'ai besoin que ces tuniques et bandeaux soient fabriqués, et j\'ai aussi besoin de cette pièce de liane sauvage avant de partager avec vous la connaissance des casques en Cuir Sauvage.$b$bLes équipements de tête sont très convoités par les aventuriers, qu\'il s\'agisse d\'un bandeau d\'une simplicité désarmante ou d\'un casque couvrant entièrement. Les fondamentaux de la création d\'équipements de tête de valeur restent constants, quelle que soit l\'apparence cosmétique de l\'équipement.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai besoin que ces tuniques et bandeaux soient fabriqués, et j\'ai aussi besoin de cette pièce de liane sauvage avant de partager avec vous la connaissance des casques en Cuir Sauvage.$b$bLes équipements de tête sont très convoités par les aventuriers, qu\'il s\'agisse d\'un bandeau d\'une simplicité désarmante ou d\'un casque couvrant entièrement. Les fondamentaux de la création d\'équipements de tête de valeur restent constants, quelle que soit l\'apparence cosmétique de l\'équipement.';
-- Quest 2857 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2857, 'frFR', 'Cet équipement de Paysage Nocturne que vous avez fourni correspond parfaitement aux exigences que je vous ai données, $N. Je n\'attends rien de moins d\'un travailleur du cuir de votre calibre.$b$bVous avez gagné l\'honneur de fabriquer des casques en Cuir Sauvage. Je vous donne ce modèle librement, et j\'espère que vous en profiterez en conséquence.') ON DUPLICATE KEY UPDATE RewardText='Cet équipement de Paysage Nocturne que vous avez fourni correspond parfaitement aux exigences que je vous ai données, $N. Je n\'attends rien de moins d\'un travailleur du cuir de votre calibre.$b$bVous avez gagné l\'honneur de fabriquer des casques en Cuir Sauvage. Je vous donne ce modèle librement, et j\'espère que vous en profiterez en conséquence.';
-- Quest 2858 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2858, 'frFR', 'Les pantalons, les bottes et les lianes sauvages doivent m\'être livrés avant que vous appreniez le modèle, $N. Avez-vous fait ce que j\'ai demandé?$b$bÀ partir de la première paire de bottes que nous apprenons à fabriquer, nous commençons à comprendre qu\'une botte de qualité doit trouver un équilibre entre le confort et la fonction. Avec les deux, nous sommes capables de créer des objets qui permettent au porteur d\'ignorer la fatigue qui paralyserait ceux qui portent des articles de qualité inférieure.') ON DUPLICATE KEY UPDATE CompletionText='Les pantalons, les bottes et les lianes sauvages doivent m\'être livrés avant que vous appreniez le modèle, $N. Avez-vous fait ce que j\'ai demandé?$b$bÀ partir de la première paire de bottes que nous apprenons à fabriquer, nous commençons à comprendre qu\'une botte de qualité doit trouver un équilibre entre le confort et la fonction. Avec les deux, nous sommes capables de créer des objets qui permettent au porteur d\'ignorer la fatigue qui paralyserait ceux qui portent des articles de qualité inférieure.';
-- Quest 2858 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2858, 'frFR', 'Encore une fois, vous avez produit des objets avec le savoir-faire d\'un professionnel aguerri. Vous avez gagné ce modèle, ainsi que mes félicitations.') ON DUPLICATE KEY UPDATE RewardText='Encore une fois, vous avez produit des objets avec le savoir-faire d\'un professionnel aguerri. Vous avez gagné ce modèle, ainsi que mes félicitations.';

-- Quest 2859 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2859, 'frFR', 'As-tu les brassards et les casques en Échelle de Tortue prêts ? N\'oublie pas les deux lianes sauvages dont j\'ai besoin.$b$bÀ présent, tu commences à réaliser le potentiel de puissance qui réside dans les armures de Cuir Sauvage. Une armure qui n\'a pas de limites d\'application est presque inestimable pour un travailleur de cuir. Les limites ne sont que dans les quantités de ressources pour fabriquer les objets - pas dans la qualité des produits finis !') ON DUPLICATE KEY UPDATE CompletionText='As-tu les brassards et les casques en Échelle de Tortue prêts ? N\'oublie pas les deux lianes sauvages dont j\'ai besoin.$b$bÀ présent, tu commences à réaliser le potentiel de puissance qui réside dans les armures de Cuir Sauvage. Une armure qui n\'a pas de limites d\'application est presque inestimable pour un travailleur de cuir. Les limites ne sont que dans les quantités de ressources pour fabriquer les objets - pas dans la qualité des produits finis !';
-- Quest 2859 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2859, 'frFR', 'Encore une fois, tu as accompli ma tâche sans faute. Peut-être qu\'un jour je viendraI CHEZ TOI pour chercher des connaissances, hein $N?$b$bVoici le modèle pour les leggings, ainsi que mes remerciements. Imprègne cette connaissance dans ton savoir, et laisse tes produits finis exploiter tes compétences impressionnantes !') ON DUPLICATE KEY UPDATE RewardText='Encore une fois, tu as accompli ma tâche sans faute. Peut-être qu\'un jour je viendraI CHEZ TOI pour chercher des connaissances, hein $N?$b$bVoici le modèle pour les leggings, ainsi que mes remerciements. Imprègne cette connaissance dans ton savoir, et laisse tes produits finis exploiter tes compétences impressionnantes !';
-- Quest 2860 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2860, 'frFR', 'Salutations, $r... de ton apparence, je peux dire que tu es un travailleur de cuir comme moi. Es-tu venu puiser dans mes compétences, ou peut-être as-tu d\'autres affaires avec moi ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $r... de ton apparence, je peux dire que tu es un travailleur de cuir comme moi. Es-tu venu puiser dans mes compétences, ou peut-être as-tu d\'autres affaires avec moi ?';
-- Quest 2860 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2860, 'frFR', 'Ah oui, Jangdor t\'a envoyé. Je suis heureux de voir qu\'un de mes meilleurs étudiants a maintenant un étudiant en lui.$b$bSon dévouement et ses talents avec le cuir sont impressionnants. Qu\'il te complimente ainsi dans cette lettre, c\'est un signe de respect que j\'accueille.$b$bJe sais qu\'il t\'a appris l\'art du Cuir Sauvage. Permets-moi de terminer ta formation avec ce modèle. Utilise-le bien ; peu dans le monde connaissent les secrets des capes de Cuir Sauvage.') ON DUPLICATE KEY UPDATE RewardText='Ah oui, Jangdor t\'a envoyé. Je suis heureux de voir qu\'un de mes meilleurs étudiants a maintenant un étudiant en lui.$b$bSon dévouement et ses talents avec le cuir sont impressionnants. Qu\'il te complimente ainsi dans cette lettre, c\'est un signe de respect que j\'accueille.$b$bJe sais qu\'il t\'a appris l\'art du Cuir Sauvage. Permets-moi de terminer ta formation avec ce modèle. Utilise-le bien ; peu dans le monde connaissent les secrets des capes de Cuir Sauvage.';
-- Quest 2862 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2862, 'frFR', 'Nous les repoussons, et pourtant ils attaquent toujours ! Quelqu\'un ou quelque chose doit les pousser à la frénésie... oh, tu es revenu, hein $N? As-tu les crinières dont j\'ai besoin pour que la prime soit honorée ?') ON DUPLICATE KEY UPDATE CompletionText='Nous les repoussons, et pourtant ils attaquent toujours ! Quelqu\'un ou quelque chose doit les pousser à la frénésie... oh, tu es revenu, hein $N? As-tu les crinières dont j\'ai besoin pour que la prime soit honorée ?';
-- Quest 2863 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2863, 'frFR', 'Le temps presse, $N! Si tu n\'es pas là pour rapporter que tu as abattu les Alpha, alors tu perds ton temps !') ON DUPLICATE KEY UPDATE CompletionText='Le temps presse, $N! Si tu n\'es pas là pour rapporter que tu as abattu les Alpha, alors tu perds ton temps !';
-- Quest 2873 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2873, 'frFR', 'As-tu trouvé mon envoi de rhum, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé mon envoi de rhum, $N?';
-- Quest 2878 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2878, 'frFR', 'Tu as trouvé une version malade et corrompue de ce qui semble être une fleur de chant. Une odeur nauséabonde et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.') ON DUPLICATE KEY UPDATE CompletionText='Tu as trouvé une version malade et corrompue de ce qui semble être une fleur de chant. Une odeur nauséabonde et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.';
-- Quest 2878 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2878, 'frFR', 'Tu appliques un onguent de plante de Cenarion à la fleur de chant. Elle commence immédiatement à perdre sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Tu appliques un onguent de plante de Cenarion à la fleur de chant. Elle commence immédiatement à perdre sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
-- Quest 2881 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2881, 'frFR', 'Je veux cinq de ces colliers tribaux que les trolls portent. Si tu as besoin qu\'on te le dise plus clairement, alors tu en tuer un d\'eux te donne de bonnes chances d\'en obtenir un !$B$BProuve ta valeur aux Marteaux Sauvages !') ON DUPLICATE KEY UPDATE CompletionText='Je veux cinq de ces colliers tribaux que les trolls portent. Si tu as besoin qu\'on te le dise plus clairement, alors tu en tuer un d\'eux te donne de bonnes chances d\'en obtenir un !$B$BProuve ta valeur aux Marteaux Sauvages !';
-- Quest 2881 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2881, 'frFR', 'C\'est ça que j\'appelle ! Regarde - ces colliers prouvent que tu es prêt à te salir les mains. Nous, les Marteaux Sauvages, valorisons cela chez ceux avec qui nous nous associons.$B$BSi tu continues comme ça, tu seras dans notre bienveillance.') ON DUPLICATE KEY UPDATE RewardText='C\'est ça que j\'appelle ! Regarde - ces colliers prouvent que tu es prêt à te salir les mains. Nous, les Marteaux Sauvages, valorisons cela chez ceux avec qui nous nous associons.$B$BSi tu continues comme ça, tu seras dans notre bienveillance.';
-- Quest 2922 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2922, 'frFR', 'As-tu trouvé Techbot ? As-tu récupéré son cœur de mémoire ??') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé Techbot ? As-tu récupéré son cœur de mémoire ??';
-- Quest 2922 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2922, 'frFR', 'Oh, c\'est merveilleux ! Merci, $N! Je vais commencer immédiatement!!$B$BMalheureux, pauvre Techbot... Ne t\'inquiète pas. Nous allons te réparer.$B$BMaintenant, où ai-je mis cette pièce pour ma clé à douille hydro-jack...') ON DUPLICATE KEY UPDATE RewardText='Oh, c\'est merveilleux ! Merci, $N! Je vais commencer immédiatement!!$B$BMalheureux, pauvre Techbot... Ne t\'inquiète pas. Nous allons te réparer.$B$BMaintenant, où ai-je mis cette pièce pour ma clé à douille hydro-jack...';
-- Quest 2924 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2924, 'frFR', 'As-tu les artifices essentiels ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu les artifices essentiels ?';
-- Quest 2924 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2924, 'frFR', 'Tu les as !  Maintenant je peux commencer mes nouvelles expériences!$B$Je ne peux pas te remercier assez, <name>!  Ton courage a fait progresser la recherche gnomique d\'un bond et d\'un saut !') ON DUPLICATE KEY UPDATE RewardText='Tu les as !  Maintenant je peux commencer mes nouvelles expériences!$B$Je ne peux pas te remercier assez, <name>!  Ton courage a fait progresser la recherche gnomique d\'un bond et d\'un saut !';

-- Quest 2925 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2925, 'frFR', 'Je le fais !  J\'ai besoin d\'aide pour une mission dans Gnomeregan.  Et vous êtes le <class> pour le faire !') ON DUPLICATE KEY UPDATE RewardText='Je le fais !  J\'ai besoin d\'aide pour une mission dans Gnomeregan.  Et vous êtes le <class> pour le faire !';
-- Quest 2929 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2929, 'frFR', 'La tâche est terminée ? Est-ce qu\'il a supplié pour la clémence ? Pour la pitié??') ON DUPLICATE KEY UPDATE CompletionText='La tâche est terminée ? Est-ce qu\'il a supplié pour la clémence ? Pour la pitié??';
-- Quest 2932 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2932, 'frFR', 'Vous n\'avez pas complété ma tâche, $N.') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas complété ma tâche, $N.';
-- Quest 2934 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2934, 'frFR', 'Avez-vous le sac de venin intact, $N? Je désire faire des expériences avec son venin frais, et j\'ai commandé une collection de petits animaux terriblement mignons sur lesquels le tester !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous le sac de venin intact, $N? Je désire faire des expériences avec son venin frais, et j\'ai commandé une collection de petits animaux terriblement mignons sur lesquels le tester !';
-- Quest 2936 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2936, 'frFR', 'Savez-vous le nom du dieu araignée ?') ON DUPLICATE KEY UPDATE CompletionText='Savez-vous le nom du dieu araignée ?';
-- Quest 2946 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2946, 'frFR', 'Ce piédestal familier dépasse du sable chaud. Peut-être y a-t-il quelque chose à sa présence ici...') ON DUPLICATE KEY UPDATE CompletionText='Ce piédestal familier dépasse du sable chaud. Peut-être y a-t-il quelque chose à sa présence ici...';
-- Quest 2946 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2946, 'frFR', 'Lorsque vous touchez le piédestal, les disques miniatures d\'Uldaman bourdonnent et brillent dans votre sac à dos.  Une sensation familière vous parcourt les mains, tandis que l\'image d\'un autre Observateur de Pierre prend vie devant les portes d\'Uldum.$B$BSalutations.  Je suis un gardien d\'entrée.  Les disques utilisés pour l\'accès sont dépourvus des disques d\'entrée corrects, les Plaques d\'Uldum.  Veuillez intégrer ces plaques à la structure de disque et répéter votre séquence d\'accès.  Merci."') ON DUPLICATE KEY UPDATE RewardText='Lorsque vous touchez le piédestal, les disques miniatures d\'Uldaman bourdonnent et brillent dans votre sac à dos.  Une sensation familière vous parcourt les mains, tandis que l\'image d\'un autre Observateur de Pierre prend vie devant les portes d\'Uldum.$B$BSalutations.  Je suis un gardien d\'entrée.  Les disques utilisés pour l\'accès sont dépourvus des disques d\'entrée corrects, les Plaques d\'Uldum.  Veuillez intégrer ces plaques à la structure de disque et répéter votre séquence d\'accès.  Merci."';
-- Quest 2948 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2948, 'frFR', 'Avez-vous les matériaux dont j\'ai besoin ? Je ne vous les demanderais pas si je n\'étais pas dans une mauvaise passe...') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les matériaux dont j\'ai besoin ? Je ne vous les demanderais pas si je n\'étais pas dans une mauvaise passe...';
-- Quest 2949 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2949, 'frFR', 'On pourrait penser que nous trouverions un moyen par nous-mêmes de surpasser ces petits gnomes sales. Je parierais même qu\'ils nous ont volé ce dispositif au départ ! Bah, ces... erm, oui ? Vous avez besoin de quelque chose ?') ON DUPLICATE KEY UPDATE CompletionText='On pourrait penser que nous trouverions un moyen par nous-mêmes de surpasser ces petits gnomes sales. Je parierais même qu\'ils nous ont volé ce dispositif au départ ! Bah, ces... erm, oui ? Vous avez besoin de quelque chose ?';
-- Quest 2950 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2950, 'frFR', 'Avez-vous les matériaux dont j\'ai besoin ? Je ne peux pas améliorer ce design sans tout ce que j\'ai demandé.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les matériaux dont j\'ai besoin ? Je ne peux pas améliorer ce design sans tout ce que j\'ai demandé.';
-- Quest 2952 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2952, 'frFR', 'Aussi vite que cela a commencé, le Sparklematic 5200 s\'arrête brusquement. Un simple "ding" est entendu depuis la machine, et la bouche de la machine s\'enroule vers le haut. À l\'intérieur du Sparklematic 5200 se trouve une petite boîte enveloppée d\'un petit nœud. La machine semblerait envelopper un objet après avoir éliminé son état incrusté de crasse. Même si la machine ne fonctionnait pas, au moins l\'objet est maintenant enveloppé dans une jolie boîte.$B$BEh bien, il y a un moyen de savoir si elle a nettoyé l\'objet ou pas...') ON DUPLICATE KEY UPDATE RewardText='Aussi vite que cela a commencé, le Sparklematic 5200 s\'arrête brusquement. Un simple "ding" est entendu depuis la machine, et la bouche de la machine s\'enroule vers le haut. À l\'intérieur du Sparklematic 5200 se trouve une petite boîte enveloppée d\'un petit nœud. La machine semblerait envelopper un objet après avoir éliminé son état incrusté de crasse. Même si la machine ne fonctionnait pas, au moins l\'objet est maintenant enveloppé dans une jolie boîte.$B$BEh bien, il y a un moyen de savoir si elle a nettoyé l\'objet ou pas...';
-- Quest 2953 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2953, 'frFR', 'Le Sparklematic 5200 est vide, attendant un objet incrusté de crasse à nettoyer et trois pièces d\'argent pour commencer !') ON DUPLICATE KEY UPDATE CompletionText='Le Sparklematic 5200 est vide, attendant un objet incrusté de crasse à nettoyer et trois pièces d\'argent pour commencer !';
-- Quest 2954 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2954, 'frFR', 'Le but de l\'observateur de pierre doit être appris avant de continuer...') ON DUPLICATE KEY UPDATE CompletionText='Le but de l\'observateur de pierre doit être appris avant de continuer...';
-- Quest 2963 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2963, 'frFR', 'Je suis heureux que vous mainteniez votre intérêt pour l\'exploration, <name> !  Avec votre talent naturel et votre cran, nous pourrions percer des secrets que nous pensions impossibles !$B$BLes Disques de Norgannon dans Uldaman étaient un dépôt d\'informations vastes ; vous n\'avez été autorisé à accéder qu\'aux couches supérieures, disons, des informations stockées là-dedans.  Il était dit que les Créateurs avaient d\'autres dépôts situés à travers Azeroth.  Ceci nous amène maintenant à Uldum...') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que vous mainteniez votre intérêt pour l\'exploration, <name> !  Avec votre talent naturel et votre cran, nous pourrions percer des secrets que nous pensions impossibles !$B$BLes Disques de Norgannon dans Uldaman étaient un dépôt d\'informations vastes ; vous n\'avez été autorisé à accéder qu\'aux couches supérieures, disons, des informations stockées là-dedans.  Il était dit que les Créateurs avaient d\'autres dépôts situés à travers Azeroth.  Ceci nous amène maintenant à Uldum...';
-- Quest 2966 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2966, 'frFR', 'Ce piédestal familier dépasse du sable chaud. Peut-être y a-t-il quelque chose à sa présence ici...') ON DUPLICATE KEY UPDATE CompletionText='Ce piédestal familier dépasse du sable chaud. Peut-être y a-t-il quelque chose à sa présence ici...';

-- Quest 2966 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2966, 'frFR', 'En touchant le piédestal, les disques miniatures d\'Uldaman bourdonnent et s\'illuminent dans votre sac à dos. Une sensation familière vous parcourt les mains, tandis que l\'image d\'un autre Observateur de Pierre prend vie devant les portes d\'Uldum.$B$B"Salutations. Je suis un gardien d\'entrée. Les disques utilisés pour l\'accès sont dépourvus des disques d\'entrée corrects, les Plaques d\'Uldum. Veuillez intégrer ces plaques à la structure du disque et répéter votre séquence d\'accès. Merci."') ON DUPLICATE KEY UPDATE RewardText='En touchant le piédestal, les disques miniatures d\'Uldaman bourdonnent et s\'illuminent dans votre sac à dos. Une sensation familière vous parcourt les mains, tandis que l\'image d\'un autre Observateur de Pierre prend vie devant les portes d\'Uldum.$B$B"Salutations. Je suis un gardien d\'entrée. Les disques utilisés pour l\'accès sont dépourvus des disques d\'entrée corrects, les Plaques d\'Uldum. Veuillez intégrer ces plaques à la structure du disque et répéter votre séquence d\'accès. Merci."';
-- Quest 2967 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2967, 'frFR', 'Bienvenue de retour $N$. Avez-vous réussi à utiliser les disques à votre avantage, ou cela n\'a-t-il servi à rien ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue de retour $N$. Avez-vous réussi à utiliser les disques à votre avantage, ou cela n\'a-t-il servi à rien ?';
-- Quest 2967 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2967, 'frFR', 'Il vous manquait des disques ? Il est intéressant de noter que les disques de Norgannon ne sont que des parties de l\'ensemble complet - comme des clés sur un porte-clés, si vous voulez.$B$BSi nous trouvons les Plaques d\'Uldum, nous pourrons en fait accéder au complexe d\'Uldum lui-même. Je ne sais pas si je dois être excité par cette perspective, ou terrifié.$B$BNous pourrions devoir tout risquer pour nous assurer que les secrets que la terre garde et qui pourraient nous détruire restent juste cela - des secrets.') ON DUPLICATE KEY UPDATE RewardText='Il vous manquait des disques ? Il est intéressant de noter que les disques de Norgannon ne sont que des parties de l\'ensemble complet - comme des clés sur un porte-clés, si vous voulez.$B$BSi nous trouvons les Plaques d\'Uldum, nous pourrons en fait accéder au complexe d\'Uldum lui-même. Je ne sais pas si je dois être excité par cette perspective, ou terrifié.$B$BNous pourrions devoir tout risquer pour nous assurer que les secrets que la terre garde et qui pourraient nous détruire restent juste cela - des secrets.';
-- Quest 2968 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2968, 'frFR', 'Nous sommes tous d\'accord alors - la meilleure ligne de conduite est d\'attendre que nous puissions cerner les zones où ces plaques pourraient être cachées. Vous nous avez menés jusque-là <name>, et j\'espère que vous serez celui qui retournera sur le terrain pour affronter les secrets d\'Uldum.$B$BPermettez-moi de vous donner cet honorarium entre-temps ; cela devrait couvrir toutes les dépenses que vous avez rencontrées en nous aidant, et un peu plus. Assurez-vous de revenir nous voir bientôt... Uldum nous appelle tous, jeune.') ON DUPLICATE KEY UPDATE RewardText='Nous sommes tous d\'accord alors - la meilleure ligne de conduite est d\'attendre que nous puissions cerner les zones où ces plaques pourraient être cachées. Vous nous avez menés jusque-là <name>, et j\'espère que vous serez celui qui retournera sur le terrain pour affronter les secrets d\'Uldum.$B$BPermettez-moi de vous donner cet honorarium entre-temps ; cela devrait couvrir toutes les dépenses que vous avez rencontrées en nous aidant, et un peu plus. Assurez-vous de revenir nous voir bientôt... Uldum nous appelle tous, jeune.';
-- Quest 2969 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2969, 'frFR', 'Merci Elune, <name> ! Vous êtes une grande bénédiction pour nous et pour les darters que vous avez sauvés. Jer\'kai et moi n\'aurions jamais pu aider les dragons nous-mêmes -- votre intervention dans les affaires des Grimtotem sera mémorisée.$B$BParlez à Jer\'kai maintenant... Je dois me préparer à notre rétribution. Le simple fait que les dragons fées soient libres ne signifie pas qu\'ils resteront ainsi. Jer\'kai et moi allons maintenant passer à l\'offensive.') ON DUPLICATE KEY UPDATE RewardText='Merci Elune, <name> ! Vous êtes une grande bénédiction pour nous et pour les darters que vous avez sauvés. Jer\'kai et moi n\'aurions jamais pu aider les dragons nous-mêmes -- votre intervention dans les affaires des Grimtotem sera mémorisée.$B$BParlez à Jer\'kai maintenant... Je dois me préparer à notre rétribution. Le simple fait que les dragons fées soient libres ne signifie pas qu\'ils resteront ainsi. Jer\'kai et moi allons maintenant passer à l\'offensive.';
-- Quest 2970 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2970, 'frFR', 'Kindal a besoin de temps pour se préparer, mais nos tueries comptent déjà des dizaines. Le clan Grimtotem est bien conscient de notre présence dans la zone, et ils nous cherchent comme des vipères.$B$BIls feront tout en leur pouvoir pour nous arracher la tête du corps. Vous devriez être vigilant... ils vont venir vous chercher aussi maintenant que vous êtes intervenu.') ON DUPLICATE KEY UPDATE CompletionText='Kindal a besoin de temps pour se préparer, mais nos tueries comptent déjà des dizaines. Le clan Grimtotem est bien conscient de notre présence dans la zone, et ils nous cherchent comme des vipères.$B$BIls feront tout en leur pouvoir pour nous arracher la tête du corps. Vous devriez être vigilant... ils vont venir vous chercher aussi maintenant que vous êtes intervenu.';
-- Quest 2973 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2973, 'frFR', 'Les darters sprites peuvent être des créatures dangereuses lorsqu\'elles sont provoquées. Faites attention lorsque vous les manipulez, $C$. Et soyez encore plus prudent avec tout elfe de la nuit dans la zone. Les idiots importuns ont tendance à se retrouver aussi dans les forêts.$b$bQuand vous aurez assez d\'ailes, faites-le moi savoir, je serai sûr de vous récompenser généreusement !') ON DUPLICATE KEY UPDATE CompletionText='Les darters sprites peuvent être des créatures dangereuses lorsqu\'elles sont provoquées. Faites attention lorsque vous les manipulez, $C$. Et soyez encore plus prudent avec tout elfe de la nuit dans la zone. Les idiots importuns ont tendance à se retrouver aussi dans les forêts.$b$bQuand vous aurez assez d\'ailes, faites-le moi savoir, je serai sûr de vous récompenser généreusement !';
-- Quest 2973 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2973, 'frFR', 'Merveilleux, <class> ! Ceux-ci feront l\'affaire. Il y en a assez pour confectionner une cape pour Korrin, et peut-être même plus ! Merci.$B$BJ\'espère que le voyage n\'a pas été trop dangereux ? La zone de Feralas n\'est pas connue pour être indulgente, mais vous avez manifestement fait suffisamment bien.$B$BMerci encore, <class>.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux, <class> ! Ceux-ci feront l\'affaire. Il y en a assez pour confectionner une cape pour Korrin, et peut-être même plus ! Merci.$B$BJ\'espère que le voyage n\'a pas été trop dangereux ? La zone de Feralas n\'est pas connue pour être indulgente, mais vous avez manifestement fait suffisamment bien.$B$BMerci encore, <class>.';
-- Quest 2975 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2975, 'frFR', 'Agissez rapidement, $N$. Ou est-ce que la tâche que j\'ai demandée est trop difficile ?') ON DUPLICATE KEY UPDATE CompletionText='Agissez rapidement, $N$. Ou est-ce que la tâche que j\'ai demandée est trop difficile ?';
-- Quest 2982 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2982, 'frFR', 'Soyez vigilant autour des Gordunni, $N$. Leur magie semble semer le chaos dans la terre même sur laquelle ils se tiennent.') ON DUPLICATE KEY UPDATE CompletionText='Soyez vigilant autour des Gordunni, $N$. Leur magie semble semer le chaos dans la terre même sur laquelle ils se tiennent.';
-- Quest 2983 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2983, 'frFR', 'Hmmm, Swart vous a envoyé chez moi, est-ce ça?$B$BEh bien, Swart pouvait toujours être fait confiance, donc cela doit signifier que vous êtes prêt à participer au prochain sapta--le sapta de feu.$B$Je le vois déjà dans tes yeux, l\'ardeur, le désir. Tu as goûté au pouvoir, et maintenant tu es prêt pour plus. Patience, $N$. Souviens-toi de ce que la terre t\'a appris. Le pouvoir et la destruction viendront facilement, mais tu dois quand même savoir quand te retenir.') ON DUPLICATE KEY UPDATE RewardText='Hmmm, Swart vous a envoyé chez moi, est-ce ça?$B$BEh bien, Swart pouvait toujours être fait confiance, donc cela doit signifier que vous êtes prêt à participer au prochain sapta--le sapta de feu.$B$Je le vois déjà dans tes yeux, l\'ardeur, le désir. Tu as goûté au pouvoir, et maintenant tu es prêt pour plus. Patience, $N$. Souviens-toi de ce que la terre t\'a appris. Le pouvoir et la destruction viendront facilement, mais tu dois quand même savoir quand te retenir.';
-- Quest 2984 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2984, 'frFR', 'Hmmm, Narm vous a envoyé chez moi, est-ce ça?$B$BEh bien, Narm pouvait toujours être fait confiance, donc cela doit signifier que vous êtes prêt à participer au prochain sapta--le sapta de feu.$B$Je le vois déjà dans tes yeux, l\'ardeur, le désir. Tu as goûté au pouvoir, et maintenant tu es prêt pour plus. Patience, $N$. Souviens-toi de ce que la terre t\'a appris. Le pouvoir et la destruction viendront facilement, mais tu dois quand même savoir quand te retenir.') ON DUPLICATE KEY UPDATE RewardText='Hmmm, Narm vous a envoyé chez moi, est-ce ça?$B$BEh bien, Narm pouvait toujours être fait confiance, donc cela doit signifier que vous êtes prêt à participer au prochain sapta--le sapta de feu.$B$Je le vois déjà dans tes yeux, l\'ardeur, le désir. Tu as goûté au pouvoir, et maintenant tu es prêt pour plus. Patience, $N$. Souviens-toi de ce que la terre t\'a appris. Le pouvoir et la destruction viendront facilement, mais tu dois quand même savoir quand te retenir.';
-- Quest 2985 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2985, 'frFR', 'Le vent vous approche rapidement de l\'horizon ; la terre est stable sous vos pieds ; et votre esprit est déjà réchauffé par le feu -- je dirais qu\'il est temps pour vous d\'apprendre la pureté de l\'eau.$B$BVotre chemin vous a mené jusque-là, et votre esprit vous donnera la force de continuer plus loin. Mais le premier pas vous appartient.') ON DUPLICATE KEY UPDATE RewardText='Le vent vous approche rapidement de l\'horizon ; la terre est stable sous vos pieds ; et votre esprit est déjà réchauffé par le feu -- je dirais qu\'il est temps pour vous d\'apprendre la pureté de l\'eau.$B$BVotre chemin vous a mené jusque-là, et votre esprit vous donnera la force de continuer plus loin. Mais le premier pas vous appartient.';
-- Quest 2986 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2986, 'frFR', 'Le vent vous approche rapidement de l\'horizon ; la terre est stable sous vos pieds ; et votre esprit est déjà réchauffé par le feu -- je dirais qu\'il est temps pour vous d\'apprendre la pureté de l\'eau.$B$BVotre chemin vous a mené jusque-là, et votre esprit vous donnera la force de continuer plus loin. Mais le premier pas vous appartient.') ON DUPLICATE KEY UPDATE RewardText='Le vent vous approche rapidement de l\'horizon ; la terre est stable sous vos pieds ; et votre esprit est déjà réchauffé par le feu -- je dirais qu\'il est temps pour vous d\'apprendre la pureté de l\'eau.$B$BVotre chemin vous a mené jusque-là, et votre esprit vous donnera la force de continuer plus loin. Mais le premier pas vous appartient.';

-- Quest 2988 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2988, 'frFR', 'As-tu fouillé les cages, $N$? Nous devons trouver Sharpbeak!') ON DUPLICATE KEY UPDATE CompletionText='As-tu fouillé les cages, $N$? Nous devons trouver Sharpbeak!';
-- Quest 2989 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2989, 'frFR', 'Dépêche-toi, $N$! Si les trolls de Vilebranch ont Sharpbeak, qui sait ce qu\'ils pourraient faire de lui!') ON DUPLICATE KEY UPDATE CompletionText='Dépêche-toi, $N$! Si les trolls de Vilebranch ont Sharpbeak, qui sait ce qu\'ils pourraient faire de lui!';
-- Quest 2991 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2991, 'frFR', 'As-tu le Médaillon de Nekrum, $N$? Il y a des pouvoirs cachés en lui que je suis impatient de découvrir.') ON DUPLICATE KEY UPDATE CompletionText='As-tu le Médaillon de Nekrum, $N$? Il y a des pouvoirs cachés en lui que je suis impatient de découvrir.';
-- Quest 2991 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2991, 'frFR', 'Ah, le médaillon de Nekrum.  On raconte qu\'il a donné au troll une vie anormalement longue, mais à un prix.  J\'espère découvrir un moyen de récolter le pouvoir du médaillon tout en évitant ses... effets secondaires désagréables.$B$BTu m\'as rendu un service, <name>.  Je vais maintenant honorer mon côté de notre marché.') ON DUPLICATE KEY UPDATE RewardText='Ah, le médaillon de Nekrum.  On raconte qu\'il a donné au troll une vie anormalement longue, mais à un prix.  J\'espère découvrir un moyen de récolter le pouvoir du médaillon tout en évitant ses... effets secondaires désagréables.$B$BTu m\'as rendu un service, <name>.  Je vais maintenant honorer mon côté de notre marché.';
-- Quest 2995 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2995, 'frFR', 'Garder les elfes de Highvale isolés est la clé. As-tu trouvé le lodge?') ON DUPLICATE KEY UPDATE CompletionText='Garder les elfes de Highvale isolés est la clé. As-tu trouvé le lodge?';
-- Quest 2996 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2996, 'frFR', 'Une journée bien remplie à Ratchet, n\'est-ce pas? J\'aime observer le labeur d\'une ville portuaire. Tant de mystère, tant d\'aventure... tant d\'ignorance.$B$BEst-ce cette haine que je vois dans tes yeux, $N$? Bien, nous allons l\'utiliser à bon escient.') ON DUPLICATE KEY UPDATE RewardText='Une journée bien remplie à Ratchet, n\'est-ce pas? J\'aime observer le labeur d\'une ville portuaire. Tant de mystère, tant d\'aventure... tant d\'ignorance.$B$BEst-ce cette haine que je vois dans tes yeux, $N$? Bien, nous allons l\'utiliser à bon escient.';
-- Quest 2997 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2997, 'frFR', 'Bienvenue, $N$. J\'espère que la Lumière te montrera le vrai chemin et te gardera à l\'abri du mal.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue, $N$. J\'espère que la Lumière te montrera le vrai chemin et te gardera à l\'abri du mal.';
-- Quest 2998 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2998, 'frFR', 'C\'est beau ici à Stormwind, n\'est-ce pas?$B$BTon timing n\'aurait pas pu être meilleur, $N$.') ON DUPLICATE KEY UPDATE RewardText='C\'est beau ici à Stormwind, n\'est-ce pas?$B$BTon timing n\'aurait pas pu être meilleur, $N$.';
-- Quest 2999 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (2999, 'frFR', 'Bienvenue, $N$. J\'espère que la Lumière te montrera le vrai chemin et te gardera à l\'abri du mal.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue, $N$. J\'espère que la Lumière te montrera le vrai chemin et te gardera à l\'abri du mal.';
-- Quest 3000 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3000, 'frFR', 'Je t\'accueille, et je te souhaite la bienvenue, $N$.') ON DUPLICATE KEY UPDATE RewardText='Je t\'accueille, et je te souhaite la bienvenue, $N$.';
-- Quest 3001 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3001, 'frFR', 'Une journée bien remplie à Ratchet, n\'est-ce pas? J\'aime observer le labeur d\'une ville portuaire. Tant de mystère, tant d\'aventure... tant d\'ignorance.$B$BEst-ce cette haine que je vois dans tes yeux, $N$? Bien, nous allons l\'utiliser à bon escient.') ON DUPLICATE KEY UPDATE RewardText='Une journée bien remplie à Ratchet, n\'est-ce pas? J\'aime observer le labeur d\'une ville portuaire. Tant de mystère, tant d\'aventure... tant d\'ignorance.$B$BEst-ce cette haine que je vois dans tes yeux, $N$? Bien, nous allons l\'utiliser à bon escient.';
-- Quest 3002 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3002, 'frFR', 'Fascinant, $N$...$b$bCe orbe est très puissant, mais aussi très dangereux.') ON DUPLICATE KEY UPDATE RewardText='Fascinant, $N$...$b$bCe orbe est très puissant, mais aussi très dangereux.';
-- Quest 3042 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3042, 'frFR', 'M\'as-tu apporté le tempérament, $N$?') ON DUPLICATE KEY UPDATE CompletionText='M\'as-tu apporté le tempérament, $N$?';
-- Quest 3063 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3063, 'frFR', 'Les ailes des harpies de Northspring sont noires comme la nuit; ne les quitte pas des yeux, de peur qu\'elles ne disparaissent dans l\'obscurité.') ON DUPLICATE KEY UPDATE CompletionText='Les ailes des harpies de Northspring sont noires comme la nuit; ne les quitte pas des yeux, de peur qu\'elles ne disparaissent dans l\'obscurité.';
-- Quest 3065 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3065, 'frFR', 'Un autre $R$ pour renforcer les rangs. Assez pour moi.$b$bTu auras probablement du mal à manier une bonne arme comme une hache, mais une lance est aussi bonne que n\'importe quoi d\'autre.$b$bBienvenue dans la Vallée des Épreuves.') ON DUPLICATE KEY UPDATE CompletionText='Un autre $R$ pour renforcer les rangs. Assez pour moi.$b$bTu auras probablement du mal à manier une bonne arme comme une hache, mais une lance est aussi bonne que n\'importe quoi d\'autre.$b$bBienvenue dans la Vallée des Épreuves.';

-- Quest 3065 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3065, 'frFR', 'Tu trouveras cet endroit approprié pour continuer à t\'entraîner dans les $c façons. Si tu as des questions, n\'hésite pas à demander à quiconque autour, et quand tu sentiras que tu es prêt, reviens vers moi pour l\'entraînement. J\'ai maîtrisé autant que n\'importe quel $c ici dans la Vallée et je peux te transmettre ce savoir... moyennant un prix.') ON DUPLICATE KEY UPDATE RewardText='Tu trouveras cet endroit approprié pour continuer à t\'entraîner dans les $c façons. Si tu as des questions, n\'hésite pas à demander à quiconque autour, et quand tu sentiras que tu es prêt, reviens vers moi pour l\'entraînement. J\'ai maîtrisé autant que n\'importe quel $c ici dans la Vallée et je peux te transmettre ce savoir... moyennant un prix.';
-- Quest 3083 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3083, 'frFR', 'Bienvenue dans la Vallée des Épreuves, $n. Tu ne serais pas ici si tu n\'avais pas récupéré mon parchemin, alors je vais aller droit au but.$B$Je suis Rwag et je suis responsable de l\'entraînement des rogues, des voleurs et des pickpockets ici dans la Vallée. Je suis celui vers qui la Main se tournera si tu n\'es pas prêt pour ce qui vient. Mais ne t\'inquiète pas, la Main ne contrôlera pas tout ce que tu fais, mais il serait sage de travailler avec eux s\'ils ont besoin de tes talents.') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue dans la Vallée des Épreuves, $n. Tu ne serais pas ici si tu n\'avais pas récupéré mon parchemin, alors je vais aller droit au but.$B$Je suis Rwag et je suis responsable de l\'entraînement des rogues, des voleurs et des pickpockets ici dans la Vallée. Je suis celui vers qui la Main se tournera si tu n\'es pas prêt pour ce qui vient. Mais ne t\'inquiète pas, la Main ne contrôlera pas tout ce que tu fais, mais il serait sage de travailler avec eux s\'ils ont besoin de tes talents.';
-- Quest 3083 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3083, 'frFR', 'Jusqu\'à ce temps, tu seras sous ma tutelle. Je t\'apprendrai les ficelles comme disent certains. Quand tu te sentiras préparé, viens me voir et je verrai comment te former davantage. En attendant, pratique tes compétences et garde-les affûtées comme une lame de rasoir. Tu ne sauras jamais quand tu auras besoin même de la capacité la plus insignifiante.') ON DUPLICATE KEY UPDATE RewardText='Jusqu\'à ce temps, tu seras sous ma tutelle. Je t\'apprendrai les ficelles comme disent certains. Quand tu te sentiras préparé, viens me voir et je verrai comment te former davantage. En attendant, pratique tes compétences et garde-les affûtées comme une lame de rasoir. Tu ne sauras jamais quand tu auras besoin même de la capacité la plus insignifiante.';
-- Quest 3085 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3085, 'frFR', 'Alors, tu y es arrivé... bon, bon ! Les esprits m\'ont dit que tu viendrais voir Ken\'jai bientôt. Laisse-moi être le premier à t\'accueillir dans la Vallée des Épreuves. Cet endroit ne sera pas ta maison pour longtemps, mais pendant qu\'il l\'est, pourquoi ne pas en faire le meilleur.') ON DUPLICATE KEY UPDATE CompletionText='Alors, tu y es arrivé... bon, bon ! Les esprits m\'ont dit que tu viendrais voir Ken\'jai bientôt. Laisse-moi être le premier à t\'accueillir dans la Vallée des Épreuves. Cet endroit ne sera pas ta maison pour longtemps, mais pendant qu\'il l\'est, pourquoi ne pas en faire le meilleur.';
-- Quest 3085 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3085, 'frFR', 'Alors que tu te testes, tu trouveras que tu as un meilleur et un meilleur contrôle sur les esprits -- tu les appelleras pour des choses plus grandes et plus grandes...  c\'est là que Ken\'jai intervient. Tu viens parler à Ken\'jai quand tu te sentiras prêt. Si les esprits sont d\'accord, alors nous verrons comment t\'apprendre des capacités plus puissantes... mais seulement si les esprits sont d\'accord.$B$Va maintenant, parle au reste des gens de la Vallée. Parle-moi à nouveau plus tard.') ON DUPLICATE KEY UPDATE RewardText='Alors que tu te testes, tu trouveras que tu as un meilleur et un meilleur contrôle sur les esprits -- tu les appelleras pour des choses plus grandes et plus grandes...  c\'est là que Ken\'jai intervient. Tu viens parler à Ken\'jai quand tu te sentiras prêt. Si les esprits sont d\'accord, alors nous verrons comment t\'apprendre des capacités plus puissantes... mais seulement si les esprits sont d\'accord.$B$Va maintenant, parle au reste des gens de la Vallée. Parle-moi à nouveau plus tard.';
-- Quest 3086 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3086, 'frFR', 'Tu plaises déjà à Mai\'ah, $N. C\'est bien. Tu donnes du respect à Mai\'ah, et Mai\'ah peut te rendre le respect. Mais assez, tu es ici pour apprendre la magie, pas pour entendre Mai\'ah parler.$B$Il n\'y a qu\'une seule chose que Mai\'ah peut t\'apprendre sur la magie, $N, et c\'est comment arrêter la corruption.') ON DUPLICATE KEY UPDATE CompletionText='Tu plaises déjà à Mai\'ah, $N. C\'est bien. Tu donnes du respect à Mai\'ah, et Mai\'ah peut te rendre le respect. Mais assez, tu es ici pour apprendre la magie, pas pour entendre Mai\'ah parler.$B$Il n\'y a qu\'une seule chose que Mai\'ah peut t\'apprendre sur la magie, $N, et c\'est comment arrêter la corruption.';
-- Quest 3086 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3086, 'frFR', 'Tu es parmi les êtres les plus puissants de la planète, <name>... il n\'y a pas de dispute là-dessus. Et tout le monde le sait... sache-le bien aussi !$B$Mais tu dois être prudent ! car ce n\'est pas un orc, ou un elfe, ou un nain dont tu dois avoir peur... ce sont les choses que tu ne peux pas voir. La magie est puissante. Elle te fait faire des choses que tu ne veux peut-être pas faire. Elle te fait penser que tu es plus puissant que tu ne l\'es vraiment. Sois patient. Sois intelligent.$B$Quand tu penses être prêt pour l\'entraînement, reviens à Mai\'ah. Elle t\'apprendra ce que tu es prêt à apprendre, pas de problème.') ON DUPLICATE KEY UPDATE RewardText='Tu es parmi les êtres les plus puissants de la planète, <name>... il n\'y a pas de dispute là-dessus. Et tout le monde le sait... sache-le bien aussi !$B$Mais tu dois être prudent ! car ce n\'est pas un orc, ou un elfe, ou un nain dont tu dois avoir peur... ce sont les choses que tu ne peux pas voir. La magie est puissante. Elle te fait faire des choses que tu ne veux peut-être pas faire. Elle te fait penser que tu es plus puissant que tu ne l\'es vraiment. Sois patient. Sois intelligent.$B$Quand tu penses être prêt pour l\'entraînement, reviens à Mai\'ah. Elle t\'apprendra ce que tu es prêt à apprendre, pas de problème.';
-- Quest 3087 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3087, 'frFR', 'Ah, alors tu es arrivé finalement. Bien. Jen\'shan t\'attend. $B$Beaucoup pensent que c\'est un chemin facile, mais Jen\'shan te dit que ce n\'est pas vrai. Maîtriser les bêtes de Durotar et au-delà demande autant de compétences que de maîtriser les arts arcaniques ou de parler à nos ancêtres.$B$Tirer un arc ou un fusil n\'est peut-être pas aussi dangereux pour toi que de lancer un sort, mais c\'est certainement aussi dangereux pour ton ennemi.') ON DUPLICATE KEY UPDATE CompletionText='Ah, alors tu es arrivé finalement. Bien. Jen\'shan t\'attend. $B$Beaucoup pensent que c\'est un chemin facile, mais Jen\'shan te dit que ce n\'est pas vrai. Maîtriser les bêtes de Durotar et au-delà demande autant de compétences que de maîtriser les arts arcaniques ou de parler à nos ancêtres.$B$Tirer un arc ou un fusil n\'est peut-être pas aussi dangereux pour toi que de lancer un sort, mais c\'est certainement aussi dangereux pour ton ennemi.';
-- Quest 3088 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3088, 'frFR', 'Chut, pas si fort. Je ne fais pas confiance à Nartok là-bas. Ceux qui doivent se cacher plus profondément dans une grotte que moi ne devraient pas être provoqués.$b$Je crois que tu n\'as pas eu de problème à trouver ton chemin ?') ON DUPLICATE KEY UPDATE CompletionText='Chut, pas si fort. Je ne fais pas confiance à Nartok là-bas. Ceux qui doivent se cacher plus profondément dans une grotte que moi ne devraient pas être provoqués.$b$Je crois que tu n\'as pas eu de problème à trouver ton chemin ?';
-- Quest 3088 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3088, 'frFR', 'Maintenant que tu sais où je suis, je dois te dire : la Main Brisée m\'a demandé de veiller sur toi. Ils veulent que je t\'entraîne et que je te tienne informé de tout ce dont ils pourraient avoir besoin. Même si tu n\'es pas intéressé à les aider pour l\'instant -- ce qui serait une folie de ne pas l\'être -- je ferai de mon mieux pour t\'entraîner... moyennant un petit prix.') ON DUPLICATE KEY UPDATE RewardText='Maintenant que tu sais où je suis, je dois te dire : la Main Brisée m\'a demandé de veiller sur toi. Ils veulent que je t\'entraîne et que je te tienne informé de tout ce dont ils pourraient avoir besoin. Même si tu n\'es pas intéressé à les aider pour l\'instant -- ce qui serait une folie de ne pas l\'être -- je ferai de mon mieux pour t\'entraîner... moyennant un petit prix.';
-- Quest 3090 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3090, 'frFR', 'Finalement, tu es arrivé... et discrètement aussi. Bien.$b$Notre monde est rempli de fous, Asatokta. Même le puissant Thrall a des défauts plus grands que la plupart ne peuvent voir. Il tourne le dos au pouvoir nécessaire pour faire de cette terre la nôtre complètement ! Nous ne sommes pas les mêmes gens qui ont été manipulés et utilisés par des créatures du Néant. Nous sommes notre propre peuple. Nous sommes fiers... et nous sommes forts.') ON DUPLICATE KEY UPDATE CompletionText='Finalement, tu es arrivé... et discrètement aussi. Bien.$b$Notre monde est rempli de fous, Asatokta. Même le puissant Thrall a des défauts plus grands que la plupart ne peuvent voir. Il tourne le dos au pouvoir nécessaire pour faire de cette terre la nôtre complètement ! Nous ne sommes pas les mêmes gens qui ont été manipulés et utilisés par des créatures du Néant. Nous sommes notre propre peuple. Nous sommes fiers... et nous sommes forts.';
-- Quest 3090 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3090, 'frFR', 'Et maintenant tu as rejoint nos rangs aussi. Ne te méprends pas, <name>. Le simple fait que tu aies accès à un pouvoir dont tant seront jaloux ne signifie pas que tu seras accepté facilement.  Hellscream permet à notre espèce d\'entrer dans Orgrimmar parce que nous sommes toujours ses semblables -- il ne peut pas nous tourner le dos, sinon nous deviendrions aussi pathétiques que les humains qui l\'ont asservi. Mon point est : sois prudent. Tu peux être puissant, mais si tu es stupide, alors tu es aussi bon que mort.') ON DUPLICATE KEY UPDATE RewardText='Et maintenant tu as rejoint nos rangs aussi. Ne te méprends pas, <name>. Le simple fait que tu aies accès à un pouvoir dont tant seront jaloux ne signifie pas que tu seras accepté facilement.  Hellscream permet à notre espèce d\'entrer dans Orgrimmar parce que nous sommes toujours ses semblables -- il ne peut pas nous tourner le dos, sinon nous deviendrions aussi pathétiques que les humains qui l\'ont asservi. Mon point est : sois prudent. Tu peux être puissant, mais si tu es stupide, alors tu es aussi bon que mort.';
-- Quest 3091 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3091, 'frFR', 'Ah, enfin, tu es arrivé, $C. Je n\'ai pas menti dans ma note, $N. Nous sommes aussi une race spéciale, pas contrairement aux druides ou aux shamans de notre tribu. Tu es tout aussi important. Nous sommes ceux qui sont appelés à défendre nos frontières, à chasser le centaure, et à faire la guerre.') ON DUPLICATE KEY UPDATE CompletionText='Ah, enfin, tu es arrivé, $C. Je n\'ai pas menti dans ma note, $N. Nous sommes aussi une race spéciale, pas contrairement aux druides ou aux shamans de notre tribu. Tu es tout aussi important. Nous sommes ceux qui sont appelés à défendre nos frontières, à chasser le centaure, et à faire la guerre.';
-- Quest 3092 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3092, 'frFR', 'Bienvenue au Camp Narache, $n. J\'ai de bonnes choses à ton sujet. Ta lignée est forte, et beaucoup des anciens te considèrent déjà comme compétent. Mais nous allons le tester.$b$Les plaines de Mulgore seront ta maison pour un temps -- tu devrais faire de ton mieux pour les connaître très bien. Un jour, tu voyageras vers des terres inconnues pour maîtriser des compétences plus grandes. Tu dois être prêt.') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue au Camp Narache, $n. J\'ai de bonnes choses à ton sujet. Ta lignée est forte, et beaucoup des anciens te considèrent déjà comme compétent. Mais nous allons le tester.$b$Les plaines de Mulgore seront ta maison pour un temps -- tu devrais faire de ton mieux pour les connaître très bien. Un jour, tu voyageras vers des terres inconnues pour maîtriser des compétences plus grandes. Tu dois être prêt.';
-- Quest 3092 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3092, 'frFR', 'Et c\'est mon travail de m\'assurer que tu es préparé en t\'enseignant les bases de notre profession -- comment domestiquer ton animal de compagnie, comment tirer avec ton fusil, et de nombreuses autres compétences qui deviendront nécessaires.$B$Les chasseurs sont une partie forte de notre tradition et de notre histoire, <name>. Tu ferais bien de te souvenir de l\'importance que tu as pour la tribu. Tu seras respecté et vénéré si tu sers bien notre peuple.') ON DUPLICATE KEY UPDATE RewardText='Et c\'est mon travail de m\'assurer que tu es préparé en t\'enseignant les bases de notre profession -- comment domestiquer ton animal de compagnie, comment tirer avec ton fusil, et de nombreuses autres compétences qui deviendront nécessaires.$B$Les chasseurs sont une partie forte de notre tradition et de notre histoire, <name>. Tu ferais bien de te souvenir de l\'importance que tu as pour la tribu. Tu seras respecté et vénéré si tu sers bien notre peuple.';

-- Quest 3093 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3093, 'frFR', 'Comme l\'eau tombe du ciel, vous êtes devant moi. Je suis ravi de votre hâte. Cela signifie que vous réalisez à la fois l\'importance de notre rencontre et votre présence ici. Je ne suis pas un leader, mais je comprends les éléments, et je peux parler aux esprits de notre peuple. Je vais vous apprendre à faire de même.') ON DUPLICATE KEY UPDATE CompletionText='Comme l\'eau tombe du ciel, vous êtes devant moi. Je suis ravi de votre hâte. Cela signifie que vous réalisez à la fois l\'importance de notre rencontre et votre présence ici. Je ne suis pas un leader, mais je comprends les éléments, et je peux parler aux esprits de notre peuple. Je vais vous apprendre à faire de même.';
-- Quest 3095 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3095, 'frFR', 'Ah, vous êtes arrivé. Bien. J\'ai entendu dire que quelques autres avaient réussi à échapper à la "mort" et se dirigeaient vers la ville. Peut-être que cette résilience portera ses fruits à l\'avenir également.$B$BVous pouvez remercier Sylvanas pour votre liberté... liberté d\'esprit et de corps. Bien que vous soyez toujours tourmenté par la peste et ses effets, vous êtes maintenant libre de venir et d\'aller comme vous le souhaitez.') ON DUPLICATE KEY UPDATE CompletionText='Ah, vous êtes arrivé. Bien. J\'ai entendu dire que quelques autres avaient réussi à échapper à la "mort" et se dirigeaient vers la ville. Peut-être que cette résilience portera ses fruits à l\'avenir également.$B$BVous pouvez remercier Sylvanas pour votre liberté... liberté d\'esprit et de corps. Bien que vous soyez toujours tourmenté par la peste et ses effets, vous êtes maintenant libre de venir et d\'aller comme vous le souhaitez.';
-- Quest 3097 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3097, 'frFR', 'Ah, donc entre le feu, la peste, les émeutes et bien pire, un autre des "fidèles" vient à ma porte. Eh bien, laissez-moi vous souhaiter la bienvenue, $C$. Et permettez-moi un instant pour vous expliquer quelques choses avant que vous ne décidiez qu\'il est temps pour vous de rechercher ce qui vous pousse : la Lumière Sainte ne vous concerne plus, les esprits de vos ancêtres sont des contes de fées, et les créatures du Nether ne veulent pas de vous.$b$bM\'entendez-vous jusqu\'à présent ?') ON DUPLICATE KEY UPDATE CompletionText='Ah, donc entre le feu, la peste, les émeutes et bien pire, un autre des "fidèles" vient à ma porte. Eh bien, laissez-moi vous souhaiter la bienvenue, $C$. Et permettez-moi un instant pour vous expliquer quelques choses avant que vous ne décidiez qu\'il est temps pour vous de rechercher ce qui vous pousse : la Lumière Sainte ne vous concerne plus, les esprits de vos ancêtres sont des contes de fées, et les créatures du Nether ne veulent pas de vous.$b$bM\'entendez-vous jusqu\'à présent ?';
-- Quest 3098 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3098, 'frFR', 'Je savais que vous viendriez me voir, $N$. Non pas parce que vous n\'avez pas la volonté de suivre votre propre chemin, mais parce que nous sommes des esprits similaires. Nous avons tous deux ressenti la douleur. Nous avons tous deux souffert. Et maintenant, nous voulons le pouvoir de reprendre ce que nous savons être le nôtre : cette terre, nos vies, nos destinées. Mais il y a encore beaucoup à apprendre pour vous.') ON DUPLICATE KEY UPDATE CompletionText='Je savais que vous viendriez me voir, $N$. Non pas parce que vous n\'avez pas la volonté de suivre votre propre chemin, mais parce que nous sommes des esprits similaires. Nous avons tous deux ressenti la douleur. Nous avons tous deux souffert. Et maintenant, nous voulons le pouvoir de reprendre ce que nous savons être le nôtre : cette terre, nos vies, nos destinées. Mais il y a encore beaucoup à apprendre pour vous.';
-- Quest 3100 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3100, 'frFR', 'Ah, vous avez reçu ma lettre, $N$... bien.$B$BIl y a eu un afflux de guerriers à Elwynn récemment - ce qui est bon pour Stormwind, mais mauvais pour les kobolds et les Defias dans la région.') ON DUPLICATE KEY UPDATE CompletionText='Ah, vous avez reçu ma lettre, $N$... bien.$B$BIl y a eu un afflux de guerriers à Elwynn récemment - ce qui est bon pour Stormwind, mais mauvais pour les kobolds et les Defias dans la région.';
-- Quest 3101 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3101, 'frFR', 'Enfin ! Nous nous rencontrons face à face, frère à frère. Je vous souhaite la bienvenue à Northshire. Ce sera votre foyer pour un court moment pendant que vous apprenez les rouages du fonctionnement des choses, mais sachez que Stormwind n\'est pas loin, et tôt ou tard, votre chemin vous y mènera. Mais d\'ici là, soyez patient... Chevalier de la Main d\'Argent.') ON DUPLICATE KEY UPDATE CompletionText='Enfin ! Nous nous rencontrons face à face, frère à frère. Je vous souhaite la bienvenue à Northshire. Ce sera votre foyer pour un court moment pendant que vous apprenez les rouages du fonctionnement des choses, mais sachez que Stormwind n\'est pas loin, et tôt ou tard, votre chemin vous y mènera. Mais d\'ici là, soyez patient... Chevalier de la Main d\'Argent.';
-- Quest 3101 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3101, 'frFR', 'En attendant, vous devriez savoir une ou deux autres choses. Vous êtes un symbole pour beaucoup ici dans cette terre--agissez en conséquence. La Lumière Sainte brille en vous, et cela sera évident pour vos alliés comme pour vos ennemis.$B$BDe plus, au fur et à mesure que vous gagnez en sagesse et en puissance, vous devrez vous entraîner pour apprendre de nouvelles capacités. C\'est là que j\'interviens. Lorsque vous sentirez avoir acquis une certaine expérience ici à Northshire, revenez-moi et je vous apprendrai ce que je crois que vous êtes prêt à apprendre. Bonne chance... <class>!') ON DUPLICATE KEY UPDATE RewardText='En attendant, vous devriez savoir une ou deux autres choses. Vous êtes un symbole pour beaucoup ici dans cette terre--agissez en conséquence. La Lumière Sainte brille en vous, et cela sera évident pour vos alliés comme pour vos ennemis.$B$BDe plus, au fur et à mesure que vous gagnez en sagesse et en puissance, vous devrez vous entraîner pour apprendre de nouvelles capacités. C\'est là que j\'interviens. Lorsque vous sentirez avoir acquis une certaine expérience ici à Northshire, revenez-moi et je vous apprendrai ce que je crois que vous êtes prêt à apprendre. Bonne chance... <class>!';
-- Quest 3102 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3102, 'frFR', 'Vous êtes arrivé en entier, et il ne semble pas que beaucoup de gens vous aient vu. Assez pour moi. Je n\'aime pas que beaucoup d\'attention soit attirée sur moi ici... tranquille et discret. Je suis sûr que vous pouvez comprendre.$b$bVous avez eu des problèmes jusqu\'à présent ? Je suis heureux de l\'entendre. Cela va changer bientôt.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes arrivé en entier, et il ne semble pas que beaucoup de gens vous aient vu. Assez pour moi. Je n\'aime pas que beaucoup d\'attention soit attirée sur moi ici... tranquille et discret. Je suis sûr que vous pouvez comprendre.$b$bVous avez eu des problèmes jusqu\'à présent ? Je suis heureux de l\'entendre. Cela va changer bientôt.';
-- Quest 3104 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3104, 'frFR', 'Bonjour, $N$. Je suis Khelden. Y a-t-il quelque chose que je puisse faire pour vous ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $N$. Je suis Khelden. Y a-t-il quelque chose que je puisse faire pour vous ?';
-- Quest 3106 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3106, 'frFR', 'Blast, il fait froid aujourd\'hui, n\'est-ce pas ? C\'est comme si la neige ne partait jamais, $N.$b$bVous l\'avez probablement déjà remarqué, mais il y a des gnomes qui vivent maintenant dans notre ville. C\'est parce qu\'ils se sont fait exploser leur propre foyer. Ne dites pas ça autour de vous, mais je ne peux pas les blâmer--je pense que j\'aurais aussi recours aux explosifs si Ironforge était infesté de Fer-noir ou du genre.') ON DUPLICATE KEY UPDATE CompletionText='Blast, il fait froid aujourd\'hui, n\'est-ce pas ? C\'est comme si la neige ne partait jamais, $N.$b$bVous l\'avez probablement déjà remarqué, mais il y a des gnomes qui vivent maintenant dans notre ville. C\'est parce qu\'ils se sont fait exploser leur propre foyer. Ne dites pas ça autour de vous, mais je ne peux pas les blâmer--je pense que j\'aurais aussi recours aux explosifs si Ironforge était infesté de Fer-noir ou du genre.';
-- Quest 3107 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3107, 'frFR', 'Alors, vous y êtes arrivé ! Et pas une seconde trop tôt. Il y a beaucoup à faire dans la Vallée de Coldridge et au-delà. J\'aurai besoin de votre aide autant que vous aurez besoin de la mienne !$B$BVous êtes un Chevalier de la Main d\'Argent maintenant, soyez prêt à jouer le rôle.') ON DUPLICATE KEY UPDATE CompletionText='Alors, vous y êtes arrivé ! Et pas une seconde trop tôt. Il y a beaucoup à faire dans la Vallée de Coldridge et au-delà. J\'aurai besoin de votre aide autant que vous aurez besoin de la mienne !$B$BVous êtes un Chevalier de la Main d\'Argent maintenant, soyez prêt à jouer le rôle.';
-- Quest 3109 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3109, 'frFR', 'Vous y êtes arrivé ! Super !$B$BNous avons eu un afflux d\'activité récemment, je suis donc heureux de compter un autre clan d\'Ironforge parmi nos membres. Trop d\'entre nous regardent l\'arcane et le divin pour mes propres goûts. Rien contre eux et leurs croyances, mais il n\'y a rien comme une lame froide dans votre main et une ombre pour vous éloigner de la lumière, vous voyez ce que je veux dire ?') ON DUPLICATE KEY UPDATE CompletionText='Vous y êtes arrivé ! Super !$B$BNous avons eu un afflux d\'activité récemment, je suis donc heureux de compter un autre clan d\'Ironforge parmi nos membres. Trop d\'entre nous regardent l\'arcane et le divin pour mes propres goûts. Rien contre eux et leurs croyances, mais il n\'y a rien comme une lame froide dans votre main et une ombre pour vous éloigner de la lumière, vous voyez ce que je veux dire ?';
-- Quest 3109 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3109, 'frFR', 'Quoi qu\'il en soit, lorsque vous commencerez à explorer Coldridge, vous aurez probablement besoin de vous entraîner à un moment donné. Revenez simplement-moi chaque fois que vous sentirez que vous en avez besoin et je vous apprendrai ce que je sais--une astuce ici, une manœuvre là. Vous savez, le truc qui vous maintient en vie et vous fait gagner un peu d\'argent supplémentaire.') ON DUPLICATE KEY UPDATE RewardText='Quoi qu\'il en soit, lorsque vous commencerez à explorer Coldridge, vous aurez probablement besoin de vous entraîner à un moment donné. Revenez simplement-moi chaque fois que vous sentirez que vous en avez besoin et je vous apprendrai ce que je sais--une astuce ici, une manœuvre là. Vous savez, le truc qui vous maintient en vie et vous fait gagner un peu d\'argent supplémentaire.';
-- Quest 3110 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3110, 'frFR', 'Ach ! Vous y êtes arrivé, $N$ ! Merveilleux !$B$Je voulais dire, j\'étais sur le point de perdre la foi que vous arriveriez... vous voyez, perdre la foi ? C\'est une blague, lass... oh, peu importe. Vous ne l\'êtes pas venu ici pour mes blagues nulles de toute façon.') ON DUPLICATE KEY UPDATE CompletionText='Ach ! Vous y êtes arrivé, $N$ ! Merveilleux !$B$Je voulais dire, j\'étais sur le point de perdre la foi que vous arriveriez... vous voyez, perdre la foi ? C\'est une blague, lass... oh, peu importe. Vous ne l\'êtes pas venu ici pour mes blagues nulles de toute façon.';
-- Quest 3110 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3110, 'frFR', 'Je suis celui qui peut vous entraîner lorsque vous commencerez à vous repérer dans la Vallée de Coldridge. Quand vous vous sentirez prêt, revenez-moi et nous verrons si nous pouvons vous apprendre un ou deux nouveaux sorts pour vous défendre contre ces troggs maudits.$B$Vous avez la Lumière de votre côté, ainsi que tout Ironforge, <name>... pas de pression pour devenir quelque chose de spécial.') ON DUPLICATE KEY UPDATE RewardText='Je suis celui qui peut vous entraîner lorsque vous commencerez à vous repérer dans la Vallée de Coldridge. Quand vous vous sentirez prêt, revenez-moi et nous verrons si nous pouvons vous apprendre un ou deux nouveaux sorts pour vous défendre contre ces troggs maudits.$B$Vous avez la Lumière de votre côté, ainsi que tout Ironforge, <name>... pas de pression pour devenir quelque chose de spécial.';

-- Quest 3113 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3113, 'frFR', 'Content de voir que tu as reçu mon message et que tu es venu. Désolé d\'avoir prétendu que c\'était un mémorandum de tes supérieurs... aucune offense intentionnelle. Je savais juste que nous deux, ainsi que d\'autres de notre espèce, devions rester unis.$B$BPas beaucoup pensent qu\'il y a de mieux au monde que de voir votre espèce et la mienne installées dans la même ville, mais je pense que nous pouvons nous arranger très bien. Qu\'en penses-tu ?') ON DUPLICATE KEY UPDATE CompletionText='Content de voir que tu as reçu mon message et que tu es venu. Désolé d\'avoir prétendu que c\'était un mémorandum de tes supérieurs... aucune offense intentionnelle. Je savais juste que nous deux, ainsi que d\'autres de notre espèce, devions rester unis.$B$BPas beaucoup pensent qu\'il y a de mieux au monde que de voir votre espèce et la mienne installées dans la même ville, mais je pense que nous pouvons nous arranger très bien. Qu\'en penses-tu ?';
-- Quest 3113 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3113, 'frFR', 'Je reste plutôt seul par ici pour qu\'on ne prenne pas mauvaise réputation pour les choses qui disparaissent, mais si tu as besoin de quoi que ce soit, d\'un entraînement ou quelque chose comme ça, reviens quand tu veux.$B$BToi et moi, on a un accord. On sait que quand ça se joue, tu ne peux faire confiance qu\'à ta famille... et c\'est ce qu\'on a ici, pas vrai ? Peu importe que Gnomeregan soit... envahi, et tout ce qui nous tombe dessus, on s\'entraide. Pas vrai ?') ON DUPLICATE KEY UPDATE RewardText='Je reste plutôt seul par ici pour qu\'on ne prenne pas mauvaise réputation pour les choses qui disparaissent, mais si tu as besoin de quoi que ce soit, d\'un entraînement ou quelque chose comme ça, reviens quand tu veux.$B$BToi et moi, on a un accord. On sait que quand ça se joue, tu ne peux faire confiance qu\'à ta famille... et c\'est ce qu\'on a ici, pas vrai ? Peu importe que Gnomeregan soit... envahi, et tout ce qui nous tombe dessus, on s\'entraide. Pas vrai ?';
-- Quest 3114 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3114, 'frFR', 'Ouais, c\'est quoi, $R ? Parle, si tu n\'y vois pas d\'inconvénient. Je n\'entends pas très bien après quelques bières.') ON DUPLICATE KEY UPDATE CompletionText='Ouais, c\'est quoi, $R ? Parle, si tu n\'y vois pas d\'inconvénient. Je n\'entends pas très bien après quelques bières.';
-- Quest 3114 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3114, 'frFR', 'Oh, oui ! Arts arcaniques... bien sûr.$b$bVoici ce que tu dois savoir, $N : Ne te mets pas trop en difficulté. Garde de l\'argent pour m\'acheter une bière... ou des sorts que tu pourrais vouloir. Et éloigne-toi du diable de Gnomeregan. Mis à part ça, passe une bonne journée ! Je serai là si tu as besoin de moi ou veux t\'entraîner... ou quoi que ce soit.') ON DUPLICATE KEY UPDATE RewardText='Oh, oui ! Arts arcaniques... bien sûr.$b$bVoici ce que tu dois savoir, $N : Ne te mets pas trop en difficulté. Garde de l\'argent pour m\'acheter une bière... ou des sorts que tu pourrais vouloir. Et éloigne-toi du diable de Gnomeregan. Mis à part ça, passe une bonne journée ! Je serai là si tu as besoin de moi ou veux t\'entraîner... ou quoi que ce soit.';
-- Quest 3115 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3115, 'frFR', 'Merveilleux ! Tu as mon mémorandum évidemment.$b$bIgnore les fous autour de toi, $N. La Lumière Sainte ?! L\'épée et le bouclier ?! Ce ne sont pas des chemins pour des gens aussi ouverts d\'esprit que nous. Regarde ce que la magie "normale" a fait à notre foyer. Couplé avec ces maudits ingénieurs, notre race a failli disparaître. Et maintenant nous devons compter sur les nains -- ils préfèrent passer du temps à s\'allier aux humains plutôt qu\'à nous aider à reconstruire notre propre foyer. Nous sommes comme des citoyens de seconde zone. As-tu vu comment ils nous regardent ?') ON DUPLICATE KEY UPDATE CompletionText='Merveilleux ! Tu as mon mémorandum évidemment.$b$bIgnore les fous autour de toi, $N. La Lumière Sainte ?! L\'épée et le bouclier ?! Ce ne sont pas des chemins pour des gens aussi ouverts d\'esprit que nous. Regarde ce que la magie "normale" a fait à notre foyer. Couplé avec ces maudits ingénieurs, notre race a failli disparaître. Et maintenant nous devons compter sur les nains -- ils préfèrent passer du temps à s\'allier aux humains plutôt qu\'à nous aider à reconstruire notre propre foyer. Nous sommes comme des citoyens de seconde zone. As-tu vu comment ils nous regardent ?';
-- Quest 3115 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3115, 'frFR', 'Mais rien de tout cela n\'a d\'importance. Ce qui compte, c\'est que tu aies vu ta propre Lumière Sainte ! Tu sais d\'où vient vraiment le pouvoir. Tu réalises qu\'avoir nos propres alliés est beaucoup plus... prudent. Des alliés spéciaux. Des alliés qui, quel que soit la tâche, obéiront jusqu\'à leur dernier souffle.$B$BEt c\'est là que j\'interviens, <name>. Je peux t\'entraîner aux débuts de ces pouvoirs spéciaux. Cherche-moi souvent et je ferai de mon mieux pour t\'apprendre plus de sorts.') ON DUPLICATE KEY UPDATE RewardText='Mais rien de tout cela n\'a d\'importance. Ce qui compte, c\'est que tu aies vu ta propre Lumière Sainte ! Tu sais d\'où vient vraiment le pouvoir. Tu réalises qu\'avoir nos propres alliés est beaucoup plus... prudent. Des alliés spéciaux. Des alliés qui, quel que soit la tâche, obéiront jusqu\'à leur dernier souffle.$B$BEt c\'est là que j\'interviens, <name>. Je peux t\'entraîner aux débuts de ces pouvoirs spéciaux. Cherche-moi souvent et je ferai de mon mieux pour t\'apprendre plus de sorts.';
-- Quest 3116 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3116, 'frFR', 'Tu y es arrivé. Je suis tellement content.$b$bBeaucoup s\'est passé au cours des dernières années, $N : la création de Teldrassil, la corruption de beaucoup des créatures de la forêt ici et à l\'étranger, la découverte de terres que nous pensions perdues comme Feralas... tant de choses, en si peu de temps. Mais ce ne sont que quelques raisons pour lesquelles nous sommes ici, la plus importante étant de protéger notre espèce contre un mal plus grand.') ON DUPLICATE KEY UPDATE CompletionText='Tu y es arrivé. Je suis tellement content.$b$bBeaucoup s\'est passé au cours des dernières années, $N : la création de Teldrassil, la corruption de beaucoup des créatures de la forêt ici et à l\'étranger, la découverte de terres que nous pensions perdues comme Feralas... tant de choses, en si peu de temps. Mais ce ne sont que quelques raisons pour lesquelles nous sommes ici, la plus importante étant de protéger notre espèce contre un mal plus grand.';
-- Quest 3116 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3116, 'frFR', 'Bientôt, tu verras d\'autres de différentes races dans les branches de notre foyer -- ne laisse pas cela créer de préjugés en toi. Ils sont les bienvenus. Ils nous aideront quand ils pourront. Tous ne seront pas altruistes, mais ils devraient se voir accorder un certain niveau de confiance.$B$BMais rien de tout cela n\'a d\'importance maintenant. Nous devons nous concentrer sur toi, et sur la façon dont tu peux aider notre peuple. Je suis là à cet effet même. Je t\'entraînerai dans les voies d\'un <class> à mesure que tu deviendras plus fort. Reviens quand tu veux et je ferai de mon mieux pour t\'aider.') ON DUPLICATE KEY UPDATE RewardText='Bientôt, tu verras d\'autres de différentes races dans les branches de notre foyer -- ne laisse pas cela créer de préjugés en toi. Ils sont les bienvenus. Ils nous aideront quand ils pourront. Tous ne seront pas altruistes, mais ils devraient se voir accorder un certain niveau de confiance.$B$BMais rien de tout cela n\'a d\'importance maintenant. Nous devons nous concentrer sur toi, et sur la façon dont tu peux aider notre peuple. Je suis là à cet effet même. Je t\'entraînerai dans les voies d\'un <class> à mesure que tu deviendras plus fort. Reviens quand tu veux et je ferai de mon mieux pour t\'aider.';
-- Quest 3117 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3117, 'frFR', 'Tu es arrivé, et pas trop tôt, $N. Bienvenue à Shadowglen.$B$BFais confiance à mon sceau qui t\'a trouvé en bonne santé et en bonne humeur?$B$BComme je l\'ai dit précédemment, je suis là pour t\'entraîner en tant que $C ; à dompter des bêtes pour t\'aider au combat ; à utiliser un arc avec une précision infaillible ; à respecter les terres que nous appelons foyer et aussi les terres au-delà.') ON DUPLICATE KEY UPDATE CompletionText='Tu es arrivé, et pas trop tôt, $N. Bienvenue à Shadowglen.$B$BFais confiance à mon sceau qui t\'a trouvé en bonne santé et en bonne humeur?$B$BComme je l\'ai dit précédemment, je suis là pour t\'entraîner en tant que $C ; à dompter des bêtes pour t\'aider au combat ; à utiliser un arc avec une précision infaillible ; à respecter les terres que nous appelons foyer et aussi les terres au-delà.';
-- Quest 3118 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3118, 'frFR', 'Bonjour, $n. Je suis content que tu m\'aies trouvé. Je pensais que peut-être tu t\'étais perdu en venant ici.$B$BNrien de vraiment nouveau ne s\'est passé à Shadowglen depuis que je t\'ai envoyé mon sceau, mais je laisserai la collecte de toutes les informations à ton compte. Parle au reste des gens autour d\'Aldrassil si tu veux.') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $n. Je suis content que tu m\'aies trouvé. Je pensais que peut-être tu t\'étais perdu en venant ici.$B$BNrien de vraiment nouveau ne s\'est passé à Shadowglen depuis que je t\'ai envoyé mon sceau, mais je laisserai la collecte de toutes les informations à ton compte. Parle au reste des gens autour d\'Aldrassil si tu veux.';
-- Quest 3119 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3119, 'frFR', 'Je suis ravi de voir que tu es arrivé si vite, $N. Bienvenue.$b$bComme tu l\'as probablement entendu, tout Teldrassil s\'agite avec les arrivées et les départs des voyageurs. Même des membres de l\'Alliance ont été autorisés à accéder aux branches de Teldrassil afin de rencontrer d\'autres Kaldorei qui se préparent aux aventures à venir.') ON DUPLICATE KEY UPDATE CompletionText='Je suis ravi de voir que tu es arrivé si vite, $N. Bienvenue.$b$bComme tu l\'as probablement entendu, tout Teldrassil s\'agite avec les arrivées et les départs des voyageurs. Même des membres de l\'Alliance ont été autorisés à accéder aux branches de Teldrassil afin de rencontrer d\'autres Kaldorei qui se préparent aux aventures à venir.';
-- Quest 3126 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3126, 'frFR', 'As-tu réussi à capturer les marcheurs forestiers errants ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à capturer les marcheurs forestiers errants ?';
-- Quest 3126 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3126, 'frFR', 'Merci, <name>. Notre collection de muisek est presque complète.') ON DUPLICATE KEY UPDATE RewardText='Merci, <name>. Notre collection de muisek est presque complète.';
-- Quest 3127 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3127, 'frFR', 'As-tu réussi à capturer les géants de la montagne ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à capturer les géants de la montagne ?';
-- Quest 3127 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3127, 'frFR', 'Imagine juste les possibilités de ce que nous possédons maintenant, <name>. Avec les matériaux que tu as collectés, je pourrai emprisonner à jamais les muisek de ces créatures dans ce que je veux.') ON DUPLICATE KEY UPDATE RewardText='Imagine juste les possibilités de ce que nous possédons maintenant, <name>. Avec les matériaux que tu as collectés, je pourrai emprisonner à jamais les muisek de ces créatures dans ce que je veux.';

-- Quest 3182 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3182, 'frFR', 'Bonjour ma jeune dame. Voulez-vous une visite du musée ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour ma jeune dame. Voulez-vous une visite du musée ?';
-- Quest 3182 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3182, 'frFR', 'Qu\'est-ce que c\'est ? $B$Oh là là, je n\'y crois pas ! Savez-vous ce que vous avez là, $R$? Ceci est la corne de Margol la Furieuse ! Margol, le fléau de tout archéologue qui a jamais mis les pieds dans le Gouffre Brûlant.$B$Puis-je la garder ?') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est ? $B$Oh là là, je n\'y crois pas ! Savez-vous ce que vous avez là, $R$? Ceci est la corne de Margol la Furieuse ! Margol, le fléau de tout archéologue qui a jamais mis les pieds dans le Gouffre Brûlant.$B$Puis-je la garder ?';
-- Quest 3321 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3321, 'frFR', 'Aujourd\'hui, nous finalisons notre célébration de votre engagement envers l\'Ordre.') ON DUPLICATE KEY UPDATE CompletionText='Aujourd\'hui, nous finalisons notre célébration de votre engagement envers l\'Ordre.';
-- Quest 3362 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3362, 'frFR', 'J\'aimerais regarder de plus près ce cactus dans la vallée... Alors, laissez-en un morceau, d\'accord ?') ON DUPLICATE KEY UPDATE CompletionText='J\'aimerais regarder de plus près ce cactus dans la vallée... Alors, laissez-en un morceau, d\'accord ?';
-- Quest 3363 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3363, 'frFR', 'Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur chantante. Une odeur nauséabonde et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur chantante. Une odeur nauséabonde et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.';
-- Quest 3363 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3363, 'frFR', 'Vous appliquez une pommade de plante de Cenarion sur la fleur chantante. Elle commence immédiatement à perdre sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez une pommade de plante de Cenarion sur la fleur chantante. Elle commence immédiatement à perdre sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
-- Quest 3374 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3374, 'frFR', 'Nous voici $N$, à un autre carrefour. Il est temps de faire un autre choix. Quel choix faites-vous, mortel ?') ON DUPLICATE KEY UPDATE CompletionText='Nous voici $N$, à un autre carrefour. Il est temps de faire un autre choix. Quel choix faites-vous, mortel ?';
-- Quest 3374 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3374, 'frFR', 'Vous avez fait votre choix, et c\'est ainsi que cela commence.  Vos choix ont été, jusqu\'à présent, ce que j\'appellerais les bons ; vos actions et vos actes détermineront désormais si cela doit continuer.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait votre choix, et c\'est ainsi que cela commence.  Vos choix ont été, jusqu\'à présent, ce que j\'appellerais les bons ; vos actions et vos actes détermineront désormais si cela doit continuer.';
-- Quest 3375 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3375, 'frFR', 'Pour faire un autre flacon, j\'ai besoin d\'une potion de mana, d\'un morceau de charbon et de un peu de nectar sucré.$B$BÇa, et beaucoup de patience apparemment.') ON DUPLICATE KEY UPDATE CompletionText='Pour faire un autre flacon, j\'ai besoin d\'une potion de mana, d\'un morceau de charbon et de un peu de nectar sucré.$B$BÇa, et beaucoup de patience apparemment.';
-- Quest 3375 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3375, 'frFR', 'Le vaillant aventurier livre.  Hooray pour moi.  Au fait, j\'ai menti - j\'avais un autre flacon.  Ungh, prenez-le.$B$BEh bien, à quoi vous attendiez-vous ?! "Oh, voici, en prenez un autre !  Je ne suis qu\'un idiot qui n\'a rien de mieux à faire que de distribuer des dispositifs de communication magiques aux aventuriers !" Soyez assuré cependant, ce que vous m\'avez donné sera suffisant pour vous faire un autre flacon lorsque vous perdrez celui-là.$B$BS\'il vous plaît, prouvez-moi le contraire et ne perdez pas le nouveau, d\'accord ?') ON DUPLICATE KEY UPDATE RewardText='Le vaillant aventurier livre.  Hooray pour moi.  Au fait, j\'ai menti - j\'avais un autre flacon.  Ungh, prenez-le.$B$BEh bien, à quoi vous attendiez-vous ?! "Oh, voici, en prenez un autre !  Je ne suis qu\'un idiot qui n\'a rien de mieux à faire que de distribuer des dispositifs de communication magiques aux aventuriers !" Soyez assuré cependant, ce que vous m\'avez donné sera suffisant pour vous faire un autre flacon lorsque vous perdrez celui-là.$B$BS\'il vous plaît, prouvez-moi le contraire et ne perdez pas le nouveau, d\'accord ?';
-- Quest 3378 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3378, 'frFR', 'Qu\'est-ce qui vous amène au Temple de la Lune, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui vous amène au Temple de la Lune, $N$?';
-- Quest 3379 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3379, 'frFR', 'Excellent travail, <name>.$B$Je suis sûr que ceci est un morceau de tissu d\'ombre que vous n\'avez pas encore vu.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>.$B$Je suis sûr que ceci est un morceau de tissu d\'ombre que vous n\'avez pas encore vu.';
-- Quest 3381 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3381, 'frFR', 'Je reste ici sur ordre de mon maître. On m\'a donné l\'autorisation de demander n\'importe quel prix pour le transport jusqu\'à sa tour. Pour l\'instant, je demande seulement les deux plumes de chaque voyageur afin que je puisse continuer à fabriquer mes flèches de signature.$b$bSi vous n\'êtes pas prudent, j\'augmenterai le prix. Comment voyez-vous un demi-douzaine d\'or?$b$bOui, je le pensais. Faites juste attention et je garderai le prix tel quel.') ON DUPLICATE KEY UPDATE CompletionText='Je reste ici sur ordre de mon maître. On m\'a donné l\'autorisation de demander n\'importe quel prix pour le transport jusqu\'à sa tour. Pour l\'instant, je demande seulement les deux plumes de chaque voyageur afin que je puisse continuer à fabriquer mes flèches de signature.$b$bSi vous n\'êtes pas prudent, j\'augmenterai le prix. Comment voyez-vous un demi-douzaine d\'or?$b$bOui, je le pensais. Faites juste attention et je garderai le prix tel quel.';
-- Quest 3381 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3381, 'frFR', 'Deux plumes, comme je l\'ai demandé. Et pas de mauvais du tout.$b$bPrêt alors ? Dites juste le mot et vous êtes en route.$b$bOh, et une fois de plus, faites attention... mon maître n\'aime pas les imbéciles, mais il est très généreux envers ceux qui lui plaisent.') ON DUPLICATE KEY UPDATE RewardText='Deux plumes, comme je l\'ai demandé. Et pas de mauvais du tout.$b$bPrêt alors ? Dites juste le mot et vous êtes en route.$b$bOh, et une fois de plus, faites attention... mon maître n\'aime pas les imbéciles, mais il est très généreux envers ceux qui lui plaisent.';
-- Quest 3382 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3382, 'frFR', 'Ce sera un combat difficile...') ON DUPLICATE KEY UPDATE CompletionText='Ce sera un combat difficile...';

-- Quest 3385 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3385, 'frFR', 'Vous avez porté un coup décisif au Marché souterrain. Leurs dirigeants réfléchiront à deux fois avant d\'envoyer plus de cronies dans la gorge.$B$Oh, et je n\'ai rien trouvé d\'utile dans la sacoche du marchand. Vous pouvez garder ce que vous trouvez à l\'intérieur.') ON DUPLICATE KEY UPDATE RewardText='Vous avez porté un coup décisif au Marché souterrain. Leurs dirigeants réfléchiront à deux fois avant d\'envoyer plus de cronies dans la gorge.$B$Oh, et je n\'ai rien trouvé d\'utile dans la sacoche du marchand. Vous pouvez garder ce que vous trouvez à l\'intérieur.';
-- Quest 3402 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3402, 'frFR', 'Kovic tué??! C\'est un jour glorieux, <name>! Pendant des années, ce salaud a mené des affaires louches dans le marché souterrain, sous-cotant des marchands honnêtes et travailleurs du monde entier.$B$BVous méritez une belle récompense pour cet exploit! Et une belle récompense vous sera donnée!') ON DUPLICATE KEY UPDATE RewardText='Kovic tué??! C\'est un jour glorieux, <name>! Pendant des années, ce salaud a mené des affaires louches dans le marché souterrain, sous-cotant des marchands honnêtes et travailleurs du monde entier.$B$BVous méritez une belle récompense pour cet exploit! Et une belle récompense vous sera donnée!';
-- Quest 3421 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3421, 'frFR', 'Je vous ramènerai au camp de Sanath maintenant.$B$BNe vous inquiétez pas de ses mauvaises manières--il est impoli envers tout le monde sauf le maître. Peut-être qu\'il apprendra sa leçon un jour.') ON DUPLICATE KEY UPDATE RewardText='Je vous ramènerai au camp de Sanath maintenant.$B$BNe vous inquiétez pas de ses mauvaises manières--il est impoli envers tout le monde sauf le maître. Peut-être qu\'il apprendra sa leçon un jour.';
-- Quest 3444 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3444, 'frFR', 'Ratchet n\'est pas loin, $N. Le voyage ne devrait pas prendre longtemps.') ON DUPLICATE KEY UPDATE CompletionText='Ratchet n\'est pas loin, $N. Le voyage ne devrait pas prendre longtemps.';
-- Quest 3444 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3444, 'frFR', 'Oui... C\'est cette pierre.$B$BTout me revient maintenant, <name>...') ON DUPLICATE KEY UPDATE RewardText='Oui... C\'est cette pierre.$B$BTout me revient maintenant, <name>...';
-- Quest 3450 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3450, 'frFR', 'Que puis-je faire pour vous, <name>? Je suis un peu occupé en ce moment à préparer mon vaisseau pour un long voyage. Je suis juste passé voir certains des pilotes de réservoir--j\'ai besoin de crinières de wendigo pour tapisser mon cockpit et ils en ont généralement des surplus.$B$Je peux vous accorder une minute si vous êtes bref... un des gars vient de partir au dépôt de Steelgrill pour voir si les pilotes là-bas ont des crinières en surplus pour moi.') ON DUPLICATE KEY UPDATE RewardText='Que puis-je faire pour vous, <name>? Je suis un peu occupé en ce moment à préparer mon vaisseau pour un long voyage. Je suis juste passé voir certains des pilotes de réservoir--j\'ai besoin de crinières de wendigo pour tapisser mon cockpit et ils en ont généralement des surplus.$B$Je peux vous accorder une minute si vous êtes bref... un des gars vient de partir au dépôt de Steelgrill pour voir si les pilotes là-bas ont des crinières en surplus pour moi.';
-- Quest 3453 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3453, 'frFR', 'Ne pas interrompre le processus de canalisation.') ON DUPLICATE KEY UPDATE CompletionText='Ne pas interrompre le processus de canalisation.';
-- Quest 3483 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3483, 'frFR', 'Ah, un autre fusil à signal, hein? Ça, je peux le faire.$B$BEt n\'oubliez pas, bout sud d\'Azshara. C\'est une petite île qui a été transformée en plateforme d\'atterrissage. Vous ne pouvez pas la manquer si vous êtes au bon endroit.') ON DUPLICATE KEY UPDATE RewardText='Ah, un autre fusil à signal, hein? Ça, je peux le faire.$B$BEt n\'oubliez pas, bout sud d\'Azshara. C\'est une petite île qui a été transformée en plateforme d\'atterrissage. Vous ne pouvez pas la manquer si vous êtes au bon endroit.';
-- Quest 3503 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3503, 'frFR', 'Il fut un temps où je pouvais demander ce que je voulais à ceux qui cherchaient mon maître. Mais maintenant, vous n\'avez qu\'à demander et je vous l\'enverrai.$b$bCela me chagrine, mais je ne conteste pas ses ordres. Je ne peux que prendre plaisir à me moquer des vêtements ridicules que vous portez ou de l\'air pathétique sur votre visage. Même ça m\'ennuie...$b$bMême ce bavardage m\'ennuie! Voulez-vous voir mon maître ou pas?') ON DUPLICATE KEY UPDATE RewardText='Il fut un temps où je pouvais demander ce que je voulais à ceux qui cherchaient mon maître. Mais maintenant, vous n\'avez qu\'à demander et je vous l\'enverrai.$b$bCela me chagrine, mais je ne conteste pas ses ordres. Je ne peux que prendre plaisir à me moquer des vêtements ridicules que vous portez ou de l\'air pathétique sur votre visage. Même ça m\'ennuie...$b$bMême ce bavardage m\'ennuie! Voulez-vous voir mon maître ou pas?';
-- Quest 3505 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3505, 'frFR', 'Le titre du livre est gravé sur la couverture de cuir noir en feuille d\'or--Tome de l\'invocation de Kaldorei. Lorsque vous ouvrez les pages, vous voyez que le livre est très vieux mais en superbe état.$b$bVous supposez que le texte est une langue ancienne... peut-être Kaldorei?$b$bVos instincts vous disent que vous devriez revenir ici une fois que vous aurez fini de rendre la pareille aux elfes du sang pour leur trahison.') ON DUPLICATE KEY UPDATE CompletionText='Le titre du livre est gravé sur la couverture de cuir noir en feuille d\'or--Tome de l\'invocation de Kaldorei. Lorsque vous ouvrez les pages, vous voyez que le livre est très vieux mais en superbe état.$b$bVous supposez que le texte est une langue ancienne... peut-être Kaldorei?$b$bVos instincts vous disent que vous devriez revenir ici une fois que vous aurez fini de rendre la pareille aux elfes du sang pour leur trahison.';
-- Quest 3506 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3506, 'frFR', 'Comment se passe votre massacre des traîtres elfes du sang, $N? Avez-vous fait des progrès?$b$BJ\'espère que vous êtes celui qui est assez fort pour mettre ce chien à genoux! Elle ne mérite rien d\'autre qu\'une mort douloureuse pour tout ce qu\'elle a fait!') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe votre massacre des traîtres elfes du sang, $N? Avez-vous fait des progrès?$b$BJ\'espère que vous êtes celui qui est assez fort pour mettre ce chien à genoux! Elle ne mérite rien d\'autre qu\'une mort douloureuse pour tout ce qu\'elle a fait!';
-- Quest 3506 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3506, 'frFR', 'RAR!! Incroyable!$B$BVous avez réussi! Belgrom sera ravi! Enfin les esprits de des dizaines de nos guerriers peuvent être en paix. Merci, <name>.') ON DUPLICATE KEY UPDATE RewardText='RAR!! Incroyable!$B$BVous avez réussi! Belgrom sera ravi! Enfin les esprits de des dizaines de nos guerriers peuvent être en paix. Merci, <name>.';
-- Quest 3510 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3510, 'frFR', 'Finalement, quelqu\'un digne de la sagesse d\'Arkkoroc!') ON DUPLICATE KEY UPDATE RewardText='Finalement, quelqu\'un digne de la sagesse d\'Arkkoroc!';
-- Quest 3511 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3511, 'frFR', 'Vous revenez! Étonnant, $R. Avez-vous découvert le vrai nom?') ON DUPLICATE KEY UPDATE CompletionText='Vous revenez! Étonnant, $R. Avez-vous découvert le vrai nom?';
-- Quest 3511 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3511, 'frFR', 'Le tempérament ajoutera le vitriol nécessaire pour la forge des armes. Il ne reste qu\'une étape de leur création.') ON DUPLICATE KEY UPDATE RewardText='Le tempérament ajoutera le vitriol nécessaire pour la forge des armes. Il ne reste qu\'une étape de leur création.';

-- Quest 3512 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3512, 'frFR', 'Itharius a eu sagesse de m\'envoyer auprès de moi.  Alors qu\'il n\'est pas mort au sens où vous comprenez la mort, Eranikus nous donnera bientôt des conseils en ses propres mots.  Pour l\'instant cependant, je ne peux pas vous aider directement... pas encore.$B$BI vous prêterai mon savoir sur le langage de la mort, mais d\'abord, j\'ai besoin de l\'aide de quelqu\'un qui - contrairement à moi - n\'est pas limité par les faiblesses de la vieillesse.  Mon dispositif d\'augure le plus puissant m\'a été pris contre ma volonté, et à moins que je ne l\'aie récupéré, nous serons sans recours pour aider Eranikus.') ON DUPLICATE KEY UPDATE RewardText='Itharius a eu sagesse de m\'envoyer auprès de moi.  Alors qu\'il n\'est pas mort au sens où vous comprenez la mort, Eranikus nous donnera bientôt des conseils en ses propres mots.  Pour l\'instant cependant, je ne peux pas vous aider directement... pas encore.$B$BI vous prêterai mon savoir sur le langage de la mort, mais d\'abord, j\'ai besoin de l\'aide de quelqu\'un qui - contrairement à moi - n\'est pas limité par les faiblesses de la vieillesse.  Mon dispositif d\'augure le plus puissant m\'a été pris contre ma volonté, et à moins que je ne l\'aie récupéré, nous serons sans recours pour aider Eranikus.';
-- Quest 3514 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3514, 'frFR', 'Nous ne pouvons pas permettre à l\'Alliance sur notre terre, $N$. Faites-le savoir.') ON DUPLICATE KEY UPDATE CompletionText='Nous ne pouvons pas permettre à l\'Alliance sur notre terre, $N$. Faites-le savoir.';
-- Quest 3520 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3520, 'frFR', 'Avez-vous collecté l\'essence des esprits hurleurs, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous collecté l\'essence des esprits hurleurs, $N$?';
-- Quest 3522 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3522, 'frFR', 'Oh... $N$, je suis si heureux que vous soyez revenu.') ON DUPLICATE KEY UPDATE CompletionText='Oh... $N$, je suis si heureux que vous soyez revenu.';
-- Quest 3522 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3522, 'frFR', 'Qu\'est-ce que c\'est, $N$?b$bOh, je savais que Dirania pourrait m\'aider !$b$b<Iverron boit l\'antidote>$b$bJe tombe toujours dans des ennuis et Dirania, eh bien, elle réussit toujours à m\'en sortir.$b$bJe me sens beaucoup mieux, mais je pense que je vais rester ici un peu plus longtemps, jusqu\'à ce que je me sente complètement rétabli. Eh bien, ça, et j\'espérais que vous me dégageriez un chemin à travers ces arachnides vicieux de Webwood...') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est, $N$?b$bOh, je savais que Dirania pourrait m\'aider !$b$b<Iverron boit l\'antidote>$b$bJe tombe toujours dans des ennuis et Dirania, eh bien, elle réussit toujours à m\'en sortir.$b$bJe me sens beaucoup mieux, mais je pense que je vais rester ici un peu plus longtemps, jusqu\'à ce que je me sente complètement rétabli. Eh bien, ça, et j\'espérais que vous me dégageriez un chemin à travers ces arachnides vicieux de Webwood...';
-- Quest 3526 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3526, 'frFR', 'Je peux sentir les recrues fraîches tout comme je peux sentir un excellent poudre à explosion - à un kilomètre. Êtes-vous venu chercher à apprendre la maîtrise de l\'explosion ?') ON DUPLICATE KEY UPDATE CompletionText='Je peux sentir les recrues fraîches tout comme je peux sentir un excellent poudre à explosion - à un kilomètre. Êtes-vous venu chercher à apprendre la maîtrise de l\'explosion ?';
-- Quest 3526 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3526, 'frFR', 'Eh bien $N$, vous avez eu sagesse de chercher mon enseignement ! N\'importe quel clochard peut devenir un expert dans les bases de l\'ingénierie - les gnomes et leur foyer irradié de Gnomeregan en sont la preuve. Il faut cependant un esprit fort et une main stable (accent sur STABLE) pour maîtriser la discipline de l\'ingénierie des Gobelins.$B$BGardez vos oreilles ouvertes $N$, et vous pourriez apprendre quelque chose.') ON DUPLICATE KEY UPDATE RewardText='Eh bien $N$, vous avez eu sagesse de chercher mon enseignement ! N\'importe quel clochard peut devenir un expert dans les bases de l\'ingénierie - les gnomes et leur foyer irradié de Gnomeregan en sont la preuve. Il faut cependant un esprit fort et une main stable (accent sur STABLE) pour maîtriser la discipline de l\'ingénierie des Gobelins.$B$BGardez vos oreilles ouvertes $N$, et vous pourriez apprendre quelque chose.';
-- Quest 3527 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3527, 'frFR', 'Avez-vous les tablettes de la Prophétie de Mosh\'aru, $N$?b$bQuand j\'aurai les tablettes, je les étudierai, et j\'apprendrai comment contenir l\'essence de Hakkar !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les tablettes de la Prophétie de Mosh\'aru, $N$?b$bQuand j\'aurai les tablettes, je les étudierai, et j\'apprendrai comment contenir l\'essence de Hakkar !';
-- Quest 3528 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3528, 'frFR', 'Avez-vous vaincu l\'avatar de Hakkar, $N$? Son essence a-t-elle déjà donné du pouvoir à l\'œuf que je vous ai donné ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous vaincu l\'avatar de Hakkar, $N$? Son essence a-t-elle déjà donné du pouvoir à l\'œuf que je vous ai donné ?';
-- Quest 3528 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3528, 'frFR', 'L\'essence de Hakkar a été collectée !  Même maintenant l\'Œuf s\'agite de vie !  Les mythes de Hakkar pourraient-ils être vrais?$B$BCela ne doit pas être vrai, car c\'est alors que je crains ce que Hakkar pourrait faire s\'il était à nouveau engendré.  Je garderai cet œuf en sécurité et veillerai à ce qu\'il ne tombe pas entre de mauvaises mains.$B$BVos labeurs avec moi sont terminés, <name>.  Vous avez touché une légende, et vos actions pourraient un jour changer le visage de notre monde.') ON DUPLICATE KEY UPDATE RewardText='L\'essence de Hakkar a été collectée !  Même maintenant l\'Œuf s\'agite de vie !  Les mythes de Hakkar pourraient-ils être vrais?$B$BCela ne doit pas être vrai, car c\'est alors que je crains ce que Hakkar pourrait faire s\'il était à nouveau engendré.  Je garderai cet œuf en sécurité et veillerai à ce qu\'il ne tombe pas entre de mauvaises mains.$B$BVos labeurs avec moi sont terminés, <name>.  Vous avez touché une légende, et vos actions pourraient un jour changer le visage de notre monde.';
-- Quest 3564 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3564, 'frFR', 'Avez-vous rencontré Andron ? Il quitte rarement l\'Undercity, donc je ne pense pas qu\'il soit trop difficile de le trouver.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous rencontré Andron ? Il quitte rarement l\'Undercity, donc je ne pense pas qu\'il soit trop difficile de le trouver.';
-- Quest 3564 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3564, 'frFR', 'Parfait... attendez une minute.$B$BHaha ! Qu\'est-ce que vous lui avez dit quand vous lui avez remis la tablette, <name>? Il nous a trop trop payés ! Pas comme si je me plaignais. Lui avez-vous dit que l\'accord avait changé ? Ou était-il ivre encore?$B$BÇa n\'a pas d\'importance... voici, prenez une part supplémentaire aussi.') ON DUPLICATE KEY UPDATE RewardText='Parfait... attendez une minute.$B$BHaha ! Qu\'est-ce que vous lui avez dit quand vous lui avez remis la tablette, <name>? Il nous a trop trop payés ! Pas comme si je me plaignais. Lui avez-vous dit que l\'accord avait changé ? Ou était-il ivre encore?$B$BÇa n\'a pas d\'importance... voici, prenez une part supplémentaire aussi.';
-- Quest 3567 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3567, 'frFR', 'Voulez-vous voir la vue au sommet de l\'un des colosses jumeaux ? Je peux vous y emmener, $R.$B$BConsidérez cependant comment vous allez descendre. C\'est un aller simple.') ON DUPLICATE KEY UPDATE RewardText='Voulez-vous voir la vue au sommet de l\'un des colosses jumeaux ? Je peux vous y emmener, $R.$B$BConsidérez cependant comment vous allez descendre. C\'est un aller simple.';
-- Quest 3568 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3568, 'frFR', 'Vous savez où cela mène, n\'est-ce pas, $N$? Il n\'y a aucun moyen qu\'elle survive... regardez-la. Le mieux pour elle maintenant est de nous aider à trouver un remède au fléau. Cette eau qu\'elle a bue pourrait contenir un indice qui nous aidera à comprendre comment. Elle va mourir de toute façon -- elle pourrait aussi bien mourir en faisant quelque chose de noble pour notre peuple avant de le faire. Vous êtes d\'accord ?') ON DUPLICATE KEY UPDATE CompletionText='Vous savez où cela mène, n\'est-ce pas, $N$? Il n\'y a aucun moyen qu\'elle survive... regardez-la. Le mieux pour elle maintenant est de nous aider à trouver un remède au fléau. Cette eau qu\'elle a bue pourrait contenir un indice qui nous aidera à comprendre comment. Elle va mourir de toute façon -- elle pourrait aussi bien mourir en faisant quelque chose de noble pour notre peuple avant de le faire. Vous êtes d\'accord ?';

-- Quest 3570 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3570, 'frFR', 'Tu sais où cela mène, $N ? Il n\'y a aucun moyen qu\'elle survive... regarde-la. Le meilleur pour elle maintenant est de nous aider à trouver un remède au fléau. Cette eau qu\'elle a bue pourrait contenir une piste qui nous aidera à comprendre comment. Elle va mourir de toute façon -- elle vaut mieux mourir en faisant quelque chose de noble pour notre peuple avant de le faire. Tu n\'es pas d\'accord ?') ON DUPLICATE KEY UPDATE CompletionText='Tu sais où cela mène, $N ? Il n\'y a aucun moyen qu\'elle survive... regarde-la. Le meilleur pour elle maintenant est de nous aider à trouver un remède au fléau. Cette eau qu\'elle a bue pourrait contenir une piste qui nous aidera à comprendre comment. Elle va mourir de toute façon -- elle vaut mieux mourir en faisant quelque chose de noble pour notre peuple avant de le faire. Tu n\'es pas d\'accord ?';
-- Quest 3570 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3570, 'frFR', 'Je n\'aurais jamais imaginé que l\'élixir agirait aussi vite. Merci, $N. Je vais m\'occuper du reste de ces échantillons immédiatement. Je suis sûr qu\'ils seront utilisables par Lady Sylvanas et les Désossés bientôt.') ON DUPLICATE KEY UPDATE RewardText='Je n\'aurais jamais imaginé que l\'élixir agirait aussi vite. Merci, $N. Je vais m\'occuper du reste de ces échantillons immédiatement. Je suis sûr qu\'ils seront utilisables par Lady Sylvanas et les Désossés bientôt.';
-- Quest 3602 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3602, 'frFR', 'Le mal ne dort pas, imbécile. Tu auras le temps de te reposer quand tu seras enfin mort. Maintenant, apporte-moi ces cristaux.') ON DUPLICATE KEY UPDATE CompletionText='Le mal ne dort pas, imbécile. Tu auras le temps de te reposer quand tu seras enfin mort. Maintenant, apporte-moi ces cristaux.';
-- Quest 3602 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3602, 'frFR', 'Tes tâches dans Azshara sont terminées, mortel. Je dois maintenant forger les composants nécessaires pour la prochaine étape de ton aventure.') ON DUPLICATE KEY UPDATE RewardText='Tes tâches dans Azshara sont terminées, mortel. Je dois maintenant forger les composants nécessaires pour la prochaine étape de ton aventure.';
-- Quest 3621 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3621, 'frFR', 'Loramus, hein ? Cela fait des années que je n\'ai pas entendu ce nom.') ON DUPLICATE KEY UPDATE CompletionText='Loramus, hein ? Cela fait des années que je n\'ai pas entendu ce nom.';
-- Quest 3621 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3621, 'frFR', 'Mon Dieu, je peux seulement imaginer ce que tu as traversé pour obtenir ces matériaux. Peu s\'aventurent dans Azshara et reviennent vivants, sans parler de ceux qui affrontent des demi-dieux et des géants !') ON DUPLICATE KEY UPDATE RewardText='Mon Dieu, je peux seulement imaginer ce que tu as traversé pour obtenir ces matériaux. Peu s\'aventurent dans Azshara et reviennent vivants, sans parler de ceux qui affrontent des demi-dieux et des géants !';
-- Quest 3625 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3625, 'frFR', 'Interrompre le processus de forge pourrait entraîner une arme imparfaite. Sois patient, $n.') ON DUPLICATE KEY UPDATE CompletionText='Interrompre le processus de forge pourrait entraîner une arme imparfaite. Sois patient, $n.';
-- Quest 3629 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3629, 'frFR', 'Je peux sentir les recrues fraîches tout comme je peux sentir un excellent poudre explosive - à des kilomètres. Es-tu venu chercher à apprendre la maîtrise de l\'explosion ?') ON DUPLICATE KEY UPDATE CompletionText='Je peux sentir les recrues fraîches tout comme je peux sentir un excellent poudre explosive - à des kilomètres. Es-tu venu chercher à apprendre la maîtrise de l\'explosion ?';
-- Quest 3629 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3629, 'frFR', 'Eh bien $N, tu as eu sagesse de chercher mon enseignement ! N\'importe quel clochard peut devenir un expert dans les bases de l\'ingénierie - les gnomes et leur foyer irradié de Gnomeregan en sont la preuve. Il faut cependant un esprit fort et une main stable (insistance sur STABLE) pour maîtriser la discipline de l\'ingénierie des Gobelins.$B$BGarde tes oreilles ouvertes $N, et tu pourrais apprendre quelque chose.') ON DUPLICATE KEY UPDATE RewardText='Eh bien $N, tu as eu sagesse de chercher mon enseignement ! N\'importe quel clochard peut devenir un expert dans les bases de l\'ingénierie - les gnomes et leur foyer irradié de Gnomeregan en sont la preuve. Il faut cependant un esprit fort et une main stable (insistance sur STABLE) pour maîtriser la discipline de l\'ingénierie des Gobelins.$B$BGarde tes oreilles ouvertes $N, et tu pourrais apprendre quelque chose.';
-- Quest 3630 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3630, 'frFR', 'Oui, oui, quel besoin puis-je satisfaire aujourd\'hui ? Clairement, j\'ai le temps de faire cela puisque tout ce que je fais, c\'est rester là pendant que notre chère ville est dans un nuage de mort irradiée.') ON DUPLICATE KEY UPDATE CompletionText='Oui, oui, quel besoin puis-je satisfaire aujourd\'hui ? Clairement, j\'ai le temps de faire cela puisque tout ce que je fais, c\'est rester là pendant que notre chère ville est dans un nuage de mort irradiée.';
-- Quest 3631 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3631, 'frFR', 'Bonne chance, $N. J\'ai hâte de te revoir dans le futur.') ON DUPLICATE KEY UPDATE RewardText='Bonne chance, $N. J\'ai hâte de te revoir dans le futur.';
-- Quest 3632 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3632, 'frFR', 'Oui, oui, quel besoin puis-je satisfaire aujourd\'hui ? Clairement, j\'ai le temps de faire cela puisque tout ce que je fais, c\'est rester là pendant que notre chère ville est dans un nuage de mort irradiée.') ON DUPLICATE KEY UPDATE CompletionText='Oui, oui, quel besoin puis-je satisfaire aujourd\'hui ? Clairement, j\'ai le temps de faire cela puisque tout ce que je fais, c\'est rester là pendant que notre chère ville est dans un nuage de mort irradiée.';
-- Quest 3633 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3633, 'frFR', 'Je peux sentir les recrues fraîches tout comme je peux sentir un excellent poudre explosive - à des kilomètres. Es-tu venu chercher à apprendre la maîtrise de l\'explosion ?') ON DUPLICATE KEY UPDATE CompletionText='Je peux sentir les recrues fraîches tout comme je peux sentir un excellent poudre explosive - à des kilomètres. Es-tu venu chercher à apprendre la maîtrise de l\'explosion ?';
-- Quest 3633 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3633, 'frFR', 'Eh bien $N, tu as eu sagesse de chercher mon enseignement ! N\'importe quel clochard peut devenir un expert dans les bases de l\'ingénierie - les gnomes et leur foyer irradié de Gnomeregan en sont la preuve. Il faut cependant un esprit fort et une main stable (insistance sur STABLE) pour maîtriser la discipline de l\'ingénierie des Gobelins.$B$BGarde tes oreilles ouvertes $N, et tu pourrais apprendre quelque chose.') ON DUPLICATE KEY UPDATE RewardText='Eh bien $N, tu as eu sagesse de chercher mon enseignement ! N\'importe quel clochard peut devenir un expert dans les bases de l\'ingénierie - les gnomes et leur foyer irradié de Gnomeregan en sont la preuve. Il faut cependant un esprit fort et une main stable (insistance sur STABLE) pour maîtriser la discipline de l\'ingénierie des Gobelins.$B$BGarde tes oreilles ouvertes $N, et tu pourrais apprendre quelque chose.';
-- Quest 3634 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3634, 'frFR', 'Oui, oui, quel besoin puis-je satisfaire aujourd\'hui ? Clairement, j\'ai le temps de faire cela puisque tout ce que je fais, c\'est rester là pendant que notre chère ville est dans un nuage de mort irradiée.') ON DUPLICATE KEY UPDATE CompletionText='Oui, oui, quel besoin puis-je satisfaire aujourd\'hui ? Clairement, j\'ai le temps de faire cela puisque tout ce que je fais, c\'est rester là pendant que notre chère ville est dans un nuage de mort irradiée.';

-- Quest 3634 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3634, 'frFR', 'Ah, un jeune ingénieur intéressé par la discipline unique et véritable de l\'ingénierie ! Pardonnez mon mélodrame, ami. Bien que notre situation reste désastreuse, il est toujours un bon jour de voir un autre ingénieur répondre à l\'appel clairon de la véritable ingénierie !') ON DUPLICATE KEY UPDATE RewardText='Ah, un jeune ingénieur intéressé par la discipline unique et véritable de l\'ingénierie ! Pardonnez mon mélodrame, ami. Bien que notre situation reste désastreuse, il est toujours un bon jour de voir un autre ingénieur répondre à l\'appel clairon de la véritable ingénierie !';
-- Quest 3635 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3635, 'frFR', 'Bonjour ! Si vous êtes venu à propos d\'un robot traqueur qui a peut-être fracassé un mur de votre domicile, alors je vous référerai à mon avocat par avance. Sinon, que puis-je faire pour vous aujourd\'hui ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour ! Si vous êtes venu à propos d\'un robot traqueur qui a peut-être fracassé un mur de votre domicile, alors je vous référerai à mon avocat par avance. Sinon, que puis-je faire pour vous aujourd\'hui ?';
-- Quest 3635 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3635, 'frFR', 'Vous êtes venu apprendre l\'ingénierie gnome, hein ? Eh bien, vous êtes au bon gnome. Bien que la faction dirigeante de Gnomeregan puisse utiliser la politique pour ostraciser ceux qu\'elle considère comme une menace intellectuelle, elle sait que le savoir est quelque chose qu\'elle ne peut contrôler.$B$BNous savons tous les deux que lorsque j\'ai quitté Gnomeregan, ils ont perdu l\'un de leurs plus grands ingénieurs gnomes vivants aujourd\'hui. Si vous êtes un étudiant capable, je vous enseignerai ce que je sais.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes venu apprendre l\'ingénierie gnome, hein ? Eh bien, vous êtes au bon gnome. Bien que la faction dirigeante de Gnomeregan puisse utiliser la politique pour ostraciser ceux qu\'elle considère comme une menace intellectuelle, elle sait que le savoir est quelque chose qu\'elle ne peut contrôler.$B$BNous savons tous les deux que lorsque j\'ai quitté Gnomeregan, ils ont perdu l\'un de leurs plus grands ingénieurs gnomes vivants aujourd\'hui. Si vous êtes un étudiant capable, je vous enseignerai ce que je sais.';
-- Quest 3636 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3636, 'frFR', 'Amnennar doit être éradiqué. Allez, vite.') ON DUPLICATE KEY UPDATE CompletionText='Amnennar doit être éradiqué. Allez, vite.';
-- Quest 3637 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3637, 'frFR', 'Bonjour ! Si vous êtes venu à propos d\'un robot traqueur qui a peut-être fracassé un mur de votre domicile, alors je vous référerai à mon avocat par avance. Sinon, que puis-je faire pour vous aujourd\'hui ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour ! Si vous êtes venu à propos d\'un robot traqueur qui a peut-être fracassé un mur de votre domicile, alors je vous référerai à mon avocat par avance. Sinon, que puis-je faire pour vous aujourd\'hui ?';
-- Quest 3637 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3637, 'frFR', 'Vous êtes venu apprendre l\'ingénierie gnome, hein ? Eh bien, vous êtes au bon gnome. Bien que la faction dirigeante de Gnomeregan puisse utiliser la politique pour ostraciser ceux qu\'elle considère comme une menace intellectuelle, elle sait que le savoir est quelque chose qu\'elle ne peut contrôler.$B$BNous savons tous les deux que lorsque j\'ai quitté Gnomeregan, ils ont perdu l\'un de leurs plus grands ingénieurs gnomes vivants aujourd\'hui. Si vous êtes un étudiant capable, je vous enseignerai ce que je sais.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes venu apprendre l\'ingénierie gnome, hein ? Eh bien, vous êtes au bon gnome. Bien que la faction dirigeante de Gnomeregan puisse utiliser la politique pour ostraciser ceux qu\'elle considère comme une menace intellectuelle, elle sait que le savoir est quelque chose qu\'elle ne peut contrôler.$B$BNous savons tous les deux que lorsque j\'ai quitté Gnomeregan, ils ont perdu l\'un de leurs plus grands ingénieurs gnomes vivants aujourd\'hui. Si vous êtes un étudiant capable, je vous enseignerai ce que je sais.';
-- Quest 3638 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3638, 'frFR', 'Si vous avez signé le document et êtes prêt à me le remettre, alors c\'est fait. On vous a dit que c\'était un aller simple. Si vous êtes prêt, alors montez à bord !') ON DUPLICATE KEY UPDATE CompletionText='Si vous avez signé le document et êtes prêt à me le remettre, alors c\'est fait. On vous a dit que c\'était un aller simple. Si vous êtes prêt, alors montez à bord !';
-- Quest 3638 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3638, 'frFR', 'Bienvenue à bord, Ingénieur Gobelin $N ! Vous aurez bientôt accès aux schémas d\'ingénierie les plus puissants d\'Azeroth.$b$bMaintenant que vous vous êtes engagé dans la poursuite de cette connaissance, il est temps d\'examiner votre travail d\'ingénierie orienté gobelin. À partir de là, nous vous aiderons à élaborer un plan pour maximiser vos talents d\'ingénierie gobelin !') ON DUPLICATE KEY UPDATE RewardText='Bienvenue à bord, Ingénieur Gobelin $N ! Vous aurez bientôt accès aux schémas d\'ingénierie les plus puissants d\'Azeroth.$b$bMaintenant que vous vous êtes engagé dans la poursuite de cette connaissance, il est temps d\'examiner votre travail d\'ingénierie orienté gobelin. À partir de là, nous vous aiderons à élaborer un plan pour maximiser vos talents d\'ingénierie gobelin !';
-- Quest 3640 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3640, 'frFR', 'Si vous avez signé le document et êtes prêt à me le remettre, alors c\'est fait.$B$BLes secrets que je vais partager avec vous sont d\'une telle magnitude que la signature du Serment de Confidentialité est absolument essentielle. J\'en ai signé un, mon frère et ma sœur ingénieurs gnomes aussi. Vous rejoindrez un cercle assez propice, Ingénieur $N !') ON DUPLICATE KEY UPDATE CompletionText='Si vous avez signé le document et êtes prêt à me le remettre, alors c\'est fait.$B$BLes secrets que je vais partager avec vous sont d\'une telle magnitude que la signature du Serment de Confidentialité est absolument essentielle. J\'en ai signé un, mon frère et ma sœur ingénieurs gnomes aussi. Vous rejoindrez un cercle assez propice, Ingénieur $N !';
-- Quest 3640 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3640, 'frFR', 'Bienvenue à bord, $N ! Vous aurez bientôt accès aux schémas d\'ingénierie les plus avancés d\'Azeroth.$B$BMaintenant que vous vous êtes engagé dans la poursuite de cette connaissance, il est temps d\'examiner votre travail d\'ingénierie orienté gnome. À partir de là, nous vous aiderons à élaborer un plan pour maximiser vos talents d\'ingénierie gnome !') ON DUPLICATE KEY UPDATE RewardText='Bienvenue à bord, $N ! Vous aurez bientôt accès aux schémas d\'ingénierie les plus avancés d\'Azeroth.$B$BMaintenant que vous vous êtes engagé dans la poursuite de cette connaissance, il est temps d\'examiner votre travail d\'ingénierie orienté gnome. À partir de là, nous vous aiderons à élaborer un plan pour maximiser vos talents d\'ingénierie gnome !';
-- Quest 3642 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3642, 'frFR', 'Si vous avez signé le document et êtes prêt à me le remettre, alors c\'est fait.$B$BBien que je puisse désapprouver violemment Gnomeregan - surtout ce fou Tinkmaster Overspark - politiquement, le Serment de Confidentialité transcende tout le reste ! Vous devez accepter de suivre un seul chemin et de rester fidèle à ce chemin tout au long de votre vie.') ON DUPLICATE KEY UPDATE CompletionText='Si vous avez signé le document et êtes prêt à me le remettre, alors c\'est fait.$B$BBien que je puisse désapprouver violemment Gnomeregan - surtout ce fou Tinkmaster Overspark - politiquement, le Serment de Confidentialité transcende tout le reste ! Vous devez accepter de suivre un seul chemin et de rester fidèle à ce chemin tout au long de votre vie.';
-- Quest 3642 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3642, 'frFR', 'Bienvenue à bord, <name> !  Vous aurez bientôt accès aux schémas d\'ingénierie les plus avancés d\'Azeroth.$B$BMaintenant que vous vous êtes engagé dans la poursuite de cette connaissance, il est temps d\'examiner votre travail d\'ingénierie orienté gnome.  À partir de là, nous vous aiderons à élaborer un plan pour maximiser vos talents d\'ingénierie gnome !') ON DUPLICATE KEY UPDATE RewardText='Bienvenue à bord, <name> !  Vous aurez bientôt accès aux schémas d\'ingénierie les plus avancés d\'Azeroth.$B$BMaintenant que vous vous êtes engagé dans la poursuite de cette connaissance, il est temps d\'examiner votre travail d\'ingénierie orienté gnome.  À partir de là, nous vous aiderons à élaborer un plan pour maximiser vos talents d\'ingénierie gnome !';
-- Quest 3643 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3643, 'frFR', 'Une fois que j\'aurai reçu vos objets d\'ingénierie fabriqués pour mon examen, je vous remettrai une vraie Carte de Membre d\'Ingénieur Gnome ! Tant que la carte est valide, vous aurez un accès illimité à n\'importe quel instructeur d\'ingénieur gnome dans le monde.') ON DUPLICATE KEY UPDATE CompletionText='Une fois que j\'aurai reçu vos objets d\'ingénierie fabriqués pour mon examen, je vous remettrai une vraie Carte de Membre d\'Ingénieur Gnome ! Tant que la carte est valide, vous aurez un accès illimité à n\'importe quel instructeur d\'ingénieur gnome dans le monde.';
-- Quest 3644 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3644, 'frFR', 'Pour renouveler votre carte de membre, vous devrez payer les frais de renouvellement de deux pièces d\'or.') ON DUPLICATE KEY UPDATE CompletionText='Pour renouveler votre carte de membre, vous devrez payer les frais de renouvellement de deux pièces d\'or.';
-- Quest 3644 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3644, 'frFR', 'Puisque vous êtes un praticien de l\'ingénierie gobelin et êtes en règle, je suis en mesure de renouveler une carte de membre expirée pour des frais de deux pièces d\'or.  Une fois ces frais payés, vous recevrez une nouvelle carte de membre.  Ceci vous donnera accès aux schémas d\'ingénierie gobelin auprès des instructeurs appropriés.$B$BCette carte sera valable pour deux semaines d\'activité, après quoi vos frais d\'adhésion seront à nouveau dus !  Si vous souhaitez accéder aux schémas, vous devrez régulariser vos arriérés.') ON DUPLICATE KEY UPDATE RewardText='Puisque vous êtes un praticien de l\'ingénierie gobelin et êtes en règle, je suis en mesure de renouveler une carte de membre expirée pour des frais de deux pièces d\'or.  Une fois ces frais payés, vous recevrez une nouvelle carte de membre.  Ceci vous donnera accès aux schémas d\'ingénierie gobelin auprès des instructeurs appropriés.$B$BCette carte sera valable pour deux semaines d\'activité, après quoi vos frais d\'adhésion seront à nouveau dus !  Si vous souhaitez accéder aux schémas, vous devrez régulariser vos arriérés.';

-- Quest 3645 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3645, 'frFR', 'Pour renouveler votre carte d\'adhésion, vous devrez payer les frais de renouvellement de deux pièces d\'or.') ON DUPLICATE KEY UPDATE CompletionText='Pour renouveler votre carte d\'adhésion, vous devrez payer les frais de renouvellement de deux pièces d\'or.';
-- Quest 3645 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3645, 'frFR', 'Puisque vous êtes un praticien de l\'ingénierie gnome et que vous êtes en règle, je peux renouveler une carte d\'adhésion expirée pour un frais de deux pièces d\'or. Une fois ce frais payé, vous recevrez une nouvelle carte d\'adhésion. Cela vous donnera accès aux schémas d\'ingénierie gnome à partir de formateurs appropriés.$B$BCette carte sera valable pour deux semaines d\'activité, au terme de laquelle vos frais d\'adhésion seront à nouveau dus! Si vous souhaitez accéder aux schémas, vous devrez régler vos arriérés.') ON DUPLICATE KEY UPDATE RewardText='Puisque vous êtes un praticien de l\'ingénierie gnome et que vous êtes en règle, je peux renouveler une carte d\'adhésion expirée pour un frais de deux pièces d\'or. Une fois ce frais payé, vous recevrez une nouvelle carte d\'adhésion. Cela vous donnera accès aux schémas d\'ingénierie gnome à partir de formateurs appropriés.$B$BCette carte sera valable pour deux semaines d\'activité, au terme de laquelle vos frais d\'adhésion seront à nouveau dus! Si vous souhaitez accéder aux schémas, vous devrez régler vos arriérés.';
-- Quest 3646 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3646, 'frFR', 'Pour renouveler votre carte d\'adhésion, vous devrez payer les frais de renouvellement de deux pièces d\'or.') ON DUPLICATE KEY UPDATE CompletionText='Pour renouveler votre carte d\'adhésion, vous devrez payer les frais de renouvellement de deux pièces d\'or.';
-- Quest 3646 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3646, 'frFR', 'Puisque vous êtes un praticien de l\'ingénierie gobelin et que vous êtes en règle, je peux renouveler une carte d\'adhésion expirée pour un frais de deux pièces d\'or. Une fois ce frais payé, vous recevrez une nouvelle carte d\'adhésion. Cela vous donnera accès aux schémas d\'ingénierie gobelin à partir de formateurs appropriés.$B$BCette carte sera valable pour deux semaines d\'activité, au terme de laquelle vos frais d\'adhésion seront à nouveau dus! Si vous souhaitez accéder aux schémas, vous devrez régler vos arriérés.') ON DUPLICATE KEY UPDATE RewardText='Puisque vous êtes un praticien de l\'ingénierie gobelin et que vous êtes en règle, je peux renouveler une carte d\'adhésion expirée pour un frais de deux pièces d\'or. Une fois ce frais payé, vous recevrez une nouvelle carte d\'adhésion. Cela vous donnera accès aux schémas d\'ingénierie gobelin à partir de formateurs appropriés.$B$BCette carte sera valable pour deux semaines d\'activité, au terme de laquelle vos frais d\'adhésion seront à nouveau dus! Si vous souhaitez accéder aux schémas, vous devrez régler vos arriérés.';
-- Quest 3647 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3647, 'frFR', 'Pour renouveler votre carte d\'adhésion, vous devrez payer les frais de renouvellement de deux pièces d\'or.') ON DUPLICATE KEY UPDATE CompletionText='Pour renouveler votre carte d\'adhésion, vous devrez payer les frais de renouvellement de deux pièces d\'or.';
-- Quest 3647 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3647, 'frFR', 'Puisque vous êtes un praticien de l\'ingénierie Gnomique et que vous êtes en règle, je peux renouveler une carte d\'adhésion expirée pour un frais de deux pièces d\'or. Une fois ce frais payé, vous recevrez une nouvelle carte d\'adhésion. Cela vous donnera accès aux schémas d\'ingénierie Gnomique à partir de formateurs appropriés.$B$BCette carte sera valable pour deux semaines d\'activité, au terme de laquelle vos frais d\'adhésion seront à nouveau dus! Si vous souhaitez accéder aux schémas, vous devrez régler vos arriérés.') ON DUPLICATE KEY UPDATE RewardText='Puisque vous êtes un praticien de l\'ingénierie Gnomique et que vous êtes en règle, je peux renouveler une carte d\'adhésion expirée pour un frais de deux pièces d\'or. Une fois ce frais payé, vous recevrez une nouvelle carte d\'adhésion. Cela vous donnera accès aux schémas d\'ingénierie Gnomique à partir de formateurs appropriés.$B$BCette carte sera valable pour deux semaines d\'activité, au terme de laquelle vos frais d\'adhésion seront à nouveau dus! Si vous souhaitez accéder aux schémas, vous devrez régler vos arriérés.';
-- Quest 3681 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3681, 'frFR', 'Bienvenue à la Cathédrale de la Lumière, $c.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue à la Cathédrale de la Lumière, $c.';
-- Quest 3702 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3702, 'frFR', 'Permettez-moi de vous raconter l\'histoire de Thaurissan.') ON DUPLICATE KEY UPDATE CompletionText='Permettez-moi de vous raconter l\'histoire de Thaurissan.';
-- Quest 3721 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3721, 'frFR', 'Vous avez récupéré trois de mes robots de ciblage OOX! Vous êtes allé au-delà de ce qui était nécessaire, je vais donc vous donner quelque chose de spécial pour toute votre aide. C\'est une version miniature du robot que vous avez appris à connaître et à aimer, l\'OOX!$B$BJe n\'autoriserais normalement personne à avoir un appareil potentiellement létal comme celui-ci, mais vous avez été d\'une grande aide. De plus - les mécanismes de combat et la logique de ciblage de celui-ci ont été désactivés.$B$BMis à part ça, c\'est un OOX de génie!') ON DUPLICATE KEY UPDATE RewardText='Vous avez récupéré trois de mes robots de ciblage OOX! Vous êtes allé au-delà de ce qui était nécessaire, je vais donc vous donner quelque chose de spécial pour toute votre aide. C\'est une version miniature du robot que vous avez appris à connaître et à aimer, l\'OOX!$B$BJe n\'autoriserais normalement personne à avoir un appareil potentiellement létal comme celui-ci, mais vous avez été d\'une grande aide. De plus - les mécanismes de combat et la logique de ciblage de celui-ci ont été désactivés.$B$BMis à part ça, c\'est un OOX de génie!';
-- Quest 3762 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3762, 'frFR', 'Salutations, $C; Je suis ravi que vous soyez intéressé à aider nos recherches. Il y a beaucoup à faire, et je vous ferais un tort si je vous disais que le travail que cela implique n\'est pas dangereux. J\'espère que cela ne vous effrayera pas... mais à vous voir, je suppose que le danger est quelque chose auquel vous avez été confronté auparavant.') ON DUPLICATE KEY UPDATE RewardText='Salutations, $C; Je suis ravi que vous soyez intéressé à aider nos recherches. Il y a beaucoup à faire, et je vous ferais un tort si je vous disais que le travail que cela implique n\'est pas dangereux. J\'espère que cela ne vous effrayera pas... mais à vous voir, je suppose que le danger est quelque chose auquel vous avez été confronté auparavant.';
-- Quest 3763 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3763, 'frFR', 'Eh bien, $c... puisque vous avez été informé que je menais moi-même ces recherches, vous êtes évidemment arrivé aussi vite que possible.$B$BMaintenant que vous êtes là, assurez-vous de prêter attention la première fois que je vous donne les détails ; je n\'ai pas envie de me répéter.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, $c... puisque vous avez été informé que je menais moi-même ces recherches, vous êtes évidemment arrivé aussi vite que possible.$B$BMaintenant que vous êtes là, assurez-vous de prêter attention la première fois que je vous donne les détails ; je n\'ai pas envie de me répéter.';
-- Quest 3784 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3784, 'frFR', 'Salutations, $c; Je suis ravi que vous soyez intéressé à aider nos recherches. Il y a beaucoup à faire, et je vous ferais un tort si je vous disais que le travail que cela implique n\'est pas dangereux. J\'espère que cela ne vous effrayera pas... mais à vous voir, je suppose que le danger est quelque chose auquel vous avez été confronté auparavant.') ON DUPLICATE KEY UPDATE RewardText='Salutations, $c; Je suis ravi que vous soyez intéressé à aider nos recherches. Il y a beaucoup à faire, et je vous ferais un tort si je vous disais que le travail que cela implique n\'est pas dangereux. J\'espère que cela ne vous effrayera pas... mais à vous voir, je suppose que le danger est quelque chose auquel vous avez été confronté auparavant.';
-- Quest 3785 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3785, 'frFR', 'Oui $N, avez-vous cultivé du morrowgrain pour les recherches importantes de l\'Archidruide ? Les propriétés mystérieuses du Crater Un\'Goro deviennent plus claires chaque jour qui passe, grâce à l\'aide que vous nous apportez.') ON DUPLICATE KEY UPDATE CompletionText='Oui $N, avez-vous cultivé du morrowgrain pour les recherches importantes de l\'Archidruide ? Les propriétés mystérieuses du Crater Un\'Goro deviennent plus claires chaque jour qui passe, grâce à l\'aide que vous nous apportez.';
-- Quest 3785 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3785, 'frFR', 'Bien fait $N, je m\'assurerai de les donner à l\'Archidruide lui-même lorsqu\'il en aura besoin. En attendant, veuillez accepter ceci comme un signe d\'appréciation du Cercle de Cenarion.$b$bNotre besoin de morrowgrain, pour l\'instant, est constant ; si vous souhaitez continuer à nous aider, veuillez revenir lorsque vous en aurez cultivé davantage.') ON DUPLICATE KEY UPDATE RewardText='Bien fait $N, je m\'assurerai de les donner à l\'Archidruide lui-même lorsqu\'il en aura besoin. En attendant, veuillez accepter ceci comme un signe d\'appréciation du Cercle de Cenarion.$b$bNotre besoin de morrowgrain, pour l\'instant, est constant ; si vous souhaitez continuer à nous aider, veuillez revenir lorsque vous en aurez cultivé davantage.';
-- Quest 3786 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3786, 'frFR', 'Oui $N, avez-vous cultivé du morrowgrain pour les recherches importantes de l\'Archidruide ? Les propriétés mystérieuses du Crater Un\'Goro deviennent plus claires chaque jour qui passe, grâce à l\'aide que vous nous apportez.') ON DUPLICATE KEY UPDATE CompletionText='Oui $N, avez-vous cultivé du morrowgrain pour les recherches importantes de l\'Archidruide ? Les propriétés mystérieuses du Crater Un\'Goro deviennent plus claires chaque jour qui passe, grâce à l\'aide que vous nous apportez.';

-- Quest 3787 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3787, 'frFR', 'Je vous remercie de votre venue, voyageur fatigué ! Permettez-moi de me présenter - je suis Quintis Jonespyre, druide et humble serviteur de Malfurion et du Cercle de Cenarion. Mes collègues (le Général Shandris Feathermoon et le Protectorat - vous les avez peut-être entendus) et moi souhaitions discuter avec vous du travail que vous accomplissez pour Fandral Staghelm à Darnassus.$B$BAvant d\'aller plus loin, j\'aimerais demander que notre discussion reste entre nous. Si vous n\'y voyez aucun inconvénient, alors nous pouvons continuer.') ON DUPLICATE KEY UPDATE RewardText='Je vous remercie de votre venue, voyageur fatigué ! Permettez-moi de me présenter - je suis Quintis Jonespyre, druide et humble serviteur de Malfurion et du Cercle de Cenarion. Mes collègues (le Général Shandris Feathermoon et le Protectorat - vous les avez peut-être entendus) et moi souhaitions discuter avec vous du travail que vous accomplissez pour Fandral Staghelm à Darnassus.$B$BAvant d\'aller plus loin, j\'aimerais demander que notre discussion reste entre nous. Si vous n\'y voyez aucun inconvénient, alors nous pouvons continuer.';
-- Quest 3790 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3790, 'frFR', 'Eh bien, $C... puisque vous avez été informé que je menais moi-même cette recherche, vous êtes évidemment venu aussi vite que possible.$B$BMaintenant que vous êtes là, assurez-vous de prêter attention la première fois que je vous donne les détails ; je n\'ai pas envie de me répéter.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, $C... puisque vous avez été informé que je menais moi-même cette recherche, vous êtes évidemment venu aussi vite que possible.$B$BMaintenant que vous êtes là, assurez-vous de prêter attention la première fois que je vous donne les détails ; je n\'ai pas envie de me répéter.';
-- Quest 3792 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3792, 'frFR', 'Bonjour à nouveau, $N. Ma recherche progresse assez bien, mais si vous avez cinq Morrowgrain de plus, je serais heureux de les prendre de vos mains. Eh bien... heureux est un terme figuré dans ce cas ; plus je suis près d\'eux, plus je me sens mal à l\'aise. Néanmoins, ma recherche m\'oblige à me concentrer et à traverser cela.') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau, $N. Ma recherche progresse assez bien, mais si vous avez cinq Morrowgrain de plus, je serais heureux de les prendre de vos mains. Eh bien... heureux est un terme figuré dans ce cas ; plus je suis près d\'eux, plus je me sens mal à l\'aise. Néanmoins, ma recherche m\'oblige à me concentrer et à traverser cela.';
-- Quest 3792 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3792, 'frFR', 'Merci <name>; je vais juste ranger ceux-ci hors de portée pour le moment. Bien que je ne commande pas les ressources de Staghelm, je peux vous offrir quelque chose pour votre peine. Quoi qu\'il en soit, qui sait ce qui arrivera si Staghelm continue d\'obtenir des Morrowgrain après des Morrowgrain. Il y a quelque chose de louche qui se passe, notez mes paroles.$B$BRappelez-vous que je cherche toujours plus de Morrowgrain. Je les prendrai par quantités de cinq à la fois.') ON DUPLICATE KEY UPDATE RewardText='Merci <name>; je vais juste ranger ceux-ci hors de portée pour le moment. Bien que je ne commande pas les ressources de Staghelm, je peux vous offrir quelque chose pour votre peine. Quoi qu\'il en soit, qui sait ce qui arrivera si Staghelm continue d\'obtenir des Morrowgrain après des Morrowgrain. Il y a quelque chose de louche qui se passe, notez mes paroles.$B$BRappelez-vous que je cherche toujours plus de Morrowgrain. Je les prendrai par quantités de cinq à la fois.';
-- Quest 3803 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3803, 'frFR', 'L\'Archidruide recherche toujours des morrowgrain supplémentaires pour la recherche continue du Cercle de Cenarion. Nous les prenons par incréments de dix, et nous vous récompensons avec une cache de biens que vous devriez trouver utiles. Quand vous en avez dix, faites-le-moi savoir et je vous récompenserai en conséquence.') ON DUPLICATE KEY UPDATE CompletionText='L\'Archidruide recherche toujours des morrowgrain supplémentaires pour la recherche continue du Cercle de Cenarion. Nous les prenons par incréments de dix, et nous vous récompensons avec une cache de biens que vous devriez trouver utiles. Quand vous en avez dix, faites-le-moi savoir et je vous récompenserai en conséquence.';
-- Quest 3803 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3803, 'frFR', 'Excellent - ce morrowgrain plaira sans aucun doute à l\'Archidruide. Je dois cependant admettre... être près d\'eux me rend un peu mal à l\'aise. Je peux seulement imaginer à quel point il est difficile pour l\'Archidruide de les tolérer en si grands nombres !$B$BCeci est pour vous, $N. Le Cercle de Cenarion vous remercie de votre soutien continu.') ON DUPLICATE KEY UPDATE RewardText='Excellent - ce morrowgrain plaira sans aucun doute à l\'Archidruide. Je dois cependant admettre... être près d\'eux me rend un peu mal à l\'aise. Je peux seulement imaginer à quel point il est difficile pour l\'Archidruide de les tolérer en si grands nombres !$B$BCeci est pour vous, $N. Le Cercle de Cenarion vous remercie de votre soutien continu.';
-- Quest 3804 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3804, 'frFR', 'L\'Archidruide recherche toujours plus de morrowgrain pour le projet de recherche du Cercle de Cenarion sur le Crater d\'Un\'Goro. Nous les prenons par incréments de dix, et nous vous récompensons avec une cache de biens que vous devriez trouver utiles. Quand vous en avez dix, faites-le-moi savoir et je vous récompenserai en conséquence.') ON DUPLICATE KEY UPDATE CompletionText='L\'Archidruide recherche toujours plus de morrowgrain pour le projet de recherche du Cercle de Cenarion sur le Crater d\'Un\'Goro. Nous les prenons par incréments de dix, et nous vous récompensons avec une cache de biens que vous devriez trouver utiles. Quand vous en avez dix, faites-le-moi savoir et je vous récompenserai en conséquence.';
-- Quest 3804 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3804, 'frFR', 'Excellent - ce morrowgrain aidera sans aucun doute quand le moment viendra. Nous savons que les elfes de la nuit mènent des recherches similaires sur ces herbes, bien qu\'il ne soit pas clair à quoi ils les utiliseront s\'ils découvrent quelque chose. L\'Archidruide pense que le besoin de morrowgrain persistera jusqu\'à ce que nous ayons démasqué les mystères derrière cette herbe.$B$BCeci est pour vous, $N. Le Cercle de Cenarion vous remercie de votre soutien continu.') ON DUPLICATE KEY UPDATE RewardText='Excellent - ce morrowgrain aidera sans aucun doute quand le moment viendra. Nous savons que les elfes de la nuit mènent des recherches similaires sur ces herbes, bien qu\'il ne soit pas clair à quoi ils les utiliseront s\'ils découvrent quelque chose. L\'Archidruide pense que le besoin de morrowgrain persistera jusqu\'à ce que nous ayons démasqué les mystères derrière cette herbe.$B$BCeci est pour vous, $N. Le Cercle de Cenarion vous remercie de votre soutien continu.';
-- Quest 3822 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3822, 'frFR', 'Avez-vous trouvé Sha\'ni ? Est-elle en paix ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé Sha\'ni ? Est-elle en paix ?';
-- Quest 3823 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3823, 'frFR', 'Il n\'y a pas assez de sang sur votre uniforme, soldat !') ON DUPLICATE KEY UPDATE CompletionText='Il n\'y a pas assez de sang sur votre uniforme, soldat !';
-- Quest 3825 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3825, 'frFR', 'Alors ? Avez-vous peint des images de l\'événement ?') ON DUPLICATE KEY UPDATE CompletionText='Alors ? Avez-vous peint des images de l\'événement ?';
-- Quest 3842 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3842, 'frFR', 'Plus je reste ici, plus je suis tenté de participer à ces races, $N. Vraiment ahurissant...$B$BAvez-vous trouvé les élixirs ? Une fois que je peux dire si l\'œuf sera en bonne santé ou non, je vous le rendrai pour que vous le gardiez jusqu\'à ce qu\'il soit prêt à éclore.$B$BFaites-le-moi savoir.') ON DUPLICATE KEY UPDATE CompletionText='Plus je reste ici, plus je suis tenté de participer à ces races, $N. Vraiment ahurissant...$B$BAvez-vous trouvé les élixirs ? Une fois que je peux dire si l\'œuf sera en bonne santé ou non, je vous le rendrai pour que vous le gardiez jusqu\'à ce qu\'il soit prêt à éclore.$B$BFaites-le-moi savoir.';
-- Quest 3843 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3843, 'frFR', 'Salutations, $N. Comment puis-je vous être utile ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $N. Comment puis-je vous être utile ?';
-- Quest 3901 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3901, 'frFR', 'Ceux qui tergiversent dans cette tâche pourraient aussi bien finir à errer sans but comme nos frères et sœurs tombés dans le village. Espérons que vous vous en sortirez mieux qu\'eux, oui ? $b$b') ON DUPLICATE KEY UPDATE CompletionText='Ceux qui tergiversent dans cette tâche pourraient aussi bien finir à errer sans but comme nos frères et sœurs tombés dans le village. Espérons que vous vous en sortirez mieux qu\'eux, oui ? $b$b';
-- Quest 3904 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3904, 'frFR', 'Oh merci, $N! Vous avez sauvé ma récolte ! Et j\'espère que vous avez montré à quelques-uns de ces Defias qu\'ils ne peuvent pas causer de problèmes ici.$b$bNous pourrions être en manque de gardes ces jours-ci, mais nous sommes chanceux d\'avoir des héros comme vous pour nous protéger !') ON DUPLICATE KEY UPDATE RewardText='Oh merci, $N! Vous avez sauvé ma récolte ! Et j\'espère que vous avez montré à quelques-uns de ces Defias qu\'ils ne peuvent pas causer de problèmes ici.$b$bNous pourrions être en manque de gardes ces jours-ci, mais nous sommes chanceux d\'avoir des héros comme vous pour nous protéger !';

-- Quest 3906 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3906, 'frFR', 'Les éléments sont toujours en désordre, $N.') ON DUPLICATE KEY UPDATE CompletionText='Les éléments sont toujours en désordre, $N.';
-- Quest 3906 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3906, 'frFR', 'Ceci ne peut être... cela ne doit pas être. La destruction de Pyron n\'a fait qu\'enlever un voile. Dans les profondeurs de Blackrock se trouve une source de corruption bien plus insidieuse.') ON DUPLICATE KEY UPDATE RewardText='Ceci ne peut être... cela ne doit pas être. La destruction de Pyron n\'a fait qu\'enlever un voile. Dans les profondeurs de Blackrock se trouve une source de corruption bien plus insidieuse.';
-- Quest 3907 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3907, 'frFR', 'Les flammes vont bientôt submerger ces terres. Dépêchez-vous, $N!') ON DUPLICATE KEY UPDATE CompletionText='Les flammes vont bientôt submerger ces terres. Dépêchez-vous, $N!';
-- Quest 3907 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3907, 'frFR', '$GThunderheart serre la Tablette de Kurniya.>$B$BRagnaros... ici...$B$Les anciens avaient raison de craindre la corruption émanant de la Montagne de Blackrock. Un général des Anciens ! DANS NOTRE MONDE ! Nous devons réévaluer notre position ici à Kargath. Nous devons décider si nous restons pour combattre ou si nous fuyons par peur d\'une nouvelle scission.$B<br :>Méfiez-vous de toute exploration supplémentaire dans la Montagne de Blackrock, <name. Un mal bien plus grand que tout ce qui existe dans ce monde réside dans ces profondeurs ardentes.') ON DUPLICATE KEY UPDATE RewardText='$GThunderheart serre la Tablette de Kurniya.>$B$BRagnaros... ici...$B$Les anciens avaient raison de craindre la corruption émanant de la Montagne de Blackrock. Un général des Anciens ! DANS NOTRE MONDE ! Nous devons réévaluer notre position ici à Kargath. Nous devons décider si nous restons pour combattre ou si nous fuyons par peur d\'une nouvelle scission.$B<br :>Méfiez-vous de toute exploration supplémentaire dans la Montagne de Blackrock, <name. Un mal bien plus grand que tout ce qui existe dans ce monde réside dans ces profondeurs ardentes.';
-- Quest 3909 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3909, 'frFR', 'J\'aurai besoin d\'une fiole pour m\'assurer que c\'est vraiment l\'élixir... Oui... C\'est ça.') ON DUPLICATE KEY UPDATE RewardText='J\'aurai besoin d\'une fiole pour m\'assurer que c\'est vraiment l\'élixir... Oui... C\'est ça.';
-- Quest 3911 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3911, 'frFR', 'Merveilleux ! Je ferai envoyer ceci par coursier à l\'Undercity immédiatement !$B$BPour vous - voici le paiement, comme promis. Gardez la monnaie, espèce de bête sale !') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Je ferai envoyer ceci par coursier à l\'Undercity immédiatement !$B$BPour vous - voici le paiement, comme promis. Gardez la monnaie, espèce de bête sale !';
-- Quest 3922 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (3922, 'frFR', 'Avez-vous les slugs de nugget, $N? J\'ai repéré ce Samophlange et j\'ai hâte de m\'y plonger.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les slugs de nugget, $N? J\'ai repéré ce Samophlange et j\'ai hâte de m\'y plonger.';
-- Quest 3922 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3922, 'frFR', 'Super, vous les avez !  Maintenant, je peux commencer à travailler...') ON DUPLICATE KEY UPDATE RewardText='Super, vous les avez !  Maintenant, je peux commencer à travailler...';
-- Quest 3981 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3981, 'frFR', 'Nous n\'avons pas beaucoup de temps. Écoutez attentivement, $R. Ce que je dois vous dire est classifié et pour vos oreilles seulement.') ON DUPLICATE KEY UPDATE RewardText='Nous n\'avons pas beaucoup de temps. Écoutez attentivement, $R. Ce que je dois vous dire est classifié et pour vos oreilles seulement.';
-- Quest 3982 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (3982, 'frFR', 'C\'était une évasion. Ils ont été alertés de votre présence... d\'autres vont certainement arriver.') ON DUPLICATE KEY UPDATE RewardText='C\'était une évasion. Ils ont été alertés de votre présence... d\'autres vont certainement arriver.';
-- Quest 4001 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4001, 'frFR', 'Qu\'est-ce qui vous amène sur ces terres sacrées ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui vous amène sur ces terres sacrées ?';
-- Quest 4001 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4001, 'frFR', 'C\'est une chance pour la Horde de changer le climat politique de notre monde déchiré par la guerre pour toujours. Écoutez attentivement, $N.$B$BFaillite de cette mission n\'est pas une option.') ON DUPLICATE KEY UPDATE RewardText='C\'est une chance pour la Horde de changer le climat politique de notre monde déchiré par la guerre pour toujours. Écoutez attentivement, $N.$B$BFaillite de cette mission n\'est pas une option.';
-- Quest 4002 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4002, 'frFR', 'Il n\'y a pas de retour en arrière au-delà de ce point, $N.') ON DUPLICATE KEY UPDATE RewardText='Il n\'y a pas de retour en arrière au-delà de ce point, $N.';
-- Quest 4004 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4004, 'frFR', '<Thrall est surpris par les informations que vous lui avez présentées.>$B$BUne nouvelle menace plane à l\'horizon. Alors que les années de Magni diminuent, la voie sera ouverte pour que ce Dark Iron non encore né devienne le maître d\'Ironforge.$B$BVous avez accompli ce que je vous ai demandé et pour cela, vous serez récompensé.$B$BMaintenant, laissez-moi, $N! Je dois me consulter avec Sylvanas et Cairne.') ON DUPLICATE KEY UPDATE RewardText='<Thrall est surpris par les informations que vous lui avez présentées.>$B$BUne nouvelle menace plane à l\'horizon. Alors que les années de Magni diminuent, la voie sera ouverte pour que ce Dark Iron non encore né devienne le maître d\'Ironforge.$B$BVous avez accompli ce que je vous ai demandé et pour cela, vous serez récompensé.$B$BMaintenant, laissez-moi, $N! Je dois me consulter avec Sylvanas et Cairne.';
-- Quest 4022 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4022, 'frFR', '<Cyrus examine le mue.>$B$BVous avez prouvé que vous n\'êtes pas entièrement inutile, mortel.') ON DUPLICATE KEY UPDATE RewardText='<Cyrus examine le mue.>$B$BVous avez prouvé que vous n\'êtes pas entièrement inutile, mortel.';

-- Quest 4024 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4024, 'frFR', '<Cyrus arrache l\'essence ardente de vos mains.>$B$AU REVOIR!$B$Prenez votre prix et disparaissez. Quittez ma vue immédiatement!') ON DUPLICATE KEY UPDATE RewardText='<Cyrus arrache l\'essence ardente de vos mains.>$B$AU REVOIR!$B$Prenez votre prix et disparaissez. Quittez ma vue immédiatement!';
-- Quest 4041 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4041, 'frFR', 'Apportez-moi un Evoroot, et bien sûr, je peux vous préparer un Videre Elixir.$B$Je connais toutes sortes de choses sur les herbes et l\'alchimie... Pourquoi, laissez-moi vous raconter l\'histoire de la fois où j\'ai transmuté de l\'or à partir du fromage que j\'allais manger au déjeuner... hé... Où allez-vous?') ON DUPLICATE KEY UPDATE CompletionText='Apportez-moi un Evoroot, et bien sûr, je peux vous préparer un Videre Elixir.$B$Je connais toutes sortes de choses sur les herbes et l\'alchimie... Pourquoi, laissez-moi vous raconter l\'histoire de la fois où j\'ai transmuté de l\'or à partir du fromage que j\'allais manger au déjeuner... hé... Où allez-vous?';
-- Quest 4041 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4041, 'frFR', 'Alors, vous avez dupé le vieux Miblon, hein?') ON DUPLICATE KEY UPDATE RewardText='Alors, vous avez dupé le vieux Miblon, hein?';
-- Quest 4061 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4061, 'frFR', 'Ne prenez pas cette tâche à la légère, $N!') ON DUPLICATE KEY UPDATE CompletionText='Ne prenez pas cette tâche à la légère, $N!';
-- Quest 4063 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4063, 'frFR', 'Était-ce lui? Était-il vraiment vivant?') ON DUPLICATE KEY UPDATE CompletionText='Était-ce lui? Était-il vraiment vivant?';
-- Quest 4063 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4063, 'frFR', 'Qu\'est-ce que c\'est?!? Cette tête n\'est pas de la chair. C\'est une sorte de création en fer sombre : une ombre d\'Argelmach - UNE AUTRE machine! Je soupçonne que votre destruction d\'Argelmach sera brève car une autre s\'élèvera bientôt pour prendre sa place.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est?!? Cette tête n\'est pas de la chair. C\'est une sorte de création en fer sombre : une ombre d\'Argelmach - UNE AUTRE machine! Je soupçonne que votre destruction d\'Argelmach sera brève car une autre s\'élèvera bientôt pour prendre sa place.';
-- Quest 4081 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4081, 'frFR', 'Qu\'est-ce que c\'est, $r? Ne voyez-vous pas que j\'ai un peloton à commander?$B$B') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que c\'est, $r? Ne voyez-vous pas que j\'ai un peloton à commander?$B$B';
-- Quest 4081 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4081, 'frFR', 'Cette première frappe devrait mettre Angerforge dans le pétrin. Maintenant, allez-y soldat. J\'ai du travail à faire, des batailles à planifier, des ennemis à écraser!$B$Vérifiez les affiches de recherche pour plus de travail.') ON DUPLICATE KEY UPDATE RewardText='Cette première frappe devrait mettre Angerforge dans le pétrin. Maintenant, allez-y soldat. J\'ai du travail à faire, des batailles à planifier, des ennemis à écraser!$B$Vérifiez les affiches de recherche pour plus de travail.';
-- Quest 4082 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4082, 'frFR', 'Encore vous? Je dois l\'admettre, $N, vous êtes tenace.') ON DUPLICATE KEY UPDATE CompletionText='Encore vous? Je dois l\'admettre, $N, vous êtes tenace.';
-- Quest 4082 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4082, 'frFR', 'Angerforge est sans aucun doute... en colère. Revenez-moi lorsque vous aurez reçu un troisième tribut et nous procéderons à l\'Opération : Mort à Angerforge. Je ne peux entrer dans aucun détail de ce que cela implique, mais soyez assuré que cela implique quelqu\'un qui meurt.') ON DUPLICATE KEY UPDATE RewardText='Angerforge est sans aucun doute... en colère. Revenez-moi lorsque vous aurez reçu un troisième tribut et nous procéderons à l\'Opération : Mort à Angerforge. Je ne peux entrer dans aucun détail de ce que cela implique, mais soyez assuré que cela implique quelqu\'un qui meurt.';
-- Quest 4083 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4083, 'frFR', 'Le calice spectral flotte dans l\'air, ralentissant son ascension et sa chute... comme au rythme d\'un cœur mourant.') ON DUPLICATE KEY UPDATE CompletionText='Le calice spectral flotte dans l\'air, ralentissant son ascension et sa chute... comme au rythme d\'un cœur mourant.';
-- Quest 4103 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4103, 'frFR', 'Posséder un Phare de Cenarion permet de voir un éclat d\'âme corrompu sur ces bêtes souillées qui sont abattues pour le bien supérieur. Je broie les éclats en un réactif utilisable qui sert à fabriquer le baume de plante de Cenarion. Nous utiliserons ce baume pour transformer les plantes corrompues en plantes saines à nouveau.$b$En échange de ces éclats, je vous donnerai quelques baumes de plante de Cenarion que j\'ai déjà préparés.') ON DUPLICATE KEY UPDATE CompletionText='Posséder un Phare de Cenarion permet de voir un éclat d\'âme corrompu sur ces bêtes souillées qui sont abattues pour le bien supérieur. Je broie les éclats en un réactif utilisable qui sert à fabriquer le baume de plante de Cenarion. Nous utiliserons ce baume pour transformer les plantes corrompues en plantes saines à nouveau.$b$En échange de ces éclats, je vous donnerai quelques baumes de plante de Cenarion que j\'ai déjà préparés.';
-- Quest 4103 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4103, 'frFR', 'Très bien, voici vos baumes de plante de Cenarion. Parcourez Felwood à la recherche de plantes corrompues, $N! Où qu\'elles soient, utilisez le baume que je vous ai donné pour les purifier.') ON DUPLICATE KEY UPDATE RewardText='Très bien, voici vos baumes de plante de Cenarion. Parcourez Felwood à la recherche de plantes corrompues, $N! Où qu\'elles soient, utilisez le baume que je vous ai donné pour les purifier.';
-- Quest 4104 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4104, 'frFR', 'Si vous possédez un phare de Cenarion tout en minant dans Felwood, vous serez en mesure de voir un vitriol souillé qui corrompt une veine de métal brut. Je sais comment purifier ce vitriol et le transformer en un réactif qui sert à fabriquer le baume de plante de Cenarion. Vous utiliserez ensuite ce baume sur les plantes que vous trouvez dans la nature qui ont besoin d\'être sauvées.$b$Si vous avez collecté du vitriol souillé, je vous donnerai quelques baumes de plante de Cenarion que j\'ai déjà préparés.') ON DUPLICATE KEY UPDATE CompletionText='Si vous possédez un phare de Cenarion tout en minant dans Felwood, vous serez en mesure de voir un vitriol souillé qui corrompt une veine de métal brut. Je sais comment purifier ce vitriol et le transformer en un réactif qui sert à fabriquer le baume de plante de Cenarion. Vous utiliserez ensuite ce baume sur les plantes que vous trouvez dans la nature qui ont besoin d\'être sauvées.$b$Si vous avez collecté du vitriol souillé, je vous donnerai quelques baumes de plante de Cenarion que j\'ai déjà préparés.';
-- Quest 4104 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4104, 'frFR', 'Très bien, voici un baume de plante de Cenarion. Si vous trouvez plus de vitriol en minant dans Felwood, n\'oubliez pas de le garder pour moi! Plus vous en trouvez, plus je pourrai en faire de baume.') ON DUPLICATE KEY UPDATE RewardText='Très bien, voici un baume de plante de Cenarion. Si vous trouvez plus de vitriol en minant dans Felwood, n\'oubliez pas de le garder pour moi! Plus vous en trouvez, plus je pourrai en faire de baume.';

-- Quest 4105 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4105, 'frFR', 'Un balise de Cenarion permet à un herboriste expérimenté de repérer le rampant fel insidieux - un produit malfaisant de la corruption de Felwood. Mon travail ici m\'a enseigné la connaissance de la purification du rampant fel en un réactif purificateur... utilisé dans ce que nous appelons maintenant baume de plante de Cenarion.$b$bLorsque vous cueillez des herbes dans Felwood, vous devriez rencontrer le rampant fel tant que vous avez le balise. En échange de ce que vous m\'apportez, je vous donnerai un baume de plante de Cenarion préfabriqué.') ON DUPLICATE KEY UPDATE CompletionText='Un balise de Cenarion permet à un herboriste expérimenté de repérer le rampant fel insidieux - un produit malfaisant de la corruption de Felwood. Mon travail ici m\'a enseigné la connaissance de la purification du rampant fel en un réactif purificateur... utilisé dans ce que nous appelons maintenant baume de plante de Cenarion.$b$bLorsque vous cueillez des herbes dans Felwood, vous devriez rencontrer le rampant fel tant que vous avez le balise. En échange de ce que vous m\'apportez, je vous donnerai un baume de plante de Cenarion préfabriqué.';
-- Quest 4105 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4105, 'frFR', 'Excellent travail $N - chaque morceau de ceci, une fois purifié, nous aidera à reprendre Felwood. Voici, prenez quelques doses de baume de plante de Cenarion et allez dans la forêt. La reconquête de la terre contre la corruption n\'attend aucun $R!') ON DUPLICATE KEY UPDATE RewardText='Excellent travail $N - chaque morceau de ceci, une fois purifié, nous aidera à reprendre Felwood. Voici, prenez quelques doses de baume de plante de Cenarion et allez dans la forêt. La reconquête de la terre contre la corruption n\'attend aucun $R!';
-- Quest 4106 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4106, 'frFR', 'Un balise de Cenarion permettra à un peaux-cuirier bien entraîné de repérer des parches de peau souillée provenant des bêtes capturées dans Felwood. Je transforme ces parches apparemment inutiles en une pâte épaisse qui sert d\'agent accélérateur pour le baume de plante de Cenarion. Lorsque vous écorchez vos prises ici dans Felwood, assurez-vous d\'avoir un balise sur vous!$b$bLorsque vous collectez des parches souillées, apportez-les-moi et je vous donnerai des baumes de plante de Cenarion que j\'ai déjà préparés.') ON DUPLICATE KEY UPDATE CompletionText='Un balise de Cenarion permettra à un peaux-cuirier bien entraîné de repérer des parches de peau souillée provenant des bêtes capturées dans Felwood. Je transforme ces parches apparemment inutiles en une pâte épaisse qui sert d\'agent accélérateur pour le baume de plante de Cenarion. Lorsque vous écorchez vos prises ici dans Felwood, assurez-vous d\'avoir un balise sur vous!$b$bLorsque vous collectez des parches souillées, apportez-les-moi et je vous donnerai des baumes de plante de Cenarion que j\'ai déjà préparés.';
-- Quest 4106 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4106, 'frFR', 'C\'est exactement ce dont j\'ai besoin. Voici - prenez ces baumes de plante et utilisez-les pour reconquérir Felwood contre la corruption. Nous devons persévérer, $N!') ON DUPLICATE KEY UPDATE RewardText='C\'est exactement ce dont j\'ai besoin. Voici - prenez ces baumes de plante et utilisez-les pour reconquérir Felwood contre la corruption. Nous devons persévérer, $N!';
-- Quest 4107 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4107, 'frFR', 'La puissance d\'un objet magique désenchanté se ressent par l\'essence qu\'il crée. J\'ai trouvé un moyen de transformer l\'essence brute utilisée par les enchanteurs en un réactif approprié pour créer le baume de plante de Cenarion. Vous n\'avez pas besoin d\'un balise de Cenarion pour cela; tout objet suffisamment désenchanté qui donne des essences nether inférieures fonctionnera.$b$bJ\'ai juste besoin d\'une essence nether inférieure; en échange, je vous donnerai des baumes de plante de Cenarion. L\'essence est extrêmement puissante - un peu fait certainement beaucoup d\'effet!') ON DUPLICATE KEY UPDATE CompletionText='La puissance d\'un objet magique désenchanté se ressent par l\'essence qu\'il crée. J\'ai trouvé un moyen de transformer l\'essence brute utilisée par les enchanteurs en un réactif approprié pour créer le baume de plante de Cenarion. Vous n\'avez pas besoin d\'un balise de Cenarion pour cela; tout objet suffisamment désenchanté qui donne des essences nether inférieures fonctionnera.$b$bJ\'ai juste besoin d\'une essence nether inférieure; en échange, je vous donnerai des baumes de plante de Cenarion. L\'essence est extrêmement puissante - un peu fait certainement beaucoup d\'effet!';
-- Quest 4107 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4107, 'frFR', 'Voici quelques baumes de plante de Cenarion - j\'ai seulement besoin d\'une essence nether inférieure pour cela, $N. L\'essence est de loin l\'objet le plus puissant que je puisse utiliser pour transformer des épées en charrues, si l\'on veut. Si vous avez besoin de plus de baume, alors trouvez-moi ici!') ON DUPLICATE KEY UPDATE RewardText='Voici quelques baumes de plante de Cenarion - j\'ai seulement besoin d\'une essence nether inférieure pour cela, $N. L\'essence est de loin l\'objet le plus puissant que je puisse utiliser pour transformer des épées en charrues, si l\'on veut. Si vous avez besoin de plus de baume, alors trouvez-moi ici!';
-- Quest 4108 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4108, 'frFR', 'Posséder un balise de Cenarion permet de voir un éclat d\'âme corrompu sur ces bêtes souillées qui sont abattues pour le bien supérieur. Je mouds les éclats en un réactif utilisable qui entre dans la fabrication du baume de plante de Cenarion. Nous utiliserons ce baume pour transformer les plantes corrompues en plantes saines à nouveau.$b$bEn échange de ces éclats, je vous donnerai des baumes de plante de Cenarion que j\'ai déjà préparés.') ON DUPLICATE KEY UPDATE CompletionText='Posséder un balise de Cenarion permet de voir un éclat d\'âme corrompu sur ces bêtes souillées qui sont abattues pour le bien supérieur. Je mouds les éclats en un réactif utilisable qui entre dans la fabrication du baume de plante de Cenarion. Nous utiliserons ce baume pour transformer les plantes corrompues en plantes saines à nouveau.$b$bEn échange de ces éclats, je vous donnerai des baumes de plante de Cenarion que j\'ai déjà préparés.';
-- Quest 4108 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4108, 'frFR', 'Très bien alors, voici vos baumes de plante de Cenarion. Parcourez Felwood à la recherche de plantes corrompues, $N! Où qu\'elles soient, utilisez le baume que je vous ai donné pour les purifier.') ON DUPLICATE KEY UPDATE RewardText='Très bien alors, voici vos baumes de plante de Cenarion. Parcourez Felwood à la recherche de plantes corrompues, $N! Où qu\'elles soient, utilisez le baume que je vous ai donné pour les purifier.';
-- Quest 4109 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4109, 'frFR', 'Si vous possédez un balise de Cenarion en minant dans Felwood, vous pourrez voir un vitriol souillé qui corrompt une veine de métal brut. Je sais comment purifier ce vitriol et le transformer en un réactif qui entre dans la fabrication du baume de plante de Cenarion. Vous utiliserez ensuite ce baume sur les plantes que vous trouvez dans la nature qui ont besoin d\'être sauvées.$b$bSi vous avez collecté du vitriol souillé, je vous donnerai un baume de plante de Cenarion que j\'ai déjà préparé.') ON DUPLICATE KEY UPDATE CompletionText='Si vous possédez un balise de Cenarion en minant dans Felwood, vous pourrez voir un vitriol souillé qui corrompt une veine de métal brut. Je sais comment purifier ce vitriol et le transformer en un réactif qui entre dans la fabrication du baume de plante de Cenarion. Vous utiliserez ensuite ce baume sur les plantes que vous trouvez dans la nature qui ont besoin d\'être sauvées.$b$bSi vous avez collecté du vitriol souillé, je vous donnerai un baume de plante de Cenarion que j\'ai déjà préparé.';
-- Quest 4109 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4109, 'frFR', 'Très bien alors, voici un baume de plante de Cenarion. Si vous trouvez plus de vitriol en minant dans Felwood, n\'oubliez pas de le garder pour moi! Plus vous en trouvez, plus je pourrai en faire.') ON DUPLICATE KEY UPDATE RewardText='Très bien alors, voici un baume de plante de Cenarion. Si vous trouvez plus de vitriol en minant dans Felwood, n\'oubliez pas de le garder pour moi! Plus vous en trouvez, plus je pourrai en faire.';
