INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4110, 'frFR', 'Excellent travail $N - chaque morceau de ceci, une fois purifié, nous aidera à reprendre Felwood. Voici, prenez quelques doses de baume de plante de Cenarion et allez dans la forêt. La reconquête de la terre contre la corruption n\'attend aucun $R!') ON DUPLICATE KEY UPDATE RewardText='Excellent travail $N - chaque morceau de ceci, une fois purifié, nous aidera à reprendre Felwood. Voici, prenez quelques doses de baume de plante de Cenarion et allez dans la forêt. La reconquête de la terre contre la corruption n\'attend aucun $R!';
