-- Quest 4112 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4112, 'frFR', 'La puissance d\'un objet magique désenchanté se ressent par l\'essence qu\'il crée. J\'ai trouvé un moyen de transformer l\'essence brute utilisée par les enchanteurs en un réactif approprié pour créer le baume de plante de Cenarion. Vous n\'avez pas besoin d\'un balise de Cenarion pour cela; tout objet suffisamment désenchanté qui donne des essences nether inférieures fonctionnera.$b$bJ\'ai juste besoin d\'une essence nether inférieure; en échange, je vous donnerai des baumes de plante de Cenarion. L\'essence est extrêmement puissante - un peu fait certainement beaucoup d\'effet!') ON DUPLICATE KEY UPDATE CompletionText='La puissance d\'un objet magique désenchanté se ressent par l\'essence qu\'il crée. J\'ai trouvé un moyen de transformer l\'essence brute utilisée par les enchanteurs en un réactif approprié pour créer le baume de plante de Cenarion. Vous n\'avez pas besoin d\'un balise de Cenarion pour cela; tout objet suffisamment désenchanté qui donne des essences nether inférieures fonctionnera.$b$bJ\'ai juste besoin d\'une essence nether inférieure; en échange, je vous donnerai des baumes de plante de Cenarion. L\'essence est extrêmement puissante - un peu fait certainement beaucoup d\'effet!';

-- Quest 4112 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4112, 'frFR', 'J\'ai seulement besoin d\'une essence de Nether mineure pour ceci, $N. L\'essence est de loin l\'objet le plus puissant que je puisse utiliser pour transformer des épées en charrues, si l\'on veut. Si vous avez besoin de plus de baume, venez me voir ici !') ON DUPLICATE KEY UPDATE RewardText='J\'ai seulement besoin d\'une essence de Nether mineure pour ceci, $N. L\'essence est de loin l\'objet le plus puissant que je puisse utiliser pour transformer des épées en charrues, si l\'on veut. Si vous avez besoin de plus de baume, venez me voir ici !';
-- Quest 4113 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4113, 'frFR', 'Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur-chant. Une odeur âcre et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur-chant. Une odeur âcre et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.';
-- Quest 4113 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4113, 'frFR', 'Vous appliquez un baume de plante de Cenarion sur la fleur-chant.  Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez un baume de plante de Cenarion sur la fleur-chant.  Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
-- Quest 4114 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4114, 'frFR', 'Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur-chant. Une odeur âcre et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur-chant. Une odeur âcre et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.';
