-- Quest 4115 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4115, 'frFR', 'Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur-vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version maladive et corrompue de ce qui semble être une fleur-vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.';
-- Quest 4115 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4115, 'frFR', 'Vous appliquez deux baumes de plante de Cenarion à la fleur-vent.  Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez deux baumes de plante de Cenarion à la fleur-vent.  Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
