-- Quest 4117 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4117, 'frFR', 'Vous avez trouvé une version maladive et corrompue de ce qui semble être une racine-fouettard. Les racines visibles de la plante semblent dures et coriaces, et un film visqueux pend de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version maladive et corrompue de ce qui semble être une racine-fouettard. Les racines visibles de la plante semblent dures et coriaces, et un film visqueux pend de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.';
-- Quest 4117 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4117, 'frFR', 'Vous appliquez trois baumes de plante de Cenarion à la racine-fouettard. Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez trois baumes de plante de Cenarion à la racine-fouettard. Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
