-- Quest 4119 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4119, 'frFR', 'Vous avez trouvé une version maladive et corrompue de ce qui semble être une plante du dragon nocturne. Les fruits qui pendent de la plante semblent pourris et toxiques. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version maladive et corrompue de ce qui semble être une plante du dragon nocturne. Les fruits qui pendent de la plante semblent pourris et toxiques. Elle a désespérément besoin d\'un certain type d\'attention pour retrouver sa normalité.';
-- Quest 4119 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4119, 'frFR', 'Vous appliquez quatre baumes de plante de Cenarion au dragon nocturne. Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez quatre baumes de plante de Cenarion au dragon nocturne. Elle commence immédiatement à se défaire de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';

-- Quest 4120 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4120, 'frFR', 'Tout ce qui est touché par le fel émane une étrange lueur verte... Je sens que c\'est maléfique, mais en même temps, très puissant.') ON DUPLICATE KEY UPDATE CompletionText='Tout ce qui est touché par le fel émane une étrange lueur verte... Je sens que c\'est maléfique, mais en même temps, très puissant.';
-- Quest 4121 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4121, 'frFR', 'Je prendrai cette saleté traîtresse, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Je prendrai cette saleté traîtresse, $N$.';
-- Quest 4121 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4121, 'frFR', 'Vos exploits ne passeront pas inaperçus, <name>. Vous avez gagné ce tribut. Le Seigneur de Guerre vous parlera maintenant au sujet de la mission finale.') ON DUPLICATE KEY UPDATE RewardText='Vos exploits ne passeront pas inaperçus, <name>. Vous avez gagné ce tribut. Le Seigneur de Guerre vous parlera maintenant au sujet de la mission finale.';
-- Quest 4122 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4122, 'frFR', 'Ne voyez-vous pas le pouvoir que nous gagnons en rejoignant la légion de Blackrock ?') ON DUPLICATE KEY UPDATE RewardText='Ne voyez-vous pas le pouvoir que nous gagnons en rejoignant la légion de Blackrock ?';
-- Quest 4123 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4123, 'frFR', 'Avez-vous le Cœur de la Montagne ? Pour moi, sa valeur est illimitée.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous le Cœur de la Montagne ? Pour moi, sa valeur est illimitée.';
-- Quest 4126 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4126, 'frFR', 'Avez-vous la recette, $N$? Je ne supporte pas l\'idée que ces nains de Fer Noir boivent ma boisson de famille !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous la recette, $N$? Je ne supporte pas l\'idée que ces nains de Fer Noir boivent ma boisson de famille !';
-- Quest 4126 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4126, 'frFR', 'Vous l\'avez trouvé ! Bien joué ! Et j\'espère que vous avez bien donné une bonne gifle à ces Fer Noirs, et à Hurley Blackbreath!$B$BLes Thunderbrews sont à votre service, <name>. Vous êtes un héros des héros!') ON DUPLICATE KEY UPDATE RewardText='Vous l\'avez trouvé ! Bien joué ! Et j\'espère que vous avez bien donné une bonne gifle à ces Fer Noirs, et à Hurley Blackbreath!$B$BLes Thunderbrews sont à votre service, <name>. Vous êtes un héros des héros!';
-- Quest 4132 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4132, 'frFR', 'Le Boucher de Blackrock a-t-il été éliminé ?') ON DUPLICATE KEY UPDATE CompletionText='Le Boucher de Blackrock a-t-il été éliminé ?';
-- Quest 4132 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4132, 'frFR', 'Enfin ! Le coupable a été mis à justice ! Vous êtes un individu remarquable, $N$. Portez ce médaillon comme symbole de votre dévouement constant à la Horde et au K.E.F.') ON DUPLICATE KEY UPDATE RewardText='Enfin ! Le coupable a été mis à justice ! Vous êtes un individu remarquable, $N$. Portez ce médaillon comme symbole de votre dévouement constant à la Horde et au K.E.F.';
-- Quest 4133 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4133, 'frFR', 'Merci d\'être venu, <name>. Cet endroit n\'est pas sans un charme austère, mais il manque les commodités de l\'Apothicarium.$B$BAssez de politesses. À des affaires, oui ?') ON DUPLICATE KEY UPDATE RewardText='Merci d\'être venu, <name>. Cet endroit n\'est pas sans un charme austère, mais il manque les commodités de l\'Apothicarium.$B$BAssez de politesses. À des affaires, oui ?';
-- Quest 4134 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4134, 'frFR', 'Avez-vous la recette de la Lager Thunderbrew, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous la recette de la Lager Thunderbrew, $N$?';
-- Quest 4134 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4134, 'frFR', 'Très bien. Je vais envoyer cette recette à l\'Apothicarium pour qu\'elle soit étudiée, et avec le temps, nous débloquerons ses secrets. Un jour, les nains de l\'Alliance pourraient trouver les vertus de cette boisson utilisées contre eux!$B$BI trouve cela terriblement amusant. Peut-être que la mort a un effet sur le sens de l\'humour... tu crois ?') ON DUPLICATE KEY UPDATE RewardText='Très bien. Je vais envoyer cette recette à l\'Apothicarium pour qu\'elle soit étudiée, et avec le temps, nous débloquerons ses secrets. Un jour, les nains de l\'Alliance pourraient trouver les vertus de cette boisson utilisées contre eux!$B$BI trouve cela terriblement amusant. Peut-être que la mort a un effet sur le sens de l\'humour... tu crois ?';
-- Quest 4144 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4144, 'frFR', 'Voici le plan, $n: Va collecter des pousses de pétales de sang -- tu sais, les plantes qui n\'ont pas encore complètement poussé, et ramène-les ici. Ensuite, je verrai ce que la brume d\'Atal\'ai peut faire.$B$BTu peux penser que je suis vengeur... En fait, tu as raison à ce sujet ! $B$BLa vérité est que je connais la sortie de cet endroit, mais tant que Larion n\'admettra pas que j\'ai raison, je reste ici !$B$BAlors, va-t\'en, trouve ces pousses de pétales de sang et amusons-nous !') ON DUPLICATE KEY UPDATE CompletionText='Voici le plan, $n: Va collecter des pousses de pétales de sang -- tu sais, les plantes qui n\'ont pas encore complètement poussé, et ramène-les ici. Ensuite, je verrai ce que la brume d\'Atal\'ai peut faire.$B$BTu peux penser que je suis vengeur... En fait, tu as raison à ce sujet ! $B$BLa vérité est que je connais la sortie de cet endroit, mais tant que Larion n\'admettra pas que j\'ai raison, je reste ici !$B$BAlors, va-t\'en, trouve ces pousses de pétales de sang et amusons-nous !';
-- Quest 4144 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4144, 'frFR', 'Je me lance, <name>! Ça va attirer l\'attention de Larion !') ON DUPLICATE KEY UPDATE RewardText='Je me lance, <name>! Ça va attirer l\'attention de Larion !';
-- Quest 4145 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4145, 'frFR', 'Muigin doit s\'excuser d\'abord avant que je ne lui parle à nouveau !') ON DUPLICATE KEY UPDATE CompletionText='Muigin doit s\'excuser d\'abord avant que je ne lui parle à nouveau !';

-- Quest 4148 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4148, 'frFR', 'Pour que le pistolet fonctionne, il faut un échantillon de la créature cible. Pars dans le cratère et cueille un bourgeon de Pétale de Sang. Ensuite, je peux l\'étalonner pour qu\'il fonctionne sur les petits amis de Muigin...$b$bS\'il n\'était pas si têtu, nous serions déjà sur le chemin du retour, déjà... Mais d\'ici là, je devrai juste lui montrer que sa petite farce ne m\'affecte pas du tout !') ON DUPLICATE KEY UPDATE CompletionText='Pour que le pistolet fonctionne, il faut un échantillon de la créature cible. Pars dans le cratère et cueille un bourgeon de Pétale de Sang. Ensuite, je peux l\'étalonner pour qu\'il fonctionne sur les petits amis de Muigin...$b$bS\'il n\'était pas si têtu, nous serions déjà sur le chemin du retour, déjà... Mais d\'ici là, je devrai juste lui montrer que sa petite farce ne m\'affecte pas du tout !';
-- Quest 4148 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4148, 'frFR', 'Il semble que cela va fonctionner parfaitement, <name>. Maintenant, souviens-toi, si tu vois ces nuisibles par ici, n\'hésite pas à utiliser ce pistolet !') ON DUPLICATE KEY UPDATE RewardText='Il semble que cela va fonctionner parfaitement, <name>. Maintenant, souviens-toi, si tu vois ces nuisibles par ici, n\'hésite pas à utiliser ce pistolet !';
-- Quest 4181 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4181, 'frFR', 'Je peux sentir les nouveaux recrues tout comme je peux sentir une excellente poudre explosive - à un kilomètre. Es-tu venu chercher à apprendre la maîtrise de l\'explosion ?') ON DUPLICATE KEY UPDATE CompletionText='Je peux sentir les nouveaux recrues tout comme je peux sentir une excellente poudre explosive - à un kilomètre. Es-tu venu chercher à apprendre la maîtrise de l\'explosion ?';
-- Quest 4181 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4181, 'frFR', 'Eh bien $N, tu as bien fait de chercher mon enseignement ! N\'importe quel clochard peut devenir un expert des bases de l\'ingénierie - les gnomes et leur foyer irradié de Gnomeregan en sont la preuve. Il faut cependant un esprit fort et une main ferme (insistance sur FERME) pour maîtriser la discipline de l\'Ingénierie Gobeline.$B$BGardes tes oreilles ouvertes $N, et tu pourrais apprendre quelque chose.') ON DUPLICATE KEY UPDATE RewardText='Eh bien $N, tu as bien fait de chercher mon enseignement ! N\'importe quel clochard peut devenir un expert des bases de l\'ingénierie - les gnomes et leur foyer irradié de Gnomeregan en sont la preuve. Il faut cependant un esprit fort et une main ferme (insistance sur FERME) pour maîtriser la discipline de l\'Ingénierie Gobeline.$B$BGardes tes oreilles ouvertes $N, et tu pourrais apprendre quelque chose.';
-- Quest 4182 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4182, 'frFR', 'Une chasse superbe, $N. Maintenant que nous savons que tu peux te débrouiller avec les dragonkind, nous pouvons parler de sujets plus urgents.') ON DUPLICATE KEY UPDATE RewardText='Une chasse superbe, $N. Maintenant que nous savons que tu peux te débrouiller avec les dragonkind, nous pouvons parler de sujets plus urgents.';
-- Quest 4183 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4183, 'frFR', 'Salutations, $N. Nous nous sommes déjà rencontrés ? Tu me sembles vaguement familier.') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $N. Nous nous sommes déjà rencontrés ? Tu me sembles vaguement familier.';
-- Quest 4184 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4184, 'frFR', 'Qu\'est-ce qui t\'amène au Fort de Stormwind ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui t\'amène au Fort de Stormwind ?';
-- Quest 4185 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4185, 'frFR', '<Bolvar se frotte le menton comme s\'il était en profonde réflexion.>$B$BBien que je respecte la position de Lady Prestor, je crois qu\'il existe une solution à ce dilemme qui pourrait apaiser toutes nos préoccupations.') ON DUPLICATE KEY UPDATE RewardText='<Bolvar se frotte le menton comme s\'il était en profonde réflexion.>$B$BBien que je respecte la position de Lady Prestor, je crois qu\'il existe une solution à ce dilemme qui pourrait apaiser toutes nos préoccupations.';
-- Quest 4186 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4186, 'frFR', 'Cela aurait pu être pire, je suppose...$B$B<Le Magistrat Solomon vous examine.>$B$BIl semble que le destin de Lakeshire repose entièrement sur tes épaules.$B$B<Vous remarquez que le Magistrat Solomon cligne des yeux rapidement. Il semble pleurer.>') ON DUPLICATE KEY UPDATE RewardText='Cela aurait pu être pire, je suppose...$B$B<Le Magistrat Solomon vous examine.>$B$BIl semble que le destin de Lakeshire repose entièrement sur tes épaules.$B$B<Vous remarquez que le Magistrat Solomon cligne des yeux rapidement. Il semble pleurer.>';
-- Quest 4201 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4201, 'frFR', 'As-tu les ingrédients ? Le trou dans mon cœur menace de me consumer !') ON DUPLICATE KEY UPDATE CompletionText='As-tu les ingrédients ? Le trou dans mon cœur menace de me consumer !';
-- Quest 4201 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4201, 'frFR', 'Oh, tu y es arrivé !  Je peux maintenant faire ma potion et l\'utiliser sur Rocknot.  Finalement, il sera victime de mes charmes !$B$BMerci, <name>.  Tu es un champion de l\'amour !') ON DUPLICATE KEY UPDATE RewardText='Oh, tu y es arrivé !  Je peux maintenant faire ma potion et l\'utiliser sur Rocknot.  Finalement, il sera victime de mes charmes !$B$BMerci, <name>.  Tu es un champion de l\'amour !';
-- Quest 4221 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4221, 'frFR', 'Tu as trouvé une version malade et corrompue de ce qui ressemble à une fleur du vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.') ON DUPLICATE KEY UPDATE CompletionText='Tu as trouvé une version malade et corrompue de ce qui ressemble à une fleur du vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.';
-- Quest 4221 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4221, 'frFR', 'Tu appliques deux onguents de plante de Cenarion à la fleur du vent.  Elle commence immédiatement à perdre sa forme corrompue, fleurissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Tu appliques deux onguents de plante de Cenarion à la fleur du vent.  Elle commence immédiatement à perdre sa forme corrompue, fleurissant en une plante vibrante et saine.';
-- Quest 4222 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4222, 'frFR', 'Tu as trouvé une version malade et corrompue de ce qui ressemble à une fleur du vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.') ON DUPLICATE KEY UPDATE CompletionText='Tu as trouvé une version malade et corrompue de ce qui ressemble à une fleur du vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.';
-- Quest 4222 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4222, 'frFR', 'Tu appliques deux onguents de plante de Cenarion à la fleur du vent. Elle commence immédiatement à perdre sa forme corrompue, fleurissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Tu appliques deux onguents de plante de Cenarion à la fleur du vent. Elle commence immédiatement à perdre sa forme corrompue, fleurissant en une plante vibrante et saine.';

-- Quest 4224 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4224, 'frFR', 'Avez-vous parlé à John ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous parlé à John ?';
-- Quest 4224 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4224, 'frFR', 'Je pouvais vous prévenir, mais quel plaisir est-ce ?') ON DUPLICATE KEY UPDATE RewardText='Je pouvais vous prévenir, mais quel plaisir est-ce ?';
-- Quest 4242 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4242, 'frFR', 'Il est devenu fou, apparemment.$B$B<Maxwell baisse la tête en signe de deuil.>$B$BIl est regrettable qu\'un guerrier autrefois fier et noble soit transformé en tête brûlée. JE SUPPOSE que nous sommes arrivés à une impasse...$B$BI dois vous récompenser pour vos efforts jusqu\'à présent, $N.') ON DUPLICATE KEY UPDATE RewardText='Il est devenu fou, apparemment.$B$B<Maxwell baisse la tête en signe de deuil.>$B$BIl est regrettable qu\'un guerrier autrefois fier et noble soit transformé en tête brûlée. JE SUPPOSE que nous sommes arrivés à une impasse...$B$BI dois vous récompenser pour vos efforts jusqu\'à présent, $N.';
-- Quest 4245 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4245, 'frFR', 'Avez-vous pu aider A-Me ? Ce boîtier de mithril que vous avez mentionné comme étant détruit était une bonne supposition de ce qui n\'allait pas. Je suis sûr que si vous le remplacez, elle se réactivera et pourra rentrer chez elle.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous pu aider A-Me ? Ce boîtier de mithril que vous avez mentionné comme étant détruit était une bonne supposition de ce qui n\'allait pas. Je suis sûr que si vous le remplacez, elle se réactivera et pourra rentrer chez elle.';
-- Quest 4263 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4263, 'frFR', 'Oh là là ! Êtes-vous sûr qu\'Incendius ait dit \'Ragnaros\' ?$b$b<Jalinda vous tend quelque chose et vous tapote le poignet en s\'enfonçant dans ses pensées.>') ON DUPLICATE KEY UPDATE RewardText='Oh là là ! Êtes-vous sûr qu\'Incendius ait dit \'Ragnaros\' ?$b$b<Jalinda vous tend quelque chose et vous tapote le poignet en s\'enfonçant dans ses pensées.>';
-- Quest 4265 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4265, 'frFR', 'Vous avez quelque chose à signaler, $n ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez quelque chose à signaler, $n ?';
-- Quest 4282 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4282, 'frFR', 'Bientôt ce grand subterfuge sera terminé.') ON DUPLICATE KEY UPDATE CompletionText='Bientôt ce grand subterfuge sera terminé.';
-- Quest 4285 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4285, 'frFR', 'Avez-vous visité le pylône, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous visité le pylône, $N?';
-- Quest 4287 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4287, 'frFR', 'Avez-vous visité le pylône, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous visité le pylône, $N?';
-- Quest 4288 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4288, 'frFR', 'Avez-vous visité le pylône, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous visité le pylône, $N?';
-- Quest 4293 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4293, 'frFR', 'J\'aurai besoin d\'au moins cinq échantillons corrompus pour notre groupe de contrôle, $N. Continuez à recueillir des échantillons de slime de Felwood jusqu\'à ce que vous puissiez me donner ce dont nous aurons besoin. La Dame Sylvanas le décrète...') ON DUPLICATE KEY UPDATE CompletionText='J\'aurai besoin d\'au moins cinq échantillons corrompus pour notre groupe de contrôle, $N. Continuez à recueillir des échantillons de slime de Felwood jusqu\'à ce que vous puissiez me donner ce dont nous aurons besoin. La Dame Sylvanas le décrète...';
-- Quest 4294 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4294, 'frFR', 'Vraiment incroyable, <name>. Ce Crater d\'Un\'Goro contient bien plus de secrets que je ne le pensais. Je me demande ce que nous allons découvrir en continuant nos tests.$B$BSimplement incroyable... regardez la pureté de ces échantillons. Hmm, je me demande ce que cela pourrait signifier. Ils semblent être de nature élémentaire, mais... quelque chose de plus. Ils me rappellent... les Anciens Dieux. Nous avons trouvé des traces d\'eux partout dans Azeroth, et maintenant je me demande si ces créatures ne sont pas liées à eux d\'une manière ou d\'une autre.$B$BNous devrons tester davantage.') ON DUPLICATE KEY UPDATE RewardText='Vraiment incroyable, <name>. Ce Crater d\'Un\'Goro contient bien plus de secrets que je ne le pensais. Je me demande ce que nous allons découvrir en continuant nos tests.$B$BSimplement incroyable... regardez la pureté de ces échantillons. Hmm, je me demande ce que cela pourrait signifier. Ils semblent être de nature élémentaire, mais... quelque chose de plus. Ils me rappellent... les Anciens Dieux. Nous avons trouvé des traces d\'eux partout dans Azeroth, et maintenant je me demande si ces créatures ne sont pas liées à eux d\'une manière ou d\'une autre.$B$BNous devrons tester davantage.';
-- Quest 4295 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4295, 'frFR', 'Oh, ale ! Je tuerais pour une ale de Fer Noir !! Vite, je me reprenais ! Je sais cela parce que la sobriété brouille ma vision... et ça te fait ressembler à $r que j\'ai abattu la semaine dernière !') ON DUPLICATE KEY UPDATE CompletionText='Oh, ale ! Je tuerais pour une ale de Fer Noir !! Vite, je me reprenais ! Je sais cela parce que la sobriété brouille ma vision... et ça te fait ressembler à $r que j\'ai abattu la semaine dernière !';
-- Quest 4296 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4296, 'frFR', 'Avez-vous les écrits des Sept, $N? Avez-vous appris les secrets de leur tablette ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les écrits des Sept, $N? Avez-vous appris les secrets de leur tablette ?';

-- Quest 4297 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4297, 'frFR', 'Tu as trouvé cette viande, $N ? Ton petit œuf est presque prêt à éclore. S\'il n\'a pas un premier repas assez bon, il pourrait ne pas survivre à sa première semaine, et je détesterais que cela arrive.$B$BJe ne vais pas te mentir, $N. Je suis jaloux que tu aies réussi à obtenir cet œuf en premier. Ne me fais pas regretter de t\'aider comme ça.') ON DUPLICATE KEY UPDATE CompletionText='Tu as trouvé cette viande, $N ? Ton petit œuf est presque prêt à éclore. S\'il n\'a pas un premier repas assez bon, il pourrait ne pas survivre à sa première semaine, et je détesterais que cela arrive.$B$BJe ne vais pas te mentir, $N. Je suis jaloux que tu aies réussi à obtenir cet œuf en premier. Ne me fais pas regretter de t\'aider comme ça.';
-- Quest 4297 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4297, 'frFR', 'Ça fera du bien, et si je ne me trompe pas, ton petit œuf est sur le point d\'éclore. Comment te sens-tu ? Tu sais, tu vas devenir père ? Haha, je ne pensais pas que tu devrais gérer une telle responsabilité, maintenant oui ?') ON DUPLICATE KEY UPDATE RewardText='Ça fera du bien, et si je ne me trompe pas, ton petit œuf est sur le point d\'éclore. Comment te sens-tu ? Tu sais, tu vas devenir père ? Haha, je ne pensais pas que tu devrais gérer une telle responsabilité, maintenant oui ?';
-- Quest 4322 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4322, 'frFR', 'Tu as l\'air épuisé, $n. Peut-être devrais-tu t\'asseoir près du feu et te détendre.') ON DUPLICATE KEY UPDATE CompletionText='Tu as l\'air épuisé, $n. Peut-être devrais-tu t\'asseoir près du feu et te détendre.';
-- Quest 4322 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4322, 'frFR', 'Étonnant, $N. Simplement étonnant. Windsor est passé par ici il y a moins de cinq minutes. Il fait de grandes déclarations mais prétend qu\'elles sont soutenues par ses preuves. Il se dirige maintenant vers Stormwind pour confronter Bolvar et ... Lady Prestor.') ON DUPLICATE KEY UPDATE RewardText='Étonnant, $N. Simplement étonnant. Windsor est passé par ici il y a moins de cinq minutes. Il fait de grandes déclarations mais prétend qu\'elles sont soutenues par ses preuves. Il se dirige maintenant vers Stormwind pour confronter Bolvar et ... Lady Prestor.';
-- Quest 4342 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4342, 'frFR', 'Permettez-moi de finir mon histoire.') ON DUPLICATE KEY UPDATE CompletionText='Permettez-moi de finir mon histoire.';
-- Quest 4342 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4342, 'frFR', 'Comme vous pouvez le voir, il n\'y avait rien que je puisse faire.') ON DUPLICATE KEY UPDATE RewardText='Comme vous pouvez le voir, il n\'y avait rien que je puisse faire.';
-- Quest 4343 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4343, 'frFR', 'Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur de vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur de vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.';
-- Quest 4343 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4343, 'frFR', 'Vous appliquez deux onguents de plante de Cenarion à la fleur de vent. Elle commence immédiatement à perdre sa forme corrompue, fleurissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez deux onguents de plante de Cenarion à la fleur de vent. Elle commence immédiatement à perdre sa forme corrompue, fleurissant en une plante vibrante et saine.';
-- Quest 4381 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4381, 'frFR', 'La table de Pylon vous permet de combiner des cristaux de puissance verts avec des cristaux de puissance jaunes.$B$BSelon le manuel de J.D., cette combinaison peut être utilisée pour vous soigner vous-même ou vos alliés.') ON DUPLICATE KEY UPDATE CompletionText='La table de Pylon vous permet de combiner des cristaux de puissance verts avec des cristaux de puissance jaunes.$B$BSelon le manuel de J.D., cette combinaison peut être utilisée pour vous soigner vous-même ou vos alliés.';
