INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4381, 'frFR', 'En disposant les cristaux sur la table, vous alignez soigneusement les couleurs. Lorsque vous poussez le dernier en place, une explosion de lumière fusionne les cristaux.$B$BLa combinaison résultante est maintenant la vôtre.') ON DUPLICATE KEY UPDATE RewardText='En disposant les cristaux sur la table, vous alignez soigneusement les couleurs. Lorsque vous poussez le dernier en place, une explosion de lumière fusionne les cristaux.$B$BLa combinaison résultante est maintenant la vôtre.';
