INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4401, 'frFR', 'Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur de chant. Une odeur âcre et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour être ramenée à la normale.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez trouvé une version malade et corrompue de ce qui semble être une fleur de chant. Une odeur âcre et malsaine émane de la plante. Elle a désespérément besoin d\'un certain type d\'attention pour être ramenée à la normale.';
