INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4401, 'frFR', 'Vous appliquez une pommade végétale de Cenarion sur la fleur de chant.  Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Vous appliquez une pommade végétale de Cenarion sur la fleur de chant.  Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
