INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4466, 'frFR', 'Tu appliques deux pommades de plante de Cenarion à la fleur-vent.  Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Tu appliques deux pommades de plante de Cenarion à la fleur-vent.  Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
