INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4467, 'frFR', 'Tu as trouvé une version malade et corrompue de ce qui semble être une fleur-vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.') ON DUPLICATE KEY UPDATE CompletionText='Tu as trouvé une version malade et corrompue de ce qui semble être une fleur-vent. Les baies qui pendent de la plante semblent pourries et toxiques. Elle a désespérément besoin d\'un certain type d\'attention si elle doit redevenir normale.';
-- Quest 4467 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4467, 'frFR', 'Tu appliques deux pommades de plante de Cenarion à la fleur-vent.  Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.') ON DUPLICATE KEY UPDATE RewardText='Tu appliques deux pommades de plante de Cenarion à la fleur-vent.  Elle commence immédiatement à se débarrasser de sa forme corrompue, s\'épanouissant en une plante vibrante et saine.';
-- Quest 4481 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4481, 'frFR', 'Il y a un prix à payer pour toutes les choses dans ce monde. Le prix pour l\'objet spécifique que tu recherches est de trente pièces d\'or.$B$BNaturellement, je conserverai la majorité des composants que tu as collectés. Mais ne t\'inquiète pas, tu auras ton bibelot.') ON DUPLICATE KEY UPDATE CompletionText='Il y a un prix à payer pour toutes les choses dans ce monde. Le prix pour l\'objet spécifique que tu recherches est de trente pièces d\'or.$B$BNaturellement, je conserverai la majorité des composants que tu as collectés. Mais ne t\'inquiète pas, tu auras ton bibelot.';
-- Quest 4481 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4481, 'frFR', 'C\'est une disgrâce pour sa mémoire... un mortel, tel que toi, achevant l\'œuvre de sa vie.$B$Prends ton amalgame et disparais !') ON DUPLICATE KEY UPDATE RewardText='C\'est une disgrâce pour sa mémoire... un mortel, tel que toi, achevant l\'œuvre de sa vie.$B$Prends ton amalgame et disparais !';
-- Quest 4482 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4482, 'frFR', 'Trente pièces d\'or, $R. Trente pièces d\'or et les composants requis.') ON DUPLICATE KEY UPDATE CompletionText='Trente pièces d\'or, $R. Trente pièces d\'or et les composants requis.';
-- Quest 4482 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4482, 'frFR', 'Il a fallu à Kariel ce qui équivaut à plusieurs de tes vies pour compléter le livre que tu tiens maintenant, $R. Pour quoi faire ? Pour que son disciple puisse se tenir dans les Steppes Ardentes et bastardiser ses recherches afin de satisfaire une soif arcanique sans fin... Maudis cette fâcheuse addiction.$B$Je suis dégoûté par ton manque de compassion et ta cupidité insatiable. Pars !') ON DUPLICATE KEY UPDATE RewardText='Il a fallu à Kariel ce qui équivaut à plusieurs de tes vies pour compléter le livre que tu tiens maintenant, $R. Pour quoi faire ? Pour que son disciple puisse se tenir dans les Steppes Ardentes et bastardiser ses recherches afin de satisfaire une soif arcanique sans fin... Maudis cette fâcheuse addiction.$B$Je suis dégoûté par ton manque de compassion et ta cupidité insatiable. Pars !';
-- Quest 4483 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4483, 'frFR', 'Si c\'est la résilience que tu désires, je demande trente pièces d\'or.') ON DUPLICATE KEY UPDATE CompletionText='Si c\'est la résilience que tu désires, je demande trente pièces d\'or.';

-- Quest 4483 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4483, 'frFR', 'D\'autres livres sont perdus dans ce monde. Perdus dans des endroits auxquels vous n\'oseriez pas entrer. Des endroits où vous prieriez pour qu\'ils n\'existent pas.$B$BI boira les énergies de ces composants. Vous recevrez les déchets résiduels...') ON DUPLICATE KEY UPDATE RewardText='D\'autres livres sont perdus dans ce monde. Perdus dans des endroits auxquels vous n\'oseriez pas entrer. Des endroits où vous prieriez pour qu\'ils n\'existent pas.$B$BI boira les énergies de ces composants. Vous recevrez les déchets résiduels...';
-- Quest 4484 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4484, 'frFR', 'Ne perds pas mon temps, $R. Donne-moi ce dont j\'ai besoin. Trente pièces d\'or et les composants.') ON DUPLICATE KEY UPDATE CompletionText='Ne perds pas mon temps, $R. Donne-moi ce dont j\'ai besoin. Trente pièces d\'or et les composants.';
-- Quest 4484 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4484, 'frFR', 'Ma tête bat... Les énergies des vastes étendues qui constituent notre univers... ARGGH!$B$B<Mathredis a l\'air souffrant.>$B$BPrends ce que tu désires et pars !') ON DUPLICATE KEY UPDATE RewardText='Ma tête bat... Les énergies des vastes étendues qui constituent notre univers... ARGGH!$B$B<Mathredis a l\'air souffrant.>$B$BPrends ce que tu désires et pars !';
-- Quest 4485 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4485, 'frFR', 'Ah, tu es revenu à la Cathédrale, $N. Bien. Beaucoup de choses se sont passées récemment, et je chercherais ton aide si tu te prouves digne.$B$BDe nombreux ennemis traîtres sont en approche. J\'aurai besoin de ton aide pour les arrêter.') ON DUPLICATE KEY UPDATE RewardText='Ah, tu es revenu à la Cathédrale, $N. Bien. Beaucoup de choses se sont passées récemment, et je chercherais ton aide si tu te prouves digne.$B$BDe nombreux ennemis traîtres sont en approche. J\'aurai besoin de ton aide pour les arrêter.';
-- Quest 4486 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4486, 'frFR', 'Ah, tu es revenu à la Cathédrale, $N. Bien. Beaucoup de choses se sont passées récemment, et je chercherais ton aide si tu te prouves digne.$B$BDe nombreux ennemis traîtres sont en approche. J\'aurai besoin de ton aide pour les arrêter.') ON DUPLICATE KEY UPDATE RewardText='Ah, tu es revenu à la Cathédrale, $N. Bien. Beaucoup de choses se sont passées récemment, et je chercherais ton aide si tu te prouves digne.$B$BDe nombreux ennemis traîtres sont en approche. J\'aurai besoin de ton aide pour les arrêter.';
-- Quest 4489 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4489, 'frFR', 'Alors, tu as décidé de m\'honorer de ta présence à nouveau. Quelle gentillesse.$B$BMes acolytes se demandaient si tu allais jamais apparaître. Je leur ai dit qu\'il n\'y avait aucun doute. Quand il s\'agit de pouvoir, tu es attiré comme un papillon par la flamme.') ON DUPLICATE KEY UPDATE RewardText='Alors, tu as décidé de m\'honorer de ta présence à nouveau. Quelle gentillesse.$B$BMes acolytes se demandaient si tu allais jamais apparaître. Je leur ai dit qu\'il n\'y avait aucun doute. Quand il s\'agit de pouvoir, tu es attiré comme un papillon par la flamme.';
-- Quest 4490 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4490, 'frFR', 'Bonne chance, $N. J\'attends avec impatience de te revoir dans le futur.') ON DUPLICATE KEY UPDATE RewardText='Bonne chance, $N. J\'attends avec impatience de te revoir dans le futur.';
-- Quest 4491 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4491, 'frFR', 'Je m\'inquiétais tellement pour Ringo...') ON DUPLICATE KEY UPDATE CompletionText='Je m\'inquiétais tellement pour Ringo...';
-- Quest 4493 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4493, 'frFR', 'Oui, j\'ai compris que Gracina t\'avait envoyé chez moi. Ton expérience dans le combat contre ces bêtes est inestimable ; à ma connaissance, personne n\'a jamais affaire à leur espèce auparavant. Quant à l\'idée de Gracina selon laquelle le Cratère d\'Un\'Goro est leur cœur... peut-être que c\'est le cas. Un\'Goro est une jungle mystérieuse et dangereuse à l\'ouest d\'ici. Peut-être est-ce aussi un pas de plus pour comprendre ce qu\'est le silithid.') ON DUPLICATE KEY UPDATE RewardText='Oui, j\'ai compris que Gracina t\'avait envoyé chez moi. Ton expérience dans le combat contre ces bêtes est inestimable ; à ma connaissance, personne n\'a jamais affaire à leur espèce auparavant. Quant à l\'idée de Gracina selon laquelle le Cratère d\'Un\'Goro est leur cœur... peut-être que c\'est le cas. Un\'Goro est une jungle mystérieuse et dangereuse à l\'ouest d\'ici. Peut-être est-ce aussi un pas de plus pour comprendre ce qu\'est le silithid.';
-- Quest 4494 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4494, 'frFR', 'Oui, j\'ai compris que Zilzibin t\'avait envoyé chez moi. Ton expérience dans le combat contre ces bêtes est inestimable ; à ma connaissance, personne n\'a jamais affaire à leur espèce auparavant. Quant à l\'idée de Zil selon laquelle le Cratère d\'Un\'Goro est leur cœur... peut-être que c\'est le cas. Un\'Goro est une jungle mystérieuse et dangereuse à l\'ouest d\'ici. Peut-être est-ce aussi un pas de plus pour comprendre ce qu\'est le silithid.') ON DUPLICATE KEY UPDATE RewardText='Oui, j\'ai compris que Zilzibin t\'avait envoyé chez moi. Ton expérience dans le combat contre ces bêtes est inestimable ; à ma connaissance, personne n\'a jamais affaire à leur espèce auparavant. Quant à l\'idée de Zil selon laquelle le Cratère d\'Un\'Goro est leur cœur... peut-être que c\'est le cas. Un\'Goro est une jungle mystérieuse et dangereuse à l\'ouest d\'ici. Peut-être est-ce aussi un pas de plus pour comprendre ce qu\'est le silithid.';
-- Quest 4501 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4501, 'frFR', 'Pour être honnête, je ne m\'inquiétais pas vraiment pour ces créatures étranges... Jusqu\'au jour où j\'ai vu écrit sur le côté d\'une grande pierre.$B$BFAITES ATTENTION À PTERRORDAX$B$BQui a pu l\'écrire ? Je ne sais pas, mais c\'est trop effrayant pour l\'ignorer !') ON DUPLICATE KEY UPDATE CompletionText='Pour être honnête, je ne m\'inquiétais pas vraiment pour ces créatures étranges... Jusqu\'au jour où j\'ai vu écrit sur le côté d\'une grande pierre.$B$BFAITES ATTENTION À PTERRORDAX$B$BQui a pu l\'écrire ? Je ne sais pas, mais c\'est trop effrayant pour l\'ignorer !';
-- Quest 4502 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4502, 'frFR', 'Est-ce vrai que le volcan d\'Un\'Goro est actif ? Je suis sûr que je pourrais apprendre beaucoup avec un peu de cendre du volcan, $N.') ON DUPLICATE KEY UPDATE CompletionText='Est-ce vrai que le volcan d\'Un\'Goro est actif ? Je suis sûr que je pourrais apprendre beaucoup avec un peu de cendre du volcan, $N.';
-- Quest 4502 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4502, 'frFR', 'Ces échantillons seront parfaits pour mes études ! Merci, $N! Je promets, tu seras le premier à qui je parlerai de mes découvertes.') ON DUPLICATE KEY UPDATE RewardText='Ces échantillons seront parfaits pour mes études ! Merci, $N! Je promets, tu seras le premier à qui je parlerai de mes découvertes.';
-- Quest 4506 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4506, 'frFR', 'Ne me dis pas que tu ne peux pas y retourner ! Pars !') ON DUPLICATE KEY UPDATE CompletionText='Ne me dis pas que tu ne peux pas y retourner ! Pars !';
-- Quest 4507 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4507, 'frFR', 'Acquérir le cerveau de la reine pour notre recherche est absolument impératif. D\'après ce que nous avons appris, nous croyons que ces silithid sont très probablement contrôlés par une intelligence maligne. Je frissonne à l\'idée de ce qui pourrait contrôler quelque chose d\'aussi insidieux que les silithid, $N.') ON DUPLICATE KEY UPDATE CompletionText='Acquérir le cerveau de la reine pour notre recherche est absolument impératif. D\'après ce que nous avons appris, nous croyons que ces silithid sont très probablement contrôlés par une intelligence maligne. Je frissonne à l\'idée de ce qui pourrait contrôler quelque chose d\'aussi insidieux que les silithid, $N.';

-- Quest 4507 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4507, 'frFR', 'Fantastique, <name>!  Nous avons remporté une victoire remarquable aujourd\'hui.  Il faudra du temps pour que nous comprenions tout ce qui s\'est passé ici ; nous en ferons bon usage, ne vous inquiétez pas.$B$BPour les silithides, je doute sincèrement que ce soit l\'étendue totale de leur présence.  C\'est beaucoup trop propre une résolution, je le regrette.') ON DUPLICATE KEY UPDATE RewardText='Fantastique, <name>!  Nous avons remporté une victoire remarquable aujourd\'hui.  Il faudra du temps pour que nous comprenions tout ce qui s\'est passé ici ; nous en ferons bon usage, ne vous inquiétez pas.$B$BPour les silithides, je doute sincèrement que ce soit l\'étendue totale de leur présence.  C\'est beaucoup trop propre une résolution, je le regrette.';
-- Quest 4508 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4508, 'frFR', 'Ce sont des imbéciles, $N!  Ils ne peuvent même pas penser à regarder autour d\'eux pour une menace plus grande ; leur haine irrationnelle de la Horde sera notre perte.  Je ne sais pas combien de preuves supplémentaires je peux leur donner de la menace silithide sans les jeter dans l\'une des ruches pour qu\'ils le voient par eux-mêmes !$B$BI\'m sorry, vous apportez des nouvelles pour mon attention ?') ON DUPLICATE KEY UPDATE CompletionText='Ce sont des imbéciles, $N!  Ils ne peuvent même pas penser à regarder autour d\'eux pour une menace plus grande ; leur haine irrationnelle de la Horde sera notre perte.  Je ne sais pas combien de preuves supplémentaires je peux leur donner de la menace silithide sans les jeter dans l\'une des ruches pour qu\'ils le voient par eux-mêmes !$B$BI\'m sorry, vous apportez des nouvelles pour mon attention ?';
-- Quest 4508 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4508, 'frFR', 'Bien que j\'apprécie sincèrement cela, je ne suis pas sûr de ce que cela nous sera utile.  L\'Alliance ignore les menaces provenant de toute source autre que la Horde, et même nos propres dirigeants ici à Darnassus ne parviennent pas à s\'entendre sur ce qu\'est exactement cette menace.  Des fous comme Fandral Staghelm théorisent que les silithides ne ressemblent en rien à la menace du passé ancien dont je les accuse.  Son ignorance n\'est surpassée que par son arrogance.$B$BVous avez vu la menace vous-même, <name>.  Nous devons rester déterminés à vaincre les silithides !') ON DUPLICATE KEY UPDATE RewardText='Bien que j\'apprécie sincèrement cela, je ne suis pas sûr de ce que cela nous sera utile.  L\'Alliance ignore les menaces provenant de toute source autre que la Horde, et même nos propres dirigeants ici à Darnassus ne parviennent pas à s\'entendre sur ce qu\'est exactement cette menace.  Des fous comme Fandral Staghelm théorisent que les silithides ne ressemblent en rien à la menace du passé ancien dont je les accuse.  Son ignorance n\'est surpassée que par son arrogance.$B$BVous avez vu la menace vous-même, <name>.  Nous devons rester déterminés à vaincre les silithides !';
-- Quest 4509 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4509, 'frFR', 'Ce sont des fous, $N!  Ils ne peuvent même pas penser à regarder autour d\'eux pour une menace plus grande ; leur haine irrationnelle de l\'Alliance sera notre perte.  Je ne sais pas combien de preuves supplémentaires je peux leur donner de la menace silithide sans les jeter dans l\'une des ruches pour qu\'ils le voient par eux-mêmes !$B$BI\'m sorry, vous apportez des nouvelles pour mon attention?') ON DUPLICATE KEY UPDATE CompletionText='Ce sont des fous, $N!  Ils ne peuvent même pas penser à regarder autour d\'eux pour une menace plus grande ; leur haine irrationnelle de l\'Alliance sera notre perte.  Je ne sais pas combien de preuves supplémentaires je peux leur donner de la menace silithide sans les jeter dans l\'une des ruches pour qu\'ils le voient par eux-mêmes !$B$BI\'m sorry, vous apportez des nouvelles pour mon attention?';
-- Quest 4509 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4509, 'frFR', 'Bien que j\'apprécie sincèrement cela, je ne suis pas sûr de ce que cela nous sera utile.  La Horde ignore les menaces provenant de toute source autre que l\'Alliance.  Bien que Thrall lui-même puisse prendre des mesures si les faits lui sont présentés, il est assiégé de tous côtés par des conseils contradictoires.  Ces fous nous feraient courir après nos propres queues imaginaires s\'ils pensaient que cela pourrait prendre l\'Alliance par surprise !$B$BVous avez vu la menace vous-même, $N.  Nous devons rester déterminés à vaincre les silithides !') ON DUPLICATE KEY UPDATE RewardText='Bien que j\'apprécie sincèrement cela, je ne suis pas sûr de ce que cela nous sera utile.  La Horde ignore les menaces provenant de toute source autre que l\'Alliance.  Bien que Thrall lui-même puisse prendre des mesures si les faits lui sont présentés, il est assiégé de tous côtés par des conseils contradictoires.  Ces fous nous feraient courir après nos propres queues imaginaires s\'ils pensaient que cela pourrait prendre l\'Alliance par surprise !$B$BVous avez vu la menace vous-même, $N.  Nous devons rester déterminés à vaincre les silithides !';
-- Quest 4511 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4511, 'frFR', 'Zug zug!  Avec quoi puis-je vous aider aujourd\'hui, $C?') ON DUPLICATE KEY UPDATE CompletionText='Zug zug!  Avec quoi puis-je vous aider aujourd\'hui, $C?';
-- Quest 4511 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4511, 'frFR', 'Ce bon de banque m\'autorise à retirer un objet du compte de Zilzibin Drumlore chez nous et à vous le présenter.  Félicitations semblent de mise !') ON DUPLICATE KEY UPDATE RewardText='Ce bon de banque m\'autorise à retirer un objet du compte de Zilzibin Drumlore chez nous et à vous le présenter.  Félicitations semblent de mise !';
-- Quest 4512 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4512, 'frFR', 'Certaines des expériences que j\'ai menées sont fascinantes. Je pense qu\'avec un peu plus de travail, je serai en mesure de déterminer la nature de ces créatures et comment elles s\'intègrent dans le développement de la vie sur Azeroth... si elles y ont quoi que ce soit à voir au départ.$B$BL\'une de mes plus grandes théories qui n\'est pas bien accueillie est l\'idée que les oozes et les limaces sont liés à la création de cette planète... presque comme s\'ils en étaient une sécrétion.$B$BMais je ne peux ni prouver ni réfuter cela tant que je n\'aurai pas plus d\'échantillons.') ON DUPLICATE KEY UPDATE CompletionText='Certaines des expériences que j\'ai menées sont fascinantes. Je pense qu\'avec un peu plus de travail, je serai en mesure de déterminer la nature de ces créatures et comment elles s\'intègrent dans le développement de la vie sur Azeroth... si elles y ont quoi que ce soit à voir au départ.$B$BL\'une de mes plus grandes théories qui n\'est pas bien accueillie est l\'idée que les oozes et les limaces sont liés à la création de cette planète... presque comme s\'ils en étaient une sécrétion.$B$BMais je ne peux ni prouver ni réfuter cela tant que je n\'aurai pas plus d\'échantillons.';
-- Quest 4512 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4512, 'frFR', 'Des résultats incroyables, <name>! Vous avez été assez proche pour prélever un échantillon des choses corrompues, et vous êtes parvenu à ne pas être en mauvais état ! Merci. Oh, ces échantillons seront parfaits. J\'ai hâte de commencer les tests dessus.$B$BSi j\'ai raison, je pourrais être l\'un des plus grands scientifiques des Ligues d\'Explorateurs !$B$BCela prouvera à tous les nains qu\'il n\'était pas une erreur de nous laisser les gnomes dans Ironforge  après l\'incident de Gnomeregan.') ON DUPLICATE KEY UPDATE RewardText='Des résultats incroyables, <name>! Vous avez été assez proche pour prélever un échantillon des choses corrompues, et vous êtes parvenu à ne pas être en mauvais état ! Merci. Oh, ces échantillons seront parfaits. J\'ai hâte de commencer les tests dessus.$B$BSi j\'ai raison, je pourrais être l\'un des plus grands scientifiques des Ligues d\'Explorateurs !$B$BCela prouvera à tous les nains qu\'il n\'était pas une erreur de nous laisser les gnomes dans Ironforge  après l\'incident de Gnomeregan.';
-- Quest 4513 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4513, 'frFR', 'Tant de choses à considérer. Mais qu\'est-ce que cela signifie ? Et comment cela affecte-t-il la vie des habitants d\'Azeroth ?') ON DUPLICATE KEY UPDATE CompletionText='Tant de choses à considérer. Mais qu\'est-ce que cela signifie ? Et comment cela affecte-t-il la vie des habitants d\'Azeroth ?';
-- Quest 4521 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4521, 'frFR', 'Rapportez-moi après avoir terminé la tâche que je vous ai donnée.') ON DUPLICATE KEY UPDATE CompletionText='Rapportez-moi après avoir terminé la tâche que je vous ai donnée.';
-- Quest 4542 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4542, 'frFR', 'Que voulez-vous, $C? Un message urgent - pour moi?$b') ON DUPLICATE KEY UPDATE CompletionText='Que voulez-vous, $C? Un message urgent - pour moi?$b';
-- Quest 4542 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4542, 'frFR', 'Plus mauvaises nouvelles ! Ces centaures sont allés trop loin ! Ils ont raidi l\'une de mes caravanes d\'approvisionnement et massacré tout le groupe. C\'est un outrage, et cela ne restera pas impuni !$b') ON DUPLICATE KEY UPDATE RewardText='Plus mauvaises nouvelles ! Ces centaures sont allés trop loin ! Ils ont raidi l\'une de mes caravanes d\'approvisionnement et massacré tout le groupe. C\'est un outrage, et cela ne restera pas impuni !$b';
-- Quest 4561 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4561, 'frFR', 'Vous prenez un échantillon de slime du Crater d\'Un\'Goro et en mettez dans les différents tubes et béchers sur la table. Lorsque les choses commencent à bouillir et à jaillir, le slime change de couleur. Lorsque le processus ralentit et que les liquides se calment, vous voyez une petite boîte de Pétri avec vos échantillons de slime d\'Un\'Goro purifiés ainsi que quelques autres restes.') ON DUPLICATE KEY UPDATE CompletionText='Vous prenez un échantillon de slime du Crater d\'Un\'Goro et en mettez dans les différents tubes et béchers sur la table. Lorsque les choses commencent à bouillir et à jaillir, le slime change de couleur. Lorsque le processus ralentit et que les liquides se calment, vous voyez une petite boîte de Pétri avec vos échantillons de slime d\'Un\'Goro purifiés ainsi que quelques autres restes.';
-- Quest 4561 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4561, 'frFR', 'Vous prenez la boîte de Pétri contenant l\'échantillon de slime. La seule façon de discerner si l\'échantillon est assez pur est de l\'ouvrir et d\'examiner le contenu vous-même. Idéalement, vous trouverez un échantillon qui correspond aux critères de Chemist Fuely.') ON DUPLICATE KEY UPDATE RewardText='Vous prenez la boîte de Pétri contenant l\'échantillon de slime. La seule façon de discerner si l\'échantillon est assez pur est de l\'ouvrir et d\'examiner le contenu vous-même. Idéalement, vous trouverez un échantillon qui correspond aux critères de Chemist Fuely.';

-- Quest 4602 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4602, 'frFR', 'Insérez un Objet Encrusté de Crasses dans le Sparklematic 5200, et assurez-vous d\'avoir trois pièces d\'argent pour démarrer la machine.') ON DUPLICATE KEY UPDATE CompletionText='Insérez un Objet Encrusté de Crasses dans le Sparklematic 5200, et assurez-vous d\'avoir trois pièces d\'argent pour démarrer la machine.';
-- Quest 4603 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4603, 'frFR', 'Le Sparklematic 5200 est vide, attendant un objet incrusté de crasses à nettoyer et trois pièces d\'argent pour démarrer !') ON DUPLICATE KEY UPDATE CompletionText='Le Sparklematic 5200 est vide, attendant un objet incrusté de crasses à nettoyer et trois pièces d\'argent pour démarrer !';
-- Quest 4604 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4604, 'frFR', 'Le Sparklematic 5200 est vide, attendant un objet incrusté de crasses à nettoyer et trois pièces d\'argent pour démarrer !') ON DUPLICATE KEY UPDATE CompletionText='Le Sparklematic 5200 est vide, attendant un objet incrusté de crasses à nettoyer et trois pièces d\'argent pour démarrer !';
-- Quest 4605 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4605, 'frFR', 'Aussi vite qu\'il a commencé, le Sparklematic 5200 s\'est arrêté brusquement. Un simple "ding" est entendu depuis la machine, et la bouche de la machine spirale vers le haut. À l\'intérieur du Sparklematic 5200 se trouve une petite boîte enveloppée d\'un petit nœud. La machine semble envelopper un objet après avoir éliminé son statut incrusté de crasses. Même si la machine n\'a pas fonctionné, au moins l\'objet est maintenant enveloppé dans une jolie boîte.$B$BEh bien, il y a un moyen de savoir si elle a nettoyé l\'objet ou pas...') ON DUPLICATE KEY UPDATE RewardText='Aussi vite qu\'il a commencé, le Sparklematic 5200 s\'est arrêté brusquement. Un simple "ding" est entendu depuis la machine, et la bouche de la machine spirale vers le haut. À l\'intérieur du Sparklematic 5200 se trouve une petite boîte enveloppée d\'un petit nœud. La machine semble envelopper un objet après avoir éliminé son statut incrusté de crasses. Même si la machine n\'a pas fonctionné, au moins l\'objet est maintenant enveloppé dans une jolie boîte.$B$BEh bien, il y a un moyen de savoir si elle a nettoyé l\'objet ou pas...';
-- Quest 4606 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4606, 'frFR', 'Aussi vite qu\'il a commencé, le Sparklematic 5200 s\'est arrêté brusquement. Un simple "ding" est entendu depuis la machine, et la bouche de la machine spirale vers le haut. À l\'intérieur du Sparklematic 5200 se trouve une petite boîte enveloppée d\'un petit nœud. La machine semble envelopper un objet après avoir éliminé son statut incrusté de crasses. Même si la machine n\'a pas fonctionné, au moins l\'objet est maintenant enveloppé dans une jolie boîte.$B$BEh bien, il y a un moyen de savoir si elle a nettoyé l\'objet ou pas...') ON DUPLICATE KEY UPDATE RewardText='Aussi vite qu\'il a commencé, le Sparklematic 5200 s\'est arrêté brusquement. Un simple "ding" est entendu depuis la machine, et la bouche de la machine spirale vers le haut. À l\'intérieur du Sparklematic 5200 se trouve une petite boîte enveloppée d\'un petit nœud. La machine semble envelopper un objet après avoir éliminé son statut incrusté de crasses. Même si la machine n\'a pas fonctionné, au moins l\'objet est maintenant enveloppé dans une jolie boîte.$B$BEh bien, il y a un moyen de savoir si elle a nettoyé l\'objet ou pas...';
-- Quest 4621 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4621, 'frFR', 'Tu es de retour déjà, espèce de taré ! As-tu fait ce que j\'ai ordonné ? Échoue, et tu marcheras sur le plancher.$B$BArrrrr...') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour déjà, espèce de taré ! As-tu fait ce que j\'ai ordonné ? Échoue, et tu marcheras sur le plancher.$B$BArrrrr...';
-- Quest 4621 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4621, 'frFR', 'Avast ye... Amiral <name> !  Tu es un pirate des pirates, lad !$B$BIl me réchauffe le cœur de te donner ce chapeau.  Tu ne trouveras jamais un comme ça nulle part, et tout ce qui te regarde verra que tu es un Amiral de la Marine Bloodsail !') ON DUPLICATE KEY UPDATE RewardText='Avast ye... Amiral <name> !  Tu es un pirate des pirates, lad !$B$BIl me réchauffe le cœur de te donner ce chapeau.  Tu ne trouveras jamais un comme ça nulle part, et tout ce qui te regarde verra que tu es un Amiral de la Marine Bloodsail !';
-- Quest 4641 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4641, 'frFR', 'La carapace d\'un scorpid n\'est pas si épaisse que la force d\'un guerrier déterminé ne sera découragée. Frappe fort et sans aucun doute, et les scorpides devraient être une proie facile.') ON DUPLICATE KEY UPDATE CompletionText='La carapace d\'un scorpid n\'est pas si épaisse que la force d\'un guerrier déterminé ne sera découragée. Frappe fort et sans aucun doute, et les scorpides devraient être une proie facile.';
-- Quest 4642 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4642, 'frFR', 'Comment se passe l\'expérience, $N ? Je continuerai à étudier les échantillons que vous m\'avez récupérés -- je commence à comprendre pourquoi Lady Sylvanas est si intéressée par ces créatures. Si elles font vraiment partie des Anciens Dieux, qui sait comment cela peut être utilisé à notre avantage.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe l\'expérience, $N ? Je continuerai à étudier les échantillons que vous m\'avez récupérés -- je commence à comprendre pourquoi Lady Sylvanas est si intéressée par ces créatures. Si elles font vraiment partie des Anciens Dieux, qui sait comment cela peut être utilisé à notre avantage.';
-- Quest 4642 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4642, 'frFR', 'Oh, très excellent, <name>. C\'est très excellent.$B$BQuelle histoire. Qui aurait pensé que les deux interagiraient de cette façon... Je devrai passer plus de temps à examiner les problèmes environnementaux qui provoquent des changements chez ces créatures.$B$Je continuerai mes recherches pour l\'instant. Peut-être nous parlerons bientôt. D\'ici là, je vous souhaite le meilleur.') ON DUPLICATE KEY UPDATE RewardText='Oh, très excellent, <name>. C\'est très excellent.$B$BQuelle histoire. Qui aurait pensé que les deux interagiraient de cette façon... Je devrai passer plus de temps à examiner les problèmes environnementaux qui provoquent des changements chez ces créatures.$B$Je continuerai mes recherches pour l\'instant. Peut-être nous parlerons bientôt. D\'ici là, je vous souhaite le meilleur.';
-- Quest 4661 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4661, 'frFR', 'Vous prenez un échantillon de slime de Felwood et en mettez un dans les différents tubes et béchers sur la table. Lorsque les choses commencent à bouillir et à gicler, le slime change de couleur. Lorsque le processus ralentit et que les liquides se calment, vous voyez une petite boîte de Pétri avec vos échantillons de slime de Felwood modifiés ainsi que quelques autres restes.') ON DUPLICATE KEY UPDATE CompletionText='Vous prenez un échantillon de slime de Felwood et en mettez un dans les différents tubes et béchers sur la table. Lorsque les choses commencent à bouillir et à gicler, le slime change de couleur. Lorsque le processus ralentit et que les liquides se calment, vous voyez une petite boîte de Pétri avec vos échantillons de slime de Felwood modifiés ainsi que quelques autres restes.';
-- Quest 4661 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4661, 'frFR', 'Vous prenez la boîte de Pétri avec l\'échantillon de slime. La seule façon de discerner si l\'échantillon est assez pur est de l\'ouvrir et d\'examiner le contenu vous-même. Idéalement, vous trouverez un échantillon qui correspond aux critères de Chemist Fuely.') ON DUPLICATE KEY UPDATE RewardText='Vous prenez la boîte de Pétri avec l\'échantillon de slime. La seule façon de discerner si l\'échantillon est assez pur est de l\'ouvrir et d\'examiner le contenu vous-même. Idéalement, vous trouverez un échantillon qui correspond aux critères de Chemist Fuely.';
-- Quest 4681 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4681, 'frFR', 'Une fois que vous aurez examiné les restes de la créature dans l\'eau à l\'ouest d\'ici, je devrais pouvoir déposer un rapport approprié auprès du Temple de la Lune à Darnassus. Peut-être serons-nous alors plus proches de découvrir la raison pour laquelle ces créatures malheureuses choisissent de mettre fin à leurs jours échouées sur la côte de Darkshore.') ON DUPLICATE KEY UPDATE CompletionText='Une fois que vous aurez examiné les restes de la créature dans l\'eau à l\'ouest d\'ici, je devrais pouvoir déposer un rapport approprié auprès du Temple de la Lune à Darnassus. Peut-être serons-nous alors plus proches de découvrir la raison pour laquelle ces créatures malheureuses choisissent de mettre fin à leurs jours échouées sur la côte de Darkshore.';
-- Quest 4681 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4681, 'frFR', 'Vous avez été d\'une aide formidable aujourd\'hui ; nous avons maintenant une chance solide de percer le mystère de la raison pour laquelle ces créatures choisissent de s\'échouer sur la côte de Darkshore.  L\'idée qu\'elles pourraient fuir la zone autour de Teldrassil est troublante.  Si vous en rencontrez d\'autres lors de vos voyages, veuillez me le faire savoir.  Nos recherches ici sont encore à leur stade initial.$B$Au nom du Temple de la Lune, veuillez accepter ceci comme remerciement pour l\'effort que vous avez fourni.  Merci, <name> !') ON DUPLICATE KEY UPDATE RewardText='Vous avez été d\'une aide formidable aujourd\'hui ; nous avons maintenant une chance solide de percer le mystère de la raison pour laquelle ces créatures choisissent de s\'échouer sur la côte de Darkshore.  L\'idée qu\'elles pourraient fuir la zone autour de Teldrassil est troublante.  Si vous en rencontrez d\'autres lors de vos voyages, veuillez me le faire savoir.  Nos recherches ici sont encore à leur stade initial.$B$Au nom du Temple de la Lune, veuillez accepter ceci comme remerciement pour l\'effort que vous avez fourni.  Merci, <name> !';
-- Quest 4701 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4701, 'frFR', 'Avez-vous découvert et traité la source de la menace des worg ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous découvert et traité la source de la menace des worg ?';

-- Quest 4701 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4701, 'frFR', 'Ne t\'attarde pas sur sa souffrance, $N$. La bête était corrompue - un produit de magie noire. Vous avez rendu un grand service à l\'Alliance et vous serez récompensé.') ON DUPLICATE KEY UPDATE RewardText='Ne t\'attarde pas sur sa souffrance, $N$. La bête était corrompue - un produit de magie noire. Vous avez rendu un grand service à l\'Alliance et vous serez récompensé.';
-- Quest 4722 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4722, 'frFR', 'Bonjour $N$ - avez-vous des découvertes d\'êtres qui ont échoué sur la plage à signaler ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour $N$ - avez-vous des découvertes d\'êtres qui ont échoué sur la plage à signaler ?';
-- Quest 4722 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4722, 'frFR', 'Une autre découverte pour nous étudier - bien joué $N$! Ces restes seront étudiés correctement une fois qu\'ils arriveront à Darnassus. Veuillez accepter ce petit honorarium en échange des restes que vous avez fournis pour notre étude.') ON DUPLICATE KEY UPDATE RewardText='Une autre découverte pour nous étudier - bien joué $N$! Ces restes seront étudiés correctement une fois qu\'ils arriveront à Darnassus. Veuillez accepter ce petit honorarium en échange des restes que vous avez fournis pour notre étude.';
-- Quest 4723 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4723, 'frFR', 'Bonjour à nouveau, $N$! Êtes-vous ici pour signaler une autre découverte ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau, $N$! Êtes-vous ici pour signaler une autre découverte ?';
-- Quest 4723 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4723, 'frFR', 'Une autre découverte - bien joué <name>!  Ces restes seront étudiés correctement une fois qu\'ils arriveront à Darnassus.  Veuillez accepter ce petit honorarium en échange des restes que vous avez fournis pour notre étude.') ON DUPLICATE KEY UPDATE RewardText='Une autre découverte - bien joué <name>!  Ces restes seront étudiés correctement une fois qu\'ils arriveront à Darnassus.  Veuillez accepter ce petit honorarium en échange des restes que vous avez fournis pour notre étude.';
-- Quest 4724 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4724, 'frFR', 'Avec la maîtresse du pack abattue, nous pouvons commencer à réduire les sentinelles worg de la Flèche et éventuellement faire des progrès dans la ville.') ON DUPLICATE KEY UPDATE CompletionText='Avec la maîtresse du pack abattue, nous pouvons commencer à réduire les sentinelles worg de la Flèche et éventuellement faire des progrès dans la ville.';
-- Quest 4726 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4726, 'frFR', 'Avez-vous l\'essence de la progéniture, $N$? J\'ai hâte de l\'étudier.$B$BEt par ailleurs... mon mécène n\'est pas le genre de personne que vous voulez décevoir.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous l\'essence de la progéniture, $N$? J\'ai hâte de l\'étudier.$B$BEt par ailleurs... mon mécène n\'est pas le genre de personne que vous voulez décevoir.';
-- Quest 4726 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4726, 'frFR', 'Ça a marché!  Vous avez obtenu l\'essence!  Bien joué, <name>!  Bien joué!$B$BCette essence sera inestimable dans mes recherches.  J\'espère un jour apprendre à capturer des petits dragons vivants, ou peut-être capturer leurs œufs.  Si je pouvais trouver un moyen de faire cela, alors je serais l\'envie des chercheurs de dragons du monde entier!$B$BMon employeur serait également heureux, et comme je l\'ai dit avant, c\'est quelqu\'un que vous voulez garder heureux...') ON DUPLICATE KEY UPDATE RewardText='Ça a marché!  Vous avez obtenu l\'essence!  Bien joué, <name>!  Bien joué!$B$BCette essence sera inestimable dans mes recherches.  J\'espère un jour apprendre à capturer des petits dragons vivants, ou peut-être capturer leurs œufs.  Si je pouvais trouver un moyen de faire cela, alors je serais l\'envie des chercheurs de dragons du monde entier!$B$BMon employeur serait également heureux, et comme je l\'ai dit avant, c\'est quelqu\'un que vous voulez garder heureux...';
-- Quest 4727 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4727, 'frFR', 'Bonjour à nouveau, $N$! Êtes-vous ici pour signaler une autre découverte ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau, $N$! Êtes-vous ici pour signaler une autre découverte ?';
-- Quest 4727 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4727, 'frFR', 'Les os que vous avez sont ceux de mammifères marins doux qui sont connus pour habiter les eaux entourant la base de Teldrassil. Ils n\'avaient jamais été connus pour se déverser violemment comme les traqueurs avaient été connus pour le faire. Pourquoi ces créatures feraient-elles cela, je me demande ? Eh bien, peut-être que l\'étude de leurs restes portera les fruits de la connaissance que nous recherchons.$B$BMerci encore pour votre aide. Veuillez accepter cet honorarium du Temple de la Lune.') ON DUPLICATE KEY UPDATE RewardText='Les os que vous avez sont ceux de mammifères marins doux qui sont connus pour habiter les eaux entourant la base de Teldrassil. Ils n\'avaient jamais été connus pour se déverser violemment comme les traqueurs avaient été connus pour le faire. Pourquoi ces créatures feraient-elles cela, je me demande ? Eh bien, peut-être que l\'étude de leurs restes portera les fruits de la connaissance que nous recherchons.$B$BMerci encore pour votre aide. Veuillez accepter cet honorarium du Temple de la Lune.';
-- Quest 4728 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4728, 'frFR', 'Salutations à nouveau, $N$! Qu\'est-ce qui vous ramène à Auberdine ? Êtes-vous ici pour signaler une autre découverte, peut-être ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations à nouveau, $N$! Qu\'est-ce qui vous ramène à Auberdine ? Êtes-vous ici pour signaler une autre découverte, peut-être ?';
-- Quest 4730 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4730, 'frFR', 'Bonjour à nouveau, $N$! Êtes-vous ici pour signaler une autre découverte ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau, $N$! Êtes-vous ici pour signaler une autre découverte ?';
-- Quest 4730 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4730, 'frFR', 'Les os que vous avez sont ceux de mammifères marins doux qui sont connus pour habiter les eaux entourant la base de Teldrassil.  Ils n\'avaient jamais été connus pour se déverser violemment comme les traqueurs avaient été connus pour le faire.  Pourquoi ces créatures feraient-elles cela, je me demande ?  Eh bien, peut-être que l\'étude de leurs restes portera les fruits de la connaissance que nous recherchons.$B$BMerci encore pour votre aide.  Veuillez accepter cet honorarium du Temple de la Lune.') ON DUPLICATE KEY UPDATE RewardText='Les os que vous avez sont ceux de mammifères marins doux qui sont connus pour habiter les eaux entourant la base de Teldrassil.  Ils n\'avaient jamais été connus pour se déverser violemment comme les traqueurs avaient été connus pour le faire.  Pourquoi ces créatures feraient-elles cela, je me demande ?  Eh bien, peut-être que l\'étude de leurs restes portera les fruits de la connaissance que nous recherchons.$B$BMerci encore pour votre aide.  Veuillez accepter cet honorarium du Temple de la Lune.';
-- Quest 4732 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4732, 'frFR', 'Salutations à nouveau $N$ - avez-vous d\'autres découvertes à signaler au Temple de la Lune ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations à nouveau $N$ - avez-vous d\'autres découvertes à signaler au Temple de la Lune ?';
-- Quest 4734 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4734, 'frFR', '$N$, avez-vous testé l\'éggscilloscope ?') ON DUPLICATE KEY UPDATE CompletionText='$N$, avez-vous testé l\'éggscilloscope ?';

-- Quest 4734 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4734, 'frFR', 'Ça a marché ?  Splendide !  Je le savais !$B$BPendant que vous étiez parti, j\'ai travaillé sur une nouvelle version de l\'éggscilloscope.  Celui-ci a une portée beaucoup plus grande.$B$BVoici, vous pouvez en prendre un si vous retournez à Blackrock Spire.') ON DUPLICATE KEY UPDATE RewardText='Ça a marché ?  Splendide !  Je le savais !$B$BPendant que vous étiez parti, j\'ai travaillé sur une nouvelle version de l\'éggscilloscope.  Celui-ci a une portée beaucoup plus grande.$B$BVoici, vous pouvez en prendre un si vous retournez à Blackrock Spire.';
-- Quest 4735 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4735, 'frFR', 'Vous avez les œufs, $N ? Mon mécène m\'a dit que vous les collectiez pour moi, et il est très impatient de les avoir !') ON DUPLICATE KEY UPDATE CompletionText='Vous avez les œufs, $N ? Mon mécène m\'a dit que vous les collectiez pour moi, et il est très impatient de les avoir !';
-- Quest 4735 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4735, 'frFR', 'Wow, vous les avez !  Le module collectronic a fonctionné !  Je suis un génie !$B$BMerci, <name>.  Mon mécène sera très heureux de recevoir ces œufs...') ON DUPLICATE KEY UPDATE RewardText='Wow, vous les avez !  Le module collectronic a fonctionné !  Je suis un génie !$B$BMerci, <name>.  Mon mécène sera très heureux de recevoir ces œufs...';
-- Quest 4736 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4736, 'frFR', 'Ah, Briarthorn vous a envoyé. Bien. Alors, le mot parvient assez loin pour trouver de futurs étudiants. Cela me plaît.$B$BIl est typique de notre espèce, $N, de nous unir, quelle que soit la race. C\'est d\'autant plus important que ceux avec qui nous avons le plus affaire ne font pas de distinction dans leur malice si nous échouons à les apaiser ou à les contrôler correctement.$B$BJe crois que vous avez appris beaucoup de choses, et si vous êtes disposé, je vous aiderais à créer des outils pour compléter vos compétences.') ON DUPLICATE KEY UPDATE RewardText='Ah, Briarthorn vous a envoyé. Bien. Alors, le mot parvient assez loin pour trouver de futurs étudiants. Cela me plaît.$B$BIl est typique de notre espèce, $N, de nous unir, quelle que soit la race. C\'est d\'autant plus important que ceux avec qui nous avons le plus affaire ne font pas de distinction dans leur malice si nous échouons à les apaiser ou à les contrôler correctement.$B$BJe crois que vous avez appris beaucoup de choses, et si vous êtes disposé, je vous aiderais à créer des outils pour compléter vos compétences.';
-- Quest 4737 [OfferReward]
