-- Quest 4739 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4739, 'frFR', 'Ah, Kaal vous a envoyé. Bien. Alors, le mot parvient assez loin pour trouver de futurs étudiants. Cela me plaît.$B$BIl est typique de notre espèce, $N, de nous unir, quelle que soit la race. C\'est d\'autant plus important que ceux avec qui nous avons le plus affaire ne font pas de distinction dans leur malice si nous échouons à les apaiser ou à les contrôler correctement.$B$BJe crois que vous avez appris beaucoup de choses, et si vous êtes disposé, je vous aiderais à créer des outils pour compléter vos compétences.') ON DUPLICATE KEY UPDATE RewardText='Ah, Kaal vous a envoyé. Bien. Alors, le mot parvient assez loin pour trouver de futurs étudiants. Cela me plaît.$B$BIl est typique de notre espèce, $N, de nous unir, quelle que soit la race. C\'est d\'autant plus important que ceux avec qui nous avons le plus affaire ne font pas de distinction dans leur malice si nous échouons à les apaiser ou à les contrôler correctement.$B$BJe crois que vous avez appris beaucoup de choses, et si vous êtes disposé, je vous aiderais à créer des outils pour compléter vos compétences.';
-- Quest 4740 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4740, 'frFR', 'Bonjour $c - en quoi les Sentinelles peuvent-elles vous aider aujourd\'hui ? Peut-être êtes-vous ici pour vous renseigner sur la prime de Murkdeep ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour $c - en quoi les Sentinelles peuvent-elles vous aider aujourd\'hui ? Peut-être êtes-vous ici pour vous renseigner sur la prime de Murkdeep ?';
-- Quest 4741 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4741, 'frFR', 'Ne me dites pas que vous avez trop peur ! Allez !') ON DUPLICATE KEY UPDATE CompletionText='Ne me dites pas que vous avez trop peur ! Allez !';
-- Quest 4762 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4762, 'frFR', 'La pollution de la rivière Cliffspring n\'est que le début d\'une tendance alarmante ici à Darkshore. L\'échantillon que vous fournissez nous aidera à formaliser un plan... un plan d\'attaque, je commence à le suspecter.') ON DUPLICATE KEY UPDATE CompletionText='La pollution de la rivière Cliffspring n\'est que le début d\'une tendance alarmante ici à Darkshore. L\'échantillon que vous fournissez nous aidera à formaliser un plan... un plan d\'attaque, je commence à le suspecter.';
-- Quest 4762 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4762, 'frFR', 'Il n\'est pas surprenant que cette eau soit si souillée, mais regardez comme elle devient puante !  Il semble qu\'une action soit nécessaire plus tôt que tard, n\'est-ce pas <name>?$B$BÀ notre est se trouve Felwood ; c\'est la vraie source de cette corruption, que j\'ai vue par le passé.  Je prédis que cet échantillon le confirmera.  Nous pourrions être en mesure d\'y trouver un remède ici, mais pour même essayer, nous aurons besoin d\'aide.  Quand ce moment viendra <name, j\'espère que vous pourrez nous apporter l\'aide dont nous avons besoin.') ON DUPLICATE KEY UPDATE RewardText='Il n\'est pas surprenant que cette eau soit si souillée, mais regardez comme elle devient puante !  Il semble qu\'une action soit nécessaire plus tôt que tard, n\'est-ce pas <name>?$B$BÀ notre est se trouve Felwood ; c\'est la vraie source de cette corruption, que j\'ai vue par le passé.  Je prédis que cet échantillon le confirmera.  Nous pourrions être en mesure d\'y trouver un remède ici, mais pour même essayer, nous aurons besoin d\'aide.  Quand ce moment viendra <name, j\'espère que vous pourrez nous apporter l\'aide dont nous avons besoin.';
-- Quest 4764 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4764, 'frFR', 'Avez-vous le médaillon, $N ? Mon mécène paiera très généreusement pour lui.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous le médaillon, $N ? Mon mécène paiera très généreusement pour lui.';
-- Quest 4764 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4764, 'frFR', 'Vous l\'avez trouvé !  Alors les rumeurs étaient vraies !$B$BMerci, <name>.  Mon mécène, Count Remington Ridgewell, sera très heureux de voir cet ajout à cette collection.') ON DUPLICATE KEY UPDATE RewardText='Vous l\'avez trouvé !  Alors les rumeurs étaient vraies !$B$BMerci, <name>.  Mon mécène, Count Remington Ridgewell, sera très heureux de voir cet ajout à cette collection.';
-- Quest 4765 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4765, 'frFR', 'On m\'a dit qu\'un messager viendrait. Un avec un cadeau de Blackrock Spire.$B$S\'en êtes-vous ?') ON DUPLICATE KEY UPDATE CompletionText='On m\'a dit qu\'un messager viendrait. Un avec un cadeau de Blackrock Spire.$B$S\'en êtes-vous ?';
-- Quest 4765 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4765, 'frFR', 'Ah, c\'est donc vous ! Je vous remercie, $N. Et... si vous ne le saviez pas déjà... la gratitude d\'un noble de la maison Ridgewell vaut presque un trésor de roi.') ON DUPLICATE KEY UPDATE RewardText='Ah, c\'est donc vous ! Je vous remercie, $N. Et... si vous ne le saviez pas déjà... la gratitude d\'un noble de la maison Ridgewell vaut presque un trésor de roi.';

-- Quest 4768 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4768, 'frFR', 'As-tu trouvé la Tablette, $N$? Je désire me plonger dans ses secrets.') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé la Tablette, $N$? Je désire me plonger dans ses secrets.';
-- Quest 4768 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4768, 'frFR', 'Excellent. Les formules gravées sur cette tablette nécessiteront des jours de recherche, mais je suis confiant qu\'une telle recherche portera ses fruits.$b$bMerci, $N. Tu as été inestimable pour nous.') ON DUPLICATE KEY UPDATE RewardText='Excellent. Les formules gravées sur cette tablette nécessiteront des jours de recherche, mais je suis confiant qu\'une telle recherche portera ses fruits.$b$bMerci, $N. Tu as été inestimable pour nous.';
-- Quest 4769 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4769, 'frFR', 'C\'est vrai. Je crois qu\'il y a une tablette conservée dans la Flèche de Blackrock, une tablette qui contient de vieilles recettes alchimiques. Je suis heureux que tu sois là, car j\'ai besoin d\'aide pour récupérer la tablette.$B$BInstalle-toi confortablement, et je t\'expliquerai davantage.') ON DUPLICATE KEY UPDATE RewardText='C\'est vrai. Je crois qu\'il y a une tablette conservée dans la Flèche de Blackrock, une tablette qui contient de vieilles recettes alchimiques. Je suis heureux que tu sois là, car j\'ai besoin d\'aide pour récupérer la tablette.$B$BInstalle-toi confortablement, et je t\'expliquerai davantage.';
-- Quest 4771 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4771, 'frFR', 'Souviens-toi, $N$ - nous devons être tolérants mais rigides dans nos croyances !') ON DUPLICATE KEY UPDATE CompletionText='Souviens-toi, $N$ - nous devons être tolérants mais rigides dans nos croyances !';
-- Quest 4771 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4771, 'frFR', 'Tu y es arrivé ! Vectus est vaincu ! Et le Gambit de l\'Aube... cela a fonctionné?$B$Hmm... peut-être que mon appareil n\'a pas été le succès que j\'espérais, mais je suis heureux que tu aies pu gérer les choses de toute façon. Bien joué, $n!$B$BL\'Aube Argentée, et les bons habitants d\'Azeroth, te doivent beaucoup.') ON DUPLICATE KEY UPDATE RewardText='Tu y es arrivé ! Vectus est vaincu ! Et le Gambit de l\'Aube... cela a fonctionné?$B$Hmm... peut-être que mon appareil n\'a pas été le succès que j\'espérais, mais je suis heureux que tu aies pu gérer les choses de toute façon. Bien joué, $n!$B$BL\'Aube Argentée, et les bons habitants d\'Azeroth, te doivent beaucoup.';
-- Quest 4781 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4781, 'frFR', 'Des lingots d\'or, oui... oui. Apporte-m\'en un et nous verrons ce que nous pouvons faire pour filer un peu de fil pour toi. D\'ici là, je te suggère de concentrer tes efforts à devenir plus puissant. Tes épreuves les plus difficiles sont encore devant toi. Et crois-moi... tu regretteras de ne pas avoir été plus préparé, peu importe à quel point tu penses être puissant.') ON DUPLICATE KEY UPDATE CompletionText='Des lingots d\'or, oui... oui. Apporte-m\'en un et nous verrons ce que nous pouvons faire pour filer un peu de fil pour toi. D\'ici là, je te suggère de concentrer tes efforts à devenir plus puissant. Tes épreuves les plus difficiles sont encore devant toi. Et crois-moi... tu regretteras de ne pas avoir été plus préparé, peu importe à quel point tu penses être puissant.';
-- Quest 4781 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4781, 'frFR', 'Parfait, $N$. Je suis heureux que tu aies pu trouver un mineur pour t\'aider si rapidement. Ou as-tu fait ce travail toi-même ? Dans les deux cas, tu as bien fait. Ceci sera parfait pour le fil.$B$BIl faudra un peu de temps pour créer la matière, donc tu devras revenir--je l\'envoie en fait à une princesse que nous avons enfermée dans une tour dont le seul travail est de filer du fil d\'or... non, sérieusement. Je le pense... d\'accord, pas vraiment.') ON DUPLICATE KEY UPDATE RewardText='Parfait, $N$. Je suis heureux que tu aies pu trouver un mineur pour t\'aider si rapidement. Ou as-tu fait ce travail toi-même ? Dans les deux cas, tu as bien fait. Ceci sera parfait pour le fil.$B$BIl faudra un peu de temps pour créer la matière, donc tu devras revenir--je l\'envoie en fait à une princesse que nous avons enfermée dans une tour dont le seul travail est de filer du fil d\'or... non, sérieusement. Je le pense... d\'accord, pas vraiment.';
-- Quest 4782 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4782, 'frFR', 'Bien, tu es revenu, $N$. Et où est le fil?$B$Ah, je comprends. C\'est acceptable. Le gobelin et son frère ne nous ont pas encore déçus -- je suppose qu\'il est compréhensible qu\'il ne l\'ait pas préparé à ce moment-là. Ainsi soit-il... nous avons d\'autres choses auxquelles nous pouvons nous consacrer entre-temps.$B$Es-tu prêt pour l\'étape suivante?') ON DUPLICATE KEY UPDATE RewardText='Bien, tu es revenu, $N$. Et où est le fil?$B$Ah, je comprends. C\'est acceptable. Le gobelin et son frère ne nous ont pas encore déçus -- je suppose qu\'il est compréhensible qu\'il ne l\'ait pas préparé à ce moment-là. Ainsi soit-il... nous avons d\'autres choses auxquelles nous pouvons nous consacrer entre-temps.$B$Es-tu prêt pour l\'étape suivante?';
-- Quest 4783 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4783, 'frFR', 'Desolace n\'est pas un endroit aimable : naga, géants, satyre, la Légion Ardente... tout cela et les clans de centaures en guerre rendent la terre dangereuse si tu n\'y prends garde.$B$Comme je l\'ai dit auparavant, cela ne testera pas seulement ta force et ton ingéniosité, mais aussi ta patience. Sois prudent dans ces terres, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Desolace n\'est pas un endroit aimable : naga, géants, satyre, la Légion Ardente... tout cela et les clans de centaures en guerre rendent la terre dangereuse si tu n\'y prends garde.$B$Comme je l\'ai dit auparavant, cela ne testera pas seulement ta force et ton ingéniosité, mais aussi ta patience. Sois prudent dans ces terres, $N$.';
-- Quest 4783 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4783, 'frFR', 'Excellent, $N$. Ceux-ci conviendront bien. Je vais les préparer maintenant pendant que tu passes à tes deux dernières composantes. Es-tu prêt?') ON DUPLICATE KEY UPDATE RewardText='Excellent, $N$. Ceux-ci conviendront bien. Je vais les préparer maintenant pendant que tu passes à tes deux dernières composantes. Es-tu prêt?';
-- Quest 4784 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4784, 'frFR', 'Bientôt, $N$. Je te le promets. La robe sera plus que suffisante pour tes besoins et te donnera certainement un avantage sur tes adversaires.') ON DUPLICATE KEY UPDATE CompletionText='Bientôt, $N$. Je te le promets. La robe sera plus que suffisante pour tes besoins et te donnera certainement un avantage sur tes adversaires.';
-- Quest 4784 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4784, 'frFR', 'Excellent, $N! Les composants sont rassemblés et nous sommes prêts.$B$Je crois que tu en seras satisfait.') ON DUPLICATE KEY UPDATE RewardText='Excellent, $N! Les composants sont rassemblés et nous sommes prêts.$B$Je crois que tu en seras satisfait.';
-- Quest 4785 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4785, 'frFR', 'Tiens, $N$. Et dis à Menara que nous disons bonjour.$B$Nous attendons de grandes choses de toi. Peut-être que lorsque la Légion sera à genoux, ton nom sera prononcé à haute voix et en louange de ta puissance. J\'ai hâte!') ON DUPLICATE KEY UPDATE RewardText='Tiens, $N$. Et dis à Menara que nous disons bonjour.$B$Nous attendons de grandes choses de toi. Peut-être que lorsque la Légion sera à genoux, ton nom sera prononcé à haute voix et en louange de ta puissance. J\'ai hâte!';
-- Quest 4786 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4786, 'frFR', 'C\'est fait, $N$. Voici. Porte-le avec fierté.$B$Tu as travaillé dur et je vois de grandes choses dans ton avenir. Souviens-toi, défier la corruption qui accompagne notre chemin demande une grande volonté et une grande fortitude. Tant que ta volonté est la tienne, alors tu connaîtras un grand succès.') ON DUPLICATE KEY UPDATE RewardText='C\'est fait, $N$. Voici. Porte-le avec fierté.$B$Tu as travaillé dur et je vois de grandes choses dans ton avenir. Souviens-toi, défier la corruption qui accompagne notre chemin demande une grande volonté et une grande fortitude. Tant que ta volonté est la tienne, alors tu connaîtras un grand succès.';
-- Quest 4788 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4788, 'frFR', 'Es-tu allé dans la flèche, $N$? As-tu les cinquième et sixième tablettes?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé dans la flèche, $N$? As-tu les cinquième et sixième tablettes?';

-- Quest 4788 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4788, 'frFR', 'Incroyable !  Vous les avez trouvés !  Vous êtes vraiment un héros, <name>!$B$BC\'est une bonne chose, parce que j\'ai lu les tablettes que vous m\'avez apportées avant, et d\'après ce que j\'ai compris... nous allons avoir besoin d\'un héros pour arrêter ce qui arrive...') ON DUPLICATE KEY UPDATE RewardText='Incroyable !  Vous les avez trouvés !  Vous êtes vraiment un héros, <name>!$B$BC\'est une bonne chose, parce que j\'ai lu les tablettes que vous m\'avez apportées avant, et d\'après ce que j\'ai compris... nous allons avoir besoin d\'un héros pour arrêter ce qui arrive...';
-- Quest 4801 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4801, 'frFR', 'En Winterspring, vous combattrez de grands félins appelés sabres-de-glace. Ces bêtes possèdent une vitesse et une ruse incroyables. Si vous souhaitez acquérir la vitesse de la sabre-de-glace, apportez-moi l\'E\'ko que vous trouvez chez eux.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.') ON DUPLICATE KEY UPDATE CompletionText='En Winterspring, vous combattrez de grands félins appelés sabres-de-glace. Ces bêtes possèdent une vitesse et une ruse incroyables. Si vous souhaitez acquérir la vitesse de la sabre-de-glace, apportez-moi l\'E\'ko que vous trouvez chez eux.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.';
-- Quest 4801 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4801, 'frFR', 'Mau\'ari peut dériver le juju pour <name>... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.') ON DUPLICATE KEY UPDATE RewardText='Mau\'ari peut dériver le juju pour <name>... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.';
-- Quest 4802 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4802, 'frFR', 'En Winterspring, vous combattrez des créatures égarées connues sous le nom de furbolg de l\'hiver. Par le souhait de leur chef, ils ont acquis une force incroyable. Si vous souhaitez acquérir la puissance du furbolg de l\'hiver, apportez-moi l\'E\'ko que vous trouvez chez eux.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.') ON DUPLICATE KEY UPDATE CompletionText='En Winterspring, vous combattrez des créatures égarées connues sous le nom de furbolg de l\'hiver. Par le souhait de leur chef, ils ont acquis une force incroyable. Si vous souhaitez acquérir la puissance du furbolg de l\'hiver, apportez-moi l\'E\'ko que vous trouvez chez eux.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.';
-- Quest 4802 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4802, 'frFR', 'Mau\'ari peut dériver le juju pour $N... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.') ON DUPLICATE KEY UPDATE RewardText='Mau\'ari peut dériver le juju pour $N... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.';
-- Quest 4803 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4803, 'frFR', 'En Winterspring, vous trouverez des ours massifs aux peaux extrêmement épaisses. Ces ours à dents de shard acquièrent beaucoup de protection contre ce qu\'ils peuvent endurer. Si vous souhaitez acquérir la résistance au feu, apportez-moi l\'E\'ko que vous trouvez chez le Shardtooth.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.$B$B') ON DUPLICATE KEY UPDATE CompletionText='En Winterspring, vous trouverez des ours massifs aux peaux extrêmement épaisses. Ces ours à dents de shard acquièrent beaucoup de protection contre ce qu\'ils peuvent endurer. Si vous souhaitez acquérir la résistance au feu, apportez-moi l\'E\'ko que vous trouvez chez le Shardtooth.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.$B$B';
-- Quest 4803 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4803, 'frFR', 'Mau\'ari peut dériver le juju pour $N... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.') ON DUPLICATE KEY UPDATE RewardText='Mau\'ari peut dériver le juju pour $N... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.';
-- Quest 4804 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4804, 'frFR', 'En Winterspring, vous combattrez de grands créatures volantes appelées Chillwind. Ces bêtes possèdent le pouvoir de manier les magies de glace. Si vous souhaitez acquérir la résistance au froid, apportez-moi l\'E\'ko que vous trouvez chez le Chillwind.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.$B$B') ON DUPLICATE KEY UPDATE CompletionText='En Winterspring, vous combattrez de grands créatures volantes appelées Chillwind. Ces bêtes possèdent le pouvoir de manier les magies de glace. Si vous souhaitez acquérir la résistance au froid, apportez-moi l\'E\'ko que vous trouvez chez le Chillwind.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.$B$B';
-- Quest 4804 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4804, 'frFR', 'Mau\'ari peut dériver le juju pour <name>... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.') ON DUPLICATE KEY UPDATE RewardText='Mau\'ari peut dériver le juju pour <name>... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.';
-- Quest 4805 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4805, 'frFR', 'En Winterspring, vous combattrez de grandes créatures appelées yeti de l\'épine de glace. Ces bêtes se déplacent lentement, mais elles sont capables d\'esquiver de nombreux coups grâce à la protection que leur fourrure épaisse leur offre. Si vous souhaitez acquérir la capacité d\'esquiver les attaques, apportez-moi l\'E\'ko que vous trouvez chez elles.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.$B$B') ON DUPLICATE KEY UPDATE CompletionText='En Winterspring, vous combattrez de grandes créatures appelées yeti de l\'épine de glace. Ces bêtes se déplacent lentement, mais elles sont capables d\'esquiver de nombreux coups grâce à la protection que leur fourrure épaisse leur offre. Si vous souhaitez acquérir la capacité d\'esquiver les attaques, apportez-moi l\'E\'ko que vous trouvez chez elles.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.$B$B';
-- Quest 4805 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4805, 'frFR', 'Mau\'ari peut dériver le juju pour $N... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.') ON DUPLICATE KEY UPDATE RewardText='Mau\'ari peut dériver le juju pour $N... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.';
-- Quest 4806 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4806, 'frFR', 'En Winterspring, vous avez combattu de grands géants de glace appelés frostmaul. Une puissance brute et une force sont à leur disposition. Si vous souhaitez acquérir la force du frostmaul, apportez-moi l\'E\'ko que vous trouvez chez eux.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.') ON DUPLICATE KEY UPDATE CompletionText='En Winterspring, vous avez combattu de grands géants de glace appelés frostmaul. Une puissance brute et une force sont à leur disposition. Si vous souhaitez acquérir la force du frostmaul, apportez-moi l\'E\'ko que vous trouvez chez eux.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.';
-- Quest 4806 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4806, 'frFR', 'Mau\'ari peut dériver le juju pour <name>... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.') ON DUPLICATE KEY UPDATE RewardText='Mau\'ari peut dériver le juju pour <name>... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.';
-- Quest 4807 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4807, 'frFR', 'En Winterspring, vous combattrez des créatures de puissance qui semblent posséder une capacité magique innée. Ces sauvages peuvent utiliser de fortes magies. Si vous souhaitez obtenir une augmentation de votre intellect, apportez-moi l\'E\'ko que vous trouvez chez n\'importe quel des oiseaux sauvages que vous trouvez là.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.$B$B') ON DUPLICATE KEY UPDATE CompletionText='En Winterspring, vous combattrez des créatures de puissance qui semblent posséder une capacité magique innée. Ces sauvages peuvent utiliser de fortes magies. Si vous souhaitez obtenir une augmentation de votre intellect, apportez-moi l\'E\'ko que vous trouvez chez n\'importe quel des oiseaux sauvages que vous trouvez là.$B$BRappelez-vous, vous devez avoir le Cache de Mau\'ari dans votre inventaire si vous voulez chasser l\'E\'ko.$B$B';
-- Quest 4807 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4807, 'frFR', 'Mau\'ari peut dériver le juju pour $N... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.') ON DUPLICATE KEY UPDATE RewardText='Mau\'ari peut dériver le juju pour $N... Utilisez le Cache de Mau\'ari pour lancer ceci sur vous-même ou sur vos alliés.';

-- Quest 4809 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4809, 'frFR', 'As-tu les cornes de Chillwind, $N$ ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu les cornes de Chillwind, $N$ ?';
-- Quest 4809 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4809, 'frFR', 'Ce sont de beaux spécimens.  Ils sont remplis de froid !  Laisse-moi mettre des gants, puis emballer ça avec les autres choses dont Tinkee a besoin...') ON DUPLICATE KEY UPDATE RewardText='Ce sont de beaux spécimens.  Ils sont remplis de froid !  Laisse-moi mettre des gants, puis emballer ça avec les autres choses dont Tinkee a besoin...';
-- Quest 4810 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4810, 'frFR', '$N$ ! As-tu parlé à Felnok ? As-tu apporté les composants dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='$N$ ! As-tu parlé à Felnok ? As-tu apporté les composants dont j\'ai besoin ?';
-- Quest 4810 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4810, 'frFR', 'Tu les as apportés ! Super ! Je commence tout de suite ! Merci beaucoup, $N$ !$b$bTu as été si utile pour moi, j\'aurai peut-être besoin de toi pour des tâches encore plus importantes plus tard...') ON DUPLICATE KEY UPDATE RewardText='Tu les as apportés ! Super ! Je commence tout de suite ! Merci beaucoup, $N$ !$b$bTu as été si utile pour moi, j\'aurai peut-être besoin de toi pour des tâches encore plus importantes plus tard...';
-- Quest 4811 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4811, 'frFR', 'Qu\'as-tu à rapporter sur ce cristal rouge ? Est-ce qu\'il existe vraiment ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'as-tu à rapporter sur ce cristal rouge ? Est-ce qu\'il existe vraiment ?';
-- Quest 4811 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4811, 'frFR', 'Alors le cristal existe, <name> ?  Fascinant... de toute façon, ta tâche a été bien exécutée ; bon travail !$B$BQu\'est-ce que c\'est exactement ce cristal ?  Ceci n\'est qu\'une question dans une mer de questions.  Une autre question qui me vient à l\'esprit est de savoir pourquoi les moonkin seraient attirés par cet objet ?  Le cristal est-il bénin en nature, ou cache-t-il un dessein plus sinistre?$B$BI ai beaucoup plus de questions, mais nous allons devoir examiner ce cristal de près pour obtenir des réponses.') ON DUPLICATE KEY UPDATE RewardText='Alors le cristal existe, <name> ?  Fascinant... de toute façon, ta tâche a été bien exécutée ; bon travail !$B$BQu\'est-ce que c\'est exactement ce cristal ?  Ceci n\'est qu\'une question dans une mer de questions.  Une autre question qui me vient à l\'esprit est de savoir pourquoi les moonkin seraient attirés par cet objet ?  Le cristal est-il bénin en nature, ou cache-t-il un dessein plus sinistre?$B$BI ai beaucoup plus de questions, mais nous allons devoir examiner ce cristal de près pour obtenir des réponses.';
-- Quest 4822 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4822, 'frFR', 'J\'aimerais qu\'ils fassent plus de saveurs de crème glacée autres que la fraise, mais je suppose que je suis chanceux que la fraise soit ma préférée !') ON DUPLICATE KEY UPDATE CompletionText='J\'aimerais qu\'ils fassent plus de saveurs de crème glacée autres que la fraise, mais je suppose que je suis chanceux que la fraise soit ma préférée !';
-- Quest 4841 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4841, 'frFR', 'Allez $N$, je sais que tu n\'as pas encore tué ta part. Chasse-les, et je te donnerai une récompense pour ma gratitude.') ON DUPLICATE KEY UPDATE CompletionText='Allez $N$, je sais que tu n\'as pas encore tué ta part. Chasse-les, et je te donnerai une récompense pour ma gratitude.';
-- Quest 4842 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4842, 'frFR', 'L\'eau des sources semble avoir des propriétés très étranges... Je ne suis toujours pas sûr de ce que cela signifie...') ON DUPLICATE KEY UPDATE CompletionText='L\'eau des sources semble avoir des propriétés très étranges... Je ne suis toujours pas sûr de ce que cela signifie...';
-- Quest 4867 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4867, 'frFR', 'Aha !  Je sens déjà mes pouvoirs revenir.  Et mon esprit n\'est plus tourmenté par la malédiction d\'Urok.$B$BMerci, <name> !  L\'humilité est en dessous de moi, mais je dois reconnaître ton aide.$B$BEt je te souhaite bonne fortune dans tes voyages à Blackrock Spire.  Tu es un fou de penser que tu pourrais atteindre le sommet, mais ta bravoure est sans aucun doute.') ON DUPLICATE KEY UPDATE RewardText='Aha !  Je sens déjà mes pouvoirs revenir.  Et mon esprit n\'est plus tourmenté par la malédiction d\'Urok.$B$BMerci, <name> !  L\'humilité est en dessous de moi, mais je dois reconnaître ton aide.$B$BEt je te souhaite bonne fortune dans tes voyages à Blackrock Spire.  Tu es un fou de penser que tu pourrais atteindre le sommet, mais ta bravoure est sans aucun doute.';
-- Quest 4883 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4883, 'frFR', 'L\'énergie de ce collier, $N$. Je crois qu\'elle ne vient que d\'une seule source.$b$b<Nara ferme les yeux et se tait un moment.>$b$bLes wildkin, maintenant égarés et confus, ne l\'étaient pas autrefois. Ils avaient un but, et ils étaient guidés pour servir. La déesse des elfes de la nuit Elune créa ces créatures pour garder ses lieux les plus sacrés.$b$bBien que ce fait puisse sembler n\'avoir aucune valeur ; je t\'exhorte à regarder plus profondément.$b$bTu apprendras, avec le temps. Merci de m\'avoir apporté ceci, $N$.') ON DUPLICATE KEY UPDATE RewardText='L\'énergie de ce collier, $N$. Je crois qu\'elle ne vient que d\'une seule source.$b$b<Nara ferme les yeux et se tait un moment.>$b$bLes wildkin, maintenant égarés et confus, ne l\'étaient pas autrefois. Ils avaient un but, et ils étaient guidés pour servir. La déesse des elfes de la nuit Elune créa ces créatures pour garder ses lieux les plus sacrés.$b$bBien que ce fait puisse sembler n\'avoir aucune valeur ; je t\'exhorte à regarder plus profondément.$b$bTu apprendras, avec le temps. Merci de m\'avoir apporté ceci, $N$.';
-- Quest 4906 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4906, 'frFR', 'S\'il vous plaît, mettez fin à la souffrance des créatures de Felwood.') ON DUPLICATE KEY UPDATE CompletionText='S\'il vous plaît, mettez fin à la souffrance des créatures de Felwood.';
-- Quest 4907 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4907, 'frFR', 'Felnok avait raison ! J\'ai besoin de ton aide à nouveau, et cette fois... ça va être vraiment dangereux.$b$bEs-tu prêt??') ON DUPLICATE KEY UPDATE RewardText='Felnok avait raison ! J\'ai besoin de ton aide à nouveau, et cette fois... ça va être vraiment dangereux.$b$bEs-tu prêt??';
-- Quest 4921 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4921, 'frFR', 'As-tu trouvé le moindre signe d\'elle ? La douleur dans ma poitrine me dit que le pire est arrivé, mais j\'ai l\'espoir que tu la trouveras saine et sauve.') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé le moindre signe d\'elle ? La douleur dans ma poitrine me dit que le pire est arrivé, mais j\'ai l\'espoir que tu la trouveras saine et sauve.';
-- Quest 4941 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4941, 'frFR', 'Ne vois-tu pas que je ne dois pas être interrompu ?') ON DUPLICATE KEY UPDATE CompletionText='Ne vois-tu pas que je ne dois pas être interrompu ?';

-- Quest 4961 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4961, 'frFR', 'Tu devras tuer ce démon pour en retirer sa présence de l\'orbe de façon permanente, $N.') ON DUPLICATE KEY UPDATE CompletionText='Tu devras tuer ce démon pour en retirer sa présence de l\'orbe de façon permanente, $N.';
-- Quest 4961 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4961, 'frFR', 'Bien fait, $N! Tu as donné une leçon à ce démon qu\'il n\'oubliera pas. Tu as montré une grande puissance et une grande habileté. Maintenant, je suppose qu\'il est temps que tu retournes à Menara avec ton orbe purifié afin que tu puisses en faire bon usage.$B$BBonne chance, $c. Peut-être nos chemins se croiseront à nouveau.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, $N! Tu as donné une leçon à ce démon qu\'il n\'oubliera pas. Tu as montré une grande puissance et une grande habileté. Maintenant, je suppose qu\'il est temps que tu retournes à Menara avec ton orbe purifié afin que tu puisses en faire bon usage.$B$BBonne chance, $c. Peut-être nos chemins se croiseront à nouveau.';
-- Quest 4962 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4962, 'frFR', 'Oui, $N? As-tu choisi ? Infernal ou felhound?$B$BChaque choix est personnel et devrait refléter tes forces et tes faiblesses. Il n\'est pas inhabituel qu\'un $C s\'améliore davantage au lieu de compenser les domaines dans lesquels il est faible. Parfois, surpasser un ennemi est une tactique tout aussi forte que de devenir un lanceur de sorts plus équilibré.') ON DUPLICATE KEY UPDATE CompletionText='Oui, $N? As-tu choisi ? Infernal ou felhound?$B$BChaque choix est personnel et devrait refléter tes forces et tes faiblesses. Il n\'est pas inhabituel qu\'un $C s\'améliore davantage au lieu de compenser les domaines dans lesquels il est faible. Parfois, surpasser un ennemi est une tactique tout aussi forte que de devenir un lanceur de sorts plus équilibré.';
-- Quest 4962 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4962, 'frFR', 'Ah, l\'esprit d\'un felhound. Bien fait, $N.$B$BQuand j\'aurai à la fois l\'esprit et l\'orbe purifié, je les fusionnerai pour toi, mais pas avant.') ON DUPLICATE KEY UPDATE RewardText='Ah, l\'esprit d\'un felhound. Bien fait, $N.$B$BQuand j\'aurai à la fois l\'esprit et l\'orbe purifié, je les fusionnerai pour toi, mais pas avant.';
-- Quest 4963 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4963, 'frFR', 'Oui, $N? As-tu choisi ? Infernal ou felhound?$B$BChaque choix est personnel et devrait refléter tes forces et tes faiblesses. Il n\'est pas inhabituel qu\'un $C s\'améliore davantage au lieu de compenser les domaines dans lesquels il est faible. Parfois, surpasser un ennemi est une tactique tout aussi forte que de devenir un lanceur de sorts plus équilibré.') ON DUPLICATE KEY UPDATE CompletionText='Oui, $N? As-tu choisi ? Infernal ou felhound?$B$BChaque choix est personnel et devrait refléter tes forces et tes faiblesses. Il n\'est pas inhabituel qu\'un $C s\'améliore davantage au lieu de compenser les domaines dans lesquels il est faible. Parfois, surpasser un ennemi est une tactique tout aussi forte que de devenir un lanceur de sorts plus équilibré.';
-- Quest 4963 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4963, 'frFR', 'Ah, l\'esprit d\'un infernal. Bien fait, $N.$B$BQuand j\'aurai à la fois l\'esprit et l\'orbe purifié, je les fusionnerai pour toi, mais pas avant.') ON DUPLICATE KEY UPDATE RewardText='Ah, l\'esprit d\'un infernal. Bien fait, $N.$B$BQuand j\'aurai à la fois l\'esprit et l\'orbe purifié, je les fusionnerai pour toi, mais pas avant.';
-- Quest 4964 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4964, 'frFR', 'C\'est fait, $N. Dis-moi simplement ce que tu préfères : un bâton qui te demanderait d\'utiliser les deux mains, ou un orbe afin que tu puisses utiliser un poignard ou une épée comme arme.$B$BAffronter un felhound était un exploit remarquable de ta part. Je suis sûr que ton objet te sera utile à l\'avenir. Continue de travailler dur dans les arts, $N. J\'attendrai les détails de tes exploits.') ON DUPLICATE KEY UPDATE RewardText='C\'est fait, $N. Dis-moi simplement ce que tu préfères : un bâton qui te demanderait d\'utiliser les deux mains, ou un orbe afin que tu puisses utiliser un poignard ou une épée comme arme.$B$BAffronter un felhound était un exploit remarquable de ta part. Je suis sûr que ton objet te sera utile à l\'avenir. Continue de travailler dur dans les arts, $N. J\'attendrai les détails de tes exploits.';
-- Quest 4965 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4965, 'frFR', 'Ah, tu cherches quelque chose de plus... substantiel. Je peux t\'aider si tu es vraiment prêt.$B$BC\'est un changement bienvenu de voir l\'un des nôtres chercher plus de pouvoir sous des formes autres que la simple connaissance.$B$BAlors, penses-tu être prêt, $N?') ON DUPLICATE KEY UPDATE RewardText='Ah, tu cherches quelque chose de plus... substantiel. Je peux t\'aider si tu es vraiment prêt.$B$BC\'est un changement bienvenu de voir l\'un des nôtres chercher plus de pouvoir sous des formes autres que la simple connaissance.$B$BAlors, penses-tu être prêt, $N?';
-- Quest 4967 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4967, 'frFR', 'Ah, tu cherches quelque chose de plus... substantiel. Je peux t\'aider si tu es vraiment prêt.$B$BC\'est un changement bienvenu de voir l\'un des nôtres chercher plus de pouvoir sous des formes autres que la simple connaissance.$B$BAlors, penses-tu être prêt, $N?') ON DUPLICATE KEY UPDATE RewardText='Ah, tu cherches quelque chose de plus... substantiel. Je peux t\'aider si tu es vraiment prêt.$B$BC\'est un changement bienvenu de voir l\'un des nôtres chercher plus de pouvoir sous des formes autres que la simple connaissance.$B$BAlors, penses-tu être prêt, $N?';
-- Quest 4968 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4968, 'frFR', 'Ah, tu cherches quelque chose de plus... substantiel. Je peux t\'aider si tu es vraiment prêt.$B$BC\'est un changement bienvenu de voir l\'un des nôtres chercher plus de pouvoir sous des formes autres que la simple connaissance.$B$BAlors, penses-tu être prêt, $N?') ON DUPLICATE KEY UPDATE RewardText='Ah, tu cherches quelque chose de plus... substantiel. Je peux t\'aider si tu es vraiment prêt.$B$BC\'est un changement bienvenu de voir l\'un des nôtres chercher plus de pouvoir sous des formes autres que la simple connaissance.$B$BAlors, penses-tu être prêt, $N?';
-- Quest 4969 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4969, 'frFR', 'Ah, tu cherches quelque chose de plus... substantiel. Je peux t\'aider si tu es vraiment prêt.$B$BC\'est un changement bienvenu de voir l\'un des nôtres chercher plus de pouvoir sous des formes autres que la simple connaissance.$B$BAlors, penses-tu être prêt, $N?') ON DUPLICATE KEY UPDATE RewardText='Ah, tu cherches quelque chose de plus... substantiel. Je peux t\'aider si tu es vraiment prêt.$B$BC\'est un changement bienvenu de voir l\'un des nôtres chercher plus de pouvoir sous des formes autres que la simple connaissance.$B$BAlors, penses-tu être prêt, $N?';
-- Quest 4974 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4974, 'frFR', 'Tu as porté un coup dévastateur aux forces de Blackrock, $N. Avec la mort de leur chef de guerre, la légion de Blackrock est à nouveau jetée dans la gueule du chaos.$B$BEn l\'honneur de tes exploits, le peuple de Kalimdor sera récompensé !') ON DUPLICATE KEY UPDATE RewardText='Tu as porté un coup dévastateur aux forces de Blackrock, $N. Avec la mort de leur chef de guerre, la légion de Blackrock est à nouveau jetée dans la gueule du chaos.$B$BEn l\'honneur de tes exploits, le peuple de Kalimdor sera récompensé !';
-- Quest 4975 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4975, 'frFR', 'C\'est fait, $N. Dis-moi simplement ce que tu préfères : un bâton qui te demanderait d\'utiliser les deux mains, ou un orbe afin que tu puisses utiliser un poignard ou une épée comme arme.$B$BAffronter l\'infernal était un exploit remarquable de ta part et cette récompense te conviendra parfaitement. Je te souhaite plus de succès dans les arts, $N.') ON DUPLICATE KEY UPDATE RewardText='C\'est fait, $N. Dis-moi simplement ce que tu préfères : un bâton qui te demanderait d\'utiliser les deux mains, ou un orbe afin que tu puisses utiliser un poignard ou une épée comme arme.$B$BAffronter l\'infernal était un exploit remarquable de ta part et cette récompense te conviendra parfaitement. Je te souhaite plus de succès dans les arts, $N.';
-- Quest 4976 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4976, 'frFR', 'Comment se passe ta recherche de Tabetha et de l\'orbe, $N?$B$BTabetha a été plus qu\'utile en ce qui concerne les affaires arcaniques. Je suis sûr qu\'elle n\'aura aucun problème à t\'aider si tu parviens à la trouver.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe ta recherche de Tabetha et de l\'orbe, $N?$B$BTabetha a été plus qu\'utile en ce qui concerne les affaires arcaniques. Je suis sûr qu\'elle n\'aura aucun problème à t\'aider si tu parviens à la trouver.';
-- Quest 4976 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4976, 'frFR', 'Bien fait, $N. Ça fera l\'affaire.$B$BLa seule chose qui te reste à faire est de décider quel démon tu veux que j\'emprisonne dans l\'orbe purifié. Fais cela, et tu auras un nouvel objet magnifique à manier.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, $N. Ça fera l\'affaire.$B$BLa seule chose qui te reste à faire est de décider quel démon tu veux que j\'emprisonne dans l\'orbe purifié. Fais cela, et tu auras un nouvel objet magnifique à manier.';

-- Quest 4981 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4981, 'frFR', 'Je ne vais pas te mentir, $R$. J\'avais besoin de l\'argent ! Kibler paie très, très bien - bien mieux que le K.E.F. n\'aurait jamais pu payer.$B$BMais ne doute pas de ma loyauté ! Pourquoi penses-tu que je suis descendu ici ? Pour aller chercher des œufs d\'animaux exotiques à ce gobelin fou ou quelque chose d\'aussi absurde ? Non, seul un vrai imbécile viendrait à Blackrock Spire pour ramasser des animaux de compagnie. Oui, je ne crois pas qu\'il y en ait beaucoup dans ce monde.$B$B$B$BLa dernière chose dont nous avons besoin, ce sont ces gens qui se reproduisent.') ON DUPLICATE KEY UPDATE RewardText='Je ne vais pas te mentir, $R$. J\'avais besoin de l\'argent ! Kibler paie très, très bien - bien mieux que le K.E.F. n\'aurait jamais pu payer.$B$BMais ne doute pas de ma loyauté ! Pourquoi penses-tu que je suis descendu ici ? Pour aller chercher des œufs d\'animaux exotiques à ce gobelin fou ou quelque chose d\'aussi absurde ? Non, seul un vrai imbécile viendrait à Blackrock Spire pour ramasser des animaux de compagnie. Oui, je ne crois pas qu\'il y en ait beaucoup dans ce monde.$B$B$B$BLa dernière chose dont nous avons besoin, ce sont ces gens qui se reproduisent.';
-- Quest 4982 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4982, 'frFR', 'Tu l\'as fait ! Une fois que Lexlort aura ces plans, il oubliera toutes les choses horribles qu\'il voulait me faire.$B$B<name>, tu es mon héros !') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait ! Une fois que Lexlort aura ces plans, il oubliera toutes les choses horribles qu\'il voulait me faire.$B$B<name>, tu es mon héros !';
-- Quest 4983 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (4983, 'frFR', 'Je dois lui admettre ; elle est parvenue à se dégager d\'une autre situation délicate ! Ces rapports seront inestimables dans nos dealings avec les orcs de Blackrock.$b$bBien sûr, tu seras récompensé pour ton travail acharné.') ON DUPLICATE KEY UPDATE RewardText='Je dois lui admettre ; elle est parvenue à se dégager d\'une autre situation délicate ! Ces rapports seront inestimables dans nos dealings avec les orcs de Blackrock.$b$bBien sûr, tu seras récompensé pour ton travail acharné.';
-- Quest 4984 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4984, 'frFR', 'Les loups infectés par le fléau doivent être abattus, $N$. La maladie qu\'ils portent ne peut pas être guérie. J\'ai essayé... J\'ai essayé jusqu\'à succomber moi-même au fléau.') ON DUPLICATE KEY UPDATE CompletionText='Les loups infectés par le fléau doivent être abattus, $N$. La maladie qu\'ils portent ne peut pas être guérie. J\'ai essayé... J\'ai essayé jusqu\'à succomber moi-même au fléau.';
-- Quest 4985 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4985, 'frFR', 'J\'entends tes pas, $N$. Ma vision s\'est estompée, mais je suis toujours capable de sentir les choses autour de moi. As-tu mis fin à la misère des grizzlis atteints de maladie ?') ON DUPLICATE KEY UPDATE CompletionText='J\'entends tes pas, $N$. Ma vision s\'est estompée, mais je suis toujours capable de sentir les choses autour de moi. As-tu mis fin à la misère des grizzlis atteints de maladie ?';
-- Quest 4987 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4987, 'frFR', 'Au nom du Cercle de Cenarion, je vous souhaite la bienvenue dans cet enclave, $C$. Quel est votre intérêt avec nous ?') ON DUPLICATE KEY UPDATE CompletionText='Au nom du Cercle de Cenarion, je vous souhaite la bienvenue dans cet enclave, $C$. Quel est votre intérêt avec nous ?';
-- Quest 5041 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5041, 'frFR', 'Comment se passe ta recherche de fournitures, $N$? Je crois que les quilboars tombent facilement sous ta puissance.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe ta recherche de fournitures, $N$? Je crois que les quilboars tombent facilement sous ta puissance.';
-- Quest 5041 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5041, 'frFR', 'Haha ! Merci, <name> ! Cela nous aidera beaucoup. Je vais faire emballer ces fournitures et les envoyer à la Crossroads immédiatement.') ON DUPLICATE KEY UPDATE RewardText='Haha ! Merci, <name> ! Cela nous aidera beaucoup. Je vais faire emballer ces fournitures et les envoyer à la Crossroads immédiatement.';
-- Quest 5042 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5042, 'frFR', 'J\'aurai besoin de 4 éclats de sang si tu souhaites la force d\'Agamaggan, $r.$B$BTes ennemis trembleront devant ta puissance si on t\'octroie cette bénédiction. <snort>$B$BLes plus grands guerriers du Razormane sont infusés d\'une telle puissance !') ON DUPLICATE KEY UPDATE CompletionText='J\'aurai besoin de 4 éclats de sang si tu souhaites la force d\'Agamaggan, $r.$B$BTes ennemis trembleront devant ta puissance si on t\'octroie cette bénédiction. <snort>$B$BLes plus grands guerriers du Razormane sont infusés d\'une telle puissance !';
-- Quest 5042 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5042, 'frFR', 'Si seulement Mangletooth était libre de te voir décimer ceux qui l\'ont trahi ! $Gsnort>$B<br :>Je vous remercie d\'avoir détruit plus de Bristleback en rassemblant ces éclats. S\'il vous plaît, continuez à le faire, et je continuerai à vous aider. <snort') ON DUPLICATE KEY UPDATE RewardText='Si seulement Mangletooth était libre de te voir décimer ceux qui l\'ont trahi ! $Gsnort>$B<br :>Je vous remercie d\'avoir détruit plus de Bristleback en rassemblant ces éclats. S\'il vous plaît, continuez à le faire, et je continuerai à vous aider. <snort';
-- Quest 5043 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5043, 'frFR', 'Les meilleurs éclaireurs de ma tribu sont réputés inégalés en précision, et aucun renégat <snort> ne pourrait rivaliser avec leur rapidité au combat.$B$BBring me 4 blood shards and I will make you even more agile than any quilboar born.') ON DUPLICATE KEY UPDATE CompletionText='Les meilleurs éclaireurs de ma tribu sont réputés inégalés en précision, et aucun renégat <snort> ne pourrait rivaliser avec leur rapidité au combat.$B$BBring me 4 blood shards and I will make you even more agile than any quilboar born.';
-- Quest 5043 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5043, 'frFR', 'Que ton aimant soit infaillible, et la marque de ton arme soit juste, $R.$B$BAgamaggan\'s spirit is with you. Return  to me if you wish. Mangletooth will bless you again if the great boar god deems me worthy.') ON DUPLICATE KEY UPDATE RewardText='Que ton aimant soit infaillible, et la marque de ton arme soit juste, $R.$B$BAgamaggan\'s spirit is with you. Return  to me if you wish. Mangletooth will bless you again if the great boar god deems me worthy.';
-- Quest 5044 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5044, 'frFR', 'Les chamanes et les géomanciens des tribus de quilboar <snort> invoquent la force d\'Agamaggan pour les aider au combat et dans leurs rituels, $r.$B$BSi toi aussi tu souhaites le pouvoir ajouté de la bénédiction d\'Agamaggan avec tes sorts, alors apporte-moi 4 éclats de sang et Mangletooth t\'aidera. <snort>') ON DUPLICATE KEY UPDATE CompletionText='Les chamanes et les géomanciens des tribus de quilboar <snort> invoquent la force d\'Agamaggan pour les aider au combat et dans leurs rituels, $r.$B$BSi toi aussi tu souhaites le pouvoir ajouté de la bénédiction d\'Agamaggan avec tes sorts, alors apporte-moi 4 éclats de sang et Mangletooth t\'aidera. <snort>';
-- Quest 5045 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5045, 'frFR', 'Nos plus grands guerriers, et nos plus grands <snort> shamans seraient jaloux de ta volonté, $R.$B$BVaincs plus de Bristlebacks en sachant qu\'ils ne peuvent pas t\'arrêter ! <snort>') ON DUPLICATE KEY UPDATE RewardText='Nos plus grands guerriers, et nos plus grands <snort> shamans seraient jaloux de ta volonté, $R.$B$BVaincs plus de Bristlebacks en sachant qu\'ils ne peuvent pas t\'arrêter ! <snort>';
-- Quest 5046 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5046, 'frFR', 'Tous ceux qui <snort> entrent en bataille ont besoin de protection. Leurs os doivent être solides. Leur peau épaisse. <snort> Ma tribu le sait aussi, et pour ajouter à la protection naturelle que nous donnent nos épines et notre peau, <snort> nous invoquons souvent Agamaggan pour nous protéger des maux avant d\'aller à la guerre.$B$BBring me 4 blood shards <snort> et je te donnerai la même protection.') ON DUPLICATE KEY UPDATE CompletionText='Tous ceux qui <snort> entrent en bataille ont besoin de protection. Leurs os doivent être solides. Leur peau épaisse. <snort> Ma tribu le sait aussi, et pour ajouter à la protection naturelle que nous donnent nos épines et notre peau, <snort> nous invoquons souvent Agamaggan pour nous protéger des maux avant d\'aller à la guerre.$B$BBring me 4 blood shards <snort> et je te donnerai la même protection.';
-- Quest 5047 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5047, 'frFR', 'Vivant ? Suit fonctionnel ? Et qu\'avons-nous ici ?') ON DUPLICATE KEY UPDATE RewardText='Vivant ? Suit fonctionnel ? Et qu\'avons-nous ici ?';
-- Quest 5056 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5056, 'frFR', 'Shy-Rotam est audacieuse et impitoyable ; elle défendra sa tribu avec un enthousiasme fervent.') ON DUPLICATE KEY UPDATE CompletionText='Shy-Rotam est audacieuse et impitoyable ; elle défendra sa tribu avec un enthousiasme fervent.';
-- Quest 5057 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5057, 'frFR', 'Nous apprenons de nos expériences de vie, $Gname>. Je suis sûr que tu n\'es devenu plus fort et plus sage qu\'à cause des tiennes. Tu as beaucoup grandi depuis que nous nous sommes parlé pour la première fois.$B<br :>Prends ceci en souvenir des tâches difficiles que tu as accomplies en tant que $R <class>, et sache que tu auras toujours mon respect et mon admiration.') ON DUPLICATE KEY UPDATE RewardText='Nous apprenons de nos expériences de vie, $Gname>. Je suis sûr que tu n\'es devenu plus fort et plus sage qu\'à cause des tiennes. Tu as beaucoup grandi depuis que nous nous sommes parlé pour la première fois.$B<br :>Prends ceci en souvenir des tâches difficiles que tu as accomplies en tant que $R <class>, et sache que tu auras toujours mon respect et mon admiration.';
-- Quest 5058 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5058, 'frFR', 'Un journal aux pages jaunies est ouvert sur la dernière entrée:$B$B"Je ne sais pas ce qui va se passer maintenant que Harold est devenu fou. Il m\'a fallu tout pour le traîner dans le seul endroit où j\'ai pu trouver qui l\'emprisonner fermement et le garder. J\'ai caché la clé sur moi, et j\'espère que ça marche...$B$BI espère pouvoir sortir d\'ici, mais j\'ai besoin d\'argent pour faire ça. Nos affaires sont toutes dans l\'armoire je crois... et maintenant que j\'y pense, Harold garde la clé sur lui ?$B$BI m\'en tiendrai compte, je suis épuisé."') ON DUPLICATE KEY UPDATE RewardText='Un journal aux pages jaunies est ouvert sur la dernière entrée:$B$B"Je ne sais pas ce qui va se passer maintenant que Harold est devenu fou. Il m\'a fallu tout pour le traîner dans le seul endroit où j\'ai pu trouver qui l\'emprisonner fermement et le garder. J\'ai caché la clé sur moi, et j\'espère que ça marche...$B$BI espère pouvoir sortir d\'ici, mais j\'ai besoin d\'argent pour faire ça. Nos affaires sont toutes dans l\'armoire je crois... et maintenant que j\'y pense, Harold garde la clé sur lui ?$B$BI m\'en tiendrai compte, je suis épuisé."';
-- Quest 5059 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5059, 'frFR', 'La porte des toilettes sèches a commencé à s\'écailler sur les bords du cadre comme si elle avait été forcée de manière répétée et incessante. Elle est actuellement verrouillée de l\'extérieur des toilettes sèches.$B$BQuand tu secoues la porte, tu entends un gémissement guttural venant de l\'intérieur ! Ce qui est là-dedans, cela ne semble certainement pas amical.') ON DUPLICATE KEY UPDATE CompletionText='La porte des toilettes sèches a commencé à s\'écailler sur les bords du cadre comme si elle avait été forcée de manière répétée et incessante. Elle est actuellement verrouillée de l\'extérieur des toilettes sèches.$B$BQuand tu secoues la porte, tu entends un gémissement guttural venant de l\'intérieur ! Ce qui est là-dedans, cela ne semble certainement pas amical.';
-- Quest 5059 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5059, 'frFR', 'En utilisant la clé trouvée sur le squelette de l\'ancienne Mme Dalson, tu déverrouilles la porte des toilettes sèches. Un goule sanguinaire saute des toilettes sèches, ayant été piégé à l\'intérieur depuis qui sait combien de temps.') ON DUPLICATE KEY UPDATE RewardText='En utilisant la clé trouvée sur le squelette de l\'ancienne Mme Dalson, tu déverrouilles la porte des toilettes sèches. Un goule sanguinaire saute des toilettes sèches, ayant été piégé à l\'intérieur depuis qui sait combien de temps.';
-- Quest 5060 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5060, 'frFR', 'Une armoire extrêmement solide se trouve devant toi, fermement verrouillée par une serrure intégrée. Le devant de l\'armoire est profondément éraflé et marqué. Cela pourrait être supposé provenir de nombreuses tentatives violentes et infructueuses pour révéler quels secrets l\'armoire masque actuellement de la vue.$B$BSi tu vas ouvrir cette armoire, tu auras besoin de trouver la clé.') ON DUPLICATE KEY UPDATE CompletionText='Une armoire extrêmement solide se trouve devant toi, fermement verrouillée par une serrure intégrée. Le devant de l\'armoire est profondément éraflé et marqué. Cela pourrait être supposé provenir de nombreuses tentatives violentes et infructueuses pour révéler quels secrets l\'armoire masque actuellement de la vue.$B$BSi tu vas ouvrir cette armoire, tu auras besoin de trouver la clé.';
-- Quest 5060 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5060, 'frFR', 'La clé prise des restes de goule de Farmer Dalson correspond parfaitement à la serrure. Les portes de l\'armoire s\'ouvrent, révélant plusieurs objets qui restent intacts et semblent assez précieux.') ON DUPLICATE KEY UPDATE RewardText='La clé prise des restes de goule de Farmer Dalson correspond parfaitement à la serrure. Les portes de l\'armoire s\'ouvrent, révélant plusieurs objets qui restent intacts et semblent assez précieux.';
-- Quest 5061 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5061, 'frFR', 'Ton retour à Darnassus n\'est pas sans présages, bien que j\'aurai besoin de preuves de tes leçons apprises à Moonglade avant de t\'enseigner ta forme aquatique.$B$BAs-tu le pendentif du Lion de mer ?') ON DUPLICATE KEY UPDATE CompletionText='Ton retour à Darnassus n\'est pas sans présages, bien que j\'aurai besoin de preuves de tes leçons apprises à Moonglade avant de t\'enseigner ta forme aquatique.$B$BAs-tu le pendentif du Lion de mer ?';
-- Quest 5061 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5061, 'frFR', 'Très impressionnant, $N. Tu es prêt à apprendre ta forme aquatique, et c\'est un plaisir de te l\'enseigner.$B$BDe plus, en reconnaissance de ton exploit lors des deux épreuves, je te donne cet objet. J\'espère que tu le trouveras un ajout bienvenu à ton équipement en tant que protecteur de la nature et gardien de l\'équilibre.') ON DUPLICATE KEY UPDATE RewardText='Très impressionnant, $N. Tu es prêt à apprendre ta forme aquatique, et c\'est un plaisir de te l\'enseigner.$B$BDe plus, en reconnaissance de ton exploit lors des deux épreuves, je te donne cet objet. J\'espère que tu le trouveras un ajout bienvenu à ton équipement en tant que protecteur de la nature et gardien de l\'équilibre.';
-- Quest 5063 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5063, 'frFR', 'À moins que tu n\'aies tout ce dont j\'ai besoin, tu me fais perdre mon temps.') ON DUPLICATE KEY UPDATE CompletionText='À moins que tu n\'aies tout ce dont j\'ai besoin, tu me fais perdre mon temps.';
-- Quest 5063 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5063, 'frFR', 'Étonnant ! Il a dû prendre des semaines de rassembler ces composants... et comment as-tu trouvé une peau immaculée?!?$b$bProfite du cap, $N!') ON DUPLICATE KEY UPDATE RewardText='Étonnant ! Il a dû prendre des semaines de rassembler ces composants... et comment as-tu trouvé une peau immaculée?!?$b$bProfite du cap, $N!';
-- Quest 5067 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5067, 'frFR', 'À moins que tu n\'aies tout ce dont j\'ai besoin, tu me fais perdre mon temps.') ON DUPLICATE KEY UPDATE CompletionText='À moins que tu n\'aies tout ce dont j\'ai besoin, tu me fais perdre mon temps.';

-- Quest 5067 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5067, 'frFR', 'Quelques autres tâches improbables que j\'ai vues accomplies par des mortels. Plongez dans la gloire de mon œuvre ! Récoltez ses récompenses !') ON DUPLICATE KEY UPDATE RewardText='Quelques autres tâches improbables que j\'ai vues accomplies par des mortels. Plongez dans la gloire de mon œuvre ! Récoltez ses récompenses !';
-- Quest 5068 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5068, 'frFR', 'À moins que vous n\'ayez tout ce dont j\'ai besoin, vous me faites perdre mon temps.') ON DUPLICATE KEY UPDATE CompletionText='À moins que vous n\'ayez tout ce dont j\'ai besoin, vous me faites perdre mon temps.';
-- Quest 5068 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5068, 'frFR', 'Je pensais être mort et enterré avant de voir ce jour. $B$Un accomplissement d\'une telle ampleur ne peut être éclipsé que par la récompense.') ON DUPLICATE KEY UPDATE RewardText='Je pensais être mort et enterré avant de voir ce jour. $B$Un accomplissement d\'une telle ampleur ne peut être éclipsé que par la récompense.';
-- Quest 5081 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5081, 'frFR', 'Excellent travail, <name>. Au minimum, vous nous avez acheté plus de temps - un temps précieux, précieux.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>. Au minimum, vous nous avez acheté plus de temps - un temps précieux, précieux.';
-- Quest 5082 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5082, 'frFR', 'Merci beaucoup, $N! Maintenant, je peux retourner au travail ici.$B$Avez-vous trouvé quelque chose d\'intéressant au camp de Winterfall ?') ON DUPLICATE KEY UPDATE RewardText='Merci beaucoup, $N! Maintenant, je peux retourner au travail ici.$B$Avez-vous trouvé quelque chose d\'intéressant au camp de Winterfall ?';
-- Quest 5088 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5088, 'frFR', 'Avez-vous abattu le serpent vicieux Arikara, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous abattu le serpent vicieux Arikara, $N?';
-- Quest 5090 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5090, 'frFR', 'Bienvenue aux Plaguelands, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue aux Plaguelands, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.';
-- Quest 5091 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5091, 'frFR', 'Bienvenue aux Plaguelands, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue aux Plaguelands, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.';
-- Quest 5092 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5092, 'frFR', 'Je veux que vous vous prépariez au pire, $N - creusez profondément. La tâche qui nous attend ne sera pas facile. Alors que nous rassemblons nos forces ici pour finalement frapper contre la Horde noire, vous ferez partie de notre effort d\'avancée qui emmènera le combat chez eux ! Votre mission assignée dans Sorrow Hill commencera notre chemin vers la victoire !') ON DUPLICATE KEY UPDATE CompletionText='Je veux que vous vous prépariez au pire, $N - creusez profondément. La tâche qui nous attend ne sera pas facile. Alors que nous rassemblons nos forces ici pour finalement frapper contre la Horde noire, vous ferez partie de notre effort d\'avancée qui emmènera le combat chez eux ! Votre mission assignée dans Sorrow Hill commencera notre chemin vers la victoire !';
-- Quest 5092 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5092, 'frFR', 'Mission accomplie, <name>!  Bien joué, bien joué.$B$BPermettez-moi de récompenser votre travail jusqu\'à présent avec quelques pièces des coffres de Stormwind.  Je vous recommande de les dépenser pour du matériel qui vous aidera dans votre prochaine mission... une qui vous mènera aux ruines mêmes d\'Andorhal.$B$BSoyez prêt !  Soyez vigilant !') ON DUPLICATE KEY UPDATE RewardText='Mission accomplie, <name>!  Bien joué, bien joué.$B$BPermettez-moi de récompenser votre travail jusqu\'à présent avec quelques pièces des coffres de Stormwind.  Je vous recommande de les dépenser pour du matériel qui vous aidera dans votre prochaine mission... une qui vous mènera aux ruines mêmes d\'Andorhal.$B$BSoyez prêt !  Soyez vigilant !';
-- Quest 5093 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5093, 'frFR', 'Bienvenue aux Plaguelands, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue aux Plaguelands, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.';
-- Quest 5094 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5094, 'frFR', 'Bienvenue aux Plaguelands, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue aux Plaguelands, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.';
-- Quest 5095 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5095, 'frFR', 'Bienvenue aux Plaguelands, héros.  C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là.  Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue aux Plaguelands, héros.  C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde noire à notre est, et encore plus loin vers l\'est à partir de là.  Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Plaguelands.';
-- Quest 5097 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5097, 'frFR', 'Une fois que les tours sont marquées, elles deviendront des cibles prioritaires pour notre attaque sur Andorhal. Je soupçonne qu\'une fois que nous neutraliserons les tours, la menace principale d\'Andorhal émergera. À partir de ce point, nous aurons un combat direct pour le contrôle de la ville !$B$Vous êtes de retour pour rapporter le succès, n\'est-ce pas ? N\'oubliez pas le flambeau balise non plus ; nous devons maintenir le contrôle de notre matériel.') ON DUPLICATE KEY UPDATE CompletionText='Une fois que les tours sont marquées, elles deviendront des cibles prioritaires pour notre attaque sur Andorhal. Je soupçonne qu\'une fois que nous neutraliserons les tours, la menace principale d\'Andorhal émergera. À partir de ce point, nous aurons un combat direct pour le contrôle de la ville !$B$Vous êtes de retour pour rapporter le succès, n\'est-ce pas ? N\'oubliez pas le flambeau balise non plus ; nous devons maintenir le contrôle de notre matériel.';
-- Quest 5097 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5097, 'frFR', 'Mes prêtres rapportent que nos traceurs de balises détectent des signaux extrêmement forts sur les quatre tours !  J\'ose dire que je crois que vous avez exécuté une autre mission avec succès total et complet !  Bien joué une fois de plus, <name>!$B$BAvec les tours marquées, nos préparatifs pour l\'attaque sont maintenant en place.  Il est temps d\'emmener le combat chez la Horde noire !') ON DUPLICATE KEY UPDATE RewardText='Mes prêtres rapportent que nos traceurs de balises détectent des signaux extrêmement forts sur les quatre tours !  J\'ose dire que je crois que vous avez exécuté une autre mission avec succès total et complet !  Bien joué une fois de plus, <name>!$B$BAvec les tours marquées, nos préparatifs pour l\'attaque sont maintenant en place.  Il est temps d\'emmener le combat chez la Horde noire !';

-- Quest 5098 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5098, 'frFR', 'Une fois les tours marquées, elles deviendront les cibles prioritaires de notre attaque sur Andorhal. Je soupçonne qu\'une fois que nous aurons neutralisé les tours, la menace principale d\'Andorhal apparaîtra. À partir de ce point, nous aurons un combat direct pour le contrôle de la ville !$b$bVous êtes de retour pour rapporter le succès, n\'est-ce pas ? N\'oubliez pas non plus la torche balise ; nous devons maintenir le contrôle de notre matériel.') ON DUPLICATE KEY UPDATE CompletionText='Une fois les tours marquées, elles deviendront les cibles prioritaires de notre attaque sur Andorhal. Je soupçonne qu\'une fois que nous aurons neutralisé les tours, la menace principale d\'Andorhal apparaîtra. À partir de ce point, nous aurons un combat direct pour le contrôle de la ville !$b$bVous êtes de retour pour rapporter le succès, n\'est-ce pas ? N\'oubliez pas non plus la torche balise ; nous devons maintenir le contrôle de notre matériel.';
-- Quest 5098 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5098, 'frFR', 'Mes sorciers rapportent que nos traceurs de balises détectent des signaux extrêmement forts sur les quatre tours !  Vous avez exécuté mes ordres avec le talent et la précision d\'un vétéran aguerri.  Votre service à la Horde est noté une fois de plus, <name>!$B$BAvec les tours marquées, nos préparatifs pour l\'attaque sont maintenant en place.  Il est temps de mener le combat contre les Scourge !') ON DUPLICATE KEY UPDATE RewardText='Mes sorciers rapportent que nos traceurs de balises détectent des signaux extrêmement forts sur les quatre tours !  Vous avez exécuté mes ordres avec le talent et la précision d\'un vétéran aguerri.  Votre service à la Horde est noté une fois de plus, <name>!$B$BAvec les tours marquées, nos préparatifs pour l\'attaque sont maintenant en place.  Il est temps de mener le combat contre les Scourge !';
-- Quest 5121 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5121, 'frFR', 'Peut-être en saurez-vous plus dans le Village de Winterfall, $N.') ON DUPLICATE KEY UPDATE CompletionText='Peut-être en saurez-vous plus dans le Village de Winterfall, $N.';
-- Quest 5122 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5122, 'frFR', 'La puissance de ce chapelle me donne la force de résister à la corruption dans mon cœur. Si je la quitte, je deviendrai un chevalier de la mort. Mais il y a un médaillon, le médaillon de foi, qui me donnera la force dont j\'ai besoin pour partir.$B$BS\'il vous plaît, $N, récupérez le médaillon. Il est gardé par Malor le Zélé, un membre fou de la Croisade Écarlate qui réside au fond de la Bastion Écarlate dans l\'ouest de Stratholme.') ON DUPLICATE KEY UPDATE CompletionText='La puissance de ce chapelle me donne la force de résister à la corruption dans mon cœur. Si je la quitte, je deviendrai un chevalier de la mort. Mais il y a un médaillon, le médaillon de foi, qui me donnera la force dont j\'ai besoin pour partir.$B$BS\'il vous plaît, $N, récupérez le médaillon. Il est gardé par Malor le Zélé, un membre fou de la Croisade Écarlate qui réside au fond de la Bastion Écarlate dans l\'ouest de Stratholme.';
-- Quest 5122 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5122, 'frFR', 'Vous avez récupéré le médaillon ! Maintenant, je pourrai quitter la chapelle et accomplir mon devoir.$B$BCe devoir est de tuer la bête qui m\'a aidé à me corrompre, moi et tant de mes frères et sœurs, Baron Rivendare !') ON DUPLICATE KEY UPDATE RewardText='Vous avez récupéré le médaillon ! Maintenant, je pourrai quitter la chapelle et accomplir mon devoir.$B$BCe devoir est de tuer la bête qui m\'a aidé à me corrompre, moi et tant de mes frères et sœurs, Baron Rivendare !';
-- Quest 5124 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5124, 'frFR', 'Le temps, c\'est de l\'argent, $N, et je n\'ai pas beaucoup des deux.') ON DUPLICATE KEY UPDATE CompletionText='Le temps, c\'est de l\'argent, $N, et je n\'ai pas beaucoup des deux.';
-- Quest 5124 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5124, 'frFR', 'Comme promis, $N, voici votre recette ! Je vais aussi ajouter un petit quelque chose en plus pour tout votre travail et votre dévouement. Qu\'est-ce que je vais faire avec ça, de toute façon???') ON DUPLICATE KEY UPDATE RewardText='Comme promis, $N, voici votre recette ! Je vais aussi ajouter un petit quelque chose en plus pour tout votre travail et votre dévouement. Qu\'est-ce que je vais faire avec ça, de toute façon???';
-- Quest 5125 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5125, 'frFR', '$N, je meurs... mais mon âme est sauvée. Pour cela, je vous dois plus que les mots ne peuvent le dire. S\'il vous plaît, prenez ceci... et continuez à vous battre, brave $c!') ON DUPLICATE KEY UPDATE RewardText='$N, je meurs... mais mon âme est sauvée. Pour cela, je vous dois plus que les mots ne peuvent le dire. S\'il vous plaît, prenez ceci... et continuez à vous battre, brave $c!';
-- Quest 5127 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5127, 'frFR', 'Notre pacte vous ne l\'avez pas brisé. L\'âme que j\'ai prise. La récompense que je vous donnerai.') ON DUPLICATE KEY UPDATE RewardText='Notre pacte vous ne l\'avez pas brisé. L\'âme que j\'ai prise. La récompense que je vous donnerai.';
-- Quest 5141 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5141, 'frFR', 'Si vous êtes prêt à vous engager dans une décision permanente en devenant un artisan de cuir à écailles de dragon, alors je suis prêt à vous prendre comme étudiant. Apportez-moi simplement ce que j\'ai demandé, et nous commencerons votre éducation.') ON DUPLICATE KEY UPDATE CompletionText='Si vous êtes prêt à vous engager dans une décision permanente en devenant un artisan de cuir à écailles de dragon, alors je suis prêt à vous prendre comme étudiant. Apportez-moi simplement ce que j\'ai demandé, et nous commencerons votre éducation.';
-- Quest 5141 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5141, 'frFR', 'Je vous le remets - il faut une volonté forte pour prendre une décision permanente comme vous venez de le faire. Je vous assure que le travail du cuir à écailles de dragon s\'avérera un chemin profitable et gratifiant à suivre pour vous.$B$BPour vous former dans cet art pour l\'avenir, il vous suffit de me parler et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.') ON DUPLICATE KEY UPDATE RewardText='Je vous le remets - il faut une volonté forte pour prendre une décision permanente comme vous venez de le faire. Je vous assure que le travail du cuir à écailles de dragon s\'avérera un chemin profitable et gratifiant à suivre pour vous.$B$BPour vous former dans cet art pour l\'avenir, il vous suffit de me parler et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.';
-- Quest 5143 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5143, 'frFR', 'La nature est une force qui doit être apaisée avant que vous espériez apprendre à plier sa volonté dans vos vêtements de cuir. Apportez-moi votre offrande à cette force, et je m\'assurerai que vous soyez entendu.') ON DUPLICATE KEY UPDATE CompletionText='La nature est une force qui doit être apaisée avant que vous espériez apprendre à plier sa volonté dans vos vêtements de cuir. Apportez-moi votre offrande à cette force, et je m\'assurerai que vous soyez entendu.';
-- Quest 5143 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5143, 'frFR', 'Vous avez fait vos offrandes les plus précieuses, et la nature vous permettra bientôt de la plier à votre volonté. Une fois que j\'aurai terminé mon tutorat, votre travail sera une force de la nature en soi.$B$BPour vous former dans cet art pour l\'avenir, il vous suffit de me parler et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait vos offrandes les plus précieuses, et la nature vous permettra bientôt de la plier à votre volonté. Une fois que j\'aurai terminé mon tutorat, votre travail sera une force de la nature en soi.$B$BPour vous former dans cet art pour l\'avenir, il vous suffit de me parler et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.';
-- Quest 5144 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5144, 'frFR', 'Fabriquer cette sorte d\'armure en cuir nécessite de la patience et du dévouement. Une fois que vous avez fait votre choix parmi les éléments, il n\'y a pas de retour en arrière. Apportez-moi la preuve de votre valeur, et nous commencerons.') ON DUPLICATE KEY UPDATE CompletionText='Fabriquer cette sorte d\'armure en cuir nécessite de la patience et du dévouement. Une fois que vous avez fait votre choix parmi les éléments, il n\'y a pas de retour en arrière. Apportez-moi la preuve de votre valeur, et nous commencerons.';
-- Quest 5144 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5144, 'frFR', 'Vous avez fait votre choix, et les éléments vous acceptent. Une fois que j\'aurai terminé mon tutorat, vous commanderez la volonté de confectionner les plus beaux habits de cuir.$B$BPour vous former dans cet art pour l\'avenir, il vous suffit de me parler et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait votre choix, et les éléments vous acceptent. Une fois que j\'aurai terminé mon tutorat, vous commanderez la volonté de confectionner les plus beaux habits de cuir.$B$BPour vous former dans cet art pour l\'avenir, il vous suffit de me parler et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.';

-- Quest 5145 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5145, 'frFR', 'Si vous êtes prêt à prendre une décision permanente en devenant un travailleur de cuir à écailles de dragon, alors je suis prêt à vous prendre comme étudiant. Apportez-moi simplement ce que j\'ai demandé, et nous commencerons votre éducation.') ON DUPLICATE KEY UPDATE CompletionText='Si vous êtes prêt à prendre une décision permanente en devenant un travailleur de cuir à écailles de dragon, alors je suis prêt à vous prendre comme étudiant. Apportez-moi simplement ce que j\'ai demandé, et nous commencerons votre éducation.';
-- Quest 5145 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5145, 'frFR', 'Je vous la donne - il faut une volonté forte pour prendre une décision permanente comme celle que vous venez de prendre. Je vous assure que le travail du cuir à écailles de dragon s\'avérera un chemin profitable et gratifiant à suivre.$b$bPour vous former dans cet art pour l\'avenir, parlez-moi simplement et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.') ON DUPLICATE KEY UPDATE RewardText='Je vous la donne - il faut une volonté forte pour prendre une décision permanente comme celle que vous venez de prendre. Je vous assure que le travail du cuir à écailles de dragon s\'avérera un chemin profitable et gratifiant à suivre.$b$bPour vous former dans cet art pour l\'avenir, parlez-moi simplement et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.';
-- Quest 5146 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5146, 'frFR', 'La confection de cette armure à base de cuir nécessite patience et dévouement. Une fois que vous avez fait votre choix parmi les éléments, il n\'y a pas de retour en arrière. Apportez-moi la preuve de votre valeur, et nous commencerons.') ON DUPLICATE KEY UPDATE CompletionText='La confection de cette armure à base de cuir nécessite patience et dévouement. Une fois que vous avez fait votre choix parmi les éléments, il n\'y a pas de retour en arrière. Apportez-moi la preuve de votre valeur, et nous commencerons.';
-- Quest 5146 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5146, 'frFR', 'Vous avez fait votre choix, et les éléments vous acceptent. Une fois que j\'aurai terminé mon tutorat, vous commanderez la volonté de confectionner les plus fins des vêtements en cuir.$B$BPour vous former dans cet art pour l\'avenir, parlez-moi simplement et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait votre choix, et les éléments vous acceptent. Une fois que j\'aurai terminé mon tutorat, vous commanderez la volonté de confectionner les plus fins des vêtements en cuir.$B$BPour vous former dans cet art pour l\'avenir, parlez-moi simplement et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.';
-- Quest 5148 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5148, 'frFR', 'La nature est une force qui doit être apaisée avant que vous espériez apprendre à plier sa volonté dans vos vêtements de cuir. Apportez-moi votre offrande à cette force, et je m\'assurerai que vous soyez entendu.') ON DUPLICATE KEY UPDATE CompletionText='La nature est une force qui doit être apaisée avant que vous espériez apprendre à plier sa volonté dans vos vêtements de cuir. Apportez-moi votre offrande à cette force, et je m\'assurerai que vous soyez entendu.';
-- Quest 5148 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5148, 'frFR', 'Vous avez fait vos offrandes les plus précieuses, et la nature vous permettra bientôt de la soumettre à votre volonté. Une fois que j\'aurai terminé mon tutorat, votre travail sera une force de la nature en soi.$B$BPour vous former dans cet art pour l\'avenir, parlez-moi simplement et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait vos offrandes les plus précieuses, et la nature vous permettra bientôt de la soumettre à votre volonté. Une fois que j\'aurai terminé mon tutorat, votre travail sera une force de la nature en soi.$B$BPour vous former dans cet art pour l\'avenir, parlez-moi simplement et je rendrai disponible toute connaissance que vous n\'avez pas encore adoptée comme la vôtre.';
-- Quest 5150 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5150, 'frFR', 'Dadanga vous regarde lorsque vous vous approchez d\'elle. Elle semble espérer quelque chose...$B$BElle a probablement faim !$B$BIl doit y avoir quelque chose qui pousse dans le cratère qui serait le snack parfait pour un grand herbivore. Dadanga est une grande fille ; tout ce que vous lui apporterez, il faudrait qu\'il y en ait beaucoup !') ON DUPLICATE KEY UPDATE CompletionText='Dadanga vous regarde lorsque vous vous approchez d\'elle. Elle semble espérer quelque chose...$B$BElle a probablement faim !$B$BIl doit y avoir quelque chose qui pousse dans le cratère qui serait le snack parfait pour un grand herbivore. Dadanga est une grande fille ; tout ce que vous lui apporterez, il faudrait qu\'il y en ait beaucoup !';
-- Quest 5150 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5150, 'frFR', 'En plaçant les pousses devant elle, Dadanga semble satisfaite.$B$BElle vous pousse un petit paquet enveloppé de brun, en échange de la friandise !') ON DUPLICATE KEY UPDATE RewardText='En plaçant les pousses devant elle, Dadanga semble satisfaite.$B$BElle vous pousse un petit paquet enveloppé de brun, en échange de la friandise !';
-- Quest 5155 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5155, 'frFR', 'Comment se passe votre combat, $N ? Je sais que le déversement de sang comme preuve d\'honneur peut être dégoûtant pour certains, mais vous devez comprendre que cela sert deux objectifs : vous facilite ma tâche en diminuant leurs effectifs, et nous gagnons un respect mutuel qui ne fera que nous renforcer à l\'avenir.$B$BJ\'espère que vous comprenez.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe votre combat, $N ? Je sais que le déversement de sang comme preuve d\'honneur peut être dégoûtant pour certains, mais vous devez comprendre que cela sert deux objectifs : vous facilite ma tâche en diminuant leurs effectifs, et nous gagnons un respect mutuel qui ne fera que nous renforcer à l\'avenir.$B$BJ\'espère que vous comprenez.';
-- Quest 5155 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5155, 'frFR', 'Bien, $N ! Avec leur nombre qui diminue, nous pouvons les presser davantage.$b$bComment avez-vous goûté leur puissance pour la première fois ? Étaient-ils aussi forts que vous le pensiez ? Plus forts ? Ou peut-être n\'ont-ils représenté aucun défi pour vous. Ne serait-ce pas quelque chose?$b$bNous pourrons discuter des détails de vos exploits plus tard. Il y a d\'autres choses sur lesquelles nous devons nous concentrer maintenant.') ON DUPLICATE KEY UPDATE RewardText='Bien, $N ! Avec leur nombre qui diminue, nous pouvons les presser davantage.$b$bComment avez-vous goûté leur puissance pour la première fois ? Étaient-ils aussi forts que vous le pensiez ? Plus forts ? Ou peut-être n\'ont-ils représenté aucun défi pour vous. Ne serait-ce pas quelque chose?$b$bNous pourrons discuter des détails de vos exploits plus tard. Il y a d\'autres choses sur lesquelles nous devons nous concentrer maintenant.';
-- Quest 5156 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5156, 'frFR', 'J\'espère que votre recherche se déroulera bien, $N. Je n\'ai pas commencé à me diriger si loin au nord, mais je dois admettre que l\'idée de croiser le chemin d\'un infernal à tout moment me fait un peu peur. Les créatures sont sans cerveau, mais tout de même assez intimidantes.') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que votre recherche se déroulera bien, $N. Je n\'ai pas commencé à me diriger si loin au nord, mais je dois admettre que l\'idée de croiser le chemin d\'un infernal à tout moment me fait un peu peur. Les créatures sont sans cerveau, mais tout de même assez intimidantes.';
-- Quest 5160 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5160, 'frFR', 'Les Aspects insistent pour que nous restions hors des affaires des mortels. Dans ce monde, cependant, une telle chose n\'est pas toujours possible - surtout lorsqu\'un de nos propres dénigre ces édits.') ON DUPLICATE KEY UPDATE RewardText='Les Aspects insistent pour que nous restions hors des affaires des mortels. Dans ce monde, cependant, une telle chose n\'est pas toujours possible - surtout lorsqu\'un de nos propres dénigre ces édits.';
-- Quest 5162 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5162, 'frFR', 'Je suis Jeziba, connue de beaucoup comme la Sculptrice. Ce que je sculpte, cependant, ne sont pas des statues, mais des héros.') ON DUPLICATE KEY UPDATE RewardText='Je suis Jeziba, connue de beaucoup comme la Sculptrice. Ce que je sculpte, cependant, ne sont pas des statues, mais des héros.';
-- Quest 5164 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5164, 'frFR', 'Des centaines de pages remplies de texte et de symboles confus constituent l\'essentiel de ce livre.') ON DUPLICATE KEY UPDATE RewardText='Des centaines de pages remplies de texte et de symboles confus constituent l\'essentiel de ce livre.';
-- Quest 5165 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5165, 'frFR', 'Les braseros doivent être éteints si nous voulons espérer être préparés pour une bataille bien plus grande. Entrer dans la tanière du dragon sans aucune connaissance est une folie. Et c\'est bien pire qu\'un dragon. Le Conseil des Ombres est uniquement responsable d\'un grand nombre de crimes et d\'atrocités. Nous devrons agir rapidement si nous voulons les arrêter.') ON DUPLICATE KEY UPDATE CompletionText='Les braseros doivent être éteints si nous voulons espérer être préparés pour une bataille bien plus grande. Entrer dans la tanière du dragon sans aucune connaissance est une folie. Et c\'est bien pire qu\'un dragon. Le Conseil des Ombres est uniquement responsable d\'un grand nombre de crimes et d\'atrocités. Nous devrons agir rapidement si nous voulons les arrêter.';

-- Quest 5166 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5166, 'frFR', 'Tu ne comprends pas encore ? Le voyage était la destination. Ne peux-tu pas sentir les cicatrices de bataille ? La douleur que tu as endurée ? $B$BAprès avoir survécu à l\'épreuve, tu es un être plus puissant. Beaucoup plus puissant. Cette cuirasse n\'est qu\'un reflet de tes capacités innées.') ON DUPLICATE KEY UPDATE RewardText='Tu ne comprends pas encore ? Le voyage était la destination. Ne peux-tu pas sentir les cicatrices de bataille ? La douleur que tu as endurée ? $B$BAprès avoir survécu à l\'épreuve, tu es un être plus puissant. Beaucoup plus puissant. Cette cuirasse n\'est qu\'un reflet de tes capacités innées.';
-- Quest 5167 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5167, 'frFR', 'Un tel objet n\'a jamais été fabriqué !') ON DUPLICATE KEY UPDATE CompletionText='Un tel objet n\'a jamais été fabriqué !';
-- Quest 5167 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5167, 'frFR', 'Ils sentiront leurs semblables lorsque tu entreras dans leurs salles, <name>. Écrase-les avec leur propre peur !') ON DUPLICATE KEY UPDATE RewardText='Ils sentiront leurs semblables lorsque tu entreras dans leurs salles, <name>. Écrase-les avec leur propre peur !';
-- Quest 5168 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5168, 'frFR', 'Tu as le libram et le bouclier ! $B$BLeur histoire est entrelacée avec l\'histoire de Darrowshire, et d\'une manière ou d\'une autre, je sais que le destin les réunira à nouveau.') ON DUPLICATE KEY UPDATE RewardText='Tu as le libram et le bouclier ! $B$BLeur histoire est entrelacée avec l\'histoire de Darrowshire, et d\'une manière ou d\'une autre, je sais que le destin les réunira à nouveau.';
-- Quest 5181 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5181, 'frFR', 'As-tu trouvé le crâne et l\'épée, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé le crâne et l\'épée, $N?';
-- Quest 5181 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5181, 'frFR', 'Tu les as trouvés ! Bien fait, $N! Ces reliques détiennent un pouvoir que je ne comprends pas entièrement, un pouvoir que tu exploiteras un jour.$B$BElles apportent également des souvenirs sombres à mon esprit, des souvenirs de mort et de trahison, et de la dernière nuit de Darrowshire...') ON DUPLICATE KEY UPDATE RewardText='Tu les as trouvés ! Bien fait, $N! Ces reliques détiennent un pouvoir que je ne comprends pas entièrement, un pouvoir que tu exploiteras un jour.$B$BElles apportent également des souvenirs sombres à mon esprit, des souvenirs de mort et de trahison, et de la dernière nuit de Darrowshire...';
-- Quest 5201 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5201, 'frFR', 'Les furbolgs semblent souffrir d\'une telle paranoïa...') ON DUPLICATE KEY UPDATE CompletionText='Les furbolgs semblent souffrir d\'une telle paranoïa...';
-- Quest 5203 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5203, 'frFR', 'Tu as l\'air essoufflé, $n. Est-ce que ça va, ou quelque chose ne va pas ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as l\'air essoufflé, $n. Est-ce que ça va, ou quelque chose ne va pas ?';
-- Quest 5204 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5204, 'frFR', 'Tu inspectes le corps, et il n\'y a aucun doute qu\'il s\'agit des restes du Chevalier de la Main d\'Argent, Trey Lightforge. Pendant un moment, tu penses à Arko\'narin et te demandes si quelqu\'un dans ta vie compte autant pour toi que cet homme comptait pour la elfe de la nuit que tu as récemment aidé à échapper à Shadow Hold.$B$BAprès avoir pris un autre moment pour rassembler tes pensées, tu sais que tu ne peux pas ramener les restes du paladin à Jessir sans d\'abord tuer son bourreau.') ON DUPLICATE KEY UPDATE CompletionText='Tu inspectes le corps, et il n\'y a aucun doute qu\'il s\'agit des restes du Chevalier de la Main d\'Argent, Trey Lightforge. Pendant un moment, tu penses à Arko\'narin et te demandes si quelqu\'un dans ta vie compte autant pour toi que cet homme comptait pour la elfe de la nuit que tu as récemment aidé à échapper à Shadow Hold.$B$BAprès avoir pris un autre moment pour rassembler tes pensées, tu sais que tu ne peux pas ramener les restes du paladin à Jessir sans d\'abord tuer son bourreau.';
-- Quest 5211 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5211, 'frFR', 'Les pauvres défenseurs de Darrowshire crient vers moi dans mes rêves, $N. Tu dois les libérer !') ON DUPLICATE KEY UPDATE CompletionText='Les pauvres défenseurs de Darrowshire crient vers moi dans mes rêves, $N. Tu dois les libérer !';
-- Quest 5214 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5214, 'frFR', 'Je ne peux pas le faire, $N! Tu dois m\'aider ! Je meurs !') ON DUPLICATE KEY UPDATE CompletionText='Je ne peux pas le faire, $N! Tu dois m\'aider ! Je meurs !';
-- Quest 5218 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5218, 'frFR', 'Le chaudron de la peste du Scourge se dresse devant toi, crachant d\'énormes quantités de toxines dans l\'air. Un petit panneau d\'accès sans particularité se trouve à la base de la vaste plateforme du chaudron.$B$BAyant déjà vaincu le maître du chaudron et acquis sa clé, tu es libre d\'ajouter les réactifs appropriés au chaudron pour créer un contre-agent à la peste.') ON DUPLICATE KEY UPDATE CompletionText='Le chaudron de la peste du Scourge se dresse devant toi, crachant d\'énormes quantités de toxines dans l\'air. Un petit panneau d\'accès sans particularité se trouve à la base de la vaste plateforme du chaudron.$B$BAyant déjà vaincu le maître du chaudron et acquis sa clé, tu es libre d\'ajouter les réactifs appropriés au chaudron pour créer un contre-agent à la peste.';
-- Quest 5218 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5218, 'frFR', 'L\'ajout des réactifs au mélange du chaudron commence à changer la couleur et la texture du nuage qu\'il crache. Les Scourge qui sont même vaguement proches du chaudron semblent reculer à l\'introduction des nouveaux composants dans l\'environnement.') ON DUPLICATE KEY UPDATE RewardText='L\'ajout des réactifs au mélange du chaudron commence à changer la couleur et la texture du nuage qu\'il crache. Les Scourge qui sont même vaguement proches du chaudron semblent reculer à l\'introduction des nouveaux composants dans l\'environnement.';
-- Quest 5220 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5220, 'frFR', 'Nous savons que chaque chaudron utilise un mélange différent de réactifs pour générer son toxine induisant la peste ; de même, nous savons que nous devrons développer un contre-agent qui est unique pour chaque chaudron. Ton échantillon des Larmes de Dalson sera la clé pour découvrir l\'exigence de réactif distincte de ce chaudron.') ON DUPLICATE KEY UPDATE CompletionText='Nous savons que chaque chaudron utilise un mélange différent de réactifs pour générer son toxine induisant la peste ; de même, nous savons que nous devrons développer un contre-agent qui est unique pour chaque chaudron. Ton échantillon des Larmes de Dalson sera la clé pour découvrir l\'exigence de réactif distincte de ce chaudron.';
-- Quest 5220 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5220, 'frFR', 'Ah, il y a beaucoup de choses ici pour étudier. Bien fait, <name>!$B$BPour l\'instant, l\'étape suivante est entre nos mains. Nous devrons produire une liste de réactifs qui, combinés à ce qui est déjà dans le chaudron, agiront comme son contre.$B$BLa seule façon dont nous pourrons introduire cela est en plaçant les réactifs directement dans le chaudron. L\'alchimiste Arbington disposera de plus d\'informations à ce sujet, alors assure-toi de lui parler dès que possible.') ON DUPLICATE KEY UPDATE RewardText='Ah, il y a beaucoup de choses ici pour étudier. Bien fait, <name>!$B$BPour l\'instant, l\'étape suivante est entre nos mains. Nous devrons produire une liste de réactifs qui, combinés à ce qui est déjà dans le chaudron, agiront comme son contre.$B$BLa seule façon dont nous pourrons introduire cela est en plaçant les réactifs directement dans le chaudron. L\'alchimiste Arbington disposera de plus d\'informations à ce sujet, alors assure-toi de lui parler dès que possible.';

-- Quest 5221 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5221, 'frFR', 'Le chaudron de la peste de la Horde se dresse devant vous, crachant d\'énormes quantités de toxines dans l\'air. Un petit panneau d\'accès sans particularité se trouve à la base de la vaste plateforme du chaudron.$B$BAprès avoir vaincu le seigneur du chaudron et acquis sa clé, vous êtes libre d\'ajouter les réactifs appropriés au chaudron pour créer un contre-agent à la peste.') ON DUPLICATE KEY UPDATE CompletionText='Le chaudron de la peste de la Horde se dresse devant vous, crachant d\'énormes quantités de toxines dans l\'air. Un petit panneau d\'accès sans particularité se trouve à la base de la vaste plateforme du chaudron.$B$BAprès avoir vaincu le seigneur du chaudron et acquis sa clé, vous êtes libre d\'ajouter les réactifs appropriés au chaudron pour créer un contre-agent à la peste.';
-- Quest 5221 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5221, 'frFR', 'L\'ajout des réactifs au mélange du chaudron commence à changer la couleur et la texture du nuage qu\'il crache. Les membres de la Horde qui sont même à proximité du chaudron semblent reculer à l\'introduction des nouveaux composants dans l\'environnement.') ON DUPLICATE KEY UPDATE RewardText='L\'ajout des réactifs au mélange du chaudron commence à changer la couleur et la texture du nuage qu\'il crache. Les membres de la Horde qui sont même à proximité du chaudron semblent reculer à l\'introduction des nouveaux composants dans l\'environnement.';
-- Quest 5223 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5223, 'frFR', 'Une fois que nous aurons analysé l\'échantillon tiré du chaudron de la Demeure Frémissante, cela nous fournira une troisième voie pour délivrer un contre-agent dévastateur contre la Horde !') ON DUPLICATE KEY UPDATE CompletionText='Une fois que nous aurons analysé l\'échantillon tiré du chaudron de la Demeure Frémissante, cela nous fournira une troisième voie pour délivrer un contre-agent dévastateur contre la Horde !';
-- Quest 5223 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5223, 'frFR', 'Une autre mission parfaitement exécutée, <name>!  Cela nous donne trois chaudrons à utiliser contre la Horde.  Si la domination nécromantique de Kel\'Thuzad sur ces terres n\'était pas aussi forte qu\'elle l\'est actuellement, j\'oserais dire que vous les auriez mis hors service complètement !$B$BL\'apothicaire Arbington fera un rapport sur ce dont ce chaudron - ainsi que les autres chaudrons subvertis - aura besoin pour livrer notre contre-agent à la peste.  Avec cela, il est temps d\'intégrer le dernier chaudron de l\'ouest sous notre influence !') ON DUPLICATE KEY UPDATE RewardText='Une autre mission parfaitement exécutée, <name>!  Cela nous donne trois chaudrons à utiliser contre la Horde.  Si la domination nécromantique de Kel\'Thuzad sur ces terres n\'était pas aussi forte qu\'elle l\'est actuellement, j\'oserais dire que vous les auriez mis hors service complètement !$B$BL\'apothicaire Arbington fera un rapport sur ce dont ce chaudron - ainsi que les autres chaudrons subvertis - aura besoin pour livrer notre contre-agent à la peste.  Avec cela, il est temps d\'intégrer le dernier chaudron de l\'ouest sous notre influence !';
-- Quest 5224 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5224, 'frFR', 'Le chaudron de la peste de la Horde se dresse devant vous, crachant d\'énormes quantités de toxines dans l\'air. Un petit panneau d\'accès sans particularité se trouve à la base de la vaste plateforme du chaudron.$B$BAprès avoir vaincu le seigneur du chaudron et acquis sa clé, vous êtes libre d\'ajouter les réactifs appropriés au chaudron pour créer un contre-agent à la peste.') ON DUPLICATE KEY UPDATE CompletionText='Le chaudron de la peste de la Horde se dresse devant vous, crachant d\'énormes quantités de toxines dans l\'air. Un petit panneau d\'accès sans particularité se trouve à la base de la vaste plateforme du chaudron.$B$BAprès avoir vaincu le seigneur du chaudron et acquis sa clé, vous êtes libre d\'ajouter les réactifs appropriés au chaudron pour créer un contre-agent à la peste.';
-- Quest 5224 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5224, 'frFR', 'L\'ajout des réactifs au mélange du chaudron commence à changer la couleur et la texture du nuage qu\'il crache. Les membres de la Horde qui sont même à proximité du chaudron semblent reculer à l\'introduction des nouveaux composants dans l\'environnement.') ON DUPLICATE KEY UPDATE RewardText='L\'ajout des réactifs au mélange du chaudron commence à changer la couleur et la texture du nuage qu\'il crache. Les membres de la Horde qui sont même à proximité du chaudron semblent reculer à l\'introduction des nouveaux composants dans l\'environnement.';
-- Quest 5227 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5227, 'frFR', 'Le chaudron de la peste de la Horde se dresse devant vous, crachant d\'énormes quantités de toxines dans l\'air. Un petit panneau d\'accès sans particularité se trouve à la base de la vaste plateforme du chaudron.$B$BAprès avoir vaincu le seigneur du chaudron et acquis sa clé, vous êtes libre d\'ajouter les réactifs appropriés au chaudron pour créer un contre-agent à la peste.') ON DUPLICATE KEY UPDATE CompletionText='Le chaudron de la peste de la Horde se dresse devant vous, crachant d\'énormes quantités de toxines dans l\'air. Un petit panneau d\'accès sans particularité se trouve à la base de la vaste plateforme du chaudron.$B$BAprès avoir vaincu le seigneur du chaudron et acquis sa clé, vous êtes libre d\'ajouter les réactifs appropriés au chaudron pour créer un contre-agent à la peste.';
-- Quest 5227 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5227, 'frFR', 'L\'ajout des réactifs au mélange du chaudron commence à changer la couleur et la texture du nuage qu\'il crache. Les membres de la Horde qui sont même à proximité du chaudron semblent reculer à l\'introduction des nouveaux composants dans l\'environnement.') ON DUPLICATE KEY UPDATE RewardText='L\'ajout des réactifs au mélange du chaudron commence à changer la couleur et la texture du nuage qu\'il crache. Les membres de la Horde qui sont même à proximité du chaudron semblent reculer à l\'introduction des nouveaux composants dans l\'environnement.';
-- Quest 5232 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5232, 'frFR', 'Nous savons que chaque chaudron utilise un mélange différent de réactifs pour générer sa toxine induisant la peste ; de même, nous savons que nous devrons développer un contre-agent unique pour chaque chaudron. Votre échantillon des Larmes de Dalson sera la clé pour déterminer l\'exigence de réactif distincte de ce chaudron.') ON DUPLICATE KEY UPDATE CompletionText='Nous savons que chaque chaudron utilise un mélange différent de réactifs pour générer sa toxine induisant la peste ; de même, nous savons que nous devrons développer un contre-agent unique pour chaque chaudron. Votre échantillon des Larmes de Dalson sera la clé pour déterminer l\'exigence de réactif distincte de ce chaudron.';
-- Quest 5232 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5232, 'frFR', 'Ah, il y a beaucoup de choses ici pour étudier.  Bien joué, <name>!$B$BPour l\'instant, l\'étape suivante est entre nos mains.  Nous devrons produire une liste de réactifs qui, combinés à ce qui est déjà dans le chaudron, agiront comme son contre. $B$BLa seule façon dont nous pourrons introduire cela est d\'ajouter les réactifs directement dans le chaudron.  L\'apothicaire Dithers aura plus d\'informations à ce sujet, alors assurez-vous de lui parler dès que possible.') ON DUPLICATE KEY UPDATE RewardText='Ah, il y a beaucoup de choses ici pour étudier.  Bien joué, <name>!$B$BPour l\'instant, l\'étape suivante est entre nos mains.  Nous devrons produire une liste de réactifs qui, combinés à ce qui est déjà dans le chaudron, agiront comme son contre. $B$BLa seule façon dont nous pourrons introduire cela est d\'ajouter les réactifs directement dans le chaudron.  L\'apothicaire Dithers aura plus d\'informations à ce sujet, alors assurez-vous de lui parler dès que possible.';
-- Quest 5234 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5234, 'frFR', 'Une fois que nous aurons analysé l\'échantillon tiré du chaudron de la Demeure Frémissante, cela nous fournira une troisième voie pour délivrer un contre-agent dévastateur contre la Horde !') ON DUPLICATE KEY UPDATE CompletionText='Une fois que nous aurons analysé l\'échantillon tiré du chaudron de la Demeure Frémissante, cela nous fournira une troisième voie pour délivrer un contre-agent dévastateur contre la Horde !';
-- Quest 5234 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5234, 'frFR', 'Une autre mission parfaitement exécutée, <name>!  Cela nous donne trois chaudrons à utiliser contre la Horde.  Si la domination nécromantique de Kel\'Thuzad sur ces terres n\'était pas aussi forte qu\'elle l\'est actuellement, j\'oserais dire que vous les auriez mis hors service complètement !$B$BL\'apothicaire Dithers fera un rapport sur ce dont ce chaudron - ainsi que les autres chaudrons subvertis - aura besoin pour livrer notre contre-agent à la peste.  Avec cela, il est temps d\'intégrer le dernier chaudron de l\'ouest sous notre influence !') ON DUPLICATE KEY UPDATE RewardText='Une autre mission parfaitement exécutée, <name>!  Cela nous donne trois chaudrons à utiliser contre la Horde.  Si la domination nécromantique de Kel\'Thuzad sur ces terres n\'était pas aussi forte qu\'elle l\'est actuellement, j\'oserais dire que vous les auriez mis hors service complètement !$B$BL\'apothicaire Dithers fera un rapport sur ce dont ce chaudron - ainsi que les autres chaudrons subvertis - aura besoin pour livrer notre contre-agent à la peste.  Avec cela, il est temps d\'intégrer le dernier chaudron de l\'ouest sous notre influence !';
-- Quest 5237 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5237, 'frFR', '$Gname>, votre réingénierie réussie des chaudrons est une victoire immense pour nous !$B$B$B<br :>Que tous ceux en ma présence entendent : pour le service au Royaume de Stormwind et à l\'Alliance au-delà de l\'appel du devoir - face à des adversités écrasantes et un danger incroyable, je peux ajouter - je donne <name this, et je lui témoigne notre gratitude éternelle en tant que véritable héros de l\'Alliance.  Santé, je dis !') ON DUPLICATE KEY UPDATE RewardText='$Gname>, votre réingénierie réussie des chaudrons est une victoire immense pour nous !$B$B$B<br :>Que tous ceux en ma présence entendent : pour le service au Royaume de Stormwind et à l\'Alliance au-delà de l\'appel du devoir - face à des adversités écrasantes et un danger incroyable, je peux ajouter - je donne <name this, et je lui témoigne notre gratitude éternelle en tant que véritable héros de l\'Alliance.  Santé, je dis !';
-- Quest 5238 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5238, 'frFR', '$Gname>, votre réingénierie réussie des chaudrons est une victoire immense pour nous !$B$B$B<br :>Que tous ceux en ma présence entendent : pour le service aux Désespérés et à la Horde en tant que tout, au-delà de ce qui était attendu - face à des adversités écrasantes et un danger incroyable, je peux ajouter - je donne <name this, et je lui témoigne notre gratitude éternelle en tant que véritable héros de la Horde.  Hurra !') ON DUPLICATE KEY UPDATE RewardText='$Gname>, votre réingénierie réussie des chaudrons est une victoire immense pour nous !$B$B$B<br :>Que tous ceux en ma présence entendent : pour le service aux Désespérés et à la Horde en tant que tout, au-delà de ce qui était attendu - face à des adversités écrasantes et un danger incroyable, je peux ajouter - je donne <name this, et je lui témoigne notre gratitude éternelle en tant que véritable héros de la Horde.  Hurra !';
-- Quest 5242 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5242, 'frFR', 'Sans Fel\'dan, le Conseil des Ombres perdra espérons-le son focus et commencera des luttes intestines. Ils lutteront les uns contre les autres pour le contrôle et accumuleront des ressources pour des plans futurs. Ce sera un moment opportun pour les dévaster eux et leurs esclaves démons.') ON DUPLICATE KEY UPDATE CompletionText='Sans Fel\'dan, le Conseil des Ombres perdra espérons-le son focus et commencera des luttes intestines. Ils lutteront les uns contre les autres pour le contrôle et accumuleront des ressources pour des plans futurs. Ce sera un moment opportun pour les dévaster eux et leurs esclaves démons.';

-- Quest 5242 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5242, 'frFR', 'La Mère Terre soit louée, $N! Merci! C\'est un grand jour, en vérité!$b$bLe Conseil des Ombres sera mis à rude épreuve pour atteindre les mêmes niveaux de puissance qu\'ils avaient autrefois avec ce coup porté à leur hiérarchie. Vous avez fait une grande chose ce jour-là!') ON DUPLICATE KEY UPDATE RewardText='La Mère Terre soit louée, $N! Merci! C\'est un grand jour, en vérité!$b$bLe Conseil des Ombres sera mis à rude épreuve pour atteindre les mêmes niveaux de puissance qu\'ils avaient autrefois avec ce coup porté à leur hiérarchie. Vous avez fait une grande chose ce jour-là!';
-- Quest 5246 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5246, 'frFR', 'Ce n\'est que dans les pages des écritures sacrées que je pourrai discerner si je peux vous aider...') ON DUPLICATE KEY UPDATE CompletionText='Ce n\'est que dans les pages des écritures sacrées que je pourrai discerner si je peux vous aider...';
-- Quest 5246 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5246, 'frFR', 'Les pages sont restées intactes depuis de très longues années...') ON DUPLICATE KEY UPDATE RewardText='Les pages sont restées intactes depuis de très longues années...';
-- Quest 5247 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5247, 'frFR', 'La relique doit être placée entre les mains de ceux qui sont les plus dignes de confiance. Elle ne peut plus être volée...') ON DUPLICATE KEY UPDATE CompletionText='La relique doit être placée entre les mains de ceux qui sont les plus dignes de confiance. Elle ne peut plus être volée...';
-- Quest 5247 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5247, 'frFR', 'En utilisant ces éléments, je peux fusionner les fragments ensemble... pour espérer ce qu\'ils étaient autrefois.') ON DUPLICATE KEY UPDATE RewardText='En utilisant ces éléments, je peux fusionner les fragments ensemble... pour espérer ce qu\'ils étaient autrefois.';
-- Quest 5251 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5251, 'frFR', 'Souviens-toi, $N$ - nous devons être tolérants mais rigides dans nos croyances!') ON DUPLICATE KEY UPDATE CompletionText='Souviens-toi, $N$ - nous devons être tolérants mais rigides dans nos croyances!';
-- Quest 5251 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5251, 'frFR', 'Remarquable, <name>! Des années d\'intelligence, perdues! La Croisade Écarlate sentira certainement ce coup dans les semaines à venir.') ON DUPLICATE KEY UPDATE RewardText='Remarquable, <name>! Des années d\'intelligence, perdues! La Croisade Écarlate sentira certainement ce coup dans les semaines à venir.';
-- Quest 5252 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5252, 'frFR', 'Il y a un moment que tu es parti, $N$. Comment as-tu vécu?') ON DUPLICATE KEY UPDATE CompletionText='Il y a un moment que tu es parti, $N$. Comment as-tu vécu?';
-- Quest 5252 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5252, 'frFR', 'Est-ce... ce que je crois?') ON DUPLICATE KEY UPDATE RewardText='Est-ce... ce que je crois?';
-- Quest 5253 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5253, 'frFR', 'J\'ai entendu parler du Cristal de Zin-Malor; l\'utilisateur du cristal devient capable d\'une incroyable puissance arcanique, mais seulement s\'il est vraiment digne. Je suis impressionné que vous non seulement ayez récupéré le cristal, mais que vous ayez aussi réalisé vos propres limites, et ne pas avoir tenté d\'utiliser le cristal vous-même.$B$BMerci de me l\'avoir apporté, $N$. Nous le garderons en sécurité, et que les esprits maudits qui gardaient autrefois le cristal brisé soient enfin en paix.') ON DUPLICATE KEY UPDATE RewardText='J\'ai entendu parler du Cristal de Zin-Malor; l\'utilisateur du cristal devient capable d\'une incroyable puissance arcanique, mais seulement s\'il est vraiment digne. Je suis impressionné que vous non seulement ayez récupéré le cristal, mais que vous ayez aussi réalisé vos propres limites, et ne pas avoir tenté d\'utiliser le cristal vous-même.$B$BMerci de me l\'avoir apporté, $N$. Nous le garderons en sécurité, et que les esprits maudits qui gardaient autrefois le cristal brisé soient enfin en paix.';
-- Quest 5262 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5262, 'frFR', 'Qu\'est-ce que cela va signifier pour la Crusade? Serait-il possible qu\'ils aient été sous le contrôle de ce démon? Servant inconsciemment de pions à un plus grand mal?') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que cela va signifier pour la Crusade? Serait-il possible qu\'ils aient été sous le contrôle de ce démon? Servant inconsciemment de pions à un plus grand mal?';
-- Quest 5282 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5282, 'frFR', 'La compassion est ce qui nous sépare des animaux, $N$. Souviens-toi de ça...') ON DUPLICATE KEY UPDATE CompletionText='La compassion est ce qui nous sépare des animaux, $N$. Souviens-toi de ça...';
-- Quest 5282 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5282, 'frFR', '$GEgan essuie une larme de son œil.>$B<br :>As-tu vu ma mère, <name? L\'as-tu libérée?$B$BTu es un exemple éclatant de décence. Pour tes troubles...') ON DUPLICATE KEY UPDATE RewardText='$GEgan essuie une larme de son œil.>$B<br :>As-tu vu ma mère, <name? L\'as-tu libérée?$B$BTu es un exemple éclatant de décence. Pour tes troubles...';
-- Quest 5283 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5283, 'frFR', 'Ah, rien ne vaut un bon bronzage de forge. On peut voir qui a les meilleurs bronzages à leurs tabliers.') ON DUPLICATE KEY UPDATE CompletionText='Ah, rien ne vaut un bon bronzage de forge. On peut voir qui a les meilleurs bronzages à leurs tabliers.';
-- Quest 5283 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5283, 'frFR', 'C\'est ça, $N$. Après ça, il n\'y a plus de retour en arrière. Il n\'est pas trop tard pour devenir un fabricant de jouets, euh, un forgeron d\'armes.$B$BJe crois que tu prendras la bonne décision.') ON DUPLICATE KEY UPDATE RewardText='C\'est ça, $N$. Après ça, il n\'y a plus de retour en arrière. Il n\'est pas trop tard pour devenir un fabricant de jouets, euh, un forgeron d\'armes.$B$BJe crois que tu prendras la bonne décision.';

-- Quest 5284 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5284, 'frFR', 'Il est temps ! J\'ai des clients qui attendent.$B$BDonnez-les ici et faites attention. Vous allez faire le premier pas de votre carrière d\'armurier d\'armes.') ON DUPLICATE KEY UPDATE RewardText='Il est temps ! J\'ai des clients qui attendent.$B$BDonnez-les ici et faites attention. Vous allez faire le premier pas de votre carrière d\'armurier d\'armes.';
-- Quest 5301 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5301, 'frFR', 'Je vais marteler l\'acier jusqu\'à ce que le souffle lui-même m\'ait quitté.') ON DUPLICATE KEY UPDATE CompletionText='Je vais marteler l\'acier jusqu\'à ce que le souffle lui-même m\'ait quitté.';
-- Quest 5301 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5301, 'frFR', 'C\'est l\'étape finale avant que vous ne commenciez votre nouvelle carrière d\'armurier d\'armures, $N. Si vous décidez de renoncer, ce serait votre dernière chance. Sinon, préparez-vous à une vie de gloire.') ON DUPLICATE KEY UPDATE RewardText='C\'est l\'étape finale avant que vous ne commenciez votre nouvelle carrière d\'armurier d\'armures, $N. Si vous décidez de renoncer, ce serait votre dernière chance. Sinon, préparez-vous à une vie de gloire.';
-- Quest 5302 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5302, 'frFR', 'C\'est l\'étape finale avant que vous ne commenciez votre nouvelle carrière d\'armurier d\'armes, $N. Si vous décidez de renoncer, ce serait votre dernière chance. Sinon, préparez-vous à être consumé par la connaissance !') ON DUPLICATE KEY UPDATE RewardText='C\'est l\'étape finale avant que vous ne commenciez votre nouvelle carrière d\'armurier d\'armes, $N. Si vous décidez de renoncer, ce serait votre dernière chance. Sinon, préparez-vous à être consumé par la connaissance !';
-- Quest 5305 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5305, 'frFR', 'Que vous fracassiez beaucoup de crânes, <name> !') ON DUPLICATE KEY UPDATE RewardText='Que vous fracassiez beaucoup de crânes, <name> !';
-- Quest 5306 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5306, 'frFR', 'La légende raconte qu\'une seule utilisation de la pierre de serpent de Vosh\'gajin gardera une hache affûtée pendant 1000 ans !') ON DUPLICATE KEY UPDATE CompletionText='La légende raconte qu\'une seule utilisation de la pierre de serpent de Vosh\'gajin gardera une hache affûtée pendant 1000 ans !';
-- Quest 5307 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5307, 'frFR', 'Avez-vous oublié ce pour quoi vous avez été chargé, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous oublié ce pour quoi vous avez été chargé, $N ?';
-- Quest 5307 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5307, 'frFR', 'Il devrait être évident qu\'une épée est toujours le meilleur choix.') ON DUPLICATE KEY UPDATE RewardText='Il devrait être évident qu\'une épée est toujours le meilleur choix.';
-- Quest 5361 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5361, 'frFR', 'Quelle nouvelle avez-vous, $C ! Ah - un message de mon frère, dites-vous ? Eh bien, donnez-moi le rapport !') ON DUPLICATE KEY UPDATE CompletionText='Quelle nouvelle avez-vous, $C ! Ah - un message de mon frère, dites-vous ? Eh bien, donnez-moi le rapport !';
-- Quest 5361 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5361, 'frFR', 'Je ne sais quelle connexion vous avez avec mon frère, mais il semble qu\'il ait confiance en vous, $Gclass>.$B<br :>Je suis Nataka Longhorn et je voudrais vous souhaiter la bienvenue à Ghost Walker Post, nous avons de nombreux besoins pour un <class! Parlez avec les autres, peut-être qu\'il y a besoin de vous ici.') ON DUPLICATE KEY UPDATE RewardText='Je ne sais quelle connexion vous avez avec mon frère, mais il semble qu\'il ait confiance en vous, $Gclass>.$B<br :>Je suis Nataka Longhorn et je voudrais vous souhaiter la bienvenue à Ghost Walker Post, nous avons de nombreux besoins pour un <class! Parlez avec les autres, peut-être qu\'il y a besoin de vous ici.';
-- Quest 5384 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5384, 'frFR', 'Méfiez-vous, Kirtonos est un combattant aguerri.') ON DUPLICATE KEY UPDATE CompletionText='Méfiez-vous, Kirtonos est un combattant aguerri.';
-- Quest 5385 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5385, 'frFR', 'Comment s\'est passée la chose à Jaedenar, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Comment s\'est passée la chose à Jaedenar, $N ?';
-- Quest 5386 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5386, 'frFR', 'Mes sabots picotent et ma bouche commence à suinter quand je pense au poisson Bloodbelly frit... En avez-vous sur vous ?') ON DUPLICATE KEY UPDATE CompletionText='Mes sabots picotent et ma bouche commence à suinter quand je pense au poisson Bloodbelly frit... En avez-vous sur vous ?';
-- Quest 5386 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5386, 'frFR', 'Vous êtes un sauveur, <name> ! Ces poissons Bloodbelly ont l\'air presque bons à manger crus.$B$B$B$BVoici - choisissez l\'un de ces objets comme paiement pour ces poissons.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes un sauveur, <name> ! Ces poissons Bloodbelly ont l\'air presque bons à manger crus.$B$B$B$BVoici - choisissez l\'un de ces objets comme paiement pour ces poissons.';
-- Quest 5401 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5401, 'frFR', 'Tous ceux qui combattent le mal au nom de l\'Aube Argentée doivent porter notre commission. Porter ceci vous donnera le droit de réclamer les récompenses que nos intendants ont à offrir.$B$BTandis que vous êtes sous commission, vous pourrez acquérir des Pierres de Fauche à partir de Scourge abattus ; ce sont des marques d\'insigne qu\'ils possèdent parfois. Procurez-vous ces insignes et apportez-les-moi. Pour chaque ensemble que vous remettez, vous recevrez notre marque d\'héroïsme - le Jeton de Valeur de l\'Aube Argentée.$B$Atteignez votre destin, $c - rejoignez le combat aujourd\'hui !') ON DUPLICATE KEY UPDATE RewardText='Tous ceux qui combattent le mal au nom de l\'Aube Argentée doivent porter notre commission. Porter ceci vous donnera le droit de réclamer les récompenses que nos intendants ont à offrir.$B$BTandis que vous êtes sous commission, vous pourrez acquérir des Pierres de Fauche à partir de Scourge abattus ; ce sont des marques d\'insigne qu\'ils possèdent parfois. Procurez-vous ces insignes et apportez-les-moi. Pour chaque ensemble que vous remettez, vous recevrez notre marque d\'héroïsme - le Jeton de Valeur de l\'Aube Argentée.$B$Atteignez votre destin, $c - rejoignez le combat aujourd\'hui !';

-- Quest 5402 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5402, 'frFR', 'Une Scourgestone de Marionnette est l\'insigne du rang et de la file de la Horde. On les trouve parfois sur les troupes plus faibles de la Horde positionnées dans les Plaguelands, bien que le terme "plus faibles" doive être considéré dans son contexte. La Horde, où qu\'elle soit, ne doit jamais être sous-estimée.$B$BL\'Aube Argent offre actuellement un jeton de valeur en échange de vingt de ces insignes - un échange que je suis heureux de faire, à condition que vous ayez gagné suffisamment de scourgestones !') ON DUPLICATE KEY UPDATE CompletionText='Une Scourgestone de Marionnette est l\'insigne du rang et de la file de la Horde. On les trouve parfois sur les troupes plus faibles de la Horde positionnées dans les Plaguelands, bien que le terme "plus faibles" doive être considéré dans son contexte. La Horde, où qu\'elle soit, ne doit jamais être sous-estimée.$B$BL\'Aube Argent offre actuellement un jeton de valeur en échange de vingt de ces insignes - un échange que je suis heureux de faire, à condition que vous ayez gagné suffisamment de scourgestones !';
-- Quest 5403 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5403, 'frFR', 'Une Scourgestone d\'Invasor est l\'insigne des troupes d\'élite de la Horde. On les trouve parfois sur les troupes plus fortes positionnées dans les Plaguelands. Tuer une telle créature est en effet un défi, mais un défi qui doit être savouré avec une commission pour vaincre le mal.$B$BL\'Aube Argent offre actuellement un jeton de valeur en échange de dix de ces insignes. Apportez-les-moi ici, et je m\'assurerai que vous receviez votre juste récompense.') ON DUPLICATE KEY UPDATE CompletionText='Une Scourgestone d\'Invasor est l\'insigne des troupes d\'élite de la Horde. On les trouve parfois sur les troupes plus fortes positionnées dans les Plaguelands. Tuer une telle créature est en effet un défi, mais un défi qui doit être savouré avec une commission pour vaincre le mal.$B$BL\'Aube Argent offre actuellement un jeton de valeur en échange de dix de ces insignes. Apportez-les-moi ici, et je m\'assurerai que vous receviez votre juste récompense.';
-- Quest 5403 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5403, 'frFR', 'Félicitations, $N - Je suis heureux de vous décerner un jeton de valeur de l\'Aube Argent !$B$BChaque jeton de valeur remis aux récipiendaires dignes est un signe que la marée se retourne contre la Horde. Avec de plus en plus de héros combattant la Horde sur leurs propres terres, l\'Aube Argent sera assurément à l\'avant-garde lorsque le moment viendra de mener la guerre contre le mal ultime de la Horde. J\'espère que le courage que vous avez montré pour acquérir votre jeton portera également le jour !') ON DUPLICATE KEY UPDATE RewardText='Félicitations, $N - Je suis heureux de vous décerner un jeton de valeur de l\'Aube Argent !$B$BChaque jeton de valeur remis aux récipiendaires dignes est un signe que la marée se retourne contre la Horde. Avec de plus en plus de héros combattant la Horde sur leurs propres terres, l\'Aube Argent sera assurément à l\'avant-garde lorsque le moment viendra de mener la guerre contre le mal ultime de la Horde. J\'espère que le courage que vous avez montré pour acquérir votre jeton portera également le jour !';
-- Quest 5404 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5404, 'frFR', 'Une Scourgestone de Corrupteur est l\'insigne des maîtres de la Horde. Un être puissant qui détient une position d\'autorité sur la Horde en possédera toujours un. Tuer une créature aussi malveillante ferait certainement avancer la cause de l\'Aube Argent, et toutes les bonnes causes !$B$BAu nom de l\'Aube Argent, je vous donnerai un jeton de valeur en échange d\'un seul de ces insignes. Faites preuve de prudence lors de l\'acquisition d\'un, $N - de tels êtres puissants ne doivent pas être pris à la légère.') ON DUPLICATE KEY UPDATE CompletionText='Une Scourgestone de Corrupteur est l\'insigne des maîtres de la Horde. Un être puissant qui détient une position d\'autorité sur la Horde en possédera toujours un. Tuer une créature aussi malveillante ferait certainement avancer la cause de l\'Aube Argent, et toutes les bonnes causes !$B$BAu nom de l\'Aube Argent, je vous donnerai un jeton de valeur en échange d\'un seul de ces insignes. Faites preuve de prudence lors de l\'acquisition d\'un, $N - de tels êtres puissants ne doivent pas être pris à la légère.';
-- Quest 5404 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5404, 'frFR', 'Félicitations, $N - Je suis heureux de vous décerner un jeton de valeur de l\'Aube Argent !\n \nAcquérir un jeton de valeur de cette manière indique que vous êtes un vrai héros dans la cause du bien. Nous valorisons tous les efforts déployés contre la Horde, mais abattre l\'un de leurs dirigeants est de lui infliger une défaite écrasante !\n \nPour l\'Aube, mon $gfrère:sœur;!') ON DUPLICATE KEY UPDATE RewardText='Félicitations, $N - Je suis heureux de vous décerner un jeton de valeur de l\'Aube Argent !\n \nAcquérir un jeton de valeur de cette manière indique que vous êtes un vrai héros dans la cause du bien. Nous valorisons tous les efforts déployés contre la Horde, mais abattre l\'un de leurs dirigeants est de lui infliger une défaite écrasante !\n \nPour l\'Aube, mon $gfrère:sœur;!';
-- Quest 5405 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5405, 'frFR', 'Tous ceux qui combattent le mal au nom de l\'Aube Argent doivent revêtir notre commission. Porter ceci vous donnera le droit de réclamer les récompenses que nos intendants ont à offrir.$B$BTandis que vous êtes sous commission, vous pourrez acquérir des Scourgestones auprès de la Horde tuée ; ce sont des marques d\'insignes qu\'ils possèdent parfois. Procurez-vous ces insignes et apportez-les-moi. Pour chaque ensemble que vous me remettez, vous recevrez notre marque d\'héroïsme - le Jeton de Valeur de l\'Aube Argent.$B$BAccomplissez votre destin, $c rejoignez le combat aujourd\'hui !') ON DUPLICATE KEY UPDATE RewardText='Tous ceux qui combattent le mal au nom de l\'Aube Argent doivent revêtir notre commission. Porter ceci vous donnera le droit de réclamer les récompenses que nos intendants ont à offrir.$B$BTandis que vous êtes sous commission, vous pourrez acquérir des Scourgestones auprès de la Horde tuée ; ce sont des marques d\'insignes qu\'ils possèdent parfois. Procurez-vous ces insignes et apportez-les-moi. Pour chaque ensemble que vous me remettez, vous recevrez notre marque d\'héroïsme - le Jeton de Valeur de l\'Aube Argent.$B$BAccomplissez votre destin, $c rejoignez le combat aujourd\'hui !';
-- Quest 5406 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5406, 'frFR', 'Une Scourgestone de Corrupteur est l\'insigne des maîtres de la Horde. Un être puissant qui détient une position d\'autorité sur la Horde en possédera toujours un. Tuer une créature aussi malveillante ferait certainement avancer la cause de l\'Aube Argent, et toutes les bonnes causes !$B$BAu nom de l\'Aube Argent, je vous donnerai un jeton de valeur en échange d\'un seul de ces insignes. Faites preuve de prudence lors de l\'acquisition d\'un, $N - de tels êtres puissants ne doivent pas être pris à la légère.') ON DUPLICATE KEY UPDATE CompletionText='Une Scourgestone de Corrupteur est l\'insigne des maîtres de la Horde. Un être puissant qui détient une position d\'autorité sur la Horde en possédera toujours un. Tuer une créature aussi malveillante ferait certainement avancer la cause de l\'Aube Argent, et toutes les bonnes causes !$B$BAu nom de l\'Aube Argent, je vous donnerai un jeton de valeur en échange d\'un seul de ces insignes. Faites preuve de prudence lors de l\'acquisition d\'un, $N - de tels êtres puissants ne doivent pas être pris à la légère.';
-- Quest 5407 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5407, 'frFR', 'Une Scourgestone d\'Invasor est l\'insigne des troupes d\'élite de la Horde. On les trouve parfois sur les troupes plus fortes positionnées dans les Plaguelands. Tuer une telle créature est en effet un défi, mais un défi qui doit être savouré avec une commission pour vaincre le mal.$B$BL\'Aube Argent offre actuellement un jeton de valeur en échange de dix de ces insignes. Apportez-les-moi ici, et je m\'assurerai que vous receviez votre juste récompense.') ON DUPLICATE KEY UPDATE CompletionText='Une Scourgestone d\'Invasor est l\'insigne des troupes d\'élite de la Horde. On les trouve parfois sur les troupes plus fortes positionnées dans les Plaguelands. Tuer une telle créature est en effet un défi, mais un défi qui doit être savouré avec une commission pour vaincre le mal.$B$BL\'Aube Argent offre actuellement un jeton de valeur en échange de dix de ces insignes. Apportez-les-moi ici, et je m\'assurerai que vous receviez votre juste récompense.';
-- Quest 5408 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5408, 'frFR', 'Une Scourgestone de Marionnette est l\'insigne du rang et de la file de la Horde. On les trouve parfois sur les troupes plus faibles de la Horde positionnées dans les Plaguelands, bien que le terme "plus faibles" doive être considéré dans son contexte. La Horde, où qu\'elle soit, ne doit jamais être sous-estimée.$B$BL\'Aube Argent offre actuellement un jeton de valeur en échange de vingt de ces insignes - un échange que je suis heureux de faire, à condition que vous ayez gagné suffisamment de scourgestones!') ON DUPLICATE KEY UPDATE CompletionText='Une Scourgestone de Marionnette est l\'insigne du rang et de la file de la Horde. On les trouve parfois sur les troupes plus faibles de la Horde positionnées dans les Plaguelands, bien que le terme "plus faibles" doive être considéré dans son contexte. La Horde, où qu\'elle soit, ne doit jamais être sous-estimée.$B$BL\'Aube Argent offre actuellement un jeton de valeur en échange de vingt de ces insignes - un échange que je suis heureux de faire, à condition que vous ayez gagné suffisamment de scourgestones!';
-- Quest 5408 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5408, 'frFR', 'Félicitations, <name> - Je suis heureux de vous décerner un jeton de valeur de l\'Aube Argent !$B$BLes jetons servent deux objectifs.  Un - ils peuvent être utilisés pour faire progresser votre statut au sein de l\'Aube Argent ; le faire peut vous offrir des options et des récompenses réservées à nos alliés honorés et vénérés.  Deux - ils peuvent être donnés à nos intendants, avec de la monnaie, comme paiement pour certains des articles les plus précieux de l\'Aube.$B$BQuoi que vous décidiez, sachez que vous gagnez votre commission.  Bien joué !') ON DUPLICATE KEY UPDATE RewardText='Félicitations, <name> - Je suis heureux de vous décerner un jeton de valeur de l\'Aube Argent !$B$BLes jetons servent deux objectifs.  Un - ils peuvent être utilisés pour faire progresser votre statut au sein de l\'Aube Argent ; le faire peut vous offrir des options et des récompenses réservées à nos alliés honorés et vénérés.  Deux - ils peuvent être donnés à nos intendants, avec de la monnaie, comme paiement pour certains des articles les plus précieux de l\'Aube.$B$BQuoi que vous décidiez, sachez que vous gagnez votre commission.  Bien joué !';
-- Quest 5421 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5421, 'frFR', 'Je récompenserai quiconque me facilite un peu la vie... J\'aime faire le moins possible, mon !$B$BSous les quais ici dans le Village de Shadowprey, j\'ai beaucoup de pièges à coquillages. Si vous êtes assez gentil pour faire mon travail et me ramener mes coquillages, alors je vous récompenserai avec quelque chose que vous voulez... vous voyez ce que je veux dire, mon ? Pour chaque cinq coquillages que vous m\'apportez, je vous donnerai un beau poisson Bloodbelly !') ON DUPLICATE KEY UPDATE CompletionText='Je récompenserai quiconque me facilite un peu la vie... J\'aime faire le moins possible, mon !$B$BSous les quais ici dans le Village de Shadowprey, j\'ai beaucoup de pièges à coquillages. Si vous êtes assez gentil pour faire mon travail et me ramener mes coquillages, alors je vous récompenserai avec quelque chose que vous voulez... vous voyez ce que je veux dire, mon ? Pour chaque cinq coquillages que vous m\'apportez, je vous donnerai un beau poisson Bloodbelly !';
-- Quest 5461 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5461, 'frFR', 'Un souvenir de mémoire est une trouvaille rare, $N.') ON DUPLICATE KEY UPDATE CompletionText='Un souvenir de mémoire est une trouvaille rare, $N.';
-- Quest 5461 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5461, 'frFR', 'J\'avais douté de l\'existence d\'un tel objet. Cela ouvre certainement une incroyable opportunité - une que nous ne devons pas gaspiller.$B$BPréparez-vous, <name>, car ce que je vais vous demander vous mènera dans les profondeurs de l\'enfer.') ON DUPLICATE KEY UPDATE RewardText='J\'avais douté de l\'existence d\'un tel objet. Cela ouvre certainement une incroyable opportunité - une que nous ne devons pas gaspiller.$B$BPréparez-vous, <name>, car ce que je vais vous demander vous mènera dans les profondeurs de l\'enfer.';
-- Quest 5462 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5462, 'frFR', 'Ne posez pas de questions auxquelles vous ne voulez pas de réponses.') ON DUPLICATE KEY UPDATE CompletionText='Ne posez pas de questions auxquelles vous ne voulez pas de réponses.';
-- Quest 5462 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5462, 'frFR', '<Leonid examine le souvenir.>$B$BVotre dilemme suscite des souvenirs que j\'espérais ne jamais refaire.') ON DUPLICATE KEY UPDATE RewardText='<Leonid examine le souvenir.>$B$BVotre dilemme suscite des souvenirs que j\'espérais ne jamais refaire.';

-- Quest 5463 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5463, 'frFR', 'La zone autour du Don de Menethil est exceptionnellement froide.') ON DUPLICATE KEY UPDATE CompletionText='La zone autour du Don de Menethil est exceptionnellement froide.';
-- Quest 5463 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5463, 'frFR', 'Vous placez le souvenir sur le sol souillé.') ON DUPLICATE KEY UPDATE RewardText='Vous placez le souvenir sur le sol souillé.';
-- Quest 5464 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5464, 'frFR', 'Alors que l\'âme s\'accrochait au souvenir, elle s\'accrochera à la forme physique de Ras Frostwhisper.') ON DUPLICATE KEY UPDATE RewardText='Alors que l\'âme s\'accrochait au souvenir, elle s\'accrochera à la forme physique de Ras Frostwhisper.';
-- Quest 5465 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5465, 'frFR', 'J\'étais certain que vous vous joindriez à moi en tant qu\'autre esprit malheureux.') ON DUPLICATE KEY UPDATE RewardText='J\'étais certain que vous vous joindriez à moi en tant qu\'autre esprit malheureux.';
-- Quest 5466 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5466, 'frFR', 'Vous portez le fardeau de dix mille âmes agitées, $N.') ON DUPLICATE KEY UPDATE CompletionText='Vous portez le fardeau de dix mille âmes agitées, $N.';
-- Quest 5466 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5466, 'frFR', 'Dix mille âmes crient à l\'unisson, <name>! Vous avez porté un coup mortel au Fléau et à leurs maîtres.') ON DUPLICATE KEY UPDATE RewardText='Dix mille âmes crient à l\'unisson, <name>! Vous avez porté un coup mortel au Fléau et à leurs maîtres.';
-- Quest 5502 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5502, 'frFR', 'C\'est un plaisir de vous revoir, $N. Avez-vous rempli les devoirs pour lesquels vous vous êtes porté volontaire pendant la Semaine des Enfants ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est un plaisir de vous revoir, $N. Avez-vous rempli les devoirs pour lesquels vous vous êtes porté volontaire pendant la Semaine des Enfants ?';
-- Quest 5503 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5503, 'frFR', 'Tous ceux qui combattent le mal au nom de l\'Aube Argentée doivent revêtir notre commission. Porter une telle volonté vous donnera le droit de réclamer les récompenses que nos intendants ont à offrir.$B$BSous commission, vous pourrez acquérir des Pierres du Fléau auprès des morts-vivants du Fléau ; ce sont des marques d\'insigne qu\'ils possèdent parfois. Procurez-vous ces insignes et apportez-les-moi. Pour chaque ensemble que vous remettez, vous recevrez notre marque d\'héroïsme - le Jeton de Valeur de l\'Aube Argentée.$B$BAtingez votre destin, $c rejoignez le combat aujourd\'hui!') ON DUPLICATE KEY UPDATE RewardText='Tous ceux qui combattent le mal au nom de l\'Aube Argentée doivent revêtir notre commission. Porter une telle volonté vous donnera le droit de réclamer les récompenses que nos intendants ont à offrir.$B$BSous commission, vous pourrez acquérir des Pierres du Fléau auprès des morts-vivants du Fléau ; ce sont des marques d\'insigne qu\'ils possèdent parfois. Procurez-vous ces insignes et apportez-les-moi. Pour chaque ensemble que vous remettez, vous recevrez notre marque d\'héroïsme - le Jeton de Valeur de l\'Aube Argentée.$B$BAtingez votre destin, $c rejoignez le combat aujourd\'hui!';
-- Quest 5504 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5504, 'frFR', 'Ah, noble $C! Avez-vous apporté les jetons de valeur qui vous ont été demandés ? Une fois que vous me les remettrez, je rendrai nos divers manteaux disponibles à l\'achat.') ON DUPLICATE KEY UPDATE CompletionText='Ah, noble $C! Avez-vous apporté les jetons de valeur qui vous ont été demandés ? Une fois que vous me les remettrez, je rendrai nos divers manteaux disponibles à l\'achat.';
-- Quest 5504 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5504, 'frFR', 'Remarquable - votre tribut à l\'Aube est dûment noté, $N. Avec ceci accompli, je suis ravi de rendre nos manteaux disponibles à l\'achat. Tant que vous maintenez votre statut actuel avec nous, ces manteaux pourront être achetés auprès de tout intendant autorisé de l\'Aube Argentée.$B$BPour l\'Aube, mon frère!') ON DUPLICATE KEY UPDATE RewardText='Remarquable - votre tribut à l\'Aube est dûment noté, $N. Avec ceci accompli, je suis ravi de rendre nos manteaux disponibles à l\'achat. Tant que vous maintenez votre statut actuel avec nous, ces manteaux pourront être achetés auprès de tout intendant autorisé de l\'Aube Argentée.$B$BPour l\'Aube, mon frère!';
-- Quest 5505 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5505, 'frFR', 'Eh bien, voici, $n - la Clé de Squelette complétée. Je suis certain que cette clé vous permettra d\'accéder aux confins de la Scholomance. Il n\'y a qu\'une seule façon d\'en être absolument certain, cependant. Ne perdez pas de temps à l\'essayer, je le dis.') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, voici, $n - la Clé de Squelette complétée. Je suis certain que cette clé vous permettra d\'accéder aux confins de la Scholomance. Il n\'y a qu\'une seule façon d\'en être absolument certain, cependant. Ne perdez pas de temps à l\'essayer, je le dis.';
-- Quest 5505 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5505, 'frFR', 'Bonne chance, héros puissant. Que vos victoires continuent à vous apporter gloire et puissance alors que vous ravagez la Scholomance!') ON DUPLICATE KEY UPDATE RewardText='Bonne chance, héros puissant. Que vos victoires continuent à vous apporter gloire et puissance alors que vous ravagez la Scholomance!';
-- Quest 5507 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5507, 'frFR', 'Remarquable - votre tribut à l\'Aube est dûment noté, <name>.  Avec ceci accompli, je suis ravi de rendre nos manteaux disponibles à l\'achat.  Tant que vous maintenez votre statut actuel avec nous, ces manteaux pourront être achetés auprès de tout intendant autorisé de l\'Aube Argentée.$B$BPour l\'Aube, mon frère!') ON DUPLICATE KEY UPDATE RewardText='Remarquable - votre tribut à l\'Aube est dûment noté, <name>.  Avec ceci accompli, je suis ravi de rendre nos manteaux disponibles à l\'achat.  Tant que vous maintenez votre statut actuel avec nous, ces manteaux pourront être achetés auprès de tout intendant autorisé de l\'Aube Argentée.$B$BPour l\'Aube, mon frère!';
-- Quest 5508 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5508, 'frFR', 'Une Pierre du Fléau d\'un Corrupteur est l\'insigne des maîtres du Fléau. Un être puissant qui détient une position d\'autorité sur le Fléau en possédera toujours une. Tuer une telle créature malveillante ferait certainement progresser la cause de l\'Aube Argentée, et toutes les bonnes causes!$B$BAu nom de l\'Aube Argentée, je vous donnerai un jeton de valeur en échange d\'une seule de ces insignes. Faites preuve de prudence lors de l\'acquisition d\'un tel objet, $N - de tels êtres puissants ne sont pas à prendre à la légère.') ON DUPLICATE KEY UPDATE CompletionText='Une Pierre du Fléau d\'un Corrupteur est l\'insigne des maîtres du Fléau. Un être puissant qui détient une position d\'autorité sur le Fléau en possédera toujours une. Tuer une telle créature malveillante ferait certainement progresser la cause de l\'Aube Argentée, et toutes les bonnes causes!$B$BAu nom de l\'Aube Argentée, je vous donnerai un jeton de valeur en échange d\'une seule de ces insignes. Faites preuve de prudence lors de l\'acquisition d\'un tel objet, $N - de tels êtres puissants ne sont pas à prendre à la légère.';
-- Quest 5509 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5509, 'frFR', 'Une Pierre du Fléau d\'un Invadateur est l\'insigne des troupes d\'élite du Fléau. On les trouve parfois sur les troupes les plus fortes positionnées dans les Terres de la Plague. Tuer une telle créature est en effet un défi, mais un défi qui devrait être apprécié avec une commission pour vaincre le mal.$B$BL\'Aube Argentée offre actuellement un jeton de valeur en échange de dix de ces insignes. Apportez-les-moi ici, et je m\'assurerai que vous receviez votre juste récompense.') ON DUPLICATE KEY UPDATE CompletionText='Une Pierre du Fléau d\'un Invadateur est l\'insigne des troupes d\'élite du Fléau. On les trouve parfois sur les troupes les plus fortes positionnées dans les Terres de la Plague. Tuer une telle créature est en effet un défi, mais un défi qui devrait être apprécié avec une commission pour vaincre le mal.$B$BL\'Aube Argentée offre actuellement un jeton de valeur en échange de dix de ces insignes. Apportez-les-moi ici, et je m\'assurerai que vous receviez votre juste récompense.';

-- Quest 5509 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5509, 'frFR', 'Félicitations, <name> - J\'ai le plaisir de vous décerner un jeton de valeur de l\'Aube Argentée !$B$BChaque jeton de valeur remis aux récipiendaires dignes est un signe que la marée se retourne contre les Squelettes.  Avec de plus en plus de héros combattant les Squelettes sur leurs propres terres, l\'Aube Argentée sera assurément en première ligne lorsque le moment viendra de mener la guerre contre le mal ultime des Squelettes.  J\'espère que la valeur que vous avez montrée pour acquérir votre jeton fera également le jour !') ON DUPLICATE KEY UPDATE RewardText='Félicitations, <name> - J\'ai le plaisir de vous décerner un jeton de valeur de l\'Aube Argentée !$B$BChaque jeton de valeur remis aux récipiendaires dignes est un signe que la marée se retourne contre les Squelettes.  Avec de plus en plus de héros combattant les Squelettes sur leurs propres terres, l\'Aube Argentée sera assurément en première ligne lorsque le moment viendra de mener la guerre contre le mal ultime des Squelettes.  J\'espère que la valeur que vous avez montrée pour acquérir votre jeton fera également le jour !';
-- Quest 5510 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5510, 'frFR', 'Une Pierre de Scourge d\'un Minion est l\'insigne de la classe des Squelettes. On les trouve parfois sur les troupes les plus faibles de leur rang positionnées dans les Terres de la Plague, bien que le terme "plus faibles" doive être considéré dans son contexte. Les Squelettes, où qu\'ils soient, ne doivent jamais être sous-estimés.$B$BL\'Aube Argentée offre actuellement un jeton de valeur en échange de vingt de ces insignes - un échange que je suis heureux de faire, à condition que vous ayez gagné suffisamment de pierres de scourge !') ON DUPLICATE KEY UPDATE CompletionText='Une Pierre de Scourge d\'un Minion est l\'insigne de la classe des Squelettes. On les trouve parfois sur les troupes les plus faibles de leur rang positionnées dans les Terres de la Plague, bien que le terme "plus faibles" doive être considéré dans son contexte. Les Squelettes, où qu\'ils soient, ne doivent jamais être sous-estimés.$B$BL\'Aube Argentée offre actuellement un jeton de valeur en échange de vingt de ces insignes - un échange que je suis heureux de faire, à condition que vous ayez gagné suffisamment de pierres de scourge !';
-- Quest 5510 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5510, 'frFR', 'Félicitations, <name> - J\'ai le plaisir de vous décerner un jeton de valeur de l\'Aube Argentée !$B$BLes jetons servent deux objectifs.  Un - ils peuvent être utilisés pour faire progresser votre statut au sein de l\'Aube Argentée ; le faire peut vous offrir des options et des récompenses réservées à nos alliés honorés et vénérés.  Deux - ils peuvent être donnés à nos intendants, avec de la monnaie, en paiement de certains des articles les plus précieux de l\'Aube.$B$BQuoi que vous décidiez, sachez que vous gagnez votre commission.  Bien joué !') ON DUPLICATE KEY UPDATE RewardText='Félicitations, <name> - J\'ai le plaisir de vous décerner un jeton de valeur de l\'Aube Argentée !$B$BLes jetons servent deux objectifs.  Un - ils peuvent être utilisés pour faire progresser votre statut au sein de l\'Aube Argentée ; le faire peut vous offrir des options et des récompenses réservées à nos alliés honorés et vénérés.  Deux - ils peuvent être donnés à nos intendants, avec de la monnaie, en paiement de certains des articles les plus précieux de l\'Aube.$B$BQuoi que vous décidiez, sachez que vous gagnez votre commission.  Bien joué !';
-- Quest 5511 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5511, 'frFR', 'Eh bien, voici, $n - la Clé squelettique complétée. Je suis certain que cette clé vous permettra d\'accéder aux confins de la Scholomance. Il n\'y a qu\'une seule façon d\'en être absolument certain. Ne perdez pas de temps à l\'essayer, je vous le dis.') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, voici, $n - la Clé squelettique complétée. Je suis certain que cette clé vous permettra d\'accéder aux confins de la Scholomance. Il n\'y a qu\'une seule façon d\'en être absolument certain. Ne perdez pas de temps à l\'essayer, je vous le dis.';
-- Quest 5511 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5511, 'frFR', 'Eh bien, voici, $N - la Clé squelettique complétée. Je suis certain que cette clé vous permettra d\'accéder aux confins de la Scholomance. Il n\'y a qu\'une seule façon d\'en être absolument certain. Ne perdez pas de temps à l\'essayer, je vous le dis.$B$BBonne chance, héros puissant. Que vos victoires continuent à vous apporter gloire et pouvoir alors que vous ravagez la Scholomance !') ON DUPLICATE KEY UPDATE RewardText='Eh bien, voici, $N - la Clé squelettique complétée. Je suis certain que cette clé vous permettra d\'accéder aux confins de la Scholomance. Il n\'y a qu\'une seule façon d\'en être absolument certain. Ne perdez pas de temps à l\'essayer, je vous le dis.$B$BBonne chance, héros puissant. Que vos victoires continuent à vous apporter gloire et pouvoir alors que vous ravagez la Scholomance !';
-- Quest 5513 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5513, 'frFR', 'Ah, noble $C! Avez-vous apporté les jetons de valeur que je vous ai demandés ? Une fois que vous me les remettrez, je vous rendrai nos différents manteaux à l\'achat.') ON DUPLICATE KEY UPDATE CompletionText='Ah, noble $C! Avez-vous apporté les jetons de valeur que je vous ai demandés ? Une fois que vous me les remettrez, je vous rendrai nos différents manteaux à l\'achat.';
-- Quest 5513 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5513, 'frFR', 'Remarquable - votre tribut à l\'Aube est dûment noté, <name>.  Avec ceci accompli, je suis ravi de vous rendre nos manteaux à l\'achat.  Tant que vous maintenez votre statut actuel avec nous, ces manteaux pourront être achetés auprès de tout intendant autorisé de l\'Aube Argentée.$B$BPour l\'Aube, mon frère !') ON DUPLICATE KEY UPDATE RewardText='Remarquable - votre tribut à l\'Aube est dûment noté, <name>.  Avec ceci accompli, je suis ravi de vous rendre nos manteaux à l\'achat.  Tant que vous maintenez votre statut actuel avec nous, ces manteaux pourront être achetés auprès de tout intendant autorisé de l\'Aube Argentée.$B$BPour l\'Aube, mon frère !';
-- Quest 5517 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5517, 'frFR', 'Salutations, puissant $c! Avez-vous apporté les jetons de valeur que j\'ai demandés ? Une fois que vous me les remettrez, je vous délivrerai votre propre Manteau Chromatique de l\'Aube.') ON DUPLICATE KEY UPDATE CompletionText='Salutations, puissant $c! Avez-vous apporté les jetons de valeur que j\'ai demandés ? Une fois que vous me les remettrez, je vous délivrerai votre propre Manteau Chromatique de l\'Aube.';
-- Quest 5517 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5517, 'frFR', 'Très impressionnant, $N - le Manteau Chromatique de l\'Aube est maintenant le vôtre !$B$BTant que vous maintenez un statut d\'Exalté avec l\'Aube Argentée, vous pourrez acheter des Manteaux Chromatiques supplémentaires. Ils vous seront immédiatement disponibles auprès de n\'importe quel intendant de l\'Aube.') ON DUPLICATE KEY UPDATE RewardText='Très impressionnant, $N - le Manteau Chromatique de l\'Aube est maintenant le vôtre !$B$BTant que vous maintenez un statut d\'Exalté avec l\'Aube Argentée, vous pourrez acheter des Manteaux Chromatiques supplémentaires. Ils vous seront immédiatement disponibles auprès de n\'importe quel intendant de l\'Aube.';
-- Quest 5519 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5519, 'frFR', 'Besoin d\'un autre costume, hein ? Eh bien, je ne pars pas de sitôt, il semble - apportez-moi les mêmes choses que je vous ai demandées avant, et je vous ferai un autre costume d\'ogre.') ON DUPLICATE KEY UPDATE CompletionText='Besoin d\'un autre costume, hein ? Eh bien, je ne pars pas de sitôt, il semble - apportez-moi les mêmes choses que je vous ai demandées avant, et je vous ferai un autre costume d\'ogre.';
-- Quest 5519 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5519, 'frFR', 'Voici $N - mettez ce truc, et vous aurez dix minutes pour faire ce que vous voulez. Bonne chance !$B$Oh, et si vous trouvez une clé pour me faire sortir d\'ici, PAR TOUS LES MOYENS, DITES-LE-MOI!!!') ON DUPLICATE KEY UPDATE RewardText='Voici $N - mettez ce truc, et vous aurez dix minutes pour faire ce que vous voulez. Bonne chance !$B$Oh, et si vous trouvez une clé pour me faire sortir d\'ici, PAR TOUS LES MOYENS, DITES-LE-MOI!!!';
-- Quest 5521 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5521, 'frFR', 'Salutations, puissant $C! Avez-vous apporté les jetons de valeur que j\'ai demandés ? Une fois que vous me les remettrez, je vous délivrerai votre propre Manteau Chromatique de l\'Aube.') ON DUPLICATE KEY UPDATE CompletionText='Salutations, puissant $C! Avez-vous apporté les jetons de valeur que j\'ai demandés ? Une fois que vous me les remettrez, je vous délivrerai votre propre Manteau Chromatique de l\'Aube.';
-- Quest 5521 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5521, 'frFR', 'Très impressionnant, $N - le Manteau Chromatique de l\'Aube est maintenant le vôtre !$B$BTant que vous maintenez un statut d\'Exalté avec l\'Aube Argentée, vous pourrez acheter des Manteaux Chromatiques supplémentaires. Ils vous seront immédiatement disponibles auprès de n\'importe quel intendant de l\'Aube.') ON DUPLICATE KEY UPDATE RewardText='Très impressionnant, $N - le Manteau Chromatique de l\'Aube est maintenant le vôtre !$B$BTant que vous maintenez un statut d\'Exalté avec l\'Aube Argentée, vous pourrez acheter des Manteaux Chromatiques supplémentaires. Ils vous seront immédiatement disponibles auprès de n\'importe quel intendant de l\'Aube.';
-- Quest 5522 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5522, 'frFR', 'Vous êtes celui qui sème le trouble à Blackrock Spire, n\'est-ce pas ? Avez-vous ce que j\'ai demandé ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes celui qui sème le trouble à Blackrock Spire, n\'est-ce pas ? Avez-vous ce que j\'ai demandé ?';
-- Quest 5522 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5522, 'frFR', 'Ah, très bien.  Vous ne connaissez pas le pouvoir maléfique pour qui vous avez travaillé, mais maintenant vous connaîtrez la vérité.  Et ne craignez pas -- je ne suis pas le serviteur de ce maître.  Je suis Leonid Barthalomew, connu sous le nom de "le Vénéré" par mes frères de l\'Aube Argentée.$B$J\'ai trompé Tinkee pour qu\'il vous envoie, vous et les œufs de dragon, jusqu\'à moi.  Et il est bon que mon coup soit réussi, car si ces œufs avaient atteint leur destination prévue, un grand pouvoir serait tombé entre les mains de l\'ennemi.') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien.  Vous ne connaissez pas le pouvoir maléfique pour qui vous avez travaillé, mais maintenant vous connaîtrez la vérité.  Et ne craignez pas -- je ne suis pas le serviteur de ce maître.  Je suis Leonid Barthalomew, connu sous le nom de "le Vénéré" par mes frères de l\'Aube Argentée.$B$J\'ai trompé Tinkee pour qu\'il vous envoie, vous et les œufs de dragon, jusqu\'à moi.  Et il est bon que mon coup soit réussi, car si ces œufs avaient atteint leur destination prévue, un grand pouvoir serait tombé entre les mains de l\'ennemi.';

-- Quest 5524 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5524, 'frFR', 'Salutations, mighty $C! Avez-vous apporté les jetons de valeur que j\'ai demandés ? Une fois que vous me les remettrez, je vous délivrerai votre propre Manteau Chromatique de l\'Aube.') ON DUPLICATE KEY UPDATE CompletionText='Salutations, mighty $C! Avez-vous apporté les jetons de valeur que j\'ai demandés ? Une fois que vous me les remettrez, je vous délivrerai votre propre Manteau Chromatique de l\'Aube.';
-- Quest 5524 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5524, 'frFR', 'Impressionnant, $N$ - le Manteau Chromatique de l\'Aube est maintenant le vôtre !$B$BTant que vous maintenez un statut Exalté auprès de l\'Aube Argentée, vous pourrez acheter des Manteaux Chromatiques supplémentaires. Ils vous seront immédiatement disponibles auprès de n\'importe quel intendant de l\'Aube.') ON DUPLICATE KEY UPDATE RewardText='Impressionnant, $N$ - le Manteau Chromatique de l\'Aube est maintenant le vôtre !$B$BTant que vous maintenez un statut Exalté auprès de l\'Aube Argentée, vous pourrez acheter des Manteaux Chromatiques supplémentaires. Ils vous seront immédiatement disponibles auprès de n\'importe quel intendant de l\'Aube.';
-- Quest 5525 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5525, 'frFR', 'Il s\'appelle la Clé de menotte de Gordok - eh bien, c\'est ce que ces "tonnes de fun" appellent. Je pense que n\'importe quel ogre pourrait l\'avoir, mais je ne suis pas sûr si des spécifiquement. Peut-être que les gardes ont plus de chances d\'en avoir...$B$BDe quoi je parle - vous l\'avez déjà, n\'est-ce pas ?! C\'est ça là??!') ON DUPLICATE KEY UPDATE CompletionText='Il s\'appelle la Clé de menotte de Gordok - eh bien, c\'est ce que ces "tonnes de fun" appellent. Je pense que n\'importe quel ogre pourrait l\'avoir, mais je ne suis pas sûr si des spécifiquement. Peut-être que les gardes ont plus de chances d\'en avoir...$B$BDe quoi je parle - vous l\'avez déjà, n\'est-ce pas ?! C\'est ça là??!';
-- Quest 5525 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5525, 'frFR', 'Oh, merci de m\'avoir libéré ! Vous - classé numéro un. Tous les autres - classés numéro deux ou moins.$B$BI savais que ma vie était destinée à plus qu\'être une simple entrée pour un ogre !') ON DUPLICATE KEY UPDATE RewardText='Oh, merci de m\'avoir libéré ! Vous - classé numéro un. Tous les autres - classés numéro deux ou moins.$B$BI savais que ma vie était destinée à plus qu\'être une simple entrée pour un ogre !';
-- Quest 5526 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5526, 'frFR', 'Avec le Reliquaire Scellé de Pureté en notre possession, il sera possible non seulement d\'éliminer une menace corrompante du monde, mais aussi de l\'étudier sous notre surveillance judicieuse. Peut-être pouvons-nous même concevoir de nouveaux moyens de combattre le taint de la corruption qui menace toujours Azeroth.$b$bJe sais que Milli l\'aurait fait de cette façon...') ON DUPLICATE KEY UPDATE CompletionText='Avec le Reliquaire Scellé de Pureté en notre possession, il sera possible non seulement d\'éliminer une menace corrompante du monde, mais aussi de l\'étudier sous notre surveillance judicieuse. Peut-être pouvons-nous même concevoir de nouveaux moyens de combattre le taint de la corruption qui menace toujours Azeroth.$b$bJe sais que Milli l\'aurait fait de cette façon...';
-- Quest 5526 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5526, 'frFR', 'C\'est fait, brave $c$, et avec cela, le Cercle de Cenarion vous doit. Bien que la guerre soit loin d\'être terminée, une grande bataille a été gagnée contre ceux qui souhaiteraient notre perte.$b$bVeuillez - accepter ceci comme un signe de notre gratitude durable. Sachez que vous êtes accueilli ici en tant que héros du Cercle de Cenarion pour votre grande œuvre, $N$. Merci.') ON DUPLICATE KEY UPDATE RewardText='C\'est fait, brave $c$, et avec cela, le Cercle de Cenarion vous doit. Bien que la guerre soit loin d\'être terminée, une grande bataille a été gagnée contre ceux qui souhaiteraient notre perte.$b$bVeuillez - accepter ceci comme un signe de notre gratitude durable. Sachez que vous êtes accueilli ici en tant que héros du Cercle de Cenarion pour votre grande œuvre, $N$. Merci.';
-- Quest 5528 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5528, 'frFR', 'Vous êtes le gros boss maintenant, alors vous obtenez un échantillon gratuit de mes meilleures bières ! Ces boissons vous boostent ET vous donnent un bon buzz ! Ce sont les bonnes, chef... vous essayez de le dire à Kreeg vous-même !') ON DUPLICATE KEY UPDATE RewardText='Vous êtes le gros boss maintenant, alors vous obtenez un échantillon gratuit de mes meilleures bières ! Ces boissons vous boostent ET vous donnent un bon buzz ! Ce sont les bonnes, chef... vous essayez de le dire à Kreeg vous-même !';
-- Quest 5529 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5529, 'frFR', 'Rendez-vous à la Scholomance, $N$. Éliminez ces petits crocs maudits avant qu\'ils ne grandissent !') ON DUPLICATE KEY UPDATE CompletionText='Rendez-vous à la Scholomance, $N$. Éliminez ces petits crocs maudits avant qu\'ils ne grandissent !';
-- Quest 5529 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5529, 'frFR', 'Bien joué, <name>!  Il faudra longtemps avant qu\'ils puissent faire une autre portée de dragons.$B$B... Au moins, j\'espère que oui !') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name>!  Il faudra longtemps avant qu\'ils puissent faire une autre portée de dragons.$B$B... Au moins, j\'espère que oui !';
-- Quest 5531 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5531, 'frFR', 'Bonjour, $N! J\'ai entendu dire que vous étiez ici avec des œufs de dragon ? Eh bien, montrons-les !') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $N! J\'ai entendu dire que vous étiez ici avec des œufs de dragon ? Eh bien, montrons-les !';
-- Quest 5531 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5531, 'frFR', 'Ils sont là ! Et dans un si joli contenant. La taille parfaite !$b$bNous garderons ces œufs en un endroit sûr afin de pouvoir les étudier plus tard, mais pour l\'instant, nous avons besoin de cette chose dans laquelle vous les avez apportés.$b$bJ\'ai créé un appareil avec une utilisation très spécifique : détruire les érudits morts-vivants de la Scholomance. Ils étudient les dragons dans leurs efforts pour créer une volée de dragons maudite, et nous devons arrêter leur progression.$b$bJ\'appelle l\'appareil le Gambit de l\'Aube, parce que... je ne suis pas sûr que ça marche !$b$bAllez-vous le découvrir pour nous ?') ON DUPLICATE KEY UPDATE RewardText='Ils sont là ! Et dans un si joli contenant. La taille parfaite !$b$bNous garderons ces œufs en un endroit sûr afin de pouvoir les étudier plus tard, mais pour l\'instant, nous avons besoin de cette chose dans laquelle vous les avez apportés.$b$bJ\'ai créé un appareil avec une utilisation très spécifique : détruire les érudits morts-vivants de la Scholomance. Ils étudient les dragons dans leurs efforts pour créer une volée de dragons maudite, et nous devons arrêter leur progression.$b$bJ\'appelle l\'appareil le Gambit de l\'Aube, parce que... je ne suis pas sûr que ça marche !$b$bAllez-vous le découvrir pour nous ?';
-- Quest 5534 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5534, 'frFR', 'Eh bien, $N? Où est la rune ? Vous êtes un bon employé, n\'est-ce pas ? Vous êtes là pour aider?$b$bNe me faites pas douter de ce que nous avons convenu de vous payer. Quoi ? Oh, nous n\'avons rien convenu ? Oh, super... alors prenez votre temps--sachez juste que ce sera beaucoup moins si vous prenez beaucoup de temps.') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, $N? Où est la rune ? Vous êtes un bon employé, n\'est-ce pas ? Vous êtes là pour aider?$b$bNe me faites pas douter de ce que nous avons convenu de vous payer. Quoi ? Oh, nous n\'avons rien convenu ? Oh, super... alors prenez votre temps--sachez juste que ce sera beaucoup moins si vous prenez beaucoup de temps.';
-- Quest 5534 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5534, 'frFR', 'Haha ! Merveilleux !$B$BI m\'assurerai de découvrir à quoi cela sert et pourquoi Magus Rimtori--c\'est la vache qui m\'a embauché--l\'a voulu. Ha ! Je vous ai, vous les elfes du Sang pourris ! Kim\'jael ! Ha ! Je leur apprendrai qui sont les rats !$B$Vous avez bien fait, <name>. Merci beaucoup. Tenez, prenez cette pièce et allez-vous-en--j\'ai des choses à régler.') ON DUPLICATE KEY UPDATE RewardText='Haha ! Merveilleux !$B$BI m\'assurerai de découvrir à quoi cela sert et pourquoi Magus Rimtori--c\'est la vache qui m\'a embauché--l\'a voulu. Ha ! Je vous ai, vous les elfes du Sang pourris ! Kim\'jael ! Ha ! Je leur apprendrai qui sont les rats !$B$Vous avez bien fait, <name>. Merci beaucoup. Tenez, prenez cette pièce et allez-vous-en--j\'ai des choses à régler.';
-- Quest 5535 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5535, 'frFR', 'Comment se passe votre recherche des esprits des Hauts-Nés, $c?$B$BDe nombreux événements ont causé à toutes les races d\'Azeroth une grande souffrance, mais pour une raison quelconque, ces esprits semblent être une plaie pour tout le monde. Peut-être est-ce leur désir continu de toute magie arcanique--un tel désir est un signe avant-coureur de la Légion Ardente, et nous savons ce que cela peut entraîner.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe votre recherche des esprits des Hauts-Nés, $c?$B$BDe nombreux événements ont causé à toutes les races d\'Azeroth une grande souffrance, mais pour une raison quelconque, ces esprits semblent être une plaie pour tout le monde. Peut-être est-ce leur désir continu de toute magie arcanique--un tel désir est un signe avant-coureur de la Légion Ardente, et nous savons ce que cela peut entraîner.';
-- Quest 5536 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5536, 'frFR', 'Comment se passe votre bataille contre le satyre, $c?$B$Sont-ils aussi forts que vous le pensiez ? Plus forts ? Ou peut-être n\'étaient-ils rien face à votre puissance.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe votre bataille contre le satyre, $c?$B$Sont-ils aussi forts que vous le pensiez ? Plus forts ? Ou peut-être n\'étaient-ils rien face à votre puissance.';

-- Quest 5537 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5537, 'frFR', 'Aussi morbide que cela puisse paraître, nous aurons besoin d\'un bon approvisionnement en fragments squelettiques appropriés pour former la couche extérieure de la clé. Ils ne l\'appellent pas Clé Squelette pour rien, vous savez.') ON DUPLICATE KEY UPDATE CompletionText='Aussi morbide que cela puisse paraître, nous aurons besoin d\'un bon approvisionnement en fragments squelettiques appropriés pour former la couche extérieure de la clé. Ils ne l\'appellent pas Clé Squelette pour rien, vous savez.';
-- Quest 5537 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5537, 'frFR', 'Ça marchera, $N$!  À mon tour maintenant - je vais les imprégner d\'un tempérament approprié qui leur permettra de survivre au processus de forge intense qu\'ils subiront éventuellement.$B$BL\'étape suivante sera d\'obtenir un moule approprié pour la clé.  Je connais un forgeron gobelin à Tanaris qui a fait par le passé des moules pour des objets tout aussi macabres.  Il travaille pour qui les gobelins travaillent habituellement - le plus offrant.') ON DUPLICATE KEY UPDATE RewardText='Ça marchera, $N$!  À mon tour maintenant - je vais les imprégner d\'un tempérament approprié qui leur permettra de survivre au processus de forge intense qu\'ils subiront éventuellement.$B$BL\'étape suivante sera d\'obtenir un moule approprié pour la clé.  Je connais un forgeron gobelin à Tanaris qui a fait par le passé des moules pour des objets tout aussi macabres.  Il travaille pour qui les gobelins travaillent habituellement - le plus offrant.';
-- Quest 5542 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5542, 'frFR', 'Ne compatissez pas aux chiens démons, $r$. Ce sont des abominations !') ON DUPLICATE KEY UPDATE CompletionText='Ne compatissez pas aux chiens démons, $r$. Ce sont des abominations !';
-- Quest 5543 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5543, 'frFR', 'Ne sous-estimez pas les vermines ailées, $r$. La Plaque les a dotées d\'aptitudes surnaturelles.') ON DUPLICATE KEY UPDATE CompletionText='Ne sous-estimez pas les vermines ailées, $r$. La Plaque les a dotées d\'aptitudes surnaturelles.';
-- Quest 5543 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5543, 'frFR', 'Vous êtes un exemple éclatant de décence, $R$! Il y a longtemps que je n\'ai pas senti le sang des héros pomper dans mes veines. Vos actes de bravoure sont édifiants !') ON DUPLICATE KEY UPDATE RewardText='Vous êtes un exemple éclatant de décence, $R$! Il y a longtemps que je n\'ai pas senti le sang des héros pomper dans mes veines. Vos actes de bravoure sont édifiants !';
-- Quest 5621 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5621, 'frFR', 'Nos sorts de Fortifier sont très puissants, Delor. Ils permettent à nos compagnons de subir des blessures supplémentaires de tous types d\'attaques et de survivre dans des situations où ils tomberaient normalement. Mais ce n\'est rien comparé à notre capacité à guérir. Il n\'y a pas de guérisseurs plus grands qu\'un prêtre--souvenez-vous-en bien. Votre pouvoir seul peut facilement renverser le cours des batailles.') ON DUPLICATE KEY UPDATE CompletionText='Nos sorts de Fortifier sont très puissants, Delor. Ils permettent à nos compagnons de subir des blessures supplémentaires de tous types d\'attaques et de survivre dans des situations où ils tomberaient normalement. Mais ce n\'est rien comparé à notre capacité à guérir. Il n\'y a pas de guérisseurs plus grands qu\'un prêtre--souvenez-vous-en bien. Votre pouvoir seul peut facilement renverser le cours des batailles.';
-- Quest 5621 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5621, 'frFR', 'Vous avez bien fait et vous avez servi Elune. Pour cela, je vous remercie.$B$BPrenez, cette robe en guise de remerciement. Elle signifie que vous avez gagné votre place au sein de notre ordre. Si vous le souhaitez, portez-la avec fierté, mais dans tous les cas, nous vous reconnaîtrons comme l\'un des nôtres.$B$BAllez avec Elune, $N$, et merci.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait et vous avez servi Elune. Pour cela, je vous remercie.$B$BPrenez, cette robe en guise de remerciement. Elle signifie que vous avez gagné votre place au sein de notre ordre. Si vous le souhaitez, portez-la avec fierté, mais dans tous les cas, nous vous reconnaîtrons comme l\'un des nôtres.$B$BAllez avec Elune, $N$, et merci.';
-- Quest 5622 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5622, 'frFR', 'Je suis heureux de voir que Shanda vous a envoyé me trouver, $N$. Enseigner aux jeunes prêtres les voies d\'Elune me procure une grande satisfaction.') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux de voir que Shanda vous a envoyé me trouver, $N$. Enseigner aux jeunes prêtres les voies d\'Elune me procure une grande satisfaction.';
-- Quest 5624 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5624, 'frFR', 'Comme vous l\'avez peut-être déjà appris, nos magies de guérison sont vitales à la survie de notre peuple en ces temps difficiles--surtout pour les aventuriers et les héros qui prennent les armes et la magie pour combattre tant de menaces différentes.$B$BVous feriez bien de toujours vous souvenir de l\'importance de cette compétence. Cela, couplé à la Fortitude, rend vos compagnons beaucoup plus capables au combat puisqu\'ils pourront encaisser un plus grand nombre de coups.$B$BNe laissez personne minimiser la puissance de vos magies.') ON DUPLICATE KEY UPDATE CompletionText='Comme vous l\'avez peut-être déjà appris, nos magies de guérison sont vitales à la survie de notre peuple en ces temps difficiles--surtout pour les aventuriers et les héros qui prennent les armes et la magie pour combattre tant de menaces différentes.$B$BVous feriez bien de toujours vous souvenir de l\'importance de cette compétence. Cela, couplé à la Fortitude, rend vos compagnons beaucoup plus capables au combat puisqu\'ils pourront encaisser un plus grand nombre de coups.$B$BNe laissez personne minimiser la puissance de vos magies.';
-- Quest 5625 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5625, 'frFR', 'Avez-vous trouvé Dolf, $N$?B$BVous l\'avez probablement déjà appris, mais notre capacité à guérir est très utile. Nous ne faisons pas seulement le soin aux blessés, mais nous sommes vitaux à la survie de tous ces héros potentiels qui essaient de se faire un nom. Avec la Fortitude pour augmenter le nombre de coups que nous pouvons encaisser, et notre magie de guérison pour les maintenir en vie, il n\'y a rien que nous ne puissions surmonter !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé Dolf, $N$?B$BVous l\'avez probablement déjà appris, mais notre capacité à guérir est très utile. Nous ne faisons pas seulement le soin aux blessés, mais nous sommes vitaux à la survie de tous ces héros potentiels qui essaient de se faire un nom. Avec la Fortitude pour augmenter le nombre de coups que nous pouvons encaisser, et notre magie de guérison pour les maintenir en vie, il n\'y a rien que nous ne puissions surmonter !';
-- Quest 5625 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5625, 'frFR', 'Bien fait, $N$. Tu as la Lumière en toi, c\'est certain.$B$BTiens, prends cette robe. Elle dénotera ton rôle dans l\'église et aidera les gens à te reconnaître comme un $c$--porte-la si tu veux.$B$BLater, il y aura d\'autres épreuves que tu devras traverser. Fais ce que tu peux pour apprendre sur tes capacités et ce dont tu es capable. Essaie un ou deux combats seul, puis à nouveau avec d\'autres voyageurs.$B$BMais ne t\'inquiète pas... tu es aussi puissant que les autres.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, $N$. Tu as la Lumière en toi, c\'est certain.$B$BTiens, prends cette robe. Elle dénotera ton rôle dans l\'église et aidera les gens à te reconnaître comme un $c$--porte-la si tu veux.$B$BLater, il y aura d\'autres épreuves que tu devras traverser. Fais ce que tu peux pour apprendre sur tes capacités et ce dont tu es capable. Essaie un ou deux combats seul, puis à nouveau avec d\'autres voyageurs.$B$BMais ne t\'inquiète pas... tu es aussi puissant que les autres.';
-- Quest 5626 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5626, 'frFR', 'Oh, donc Branstock t\'a envoyé, c\'est ça ? Bien, bien ! Il a raison, il est temps que tu commences à faire un pas beaucoup plus grand vers la Lumière. Ça développera le caractère et te rendra plus fort... et c\'est ce dont tu auras plus besoin que de quoi : la force du corps... la force de la volonté.') ON DUPLICATE KEY UPDATE RewardText='Oh, donc Branstock t\'a envoyé, c\'est ça ? Bien, bien ! Il a raison, il est temps que tu commences à faire un pas beaucoup plus grand vers la Lumière. Ça développera le caractère et te rendra plus fort... et c\'est ce dont tu auras plus besoin que de quoi : la force du corps... la force de la volonté.';
-- Quest 5627 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5627, 'frFR', 'Tu t\'es prouvé digne de l\'attention d\'Elune, $N$. Si tu penses être prêt, j\'aimerais beaucoup t\'enseigner l\'un de ses sorts propres à notre peuple.') ON DUPLICATE KEY UPDATE RewardText='Tu t\'es prouvé digne de l\'attention d\'Elune, $N$. Si tu penses être prêt, j\'aimerais beaucoup t\'enseigner l\'un de ses sorts propres à notre peuple.';
-- Quest 5628 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5628, 'frFR', 'Merveilleux, tu es rentré chez toi, $N$. Tyrande et moi sommes toujours ravis lorsque ceux que nous avons entraînés partent dans le monde et reviennent à nous en toute sécurité. Comment s\'est-il passé pour toi ? Elune bénit-elle toujours tes voyages ? Peut-être après que nous ayons discuté davantage de l\'affaire en question, tu pourrais m\'en dire plus de tes voyages.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux, tu es rentré chez toi, $N$. Tyrande et moi sommes toujours ravis lorsque ceux que nous avons entraînés partent dans le monde et reviennent à nous en toute sécurité. Comment s\'est-il passé pour toi ? Elune bénit-elle toujours tes voyages ? Peut-être après que nous ayons discuté davantage de l\'affaire en question, tu pourrais m\'en dire plus de tes voyages.';
-- Quest 5629 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5629, 'frFR', 'Merveilleux, tu es revenu, $N$. Tyrande et moi sommes toujours ravis lorsque ceux que nous avons entraînés partent dans le monde et reviennent à nous en toute sécurité. Comment s\'est-il passé pour toi ? Elune bénit-elle toujours tes voyages ? Peut-être après que nous ayons discuté davantage de l\'affaire en question, tu pourrais m\'en dire plus de tes voyages.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux, tu es revenu, $N$. Tyrande et moi sommes toujours ravis lorsque ceux que nous avons entraînés partent dans le monde et reviennent à nous en toute sécurité. Comment s\'est-il passé pour toi ? Elune bénit-elle toujours tes voyages ? Peut-être après que nous ayons discuté davantage de l\'affaire en question, tu pourrais m\'en dire plus de tes voyages.';

-- Quest 5631 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5631, 'frFR', 'Vous êtes rentré chez vous, $N$. Il fait toujours plaisir à Tyrande et à moi lorsque ceux que nous avons entraînés partent dans le monde et reviennent à nous en toute sécurité. Comment s\'est-il passé pour toi ? Elune bénit-elle toujours tes voyages ? Peut-être qu\'après que nous ayons discuté davantage des affaires en cours, tu pourras m\'en dire plus sur tes voyages.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes rentré chez vous, $N$. Il fait toujours plaisir à Tyrande et à moi lorsque ceux que nous avons entraînés partent dans le monde et reviennent à nous en toute sécurité. Comment s\'est-il passé pour toi ? Elune bénit-elle toujours tes voyages ? Peut-être qu\'après que nous ayons discuté davantage des affaires en cours, tu pourras m\'en dire plus sur tes voyages.';
-- Quest 5634 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5634, 'frFR', 'Tu as rendu un grand service à la Lumière en devenant un exemple brillant pour ceux qui voyagent dans ces terres dangereuses et au-delà. S\'il te plaît, accepte cette leçon comme un remerciement pour tout ce que tu as fait.') ON DUPLICATE KEY UPDATE RewardText='Tu as rendu un grand service à la Lumière en devenant un exemple brillant pour ceux qui voyagent dans ces terres dangereuses et au-delà. S\'il te plaît, accepte cette leçon comme un remerciement pour tout ce que tu as fait.';
-- Quest 5635 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5635, 'frFR', 'Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.';
-- Quest 5636 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5636, 'frFR', 'Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.';
-- Quest 5637 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5637, 'frFR', 'Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.';
-- Quest 5638 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5638, 'frFR', 'Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.';
-- Quest 5639 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5639, 'frFR', 'Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.';
-- Quest 5640 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5640, 'frFR', 'Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que tu sois arrivé, <name>. Nous aurons beaucoup de choses à discuter, mais plus important est ton entraînement dans les voies de la Lumière.$B$BIl y a des leçons que tous les serviteurs de la Lumière doivent apprendre. Si tu es prêt, nous commencerons à en discuter maintenant.';
-- Quest 5641 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5641, 'frFR', 'Tu as le potentiel d\'un grand $c, $N. Continue le bon travail !$B$BTu as déjà montré que tu étais prêt pour le combat. Peut-être est-il temps que nous t\'enseignions quelque chose de plus.') ON DUPLICATE KEY UPDATE RewardText='Tu as le potentiel d\'un grand $c, $N. Continue le bon travail !$B$BTu as déjà montré que tu étais prêt pour le combat. Peut-être est-il temps que nous t\'enseignions quelque chose de plus.';
-- Quest 5646 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5646, 'frFR', 'Bien, tu es revenu, et pas un instant trop tard. Nous avons de grandes choses à discuter, $N. Tes capacités deviennent plus fortes, et nous devons nous assurer que tu es prêt.') ON DUPLICATE KEY UPDATE RewardText='Bien, tu es revenu, et pas un instant trop tard. Nous avons de grandes choses à discuter, $N. Tes capacités deviennent plus fortes, et nous devons nous assurer que tu es prêt.';
-- Quest 5648 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5648, 'frFR', 'La plupart pensent qu\'il est logique que les magies de guérison soient puissantes, mais peu comprennent à quel point elles sont puissantes. Tu peux maintenir en vie beaucoup de gens alors qu\'ils devraient rencontrer leurs propres ancêtres. Cette magie de guérison mélangée à la capacité de Fortitude est une combinaison de sorts très puissante. Tu te souviens de cela. C\'est utile pour toutes sortes de gens : guerriers, mages et tout ce qui se trouve entre les deux.') ON DUPLICATE KEY UPDATE CompletionText='La plupart pensent qu\'il est logique que les magies de guérison soient puissantes, mais peu comprennent à quel point elles sont puissantes. Tu peux maintenir en vie beaucoup de gens alors qu\'ils devraient rencontrer leurs propres ancêtres. Cette magie de guérison mélangée à la capacité de Fortitude est une combinaison de sorts très puissante. Tu te souviens de cela. C\'est utile pour toutes sortes de gens : guerriers, mages et tout ce qui se trouve entre les deux.';
-- Quest 5648 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5648, 'frFR', 'Bien, alors Kor\'ja vit et part défendre notre ville contre ces humains malveillants. Je souhaite souvent me souvenir des jours de bataille ; où la puissance était montrée au combat et où c\'est le sage qui détruisait souvent ceux qui ne dépendaient que de leur force.$B$BTu as bien fait pour moi, $N. Tu prends cette robe maintenant. Peut-être que ça aide, peut-être que tu t\'en moques, mais tu l\'as mérité et je suis fier de t\'appeler frère.') ON DUPLICATE KEY UPDATE RewardText='Bien, alors Kor\'ja vit et part défendre notre ville contre ces humains malveillants. Je souhaite souvent me souvenir des jours de bataille ; où la puissance était montrée au combat et où c\'est le sage qui détruisait souvent ceux qui ne dépendaient que de leur force.$B$BTu as bien fait pour moi, $N. Tu prends cette robe maintenant. Peut-être que ça aide, peut-être que tu t\'en moques, mais tu l\'as mérité et je suis fier de t\'appeler frère.';
-- Quest 5649 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5649, 'frFR', 'Ahh... alors tu viens enfin à Tai\'jin. C\'est bien.$B$BTu sais déjà que nous ne sommes pas la même tribu qui s\'est alliée à la Horde. Nous sommes beaucoup plus forts maintenant. Nous sommes plus forts parce que nous nous adaptons -- la Horde nous a appris cela. Nous ne battons plus nos ennemis et ne tirons pas de force d\'eux ; maintenant nous tirons de la force, puis nous battons nos ennemis.$B$BLa différence est subtile, mais tu apprendras. Tu verras. La tribu compte sur toi pour apprendre de telles choses.') ON DUPLICATE KEY UPDATE RewardText='Ahh... alors tu viens enfin à Tai\'jin. C\'est bien.$B$BTu sais déjà que nous ne sommes pas la même tribu qui s\'est alliée à la Horde. Nous sommes beaucoup plus forts maintenant. Nous sommes plus forts parce que nous nous adaptons -- la Horde nous a appris cela. Nous ne battons plus nos ennemis et ne tirons pas de force d\'eux ; maintenant nous tirons de la force, puis nous battons nos ennemis.$B$BLa différence est subtile, mais tu apprendras. Tu verras. La tribu compte sur toi pour apprendre de telles choses.';
-- Quest 5650 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5650, 'frFR', 'Nos pouvoirs nous rendent idéaux pour tant de situations, $N. Tu découvriras que peu importe quoi, notre capacité à guérir les blessures et à augmenter la quantité de dégâts que nos compagnons peuvent subir sera toujours le talent le plus recherché auquel nous avons accès. Ne laisse pas cela t\'empêcher de poursuivre d\'autres chemins en tant que $C--tu peux être efficace de nombreuses façons. Mais... si tu souhaites vraiment détruire tes ennemis avec de l\'énergie magique, peut-être que l\'arcane te convient mieux.') ON DUPLICATE KEY UPDATE CompletionText='Nos pouvoirs nous rendent idéaux pour tant de situations, $N. Tu découvriras que peu importe quoi, notre capacité à guérir les blessures et à augmenter la quantité de dégâts que nos compagnons peuvent subir sera toujours le talent le plus recherché auquel nous avons accès. Ne laisse pas cela t\'empêcher de poursuivre d\'autres chemins en tant que $C--tu peux être efficace de nombreuses façons. Mais... si tu souhaites vraiment détruire tes ennemis avec de l\'énergie magique, peut-être que l\'arcane te convient mieux.';
-- Quest 5652 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5652, 'frFR', 'Tu ferais bien de prêter attention à cette leçon, jeune. Le Sort de Faiblesse sera une grande bénédiction pour toi au combat. Plus tard, j\'aurai des tests pour toi afin de te perfectionner et de prouver ta valeur à la tribu.') ON DUPLICATE KEY UPDATE RewardText='Tu ferais bien de prêter attention à cette leçon, jeune. Le Sort de Faiblesse sera une grande bénédiction pour toi au combat. Plus tard, j\'aurai des tests pour toi afin de te perfectionner et de prouver ta valeur à la tribu.';

-- Quest 5658 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5658, 'frFR', 'Ah, jeune $c, je suis heureux que tu sois revenu ici. Je vais t\'apprendre une leçon que tu feras bien de ne pas oublier. Es-tu prêt?') ON DUPLICATE KEY UPDATE RewardText='Ah, jeune $c, je suis heureux que tu sois revenu ici. Je vais t\'apprendre une leçon que tu feras bien de ne pas oublier. Es-tu prêt?';
-- Quest 5659 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5659, 'frFR', 'Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.') ON DUPLICATE KEY UPDATE RewardText='Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.';
-- Quest 5660 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5660, 'frFR', 'Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.') ON DUPLICATE KEY UPDATE RewardText='Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.';
