INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5661, 'frFR', 'Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.') ON DUPLICATE KEY UPDATE RewardText='Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.';
-- Quest 5662 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5662, 'frFR', 'Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.') ON DUPLICATE KEY UPDATE RewardText='Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.';
-- Quest 5663 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5663, 'frFR', 'Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.') ON DUPLICATE KEY UPDATE RewardText='Ah, bien, un autre est arrivé. Le temps peut ne pas m\'importe pas, mais pour toi, il est essentiel. Il y a beaucoup à apprendre pour toi et beaucoup que je souhaite t\'enseigner. Tu dois simplement prouver ta valeur. Fais cela, et tu seras grandement récompensé.';
-- Quest 5672 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5672, 'frFR', 'En te consacrant à Elune et à notre peuple, tu as atteint un état que nous ne pouvons pas tous atteindre. Il est de tradition que tu sois alors enseigné des capacités encore plus grandes pour ta dévotion. Accepte-tu?') ON DUPLICATE KEY UPDATE RewardText='En te consacrant à Elune et à notre peuple, tu as atteint un état que nous ne pouvons pas tous atteindre. Il est de tradition que tu sois alors enseigné des capacités encore plus grandes pour ta dévotion. Accepte-tu?';
-- Quest 5673 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5673, 'frFR', 'Elune te bénit pour ton retour si rapide parmi nous. C\'est un moment important dans ton entraînement, et un moment que toute notre ordre prend très au sérieux. Quand tu te seras reposé de ton voyage ici, s\'il te plaît, fais-le moi savoir. Nous pourrons alors discuter de la poursuite de ton entraînement et de la direction que ton chemin te mènera ensuite.') ON DUPLICATE KEY UPDATE RewardText='Elune te bénit pour ton retour si rapide parmi nous. C\'est un moment important dans ton entraînement, et un moment que toute notre ordre prend très au sérieux. Quand tu te seras reposé de ton voyage ici, s\'il te plaît, fais-le moi savoir. Nous pourrons alors discuter de la poursuite de ton entraînement et de la direction que ton chemin te mènera ensuite.';
-- Quest 5676 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5676, 'frFR', 'Nous avons été forcés d\'apprendre des magies pour nous protéger de ce que l\'on appelle communément notre plus grand ennemi : l\'arcane.$B$BI t\'enseignera un sort pour t\'aider à te défendre toi et tes compagnons contre ceux qui voudraient manier un tel pouvoir.') ON DUPLICATE KEY UPDATE RewardText='Nous avons été forcés d\'apprendre des magies pour nous protéger de ce que l\'on appelle communément notre plus grand ennemi : l\'arcane.$B$BI t\'enseignera un sort pour t\'aider à te défendre toi et tes compagnons contre ceux qui voudraient manier un tel pouvoir.';
-- Quest 5677 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5677, 'frFR', 'Ah, tu as un timing merveilleux, <name>. Je commençais à me demander si tous mes messagers avaient réussi. Je suis heureux de voir qu\'ils l\'ont fait, sinon je parierais que tu serais encore dans le monde à apprendre davantage sur toutes les menaces qui pèsent sur notre peuple.$B$Es-tu prêt? Prêt pour plus d\'entraînement, je veux dire. Tu grandis en puissance plus rapidement, et je sens que tu es prêt à en apprendre davantage sur notre foi.') ON DUPLICATE KEY UPDATE RewardText='Ah, tu as un timing merveilleux, <name>. Je commençais à me demander si tous mes messagers avaient réussi. Je suis heureux de voir qu\'ils l\'ont fait, sinon je parierais que tu serais encore dans le monde à apprendre davantage sur toutes les menaces qui pèsent sur notre peuple.$B$Es-tu prêt? Prêt pour plus d\'entraînement, je veux dire. Tu grandis en puissance plus rapidement, et je sens que tu es prêt à en apprendre davantage sur notre foi.';
-- Quest 5678 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5678, 'frFR', 'Ah, tu as un timing merveilleux, <name>. Je commençais à me demander si tous mes messagers avaient réussi. Je suis heureux de voir qu\'ils l\'ont fait, sinon je parierais que tu serais encore dans le monde à apprendre davantage sur toutes les menaces qui pèsent sur notre peuple.$B$Es-tu prêt? Prêt pour plus d\'entraînement, je veux dire. Tu grandis en puissance plus rapidement, et je sens que tu es prêt à en apprendre davantage sur notre foi.') ON DUPLICATE KEY UPDATE RewardText='Ah, tu as un timing merveilleux, <name>. Je commençais à me demander si tous mes messagers avaient réussi. Je suis heureux de voir qu\'ils l\'ont fait, sinon je parierais que tu serais encore dans le monde à apprendre davantage sur toutes les menaces qui pèsent sur notre peuple.$B$Es-tu prêt? Prêt pour plus d\'entraînement, je veux dire. Tu grandis en puissance plus rapidement, et je sens que tu es prêt à en apprendre davantage sur notre foi.';
-- Quest 5679 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5679, 'frFR', 'Je t\'enseignerais la Plaque Dévorante si tu penses être prêt, $N. Un sort d\'une puissance non négligeable, il t\'aidera dans tes batailles à venir. Entraîne-toi avec lui -- il y aura des tests plus tard.') ON DUPLICATE KEY UPDATE RewardText='Je t\'enseignerais la Plaque Dévorante si tu penses être prêt, $N. Un sort d\'une puissance non négligeable, il t\'aidera dans tes batailles à venir. Entraîne-toi avec lui -- il y aura des tests plus tard.';
-- Quest 5680 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5680, 'frFR', 'Tes rites arriveront bientôt. Pour l\'instant, je t\'enseigne un sort qui te sera d\'une grande utilité lorsque tu combattras tes ennemis.') ON DUPLICATE KEY UPDATE RewardText='Tes rites arriveront bientôt. Pour l\'instant, je t\'enseigne un sort qui te sera d\'une grande utilité lorsque tu combattras tes ennemis.';
-- Quest 5713 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5713, 'frFR', 'As-tu vu Sentinel Aynasha sur la route? Elle est partie en mission importante mais elle n\'est pas encore revenue.') ON DUPLICATE KEY UPDATE CompletionText='As-tu vu Sentinel Aynasha sur la route? Elle est partie en mission importante mais elle n\'est pas encore revenue.';
-- Quest 5721 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5721, 'frFR', 'Je crois que j\'ai entendu des fantômes dehors. Ils me murmurent des choses effrayantes...') ON DUPLICATE KEY UPDATE CompletionText='Je crois que j\'ai entendu des fantômes dehors. Ils me murmurent des choses effrayantes...';

-- Quest 5723 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5723, 'frFR', 'Comment se passe ta recherche du Gouffre ? Et des troggs ? $B$BLa menace ne peut pas persister -- elle ne fera qu\'infliger des blessures à nos frères orcs si elle continue.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe ta recherche du Gouffre ? Et des troggs ? $B$BLa menace ne peut pas persister -- elle ne fera qu\'infliger des blessures à nos frères orcs si elle continue.';
-- Quest 5724 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5724, 'frFR', 'As-tu trouvé quelque chose, $N$? Des indices sur la raison pour laquelle l\'un de ses clansmen a dû mourir inutilement seraient utiles.') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé quelque chose, $N$? Des indices sur la raison pour laquelle l\'un de ses clansmen a dû mourir inutilement seraient utiles.';
-- Quest 5726 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5726, 'frFR', 'As-tu l\'insigne, $N$?b$bCe sera un outil vital pour infiltrer ce que je crois être la plus grande menace pour la Horde et pour nous trouver enfin la paix dans notre nouveau foyer.$b$bTu apprendras à quel point une toile complexe des hommes et des orcs peut tisser lorsqu\'ils sont motivés par la cupidité et le pouvoir. Les agendas cachés, la corruption, tout cela deviendra clair. Tu te retrouveras au milieu d\'une guerre dont tu ne savais pas exister.') ON DUPLICATE KEY UPDATE CompletionText='As-tu l\'insigne, $N$?b$bCe sera un outil vital pour infiltrer ce que je crois être la plus grande menace pour la Horde et pour nous trouver enfin la paix dans notre nouveau foyer.$b$bTu apprendras à quel point une toile complexe des hommes et des orcs peut tisser lorsqu\'ils sont motivés par la cupidité et le pouvoir. Les agendas cachés, la corruption, tout cela deviendra clair. Tu te retrouveras au milieu d\'une guerre dont tu ne savais pas exister.';
-- Quest 5727 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5727, 'frFR', 'Eh bien, $c$? Croit-il notre stratagème, ou les choses sont pires que je ne l\'avais estimé?$b$bÊtre utile à Neeru rendra notre infiltration du Conseil des Ombres beaucoup plus facile. Il aura beaucoup d\'informations que nous pourrons utiliser pour écarter ceux qui voudraient détruire tout ce que nous avons construit à Durotar.') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, $c$? Croit-il notre stratagème, ou les choses sont pires que je ne l\'avais estimé?$b$bÊtre utile à Neeru rendra notre infiltration du Conseil des Ombres beaucoup plus facile. Il aura beaucoup d\'informations que nous pourrons utiliser pour écarter ceux qui voudraient détruire tout ce que nous avons construit à Durotar.';
-- Quest 5727 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5727, 'frFR', 'Excellent ! Très excellent, <class>!$B$BCe que tu as fait aujourd\'hui n\'est que la première étape d\'une fondation beaucoup plus vaste -- une fondation sur laquelle nous allons bâtir la destruction du Conseil des Ombres, une fois pour toutes.$B$Dis-moi tout ce qu\'il a dit... et ne laisse pas un seul mot de côté -- cela pourrait être plus important que tu ne le penses.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Très excellent, <class>!$B$BCe que tu as fait aujourd\'hui n\'est que la première étape d\'une fondation beaucoup plus vaste -- une fondation sur laquelle nous allons bâtir la destruction du Conseil des Ombres, une fois pour toutes.$B$Dis-moi tout ce qu\'il a dit... et ne laisse pas un seul mot de côté -- cela pourrait être plus important que tu ne le penses.';
-- Quest 5728 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5728, 'frFR', 'Les as-tu trouvés, $N$? Les chefs de la Lame Ardente.$b$bJe savais que le Conseil des Ombres cherchait à prendre Orgrimmar et toute la Horde de moi, mais je n\'avais pas réalisé à quelle vitesse ils ont pu infiltrer la ville. Tant d\'armes ce monstre a... nous pouvons les couper jusqu\'à ce qu\'ils soient épuisés, mais nous n\'irons pas plus loin que là où nous avons commencé. Je devrai faire doubler les efforts de mes espions.') ON DUPLICATE KEY UPDATE CompletionText='Les as-tu trouvés, $N$? Les chefs de la Lame Ardente.$b$bJe savais que le Conseil des Ombres cherchait à prendre Orgrimmar et toute la Horde de moi, mais je n\'avais pas réalisé à quelle vitesse ils ont pu infiltrer la ville. Tant d\'armes ce monstre a... nous pouvons les couper jusqu\'à ce qu\'ils soient épuisés, mais nous n\'irons pas plus loin que là où nous avons commencé. Je devrai faire doubler les efforts de mes espions.';
-- Quest 5729 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5729, 'frFR', 'Qu\'est-ce que c\'est ?! Oh, toi, <class>... mes excuses. Ma colère rivalise avec celle d\'un taureau kodo enragé... mais peut-être est-ce ma faute. En envoyant des voyageurs dans le Gouffre de Ragefire, j\'aurais dû voir la possibilité que quelque chose en vienne. Il semble que Bazzalan et Jergosh aient été pris au dépourvu et tués par certains des bienfaiteurs de Thrall. Un moment fort inopportune, mais il ne peut rien être fait à ce sujet maintenant.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est ?! Oh, toi, <class>... mes excuses. Ma colère rivalise avec celle d\'un taureau kodo enragé... mais peut-être est-ce ma faute. En envoyant des voyageurs dans le Gouffre de Ragefire, j\'aurais dû voir la possibilité que quelque chose en vienne. Il semble que Bazzalan et Jergosh aient été pris au dépourvu et tués par certains des bienfaiteurs de Thrall. Un moment fort inopportune, mais il ne peut rien être fait à ce sujet maintenant.';
-- Quest 5742 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5742, 'frFR', 'S\'il te plaît, ami ; assieds-toi et écoute mon histoire.') ON DUPLICATE KEY UPDATE CompletionText='S\'il te plaît, ami ; assieds-toi et écoute mon histoire.';
-- Quest 5801 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5801, 'frFR', 'As-tu terminé la tige de la clé squelettique ? Je suis vraiment désolé que tu aies dû supporter le poids des frais pour acheter le moule, mais nous devons tous faire notre part pour contrer le Fléau. Une fois que tu m\'auras remis la clé inachevée, tu seras prêt pour l\'élément final nécessaire pour compléter sa construction.$b$bCe ne sera pas facile du tout, mais le travail que tu as accompli jusqu\'à présent en préparation d\'une attaque sur Andorhal commencera maintenant à porter ses fruits. Tu verras.') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé la tige de la clé squelettique ? Je suis vraiment désolé que tu aies dû supporter le poids des frais pour acheter le moule, mais nous devons tous faire notre part pour contrer le Fléau. Une fois que tu m\'auras remis la clé inachevée, tu seras prêt pour l\'élément final nécessaire pour compléter sa construction.$b$bCe ne sera pas facile du tout, mais le travail que tu as accompli jusqu\'à présent en préparation d\'une attaque sur Andorhal commencera maintenant à porter ses fruits. Tu verras.';
-- Quest 5801 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5801, 'frFR', 'Nous avons une clé squelettique assez coûteuse, n\'est-ce pas <name>?  Pourtant, elle reste inachevée ; il est maintenant temps de concentrer nos efforts sur notre création.  À cette fin, tu vas devoir affronter le féroce ennemi que nous essayons d\'affronter à Andorhal... le être maléfique qui dirige la scène à l\'intérieur des murs de la ville en ruine.$B$Je parle d\'Araj le Convocateur - un liche, et l\'un des êtres les plus puissants que le Fléau appelle le sien.') ON DUPLICATE KEY UPDATE RewardText='Nous avons une clé squelettique assez coûteuse, n\'est-ce pas <name>?  Pourtant, elle reste inachevée ; il est maintenant temps de concentrer nos efforts sur notre création.  À cette fin, tu vas devoir affronter le féroce ennemi que nous essayons d\'affronter à Andorhal... le être maléfique qui dirige la scène à l\'intérieur des murs de la ville en ruine.$B$Je parle d\'Araj le Convocateur - un liche, et l\'un des êtres les plus puissants que le Fléau appelle le sien.';
-- Quest 5802 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5802, 'frFR', 'As-tu terminé la tige de la clé squelettique ? Je suis vraiment désolé que tu aies dû supporter le poids des frais pour acheter le moule, mais nous devons tous faire notre part pour contrer le Fléau. Une fois que tu m\'auras remis la clé inachevée, tu seras prêt pour l\'élément final nécessaire pour compléter sa construction.$b$bCe ne sera pas facile du tout, mais le travail que tu as accompli jusqu\'à présent en préparation d\'une attaque sur Andorhal commencera maintenant à porter ses fruits. Tu verras.') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé la tige de la clé squelettique ? Je suis vraiment désolé que tu aies dû supporter le poids des frais pour acheter le moule, mais nous devons tous faire notre part pour contrer le Fléau. Une fois que tu m\'auras remis la clé inachevée, tu seras prêt pour l\'élément final nécessaire pour compléter sa construction.$b$bCe ne sera pas facile du tout, mais le travail que tu as accompli jusqu\'à présent en préparation d\'une attaque sur Andorhal commencera maintenant à porter ses fruits. Tu verras.';
-- Quest 5802 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5802, 'frFR', 'Nous avons une clé squelettique assez coûteuse, n\'est-ce pas <name>?  Pourtant, elle reste inachevée ; il est maintenant temps de concentrer nos efforts sur notre création.  À cette fin, tu vas devoir affronter le féroce ennemi que nous essayons d\'affronter à Andorhal... l\'être qui dirige la scène à l\'intérieur des murs de la ville en ruine.$B$Je parle d\'Araj le Convocateur - un liche, et l\'un des êtres les plus puissants que le Fléau appelle le sien.') ON DUPLICATE KEY UPDATE RewardText='Nous avons une clé squelettique assez coûteuse, n\'est-ce pas <name>?  Pourtant, elle reste inachevée ; il est maintenant temps de concentrer nos efforts sur notre création.  À cette fin, tu vas devoir affronter le féroce ennemi que nous essayons d\'affronter à Andorhal... l\'être qui dirige la scène à l\'intérieur des murs de la ville en ruine.$B$Je parle d\'Araj le Convocateur - un liche, et l\'un des êtres les plus puissants que le Fléau appelle le sien.';
-- Quest 5805 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5805, 'frFR', 'Salutations ! C\'est un plaisir de vous rencontrer !$B$Je vois que vous avez un bon d\'achat spécial. Donnez-le-moi et je vous offrirai quelque chose en échange.') ON DUPLICATE KEY UPDATE CompletionText='Salutations ! C\'est un plaisir de vous rencontrer !$B$Je vois que vous avez un bon d\'achat spécial. Donnez-le-moi et je vous offrirai quelque chose en échange.';
-- Quest 5805 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5805, 'frFR', 'Vous êtes en effet un héros spécial, <name>. Nous vous souhaitons la bienvenue dans le monde d\'Azeroth, et vous offrons l\'un de ces cadeaux uniques !') ON DUPLICATE KEY UPDATE RewardText='Vous êtes en effet un héros spécial, <name>. Nous vous souhaitons la bienvenue dans le monde d\'Azeroth, et vous offrons l\'un de ces cadeaux uniques !';
-- Quest 5821 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5821, 'frFR', 'Pourquoi me retrouve-je à attendre cette maudite caravane?$b$b<Smeed semble éclairé.>$b$bOh oui, ils paient les factures. Les as-tu vus ?') ON DUPLICATE KEY UPDATE CompletionText='Pourquoi me retrouve-je à attendre cette maudite caravane?$b$b<Smeed semble éclairé.>$b$bOh oui, ils paient les factures. Les as-tu vus ?';

-- Quest 5841 [RequestItems]
