-- Quest 5845 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5845, 'frFR', 'Ma foi vous guidera, $N. La Lumière ne connaît pas de limites.') ON DUPLICATE KEY UPDATE CompletionText='Ma foi vous guidera, $N. La Lumière ne connaît pas de limites.';
-- Quest 5847 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5847, 'frFR', 'Salutations ! C\'est un plaisir de vous rencontrer !$B$Je vois que vous avez un bon d\'achat spécial. Donnez-le-moi et je vous offrirai quelque chose en échange.') ON DUPLICATE KEY UPDATE CompletionText='Salutations ! C\'est un plaisir de vous rencontrer !$B$Je vois que vous avez un bon d\'achat spécial. Donnez-le-moi et je vous offrirai quelque chose en échange.';
