-- Quest 5848 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5848, 'frFR', 'Le tableau, $N. Avez-vous le tableau ?') ON DUPLICATE KEY UPDATE CompletionText='Le tableau, $N. Avez-vous le tableau ?';
-- Quest 5861 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5861, 'frFR', 'J\'étais le conseiller le plus digne de confiance de Tirion lorsque celui-ci occupait le rang de Seigneur de Mardenholde. J\'ai ouvertement disserté le verdict rendu par l\'Ordre de la Main d\'Argent et j\'ai été banni pour mon insolence.$B$Il a traversé tant de douleurs et de déceptions dans sa vie, $R. Êtes-vous prêt à réparer les torts infligés aux Fordrings ?') ON DUPLICATE KEY UPDATE RewardText='J\'étais le conseiller le plus digne de confiance de Tirion lorsque celui-ci occupait le rang de Seigneur de Mardenholde. J\'ai ouvertement disserté le verdict rendu par l\'Ordre de la Main d\'Argent et j\'ai été banni pour mon insolence.$B$Il a traversé tant de douleurs et de déceptions dans sa vie, $R. Êtes-vous prêt à réparer les torts infligés aux Fordrings ?';
-- Quest 5862 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5862, 'frFR', 'Êtes-vous les renforts de la Main de Tyr ?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous les renforts de la Main de Tyr ?';
-- Quest 5862 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5862, 'frFR', 'Qu\'est-ce que c\'est, soldat?$B$Taelan ouvre la boîte et commence à examiner son contenu.>$B$Ceci... ceci ne peut être vrai. Mais tout ce que vous m\'avez montré...$B<br :><Taelan tombe à genoux, son cœur s\'accélère. La fureur des âges est sur le point d\'être déchaînée sur cette ville.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est, soldat?$B$Taelan ouvre la boîte et commence à examiner son contenu.>$B$Ceci... ceci ne peut être vrai. Mais tout ce que vous m\'avez montré...$B<br :><Taelan tombe à genoux, son cœur s\'accélère. La fureur des âges est sur le point d\'être déchaînée sur cette ville.';

-- Quest 5889 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5889, 'frFR', 'Un balise de Cenarion permet à un herboriste aguerri de repérer le rampant fel insidieux - un produit malfaisant de la corruption de Felwood. Mon travail ici m\'a enseigné la connaissance de la purification du rampant fel en un réactif purificateur... utilisé dans ce que nous appelons maintenant baume de plante de Cenarion.$b$bLorsque vous cueillez des herbes dans Felwood, vous devriez rencontrer le rampant fel tant que vous avez la balise. En échange de ce que vous m\'apportez, je vous donnerai un baume de plante de Cenarion préfabriqué.') ON DUPLICATE KEY UPDATE CompletionText='Un balise de Cenarion permet à un herboriste aguerri de repérer le rampant fel insidieux - un produit malfaisant de la corruption de Felwood. Mon travail ici m\'a enseigné la connaissance de la purification du rampant fel en un réactif purificateur... utilisé dans ce que nous appelons maintenant baume de plante de Cenarion.$b$bLorsque vous cueillez des herbes dans Felwood, vous devriez rencontrer le rampant fel tant que vous avez la balise. En échange de ce que vous m\'apportez, je vous donnerai un baume de plante de Cenarion préfabriqué.';
-- Quest 5889 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5889, 'frFR', 'Excellent travail $N - chaque morceau de ceci, une fois purifié, nous aidera à reconquérir Felwood. Ici, prenez quelques doses de baume de plante de Cenarion et allez dans la forêt. La reconquête de la terre contre la corruption n\'attend pas $R!') ON DUPLICATE KEY UPDATE RewardText='Excellent travail $N - chaque morceau de ceci, une fois purifié, nous aidera à reconquérir Felwood. Ici, prenez quelques doses de baume de plante de Cenarion et allez dans la forêt. La reconquête de la terre contre la corruption n\'attend pas $R!';
-- Quest 5890 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5890, 'frFR', 'Une balise de Cenarion permettra à un peaux-cuir bien entraîné de repérer des parches de peau corrompues provenant de la chasse dans Felwood. Je convertis ces parches apparemment inutiles en une pâte épaisse qui sert d\'agent accélérateur pour le baume de plante de Cenarion. Lorsque vous écorchez vos proies ici dans Felwood, assurez-vous d\'avoir une balise sur vous!$b$bLorsque vous collectez des parches corrompues, apportez-les-moi et je vous donnerai des baumes de plante de Cenarion que j\'ai déjà préparés.') ON DUPLICATE KEY UPDATE CompletionText='Une balise de Cenarion permettra à un peaux-cuir bien entraîné de repérer des parches de peau corrompues provenant de la chasse dans Felwood. Je convertis ces parches apparemment inutiles en une pâte épaisse qui sert d\'agent accélérateur pour le baume de plante de Cenarion. Lorsque vous écorchez vos proies ici dans Felwood, assurez-vous d\'avoir une balise sur vous!$b$bLorsque vous collectez des parches corrompues, apportez-les-moi et je vous donnerai des baumes de plante de Cenarion que j\'ai déjà préparés.';
-- Quest 5890 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5890, 'frFR', 'C\'est exactement ce dont j\'ai besoin. Voici - prenez ces baumes de plante et utilisez-les pour reconquérir Felwood contre la corruption. Nous devons persévérer, $N!') ON DUPLICATE KEY UPDATE RewardText='C\'est exactement ce dont j\'ai besoin. Voici - prenez ces baumes de plante et utilisez-les pour reconquérir Felwood contre la corruption. Nous devons persévérer, $N!';
-- Quest 5891 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5891, 'frFR', 'Le pouvoir d\'un objet magique désenchanté est ressenti par l\'essence qu\'il crée. J\'ai trouvé un moyen de transformer l\'essence brute utilisée par les enchanteurs en un réactif approprié pour créer le baume de plante de Cenarion. Vous n\'avez pas besoin d\'une balise de Cenarion pour cela ; tout objet suffisamment désenchanté qui donne des essences de néther inférieures fonctionnera.$B$BI ai juste besoin d\'une essence de néther inférieure ; en échange, je vous donnerai des baumes de plante de Cenarion. L\'essence est extrêmement puissante - un peu fait certainement beaucoup d\'effet!') ON DUPLICATE KEY UPDATE CompletionText='Le pouvoir d\'un objet magique désenchanté est ressenti par l\'essence qu\'il crée. J\'ai trouvé un moyen de transformer l\'essence brute utilisée par les enchanteurs en un réactif approprié pour créer le baume de plante de Cenarion. Vous n\'avez pas besoin d\'une balise de Cenarion pour cela ; tout objet suffisamment désenchanté qui donne des essences de néther inférieures fonctionnera.$B$BI ai juste besoin d\'une essence de néther inférieure ; en échange, je vous donnerai des baumes de plante de Cenarion. L\'essence est extrêmement puissante - un peu fait certainement beaucoup d\'effet!';
-- Quest 5891 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5891, 'frFR', 'Voici quelques baumes de plante de Cenarion - je n\'ai besoin que d\'une essence de néther inférieure pour cela, $N. L\'essence est de loin l\'article le plus puissant que je puisse utiliser pour transformer des épées en charrues, si l\'on veut. Si vous avez besoin de plus de baume, venez me voir ici!') ON DUPLICATE KEY UPDATE RewardText='Voici quelques baumes de plante de Cenarion - je n\'ai besoin que d\'une essence de néther inférieure pour cela, $N. L\'essence est de loin l\'article le plus puissant que je puisse utiliser pour transformer des épées en charrues, si l\'on veut. Si vous avez besoin de plus de baume, venez me voir ici!';
-- Quest 5892 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5892, 'frFR', 'Avez-vous les fournitures, $N? Nous ne pouvons jamais en avoir assez!') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les fournitures, $N? Nous ne pouvons jamais en avoir assez!';
-- Quest 5892 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5892, 'frFR', 'Bien fait!  Je mettrai ces fournitures à profit!  Merci, <name>!') ON DUPLICATE KEY UPDATE RewardText='Bien fait!  Je mettrai ces fournitures à profit!  Merci, <name>!';
-- Quest 5893 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5893, 'frFR', 'Êtes-vous allé à la mine de Coldtooth, $N? Avez-vous les fournitures que j\'ai demandées?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous allé à la mine de Coldtooth, $N? Avez-vous les fournitures que j\'ai demandées?';
-- Quest 5893 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5893, 'frFR', 'Ah, vous les avez.  Bon travail, $Gname>!  Ces fournitures sont un peu moisis après être restées dans cette mine sombre si longtemps, mais nous les utiliserons quand même.$B<br :>Merci, <name.  Vos actions sont vitales pour le maintien de nos forces combattantes.') ON DUPLICATE KEY UPDATE RewardText='Ah, vous les avez.  Bon travail, $Gname>!  Ces fournitures sont un peu moisis après être restées dans cette mine sombre si longtemps, mais nous les utiliserons quand même.$B<br :>Merci, <name.  Vos actions sont vitales pour le maintien de nos forces combattantes.';
-- Quest 5901 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5901, 'frFR', 'Avez-vous les termites, $N? Je suis sûr qu\'il est évident pour un $C intelligent comme vous.$B$BUne fois que nous en aurons assez, nous nous assurerons que personne ne pourra plus utiliser l\'usine à bois!') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les termites, $N? Je suis sûr qu\'il est évident pour un $C intelligent comme vous.$B$BUne fois que nous en aurons assez, nous nous assurerons que personne ne pourra plus utiliser l\'usine à bois!';
-- Quest 5901 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5901, 'frFR', 'Ceci fera l\'affaire, <name>. Merci.$B$BSi vous êtes prêt, nous pouvons passer à l\'étape suivante.') ON DUPLICATE KEY UPDATE RewardText='Ceci fera l\'affaire, <name>. Merci.$B$BSi vous êtes prêt, nous pouvons passer à l\'étape suivante.';
-- Quest 5903 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5903, 'frFR', 'Avez-vous trouvé les monticules de termites, $N? J\'ai entendu dire qu\'ils étaient partout dans Plaguewood.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé les monticules de termites, $N? J\'ai entendu dire qu\'ils étaient partout dans Plaguewood.';
-- Quest 5903 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5903, 'frFR', 'Ceci fera l\'affaire, <name>. Merci. Regardez-les... tant d\'entre eux, tous regroupés. Je me sens presque mal pour la Crusade, mais après tout, ce n\'était pas leur usine à prendre, maintenant, n\'est-ce pas?') ON DUPLICATE KEY UPDATE RewardText='Ceci fera l\'affaire, <name>. Merci. Regardez-les... tant d\'entre eux, tous regroupés. Je me sens presque mal pour la Crusade, mais après tout, ce n\'était pas leur usine à prendre, maintenant, n\'est-ce pas?';
-- Quest 5922 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5922, 'frFR', '"Et ainsi commence, Père Cenarius. Et ainsi commence."$B$BDendrite fait un geste rapide et invisible dans l\'air au-dessus de lui. Une légère aura de pouvoir l\'enveloppe.$B$B"La première perspective de la nature à laquelle vous devez vous adapter est celle du ours. Je vous mettrai sur le chemin de la compréhension de cet aspect de la vie druidique, mais c\'est vous qui devez l\'embrasser et le propager - maintenant et pour toujours!"') ON DUPLICATE KEY UPDATE RewardText='"Et ainsi commence, Père Cenarius. Et ainsi commence."$B$BDendrite fait un geste rapide et invisible dans l\'air au-dessus de lui. Une légère aura de pouvoir l\'enveloppe.$B$B"La première perspective de la nature à laquelle vous devez vous adapter est celle du ours. Je vous mettrai sur le chemin de la compréhension de cet aspect de la vie druidique, mais c\'est vous qui devez l\'embrasser et le propager - maintenant et pour toujours!"';

-- Quest 5923 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5923, 'frFR', 'Je suis heureux que vous ayez trouvé le chemin ici aujourd\'hui, jeune $C. Il est temps pour vous de faire un grand pas dans un monde bien plus vaste.$B$BEn chacun des enfants de Cenarius réside l\'appel à servir la nature. Les animaux et les plantes sont nos amis comme nos charges. Nous choisissons de dédier nos vies à préserver l\'équilibre pour eux comme pour nous-mêmes. Votre premier pas dans ce monde sera d\'apprendre les voies du ours, et d\'apprendre la force du corps et du cœur.$B$BPréparez-vous !') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que vous ayez trouvé le chemin ici aujourd\'hui, jeune $C. Il est temps pour vous de faire un grand pas dans un monde bien plus vaste.$B$BEn chacun des enfants de Cenarius réside l\'appel à servir la nature. Les animaux et les plantes sont nos amis comme nos charges. Nous choisissons de dédier nos vies à préserver l\'équilibre pour eux comme pour nous-mêmes. Votre premier pas dans ce monde sera d\'apprendre les voies du ours, et d\'apprendre la force du corps et du cœur.$B$BPréparez-vous !';
-- Quest 5924 [OfferReward]
