INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5928, 'frFR', 'Je suis heureux que vous ayez trouvé le chemin ici aujourd\'hui. jeune $c. Il est temps pour vous de faire un grand pas dans un monde bien plus vaste.$B$BEn chacun des enfants de Cenarius réside l\'appel à servir la nature. Les animaux et les plantes sont nos amis comme nos charges. Nous choisissons de dédier nos vies à préserver l\'équilibre pour eux comme pour nous-mêmes. Votre premier pas dans ce monde sera d\'apprendre les voies du ours, et d\'apprendre la force du corps et du cœur.$B$BPréparez-vous !') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que vous ayez trouvé le chemin ici aujourd\'hui. jeune $c. Il est temps pour vous de faire un grand pas dans un monde bien plus vaste.$B$BEn chacun des enfants de Cenarius réside l\'appel à servir la nature. Les animaux et les plantes sont nos amis comme nos charges. Nous choisissons de dédier nos vies à préserver l\'équilibre pour eux comme pour nous-mêmes. Votre premier pas dans ce monde sera d\'apprendre les voies du ours, et d\'apprendre la force du corps et du cœur.$B$BPréparez-vous !';
-- Quest 5929 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5929, 'frFR', 'Dendrite fait un autre geste invisible dans l\'air au-dessus de lui alors que vous vous approchez. Une autre aura de puissance l\'envahit, et il sourit très légèrement.$B$B"Je ressens une sagesse en vous, jeune, qui n\'était pas présente lorsque nous nous sommes rencontrés pour la première fois. Vous me regardez avec force et intention connaissante, bien que cette intention ne soit pas encore focalisée. Vous apprendrez maintenant à concentrer votre force et à adopter la nature du ours dans votre travail."') ON DUPLICATE KEY UPDATE RewardText='Dendrite fait un autre geste invisible dans l\'air au-dessus de lui alors que vous vous approchez. Une autre aura de puissance l\'envahit, et il sourit très légèrement.$B$B"Je ressens une sagesse en vous, jeune, qui n\'était pas présente lorsque nous nous sommes rencontrés pour la première fois. Vous me regardez avec force et intention connaissante, bien que cette intention ne soit pas encore focalisée. Vous apprendrez maintenant à concentrer votre force et à adopter la nature du ours dans votre travail."';
-- Quest 5930 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5930, 'frFR', 'Dendrite fait un autre geste invisible dans l\'air au-dessus de lui alors que vous vous approchez. Une autre aura de puissance l\'envahit, et il sourit très légèrement.$B$B"Je ressens une sagesse en vous, jeune, qui n\'était pas présente lorsque nous nous sommes rencontrés pour la première fois. Vous me regardez avec force et intention connaissante, bien que cette intention ne soit pas encore focalisée. Vous apprendrez maintenant à concentrer votre force et à adopter la nature du ours dans votre travail."') ON DUPLICATE KEY UPDATE RewardText='Dendrite fait un autre geste invisible dans l\'air au-dessus de lui alors que vous vous approchez. Une autre aura de puissance l\'envahit, et il sourit très légèrement.$B$B"Je ressens une sagesse en vous, jeune, qui n\'était pas présente lorsque nous nous sommes rencontrés pour la première fois. Vous me regardez avec force et intention connaissante, bien que cette intention ne soit pas encore focalisée. Vous apprendrez maintenant à concentrer votre force et à adopter la nature du ours dans votre travail."';
-- Quest 5943 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5943, 'frFR', 'Vous savez, si cette caravane devait disparaître, je serais ruiné ! Vous n\'êtes pas celui qui apporte les mauvaises nouvelles concernant la caravane, n\'est-ce pas?$b$b<Smeed s\'essuie le front.>$b$bRemerciez la déesse de la cupidité !') ON DUPLICATE KEY UPDATE CompletionText='Vous savez, si cette caravane devait disparaître, je serais ruiné ! Vous n\'êtes pas celui qui apporte les mauvaises nouvelles concernant la caravane, n\'est-ce pas?$b$b<Smeed s\'essuie le front.>$b$bRemerciez la déesse de la cupidité !';
-- Quest 5944 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5944, 'frFR', 'La mort de mon fils aux mains de ces monstres ne passera pas sans incident. Trouvez du réconfort à savoir que l\'Ordre renaît.$B$BI prenez maintenant ma place en tant que Haut-Seigneur de la nouvelle Ordre de la Main d\'Argent.$B$BCes possessions de mon passé - c\'est tout ce que j\'ai à offrir pour tout ce que vous avez fait. S\'il vous plaît, prenez ceci comme un symbole de ma gratitude ; tout m\'a servi bien au fil des années.$B$BPouvons-nous nous revoir, en meilleurs temps, et nous remémorer des jours passés... des batailles âprement menées... des rêves réalisés.') ON DUPLICATE KEY UPDATE RewardText='La mort de mon fils aux mains de ces monstres ne passera pas sans incident. Trouvez du réconfort à savoir que l\'Ordre renaît.$B$BI prenez maintenant ma place en tant que Haut-Seigneur de la nouvelle Ordre de la Main d\'Argent.$B$BCes possessions de mon passé - c\'est tout ce que j\'ai à offrir pour tout ce que vous avez fait. S\'il vous plaît, prenez ceci comme un symbole de ma gratitude ; tout m\'a servi bien au fil des années.$B$BPouvons-nous nous revoir, en meilleurs temps, et nous remémorer des jours passés... des batailles âprement menées... des rêves réalisés.';
-- Quest 5981 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5981, 'frFR', 'Vous devez continuer à vous prouver, $N.') ON DUPLICATE KEY UPDATE CompletionText='Vous devez continuer à vous prouver, $N.';
-- Quest 6002 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6002, 'frFR', 'Lorsque vous aurez affronté le défi qui se présente à vous, votre compréhension de la force du corps et de la force du cœur sera pleinement réalisée. Jusqu\'à ce temps, je ne peux plus vous aider.') ON DUPLICATE KEY UPDATE CompletionText='Lorsque vous aurez affronté le défi qui se présente à vous, votre compréhension de la force du corps et de la force du cœur sera pleinement réalisée. Jusqu\'à ce temps, je ne peux plus vous aider.';
-- Quest 6004 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6004, 'frFR', 'Comment ça va, $N? Sont-ils plus forts que vous ne le pensiez ? J\'espère pas. Si je vais suivre cela, cela va nécessiter beaucoup plus de force que ce que je vous ai déjà demandé de faire.') ON DUPLICATE KEY UPDATE CompletionText='Comment ça va, $N? Sont-ils plus forts que vous ne le pensiez ? J\'espère pas. Si je vais suivre cela, cela va nécessiter beaucoup plus de force que ce que je vous ai déjà demandé de faire.';
-- Quest 6021 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6021, 'frFR', 'Avez-vous trouvé le repaire, $N? Avez-vous pris soin de Zaeldarr ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé le repaire, $N? Avez-vous pris soin de Zaeldarr ?';
-- Quest 6022 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6022, 'frFR', 'Vous pleurez ? Si c\'est trop \'ennuyeux\' pour vous, \'héros\', je vous recommande de retourner auprès de la Dame Noire et de lui signaler le mauvais traitement horrible que vous avez subi dans ma ferme.$b$bSortez de ma vue !') ON DUPLICATE KEY UPDATE CompletionText='Vous pleurez ? Si c\'est trop \'ennuyeux\' pour vous, \'héros\', je vous recommande de retourner auprès de la Dame Noire et de lui signaler le mauvais traitement horrible que vous avez subi dans ma ferme.$b$bSortez de ma vue !';

-- Quest 6023 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6023, 'frFR', 'As-tu trouvé $N ? Une fois les deux pris en charge, je peux me rendre à Hearthglen pour examiner leur installation de plus près. Je ne peux pas le faire sans ton aide. S\'il te plaît, trouve Radley et Durgen pour moi.') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé $N ? Une fois les deux pris en charge, je peux me rendre à Hearthglen pour examiner leur installation de plus près. Je ne peux pas le faire sans ton aide. S\'il te plaît, trouve Radley et Durgen pour moi.';
-- Quest 6025 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6025, 'frFR', 'C\'est une tâche dangereuse, $n. J\'envie ton courage.') ON DUPLICATE KEY UPDATE CompletionText='C\'est une tâche dangereuse, $n. J\'envie ton courage.';
-- Quest 6025 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6025, 'frFR', 'Tu l\'as fait, $Gname>! Merci!$B<br :>Je retournerai à Elling... je veux dire Stormwind dès que possible. Tiens, prends cette pièce, c\'est le moins que je puisse faire pour toi. Tu es une fierté pour ton peuple, <name. Merci et bonne chance.') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait, $Gname>! Merci!$B<br :>Je retournerai à Elling... je veux dire Stormwind dès que possible. Tiens, prends cette pièce, c\'est le moins que je puisse faire pour toi. Tu es une fierté pour ton peuple, <name. Merci et bonne chance.';
-- Quest 6026 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6026, 'frFR', 'Fais confiance à ol\' Smokey, $r. La récompense en vaudra la peine. Ces gens de l\'Aube Argentée ne plaisantent pas quand il s\'agit de paiement.') ON DUPLICATE KEY UPDATE CompletionText='Fais confiance à ol\' Smokey, $r. La récompense en vaudra la peine. Ces gens de l\'Aube Argentée ne plaisantent pas quand il s\'agit de paiement.';
-- Quest 6026 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6026, 'frFR', 'Je peux te payer la moitié à l\'avance et la moitié une fois le travail terminé.') ON DUPLICATE KEY UPDATE RewardText='Je peux te payer la moitié à l\'avance et la moitié une fois le travail terminé.';
-- Quest 6027 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6027, 'frFR', 'Ah, $N! C\'est bon de te revoir. As-tu le Livre des Anciens ?') ON DUPLICATE KEY UPDATE CompletionText='Ah, $N! C\'est bon de te revoir. As-tu le Livre des Anciens ?';
-- Quest 6032 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6032, 'frFR', 'As-tu apporté le tissu de lune, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté le tissu de lune, $N?';
-- Quest 6032 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6032, 'frFR', 'Ah, très bien.  Ce tissu de lune sera utilisé pour des vêtements sacrés à notre peuple.  Merci, <name>.  Maintenant, je vais t\'entraîner.') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien.  Ce tissu de lune sera utilisé pour des vêtements sacrés à notre peuple.  Merci, <name>.  Maintenant, je vais t\'entraîner.';
-- Quest 6041 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6041, 'frFR', 'J\'ai des fournitures restantes pour fabriquer quelques bâtons supplémentaires du composé spécial. Dis-le simplement à ol\' Smokey si tu as besoin de plus.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai des fournitures restantes pour fabriquer quelques bâtons supplémentaires du composé spécial. Dis-le simplement à ol\' Smokey si tu as besoin de plus.';
-- Quest 6041 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6041, 'frFR', 'Tu es beaucoup plus sombre que je ne m\'en souviens. Tu as ce regard qui te va bien ; le regard qui dit : \'J\'ai été charbonné par une bombe explosive.\'$B$B<Smokey rit.>$B$Quoi qu\'il en soit! Voici ta part du butin. J\'ai ajouté quelque chose d\'extra pour t\'aider à apaiser les brûlures.') ON DUPLICATE KEY UPDATE RewardText='Tu es beaucoup plus sombre que je ne m\'en souviens. Tu as ce regard qui te va bien ; le regard qui dit : \'J\'ai été charbonné par une bombe explosive.\'$B$B<Smokey rit.>$B$Quoi qu\'il en soit! Voici ta part du butin. J\'ai ajouté quelque chose d\'extra pour t\'aider à apaiser les brûlures.';
-- Quest 6042 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6042, 'frFR', 'Ça aurait pu être pire. J\'aurais pu te faire collecter du guano de chauve-souris.$B$B<Nathanos te regarde en contemplation.>$B$Hmm... Hé! Attends une minute. Où vas-tu ?') ON DUPLICATE KEY UPDATE CompletionText='Ça aurait pu être pire. J\'aurais pu te faire collecter du guano de chauve-souris.$B$B<Nathanos te regarde en contemplation.>$B$Hmm... Hé! Attends une minute. Où vas-tu ?';
-- Quest 6061 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6061, 'frFR', 'Entraîne tes compétences, $N. Dompte le marcheur adulte.') ON DUPLICATE KEY UPDATE CompletionText='Entraîne tes compétences, $N. Dompte le marcheur adulte.';
-- Quest 6061 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6061, 'frFR', 'Des signes m\'ont apparus de la Mère-Terre ; tu as bien fait.') ON DUPLICATE KEY UPDATE RewardText='Des signes m\'ont apparus de la Mère-Terre ; tu as bien fait.';
-- Quest 6062 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6062, 'frFR', 'Tu as bien fait, $N. Je crois que tu es prêt pour ta prochaine tâche.') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait, $N. Je crois que tu es prêt pour ta prochaine tâche.';
-- Quest 6063 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6063, 'frFR', 'Tu apprendras, $N, et un jour tu seras un grand $C.') ON DUPLICATE KEY UPDATE CompletionText='Tu apprendras, $N, et un jour tu seras un grand $C.';

-- Quest 6063 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6063, 'frFR', 'Excellent, $N! Tu apprends vite.') ON DUPLICATE KEY UPDATE RewardText='Excellent, $N! Tu apprends vite.';
-- Quest 6064 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6064, 'frFR', 'Ne t\'inquiète pas, lass ! Tu vas pouvoir en essayer quelques-uns avant de devoir en choisir un seul.') ON DUPLICATE KEY UPDATE CompletionText='Ne t\'inquiète pas, lass ! Tu vas pouvoir en essayer quelques-uns avant de devoir en choisir un seul.';
-- Quest 6064 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6064, 'frFR', 'Je sais, je sais ; tu te demandes ce qui vient ensuite, n\'est-ce pas ?!') ON DUPLICATE KEY UPDATE RewardText='Je sais, je sais ; tu te demandes ce qui vient ensuite, n\'est-ce pas ?!';
-- Quest 6065 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6065, 'frFR', 'Oui, je crois que tu es prête...') ON DUPLICATE KEY UPDATE RewardText='Oui, je crois que tu es prête...';
-- Quest 6066 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6066, 'frFR', 'Oui, je crois que tu es prête...') ON DUPLICATE KEY UPDATE RewardText='Oui, je crois que tu es prête...';
-- Quest 6067 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6067, 'frFR', 'Oui, je crois que tu es prête...') ON DUPLICATE KEY UPDATE RewardText='Oui, je crois que tu es prête...';
-- Quest 6068 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6068, 'frFR', 'Oui, il est temps pour toi de commencer ton entraînement.') ON DUPLICATE KEY UPDATE RewardText='Oui, il est temps pour toi de commencer ton entraînement.';
-- Quest 6069 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6069, 'frFR', 'Oui, il est temps pour toi de commencer ton entraînement.') ON DUPLICATE KEY UPDATE RewardText='Oui, il est temps pour toi de commencer ton entraînement.';
-- Quest 6070 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6070, 'frFR', 'Oui, il est temps pour toi de commencer ton entraînement.') ON DUPLICATE KEY UPDATE RewardText='Oui, il est temps pour toi de commencer ton entraînement.';
-- Quest 6074 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6074, 'frFR', 'Oui, je crois que tu es prête, aussi....') ON DUPLICATE KEY UPDATE RewardText='Oui, je crois que tu es prête, aussi....';
-- Quest 6075 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6075, 'frFR', 'Oui, je crois que tu es prête, aussi....') ON DUPLICATE KEY UPDATE RewardText='Oui, je crois que tu es prête, aussi....';
-- Quest 6076 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6076, 'frFR', 'Oui, je crois que tu es prête, aussi....') ON DUPLICATE KEY UPDATE RewardText='Oui, je crois que tu es prête, aussi....';
-- Quest 6082 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6082, 'frFR', 'As-tu réussi à dompter le scorpide ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à dompter le scorpide ?';
-- Quest 6082 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6082, 'frFR', 'Tu as appris tout ce que je peux t\'enseigner, $N. Il est temps pour toi de prendre ce que tu as appris ici et de choisir un animal de compagnie par toi-même.$B$BVoici, $N. Je vais maintenant te donner le pouvoir de dompter une bête, ainsi que de l\'appeler et de la renvoyer comme tu le jugeras bon. Utilise tes nouvelles compétences avec fierté ; tu les as méritées.') ON DUPLICATE KEY UPDATE RewardText='Tu as appris tout ce que je peux t\'enseigner, $N. Il est temps pour toi de prendre ce que tu as appris ici et de choisir un animal de compagnie par toi-même.$B$BVoici, $N. Je vais maintenant te donner le pouvoir de dompter une bête, ainsi que de l\'appeler et de la renvoyer comme tu le jugeras bon. Utilise tes nouvelles compétences avec fierté ; tu les as méritées.';
-- Quest 6083 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6083, 'frFR', 'Tu dois t\'entraîner pour acquérir les compétences nécessaires pour contrôler efficacement ton animal de compagnie. As-tu dompté un rampeur de surface ?') ON DUPLICATE KEY UPDATE CompletionText='Tu dois t\'entraîner pour acquérir les compétences nécessaires pour contrôler efficacement ton animal de compagnie. As-tu dompté un rampeur de surface ?';

-- Quest 6083 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6083, 'frFR', 'Tu es un apprenant rapide, $N$. Tu as bien réussi.') ON DUPLICATE KEY UPDATE RewardText='Tu es un apprenant rapide, $N$. Tu as bien réussi.';
-- Quest 6084 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6084, 'frFR', 'Qu\'en penses-tu du léopard des neiges, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'en penses-tu du léopard des neiges, $N$?';
-- Quest 6084 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6084, 'frFR', 'Quand je sentirai que tu as appris suffisamment, je te donnerai la capacité de choisir n\'importe quel animal de compagnie de ton choix.') ON DUPLICATE KEY UPDATE RewardText='Quand je sentirai que tu as appris suffisamment, je te donnerai la capacité de choisir n\'importe quel animal de compagnie de ton choix.';
-- Quest 6085 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6085, 'frFR', 'As-tu déjà dompté l\'ours à griffes de glace?') ON DUPLICATE KEY UPDATE CompletionText='As-tu déjà dompté l\'ours à griffes de glace?';
-- Quest 6085 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6085, 'frFR', 'Voici, $N$. Je vais maintenant te donner le pouvoir de dompter une bête, ainsi que de l\'appeler et de la renvoyer comme tu le souhaites.$B$BTrouve-toi un animal de compagnie bon et loyal, et profite de la chasse!') ON DUPLICATE KEY UPDATE RewardText='Voici, $N$. Je vais maintenant te donner le pouvoir de dompter une bête, ainsi que de l\'appeler et de la renvoyer comme tu le souhaites.$B$BTrouve-toi un animal de compagnie bon et loyal, et profite de la chasse!';
-- Quest 6086 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6086, 'frFR', 'Un nouveau recrue, hein? Tu es en train de devenir un grand $c$, je vois.$B$BOui, je peux t\'accorder les compétences dont tu as besoin pour entraîner et guider ton animal de compagnie. Non seulement tu pourras enseigner de nouvelles capacités à ton animal de compagnie, tu pourras maintenant aussi nourrir ton animal de compagnie, ainsi que le ressusciter, s\'il tombe au combat.$B$BSouviens-toi que la clé pour tirer le meilleur parti de ton nouvel animal de compagnie est de le respecter et de bien le traiter. En retour, ton animal de compagnie sera ton ami le plus loyal.') ON DUPLICATE KEY UPDATE RewardText='Un nouveau recrue, hein? Tu es en train de devenir un grand $c$, je vois.$B$BOui, je peux t\'accorder les compétences dont tu as besoin pour entraîner et guider ton animal de compagnie. Non seulement tu pourras enseigner de nouvelles capacités à ton animal de compagnie, tu pourras maintenant aussi nourrir ton animal de compagnie, ainsi que le ressusciter, s\'il tombe au combat.$B$BSouviens-toi que la clé pour tirer le meilleur parti de ton nouvel animal de compagnie est de le respecter et de bien le traiter. En retour, ton animal de compagnie sera ton ami le plus loyal.';
-- Quest 6087 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6087, 'frFR', 'As-tu trouvé un chasseur de prairie?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé un chasseur de prairie?';
-- Quest 6087 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6087, 'frFR', 'Oui... La Mère Terre croit que tu es prêt pour la leçon suivante.') ON DUPLICATE KEY UPDATE RewardText='Oui... La Mère Terre croit que tu es prêt pour la leçon suivante.';
-- Quest 6088 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6088, 'frFR', 'Tu as appris tout ce que je peux t\'enseigner, $N$. Que les bénédictions de la Mère Terre te guident dans le choix d\'un animal de compagnie.$B$BVoici, $N$. Je vais maintenant te donner le pouvoir de dompter une bête, ainsi que de l\'appeler et de la renvoyer comme tu le jugeras bon. Utilise tes nouvelles compétences avec fierté et honore la Mère Terre.') ON DUPLICATE KEY UPDATE RewardText='Tu as appris tout ce que je peux t\'enseigner, $N$. Que les bénédictions de la Mère Terre te guident dans le choix d\'un animal de compagnie.$B$BVoici, $N$. Je vais maintenant te donner le pouvoir de dompter une bête, ainsi que de l\'appeler et de la renvoyer comme tu le jugeras bon. Utilise tes nouvelles compétences avec fierté et honore la Mère Terre.';
-- Quest 6089 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6089, 'frFR', 'Un jeune $c$, je vois. Oui, je peux t\'accorder les compétences dont tu as besoin pour entraîner et guider ton animal de compagnie. Non seulement tu pourras enseigner de nouvelles capacités à ton animal de compagnie, tu pourras maintenant aussi nourrir ton animal de compagnie, ainsi que le ressusciter, s\'il tombe au combat.$B$BSouviens-toi, $N$, de toujours respecter l\'équilibre et de vivre avec admiration la nature qui t\'entoure. Maintenant, pars. Nous parlerons à nouveau, à un moment ultérieur.') ON DUPLICATE KEY UPDATE RewardText='Un jeune $c$, je vois. Oui, je peux t\'accorder les compétences dont tu as besoin pour entraîner et guider ton animal de compagnie. Non seulement tu pourras enseigner de nouvelles capacités à ton animal de compagnie, tu pourras maintenant aussi nourrir ton animal de compagnie, ainsi que le ressusciter, s\'il tombe au combat.$B$BSouviens-toi, $N$, de toujours respecter l\'équilibre et de vivre avec admiration la nature qui t\'entoure. Maintenant, pars. Nous parlerons à nouveau, à un moment ultérieur.';
-- Quest 6101 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6101, 'frFR', 'Comprendre l\'équilibre entre la nature et soi-même est un mode de vie pour chaque $R$.') ON DUPLICATE KEY UPDATE CompletionText='Comprendre l\'équilibre entre la nature et soi-même est un mode de vie pour chaque $R$.';
-- Quest 6101 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6101, 'frFR', 'Je vois ton engagement et que tu as compris ce que je t\'ai enseigné, $N$.') ON DUPLICATE KEY UPDATE RewardText='Je vois ton engagement et que tu as compris ce que je t\'ai enseigné, $N$.';
-- Quest 6102 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6102, 'frFR', 'Je suis fier de tes accomplissements, $N$. As-tu terminé la dernière tâche que je t\'ai donnée?') ON DUPLICATE KEY UPDATE CompletionText='Je suis fier de tes accomplissements, $N$. As-tu terminé la dernière tâche que je t\'ai donnée?';
-- Quest 6102 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6102, 'frFR', 'Tu as appris tout ce que je peux t\'enseigner, $N$. Puis-je te donner un dernier conseil : fais preuve de discernement en choisissant ton premier animal de compagnie. Choisiras-tu une créature de la terre, de l\'eau ou du ciel? Quelle qu\'elle soit, sans aucun doute, ton animal de compagnie sera avec toi pendant un certain temps.$B$BVoici, $N$. Je vais maintenant te donner le pouvoir de dompter une bête, ainsi que de l\'appeler et de la renvoyer comme tu le jugeras bon. Utilise tes nouvelles compétences avec fierté; tu les as méritées.') ON DUPLICATE KEY UPDATE RewardText='Tu as appris tout ce que je peux t\'enseigner, $N$. Puis-je te donner un dernier conseil : fais preuve de discernement en choisissant ton premier animal de compagnie. Choisiras-tu une créature de la terre, de l\'eau ou du ciel? Quelle qu\'elle soit, sans aucun doute, ton animal de compagnie sera avec toi pendant un certain temps.$B$BVoici, $N$. Je vais maintenant te donner le pouvoir de dompter une bête, ainsi que de l\'appeler et de la renvoyer comme tu le jugeras bon. Utilise tes nouvelles compétences avec fierté; tu les as méritées.';
-- Quest 6103 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6103, 'frFR', 'Un novice $c$. Je vois. Oui. Je peux t\'accorder les compétences dont tu as besoin pour entraîner et guider ton animal de compagnie. Non seulement tu pourras enseigner de nouvelles capacités à ton animal de compagnie, tu pourras maintenant aussi nourrir ton animal de compagnie, ainsi que le ressusciter, s\'il tombe au combat.$B$BSouviens-toi, $N$, de toujours respecter l\'équilibre et de vivre avec admiration la nature qui t\'entoure. Maintenant, pars. Nous parlerons à nouveau, à un moment ultérieur.') ON DUPLICATE KEY UPDATE RewardText='Un novice $c$. Je vois. Oui. Je peux t\'accorder les compétences dont tu as besoin pour entraîner et guider ton animal de compagnie. Non seulement tu pourras enseigner de nouvelles capacités à ton animal de compagnie, tu pourras maintenant aussi nourrir ton animal de compagnie, ainsi que le ressusciter, s\'il tombe au combat.$B$BSouviens-toi, $N$, de toujours respecter l\'équilibre et de vivre avec admiration la nature qui t\'entoure. Maintenant, pars. Nous parlerons à nouveau, à un moment ultérieur.';

-- Quest 6122 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6122, 'frFR', 'Tu es celui que le Cercle de Cenarion à Moonglade a envoyé ? C\'est merveilleux ! Nous avons une crise assez sérieuse ici concernant les pauvres biches, et nous sommes heureux de toute l\'aide que nous pouvons obtenir.$B$As-tu l\'échantillon d\'eau que Dendrite Starblaze a dit que tu avais ? Il m\'a informé que tu en tirerais un pour que nous puissions travailler sur un remède ensemble...') ON DUPLICATE KEY UPDATE CompletionText='Tu es celui que le Cercle de Cenarion à Moonglade a envoyé ? C\'est merveilleux ! Nous avons une crise assez sérieuse ici concernant les pauvres biches, et nous sommes heureux de toute l\'aide que nous pouvons obtenir.$B$As-tu l\'échantillon d\'eau que Dendrite Starblaze a dit que tu avais ? Il m\'a informé que tu en tirerais un pour que nous puissions travailler sur un remède ensemble...';
-- Quest 6122 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6122, 'frFR', 'Par Elune, cette eau est dégoûtante ! Pas étonnant que les biches soient malades.$B$Quelque chose pollue l\'eau, et en retour, corrompt toute la nappe phréatique de Darkshore. Des biches malades ont été vues dans toute la zone, et pas seulement près de la rivière. Bien que cette eau soit très probablement une source principale de la maladie qui se propage, il y a autre chose à l\'œuvre.$B$Cette eau, croyez-le ou non, nous aidera à formuler un remède. Pendant que je recherche cette eau, j\'ai besoin de certains objets pour formuler un remède...') ON DUPLICATE KEY UPDATE RewardText='Par Elune, cette eau est dégoûtante ! Pas étonnant que les biches soient malades.$B$Quelque chose pollue l\'eau, et en retour, corrompt toute la nappe phréatique de Darkshore. Des biches malades ont été vues dans toute la zone, et pas seulement près de la rivière. Bien que cette eau soit très probablement une source principale de la maladie qui se propage, il y a autre chose à l\'œuvre.$B$Cette eau, croyez-le ou non, nous aidera à formuler un remède. Pendant que je recherche cette eau, j\'ai besoin de certains objets pour formuler un remède...';
-- Quest 6123 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6123, 'frFR', 'As-tu les réactifs dont j\'ai besoin pour faire le baume ? Les biches ne s\'améliorent pas seules, nous devons donc nous dépêcher de les aider !') ON DUPLICATE KEY UPDATE CompletionText='As-tu les réactifs dont j\'ai besoin pour faire le baume ? Les biches ne s\'améliorent pas seules, nous devons donc nous dépêcher de les aider !';
-- Quest 6123 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6123, 'frFR', 'C\'est bon, $N, tellement bon que cela devrait suffire à faire des doses suffisantes de baume - au moins assez pour commencer à faire une différence.$B$Créer un remède contre les poisons peut être assez difficile parfois parce que chacun nécessite souvent un antidote très spécifique pour le contrecarrer. Imagine pouvoir guérir un poison à volonté sans avoir à se soucier des ingrédients exacts de ce que l\'antidote doit être !$B$Maintenant, laisse-moi travailler là-dessus !') ON DUPLICATE KEY UPDATE RewardText='C\'est bon, $N, tellement bon que cela devrait suffire à faire des doses suffisantes de baume - au moins assez pour commencer à faire une différence.$B$Créer un remède contre les poisons peut être assez difficile parfois parce que chacun nécessite souvent un antidote très spécifique pour le contrecarrer. Imagine pouvoir guérir un poison à volonté sans avoir à se soucier des ingrédients exacts de ce que l\'antidote doit être !$B$Maintenant, laisse-moi travailler là-dessus !';
-- Quest 6124 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6124, 'frFR', 'As-tu accompli ce qu\'on t\'a demandé par Alanndarian Nightsong d\'Auberdine ? Ton travail n\'est pas complet tant qu\'il ne l\'est pas.') ON DUPLICATE KEY UPDATE CompletionText='As-tu accompli ce qu\'on t\'a demandé par Alanndarian Nightsong d\'Auberdine ? Ton travail n\'est pas complet tant qu\'il ne l\'est pas.';
-- Quest 6124 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6124, 'frFR', 'Tu as bien fait en prenant soin des biches malades de Darkshore ; elles sont des victimes involontaires d\'une plus grande souillure et corruption qui se répand dans tout le pays. Il y a ceux à Darnassus qui choisissent de reconnaître cette menace... et il y a ceux qui ignorent les signes croissants. J\'espère que tu ne seras pas celui qui mettra des bandeau sur ce qui te saute aux yeux, $N.$B$BQuoi qu\'il en soit, tu as prouvé ta valeur en tant qu\'ami de la nature et du Cercle - prends ceci comme un symbole de cela.') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait en prenant soin des biches malades de Darkshore ; elles sont des victimes involontaires d\'une plus grande souillure et corruption qui se répand dans tout le pays. Il y a ceux à Darnassus qui choisissent de reconnaître cette menace... et il y a ceux qui ignorent les signes croissants. J\'espère que tu ne seras pas celui qui mettra des bandeau sur ce qui te saute aux yeux, $N.$B$BQuoi qu\'il en soit, tu as prouvé ta valeur en tant qu\'ami de la nature et du Cercle - prends ceci comme un symbole de cela.';
-- Quest 6125 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6125, 'frFR', 'Bienvenue de retour - j\'ai suivi tes progrès dans cette leçon depuis ton départ, et je dois avouer que j\'ai été surpris d\'apprendre la situation à Auberdine. Cela mérite une enquête plus approfondie, car l\'introduction de tels poisons dans l\'environnement est très dérangeante pour l\'équilibre.$B$Tu t\'es comporté avec grâce sous la pression. Pour cela, je ne peux trouver de meilleure façon de te récompenser que par un pouvoir permanent sur le poison. Utilise-le bien, $N$... utilise-le bien.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue de retour - j\'ai suivi tes progrès dans cette leçon depuis ton départ, et je dois avouer que j\'ai été surpris d\'apprendre la situation à Auberdine. Cela mérite une enquête plus approfondie, car l\'introduction de tels poisons dans l\'environnement est très dérangeante pour l\'équilibre.$B$Tu t\'es comporté avec grâce sous la pression. Pour cela, je ne peux trouver de meilleure façon de te récompenser que par un pouvoir permanent sur le poison. Utilise-le bien, $N$... utilise-le bien.';
-- Quest 6127 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6127, 'frFR', 'Tu es celui que le Cercle de Cenarion à Moonglade a envoyé, n\'est-ce pas ? C\'est très fortuit pour nous ! Nous sommes bloqués dans notre effort pour apporter un équilibre aux gazelles malades qui errent dans les Barrens du Nord ; nous sommes heureux de toute l\'aide que nous pouvons obtenir.$B$As-tu l\'échantillon d\'eau que Dendrite Starblaze a dit que tu avais ? Il m\'a informé que tu en tirerais un pour que nous puissions travailler sur un remède ensemble...') ON DUPLICATE KEY UPDATE CompletionText='Tu es celui que le Cercle de Cenarion à Moonglade a envoyé, n\'est-ce pas ? C\'est très fortuit pour nous ! Nous sommes bloqués dans notre effort pour apporter un équilibre aux gazelles malades qui errent dans les Barrens du Nord ; nous sommes heureux de toute l\'aide que nous pouvons obtenir.$B$As-tu l\'échantillon d\'eau que Dendrite Starblaze a dit que tu avais ? Il m\'a informé que tu en tirerais un pour que nous puissions travailler sur un remède ensemble...';
-- Quest 6128 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6128, 'frFR', 'As-tu les réactifs dont j\'ai besoin pour faire le baume ? Les gazelles ne s\'améliorent pas seules, nous ne devons donc pas tarder dans notre effort pour les sauver !') ON DUPLICATE KEY UPDATE CompletionText='As-tu les réactifs dont j\'ai besoin pour faire le baume ? Les gazelles ne s\'améliorent pas seules, nous ne devons donc pas tarder dans notre effort pour les sauver !';
-- Quest 6129 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6129, 'frFR', 'As-tu accompli ce qu\'on t\'a demandé par Tonga Runetotem à la Croisée des chemins ? Ton travail n\'est pas complet tant qu\'il ne l\'est pas.') ON DUPLICATE KEY UPDATE CompletionText='As-tu accompli ce qu\'on t\'a demandé par Tonga Runetotem à la Croisée des chemins ? Ton travail n\'est pas complet tant qu\'il ne l\'est pas.';
-- Quest 6131 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6131, 'frFR', 'Nous souffrons beaucoup des événements du passé. Merci pour ce que tu as fait pour aider à protéger le Timbermaw.') ON DUPLICATE KEY UPDATE RewardText='Nous souffrons beaucoup des événements du passé. Merci pour ce que tu as fait pour aider à protéger le Timbermaw.';
-- Quest 6132 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6132, 'frFR', 'As-tu vu ma sœur Melizza ? Elle est toujours en mouvement, ce qui la met toujours dans le pétrin.') ON DUPLICATE KEY UPDATE CompletionText='As-tu vu ma sœur Melizza ? Elle est toujours en mouvement, ce qui la met toujours dans le pétrin.';
-- Quest 6135 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6135, 'frFR', 'Je ne recommanderais pas que tu prennes ce défi seul, $c.') ON DUPLICATE KEY UPDATE CompletionText='Je ne recommanderais pas que tu prennes ce défi seul, $c.';
-- Quest 6136 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6136, 'frFR', 'Est-ce que je t\'ai dit récemment que je te déteste ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce que je t\'ai dit récemment que je te déteste ?';
-- Quest 6143 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6143, 'frFR', 'J\'entends toujours leurs voix crier à l\'aide lorsque les naga ont déchaîné leur chaos sur nous. Si je n\'avais pas ce genou douloureux, j\'irais t\'aider à tuer ces maudits naga !$B$Tu peux généralement garantir de les trouver au plus profond des récifs coralliens sous la surface... rôdant... complotant...') ON DUPLICATE KEY UPDATE CompletionText='J\'entends toujours leurs voix crier à l\'aide lorsque les naga ont déchaîné leur chaos sur nous. Si je n\'avais pas ce genou douloureux, j\'irais t\'aider à tuer ces maudits naga !$B$Tu peux généralement garantir de les trouver au plus profond des récifs coralliens sous la surface... rôdant... complotant...';

-- Quest 6144 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6144, 'frFR', 'Le Grand Croisé siège dans la Bastion Écarlate tandis que ses forces déferlent sur vos terres, profanent vos structures et monuments et massacrent votre peuple.$B$BLa Dame Sombre souhaite régler cette mouche une fois pour toutes et je suis d\'accord. Vous deviendrez l\'instrument du châtiment de la Horde.') ON DUPLICATE KEY UPDATE RewardText='Le Grand Croisé siège dans la Bastion Écarlate tandis que ses forces déferlent sur vos terres, profanent vos structures et monuments et massacrent votre peuple.$B$BLa Dame Sombre souhaite régler cette mouche une fois pour toutes et je suis d\'accord. Vous deviendrez l\'instrument du châtiment de la Horde.';
-- Quest 6145 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6145, 'frFR', 'Réussissez maintenant et vous aurez presque gagné mon respect, $C.') ON DUPLICATE KEY UPDATE CompletionText='Réussissez maintenant et vous aurez presque gagné mon respect, $C.';
-- Quest 6145 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6145, 'frFR', '<Nathanos rit.>$B$BExcellent ! Enfin ! Une occasion de détruire l\'Oracle Écarlate !') ON DUPLICATE KEY UPDATE RewardText='<Nathanos rit.>$B$BExcellent ! Enfin ! Une occasion de détruire l\'Oracle Écarlate !';
-- Quest 6146 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6146, 'frFR', 'Où étais-tu ? Nous pensions que le Fléau t\'avait capturé.') ON DUPLICATE KEY UPDATE RewardText='Où étais-tu ? Nous pensions que le Fléau t\'avait capturé.';
-- Quest 6147 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6147, 'frFR', 'Les fous ! Mon subterfuge est passé inaperçu ! Prépare-toi, <class>. Nous devons frapper avec une ruse froide !') ON DUPLICATE KEY UPDATE RewardText='Les fous ! Mon subterfuge est passé inaperçu ! Prépare-toi, <class>. Nous devons frapper avec une ruse froide !';
-- Quest 6148 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6148, 'frFR', 'Ils seront secoués par ce coup pendant des années ! Bien fait, <name> ! Tu as gagné non seulement mon respect, mais aussi cette récompense.') ON DUPLICATE KEY UPDATE RewardText='Ils seront secoués par ce coup pendant des années ! Bien fait, <name> ! Tu as gagné non seulement mon respect, mais aussi cette récompense.';
-- Quest 6162 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6162, 'frFR', 'As-tu encore la griffe de la bête, $N ? Elle paiera pour ses crimes. Je me fiche qu\'elle soit corrompue ou juste en colère d\'avoir vécu dans une forêt aussi misérable. Aucun furbolg ne vivra longtemps en commettant de tels crimes contre ma famille !') ON DUPLICATE KEY UPDATE CompletionText='As-tu encore la griffe de la bête, $N ? Elle paiera pour ses crimes. Je me fiche qu\'elle soit corrompue ou juste en colère d\'avoir vécu dans une forêt aussi misérable. Aucun furbolg ne vivra longtemps en commettant de tels crimes contre ma famille !';
-- Quest 6163 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6163, 'frFR', 'Après que Sylvanas m\'a libéré, j\'ai traqué la bête à travers ces déserts pendant des mois. Elle s\'est enfuie dans la sécurité de Stratholme. Le bâtard...') ON DUPLICATE KEY UPDATE CompletionText='Après que Sylvanas m\'a libéré, j\'ai traqué la bête à travers ces déserts pendant des mois. Elle s\'est enfuie dans la sécurité de Stratholme. Le bâtard...';
-- Quest 6163 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6163, 'frFR', 'Je me demande... est-ce qu\'elle a imploré la pitié ? Pourrait-elle savoir ce qu\'est la pitié?$B$B$GNathanos crache.>$B$Je clouerai la tête de cette bête sur mon mur.$B<br :>Tu as mérité une place parmi l\'un de mes champions, <name.') ON DUPLICATE KEY UPDATE RewardText='Je me demande... est-ce qu\'elle a imploré la pitié ? Pourrait-elle savoir ce qu\'est la pitié?$B$B$GNathanos crache.>$B$Je clouerai la tête de cette bête sur mon mur.$B<br :>Tu as mérité une place parmi l\'un de mes champions, <name.';
-- Quest 6164 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6164, 'frFR', 'As-tu mon livre de reçus ? Je ne peux pas attendre pour reprendre le travail !') ON DUPLICATE KEY UPDATE CompletionText='As-tu mon livre de reçus ? Je ne peux pas attendre pour reprendre le travail !';
-- Quest 6164 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6164, 'frFR', 'La voilà ! Et oh là là ! J\'avais oublié comme il était plein !$B$BC\'est un jour glorieux, $N! Époustouflant ! Insanement bon, je dis !') ON DUPLICATE KEY UPDATE RewardText='La voilà ! Et oh là là ! J\'avais oublié comme il était plein !$B$BC\'est un jour glorieux, $N! Époustouflant ! Insanement bon, je dis !';
-- Quest 6187 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6187, 'frFR', 'C\'est une tragédie. Je crois... je crois que notre espèce est maudite, $Gname>. Nous sommes maudits de perdre nos plus grands guerriers ; nos héros les plus nobles ; nos érudits les plus doués.$B<br :>Nous te devons beaucoup et je t\'assure, <name, où que Nathanos Marris soit maintenant, il te regarde avec bienveillance.') ON DUPLICATE KEY UPDATE RewardText='C\'est une tragédie. Je crois... je crois que notre espèce est maudite, $Gname>. Nous sommes maudits de perdre nos plus grands guerriers ; nos héros les plus nobles ; nos érudits les plus doués.$B<br :>Nous te devons beaucoup et je t\'assure, <name, où que Nathanos Marris soit maintenant, il te regarde avec bienveillance.';
-- Quest 6241 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6241, 'frFR', 'Merci pour ce que tu as fait. S\'il te plaît, continue de nous aider, $N. Nous avons très peu d\'alliés sur lesquels nous pouvons compter.') ON DUPLICATE KEY UPDATE RewardText='Merci pour ce que tu as fait. S\'il te plaît, continue de nous aider, $N. Nous avons très peu d\'alliés sur lesquels nous pouvons compter.';
-- Quest 6282 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6282, 'frFR', 'Ne sois pas lassé de la Vallée des Cendres ; de nombreuses créatures maléfiques y résident. Reste fort $N, et tu triompheras de cette menace pour notre peuple. Pars maintenant et frappe fort - nos enfants ne connaîtront jamais le mal de ce qui fut.') ON DUPLICATE KEY UPDATE CompletionText='Ne sois pas lassé de la Vallée des Cendres ; de nombreuses créatures maléfiques y résident. Reste fort $N, et tu triompheras de cette menace pour notre peuple. Pars maintenant et frappe fort - nos enfants ne connaîtront jamais le mal de ce qui fut.';
-- Quest 6284 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6284, 'frFR', 'Besseleth est un prédateur impitoyable... Je crains pour ceux qui voyagent sur le Sentier de Webwinder la nuit. C\'est alors qu\'elle et ses enfants dévorent les voyageurs innocents. Moi-même, j\'ai été victime de sa fange de mort à deux pieds, mais heureusement, j\'ai réussi à me défendre et à atteindre la sécurité. Je donnerais tout pour voir ce monstre détruit.') ON DUPLICATE KEY UPDATE CompletionText='Besseleth est un prédateur impitoyable... Je crains pour ceux qui voyagent sur le Sentier de Webwinder la nuit. C\'est alors qu\'elle et ses enfants dévorent les voyageurs innocents. Moi-même, j\'ai été victime de sa fange de mort à deux pieds, mais heureusement, j\'ai réussi à me défendre et à atteindre la sécurité. Je donnerais tout pour voir ce monstre détruit.';

-- Quest 6284 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6284, 'frFR', 'Bonne chasse, <name>! Besseleth est un vieux prédateur dans ces parages... Je ne l\'oublierai pas. Prenez cette récompense comme un gage pour avoir été le champion de la forêt.$B$B$B$BPeut-être que beaucoup plus de gens se rendront au Refuge de Sun Rock sans craindre ce qui rôde dans l\'obscurité.') ON DUPLICATE KEY UPDATE RewardText='Bonne chasse, <name>! Besseleth est un vieux prédateur dans ces parages... Je ne l\'oublierai pas. Prenez cette récompense comme un gage pour avoir été le champion de la forêt.$B$B$B$BPeut-être que beaucoup plus de gens se rendront au Refuge de Sun Rock sans craindre ce qui rôde dans l\'obscurité.';
-- Quest 6301 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6301, 'frFR', 'La destruction continue causée par la guerre et par ceux qui tirent profit de l\'exploitation forestière me peine profondément. Pour aider le cycle de renaissance et reconstituer les terres, j\'ai besoin de graines de Gaea. Les avez-vous, $C?') ON DUPLICATE KEY UPDATE CompletionText='La destruction continue causée par la guerre et par ceux qui tirent profit de l\'exploitation forestière me peine profondément. Pour aider le cycle de renaissance et reconstituer les terres, j\'ai besoin de graines de Gaea. Les avez-vous, $C?';
-- Quest 6361 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6361, 'frFR', 'Êtes-vous ici pour un cavalier du vent? Avez-vous quelque chose à transporter?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous ici pour un cavalier du vent? Avez-vous quelque chose à transporter?';
-- Quest 6362 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6362, 'frFR', 'Il y a de la poussière sur vos épaules qui doit venir des Barrens. Avez-vous parlé à mon ami Jahan?') ON DUPLICATE KEY UPDATE CompletionText='Il y a de la poussière sur vos épaules qui doit venir des Barrens. Avez-vous parlé à mon ami Jahan?';
-- Quest 6363 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6363, 'frFR', 'Salutations, $C. Que puis-je faire pour vous?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $C. Que puis-je faire pour vous?';
-- Quest 6381 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6381, 'frFR', 'Ces graines que vous plantez sont fortes, résistantes à la corruption, et créent un point d\'appui pour d\'autres formes de vie. Elles pousseront et pousseront, d\'abord en empêchant la corruption et en guérissant la terre blessée, puis un jour, en restaurant Stonetalon à une forêt luxuriante, une fois de plus.$b$bAvez-vous planté toutes les graines de Gaea?') ON DUPLICATE KEY UPDATE CompletionText='Ces graines que vous plantez sont fortes, résistantes à la corruption, et créent un point d\'appui pour d\'autres formes de vie. Elles pousseront et pousseront, d\'abord en empêchant la corruption et en guérissant la terre blessée, puis un jour, en restaurant Stonetalon à une forêt luxuriante, une fois de plus.$b$bAvez-vous planté toutes les graines de Gaea?';
-- Quest 6381 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6381, 'frFR', 'C\'est une grande victoire pour la terre. Avec le temps, d\'autres choses se produiront : la Venture Co. rangera ses scies à gazon et ses haches, les esprits de feu en colère se calmeront, et les harpies seront chassées par la terre.$B$BCe n\'est qu\'alors $Gname> que Stonetalon sera vraiment en paix.$B<br :>Vous avez bien fait <class; prenez l\'un de ces objets en remerciement pour la nouvelle vie que vous avez créée aujourd\'hui.') ON DUPLICATE KEY UPDATE RewardText='C\'est une grande victoire pour la terre. Avec le temps, d\'autres choses se produiront : la Venture Co. rangera ses scies à gazon et ses haches, les esprits de feu en colère se calmeront, et les harpies seront chassées par la terre.$B$BCe n\'est qu\'alors $Gname> que Stonetalon sera vraiment en paix.$B<br :>Vous avez bien fait <class; prenez l\'un de ces objets en remerciement pour la nouvelle vie que vous avez créée aujourd\'hui.';
-- Quest 6383 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6383, 'frFR', 'Il y a trois créatures légendaires qui composent la Chasse d\'Ashenvale; vous pouvez les rechercher et vous tester contre leur ruse et leur puissance. Dans le processus, vous apprendrez peut-être quelque chose sur vous-même. Les créatures sont : l\'ours Ursangous, le chat sabreur nocturne Shadumbra, et l\'hippogryphe Sharptalon.$B$BLes créatures de la Chasse d\'Ashenvale sont puissantes, et vous pourriez avoir besoin d\'aide pour les abattre. Si vous parvenez à les vaincre, apportez-moi la preuve de votre exploit.') ON DUPLICATE KEY UPDATE RewardText='Il y a trois créatures légendaires qui composent la Chasse d\'Ashenvale; vous pouvez les rechercher et vous tester contre leur ruse et leur puissance. Dans le processus, vous apprendrez peut-être quelque chose sur vous-même. Les créatures sont : l\'ours Ursangous, le chat sabreur nocturne Shadumbra, et l\'hippogryphe Sharptalon.$B$BLes créatures de la Chasse d\'Ashenvale sont puissantes, et vous pourriez avoir besoin d\'aide pour les abattre. Si vous parvenez à les vaincre, apportez-moi la preuve de votre exploit.';
-- Quest 6389 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6389, 'frFR', 'L\'avez-vous fait, $N? Avez-vous libéré les termites? La Lumière nous aide si la Croisade Écarlate avait pu garder à la fois le moulin et Hearthglen. Ils ne devraient avoir ni l\'un ni l\'autre. Ils ne font que profiter des victimes de la dernière guerre et devraient être abattus comme des animaux rabides!') ON DUPLICATE KEY UPDATE CompletionText='L\'avez-vous fait, $N? Avez-vous libéré les termites? La Lumière nous aide si la Croisade Écarlate avait pu garder à la fois le moulin et Hearthglen. Ils ne devraient avoir ni l\'un ni l\'autre. Ils ne font que profiter des victimes de la dernière guerre et devraient être abattus comme des animaux rabides!';
-- Quest 6389 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6389, 'frFR', 'Haha! Merci, <name>! Vous l\'avez fait! L\'esprit de mon père peut maintenant reposer et je peux vivre en paix.$B$BMerci encore. S\'il y a quelque chose que je puisse faire pour vous, s\'il vous plaît, demandez.') ON DUPLICATE KEY UPDATE RewardText='Haha! Merci, <name>! Vous l\'avez fait! L\'esprit de mon père peut maintenant reposer et je peux vivre en paix.$B$BMerci encore. S\'il y a quelque chose que je puisse faire pour vous, s\'il vous plaît, demandez.';
-- Quest 6390 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6390, 'frFR', 'L\'avez-vous fait, $N? Avez-vous libéré les termites dans le moulin à bois?$B$BIl était déjà mauvais que ma famille perde son emploi et sa vie, mais voir l\'endroit où j\'ai passé mon enfance pris par ces soi-disant hommes saints dégoûtants... pfah!!') ON DUPLICATE KEY UPDATE CompletionText='L\'avez-vous fait, $N? Avez-vous libéré les termites dans le moulin à bois?$B$BIl était déjà mauvais que ma famille perde son emploi et sa vie, mais voir l\'endroit où j\'ai passé mon enfance pris par ces soi-disant hommes saints dégoûtants... pfah!!';
-- Quest 6390 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6390, 'frFR', 'Merci, <name>. Voici, prenez cette pièce. Je suis désolé que ce ne soit pas plus, mais essayez de trouver un peu de joie à aider à détruire les efforts de la Croisade Écarlate!') ON DUPLICATE KEY UPDATE RewardText='Merci, <name>. Voici, prenez cette pièce. Je suis désolé que ce ne soit pas plus, mais essayez de trouver un peu de joie à aider à détruire les efforts de la Croisade Écarlate!';
-- Quest 6394 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6394, 'frFR', 'Êtes-vous entré dans le Culte de la Lame Ardente, $N? Avez-vous trouvé mon pic?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous entré dans le Culte de la Lame Ardente, $N? Avez-vous trouvé mon pic?';
-- Quest 6395 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6395, 'frFR', 'Nous devons respecter nos morts, $N. C\'est l\'une des façons dont nous différons du Fléau...') ON DUPLICATE KEY UPDATE CompletionText='Nous devons respecter nos morts, $N. C\'est l\'une des façons dont nous différons du Fléau...';
-- Quest 6402 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6402, 'frFR', 'Avant de commencer, je vous demande d\'abord de rassembler une armée. Nous affrontons un dragon, après tout!') ON DUPLICATE KEY UPDATE RewardText='Avant de commencer, je vous demande d\'abord de rassembler une armée. Nous affrontons un dragon, après tout!';

-- Quest 6403 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6403, 'frFR', '<Bolvar tient le médaillon brisé.>$B$BLa magie qu\'il contient doit être rallumée. L\'œil du dragon doit être accordé.$B$BLe sacrifice de Windsor a libéré notre Royaume, mais la menace d\'Onyxia et de ses semblables plane toujours.$B$BCe médaillon est ce qui a retenu mon esprit et mon corps en captivité. C\'est aussi ce qui m\'a donné accès à l\'esprit d\'Onyxia elle-même - à ses secrets. Bien que les visions soient confuses maintenant, je me souviens de certaines choses.') ON DUPLICATE KEY UPDATE RewardText='<Bolvar tient le médaillon brisé.>$B$BLa magie qu\'il contient doit être rallumée. L\'œil du dragon doit être accordé.$B$BLe sacrifice de Windsor a libéré notre Royaume, mais la menace d\'Onyxia et de ses semblables plane toujours.$B$BCe médaillon est ce qui a retenu mon esprit et mon corps en captivité. C\'est aussi ce qui m\'a donné accès à l\'esprit d\'Onyxia elle-même - à ses secrets. Bien que les visions soient confuses maintenant, je me souviens de certaines choses.';
-- Quest 6441 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6441, 'frFR', 'J\'espère que tu pourras être rapide pour récupérer ces cornes, $N. Je retourne bientôt à Ratchet !') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que tu pourras être rapide pour récupérer ces cornes, $N. Je retourne bientôt à Ratchet !';
-- Quest 6441 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6441, 'frFR', 'C\'est parfait, <name>! Merci de m\'avoir aidé!$B$BOh, et ceci est pour ton temps...') ON DUPLICATE KEY UPDATE RewardText='C\'est parfait, <name>! Merci de m\'avoir aidé!$B$BOh, et ceci est pour ton temps...';
-- Quest 6461 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6461, 'frFR', 'Hey mon, as-tu abattu les mangeurs de sang poilus? Je ne crains personne ici à Stonetalon, mais je ne me promène pas ici la nuit... si tu vois ce que je veux dire mon!$b$bTant que je ne suis pas sur leur assiette, tout va bien.$b$bBonne chance à toi, $c!') ON DUPLICATE KEY UPDATE CompletionText='Hey mon, as-tu abattu les mangeurs de sang poilus? Je ne crains personne ici à Stonetalon, mais je ne me promène pas ici la nuit... si tu vois ce que je veux dire mon!$b$bTant que je ne suis pas sur leur assiette, tout va bien.$b$bBonne chance à toi, $c!';
-- Quest 6462 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6462, 'frFR', 'As-tu trouvé les charmes, $N? Chaque moment où les furbolgs possèdent ces objets sacrés, mon sang bout de rage!') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé les charmes, $N? Chaque moment où les furbolgs possèdent ces objets sacrés, mon sang bout de rage!';
-- Quest 6462 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6462, 'frFR', 'Tu les as trouvés!  Merci!  Merci, <name>!  Tu ne sais pas quel grand bien tu as fait pour moi.$B$BUn troll sans son charme est comme un orc sans ses cicatrices de bataille...$B$BSans valeur.') ON DUPLICATE KEY UPDATE RewardText='Tu les as trouvés!  Merci!  Merci, <name>!  Tu ne sais pas quel grand bien tu as fait pour moi.$B$BUn troll sans son charme est comme un orc sans ses cicatrices de bataille...$B$BSans valeur.';
-- Quest 6481 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6481, 'frFR', 'Je crains que si nous ne nous débarrassons pas de cette menace immédiatement, tout Stonetalon sera perdu. La puissance d\'un Earthen ne peut être égalée par aucun moyen. Une fois réveillé, Goggeroc sera faible de son long sommeil, ceci sera l\'opportunité que tu dois saisir... pars maintenant $N!') ON DUPLICATE KEY UPDATE CompletionText='Je crains que si nous ne nous débarrassons pas de cette menace immédiatement, tout Stonetalon sera perdu. La puissance d\'un Earthen ne peut être égalée par aucun moyen. Une fois réveillé, Goggeroc sera faible de son long sommeil, ceci sera l\'opportunité que tu dois saisir... pars maintenant $N!';
-- Quest 6481 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6481, 'frFR', 'Tu apportes de bonnes nouvelles, $Gclass>! Je crains les possibilités qu\'un Earthen pourrait représenter pour Kalimdor.$B<br :>Abattre Goggeroc était une tâche pour personne d\'autre qu\'un héros. Tu as bien fait; tout Stonetalon et Kalimdor te doivent, noble <class.$B$BAccepte ceci comme ta récompense, ô plus honoré.') ON DUPLICATE KEY UPDATE RewardText='Tu apportes de bonnes nouvelles, $Gclass>! Je crains les possibilités qu\'un Earthen pourrait représenter pour Kalimdor.$B<br :>Abattre Goggeroc était une tâche pour personne d\'autre qu\'un héros. Tu as bien fait; tout Stonetalon et Kalimdor te doivent, noble <class.$B$BAccepte ceci comme ta récompense, ô plus honoré.';
-- Quest 6482 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6482, 'frFR', 'As-tu vu mon frère Ruul? Il est entré dans la forêt il y a des jours et n\'est pas revenu...') ON DUPLICATE KEY UPDATE CompletionText='As-tu vu mon frère Ruul? Il est entré dans la forêt il y a des jours et n\'est pas revenu...';
-- Quest 6501 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6501, 'frFR', 'Je sens une aura de mal qui émane de toi, $R. Qu\'est-ce que tu pourrais tenir qui émet une telle aura?') ON DUPLICATE KEY UPDATE CompletionText='Je sens une aura de mal qui émane de toi, $R. Qu\'est-ce que tu pourrais tenir qui émet une telle aura?';
-- Quest 6501 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6501, 'frFR', 'J\'aurais dû le savoir - un morceau de la mère des dragons noirs, Onyxia. Comme c\'est révoltant...') ON DUPLICATE KEY UPDATE RewardText='J\'aurais dû le savoir - un morceau de la mère des dragons noirs, Onyxia. Comme c\'est révoltant...';
-- Quest 6502 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6502, 'frFR', 'Le flux du temps ne s\'arrête pas ni ne ralentit, $R. Alors que ma vie est éternelle, la tienne ne l\'est pas. Ne gaspille pas le temps que tu as...') ON DUPLICATE KEY UPDATE CompletionText='Le flux du temps ne s\'arrête pas ni ne ralentit, $R. Alors que ma vie est éternelle, la tienne ne l\'est pas. Ne gaspille pas le temps que tu as...';
-- Quest 6502 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6502, 'frFR', 'Cet amulet te donnera l\'accès que tu recherches. Le repaire d\'Onyxia peut être trouvé dans Dustwallow Marsh. Tant que tu tiens l\'amulette, ses gardes ne peuvent t\'empêcher d\'entrer.$B$BLe Vol Bleu te souhaite bonne chance, $N.') ON DUPLICATE KEY UPDATE RewardText='Cet amulet te donnera l\'accès que tu recherches. Le repaire d\'Onyxia peut être trouvé dans Dustwallow Marsh. Tant que tu tiens l\'amulette, ses gardes ne peuvent t\'empêcher d\'entrer.$B$BLe Vol Bleu te souhaite bonne chance, $N.';
-- Quest 6503 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6503, 'frFR', 'J\'attends des rapports de tes tueries d\'outrunners, $N.') ON DUPLICATE KEY UPDATE CompletionText='J\'attends des rapports de tes tueries d\'outrunners, $N.';
-- Quest 6504 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6504, 'frFR', 'J\'espère que tu trouveras les pages bientôt, $N! J\'ai vraiment besoin de retourner au travail!') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que tu trouveras les pages bientôt, $N! J\'ai vraiment besoin de retourner au travail!';

-- Quest 6504 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6504, 'frFR', 'La lecture n\'est pas mon fort... mais maintenant je pourrai retourner au travail ! Merci, <name>!') ON DUPLICATE KEY UPDATE RewardText='La lecture n\'est pas mon fort... mais maintenant je pourrai retourner au travail ! Merci, <name>!';
-- Quest 6521 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6521, 'frFR', 'Avez-vous trouvé l\'Ambassadeur, $N? Est-il mort?$B$BNous ne pouvons pas nous permettre de laisser le Fléau prendre pied à Kalimdor. Ils représentent une menace suffisante pour nos propres frontières pour que nous devions nous en occuper sur deux fronts.$B$BLe seul signe optimiste des événements que vous m\'avez rapportés est que la vieille femme semblait non corrompue. Elle doit savoir au plus profond de son être que le Fléau peut apporter un grand pouvoir, mais que les Barrens ne lui appartiennent pas vraiment si elle acceptait leur accord.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé l\'Ambassadeur, $N? Est-il mort?$B$BNous ne pouvons pas nous permettre de laisser le Fléau prendre pied à Kalimdor. Ils représentent une menace suffisante pour nos propres frontières pour que nous devions nous en occuper sur deux fronts.$B$BLe seul signe optimiste des événements que vous m\'avez rapportés est que la vieille femme semblait non corrompue. Elle doit savoir au plus profond de son être que le Fléau peut apporter un grand pouvoir, mais que les Barrens ne lui appartiennent pas vraiment si elle acceptait leur accord.';
-- Quest 6521 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6521, 'frFR', 'Bien. Bien joué, <class>.$B$BMaintenant que Malcin est mort, nous savons au moins que l\'avancée des Fléaux sera stoppée. Je vous remercie de vos efforts et souhaite vous récompenser avec un cadeau.$B$BBien que nous ne connaissions pas l\'étendue de l\'influence des Fléaux dans les Downs, je suis sûr que nous découvrirons leurs complots assez rapidement.') ON DUPLICATE KEY UPDATE RewardText='Bien. Bien joué, <class>.$B$BMaintenant que Malcin est mort, nous savons au moins que l\'avancée des Fléaux sera stoppée. Je vous remercie de vos efforts et souhaite vous récompenser avec un cadeau.$B$BBien que nous ne connaissions pas l\'étendue de l\'influence des Fléaux dans les Downs, je suis sûr que nous découvrirons leurs complots assez rapidement.';
-- Quest 6522 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6522, 'frFR', 'De quoi souhaitez-vous parler, $N? Vous devez penser que c\'est important si vous continuez à me harceler.') ON DUPLICATE KEY UPDATE CompletionText='De quoi souhaitez-vous parler, $N? Vous devez penser que c\'est important si vous continuez à me harceler.';
-- Quest 6541 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6541, 'frFR', 'Ashenvale est une terre divisée, mais nos efforts les plus récents ont été très réussis. Nous avons non seulement un avant-poste à Zoram Strand, mais un autre juste au nord d\'ici appelé Splintertree.') ON DUPLICATE KEY UPDATE RewardText='Ashenvale est une terre divisée, mais nos efforts les plus récents ont été très réussis. Nous avons non seulement un avant-poste à Zoram Strand, mais un autre juste au nord d\'ici appelé Splintertree.';
-- Quest 6542 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6542, 'frFR', 'Ashenvale est une terre divisée, mais nos efforts les plus récents ont été très réussis. Nous avons non seulement un avant-poste à Zoram Strand, mais un autre juste au nord d\'ici appelé Splintertree.') ON DUPLICATE KEY UPDATE RewardText='Ashenvale est une terre divisée, mais nos efforts les plus récents ont été très réussis. Nous avons non seulement un avant-poste à Zoram Strand, mais un autre juste au nord d\'ici appelé Splintertree.';
-- Quest 6544 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6544, 'frFR', 'Torek a été envoyé en mission contre l\'Avant-poste de Silverwing. L\'attaque a-t-elle réussi ?') ON DUPLICATE KEY UPDATE CompletionText='Torek a été envoyé en mission contre l\'Avant-poste de Silverwing. L\'attaque a-t-elle réussi ?';
-- Quest 6545 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6545, 'frFR', 'Alors vous êtes ici sur mes ordres ? C\'est toujours bon de voir un nouveau recrue avec une nature exubérante et une volonté forte.$B$BVous feriez mieux d\'apprendre vite si vous voulez suivre le rythme ici. La menace des naga grandit, $N. J\'ai observé et j\'ai mis en place des défenses contre plusieurs attaques sur cet avant-poste depuis mon arrivée ici.$B$BMais si vous souhaitez participer à cet effort, parlez à l\'un des autres ici à l\'avant-poste.') ON DUPLICATE KEY UPDATE CompletionText='Alors vous êtes ici sur mes ordres ? C\'est toujours bon de voir un nouveau recrue avec une nature exubérante et une volonté forte.$B$BVous feriez mieux d\'apprendre vite si vous voulez suivre le rythme ici. La menace des naga grandit, $N. J\'ai observé et j\'ai mis en place des défenses contre plusieurs attaques sur cet avant-poste depuis mon arrivée ici.$B$BMais si vous souhaitez participer à cet effort, parlez à l\'un des autres ici à l\'avant-poste.';
-- Quest 6545 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6545, 'frFR', 'Eh bien, ma mise à jour expliquera tout cela à Kadrak. Vous devez lui rendre ceci le plus rapidement possible.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, ma mise à jour expliquera tout cela à Kadrak. Vous devez lui rendre ceci le plus rapidement possible.';
-- Quest 6546 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6546, 'frFR', 'Beaucoup de danger se trouve le long de ce chemin, $N. Vous feriez mieux de vous en souvenir en voyageant dans ces terres. La menace de l\'alliance est très proche.$B$BNous sommes confrontés à des ennemis sur tous les fronts. Les satyres sont une force formidable et prévalente dans l\'est d\'Ashenvale. J\'ai également découvert que les naga ont pris possession d\'une grande partie du territoire d\'Azshara.$B$BC\'est bon de voir que nous renforcions toujours nos effectifs -- soyez prêt pour ce qui vient, $N.') ON DUPLICATE KEY UPDATE CompletionText='Beaucoup de danger se trouve le long de ce chemin, $N. Vous feriez mieux de vous en souvenir en voyageant dans ces terres. La menace de l\'alliance est très proche.$B$BNous sommes confrontés à des ennemis sur tous les fronts. Les satyres sont une force formidable et prévalente dans l\'est d\'Ashenvale. J\'ai également découvert que les naga ont pris possession d\'une grande partie du territoire d\'Azshara.$B$BC\'est bon de voir que nous renforcions toujours nos effectifs -- soyez prêt pour ce qui vient, $N.';
-- Quest 6546 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6546, 'frFR', 'Transmettez ma mise à jour à Kadrak. Rapidement, <name>.') ON DUPLICATE KEY UPDATE RewardText='Transmettez ma mise à jour à Kadrak. Rapidement, <name>.';
-- Quest 6547 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6547, 'frFR', 'Gardez l\'œil ouvert, $R. Les elfes se cachent souvent dans l\'ombre...$B$BNous devons toujours être vigilants. Nous avons travaillé très dur pour revendiquer cette terre, et les elfes cherchent une chance pour nous la prendre. $B$Je suppose que vous avez mes ordres suivants de Kadrak ?') ON DUPLICATE KEY UPDATE CompletionText='Gardez l\'œil ouvert, $R. Les elfes se cachent souvent dans l\'ombre...$B$BNous devons toujours être vigilants. Nous avons travaillé très dur pour revendiquer cette terre, et les elfes cherchent une chance pour nous la prendre. $B$Je suppose que vous avez mes ordres suivants de Kadrak ?';
-- Quest 6547 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6547, 'frFR', 'Faites savoir à Kadrak le succès que nous avons eu ici en repoussant les elfes de la nuit. Nos plans se déroulent bien.') ON DUPLICATE KEY UPDATE RewardText='Faites savoir à Kadrak le succès que nous avons eu ici en repoussant les elfes de la nuit. Nos plans se déroulent bien.';
-- Quest 6561 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6561, 'frFR', 'Que la Mère Terre soit avec vous, $N.$B$BLa paix entre la terre et tout son peuple devrait être notre objectif. Elle a un grand plan pour la nature, et nous avons tous un rôle à jouer dans ce plan.') ON DUPLICATE KEY UPDATE CompletionText='Que la Mère Terre soit avec vous, $N.$B$BLa paix entre la terre et tout son peuple devrait être notre objectif. Elle a un grand plan pour la nature, et nous avons tous un rôle à jouer dans ce plan.';
-- Quest 6563 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6563, 'frFR', 'Comment se passe votre recherche des cristaux, $N? Avez-vous vu les naga les récolter ? Je prie mes ancêtres que nous trouvions la raison pour laquelle ils collectent de telles choses.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe votre recherche des cristaux, $N? Avez-vous vu les naga les récolter ? Je prie mes ancêtres que nous trouvions la raison pour laquelle ils collectent de telles choses.';

-- Quest 6564 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6564, 'frFR', 'Oui, $N$? Qu\'est-ce qu\'il vous faut ? Il y a encore beaucoup de choses que je dois apprendre sur les cristaux que les naga sont en train de rassembler.') ON DUPLICATE KEY UPDATE CompletionText='Oui, $N$? Qu\'est-ce qu\'il vous faut ? Il y a encore beaucoup de choses que je dois apprendre sur les cristaux que les naga sont en train de rassembler.';
-- Quest 6565 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6565, 'frFR', 'L\'as-tu trouvé, $N$? Lorgus doit être arrêté !') ON DUPLICATE KEY UPDATE CompletionText='L\'as-tu trouvé, $N$? Lorgus doit être arrêté !';
-- Quest 6566 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6566, 'frFR', 'Es-tu prêt à accepter cette tâche ?') ON DUPLICATE KEY UPDATE RewardText='Es-tu prêt à accepter cette tâche ?';
-- Quest 6567 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6567, 'frFR', 'Il n\'y a qu\'un seul chemin vers la tanière du dragon, $R.$B$BTu vois, seuls les plus forts de la Volée du Dragon Noir ont le droit d\'entrer dans la tanière de la mère des couvées. De nombreux essais doivent être réussis et la clé d\'entrée est cérémoniellement enchantée par le Général Drakkisath lui-même !$B$BS\'il ne fait pas partie des dragonniques noirs, tu pourrais avoir des difficultés à obtenir le passage.$B$B<Rexxar sourit.>') ON DUPLICATE KEY UPDATE RewardText='Il n\'y a qu\'un seul chemin vers la tanière du dragon, $R.$B$BTu vois, seuls les plus forts de la Volée du Dragon Noir ont le droit d\'entrer dans la tanière de la mère des couvées. De nombreux essais doivent être réussis et la clé d\'entrée est cérémoniellement enchantée par le Général Drakkisath lui-même !$B$BS\'il ne fait pas partie des dragonniques noirs, tu pourrais avoir des difficultés à obtenir le passage.$B$B<Rexxar sourit.>';
-- Quest 6568 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6568, 'frFR', 'Ce n\'est pas souvent que je vois un membre de la Horde dans ces régions de Lordaeron. Qu\'as-tu pour Myranda ?') ON DUPLICATE KEY UPDATE CompletionText='Ce n\'est pas souvent que je vois un membre de la Horde dans ces régions de Lordaeron. Qu\'as-tu pour Myranda ?';
-- Quest 6568 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6568, 'frFR', '<Myranda tient la note, fait une pause, puis sourit.>$B$BComment va-t-il ? Rexxar, je veux dire. Oh, allez, ne sois pas si confus. La lettre était intentionnellement laissée vide. Elle portait les intentions et les pensées de son créateur. À en juger par son contenu, il n\'est pas étonnant que Rexxar l\'ait laissée ainsi. Imagine si tu avais été capturé ou tué et que cette information était découverte !$B$BOh, oublie ! Myranda t\'aidera, $R. Je dois une faveur ou deux au Chef de Guerre.$B$B<Myranda sourit.>') ON DUPLICATE KEY UPDATE RewardText='<Myranda tient la note, fait une pause, puis sourit.>$B$BComment va-t-il ? Rexxar, je veux dire. Oh, allez, ne sois pas si confus. La lettre était intentionnellement laissée vide. Elle portait les intentions et les pensées de son créateur. À en juger par son contenu, il n\'est pas étonnant que Rexxar l\'ait laissée ainsi. Imagine si tu avais été capturé ou tué et que cette information était découverte !$B$BOh, oublie ! Myranda t\'aidera, $R. Je dois une faveur ou deux au Chef de Guerre.$B$B<Myranda sourit.>';
-- Quest 6569 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6569, 'frFR', 'Les yeux de ce que nous souhaitons imiter sont l\'ingrédient le plus important de toute illusion, $N.$B$B<Myranda pointe un sac presque débordant d\'yeux étiquetés \'Croisade Scarlate.\'>$B$B<Myranda rit.>') ON DUPLICATE KEY UPDATE CompletionText='Les yeux de ce que nous souhaitons imiter sont l\'ingrédient le plus important de toute illusion, $N.$B$B<Myranda pointe un sac presque débordant d\'yeux étiquetés \'Croisade Scarlate.\'>$B$B<Myranda rit.>';
-- Quest 6569 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6569, 'frFR', 'Laisse Myranda jeter un œil, $R.$B$BOh oui, ceux-ci feront l\'affaire.$B$BAvec ces réactifs, Myranda créera pour toi un médaillon qui donnera une illusion capable de tromper le gardien de la volée du dragon noir.') ON DUPLICATE KEY UPDATE RewardText='Laisse Myranda jeter un œil, $R.$B$BOh oui, ceux-ci feront l\'affaire.$B$BAvec ces réactifs, Myranda créera pour toi un médaillon qui donnera une illusion capable de tromper le gardien de la volée du dragon noir.';
-- Quest 6570 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6570, 'frFR', 'Avons-nous si peu de soldats capables que Nefarian m\'envoie des gamins ? Tu ne réussiras jamais mes tests, petit couvaison.') ON DUPLICATE KEY UPDATE RewardText='Avons-nous si peu de soldats capables que Nefarian m\'envoie des gamins ? Tu ne réussiras jamais mes tests, petit couvaison.';
-- Quest 6581 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6581, 'frFR', 'Direct de Ratchet, les lames de la Guerre des Songes ! Oui, je les ai juste ici.$B$B..Mais quel genre de paiement as-tu pour moi ? Tu ne peux pas juste les prendre, tu sais ! Mon temps n\'est pas bon marché !$B$BCe dont j\'ai vraiment besoin, c\'est d\'un bon pistolet à emporter avec moi lors de mes voyages. Une fille doit se protéger, tu sais ? Il y a un pistolet que j\'aime vraiment et je suis sûr qu\'un ingénieur ne craindra pas de le fabriquer.$B$BAlors, si tu m\'apportes un blunderbuss mortel, je te donnerai l\'envoi de lames. On est d\'accord ?') ON DUPLICATE KEY UPDATE CompletionText='Direct de Ratchet, les lames de la Guerre des Songes ! Oui, je les ai juste ici.$B$B..Mais quel genre de paiement as-tu pour moi ? Tu ne peux pas juste les prendre, tu sais ! Mon temps n\'est pas bon marché !$B$BCe dont j\'ai vraiment besoin, c\'est d\'un bon pistolet à emporter avec moi lors de mes voyages. Une fille doit se protéger, tu sais ? Il y a un pistolet que j\'aime vraiment et je suis sûr qu\'un ingénieur ne craindra pas de le fabriquer.$B$BAlors, si tu m\'apportes un blunderbuss mortel, je te donnerai l\'envoi de lames. On est d\'accord ?';
-- Quest 6581 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6581, 'frFR', 'C\'est parfait -- juste ce qu\'il faut ! Eh bien, voici l\'envoi.') ON DUPLICATE KEY UPDATE RewardText='C\'est parfait -- juste ce qu\'il faut ! Eh bien, voici l\'envoi.';
-- Quest 6583 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6583, 'frFR', 'Ne reviens pas ici tant que tu n\'as pas baigné dans le sang de nos ennemis et bu de leur souffrance.') ON DUPLICATE KEY UPDATE CompletionText='Ne reviens pas ici tant que tu n\'as pas baigné dans le sang de nos ennemis et bu de leur souffrance.';
-- Quest 6584 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6584, 'frFR', 'Ironiquement, petit couvaison, le temps est essentiel.') ON DUPLICATE KEY UPDATE CompletionText='Ironiquement, petit couvaison, le temps est essentiel.';
-- Quest 6585 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6585, 'frFR', 'Changesss... Je les sens se dérouler en toi, petit couvaison. Passe ce test et seule la cérémonie reste.') ON DUPLICATE KEY UPDATE CompletionText='Changesss... Je les sens se dérouler en toi, petit couvaison. Passe ce test et seule la cérémonie reste.';
-- Quest 6585 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6585, 'frFR', 'J\'avais douté de ton dévouement, petit couvaison. Tu as persisté, dominant nos ennemis, apportant de l\'honneur à notre volée.$B$BJe dois maintenant préparer les crânes pour ton ascension.') ON DUPLICATE KEY UPDATE RewardText='J\'avais douté de ton dévouement, petit couvaison. Tu as persisté, dominant nos ennemis, apportant de l\'honneur à notre volée.$B$BJe dois maintenant préparer les crânes pour ton ascension.';

-- Quest 6601 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6601, 'frFR', 'Ce n\'est que du bavardage de dragon, $N - plus de vent chaud que d\'informations substantielles. Un comportement pompeux et agressif est à attendre de leur espèce.') ON DUPLICATE KEY UPDATE RewardText='Ce n\'est que du bavardage de dragon, $N - plus de vent chaud que d\'informations substantielles. Un comportement pompeux et agressif est à attendre de leur espèce.';
-- Quest 6602 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6602, 'frFR', 'Je ne pense pas que je doive te dire que Drakkisath ne doit pas être pris à la légère.$B$BI que les milliers de morts à sa main parlent.') ON DUPLICATE KEY UPDATE CompletionText='Je ne pense pas que je doive te dire que Drakkisath ne doit pas être pris à la légère.$B$BI que les milliers de morts à sa main parlent.';
-- Quest 6602 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6602, 'frFR', 'Une victoire qui sera mémorisée pendant de nombreuses années, $N. Le pendentif de feu de dragon ouvrira le repaire d\'Onyxia. Rassemble tes alliés et apporte la victoire à la Horde.') ON DUPLICATE KEY UPDATE RewardText='Une victoire qui sera mémorisée pendant de nombreuses années, $N. Le pendentif de feu de dragon ouvrira le repaire d\'Onyxia. Rassemble tes alliés et apporte la victoire à la Horde.';
-- Quest 6606 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6606, 'frFR', 'Ah, alors Harlo t\'envoie ? Eh bien, alors, qui es-tu ? Je suppose que tu veux mon aide ?') ON DUPLICATE KEY UPDATE RewardText='Ah, alors Harlo t\'envoie ? Eh bien, alors, qui es-tu ? Je suppose que tu veux mon aide ?';
-- Quest 6610 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6610, 'frFR', 'Mes envies vont me tuer ! Dépêche-toi, $N - avant que je ne puise dans mes propres réserves.') ON DUPLICATE KEY UPDATE CompletionText='Mes envies vont me tuer ! Dépêche-toi, $N - avant que je ne puise dans mes propres réserves.';
-- Quest 6621 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6621, 'frFR', 'As-tu vaincu le chef Murgut, $N ? As-tu récupéré son Totem de Foulweald ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu vaincu le chef Murgut, $N ? As-tu récupéré son Totem de Foulweald ?';
-- Quest 6626 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6626, 'frFR', 'Comment se passe la chasse, $N ? Voir juste ce petit échantillon du pouvoir de ce diplomate ici enlève tout doute que j\'avais sur le fait que les Scourge sont l\'une des plus grandes menaces que ce monde ait jamais vue.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe la chasse, $N ? Voir juste ce petit échantillon du pouvoir de ce diplomate ici enlève tout doute que j\'avais sur le fait que les Scourge sont l\'une des plus grandes menaces que ce monde ait jamais vue.';
-- Quest 6626 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6626, 'frFR', 'Merci, <name>! Le travail que tu as accompli sera d\'une grande aide, je suis sûr.$B$BI continuerai mon étude de ce diplomate et du reste des quilboar ici. Si tu cherches une aventure plus grande, je trouverais quelques amis et irais dans la caverne qui ressemble à une grande gueule de porc juste là. Je suis sûr qu\'une fois à l\'intérieur, tu trouveras des défis plus grands à relever.') ON DUPLICATE KEY UPDATE RewardText='Merci, <name>! Le travail que tu as accompli sera d\'une grande aide, je suis sûr.$B$BI continuerai mon étude de ce diplomate et du reste des quilboar ici. Si tu cherches une aventure plus grande, je trouverais quelques amis et irais dans la caverne qui ressemble à une grande gueule de porc juste là. Je suis sûr qu\'une fois à l\'intérieur, tu trouveras des défis plus grands à relever.';
-- Quest 6627 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6627, 'frFR', 'La vie est pleine de questions, $C. Tu ne pourras jamais y répondre toutes, mais avec un peu de temps et d\'étude, peut-être deviendras-tu un peu plus savant.') ON DUPLICATE KEY UPDATE CompletionText='La vie est pleine de questions, $C. Tu ne pourras jamais y répondre toutes, mais avec un peu de temps et d\'étude, peut-être deviendras-tu un peu plus savant.';
-- Quest 6628 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6628, 'frFR', 'Il n\'y a qu\'une seule règle que je crois que tu dois connaître si tu souhaites survivre dans ce monde : plus tu sais, plus tu verras.$b$bSi tu étudies, si tu observes, alors tu commenceras à voir des choses dans le monde que personne d\'autre ne verra.') ON DUPLICATE KEY UPDATE CompletionText='Il n\'y a qu\'une seule règle que je crois que tu dois connaître si tu souhaites survivre dans ce monde : plus tu sais, plus tu verras.$b$bSi tu étudies, si tu observes, alors tu commenceras à voir des choses dans le monde que personne d\'autre ne verra.';
-- Quest 6629 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6629, 'frFR', 'As-tu tué Grundig Darkcloud et sa bande personnelle de Brutes ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu tué Grundig Darkcloud et sa bande personnelle de Brutes ?';
-- Quest 6642 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6642, 'frFR', 'Le fer noir, bien que abondant dans les profondeurs, est toujours une marchandise précieuse parmi les Frères. Les armes et armements sacrés de Ragnaros favorisent le fer noir.$B$BPour chaque 10 pièces de minerai de fer noir que tu offres, tu gagneras une faveur parmi les Frères.') ON DUPLICATE KEY UPDATE CompletionText='Le fer noir, bien que abondant dans les profondeurs, est toujours une marchandise précieuse parmi les Frères. Les armes et armements sacrés de Ragnaros favorisent le fer noir.$B$BPour chaque 10 pièces de minerai de fer noir que tu offres, tu gagneras une faveur parmi les Frères.';
-- Quest 6643 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6643, 'frFR', 'Malheur à ceux qui tentent le destin à l\'intérieur du Cœur Molten. La mort vient vite - la punition est infligée sans pitié.$B$BBeaucoup des Frères ont été perdus dans leur recherche de Cœurs de Feu.$B$BOffre 1 Cœur de Feu et tu seras honoré parmi les Frères.') ON DUPLICATE KEY UPDATE CompletionText='Malheur à ceux qui tentent le destin à l\'intérieur du Cœur Molten. La mort vient vite - la punition est infligée sans pitié.$B$BBeaucoup des Frères ont été perdus dans leur recherche de Cœurs de Feu.$B$BOffre 1 Cœur de Feu et tu seras honoré parmi les Frères.';

-- Quest 6644 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6644, 'frFR', 'La Fraternité du Thorium sympathise avec votre détresse, $r. C\'est pourquoi Lokthos a été habilité à négocier.$B$BOffrez 1 Cœur de Lave et vous recevrez la faveur de la Fraternité.') ON DUPLICATE KEY UPDATE CompletionText='La Fraternité du Thorium sympathise avec votre détresse, $r. C\'est pourquoi Lokthos a été habilité à négocier.$B$BOffrez 1 Cœur de Lave et vous recevrez la faveur de la Fraternité.';
-- Quest 6645 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6645, 'frFR', 'Beaucoup des recettes sacrées nécessitent la peau des animaux de compagnie choisis par Ragnaros.$B$BOffrez 2 Cuir de Cœur, peauné des cadavres fumants des Chiens de Cœur du Cœur Molten et vous recevrez la faveur de la Fraternité.') ON DUPLICATE KEY UPDATE CompletionText='Beaucoup des recettes sacrées nécessitent la peau des animaux de compagnie choisis par Ragnaros.$B$BOffrez 2 Cuir de Cœur, peauné des cadavres fumants des Chiens de Cœur du Cœur Molten et vous recevrez la faveur de la Fraternité.';
-- Quest 6646 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6646, 'frFR', 'Les larmes du Seigneur de Feu sont une trouvaille rare en effet.$B$BOffrez 1 Sang de la Montagne et vous recevrez la faveur de la Fraternité.') ON DUPLICATE KEY UPDATE CompletionText='Les larmes du Seigneur de Feu sont une trouvaille rare en effet.$B$BOffrez 1 Sang de la Montagne et vous recevrez la faveur de la Fraternité.';
-- Quest 6646 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6646, 'frFR', 'Votre offrande a été acceptée. La faveur que vous avez gagnée. Continuez et vous aurez accès aux anciens métiers.') ON DUPLICATE KEY UPDATE RewardText='Votre offrande a été acceptée. La faveur que vous avez gagnée. Continuez et vous aurez accès aux anciens métiers.';
-- Quest 6681 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6681, 'frFR', 'Très excellent, jeune voleur.$B$BVous avez l\'air un peu abîmé, mais pas plus pour le port.$B$Un long voyage vous attend - long et gratifiant. Êtes-vous prêt à embrasser votre destin parmi les maîtres de Ravenholdt?$B$Parlez avec les gardes à l\'extérieur. Ils vous mettront sur la bonne voie.') ON DUPLICATE KEY UPDATE RewardText='Très excellent, jeune voleur.$B$BVous avez l\'air un peu abîmé, mais pas plus pour le port.$B$Un long voyage vous attend - long et gratifiant. Êtes-vous prêt à embrasser votre destin parmi les maîtres de Ravenholdt?$B$Parlez avec les gardes à l\'extérieur. Ils vous mettront sur la bonne voie.';
-- Quest 6701 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6701, 'frFR', 'Nous sommes en embuscade dans une bataille avec le Syndicat depuis des années. Ce qui leur manque en compétence, ils le compensent en nombre. Il est impossible de les tuer assez vite pour avoir un impact notable sur leur population !$B$Nous avons découvert que le meilleur moyen de gérer leur taille est de dérober leurs emblèmes. Une fois qu\'un emblème est volé, le membre honteux est \'traité\' en interne.$B$Videz leurs poches et remettez les emblèmes à moi ou à l\'un des autres gardes.$B$Commencez à Durnholde, au sud d\'ici.') ON DUPLICATE KEY UPDATE CompletionText='Nous sommes en embuscade dans une bataille avec le Syndicat depuis des années. Ce qui leur manque en compétence, ils le compensent en nombre. Il est impossible de les tuer assez vite pour avoir un impact notable sur leur population !$B$Nous avons découvert que le meilleur moyen de gérer leur taille est de dérober leurs emblèmes. Une fois qu\'un emblème est volé, le membre honteux est \'traité\' en interne.$B$Videz leurs poches et remettez les emblèmes à moi ou à l\'un des autres gardes.$B$Commencez à Durnholde, au sud d\'ici.';
-- Quest 6701 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6701, 'frFR', 'Hé, bon travail ! Continuez comme ça et les autres voleurs pourraient arrêter de vous cracher dessus.') ON DUPLICATE KEY UPDATE RewardText='Hé, bon travail ! Continuez comme ça et les autres voleurs pourraient arrêter de vous cracher dessus.';
-- Quest 6741 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6741, 'frFR', 'J\'ai besoin de plus de morceaux d\'armure, $N! En avez-vous ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ai besoin de plus de morceaux d\'armure, $N! En avez-vous ?';
-- Quest 6781 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6781, 'frFR', '$N, nous avons besoin de plus de morceaux d\'armure pour approvisionner nos troupes !') ON DUPLICATE KEY UPDATE CompletionText='$N, nous avons besoin de plus de morceaux d\'armure pour approvisionner nos troupes !';
-- Quest 6801 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6801, 'frFR', 'Je viens de Thunder Bluff, $r. Cairne lui-même a veillé à ce que j\'aide le Clan des Loups de Glace en ces temps difficiles.$b$bMais ne perdons plus de temps. Vous devez abattre nos ennemis et m\'apporter leur sang. Une fois qu\'assez de sang a été recueilli, le rituel d\'invocation peut commencer.$b$bLa victoire sera assurée lorsque le seigneur élémentaire sera relâché sur l\'armée de Stormpike.') ON DUPLICATE KEY UPDATE CompletionText='Je viens de Thunder Bluff, $r. Cairne lui-même a veillé à ce que j\'aide le Clan des Loups de Glace en ces temps difficiles.$b$bMais ne perdons plus de temps. Vous devez abattre nos ennemis et m\'apporter leur sang. Une fois qu\'assez de sang a été recueilli, le rituel d\'invocation peut commencer.$b$bLa victoire sera assurée lorsque le seigneur élémentaire sera relâché sur l\'armée de Stormpike.';
-- Quest 6804 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6804, 'frFR', 'Vous avez bien fait, $c. Les élémentaires corrompus que vous avez guéris étaient une outrage à tous les corps d\'eau. Notre force réside dans notre pureté et si nous voulons gagner notre guerre contre les autres, nous devons rester forts.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, $c. Les élémentaires corrompus que vous avez guéris étaient une outrage à tous les corps d\'eau. Notre force réside dans notre pureté et si nous voulons gagner notre guerre contre les autres, nous devons rester forts.';
-- Quest 6805 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6805, 'frFR', 'La lâcheté n\'est pas quelque chose que nous apprécions, $c. Allez à Silithus et prouvez votre bravoure.') ON DUPLICATE KEY UPDATE CompletionText='La lâcheté n\'est pas quelque chose que nous apprécions, $c. Allez à Silithus et prouvez votre bravoure.';
-- Quest 6805 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6805, 'frFR', 'Votre bravoure est prouvée, comme l\'est votre valeur pour nous. Peut-être que j\'aurai des tâches futures pour vous, des tâches plus dignes d\'un allié de valeur des Seigneurs de l\'Eau.') ON DUPLICATE KEY UPDATE RewardText='Votre bravoure est prouvée, comme l\'est votre valeur pour nous. Peut-être que j\'aurai des tâches futures pour vous, des tâches plus dignes d\'un allié de valeur des Seigneurs de l\'Eau.';
-- Quest 6821 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6821, 'frFR', 'Avez-vous l\'Œil, $C? Avez-vous la force d\'entrer dans la Flèche de Blackrock ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous l\'Œil, $C? Avez-vous la force d\'entrer dans la Flèche de Blackrock ?';
-- Quest 6821 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6821, 'frFR', 'Ah, vous avez donc la force. Et vous avez aussi l\'intelligence, car la Flèche de Blackrock est plus qu\'une simple affaire de force brute.$B$En effet $N, vous pourriez encore prouver être un allié de valeur pour nous...') ON DUPLICATE KEY UPDATE RewardText='Ah, vous avez donc la force. Et vous avez aussi l\'intelligence, car la Flèche de Blackrock est plus qu\'une simple affaire de force brute.$B$En effet $N, vous pourriez encore prouver être un allié de valeur pour nous...';

-- Quest 6822 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6822, 'frFR', 'Votre succès dans le Cœur Molten attend, $N.') ON DUPLICATE KEY UPDATE CompletionText='Votre succès dans le Cœur Molten attend, $N.';
-- Quest 6822 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6822, 'frFR', 'Vous avez fait ce que la plupart de votre espèce tiendraient pour impossible. Vous avez affronté les êtres du Cœur Molten, et triomphé !$B$BPour une créature si petite, vous avez fait preuve d\'une grande ressources.$B$BSoyons un jour, nous pourrions établir une véritable alliance entre votre espèce et les Seigneurs de l\'Eau.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait ce que la plupart de votre espèce tiendraient pour impossible. Vous avez affronté les êtres du Cœur Molten, et triomphé !$B$BPour une créature si petite, vous avez fait preuve d\'une grande ressources.$B$BSoyons un jour, nous pourrions établir une véritable alliance entre votre espèce et les Seigneurs de l\'Eau.';
-- Quest 6823 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6823, 'frFR', 'Vos exploits contre nos ennemis résonnent dans les chambres des Seigneurs de l\'Eau, $N. Certains pensaient que votre forme était trop petite et fragile pour combattre dans notre guerre, mais vous avez obtenu de grands progrès. Vous avez gagné le respect parmi nous, un exploit incroyable.') ON DUPLICATE KEY UPDATE RewardText='Vos exploits contre nos ennemis résonnent dans les chambres des Seigneurs de l\'Eau, $N. Certains pensaient que votre forme était trop petite et fragile pour combattre dans notre guerre, mais vous avez obtenu de grands progrès. Vous avez gagné le respect parmi nous, un exploit incroyable.';
-- Quest 6824 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6824, 'frFR', 'Avez-vous vaincu Lucifron et les autres, $N? Avez-vous les mains de l\'ennemi?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous vaincu Lucifron et les autres, $N? Avez-vous les mains de l\'ennemi?';
-- Quest 6824 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6824, 'frFR', 'Vous avez les mains ! Vous avez vaincu les capitaines de feu ! Je n\'aurais pas pensé cela possible, si je ne vous connaissais pas et ce que vous êtes capable d\'accomplir.$B$BN, vos exploits sont innombrables, mais la nouvelle de ce dernier exploit fera des vagues parmi les Seigneurs de l\'Eau. Votre nom pourrait un jour être une légende pour nous.$B$BS\'il vous plaît, parlez-moi à nouveau, $N. J\'ai peut-être une autre tâche...') ON DUPLICATE KEY UPDATE RewardText='Vous avez les mains ! Vous avez vaincu les capitaines de feu ! Je n\'aurais pas pensé cela possible, si je ne vous connaissais pas et ce que vous êtes capable d\'accomplir.$B$BN, vos exploits sont innombrables, mais la nouvelle de ce dernier exploit fera des vagues parmi les Seigneurs de l\'Eau. Votre nom pourrait un jour être une légende pour nous.$B$BS\'il vous plaît, parlez-moi à nouveau, $N. J\'ai peut-être une autre tâche...';
-- Quest 6825 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6825, 'frFR', 'Nous devons préparer la nouvelle flotte de Cavaliers de Guerre, $r! Mes cavaliers sont prêts à lancer une frappe sur le champ de bataille central ; mais d\'abord, je dois les préparer à l\'assaut - les préparer à l\'assaut.$b$bJ\'ai besoin de suffisamment de chair de Soldat de Stormpike pour nourrir une flotte ! Des centaines de livres ! Vous pouvez gérer ça, n\'est-ce pas ? Allez !') ON DUPLICATE KEY UPDATE CompletionText='Nous devons préparer la nouvelle flotte de Cavaliers de Guerre, $r! Mes cavaliers sont prêts à lancer une frappe sur le champ de bataille central ; mais d\'abord, je dois les préparer à l\'assaut - les préparer à l\'assaut.$b$bJ\'ai besoin de suffisamment de chair de Soldat de Stormpike pour nourrir une flotte ! Des centaines de livres ! Vous pouvez gérer ça, n\'est-ce pas ? Allez !';
-- Quest 6826 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6826, 'frFR', 'Vous avez travaillé dur, $n, mais nous ne faisons que commencer !$b$bMes Cavaliers de Guerre doivent goûter à la chair de leurs cibles. Cela assurera une frappe chirurgicale contre nos ennemis !$b$bMa flotte est la deuxième plus puissante de notre commandement aérien. Ainsi, ils frapperont les plus puissants de nos adversaires. Pour cela, ils ont besoin de la chair des Lieutenants de Stormpike.$b$bDépêchez-vous, soldat !') ON DUPLICATE KEY UPDATE CompletionText='Vous avez travaillé dur, $n, mais nous ne faisons que commencer !$b$bMes Cavaliers de Guerre doivent goûter à la chair de leurs cibles. Cela assurera une frappe chirurgicale contre nos ennemis !$b$bMa flotte est la deuxième plus puissante de notre commandement aérien. Ainsi, ils frapperont les plus puissants de nos adversaires. Pour cela, ils ont besoin de la chair des Lieutenants de Stormpike.$b$bDépêchez-vous, soldat !';
-- Quest 6827 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6827, 'frFR', 'J\'étais enfermé dans un trou infernal nain pendant des jours. Vous savez que je veux me venger !$b$bNous devons planifier avec soin.$b$bD\'abord, mes cavaliers de guerre ont besoin de cibles à viser - des cibles de haute priorité. Je vais avoir besoin de leur donner la chair des Commandants de Stormpike. Malheureusement, ces petits salauds sont retranchés profondément derrière les lignes ennemies ! Vous avez certainement du travail de prévu.') ON DUPLICATE KEY UPDATE CompletionText='J\'étais enfermé dans un trou infernal nain pendant des jours. Vous savez que je veux me venger !$b$bNous devons planifier avec soin.$b$bD\'abord, mes cavaliers de guerre ont besoin de cibles à viser - des cibles de haute priorité. Je vais avoir besoin de leur donner la chair des Commandants de Stormpike. Malheureusement, ces petits salauds sont retranchés profondément derrière les lignes ennemies ! Vous avez certainement du travail de prévu.';
-- Quest 6827 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6827, 'frFR', 'Pas assez ! J\'attendrais ce niveau de travail d\'un initié, mais vous, <name> ? Allez, soldat ! EN BOUGE ! Il faut plus de chair !') ON DUPLICATE KEY UPDATE RewardText='Pas assez ! J\'attendrais ce niveau de travail d\'un initié, mais vous, <name> ? Allez, soldat ! EN BOUGE ! Il faut plus de chair !';
-- Quest 6845 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6845, 'frFR', 'Ah, $Gname> - J\'avais espéré que vous passeriez.  Je suis heureux de vous voir en bonne santé.$B$BI ai reçu la notification que vous viendriez du terrain, et je voulais exprimer personnellement la gratitude du Cercle de Cenarion pour l\'aide que vous nous avez apportée jusqu\'à présent.  Il n\'y a aucun doute qu\'il y a plus de secrets à découvrir dans Silithus ; votre livraison à Umber devrait être très intéressante une fois découverte.  Veuillez accepter ceci comme un signe de notre appréciation continue pour votre aide.$B<br :>Merci, généreux <class.') ON DUPLICATE KEY UPDATE RewardText='Ah, $Gname> - J\'avais espéré que vous passeriez.  Je suis heureux de vous voir en bonne santé.$B$BI ai reçu la notification que vous viendriez du terrain, et je voulais exprimer personnellement la gratitude du Cercle de Cenarion pour l\'aide que vous nous avez apportée jusqu\'à présent.  Il n\'y a aucun doute qu\'il y a plus de secrets à découvrir dans Silithus ; votre livraison à Umber devrait être très intéressante une fois découverte.  Veuillez accepter ceci comme un signe de notre appréciation continue pour votre aide.$B<br :>Merci, généreux <class.';
-- Quest 6846 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6846, 'frFR', 'Mes troupes sont approvisionnées et prêtes à assaillir. Nous avons juste besoin d\'ordres de Noreg Stormpike et je les enverrai dans la mêlée !') ON DUPLICATE KEY UPDATE CompletionText='Mes troupes sont approvisionnées et prêtes à assaillir. Nous avons juste besoin d\'ordres de Noreg Stormpike et je les enverrai dans la mêlée !';
-- Quest 6846 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6846, 'frFR', 'Ah, les ordres ! Ils disent que je dois assaillir à volonté, et ma volonté dit... maintenant !') ON DUPLICATE KEY UPDATE RewardText='Ah, les ordres ! Ils disent que je dois assaillir à volonté, et ma volonté dit... maintenant !';
-- Quest 6881 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6881, 'frFR', 'Le Clan Frostwolf est protégé par une souillure d\'énergie élémentaire. Leur chaman s\'immisce dans des pouvoirs qui nous détruiront certainement tous s\'ils ne sont pas contrôlés.$b$bLes dégâts sont devenus trop grands pour que le Cercle puisse les contrôler ! Ivus doit être appelé à notre aide.$b$bLes soldats Frostwolf portent des charmes élémentaires appelés cristaux de tempête. Nous pouvons utiliser les charmes pour invoquer Ivus. Avancez et réclamez les cristaux, $n!') ON DUPLICATE KEY UPDATE CompletionText='Le Clan Frostwolf est protégé par une souillure d\'énergie élémentaire. Leur chaman s\'immisce dans des pouvoirs qui nous détruiront certainement tous s\'ils ne sont pas contrôlés.$b$bLes dégâts sont devenus trop grands pour que le Cercle puisse les contrôler ! Ivus doit être appelé à notre aide.$b$bLes soldats Frostwolf portent des charmes élémentaires appelés cristaux de tempête. Nous pouvons utiliser les charmes pour invoquer Ivus. Avancez et réclamez les cristaux, $n!';
-- Quest 6901 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6901, 'frFR', 'Il est temps ! Maintenant, nous pouvons montrer à l\'Alliance leur folie d\'être venue dans la Vallée d\'Alterac !') ON DUPLICATE KEY UPDATE RewardText='Il est temps ! Maintenant, nous pouvons montrer à l\'Alliance leur folie d\'être venue dans la Vallée d\'Alterac !';
-- Quest 6941 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6941, 'frFR', 'Les unités d\'élite de Frostwolf qui gardent les lignes doivent être traitées, soldat ! Je vous confie la tâche de réduire ce troupeau de sauvages. Revenez-moi avec des médailles de leurs lieutenants et légionnaires. Quand je sentirai que suffisamment de rabat-joie a été traité, je déploierai la frappe aérienne.') ON DUPLICATE KEY UPDATE CompletionText='Les unités d\'élite de Frostwolf qui gardent les lignes doivent être traitées, soldat ! Je vous confie la tâche de réduire ce troupeau de sauvages. Revenez-moi avec des médailles de leurs lieutenants et légionnaires. Quand je sentirai que suffisamment de rabat-joie a été traité, je déploierai la frappe aérienne.';

-- Quest 6942 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6942, 'frFR', 'Mes griffons sont prêts à frapper sur les lignes de front, mais ne peuvent lancer l\'attaque tant que les lignes ne sont pas affaiblies.$b$bLes guerriers de Frostwolf qui ont tenu les lignes de front portent fièrement des médailles de service sur leur poitrine. Arrachez ces médailles de leurs cadavres pourris et ramenez-les ici.$b$bUne fois que la ligne de front sera suffisamment affaiblie, je donnerai l\'ordre de frapper par les airs ! La mort d\'en haut !') ON DUPLICATE KEY UPDATE CompletionText='Mes griffons sont prêts à frapper sur les lignes de front, mais ne peuvent lancer l\'attaque tant que les lignes ne sont pas affaiblies.$b$bLes guerriers de Frostwolf qui ont tenu les lignes de front portent fièrement des médailles de service sur leur poitrine. Arrachez ces médailles de leurs cadavres pourris et ramenez-les ici.$b$bUne fois que la ligne de front sera suffisamment affaiblie, je donnerai l\'ordre de frapper par les airs ! La mort d\'en haut !';
-- Quest 6943 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6943, 'frFR', 'Leurs esprits sont abattus, soldat. Après notre dernière frappe aérienne ratée contre la Horde, ils refusent de voler ! Il vous appartient de remonter leur moral.$B$BRetournez au champ de bataille et frappez au cœur du commandement des Frostwolves. Abattez leurs commandants et leurs gardiens. Revenez-moi avec autant de leurs médailles que vous pourrez bourrer dans votre sac ! Je vous promets, quand mes griffons verront le butin et sentiront le sang de nos ennemis, ils voleront à nouveau ! Allez !') ON DUPLICATE KEY UPDATE CompletionText='Leurs esprits sont abattus, soldat. Après notre dernière frappe aérienne ratée contre la Horde, ils refusent de voler ! Il vous appartient de remonter leur moral.$B$BRetournez au champ de bataille et frappez au cœur du commandement des Frostwolves. Abattez leurs commandants et leurs gardiens. Revenez-moi avec autant de leurs médailles que vous pourrez bourrer dans votre sac ! Je vous promets, quand mes griffons verront le butin et sentiront le sang de nos ennemis, ils voleront à nouveau ! Allez !';
-- Quest 6982 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6982, 'frFR', 'Vous les avez !  Bien joué, <name> !  Je vais trier ces fournitures et les préparer pour nos propres troupes !') ON DUPLICATE KEY UPDATE RewardText='Vous les avez !  Bien joué, <name> !  Je vais trier ces fournitures et les préparer pour nos propres troupes !';
-- Quest 6985 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (6985, 'frFR', 'Avez-vous pénétré dans la mine d\'Irondeep, $N ? Avez-vous pillé ses fournitures ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous pénétré dans la mine d\'Irondeep, $N ? Avez-vous pillé ses fournitures ?';
-- Quest 6985 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (6985, 'frFR', 'Vous les avez !  Bien joué, <name> !  Et j\'espère que vous avez vu quelques nains pendant votre raid, et que vous avez versé leur sang pour les Frostwolves !') ON DUPLICATE KEY UPDATE RewardText='Vous les avez !  Bien joué, <name> !  Et j\'espère que vous avez vu quelques nains pendant votre raid, et que vous avez versé leur sang pour les Frostwolves !';
-- Quest 7001 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7001, 'frFR', 'Sans votre aide, les Cavaliers de Wolf de Frostwolf n\'auraient pas d\'équidés pour entrer en bataille. Vous nous rendez un grand service !') ON DUPLICATE KEY UPDATE CompletionText='Sans votre aide, les Cavaliers de Wolf de Frostwolf n\'auraient pas d\'équidés pour entrer en bataille. Vous nous rendez un grand service !';
-- Quest 7002 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7002, 'frFR', 'Pendant que certains de nos soldats sont occupés à capturer des loups pour le maître d\'écurie, d\'autres doivent fournir les nécessités simples qu\'exige la cavalerie. Je parle des harnais de selle, bien sûr.$B$BVous devez frapper les rams indigènes de la région. Les mêmes rams que la cavalerie de Stormpike utilise comme montures !$B$BAbattez-les et revenez-moi avec leurs peaux. Une fois que nous aurons rassemblé suffisamment de peaux, nous fabriquerons des harnais pour les cavaliers. Les Cavaliers de Wolf de Frostwolf chevaucheront à nouveau !') ON DUPLICATE KEY UPDATE CompletionText='Pendant que certains de nos soldats sont occupés à capturer des loups pour le maître d\'écurie, d\'autres doivent fournir les nécessités simples qu\'exige la cavalerie. Je parle des harnais de selle, bien sûr.$B$BVous devez frapper les rams indigènes de la région. Les mêmes rams que la cavalerie de Stormpike utilise comme montures !$B$BAbattez-les et revenez-moi avec leurs peaux. Une fois que nous aurons rassemblé suffisamment de peaux, nous fabriquerons des harnais pour les cavaliers. Les Cavaliers de Wolf de Frostwolf chevaucheront à nouveau !';
-- Quest 7002 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7002, 'frFR', 'Bien joué, soldat. Je vous préviendrai lorsque j\'aurai accumulé suffisamment de peaux.$B$BContinuez !') ON DUPLICATE KEY UPDATE RewardText='Bien joué, soldat. Je vous préviendrai lorsque j\'aurai accumulé suffisamment de peaux.$B$BContinuez !';
-- Quest 7026 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7026, 'frFR', 'La Brigade de Stormpike ne peut pas charger en bataille sans selle ! Nous avons besoin de harnais pour nos montures, après tout, nous ne sommes pas des sauvages.$B$BBien que nous puissions facilement abattre les rams qui rôdent près de notre base pour la peau nécessaire à la confection d\'un harnais, le faire serait idiot. Nous avons besoin de ces rams pour les montures.$B$BVous devez frapper la base de notre ennemi, abattant les frostwolves qu\'ils utilisent comme montures et prenant leurs peaux. Ramenez leurs peaux à moi afin que des harnais puissent être fabriqués pour la cavalerie. Allez !') ON DUPLICATE KEY UPDATE CompletionText='La Brigade de Stormpike ne peut pas charger en bataille sans selle ! Nous avons besoin de harnais pour nos montures, après tout, nous ne sommes pas des sauvages.$B$BBien que nous puissions facilement abattre les rams qui rôdent près de notre base pour la peau nécessaire à la confection d\'un harnais, le faire serait idiot. Nous avons besoin de ces rams pour les montures.$B$BVous devez frapper la base de notre ennemi, abattant les frostwolves qu\'ils utilisent comme montures et prenant leurs peaux. Ramenez leurs peaux à moi afin que des harnais puissent être fabriqués pour la cavalerie. Allez !';
-- Quest 7026 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7026, 'frFR', 'Bien joué, soldat. Je vous préviendrai lorsque j\'aurai accumulé suffisamment de peaux.$B$BContinuez !') ON DUPLICATE KEY UPDATE RewardText='Bien joué, soldat. Je vous préviendrai lorsque j\'aurai accumulé suffisamment de peaux.$B$BContinuez !';
-- Quest 7027 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7027, 'frFR', 'Sans votre aide, les Cavaliers de Ram de Stormpike n\'auraient pas d\'équidés pour entrer en bataille. Vous nous rendez un grand service !') ON DUPLICATE KEY UPDATE CompletionText='Sans votre aide, les Cavaliers de Ram de Stormpike n\'auraient pas d\'équidés pour entrer en bataille. Vous nous rendez un grand service !';
-- Quest 7029 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7029, 'frFR', 'Si vous êtes capable de guérir la plante, elle recommencera à pousser. Nous devons faire ce que nous pouvons, $N...') ON DUPLICATE KEY UPDATE CompletionText='Si vous êtes capable de guérir la plante, elle recommencera à pousser. Nous devons faire ce que nous pouvons, $N...';
-- Quest 7029 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7029, 'frFR', 'Merci d\'avoir ramené ceci, <name>. Avec le liquide restant que vous m\'avez apporté, je peux continuer mes études.$B$BBien qu\'il reste beaucoup à faire, vous avez aidé à guérir une partie de la corruption que Vyletongue a répandue à travers Maraudon. Veuillez accepter ceci avec ma gratitude.') ON DUPLICATE KEY UPDATE RewardText='Merci d\'avoir ramené ceci, <name>. Avec le liquide restant que vous m\'avez apporté, je peux continuer mes études.$B$BBien qu\'il reste beaucoup à faire, vous avez aidé à guérir une partie de la corruption que Vyletongue a répandue à travers Maraudon. Veuillez accepter ceci avec ma gratitude.';
-- Quest 7041 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7041, 'frFR', 'Si vous êtes capable de guérir la plante, elle recommencera à pousser. Nous devons faire ce que nous pouvons, $N...') ON DUPLICATE KEY UPDATE CompletionText='Si vous êtes capable de guérir la plante, elle recommencera à pousser. Nous devons faire ce que nous pouvons, $N...';
-- Quest 7041 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7041, 'frFR', 'Merci d\'avoir ramené ceci, <name>. Avec le liquide restant que vous m\'avez apporté, je peux continuer mes études.$B$BBien qu\'il reste beaucoup à faire, vous avez aidé à guérir une partie de la corruption que Vyletongue a répandue à travers Maraudon. Veuillez accepter ceci avec ma gratitude.') ON DUPLICATE KEY UPDATE RewardText='Merci d\'avoir ramené ceci, <name>. Avec le liquide restant que vous m\'avez apporté, je peux continuer mes études.$B$BBien qu\'il reste beaucoup à faire, vous avez aidé à guérir une partie de la corruption que Vyletongue a répandue à travers Maraudon. Veuillez accepter ceci avec ma gratitude.';

-- Quest 7046 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7046, 'frFR', 'Si vous souhaitez relancer le rituel, veuillez abandonner notre première tentative et me parler à nouveau.') ON DUPLICATE KEY UPDATE CompletionText='Si vous souhaitez relancer le rituel, veuillez abandonner notre première tentative et me parler à nouveau.';
-- Quest 7061 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7061, 'frFR', 'Je vous souhaite la bienvenue à Mulgore et à notre humble communauté de Thunder Bluff, ami. Je m\'intéresse toujours à ceux qui choisissent de s\'intéresser au royaume, à son peuple et à son lore. Est-ce la raison pour laquelle vous êtes devant moi ?') ON DUPLICATE KEY UPDATE CompletionText='Je vous souhaite la bienvenue à Mulgore et à notre humble communauté de Thunder Bluff, ami. Je m\'intéresse toujours à ceux qui choisissent de s\'intéresser au royaume, à son peuple et à son lore. Est-ce la raison pour laquelle vous êtes devant moi ?';
-- Quest 7064 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7064, 'frFR', 'Je préférerais mener cette bataille par nous-mêmes, mais nous n\'avons pas d\'autre choix--nous avons besoin de ceux qui sont plus puissants, et les races d\'Azeroth ont prouvé sans aucun doute qu\'elles peuvent surmonter de telles choses lorsqu\'elles travaillent ensemble. C\'est pourquoi nous nous tournons vers vous pour de l\'aide.$B$BI espère seulement que ce sera suffisant.$B$BZaetar, frère de Remulos, a apporté beaucoup de douleurs à ce monde, et finalement cela a causé sa propre mort. J\'espère juste ne pas avoir causé plus de morts en vous demandant de nous aider.') ON DUPLICATE KEY UPDATE CompletionText='Je préférerais mener cette bataille par nous-mêmes, mais nous n\'avons pas d\'autre choix--nous avons besoin de ceux qui sont plus puissants, et les races d\'Azeroth ont prouvé sans aucun doute qu\'elles peuvent surmonter de telles choses lorsqu\'elles travaillent ensemble. C\'est pourquoi nous nous tournons vers vous pour de l\'aide.$B$BI espère seulement que ce sera suffisant.$B$BZaetar, frère de Remulos, a apporté beaucoup de douleurs à ce monde, et finalement cela a causé sa propre mort. J\'espère juste ne pas avoir causé plus de morts en vous demandant de nous aider.';
-- Quest 7064 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7064, 'frFR', 'C\'est une nouvelle merveilleuse, <name>! Merci!$B$BI parlera avec Marandis et demandera son avis sur le sujet des restes de Zaetar, mais au moins vous avez surmonté la tâche la plus difficile.$B$BI m\'a été dit que si nous réussissions notre mission, j\'avais l\'autorisation de récompenser ceux qui nous ont aidés. Je vous ai donné ces objets comme jetons de notre peuple--vous pouvez en choisir un.') ON DUPLICATE KEY UPDATE RewardText='C\'est une nouvelle merveilleuse, <name>! Merci!$B$BI parlera avec Marandis et demandera son avis sur le sujet des restes de Zaetar, mais au moins vous avez surmonté la tâche la plus difficile.$B$BI m\'a été dit que si nous réussissions notre mission, j\'avais l\'autorisation de récompenser ceux qui nous ont aidés. Je vous ai donné ces objets comme jetons de notre peuple--vous pouvez en choisir un.';
-- Quest 7065 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7065, 'frFR', 'Je ressens le poids d\'imposer ma requête aux races mortelles, mais nous n\'avons pas d\'autre choix. Les races d\'Azeroth ont prouvé sans aucun doute qu\'elles peuvent surmonter de telles choses lorsqu\'elles travaillent ensemble, c\'est pourquoi je leur demande de l\'aide.$B$BI espère seulement que ce sera suffisant.$B$BZaetar, frère de Remulos, a apporté beaucoup de douleurs à ce monde, et finalement cela a causé sa propre mort. Il y a une leçon là pour nous tous si nous sommes assez sages pour la voir.') ON DUPLICATE KEY UPDATE CompletionText='Je ressens le poids d\'imposer ma requête aux races mortelles, mais nous n\'avons pas d\'autre choix. Les races d\'Azeroth ont prouvé sans aucun doute qu\'elles peuvent surmonter de telles choses lorsqu\'elles travaillent ensemble, c\'est pourquoi je leur demande de l\'aide.$B$BI espère seulement que ce sera suffisant.$B$BZaetar, frère de Remulos, a apporté beaucoup de douleurs à ce monde, et finalement cela a causé sa propre mort. Il y a une leçon là pour nous tous si nous sommes assez sages pour la voir.';
-- Quest 7065 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7065, 'frFR', 'C\'est une nouvelle merveilleuse, <name>! Merci!$B$Bien que cela m\'inquiète que vous n\'ayez pas réussi à ramener les restes de Zaetar, qui suis-je pour remettre en question la volonté du premier-né de Cenarius. Peut-être que maintenant la volonté du centaure se brisera et leur soif de sang diminuera--nous ne pouvons que l\'espérer.$B$Si nous réussissons notre mission, on m\'a donné ces objets pour récompenser ceux qui nous ont aidés. Vous pouvez en choisir un en guise de remerciement.') ON DUPLICATE KEY UPDATE RewardText='C\'est une nouvelle merveilleuse, <name>! Merci!$B$Bien que cela m\'inquiète que vous n\'ayez pas réussi à ramener les restes de Zaetar, qui suis-je pour remettre en question la volonté du premier-né de Cenarius. Peut-être que maintenant la volonté du centaure se brisera et leur soif de sang diminuera--nous ne pouvons que l\'espérer.$B$Si nous réussissons notre mission, on m\'a donné ces objets pour récompenser ceux qui nous ont aidés. Vous pouvez en choisir un en guise de remerciement.';
-- Quest 7067 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7067, 'frFR', 'Qu\'avez-vous décidé, $N? Pouvez-vous m\'aider? Allez-vous mettre le pied sur un terrain sacré pour m\'aider à forger une grande tribu de centaures!?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'avez-vous décidé, $N? Pouvez-vous m\'aider? Allez-vous mettre le pied sur un terrain sacré pour m\'aider à forger une grande tribu de centaures!?';
-- Quest 7067 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7067, 'frFR', 'C\'est ça, $R! C\'est ça! Maintenant, je peux commencer la grande tâche d\'unir les tribus. Merci.$B$Prenez ceci pour vos efforts, s\'il vous plaît. J\'espère que lorsque nous nous rencontrerons à nouveau, ce sera dans des termes bien différents.') ON DUPLICATE KEY UPDATE RewardText='C\'est ça, $R! C\'est ça! Maintenant, je peux commencer la grande tâche d\'unir les tribus. Merci.$B$Prenez ceci pour vos efforts, s\'il vous plaît. J\'espère que lorsque nous nous rencontrerons à nouveau, ce sera dans des termes bien différents.';
-- Quest 7070 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7070, 'frFR', 'Avez-vous fait le voyage déjà? Je sais que ce serait assez dangereux, mais si vous y êtes parvenu, cela en vaudrait vraiment la peine.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous fait le voyage déjà? Je sais que ce serait assez dangereux, mais si vous y êtes parvenu, cela en vaudrait vraiment la peine.';
-- Quest 7070 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7070, 'frFR', 'Ce sont parfaits, <name>. J\'ai en fait eu d\'autres aventuriers revenir de là aussi et grâce à eux, j\'ai pu confectionner ceci... s\'il vous plaît, n\'hésitez pas à en prendre un pour votre travail acharné. Et merci encore pour les échantillons supplémentaires à étudier.') ON DUPLICATE KEY UPDATE RewardText='Ce sont parfaits, <name>. J\'ai en fait eu d\'autres aventuriers revenir de là aussi et grâce à eux, j\'ai pu confectionner ceci... s\'il vous plaît, n\'hésitez pas à en prendre un pour votre travail acharné. Et merci encore pour les échantillons supplémentaires à étudier.';
-- Quest 7081 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7081, 'frFR', '$N, vous n\'avez pas encore assailli de cimetière. Revenez-moi lorsque cette tâche sera terminée!') ON DUPLICATE KEY UPDATE CompletionText='$N, vous n\'avez pas encore assailli de cimetière. Revenez-moi lorsque cette tâche sera terminée!';
-- Quest 7082 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7082, 'frFR', 'Attaquez un cimetière détenu par l\'Alliance!') ON DUPLICATE KEY UPDATE CompletionText='Attaquez un cimetière détenu par l\'Alliance!';
-- Quest 7082 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7082, 'frFR', 'Bien joué, <name>!  Avec chaque cimetière sous notre contrôle, les esprits de nos ennemis vagabonderont plus perdus et sans but.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name>!  Avec chaque cimetière sous notre contrôle, les esprits de nos ennemis vagabonderont plus perdus et sans but.';
-- Quest 7101 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7101, 'frFR', 'Vous n\'avez pas encore assailli de bunker, $N! Attendez-vous que d\'autres réclament votre gloire ?') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas encore assailli de bunker, $N! Attendez-vous que d\'autres réclament votre gloire ?';
-- Quest 7102 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7102, 'frFR', 'Vous n\'avez pas encore assailli de tour, $N! Qu\'attendez-vous ?') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas encore assailli de tour, $N! Qu\'attendez-vous ?';

-- Quest 7102 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7102, 'frFR', 'J\'ai reçu un rapport de terrain indiquant que vous avez aidé à sécuriser une bannière ennemie.  Bien joué, <name>!  Avec leurs troupes à distance hors de position, nous pouvons faire avancer la ligne de bataille!') ON DUPLICATE KEY UPDATE RewardText='J\'ai reçu un rapport de terrain indiquant que vous avez aidé à sécuriser une bannière ennemie.  Bien joué, <name>!  Avec leurs troupes à distance hors de position, nous pouvons faire avancer la ligne de bataille!';
-- Quest 7122 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7122, 'frFR', 'Vous n\'avez pas encore capturé la mine, $N!$B$BAprès que nous contrôlions une mine, il sera beaucoup plus facile d\'y recueillir des minéraux et des fournitures.') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas encore capturé la mine, $N!$B$BAprès que nous contrôlions une mine, il sera beaucoup plus facile d\'y recueillir des minéraux et des fournitures.';
-- Quest 7122 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7122, 'frFR', 'Vous l\'avez fait!  Bien joué, <name>!$B$BLorsque nous contrôlons une mine et que nous avons des troupes stationnées là-bas, il est beaucoup plus facile d\'y recueillir des minéraux et des fournitures.') ON DUPLICATE KEY UPDATE RewardText='Vous l\'avez fait!  Bien joué, <name>!$B$BLorsque nous contrôlons une mine et que nous avons des troupes stationnées là-bas, il est beaucoup plus facile d\'y recueillir des minéraux et des fournitures.';
-- Quest 7123 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7123, 'frFR', 'Salut, <name>!  C\'est bon de voir un <class> comme vous, désireux de faire sa part pour la Horde.  Parlez-moi à nouveau, car j\'ai des tâches vitales pour vous...') ON DUPLICATE KEY UPDATE RewardText='Salut, <name>!  C\'est bon de voir un <class> comme vous, désireux de faire sa part pour la Horde.  Parlez-moi à nouveau, car j\'ai des tâches vitales pour vous...';
-- Quest 7124 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7124, 'frFR', 'Vous n\'avez pas encore capturé de mine, $N! Trouvez-en une que nous ne contrôlons pas et battez son chef!') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas encore capturé de mine, $N! Trouvez-en une que nous ne contrôlons pas et battez son chef!';
-- Quest 7141 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7141, 'frFR', 'Allez, $N. Allez dans la Vallée d\'Alterac et battez le général orc!') ON DUPLICATE KEY UPDATE CompletionText='Allez, $N. Allez dans la Vallée d\'Alterac et battez le général orc!';
-- Quest 7161 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7161, 'frFR', 'Réveillez-vous! Réveillez-vous, $N! Ce n\'est pas un rêve. Vous êtes vraiment en plein milieu d\'une bataille rageuse!') ON DUPLICATE KEY UPDATE CompletionText='Réveillez-vous! Réveillez-vous, $N! Ce n\'est pas un rêve. Vous êtes vraiment en plein milieu d\'une bataille rageuse!';
-- Quest 7163 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7163, 'frFR', 'Ce nouveau insigne reflète votre rang parmi les Frostwolf. Gardez-le sur vous en tout temps.$B$BEt <class>... Mourez avec honneur!') ON DUPLICATE KEY UPDATE RewardText='Ce nouveau insigne reflète votre rang parmi les Frostwolf. Gardez-le sur vous en tout temps.$B$BEt <class>... Mourez avec honneur!';
-- Quest 7164 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7164, 'frFR', '$GWarmaster Laggrond salue.>$B<br :>Allez, <name! Continuez votre défense des Frostwolf. Cette guerre doit être gagnée! Pour Drek\'Thar! Pour le Chef de Guerre!') ON DUPLICATE KEY UPDATE RewardText='$GWarmaster Laggrond salue.>$B<br :>Allez, <name! Continuez votre défense des Frostwolf. Cette guerre doit être gagnée! Pour Drek\'Thar! Pour le Chef de Guerre!';
-- Quest 7166 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7166, 'frFR', 'Bientôt, tous sur le champ de bataille seront sous votre surveillance. La commanderie de la Vallée et de ses troupes sera la vôtre!') ON DUPLICATE KEY UPDATE RewardText='Bientôt, tous sur le champ de bataille seront sous votre surveillance. La commanderie de la Vallée et de ses troupes sera la vôtre!';
-- Quest 7167 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7167, 'frFR', 'Canalisez la puissance de l\'insigne. Que l\'ennemi entende vos paroles. La puissance de la Horde est incontestable!') ON DUPLICATE KEY UPDATE RewardText='Canalisez la puissance de l\'insigne. Que l\'ennemi entende vos paroles. La puissance de la Horde est incontestable!';
-- Quest 7168 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7168, 'frFR', 'La plupart ne vivent pas assez longtemps pour s\'élever au-dessus de leur propre médiocrité. Vous vous êtes prouvé être un soldat exemplaire, $c. Le moment est venu.$B$BPresentez votre insigne.') ON DUPLICATE KEY UPDATE CompletionText='La plupart ne vivent pas assez longtemps pour s\'élever au-dessus de leur propre médiocrité. Vous vous êtes prouvé être un soldat exemplaire, $c. Le moment est venu.$B$BPresentez votre insigne.';
-- Quest 7169 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7169, 'frFR', 'La base bourdonne des nouvelles de vos exploits sur le Champ de la Lutte! Vous avez porté de lourds coups à notre ennemi - écrasant leur moral! Pour cela, vous avez gagné un rang d\'honneur parmi les Stormpike.$B$BPresentez votre insigne.') ON DUPLICATE KEY UPDATE CompletionText='La base bourdonne des nouvelles de vos exploits sur le Champ de la Lutte! Vous avez porté de lourds coups à notre ennemi - écrasant leur moral! Pour cela, vous avez gagné un rang d\'honneur parmi les Stormpike.$B$BPresentez votre insigne.';
-- Quest 7169 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7169, 'frFR', 'Le roi a été informé de vos exploits sur le champ de bataille, <class>. Continuez votre défense vaillante de la Garde Stormpike!') ON DUPLICATE KEY UPDATE RewardText='Le roi a été informé de vos exploits sur le champ de bataille, <class>. Continuez votre défense vaillante de la Garde Stormpike!';
-- Quest 7170 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7170, 'frFR', 'Je dois savoir, $n. Quand vous regardez directement dans les yeux de l\'ennemi, voyez-vous la peur? Tremblent-ils maintenant en votre présence? Ils doivent réaliser qu\'ils sont vaincus!$B$BVous avez gagné le respect parmi la Garde. Présentez votre insigne!') ON DUPLICATE KEY UPDATE CompletionText='Je dois savoir, $n. Quand vous regardez directement dans les yeux de l\'ennemi, voyez-vous la peur? Tremblent-ils maintenant en votre présence? Ils doivent réaliser qu\'ils sont vaincus!$B$BVous avez gagné le respect parmi la Garde. Présentez votre insigne!';

-- Quest 7170 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7170, 'frFR', 'Quand nous nous sommes rencontrés pour la première fois, je n\'aurais jamais imaginé qu\'un héros était en devenir. Continue, soldat !') ON DUPLICATE KEY UPDATE RewardText='Quand nous nous sommes rencontrés pour la première fois, je n\'aurais jamais imaginé qu\'un héros était en devenir. Continue, soldat !';
-- Quest 7171 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7171, 'frFR', 'Devant moi se tient un héros exalté de l\'Alliance.$B$B<Lieutenant Haggerdin salue.>$B$BPeu ont atteint un tel rang parmi les Stormpike. J\'ai vu l\'ennemi tomber devant toi. J\'ai vu leur résolution s\'effondrer en ta présence. Lorsque tu entres dans la mêlée, tu deviens le phare d\'espoir pour nos forces !$B$BPresente ton insigne.') ON DUPLICATE KEY UPDATE CompletionText='Devant moi se tient un héros exalté de l\'Alliance.$B$B<Lieutenant Haggerdin salue.>$B$BPeu ont atteint un tel rang parmi les Stormpike. J\'ai vu l\'ennemi tomber devant toi. J\'ai vu leur résolution s\'effondrer en ta présence. Lorsque tu entres dans la mêlée, tu deviens le phare d\'espoir pour nos forces !$B$BPresente ton insigne.';
-- Quest 7171 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7171, 'frFR', 'C\'est sûrement toi qui portera l\'Œil du Commandement !') ON DUPLICATE KEY UPDATE RewardText='C\'est sûrement toi qui portera l\'Œil du Commandement !';
-- Quest 7172 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7172, 'frFR', 'Qu\'ils entendent ta voix, commandant $n! Qu\'ils connaissent la peur. Montre-leur la puissance que les Stormpike détiennent dans leur rang !$B$BPresente ton insigne.') ON DUPLICATE KEY UPDATE CompletionText='Qu\'ils entendent ta voix, commandant $n! Qu\'ils connaissent la peur. Montre-leur la puissance que les Stormpike détiennent dans leur rang !$B$BPresente ton insigne.';
-- Quest 7172 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7172, 'frFR', 'C\'est toi qui dois mener nos troupes à la victoire, Commandant ! Les soldats sont sous ton commandement. Ils suivront tes ordres directs. Mène-les... Écrase le Loup de glace.') ON DUPLICATE KEY UPDATE RewardText='C\'est toi qui dois mener nos troupes à la victoire, Commandant ! Les soldats sont sous ton commandement. Ils suivront tes ordres directs. Mène-les... Écrase le Loup de glace.';
-- Quest 7201 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7201, 'frFR', 'Merveilleux ! Je ferai envoyer ceci par coursier à l\'Inframonde immédiatement !$B$BPour toi - voici le paiement, comme promis. Garde la monnaie, espèce de bête sale !') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Je ferai envoyer ceci par coursier à l\'Inframonde immédiatement !$B$BPour toi - voici le paiement, comme promis. Garde la monnaie, espèce de bête sale !';
-- Quest 7224 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7224, 'frFR', 'Comment se passe la chasse, $N. Tu as des morceaux d\'armure pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe la chasse, $N. Tu as des morceaux d\'armure pour moi ?';
-- Quest 7224 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7224, 'frFR', 'Ceux-ci feront l\'affaire.  Je les ferai fondre et les réparerai et tu ne sauras jamais qu\'ils venaient de ces lâches Stormpike !$B$BMerci, <name>.  Et laisse-moi polir ton armure...') ON DUPLICATE KEY UPDATE RewardText='Ceux-ci feront l\'affaire.  Je les ferai fondre et les réparerai et tu ne sauras jamais qu\'ils venaient de ces lâches Stormpike !$B$BMerci, <name>.  Et laisse-moi polir ton armure...';
-- Quest 7281 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7281, 'frFR', 'Comme il doit lui faire mal de rester parmi les vivants alors que son frère bien-aimé est monté au perfection.') ON DUPLICATE KEY UPDATE CompletionText='Comme il doit lui faire mal de rester parmi les vivants alors que son frère bien-aimé est monté au perfection.';
-- Quest 7281 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7281, 'frFR', 'Tes exploits ne passeront pas inaperçus, $N.$B$BJe ne peux pas perdre de temps s\'il doit être sauvé. Sylvanas doit être contactée !') ON DUPLICATE KEY UPDATE RewardText='Tes exploits ne passeront pas inaperçus, $N.$B$BJe ne peux pas perdre de temps s\'il doit être sauvé. Sylvanas doit être contactée !';
-- Quest 7282 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7282, 'frFR', 'C\'est avec un cœur lourd que je donne un tel ordre, soldat.') ON DUPLICATE KEY UPDATE CompletionText='C\'est avec un cœur lourd que je donne un tel ordre, soldat.';
-- Quest 7282 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7282, 'frFR', 'Tu t\'es souvenu de brûler le cadavre, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE RewardText='Tu t\'es souvenu de brûler le cadavre, n\'est-ce pas ?';
-- Quest 7301 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7301, 'frFR', 'Quelque chose que j\'aimerais entendre ?') ON DUPLICATE KEY UPDATE CompletionText='Quelque chose que j\'aimerais entendre ?';
-- Quest 7301 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7301, 'frFR', 'Incroyable ! Tu les as libérés, n\'est-ce pas ? N\'est-ce pas??? Au moins, nous savons où ils étaient détenus.') ON DUPLICATE KEY UPDATE RewardText='Incroyable ! Tu les as libérés, n\'est-ce pas ? N\'est-ce pas??? Au moins, nous savons où ils étaient détenus.';
-- Quest 7302 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7302, 'frFR', 'Bien joué ! Les informations que tu as récupérées seront inestimables pour notre cause.') ON DUPLICATE KEY UPDATE RewardText='Bien joué ! Les informations que tu as récupérées seront inestimables pour notre cause.';

-- Quest 7341 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7341, 'frFR', 'Bonjour, $r. Je suis Kolark, Chasseur de primes de Thunderbluff. J\'ai voyagé dans beaucoup de mondes et j\'ai beaucoup vu.$B$BMes voyages à travers les Mers du Sud ont mené à la découverte de ces merveilleuses flèches à tête de thorium. Malheureusement, j\'ai un stock infini de flèches mais j\'ai épuisé mon stock de munitions. Bah, aucun Tauren digne de ce nom ne se laisserait prendre à utiliser un arc fragile. Les flèches sont inutiles !$B$BJe propose un échange : un échange équitable de munitions de thorium contre mes flèches à tête de thorium. Marché ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $r. Je suis Kolark, Chasseur de primes de Thunderbluff. J\'ai voyagé dans beaucoup de mondes et j\'ai beaucoup vu.$B$BMes voyages à travers les Mers du Sud ont mené à la découverte de ces merveilleuses flèches à tête de thorium. Malheureusement, j\'ai un stock infini de flèches mais j\'ai épuisé mon stock de munitions. Bah, aucun Tauren digne de ce nom ne se laisserait prendre à utiliser un arc fragile. Les flèches sont inutiles !$B$BJe propose un échange : un échange équitable de munitions de thorium contre mes flèches à tête de thorium. Marché ?';
-- Quest 7341 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7341, 'frFR', 'Excellent ! Je suis un Tauren de ma parole, $r. Les flèches sont à vous.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Je suis un Tauren de ma parole, $r. Les flèches sont à vous.';
-- Quest 7342 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7342, 'frFR', 'Vous croyez à ces futilités ?! La dernière livraison de munitions de Kharanos a été ratée ! Tout ce que nous avons pour les munitions, ce sont ces flèches fragiles et inutiles ! Qu\'est-ce que je vais faire avec 500 000 flèches à tête de thorium ? $b$bJe vais vous dire quoi, gamin. Si tu peux m\'apporter des munitions de thorium, je t\'échangerai des flèches à tête de thorium - tout simplement ! Marché ?') ON DUPLICATE KEY UPDATE CompletionText='Vous croyez à ces futilités ?! La dernière livraison de munitions de Kharanos a été ratée ! Tout ce que nous avons pour les munitions, ce sont ces flèches fragiles et inutiles ! Qu\'est-ce que je vais faire avec 500 000 flèches à tête de thorium ? $b$bJe vais vous dire quoi, gamin. Si tu peux m\'apporter des munitions de thorium, je t\'échangerai des flèches à tête de thorium - tout simplement ! Marché ?';
-- Quest 7342 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7342, 'frFR', 'Un marché conclu si j\'en vois un ! Les flèches sont à vous.') ON DUPLICATE KEY UPDATE RewardText='Un marché conclu si j\'en vois un ! Les flèches sont à vous.';
-- Quest 7361 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7361, 'frFR', 'Ils cherchent à nous exterminer ? Ce sont eux qui seront exterminés.') ON DUPLICATE KEY UPDATE CompletionText='Ils cherchent à nous exterminer ? Ce sont eux qui seront exterminés.';
-- Quest 7361 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7361, 'frFR', '$N, ce n\'en est qu\'un parmi des milliers. Un travail bien fait néanmoins.') ON DUPLICATE KEY UPDATE RewardText='$N, ce n\'en est qu\'un parmi des milliers. Un travail bien fait néanmoins.';
-- Quest 7362 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7362, 'frFR', 'Je me fiche d\'où vient le poil, $R.') ON DUPLICATE KEY UPDATE CompletionText='Je me fiche d\'où vient le poil, $R.';
-- Quest 7362 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7362, 'frFR', 'Oui, c\'est définitivement gnome. Bien fait, $R, mais il y a plus de travail à faire.') ON DUPLICATE KEY UPDATE RewardText='Oui, c\'est définitivement gnome. Bien fait, $R, mais il y a plus de travail à faire.';
-- Quest 7363 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7363, 'frFR', 'Oui, c\'est vrai. Mon frère est un humain. Honteux... Une tache sur mon dossier presque immaculé.') ON DUPLICATE KEY UPDATE CompletionText='Oui, c\'est vrai. Mon frère est un humain. Honteux... Une tache sur mon dossier presque immaculé.';
-- Quest 7363 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7363, 'frFR', 'Il serait plus facile s\'ils acceptaient simplement leur maladie et cédaient à votre toucher guérisseur. Ce serait aussi probablement moins amusant. Continuez ! Nous allons les guérir, d\'une manière ou d\'une autre.') ON DUPLICATE KEY UPDATE RewardText='Il serait plus facile s\'ils acceptaient simplement leur maladie et cédaient à votre toucher guérisseur. Ce serait aussi probablement moins amusant. Continuez ! Nous allons les guérir, d\'une manière ou d\'une autre.';
-- Quest 7366 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7366, 'frFR', 'Benedictus ! Je ne suis qu\'un grain dans l\'ombre de sa grandeur. Louez-le !') ON DUPLICATE KEY UPDATE CompletionText='Benedictus ! Je ne suis qu\'un grain dans l\'ombre de sa grandeur. Louez-le !';
-- Quest 7366 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7366, 'frFR', 'Louez Benedictus ! Une autre âme perdue, bientôt sauvée par les flammes blanches de la Lumière !$B$BAllez, ô soldat de la Lumière ! Il faut en sauver plus !') ON DUPLICATE KEY UPDATE RewardText='Louez Benedictus ! Une autre âme perdue, bientôt sauvée par les flammes blanches de la Lumière !$B$BAllez, ô soldat de la Lumière ! Il faut en sauver plus !';
-- Quest 7385 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7385, 'frFR', 'Vous avez l\'option d\'offrir de plus grandes quantités du sang prélevé sur nos ennemis. Je serai ravi d\'accepter des offrandes de la taille d\'un gallon, $n.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez l\'option d\'offrir de plus grandes quantités du sang prélevé sur nos ennemis. Je serai ravi d\'accepter des offrandes de la taille d\'un gallon, $n.';
-- Quest 7386 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7386, 'frFR', 'Il y a des moments où vous pourriez être retranché au combat pendant des jours ou des semaines. Durant ces périodes d\'activité plus longues, vous pourriez finir par collecter de grands amas de cristaux de tempête du Frostwolf.$B$BLe Cercle accepte de telles offrandes, $n.') ON DUPLICATE KEY UPDATE CompletionText='Il y a des moments où vous pourriez être retranché au combat pendant des jours ou des semaines. Durant ces périodes d\'activité plus longues, vous pourriez finir par collecter de grands amas de cristaux de tempête du Frostwolf.$B$BLe Cercle accepte de telles offrandes, $n.';
-- Quest 7401 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7401, 'frFR', 'Je traite l\'ironie en gros, soldat.') ON DUPLICATE KEY UPDATE CompletionText='Je traite l\'ironie en gros, soldat.';

-- Quest 7401 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7401, 'frFR', 'Vous avez maintenant le droit de décimer les nains par douzaine, $c!$B$B<Yazra regarde au loin pendant un moment.>$B$BVous n\'oubliez jamais votre premier dé-enroulement...') ON DUPLICATE KEY UPDATE RewardText='Vous avez maintenant le droit de décimer les nains par douzaine, $c!$B$B<Yazra regarde au loin pendant un moment.>$B$BVous n\'oubliez jamais votre premier dé-enroulement...';
-- Quest 7424 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7424, 'frFR', '*Dirk jette le sabot dans un tas derrière lui.*') ON DUPLICATE KEY UPDATE RewardText='*Dirk jette le sabot dans un tas derrière lui.*';
-- Quest 7429 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7429, 'frFR', 'Ça s\'appelle la Clé de la Menotte de Gordok - enfin, c\'est ce que ces "tonnes de plaisir" appellent. Je pense que certains des ogres l\'ont, mais je ne suis pas sûr que ce soit des spécifiquement. Peut-être que les gardes ont plus de chances d\'en avoir...$b$bDe quoi je parle - tu l\'as déjà, n\'est-ce pas ?! C\'est ça là??!') ON DUPLICATE KEY UPDATE CompletionText='Ça s\'appelle la Clé de la Menotte de Gordok - enfin, c\'est ce que ces "tonnes de plaisir" appellent. Je pense que certains des ogres l\'ont, mais je ne suis pas sûr que ce soit des spécifiquement. Peut-être que les gardes ont plus de chances d\'en avoir...$b$bDe quoi je parle - tu l\'as déjà, n\'est-ce pas ?! C\'est ça là??!';
-- Quest 7461 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7461, 'frFR', 'Soyez prudent, aventurier. Le Prince est... persuasif.') ON DUPLICATE KEY UPDATE CompletionText='Soyez prudent, aventurier. Le Prince est... persuasif.';
-- Quest 7463 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7463, 'frFR', 'Merveilleux ! Qui êtes-vous encore ? Oh, cela n\'a pas d\'importance. Qu\'étais-je censé vous donner ? Hmm... eh bien, vous êtes un $c, peut-être trouverez-vous cela utile.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Qui êtes-vous encore ? Oh, cela n\'a pas d\'importance. Qu\'étais-je censé vous donner ? Hmm... eh bien, vous êtes un $c, peut-être trouverez-vous cela utile.';
-- Quest 7481 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7481, 'frFR', 'Mon associée, l\'érudite elfe de la nuit, Runethorn, recrute ses alliés pour cette tâche.') ON DUPLICATE KEY UPDATE CompletionText='Mon associée, l\'érudite elfe de la nuit, Runethorn, recrute ses alliés pour cette tâche.';
-- Quest 7482 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7482, 'frFR', 'Mon associée, l\'érudite elfe de la nuit, Runethorn, recrute ses alliés pour cette tâche.') ON DUPLICATE KEY UPDATE CompletionText='Mon associée, l\'érudite elfe de la nuit, Runethorn, recrute ses alliés pour cette tâche.';
-- Quest 7484 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7484, 'frFR', 'Encore toi ? Qu\'est-ce que tu pourrais vouloir maintenant ?') ON DUPLICATE KEY UPDATE CompletionText='Encore toi ? Qu\'est-ce que tu pourrais vouloir maintenant ?';
-- Quest 7486 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7486, 'frFR', 'La voix d\'Hydraxis descend de la surface de l\'eau...$B$B"Choisissez ce qui vous convient le mieux, $N. Qu\'il vous protège contre les ennemis des Seigneurs de l\'Eau."') ON DUPLICATE KEY UPDATE RewardText='La voix d\'Hydraxis descend de la surface de l\'eau...$B$B"Choisissez ce qui vous convient le mieux, $N. Qu\'il vous protège contre les ennemis des Seigneurs de l\'Eau."';
-- Quest 7487 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7487, 'frFR', 'Vous devez attuner votre âme au Cœur Molten avant que l\'accès ne soit accordé.') ON DUPLICATE KEY UPDATE CompletionText='Vous devez attuner votre âme au Cœur Molten avant que l\'accès ne soit accordé.';
-- Quest 7487 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7487, 'frFR', 'Je suis maintenant capable de vous transporter au Cœur Molten. Demandez et ce sera fait.') ON DUPLICATE KEY UPDATE RewardText='Je suis maintenant capable de vous transporter au Cœur Molten. Demandez et ce sera fait.';
-- Quest 7488 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7488, 'frFR', 'Vous avez récupéré la toile !  Bien joué, $Gname>!  Lethtendris, comme beaucoup d\'elfes de son espèce, sont aveugles aux dangers que l\'abus de la magie peut causer à notre monde.  Ils croient être les maîtres de la magie ; ils ne réalisent pas qu\'ils sont les esclaves de leur propre addiction.  Sa mort me chagrine, mais elle était nécessaire.$B<br :>Merci, <name.  Je ferai libérer les énergies contenues dans la toile en toute sécurité sur une large zone, puis je la détruirai pour prévenir de futures exploitations magiques.') ON DUPLICATE KEY UPDATE RewardText='Vous avez récupéré la toile !  Bien joué, $Gname>!  Lethtendris, comme beaucoup d\'elfes de son espèce, sont aveugles aux dangers que l\'abus de la magie peut causer à notre monde.  Ils croient être les maîtres de la magie ; ils ne réalisent pas qu\'ils sont les esclaves de leur propre addiction.  Sa mort me chagrine, mais elle était nécessaire.$B<br :>Merci, <name.  Je ferai libérer les énergies contenues dans la toile en toute sécurité sur une large zone, puis je la détruirai pour prévenir de futures exploitations magiques.';
-- Quest 7493 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7493, 'frFR', 'Un chasseur de dragon et un cordonnier aguerri ? Vous ne cessez d\'étonner, héros. Je suis humble.$B$BVeuillez accepter ce que je suis sur le point de vous enseigner. Cette connaissance s\'avérera inestimable si vous voulez détruire ce qui reste de la Volée Noire de Dragons.$B$BCréez la cape à partir des écailles de la mère du nid. Elle vous protégera vous et vos alliés contre le souffle incendiaire du Seigneur de Blackrock... Nefarian.') ON DUPLICATE KEY UPDATE RewardText='Un chasseur de dragon et un cordonnier aguerri ? Vous ne cessez d\'étonner, héros. Je suis humble.$B$BVeuillez accepter ce que je suis sur le point de vous enseigner. Cette connaissance s\'avérera inestimable si vous voulez détruire ce qui reste de la Volée Noire de Dragons.$B$BCréez la cape à partir des écailles de la mère du nid. Elle vous protégera vous et vos alliés contre le souffle incendiaire du Seigneur de Blackrock... Nefarian.';
-- Quest 7497 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7497, 'frFR', 'Un chasseur de dragon et un cordonnier aguerri ? Vous ne cessez d\'étonner, héros. Je suis humble.$B$BVeuillez accepter ce que je suis sur le point de vous enseigner. Cette connaissance s\'avérera inestimable si vous voulez détruire ce qui reste de la Volée Noire de Dragons.$B$BCréez la cape à partir des écailles de la mère du nid. Elle vous protégera vous et vos alliés contre le souffle incendiaire du Seigneur de Blackrock... Nefarian.') ON DUPLICATE KEY UPDATE RewardText='Un chasseur de dragon et un cordonnier aguerri ? Vous ne cessez d\'étonner, héros. Je suis humble.$B$BVeuillez accepter ce que je suis sur le point de vous enseigner. Cette connaissance s\'avérera inestimable si vous voulez détruire ce qui reste de la Volée Noire de Dragons.$B$BCréez la cape à partir des écailles de la mère du nid. Elle vous protégera vous et vos alliés contre le souffle incendiaire du Seigneur de Blackrock... Nefarian.';
-- Quest 7498 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7498, 'frFR', 'Excellent travail, $R. Si vous trouvez d\'autres tomes, n\'hésitez pas à nous les retourner.$B$BAu fil du temps, nous avons tendance à changer et même à ajouter de nouvelles récompenses pour le retour des tomes manquants.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, $R. Si vous trouvez d\'autres tomes, n\'hésitez pas à nous les retourner.$B$BAu fil du temps, nous avons tendance à changer et même à ajouter de nouvelles récompenses pour le retour des tomes manquants.';

-- Quest 7563 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7563, 'frFR', 'Ah, très bien. Je ferai distiller ce sang en encre et l\'utiliserai pour le parchemin que je t\'ai promis. Et peut-être que j\'en garderai un peu pour moi, car j\'ai entendu dire que son goût est assez euphorique...') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien. Je ferai distiller ce sang en encre et l\'utiliserai pour le parchemin que je t\'ai promis. Et peut-être que j\'en garderai un peu pour moi, car j\'ai entendu dire que son goût est assez euphorique...';
-- Quest 7564 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7564, 'frFR', 'Tu as quelque chose pour moi ? Ce n\'est pas une araignée grosse et juteuse, si ? Ou peut-être une blatte ? J\'espère qu\'elle est encore vivante... J\'adore les mâcher quand elles sont encore vivantes...') ON DUPLICATE KEY UPDATE CompletionText='Tu as quelque chose pour moi ? Ce n\'est pas une araignée grosse et juteuse, si ? Ou peut-être une blatte ? J\'espère qu\'elle est encore vivante... J\'adore les mâcher quand elles sont encore vivantes...';
-- Quest 7564 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7564, 'frFR', 'Oh, c\'est du sang. Il doit venir du maître Mor\'zul alors. Il est tellement épris de cette substance, et il adore la voir se répandre. Moi, cependant, je préfère qu\'il circule dans les veines d\'un petit rongeur. Il reste chaud de cette façon... jusqu\'à ce que tu le veuilles.$B$BCeci est un sang puissant. Mor\'zul doit être en train de faire un autre parchemin pour invoquer un cheval de terreur ! Comme c\'est excitant !$B$BSi c\'est vrai, et que tu vas effectuer le rituel, alors... tu vas avoir besoin de beaucoup plus que du sang, mon ami.') ON DUPLICATE KEY UPDATE RewardText='Oh, c\'est du sang. Il doit venir du maître Mor\'zul alors. Il est tellement épris de cette substance, et il adore la voir se répandre. Moi, cependant, je préfère qu\'il circule dans les veines d\'un petit rongeur. Il reste chaud de cette façon... jusqu\'à ce que tu le veuilles.$B$BCeci est un sang puissant. Mor\'zul doit être en train de faire un autre parchemin pour invoquer un cheval de terreur ! Comme c\'est excitant !$B$BSi c\'est vrai, et que tu vas effectuer le rituel, alors... tu vas avoir besoin de beaucoup plus que du sang, mon ami.';
-- Quest 7581 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7581, 'frFR', 'Seul le sang du satyre de Wildspawn suffira.') ON DUPLICATE KEY UPDATE CompletionText='Seul le sang du satyre de Wildspawn suffira.';
-- Quest 7581 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7581, 'frFR', 'Ah, une excellente récupération. Le sang supprimera les défenses magiques du Garde du Jugement.') ON DUPLICATE KEY UPDATE RewardText='Ah, une excellente récupération. Le sang supprimera les défenses magiques du Garde du Jugement.';
-- Quest 7582 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7582, 'frFR', 'Les Hederine ne renonceront pas à leurs précieuses gemmes sans combat, $N.') ON DUPLICATE KEY UPDATE CompletionText='Les Hederine ne renonceront pas à leurs précieuses gemmes sans combat, $N.';
-- Quest 7582 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7582, 'frFR', 'Je dois simplement combiner le sang de Wildspawn avec ces cristaux et la prison sera prête à l\'emploi.') ON DUPLICATE KEY UPDATE RewardText='Je dois simplement combiner le sang de Wildspawn avec ces cristaux et la prison sera prête à l\'emploi.';
-- Quest 7583 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7583, 'frFR', 'Tu as fait ce que j\'ai demandé. Tu es prêt à recevoir la connaissance pour conjurer et contrôler la bête.') ON DUPLICATE KEY UPDATE RewardText='Tu as fait ce que j\'ai demandé. Tu es prêt à recevoir la connaissance pour conjurer et contrôler la bête.';
-- Quest 7602 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7602, 'frFR', 'Ne le dis à personne, mais Niby est stupide.') ON DUPLICATE KEY UPDATE CompletionText='Ne le dis à personne, mais Niby est stupide.';
-- Quest 7602 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7602, 'frFR', 'Donne-moi une minute et je combinerai les essences en feu de Fel.') ON DUPLICATE KEY UPDATE RewardText='Donne-moi une minute et je combinerai les essences en feu de Fel.';
-- Quest 7603 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7603, 'frFR', 'Un accord est un accord ! Vite, prends ceci et écris ceci. Je n\'ai pas le temps ! Ma plus grande conjuration est sur nous !') ON DUPLICATE KEY UPDATE RewardText='Un accord est un accord ! Vite, prends ceci et écris ceci. Je n\'ai pas le temps ! Ma plus grande conjuration est sur nous !';
-- Quest 7604 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7604, 'frFR', 'Ce fut un plaisir de faire affaire avec toi, <name>!$B$BAu nom de TB Ltd., je te souhaite bonne chance dans ta recherche de Sulfuras !') ON DUPLICATE KEY UPDATE RewardText='Ce fut un plaisir de faire affaire avec toi, <name>!$B$BAu nom de TB Ltd., je te souhaite bonne chance dans ta recherche de Sulfuras !';
-- Quest 7621 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7621, 'frFR', '$c, tu es sur le point de subir une série d\'événements rigoureux qui testeront toutes tes capacités.$B$BI suggère que tu écoutes l\'histoire que je dois te raconter.$B$BMéfie-toi, tu dois accomplir cette tâche seul. Il est recommandé que tes alliés restent à distance. Toute interférence par des agents extérieurs entraînera une punition très sévère.$B$BDestin t\'a mené, toi seul, ici. Bat avec honneur. Exploite la Lumière.') ON DUPLICATE KEY UPDATE RewardText='$c, tu es sur le point de subir une série d\'événements rigoureux qui testeront toutes tes capacités.$B$BI suggère que tu écoutes l\'histoire que je dois te raconter.$B$BMéfie-toi, tu dois accomplir cette tâche seul. Il est recommandé que tes alliés restent à distance. Toute interférence par des agents extérieurs entraînera une punition très sévère.$B$BDestin t\'a mené, toi seul, ici. Bat avec honneur. Exploite la Lumière.';
-- Quest 7622 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7622, 'frFR', 'Ta ténacité et ton courage sont étonnants, prêtresse. Tu as gagné le droit de détenir l\'Éclat de Nordrassil. Une seule tâche reste : l\'Œil de l\'Ombre doit être récupéré. Parcourez le monde.') ON DUPLICATE KEY UPDATE RewardText='Ta ténacité et ton courage sont étonnants, prêtresse. Tu as gagné le droit de détenir l\'Éclat de Nordrassil. Une seule tâche reste : l\'Œil de l\'Ombre doit être récupéré. Parcourez le monde.';
-- Quest 7623 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7623, 'frFR', 'Ma patience s\'étend sur les millénaires, $c. Mais ne pense pas que cela t\'accorde plus qu\'un instant de mon temps...') ON DUPLICATE KEY UPDATE RewardText='Ma patience s\'étend sur les millénaires, $c. Mais ne pense pas que cela t\'accorde plus qu\'un instant de mon temps...';

-- Quest 7624 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7624, 'frFR', 'Je peux déjà goûter le cœur d\'Ulathek sur mes lèvres. Si doux est la chair d\'un traître...') ON DUPLICATE KEY UPDATE CompletionText='Je peux déjà goûter le cœur d\'Ulathek sur mes lèvres. Si doux est la chair d\'un traître...';
-- Quest 7624 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7624, 'frFR', 'Ah, comme c\'est splendide ! Après une semaine de pourriture, ce cœur sera un mets succulent ! Peut-être demanderai-je la tête d\'Ulathek et la placerai devant moi en mangeant...$B$Vous m\'avez rendu un service, $c$, et par conséquent, ma patience envers vous a augmenté. Marginalement.') ON DUPLICATE KEY UPDATE RewardText='Ah, comme c\'est splendide ! Après une semaine de pourriture, ce cœur sera un mets succulent ! Peut-être demanderai-je la tête d\'Ulathek et la placerai devant moi en mangeant...$B$Vous m\'avez rendu un service, $c$, et par conséquent, ma patience envers vous a augmenté. Marginalement.';
-- Quest 7625 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7625, 'frFR', 'Es-tu allé à Jaedenar, $N$? As-tu obtenu la poussière d\'étoile de Lord Banehollow?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé à Jaedenar, $N$? As-tu obtenu la poussière d\'étoile de Lord Banehollow?';
-- Quest 7625 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7625, 'frFR', 'La voilà ! J\'ai du mal à croire que tu l\'aies obtenue ! Tu dois avoir fait une bonne affaire avec ce Seigneur de la Terreur ou avoir payé une somme énorme, ou les deux !$B$Mor\'zul aura son encre très bientôt et pourra alors fabriquer le parchemin de glyphe, afin que tu puisses ouvrir un portail vers Xoroth et en tirer un des fameux chevaux de terreur !') ON DUPLICATE KEY UPDATE RewardText='La voilà ! J\'ai du mal à croire que tu l\'aies obtenue ! Tu dois avoir fait une bonne affaire avec ce Seigneur de la Terreur ou avoir payé une somme énorme, ou les deux !$B$Mor\'zul aura son encre très bientôt et pourra alors fabriquer le parchemin de glyphe, afin que tu puisses ouvrir un portail vers Xoroth et en tirer un des fameux chevaux de terreur !';
-- Quest 7626 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7626, 'frFR', 'Tu as ces élixirs, $N$? Mor\'zul m\'a dit que tu as besoin d\'une cloche de Dethmoora, et fabriquer une de ces choses demande beaucoup de pouvoir d\'ombre !') ON DUPLICATE KEY UPDATE CompletionText='Tu as ces élixirs, $N$? Mor\'zul m\'a dit que tu as besoin d\'une cloche de Dethmoora, et fabriquer une de ces choses demande beaucoup de pouvoir d\'ombre !';
-- Quest 7626 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7626, 'frFR', 'Très bien ! J\'espère que ces élixirs n\'ont pas été trop difficiles à obtenir. Parfois, les alchimistes peuvent être si avares avec leurs créations...$B$Je fabriquerai la cloche et la garderai jusqu\'à ce que tu sois prêt pour ton rituel.') ON DUPLICATE KEY UPDATE RewardText='Très bien ! J\'espère que ces élixirs n\'ont pas été trop difficiles à obtenir. Parfois, les alchimistes peuvent être si avares avec leurs créations...$B$Je fabriquerai la cloche et la garderai jusqu\'à ce que tu sois prêt pour ton rituel.';
-- Quest 7627 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7627, 'frFR', 'La Roue de la Marche Noire n\'est pas facile à fabriquer, et nécessite beaucoup de matériaux. Les as-tu rassemblés ?') ON DUPLICATE KEY UPDATE CompletionText='La Roue de la Marche Noire n\'est pas facile à fabriquer, et nécessite beaucoup de matériaux. Les as-tu rassemblés ?';
-- Quest 7627 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7627, 'frFR', 'Ils sont là ! J\'ai entendu dire que le minerai de fer noir ne se trouve qu\'en profondeur à Blackrock, et je suis sûr que ces éclats n\'étaient pas faciles à trouver non plus. Je suis souvent émerveillé par le dévouement des warlocks. Si au lieu de cela tu avais concentré toute cette énergie dans l\'art de la capture d\'insectes, oh... quel festin tu aurais !$B$Désolé, une petite digression. Je créerai la roue et la garderai pour toi jusqu\'à ce que tu sois prêt pour ton rituel.') ON DUPLICATE KEY UPDATE RewardText='Ils sont là ! J\'ai entendu dire que le minerai de fer noir ne se trouve qu\'en profondeur à Blackrock, et je suis sûr que ces éclats n\'étaient pas faciles à trouver non plus. Je suis souvent émerveillé par le dévouement des warlocks. Si au lieu de cela tu avais concentré toute cette énergie dans l\'art de la capture d\'insectes, oh... quel festin tu aurais !$B$Désolé, une petite digression. Je créerai la roue et la garderai pour toi jusqu\'à ce que tu sois prêt pour ton rituel.';
-- Quest 7628 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7628, 'frFR', 'As-tu apporté les écailles de dragon, $N$? Je ne veux pas commencer avec la bougie tant que je ne les ai pas... sinon je pourrais faire exploser tout le camp !') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les écailles de dragon, $N$? Je ne veux pas commencer avec la bougie tant que je ne les ai pas... sinon je pourrais faire exploser tout le camp !';
-- Quest 7628 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7628, 'frFR', 'Ah, très bien. J\'aurai besoin de celles-ci pour contenir les flammes de la bougie. Maintenant que j\'ai les écailles, je fabriquerai la bougie et la garderai jusqu\'à ce que tu sois prêt à commencer ton rituel pour le Cercle de l\'Appel Majeur.') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien. J\'aurai besoin de celles-ci pour contenir les flammes de la bougie. Maintenant que j\'ai les écailles, je fabriquerai la bougie et la garderai jusqu\'à ce que tu sois prêt à commencer ton rituel pour le Cercle de l\'Appel Majeur.';
-- Quest 7629 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7629, 'frFR', 'Es-tu allé à la Scholomance, $N$? L\'imp a-t-il infusé le parchemin avec la poussière d\'étoile ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé à la Scholomance, $N$? L\'imp a-t-il infusé le parchemin avec la poussière d\'étoile ?';
-- Quest 7629 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7629, 'frFR', 'Ah, bien. J\'eevee a créé le parchemin. Comment était la Scholomance ? Charmant, ne trouves-tu pas ? Et les insectes là-bas... J\'ai entendu dire qu\'ils sont délicieux !$B$Bien joué, $N$, et merci d\'avoir rendu mon pot. Je l\'ai depuis longtemps... et il n\'est pas à vendre !') ON DUPLICATE KEY UPDATE RewardText='Ah, bien. J\'eevee a créé le parchemin. Comment était la Scholomance ? Charmant, ne trouves-tu pas ? Et les insectes là-bas... J\'ai entendu dire qu\'ils sont délicieux !$B$Bien joué, $N$, et merci d\'avoir rendu mon pot. Je l\'ai depuis longtemps... et il n\'est pas à vendre !';
-- Quest 7630 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7630, 'frFR', 'As-tu l\'arcanite, $N$? Une fois que je l\'aurai, je pourrai te fabriquer la lodestone noire.') ON DUPLICATE KEY UPDATE CompletionText='As-tu l\'arcanite, $N$? Une fois que je l\'aurai, je pourrai te fabriquer la lodestone noire.';
-- Quest 7630 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7630, 'frFR', 'Tu l\'as ! Bien fait ! Maintenant, je peux créer la lodestone. Quand tu seras finalement prêt pour ton rituel de création du Cercle de l\'Appel Majeur, tu auras besoin d\'une lodestone pour t\'assurer que le rituel ne s\'éteigne pas !') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as ! Bien fait ! Maintenant, je peux créer la lodestone. Quand tu seras finalement prêt pour ton rituel de création du Cercle de l\'Appel Majeur, tu auras besoin d\'une lodestone pour t\'assurer que le rituel ne s\'éteigne pas !';
-- Quest 7631 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7631, 'frFR', 'L\'esprit du Cheval de Terreur Xorothien est vaincu. Bien qu\'une rage pulse à travers ses flancs fantomatiques, tu sais que l\'âme de la bête t\'appartient...$B$Il murmure de la magie noire dans ton esprit et t\'instille en toi la connaissance pour invoquer un cheval de terreur.') ON DUPLICATE KEY UPDATE RewardText='L\'esprit du Cheval de Terreur Xorothien est vaincu. Bien qu\'une rage pulse à travers ses flancs fantomatiques, tu sais que l\'âme de la bête t\'appartient...$B$Il murmure de la magie noire dans ton esprit et t\'instille en toi la connaissance pour invoquer un cheval de terreur.';

-- Quest 7632 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7632, 'frFR', 'Bien sûr, je reconnais mes propres feuilles. Regarde ça ! Elle est en parfait état.$B$BComme tu es gentil de la rendre, <class>.$B$BPeut-être pourrais-tu nous être utile et nous pourrais être utile à toi.') ON DUPLICATE KEY UPDATE RewardText='Bien sûr, je reconnais mes propres feuilles. Regarde ça ! Elle est en parfait état.$B$BComme tu es gentil de la rendre, <class>.$B$BPeut-être pourrais-tu nous être utile et nous pourrais être utile à toi.';
-- Quest 7633 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7633, 'frFR', 'Ta diligence et ton intégrité ont été notées, $c.$B$BNous sommes les Anciens : Protecteurs de cette forêt autrefois grandiose. Nos formes physiques ont été détruites il y a 10 000 ans lorsque Archimonde et la Légion Ardente ont marché sur Hyjal. Nos esprits, cependant, restent intacts.$B$BIl y a des tâches que nous pouvons t\'offrir. Des tâches dont l\'accomplissement ouvrira les secrets des Anciens pour toi.$B$BSache ceci, si tu accomplis ces tâches, reviens simplement à ce rocher et nous répondrons à l\'appel.') ON DUPLICATE KEY UPDATE RewardText='Ta diligence et ton intégrité ont été notées, $c.$B$BNous sommes les Anciens : Protecteurs de cette forêt autrefois grandiose. Nos formes physiques ont été détruites il y a 10 000 ans lorsque Archimonde et la Légion Ardente ont marché sur Hyjal. Nos esprits, cependant, restent intacts.$B$BIl y a des tâches que nous pouvons t\'offrir. Des tâches dont l\'accomplissement ouvrira les secrets des Anciens pour toi.$B$BSache ceci, si tu accomplis ces tâches, reviens simplement à ce rocher et nous répondrons à l\'appel.';
-- Quest 7634 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7634, 'frFR', 'Que mes feuilles offrent à tes flèches une protection contre le mal. Que tes flèches frappent juste. Que les ennemis de notre monde soient frappés.') ON DUPLICATE KEY UPDATE RewardText='Que mes feuilles offrent à tes flèches une protection contre le mal. Que tes flèches frappent juste. Que les ennemis de notre monde soient frappés.';
-- Quest 7635 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7635, 'frFR', 'Je suis certain que tu auras peu de difficulté à trouver et à abattre un dragon noir, $N. Ne perds pas mon temps avec des bavardages inutiles.') ON DUPLICATE KEY UPDATE CompletionText='Je suis certain que tu auras peu de difficulté à trouver et à abattre un dragon noir, $N. Ne perds pas mon temps avec des bavardages inutiles.';
-- Quest 7635 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7635, 'frFR', 'C\'était un dragon fort mauvais. Le tendon puante d\'un mal. $B$BDonne-moi un instant pour purifier la saleté de cette chair et appliquer les enchantements appropriés.') ON DUPLICATE KEY UPDATE RewardText='C\'était un dragon fort mauvais. Le tendon puante d\'un mal. $B$BDonne-moi un instant pour purifier la saleté de cette chair et appliquer les enchantements appropriés.';
-- Quest 7636 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7636, 'frFR', 'Ne sois pas trompé par leurs déguisements !') ON DUPLICATE KEY UPDATE CompletionText='Ne sois pas trompé par leurs déguisements !';
-- Quest 7636 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7636, 'frFR', 'Tu nous as bien servis, $N! Prends cette baguette et combine-la avec la corde de taureau que Stoma est capable de créer. Ensemble, ils forment une arme formidable.') ON DUPLICATE KEY UPDATE RewardText='Tu nous as bien servis, $N! Prends cette baguette et combine-la avec la corde de taureau que Stoma est capable de créer. Ensemble, ils forment une arme formidable.';
-- Quest 7637 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7637, 'frFR', 'Salutations, noble $C! J\'ai préparé mon encensoir de confiance avec le plus frais des encens et l\'ai béni trois fois pour ton usage. Ton don nous aidera à Ironforge non seulement à créer un nouvel encensoir, mais aussi à renforcer les réserves de nourriture qui s\'affaiblissent pour nos nécessiteux.') ON DUPLICATE KEY UPDATE CompletionText='Salutations, noble $C! J\'ai préparé mon encensoir de confiance avec le plus frais des encens et l\'ai béni trois fois pour ton usage. Ton don nous aidera à Ironforge non seulement à créer un nouvel encensoir, mais aussi à renforcer les réserves de nourriture qui s\'affaiblissent pour nos nécessiteux.';
-- Quest 7637 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7637, 'frFR', 'Bénédictions sur toi, ami $c! Ton don va bien au-delà de ce qui était nécessaire. Ton sacrifice nous aidera non seulement à récupérer ce que nous avons perdu, mais aussi à aider ceux qui sont le plus dans le besoin ici à Ironforge.$B$BMaintenant, laisse-moi m\'assurer que j\'ai préparé cet encensoir de manière appropriée pour tes futurs besoins...') ON DUPLICATE KEY UPDATE RewardText='Bénédictions sur toi, ami $c! Ton don va bien au-delà de ce qui était nécessaire. Ton sacrifice nous aidera non seulement à récupérer ce que nous avons perdu, mais aussi à aider ceux qui sont le plus dans le besoin ici à Ironforge.$B$BMaintenant, laisse-moi m\'assurer que j\'ai préparé cet encensoir de manière appropriée pour tes futurs besoins...';
-- Quest 7638 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7638, 'frFR', 'Je suis heureux de te voir $N. Je sais que tu as attendu des nouvelles sur la manière d\'acquérir ton destrier, et maintenant ce moment est arrivé.$B$BTu seras certainement testé de plusieurs manières différentes, mais surtout dans ta volonté de dépasser de nombreux obstacles qui t\'ont été présentés. Ce ne sont pas des exercices d\'apprentissage - ta stature est au-delà des simples tests éducatifs. Tu dois sauver ton compagnon futur des griffes du mal que tu as passé ta vie à combattre.$B$BPrends garde, ton heure est arrivée !') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux de te voir $N. Je sais que tu as attendu des nouvelles sur la manière d\'acquérir ton destrier, et maintenant ce moment est arrivé.$B$BTu seras certainement testé de plusieurs manières différentes, mais surtout dans ta volonté de dépasser de nombreux obstacles qui t\'ont été présentés. Ce ne sont pas des exercices d\'apprentissage - ta stature est au-delà des simples tests éducatifs. Tu dois sauver ton compagnon futur des griffes du mal que tu as passé ta vie à combattre.$B$BPrends garde, ton heure est arrivée !';
-- Quest 7639 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7639, 'frFR', 'Bienvenue de retour, $N. As-tu acquis l\'encensoir d\'exorcisme ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue de retour, $N. As-tu acquis l\'encensoir d\'exorcisme ?';
-- Quest 7639 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7639, 'frFR', 'Oui, ça ira. On te demandera plus d\'une fois pendant ce processus d\'accomplir des actes de sacrifice ; je suis heureux de voir que tu es prêt à faire cela. Le sacrifice est un élément clé dans ce qu\'il faut pour maintenir les devoirs d\'un Paladin... mais je n\'ai pas besoin de te le rappeler.$B$BMaintenant $N, tu devras faire preuve de jugement dans tes actions. À cette fin, cet encensoir servira de réceptacle pour dispenser un tel jugement sur les esprits tourmentés des terres qui nous sont perdues.') ON DUPLICATE KEY UPDATE RewardText='Oui, ça ira. On te demandera plus d\'une fois pendant ce processus d\'accomplir des actes de sacrifice ; je suis heureux de voir que tu es prêt à faire cela. Le sacrifice est un élément clé dans ce qu\'il faut pour maintenir les devoirs d\'un Paladin... mais je n\'ai pas besoin de te le rappeler.$B$BMaintenant $N, tu devras faire preuve de jugement dans tes actions. À cette fin, cet encensoir servira de réceptacle pour dispenser un tel jugement sur les esprits tourmentés des terres qui nous sont perdues.';
-- Quest 7640 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7640, 'frFR', 'C\'est bon de te revoir $N. Ton travail est-il terminé à Terrordale ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est bon de te revoir $N. Ton travail est-il terminé à Terrordale ?';
-- Quest 7640 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7640, 'frFR', 'Bien fait, $N. Rendre le jugement de la Lumière sur ceux qui habitent dans l\'obscurité est une tâche que nous devons aborder avec vigueur et zèle ; tu as fait cela avec ton sacrifice à Ironforge et tes jugements des esprits à Terrordale.$B$BTes prochaines étapes nécessiteront à la fois sacrifice et jugement alors que tu cherches maintenant à récupérer l\'esprit d\'un destrier tombé qui sert maintenant un Chevalier de la Mort connu sous le nom de Darkreaver.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, $N. Rendre le jugement de la Lumière sur ceux qui habitent dans l\'obscurité est une tâche que nous devons aborder avec vigueur et zèle ; tu as fait cela avec ton sacrifice à Ironforge et tes jugements des esprits à Terrordale.$B$BTes prochaines étapes nécessiteront à la fois sacrifice et jugement alors que tu cherches maintenant à récupérer l\'esprit d\'un destrier tombé qui sert maintenant un Chevalier de la Mort connu sous le nom de Darkreaver.';
-- Quest 7642 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7642, 'frFR', 'Ah, $C. Je ne pourrai pas finir ton armure sans les choses que j\'ai mentionnées. As-tu tout rassemblé ?') ON DUPLICATE KEY UPDATE CompletionText='Ah, $C. Je ne pourrai pas finir ton armure sans les choses que j\'ai mentionnées. As-tu tout rassemblé ?';

-- Quest 7642 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7642, 'frFR', 'Ceci... eh bien, c\'est exactement ce dont j\'avais besoin. Tu es tout à fait ingénieux, n\'est-ce pas ?B$BTrès bien, allons finir cette sellerie pour toi !') ON DUPLICATE KEY UPDATE RewardText='Ceci... eh bien, c\'est exactement ce dont j\'avais besoin. Tu es tout à fait ingénieux, n\'est-ce pas ?B$BTrès bien, allons finir cette sellerie pour toi !';
-- Quest 7643 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7643, 'frFR', 'L\'Esprit Équin Ancien vous regarde avec attente, comme s\'il attendait quelque chose de vous.') ON DUPLICATE KEY UPDATE CompletionText='L\'Esprit Équin Ancien vous regarde avec attente, comme s\'il attendait quelque chose de vous.';
-- Quest 7643 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7643, 'frFR', 'L\'Esprit Équin Ancien accepte l\'offrande de l\'Aliment pour Cheval Enrichi en Mana, reniflant le récipient en se délectant des flocons et des grains spéciaux. Après avoir mangé un peu, il regarde la sellerie que vous possédez et se positionne comme s\'il voulait que vous la placiez sur son dos...') ON DUPLICATE KEY UPDATE RewardText='L\'Esprit Équin Ancien accepte l\'offrande de l\'Aliment pour Cheval Enrichi en Mana, reniflant le récipient en se délectant des flocons et des grains spéciaux. Après avoir mangé un peu, il regarde la sellerie que vous possédez et se positionne comme s\'il voulait que vous la placiez sur son dos...';
-- Quest 7644 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7644, 'frFR', '$N, tu es de retour ! As-tu réussi à t\'occuper de Merideth Carlson et de Tendris Warpwood ? Honnêtement, je ne sais pas lequel est une plus grande menace parfois...') ON DUPLICATE KEY UPDATE CompletionText='$N, tu es de retour ! As-tu réussi à t\'occuper de Merideth Carlson et de Tendris Warpwood ? Honnêtement, je ne sais pas lequel est une plus grande menace parfois...';
-- Quest 7644 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7644, 'frFR', 'Tu as beaucoup progressé, mon ami. Ta sellerie est maintenant suffisamment préparée pour la dernière tâche à accomplir.$B$BTu utiliseras cette sellerie pour dompter ton charger une fois la tâche de rédemption terminée. Avant cela, cependant, tu auras une lutte monumentale à surmonter. Ton heure approche - hourra !$B$BIl y a un dernier élément qui doit être fabriqué avant que nous commencions, $N. J\'espère que ton ingéniosité ne t\'a pas quitté depuis que tu as fait fabriquer ta sellerie...') ON DUPLICATE KEY UPDATE RewardText='Tu as beaucoup progressé, mon ami. Ta sellerie est maintenant suffisamment préparée pour la dernière tâche à accomplir.$B$BTu utiliseras cette sellerie pour dompter ton charger une fois la tâche de rédemption terminée. Avant cela, cependant, tu auras une lutte monumentale à surmonter. Ton heure approche - hourra !$B$BIl y a un dernier élément qui doit être fabriqué avant que nous commencions, $N. J\'espère que ton ingéniosité ne t\'a pas quitté depuis que tu as fait fabriquer ta sellerie...';
-- Quest 7645 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7645, 'frFR', 'Oui, je t\'ai prouvé tort maintenant, n\'est-ce pas ? Je les ai tous prouvés tort ! J\'AVAIS RAISON TOUT CE TEMPS!!!') ON DUPLICATE KEY UPDATE CompletionText='Oui, je t\'ai prouvé tort maintenant, n\'est-ce pas ? Je les ai tous prouvés tort ! J\'AVAIS RAISON TOUT CE TEMPS!!!';
-- Quest 7645 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7645, 'frFR', 'OUI, MAINTENANT QUI - attendez - tu me donnes aussi l\'or ? Tu n\'étais pas celui qui m\'a traité de fou (en fait, ils m\'ont appelé un taré aux fruits)... quand même, tu es prêt à montrer du sacrifice même pour des torts que tu n\'as pas commis?$B$BI... Je t\'ai mal jugé, $N. Si tu as besoin de plus d\'aliments pour chevaux, viens me voir. Je te les donnerai gratuitement. Merci... noble $c.$B$BI je vais garder l\'argent cependant - je ne suis pas si taré que de renoncer à une fortune.') ON DUPLICATE KEY UPDATE RewardText='OUI, MAINTENANT QUI - attendez - tu me donnes aussi l\'or ? Tu n\'étais pas celui qui m\'a traité de fou (en fait, ils m\'ont appelé un taré aux fruits)... quand même, tu es prêt à montrer du sacrifice même pour des torts que tu n\'as pas commis?$B$BI... Je t\'ai mal jugé, $N. Si tu as besoin de plus d\'aliments pour chevaux, viens me voir. Je te les donnerai gratuitement. Merci... noble $c.$B$BI je vais garder l\'argent cependant - je ne suis pas si taré que de renoncer à une fortune.';
-- Quest 7646 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7646, 'frFR', 'Tu es allé si loin, $N. Ton dernier acte de sacrifice d\'objet mondain sera le génesis d\'un de tes plus grands accomplissements. Je le sens dans la fibre même de mon être !') ON DUPLICATE KEY UPDATE CompletionText='Tu es allé si loin, $N. Ton dernier acte de sacrifice d\'objet mondain sera le génesis d\'un de tes plus grands accomplissements. Je le sens dans la fibre même de mon être !';
-- Quest 7646 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7646, 'frFR', 'Ce sont de beaux spécimens, $N - les dernières pièces sont en place. Enfin, ton heure est arrivée !$B$BAu plus profond de l\'Ossuaire de Scholomance se trouvent les restes squelettiques de nombreux êtres. Parmi eux se trouve un charger autrefois noble. L\'âme vidée de ce charger sert maintenant de monture au Chevalier de la Mort Darkreaver. C\'est lui que tu affronteras, et c\'est ce monture sur lequel tu jugeras. Seul toi, $N, peux racheter son âme et le sauver du tourment de son servitude.') ON DUPLICATE KEY UPDATE RewardText='Ce sont de beaux spécimens, $N - les dernières pièces sont en place. Enfin, ton heure est arrivée !$B$BAu plus profond de l\'Ossuaire de Scholomance se trouvent les restes squelettiques de nombreux êtres. Parmi eux se trouve un charger autrefois noble. L\'âme vidée de ce charger sert maintenant de monture au Chevalier de la Mort Darkreaver. C\'est lui que tu affronteras, et c\'est ce monture sur lequel tu jugeras. Seul toi, $N, peux racheter son âme et le sauver du tourment de son servitude.';
-- Quest 7647 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7647, 'frFR', 'L\'esprit du charger tombé vous regarde avec un regard mélancolique. Des yeux tristes, presque vides, vous regardent comme si tout espoir lui était perdu.') ON DUPLICATE KEY UPDATE CompletionText='L\'esprit du charger tombé vous regarde avec un regard mélancolique. Des yeux tristes, presque vides, vous regardent comme si tout espoir lui était perdu.';
-- Quest 7647 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7647, 'frFR', 'Une lueur de vie - longtemps absente de la pauvre bête - brille dans ses yeux lorsque vous lui rendez son âme jugée. Vous sentez une vague sainte de puissance vous traverser alors que vous placez la sellerie sur son dos, ayant jugé le charger racheté. Le charger renifle votre main alors que les fardeaux du passé sont levés de la bête. Vous avez maintenant l\'impression de pouvoir invoquer cette bête pour qu\'elle serve de monture, si le besoin s\'en faisait.$B$BTu as réclamé ton charger épique, $c! Félicitations !') ON DUPLICATE KEY UPDATE RewardText='Une lueur de vie - longtemps absente de la pauvre bête - brille dans ses yeux lorsque vous lui rendez son âme jugée. Vous sentez une vague sainte de puissance vous traverser alors que vous placez la sellerie sur son dos, ayant jugé le charger racheté. Le charger renifle votre main alors que les fardeaux du passé sont levés de la bête. Vous avez maintenant l\'impression de pouvoir invoquer cette bête pour qu\'elle serve de monture, si le besoin s\'en faisait.$B$BTu as réclamé ton charger épique, $c! Félicitations !';
-- Quest 7648 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7648, 'frFR', 'Tu progresses bien, $N. Une fois que tu auras fait ta sellerie, tu seras bien sur la bonne voie pour la prochaine tâche.') ON DUPLICATE KEY UPDATE CompletionText='Tu progresses bien, $N. Une fois que tu auras fait ta sellerie, tu seras bien sur la bonne voie pour la prochaine tâche.';
-- Quest 7648 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7648, 'frFR', 'C\'est un travail très impressionnant. Il semble qu\'en vieillissant, le savoir-faire de Grimand continue de s\'améliorer. C\'est un exploit considérable alors que son travail était déjà parmi les plus fins que l\'on puisse trouver n\'importe où quand il m\'a fait ma sellerie à l\'époque.$B$BBien que cette sellerie serait un ajout parfait à n\'importe quel monture ordinaire, nous ne traitons pas d\'une bête aussi triviale. Tu auras besoin que cette sellerie soit bénie par une source appropriée pour qu\'elle soit digne de reposer sur le charger d\'un $c. Je la garderai pour toi d\'ici là.') ON DUPLICATE KEY UPDATE RewardText='C\'est un travail très impressionnant. Il semble qu\'en vieillissant, le savoir-faire de Grimand continue de s\'améliorer. C\'est un exploit considérable alors que son travail était déjà parmi les plus fins que l\'on puisse trouver n\'importe où quand il m\'a fait ma sellerie à l\'époque.$B$BBien que cette sellerie serait un ajout parfait à n\'importe quel monture ordinaire, nous ne traitons pas d\'une bête aussi triviale. Tu auras besoin que cette sellerie soit bénie par une source appropriée pour qu\'elle soit digne de reposer sur le charger d\'un $c. Je la garderai pour toi d\'ici là.';
-- Quest 7649 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7649, 'frFR', 'Bien fait, mon $gboy:girl;.$B$B<Lorekeeper Lydros arrache une page du livre.>$B$BI suis sûr que tu peux faire usage de cette recette.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, mon $gboy:girl;.$B$B<Lorekeeper Lydros arrache une page du livre.>$B$BI suis sûr que tu peux faire usage de cette recette.';
-- Quest 7650 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7650, 'frFR', 'Bien fait, mon $gboy:girl;.$B$B<Lorekeeper Lydros arrache une page du livre.>$B$BI suis sûr que tu peux faire usage de cette recette.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, mon $gboy:girl;.$B$B<Lorekeeper Lydros arrache une page du livre.>$B$BI suis sûr que tu peux faire usage de cette recette.';

-- Quest 7651 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7651, 'frFR', 'Bien joué, ma $gboy:girl;.$B$B<Lorekeeper Lydros arrache une page du livre.>$B$BI suis sûr que tu pourras faire quelque chose avec cette recette.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, ma $gboy:girl;.$B$B<Lorekeeper Lydros arrache une page du livre.>$B$BI suis sûr que tu pourras faire quelque chose avec cette recette.';
-- Quest 7652 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7652, 'frFR', 'D\'accord, $gmister:lady;, j\'ai une bonne affaire pour toi.$B$BI je cherche à me débarrasser de certaines de ces recettes d\'armure en plaques impériale et j\'ai besoin de quelqu\'un de prêt à prendre cette charge. Tout ce que je veux en échange, ce sont des barres de thorium. Ça te va ?') ON DUPLICATE KEY UPDATE RewardText='D\'accord, $gmister:lady;, j\'ai une bonne affaire pour toi.$B$BI je cherche à me débarrasser de certaines de ces recettes d\'armure en plaques impériale et j\'ai besoin de quelqu\'un de prêt à prendre cette charge. Tout ce que je veux en échange, ce sont des barres de thorium. Ça te va ?';
-- Quest 7653 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7653, 'frFR', 'Pour les plans de ceinture, j\'aurai besoin de 10 barres de thorium.') ON DUPLICATE KEY UPDATE CompletionText='Pour les plans de ceinture, j\'aurai besoin de 10 barres de thorium.';
-- Quest 7653 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7653, 'frFR', 'C\'est un plaisir de faire affaire avec toi.$B$BEt <name>, enlève ce regard de dégoût de ton visage.') ON DUPLICATE KEY UPDATE RewardText='C\'est un plaisir de faire affaire avec toi.$B$BEt <name>, enlève ce regard de dégoût de ton visage.';
-- Quest 7654 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7654, 'frFR', 'Pour les plans de bottes, j\'aurai besoin de 20 barres de thorium. Oui, 20. Tu vas pleurer ? Tu veux une mouchoir?$B$B<Derotain rit.>') ON DUPLICATE KEY UPDATE CompletionText='Pour les plans de bottes, j\'aurai besoin de 20 barres de thorium. Oui, 20. Tu vas pleurer ? Tu veux une mouchoir?$B$B<Derotain rit.>';
