-- Quest 7655 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7655, 'frFR', 'Pour les plans de brassards, j\'aurai besoin de 10 barres de thorium.$B$BEst-ce que ça va, mon garçon ? Tu deviens tout rouge.') ON DUPLICATE KEY UPDATE CompletionText='Pour les plans de brassards, j\'aurai besoin de 10 barres de thorium.$B$BEst-ce que ça va, mon garçon ? Tu deviens tout rouge.';
