-- Quest 7656 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7656, 'frFR', 'Pour les plans de pièce de poitrine, j\'aurai besoin de 30 barres de thorium.$B$Oh là là, encore toi. Tu vas courir vers tes Dieux bleus, demander pourquoi ils t\'ont abandonné?!? Reprends-toi, Nancy ! Personne n\'a jamais dit que la vie était juste.') ON DUPLICATE KEY UPDATE CompletionText='Pour les plans de pièce de poitrine, j\'aurai besoin de 30 barres de thorium.$B$Oh là là, encore toi. Tu vas courir vers tes Dieux bleus, demander pourquoi ils t\'ont abandonné?!? Reprends-toi, Nancy ! Personne n\'a jamais dit que la vie était juste.';
