INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7656, 'frFR', 'C\'est un plaisir de faire affaire avec toi.$B$BEt $N, enlève ce regard de dégoût de ton visage.') ON DUPLICATE KEY UPDATE RewardText='C\'est un plaisir de faire affaire avec toi.$B$BEt $N, enlève ce regard de dégoût de ton visage.';
-- Quest 7657 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7657, 'frFR', 'Donne-moi juste 25 barres de thorium et les plans de casque sont à toi.') ON DUPLICATE KEY UPDATE CompletionText='Donne-moi juste 25 barres de thorium et les plans de casque sont à toi.';
-- Quest 7657 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7657, 'frFR', 'C\'est un plaisir de faire affaire avec toi.$B$BEt <name>, enlève ce regard de dégoût de ton visage.') ON DUPLICATE KEY UPDATE RewardText='C\'est un plaisir de faire affaire avec toi.$B$BEt <name>, enlève ce regard de dégoût de ton visage.';
-- Quest 7658 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7658, 'frFR', 'Donne-moi juste 30 barres de thorium et les plans de jambe sont à toi.$B$BI je sais, je te conduis à la faillite ! J\'ai tout entendu avant, alors tu peux garder ton histoire de pleurniche, faible.') ON DUPLICATE KEY UPDATE CompletionText='Donne-moi juste 30 barres de thorium et les plans de jambe sont à toi.$B$BI je sais, je te conduis à la faillite ! J\'ai tout entendu avant, alors tu peux garder ton histoire de pleurniche, faible.';
