INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7658, 'frFR', 'C\'est un plaisir de faire affaire avec toi.$B$BEt <name>, enlève ce regard de dégoût de ton visage.') ON DUPLICATE KEY UPDATE RewardText='C\'est un plaisir de faire affaire avec toi.$B$BEt <name>, enlève ce regard de dégoût de ton visage.';
-- Quest 7659 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7659, 'frFR', 'Pour les plans d\'épaules, j\'aurai besoin de 10 barres de thorium.') ON DUPLICATE KEY UPDATE CompletionText='Pour les plans d\'épaules, j\'aurai besoin de 10 barres de thorium.';

-- Quest 7659 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7659, 'frFR', 'Un plaisir de faire affaire avec vous.$B$BEt $N$, enlève ce look de dégoût de ton visage.') ON DUPLICATE KEY UPDATE RewardText='Un plaisir de faire affaire avec vous.$B$BEt $N$, enlève ce look de dégoût de ton visage.';
-- Quest 7660 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7660, 'frFR', 'Si tu m\'apportes ton vieux loup rapide, je l\'échangerai contre un du nouveau groupe. Le nouveau loup sera aussi rapide que le tien, mais il aura un aspect différent. Tu peux regarder les loups rapides que nous avons déjà dans la cour ici pour voir à quoi il ressemblera.') ON DUPLICATE KEY UPDATE CompletionText='Si tu m\'apportes ton vieux loup rapide, je l\'échangerai contre un du nouveau groupe. Le nouveau loup sera aussi rapide que le tien, mais il aura un aspect différent. Tu peux regarder les loups rapides que nous avons déjà dans la cour ici pour voir à quoi il ressemblera.';
-- Quest 7661 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7661, 'frFR', 'Si tu m\'apportes ton vieux loup rapide, je l\'échangerai contre un du nouveau groupe. Le nouveau loup sera aussi rapide que le tien, mais il aura un aspect différent. Tu peux regarder les loups rapides que nous avons déjà dans la cour ici pour voir à quoi il ressemblera.') ON DUPLICATE KEY UPDATE CompletionText='Si tu m\'apportes ton vieux loup rapide, je l\'échangerai contre un du nouveau groupe. Le nouveau loup sera aussi rapide que le tien, mais il aura un aspect différent. Tu peux regarder les loups rapides que nous avons déjà dans la cour ici pour voir à quoi il ressemblera.';
-- Quest 7662 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7662, 'frFR', 'Si tu m\'apportes ton vieux kodo, je l\'échangerai contre un du nouveau troupeau. Le nouveau kodo sera aussi rapide que le tien, mais il aura un aspect différent. Tu peux regarder les grands kodos que nous avons déjà dans la cour ici pour voir ce que tu devras choisir.') ON DUPLICATE KEY UPDATE CompletionText='Si tu m\'apportes ton vieux kodo, je l\'échangerai contre un du nouveau troupeau. Le nouveau kodo sera aussi rapide que le tien, mais il aura un aspect différent. Tu peux regarder les grands kodos que nous avons déjà dans la cour ici pour voir ce que tu devras choisir.';
-- Quest 7663 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7663, 'frFR', 'Si tu m\'apportes ton vieux kodo, je l\'échangerai contre un du nouveau troupeau. Le nouveau kodo sera aussi rapide que le tien, mais il aura un aspect différent. Tu peux regarder les grands kodos que nous avons déjà dans la cour ici pour voir ce que tu devras choisir.') ON DUPLICATE KEY UPDATE CompletionText='Si tu m\'apportes ton vieux kodo, je l\'échangerai contre un du nouveau troupeau. Le nouveau kodo sera aussi rapide que le tien, mais il aura un aspect différent. Tu peux regarder les grands kodos que nous avons déjà dans la cour ici pour voir ce que tu devras choisir.';
-- Quest 7664 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7664, 'frFR', 'Tu m\'apportes ton vieux raptoir, je te donne un nouveau avec des griffes fraîchement aiguisées ! Le nouveau raptoir sera aussi rapide que le tien, mais avec un nouvel aspect. Tu peux regarder les raptoirs rapides ici pour voir ce que tu devras choisir.') ON DUPLICATE KEY UPDATE CompletionText='Tu m\'apportes ton vieux raptoir, je te donne un nouveau avec des griffes fraîchement aiguisées ! Le nouveau raptoir sera aussi rapide que le tien, mais avec un nouvel aspect. Tu peux regarder les raptoirs rapides ici pour voir ce que tu devras choisir.';
-- Quest 7665 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7665, 'frFR', 'Tu m\'apportes ton vieux raptoir, je te donne un nouveau avec des griffes fraîchement aiguisées ! Le nouveau raptoir sera aussi rapide que le tien, mais avec un nouvel aspect. Tu peux regarder les raptoirs rapides ici pour voir ce que tu devras choisir.') ON DUPLICATE KEY UPDATE CompletionText='Tu m\'apportes ton vieux raptoir, je te donne un nouveau avec des griffes fraîchement aiguisées ! Le nouveau raptoir sera aussi rapide que le tien, mais avec un nouvel aspect. Tu peux regarder les raptoirs rapides ici pour voir ce que tu devras choisir.';
-- Quest 7666 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7666, 'frFR', 'Tu te rends à nouveau à la Scholomance, $N$? Tu as déjà payé un si grand prix pour l\'utilisation du Scryer de Divination - peut-être aimerais-tu en prendre un autre avec toi. Avec, tu serais en mesure d\'affronter les périls de l\'Ossuaire Grand une fois de plus.$b$bSans aucun doute, prends-le. Tu l\'as certainement mérité.') ON DUPLICATE KEY UPDATE RewardText='Tu te rends à nouveau à la Scholomance, $N$? Tu as déjà payé un si grand prix pour l\'utilisation du Scryer de Divination - peut-être aimerais-tu en prendre un autre avec toi. Avec, tu serais en mesure d\'affronter les périls de l\'Ossuaire Grand une fois de plus.$b$bSans aucun doute, prends-le. Tu l\'as certainement mérité.';
-- Quest 7667 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7667, 'frFR', 'Je me sens mal de demander une aide matérielle, mais mon scryer de divination - l\'appareil que j\'espère finir - nécessite un de chaque. Si tu ne peux pas m\'aider, je le comprendrais certainement.') ON DUPLICATE KEY UPDATE CompletionText='Je me sens mal de demander une aide matérielle, mais mon scryer de divination - l\'appareil que j\'espère finir - nécessite un de chaque. Si tu ne peux pas m\'aider, je le comprendrais certainement.';
-- Quest 7667 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7667, 'frFR', 'Ta générosité est inégalée, $N$. Je te remercie pour ta gentillesse.$B$Je pourrai finir mon scryer de divination maintenant, et je devrais être en mesure d\'en fabriquer d\'autres sans avoir besoin de diamants... peut-être serais-tu intéressé à m\'aider dans son utilisation ? C\'est pour une tâche très importante, je t\'assure... une tâche qui, si elle n\'était pas contrôlée, pourrait engendrer un désastre sans limites pour le royaume des esprits !') ON DUPLICATE KEY UPDATE RewardText='Ta générosité est inégalée, $N$. Je te remercie pour ta gentillesse.$B$Je pourrai finir mon scryer de divination maintenant, et je devrais être en mesure d\'en fabriquer d\'autres sans avoir besoin de diamants... peut-être serais-tu intéressé à m\'aider dans son utilisation ? C\'est pour une tâche très importante, je t\'assure... une tâche qui, si elle n\'était pas contrôlée, pourrait engendrer un désastre sans limites pour le royaume des esprits !';
-- Quest 7670 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7670, 'frFR', 'Je suis heureux de te voir $N$. Je sais que tu as attendu des nouvelles sur la manière d\'acquérir ton palefrenier, et maintenant ce moment est arrivé.$B$BTu seras certainement testé de différentes manières, mais surtout dans ta volonté de dépasser de nombreux obstacles qui te sont présentés. Ce ne sont pas des exercices d\'apprentissage - ta stature est au-delà de simples tests éducatifs. Tu dois sauver ton compagnon futur des griffes du mal que tu as passé ta vie à combattre.$B$BPrends garde, ton heure est arrivée !') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux de te voir $N$. Je sais que tu as attendu des nouvelles sur la manière d\'acquérir ton palefrenier, et maintenant ce moment est arrivé.$B$BTu seras certainement testé de différentes manières, mais surtout dans ta volonté de dépasser de nombreux obstacles qui te sont présentés. Ce ne sont pas des exercices d\'apprentissage - ta stature est au-delà de simples tests éducatifs. Tu dois sauver ton compagnon futur des griffes du mal que tu as passé ta vie à combattre.$B$BPrends garde, ton heure est arrivée !';
-- Quest 7702 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7702, 'frFR', 'Ne laisse pas les lunettes folles te tromper, $N$. C\'est moi le plus intelligent ici.') ON DUPLICATE KEY UPDATE CompletionText='Ne laisse pas les lunettes folles te tromper, $N$. C\'est moi le plus intelligent ici.';
-- Quest 7702 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7702, 'frFR', 'Merveilleux ! Ces Irons Sombres somnolents retourneront à leurs foyers dans les Profondeurs pour se reposer, ralentissant grandement la productivité de la Fosse de Scories.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Ces Irons Sombres somnolents retourneront à leurs foyers dans les Profondeurs pour se reposer, ralentissant grandement la productivité de la Fosse de Scories.';
-- Quest 7703 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7703, 'frFR', 'Hah, tu ne le trouves pas, boss ? Peut-être que les vieilles histoires sont une mauvaise histoire... difficile de croire que ce créature elfique effrayante puisse voler à Gordok le roi !') ON DUPLICATE KEY UPDATE CompletionText='Hah, tu ne le trouves pas, boss ? Peut-être que les vieilles histoires sont une mauvaise histoire... difficile de croire que ce créature elfique effrayante puisse voler à Gordok le roi !';
-- Quest 7703 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7703, 'frFR', 'Wow... tu ES le vrai roi ! Je ne crois pas voir ce gant dans ma vie ! Il a l\'air de n\'avoir plus de magie... peut-être que ce créature elfique effrayante a essayé de ruiner le gant. Eh bien, je dis HAR HAR à lui !$B$Regarde - cette marque sur le gant est une vieille marque magique, plus ancienne que les Gordok, disent-ils. Eh bien, en tant que Capitaine des Gordok, nous apprenons une chose après l\'autre - comment faire en sorte que la marque prenne vie et redonne de la puissance au gant !$B$Je le fais pour toi, roi ! Tiens, prends le gant et règne POUR TOUJOURS !') ON DUPLICATE KEY UPDATE RewardText='Wow... tu ES le vrai roi ! Je ne crois pas voir ce gant dans ma vie ! Il a l\'air de n\'avoir plus de magie... peut-être que ce créature elfique effrayante a essayé de ruiner le gant. Eh bien, je dis HAR HAR à lui !$B$Regarde - cette marque sur le gant est une vieille marque magique, plus ancienne que les Gordok, disent-ils. Eh bien, en tant que Capitaine des Gordok, nous apprenons une chose après l\'autre - comment faire en sorte que la marque prenne vie et redonne de la puissance au gant !$B$Je le fais pour toi, roi ! Tiens, prends le gant et règne POUR TOUJOURS !';

-- Quest 7704 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7704, 'frFR', 'C\'est un énorme oreiller ! Où l\'as-tu trouvé ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est un énorme oreiller ! Où l\'as-tu trouvé ?';
-- Quest 7704 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7704, 'frFR', 'C\'est mieux que ce que j\'aurais pu imaginer ! L\'oreiller magique de la Femme de chambre est le mien ! Tu peux croire que tu vas recevoir une belle récompense pour cette réussite, <name> !') ON DUPLICATE KEY UPDATE RewardText='C\'est mieux que ce que j\'aurais pu imaginer ! L\'oreiller magique de la Femme de chambre est le mien ! Tu peux croire que tu vas recevoir une belle récompense pour cette réussite, <name> !';
-- Quest 7724 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7724, 'frFR', 'Est-ce qu\'il avait raison ? Est-ce que ça sort de leurs fesses ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce qu\'il avait raison ? Est-ce que ça sort de leurs fesses ?';
-- Quest 7725 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7725, 'frFR', 'Incroyablement fantastique, <name> !  Tu m\'as encore sauvé, et pour ça, je te remercie.$B$BMerci !$B$BBien que tu trouves cette pièce un peu moins que ce à quoi tu es habitué, rassure-toi que tes grandes actions sur le champ du goblindom résonnent dans les couloirs du Cartel Steamwheedle.  Si tu as besoin de autre chose à faire, alors n\'hésite pas à me parler !') ON DUPLICATE KEY UPDATE RewardText='Incroyablement fantastique, <name> !  Tu m\'as encore sauvé, et pour ça, je te remercie.$B$BMerci !$B$BBien que tu trouves cette pièce un peu moins que ce à quoi tu es habitué, rassure-toi que tes grandes actions sur le champ du goblindom résonnent dans les couloirs du Cartel Steamwheedle.  Si tu as besoin de autre chose à faire, alors n\'hésite pas à me parler !';
-- Quest 7727 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7727, 'frFR', '<Hansel se frotte les orteils.$B$BNe reste pas là, prends de l\'huile et une luffa et commence à frotter ces orteils.$B$Tu n\'as pas de luffa ? Eh bien ! Peut-être est-il temps que je t\'envoie chercher une luffa?$B$BHé, où est-ce que tu vas ?') ON DUPLICATE KEY UPDATE CompletionText='<Hansel se frotte les orteils.$B$BNe reste pas là, prends de l\'huile et une luffa et commence à frotter ces orteils.$B$Tu n\'as pas de luffa ? Eh bien ! Peut-être est-il temps que je t\'envoie chercher une luffa?$B$BHé, où est-ce que tu vas ?';
-- Quest 7729 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7729, 'frFR', 'Nous allons devoir te peser avec et sans vêtements pour être sûrs.') ON DUPLICATE KEY UPDATE CompletionText='Nous allons devoir te peser avec et sans vêtements pour être sûrs.';
-- Quest 7729 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7729, 'frFR', '15,9 livres ! Cela pourrait être un nouveau record pour le poids du sang et des intestins sur les vêtements ! Félicitations, $c!') ON DUPLICATE KEY UPDATE RewardText='15,9 livres ! Cela pourrait être un nouveau record pour le poids du sang et des intestins sur les vêtements ! Félicitations, $c!';
-- Quest 7730 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7730, 'frFR', 'Comment se passe la chasse, $N ? Es-tu là pour faire un rapport de succès ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe la chasse, $N ? Es-tu là pour faire un rapport de succès ?';
-- Quest 7730 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7730, 'frFR', 'Bien joué, <class>.  Bien que l\'étendue de la présence de Zukk\'ash ne sera pas contrecarrée par moins qu\'une invasion à grande échelle, tu nous as acheté du temps pour que nous puissions élaborer une stratégie appropriée.$B$Je m\'assurerai que ces carapaces soient analysées ; nous devrons tout apprendre à leur sujet avant de nous occuper de ce qui est malheureusement devenu un problème beaucoup plus important que nous ne l\'avions anticipé.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <class>.  Bien que l\'étendue de la présence de Zukk\'ash ne sera pas contrecarrée par moins qu\'une invasion à grande échelle, tu nous as acheté du temps pour que nous puissions élaborer une stratégie appropriée.$B$Je m\'assurerai que ces carapaces soient analysées ; nous devrons tout apprendre à leur sujet avant de nous occuper de ce qui est malheureusement devenu un problème beaucoup plus important que nous ne l\'avions anticipé.';
-- Quest 7735 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7735, 'frFR', 'Qu\'est-ce que c\'est, $N - tu as quelque chose de spécial pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que c\'est, $N - tu as quelque chose de spécial pour moi ?';
-- Quest 7735 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7735, 'frFR', 'Incroyable !  Tu as peut-être trouvé le grand-père de toutes les peaux de yeti avec ça !$B$BTu peux croire que je te paierai pour ça.  Je ne paie normalement pas autant pour une seule peau, mais je suis sûr de pouvoir en faire quelque chose de spécial.  Merci de penser à moi pour ça, <name> !') ON DUPLICATE KEY UPDATE RewardText='Incroyable !  Tu as peut-être trouvé le grand-père de toutes les peaux de yeti avec ça !$B$BTu peux croire que je te paierai pour ça.  Je ne paie normalement pas autant pour une seule peau, mais je suis sûr de pouvoir en faire quelque chose de spécial.  Merci de penser à moi pour ça, <name> !';
-- Quest 7736 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7736, 'frFR', 'Ne gaspillons plus mon précieux temps avec des bavardages, $r. Il est temps de se concentrer sur le réapprovisionnement de notre maigre réserve de flux ardent.$B$Ce dont j\'ai besoin de toi, c\'est ce qui suit:$B$B*Écailles d\'Incendosaur.$B$B*Sang de Roi.$B$B*Charbon.$B$Je prendrai tout ce que tu peux offrir !$B$Et tu le feras vite si tu veux te faire bien voir auprès de la Fraternité.') ON DUPLICATE KEY UPDATE CompletionText='Ne gaspillons plus mon précieux temps avec des bavardages, $r. Il est temps de se concentrer sur le réapprovisionnement de notre maigre réserve de flux ardent.$B$Ce dont j\'ai besoin de toi, c\'est ce qui suit:$B$B*Écailles d\'Incendosaur.$B$B*Sang de Roi.$B$B*Charbon.$B$Je prendrai tout ce que tu peux offrir !$B$Et tu le feras vite si tu veux te faire bien voir auprès de la Fraternité.';
-- Quest 7736 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7736, 'frFR', 'Il y a toujours de la place pour plus de flux ardent, junior. Continue... à moins que je ne te dise d\'arrêter.') ON DUPLICATE KEY UPDATE RewardText='Il y a toujours de la place pour plus de flux ardent, junior. Continue... à moins que je ne te dise d\'arrêter.';
-- Quest 7737 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7737, 'frFR', 'Tu t\'es hissé dans la hiérarchie corporative de la Fraternité, $r. Nous avons commencé à t\'accorder un regard favorable. Quelle réussite !$B$Si tu es intéressé par plus de travail et gagner plus de respect parmi nous, écoute bien.$B$Nous pouvons raffiner le flux ardent en ajoutant un simple résidu de Fer Sombre au mélange. Le résidu de Fer Sombre peut être trouvé dans les Profondeurs de Blackrock.$B$Apporte-moi tout le résidu de Fer Sombre que tu trouves !') ON DUPLICATE KEY UPDATE CompletionText='Tu t\'es hissé dans la hiérarchie corporative de la Fraternité, $r. Nous avons commencé à t\'accorder un regard favorable. Quelle réussite !$B$Si tu es intéressé par plus de travail et gagner plus de respect parmi nous, écoute bien.$B$Nous pouvons raffiner le flux ardent en ajoutant un simple résidu de Fer Sombre au mélange. Le résidu de Fer Sombre peut être trouvé dans les Profondeurs de Blackrock.$B$Apporte-moi tout le résidu de Fer Sombre que tu trouves !';
-- Quest 7738 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7738, 'frFR', 'Qu\'est-ce que c\'est, $N - tu as quelque chose de spécial pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que c\'est, $N - tu as quelque chose de spécial pour moi ?';

-- Quest 7738 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7738, 'frFR', 'C\'est une découverte incroyable ! J\' crois que c\'est le plus beau spécimen de peau de yeti que j\'aie jamais vu !$B$BEn effet, ceci mérite certainement une récompense appropriée. Je ne paie normalement pas autant pour une seule peau, mais je suis sûr de pouvoir en faire quelque chose de spécial. Merci de penser à moi pour ceci, <name> !') ON DUPLICATE KEY UPDATE RewardText='C\'est une découverte incroyable ! J\' crois que c\'est le plus beau spécimen de peau de yeti que j\'aie jamais vu !$B$BEn effet, ceci mérite certainement une récompense appropriée. Je ne paie normalement pas autant pour une seule peau, mais je suis sûr de pouvoir en faire quelque chose de spécial. Merci de penser à moi pour ceci, <name> !';
-- Quest 7783 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7783, 'frFR', 'J\'aurais aimé être là pour voir l\'expression de la bête lorsque vous avez porté le coup de grâce, $N.') ON DUPLICATE KEY UPDATE CompletionText='J\'aurais aimé être là pour voir l\'expression de la bête lorsque vous avez porté le coup de grâce, $N.';
-- Quest 7785 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7785, 'frFR', 'Allez-vous le libérer de sa prison éternelle ?') ON DUPLICATE KEY UPDATE CompletionText='Allez-vous le libérer de sa prison éternelle ?';
-- Quest 7786 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7786, 'frFR', 'Amenez le monde à genoux si vous le devez !') ON DUPLICATE KEY UPDATE CompletionText='Amenez le monde à genoux si vous le devez !';
-- Quest 7789 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7789, 'frFR', 'Le sang de nos ennemis est un signe d\'honneur. Avez-vous un tel signe ?') ON DUPLICATE KEY UPDATE CompletionText='Le sang de nos ennemis est un signe d\'honneur. Avez-vous un tel signe ?';
-- Quest 7789 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7789, 'frFR', '<Captain Shatterskull rugit de triomphe.>$B$BCombien plus peuvent-ils endurer ? Combien de déchets de l\'Alliance doivent périr aux mains de la Horde pour qu\'ils reculent ? Seul le temps dira, $R...') ON DUPLICATE KEY UPDATE RewardText='<Captain Shatterskull rugit de triomphe.>$B$BCombien plus peuvent-ils endurer ? Combien de déchets de l\'Alliance doivent périr aux mains de la Horde pour qu\'ils reculent ? Seul le temps dira, $R...';
