-- Quest 7793 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7793, 'frFR', 'Un cadeau bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Un cadeau bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.';
