-- Quest 7795 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7795, 'frFR', '$n, vous avez été un contributeur formidable à notre collecte de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critiqueement bas - le runecloth. Nous en avons un besoin absolument désespéré, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez consacrer. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons.') ON DUPLICATE KEY UPDATE CompletionText='$n, vous avez été un contributeur formidable à notre collecte de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critiqueement bas - le runecloth. Nous en avons un besoin absolument désespéré, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez consacrer. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons.';

-- Quest 7795 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7795, 'frFR', 'Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous.$B$Avec toutes les donations que vous avez faites, j\'accepterais certainement toute donation supplémentaire de runecloth que vous souhaiteriez faire à l\'avenir. Assurez-vous simplement de me contacter, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !') ON DUPLICATE KEY UPDATE RewardText='Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous.$B$Avec toutes les donations que vous avez faites, j\'accepterais certainement toute donation supplémentaire de runecloth que vous souhaiteriez faire à l\'avenir. Assurez-vous simplement de me contacter, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !';
-- Quest 7796 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7796, 'frFR', 'Quand vous serez prêt à remettre la pile de runecloth, je l\'accepterai.') ON DUPLICATE KEY UPDATE CompletionText='Quand vous serez prêt à remettre la pile de runecloth, je l\'accepterai.';
-- Quest 7796 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7796, 'frFR', '$N - sans des héros comme vous œuvrant au nom de Stormwind, nous souffririons certainement. Merci pour vos efforts continus !') ON DUPLICATE KEY UPDATE RewardText='$N - sans des héros comme vous œuvrant au nom de Stormwind, nous souffririons certainement. Merci pour vos efforts continus !';
-- Quest 7798 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7798, 'frFR', 'Un don bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Un don bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.';
