-- Quest 7800 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7800, 'frFR', '$n, vous avez été un contributeur formidable à notre campagne de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critique - le runecloth. Nous en avons un besoin absolu, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le runecloth dont vous pouvez vous passer. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons ce qui se passe.') ON DUPLICATE KEY UPDATE CompletionText='$n, vous avez été un contributeur formidable à notre campagne de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critique - le runecloth. Nous en avons un besoin absolu, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le runecloth dont vous pouvez vous passer. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons ce qui se passe.';
-- Quest 7800 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7800, 'frFR', 'Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous. Avec toutes les donations que vous avez faites, j\'accepterais certainement toute donation supplémentaire de runecloth que vous souhaiteriez faire à l\'avenir. Assurez-vous simplement de me contacter, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !') ON DUPLICATE KEY UPDATE RewardText='Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous. Avec toutes les donations que vous avez faites, j\'accepterais certainement toute donation supplémentaire de runecloth que vous souhaiteriez faire à l\'avenir. Assurez-vous simplement de me contacter, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !';
