-- Quest 7801 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7801, 'frFR', '$N - sans des héros comme vous œuvrant au nom de Darnassus, nous souffririons certainement. Merci pour vos efforts continus !') ON DUPLICATE KEY UPDATE RewardText='$N - sans des héros comme vous œuvrant au nom de Darnassus, nous souffririons certainement. Merci pour vos efforts continus !';
-- Quest 7802 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7802, 'frFR', 'Nous acceptons actuellement les dons de tissu de laine. Un don de soixante pièces de tissu de laine vous apportera une reconnaissance totale par Ironforge pour vos actions généreuses. Nos réserves sont si faibles en laine que nous n\'aurions besoin que de soixante pièces de votre part au total ; nous devrions pouvoir en acquérir suffisamment auprès d\'autres dans le royaume pour soutenir notre campagne.$B$BSi vous avez les soixante pièces de tissu de laine sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Nous acceptons actuellement les dons de tissu de laine. Un don de soixante pièces de tissu de laine vous apportera une reconnaissance totale par Ironforge pour vos actions généreuses. Nos réserves sont si faibles en laine que nous n\'aurions besoin que de soixante pièces de votre part au total ; nous devrions pouvoir en acquérir suffisamment auprès d\'autres dans le royaume pour soutenir notre campagne.$B$BSi vous avez les soixante pièces de tissu de laine sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.';
-- Quest 7802 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7802, 'frFR', 'Merveilleux ! Nous vous remercions pour votre généreux don, $N!') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Nous vous remercions pour votre généreux don, $N!';
-- Quest 7803 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7803, 'frFR', 'Comme pour la plupart des autres tissus, nos stocks de soie sont à un niveau record. Nos réserves sont telles que nous n\'aurions besoin que de soixante pièces de soie de vous au total ; nous devrions pouvoir atteindre notre objectif avec l\'aide des autres.$B$Un don bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Comme pour la plupart des autres tissus, nos stocks de soie sont à un niveau record. Nos réserves sont telles que nous n\'aurions besoin que de soixante pièces de soie de vous au total ; nous devrions pouvoir atteindre notre objectif avec l\'aide des autres.$B$Un don bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.';
-- Quest 7803 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7803, 'frFR', 'Merveilleux ! Nous vous remercions pour votre généreux don, $N!') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Nous vous remercions pour votre généreux don, $N!';

-- Quest 7804 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7804, 'frFR', 'La mageweave est en quantité limitée, et nous pourrions avoir besoin de votre aide pour reconstituer nos stocks ! En comptant sur la communauté dans son ensemble, nous aurions seulement besoin d\'un don de 60 pièces de tissu mageweave de votre part pour atteindre notre objectif. Une telle générosité ne passera pas inaperçue pour Ironforge, je vous l\'assure !$B$BSi vous avez les soixante pièces de tissu mageweave sur vous et êtes prêt à les donner, je peux les prendre maintenant.') ON DUPLICATE KEY UPDATE CompletionText='La mageweave est en quantité limitée, et nous pourrions avoir besoin de votre aide pour reconstituer nos stocks ! En comptant sur la communauté dans son ensemble, nous aurions seulement besoin d\'un don de 60 pièces de tissu mageweave de votre part pour atteindre notre objectif. Une telle générosité ne passera pas inaperçue pour Ironforge, je vous l\'assure !$B$BSi vous avez les soixante pièces de tissu mageweave sur vous et êtes prêt à les donner, je peux les prendre maintenant.';
-- Quest 7804 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7804, 'frFR', 'Merveilleux ! Nous vous remercions pour votre généreux don, $N!') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Nous vous remercions pour votre généreux don, $N!';
-- Quest 7805 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7805, 'frFR', '$N, vous avez été un contributeur formidable à notre campagne de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste en quantité critique - le runecloth. Nous en avons absolument besoin, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$B$BSi vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez consacrer. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons ce qu\'il en sera.') ON DUPLICATE KEY UPDATE CompletionText='$N, vous avez été un contributeur formidable à notre campagne de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste en quantité critique - le runecloth. Nous en avons absolument besoin, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$B$BSi vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez consacrer. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons ce qu\'il en sera.';
-- Quest 7805 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7805, 'frFR', 'Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous.$B$BAvec tous les dons que vous avez faits, j\'accepterai certainement tout don supplémentaire de runecloth que vous voudrez faire à l\'avenir. Assurez-vous simplement de me consulter, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !') ON DUPLICATE KEY UPDATE RewardText='Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous.$B$BAvec tous les dons que vous avez faits, j\'accepterai certainement tout don supplémentaire de runecloth que vous voudrez faire à l\'avenir. Assurez-vous simplement de me consulter, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !';
-- Quest 7806 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7806, 'frFR', 'Quand vous serez prêt à remettre la pile de runecloth, je l\'accepterai.') ON DUPLICATE KEY UPDATE CompletionText='Quand vous serez prêt à remettre la pile de runecloth, je l\'accepterai.';
-- Quest 7806 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7806, 'frFR', '$N - sans des héros comme vous travaillant au nom d\'Ironforge, nous souffririons certainement. Merci pour vos efforts continus !') ON DUPLICATE KEY UPDATE RewardText='$N - sans des héros comme vous travaillant au nom d\'Ironforge, nous souffririons certainement. Merci pour vos efforts continus !';
-- Quest 7807 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7807, 'frFR', 'Nous acceptons actuellement les dons de tissu de laine. Un don de soixante pièces de tissu de laine vous garantira une reconnaissance totale de la part des Exilés Gnomeregan pour vos actions généreuses. Nos stocks sont si faibles en laine que nous aurions seulement besoin de soixante pièces de votre part au total ; nous devrions être en mesure d\'en acquérir suffisamment auprès d\'autres dans le royaume pour soutenir notre campagne.$B$BSi vous avez les soixante pièces de tissu de laine sur vous et êtes prêt à les donner, je peux les prendre maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Nous acceptons actuellement les dons de tissu de laine. Un don de soixante pièces de tissu de laine vous garantira une reconnaissance totale de la part des Exilés Gnomeregan pour vos actions généreuses. Nos stocks sont si faibles en laine que nous aurions seulement besoin de soixante pièces de votre part au total ; nous devrions être en mesure d\'en acquérir suffisamment auprès d\'autres dans le royaume pour soutenir notre campagne.$B$BSi vous avez les soixante pièces de tissu de laine sur vous et êtes prêt à les donner, je peux les prendre maintenant.';
-- Quest 7807 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7807, 'frFR', 'Merveilleux ! Nous vous remercions pour votre généreux don, $N!') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Nous vous remercions pour votre généreux don, $N!';
-- Quest 7808 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7808, 'frFR', 'Comme pour la plupart des autres tissus, nos stocks de soie sont à un niveau record. Nos stocks sont tels que nous aurions seulement besoin de soixante pièces de soie de votre part au total ; nous devrions être en mesure d\'atteindre notre objectif avec l\'aide d\'autres.$B$BUn cadeau bienveillant tel que la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les donner, je peux les prendre maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Comme pour la plupart des autres tissus, nos stocks de soie sont à un niveau record. Nos stocks sont tels que nous aurions seulement besoin de soixante pièces de soie de votre part au total ; nous devrions être en mesure d\'atteindre notre objectif avec l\'aide d\'autres.$B$BUn cadeau bienveillant tel que la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les donner, je peux les prendre maintenant.';
