-- Quest 7818 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7818, 'frFR', '$n, vous avez été un contributeur formidable à notre campagne de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critique - le runecloth. Nous en avons un besoin absolument désespéré, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez offrir. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons ce qui se passe.') ON DUPLICATE KEY UPDATE CompletionText='$n, vous avez été un contributeur formidable à notre campagne de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critique - le runecloth. Nous en avons un besoin absolument désespéré, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez offrir. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons ce qui se passe.';
-- Quest 7818 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7818, 'frFR', 'Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous.$B$BAvec tous les dons que vous avez faits, j\'accepterais certainement tout don supplémentaire de runecloth que vous voudriez faire à l\'avenir. Assurez-vous simplement de venir me voir, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !') ON DUPLICATE KEY UPDATE RewardText='Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous.$B$BAvec tous les dons que vous avez faits, j\'accepterais certainement tout don supplémentaire de runecloth que vous voudriez faire à l\'avenir. Assurez-vous simplement de venir me voir, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !';
-- Quest 7819 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7819, 'frFR', 'Salutations encore une fois, $N ! Notre besoin en runecloth est constant, et nous pouvons toujours utiliser des ressources supplémentaires si vous êtes disposé à vous en séparer. Pour un paquet supplémentaire de vingt runecloth, je m\'assurerai que vous soyez reconnu pour vos efforts continus au nom de l\'Undercity.$B$BDès que vous êtes prêt à remettre le paquet de runecloth, je l\'accepterai.') ON DUPLICATE KEY UPDATE CompletionText='Salutations encore une fois, $N ! Notre besoin en runecloth est constant, et nous pouvons toujours utiliser des ressources supplémentaires si vous êtes disposé à vous en séparer. Pour un paquet supplémentaire de vingt runecloth, je m\'assurerai que vous soyez reconnu pour vos efforts continus au nom de l\'Undercity.$B$BDès que vous êtes prêt à remettre le paquet de runecloth, je l\'accepterai.';
-- Quest 7819 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7819, 'frFR', '$N - sans héros comme vous travaillant au nom des Forsakés, nous souffririons certainement. Merci pour vos efforts continus !') ON DUPLICATE KEY UPDATE RewardText='$N - sans héros comme vous travaillant au nom des Forsakés, nous souffririons certainement. Merci pour vos efforts continus !';
-- Quest 7820 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7820, 'frFR', 'Nous acceptons actuellement les dons de tissu de laine. Un don de soixante pièces de tissu de laine vous apportera une reconnaissance totale de Thunder Bluff pour vos actions généreuses. Nos réserves sont si faibles en laine que nous n\'aurions besoin que de soixante pièces de votre part au total ; nous devrions être en mesure d\'en obtenir suffisamment auprès d\'autres dans le royaume pour soutenir notre campagne.$B$BSi vous avez les soixante pièces de tissu de laine sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Nous acceptons actuellement les dons de tissu de laine. Un don de soixante pièces de tissu de laine vous apportera une reconnaissance totale de Thunder Bluff pour vos actions généreuses. Nos réserves sont si faibles en laine que nous n\'aurions besoin que de soixante pièces de votre part au total ; nous devrions être en mesure d\'en obtenir suffisamment auprès d\'autres dans le royaume pour soutenir notre campagne.$B$BSi vous avez les soixante pièces de tissu de laine sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.';
