-- Quest 7821 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7821, 'frFR', 'Comme pour la plupart des autres tissus, nos stocks de soie sont à un niveau record. Nos réserves sont telles que nous n\'aurions besoin que de soixante pièces de soie de votre part au total ; nous devrions atteindre notre objectif avec l\'aide d\'autres.$B$BUn cadeau bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre statut local dans la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Comme pour la plupart des autres tissus, nos stocks de soie sont à un niveau record. Nos réserves sont telles que nous n\'aurions besoin que de soixante pièces de soie de votre part au total ; nous devrions atteindre notre objectif avec l\'aide d\'autres.$B$BUn cadeau bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre statut local dans la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.';
