-- Quest 7822 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7822, 'frFR', 'La Mageweave est en quantité limitée, et nous pourrions avoir besoin de votre aide pour reconstituer nos stocks ! En comptant sur la communauté dans son ensemble, nous aurions seulement besoin d\'un don de 60 pièces de tissu Mageweave de votre part pour atteindre notre objectif. Une telle générosité ne passera pas inaperçue à Orgrimmar, je vous l\'assure !$B$BSi vous avez les soixante pièces de tissu Mageweave sur vous et êtes prêt à les donner, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='La Mageweave est en quantité limitée, et nous pourrions avoir besoin de votre aide pour reconstituer nos stocks ! En comptant sur la communauté dans son ensemble, nous aurions seulement besoin d\'un don de 60 pièces de tissu Mageweave de votre part pour atteindre notre objectif. Une telle générosité ne passera pas inaperçue à Orgrimmar, je vous l\'assure !$B$BSi vous avez les soixante pièces de tissu Mageweave sur vous et êtes prêt à les donner, je peux les prendre de vous maintenant.';
