INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7823, 'frFR', 'Fantastique - ceux-ci iront directement à l\'usage, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous.$B$BAvec tous les dons que vous avez faits, je traiterai certainement tout don supplémentaire de runecloth que vous voudrez faire à l\'avenir. Assurez-vous simplement de revenir me voir, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !') ON DUPLICATE KEY UPDATE RewardText='Fantastique - ceux-ci iront directement à l\'usage, je vous l\'assure. Merci encore pour votre aide ! Nous serions certainement perdus sans vous.$B$BAvec tous les dons que vous avez faits, je traiterai certainement tout don supplémentaire de runecloth que vous voudrez faire à l\'avenir. Assurez-vous simplement de revenir me voir, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues !';
