INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7828, 'frFR', 'Montrez la puissance de Revantusk !') ON DUPLICATE KEY UPDATE CompletionText='Montrez la puissance de Revantusk !';
