-- Quest 7834 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7834, 'frFR', 'Comme pour la plupart des autres tissus, nos stocks de soie sont au plus bas. Nos magasins sont tels que nous aurions seulement besoin de soixante pièces de soie de votre part au total; nous devrions atteindre notre objectif avec l\'aide des autres.$B$Un don bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Comme pour la plupart des autres tissus, nos stocks de soie sont au plus bas. Nos magasins sont tels que nous aurions seulement besoin de soixante pièces de soie de votre part au total; nous devrions atteindre notre objectif avec l\'aide des autres.$B$Un don bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.';
