-- Quest 7835 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7835, 'frFR', 'Le Mageweave est en quantité limitée, et nous pourrions avoir besoin de votre aide pour reconstituer nos stocks! En comptant sur la communauté dans son ensemble, nous n\'aurions besoin que d\'un don de 60 pièces de tissu de mageweave de votre part pour nous permettre d\'atteindre notre objectif. Une telle générosité ne passera pas inaperçue pour les Trolls Darkspear, je vous l\'assure!$B$Si vous avez les soixante pièces de tissu de mageweave sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Le Mageweave est en quantité limitée, et nous pourrions avoir besoin de votre aide pour reconstituer nos stocks! En comptant sur la communauté dans son ensemble, nous n\'aurions besoin que d\'un don de 60 pièces de tissu de mageweave de votre part pour nous permettre d\'atteindre notre objectif. Une telle générosité ne passera pas inaperçue pour les Trolls Darkspear, je vous l\'assure!$B$Si vous avez les soixante pièces de tissu de mageweave sur vous et êtes prêt à les faire don, je peux les prendre de vous maintenant.';
-- Quest 7835 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7835, 'frFR', 'Magnifique ! Nous vous remercions pour votre généreuse donation, $N!') ON DUPLICATE KEY UPDATE RewardText='Magnifique ! Nous vous remercions pour votre généreuse donation, $N!';
-- Quest 7836 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7836, 'frFR', '$n, vous avez été un contributeur formidable à notre campagne de tissus. Alors que nous travaillons dur pour reconstituer nos réserves, un type de tissu reste en quantité critique - le runecloth. Nous en avons un besoin absolu, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé!$b$Si vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez vous permettre. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons ce qui se passe.') ON DUPLICATE KEY UPDATE CompletionText='$n, vous avez été un contributeur formidable à notre campagne de tissus. Alors que nous travaillons dur pour reconstituer nos réserves, un type de tissu reste en quantité critique - le runecloth. Nous en avons un besoin absolu, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé!$b$Si vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez vous permettre. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons ce qui se passe.';
-- Quest 7836 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7836, 'frFR', 'Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide! Nous serions certainement perdus sans vous.$B$Avec tous les dons que vous avez faits, je traiterai certainement toute donation supplémentaire de runecloth que vous souhaiteriez faire à l\'avenir. Assurez-vous simplement de revenir me voir, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues!') ON DUPLICATE KEY UPDATE RewardText='Fantastique - ceux-ci seront utilisés immédiatement, je vous l\'assure. Merci encore pour votre aide! Nous serions certainement perdus sans vous.$B$Avec tous les dons que vous avez faits, je traiterai certainement toute donation supplémentaire de runecloth que vous souhaiteriez faire à l\'avenir. Assurez-vous simplement de revenir me voir, et je m\'assurerai personnellement que vos bonnes actions ne passeront pas inaperçues!';
-- Quest 7837 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7837, 'frFR', 'Quand vous serez prêt à remettre la pile de runecloth, je l\'accepterai.') ON DUPLICATE KEY UPDATE CompletionText='Quand vous serez prêt à remettre la pile de runecloth, je l\'accepterai.';
