INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7837, 'frFR', '$N - sans des héros comme vous travaillant au nom des trolls, nous souffririons certainement. Merci pour vos efforts continus!') ON DUPLICATE KEY UPDATE RewardText='$N - sans des héros comme vous travaillant au nom des trolls, nous souffririons certainement. Merci pour vos efforts continus!';
