INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7838, 'frFR', 'Avast Lubber! Apportez-moi 12 bibelots du Maître de l\'Arène.') ON DUPLICATE KEY UPDATE CompletionText='Avast Lubber! Apportez-moi 12 bibelots du Maître de l\'Arène.';
-- Quest 7841 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7841, 'frFR', 'Tu es trop propre, mon. Tu dois te mélanger - descends dans la boue avec l\'ennemi.') ON DUPLICATE KEY UPDATE CompletionText='Tu es trop propre, mon. Tu dois te mélanger - descends dans la boue avec l\'ennemi.';

-- Quest 7842 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7842, 'frFR', 'Le dernier message va certainement les effrayer. Soit ça, soit les rendre très, très en colère.') ON DUPLICATE KEY UPDATE CompletionText='Le dernier message va certainement les effrayer. Soit ça, soit les rendre très, très en colère.';
-- Quest 7842 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7842, 'frFR', 'Oh, mon, ça va être bon. Encore une étape et Wildhammer verra qu\'ils ne peuvent pas s\'en prendre aux trolls !') ON DUPLICATE KEY UPDATE RewardText='Oh, mon, ça va être bon. Encore une étape et Wildhammer verra qu\'ils ne peuvent pas s\'en prendre aux trolls !';
