INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7844, 'frFR', 'Les Voyantes et les Spéculateurs de Vilebranch habitent la région nord-nord-est des Terres arides.') ON DUPLICATE KEY UPDATE CompletionText='Les Voyantes et les Spéculateurs de Vilebranch habitent la région nord-nord-est des Terres arides.';
-- Quest 7847 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7847, 'frFR', 'Vous avez rendu un grand service à Revantusk, $N ! Nous vous devons une grande gratitude.') ON DUPLICATE KEY UPDATE RewardText='Vous avez rendu un grand service à Revantusk, $N ! Nous vous devons une grande gratitude.';
