INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7861, 'frFR', 'Apportez-vous des nouvelles de Jintha\'alor ?') ON DUPLICATE KEY UPDATE CompletionText='Apportez-vous des nouvelles de Jintha\'alor ?';
