INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7862, 'frFR', 'Êtes-vous ici pour le poste vacant ?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous ici pour le poste vacant ?';
-- Quest 7863 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7863, 'frFR', 'Vous avez certainement commencé à vous prouver à nous, $N. En récompense, veuillez prendre ce colis de soins ! À l\'intérieur, vous trouverez des rations et des bandages utilisables uniquement à l\'intérieur de Warsong Gulch. $B$BAs vous continuez à vous prouver à l\'intérieur du Gulch, vous trouverez que ces objets seront disponibles à l\'achat pour vous. Les rations deviennent disponibles lorsque vous êtes Amical avec nous, et les bandages lorsque vous êtes Honoré.') ON DUPLICATE KEY UPDATE RewardText='Vous avez certainement commencé à vous prouver à nous, $N. En récompense, veuillez prendre ce colis de soins ! À l\'intérieur, vous trouverez des rations et des bandages utilisables uniquement à l\'intérieur de Warsong Gulch. $B$BAs vous continuez à vous prouver à l\'intérieur du Gulch, vous trouverez que ces objets seront disponibles à l\'achat pour vous. Les rations deviennent disponibles lorsque vous êtes Amical avec nous, et les bandages lorsque vous êtes Honoré.';
