-- Quest 7874 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7874, 'frFR', '<Captain Shatterskull rugit de triomphe.>$B$BCombien de plus peuvent-ils endurer ? Combien de déchets de l\'Alliance doivent périr aux mains de la Horde pour qu\'ils reculent ? Seul le temps le dira, $R.') ON DUPLICATE KEY UPDATE RewardText='<Captain Shatterskull rugit de triomphe.>$B$BCombien de plus peuvent-ils endurer ? Combien de déchets de l\'Alliance doivent périr aux mains de la Horde pour qu\'ils reculent ? Seul le temps le dira, $R.';
