INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7876, 'frFR', '<Captain Shatterskull rugit de triomphe.>$B$BCombien de plus peuvent-ils endurer ? Combien de vilains de l\'Alliance doivent périr aux mains de la Horde pour qu\'ils reculent ? Le temps seul le dira, $R.') ON DUPLICATE KEY UPDATE RewardText='<Captain Shatterskull rugit de triomphe.>$B$BCombien de plus peuvent-ils endurer ? Combien de vilains de l\'Alliance doivent périr aux mains de la Horde pour qu\'ils reculent ? Le temps seul le dira, $R.';
-- Quest 7881 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7881, 'frFR', 'Nous, au Foire de la Lune Noire, faisons beaucoup de marche. Nous marchons d\'un site de foire à un autre... en fait, vous ne nous verrez jamais assis au travail ! Il n\'est donc pas surprenant que nous usions beaucoup de bottes ! Nous avons besoin de bottes en cuir à la fois durables et élégantes, et les bottes en cuir estampées correspondent bien à ce besoin.$B$BVous ! Vous êtes un travailleur du cuir ; faites-moi des bottes en cuir estampées et je vous donnerai un ticket de Foire de la Lune Noire en échange du travail.') ON DUPLICATE KEY UPDATE CompletionText='Nous, au Foire de la Lune Noire, faisons beaucoup de marche. Nous marchons d\'un site de foire à un autre... en fait, vous ne nous verrez jamais assis au travail ! Il n\'est donc pas surprenant que nous usions beaucoup de bottes ! Nous avons besoin de bottes en cuir à la fois durables et élégantes, et les bottes en cuir estampées correspondent bien à ce besoin.$B$BVous ! Vous êtes un travailleur du cuir ; faites-moi des bottes en cuir estampées et je vous donnerai un ticket de Foire de la Lune Noire en échange du travail.';
-- Quest 7881 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7881, 'frFR', 'Merci, <name>.  Celles-ci sont très bien faites.  Le savoir-faire est de premier ordre !  Voici un ticket de Foire de la Lune Noire... profitez-en, monsieur.') ON DUPLICATE KEY UPDATE RewardText='Merci, <name>.  Celles-ci sont très bien faites.  Le savoir-faire est de premier ordre !  Voici un ticket de Foire de la Lune Noire... profitez-en, monsieur.';
-- Quest 7882 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7882, 'frFR', 'Nos travailleurs de la Foire font plus que balayer les déchets et marteler les clous ! Ils aident également à garder le carnaval pendant son voyage, et à cette fin, ils ont toujours besoin de bons gilets d\'armure solides.$B$BSi vous fabriquez une armure en cuir solide et me l\'apportez, alors je m\'assurerai qu\'elle arrive aux bonnes personnes. Je vous donnerai également des tickets de Foire de la Lune Noire en échange.') ON DUPLICATE KEY UPDATE CompletionText='Nos travailleurs de la Foire font plus que balayer les déchets et marteler les clous ! Ils aident également à garder le carnaval pendant son voyage, et à cette fin, ils ont toujours besoin de bons gilets d\'armure solides.$B$BSi vous fabriquez une armure en cuir solide et me l\'apportez, alors je m\'assurerai qu\'elle arrive aux bonnes personnes. Je vous donnerai également des tickets de Foire de la Lune Noire en échange.';
-- Quest 7882 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7882, 'frFR', 'Ah, vous avez apporté les gilets. Splendide. De quelle peau d\'animal avez-vous utilisé pour les fabriquer, puis-je demander ? Le travail de couture est très bien fait, et la texture du cuir a un style robuste. Je peux dire que vous êtes un artisan talentueux !$b$bMerci, $n, et voici vos tickets.') ON DUPLICATE KEY UPDATE RewardText='Ah, vous avez apporté les gilets. Splendide. De quelle peau d\'animal avez-vous utilisé pour les fabriquer, puis-je demander ? Le travail de couture est très bien fait, et la texture du cuir a un style robuste. Je peux dire que vous êtes un artisan talentueux !$b$bMerci, $n, et voici vos tickets.';
-- Quest 7883 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7883, 'frFR', 'Yebb Nebblegear souhaite ajouter plus de talent à son spectacle, et il cherche partout le plus grand gnome du monde. Connaissez-vous des gnomes de taille considérable ??$B$BAvant qu\'il ne trouve le gnome, il veut que son costume soit prêt. Je pense qu\'un harnais barbare serait une bonne base pour le costume ; pouvez-vous en fabriquer quelques-uns et me les apporter ? Faites cela, et je vous donnerai une pile de tickets de Foire de la Lune Noire...') ON DUPLICATE KEY UPDATE CompletionText='Yebb Nebblegear souhaite ajouter plus de talent à son spectacle, et il cherche partout le plus grand gnome du monde. Connaissez-vous des gnomes de taille considérable ??$B$BAvant qu\'il ne trouve le gnome, il veut que son costume soit prêt. Je pense qu\'un harnais barbare serait une bonne base pour le costume ; pouvez-vous en fabriquer quelques-uns et me les apporter ? Faites cela, et je vous donnerai une pile de tickets de Foire de la Lune Noire...';
-- Quest 7883 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7883, 'frFR', 'Oh là là, celles-ci sont assez grandes !! Je ne peux pas imaginer trouver un gnome qui rentrerait parfaitement dedans, mais ne vous inquiétez pas - si le gnome que nous trouvons n\'est pas assez grand, je peux ajuster son costume.$b$bMerci beaucoup, $n. Voici les tickets que je vous ai promis.') ON DUPLICATE KEY UPDATE RewardText='Oh là là, celles-ci sont assez grandes !! Je ne peux pas imaginer trouver un gnome qui rentrerait parfaitement dedans, mais ne vous inquiétez pas - si le gnome que nous trouvons n\'est pas assez grand, je peux ajuster son costume.$b$bMerci beaucoup, $n. Voici les tickets que je vous ai promis.';
-- Quest 7884 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7884, 'frFR', 'Yebb travaille sur d\'autres attractions pour son zoo, y compris des habitations humides et marécageuses pour un garçon élevé par des crocodils, et peut-être pour un murloc. Nous aurons besoin de leggings étanches et jolis afin de ne pas être gorgés d\'eau pendant les montages et les démontages. Pour ce travail, je pense que des leggings en écailles de tortue feront l\'affaire.$B$B$N, pouvez-vous faire ces leggings ? Si vous le faites, alors une grosse pile de tickets de Foire de la Lune Noire sera votre récompense...') ON DUPLICATE KEY UPDATE CompletionText='Yebb travaille sur d\'autres attractions pour son zoo, y compris des habitations humides et marécageuses pour un garçon élevé par des crocodils, et peut-être pour un murloc. Nous aurons besoin de leggings étanches et jolis afin de ne pas être gorgés d\'eau pendant les montages et les démontages. Pour ce travail, je pense que des leggings en écailles de tortue feront l\'affaire.$B$B$N, pouvez-vous faire ces leggings ? Si vous le faites, alors une grosse pile de tickets de Foire de la Lune Noire sera votre récompense...';
-- Quest 7884 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7884, 'frFR', 'Super, vous les avez faits ! Ceux-ci feront l\'affaire... J\'espère juste que je ne serai pas celui qui nettoiera le cage de crocodils quand le moment viendra. Ces bêtes peuvent être assez sauvages, ne pensez-vous pas ??$B$BVoici vos tickets, $N. Profitez-en, et profitez de votre séjour à la Foire de la Lune Noire !') ON DUPLICATE KEY UPDATE RewardText='Super, vous les avez faits ! Ceux-ci feront l\'affaire... J\'espère juste que je ne serai pas celui qui nettoiera le cage de crocodils quand le moment viendra. Ces bêtes peuvent être assez sauvages, ne pensez-vous pas ??$B$BVoici vos tickets, $N. Profitez-en, et profitez de votre séjour à la Foire de la Lune Noire !';
-- Quest 7885 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7885, 'frFR', 'Vous ne vous en rendez peut-être pas compte, mais faire fonctionner un carnaval itinérant est coûteux ! Tout s\'use si vite qu\'il est étonnant que nous puissions faire un profit.$B$BEn raison de tous ces coûts cachés, nous cherchons toujours des moyens d\'entretenir notre équipement le moins cher possible. Nos tentes, par exemple, se déchirent régulièrement, mais j\'ai trouvé que les kits d\'armure en cuir faisaient d\'excellents patchs. Pouvez-vous me trouver et m\'apporter des kits d\'armure ? Cela nous fera économiser un paquet ! Faites cela, et j\'ai une poignée de tickets de Foire de la Lune Noire pour vous...') ON DUPLICATE KEY UPDATE CompletionText='Vous ne vous en rendez peut-être pas compte, mais faire fonctionner un carnaval itinérant est coûteux ! Tout s\'use si vite qu\'il est étonnant que nous puissions faire un profit.$B$BEn raison de tous ces coûts cachés, nous cherchons toujours des moyens d\'entretenir notre équipement le moins cher possible. Nos tentes, par exemple, se déchirent régulièrement, mais j\'ai trouvé que les kits d\'armure en cuir faisaient d\'excellents patchs. Pouvez-vous me trouver et m\'apporter des kits d\'armure ? Cela nous fera économiser un paquet ! Faites cela, et j\'ai une poignée de tickets de Foire de la Lune Noire pour vous...';
-- Quest 7886 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7886, 'frFR', 'Merci, $N. Vos exploits dans le Gully de Warsong résonnent dans toute la Forêt d\'Ashenvale.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Vos exploits dans le Gully de Warsong résonnent dans toute la Forêt d\'Ashenvale.';
-- Quest 7887 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7887, 'frFR', 'Merci, $N. Vos exploits dans le Gully de Warsong résonnent dans toute la Forêt d\'Ashenvale.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Vos exploits dans le Gully de Warsong résonnent dans toute la Forêt d\'Ashenvale.';
-- Quest 7888 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7888, 'frFR', 'Merci, $N. Vos exploits dans le Gully de Warsong résonnent dans toute la Forêt d\'Ashenvale.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Vos exploits dans le Gully de Warsong résonnent dans toute la Forêt d\'Ashenvale.';

-- Quest 7889 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7889, 'frFR', 'Il faut beaucoup de travail pour être la femme la plus forte vivante ! Mon ensemble de poids devient trop léger et si je veux rester en forme, j\'aurai besoin de plus de poids !$B$BPensez-vous pouvoir m\'apporter des pierres de poids ? Si oui, je vous donnerai un ticket de Foire de la Lune Noire.') ON DUPLICATE KEY UPDATE CompletionText='Il faut beaucoup de travail pour être la femme la plus forte vivante ! Mon ensemble de poids devient trop léger et si je veux rester en forme, j\'aurai besoin de plus de poids !$B$BPensez-vous pouvoir m\'apporter des pierres de poids ? Si oui, je vous donnerai un ticket de Foire de la Lune Noire.';
-- Quest 7889 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7889, 'frFR', 'Super !  Celles-ci fonctionneront très bien !  Elles ne sont pas trop lourdes, mais pas non plus trop légères.  Elles sont parfaites pour développer la masse musculaire !$B$BMerci beaucoup, <name>.  Voici votre ticket de Foire de la Lune Noire !') ON DUPLICATE KEY UPDATE RewardText='Super !  Celles-ci fonctionneront très bien !  Elles ne sont pas trop lourdes, mais pas non plus trop légères.  Elles sont parfaites pour développer la masse musculaire !$B$BMerci beaucoup, <name>.  Voici votre ticket de Foire de la Lune Noire !';
-- Quest 7890 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7890, 'frFR', 'Pour m\'aider à m\'entraîner, j\'aime faire passer un bâton entre des pierres de broyage lourdes, puis soulever le bâton au-dessus de ma tête. Ce n\'est pas facile, mais être la femme la plus forte au monde, comme je l\'ai, ne s\'obtient pas en restant assis !$B$BPouvez-vous m\'aider ? J\'ai besoin de plus de pierres de broyage - apportez-m\'en et je les échangerai contre des tickets de Foire de la Lune Noire.') ON DUPLICATE KEY UPDATE CompletionText='Pour m\'aider à m\'entraîner, j\'aime faire passer un bâton entre des pierres de broyage lourdes, puis soulever le bâton au-dessus de ma tête. Ce n\'est pas facile, mais être la femme la plus forte au monde, comme je l\'ai, ne s\'obtient pas en restant assis !$B$BPouvez-vous m\'aider ? J\'ai besoin de plus de pierres de broyage - apportez-m\'en et je les échangerai contre des tickets de Foire de la Lune Noire.';
-- Quest 7890 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7890, 'frFR', 'Vous avez apporté les pierres !  Et elles sont lourdes !  Je sens déjà mes muscles grossir.  Merci $Gname>!$B<br :>Voici, prenez ces tickets, et assurez-vous de ne pas manger trop de sucreries pendant votre visite à la foire.  Une grande et forte <class comme vous doit se maintenir en forme de combattante !') ON DUPLICATE KEY UPDATE RewardText='Vous avez apporté les pierres !  Et elles sont lourdes !  Je sens déjà mes muscles grossir.  Merci $Gname>!$B<br :>Voici, prenez ces tickets, et assurez-vous de ne pas manger trop de sucreries pendant votre visite à la foire.  Une grande et forte <class comme vous doit se maintenir en forme de combattante !';
-- Quest 7891 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7891, 'frFR', 'Je travaille sur un nouveau costume, pour quand j\'aurai mon propre stand en tant que femme la plus forte vivante ! Pour l\'instant, je cherche des brassards que je peux porter. Ils ne peuvent pas couvrir beaucoup car les gens veulent voir mes muscles, mais je veux quand même montrer un peu de couleur, vous voyez?$B$BQue diriez-vous de brassards en fer vert, $N? Pouvez-vous me faire des brassards en fer vert ? Si oui, alors j\'ai plein de tickets de Foire de la Lune Noire pour vous.') ON DUPLICATE KEY UPDATE CompletionText='Je travaille sur un nouveau costume, pour quand j\'aurai mon propre stand en tant que femme la plus forte vivante ! Pour l\'instant, je cherche des brassards que je peux porter. Ils ne peuvent pas couvrir beaucoup car les gens veulent voir mes muscles, mais je veux quand même montrer un peu de couleur, vous voyez?$B$BQue diriez-vous de brassards en fer vert, $N? Pouvez-vous me faire des brassards en fer vert ? Si oui, alors j\'ai plein de tickets de Foire de la Lune Noire pour vous.';
-- Quest 7891 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7891, 'frFR', 'Oui !  C\'est exactement ce dont j\'ai besoin !  Quelle jolie couleur, et ils laissent toujours mes bras nus pour que l\'on puisse voir à quel point ils sont forts !  Parfait!$B$BVoici, <name>.  Voici vos tickets - profitez-en !') ON DUPLICATE KEY UPDATE RewardText='Oui !  C\'est exactement ce dont j\'ai besoin !  Quelle jolie couleur, et ils laissent toujours mes bras nus pour que l\'on puisse voir à quel point ils sont forts !  Parfait!$B$BVoici, <name>.  Voici vos tickets - profitez-en !';
-- Quest 7892 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7892, 'frFR', 'Pour mon spectacle en tant que femme la plus forte vivante, je prévois d\'accepter des objets du public et de les briser avec une grosse massue noire !$B$BPouvez-vous me faire une grosse massue noire, $N?') ON DUPLICATE KEY UPDATE CompletionText='Pour mon spectacle en tant que femme la plus forte vivante, je prévois d\'accepter des objets du public et de les briser avec une grosse massue noire !$B$BPouvez-vous me faire une grosse massue noire, $N?';
-- Quest 7892 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7892, 'frFR', 'Ah, parfait !  Cette massue a une tête grosse et lourde.  Je parie que je pourrais briser presque n\'importe quoi avec elle.  J\'espère juste ne pas la casser en même temps que ce contre quoi je la balance !$B$BVoici vos tickets, <name>.  Profitez bien de votre séjour à la foire !') ON DUPLICATE KEY UPDATE RewardText='Ah, parfait !  Cette massue a une tête grosse et lourde.  Je parie que je pourrais briser presque n\'importe quoi avec elle.  J\'espère juste ne pas la casser en même temps que ce contre quoi je la balance !$B$BVoici vos tickets, <name>.  Profitez bien de votre séjour à la foire !';
-- Quest 7893 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7893, 'frFR', '$N, dans ma quête pour devenir la femme la plus forte vivante, j\'ai voyagé dans le monde et appris des secrets de musculation auprès de maîtres de poids lointains, de gourous de force et de manuels anciens. Je connais maintenant des exercices interdits qui tueraient les faibles et mutileraient les inexpérimentés !$B$BCes prouesses de force et d\'entraînement nécessitent un entraînement avec les pierres de broyage les plus denses. $N, pouvez-vous en trouver ou en fabriquer des pierres de broyage et me les apporter ? Je vous donnerai des tickets si vous le faites...') ON DUPLICATE KEY UPDATE CompletionText='$N, dans ma quête pour devenir la femme la plus forte vivante, j\'ai voyagé dans le monde et appris des secrets de musculation auprès de maîtres de poids lointains, de gourous de force et de manuels anciens. Je connais maintenant des exercices interdits qui tueraient les faibles et mutileraient les inexpérimentés !$B$BCes prouesses de force et d\'entraînement nécessitent un entraînement avec les pierres de broyage les plus denses. $N, pouvez-vous en trouver ou en fabriquer des pierres de broyage et me les apporter ? Je vous donnerai des tickets si vous le faites...';
-- Quest 7894 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7894, 'frFR', 'Yebb développe une nouvelle attraction pour le Zoo Bizarre, une qui fera devenir fous de merveille et de plaisir ! Mais cela demandera beaucoup de travail, et beaucoup de matériaux...$B$BCela inclut des modulateurs de cuivre. Nous avons besoin de beaucoup de modulateurs pour les parties mécaniques de l\'attraction. Apportez-moi des modulateurs de cuivre et je les échangerai contre un ticket de Foire de la Lune Noire.') ON DUPLICATE KEY UPDATE CompletionText='Yebb développe une nouvelle attraction pour le Zoo Bizarre, une qui fera devenir fous de merveille et de plaisir ! Mais cela demandera beaucoup de travail, et beaucoup de matériaux...$B$BCela inclut des modulateurs de cuivre. Nous avons besoin de beaucoup de modulateurs pour les parties mécaniques de l\'attraction. Apportez-moi des modulateurs de cuivre et je les échangerai contre un ticket de Foire de la Lune Noire.';
-- Quest 7895 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7895, 'frFR', 'Mon nouveau stand sera un spectacle à voir, oui monsieur ! Un spectacle à voir, et... pour quelques chanceux, à toucher !$B$J\'entends déjà les gizmos en bronze qui vrombissent en chantant leur chanson de ravissement mécanique lorsque les visiteurs viennent à mon stand et testent leur habileté !$B$Ah... maintenant j\'ai besoin des gizmos eux-mêmes pour rapprocher mon rêve de sa réalisation. S\'il vous plaît, $N, apportez-moi des gizmos en bronze qui vrombissent... et des tickets de Foire de la Lune Noire seront à vous !') ON DUPLICATE KEY UPDATE CompletionText='Mon nouveau stand sera un spectacle à voir, oui monsieur ! Un spectacle à voir, et... pour quelques chanceux, à toucher !$B$J\'entends déjà les gizmos en bronze qui vrombissent en chantant leur chanson de ravissement mécanique lorsque les visiteurs viennent à mon stand et testent leur habileté !$B$Ah... maintenant j\'ai besoin des gizmos eux-mêmes pour rapprocher mon rêve de sa réalisation. S\'il vous plaît, $N, apportez-moi des gizmos en bronze qui vrombissent... et des tickets de Foire de la Lune Noire seront à vous !';
-- Quest 7895 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7895, 'frFR', 'Vous avez apporté les gizmos !  Merveilleux !  Même maintenant, je peux entendre leur chœur bourdonnant et vrombissant dans mon esprit !  Oh, quand ce stand sera prêt, ce sera la merveille du monde, notez-le !$B$Voici vos tickets, <name>.  Et s\'il vous plaît, profitez de votre séjour à la foire !') ON DUPLICATE KEY UPDATE RewardText='Vous avez apporté les gizmos !  Merveilleux !  Même maintenant, je peux entendre leur chœur bourdonnant et vrombissant dans mon esprit !  Oh, quand ce stand sera prêt, ce sera la merveille du monde, notez-le !$B$Voici vos tickets, <name>.  Et s\'il vous plaît, profitez de votre séjour à la foire !';
-- Quest 7896 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7896, 'frFR', 'Quand j\'aurai enfin mis ce stand en marche, je voudrai faire de la publicité ! Et quelle meilleure façon y a-t-il pour faire de la publicité qu\'avec des feux d\'artifice?$B$Eh bien, certains pourraient penser que l\'odeur d\'une marmite, bouillonnant des têtes de vos ennemis, est meilleure pour attirer les foules, mais... nous sommes en compagnie mixte. Alors, ce sera des feux d\'artifice !$B$Apportez-moi des feux d\'artifice verts, $N, et j\'ai une grosse poignée de tickets de Foire de la Lune Noire pour vous.') ON DUPLICATE KEY UPDATE CompletionText='Quand j\'aurai enfin mis ce stand en marche, je voudrai faire de la publicité ! Et quelle meilleure façon y a-t-il pour faire de la publicité qu\'avec des feux d\'artifice?$B$Eh bien, certains pourraient penser que l\'odeur d\'une marmite, bouillonnant des têtes de vos ennemis, est meilleure pour attirer les foules, mais... nous sommes en compagnie mixte. Alors, ce sera des feux d\'artifice !$B$Apportez-moi des feux d\'artifice verts, $N, et j\'ai une grosse poignée de tickets de Foire de la Lune Noire pour vous.';
-- Quest 7896 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7896, 'frFR', 'Vous avez apporté les feux d\'artifice.  Travail merveilleux, <name>!  J\'ai hâte de les allumer et d\'annoncer au monde que mon stand est prêt !  Je dois encore attendre, un très long moment je crois, mais... je serai prêt quand je le serai, oui?$B$Voici les tickets, <name.  Amusez-vous !') ON DUPLICATE KEY UPDATE RewardText='Vous avez apporté les feux d\'artifice.  Travail merveilleux, <name>!  J\'ai hâte de les allumer et d\'annoncer au monde que mon stand est prêt !  Je dois encore attendre, un très long moment je crois, mais... je serai prêt quand je le serai, oui?$B$Voici les tickets, <name.  Amusez-vous !';
-- Quest 7897 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7897, 'frFR', 'La plus grande raison pour laquelle je ne peux pas ouvrir mon stand est que... tout est cassé ! J\'ai besoin de kits de réparation mécanique pour réparer tout ça !$B$Pouvez-vous m\'apporter ces kits, $N? Je vous les échange... des kits contre des tickets de Foire de la Lune Noire. Qu\'en dites-vous ?') ON DUPLICATE KEY UPDATE CompletionText='La plus grande raison pour laquelle je ne peux pas ouvrir mon stand est que... tout est cassé ! J\'ai besoin de kits de réparation mécanique pour réparer tout ça !$B$Pouvez-vous m\'apporter ces kits, $N? Je vous les échange... des kits contre des tickets de Foire de la Lune Noire. Qu\'en dites-vous ?';

-- Quest 7897 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7897, 'frFR', 'Merci !  Maintenant, je peux m\'attaquer aux réparations.$B$BÇa va prendre beaucoup de kits de réparation et beaucoup de nuits blanches pour que tout fonctionne correctement.  Parfois, je pense qu\'il serait mieux de revenir à mes racines et de relancer ma carrière de chasseur de têtes, mais... le Faire m\'a bien traité.$B$BPrends ces tickets, <name>, et amuse-toi bien !') ON DUPLICATE KEY UPDATE RewardText='Merci !  Maintenant, je peux m\'attaquer aux réparations.$B$BÇa va prendre beaucoup de kits de réparation et beaucoup de nuits blanches pour que tout fonctionne correctement.  Parfois, je pense qu\'il serait mieux de revenir à mes racines et de relancer ma carrière de chasseur de têtes, mais... le Faire m\'a bien traité.$B$BPrends ces tickets, <name>, et amuse-toi bien !';
-- Quest 7898 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7898, 'frFR', 'Yebb Nebblegear, comme moi, travaille sur une attraction future. Cette attraction est si incroyable, dit Nebb, qu\'elle attirera des gens du monde entier... et cela nous rendra tous très, très riches !$B$BIl dit qu\'il a besoin de widgets de thorium pour sa construction, et veut que je les collecte pour lui. Alors, qu\'en dis-tu, $N? Sais-tu où trouver des widgets de thorium ? Si tu es ingénieur, peux-tu les fabriquer ? Veux-tu les échanger contre des tickets du Darkmoon Faire ?') ON DUPLICATE KEY UPDATE CompletionText='Yebb Nebblegear, comme moi, travaille sur une attraction future. Cette attraction est si incroyable, dit Nebb, qu\'elle attirera des gens du monde entier... et cela nous rendra tous très, très riches !$B$BIl dit qu\'il a besoin de widgets de thorium pour sa construction, et veut que je les collecte pour lui. Alors, qu\'en dis-tu, $N? Sais-tu où trouver des widgets de thorium ? Si tu es ingénieur, peux-tu les fabriquer ? Veux-tu les échanger contre des tickets du Darkmoon Faire ?';
-- Quest 7898 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7898, 'frFR', 'Ah, merci, $Gname>!  Yebb appréciera ces widgets.  Je ne sais pas ce qu\'il a prévu pour eux, mais Yebb est un petit gnome malin.  Il est malin, et peut-être un peu diabolique....$B$BSi seulement il aimait le goût de chair humanoïde... il ferait un excellent troll !$B<br :>Voici, <name.  Un accord est un accord, et ces tickets sont les tiens.') ON DUPLICATE KEY UPDATE RewardText='Ah, merci, $Gname>!  Yebb appréciera ces widgets.  Je ne sais pas ce qu\'il a prévu pour eux, mais Yebb est un petit gnome malin.  Il est malin, et peut-être un peu diabolique....$B$BSi seulement il aimait le goût de chair humanoïde... il ferait un excellent troll !$B<br :>Voici, <name.  Un accord est un accord, et ces tickets sont les tiens.';
-- Quest 7899 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7899, 'frFR', 'La première leçon pour attirer une foule est : les attirer avec des gadgets et des bibelots ! Peux-tu m\'aider?$B$J\'ai besoin de petites pattes poilues à utiliser comme prix. Tu peux les trouver sur les chats des Barrens ou de Darkshore....$B$Apporte-moi quelques pattes et je t\'échangerai un ticket du Darkmoon Faire contre elles.') ON DUPLICATE KEY UPDATE CompletionText='La première leçon pour attirer une foule est : les attirer avec des gadgets et des bibelots ! Peux-tu m\'aider?$B$J\'ai besoin de petites pattes poilues à utiliser comme prix. Tu peux les trouver sur les chats des Barrens ou de Darkshore....$B$Apporte-moi quelques pattes et je t\'échangerai un ticket du Darkmoon Faire contre elles.';
-- Quest 7899 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7899, 'frFR', 'Super, tu les as !  Nous pouvons les utiliser pour fabriquer des jouets et des bibelots, et ceux-ci attireront plus de monde au Faire !$B$Voici ton ticket, <name>.  Tu l\'as mérité !') ON DUPLICATE KEY UPDATE RewardText='Super, tu les as !  Nous pouvons les utiliser pour fabriquer des jouets et des bibelots, et ceux-ci attireront plus de monde au Faire !$B$Voici ton ticket, <name>.  Tu l\'as mérité !';
-- Quest 7900 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7900, 'frFR', 'Les enfants adorent les jouets ! Et peu importe la race, j\'ai trouvé que tous les enfants adorent les jouets en peluche et poilus faits à partir de peaux de ours déchirées !$B$Tu peux obtenir ces peaux auprès des ours d\'Ashenvale ou de Hillsbrad. Apporte-m\'en une bonne quantité et gagne toi une bonne quantité de tickets du Darkmoon Faire !') ON DUPLICATE KEY UPDATE CompletionText='Les enfants adorent les jouets ! Et peu importe la race, j\'ai trouvé que tous les enfants adorent les jouets en peluche et poilus faits à partir de peaux de ours déchirées !$B$Tu peux obtenir ces peaux auprès des ours d\'Ashenvale ou de Hillsbrad. Apporte-m\'en une bonne quantité et gagne toi une bonne quantité de tickets du Darkmoon Faire !';
-- Quest 7900 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7900, 'frFR', 'De belles peaux, <name> !  Je vais faire en sorte que quelqu\'un les coude dans une série de jouets en peluche.  Avec un peu de rembourrage et de peinture, je pense qu\'ils seront l\'envie des enfants d\'Azeroth !$B$Des tickets ?  Ah oui, ton paiement !  Voici !') ON DUPLICATE KEY UPDATE RewardText='De belles peaux, <name> !  Je vais faire en sorte que quelqu\'un les coude dans une série de jouets en peluche.  Avec un peu de rembourrage et de peinture, je pense qu\'ils seront l\'envie des enfants d\'Azeroth !$B$Des tickets ?  Ah oui, ton paiement !  Voici !';
-- Quest 7901 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7901, 'frFR', 'C\'est incroyable ce que les gens valorisent ! Prends, par exemple, un bâton en bois avec une douce queue touffue attachée. Maintenant, toi et moi, nous pourrions penser que quelque chose comme ça n\'a pas beaucoup de valeur... mais si tu donnes un joli nom à cette babiola comme "Queue de Fauve Sauvage" et que tu la mets dans une jolie boîte, alors les gens penseront qu\'elle a de la valeur. La poubelle devient un trésor !$B$Apporte-moi des queues touffues et douces des loups de Desolace et des Badlands, et je te donnerai des tickets du Darkmoon Faire.') ON DUPLICATE KEY UPDATE CompletionText='C\'est incroyable ce que les gens valorisent ! Prends, par exemple, un bâton en bois avec une douce queue touffue attachée. Maintenant, toi et moi, nous pourrions penser que quelque chose comme ça n\'a pas beaucoup de valeur... mais si tu donnes un joli nom à cette babiola comme "Queue de Fauve Sauvage" et que tu la mets dans une jolie boîte, alors les gens penseront qu\'elle a de la valeur. La poubelle devient un trésor !$B$Apporte-moi des queues touffues et douces des loups de Desolace et des Badlands, et je te donnerai des tickets du Darkmoon Faire.';
-- Quest 7901 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7901, 'frFR', 'Bien fait, <name> !  Ces queues feront de superbes prix pour nos visiteurs, et cela signifie des visiteurs heureux... qui parlent à leurs amis et amènent plus de visiteurs !$B$Voici tes tickets !  Passe un bon moment au Darkmoon Faire... et n\'oublie pas de nous en parler à tes amis !') ON DUPLICATE KEY UPDATE RewardText='Bien fait, <name> !  Ces queues feront de superbes prix pour nos visiteurs, et cela signifie des visiteurs heureux... qui parlent à leurs amis et amènent plus de visiteurs !$B$Voici tes tickets !  Passe un bon moment au Darkmoon Faire... et n\'oublie pas de nous en parler à tes amis !';
-- Quest 7902 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7902, 'frFR', 'L\'imagination d\'une personne est une chose incroyable. Elle peut faire paraître la plus petite colline comme la plus grande montagne. Elle peut faire apparaître la plus innocente des ombres comme étant projetée par un cauchemar horrible !$B$Nous, au Darkmoon Faire, laissons l\'imagination de nos visiteurs s\'épanouir ! Mais pour aider à étirer leur imagination... nous devons parfois être malins.$B$J\'ai besoin de plumes vibrantes pour l\'une de mes attractions. Tu peux les obtenir auprès des oiseaux des zones plus dangereuses d\'Azeroth. Apporte-moi les plumes et beaucoup de tickets seront les tiens !') ON DUPLICATE KEY UPDATE CompletionText='L\'imagination d\'une personne est une chose incroyable. Elle peut faire paraître la plus petite colline comme la plus grande montagne. Elle peut faire apparaître la plus innocente des ombres comme étant projetée par un cauchemar horrible !$B$Nous, au Darkmoon Faire, laissons l\'imagination de nos visiteurs s\'épanouir ! Mais pour aider à étirer leur imagination... nous devons parfois être malins.$B$J\'ai besoin de plumes vibrantes pour l\'une de mes attractions. Tu peux les obtenir auprès des oiseaux des zones plus dangereuses d\'Azeroth. Apporte-moi les plumes et beaucoup de tickets seront les tiens !';
-- Quest 7903 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7903, 'frFR', 'Te retrouves-tu parfois à errer dans une grotte, tard la nuit, à la recherche d\'aventure ? Tu le fais ? Vraiment ? Eh bien, alors tu as vu les yeux effrayants des chauves-souris te fixant d\'en haut, attendant que tu baisses ta garde pour qu\'ils puissent te saigner !$B$Pensée effrayante, ne trouves-tu pas ? Bien sûr ! Il n\'est aucun doute que les yeux de chauve-souris sont effrayants !$B$Voudras-tu m\'apporter quelques yeux de chauve-souris maléfiques, $N? Je les veux pour... quelque chose que je suis en train de concevoir. Quelque chose d\'effrayant.$B$Tu peux les obtenir auprès des chauves-souris des Plaines de la Peste Orientales.') ON DUPLICATE KEY UPDATE CompletionText='Te retrouves-tu parfois à errer dans une grotte, tard la nuit, à la recherche d\'aventure ? Tu le fais ? Vraiment ? Eh bien, alors tu as vu les yeux effrayants des chauves-souris te fixant d\'en haut, attendant que tu baisses ta garde pour qu\'ils puissent te saigner !$B$Pensée effrayante, ne trouves-tu pas ? Bien sûr ! Il n\'est aucun doute que les yeux de chauve-souris sont effrayants !$B$Voudras-tu m\'apporter quelques yeux de chauve-souris maléfiques, $N? Je les veux pour... quelque chose que je suis en train de concevoir. Quelque chose d\'effrayant.$B$Tu peux les obtenir auprès des chauves-souris des Plaines de la Peste Orientales.';
-- Quest 7905 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7905, 'frFR', 'Oui ami, puis-je vous aider ? Avez-vous un bon d\'achat à échanger ?') ON DUPLICATE KEY UPDATE CompletionText='Oui ami, puis-je vous aider ? Avez-vous un bon d\'achat à échanger ?';
-- Quest 7921 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7921, 'frFR', 'Merci, $N$. Tes exploits dans Warsong Gulch résonnent dans toute la Forêt d\'Ashenvale.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N$. Tes exploits dans Warsong Gulch résonnent dans toute la Forêt d\'Ashenvale.';
-- Quest 7922 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7922, 'frFR', 'Les elfes de la nuit et leurs alliés doivent trembler au simple murmure de ton nom ! Pour la Horde !') ON DUPLICATE KEY UPDATE RewardText='Les elfes de la nuit et leurs alliés doivent trembler au simple murmure de ton nom ! Pour la Horde !';
