INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7930, 'frFR', 'Avancez, avancez ! Si vous avez des tickets de la Foire de la Lune Noire que vous souhaitez faire échanger, dites-le moi ! Vous pouvez échanger des tickets de différentes valeurs contre des prix merveilleux et fantastiques. N\'ayez pas peur, essayez !') ON DUPLICATE KEY UPDATE CompletionText='Avancez, avancez ! Si vous avez des tickets de la Foire de la Lune Noire que vous souhaitez faire échanger, dites-le moi ! Vous pouvez échanger des tickets de différentes valeurs contre des prix merveilleux et fantastiques. N\'ayez pas peur, essayez !';
