INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7934, 'frFR', 'Voici, voici ! Un prix digne d\'un roi ! Félicitations à vous, mon ami !$b$bSi vous avez d\'autres tickets que vous souhaitez remettre, faites-le moi savoir ! Tant que la Foire de la Lune Noire est là, j\'échangerai vos tickets.') ON DUPLICATE KEY UPDATE RewardText='Voici, voici ! Un prix digne d\'un roi ! Félicitations à vous, mon ami !$b$bSi vous avez d\'autres tickets que vous souhaitez remettre, faites-le moi savoir ! Tant que la Foire de la Lune Noire est là, j\'échangerai vos tickets.';
