-- Quest 7937 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7937, 'frFR', 'Cette botte de foin ressemble à celle de votre vision.') ON DUPLICATE KEY UPDATE CompletionText='Cette botte de foin ressemble à celle de votre vision.';
-- Quest 7937 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7937, 'frFR', 'Une brève recherche dans la botte de foin révèle une boîte au trésor à l\'intérieur !  Il semble que vous ayez trouvé votre fortune !') ON DUPLICATE KEY UPDATE RewardText='Une brève recherche dans la botte de foin révèle une boîte au trésor à l\'intérieur !  Il semble que vous ayez trouvé votre fortune !';
-- Quest 7938 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7938, 'frFR', 'Ce coffre ressemble à celui de votre vision...') ON DUPLICATE KEY UPDATE CompletionText='Ce coffre ressemble à celui de votre vision...';

-- Quest 7938 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7938, 'frFR', 'Une brève recherche dans le coffre révèle une boîte de rangement à l\'intérieur ! Il semblerait que vous ayez trouvé votre fortune !') ON DUPLICATE KEY UPDATE RewardText='Une brève recherche dans le coffre révèle une boîte de rangement à l\'intérieur ! Il semblerait que vous ayez trouvé votre fortune !';
-- Quest 7939 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7939, 'frFR', '$N, merci pour toute l\'aide que vous m\'avez apportée. Je ne peux vraiment vous remercier assez !$B$BBien que mon besoin ne soit plus grand... si vous m\'apportez plus de pierres de broyage denses, j\'ai encore des tickets de la Foire de la Lune Noire pour vous.') ON DUPLICATE KEY UPDATE CompletionText='$N, merci pour toute l\'aide que vous m\'avez apportée. Je ne peux vraiment vous remercier assez !$B$BBien que mon besoin ne soit plus grand... si vous m\'apportez plus de pierres de broyage denses, j\'ai encore des tickets de la Foire de la Lune Noire pour vous.';
-- Quest 7940 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7940, 'frFR', 'Avancez, avancez ! Si vous avez des tickets de la Foire de la Lune Noire que vous souhaitez faire échanger, dites-le simplement ! Vous pouvez échanger des tickets de différentes valeurs contre des prix merveilleux et fantastiques. N\'ayez pas peur, essayez !') ON DUPLICATE KEY UPDATE CompletionText='Avancez, avancez ! Si vous avez des tickets de la Foire de la Lune Noire que vous souhaitez faire échanger, dites-le simplement ! Vous pouvez échanger des tickets de différentes valeurs contre des prix merveilleux et fantastiques. N\'ayez pas peur, essayez !';
-- Quest 7940 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7940, 'frFR', 'Voici, voici ! Un prix digne d\'un roi ! Félicitations, mon ami !$b$bSi vous avez plus de tickets que vous souhaitez remettre, faites-le-moi savoir ! Tant que la Foire de la Lune Noire est là, j\'échangerai vos tickets.') ON DUPLICATE KEY UPDATE RewardText='Voici, voici ! Un prix digne d\'un roi ! Félicitations, mon ami !$b$bSi vous avez plus de tickets que vous souhaitez remettre, faites-le-moi savoir ! Tant que la Foire de la Lune Noire est là, j\'échangerai vos tickets.';
-- Quest 7941 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7941, 'frFR', '$N, je dois vous remercier pour toute votre aide. J\'ai beaucoup de fournitures, grâce à vos efforts non négligeables, mais si vous souhaitez m\'apporter plus de kits d\'armure, je les échangerai volontiers contre des tickets de la Foire de la Lune Noire.') ON DUPLICATE KEY UPDATE CompletionText='$N, je dois vous remercier pour toute votre aide. J\'ai beaucoup de fournitures, grâce à vos efforts non négligeables, mais si vous souhaitez m\'apporter plus de kits d\'armure, je les échangerai volontiers contre des tickets de la Foire de la Lune Noire.';
-- Quest 7941 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7941, 'frFR', 'Le voici, $n. Un échange équitable. Profitez-en.') ON DUPLICATE KEY UPDATE RewardText='Le voici, $n. Un échange équitable. Profitez-en.';
-- Quest 7942 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7942, 'frFR', '$N, vous avez été si gentil avec nous, en m\'apportant des biens sans vous fatiguer. Vous avez mes remerciements éternels !$B$BBien que notre besoin de widgets de Thorium ne soit pas aussi grand qu\'auparavant, vous pouvez toujours m\'en apporter et je les échangerai volontiers contre des tickets de la Foire de la Lune Noire.') ON DUPLICATE KEY UPDATE CompletionText='$N, vous avez été si gentil avec nous, en m\'apportant des biens sans vous fatiguer. Vous avez mes remerciements éternels !$B$BBien que notre besoin de widgets de Thorium ne soit pas aussi grand qu\'auparavant, vous pouvez toujours m\'en apporter et je les échangerai volontiers contre des tickets de la Foire de la Lune Noire.';
-- Quest 7943 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7943, 'frFR', '$N, l\'attraction que je conçois sera l\'événement le plus effrayant depuis que Gnomeregan a été envahi ! Et c\'est largement grâce à vous et à toutes les babioles que vous m\'avez apportées. Merci beaucoup !$B$BI ne veux pas grand-chose d\'autre, mais... si vous m\'apportez plus d\'yeux de bat maléfiques des chauves-souris des Plaguelands de l\'Est... je pourrais avoir plus de tickets de la Foire de la Lune Noire pour vous.') ON DUPLICATE KEY UPDATE CompletionText='$N, l\'attraction que je conçois sera l\'événement le plus effrayant depuis que Gnomeregan a été envahi ! Et c\'est largement grâce à vous et à toutes les babioles que vous m\'avez apportées. Merci beaucoup !$B$BI ne veux pas grand-chose d\'autre, mais... si vous m\'apportez plus d\'yeux de bat maléfiques des chauves-souris des Plaguelands de l\'Est... je pourrais avoir plus de tickets de la Foire de la Lune Noire pour vous.';
-- Quest 7943 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7943, 'frFR', 'Merci encore, <name>. Voici vos tickets !') ON DUPLICATE KEY UPDATE RewardText='Merci encore, <name>. Voici vos tickets !';
