INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7945, 'frFR', 'Une brève recherche dans le souche d\'arbre révèle une boîte de rangement à l\'intérieur ! Il semblerait que vous ayez trouvé votre fortune !') ON DUPLICATE KEY UPDATE RewardText='Une brève recherche dans le souche d\'arbre révèle une boîte de rangement à l\'intérieur ! Il semblerait que vous ayez trouvé votre fortune !';
-- Quest 7946 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7946, 'frFR', 'Je suis si heureux que Jubjub ne soit plus perdue. Elle adore l\'ale de Fer Noir tellement que quand je suis tombé à court... elle s\'est enfuie pour en trouver plus !$B$BMaintenant que Jubjub est de retour, je veux autant d\'ale que je peux obtenir ! Je ne veux pas qu\'elle s\'enfuie à nouveau !$B$BAvez-vous de l\'ale de Fer Noir ? Si oui, alors je vous échangerai un des œufs de grenouille de Jubjub contre une mug...') ON DUPLICATE KEY UPDATE CompletionText='Je suis si heureux que Jubjub ne soit plus perdue. Elle adore l\'ale de Fer Noir tellement que quand je suis tombé à court... elle s\'est enfuie pour en trouver plus !$B$BMaintenant que Jubjub est de retour, je veux autant d\'ale que je peux obtenir ! Je ne veux pas qu\'elle s\'enfuie à nouveau !$B$BAvez-vous de l\'ale de Fer Noir ? Si oui, alors je vous échangerai un des œufs de grenouille de Jubjub contre une mug...';
-- Quest 7981 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7981, 'frFR', 'Avancez, avancez ! Si vous avez des tickets de la Foire de la Lune Noire que vous souhaitez faire échanger, dites-le simplement ! Vous pouvez échanger des tickets de différentes valeurs contre des prix merveilleux et fantastiques. N\'ayez pas peur, essayez !') ON DUPLICATE KEY UPDATE CompletionText='Avancez, avancez ! Si vous avez des tickets de la Foire de la Lune Noire que vous souhaitez faire échanger, dites-le simplement ! Vous pouvez échanger des tickets de différentes valeurs contre des prix merveilleux et fantastiques. N\'ayez pas peur, essayez !';

-- Quest 7981 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7981, 'frFR', 'Voici, voici ! Un prix digne d\'un $gking:queen ;! Félicitations à toi, mon ami ! $B$BSi tu as d\'autres tickets que tu souhaites échanger, alors fais-le moi savoir ! Tant que la Foire de la Lune Noire est là, j\'échangerai tes tickets.') ON DUPLICATE KEY UPDATE RewardText='Voici, voici ! Un prix digne d\'un $gking:queen ;! Félicitations à toi, mon ami ! $B$BSi tu as d\'autres tickets que tu souhaites échanger, alors fais-le moi savoir ! Tant que la Foire de la Lune Noire est là, j\'échangerai tes tickets.';
-- Quest 8041 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8041, 'frFR', 'Salut, $c. Je suis Jin\'rokh le Briseur, troll de Mugamba. Nous, de la tribu de Zandalar, reconnaissons tes accomplissements. Nous saluons ta ténacité et ta force de volonté.$b$bPorte ce talisman autour de ton cou, $c. Que la force du Mont Mugamba coule à travers ton être. Sois fort alors que tu abattrais nos ennemis !') ON DUPLICATE KEY UPDATE RewardText='Salut, $c. Je suis Jin\'rokh le Briseur, troll de Mugamba. Nous, de la tribu de Zandalar, reconnaissons tes accomplissements. Nous saluons ta ténacité et ta force de volonté.$b$bPorte ce talisman autour de ton cou, $c. Que la force du Mont Mugamba coule à travers ton être. Sois fort alors que tu abattrais nos ennemis !';
-- Quest 8042 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8042, 'frFR', 'C\'est bon de te voir en bonne santé, $n. Les glorieuses batailles que tu as entreprises affectent toute vie sur cette planète. Hakkar ne doit jamais quitter les confins de Zul\'Gurub car le monde s\'effondrera certainement sous sa faim immense.$b$bDonne-moi ton talisman et j\'amplifierai sa puissance. Utilise la Force de Mugamba pour punir nos ennemis !') ON DUPLICATE KEY UPDATE CompletionText='C\'est bon de te voir en bonne santé, $n. Les glorieuses batailles que tu as entreprises affectent toute vie sur cette planète. Hakkar ne doit jamais quitter les confins de Zul\'Gurub car le monde s\'effondrera certainement sous sa faim immense.$b$bDonne-moi ton talisman et j\'amplifierai sa puissance. Utilise la Force de Mugamba pour punir nos ennemis !';
-- Quest 8042 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8042, 'frFR', 'Nos chemins se croiseront à nouveau, $C.') ON DUPLICATE KEY UPDATE RewardText='Nos chemins se croiseront à nouveau, $C.';
-- Quest 8043 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8043, 'frFR', 'Maître $n, tu reviens ! Molthor a envoyé des nouvelles de tes exploits au Roi. Ton nom est connu même dans les Mers du Sud. Peut-être qu\'un jour tu seras un $c légendaire - une histoire pour les âges.$b$bDonne-moi ton talisman afin que je puisse une fois de plus amplifier son pouvoir.') ON DUPLICATE KEY UPDATE CompletionText='Maître $n, tu reviens ! Molthor a envoyé des nouvelles de tes exploits au Roi. Ton nom est connu même dans les Mers du Sud. Peut-être qu\'un jour tu seras un $c légendaire - une histoire pour les âges.$b$bDonne-moi ton talisman afin que je puisse une fois de plus amplifier son pouvoir.';
-- Quest 8043 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8043, 'frFR', 'Utilise ta nouvelle force pour détruire les Gurubashi !') ON DUPLICATE KEY UPDATE RewardText='Utilise ta nouvelle force pour détruire les Gurubashi !';
-- Quest 8044 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8044, 'frFR', 'Le Roi Rastakhan te salue, Maître $n. Un tel honneur n\'a jamais été donné à quelqu\'un en dehors de la tribu de Zandalar.$b$b<Jin\'rokh s\'incline.>$b$bDonne-moi ton talisman afin que je puisse l\'améliorer une fois de plus. Sache que la Rage de Mugamba est maintenant intrinsèquement liée à ton âme même.') ON DUPLICATE KEY UPDATE CompletionText='Le Roi Rastakhan te salue, Maître $n. Un tel honneur n\'a jamais été donné à quelqu\'un en dehors de la tribu de Zandalar.$b$b<Jin\'rokh s\'incline.>$b$bDonne-moi ton talisman afin que je puisse l\'améliorer une fois de plus. Sache que la Rage de Mugamba est maintenant intrinsèquement liée à ton âme même.';
-- Quest 8044 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8044, 'frFR', 'Zul\'jin serait jaloux, $c. Va et conquiers !') ON DUPLICATE KEY UPDATE RewardText='Zul\'jin serait jaloux, $c. Va et conquiers !';
-- Quest 8045 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8045, 'frFR', 'Sache ceci, païen : Une catastrophe nous a réunis. Tes voies païennes ne sont ni comprises ni appréciées par Zandalar, mais nous sommes un peuple juste. Porte ce signe autour de ton cou. Il servira à la fois d\'avertissement à nos ennemis et de symbole de ton amitié avec Zandalar.$b$bContinue de servir notre peuple et j\'amplifierai le pouvoir du signe.') ON DUPLICATE KEY UPDATE RewardText='Sache ceci, païen : Une catastrophe nous a réunis. Tes voies païennes ne sont ni comprises ni appréciées par Zandalar, mais nous sommes un peuple juste. Porte ce signe autour de ton cou. Il servira à la fois d\'avertissement à nos ennemis et de symbole de ton amitié avec Zandalar.$b$bContinue de servir notre peuple et j\'amplifierai le pouvoir du signe.';
-- Quest 8046 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8046, 'frFR', 'J\'ai peut-être été trop hâtif dans mon jugement, $c. Il semble que ta foi aveugle en cette Lumière ait une certaine valeur après tout.$b$bDonne-moi ton signe et j\'amplifierai son pouvoir.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai peut-être été trop hâtif dans mon jugement, $c. Il semble que ta foi aveugle en cette Lumière ait une certaine valeur après tout.$b$bDonne-moi ton signe et j\'amplifierai son pouvoir.';
-- Quest 8046 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8046, 'frFR', 'Fais ce que tu dois pour vaincre nos ennemis, $C. Même si cela signifie canaliser la Lumière.$B$B<Jin\'rokh frissonne.>') ON DUPLICATE KEY UPDATE RewardText='Fais ce que tu dois pour vaincre nos ennemis, $C. Même si cela signifie canaliser la Lumière.$B$B<Jin\'rokh frissonne.>';
-- Quest 8047 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8047, 'frFR', 'Je dois avouer, je ne pensais pas que tu avais la résolution de mener cette cause à terme, $c. Zandalar te considère maintenant comme un allié inestimable. Bien fait, en effet.$b$bDonne-moi ton signe et j\'amplifierai une fois de plus son pouvoir.') ON DUPLICATE KEY UPDATE CompletionText='Je dois avouer, je ne pensais pas que tu avais la résolution de mener cette cause à terme, $c. Zandalar te considère maintenant comme un allié inestimable. Bien fait, en effet.$b$bDonne-moi ton signe et j\'amplifierai une fois de plus son pouvoir.';
-- Quest 8047 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8047, 'frFR', 'Nos croyances diffèrent mais notre cause est juste. Abatrez nos ennemis, noble $C.') ON DUPLICATE KEY UPDATE RewardText='Nos croyances diffèrent mais notre cause est juste. Abatrez nos ennemis, noble $C.';
-- Quest 8048 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8048, 'frFR', 'Le Roi a reconnu ton existence, $c. Tu es le premier de ton espèce à être accepté par Rastakhan comme un véritable allié de Zandalar.$b$bTu seras récompensé grandement pour tes efforts. Présente ton signe et j\'appliquerai l\'amplification finale.') ON DUPLICATE KEY UPDATE CompletionText='Le Roi a reconnu ton existence, $c. Tu es le premier de ton espèce à être accepté par Rastakhan comme un véritable allié de Zandalar.$b$bTu seras récompensé grandement pour tes efforts. Présente ton signe et j\'appliquerai l\'amplification finale.';
-- Quest 8048 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8048, 'frFR', 'Vigilance, honneur, loyauté, bravoure... Tu incarnes toutes ces qualités et ton signe le fera aussi.') ON DUPLICATE KEY UPDATE RewardText='Vigilance, honneur, loyauté, bravoure... Tu incarnes toutes ces qualités et ton signe le fera aussi.';

-- Quest 8049 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8049, 'frFR', 'Accepte ce talisman comme un signe de notre appréciation, $c.$b$bL\'Œil de Zuldazar grandira en puissance à mesure que votre lien avec les trolls de Zandalar se renforcera. Revenez me voir périodiquement et je imprégnerai le joyau.') ON DUPLICATE KEY UPDATE RewardText='Accepte ce talisman comme un signe de notre appréciation, $c.$b$bL\'Œil de Zuldazar grandira en puissance à mesure que votre lien avec les trolls de Zandalar se renforcera. Revenez me voir périodiquement et je imprégnerai le joyau.';
-- Quest 8050 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8050, 'frFR', 'Des récits de vos batailles contre les Gurubashi sont murmurés dans les vents, prêtresse. Même la royauté commence à parler de vos exploits. Il est dit que le Roi Rastakhan vous a même mentionnée par son nom.$b$bIl est temps d\'imprégner l\'Œil. Donnez-moi le talisman et j\'accomplirai le service.') ON DUPLICATE KEY UPDATE CompletionText='Des récits de vos batailles contre les Gurubashi sont murmurés dans les vents, prêtresse. Même la royauté commence à parler de vos exploits. Il est dit que le Roi Rastakhan vous a même mentionnée par son nom.$b$bIl est temps d\'imprégner l\'Œil. Donnez-moi le talisman et j\'accomplirai le service.';
-- Quest 8050 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8050, 'frFR', 'Soyez résolu dans vos entreprises, $N. Le Flayer d\'Âmes tentera de siphonner votre volonté de vivre.') ON DUPLICATE KEY UPDATE RewardText='Soyez résolu dans vos entreprises, $N. Le Flayer d\'Âmes tentera de siphonner votre volonté de vivre.';
-- Quest 8051 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8051, 'frFR', 'Bienvenue $c. L\'Œil de Zuldazar pulse d\'énergie. Vous êtes prêt à faire le pas suivant. Donnez-moi le talisman et j\'accomplirai l\'imprégnation.') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue $c. L\'Œil de Zuldazar pulse d\'énergie. Vous êtes prêt à faire le pas suivant. Donnez-moi le talisman et j\'accomplirai l\'imprégnation.';
-- Quest 8051 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8051, 'frFR', 'Continuez votre bataille contre le Flayer d\'Âmes et ses sbires, $N. Il ne doit jamais être permis de quitter les confins de Zul\'Gurub.') ON DUPLICATE KEY UPDATE RewardText='Continuez votre bataille contre le Flayer d\'Âmes et ses sbires, $N. Il ne doit jamais être permis de quitter les confins de Zul\'Gurub.';
-- Quest 8052 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8052, 'frFR', 'Si seulement nous avions dix mille comme vous, $n. Les armées de Hakkar seraient dispersées dans le vent en un clin d\'œil.$b$b<Al\'tabim soupire.>$b$bMalheureusement, l\'Œil est prêt à réaliser son plein potentiel. Donnez-le-moi.') ON DUPLICATE KEY UPDATE CompletionText='Si seulement nous avions dix mille comme vous, $n. Les armées de Hakkar seraient dispersées dans le vent en un clin d\'œil.$b$b<Al\'tabim soupire.>$b$bMalheureusement, l\'Œil est prêt à réaliser son plein potentiel. Donnez-le-moi.';
-- Quest 8052 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8052, 'frFR', 'Écrasez-les tous et laissez Hakkar s\'en occuper...') ON DUPLICATE KEY UPDATE RewardText='Écrasez-les tous et laissez Hakkar s\'en occuper...';
-- Quest 8053 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8053, 'frFR', 'Vous êtes revenu ? Avez-vous les Paragons de Puissance ? Êtes-vous en train de me faire perdre mon temps?$B$J\'espère ne pas, païen.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu ? Avez-vous les Paragons de Puissance ? Êtes-vous en train de me faire perdre mon temps?$B$J\'espère ne pas, païen.';
-- Quest 8053 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8053, 'frFR', 'Vous faites beaucoup pour nous honorer.  Vos mains dégoulinent du sang des sbires de Hakkar.  Vous êtes un ami de la tribu.$B$Portez ces brassards.  Ce sont les armures des penseurs libres.  C\'est ce que je veux dire par la vraie puissance.') ON DUPLICATE KEY UPDATE RewardText='Vous faites beaucoup pour nous honorer.  Vos mains dégoulinent du sang des sbires de Hakkar.  Vous êtes un ami de la tribu.$B$Portez ces brassards.  Ce sont les armures des penseurs libres.  C\'est ce que je veux dire par la vraie puissance.';
-- Quest 8054 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8054, 'frFR', 'Votre présence signifie la victoire ? Avez-vous les Paragons ? Êtes-vous dégoulinant des restes de vos ennemis ?') ON DUPLICATE KEY UPDATE CompletionText='Votre présence signifie la victoire ? Avez-vous les Paragons ? Êtes-vous dégoulinant des restes de vos ennemis ?';
-- Quest 8054 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8054, 'frFR', 'Votre honneur est assuré au sein de la tribu.  Vous réclamez de nombreuses morts à Zul\'Gurub.  Les ennemis tombent devant vos convictions.  Les ennemis tombent devant votre puissance.$B$Ceinture des penseurs libres.  C\'est un symbole d\'honneur.  C\'est un puissant mojo.  C\'est à vous maintenant.') ON DUPLICATE KEY UPDATE RewardText='Votre honneur est assuré au sein de la tribu.  Vous réclamez de nombreuses morts à Zul\'Gurub.  Les ennemis tombent devant vos convictions.  Les ennemis tombent devant votre puissance.$B$Ceinture des penseurs libres.  C\'est un symbole d\'honneur.  C\'est un puissant mojo.  C\'est à vous maintenant.';
-- Quest 8055 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8055, 'frFR', 'Avez-vous les Paragons ? Ils ont du mojo à l\'intérieur. Nous devons les avoir. Vous nous aiderez.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les Paragons ? Ils ont du mojo à l\'intérieur. Nous devons les avoir. Vous nous aiderez.';
-- Quest 8055 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8055, 'frFR', 'Vous avez fait ce que peu ont pu faire.  Vous avez mis à genoux les sbires de Hakkar.  Vous leur avez montré ce qu\'un penseur libre peut faire.  Vous nous avez montré comment un hérétique pouvait être vénéré dans la tribu.  Vous avez plus que de la vraie puissance.  VOUS ÊTES la vraie puissance.$B$Prenez la cuirasse, penseur libre.  Écrasez ceux qui s\'opposent à vous.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait ce que peu ont pu faire.  Vous avez mis à genoux les sbires de Hakkar.  Vous leur avez montré ce qu\'un penseur libre peut faire.  Vous nous avez montré comment un hérétique pouvait être vénéré dans la tribu.  Vous avez plus que de la vraie puissance.  VOUS ÊTES la vraie puissance.$B$Prenez la cuirasse, penseur libre.  Écrasez ceux qui s\'opposent à vous.';
-- Quest 8056 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8056, 'frFR', 'Avez-vous les Paragons de Puissance de Zul\'Gurub dont j\'ai besoin ? Ces brassards valent bien l\'effort que vous devrez faire pour les obtenir !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les Paragons de Puissance de Zul\'Gurub dont j\'ai besoin ? Ces brassards valent bien l\'effort que vous devrez faire pour les obtenir !';
-- Quest 8056 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8056, 'frFR', 'Il semble que vous ayez un peu de l\'augure de Zandalar en vous.  Nous savons ce que vous avez fait à Zul\'Gurub en notre nom, mon.  Ces Paragons de Puissance aideront beaucoup la tribu de Zandalar - une tribu, je peux ajouter, que vous pouvez considérer comme des amis.  Prenez ces brassards, <name>; vous les avez mérités et plus encore !') ON DUPLICATE KEY UPDATE RewardText='Il semble que vous ayez un peu de l\'augure de Zandalar en vous.  Nous savons ce que vous avez fait à Zul\'Gurub en notre nom, mon.  Ces Paragons de Puissance aideront beaucoup la tribu de Zandalar - une tribu, je peux ajouter, que vous pouvez considérer comme des amis.  Prenez ces brassards, <name>; vous les avez mérités et plus encore !';

-- Quest 8057 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8057, 'frFR', 'As-tu les Paragons of Power de Zul\'Gurub ? Ces brassards valent l\'effort, $N. Fais-moi confiance mon !') ON DUPLICATE KEY UPDATE CompletionText='As-tu les Paragons of Power de Zul\'Gurub ? Ces brassards valent l\'effort, $N. Fais-moi confiance mon !';
-- Quest 8057 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8057, 'frFR', 'Ah, je ressens la puissance qui émane de ces Paragons of Power, <name>. Tu t\'es prouvé être quelqu\'un que nous dans la tribu pouvons appeler "ami". Un accord est un accord, <name>... contemple la puissance des brassards de l\'haruspex !') ON DUPLICATE KEY UPDATE RewardText='Ah, je ressens la puissance qui émane de ces Paragons of Power, <name>. Tu t\'es prouvé être quelqu\'un que nous dans la tribu pouvons appeler "ami". Un accord est un accord, <name>... contemple la puissance des brassards de l\'haruspex !';
-- Quest 8058 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8058, 'frFR', 'As-tu apporté les Paragons of Power ? La vengeance a-t-elle été prise au nom de Zandalar ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les Paragons of Power ? La vengeance a-t-elle été prise au nom de Zandalar ?';
-- Quest 8058 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8058, 'frFR', 'Tu as accompli beaucoup de vengeance aujourd\'hui. Tu as pris l\'apparence du vindicateur. Tu as mis à genoux les sbires du Dieu Sang. $B$BPrends ceci. Cela alimentera ta vengeance pour l\'avenir. Tu es un ami de Zandalar maintenant.') ON DUPLICATE KEY UPDATE RewardText='Tu as accompli beaucoup de vengeance aujourd\'hui. Tu as pris l\'apparence du vindicateur. Tu as mis à genoux les sbires du Dieu Sang. $B$BPrends ceci. Cela alimentera ta vengeance pour l\'avenir. Tu es un ami de Zandalar maintenant.';
-- Quest 8059 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8059, 'frFR', 'Es-tu revenu avec les Paragons of Power ? En battant les sbires diaboliques de Hakkar, tu ne te prouveras pas seulement à nous, mais aussi ta volonté d\'apprendre les voies du démoniaque.') ON DUPLICATE KEY UPDATE CompletionText='Es-tu revenu avec les Paragons of Power ? En battant les sbires diaboliques de Hakkar, tu ne te prouveras pas seulement à nous, mais aussi ta volonté d\'apprendre les voies du démoniaque.';
-- Quest 8059 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8059, 'frFR', 'Bien joué... sans aucun doute, ils ont été faits pour payer de manière exaspérante avant de livrer les Paragons of Power. Prends ceci - les bandelettes du démoniaque. Fabriquées à partir de mojo puissant utilisé pour invoquer la proie du démoniaque, c\'est un outil puissant dans ton acquisition de pouvoir.') ON DUPLICATE KEY UPDATE RewardText='Bien joué... sans aucun doute, ils ont été faits pour payer de manière exaspérante avant de livrer les Paragons of Power. Prends ceci - les bandelettes du démoniaque. Fabriquées à partir de mojo puissant utilisé pour invoquer la proie du démoniaque, c\'est un outil puissant dans ton acquisition de pouvoir.';
-- Quest 8060 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8060, 'frFR', '$N - tu es déjà revenu ? As-tu réussi à obtenir les Paragons of Power dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='$N - tu es déjà revenu ? As-tu réussi à obtenir les Paragons of Power dont j\'ai besoin ?';
-- Quest 8060 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8060, 'frFR', 'Impressionnant... pouvais-tu sentir le mojo couler à travers eux ? Les Paragons of Power ont servi de monnaie à une époque où l\'Empire Gurubashi régnait sur ces terres. Maintenant, nous Zandalar utiliserons le mojo latent à l\'intérieur d\'eux pour combattre la seconde montée du Dieu Sang Hakkar !$B$BTu as bien fait aujourd\'hui - considère-toi comme ayant un ami dans Zandalar. Pour cela, voici les bandelettes de l\'illusionniste que j\'avais promises !') ON DUPLICATE KEY UPDATE RewardText='Impressionnant... pouvais-tu sentir le mojo couler à travers eux ? Les Paragons of Power ont servi de monnaie à une époque où l\'Empire Gurubashi régnait sur ces terres. Maintenant, nous Zandalar utiliserons le mojo latent à l\'intérieur d\'eux pour combattre la seconde montée du Dieu Sang Hakkar !$B$BTu as bien fait aujourd\'hui - considère-toi comme ayant un ami dans Zandalar. Pour cela, voici les bandelettes de l\'illusionniste que j\'avais promises !';
-- Quest 8061 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8061, 'frFR', 'De retour de Zul\'Gurub, n\'est-ce pas ? As-tu réussi à récupérer les Paragons of Power des sbires de Hakkar ?') ON DUPLICATE KEY UPDATE CompletionText='De retour de Zul\'Gurub, n\'est-ce pas ? As-tu réussi à récupérer les Paragons of Power des sbires de Hakkar ?';
-- Quest 8061 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8061, 'frFR', 'Remarquable, <name> ! Ce n\'était pas une petite prouesse de m\'apporter ceci. Sans aucun doute, tu as agi comme le confesseur de notre tribu aujourd\'hui en nous préservant de la menace de Hakkar. Ces bandelettes sont dignes d\'un ami de la tribu comme toi !') ON DUPLICATE KEY UPDATE RewardText='Remarquable, <name> ! Ce n\'était pas une petite prouesse de m\'apporter ceci. Sans aucun doute, tu as agi comme le confesseur de notre tribu aujourd\'hui en nous préservant de la menace de Hakkar. Ces bandelettes sont dignes d\'un ami de la tribu comme toi !';
-- Quest 8062 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8062, 'frFR', 'Chasse ceux de Zul\'Gurub qui posséderaient les Paragons of Power, $N. Ils sont ta proie ; ils possèdent ce que nous devons tous avoir.') ON DUPLICATE KEY UPDATE CompletionText='Chasse ceux de Zul\'Gurub qui posséderaient les Paragons of Power, $N. Ils sont ta proie ; ils possèdent ce que nous devons tous avoir.';
-- Quest 8062 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8062, 'frFR', 'Oui... je n\'ai besoin d\'aucune vision pour sentir la présence des Paragons of Power. Ton succès à Zul\'Gurub a impressionné beaucoup au sein de la tribu. Nous ne te considérons pas seulement comme un ami de Zandalar, mais nous te considérons aussi comme assez digne de posséder les brassards du prédateur - des objets puissants, et un symbole de ce que signifie être un prédateur. Bien joué, <name>.') ON DUPLICATE KEY UPDATE RewardText='Oui... je n\'ai besoin d\'aucune vision pour sentir la présence des Paragons of Power. Ton succès à Zul\'Gurub a impressionné beaucoup au sein de la tribu. Nous ne te considérons pas seulement comme un ami de Zandalar, mais nous te considérons aussi comme assez digne de posséder les brassards du prédateur - des objets puissants, et un symbole de ce que signifie être un prédateur. Bien joué, <name>.';
-- Quest 8063 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8063, 'frFR', 'Cherche la folie au sein de Zul\'Gurub et éclipse-la par la tienne, $N ! Le faire signifie le succès, et le succès signifie la récompense ! Que le Dieu Sang ne règne plus suprême !') ON DUPLICATE KEY UPDATE CompletionText='Cherche la folie au sein de Zul\'Gurub et éclipse-la par la tienne, $N ! Le faire signifie le succès, et le succès signifie la récompense ! Que le Dieu Sang ne règne plus suprême !';
-- Quest 8063 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8063, 'frFR', 'Bien joué, $N... tes accomplissements à Zul\'Gurub t\'ont valu le droit d\'appeler la tribu Zandalar comme un ami. Je m\'occuperai de la disposition des Paragons ; pour ton effort, veuillez accepter cette récompense !') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N... tes accomplissements à Zul\'Gurub t\'ont valu le droit d\'appeler la tribu Zandalar comme un ami. Je m\'occuperai de la disposition des Paragons ; pour ton effort, veuillez accepter cette récompense !';
-- Quest 8064 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8064, 'frFR', 'As-tu les Paragons of Power de Zul\'Gurub dont j\'ai besoin ? Le ceinturon de l\'haruspex sera le tien si tu les as.') ON DUPLICATE KEY UPDATE CompletionText='As-tu les Paragons of Power de Zul\'Gurub dont j\'ai besoin ? Le ceinturon de l\'haruspex sera le tien si tu les as.';

-- Quest 8064 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8064, 'frFR', 'Je vous remercie - la puissance latente dans ces objets seront des trésors en eux-mêmes, vous êtes sûr.  Non seulement vous avez fait ce que je vous ai demandé, mais vous vous êtes aussi montré honorable envers nous ici dans la tribu.  Comme promis, voici votre récompense !') ON DUPLICATE KEY UPDATE RewardText='Je vous remercie - la puissance latente dans ces objets seront des trésors en eux-mêmes, vous êtes sûr.  Non seulement vous avez fait ce que je vous ai demandé, mais vous vous êtes aussi montré honorable envers nous ici dans la tribu.  Comme promis, voici votre récompense !';
-- Quest 8065 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8065, 'frFR', 'Vous avez obtenu les Paragons de Puissance nécessaires de Zul\'Gurub ? La tunique de l\'haruspex vaut tout l\'effort que vous voudrez faire.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez obtenu les Paragons de Puissance nécessaires de Zul\'Gurub ? La tunique de l\'haruspex vaut tout l\'effort que vous voudrez faire.';
-- Quest 8065 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8065, 'frFR', 'Impressionnant... vous avez réussi à collecter les Paragons de Puissance requis, <name>.  Vos accomplissements à Zul\'Gurub pour les Zandalar sont légendaires ; désormais, vous serez vénéré au sein de la tribu.  Voici votre tunique, puissant <class> !') ON DUPLICATE KEY UPDATE RewardText='Impressionnant... vous avez réussi à collecter les Paragons de Puissance requis, <name>.  Vos accomplissements à Zul\'Gurub pour les Zandalar sont légendaires ; désormais, vous serez vénéré au sein de la tribu.  Voici votre tunique, puissant <class> !';
-- Quest 8066 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8066, 'frFR', 'Frappez les sbires fous de Hakkar dans Zul\'Gurub - ce sont eux qui détiennent les Paragons de Puissance, $N. Prouvez votre succès à eux - et à la tribu - en tant qu\'aspirant au prédateur.') ON DUPLICATE KEY UPDATE CompletionText='Frappez les sbires fous de Hakkar dans Zul\'Gurub - ce sont eux qui détiennent les Paragons de Puissance, $N. Prouvez votre succès à eux - et à la tribu - en tant qu\'aspirant au prédateur.';
-- Quest 8066 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8066, 'frFR', 'J\'ai senti votre arrivée des moments auparavant, <name>, mais pas trop facilement.  Ce qui m\'a révélé était les Paragons de Puissance que vous avez apportés.  Je peux sentir la puissance sans avoir besoin de voir les bibelots ; leur mojo latent - magie brute, si vous voulez - continuera d\'alimenter nos efforts pour vaincre les plans diaboliques du Dieu Sanglant Hakkar.$B$BVous devez être loué - et récompensé - pour votre succès.  Vous êtes honoré au sein de la tribu, et vous êtes digne de porter la ceinture du prédateur.') ON DUPLICATE KEY UPDATE RewardText='J\'ai senti votre arrivée des moments auparavant, <name>, mais pas trop facilement.  Ce qui m\'a révélé était les Paragons de Puissance que vous avez apportés.  Je peux sentir la puissance sans avoir besoin de voir les bibelots ; leur mojo latent - magie brute, si vous voulez - continuera d\'alimenter nos efforts pour vaincre les plans diaboliques du Dieu Sanglant Hakkar.$B$BVous devez être loué - et récompensé - pour votre succès.  Vous êtes honoré au sein de la tribu, et vous êtes digne de porter la ceinture du prédateur.';
-- Quest 8067 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8067, 'frFR', 'Vos frappes dans Zul\'Gurub ont-elles donné succès, $N? Ce n\'est que lorsque vous m\'aurez apporté ce que je cherche - et prouvé votre valeur à la tribu - que vous gagnerez un manteau sans pareil parmi les Zandalar.') ON DUPLICATE KEY UPDATE CompletionText='Vos frappes dans Zul\'Gurub ont-elles donné succès, $N? Ce n\'est que lorsque vous m\'aurez apporté ce que je cherche - et prouvé votre valeur à la tribu - que vous gagnerez un manteau sans pareil parmi les Zandalar.';
-- Quest 8067 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8067, 'frFR', 'Succès... vous devez être vénéré au sein de la tribu, <name>.  Ce n\'était pas une petite tâche d\'acquérir les Paragons de Puissance nécessaires pour le manteau, mais vous l\'avez géré à la manière du plus meurtrier de nos prédateurs.  Vous avez gagné votre place parmi eux, et vous avez certainement gagné le droit de porter leur manteau.') ON DUPLICATE KEY UPDATE RewardText='Succès... vous devez être vénéré au sein de la tribu, <name>.  Ce n\'était pas une petite tâche d\'acquérir les Paragons de Puissance nécessaires pour le manteau, mais vous l\'avez géré à la manière du plus meurtrier de nos prédateurs.  Vous avez gagné votre place parmi eux, et vous avez certainement gagné le droit de porter leur manteau.';
-- Quest 8068 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8068, 'frFR', 'Comment s\'est déroulée votre incursion dans Zul\'Gurub ? Avez-vous rendu vos ennemis fous par le pouvoir de l\'illusion ? Illusion ou pas, leur mort - et les Paragons de Puissance pris chez eux - aideront à contrecarrer l\'ascension de Hakkar.') ON DUPLICATE KEY UPDATE CompletionText='Comment s\'est déroulée votre incursion dans Zul\'Gurub ? Avez-vous rendu vos ennemis fous par le pouvoir de l\'illusion ? Illusion ou pas, leur mort - et les Paragons de Puissance pris chez eux - aideront à contrecarrer l\'ascension de Hakkar.';
-- Quest 8068 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8068, 'frFR', 'Succès !  Vous serez honoré dans la tribu à partir de maintenant !  Zul\'Gurub a certainement goûté à la puissance des Zandalar aujourd\'hui, grâce à vous <name>.$B$BAvec la bénédiction de la tribu, prenez le manteau de l\'illusionniste Zandalar.  Qu\'il vous serve bien.') ON DUPLICATE KEY UPDATE RewardText='Succès !  Vous serez honoré dans la tribu à partir de maintenant !  Zul\'Gurub a certainement goûté à la puissance des Zandalar aujourd\'hui, grâce à vous <name>.$B$BAvec la bénédiction de la tribu, prenez le manteau de l\'illusionniste Zandalar.  Qu\'il vous serve bien.';
-- Quest 8069 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8069, 'frFR', 'Êtes-vous revenu avec les Paragons de Puissance dont nous avons besoin ? Je sais que ce ne sera pas facile... mais j\'ai longtemps prédit qu\'un étranger viendrait nous aider dans notre lutte contre Hakkar. Que ce soit vous, je dis !') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous revenu avec les Paragons de Puissance dont nous avons besoin ? Je sais que ce ne sera pas facile... mais j\'ai longtemps prédit qu\'un étranger viendrait nous aider dans notre lutte contre Hakkar. Que ce soit vous, je dis !';
-- Quest 8069 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8069, 'frFR', 'Enfin, quelqu\'un digne de porter la robe de l\'illusionniste !  Votre succès dans Zul\'Gurub a assuré votre vénération au sein de la tribu pour les âges à venir.  Portez-le avec fierté, <name> !') ON DUPLICATE KEY UPDATE RewardText='Enfin, quelqu\'un digne de porter la robe de l\'illusionniste !  Votre succès dans Zul\'Gurub a assuré votre vénération au sein de la tribu pour les âges à venir.  Portez-le avec fierté, <name> !';
-- Quest 8070 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8070, 'frFR', 'Les Paragons de Puissance... les avez-vous ? Ce n\'est que lorsque nous les aurons que nous pourrons utiliser la puissance latente qu\'ils contiennent. Ce sera bon de renverser la situation contre les sbires du Dieu Sanglant...') ON DUPLICATE KEY UPDATE CompletionText='Les Paragons de Puissance... les avez-vous ? Ce n\'est que lorsque nous les aurons que nous pourrons utiliser la puissance latente qu\'ils contiennent. Ce sera bon de renverser la situation contre les sbires du Dieu Sanglant...';
-- Quest 8070 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8070, 'frFR', 'Succès !  Ceci aidera beaucoup à renforcer notre puissance contre l\'ascension de Hakkar.  Avec votre aide, nous avons fait un pas significatif pour nous assurer que le Dieu Sanglant ne nous détruira pas tous.$B$BVous avez gagné l\'honneur de la tribu aujourd\'hui, <name>.  Prenez ceci - les liens du confesseur - comme un symbole de notre gratitude.') ON DUPLICATE KEY UPDATE RewardText='Succès !  Ceci aidera beaucoup à renforcer notre puissance contre l\'ascension de Hakkar.  Avec votre aide, nous avons fait un pas significatif pour nous assurer que le Dieu Sanglant ne nous détruira pas tous.$B$BVous avez gagné l\'honneur de la tribu aujourd\'hui, <name>.  Prenez ceci - les liens du confesseur - comme un symbole de notre gratitude.';
-- Quest 8071 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8071, 'frFR', 'Avez-vous les Paragons de Puissance de Zul\'Gurub ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les Paragons de Puissance de Zul\'Gurub ?';
-- Quest 8071 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8071, 'frFR', 'Bien fait, <name> - les sbires de Hakkar ont certainement senti la rétribution des Zandalar aujourd\'hui, grâce à vous.  Vos actions vous ont donné une place de vénération permanente au sein de la tribu.  Avec notre bénédiction, veuillez prendre ce manteau de confesseur comme le vôtre !') ON DUPLICATE KEY UPDATE RewardText='Bien fait, <name> - les sbires de Hakkar ont certainement senti la rétribution des Zandalar aujourd\'hui, grâce à vous.  Vos actions vous ont donné une place de vénération permanente au sein de la tribu.  Avec notre bénédiction, veuillez prendre ce manteau de confesseur comme le vôtre !';

-- Quest 8072 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8072, 'frFR', 'Vous êtes revenu - avez-vous les Paragons of Power dont j\'ai besoin?$B$BLa légende de Khar\'vaxal le Fêlé nous rappelle aujourd\'hui qu\'aucun ennemi - aussi grande soit la menace qu\'il représente - n\'est impossible à vaincre. Le chaos mènera tout à genoux, c\'est certain... et peut-être les éléments les moins chaotiques du chaos.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu - avez-vous les Paragons of Power dont j\'ai besoin?$B$BLa légende de Khar\'vaxal le Fêlé nous rappelle aujourd\'hui qu\'aucun ennemi - aussi grande soit la menace qu\'il représente - n\'est impossible à vaincre. Le chaos mènera tout à genoux, c\'est certain... et peut-être les éléments les moins chaotiques du chaos.';
-- Quest 8072 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8072, 'frFR', 'La victoire est la nôtre aujourd\'hui, grâce à la folie que vous avez semée parmi nos ennemis mutuels ! Vous devez être honoré parmi les Zandalar, et il n\'y a pas de meilleure façon de montrer votre gratitude pour vos actes qu\'en vous offrant le manteau du fou !') ON DUPLICATE KEY UPDATE RewardText='La victoire est la nôtre aujourd\'hui, grâce à la folie que vous avez semée parmi nos ennemis mutuels ! Vous devez être honoré parmi les Zandalar, et il n\'y a pas de meilleure façon de montrer votre gratitude pour vos actes qu\'en vous offrant le manteau du fou !';
-- Quest 8073 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8073, 'frFR', 'Bienvenue à l\'Île, $N... êtes-vous revenu triomphal avec les Paragons of Power ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue à l\'Île, $N... êtes-vous revenu triomphal avec les Paragons of Power ?';
-- Quest 8073 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8073, 'frFR', 'Impressionnant... vous avez accompli aujourd\'hui ce que peu pensaient possible.  Votre vénération au sein de la tribu est assurée pour toute une vie, <name>.  Vous avez gagné le droit de porter la tunique du fou - faites-le avec notre bénédiction.') ON DUPLICATE KEY UPDATE RewardText='Impressionnant... vous avez accompli aujourd\'hui ce que peu pensaient possible.  Votre vénération au sein de la tribu est assurée pour toute une vie, <name>.  Vous avez gagné le droit de porter la tunique du fou - faites-le avec notre bénédiction.';
-- Quest 8074 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8074, 'frFR', 'Les Paragons of Power sont ce dont j\'ai besoin mon - nous allons en tirer le pouvoir lors de notre combat contre le mal de Zul\'Gurub. Vous les avez pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Les Paragons of Power sont ce dont j\'ai besoin mon - nous allons en tirer le pouvoir lors de notre combat contre le mal de Zul\'Gurub. Vous les avez pour moi ?';
-- Quest 8074 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8074, 'frFR', 'Je peux sentir l\'odeur du mal vaincu sur toi, <name>.  C\'est une odeur douce mon... une que je pense que tu connais bien.$B$Je sais qu\'il n\'est pas facile de m\'apporter les Paragons of Power nécessaires pour la ceinture.  Vos actes n\'ont pas seulement honoré la tribu, mais aussi vous-même au sein de ma tribu.  Voici - prends la ceinture de l\'augure et porte-la comme la tienne !') ON DUPLICATE KEY UPDATE RewardText='Je peux sentir l\'odeur du mal vaincu sur toi, <name>.  C\'est une odeur douce mon... une que je pense que tu connais bien.$B$Je sais qu\'il n\'est pas facile de m\'apporter les Paragons of Power nécessaires pour la ceinture.  Vos actes n\'ont pas seulement honoré la tribu, mais aussi vous-même au sein de ma tribu.  Voici - prends la ceinture de l\'augure et porte-la comme la tienne !';
-- Quest 8075 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8075, 'frFR', 'Les Paragons of Power sont une source clé de pouvoir magique - le même type de pouvoir qui sert à fabriquer le hauberk de l\'augure. Apportez-moi ce dont j\'ai besoin, et je pourrai partager le meilleur des vêtements qu\'un augure Zandalar voudrait posséder.') ON DUPLICATE KEY UPDATE CompletionText='Les Paragons of Power sont une source clé de pouvoir magique - le même type de pouvoir qui sert à fabriquer le hauberk de l\'augure. Apportez-moi ce dont j\'ai besoin, et je pourrai partager le meilleur des vêtements qu\'un augure Zandalar voudrait posséder.';
-- Quest 8075 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8075, 'frFR', 'Je sais ce que vous avez dû traverser pour m\'apporter les Paragons of Power, $N. Ce n\'était pas facile, mon - vaincre le mal qui suinte de Zul\'Gurub comme une fange vile - mais maintenant que tout est dit et fait, je peux facilement dire que vous serez vénéré parmi les Zandalar pour les âges à venir !$B$BVoici - prenez le hauberk de l\'augure et portez-le avec fierté !') ON DUPLICATE KEY UPDATE RewardText='Je sais ce que vous avez dû traverser pour m\'apporter les Paragons of Power, $N. Ce n\'était pas facile, mon - vaincre le mal qui suinte de Zul\'Gurub comme une fange vile - mais maintenant que tout est dit et fait, je peux facilement dire que vous serez vénéré parmi les Zandalar pour les âges à venir !$B$BVoici - prenez le hauberk de l\'augure et portez-le avec fierté !';
-- Quest 8076 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8076, 'frFR', 'Récupéré les Paragons of Power de Zul\'Gurub ? Bien que nous prenions le pouvoir latent de ces objets pour faire le nôtre, nous vous donnerons votre propre récompense de pouvoir si vous réussissez...') ON DUPLICATE KEY UPDATE CompletionText='Récupéré les Paragons of Power de Zul\'Gurub ? Bien que nous prenions le pouvoir latent de ces objets pour faire le nôtre, nous vous donnerons votre propre récompense de pouvoir si vous réussissez...';
-- Quest 8076 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8076, 'frFR', 'Bien fait, <name>.  Les Paragons of Power de Zul\'Gurub devraient servir de rappel du pouvoir gaspillé.  Les Gurubashi étaient forts à leur apogée, mais ils se sont laissé consumer par lui.  Un démoniaque sait que le jeu qu\'ils jouent est très similaire, mais le pouvoir libéré est souvent ce dont il faut pour survivre.$B$Utilisez ce manteau comme un allié honoré des Zandalar... cela vous sera utile.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, <name>.  Les Paragons of Power de Zul\'Gurub devraient servir de rappel du pouvoir gaspillé.  Les Gurubashi étaient forts à leur apogée, mais ils se sont laissé consumer par lui.  Un démoniaque sait que le jeu qu\'ils jouent est très similaire, mais le pouvoir libéré est souvent ce dont il faut pour survivre.$B$Utilisez ce manteau comme un allié honoré des Zandalar... cela vous sera utile.';
-- Quest 8077 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8077, 'frFR', 'Les Paragons of Power... vous êtes revenu avec eux ? Ce n\'est qu\'une fois que nous les aurons que nous partagerons le symbole ultime du pouvoir démoniaque avec vous, $N.') ON DUPLICATE KEY UPDATE CompletionText='Les Paragons of Power... vous êtes revenu avec eux ? Ce n\'est qu\'une fois que nous les aurons que nous partagerons le symbole ultime du pouvoir démoniaque avec vous, $N.';
-- Quest 8077 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8077, 'frFR', 'Impressionnant - votre victoire à Zul\'Gurub nous l\'a assuré - non, le monde - que Hakkar ne triomphera pas.  Le moment peut venir où vous affronterez le Dieu Sang... et si cela se produit, sachez que votre vénération est assurée au sein de la tribu Zandalar.$B$Oh, et cette robe simple devrait aider aussi je pense.$B$B<Al\'tabim vous fait un clin d\'œil en connaissance de cause.>') ON DUPLICATE KEY UPDATE RewardText='Impressionnant - votre victoire à Zul\'Gurub nous l\'a assuré - non, le monde - que Hakkar ne triomphera pas.  Le moment peut venir où vous affronterez le Dieu Sang... et si cela se produit, sachez que votre vénération est assurée au sein de la tribu Zandalar.$B$Oh, et cette robe simple devrait aider aussi je pense.$B$B<Al\'tabim vous fait un clin d\'œil en connaissance de cause.>';
-- Quest 8078 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8078, 'frFR', 'Avez-vous apporté les Paragons of Power ? Avez-vous abattu les ennemis de la tribu ? Hakkar doit connaître la colère du vindicateur !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous apporté les Paragons of Power ? Avez-vous abattu les ennemis de la tribu ? Hakkar doit connaître la colère du vindicateur !';
-- Quest 8078 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8078, 'frFR', 'La voie du vindicateur vous est maintenant connue.  Vous avez apporté l\'honneur à la tribu.  Vous avez apporté l\'honneur à vous-même.  Vous avez apporté la douleur à nos ennemis.$B$La ceinture du vindicateur est la vôtre.  Vous devenez certainement un avec la voie du vindicateur.') ON DUPLICATE KEY UPDATE RewardText='La voie du vindicateur vous est maintenant connue.  Vous avez apporté l\'honneur à la tribu.  Vous avez apporté l\'honneur à vous-même.  Vous avez apporté la douleur à nos ennemis.$B$La ceinture du vindicateur est la vôtre.  Vous devenez certainement un avec la voie du vindicateur.';
-- Quest 8079 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8079, 'frFR', 'Votre présence signifie-t-elle la victoire ? Avez-vous les Paragons of Power ? Parlez-moi de la vengeance que vous avez accomplie aujourd\'hui !') ON DUPLICATE KEY UPDATE CompletionText='Votre présence signifie-t-elle la victoire ? Avez-vous les Paragons of Power ? Parlez-moi de la vengeance que vous avez accomplie aujourd\'hui !';

-- Quest 8079 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8079, 'frFR', 'Tu seras vénéré pour tes exploits.  La tribu récompense ses héros.  Zul\'Gurub a goûté à la vengeance de Zandalar comme jamais auparavant.$B$BTes actes annonceront les actes des autres à venir.  Ils te verront comme un signe de pouvoir réel.  Ils te verront comme la vengeance personnifiée !') ON DUPLICATE KEY UPDATE RewardText='Tu seras vénéré pour tes exploits.  La tribu récompense ses héros.  Zul\'Gurub a goûté à la vengeance de Zandalar comme jamais auparavant.$B$BTes actes annonceront les actes des autres à venir.  Ils te verront comme un signe de pouvoir réel.  Ils te verront comme la vengeance personnifiée !';
-- Quest 8080 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8080, 'frFR', 'As-tu la caisse de ressources, $N? La Ligue d\'Arathor ne peut mener une bataille décente sans elles...') ON DUPLICATE KEY UPDATE CompletionText='As-tu la caisse de ressources, $N? La Ligue d\'Arathor ne peut mener une bataille décente sans elles...';
-- Quest 8080 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8080, 'frFR', 'Tu as les ressources ! Beau travail ! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que tu as réalisée est ainsi que les guerres sont réellement gagnées.') ON DUPLICATE KEY UPDATE RewardText='Tu as les ressources ! Beau travail ! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que tu as réalisée est ainsi que les guerres sont réellement gagnées.';
-- Quest 8081 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8081, 'frFR', '$N, la Ligue d\'Arathor a une mission en cours pour toi : réentrer dans le Bassin d\'Arathi, obtenir plus de caisses de ressources et me les apporter.') ON DUPLICATE KEY UPDATE CompletionText='$N, la Ligue d\'Arathor a une mission en cours pour toi : réentrer dans le Bassin d\'Arathi, obtenir plus de caisses de ressources et me les apporter.';
-- Quest 8081 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8081, 'frFR', 'Très bien. Je les ferai parvenir à nos intendants immédiatement, et une commendation pour tes actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Tes contributions à nos luttes sont remarquées par le soldat et le maréchal de camp.') ON DUPLICATE KEY UPDATE RewardText='Très bien. Je les ferai parvenir à nos intendants immédiatement, et une commendation pour tes actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Tes contributions à nos luttes sont remarquées par le soldat et le maréchal de camp.';
-- Quest 8101 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8101, 'frFR', '$R, le caillou contenu dans le cadre de ce talisman provient du Mont Kajaro dans les Mers du Sud. Le Mont Kajaro est une zone en proie à la volatilité - marquée par des éruptions volcaniques violentes et souvent magiques.$b$bPlus ton lien avec les trolls de Zandalar grandit, plus le pouvoir de ce caillou grandira. Exploite le pouvoir du caillou pour abattre nos ennemis. Sois comme la montagne : Rapide, explosif, mortel...') ON DUPLICATE KEY UPDATE RewardText='$R, le caillou contenu dans le cadre de ce talisman provient du Mont Kajaro dans les Mers du Sud. Le Mont Kajaro est une zone en proie à la volatilité - marquée par des éruptions volcaniques violentes et souvent magiques.$b$bPlus ton lien avec les trolls de Zandalar grandit, plus le pouvoir de ce caillou grandira. Exploite le pouvoir du caillou pour abattre nos ennemis. Sois comme la montagne : Rapide, explosif, mortel...';
-- Quest 8102 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8102, 'frFR', 'Bienvenue de retour, $c. Je vois que le caillou a beaucoup servi. Beaucoup de nos ennemis sont tombés sous tes capacités surnaturelles. Leur souffrance a été grande. Il est temps que j\'améliore le pouvoir du caillou. Donne-le-moi.') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue de retour, $c. Je vois que le caillou a beaucoup servi. Beaucoup de nos ennemis sont tombés sous tes capacités surnaturelles. Leur souffrance a été grande. Il est temps que j\'améliore le pouvoir du caillou. Donne-le-moi.';
-- Quest 8102 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8102, 'frFR', 'Sois invincible, comme les fronts coulants de Kajaro.') ON DUPLICATE KEY UPDATE RewardText='Sois invincible, comme les fronts coulants de Kajaro.';
-- Quest 8103 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8103, 'frFR', 'Hakkari te craint, $n. Ils parlent d\'horreurs qu\'ils croyaient que seul leur Dieu sans visage pouvait perpétrer. Tu les as brûlés avec la force de Kajaro. Ils connaissent maintenant la peur à deux endroits.$b$bIl est temps de renforcer davantage le caillou. Donne-moi le talisman.') ON DUPLICATE KEY UPDATE CompletionText='Hakkari te craint, $n. Ils parlent d\'horreurs qu\'ils croyaient que seul leur Dieu sans visage pouvait perpétrer. Tu les as brûlés avec la force de Kajaro. Ils connaissent maintenant la peur à deux endroits.$b$bIl est temps de renforcer davantage le caillou. Donne-moi le talisman.';
-- Quest 8103 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8103, 'frFR', 'Continue ta décimation des trolls de Zul\'Gurub. Hakkar doit voir que le monde ne pliera pas sous sa volonté indomptable.') ON DUPLICATE KEY UPDATE RewardText='Continue ta décimation des trolls de Zul\'Gurub. Hakkar doit voir que le monde ne pliera pas sous sa volonté indomptable.';
-- Quest 8104 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8104, 'frFR', 'Donne-moi le talisman, $n. Je dois te montrer quelque chose.') ON DUPLICATE KEY UPDATE CompletionText='Donne-moi le talisman, $n. Je dois te montrer quelque chose.';
-- Quest 8104 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8104, 'frFR', '<Al\'tabim brise le caillou avec une force invisible puissante.>$B$BTu vois ? Le caillou est ce que nous appelons une géode. À l\'intérieur du caillou se trouvent des cristaux puissants qui ont absorbé les énergies latentes de notre monde. En coupant le caillou en deux, j\'ai finalement permis à son plein potentiel d\'être réalisé. Utilise-le pour ravager nos ennemis.') ON DUPLICATE KEY UPDATE RewardText='<Al\'tabim brise le caillou avec une force invisible puissante.>$B$BTu vois ? Le caillou est ce que nous appelons une géode. À l\'intérieur du caillou se trouvent des cristaux puissants qui ont absorbé les énergies latentes de notre monde. En coupant le caillou en deux, j\'ai finalement permis à son plein potentiel d\'être réalisé. Utilise-le pour ravager nos ennemis.';
-- Quest 8106 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8106, 'frFR', 'Accepte ce talisman, $c. Accepte-le et utilise son pouvoir pour abattre nos ennemis mutuels.$b$bSache que autour de ton cou, tu portes un morceau d\'histoire. Kezan fut autrefois un grand territoire de l\'Empire de Zandalar. Malheureusement, la souillure des princes marchands gobelins a chassé mes frères et sœurs fiers.$b$bKezan est maintenant le siège de la capitale gobeline de l\'Under-mine ; mais sache qu\'avant la souillure, il possédait la grandeur. Encore aujourd\'hui, Kezan est considéré comme une terre sacrée par mon peuple.') ON DUPLICATE KEY UPDATE RewardText='Accepte ce talisman, $c. Accepte-le et utilise son pouvoir pour abattre nos ennemis mutuels.$b$bSache que autour de ton cou, tu portes un morceau d\'histoire. Kezan fut autrefois un grand territoire de l\'Empire de Zandalar. Malheureusement, la souillure des princes marchands gobelins a chassé mes frères et sœurs fiers.$b$bKezan est maintenant le siège de la capitale gobeline de l\'Under-mine ; mais sache qu\'avant la souillure, il possédait la grandeur. Encore aujourd\'hui, Kezan est considéré comme une terre sacrée par mon peuple.';
-- Quest 8107 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8107, 'frFR', 'L\'honneur est gagné parmi les trolls de Zandalar, $n. Avec l\'honneur vient la récompense - l\'amitié, l\'alliance...$b$bDonne-moi le talisman afin que je puisse en améliorer le pouvoir.') ON DUPLICATE KEY UPDATE CompletionText='L\'honneur est gagné parmi les trolls de Zandalar, $n. Avec l\'honneur vient la récompense - l\'amitié, l\'alliance...$b$bDonne-moi le talisman afin que je puisse en améliorer le pouvoir.';
-- Quest 8107 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8107, 'frFR', 'Tire de l\'obscurité, $C. Embrasse les ombres. Laisse la Souillure de Kezan compléter tes manœuvres sombres.') ON DUPLICATE KEY UPDATE RewardText='Tire de l\'obscurité, $C. Embrasse les ombres. Laisse la Souillure de Kezan compléter tes manœuvres sombres.';

-- Quest 8108 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8108, 'frFR', 'Je suis prêt pour toi, $c. Une fois de plus, j\'améliorerai ton talisman. Je ne demande qu\'à ce que tu continues dans ta destruction de Hakkar et de ses sbires.$b$bDonne-moi le talisman.') ON DUPLICATE KEY UPDATE CompletionText='Je suis prêt pour toi, $c. Une fois de plus, j\'améliorerai ton talisman. Je ne demande qu\'à ce que tu continues dans ta destruction de Hakkar et de ses sbires.$b$bDonne-moi le talisman.';
-- Quest 8108 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8108, 'frFR', 'C\'est seulement par nos efforts combinés que nous arrêterons le Soulflayer.') ON DUPLICATE KEY UPDATE RewardText='C\'est seulement par nos efforts combinés que nous arrêterons le Soulflayer.';
-- Quest 8109 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8109, 'frFR', 'Appelle tes démons, $c. Laisse-les baigner dans l\'énergie de la Taint de Kezan. Commandez-les sur le champ de bataille ! Décimez l\'ennemi!$b$bOui... Le moment est venu d\'appliquer l\'amélioration finale à la Taint de Kezan. Donne-moi le talisman.') ON DUPLICATE KEY UPDATE CompletionText='Appelle tes démons, $c. Laisse-les baigner dans l\'énergie de la Taint de Kezan. Commandez-les sur le champ de bataille ! Décimez l\'ennemi!$b$bOui... Le moment est venu d\'appliquer l\'amélioration finale à la Taint de Kezan. Donne-moi le talisman.';
-- Quest 8109 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8109, 'frFR', 'Dépelez la chair de leurs cadavres. Regardez les ombres consumer les Hakkari. Tirez votre pouvoir de leur peur, <class>. Laissez la Taint de Kezan augmenter ce pouvoir...') ON DUPLICATE KEY UPDATE RewardText='Dépelez la chair de leurs cadavres. Regardez les ombres consumer les Hakkari. Tirez votre pouvoir de leur peur, <class>. Laissez la Taint de Kezan augmenter ce pouvoir...';
-- Quest 8110 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8110, 'frFR', 'Regarde cette algue, mon? Elle vient des Mers du Sud. Nous ajoutons juste un peu de mojo et un peu de magie et elle prend les propriétés les plus adaptées à son propriétaire.$b$bTu es un $c pour que ce soit facile, mon. Il suffit de l\'enrouler autour de ton cou et de penser à la nature ou aux écureuils ou à tout ce que vous aimez.') ON DUPLICATE KEY UPDATE RewardText='Regarde cette algue, mon? Elle vient des Mers du Sud. Nous ajoutons juste un peu de mojo et un peu de magie et elle prend les propriétés les plus adaptées à son propriétaire.$b$bTu es un $c pour que ce soit facile, mon. Il suffit de l\'enrouler autour de ton cou et de penser à la nature ou aux écureuils ou à tout ce que vous aimez.';
-- Quest 8111 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8111, 'frFR', 'Hé mon! C\'est bon de te revoir. La tribu parle de ton massacre des Hakkari et tout ça. Molthor m\'a donné l\'ordre d\'ajouter plus de mojo à ton talisman. Donne-le-moi et Maywiki le rendra meilleur.') ON DUPLICATE KEY UPDATE CompletionText='Hé mon! C\'est bon de te revoir. La tribu parle de ton massacre des Hakkari et tout ça. Molthor m\'a donné l\'ordre d\'ajouter plus de mojo à ton talisman. Donne-le-moi et Maywiki le rendra meilleur.';
-- Quest 8111 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8111, 'frFR', 'Le pendentif n\'est pas pour fumer, mon! Tu dois l\'utiliser pour combattre le mal.') ON DUPLICATE KEY UPDATE RewardText='Le pendentif n\'est pas pour fumer, mon! Tu dois l\'utiliser pour combattre le mal.';
-- Quest 8112 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8112, 'frFR', 'Comment est ce talisman, mon? On dirait qu\'il est temps d\'ajouter un peu plus de magie et de mojo à ses feuilles. Il a besoin d\'un peu de floraison dans son flétrissement. Donne-le-moi et Maywiki le réparera.') ON DUPLICATE KEY UPDATE CompletionText='Comment est ce talisman, mon? On dirait qu\'il est temps d\'ajouter un peu plus de magie et de mojo à ses feuilles. Il a besoin d\'un peu de floraison dans son flétrissement. Donne-le-moi et Maywiki le réparera.';
-- Quest 8112 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8112, 'frFR', 'Maintenant, tu prends les trolls maléfiques dans Zul\'Gurub et tu leur montres ce que tes pouvoirs de nature peuvent faire, mon!') ON DUPLICATE KEY UPDATE RewardText='Maintenant, tu prends les trolls maléfiques dans Zul\'Gurub et tu leur montres ce que tes pouvoirs de nature peuvent faire, mon!';
-- Quest 8113 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8113, 'frFR', '$n! Cela fait longtemps que je ne t\'ai pas vu. Savais-tu que le Roi Rastakhan lui-même m\'a donné l\'ordre d\'ajouter la dernière touche de mojo et de magie à ton talisman ? C\'est vrai, mon! Je n\'y aurais pas cru sans le voir de mes propres yeux. Donne-le-moi.') ON DUPLICATE KEY UPDATE CompletionText='$n! Cela fait longtemps que je ne t\'ai pas vu. Savais-tu que le Roi Rastakhan lui-même m\'a donné l\'ordre d\'ajouter la dernière touche de mojo et de magie à ton talisman ? C\'est vrai, mon! Je n\'y aurais pas cru sans le voir de mes propres yeux. Donne-le-moi.';
-- Quest 8113 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8113, 'frFR', '<name> mon, ce fut un bon voyage. Continue avec le massacre et la suppression de Hakkar et de ses sbires.') ON DUPLICATE KEY UPDATE RewardText='<name> mon, ce fut un bon voyage. Continue avec le massacre et la suppression de Hakkar et de ses sbires.';
-- Quest 8114 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8114, 'frFR', 'Très bon travail, <name>!  Un éclaireur enthousiaste est venu me rapporter tes exploits.  Nous, de la Ligue d\'Arathor, sommes très satisfaits!$B$BTu deviens rapidement un héros local parmi les soldats de la Ligue, et l\'exploit d\'aujourd\'hui prouve une fois de plus ta réputation exemplaire.') ON DUPLICATE KEY UPDATE RewardText='Très bon travail, <name>!  Un éclaireur enthousiaste est venu me rapporter tes exploits.  Nous, de la Ligue d\'Arathor, sommes très satisfaits!$B$BTu deviens rapidement un héros local parmi les soldats de la Ligue, et l\'exploit d\'aujourd\'hui prouve une fois de plus ta réputation exemplaire.';
-- Quest 8115 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8115, 'frFR', 'Tu l\'as fait!  Tu as pris toutes les bases!  Bien joué, <name>!$B$BIl y en a eu qui doutaient de tes chances, mais je savais que tu pouvais le faire.  Merci, et sache que la Ligue d\'Arathor te tient en haute estime, tout comme les Défileurs des Désertés doivent craindre la simple mention de ton nom!') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait!  Tu as pris toutes les bases!  Bien joué, <name>!$B$BIl y en a eu qui doutaient de tes chances, mais je savais que tu pouvais le faire.  Merci, et sache que la Ligue d\'Arathor te tient en haute estime, tout comme les Défileurs des Désertés doivent craindre la simple mention de ton nom!';
-- Quest 8116 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8116, 'frFR', 'Toi et Maywiki avez quelque chose en commun, mon. Nous sommes tous les deux $c! Bien que Maywiki soit plus un mystique et toi plus un novice. Pourtant, nous savons tous les deux ce que les grands esprits apportent.$b$bEn cadeau, je te donne cet orbe à porter autour de ton cou. Regarde au fond et vois le village de Voodress dans les Mers du Sud! Laisse-le élever ton esprit!') ON DUPLICATE KEY UPDATE RewardText='Toi et Maywiki avez quelque chose en commun, mon. Nous sommes tous les deux $c! Bien que Maywiki soit plus un mystique et toi plus un novice. Pourtant, nous savons tous les deux ce que les grands esprits apportent.$b$bEn cadeau, je te donne cet orbe à porter autour de ton cou. Regarde au fond et vois le village de Voodress dans les Mers du Sud! Laisse-le élever ton esprit!';
-- Quest 8117 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8117, 'frFR', 'Bonne nouvelle, $n. Molthor chante tes louanges ces derniers temps. Il dit comment tu deviens un vrai héros de Zandalar.$b$bIl dit aussi que Maywiki doit polir ton orbe davantage! Donne-le-moi afin que Maywiki puisse éclaircir la vision.') ON DUPLICATE KEY UPDATE CompletionText='Bonne nouvelle, $n. Molthor chante tes louanges ces derniers temps. Il dit comment tu deviens un vrai héros de Zandalar.$b$bIl dit aussi que Maywiki doit polir ton orbe davantage! Donne-le-moi afin que Maywiki puisse éclaircir la vision.';

-- Quest 8118 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8118, 'frFR', 'Sha-mon! Maywiki fait une blague!$b$b<Maywiki rit.>$b$bAlors, vous avez utilisé les esprits et les éléments contre nos ennemis à Zul\'Gurub, hein ? Les esprits soient loués !$b$bMaywiki va éclairer votre orbe. Donnez-le-moi, $n.') ON DUPLICATE KEY UPDATE CompletionText='Sha-mon! Maywiki fait une blague!$b$b<Maywiki rit.>$b$bAlors, vous avez utilisé les esprits et les éléments contre nos ennemis à Zul\'Gurub, hein ? Les esprits soient loués !$b$bMaywiki va éclairer votre orbe. Donnez-le-moi, $n.';
-- Quest 8118 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8118, 'frFR', 'Regardez-le maintenant, $N. Voodress est encore plus clair maintenant, hein ? Laissez la puissance primale couler à travers vous, mon.') ON DUPLICATE KEY UPDATE RewardText='Regardez-le maintenant, $N. Voodress est encore plus clair maintenant, hein ? Laissez la puissance primale couler à travers vous, mon.';
-- Quest 8119 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8119, 'frFR', '<Maywiki pointe votre talisman.>$b$bRegardez-le, $n ! Il est vivant. Les esprits dansent autour de l\'orbe.$b$bDonnez-le à Maywiki pour qu\'elle puisse faire un dernier ajustement.') ON DUPLICATE KEY UPDATE CompletionText='<Maywiki pointe votre talisman.>$b$bRegardez-le, $n ! Il est vivant. Les esprits dansent autour de l\'orbe.$b$bDonnez-le à Maywiki pour qu\'elle puisse faire un dernier ajustement.';
-- Quest 8119 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8119, 'frFR', 'Un jour, <name>, vous serez capable d\'utiliser cet orbe pour communiquer directement avec moi. Chaque fois que cette bataille avec Hakkar sera terminée et que Maywiki rentrera chez elle. Appelons aux esprits et demandons-leur que ce jour arrive bientôt.') ON DUPLICATE KEY UPDATE RewardText='Un jour, <name>, vous serez capable d\'utiliser cet orbe pour communiquer directement avec moi. Chaque fois que cette bataille avec Hakkar sera terminée et que Maywiki rentrera chez elle. Appelons aux esprits et demandons-leur que ce jour arrive bientôt.';
-- Quest 8120 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8120, 'frFR', 'Un éclaireur des Défileurs m\'a rapporté votre succès, <name>. Bien fait.$B$BComme vous allez apprendre, pour gagner la bataille pour la Plaine d\'Arathi, nous devons être toujours vigilants et écraser toute tentative d\'expansion de l\'Alliance. Faites cela, et notre victoire ici est assurée.') ON DUPLICATE KEY UPDATE RewardText='Un éclaireur des Défileurs m\'a rapporté votre succès, <name>. Bien fait.$B$BComme vous allez apprendre, pour gagner la bataille pour la Plaine d\'Arathi, nous devons être toujours vigilants et écraser toute tentative d\'expansion de l\'Alliance. Faites cela, et notre victoire ici est assurée.';
-- Quest 8121 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8121, 'frFR', 'Bon travail, <name>! Vos dernières actions dans la Plaine d\'Arathi ont été assez difficiles, et leurs succès sont assez louables. La Ligue d\'Arathor doit être secouée par les dernières escarmouches dans la plaine, se remettant de leurs blessures et, espérons-le, repensant leur choix de se battre ici.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, <name>! Vos dernières actions dans la Plaine d\'Arathi ont été assez difficiles, et leurs succès sont assez louables. La Ligue d\'Arathor doit être secouée par les dernières escarmouches dans la plaine, se remettant de leurs blessures et, espérons-le, repensant leur choix de se battre ici.';
-- Quest 8122 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8122, 'frFR', 'Les cris de l\'Alliance alors que vous et vos compatriotes les attaquiez pouvaient être entendus même d\'ici, <name>. Je peux presque les plaindre pour la douleur et la peur que vous avez infligées à leurs rangs. Presque, mais pas tout à fait.$B$BVotre valeur pour les Défileurs est incontestable. Vos exploits dans la Plaine d\'Arathi ont été très impressionnants, et ont résonné dans les chambres de Varimathras... et de la Dame Noire elle-même.') ON DUPLICATE KEY UPDATE RewardText='Les cris de l\'Alliance alors que vous et vos compatriotes les attaquiez pouvaient être entendus même d\'ici, <name>. Je peux presque les plaindre pour la douleur et la peur que vous avez infligées à leurs rangs. Presque, mais pas tout à fait.$B$BVotre valeur pour les Défileurs est incontestable. Vos exploits dans la Plaine d\'Arathi ont été très impressionnants, et ont résonné dans les chambres de Varimathras... et de la Dame Noire elle-même.';
-- Quest 8124 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8124, 'frFR', '$N, les Défileurs ont une mission en cours pour vous de rentrer dans la Plaine d\'Arathi, de récupérer plus de caisses de ressources et de me les apporter.') ON DUPLICATE KEY UPDATE CompletionText='$N, les Défileurs ont une mission en cours pour vous de rentrer dans la Plaine d\'Arathi, de récupérer plus de caisses de ressources et de me les apporter.';
-- Quest 8124 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8124, 'frFR', 'Très bien. Je vais les remettre à nos intendants immédiatement, et une commendation pour vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par le soldat comme par le haut chef de guerre.') ON DUPLICATE KEY UPDATE RewardText='Très bien. Je vais les remettre à nos intendants immédiatement, et une commendation pour vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par le soldat comme par le haut chef de guerre.';
-- Quest 8141 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8141, 'frFR', 'Vous progressez rapidement, jeune $c. Peut-être est-il temps de vous initier à la Shera Ali\'kh - Zandalari pour la Main de la Mort. Pendant des milliers d\'années, nous avons joué le rôle d\'assassin pour l\'Empire Zandalar. Nous sommes restés trop longtemps assis sans rien faire, laissant les Hakkari grandir en force. Nous affrontons Hakkar une fois de plus, mais cette fois sans le soutien d\'un front $r uni. C\'est vous et vos alliés qui devez aider à vaincre le Dieu Sanglant et ses sbires !$b$bPortez ce talisman et laissez-le vous aider dans vos voyages.') ON DUPLICATE KEY UPDATE RewardText='Vous progressez rapidement, jeune $c. Peut-être est-il temps de vous initier à la Shera Ali\'kh - Zandalari pour la Main de la Mort. Pendant des milliers d\'années, nous avons joué le rôle d\'assassin pour l\'Empire Zandalar. Nous sommes restés trop longtemps assis sans rien faire, laissant les Hakkari grandir en force. Nous affrontons Hakkar une fois de plus, mais cette fois sans le soutien d\'un front $r uni. C\'est vous et vos alliés qui devez aider à vaincre le Dieu Sanglant et ses sbires !$b$bPortez ce talisman et laissez-le vous aider dans vos voyages.';
-- Quest 8142 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8142, 'frFR', 'Impressionnant, $n. Vous avez un don pour le meurtre que je n\'ai pas senti chez un autre depuis de nombreuses années. Même Molthor est au courant du travail que vous avez accompli pour Zandalar. Il est temps d\'améliorer davantage votre talisman. Donnez-le-moi.') ON DUPLICATE KEY UPDATE CompletionText='Impressionnant, $n. Vous avez un don pour le meurtre que je n\'ai pas senti chez un autre depuis de nombreuses années. Même Molthor est au courant du travail que vous avez accompli pour Zandalar. Il est temps d\'améliorer davantage votre talisman. Donnez-le-moi.';
-- Quest 8142 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8142, 'frFR', 'Il ne reste qu\'une seule amélioration qui puisse être placée sur le talisman, $C. Quand le moment sera venu, j\'appliquerai cette amélioration.') ON DUPLICATE KEY UPDATE RewardText='Il ne reste qu\'une seule amélioration qui puisse être placée sur le talisman, $C. Quand le moment sera venu, j\'appliquerai cette amélioration.';
-- Quest 8143 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8143, 'frFR', 'Je sens que vous avez infligé d\'innombrables décès aux Hakkari, $n. Vous portez le stigmate de leur magie.$b$bJe suppose que le talisman de l\'Ombre a aidé au nettoyage ? Donnez-le-moi et laissez-moi en améliorer le pouvoir.') ON DUPLICATE KEY UPDATE CompletionText='Je sens que vous avez infligé d\'innombrables décès aux Hakkari, $n. Vous portez le stigmate de leur magie.$b$bJe suppose que le talisman de l\'Ombre a aidé au nettoyage ? Donnez-le-moi et laissez-moi en améliorer le pouvoir.';
-- Quest 8143 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8143, 'frFR', 'Un assassin de votre calibre devrait être laissé tranquille. Vos ennemis doivent apprendre le respect ! Vous obtiendrez cela lorsque l\'ennemi verra l\'éclat de la Main de la Mort - trop tard...') ON DUPLICATE KEY UPDATE RewardText='Un assassin de votre calibre devrait être laissé tranquille. Vos ennemis doivent apprendre le respect ! Vous obtiendrez cela lorsque l\'ennemi verra l\'éclat de la Main de la Mort - trop tard...';
-- Quest 8144 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8144, 'frFR', 'Il aspire à grandir, $n. Le talisman a absorbé tout ce que vous avez fait. Les milliers de cadavres de trolls jonchant Zul\'Gurub ont alimenté son pouvoir. Donnez-le-moi et je ferai l\'amélioration finale.') ON DUPLICATE KEY UPDATE CompletionText='Il aspire à grandir, $n. Le talisman a absorbé tout ce que vous avez fait. Les milliers de cadavres de trolls jonchant Zul\'Gurub ont alimenté son pouvoir. Donnez-le-moi et je ferai l\'amélioration finale.';

-- Quest 8144 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8144, 'frFR', 'C\'est la dernière fois que nous parlerons sous les auspices de Shera Ali\'kh. Tu sais tout ce que tu dois savoir. Prends le talisman et continue dans ton massacre. Hakkar ne doit jamais être autorisé à quitter Zul\'Gurub.') ON DUPLICATE KEY UPDATE RewardText='C\'est la dernière fois que nous parlerons sous les auspices de Shera Ali\'kh. Tu sais tout ce que tu dois savoir. Prends le talisman et continue dans ton massacre. Hakkar ne doit jamais être autorisé à quitter Zul\'Gurub.';
-- Quest 8145 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8145, 'frFR', 'Parmi les Zandalari, le métier de $c est vénéré. Nos meilleurs chasseurs voyagent jusqu\'à l\'extrême du Maelström pour prouver leur résolution.$b$bÀ partir du cœur de la mer, ils tirent des brins de varech connus sous le nom de Tentacules du Maelström. Le varech est ensuite tissé dans un talisman qui est enchanté pour améliorer leur précision et leur puissance.$b$bJe te donne maintenant un tissage du Tentacule du Maelström. À mesure que ton lien avec Zandalar grandit, j\'en tisserai plus de puissance dans le talisman.') ON DUPLICATE KEY UPDATE RewardText='Parmi les Zandalari, le métier de $c est vénéré. Nos meilleurs chasseurs voyagent jusqu\'à l\'extrême du Maelström pour prouver leur résolution.$b$bÀ partir du cœur de la mer, ils tirent des brins de varech connus sous le nom de Tentacules du Maelström. Le varech est ensuite tissé dans un talisman qui est enchanté pour améliorer leur précision et leur puissance.$b$bJe te donne maintenant un tissage du Tentacule du Maelström. À mesure que ton lien avec Zandalar grandit, j\'en tisserai plus de puissance dans le talisman.';
-- Quest 8146 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8146, 'frFR', 'Même d\'ici, j\'entends le son de tes volées ravageant nos ennemis. Leurs cris résonnent d\'agonie.$b$bTu t\'es fait un nom parmi les trolls de Zandalar, $n. Nous sommes reconnaissants pour tout ce que tu as fait.$b$bDonne-moi ton talisman afin que je puisse ajouter un autre tissage.') ON DUPLICATE KEY UPDATE CompletionText='Même d\'ici, j\'entends le son de tes volées ravageant nos ennemis. Leurs cris résonnent d\'agonie.$b$bTu t\'es fait un nom parmi les trolls de Zandalar, $n. Nous sommes reconnaissants pour tout ce que tu as fait.$b$bDonne-moi ton talisman afin que je puisse ajouter un autre tissage.';
-- Quest 8146 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8146, 'frFR', 'Il ne reste qu\'un seul tissage que je pourrai ajouter à ton talisman, $C.') ON DUPLICATE KEY UPDATE RewardText='Il ne reste qu\'un seul tissage que je pourrai ajouter à ton talisman, $C.';
-- Quest 8147 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8147, 'frFR', 'Ah, $n, c\'est bon de te sentir à nouveau.$b$b<Falthir sourit.>$b$bTu devras m\'excuser pour mon sens de l\'humour. Il peut être très mauvais parfois.$b$bJe sens que tu as causé une grande angoisse à nos ennemis. Les forces de Hakkar crient ton nom avec colère. C\'est excellent.$b$bTu as gagné un autre tissage sur ton talisman. Donne-le-moi.') ON DUPLICATE KEY UPDATE CompletionText='Ah, $n, c\'est bon de te sentir à nouveau.$b$b<Falthir sourit.>$b$bTu devras m\'excuser pour mon sens de l\'humour. Il peut être très mauvais parfois.$b$bJe sens que tu as causé une grande angoisse à nos ennemis. Les forces de Hakkar crient ton nom avec colère. C\'est excellent.$b$bTu as gagné un autre tissage sur ton talisman. Donne-le-moi.';
-- Quest 8147 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8147, 'frFR', 'Qu\'ils cherchent l\'absolution à la fin de tes munitions.') ON DUPLICATE KEY UPDATE RewardText='Qu\'ils cherchent l\'absolution à la fin de tes munitions.';
-- Quest 8148 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8148, 'frFR', 'Molthor transmet un message du Roi Rastakhan, $n. La cour royale est très impressionnée par ta décimation des forces Hakkari. Je suis censé t\'accorder le tissage final dans ton talisman. Donne-le-moi.') ON DUPLICATE KEY UPDATE CompletionText='Molthor transmet un message du Roi Rastakhan, $n. La cour royale est très impressionnée par ta décimation des forces Hakkari. Je suis censé t\'accorder le tissage final dans ton talisman. Donne-le-moi.';
-- Quest 8148 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8148, 'frFR', 'Ton voyage ne fait que commencer, jeune <class>. Peut-être un jour tu visiteras le Maelström et jetteras un regard dans le cœur du monde.$B$Je te souhaite puissance et fortitude !') ON DUPLICATE KEY UPDATE RewardText='Ton voyage ne fait que commencer, jeune <class>. Peut-être un jour tu visiteras le Maelström et jetteras un regard dans le cœur du monde.$B$Je te souhaite puissance et fortitude !';
-- Quest 8149 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8149, 'frFR', 'As-tu fait le voyage jusqu\'au Tombeau d\'Uther et y déposé le tribut?$b$bCela peut être un voyage dangereux pour les aventuriers moins expérimentés ; une manière plus sûre d\'y aller, relativement parlant, est de voyager au nord depuis la rivière qui traverse Hillsbrad jusqu\'aux Plaguelands. Elle provient d\'un lac adjacent à la Colline de la Douleur ; voyage à l\'ouest à travers les collines, en évitant le tombeau adjacent... celui qui est infesté par le Fléau.') ON DUPLICATE KEY UPDATE CompletionText='As-tu fait le voyage jusqu\'au Tombeau d\'Uther et y déposé le tribut?$b$bCela peut être un voyage dangereux pour les aventuriers moins expérimentés ; une manière plus sûre d\'y aller, relativement parlant, est de voyager au nord depuis la rivière qui traverse Hillsbrad jusqu\'aux Plaguelands. Elle provient d\'un lac adjacent à la Colline de la Douleur ; voyage à l\'ouest à travers les collines, en évitant le tombeau adjacent... celui qui est infesté par le Fléau.';
-- Quest 8149 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8149, 'frFR', 'Il était un héros parmi les héros, Uther. Je ne peux même pas imaginer l\'angoisse qu\'il a ressentie lorsque Arthas - son plus grand étudiant et quelqu\'un que Uther aimait comme son propre fils - a trahi toute l\'humanité. Pourtant, il s\'est levé pour essayer d\'arrêter Arthas, et pour cela, il sera à jamais souvenu comme un vrai paladin. Son combat a duré jusqu\'au bout, ne pensant qu\'à ceux qu\'il pouvait sauver.$B$BMerci, $N. Tu as rendu hommage à un grand héros aujourd\'hui, honorant son esprit et l\'esprit du Festival des Moissons.') ON DUPLICATE KEY UPDATE RewardText='Il était un héros parmi les héros, Uther. Je ne peux même pas imaginer l\'angoisse qu\'il a ressentie lorsque Arthas - son plus grand étudiant et quelqu\'un que Uther aimait comme son propre fils - a trahi toute l\'humanité. Pourtant, il s\'est levé pour essayer d\'arrêter Arthas, et pour cela, il sera à jamais souvenu comme un vrai paladin. Son combat a duré jusqu\'au bout, ne pensant qu\'à ceux qu\'il pouvait sauver.$B$BMerci, $N. Tu as rendu hommage à un grand héros aujourd\'hui, honorant son esprit et l\'esprit du Festival des Moissons.';
-- Quest 8150 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8150, 'frFR', 'As-tu fait le voyage jusqu\'au Monument de Grom et y déposé son tribut?$b$bLe site où le monument est toujours touché par la souillure de la Légion ardente. Si tu es moins expérimenté dans les voies de l\'aventure, sois vigilant en approchant du monument.') ON DUPLICATE KEY UPDATE CompletionText='As-tu fait le voyage jusqu\'au Monument de Grom et y déposé son tribut?$b$bLe site où le monument est toujours touché par la souillure de la Légion ardente. Si tu es moins expérimenté dans les voies de l\'aventure, sois vigilant en approchant du monument.';
-- Quest 8150 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8150, 'frFR', 'Le nom complet de Grom - Grommash - signifie "Le Cœur du Géant" ; il a fallu cela et plus pour se tenir seul contre Mannoroth. Je pense que le chef de guerre l\'a dit le mieux lorsque la malédiction des orcs a commencé et s\'est terminée avec Grom. Il est approprié que le sacrifice de Grom - et peut-être sa rédemption - soit la source d\'où coule aujourd\'hui la Horde.$B$BMerci, $N. Tu as rendu hommage à un grand héros aujourd\'hui, honorant son esprit et l\'esprit du Festival des Moissons.') ON DUPLICATE KEY UPDATE RewardText='Le nom complet de Grom - Grommash - signifie "Le Cœur du Géant" ; il a fallu cela et plus pour se tenir seul contre Mannoroth. Je pense que le chef de guerre l\'a dit le mieux lorsque la malédiction des orcs a commencé et s\'est terminée avec Grom. Il est approprié que le sacrifice de Grom - et peut-être sa rédemption - soit la source d\'où coule aujourd\'hui la Horde.$B$BMerci, $N. Tu as rendu hommage à un grand héros aujourd\'hui, honorant son esprit et l\'esprit du Festival des Moissons.';
-- Quest 8151 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8151, 'frFR', 'Il n\'est plus de mon devoir de chasser, mais d\'enseigner le $c. C\'est ce que le destin m\'a donné.$B$bCrée avec moi un charme de $c\'s -- une collection de trophées de proies tombées qui te rappelleront tes épreuves et tes triomphes passés. À la fin, je garderai le charme, mais je te récompenserai avec autre chose.') ON DUPLICATE KEY UPDATE RewardText='Il n\'est plus de mon devoir de chasser, mais d\'enseigner le $c. C\'est ce que le destin m\'a donné.$B$bCrée avec moi un charme de $c\'s -- une collection de trophées de proies tombées qui te rappelleront tes épreuves et tes triomphes passés. À la fin, je garderai le charme, mais je te récompenserai avec autre chose.';
-- Quest 8153 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8153, 'frFR', 'Tu dois posséder un sens aigu de l\'observation et une grande patience pour avoir obtenu ceux-ci. Bien joué.') ON DUPLICATE KEY UPDATE RewardText='Tu dois posséder un sens aigu de l\'observation et une grande patience pour avoir obtenu ceux-ci. Bien joué.';
-- Quest 8154 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8154, 'frFR', 'As-tu la caisse de ressources, $N? La Ligue d\'Arathor ne peut pas mener un bon combat sans eux...') ON DUPLICATE KEY UPDATE CompletionText='As-tu la caisse de ressources, $N? La Ligue d\'Arathor ne peut pas mener un bon combat sans eux...';

-- Quest 8154 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8154, 'frFR', 'Vous avez les ressources ! Bon travail ! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que vous avez réalisée est ainsi que les guerres sont réellement gagnées.') ON DUPLICATE KEY UPDATE RewardText='Vous avez les ressources ! Bon travail ! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que vous avez réalisée est ainsi que les guerres sont réellement gagnées.';
-- Quest 8155 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8155, 'frFR', 'Avez-vous la caisse de ressources, $N? La Ligue d\'Arathor ne peut mener une bataille décente sans elles...') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous la caisse de ressources, $N? La Ligue d\'Arathor ne peut mener une bataille décente sans elles...';
-- Quest 8155 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8155, 'frFR', 'Vous avez les ressources ! Bon travail ! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que vous avez réalisée est ainsi que les guerres sont réellement gagnées.') ON DUPLICATE KEY UPDATE RewardText='Vous avez les ressources ! Bon travail ! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que vous avez réalisée est ainsi que les guerres sont réellement gagnées.';
