INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8156, 'frFR', 'Vous avez les ressources ! Bon travail ! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que vous avez réalisée est ainsi que les guerres sont réellement gagnées.') ON DUPLICATE KEY UPDATE RewardText='Vous avez les ressources ! Bon travail ! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que vous avez réalisée est ainsi que les guerres sont réellement gagnées.';
-- Quest 8157 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8157, 'frFR', '$N, la Ligue d\'Arathor a une mission permanente pour vous afin de réentrer dans la Baie d\'Arathi, de vous procurer plus de caisses de ressources et de me les apporter.') ON DUPLICATE KEY UPDATE CompletionText='$N, la Ligue d\'Arathor a une mission permanente pour vous afin de réentrer dans la Baie d\'Arathi, de vous procurer plus de caisses de ressources et de me les apporter.';
-- Quest 8157 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8157, 'frFR', 'Très bien. Je les ferai parvenir à nos intendants immédiatement, et une mention de vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par le soldat et le maréchal de camp.') ON DUPLICATE KEY UPDATE RewardText='Très bien. Je les ferai parvenir à nos intendants immédiatement, et une mention de vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par le soldat et le maréchal de camp.';
