-- Quest 8165 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8165, 'frFR', '$N, les Défileurs ont une mission en cours pour que vous retourniez dans la Basse Arathi, récupériez plus de caisses de ressources et me les apportiez.') ON DUPLICATE KEY UPDATE CompletionText='$N, les Défileurs ont une mission en cours pour que vous retourniez dans la Basse Arathi, récupériez plus de caisses de ressources et me les apportiez.';
-- Quest 8165 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8165, 'frFR', 'Très bien. Je les remettrai immédiatement à nos intendants, et une commendation pour vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par les soldats et les grands chefs de guerre.') ON DUPLICATE KEY UPDATE RewardText='Très bien. Je les remettrai immédiatement à nos intendants, et une commendation pour vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par les soldats et les grands chefs de guerre.';
-- Quest 8167 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8167, 'frFR', 'J\'ai reçu des rapports de vos exploits dans la Basse Arathi, <name>.  Bien joué!  Avec des gens comme vous rejoignant les luttes ici, j\'ai confiance que nous récupérerons un jour nos patrie.') ON DUPLICATE KEY UPDATE RewardText='J\'ai reçu des rapports de vos exploits dans la Basse Arathi, <name>.  Bien joué!  Avec des gens comme vous rejoignant les luttes ici, j\'ai confiance que nous récupérerons un jour nos patrie.';
