INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8168, 'frFR', 'J\'ai reçu des rapports de vos exploits dans la Basse Arathi, <name>.  Bien joué!  Avec des gens comme vous rejoignant les luttes ici, j\'ai confiance que nous récupérerons un jour nos patrie.') ON DUPLICATE KEY UPDATE RewardText='J\'ai reçu des rapports de vos exploits dans la Basse Arathi, <name>.  Bien joué!  Avec des gens comme vous rejoignant les luttes ici, j\'ai confiance que nous récupérerons un jour nos patrie.';
-- Quest 8169 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8169, 'frFR', 'Un éclaireur des Défileurs m\'a apporté un rapport de votre succès, <name>.  Bien joué.$B$BComme vous allez apprendre, pour gagner la bataille de la Basse Arathi, nous devons être toujours vigilants et écraser toute tentative d\'expansion de l\'Alliance.  Faites cela, et notre victoire ici est assurée.') ON DUPLICATE KEY UPDATE RewardText='Un éclaireur des Défileurs m\'a apporté un rapport de votre succès, <name>.  Bien joué.$B$BComme vous allez apprendre, pour gagner la bataille de la Basse Arathi, nous devons être toujours vigilants et écraser toute tentative d\'expansion de l\'Alliance.  Faites cela, et notre victoire ici est assurée.';
