-- Quest 8193 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8193, 'frFR', 'Aujourd\'hui entre 14h et 16h, nous avons un concours pour déterminer qui est le plus grand pêcheur de tous ! Soyez le PREMIER à m\'apporter 40 Poisson-délicieux pêchés dans les bancs de Poisson-délicieux trouvés le long de la côte de Stranglethorn avant qu\'une autre personne ne le fasse et vous serez déclaré Maître Pêcheur !$b$bSi vous n\'êtes pas la première personne à m\'apporter 40 poissons, mon apprentie ici vous récompensera quand même avec de l\'argent pour chaque 5 Poisson-délicieux que vous lui apportez.$b$bOh, et ne tardez pas, les Poisson-délicieux pourrissent vite !') ON DUPLICATE KEY UPDATE CompletionText='Aujourd\'hui entre 14h et 16h, nous avons un concours pour déterminer qui est le plus grand pêcheur de tous ! Soyez le PREMIER à m\'apporter 40 Poisson-délicieux pêchés dans les bancs de Poisson-délicieux trouvés le long de la côte de Stranglethorn avant qu\'une autre personne ne le fasse et vous serez déclaré Maître Pêcheur !$b$bSi vous n\'êtes pas la première personne à m\'apporter 40 poissons, mon apprentie ici vous récompensera quand même avec de l\'argent pour chaque 5 Poisson-délicieux que vous lui apportez.$b$bOh, et ne tardez pas, les Poisson-délicieux pourrissent vite !';
-- Quest 8193 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8193, 'frFR', 'Dépêchez-vous et déposez-les si vous voulez être déclaré Maître Pêcheur !  Je suis là depuis DES HEURES sans rien à manger !   Donnez ces salauds !') ON DUPLICATE KEY UPDATE RewardText='Dépêchez-vous et déposez-les si vous voulez être déclaré Maître Pêcheur !  Je suis là depuis DES HEURES sans rien à manger !   Donnez ces salauds !';
-- Quest 8194 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8194, 'frFR', 'Même si nous avons déjà un gagnant du concours, je vous achèterai toujours vos Poisson-délicieux à un prix raisonnable. Qu\'en dites-vous !') ON DUPLICATE KEY UPDATE CompletionText='Même si nous avons déjà un gagnant du concours, je vous achèterai toujours vos Poisson-délicieux à un prix raisonnable. Qu\'en dites-vous !';
-- Quest 8195 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8195, 'frFR', 'Je recherche les Paragons de Puissance connus sous le nom de Pièces des Tribus. Ce sont la monnaie utilisée par les divers habitants de Zul\'Gurub, et chacun est imprégné d\'un mojo subtil mais puissant.$B$BIl y en a neuf sortes distinctes à trouver. Si vous en avez en trop, je vous échangerai un de nos Jetons d\'Honneur contre un ensemble de trois. Vous pouvez utiliser les jetons avec Rin\'wosho le Marchand ; il offre à nos héros des objets spéciaux pour eux.') ON DUPLICATE KEY UPDATE CompletionText='Je recherche les Paragons de Puissance connus sous le nom de Pièces des Tribus. Ce sont la monnaie utilisée par les divers habitants de Zul\'Gurub, et chacun est imprégné d\'un mojo subtil mais puissant.$B$BIl y en a neuf sortes distinctes à trouver. Si vous en avez en trop, je vous échangerai un de nos Jetons d\'Honneur contre un ensemble de trois. Vous pouvez utiliser les jetons avec Rin\'wosho le Marchand ; il offre à nos héros des objets spéciaux pour eux.';
-- Quest 8196 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8196, 'frFR', 'L\'essence de mangue extrêmement puissante pousse sur de nombreuses îles des Mers du Sud. Un seul mangue rafraîchira ceux qui le mangent, physiquement et mentalement. Si vous n\'en avez jamais mangé, vous vous faites une injustice !$B$BNous en avons suffisamment ici sur l\'île pour vous offrir une poignée en échange d\'un Jeton d\'Honneur de Zandalar. Parlez à Vinchaxa si vous avez besoin d\'apprendre comment obtenir des jetons ; sinon, passons au sujet !') ON DUPLICATE KEY UPDATE CompletionText='L\'essence de mangue extrêmement puissante pousse sur de nombreuses îles des Mers du Sud. Un seul mangue rafraîchira ceux qui le mangent, physiquement et mentalement. Si vous n\'en avez jamais mangé, vous vous faites une injustice !$B$BNous en avons suffisamment ici sur l\'île pour vous offrir une poignée en échange d\'un Jeton d\'Honneur de Zandalar. Parlez à Vinchaxa si vous avez besoin d\'apprendre comment obtenir des jetons ; sinon, passons au sujet !';

-- Quest 8196 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8196, 'frFR', 'Un juste échange, mon ami - savoure les fruits succulents des Mers du Sud, avec la bénédiction de la tribu.') ON DUPLICATE KEY UPDATE RewardText='Un juste échange, mon ami - savoure les fruits succulents des Mers du Sud, avec la bénédiction de la tribu.';
-- Quest 8201 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8201, 'frFR', 'As-tu la collection de têtes, $N$? Nous devons empêcher Hakkar d\'acquérir plus de pouvoir!') ON DUPLICATE KEY UPDATE CompletionText='As-tu la collection de têtes, $N$? Nous devons empêcher Hakkar d\'acquérir plus de pouvoir!';
-- Quest 8201 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8201, 'frFR', 'Tu as obtenu les têtes!  Tu as stoppé le pillage du pouvoir de nos dieux, et affaibli Hakkar!$B$BTes actions sont vraiment héroïques, <name>.  Que les têtes de ces esclaves troll implorent ta pitié bien après que leur sang se soit refroidi.') ON DUPLICATE KEY UPDATE RewardText='Tu as obtenu les têtes!  Tu as stoppé le pillage du pouvoir de nos dieux, et affaibli Hakkar!$B$BTes actions sont vraiment héroïques, <name>.  Que les têtes de ces esclaves troll implorent ta pitié bien après que leur sang se soit refroidi.';
-- Quest 8221 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8221, 'frFR', '*Whir* *Click*$b$bJe cherche des poissons rares pour Fishmaster Bluegill afin de les cataloguer. Si tu m\'apportes un Angelfish de Keefer, je te fournirai cette belle récompense.$b$b*Zzzap* *Whir*') ON DUPLICATE KEY UPDATE CompletionText='*Whir* *Click*$b$bJe cherche des poissons rares pour Fishmaster Bluegill afin de les cataloguer. Si tu m\'apportes un Angelfish de Keefer, je te fournirai cette belle récompense.$b$b*Zzzap* *Whir*';
-- Quest 8221 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8221, 'frFR', '*Whir* $B$B Identification de l\'Angelfish de Keefer terminée. $B$B Ta récompense est maintenant disponible. $B$B *click-click* *Bzzzz*') ON DUPLICATE KEY UPDATE RewardText='*Whir* $B$B Identification de l\'Angelfish de Keefer terminée. $B$B Ta récompense est maintenant disponible. $B$B *click-click* *Bzzzz*';
-- Quest 8222 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8222, 'frFR', 'En tout mon temps à travailler à la Foire, j\'ai appris beaucoup de choses sur les clients. Voici une de ces perles de sagesse : les clients adorent ce qui brille! Peu importe ce que c\'est - tu pourrais prendre une patte de chaise cassée et la faire briller, et chaque enfant viendrait de partout pour en avoir une!$B$BAlors, $N$, j\'ai besoin de sang de scorpid qui brille. Tu peux le trouver auprès des scorpides de Sillithus, ou des Terres Brûlées, ou des Steppes Ardentes.') ON DUPLICATE KEY UPDATE CompletionText='En tout mon temps à travailler à la Foire, j\'ai appris beaucoup de choses sur les clients. Voici une de ces perles de sagesse : les clients adorent ce qui brille! Peu importe ce que c\'est - tu pourrais prendre une patte de chaise cassée et la faire briller, et chaque enfant viendrait de partout pour en avoir une!$B$BAlors, $N$, j\'ai besoin de sang de scorpid qui brille. Tu peux le trouver auprès des scorpides de Sillithus, ou des Terres Brûlées, ou des Steppes Ardentes.';
-- Quest 8222 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8222, 'frFR', 'Bon travail, <name>!  Merci beaucoup!  Je vais fabriquer de la peinture avec ce sang et transformer toutes sortes de déchets bon marché en trésors brillants!$B$BVoici tes tickets, et merci encore!') ON DUPLICATE KEY UPDATE RewardText='Bon travail, <name>!  Merci beaucoup!  Je vais fabriquer de la peinture avec ce sang et transformer toutes sortes de déchets bon marché en trésors brillants!$B$BVoici tes tickets, et merci encore!';
-- Quest 8223 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8223, 'frFR', 'Ce sang de scorpid fonctionne très bien, $N! C\'est incroyable comme un peu de scintillement et de brillance peut transformer un morceau de camelote en un bibelot précieux. Les clients adorent ce truc, et l\'amour, c\'est tout ce qui compte, tu ne crois pas...$B$BTu m\'as été d\'une grande aide, $N$, et bien que je n\'aie pas un besoin urgent de plus de sang de scorpid qui brille, si tu m\'en apportes davantage, je te donnerai quand même des tickets.') ON DUPLICATE KEY UPDATE CompletionText='Ce sang de scorpid fonctionne très bien, $N! C\'est incroyable comme un peu de scintillement et de brillance peut transformer un morceau de camelote en un bibelot précieux. Les clients adorent ce truc, et l\'amour, c\'est tout ce qui compte, tu ne crois pas...$B$BTu m\'as été d\'une grande aide, $N$, et bien que je n\'aie pas un besoin urgent de plus de sang de scorpid qui brille, si tu m\'en apportes davantage, je te donnerai quand même des tickets.';
-- Quest 8224 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8224, 'frFR', '*Whir* *Click*$b$bJe cherche des poissons rares pour Fishmaster Bluegill afin de les cataloguer. Si tu m\'apportes un Queenfish de Dezian, je te fournirai cette belle récompense.$b$b*Zzzap* *Whir*') ON DUPLICATE KEY UPDATE CompletionText='*Whir* *Click*$b$bJe cherche des poissons rares pour Fishmaster Bluegill afin de les cataloguer. Si tu m\'apportes un Queenfish de Dezian, je te fournirai cette belle récompense.$b$b*Zzzap* *Whir*';
-- Quest 8224 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8224, 'frFR', '*Whir* $B$B Identification du Queenfish de Dezian terminée. $B$B Ta récompense est maintenant disponible. $B$B *click-click* *Bzzzz*') ON DUPLICATE KEY UPDATE RewardText='*Whir* $B$B Identification du Queenfish de Dezian terminée. $B$B Ta récompense est maintenant disponible. $B$B *click-click* *Bzzzz*';
-- Quest 8225 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8225, 'frFR', '*Whir* *Click*$b$bJe cherche des poissons rares pour Fishmaster Bluegill afin de les cataloguer. Si tu m\'apportes un Racer à rayures bleues de Brownell, je te fournirai cette belle récompense.$b$b*Zzzap* *Whir*') ON DUPLICATE KEY UPDATE CompletionText='*Whir* *Click*$b$bJe cherche des poissons rares pour Fishmaster Bluegill afin de les cataloguer. Si tu m\'apportes un Racer à rayures bleues de Brownell, je te fournirai cette belle récompense.$b$b*Zzzap* *Whir*';
-- Quest 8225 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8225, 'frFR', '*Whir* $B$B Identification du Racer de Brownell terminée. $B$B Ta récompense est maintenant disponible. $B$B *click-click* *Bzzzz*') ON DUPLICATE KEY UPDATE RewardText='*Whir* $B$B Identification du Racer de Brownell terminée. $B$B Ta récompense est maintenant disponible. $B$B *click-click* *Bzzzz*';
-- Quest 8231 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8231, 'frFR', 'Les dévoreurs d\'ondes ne sont pas facilement vaincus, d\'autant plus dans leur environnement aquatique.$B$BTu t\'es prouvé prêt à chasser des proies encore plus meurtrières.') ON DUPLICATE KEY UPDATE RewardText='Les dévoreurs d\'ondes ne sont pas facilement vaincus, d\'autant plus dans leur environnement aquatique.$B$BTu t\'es prouvé prêt à chasser des proies encore plus meurtrières.';
-- Quest 8232 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8232, 'frFR', 'Je vois la sagesse dans tes yeux, $N$. Ta chasse est-elle terminée?') ON DUPLICATE KEY UPDATE CompletionText='Je vois la sagesse dans tes yeux, $N$. Ta chasse est-elle terminée?';

-- Quest 8232 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8232, 'frFR', 'Tu as appris les vieilles méthodes, $N$, et pour cela, je t\'offre un cadeau de mes jours en tant que $c$.') ON DUPLICATE KEY UPDATE RewardText='Tu as appris les vieilles méthodes, $N$, et pour cela, je t\'offre un cadeau de mes jours en tant que $c$.';
-- Quest 8233 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8233, 'frFR', 'Bienvenue, bienvenue, bienvenue ! S\'il vous plaît, $N$, asseyez-vous et discutons d\'une affaire simple avec moi.$B$BVous voyez, $N$, j\'ai récemment perdu quelque chose de cher à mon cœur, et pour être franc, je veux le récupérer à tout prix. Il y a quelque chose pour toi, ne t\'inquiète pas pour ça ! Oh oui, quelque chose de très agréable.$B$BMaintenant, qu\'en dis-tu $N$... es-tu partant pour une aventure ?') ON DUPLICATE KEY UPDATE RewardText='Bienvenue, bienvenue, bienvenue ! S\'il vous plaît, $N$, asseyez-vous et discutons d\'une affaire simple avec moi.$B$BVous voyez, $N$, j\'ai récemment perdu quelque chose de cher à mon cœur, et pour être franc, je veux le récupérer à tout prix. Il y a quelque chose pour toi, ne t\'inquiète pas pour ça ! Oh oui, quelque chose de très agréable.$B$BMaintenant, qu\'en dis-tu $N$... es-tu partant pour une aventure ?';
-- Quest 8234 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8234, 'frFR', 'Je vois que tu as le sac de Lord Ravenholdt. Pourquoi ne l\'as-tu pas dit, garçon ?') ON DUPLICATE KEY UPDATE RewardText='Je vois que tu as le sac de Lord Ravenholdt. Pourquoi ne l\'as-tu pas dit, garçon ?';
-- Quest 8235 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8235, 'frFR', 'As-tu trouvé assez de fragments pour continuer mon travail ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé assez de fragments pour continuer mon travail ?';
-- Quest 8235 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8235, 'frFR', 'Il semble que tu aies ramassé quelques-uns des meilleurs fragments. Peut-être que tu n\'es pas sans valeur après tout.') ON DUPLICATE KEY UPDATE RewardText='Il semble que tu aies ramassé quelques-uns des meilleurs fragments. Peut-être que tu n\'es pas sans valeur après tout.';
-- Quest 8236 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8236, 'frFR', 'Le sac est arrivé de l\'Archimage Xylem, as-tu trouvé la clé ?') ON DUPLICATE KEY UPDATE CompletionText='Le sac est arrivé de l\'Archimage Xylem, as-tu trouvé la clé ?';
-- Quest 8236 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8236, 'frFR', 'La clé ! Je pensais qu\'elle était perdue pour toujours. S\'il te plaît, prends un vêtement enchanté de mes réserves -- ils sont réservés aux voleurs de compétence et de loyauté exceptionnels. Il faut savoir que $N n\'est pas à prendre à la légère !$B$B<Jorach ouvre le sac et est baigné par une lueur dorée venant de l\'intérieur. Ses yeux s\'écarquillent et il fixe...>') ON DUPLICATE KEY UPDATE RewardText='La clé ! Je pensais qu\'elle était perdue pour toujours. S\'il te plaît, prends un vêtement enchanté de mes réserves -- ils sont réservés aux voleurs de compétence et de loyauté exceptionnels. Il faut savoir que $N n\'est pas à prendre à la légère !$B$B<Jorach ouvre le sac et est baigné par une lueur dorée venant de l\'intérieur. Ses yeux s\'écarquillent et il fixe...>';
-- Quest 8238 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8238, 'frFR', 'Je recherche les Paragons de Pouvoir connus sous le nom de Pièces des Tribus. Ce sont la monnaie utilisée par les divers habitants de Zul\'Gurub, et chacun est imprégné d\'un mojo subtil mais puissant.$B$BIl y a neuf types distincts à trouver. Si tu en as des excédentaires, je t\'échangerai l\'un de nos Jetons d\'Honneur contre un ensemble de trois. Tu peux utiliser les Jetons avec Rin\'wosho le Marchand ; il offre à nos héros des objets spéciaux en échange.') ON DUPLICATE KEY UPDATE CompletionText='Je recherche les Paragons de Pouvoir connus sous le nom de Pièces des Tribus. Ce sont la monnaie utilisée par les divers habitants de Zul\'Gurub, et chacun est imprégné d\'un mojo subtil mais puissant.$B$BIl y a neuf types distincts à trouver. Si tu en as des excédentaires, je t\'échangerai l\'un de nos Jetons d\'Honneur contre un ensemble de trois. Tu peux utiliser les Jetons avec Rin\'wosho le Marchand ; il offre à nos héros des objets spéciaux en échange.';
-- Quest 8239 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8239, 'frFR', 'Je recherche les Paragons de Pouvoir connus sous le nom de Pièces des Tribus. Ce sont la monnaie utilisée par les divers habitants de Zul\'Gurub, et chacun est imprégné d\'un mojo subtil mais puissant.$B$BIl y a neuf types distincts à trouver. Si tu en as des excédentaires, je t\'échangerai l\'un de nos Jetons d\'Honneur contre un ensemble de trois. Tu peux utiliser les Jetons avec Rin\'wosho le Marchand ; il offre à nos héros des objets spéciaux en échange.') ON DUPLICATE KEY UPDATE CompletionText='Je recherche les Paragons de Pouvoir connus sous le nom de Pièces des Tribus. Ce sont la monnaie utilisée par les divers habitants de Zul\'Gurub, et chacun est imprégné d\'un mojo subtil mais puissant.$B$BIl y a neuf types distincts à trouver. Si tu en as des excédentaires, je t\'échangerai l\'un de nos Jetons d\'Honneur contre un ensemble de trois. Tu peux utiliser les Jetons avec Rin\'wosho le Marchand ; il offre à nos héros des objets spéciaux en échange.';
-- Quest 8240 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8240, 'frFR', 'As-tu détruit le bijou à l\'Autel de Zanza ? Fais-le, et alors tu seras doublement béni par Zanza !') ON DUPLICATE KEY UPDATE CompletionText='As-tu détruit le bijou à l\'Autel de Zanza ? Fais-le, et alors tu seras doublement béni par Zanza !';
-- Quest 8241 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8241, 'frFR', 'Ne gaspillons plus mon précieux temps avec des bobards, $r$. Il est temps de se concentrer sur le réapprovisionnement de notre maigre réserve de flux ardent.$B$BCe dont j\'ai besoin de ta part, c\'est ce qui suit:$B$B*Écailles d\'Incendosaur.$B$B*Barres de fer.$B$B*Charbon.$B$Je prendrai tout ce que tu peux offrir !$B$BEt tu le feras vite si tu veux te faire bien avec la Fraternité.') ON DUPLICATE KEY UPDATE CompletionText='Ne gaspillons plus mon précieux temps avec des bobards, $r$. Il est temps de se concentrer sur le réapprovisionnement de notre maigre réserve de flux ardent.$B$BCe dont j\'ai besoin de ta part, c\'est ce qui suit:$B$B*Écailles d\'Incendosaur.$B$B*Barres de fer.$B$B*Charbon.$B$Je prendrai tout ce que tu peux offrir !$B$BEt tu le feras vite si tu veux te faire bien avec la Fraternité.';
-- Quest 8241 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8241, 'frFR', 'Il y a toujours de la place pour plus de flux ardent, junior. Continue... sauf si je te dis d\'arrêter.') ON DUPLICATE KEY UPDATE RewardText='Il y a toujours de la place pour plus de flux ardent, junior. Continue... sauf si je te dis d\'arrêter.';
-- Quest 8242 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8242, 'frFR', 'Ne gaspillons plus mon précieux temps avec des bobards, $r$. Il est temps de se concentrer sur le réapprovisionnement de notre maigre réserve de flux ardent.$B$BCe dont j\'ai besoin de ta part, c\'est ce qui suit:$B$B*Écailles d\'Incendosaur.$B$B*Cuir lourd.$B$B*Charbon.$B$Je prendrai tout ce que tu peux offrir !$B$BEt tu le feras vite si tu veux te faire bien avec la Fraternité.') ON DUPLICATE KEY UPDATE CompletionText='Ne gaspillons plus mon précieux temps avec des bobards, $r$. Il est temps de se concentrer sur le réapprovisionnement de notre maigre réserve de flux ardent.$B$BCe dont j\'ai besoin de ta part, c\'est ce qui suit:$B$B*Écailles d\'Incendosaur.$B$B*Cuir lourd.$B$B*Charbon.$B$Je prendrai tout ce que tu peux offrir !$B$BEt tu le feras vite si tu veux te faire bien avec la Fraternité.';
-- Quest 8242 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8242, 'frFR', 'Il y a toujours de la place pour plus de flux ardent, junior. Continue...') ON DUPLICATE KEY UPDATE RewardText='Il y a toujours de la place pour plus de flux ardent, junior. Continue...';
-- Quest 8243 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8243, 'frFR', 'Avec ton statut accru au sein de la tribu, tu as accès à certains de nos potables plus puissants. Contemple... ces infusions sont fortes en mojo - bénies par Zanza et adaptées aux aventuriers de tous horizons !$B$BI te permettra de choisir un parmi les trois que j\'offre ; en échange, j\'exige un Jeton d\'Honneur Zandarien. Note que seuls les effets d\'un seul peuvent circuler dans ton esprit à un moment donné.$B$BDis-moi quand tu es prêt à échanger !') ON DUPLICATE KEY UPDATE CompletionText='Avec ton statut accru au sein de la tribu, tu as accès à certains de nos potables plus puissants. Contemple... ces infusions sont fortes en mojo - bénies par Zanza et adaptées aux aventuriers de tous horizons !$B$BI te permettra de choisir un parmi les trois que j\'offre ; en échange, j\'exige un Jeton d\'Honneur Zandarien. Note que seuls les effets d\'un seul peuvent circuler dans ton esprit à un moment donné.$B$BDis-moi quand tu es prêt à échanger !';

-- Quest 8243 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8243, 'frFR', 'Un échange équitable, mon ami - veuillez accepter les bénédictions de Zanza avec notre compliments !') ON DUPLICATE KEY UPDATE RewardText='Un échange équitable, mon ami - veuillez accepter les bénédictions de Zanza avec notre compliments !';
-- Quest 8246 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8246, 'frFR', '$N - pour quelqu\'un d\'aussi exalté parmi les Zandalar que vous, j\'ai quelque chose de très spécial pour vous. Directement de notre foyer dans les Mers du Sud... les Signets de Zandalar ! Ces signets sont utilisés pour améliorer tout équipement d\'épaule que vous possédez. Si vous recherchez la puissance, le mojo ou la sérénité - j\'ai ce dont vous avez besoin !$B$BI demande quinze jetons d\'honneur Zandalar en échange de votre choix d\'un signet. Si vous avez les jetons prêts, alors je suis prêt à faire un marché !') ON DUPLICATE KEY UPDATE CompletionText='$N - pour quelqu\'un d\'aussi exalté parmi les Zandalar que vous, j\'ai quelque chose de très spécial pour vous. Directement de notre foyer dans les Mers du Sud... les Signets de Zandalar ! Ces signets sont utilisés pour améliorer tout équipement d\'épaule que vous possédez. Si vous recherchez la puissance, le mojo ou la sérénité - j\'ai ce dont vous avez besoin !$B$BI demande quinze jetons d\'honneur Zandalar en échange de votre choix d\'un signet. Si vous avez les jetons prêts, alors je suis prêt à faire un marché !';
-- Quest 8246 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8246, 'frFR', 'Un échange équitable, mon ami - veuillez accepter votre signet avec la bénédiction de la tribu !') ON DUPLICATE KEY UPDATE RewardText='Un échange équitable, mon ami - veuillez accepter votre signet avec la bénédiction de la tribu !';
-- Quest 8249 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8249, 'frFR', 'Mes voleurs doivent perfectionner leurs compétences en crochetage, et j\'ai besoin de serrures d\'une difficulté adéquate -- ce que Zan nous fabrique n\'est apte qu\'aux plus insignifiants néophytes.$b$bJe vous dis quoi, si vous m\'apportez 5 Boîtes de ferraille lourdes, je vous fournirai certains des plus fins couteaux de lancer connus du genre voleur.$b$bVous pouvez déverrouiller les boîtes et les fouiller, mais vous devrez laisser au moins quelques pièces dedans... même un voleur en formation a besoin de motivation.') ON DUPLICATE KEY UPDATE CompletionText='Mes voleurs doivent perfectionner leurs compétences en crochetage, et j\'ai besoin de serrures d\'une difficulté adéquate -- ce que Zan nous fabrique n\'est apte qu\'aux plus insignifiants néophytes.$b$bJe vous dis quoi, si vous m\'apportez 5 Boîtes de ferraille lourdes, je vous fournirai certains des plus fins couteaux de lancer connus du genre voleur.$b$bVous pouvez déverrouiller les boîtes et les fouiller, mais vous devrez laisser au moins quelques pièces dedans... même un voleur en formation a besoin de motivation.';
-- Quest 8250 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8250, 'frFR', '<Sanath vous lance un regard méprisant.>$B$BL\'Archimage Xylem attend votre arrivée.') ON DUPLICATE KEY UPDATE RewardText='<Sanath vous lance un regard méprisant.>$B$BL\'Archimage Xylem attend votre arrivée.';
-- Quest 8251 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8251, 'frFR', 'Bien joué, $N! Cela ne cesse de m\'étonner à quel point un vol de missiles arcaniques peut être persuasif.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N! Cela ne cesse de m\'étonner à quel point un vol de missiles arcaniques peut être persuasif.';
-- Quest 8252 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8252, 'frFR', 'Les sirènes de spitelash sont des mages étonnamment doués. Pas aussi doués que vous, j\'espère ?') ON DUPLICATE KEY UPDATE CompletionText='Les sirènes de spitelash sont des mages étonnamment doués. Pas aussi doués que vous, j\'espère ?';
-- Quest 8252 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8252, 'frFR', 'Ceci est un spécimen de corail superbe, $N. Vos compétences sont incontestablement précises et mortelles.$B$BNe pensez pas que vos efforts sont passés inaperçus. Peut-être êtes-vous digne d\'un véritable test de vos compétences...') ON DUPLICATE KEY UPDATE RewardText='Ceci est un spécimen de corail superbe, $N. Vos compétences sont incontestablement précises et mortelles.$B$BNe pensez pas que vos efforts sont passés inaperçus. Peut-être êtes-vous digne d\'un véritable test de vos compétences...';
-- Quest 8253 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8253, 'frFR', 'Avez-vous abattu mon ancien ennemi ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous abattu mon ancien ennemi ?';
-- Quest 8253 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8253, 'frFR', 'Incroyable. Le shard a grandi en absorbant l\'énergie du drake au fil des longues années.$B$BIl n\'y a plus rien que je puisse vous demander maintenant. Ma pleine capacité à forger l\'arcane est revenue avec ce shard. Ma première création vous est offerte, $N, et il ne vous reste plus qu\'à choisir...') ON DUPLICATE KEY UPDATE RewardText='Incroyable. Le shard a grandi en absorbant l\'énergie du drake au fil des longues années.$B$BIl n\'y a plus rien que je puisse vous demander maintenant. Ma pleine capacité à forger l\'arcane est revenue avec ce shard. Ma première création vous est offerte, $N, et il ne vous reste plus qu\'à choisir...';
-- Quest 8254 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8254, 'frFR', 'Votre arrivée a enlevé un poids de mes épaules. Nous avons beaucoup à faire.') ON DUPLICATE KEY UPDATE RewardText='Votre arrivée a enlevé un poids de mes épaules. Nous avons beaucoup à faire.';
-- Quest 8255 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8255, 'frFR', 'Vous êtes revenu. Avez-vous réussi ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu. Avez-vous réussi ?';
-- Quest 8255 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8255, 'frFR', 'Il est bon que le chemin divin vous ait mené à nous, $N. Vos croyances n\'interfèrent pas avec les tâches impliquées dans la création de ce baume.$B$BVous voyez, le courser est sacré pour le Cercle de Cenarion, et les tuer pour quelque raison que ce soit, aussi nécessaire soit-ce, affaiblit leur esprit.') ON DUPLICATE KEY UPDATE RewardText='Il est bon que le chemin divin vous ait mené à nous, $N. Vos croyances n\'interfèrent pas avec les tâches impliquées dans la création de ce baume.$B$BVous voyez, le courser est sacré pour le Cercle de Cenarion, et les tuer pour quelque raison que ce soit, aussi nécessaire soit-ce, affaiblit leur esprit.';
-- Quest 8256 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8256, 'frFR', 'Nous devons obtenir l\'ichor rapidement. L\'avez-vous trouvé ?') ON DUPLICATE KEY UPDATE CompletionText='Nous devons obtenir l\'ichor rapidement. L\'avez-vous trouvé ?';
-- Quest 8256 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8256, 'frFR', 'Je ne peux pas dire que je suis heureux de recevoir une substance aussi misérable, mais c\'est un mal nécessaire. Merci, $N$.') ON DUPLICATE KEY UPDATE RewardText='Je ne peux pas dire que je suis heureux de recevoir une substance aussi misérable, mais c\'est un mal nécessaire. Merci, $N$.';

-- Quest 8257 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8257, 'frFR', 'As-tu le sang de Morphaz ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu le sang de Morphaz ?';
-- Quest 8257 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8257, 'frFR', 'Tu as tué Morphaz et apporté son sang jusqu\'à nous... Je peux à peine croire cette bonne nouvelle !$B$BNous combinerons les ingrédients immédiatement et commencerons à guérir les arbres et les créatures de Felwood. Il faudra une vie pour réparer ce qui s\'est passé ici, mais tu nous as donné les moyens de le faire.') ON DUPLICATE KEY UPDATE RewardText='Tu as tué Morphaz et apporté son sang jusqu\'à nous... Je peux à peine croire cette bonne nouvelle !$B$BNous combinerons les ingrédients immédiatement et commencerons à guérir les arbres et les créatures de Felwood. Il faudra une vie pour réparer ce qui s\'est passé ici, mais tu nous as donné les moyens de le faire.';
-- Quest 8258 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8258, 'frFR', 'Le temps est critique, $N - as-tu réussi à stopper la menace de Darkreaver le Chevalier de la Mort ?') ON DUPLICATE KEY UPDATE CompletionText='Le temps est critique, $N - as-tu réussi à stopper la menace de Darkreaver le Chevalier de la Mort ?';
-- Quest 8258 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8258, 'frFR', 'C\'est une victoire à savourer, $N ! La mort de Darkreaver devrait restaurer les liens fragiles qui ancrent le royaume des esprits.$B$BTu as largement dépassé ce qui t\'a été demandé, même sans avoir idée de récompense ou de compensation. Tu es vraiment un $c de valeur, mon ami.$B$BI sais que agir pour préserver le royaume des esprits devrait être un remerciement suffisant, mais s\'il te plaît - accepte ce simple cadeau avec mes remerciements.') ON DUPLICATE KEY UPDATE RewardText='C\'est une victoire à savourer, $N ! La mort de Darkreaver devrait restaurer les liens fragiles qui ancrent le royaume des esprits.$B$BTu as largement dépassé ce qui t\'a été demandé, même sans avoir idée de récompense ou de compensation. Tu es vraiment un $c de valeur, mon ami.$B$BI sais que agir pour préserver le royaume des esprits devrait être un remerciement suffisant, mais s\'il te plaît - accepte ce simple cadeau avec mes remerciements.';
-- Quest 8260 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8260, 'frFR', 'Tu as certainement commencé à te prouver à nous, $N. En récompense, prends ce colis de soins ! À l\'intérieur, tu trouveras des rations et des bandages utilisables uniquement à Arathi Basin.$b$bEn continuant à te prouver à nous dans la Basin, tu découvriras que ces objets seront disponibles à l\'achat pour toi. Les rations deviennent disponibles lorsque tu es Amical avec nous, et les bandages lorsque tu es Honoré.') ON DUPLICATE KEY UPDATE RewardText='Tu as certainement commencé à te prouver à nous, $N. En récompense, prends ce colis de soins ! À l\'intérieur, tu trouveras des rations et des bandages utilisables uniquement à Arathi Basin.$b$bEn continuant à te prouver à nous dans la Basin, tu découvriras que ces objets seront disponibles à l\'achat pour toi. Les rations deviennent disponibles lorsque tu es Amical avec nous, et les bandages lorsque tu es Honoré.';
-- Quest 8261 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8261, 'frFR', 'Tu as certainement commencé à te prouver à nous, $N. En récompense, prends ce colis de soins ! À l\'intérieur, tu trouveras des rations et des bandages utilisables uniquement à Arathi Basin.$b$bEn continuant à te prouver à nous dans la Basin, tu découvriras que ces objets seront disponibles à l\'achat pour toi. Les rations deviennent disponibles lorsque tu es Amical avec nous, et les bandages lorsque tu es Honoré.') ON DUPLICATE KEY UPDATE RewardText='Tu as certainement commencé à te prouver à nous, $N. En récompense, prends ce colis de soins ! À l\'intérieur, tu trouveras des rations et des bandages utilisables uniquement à Arathi Basin.$b$bEn continuant à te prouver à nous dans la Basin, tu découvriras que ces objets seront disponibles à l\'achat pour toi. Les rations deviennent disponibles lorsque tu es Amical avec nous, et les bandages lorsque tu es Honoré.';
