-- Quest 8265 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8265, 'frFR', 'Tu as certainement commencé à te prouver à nous, $N. En récompense, prends ce colis de soins ! À l\'intérieur, tu trouveras des rations et des bandages utilisables uniquement à Arathi Basin.$b$bEn continuant à te prouver à nous dans la Basin, tu découvriras que ces objets seront disponibles à l\'achat pour toi. Les rations deviennent disponibles lorsque tu es Honoré avec nous, et les bandages lorsque tu es Vénéré.') ON DUPLICATE KEY UPDATE RewardText='Tu as certainement commencé à te prouver à nous, $N. En récompense, prends ce colis de soins ! À l\'intérieur, tu trouveras des rations et des bandages utilisables uniquement à Arathi Basin.$b$bEn continuant à te prouver à nous dans la Basin, tu découvriras que ces objets seront disponibles à l\'achat pour toi. Les rations deviennent disponibles lorsque tu es Honoré avec nous, et les bandages lorsque tu es Vénéré.';
-- Quest 8266 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8266, 'frFR', 'Tu n\'as pas fui face à la défaite. Tu as tenu bon, $N$, et quand tout compte, c\'est ce qui fait un vrai héros. Sans aucun doute tu gagneras la prochaine fois... mais néanmoins nous te remercions pour tes efforts.') ON DUPLICATE KEY UPDATE RewardText='Tu n\'as pas fui face à la défaite. Tu as tenu bon, $N$, et quand tout compte, c\'est ce qui fait un vrai héros. Sans aucun doute tu gagneras la prochaine fois... mais néanmoins nous te remercions pour tes efforts.';
-- Quest 8267 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8267, 'frFR', 'Tu n\'as pas fui face à la défaite. Tu as tenu bon, $N$, et quand tout compte, c\'est ce qui fait un vrai héros. Sans aucun doute tu gagneras la prochaine fois... mais néanmoins nous te remercions pour tes efforts.') ON DUPLICATE KEY UPDATE RewardText='Tu n\'as pas fui face à la défaite. Tu as tenu bon, $N$, et quand tout compte, c\'est ce qui fait un vrai héros. Sans aucun doute tu gagneras la prochaine fois... mais néanmoins nous te remercions pour tes efforts.';
