-- Quest 8269 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8269, 'frFR', 'Tu n\'as pas fui face à la défaite. Tu as tenu bon, $N$, et quand tout compte, c\'est ce qui fait un vrai héros. Sans aucun doute tu gagneras la prochaine fois... mais néanmoins nous te remercions pour tes efforts.') ON DUPLICATE KEY UPDATE RewardText='Tu n\'as pas fui face à la défaite. Tu as tenu bon, $N$, et quand tout compte, c\'est ce qui fait un vrai héros. Sans aucun doute tu gagneras la prochaine fois... mais néanmoins nous te remercions pour tes efforts.';
-- Quest 8270 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8270, 'frFR', 'Excellent ! Tu t\'es avéré être un allié précieux dans la préparation de la guerre contre les silithides.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Tu t\'es avéré être un allié précieux dans la préparation de la guerre contre les silithides.';

-- Quest 8271 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8271, 'frFR', 'En tant que héros de Stormpike, vous pouvez choisir un objet parmi ces trésors récemment... récupérés.') ON DUPLICATE KEY UPDATE RewardText='En tant que héros de Stormpike, vous pouvez choisir un objet parmi ces trésors récemment... récupérés.';
-- Quest 8272 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8272, 'frFR', 'Comment vous sentez-vous, $N? Comment vous sentez-vous de briser vos ennemis et de voir leurs rangs se désintégrer? C\'est bon, n\'est-ce pas?$b$bVous devriez être récompensé pour cet acte héroïque, soldat.') ON DUPLICATE KEY UPDATE RewardText='Comment vous sentez-vous, $N? Comment vous sentez-vous de briser vos ennemis et de voir leurs rangs se désintégrer? C\'est bon, n\'est-ce pas?$b$bVous devriez être récompensé pour cet acte héroïque, soldat.';
-- Quest 8273 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8273, 'frFR', 'N\'est-ce pas intéressant? Vous dites avoir trouvé cette tablette sur une petite île désertée aux Falaises du Regard dans Les Terres Sauvages, $c? Très intéressant en effet. <Oran range soigneusement la tablette et se frotte les mains.>$B$BI vous remercie pour vos efforts dans cette affaire. Notre Dame Sombre sera très satisfaite de cette découverte. Voici, permettez-moi de vous récompenser proportionnellement.') ON DUPLICATE KEY UPDATE RewardText='N\'est-ce pas intéressant? Vous dites avoir trouvé cette tablette sur une petite île désertée aux Falaises du Regard dans Les Terres Sauvages, $c? Très intéressant en effet. <Oran range soigneusement la tablette et se frotte les mains.>$B$BI vous remercie pour vos efforts dans cette affaire. Notre Dame Sombre sera très satisfaite de cette découverte. Voici, permettez-moi de vous récompenser proportionnellement.';
-- Quest 8274 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8274, 'frFR', 'Je vous suis sincèrement reconnaissant. Vos efforts pour aider Cenarion Hold ont montré un courage véritable.') ON DUPLICATE KEY UPDATE RewardText='Je vous suis sincèrement reconnaissant. Vos efforts pour aider Cenarion Hold ont montré un courage véritable.';
-- Quest 8280 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8280, 'frFR', 'Les briseurs de dragues sont une menace sérieuse et doivent être traités rapidement!') ON DUPLICATE KEY UPDATE CompletionText='Les briseurs de dragues sont une menace sérieuse et doivent être traités rapidement!';
-- Quest 8281 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8281, 'frFR', 'Les écraseurs de dragues sont une menace sérieuse et doivent être traités immédiatement!') ON DUPLICATE KEY UPDATE CompletionText='Les écraseurs de dragues sont une menace sérieuse et doivent être traités immédiatement!';
-- Quest 8292 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8292, 'frFR', 'Merci, $N. Vos exploits dans Warsong Gulch résonnent dans toute la Forêt d\'Ashenvale.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Vos exploits dans Warsong Gulch résonnent dans toute la Forêt d\'Ashenvale.';
-- Quest 8293 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8293, 'frFR', 'Les elfes de la nuit et leurs alliés doivent trembler au moindre murmure de votre nom! Pour la Horde!') ON DUPLICATE KEY UPDATE RewardText='Les elfes de la nuit et leurs alliés doivent trembler au moindre murmure de votre nom! Pour la Horde!';
-- Quest 8294 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8294, 'frFR', 'Le sang de nos ennemis est une marque d\'honneur. Avez-vous une telle marque?') ON DUPLICATE KEY UPDATE CompletionText='Le sang de nos ennemis est une marque d\'honneur. Avez-vous une telle marque?';
-- Quest 8294 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8294, 'frFR', '<Captain Shatterskull rugit de triomphe.>$B$BCombien plus peuvent-ils endurer? Combien de déchets de l\'Alliance doivent périr aux mains de la Horde pour qu\'ils reculent? Seul le temps le dira, $R.') ON DUPLICATE KEY UPDATE RewardText='<Captain Shatterskull rugit de triomphe.>$B$BCombien plus peuvent-ils endurer? Combien de déchets de l\'Alliance doivent périr aux mains de la Horde pour qu\'ils reculent? Seul le temps le dira, $R.';
-- Quest 8297 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8297, 'frFR', 'Avez-vous la caisse de ressources, $N? La Ligue d\'Arathor ne peut mener une bataille décente sans elles...') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous la caisse de ressources, $N? La Ligue d\'Arathor ne peut mener une bataille décente sans elles...';
-- Quest 8297 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8297, 'frFR', 'Vous avez les ressources! Bon travail! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que vous avez réalisée est ainsi que les guerres sont vraiment gagnées.') ON DUPLICATE KEY UPDATE RewardText='Vous avez les ressources! Bon travail! J\'enverrai les ressources à nos intendants, qui pourront les distribuer rapidement à nos troupes.$B$BMerci, $N. En effet, accomplir des missions réussies comme celle que vous avez réalisée est ainsi que les guerres sont vraiment gagnées.';
-- Quest 8298 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8298, 'frFR', '$N, la Ligue d\'Arathor a une mission en cours pour vous de rentrer dans le Bassin d\'Arathi, de vous procurer plus de caisses de ressources et de me les apporter.') ON DUPLICATE KEY UPDATE CompletionText='$N, la Ligue d\'Arathor a une mission en cours pour vous de rentrer dans le Bassin d\'Arathi, de vous procurer plus de caisses de ressources et de me les apporter.';
-- Quest 8298 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8298, 'frFR', 'Très bien. Je ferai parvenir ces éléments à nos intendants immédiatement, et une commendation pour vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par le soldat comme par le maréchal de camp.') ON DUPLICATE KEY UPDATE RewardText='Très bien. Je ferai parvenir ces éléments à nos intendants immédiatement, et une commendation pour vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par le soldat comme par le maréchal de camp.';
-- Quest 8300 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8300, 'frFR', '$N, les Défileurs ont une mission en cours pour vous de rentrer dans le Bassin d\'Arathi, de vous procurer plus de caisses de ressources et de me les apporter.') ON DUPLICATE KEY UPDATE CompletionText='$N, les Défileurs ont une mission en cours pour vous de rentrer dans le Bassin d\'Arathi, de vous procurer plus de caisses de ressources et de me les apporter.';

-- Quest 8300 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8300, 'frFR', '$B$BTrès bien. Je les remettrai immédiatement à nos intendants, et une commendation pour vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par les soldats et les grands warlords.') ON DUPLICATE KEY UPDATE RewardText='$B$BTrès bien. Je les remettrai immédiatement à nos intendants, et une commendation pour vos actions sera envoyée à mes supérieurs.$B$BEncore une fois, merci $N. Vos contributions à nos luttes sont remarquées par les soldats et les grands warlords.';
-- Quest 8303 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8303, 'frFR', 'Vous êtes l\'espoir de Kalimdor, $N.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes l\'espoir de Kalimdor, $N.';
-- Quest 8305 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8305, 'frFR', 'Vous pouvez sentir une grande tristesse qui entoure ce cristal. La force est si puissante que vous avez l\'impression de pouvoir vous effondrer et mourir de tristesse.') ON DUPLICATE KEY UPDATE RewardText='Vous pouvez sentir une grande tristesse qui entoure ce cristal. La force est si puissante que vous avez l\'impression de pouvoir vous effondrer et mourir de tristesse.';
-- Quest 8311 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8311, 'frFR', 'As-tu fini de faire des tours de citrouille ? Je suis triste de ne pas pouvoir y aller parce que je suis malade, mais toi qui m\'aides me fait me sentir un peu mieux...') ON DUPLICATE KEY UPDATE CompletionText='As-tu fini de faire des tours de citrouille ? Je suis triste de ne pas pouvoir y aller parce que je suis malade, mais toi qui m\'aides me fait me sentir un peu mieux...';
-- Quest 8311 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8311, 'frFR', 'Waouh, tu les as tous ! Tu es génial !$B$BMerci d\'avoir fait des tours de citrouille pour moi. Tiens, prends ces friandises de citrouille - je pense que tu vas beaucoup les aimer !$B$BJoyeux Hallow\'s End, $N!') ON DUPLICATE KEY UPDATE RewardText='Waouh, tu les as tous ! Tu es génial !$B$BMerci d\'avoir fait des tours de citrouille pour moi. Tiens, prends ces friandises de citrouille - je pense que tu vas beaucoup les aimer !$B$BJoyeux Hallow\'s End, $N!';
-- Quest 8312 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8312, 'frFR', 'As-tu fini de faire des tours de citrouille ? Je suis triste de ne pas pouvoir y aller parce que je suis malade, mais toi qui m\'aides me fait me sentir un peu mieux...') ON DUPLICATE KEY UPDATE CompletionText='As-tu fini de faire des tours de citrouille ? Je suis triste de ne pas pouvoir y aller parce que je suis malade, mais toi qui m\'aides me fait me sentir un peu mieux...';
-- Quest 8312 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8312, 'frFR', 'Waouh, tu les as tous ! Tu es génial !$B$BMerci d\'avoir fait des tours de citrouille pour moi. Tiens, prends ces friandises de citrouille - je pense que tu vas beaucoup les aimer !$B$BJoyeux Hallow\'s End, $N!') ON DUPLICATE KEY UPDATE RewardText='Waouh, tu les as tous ! Tu es génial !$B$BMerci d\'avoir fait des tours de citrouille pour moi. Tiens, prends ces friandises de citrouille - je pense que tu vas beaucoup les aimer !$B$BJoyeux Hallow\'s End, $N!';
-- Quest 8314 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8314, 'frFR', 'Oh là là ! Qu\'est-ce que tu as là, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Oh là là ! Qu\'est-ce que tu as là, $N ?';
-- Quest 8315 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8315, 'frFR', 'Tu dois saisir l\'opportunité lorsqu\'elle se présente et frapper !') ON DUPLICATE KEY UPDATE CompletionText='Tu dois saisir l\'opportunité lorsqu\'elle se présente et frapper !';
-- Quest 8315 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8315, 'frFR', 'Je tiens 20 000 ans d\'histoire dans mes mains, <name> !') ON DUPLICATE KEY UPDATE RewardText='Je tiens 20 000 ans d\'histoire dans mes mains, <name> !';
-- Quest 8316 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8316, 'frFR', 'La guerre arrive, $N, et avec elle viennent des horreurs innombrables. Tu as fait tout ce qui pouvait t\'être demandé et pour cela, tu devrais être récompensé.$B$BSi cette... cette prophétie devait se réaliser...$B$B<Geologist Larksbane pâlit.>$B$BL\'avenir de nous tous pourrait être en péril.$B$BCes armements seront inestimables pour ta campagne dans ce désert.') ON DUPLICATE KEY UPDATE RewardText='La guerre arrive, $N, et avec elle viennent des horreurs innombrables. Tu as fait tout ce qui pouvait t\'être demandé et pour cela, tu devrais être récompensé.$B$BSi cette... cette prophétie devait se réaliser...$B$B<Geologist Larksbane pâlit.>$B$BL\'avenir de nous tous pourrait être en péril.$B$BCes armements seront inestimables pour ta campagne dans ce désert.';
-- Quest 8319 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8319, 'frFR', 'Continue de m\'apporter des textes. Nous allons bientôt forcer le Marteau du Crépuscule hors de Silithus.') ON DUPLICATE KEY UPDATE CompletionText='Continue de m\'apporter des textes. Nous allons bientôt forcer le Marteau du Crépuscule hors de Silithus.';
-- Quest 8320 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8320, 'frFR', 'Entre dans le désert et trouve les géolords du crépuscule, $N. Reviens-moi après qu\'ils aient été abattus.') ON DUPLICATE KEY UPDATE CompletionText='Entre dans le désert et trouve les géolords du crépuscule, $N. Reviens-moi après qu\'ils aient été abattus.';
-- Quest 8324 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8324, 'frFR', 'Tu trouves d\'autres textes cryptés ? Apporte-m\'en un bon lot, ce travail de décryptage prend du temps.') ON DUPLICATE KEY UPDATE CompletionText='Tu trouves d\'autres textes cryptés ? Apporte-m\'en un bon lot, ce travail de décryptage prend du temps.';
-- Quest 8325 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8325, 'frFR', 'Notre travail de reconstruction de notre société commence ici, $N. Une fois que nous serons capables de sécuriser notre foyer, nous pourrons regarder vers l\'extérieur et vers le haut.') ON DUPLICATE KEY UPDATE CompletionText='Notre travail de reconstruction de notre société commence ici, $N. Une fois que nous serons capables de sécuriser notre foyer, nous pourrons regarder vers l\'extérieur et vers le haut.';

-- Quest 8329 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8329, 'frFR', 'Bienvenue à Sunspire, jeune <class>!  La maîtrise des armes et des tactiques de combat commence ici et maintenant - tout ce que j\'exige de mes élèves, c\'est qu\'ils couvrent les frais de formation qui pourraient survenir, et qu\'ils soient aussi bons auditeurs qu\'ils sont aspirants <class>.  Les leçons que j\'ai à enseigner sont vastes, et je n\'aime pas me répéter inutilement.$B$BCommençons donc !') ON DUPLICATE KEY UPDATE RewardText='Bienvenue à Sunspire, jeune <class>!  La maîtrise des armes et des tactiques de combat commence ici et maintenant - tout ce que j\'exige de mes élèves, c\'est qu\'ils couvrent les frais de formation qui pourraient survenir, et qu\'ils soient aussi bons auditeurs qu\'ils sont aspirants <class>.  Les leçons que j\'ai à enseigner sont vastes, et je n\'aime pas me répéter inutilement.$B$BCommençons donc !';
-- Quest 8333 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8333, 'frFR', 'Si vous avez besoin d\'un autre médaillon de station de cultiste de la Crépuscule, je suis heureux de vous satisfaire. Je devrai cependant avoir un autre éclat brillant et quelques crests abyssales...') ON DUPLICATE KEY UPDATE CompletionText='Si vous avez besoin d\'un autre médaillon de station de cultiste de la Crépuscule, je suis heureux de vous satisfaire. Je devrai cependant avoir un autre éclat brillant et quelques crests abyssales...';
-- Quest 8334 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8334, 'frFR', 'Il est préférable que vous appreniez à survivre - et aux coûts de la survie - maintenant plutôt que plus tard. Prendre des décisions difficiles est quelque chose auquel vous allez devoir vous habituer en tant que halfelin.$B$BPersonne n\'était là pour nous lorsque la Scourge a déchiré notre foyer en deux. C\'est nous et nous seuls qui nous sommes tirés d\'affaire.') ON DUPLICATE KEY UPDATE CompletionText='Il est préférable que vous appreniez à survivre - et aux coûts de la survie - maintenant plutôt que plus tard. Prendre des décisions difficiles est quelque chose auquel vous allez devoir vous habituer en tant que halfelin.$B$BPersonne n\'était là pour nous lorsque la Scourge a déchiré notre foyer en deux. C\'est nous et nous seuls qui nous sommes tirés d\'affaire.';
-- Quest 8341 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8341, 'frFR', 'Avez-vous les éclats et les signets, $N? J\'en aurai besoin pour créer le anneau de seigneurie.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les éclats et les signets, $N? J\'en aurai besoin pour créer le anneau de seigneurie.';
-- Quest 8341 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8341, 'frFR', 'Merci.  Juste un instant et j\'aurai ce anneau prêt pour vous...$B$BLe voici.  Maintenant, vous êtes prêt.$B$BAssurez-vous de porter ce anneau, ainsi qu\'un médaillon de station et le reste des parures de la Crépuscule, lorsque vous activez une pierre d\'air supérieure.  Faites cela, et le Conseil Abyssal vous prendra pour l\'un de ses serviteurs.  Alors, peut-être pourrez-vous en attirer un dans un embuscade !') ON DUPLICATE KEY UPDATE RewardText='Merci.  Juste un instant et j\'aurai ce anneau prêt pour vous...$B$BLe voici.  Maintenant, vous êtes prêt.$B$BAssurez-vous de porter ce anneau, ainsi qu\'un médaillon de station et le reste des parures de la Crépuscule, lorsque vous activez une pierre d\'air supérieure.  Faites cela, et le Conseil Abyssal vous prendra pour l\'un de ses serviteurs.  Alors, peut-être pourrez-vous en attirer un dans un embuscade !';
-- Quest 8342 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8342, 'frFR', '$N, si vous prévoyez de poursuivre le Haut Conseil Abyssal à nouveau, vous aurez besoin d\'un autre anneau de seigneurie de la Crépuscule. Apportez-moi plus d\'éclats et de signets et je vous en ferai un.') ON DUPLICATE KEY UPDATE CompletionText='$N, si vous prévoyez de poursuivre le Haut Conseil Abyssal à nouveau, vous aurez besoin d\'un autre anneau de seigneurie de la Crépuscule. Apportez-moi plus d\'éclats et de signets et je vous en ferai un.';
-- Quest 8342 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8342, 'frFR', 'Ah, je vois que vos convictions sont fortes.  Peu de gens affronteront ce conseil de démons !$B$BVoici votre anneau, <name>.  Que votre volonté, et votre fortune, soient fermes.') ON DUPLICATE KEY UPDATE RewardText='Ah, je vois que vos convictions sont fortes.  Peu de gens affronteront ce conseil de démons !$B$BVoici votre anneau, <name>.  Que votre volonté, et votre fortune, soient fermes.';
-- Quest 8344 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8344, 'frFR', 'Les essences des spectres me serviront bien comme sources d\'expérimentation. Tout comme votre vie en tant que $c, il est important d\'apprendre de ce que nous trouvons dans le monde... avant de le tordre à notre volonté. Avec les démons comme source la plus riche de pouvoir, ce sera un grand avantage si une telle souillure est vraiment présente sur l\'île.$B$BEh bien... un avantage pour nous, les sorciers.') ON DUPLICATE KEY UPDATE CompletionText='Les essences des spectres me serviront bien comme sources d\'expérimentation. Tout comme votre vie en tant que $c, il est important d\'apprendre de ce que nous trouvons dans le monde... avant de le tordre à notre volonté. Avec les démons comme source la plus riche de pouvoir, ce sera un grand avantage si une telle souillure est vraiment présente sur l\'île.$B$BEh bien... un avantage pour nous, les sorciers.';
-- Quest 8344 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8344, 'frFR', 'Bien fait ! Oui, cette essence devrait être suffisante pour commencer mes recherches. J\'ai fort le sentiment que cette essence souillée sera exactement ce qu\'il faut... la fenêtre, comme je l\'ai mentionné.$B$BIl est fortement recommandé de suivre les ordres de vos maîtres en tant que jeune $c. Comme je vous l\'ai promis, voici la récompense pour avoir obéi aux instructions et les avoir accomplies de manière compétente - la connaissance pour invoquer et lier votre propre imp.$B$Utilise-le bien, $N$') ON DUPLICATE KEY UPDATE RewardText='Bien fait ! Oui, cette essence devrait être suffisante pour commencer mes recherches. J\'ai fort le sentiment que cette essence souillée sera exactement ce qu\'il faut... la fenêtre, comme je l\'ai mentionné.$B$BIl est fortement recommandé de suivre les ordres de vos maîtres en tant que jeune $c. Comme je vous l\'ai promis, voici la récompense pour avoir obéi aux instructions et les avoir accomplies de manière compétente - la connaissance pour invoquer et lier votre propre imp.$B$Utilise-le bien, $N$';
-- Quest 8345 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8345, 'frFR', 'Avez-vous lu la plaque sur le sanctuaire, $c?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous lu la plaque sur le sanctuaire, $c?';
-- Quest 8346 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8346, 'frFR', 'Ah $N. Avez-vous terminé votre tâche ?') ON DUPLICATE KEY UPDATE CompletionText='Ah $N. Avez-vous terminé votre tâche ?';
-- Quest 8347 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8347, 'frFR', 'Bonjour, <class>!  J\'ai entendu dire qu\'un jeune $R ingénieux, anciennement au service de Magistrix Erona, pourrait faire le chemin ici pour nous aider, les Sorteurs.  Nous accueillons certainement l\'aide, surtout de quelqu\'un qui s\'est montré si compétent.$B$J\'espère que vous êtes intéressé à faire une ou deux courses pour nous.') ON DUPLICATE KEY UPDATE RewardText='Bonjour, <class>!  J\'ai entendu dire qu\'un jeune $R ingénieux, anciennement au service de Magistrix Erona, pourrait faire le chemin ici pour nous aider, les Sorteurs.  Nous accueillons certainement l\'aide, surtout de quelqu\'un qui s\'est montré si compétent.$B$J\'espère que vous êtes intéressé à faire une ou deux courses pour nous.';
-- Quest 8349 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8349, 'frFR', 'Ravi de vous revoir, <class>!  Alors, vous avez fait faire un médaillon ?  Bien -- vous en aurez besoin pour votre prochaine quête...') ON DUPLICATE KEY UPDATE RewardText='Ravi de vous revoir, <class>!  Alors, vous avez fait faire un médaillon ?  Bien -- vous en aurez besoin pour votre prochaine quête...';
-- Quest 8351 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8351, 'frFR', 'Oui, c\'est ça, $N. J\'ai une tâche très difficile devant moi...') ON DUPLICATE KEY UPDATE RewardText='Oui, c\'est ça, $N. J\'ai une tâche très difficile devant moi...';
-- Quest 8352 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8352, 'frFR', 'Eh bien, comment s\'est-ce passé ? Je ferais n\'importe quoi pour quitter mon poste et affronter moi-même l\'une de ces choses !') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, comment s\'est-ce passé ? Je ferais n\'importe quoi pour quitter mon poste et affronter moi-même l\'une de ces choses !';

-- Quest 8352 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8352, 'frFR', 'Tu... tu l\'as fait !  Tu l\'as fait, <name> !  Tiens !  Prends ça.  C\'est le plus gros coffre que nous avions trouvé et je l\'ai rempli avec certains des meilleurs objets que nous avons trouvés.') ON DUPLICATE KEY UPDATE RewardText='Tu... tu l\'as fait !  Tu l\'as fait, <name> !  Tiens !  Prends ça.  C\'est le plus gros coffre que nous avions trouvé et je l\'ai rempli avec certains des meilleurs objets que nous avons trouvés.';
-- Quest 8356 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8356, 'frFR', 'Pas de bonbons tant que tu ne feras pas de flex pour moi, $N...') ON DUPLICATE KEY UPDATE CompletionText='Pas de bonbons tant que tu ne feras pas de flex pour moi, $N...';
-- Quest 8357 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8357, 'frFR', 'Tu sais danser, n\'est-ce pas ? Essaie en mettant ton pied droit en... puis ton pied droit dehors... ton pied droit en... bouge tout ça...') ON DUPLICATE KEY UPDATE CompletionText='Tu sais danser, n\'est-ce pas ? Essaie en mettant ton pied droit en... puis ton pied droit dehors... ton pied droit en... bouge tout ça...';
-- Quest 8357 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8357, 'frFR', 'Tu es une vraie machine à danser, <name> !$B$BVoici ta récompense pour avoir été un si bon sportif.  Joyeux Hallow\'s End, et donne mes meilleurs vœux à ton petit ami malade !  J\'espère qu\'il ira mieux bientôt.') ON DUPLICATE KEY UPDATE RewardText='Tu es une vraie machine à danser, <name> !$B$BVoici ta récompense pour avoir été un si bon sportif.  Joyeux Hallow\'s End, et donne mes meilleurs vœux à ton petit ami malade !  J\'espère qu\'il ira mieux bientôt.';
-- Quest 8359 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8359, 'frFR', 'Pas de bonbons tant que tu ne feras pas de flex pour moi, $N...') ON DUPLICATE KEY UPDATE CompletionText='Pas de bonbons tant que tu ne feras pas de flex pour moi, $N...';
-- Quest 8360 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8360, 'frFR', 'Tu sais danser, n\'est-ce pas ? Essaie en mettant ton pied droit en... puis ton pied droit dehors... ton pied droit en... bouge tout ça...') ON DUPLICATE KEY UPDATE CompletionText='Tu sais danser, n\'est-ce pas ? Essaie en mettant ton pied droit en... puis ton pied droit dehors... ton pied droit en... bouge tout ça...';
-- Quest 8362 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8362, 'frFR', 'Tu as prouvé que tu pouvais te débrouiller dans un combat, $N. Continuons à mettre la pression sur le Marteau du Crépuscule. Va combattre d\'autres Templiers Abyssales, je te récompenserai avec certains des objets que Huum et moi avons trouvés au combat.') ON DUPLICATE KEY UPDATE CompletionText='Tu as prouvé que tu pouvais te débrouiller dans un combat, $N. Continuons à mettre la pression sur le Marteau du Crépuscule. Va combattre d\'autres Templiers Abyssales, je te récompenserai avec certains des objets que Huum et moi avons trouvés au combat.';
-- Quest 8362 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8362, 'frFR', 'Tu as bien fait !  C\'est moins de Templiers pour que je m\'inquiète.$B$BVoici, <name>.  J\'espère qu\'il y a quelque chose d\'utile dedans pour toi.') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait !  C\'est moins de Templiers pour que je m\'inquiète.$B$BVoici, <name>.  J\'espère qu\'il y a quelque chose d\'utile dedans pour toi.';
-- Quest 8363 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8363, 'frFR', 'Tu as montré que tu étais plus que capable d\'affronter un Duc Abyssal, $N. Je suis toujours enclin à promouvoir de bonnes habitudes. Apporte-moi plus de sceaux et je te donnerai une récompense.') ON DUPLICATE KEY UPDATE CompletionText='Tu as montré que tu étais plus que capable d\'affronter un Duc Abyssal, $N. Je suis toujours enclin à promouvoir de bonnes habitudes. Apporte-moi plus de sceaux et je te donnerai une récompense.';
-- Quest 8363 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8363, 'frFR', 'Excellent, $N !  Vaincre ces Ducs laissera le Marteau du Crépuscule en état de choc pendant un moment. Comme promis, voici ta récompense. Ce sont certains des meilleurs objets que Huum et moi avons trouvés.') ON DUPLICATE KEY UPDATE RewardText='Excellent, $N !  Vaincre ces Ducs laissera le Marteau du Crépuscule en état de choc pendant un moment. Comme promis, voici ta récompense. Ce sont certains des meilleurs objets que Huum et moi avons trouvés.';
-- Quest 8364 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8364, 'frFR', 'Tu as vraiment dépassé toutes mes attentes, $N. Tu as affronté des adversaires que Huum et moi envisagerions longuement avant de nous engager.$B$BÀ ce stade, le mieux que je puisse faire est de continuer à récompenser tes efforts dans le combat contre le Marteau du Crépuscule et ses maîtres.$B$BApporte-moi plus de sceptres abyssaux et je ferai de mon mieux pour te donner une récompense appropriée.') ON DUPLICATE KEY UPDATE CompletionText='Tu as vraiment dépassé toutes mes attentes, $N. Tu as affronté des adversaires que Huum et moi envisagerions longuement avant de nous engager.$B$BÀ ce stade, le mieux que je puisse faire est de continuer à récompenser tes efforts dans le combat contre le Marteau du Crépuscule et ses maîtres.$B$BApporte-moi plus de sceptres abyssaux et je ferai de mon mieux pour te donner une récompense appropriée.';

-- Quest 8364 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8364, 'frFR', 'Je savais que tu tiendrais ta promesse, $N! Voici ta récompense.') ON DUPLICATE KEY UPDATE RewardText='Je savais que tu tiendrais ta promesse, $N! Voici ta récompense.';
-- Quest 8366 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8366, 'frFR', 'De retour si vite ? J\'espère que tu as donné une leçon à ces voyous de Southsea qu\'ils n\'oublieront pas de sitôt.') ON DUPLICATE KEY UPDATE CompletionText='De retour si vite ? J\'espère que tu as donné une leçon à ces voyous de Southsea qu\'ils n\'oublieront pas de sitôt.';
-- Quest 8368 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8368, 'frFR', 'La bataille dans Warsong Gulch contre les Sentinelles de Silverwing est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laisse pas cela arriver, $N! Reviens-moi avec la preuve que tu as servi la Horde d\'une manière digne!') ON DUPLICATE KEY UPDATE CompletionText='La bataille dans Warsong Gulch contre les Sentinelles de Silverwing est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laisse pas cela arriver, $N! Reviens-moi avec la preuve que tu as servi la Horde d\'une manière digne!';
-- Quest 8368 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8368, 'frFR', 'Excellent! Tu as prouvé ta valeur en défendant nos opérations à Warsong Gulch! Que la nouvelle de ton honneur se propage loin dans nos terres.') ON DUPLICATE KEY UPDATE RewardText='Excellent! Tu as prouvé ta valeur en défendant nos opérations à Warsong Gulch! Que la nouvelle de ton honneur se propage loin dans nos terres.';
-- Quest 8369 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8369, 'frFR', 'Quelles nouvelles apportes-tu des terres des Frostwolves? Comment se déroule la bataille pour Alterac Valley?') ON DUPLICATE KEY UPDATE CompletionText='Quelles nouvelles apportes-tu des terres des Frostwolves? Comment se déroule la bataille pour Alterac Valley?';
-- Quest 8369 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8369, 'frFR', 'Tu as fait preuve d\'un grand courage en protégeant nos terres à Alterac Valley! Je raconterai tes exploits à mes supérieurs.') ON DUPLICATE KEY UPDATE RewardText='Tu as fait preuve d\'un grand courage en protégeant nos terres à Alterac Valley! Je raconterai tes exploits à mes supérieurs.';
-- Quest 8375 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8375, 'frFR', 'Quelles nouvelles apportes-tu des terres des Stormpikes? Comment se déroule la bataille pour Alterac Valley?') ON DUPLICATE KEY UPDATE CompletionText='Quelles nouvelles apportes-tu des terres des Stormpikes? Comment se déroule la bataille pour Alterac Valley?';
-- Quest 8375 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8375, 'frFR', 'Tu as fait preuve d\'un grand courage en protégeant nos terres à Alterac Valley! Je raconterai tes exploits à mes supérieurs.') ON DUPLICATE KEY UPDATE RewardText='Tu as fait preuve d\'un grand courage en protégeant nos terres à Alterac Valley! Je raconterai tes exploits à mes supérieurs.';
-- Quest 8376 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8376, 'frFR', 'La guerre arrive, $N, et avec elle viennent des horreurs innombrables. Tu as fait tout ce qui pouvait t\'être demandé et pour cela, tu devrais être récompensé.$B$BSi cette... cette prophétie devait se réaliser...$B$B<Geologist Larksbane pâlit.>$B$BL\'avenir de nous tous pourrait être en péril.$B$BCes armements seront d\'un grand secours pour ta campagne dans ce désert.') ON DUPLICATE KEY UPDATE RewardText='La guerre arrive, $N, et avec elle viennent des horreurs innombrables. Tu as fait tout ce qui pouvait t\'être demandé et pour cela, tu devrais être récompensé.$B$BSi cette... cette prophétie devait se réaliser...$B$B<Geologist Larksbane pâlit.>$B$BL\'avenir de nous tous pourrait être en péril.$B$BCes armements seront d\'un grand secours pour ta campagne dans ce désert.';
