-- Quest 8382 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8382, 'frFR', 'La guerre arrive, $N, et avec elle viennent des horreurs indicibles. Vous avez fait tout ce qui pouvait vous être demandé et pour cela, vous devriez être récompensé.$B$BSi cette... cette prophétie devait se réaliser...$B$B<Geologist Larksbane pâlit.>$B$BL\'avenir de nous tous pourrait être en péril.$B$BCes armements seront inestimables pour votre campagne dans ce désert.') ON DUPLICATE KEY UPDATE RewardText='La guerre arrive, $N, et avec elle viennent des horreurs indicibles. Vous avez fait tout ce qui pouvait vous être demandé et pour cela, vous devriez être récompensé.$B$BSi cette... cette prophétie devait se réaliser...$B$B<Geologist Larksbane pâlit.>$B$BL\'avenir de nous tous pourrait être en péril.$B$BCes armements seront inestimables pour votre campagne dans ce désert.';
-- Quest 8383 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8383, 'frFR', 'Vous continuez d\'honorer l\'Alliance, $N. La Horde sera écrasée d\'ici peu si nous maintenons nos efforts.') ON DUPLICATE KEY UPDATE RewardText='Vous continuez d\'honorer l\'Alliance, $N. La Horde sera écrasée d\'ici peu si nous maintenons nos efforts.';
-- Quest 8385 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8385, 'frFR', 'Ah, $N. J\'espère que vous continuerez à apporter votre expérience aux différents fronts de bataille. Beaucoup de nos gars et nos filles sur le terrain admirent les vétérans chevronnés comme vous.') ON DUPLICATE KEY UPDATE CompletionText='Ah, $N. J\'espère que vous continuerez à apporter votre expérience aux différents fronts de bataille. Beaucoup de nos gars et nos filles sur le terrain admirent les vétérans chevronnés comme vous.';
-- Quest 8385 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8385, 'frFR', 'Vous êtes à la hauteur de votre réputation, $N. Sans des gens comme vous, l\'Alliance n\'aurait aucune chance contre les forces sauvages de la Horde.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes à la hauteur de votre réputation, $N. Sans des gens comme vous, l\'Alliance n\'aurait aucune chance contre les forces sauvages de la Horde.';
-- Quest 8386 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8386, 'frFR', 'Avez-vous des nouvelles de Warsong Gulch, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous des nouvelles de Warsong Gulch, $N?';
-- Quest 8386 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8386, 'frFR', 'Excellent ! Vous avez prouvé votre valeur en défendant nos opérations à Warsong Gulch ! Que la nouvelle de votre honneur se propage loin et large dans nos terres.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Vous avez prouvé votre valeur en défendant nos opérations à Warsong Gulch ! Que la nouvelle de votre honneur se propage loin et large dans nos terres.';
-- Quest 8387 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8387, 'frFR', 'Quelles nouvelles apportez-vous des terres des Loups-de-Givre ? Comment se déroule la bataille pour la Vallée d\'Alterac ?') ON DUPLICATE KEY UPDATE CompletionText='Quelles nouvelles apportez-vous des terres des Loups-de-Givre ? Comment se déroule la bataille pour la Vallée d\'Alterac ?';
-- Quest 8387 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8387, 'frFR', 'Bon travail, $N! Vous devriez être fier de vous. Les envahisseurs de l\'Alliance doivent être expulsés d\'Alterac !') ON DUPLICATE KEY UPDATE RewardText='Bon travail, $N! Vous devriez être fier de vous. Les envahisseurs de l\'Alliance doivent être expulsés d\'Alterac !';
-- Quest 8388 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8388, 'frFR', 'Arathi est encore imbibée du sang de grands guerriers et le clash d\'acier résonne encore dans toute la Vallée d\'Alterac. Ne me faites pas perdre mon temps à moins que vous n\'apportiez des nouvelles du front !') ON DUPLICATE KEY UPDATE CompletionText='Arathi est encore imbibée du sang de grands guerriers et le clash d\'acier résonne encore dans toute la Vallée d\'Alterac. Ne me faites pas perdre mon temps à moins que vous n\'apportiez des nouvelles du front !';
-- Quest 8388 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8388, 'frFR', 'Vous continuez d\'honorer la Horde, $N. Je suis heureux de voir que vous n\'êtes pas devenu mou.') ON DUPLICATE KEY UPDATE RewardText='Vous continuez d\'honorer la Horde, $N. Je suis heureux de voir que vous n\'êtes pas devenu mou.';
-- Quest 8389 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8389, 'frFR', 'La bataille à Warsong Gulch contre les Sentinelles de l\'Aile d\'Argent est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laissez pas cela arriver, $N! Revenez-moi avec la preuve d\'avoir servi la Horde d\'une manière digne !') ON DUPLICATE KEY UPDATE CompletionText='La bataille à Warsong Gulch contre les Sentinelles de l\'Aile d\'Argent est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laissez pas cela arriver, $N! Revenez-moi avec la preuve d\'avoir servi la Horde d\'une manière digne !';
-- Quest 8389 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8389, 'frFR', 'Excellent ! Vous avez prouvé votre valeur en défendant nos opérations à Warsong Gulch ! Que la nouvelle de votre honneur se propage loin et large dans nos terres.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Vous avez prouvé votre valeur en défendant nos opérations à Warsong Gulch ! Que la nouvelle de votre honneur se propage loin et large dans nos terres.';
-- Quest 8401 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8401, 'frFR', 'Bien joué, $N! Vous avez bien servi l\'Alliance.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N! Vous avez bien servi l\'Alliance.';
-- Quest 8411 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8411, 'frFR', 'Ce sont les éléments dont j\'ai besoin. Maintenant, on parle.') ON DUPLICATE KEY UPDATE RewardText='Ce sont les éléments dont j\'ai besoin. Maintenant, on parle.';
-- Quest 8413 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8413, 'frFR', 'Il est temps que ce troll fasse une nuit de repos ! Le totem spirituel veillera sur moi.$B$BÇa fait longtemps que je ramasse des trucs, peut-être veux-tu quelque chose pour tous tes ennuis ?') ON DUPLICATE KEY UPDATE RewardText='Il est temps que ce troll fasse une nuit de repos ! Le totem spirituel veillera sur moi.$B$BÇa fait longtemps que je ramasse des trucs, peut-être veux-tu quelque chose pour tous tes ennuis ?';

-- Quest 8414 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8414, 'frFR', 'Quel mal m\'as-tu apporté ?') ON DUPLICATE KEY UPDATE CompletionText='Quel mal m\'as-tu apporté ?';
-- Quest 8414 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8414, 'frFR', 'Il y a un risque à bannir le mal d\'une pierre de scourgest, car cela attire l\'attention des morts-vivants sur d\'innombrables miles. Mais tu es fort dans la Lumière, $N$, et je ne crains rien pour toi...') ON DUPLICATE KEY UPDATE RewardText='Il y a un risque à bannir le mal d\'une pierre de scourgest, car cela attire l\'attention des morts-vivants sur d\'innombrables miles. Mais tu es fort dans la Lumière, $N$, et je ne crains rien pour toi...';
-- Quest 8415 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8415, 'frFR', 'Très bien, $c$! Voyons ce que tu vaux.') ON DUPLICATE KEY UPDATE RewardText='Très bien, $c$! Voyons ce que tu vaux.';
-- Quest 8416 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8416, 'frFR', 'Thal\'danis a réussi à purifier les pierres de scourgest ?') ON DUPLICATE KEY UPDATE CompletionText='Thal\'danis a réussi à purifier les pierres de scourgest ?';
-- Quest 8416 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8416, 'frFR', 'Tu as fait ce que j\'ai demandé sans question, $N.$b$bLa confiance est acquise, semble-t-il. Peut-être puis-je te révéler notre plan plus en détail maintenant.') ON DUPLICATE KEY UPDATE RewardText='Tu as fait ce que j\'ai demandé sans question, $N.$b$bLa confiance est acquise, semble-t-il. Peut-être puis-je te révéler notre plan plus en détail maintenant.';
-- Quest 8418 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8418, 'frFR', 'C\'est excellent, $N.$ Je dirais que je suis surpris, mais je savais sans aucun doute que tu ne nous décevrais pas.$B$BC\'est un honneur pour moi de t\'octroyer l\'une des Pierres de Puissance Sacrée. Utilise-la bien.') ON DUPLICATE KEY UPDATE RewardText='C\'est excellent, $N.$ Je dirais que je suis surpris, mais je savais sans aucun doute que tu ne nous décevrais pas.$B$BC\'est un honneur pour moi de t\'octroyer l\'une des Pierres de Puissance Sacrée. Utilise-la bien.';
-- Quest 8419 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8419, 'frFR', 'Quelle $c$ splendide tu es!$B$B<Impsy tient le tissu de fel sur son visage.>$B$Oh comme j\'aime la sensation, la façon dont il brûle ta peau et tisse des pensées maléfiques dans l\'esprit...') ON DUPLICATE KEY UPDATE RewardText='Quelle $c$ splendide tu es!$B$B<Impsy tient le tissu de fel sur son visage.>$B$Oh comme j\'aime la sensation, la façon dont il brûle ta peau et tisse des pensées maléfiques dans l\'esprit...';
-- Quest 8420 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8420, 'frFR', 'Waouh! Tu es trop gentil. Surtout pour un $c!$B$B<Impsy tient le tissu de fel sur son visage.>$B$Oh comme j\'aime la sensation, la façon dont il brûle ta peau et tisse des pensées maléfiques dans l\'esprit...') ON DUPLICATE KEY UPDATE RewardText='Waouh! Tu es trop gentil. Surtout pour un $c!$B$B<Impsy tient le tissu de fel sur son visage.>$B$Oh comme j\'aime la sensation, la façon dont il brûle ta peau et tisse des pensées maléfiques dans l\'esprit...';
-- Quest 8422 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8422, 'frFR', 'Tu as apporté les plumes ? Cette poupée a besoin d\'être rembourrée !') ON DUPLICATE KEY UPDATE CompletionText='Tu as apporté les plumes ? Cette poupée a besoin d\'être rembourrée !';
-- Quest 8422 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8422, 'frFR', 'Merveilleux, maintenant ma bête de compagnie est complète!$B$B<Impsy rembourre rapidement la poupée et lui donne un câlin démoniaque.>$B$Oh, quel effet secondaire étrange ces plumes de voodoo ont...') ON DUPLICATE KEY UPDATE RewardText='Merveilleux, maintenant ma bête de compagnie est complète!$B$B<Impsy rembourre rapidement la poupée et lui donne un câlin démoniaque.>$B$Oh, quel effet secondaire étrange ces plumes de voodoo ont...';
-- Quest 8424 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8424, 'frFR', 'Les vœux de l\'ombre ne sont pas facilement vaincus, n\'est-ce pas ? Mais tu es un guerrier, et tu triompheras ou périras en essayant.') ON DUPLICATE KEY UPDATE CompletionText='Les vœux de l\'ombre ne sont pas facilement vaincus, n\'est-ce pas ? Mais tu es un guerrier, et tu triompheras ou périras en essayant.';
-- Quest 8424 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8424, 'frFR', 'Tu as déjà apaisé ma douleur et m\'as honoré. Merci, $c.') ON DUPLICATE KEY UPDATE RewardText='Tu as déjà apaisé ma douleur et m\'as honoré. Merci, $c.';
-- Quest 8425 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8425, 'frFR', 'Tu es revenu si vite ? Le temps n\'est plus le même pour moi, peut-être que c\'est en effet un long voyage pour toi...') ON DUPLICATE KEY UPDATE CompletionText='Tu es revenu si vite ? Le temps n\'est plus le même pour moi, peut-être que c\'est en effet un long voyage pour toi...';
-- Quest 8425 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8425, 'frFR', 'Je peux sentir à nouveau le froid du métal, même si ce n\'est que pour un instant.') ON DUPLICATE KEY UPDATE RewardText='Je peux sentir à nouveau le froid du métal, même si ce n\'est que pour un instant.';
-- Quest 8426 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8426, 'frFR', 'La bataille dans Warsong Gulch contre les Sentinelles Ailes d\'Argent est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laisse pas cela arriver, $N! Reviens-moi avec la preuve d\'avoir servi la Horde d\'une manière digne !') ON DUPLICATE KEY UPDATE CompletionText='La bataille dans Warsong Gulch contre les Sentinelles Ailes d\'Argent est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laisse pas cela arriver, $N! Reviens-moi avec la preuve d\'avoir servi la Horde d\'une manière digne !';

-- Quest 8434 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8434, 'frFR', 'La bataille à Warsong Gulch contre les Sentinelles de Silverwing est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laissez pas cela arriver, $N! Revenez-moi avec une preuve d\'avoir servi la Horde de manière digne !') ON DUPLICATE KEY UPDATE CompletionText='La bataille à Warsong Gulch contre les Sentinelles de Silverwing est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laissez pas cela arriver, $N! Revenez-moi avec une preuve d\'avoir servi la Horde de manière digne !';
-- Quest 8434 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8434, 'frFR', 'Excellent ! Vous avez prouvé votre valeur en défendant nos opérations à Warsong Gulch ! Que le mot de votre honneur se propage loin et large dans nos terres.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Vous avez prouvé votre valeur en défendant nos opérations à Warsong Gulch ! Que le mot de votre honneur se propage loin et large dans nos terres.';
-- Quest 8435 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8435, 'frFR', 'La bataille à Warsong Gulch contre les Sentinelles de Silverwing est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laissez pas cela arriver, $N! Revenez-moi avec une preuve d\'avoir servi la Horde de manière digne !') ON DUPLICATE KEY UPDATE CompletionText='La bataille à Warsong Gulch contre les Sentinelles de Silverwing est d\'une grande importance. Sous le prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laissez pas cela arriver, $N! Revenez-moi avec une preuve d\'avoir servi la Horde de manière digne !';
-- Quest 8435 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8435, 'frFR', 'Excellent ! Vous avez prouvé votre valeur en défendant nos opérations à Warsong Gulch ! Que le mot de votre honneur se propage loin et large dans nos terres.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Vous avez prouvé votre valeur en défendant nos opérations à Warsong Gulch ! Que le mot de votre honneur se propage loin et large dans nos terres.';
-- Quest 8446 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8446, 'frFR', 'Je dois ôter la souillure de cet objet. Cela pourrait éclairer mes récentes faillites à plonger dans le Rêve. Donnez-le-moi.') ON DUPLICATE KEY UPDATE RewardText='Je dois ôter la souillure de cet objet. Cela pourrait éclairer mes récentes faillites à plonger dans le Rêve. Donnez-le-moi.';
-- Quest 8447 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8447, 'frFR', 'Prenez son anneau, <name>. Il a servi son but pour Malfurion. Il servira maintenant un nouveau but pour vous...') ON DUPLICATE KEY UPDATE RewardText='Prenez son anneau, <name>. Il a servi son but pour Malfurion. Il servira maintenant un nouveau but pour vous...';
-- Quest 8460 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8460, 'frFR', 'Continuez, $N. Si vous voulez gagner notre confiance, vous devrez vous prouver à nous.') ON DUPLICATE KEY UPDATE CompletionText='Continuez, $N. Si vous voulez gagner notre confiance, vous devrez vous prouver à nous.';
-- Quest 8461 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8461, 'frFR', 'Une fois que vous aurez gagné la confiance des Timbermaw, je suis confiant qu\'il y aura quelque chose que nous pourrons faire pour vous. Les Timbermaw n\'oublient pas leurs alliés, surtout en ces temps sombres.') ON DUPLICATE KEY UPDATE CompletionText='Une fois que vous aurez gagné la confiance des Timbermaw, je suis confiant qu\'il y aura quelque chose que nous pourrons faire pour vous. Les Timbermaw n\'oublient pas leurs alliés, surtout en ces temps sombres.';
-- Quest 8464 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8464, 'frFR', 'Nous apprécions beaucoup ce que vous avez fait pour les Timbermaw, $N. Vos efforts continus gagneront sans aucun doute la confiance et le respect de ma tribu.') ON DUPLICATE KEY UPDATE CompletionText='Nous apprécions beaucoup ce que vous avez fait pour les Timbermaw, $N. Vos efforts continus gagneront sans aucun doute la confiance et le respect de ma tribu.';
-- Quest 8466 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8466, 'frFR', 'Bien que vous vous soyez prouvé à moi, vous devrez peut-être continuer à prouver votre valeur aux frères suspicieux de ma tribu. À ce titre, je pourrai continuer à vous aider.$B$BSome of the Deadwood furbolgs wear a distinctive headdress that may be used as a means of proof in thinning their numbers. Bring me a feather from any headdresses you acquire; for every set of five you bring me, you will earn recognition amongst the Timbermaw.') ON DUPLICATE KEY UPDATE CompletionText='Bien que vous vous soyez prouvé à moi, vous devrez peut-être continuer à prouver votre valeur aux frères suspicieux de ma tribu. À ce titre, je pourrai continuer à vous aider.$B$BSome of the Deadwood furbolgs wear a distinctive headdress that may be used as a means of proof in thinning their numbers. Bring me a feather from any headdresses you acquire; for every set of five you bring me, you will earn recognition amongst the Timbermaw.';
-- Quest 8466 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8466, 'frFR', 'Bien joué, <name> !  Je veillerai à ce que vos exploits soient connus parmi les miens.$B$BN\'oubliez pas d\'apporter les plumes que vous trouvez.  Je continuerai à les accepter tant que nécessaire.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name> !  Je veillerai à ce que vos exploits soient connus parmi les miens.$B$BN\'oubliez pas d\'apporter les plumes que vous trouvez.  Je continuerai à les accepter tant que nécessaire.';
-- Quest 8467 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8467, 'frFR', 'Bien que vous vous soyez prouvé à moi, vous devrez peut-être continuer à prouver votre valeur aux frères suspicieux de ma tribu. À ce titre, je pourrai continuer à vous aider.$B$BSome of the Deadwood furbolgs wear a distinctive headdress that may be used as a means of proof in thinning their numbers. Bring me a feather from any headdresses you acquire; for every set of five you bring me, you will earn recognition amongst the Timbermaw.') ON DUPLICATE KEY UPDATE CompletionText='Bien que vous vous soyez prouvé à moi, vous devrez peut-être continuer à prouver votre valeur aux frères suspicieux de ma tribu. À ce titre, je pourrai continuer à vous aider.$B$BSome of the Deadwood furbolgs wear a distinctive headdress that may be used as a means of proof in thinning their numbers. Bring me a feather from any headdresses you acquire; for every set of five you bring me, you will earn recognition amongst the Timbermaw.';
-- Quest 8467 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8467, 'frFR', 'Bien joué, <name> !  Je veillerai à ce que vos exploits soient connus parmi les miens.$B$BN\'oubliez pas d\'apporter les plumes que vous trouvez.  Je continuerai à les accepter tant que nécessaire.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name> !  Je veillerai à ce que vos exploits soient connus parmi les miens.$B$BN\'oubliez pas d\'apporter les plumes que vous trouvez.  Je continuerai à les accepter tant que nécessaire.';
-- Quest 8469 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8469, 'frFR', 'Vous avez certainement gagné ma confiance, $N, mais vous devrez peut-être continuer à gagner la confiance de ma tribu méfiante. Il y a quelque chose que vous pouvez faire pour gagner cette confiance.$B$BLes Winterfall sont connus pour porter des perles d\'esprit pour se prémunir contre les esprits malveillants. Ces perles ont clairement échoué dans leur objectif, car les Winterfall eux-mêmes sont les agents de la corruption. Apportez-moi ces perles d\'esprit des furbolgs Winterfall tombés ; pour chaque série de cinq que vous m\'apportez, vous gagnerez la reconnaissance parmi les Timbermaw.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez certainement gagné ma confiance, $N, mais vous devrez peut-être continuer à gagner la confiance de ma tribu méfiante. Il y a quelque chose que vous pouvez faire pour gagner cette confiance.$B$BLes Winterfall sont connus pour porter des perles d\'esprit pour se prémunir contre les esprits malveillants. Ces perles ont clairement échoué dans leur objectif, car les Winterfall eux-mêmes sont les agents de la corruption. Apportez-moi ces perles d\'esprit des furbolgs Winterfall tombés ; pour chaque série de cinq que vous m\'apportez, vous gagnerez la reconnaissance parmi les Timbermaw.';
-- Quest 8472 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8472, 'frFR', 'Avez-vous réussi à rassembler les cœurs arcaniques, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à rassembler les cœurs arcaniques, $N?';

-- Quest 8473 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8473, 'frFR', 'Je crains de demander, $N... la tâche est-elle accomplie ?') ON DUPLICATE KEY UPDATE CompletionText='Je crains de demander, $N... la tâche est-elle accomplie ?';
-- Quest 8475 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8475, 'frFR', 'Tu es de retour, $N. As-tu repoussé les morts-vivants le long de la Cicatrice Morte ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour, $N. As-tu repoussé les morts-vivants le long de la Cicatrice Morte ?';
-- Quest 8476 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8476, 'frFR', 'Tu trouveras Tor\'Watha et Zeb\'Watha au sud-est d\'ici. Reviens quand tu auras tué les trolls.') ON DUPLICATE KEY UPDATE CompletionText='Tu trouveras Tor\'Watha et Zeb\'Watha au sud-est d\'ici. Reviens quand tu auras tué les trolls.';
-- Quest 8477 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8477, 'frFR', 'Tu m\'as apporté le marteau d\'Otembe ?') ON DUPLICATE KEY UPDATE CompletionText='Tu m\'as apporté le marteau d\'Otembe ?';
-- Quest 8481 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8481, 'frFR', 'Tu nous es revenu, $N... cela signifie-t-il que le démon a été abattu ?') ON DUPLICATE KEY UPDATE CompletionText='Tu nous es revenu, $N... cela signifie-t-il que le démon a été abattu ?';
-- Quest 8481 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8481, 'frFR', 'Tu as... tu nous as sauvés !  Ta défaite du démon Xandivious a assuré la sécurité de Timbermaw Hold pour les années à venir.  Tu es vraiment un héros parmi notre espèce.$B$BJe t\'en prie, accepte ceci avec notre bénédiction.  Bien que le processus de guérison sera lent parmi les furbolgs - et le conflit continuera - tu as donné à Winterfall quelque chose qu\'ils n\'avaient jamais eu avant ce jour.$B$BIls ont une chance de survivre.') ON DUPLICATE KEY UPDATE RewardText='Tu as... tu nous as sauvés !  Ta défaite du démon Xandivious a assuré la sécurité de Timbermaw Hold pour les années à venir.  Tu es vraiment un héros parmi notre espèce.$B$BJe t\'en prie, accepte ceci avec notre bénédiction.  Bien que le processus de guérison sera lent parmi les furbolgs - et le conflit continuera - tu as donné à Winterfall quelque chose qu\'ils n\'avaient jamais eu avant ce jour.$B$BIls ont une chance de survivre.';
-- Quest 8484 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8484, 'frFR', '$C, tu es le bienvenu dans mon domaine. Ironforge devrait toujours être considéré comme un foyer pour un héros tel que toi. Maintenant, quelle affaire as-tu avec moi ?') ON DUPLICATE KEY UPDATE CompletionText='$C, tu es le bienvenu dans mon domaine. Ironforge devrait toujours être considéré comme un foyer pour un héros tel que toi. Maintenant, quelle affaire as-tu avec moi ?';
-- Quest 8484 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8484, 'frFR', 'En effet, c\'est un tournant des événements fort fortuit.  Si une paix durable devait être conclue avec ces créatures, cela nous donnerait certainement un avantage dans les affaires de Kalimdor... un avantage que les Elfes de la Nuit ne peuvent soutenir seuls.  Je notifierai les autres dirigeants de l\'Alliance de cela immédiatement, et d\'autres diplomates seront dépêchés !$B$BPour toi, <name>... tu as fait preuve de courage à la fois en diplomatie et en action.  Je te remercie, comme le fait toute l\'Alliance.') ON DUPLICATE KEY UPDATE RewardText='En effet, c\'est un tournant des événements fort fortuit.  Si une paix durable devait être conclue avec ces créatures, cela nous donnerait certainement un avantage dans les affaires de Kalimdor... un avantage que les Elfes de la Nuit ne peuvent soutenir seuls.  Je notifierai les autres dirigeants de l\'Alliance de cela immédiatement, et d\'autres diplomates seront dépêchés !$B$BPour toi, <name>... tu as fait preuve de courage à la fois en diplomatie et en action.  Je te remercie, comme le fait toute l\'Alliance.';
-- Quest 8485 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8485, 'frFR', 'Les salutations du chef de guerre t\'incombent, $C. Tes exploits rendent la Horde plus forte en ces temps troublés. Maintenant, quelle affaire as-tu avec moi ?') ON DUPLICATE KEY UPDATE CompletionText='Les salutations du chef de guerre t\'incombent, $C. Tes exploits rendent la Horde plus forte en ces temps troublés. Maintenant, quelle affaire as-tu avec moi ?';
-- Quest 8485 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8485, 'frFR', 'En effet, c\'est un tournant des événements fort fortuit. Si une paix durable devait être conclue avec ces créatures, cela nous donnerait certainement un avantage pour sécuriser Kalimdor contre les menaces extérieures. Je notifierai les autres dirigeants de la Horde de cela immédiatement, et d\'autres diplomates seront dépêchés !$B$BPour toi, $N... tu as fait preuve de courage à la fois en diplomatie et en action. Je te remercie, comme l\'intégralité de la Horde.') ON DUPLICATE KEY UPDATE RewardText='En effet, c\'est un tournant des événements fort fortuit. Si une paix durable devait être conclue avec ces créatures, cela nous donnerait certainement un avantage pour sécuriser Kalimdor contre les menaces extérieures. Je notifierai les autres dirigeants de la Horde de cela immédiatement, et d\'autres diplomates seront dépêchés !$B$BPour toi, $N... tu as fait preuve de courage à la fois en diplomatie et en action. Je te remercie, comme l\'intégralité de la Horde.';
-- Quest 8486 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8486, 'frFR', 'As-tu pris soin des spectres arcaniques ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu pris soin des spectres arcaniques ?';
-- Quest 8487 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8487, 'frFR', 'As-tu fini de collecter les échantillons que j\'ai demandés, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu fini de collecter les échantillons que j\'ai demandés, $N ?';
-- Quest 8490 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8490, 'frFR', 'As-tu réussi à alimenter la pierre de rune, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à alimenter la pierre de rune, $N ?';
-- Quest 8492 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8492, 'frFR', 'As-tu collecté ces vingt barres de cuivre, soldat ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu collecté ces vingt barres de cuivre, soldat ?';
-- Quest 8492 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8492, 'frFR', 'Tu l\'as fait, garçon ! Nous allons mettre ces barres de cuivre sur la pile et les utiliser immédiatement pour fabriquer le matériel de guerre. C\'est l\'effort de gens comme toi qui me rend fier de servir l\'Alliance. Bon travail, soldat !$B$BEt si tu tombes sur d\'autres barres de cuivre, assure-toi qu\'elles me parviennent.') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait, garçon ! Nous allons mettre ces barres de cuivre sur la pile et les utiliser immédiatement pour fabriquer le matériel de guerre. C\'est l\'effort de gens comme toi qui me rend fier de servir l\'Alliance. Bon travail, soldat !$B$BEt si tu tombes sur d\'autres barres de cuivre, assure-toi qu\'elles me parviennent.';

-- Quest 8493 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8493, 'frFR', 'De retour, $C? Extraordinaire ! Les barres que vous avez fournies jusqu\'à présent vont vraiment aider à fabriquer toutes sortes de choses pour la guerre. Je sais, par exemple, que le cuivre sera utilisé pour des parties des cuves à vapeur qui sont en construction, ainsi que dans une petite flotte de gyrocoptères que nous prévoyons de déployer si le temps le permet.$B$BNe laissez pas les piles vous tromper cependant, nous avons encore besoin de barres de cuivre si vous pouvez les procurer pour l\'effort de guerre d\'Ahn\'Qiraj. Voulez-vous nous aider ?') ON DUPLICATE KEY UPDATE CompletionText='De retour, $C? Extraordinaire ! Les barres que vous avez fournies jusqu\'à présent vont vraiment aider à fabriquer toutes sortes de choses pour la guerre. Je sais, par exemple, que le cuivre sera utilisé pour des parties des cuves à vapeur qui sont en construction, ainsi que dans une petite flotte de gyrocoptères que nous prévoyons de déployer si le temps le permet.$B$BNe laissez pas les piles vous tromper cependant, nous avons encore besoin de barres de cuivre si vous pouvez les procurer pour l\'effort de guerre d\'Ahn\'Qiraj. Voulez-vous nous aider ?';
-- Quest 8493 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8493, 'frFR', 'Excellent travail ! Fouiller pour ce cuivre et le faire fondre a dû être une aventure. À moins que vous ne les ayez achetés à la maison d\'enchères. Dans tous les cas, ça me va. Vous êtes à féliciter pour votre contribution à l\'effort de guerre, $c. Et n\'hésitez pas à m\'apporter plus de barres de cuivre si vous en avez.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail ! Fouiller pour ce cuivre et le faire fondre a dû être une aventure. À moins que vous ne les ayez achetés à la maison d\'enchères. Dans tous les cas, ça me va. Vous êtes à féliciter pour votre contribution à l\'effort de guerre, $c. Et n\'hésitez pas à m\'apporter plus de barres de cuivre si vous en avez.';
-- Quest 8494 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8494, 'frFR', 'Si vous avez ces vingt barres de fer, je ne veux pas savoir où vous les cachez !') ON DUPLICATE KEY UPDATE CompletionText='Si vous avez ces vingt barres de fer, je ne veux pas savoir où vous les cachez !';
-- Quest 8494 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8494, 'frFR', 'Eh bien, eh bien, si ce n\'est pas $N. Et vous avez réussi. Je suppose maintenant que je vais devoir vous surveiller. Ça me fait mal de le dire, mais merci pour vos efforts. L\'Alliance ne l\'oubliera pas, et moi non plus. Maintenant, allez faire du boulot sur tout ce qui nécessite d\'être collecté.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, eh bien, si ce n\'est pas $N. Et vous avez réussi. Je suppose maintenant que je vais devoir vous surveiller. Ça me fait mal de le dire, mais merci pour vos efforts. L\'Alliance ne l\'oubliera pas, et moi non plus. Maintenant, allez faire du boulot sur tout ce qui nécessite d\'être collecté.';
-- Quest 8495 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8495, 'frFR', 'De retour si vite ? Arrêtez de me faire réévaluer mon opinion négative de vous, $C, vous me faites rougir. Alors, comme vous pouvez le voir, nous n\'avons toujours pas assez de barres de fer pour toutes les armes, armures, cuves à vapeur et autres qui doivent être construites pour la chasse aux insectes. Pensez-vous pouvoir ramener une autre pile de vingt barres de fer entre tous ces voyages à Zul\'Gurub, ou là où vous vous amusez ces jours-ci ?') ON DUPLICATE KEY UPDATE CompletionText='De retour si vite ? Arrêtez de me faire réévaluer mon opinion négative de vous, $C, vous me faites rougir. Alors, comme vous pouvez le voir, nous n\'avons toujours pas assez de barres de fer pour toutes les armes, armures, cuves à vapeur et autres qui doivent être construites pour la chasse aux insectes. Pensez-vous pouvoir ramener une autre pile de vingt barres de fer entre tous ces voyages à Zul\'Gurub, ou là où vous vous amusez ces jours-ci ?';
-- Quest 8495 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8495, 'frFR', 'Ça doit être froid dans les Steppes Ardentes. Regardez, c\'est $N, et elle m\'a apporté un cadeau. Vingt barres de fer ! Juste ce que je voulais toujours.$B$BMais au sérieux cependant, merci, $N. Vous êtes un crédit pour vous-même et pour l\'Alliance. Maintenant, retournez dehors et apportez plus de choses pour l\'effort de guerre !') ON DUPLICATE KEY UPDATE RewardText='Ça doit être froid dans les Steppes Ardentes. Regardez, c\'est $N, et elle m\'a apporté un cadeau. Vingt barres de fer ! Juste ce que je voulais toujours.$B$BMais au sérieux cependant, merci, $N. Vous êtes un crédit pour vous-même et pour l\'Alliance. Maintenant, retournez dehors et apportez plus de choses pour l\'effort de guerre !';
-- Quest 8496 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8496, 'frFR', 'Juste à temps. Ces fournitures sauveront des vies, $N. Votre travail est apprécié. Voici votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Juste à temps. Ces fournitures sauveront des vies, $N. Votre travail est apprécié. Voici votre prochaine mission.';
-- Quest 8497 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8497, 'frFR', 'Excellent ! Nous avions besoin de ça, $N. Merci.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Nous avions besoin de ça, $N. Merci.';
-- Quest 8498 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8498, 'frFR', 'Vous m\'avez apporté quelque chose ?') ON DUPLICATE KEY UPDATE CompletionText='Vous m\'avez apporté quelque chose ?';
-- Quest 8498 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8498, 'frFR', 'Excellent. Il est important de garder une longueur d\'avance sur la prochaine action de l\'ennemi. Ces informations nous permettront d\'anticiper les attaques du Marteau du Crépuscule.') ON DUPLICATE KEY UPDATE RewardText='Excellent. Il est important de garder une longueur d\'avance sur la prochaine action de l\'ennemi. Ces informations nous permettront d\'anticiper les attaques du Marteau du Crépuscule.';
-- Quest 8499 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8499, 'frFR', 'Oh, un envoi de mon frère ? Splendide ! La fortune me sourit vraiment aujourd\'hui !') ON DUPLICATE KEY UPDATE CompletionText='Oh, un envoi de mon frère ? Splendide ! La fortune me sourit vraiment aujourd\'hui !';
-- Quest 8499 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8499, 'frFR', 'Alors Gnoarn ne fait pas confiance à mes capacités de reconnaissance ? Je me demande pourquoi...') ON DUPLICATE KEY UPDATE RewardText='Alors Gnoarn ne fait pas confiance à mes capacités de reconnaissance ? Je me demande pourquoi...';
-- Quest 8500 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8500, 'frFR', 'C\'est si bon de vous revoir, $N. J\'espère que vous allez bien. C\'est vrai que nous avons encore besoin de barres de thorium. Si vous en avez à part, je les collecte pour l\'effort de guerre d\'Ahn\'Qiraj.') ON DUPLICATE KEY UPDATE CompletionText='C\'est si bon de vous revoir, $N. J\'espère que vous allez bien. C\'est vrai que nous avons encore besoin de barres de thorium. Si vous en avez à part, je les collecte pour l\'effort de guerre d\'Ahn\'Qiraj.';
-- Quest 8500 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8500, 'frFR', 'Excellent, $c! Un travail bien fait. Je veillerai à ce que ces barres soient mises sur la palette et entre les mains des forgerons et des ingénieurs qui travaillent dur à constituer les fournitures pour notre armée. Merci encore, et si vous tombez sur d\'autres barres de thorium, n\'hésitez pas à passer.') ON DUPLICATE KEY UPDATE RewardText='Excellent, $c! Un travail bien fait. Je veillerai à ce que ces barres soient mises sur la palette et entre les mains des forgerons et des ingénieurs qui travaillent dur à constituer les fournitures pour notre armée. Merci encore, et si vous tombez sur d\'autres barres de thorium, n\'hésitez pas à passer.';
-- Quest 8501 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8501, 'frFR', 'Vous voulez me dire quelque chose, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Vous voulez me dire quelque chose, $N ?';

-- Quest 8501 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8501, 'frFR', 'Excellent travail, <name>. Votre participation à l\'attaque de Hive\'Ashi a été notée.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>. Votre participation à l\'attaque de Hive\'Ashi a été notée.';
-- Quest 8502 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8502, 'frFR', 'Tu as quelque chose à me dire, $C?') ON DUPLICATE KEY UPDATE CompletionText='Tu as quelque chose à me dire, $C?';
-- Quest 8502 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8502, 'frFR', 'Excellent travail, <name>. Sans leurs ouvriers, le silithid aura du mal à réparer les dommages infligés à la structure de leur ruche.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>. Sans leurs ouvriers, le silithid aura du mal à réparer les dommages infligés à la structure de leur ruche.';
-- Quest 8503 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8503, 'frFR', 'Ce n\'est pas vrai ! Je ne prendrais jamais de stranglekelp sur le dessus des tas ici. On pourrait être tenté, cependant, considérant que c\'est pratiquement une panacée d\'utilité. *tousse* Tu n\'aurais pas ce stranglekelp dont nous avons parlé plus tôt ?') ON DUPLICATE KEY UPDATE CompletionText='Ce n\'est pas vrai ! Je ne prendrais jamais de stranglekelp sur le dessus des tas ici. On pourrait être tenté, cependant, considérant que c\'est pratiquement une panacée d\'utilité. *tousse* Tu n\'aurais pas ce stranglekelp dont nous avons parlé plus tôt ?';
-- Quest 8503 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8503, 'frFR', 'Hourra ! C\'est vingt de moins. Tu es le meilleur. Je suppose que je devrais tout ranger avant qu\'ils ne flétrissent. Tant de stranglekelp, si peu de temps !$B$BMerci encore, $c!') ON DUPLICATE KEY UPDATE RewardText='Hourra ! C\'est vingt de moins. Tu es le meilleur. Je suppose que je devrais tout ranger avant qu\'ils ne flétrissent. Tant de stranglekelp, si peu de temps !$B$BMerci encore, $c!';
-- Quest 8504 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8504, 'frFR', 'Bonjour à nouveau... qu\'est-ce que c\'était ? Ah oui, $N! Tu es venu voir si j\'avais encore besoin de stranglekelp, tu en as ? Eh bien, c\'est ton jour de chance, parce que la réponse à cette question très importante est un OUI très affirmatif ! Tu penses pouvoir en ramasser vingt de plus ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau... qu\'est-ce que c\'était ? Ah oui, $N! Tu es venu voir si j\'avais encore besoin de stranglekelp, tu en as ? Eh bien, c\'est ton jour de chance, parce que la réponse à cette question très importante est un OUI très affirmatif ! Tu penses pouvoir en ramasser vingt de plus ?';
-- Quest 8504 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8504, 'frFR', 'Oh mon Dieu, c\'est une bonne quantité de stranglekelp que tu as là. Vite, mettons ça dans une boîte pour qu\'il reste frais. Tu m\'as... nous, l\'Alliance, rendu un grand service en apportant ce lot. Je m\'assurerai que tout le monde sache que c\'est toi, le grand $N, qui a aidé à faire pencher la balance dans l\'effort de guerre d\'Ahn\'Qiraj avec ta contribution de stranglekelp !') ON DUPLICATE KEY UPDATE RewardText='Oh mon Dieu, c\'est une bonne quantité de stranglekelp que tu as là. Vite, mettons ça dans une boîte pour qu\'il reste frais. Tu m\'as... nous, l\'Alliance, rendu un grand service en apportant ce lot. Je m\'assurerai que tout le monde sache que c\'est toi, le grand $N, qui a aidé à faire pencher la balance dans l\'effort de guerre d\'Ahn\'Qiraj avec ta contribution de stranglekelp !';
-- Quest 8505 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8505, 'frFR', 'As-tu les herbes de lotus violet que j\'ai demandées ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu les herbes de lotus violet que j\'ai demandées ?';
-- Quest 8505 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8505, 'frFR', 'Ta contribution est grandement appréciée, $c. C\'est uniquement grâce aux efforts combinés de tous que nous serons capables de repousser l\'avancée impitoyable du silithid et de toute force qui les pousse. Même la Horde accumule sa propre collection de lotus violet. Si tu en trouves d\'autres, s\'il te plaît, reviens me voir ici.') ON DUPLICATE KEY UPDATE RewardText='Ta contribution est grandement appréciée, $c. C\'est uniquement grâce aux efforts combinés de tous que nous serons capables de repousser l\'avancée impitoyable du silithid et de toute force qui les pousse. Même la Horde accumule sa propre collection de lotus violet. Si tu en trouves d\'autres, s\'il te plaît, reviens me voir ici.';
-- Quest 8506 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8506, 'frFR', 'Bienvenue à nouveau $c. Notre collection grandit, mais même maintenant nous avons besoin de lotus violet supplémentaires. Si tu es encore en mesure d\'en ramasser davantage, je t\'en prie de le faire et de me les rapporter ici.') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue à nouveau $c. Notre collection grandit, mais même maintenant nous avons besoin de lotus violet supplémentaires. Si tu es encore en mesure d\'en ramasser davantage, je t\'en prie de le faire et de me les rapporter ici.';
-- Quest 8506 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8506, 'frFR', 'J\'accepte volontiers ta contribution au nom de l\'Alliance, $N. Tes efforts conduiront directement à la création de plusieurs potions et huiles en soutien de nos hommes et nos femmes sur le terrain. Merci, et si tu en trouves d\'autres, s\'il te plaît, considère revenir me voir.') ON DUPLICATE KEY UPDATE RewardText='J\'accepte volontiers ta contribution au nom de l\'Alliance, $N. Tes efforts conduiront directement à la création de plusieurs potions et huiles en soutien de nos hommes et nos femmes sur le terrain. Merci, et si tu en trouves d\'autres, s\'il te plaît, considère revenir me voir.';
-- Quest 8508 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8508, 'frFR', 'Je suppose que tu veux que ces papiers soient signés, $Glad:lass;?') ON DUPLICATE KEY UPDATE CompletionText='Je suppose que tu veux que ces papiers soient signés, $Glad:lass;?';
-- Quest 8508 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8508, 'frFR', 'Oui, je suppose que cette petite escarmouche passera pour devoir de terrain de nos jours. Prends ceci et ramène-le au Repaire de Cenarion, je suis sûr qu\'ils auront une tâche facile pour toi.$B$BPars !') ON DUPLICATE KEY UPDATE RewardText='Oui, je suppose que cette petite escarmouche passera pour devoir de terrain de nos jours. Prends ceci et ramène-le au Repaire de Cenarion, je suis sûr qu\'ils auront une tâche facile pour toi.$B$BPars !';
-- Quest 8509 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8509, 'frFR', 'Qu\'est-ce que c\'est ? Parle plus fort, $C! As-tu le chargement de larmes d\'Arthas que j\'ai demandé ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que c\'est ? Parle plus fort, $C! As-tu le chargement de larmes d\'Arthas que j\'ai demandé ?';
-- Quest 8509 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8509, 'frFR', 'Bon travail, $c. Je dois dire que je suis agréablement surpris. Tu ne croirais pas le nombre de personnes qui sont venues, offrant d\'aider, mais sans jamais revenir. Laisse-moi juste mettre ça dans une caisse et le faire énumérer avec ton nom dessus, et ensuite nous pourrons reparler de savoir si j\'ai besoin d\'autres de ces plantes.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, $c. Je dois dire que je suis agréablement surpris. Tu ne croirais pas le nombre de personnes qui sont venues, offrant d\'aider, mais sans jamais revenir. Laisse-moi juste mettre ça dans une caisse et le faire énumérer avec ton nom dessus, et ensuite nous pourrons reparler de savoir si j\'ai besoin d\'autres de ces plantes.';

-- Quest 8510 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8510, 'frFR', 'Il semble que j\'ai encore besoin de larmes d\'Arthas. J\'imagine que vous pourrez les trouver dans la zone générale où vous les avez ramassées pour moi la dernière fois. Plus vite nous les aurons, plus vite nous pourrons commencer l\'offensive contre les forces d\'Ahn\'Qiraj.$B$BVous allez nous aider à nouveau $c?') ON DUPLICATE KEY UPDATE CompletionText='Il semble que j\'ai encore besoin de larmes d\'Arthas. J\'imagine que vous pourrez les trouver dans la zone générale où vous les avez ramassées pour moi la dernière fois. Plus vite nous les aurons, plus vite nous pourrons commencer l\'offensive contre les forces d\'Ahn\'Qiraj.$B$BVous allez nous aider à nouveau $c?';
-- Quest 8510 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8510, 'frFR', 'Simplement exceptionnel, $N! Vous êtes une vraie fierté pour l\'Alliance. Je m\'assurerai de mettre ces herbes de côté jusqu\'à ce que quelqu\'un vienne les transformer en quelque chose d\'utile pour la guerre. N\'hésitez pas à revenir quand vous voulez, surtout si vous avez plus de larmes d\'Arthas pour moi.') ON DUPLICATE KEY UPDATE RewardText='Simplement exceptionnel, $N! Vous êtes une vraie fierté pour l\'Alliance. Je m\'assurerai de mettre ces herbes de côté jusqu\'à ce que quelqu\'un vienne les transformer en quelque chose d\'utile pour la guerre. N\'hésitez pas à revenir quand vous voulez, surtout si vous avez plus de larmes d\'Arthas pour moi.';
-- Quest 8511 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8511, 'frFR', '$C, j\'espère que c\'est le cuir léger que vous avez promis.') ON DUPLICATE KEY UPDATE CompletionText='$C, j\'espère que c\'est le cuir léger que vous avez promis.';
-- Quest 8511 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8511, 'frFR', 'J\'ose dire que l\'Alliance sera très heureuse de vos peaux ici, $c. Je m\'assurerai qu\'aucune ne soit gaspillée. Merci, et assurez-vous de revenir me voir une fois que je les aurai comptées pour voir si nous en avons besoin d\'autres.') ON DUPLICATE KEY UPDATE RewardText='J\'ose dire que l\'Alliance sera très heureuse de vos peaux ici, $c. Je m\'assurerai qu\'aucune ne soit gaspillée. Merci, et assurez-vous de revenir me voir une fois que je les aurai comptées pour voir si nous en avons besoin d\'autres.';
-- Quest 8512 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8512, 'frFR', 'Ravi de vous revoir, $N. Il semble que nous ayons besoin de plus de cuir léger pour la création des divers matériels de guerre. Si vous pouviez m\'apporter une pile de dix, ce serait parfait.') ON DUPLICATE KEY UPDATE CompletionText='Ravi de vous revoir, $N. Il semble que nous ayons besoin de plus de cuir léger pour la création des divers matériels de guerre. Si vous pouviez m\'apporter une pile de dix, ce serait parfait.';
-- Quest 8512 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8512, 'frFR', 'Merci pour votre généreuse donation, $N. Je vais les mettre dans la pile tout de suite, et je suis sûr qu\'en un rien de temps, ils seront transformés en un bel ensemble d\'armure, quelques morceaux de cuir, ou utilisés pour autre chose dans nos préparatifs. On dirait que nous avons toujours besoin de plus de cuir léger. Revenez me rendre visite bientôt.') ON DUPLICATE KEY UPDATE RewardText='Merci pour votre généreuse donation, $N. Je vais les mettre dans la pile tout de suite, et je suis sûr qu\'en un rien de temps, ils seront transformés en un bel ensemble d\'armure, quelques morceaux de cuir, ou utilisés pour autre chose dans nos préparatifs. On dirait que nous avons toujours besoin de plus de cuir léger. Revenez me rendre visite bientôt.';
-- Quest 8513 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8513, 'frFR', 'Oui monsieur, je me souviens de vous. Est-ce le cuir moyen que vous avez avec vous là ?') ON DUPLICATE KEY UPDATE CompletionText='Oui monsieur, je me souviens de vous. Est-ce le cuir moyen que vous avez avec vous là ?';
-- Quest 8513 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8513, 'frFR', 'Wow! Il semble que vous soyez juste venu ici pour faire du bénévolat. Merci beaucoup pour le don. Je vais juste tout mettre de côté et compter. Vous savez vraiment comment égayer la journée de quelqu\'un.') ON DUPLICATE KEY UPDATE RewardText='Wow! Il semble que vous soyez juste venu ici pour faire du bénévolat. Merci beaucoup pour le don. Je vais juste tout mettre de côté et compter. Vous savez vraiment comment égayer la journée de quelqu\'un.';
-- Quest 8514 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8514, 'frFR', 'Oui monsieur, il semble que nous ayons collecté beaucoup de pièces de cuir moyen, mais nous en avons besoin de plus. Je peux vous assurer que tout sera utilisé à bon escient; pas une pièce ne sera gaspillée. Je sais que c\'est beaucoup à demander, mais si vous êtes toujours disposé, je pourrais avoir besoin de votre aide pour essayer de réduire le reste de mon quota.') ON DUPLICATE KEY UPDATE CompletionText='Oui monsieur, il semble que nous ayons collecté beaucoup de pièces de cuir moyen, mais nous en avons besoin de plus. Je peux vous assurer que tout sera utilisé à bon escient; pas une pièce ne sera gaspillée. Je sais que c\'est beaucoup à demander, mais si vous êtes toujours disposé, je pourrais avoir besoin de votre aide pour essayer de réduire le reste de mon quota.';
-- Quest 8514 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8514, 'frFR', 'Mon Dieu, c\'est beaucoup de cuir moyen que vous avez apporté, monsieur! Je vais m\'assurer que tout cela soit utilisé correctement, oui en effet. Avec votre aide, nous aurons rempli notre estimation de cuir moyen en un rien de temps!$B$BMerci, $N!') ON DUPLICATE KEY UPDATE RewardText='Mon Dieu, c\'est beaucoup de cuir moyen que vous avez apporté, monsieur! Je vais m\'assurer que tout cela soit utilisé correctement, oui en effet. Avec votre aide, nous aurons rempli notre estimation de cuir moyen en un rien de temps!$B$BMerci, $N!';
-- Quest 8515 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8515, 'frFR', 'Est-ce le cuir épais que vous avez dans votre sac, $C? C\'est ça? Je ne peux pas attendre que vous me le remettiez! Tout le monde sera tellement content de nous, ne pensez-vous pas?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce le cuir épais que vous avez dans votre sac, $C? C\'est ça? Je ne peux pas attendre que vous me le remettiez! Tout le monde sera tellement content de nous, ne pensez-vous pas?';
-- Quest 8515 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8515, 'frFR', 'Oh, je savais que vous pouviez le faire, $c, je le savais! Je vais les remettre aux bonnes mains dès que je peux. Maintenant, voyons voir. Hmm, il semble que notre décompte progresse plutôt bien. Vous devriez revenir me voir dans un instant une fois que j\'aurai fini de compter pour voir si nous en avons besoin de plus. Parce que si nous en avons besoin, c\'est vous que je veux dehors pour le ramasser pour moi!') ON DUPLICATE KEY UPDATE RewardText='Oh, je savais que vous pouviez le faire, $c, je le savais! Je vais les remettre aux bonnes mains dès que je peux. Maintenant, voyons voir. Hmm, il semble que notre décompte progresse plutôt bien. Vous devriez revenir me voir dans un instant une fois que j\'aurai fini de compter pour voir si nous en avons besoin de plus. Parce que si nous en avons besoin, c\'est vous que je veux dehors pour le ramasser pour moi!';
-- Quest 8516 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8516, 'frFR', 'Oui, la pile n\'est toujours pas assez haute. $N, nous n\'avons pas encore atteint notre objectif de cuir épais. Pensez à tout ce que nous pouvons fabriquer avec tout ce cuir! Tous types d\'armures et d\'armes. Des choses pour l\'intérieur des cuves à vapeur et des lunettes de visée de fusil! Et des lunettes d\'ingénieur, c\'est toujours amusant!$B$BVous allez m\'apporter plus de cuir épais?') ON DUPLICATE KEY UPDATE CompletionText='Oui, la pile n\'est toujours pas assez haute. $N, nous n\'avons pas encore atteint notre objectif de cuir épais. Pensez à tout ce que nous pouvons fabriquer avec tout ce cuir! Tous types d\'armures et d\'armes. Des choses pour l\'intérieur des cuves à vapeur et des lunettes de visée de fusil! Et des lunettes d\'ingénieur, c\'est toujours amusant!$B$BVous allez m\'apporter plus de cuir épais?';
-- Quest 8516 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8516, 'frFR', 'Vous l\'avez fait encore! C\'est tout simplement incroyable la façon dont vous allez dehors, ramassez toutes ces choses, et puis les ramenez ici et les remettez. Je vous dis, quand ils découvriront combien vous avez aidé par ici, vous ne pourrez pas marcher dans la rue sans que les gens ne vous demandent votre autographe!$B$BMerci encore pour votre très généreuse donation de cuir épais, $N.') ON DUPLICATE KEY UPDATE RewardText='Vous l\'avez fait encore! C\'est tout simplement incroyable la façon dont vous allez dehors, ramassez toutes ces choses, et puis les ramenez ici et les remettez. Je vous dis, quand ils découvriront combien vous avez aidé par ici, vous ne pourrez pas marcher dans la rue sans que les gens ne vous demandent votre autographe!$B$BMerci encore pour votre très généreuse donation de cuir épais, $N.';
-- Quest 8517 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8517, 'frFR', 'Avez-vous les vingt bandages de lin que j\'exige, $C?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les vingt bandages de lin que j\'exige, $C?';

-- Quest 8517 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8517, 'frFR', 'De nombreux sont les soldats qui bénéficieront de votre contribution aujourd\'hui, $c. Je veillerai personnellement à ce que l\'Alliance soit informée de vos efforts. Permettez-moi un instant pour ranger ces bandages correctement et mettre à jour mon décompte, et ensuite vous devriez revenir me voir pour voir si j\'ai besoin de plus.$B$BQue la Lumière d\'Elune brille sur vous, $R!') ON DUPLICATE KEY UPDATE RewardText='De nombreux sont les soldats qui bénéficieront de votre contribution aujourd\'hui, $c. Je veillerai personnellement à ce que l\'Alliance soit informée de vos efforts. Permettez-moi un instant pour ranger ces bandages correctement et mettre à jour mon décompte, et ensuite vous devriez revenir me voir pour voir si j\'ai besoin de plus.$B$BQue la Lumière d\'Elune brille sur vous, $R!';
-- Quest 8518 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8518, 'frFR', 'Je suis toujours émerveillé par le désintéressement dont font preuve tant de gens, alors que beaucoup préféreraient se tourner vers l\'égoïsme. $C, j\'ai toujours besoin d\'un certain nombre de bandages en lin avant que ma mission ici ne soit accomplie. Pourriez-vous m\'aider une fois de plus à collecter ces bandages ?') ON DUPLICATE KEY UPDATE CompletionText='Je suis toujours émerveillé par le désintéressement dont font preuve tant de gens, alors que beaucoup préféreraient se tourner vers l\'égoïsme. $C, j\'ai toujours besoin d\'un certain nombre de bandages en lin avant que ma mission ici ne soit accomplie. Pourriez-vous m\'aider une fois de plus à collecter ces bandages ?';
-- Quest 8518 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8518, 'frFR', 'Vous êtes à féliciter, $N. Alors qu\'il y a ceux qui profiteraient de l\'économie de notre état de guerre pour engraisser leurs poches dans une ferveur de cupidité, vous avez prouvé encore et encore que votre dévouement à l\'Alliance, et en effet à tout Azeroth, passe en premier.$B$BBlesseurs d\'Elune soient avec vous toujours!') ON DUPLICATE KEY UPDATE RewardText='Vous êtes à féliciter, $N. Alors qu\'il y a ceux qui profiteraient de l\'économie de notre état de guerre pour engraisser leurs poches dans une ferveur de cupidité, vous avez prouvé encore et encore que votre dévouement à l\'Alliance, et en effet à tout Azeroth, passe en premier.$B$BBlesseurs d\'Elune soient avec vous toujours!';
-- Quest 8519 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8519, 'frFR', 'Après la trahison de Staghelm, j\'ai rassemblé les morceaux du Sceptre des Sables Mouvants et suis revenu ici. J\'avais l\'intention de protéger le sceptre de ceux qui chercheraient à l\'utiliser pour nuire à notre monde - ainsi est née la charge des Dragons-volants.$B$BUn sceptre divisé entre les quatre Aspects puissants s\'avérerait presque impossible à restaurer pour ceux qui cherchent volontairement le chaos... ou du moins, c\'est ce que je croyais. Quel imbécile j\'étais. Même maintenant, je suis traqué par ce maudit vol.') ON DUPLICATE KEY UPDATE RewardText='Après la trahison de Staghelm, j\'ai rassemblé les morceaux du Sceptre des Sables Mouvants et suis revenu ici. J\'avais l\'intention de protéger le sceptre de ceux qui chercheraient à l\'utiliser pour nuire à notre monde - ainsi est née la charge des Dragons-volants.$B$BUn sceptre divisé entre les quatre Aspects puissants s\'avérerait presque impossible à restaurer pour ceux qui cherchent volontairement le chaos... ou du moins, c\'est ce que je croyais. Quel imbécile j\'étais. Même maintenant, je suis traqué par ce maudit vol.';
-- Quest 8520 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8520, 'frFR', 'J\'ai besoin que ces tuniques et bandeaux soient fabriqués, et j\'ai aussi besoin de cette pièce de liane sauvage avant de vous partager la connaissance des casques en cuir sauvage.$B$BLes équipements de tête sont très convoités par les aventuriers, qu\'il s\'agisse d\'un bandeau d\'une simplicité désarmante ou d\'un casque couvrant tout. Les fondamentaux de la création d\'équipement de tête de valeur restent constants, quelle que soit l\'apparence cosmétique de l\'équipement.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai besoin que ces tuniques et bandeaux soient fabriqués, et j\'ai aussi besoin de cette pièce de liane sauvage avant de vous partager la connaissance des casques en cuir sauvage.$B$BLes équipements de tête sont très convoités par les aventuriers, qu\'il s\'agisse d\'un bandeau d\'une simplicité désarmante ou d\'un casque couvrant tout. Les fondamentaux de la création d\'équipement de tête de valeur restent constants, quelle que soit l\'apparence cosmétique de l\'équipement.';
-- Quest 8520 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8520, 'frFR', '$C, vous l\'avez fait ! Grâce à vous, nous sommes un pas de plus vers l\'atteinte de notre objectif avec les bandages en soie. Je vais les ranger, et ensuite nous pourrons en discuter davantage si vous le souhaitez.') ON DUPLICATE KEY UPDATE RewardText='$C, vous l\'avez fait ! Grâce à vous, nous sommes un pas de plus vers l\'atteinte de notre objectif avec les bandages en soie. Je vais les ranger, et ensuite nous pourrons en discuter davantage si vous le souhaitez.';
-- Quest 8521 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8521, 'frFR', 'C\'est très gentil de votre part de proposer de m\'aider à nouveau, $c. Il semble que nous ayons collecté un bon nombre des bandages en soie que nous avons été chargés de, mais nous en avons encore besoin. $N, y a-t-il un moyen que vous puissiez vous charger de rassembler un autre paquet et me les rapporter ici ? L\'Alliance et moi vous en serons très reconnaissants.') ON DUPLICATE KEY UPDATE CompletionText='C\'est très gentil de votre part de proposer de m\'aider à nouveau, $c. Il semble que nous ayons collecté un bon nombre des bandages en soie que nous avons été chargés de, mais nous en avons encore besoin. $N, y a-t-il un moyen que vous puissiez vous charger de rassembler un autre paquet et me les rapporter ici ? L\'Alliance et moi vous en serons très reconnaissants.';
-- Quest 8521 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8521, 'frFR', 'Vous êtes une personne si désintéressée. Merci beaucoup pour votre contribution à l\'effort de guerre. Ce sont des gens comme vous qui feront la différence entre le succès et l\'échec à Ahn\'Qiraj. J\'espère juste que tout cela sera suffisant.$B$BMerci encore, $N.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes une personne si désintéressée. Merci beaucoup pour votre contribution à l\'effort de guerre. Ce sont des gens comme vous qui feront la différence entre le succès et l\'échec à Ahn\'Qiraj. J\'espère juste que tout cela sera suffisant.$B$BMerci encore, $N.';
-- Quest 8522 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8522, 'frFR', 'Les jours passent les uns après les autres, et nous continuons. $C, avez-vous ces bandages en tissu de rune ?') ON DUPLICATE KEY UPDATE CompletionText='Les jours passent les uns après les autres, et nous continuons. $C, avez-vous ces bandages en tissu de rune ?';
-- Quest 8522 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8522, 'frFR', 'Vous êtes à féliciter, $c, pour votre persévérance dans cette tâche. Je vais ranger ces bandages, et ensuite j\'aimerais vous reparler de la possibilité que vous collectiez encore plus de bandages en tissu de rune.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes à féliciter, $c, pour votre persévérance dans cette tâche. Je vais ranger ces bandages, et ensuite j\'aimerais vous reparler de la possibilité que vous collectiez encore plus de bandages en tissu de rune.';
-- Quest 8523 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8523, 'frFR', 'C\'est donc nous qui venons discuter de questions urgentes une fois de plus, $C. Je vous remercie encore pour vos efforts précédents ; ce n\'est pas tout le monde qui donnerait avec autant de désintéressement. Mais il y a encore du travail à faire.$B$B$N, allez-vous collecter à nouveau des bandages en tissu de rune et me les rapporter ici ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est donc nous qui venons discuter de questions urgentes une fois de plus, $C. Je vous remercie encore pour vos efforts précédents ; ce n\'est pas tout le monde qui donnerait avec autant de désintéressement. Mais il y a encore du travail à faire.$B$B$N, allez-vous collecter à nouveau des bandages en tissu de rune et me les rapporter ici ?';
-- Quest 8523 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8523, 'frFR', 'C\'est un beau chemin que nous parcourons ensemble, $N. Vous êtes un excellent compagnon de travail. Je vous remercie encore pour vos efforts au nom de toute l\'Alliance. Revenez en discuter avec moi bientôt.') ON DUPLICATE KEY UPDATE RewardText='C\'est un beau chemin que nous parcourons ensemble, $N. Vous êtes un excellent compagnon de travail. Je vous remercie encore pour vos efforts au nom de toute l\'Alliance. Revenez en discuter avec moi bientôt.';
-- Quest 8524 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8524, 'frFR', 'Je suis prêt à parier que vous êtes revenu avec tout ce cabareau de poisson albacore arc-en-ciel dont nous parlions avant, n\'est-ce pas, $C ?') ON DUPLICATE KEY UPDATE CompletionText='Je suis prêt à parier que vous êtes revenu avec tout ce cabareau de poisson albacore arc-en-ciel dont nous parlions avant, n\'est-ce pas, $C ?';
-- Quest 8524 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8524, 'frFR', 'Deux pour l\'Alliance, un pour moi, deux pour l\'Alliance, un pour moi. Hé là, poissonier, excellent travail. Je vois que vous allez être une vraie fierté pour le club. Il me semble que nous avons probablement besoin de plus de cet albacore. Pourquoi ne pas partir et en ramener un peu plus. J\'entends déjà mon ventre gargouiller.') ON DUPLICATE KEY UPDATE RewardText='Deux pour l\'Alliance, un pour moi, deux pour l\'Alliance, un pour moi. Hé là, poissonier, excellent travail. Je vois que vous allez être une vraie fierté pour le club. Il me semble que nous avons probablement besoin de plus de cet albacore. Pourquoi ne pas partir et en ramener un peu plus. J\'entends déjà mon ventre gargouiller.';
-- Quest 8525 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8525, 'frFR', 'Quoi ! Encore vous ? Eh bien, je suis un singe... sauf que je suis un $R$. Gastronome Glissant pour être précis ! Alors vous êtes de retour pour aider à nouveau, hein ? Eh bien, je ne peux pas dire que je vous blâme. Vous aimez juste l\'odeur de toute cette nourriture ? <salive>$B$BAssez de traîner ! Sortez et ramenez-moi plus d\'albacore arc-en-ciel !') ON DUPLICATE KEY UPDATE CompletionText='Quoi ! Encore vous ? Eh bien, je suis un singe... sauf que je suis un $R$. Gastronome Glissant pour être précis ! Alors vous êtes de retour pour aider à nouveau, hein ? Eh bien, je ne peux pas dire que je vous blâme. Vous aimez juste l\'odeur de toute cette nourriture ? <salive>$B$BAssez de traîner ! Sortez et ramenez-moi plus d\'albacore arc-en-ciel !';

-- Quest 8525 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8525, 'frFR', 'Je savais que tu avais ça en toi, gamin. Tu as l\'air de quelqu\'un qui sait ce qu\'il aime. Spécifiquement que tu aimes me satisfaire et les puissants. Et que tu as, je le garantis.$B$Hahaha, d\'accord, je vais juste ranger ces poissons correctement, et ensuite toi et moi on pourra discuter de toi ramener vingt autres albacores.') ON DUPLICATE KEY UPDATE RewardText='Je savais que tu avais ça en toi, gamin. Tu as l\'air de quelqu\'un qui sait ce qu\'il aime. Spécifiquement que tu aimes me satisfaire et les puissants. Et que tu as, je le garantis.$B$Hahaha, d\'accord, je vais juste ranger ces poissons correctement, et ensuite toi et moi on pourra discuter de toi ramener vingt autres albacores.';
-- Quest 8526 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8526, 'frFR', 'Alors, tu as tout ce raptor rôti ?') ON DUPLICATE KEY UPDATE CompletionText='Alors, tu as tout ce raptor rôti ?';
-- Quest 8526 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8526, 'frFR', 'Eh bien, c\'est super. Merci de m\'apporter toute cette viande de bête brûlée, $c. Je vais juste la mettre sur la pile là-bas. Je suis sûr que quelqu\'un s\'en occupera. Je suppose que si tu as du temps libre, tu pourrais peut-être m\'en apporter plus ?') ON DUPLICATE KEY UPDATE RewardText='Eh bien, c\'est super. Merci de m\'apporter toute cette viande de bête brûlée, $c. Je vais juste la mettre sur la pile là-bas. Je suis sûr que quelqu\'un s\'en occupera. Je suppose que si tu as du temps libre, tu pourrais peut-être m\'en apporter plus ?';
-- Quest 8527 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8527, 'frFR', 'Salut à nouveau $c. Je peux voir que tu es très excité par tout ça. Alors, je suppose que tu veux m\'apporter vingt autres raptors rôtis. Super. Eh bien, fais ça. Je suppose que je te verrai quand tu reviendras.') ON DUPLICATE KEY UPDATE CompletionText='Salut à nouveau $c. Je peux voir que tu es très excité par tout ça. Alors, je suppose que tu veux m\'apporter vingt autres raptors rôtis. Super. Eh bien, fais ça. Je suppose que je te verrai quand tu reviendras.';
-- Quest 8527 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8527, 'frFR', 'Wow, tu es vraiment une meneuse. Tu me fatigues juste à te regarder. Quoi qu\'il en soit, merci de l\'Alliance et tout ça. Je m\'assurerai que toute cette viande morte soit emballée. Je suppose que tu pourrais revenir me voir plus tard pour voir si nous avons encore besoin de plus, même si ça commence à sentir le rance si tu veux mon avis.') ON DUPLICATE KEY UPDATE RewardText='Wow, tu es vraiment une meneuse. Tu me fatigues juste à te regarder. Quoi qu\'il en soit, merci de l\'Alliance et tout ça. Je m\'assurerai que toute cette viande morte soit emballée. Je suppose que tu pourrais revenir me voir plus tard pour voir si nous avons encore besoin de plus, même si ça commence à sentir le rance si tu veux mon avis.';
-- Quest 8528 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8528, 'frFR', 'Je suis confiant que tu reviendras bientôt avec le jaune-tail moucheté dont nous avons discuté.') ON DUPLICATE KEY UPDATE CompletionText='Je suis confiant que tu reviendras bientôt avec le jaune-tail moucheté dont nous avons discuté.';
-- Quest 8528 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8528, 'frFR', 'Merci pour ce cadeau, $c, et de manière si opportune. Nos soldats ne manqueront certainement pas de nourriture. Laisse-moi juste stocker ces poissons correctement et ensuite toi et moi nous pourrons discuter d\'une deuxième récolte si tu es d\'accord.') ON DUPLICATE KEY UPDATE RewardText='Merci pour ce cadeau, $c, et de manière si opportune. Nos soldats ne manqueront certainement pas de nourriture. Laisse-moi juste stocker ces poissons correctement et ensuite toi et moi nous pourrons discuter d\'une deuxième récolte si tu es d\'accord.';
-- Quest 8529 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8529, 'frFR', 'Si tu es toujours d\'accord, j\'aimerais t\'envoyer de nouveau pour ramener une autre cargaison de jaune-tail moucheté, $N. J\'imagine qu\'avec l\'expertise que tu as acquise la première fois, cette prise devrait être beaucoup plus rapide et plus facile. Tu es partant ?') ON DUPLICATE KEY UPDATE CompletionText='Si tu es toujours d\'accord, j\'aimerais t\'envoyer de nouveau pour ramener une autre cargaison de jaune-tail moucheté, $N. J\'imagine qu\'avec l\'expertise que tu as acquise la première fois, cette prise devrait être beaucoup plus rapide et plus facile. Tu es partant ?';
-- Quest 8529 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8529, 'frFR', 'Tu es un vrai membre de l\'Alliance, $N. Tes efforts ne passeront pas inaperçus, ni inappréciés. Et merci aussi d\'avoir préparé le poisson. Je m\'assurerai qu\'ils soient stockés correctement, et ensuite je devrai mettre à jour mon décompte. Chacun nous rapproche de notre objectif.') ON DUPLICATE KEY UPDATE RewardText='Tu es un vrai membre de l\'Alliance, $N. Tes efforts ne passeront pas inaperçus, ni inappréciés. Et merci aussi d\'avoir préparé le poisson. Je m\'assurerai qu\'ils soient stockés correctement, et ensuite je devrai mettre à jour mon décompte. Chacun nous rapproche de notre objectif.';
-- Quest 8532 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8532, 'frFR', 'J\'espère que ce sont les vingt barres de cuivre que tu as avec toi, $C.') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que ce sont les vingt barres de cuivre que tu as avec toi, $C.';
-- Quest 8532 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8532, 'frFR', 'Ces barres feront l\'affaire, et merci de ne pas les faire briller. Il n\'y a pas de sens à les rendre jolies quand elles vont être mutilées pour le matériel qui doit être construit pour la guerre. Je m\'occuperai de les mettre sur les piles, et je m\'assurerai qu\'elles soient utilisées correctement. Parle-moi à nouveau si tu es intéressé à en apporter vingt autres.') ON DUPLICATE KEY UPDATE RewardText='Ces barres feront l\'affaire, et merci de ne pas les faire briller. Il n\'y a pas de sens à les rendre jolies quand elles vont être mutilées pour le matériel qui doit être construit pour la guerre. Je m\'occuperai de les mettre sur les piles, et je m\'assurerai qu\'elles soient utilisées correctement. Parle-moi à nouveau si tu es intéressé à en apporter vingt autres.';
-- Quest 8533 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8533, 'frFR', 'De retour si vite ? Tu seras un vrai mineur en un rien de temps, $C. Alors, tu connais déjà la procédure ; je veux que tu ailles, que tu mines une montagne de minerai de cuivre, que tu le fondes en barres et que tu me le ramènes ici. Je sais que c\'est quelque chose que tu es capable de faire, la question est, es-tu prêt ?') ON DUPLICATE KEY UPDATE CompletionText='De retour si vite ? Tu seras un vrai mineur en un rien de temps, $C. Alors, tu connais déjà la procédure ; je veux que tu ailles, que tu mines une montagne de minerai de cuivre, que tu le fondes en barres et que tu me le ramènes ici. Je sais que c\'est quelque chose que tu es capable de faire, la question est, es-tu prêt ?';
-- Quest 8533 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8533, 'frFR', 'Tu t\'es prouvé à moi encore une fois, $c. Je m\'assurerai que ce cuivre soit utilisé en temps voulu. Pour l\'instant cependant, je dois mettre ces barres de cuivre sur la palette et les comptabiliser. Si tu y tiens toujours, je pourrais peut-être avoir besoin de ton aide pour rassembler encore plus de barres de cuivre.') ON DUPLICATE KEY UPDATE RewardText='Tu t\'es prouvé à moi encore une fois, $c. Je m\'assurerai que ce cuivre soit utilisé en temps voulu. Pour l\'instant cependant, je dois mettre ces barres de cuivre sur la palette et les comptabiliser. Si tu y tiens toujours, je pourrais peut-être avoir besoin de ton aide pour rassembler encore plus de barres de cuivre.';
-- Quest 8534 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8534, 'frFR', 'Tu trouveras Scout Azenel à l\'intérieur de Hive\'Zora. Dépêche-toi, $N! Le temps presse.') ON DUPLICATE KEY UPDATE CompletionText='Tu trouveras Scout Azenel à l\'intérieur de Hive\'Zora. Dépêche-toi, $N! Le temps presse.';
-- Quest 8534 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8534, 'frFR', 'Tes efforts sont grandement appréciés, <name>.  Je lirai ces rapports de reconnaissance immédiatement, n\'hésite pas à passer à ta prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Tes efforts sont grandement appréciés, <name>.  Je lirai ces rapports de reconnaissance immédiatement, n\'hésite pas à passer à ta prochaine mission.';

-- Quest 8535 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8535, 'frFR', 'Bien joué, <name>.  Voici votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name>.  Voici votre prochaine mission.';
-- Quest 8536 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8536, 'frFR', 'Bien joué, $N. Voici votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N. Voici votre prochaine mission.';
-- Quest 8537 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8537, 'frFR', 'Bien joué, $N. Voici votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N. Voici votre prochaine mission.';
-- Quest 8538 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8538, 'frFR', 'Vous avez accompli un grand exploit pour notre cause aujourd\'hui, $N. Vous avez vaincu certains de nos ennemis les plus puissants. Je vous en suis très reconnaissant.') ON DUPLICATE KEY UPDATE RewardText='Vous avez accompli un grand exploit pour notre cause aujourd\'hui, $N. Vous avez vaincu certains de nos ennemis les plus puissants. Je vous en suis très reconnaissant.';
-- Quest 8539 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8539, 'frFR', 'Vous avez quelque chose à me dire, $C?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez quelque chose à me dire, $C?';
-- Quest 8539 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8539, 'frFR', 'Excellent travail, <name>.  Vous êtes un allié digne.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>.  Vous êtes un allié digne.';
-- Quest 8540 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8540, 'frFR', 'Excellent. Nous avions besoin de ceux-ci, $N. Bon travail.') ON DUPLICATE KEY UPDATE RewardText='Excellent. Nous avions besoin de ceux-ci, $N. Bon travail.';
-- Quest 8541 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8541, 'frFR', 'Excellent.  Nous avions besoin de ceux-ci, <name>.  Bon travail.') ON DUPLICATE KEY UPDATE RewardText='Excellent.  Nous avions besoin de ceux-ci, <name>.  Bon travail.';
-- Quest 8542 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8542, 'frFR', 'Les ouvriers de la drague sont une menace sérieuse et doivent être traités rapidement !') ON DUPLICATE KEY UPDATE CompletionText='Les ouvriers de la drague sont une menace sérieuse et doivent être traités rapidement !';
-- Quest 8542 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8542, 'frFR', 'J\'ai votre sincère gratitude. Vos efforts pour aider Cenarion Hold ont montré un courage véritable.') ON DUPLICATE KEY UPDATE RewardText='J\'ai votre sincère gratitude. Vos efforts pour aider Cenarion Hold ont montré un courage véritable.';
-- Quest 8543 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8543, 'frFR', 'Très bien, je vois que vous êtes sérieux au sujet de la guerre. Je suis un peu impatient que cela commence, car je suis sûr que vous l\'êtes aussi, $C. Ce sera glorieux quand cela commencera. La Horde traversant les sables du désert de Silithus, les armes en main, chargeant tête baissée dans les masses d\'insectes. Quel grand honneur sera ce jour-là pour tous !$B$BHar! Mais d\'abord, nous avons besoin de plus de barres de étain. Drôle de voir comme une si petite chose peut faire une si grande différence, ne pensez-vous pas ?') ON DUPLICATE KEY UPDATE CompletionText='Très bien, je vois que vous êtes sérieux au sujet de la guerre. Je suis un peu impatient que cela commence, car je suis sûr que vous l\'êtes aussi, $C. Ce sera glorieux quand cela commencera. La Horde traversant les sables du désert de Silithus, les armes en main, chargeant tête baissée dans les masses d\'insectes. Quel grand honneur sera ce jour-là pour tous !$B$BHar! Mais d\'abord, nous avons besoin de plus de barres de étain. Drôle de voir comme une si petite chose peut faire une si grande différence, ne pensez-vous pas ?';
-- Quest 8543 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8543, 'frFR', 'Throm\'ka, $N. Vous m\'honorez et la Horde avec vos barres d\'étain. Je les mettrai dans la pile et ensuite ils viendront en faire des choses avec. Et puis quand tout sera fait, nous irons à la guerre et montrerons à l\'Alliance puce comment se battre contre les insectes.$B$BRamène-moi plus de barres d\'étain !') ON DUPLICATE KEY UPDATE RewardText='Throm\'ka, $N. Vous m\'honorez et la Horde avec vos barres d\'étain. Je les mettrai dans la pile et ensuite ils viendront en faire des choses avec. Et puis quand tout sera fait, nous irons à la guerre et montrerons à l\'Alliance puce comment se battre contre les insectes.$B$BRamène-moi plus de barres d\'étain !';
-- Quest 8544 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8544, 'frFR', 'Avez-vous collecté les composants dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous collecté les composants dont j\'ai besoin ?';
-- Quest 8545 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8545, 'frFR', 'Ce serait bien d\'avoir toutes les barres de mithril dont nous avons besoin pour l\'effort de guerre d\'Ahn\'Qiraj. Est-ce pour ça que vous êtes revenu, mon ? Tu as mes barres ?') ON DUPLICATE KEY UPDATE CompletionText='Ce serait bien d\'avoir toutes les barres de mithril dont nous avons besoin pour l\'effort de guerre d\'Ahn\'Qiraj. Est-ce pour ça que vous êtes revenu, mon ? Tu as mes barres ?';
-- Quest 8545 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8545, 'frFR', 'C\'est un bon début pour toi et moi, $c. Il y a encore vingt barres de mithril que je peux mettre dans les piles et cocher sur la liste. Tout sera utilisé pour faire le matériel de guerre.$B$BJe m\'assure que tu reviens me voir parce que tu sais qu\'il semble que nous aurons besoin de plus de ces barres de mithril.') ON DUPLICATE KEY UPDATE RewardText='C\'est un bon début pour toi et moi, $c. Il y a encore vingt barres de mithril que je peux mettre dans les piles et cocher sur la liste. Tout sera utilisé pour faire le matériel de guerre.$B$BJe m\'assure que tu reviens me voir parce que tu sais qu\'il semble que nous aurons besoin de plus de ces barres de mithril.';

-- Quest 8546 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8546, 'frFR', 'Oui, je suis heureux que vous soyez là, mon. Vous m\'avez aidé avant, et maintenant j\'ai besoin de votre aide à nouveau. Nous cherchons toujours à apporter plus de barres de mithril pour l\'effort de guerre ; nous allons construire beaucoup d\'armures et d\'armes et de choses pour écraser ces insectes à Ahn\'Qiraj.$B$BSi vous êtes un vrai ami, vous m\'apportez plus de piles de barres de mithril. Je prends tout ce que vous avez jusqu\'à ce que nous atteignions notre quota. En avez-vous pour moi maintenant ?') ON DUPLICATE KEY UPDATE CompletionText='Oui, je suis heureux que vous soyez là, mon. Vous m\'avez aidé avant, et maintenant j\'ai besoin de votre aide à nouveau. Nous cherchons toujours à apporter plus de barres de mithril pour l\'effort de guerre ; nous allons construire beaucoup d\'armures et d\'armes et de choses pour écraser ces insectes à Ahn\'Qiraj.$B$BSi vous êtes un vrai ami, vous m\'apportez plus de piles de barres de mithril. Je prends tout ce que vous avez jusqu\'à ce que nous atteignions notre quota. En avez-vous pour moi maintenant ?';
-- Quest 8546 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8546, 'frFR', 'C\'est du bon travail $N! Vingt autres barres nous rapprochent beaucoup plus de l\'objectif, et nous fournissent plus de matériel de guerre. Je veille à ce qu\'ils soient mis de côté. Et si vous obtenez une autre pile de barres de mithril mon, assurez-vous de les apporter ici à moi.') ON DUPLICATE KEY UPDATE RewardText='C\'est du bon travail $N! Vingt autres barres nous rapprochent beaucoup plus de l\'objectif, et nous fournissent plus de matériel de guerre. Je veille à ce qu\'ils soient mis de côté. Et si vous obtenez une autre pile de barres de mithril mon, assurez-vous de les apporter ici à moi.';
-- Quest 8547 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8547, 'frFR', 'Salutations ! C\'est un plaisir de vous rencontrer !$B$BI vois que vous avez un bon d\'achat spécial. Donnez-le-moi et je vous offrirai quelque chose en échange.') ON DUPLICATE KEY UPDATE CompletionText='Salutations ! C\'est un plaisir de vous rencontrer !$B$BI vois que vous avez un bon d\'achat spécial. Donnez-le-moi et je vous offrirai quelque chose en échange.';
-- Quest 8547 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8547, 'frFR', 'Vous êtes en effet un héros spécial, $N. Nous vous souhaitons la bienvenue dans le monde d\'Azeroth, et vous offrons l\'un de ces cadeaux uniques !') ON DUPLICATE KEY UPDATE RewardText='Vous êtes en effet un héros spécial, $N. Nous vous souhaitons la bienvenue dans le monde d\'Azeroth, et vous offrons l\'un de ces cadeaux uniques !';
-- Quest 8548 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8548, 'frFR', 'Il est dans notre meilleur intérêt de garder nos alliés les plus loyaux bien équipés, $N.') ON DUPLICATE KEY UPDATE CompletionText='Il est dans notre meilleur intérêt de garder nos alliés les plus loyaux bien équipés, $N.';
-- Quest 8548 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8548, 'frFR', 'Bon travail, $N. Veuillez accepter ceci au nom du Cercle de Cenarion. Vous l\'avez certainement mérité, ami !') ON DUPLICATE KEY UPDATE RewardText='Bon travail, $N. Veuillez accepter ceci au nom du Cercle de Cenarion. Vous l\'avez certainement mérité, ami !';
-- Quest 8549 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8549, 'frFR', 'Ce ne fut pas une tâche facile, pourtant vous avez excellé. Mais ne soyez pas trop rapide à penser que vous m\'avez impressionné, $N.') ON DUPLICATE KEY UPDATE RewardText='Ce ne fut pas une tâche facile, pourtant vous avez excellé. Mais ne soyez pas trop rapide à penser que vous m\'avez impressionné, $N.';
-- Quest 8550 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8550, 'frFR', 'Bonjour à nouveau, $N. Je suis heureux que vous souhaitiez me parler une fois de plus concernant notre besoin sans fin de fleur de paix. L\'effort de guerre continue, et avec lui notre production de potions et d\'élixirs pour aider dans les batailles à venir. Nous aiderez-vous à nouveau, $C? J\'ai besoin de la même quantité de fleur de paix que précédemment, donc si vous pouvez la cueillir et me la rendre ici, je vous en serais très reconnaissant. Bien sûr, si vous l\'avez déjà sur vous, je serai plus qu\'heureux de l\'accepter de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau, $N. Je suis heureux que vous souhaitiez me parler une fois de plus concernant notre besoin sans fin de fleur de paix. L\'effort de guerre continue, et avec lui notre production de potions et d\'élixirs pour aider dans les batailles à venir. Nous aiderez-vous à nouveau, $C? J\'ai besoin de la même quantité de fleur de paix que précédemment, donc si vous pouvez la cueillir et me la rendre ici, je vous en serais très reconnaissant. Bien sûr, si vous l\'avez déjà sur vous, je serai plus qu\'heureux de l\'accepter de vous maintenant.';
-- Quest 8550 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8550, 'frFR', 'Merci pour vos efforts continus, $N. Vous apportez un grand honneur à vous-même et à vos ancêtres par votre don désintéressé, et cela sera connu de tous ! Je stockerai ces herbes afin qu\'elles restent fraîches jusqu\'à ce qu\'elles soient nécessaires. Une fois de plus, vous révélez l\'esprit le plus vrai de la Horde, la lutte pour surmonter et la promesse que nous pouvons travailler ensemble pour le faire.') ON DUPLICATE KEY UPDATE RewardText='Merci pour vos efforts continus, $N. Vous apportez un grand honneur à vous-même et à vos ancêtres par votre don désintéressé, et cela sera connu de tous ! Je stockerai ces herbes afin qu\'elles restent fraîches jusqu\'à ce qu\'elles soient nécessaires. Une fois de plus, vous révélez l\'esprit le plus vrai de la Horde, la lutte pour surmonter et la promesse que nous pouvons travailler ensemble pour le faire.';
-- Quest 8551 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8551, 'frFR', 'Allô, $N! As-tu trouvé Gorlash ? Ce coffre était mon préféré, et il contenait un compartiment caché qui abritait mes plus grands trésors !') ON DUPLICATE KEY UPDATE CompletionText='Allô, $N! As-tu trouvé Gorlash ? Ce coffre était mon préféré, et il contenait un compartiment caché qui abritait mes plus grands trésors !';
-- Quest 8554 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8554, 'frFR', 'Tu as pris mon rapière de Negolash !  Je ne peux croire ma fortune, <name>!  Te rencontrer a changé ma chance pour le mieux, ne le conteste pas !$B$BMerci !  Et si j\'ai un jour un nouveau navire et que tu cherches à naviguer sur les mers, tu seras mon invité d\'honneur.') ON DUPLICATE KEY UPDATE RewardText='Tu as pris mon rapière de Negolash !  Je ne peux croire ma fortune, <name>!  Te rencontrer a changé ma chance pour le mieux, ne le conteste pas !$B$BMerci !  Et si j\'ai un jour un nouveau navire et que tu cherches à naviguer sur les mers, tu seras mon invité d\'honneur.';
-- Quest 8555 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8555, 'frFR', 'Eranikus, Vaelastrasz et Azuregos... Sans aucun doute, vous connaissez ces dragons, mortel. Ce n\'est pas une coïncidence, alors, qu\'ils aient joué des rôles si influents en tant que gardiens de notre monde.$B$BMalheureusement (et ma propre naïveté en est en partie responsable) que ce soit par des agents des Anciens Dieux ou par la trahison de ceux qui appelleraient ces derniers amis, chaque gardien est tombé dans la tragédie. L\'étendue de cela a alimenté ma propre méfiance envers votre espèce.$B$BCherche-les... Et $R, prépare-toi au pire.') ON DUPLICATE KEY UPDATE RewardText='Eranikus, Vaelastrasz et Azuregos... Sans aucun doute, vous connaissez ces dragons, mortel. Ce n\'est pas une coïncidence, alors, qu\'ils aient joué des rôles si influents en tant que gardiens de notre monde.$B$BMalheureusement (et ma propre naïveté en est en partie responsable) que ce soit par des agents des Anciens Dieux ou par la trahison de ceux qui appelleraient ces derniers amis, chaque gardien est tombé dans la tragédie. L\'étendue de cela a alimenté ma propre méfiance envers votre espèce.$B$BCherche-les... Et $R, prépare-toi au pire.';
-- Quest 8556 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8556, 'frFR', 'M\'as-tu apporté la bague et les matériaux, $N?') ON DUPLICATE KEY UPDATE CompletionText='M\'as-tu apporté la bague et les matériaux, $N?';
-- Quest 8556 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8556, 'frFR', 'Je vais échanger la gemme sur la bague pour toi.  Tu trouveras que l\'effet est beaucoup plus... agréable.') ON DUPLICATE KEY UPDATE RewardText='Je vais échanger la gemme sur la bague pour toi.  Tu trouveras que l\'effet est beaucoup plus... agréable.';
-- Quest 8557 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8557, 'frFR', 'As-tu apporté les matériaux pour la cape, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les matériaux pour la cape, $N?';

-- Quest 8557 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8557, 'frFR', 'Ah oui... ce drapé est immaculé.$B$BPrends cette cape, <name>.  Qu\'elle te protège de la magie vile des Qiraji.') ON DUPLICATE KEY UPDATE RewardText='Ah oui... ce drapé est immaculé.$B$BPrends cette cape, <name>.  Qu\'elle te protège de la magie vile des Qiraji.';
-- Quest 8558 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8558, 'frFR', 'As-tu apporté les composants dont j\'ai besoin, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les composants dont j\'ai besoin, $N?';
-- Quest 8558 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8558, 'frFR', 'Tu as bien fait, $Gclass>.  Ceci est un pommeau de maître... l\'équilibre est parfait.$B<br :>Prends ton arme, <name.  Manie-la avec une grande confiance et vaincs nos ennemis!') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait, $Gclass>.  Ceci est un pommeau de maître... l\'équilibre est parfait.$B<br :>Prends ton arme, <name.  Manie-la avec une grande confiance et vaincs nos ennemis!';
-- Quest 8559 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8559, 'frFR', 'Tu as acquis les objets que j\'ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='Tu as acquis les objets que j\'ai demandés, $N?';
-- Quest 8559 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8559, 'frFR', 'Tu as bien fait, <name>.  Tu as prouvé que tu n\'étais pas un mortel ordinaire.$B$BI te donne ceci avec la confiance qu\'il t\'aidera à écraser les vile qiraji.') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait, <name>.  Tu as prouvé que tu n\'étais pas un mortel ordinaire.$B$BI te donne ceci avec la confiance qu\'il t\'aidera à écraser les vile qiraji.';
-- Quest 8560 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8560, 'frFR', 'As-tu apporté les composants dont j\'ai besoin, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les composants dont j\'ai besoin, $N?';
-- Quest 8560 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8560, 'frFR', 'Oui... la peau du ver fera une excellente couche protectrice.  Combinée aux meilleures parties des Qiraji que nous avons détruits en chemin, ceci devrait faire une armure formidable.  Qu\'elle t\'aide à faire face aux horreurs indicibles qui t\'attendent à l\'intérieur!') ON DUPLICATE KEY UPDATE RewardText='Oui... la peau du ver fera une excellente couche protectrice.  Combinée aux meilleures parties des Qiraji que nous avons détruits en chemin, ceci devrait faire une armure formidable.  Qu\'elle t\'aide à faire face aux horreurs indicibles qui t\'attendent à l\'intérieur!';
-- Quest 8561 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8561, 'frFR', 'As-tu apporté les composants que j\'ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les composants que j\'ai demandés, $N?';
-- Quest 8561 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8561, 'frFR', 'Tu as réussi!  Les murmures des Deux Empereurs ont cessé.$B$BPrends ceci comme récompense.  La simple vue de cela inspirera la peur dans le cœur des Qiraji... cela leur rappellera leurs dirigeants tombés et le mortel qui les a abattus.') ON DUPLICATE KEY UPDATE RewardText='Tu as réussi!  Les murmures des Deux Empereurs ont cessé.$B$BPrends ceci comme récompense.  La simple vue de cela inspirera la peur dans le cœur des Qiraji... cela leur rappellera leurs dirigeants tombés et le mortel qui les a abattus.';
-- Quest 8562 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8562, 'frFR', 'Dans son demeure à Ahn\'Qiraj, C\'Thun redoutable attend dans son sommeil.') ON DUPLICATE KEY UPDATE CompletionText='Dans son demeure à Ahn\'Qiraj, C\'Thun redoutable attend dans son sommeil.';
-- Quest 8563 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8563, 'frFR', '<name> - ton nom m\'est parvenu comme celui qui cherche un maître dans les voies de l\'<class>.  Tu as l\'air capable, mais je cherche plus que de l\'apparence chez mes élèves.  Tu dois être prêt à plonger là où les autres ont peur de regarder pour acquérir ta puissance.  Je t\'apprendrai, mais je ne tolérerai pas l\'échec.$B$BIl y aura des coûts monétaires associés à ton entraînement, mais tu devrais être plus préoccupé par le coût que ton esprit est prêt à payer.  Si tu es prêt, nous commencerons.') ON DUPLICATE KEY UPDATE RewardText='<name> - ton nom m\'est parvenu comme celui qui cherche un maître dans les voies de l\'<class>.  Tu as l\'air capable, mais je cherche plus que de l\'apparence chez mes élèves.  Tu dois être prêt à plonger là où les autres ont peur de regarder pour acquérir ta puissance.  Je t\'apprendrai, mais je ne tolérerai pas l\'échec.$B$BIl y aura des coûts monétaires associés à ton entraînement, mais tu devrais être plus préoccupé par le coût que ton esprit est prêt à payer.  Si tu es prêt, nous commencerons.';
-- Quest 8572 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8572, 'frFR', 'Il est dans notre intérêt de garder nos alliés les plus loyaux bien équipés, $N.') ON DUPLICATE KEY UPDATE CompletionText='Il est dans notre intérêt de garder nos alliés les plus loyaux bien équipés, $N.';
