-- Quest 8575 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8575, 'frFR', 'Ooooh ! Petite chose qui pulse magiquement ! Pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Ooooh ! Petite chose qui pulse magiquement ! Pour moi ?';
-- Quest 8575 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8575, 'frFR', '<Narain examine la lettre avec enthousiasme.>$B$BExtraordinaire, $R! Qu\'est-ce que c\'est ? Je ne comprends rien au draconique.') ON DUPLICATE KEY UPDATE RewardText='<Narain examine la lettre avec enthousiasme.>$B$BExtraordinaire, $R! Qu\'est-ce que c\'est ? Je ne comprends rien au draconique.';
-- Quest 8576 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8576, 'frFR', 'Première chose, $N! Nous devons savoir ce qu\'Azuregos a écrit dans ce registre.$B$BTu dis qu\'il t\'a demandé de fabriquer une bouée en arcanite et que voici le schéma ? C\'est étrange qu\'il écrive cela en draconique. Ce vieux bougre sait que je ne peux pas lire ces absurdités.$B$BSi c\'est censé fonctionner, j\'aurai besoin de mes lunettes de divination, d\'un poulet de cinq cents livres et du volume II de "Draconique pour les nuls". Pas nécessairement dans cet ordre.') ON DUPLICATE KEY UPDATE RewardText='Première chose, $N! Nous devons savoir ce qu\'Azuregos a écrit dans ce registre.$B$BTu dis qu\'il t\'a demandé de fabriquer une bouée en arcanite et que voici le schéma ? C\'est étrange qu\'il écrive cela en draconique. Ce vieux bougre sait que je ne peux pas lire ces absurdités.$B$BSi c\'est censé fonctionner, j\'aurai besoin de mes lunettes de divination, d\'un poulet de cinq cents livres et du volume II de "Draconique pour les nuls". Pas nécessairement dans cet ordre.';
-- Quest 8578 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8578, 'frFR', 'Le Cœur Molten, hein ? J\'espère que mes lunettes sont toujours en état !') ON DUPLICATE KEY UPDATE CompletionText='Le Cœur Molten, hein ? J\'espère que mes lunettes sont toujours en état !';
-- Quest 8578 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8578, 'frFR', 'Extraordinaire ! Maintenant, où ai-je mis ce poulet de 500 livres et le volume II de "Draconique Pour les nuls"??? Oh, et voici un petit quelque chose pour tout ton travail acharné !') ON DUPLICATE KEY UPDATE RewardText='Extraordinaire ! Maintenant, où ai-je mis ce poulet de 500 livres et le volume II de "Draconique Pour les nuls"??? Oh, et voici un petit quelque chose pour tout ton travail acharné !';
-- Quest 8580 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8580, 'frFR', 'As-tu fini de collecter ces échantillons ? Nous pourrions perdre Noggle à tout moment !') ON DUPLICATE KEY UPDATE CompletionText='As-tu fini de collecter ces échantillons ? Nous pourrions perdre Noggle à tout moment !';
-- Quest 8580 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8580, 'frFR', 'Croise les doigts, ami ! Vivement qu\'on puisse sauver Noggle !') ON DUPLICATE KEY UPDATE RewardText='Croise les doigts, ami ! Vivement qu\'on puisse sauver Noggle !';
-- Quest 8581 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8581, 'frFR', 'Pele\'keiki sait que tu viens aider. Apporte beaucoup de firebloom et rends-le très heureux. Pele\'keiki pourrait fabriquer de grosses bombes avec du firebloom. Jette-les sur les insectes de son bâton au-dessus d\'Ahn\'Qiraj quand la guerre arrivera. Mais Pele\'keiki a besoin de plus de firebloom, $C!$B$BTu vas apporter ce firebloom à Pele\'keiki, vite maintenant. Reviens avec au moins autant que la dernière fois, et Pele\'keiki sera content.') ON DUPLICATE KEY UPDATE CompletionText='Pele\'keiki sait que tu viens aider. Apporte beaucoup de firebloom et rends-le très heureux. Pele\'keiki pourrait fabriquer de grosses bombes avec du firebloom. Jette-les sur les insectes de son bâton au-dessus d\'Ahn\'Qiraj quand la guerre arrivera. Mais Pele\'keiki a besoin de plus de firebloom, $C!$B$BTu vas apporter ce firebloom à Pele\'keiki, vite maintenant. Reviens avec au moins autant que la dernière fois, et Pele\'keiki sera content.';
-- Quest 8581 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8581, 'frFR', 'Ce n\'est pas une blague, $C ? Tu apportes du firebloom à Pele\'keiki aussi vite ? Pele\'keiki les compte tout de suite, mon ! Tu rends Pele\'keiki si heureux, il va dire à tout le monde, $N le meilleur collecteur de firebloom ! Pele\'keiki ne peut pas attendre le début de la guerre. Maintenant, on illumine vraiment le ciel au-dessus de Silithus, n\'est-ce pas, bruddah ?!') ON DUPLICATE KEY UPDATE RewardText='Ce n\'est pas une blague, $C ? Tu apportes du firebloom à Pele\'keiki aussi vite ? Pele\'keiki les compte tout de suite, mon ! Tu rends Pele\'keiki si heureux, il va dire à tout le monde, $N le meilleur collecteur de firebloom ! Pele\'keiki ne peut pas attendre le début de la guerre. Maintenant, on illumine vraiment le ciel au-dessus de Silithus, n\'est-ce pas, bruddah ?!';
-- Quest 8582 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8582, 'frFR', 'As-tu trouvé l\'Ambassadeur, $N ? Est-il mort?$B$BNous ne pouvons pas nous permettre de laisser le Fléau prendre pied à Kalimdor. Ils représentent une menace suffisante pour nos propres frontières pour devoir nous en occuper sur deux fronts.$B$BLe seul signe optimiste des événements que tu m\'as rapportés est que la vieille femme semblait incorruptible. Elle doit savoir au plus profond de son être que le Fléau peut apporter un grand pouvoir, mais que les Barrens ne lui appartiennent pas vraiment si elle acceptait leur accord.') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé l\'Ambassadeur, $N ? Est-il mort?$B$BNous ne pouvons pas nous permettre de laisser le Fléau prendre pied à Kalimdor. Ils représentent une menace suffisante pour nos propres frontières pour devoir nous en occuper sur deux fronts.$B$BLe seul signe optimiste des événements que tu m\'as rapportés est que la vieille femme semblait incorruptible. Elle doit savoir au plus profond de son être que le Fléau peut apporter un grand pouvoir, mais que les Barrens ne lui appartiennent pas vraiment si elle acceptait leur accord.';
-- Quest 8582 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8582, 'frFR', 'Bien. Bien joué, $c.$B$BMaintenant que Malcin est mort, nous pouvons au moins savoir que les avancées des Scourges seront stoppées. La Dame Noire te remercie pour tes efforts et souhaite te récompenser avec un cadeau.$B$BBien que nous ne connaissions pas l\'étendue de l\'influence des Scourges dans les Downs, je suis sûr que nous découvrirons leurs complots bientôt.') ON DUPLICATE KEY UPDATE RewardText='Bien. Bien joué, $c.$B$BMaintenant que Malcin est mort, nous pouvons au moins savoir que les avancées des Scourges seront stoppées. La Dame Noire te remercie pour tes efforts et souhaite te récompenser avec un cadeau.$B$BBien que nous ne connaissions pas l\'étendue de l\'influence des Scourges dans les Downs, je suis sûr que nous découvrirons leurs complots bientôt.';
-- Quest 8583 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8583, 'frFR', 'En fait, il semble que nous ayons besoin de plus de lotus pourpre, $c.$ Bien que mes propres études n\'aient pas encore déterminé d\'application utile nouvelle pour l\'herbe, il existe des méthodologies éprouvées à employer.$B$J\'ai besoin que tu retournes sur le terrain et que tu collectes au moins vingt échantillons de lotus pourpre. Ramène-les-moi ici.') ON DUPLICATE KEY UPDATE CompletionText='En fait, il semble que nous ayons besoin de plus de lotus pourpre, $c.$ Bien que mes propres études n\'aient pas encore déterminé d\'application utile nouvelle pour l\'herbe, il existe des méthodologies éprouvées à employer.$B$J\'ai besoin que tu retournes sur le terrain et que tu collectes au moins vingt échantillons de lotus pourpre. Ramène-les-moi ici.';
-- Quest 8583 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8583, 'frFR', 'Excellent travail, précis, $N. Ta diligence est à louer, tout comme ta célérité. Je veillerai personnellement à ce qu\'aucun de ces lotus pourpre ne soit gaspillé.$B$BMerci encore, et si tu trouves plus de lotus pourpre, n\'hésite pas à me les apporter avec la plus grande hâte.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, précis, $N. Ta diligence est à louer, tout comme ta célérité. Je veillerai personnellement à ce qu\'aucun de ces lotus pourpre ne soit gaspillé.$B$BMerci encore, et si tu trouves plus de lotus pourpre, n\'hésite pas à me les apporter avec la plus grande hâte.';

-- Quest 8586 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8586, 'frFR', 'Dépêche-toi, gamin. Nous ne voulons pas que cette viande pourrisse.') ON DUPLICATE KEY UPDATE CompletionText='Dépêche-toi, gamin. Nous ne voulons pas que cette viande pourrisse.';
-- Quest 8587 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8587, 'frFR', 'Quelle est cette odeur délicieuse ?') ON DUPLICATE KEY UPDATE CompletionText='Quelle est cette odeur délicieuse ?';
-- Quest 8588 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8588, 'frFR', 'Je n\'ai pas le temps pour les jeux si tu es juste là pour jacasser, $C. Il y a trop de piles de cuir lourd qui doivent être apprêtées. Reviens quand tu en as au moins dix pour moi.') ON DUPLICATE KEY UPDATE CompletionText='Je n\'ai pas le temps pour les jeux si tu es juste là pour jacasser, $C. Il y a trop de piles de cuir lourd qui doivent être apprêtées. Reviens quand tu en as au moins dix pour moi.';
-- Quest 8588 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8588, 'frFR', 'Simplement incroyable... regardez la pureté de ces échantillons. Hmm, je me demande ce que cela pourrait signifier. Ils semblent être d\'origine élémentaire, mais... quelque chose de plus. Ils me rappellent... les Anciens Dieux. Nous avons trouvé des traces d\'eux partout dans Azeroth, et maintenant je me demande si ces créatures ne sont pas liées à eux d\'une manière ou d\'une autre.$B$BNous devrons tester davantage.') ON DUPLICATE KEY UPDATE RewardText='Simplement incroyable... regardez la pureté de ces échantillons. Hmm, je me demande ce que cela pourrait signifier. Ils semblent être d\'origine élémentaire, mais... quelque chose de plus. Ils me rappellent... les Anciens Dieux. Nous avons trouvé des traces d\'eux partout dans Azeroth, et maintenant je me demande si ces créatures ne sont pas liées à eux d\'une manière ou d\'une autre.$B$BNous devrons tester davantage.';
-- Quest 8589 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8589, 'frFR', 'C\'est vrai, $c, j\'ai encore besoin de cuir lourd. Les demandes des généraux et de leurs intendants semblent infinies. Et ce n\'est rien comparé à ce que demandent les maîtres des zeppelins !$B$BI dois faire collecter ma quota immédiatement. $n, apporte-moi plus de piles de cuir lourd dès que tu peux !') ON DUPLICATE KEY UPDATE CompletionText='C\'est vrai, $c, j\'ai encore besoin de cuir lourd. Les demandes des généraux et de leurs intendants semblent infinies. Et ce n\'est rien comparé à ce que demandent les maîtres des zeppelins !$B$BI dois faire collecter ma quota immédiatement. $n, apporte-moi plus de piles de cuir lourd dès que tu peux !';
-- Quest 8589 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8589, 'frFR', 'Tu da mon, mon! Merci beaucoup pour le cuir lourd. Chaque petit peu nous rapproche de notre objectif. Je vais juste les mettre en pile pour que les autres travailleurs du cuir puissent commencer à travailler dessus.$B$BMerci encore, $N, et si tu trouves d\'autres piles de cuir lourd, tu sais où me trouver.') ON DUPLICATE KEY UPDATE RewardText='Tu da mon, mon! Merci beaucoup pour le cuir lourd. Chaque petit peu nous rapproche de notre objectif. Je vais juste les mettre en pile pour que les autres travailleurs du cuir puissent commencer à travailler dessus.$B$BMerci encore, $N, et si tu trouves d\'autres piles de cuir lourd, tu sais où me trouver.';
-- Quest 8590 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8590, 'frFR', '$C, es-tu revenu si vite avec les dix peaux épaisses dont nous avons discuté ?') ON DUPLICATE KEY UPDATE CompletionText='$C, es-tu revenu si vite avec les dix peaux épaisses dont nous avons discuté ?';
-- Quest 8590 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8590, 'frFR', 'Bon travail, $c. Je suis sûr que ces peaux épaisses seront utilisées pour renforcer des zeppelins et fabriquer toutes sortes d\'armures et d\'armes. Tu as mes remerciements, et ceux de la Horde. Reviens si tu trouves plus de cuir épais lors de tes voyages, et que la chance soit avec toi.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, $c. Je suis sûr que ces peaux épaisses seront utilisées pour renforcer des zeppelins et fabriquer toutes sortes d\'armures et d\'armes. Tu as mes remerciements, et ceux de la Horde. Reviens si tu trouves plus de cuir épais lors de tes voyages, et que la chance soit avec toi.';
-- Quest 8591 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8591, 'frFR', '$c, comme tu peux le voir, j\'ai encore besoin de rassembler plus de cuir épais. Je te demande à nouveau ton aide pour cette tâche, et je promets que si tu la termines, tu seras reconnu pour tes efforts.$B$BLe temps presse ! Reviens avec le cuir épais afin que nous puissions terminer nos préparatifs et aller à la guerre, héros !') ON DUPLICATE KEY UPDATE CompletionText='$c, comme tu peux le voir, j\'ai encore besoin de rassembler plus de cuir épais. Je te demande à nouveau ton aide pour cette tâche, et je promets que si tu la termines, tu seras reconnu pour tes efforts.$B$BLe temps presse ! Reviens avec le cuir épais afin que nous puissions terminer nos préparatifs et aller à la guerre, héros !';
-- Quest 8591 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8591, 'frFR', 'Tu l\'as fait, $N, je savais que tu le ferais ! Encore une fois, merci au nom de toute la Horde. Tes efforts ont été notés et sont grandement appréciés. Et si tu te retrouves avec plus de cuir épais que tu souhaites donner, apporte-les-moi ici.$B$BLok\'tar Ogar, $c!') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait, $N, je savais que tu le ferais ! Encore une fois, merci au nom de toute la Horde. Tes efforts ont été notés et sont grandement appréciés. Et si tu te retrouves avec plus de cuir épais que tu souhaites donner, apporte-les-moi ici.$B$BLok\'tar Ogar, $c!';
-- Quest 8592 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8592, 'frFR', 'M\'as-tu apporté les composants que j\'ai demandés, $N ?') ON DUPLICATE KEY UPDATE CompletionText='M\'as-tu apporté les composants que j\'ai demandés, $N ?';
-- Quest 8592 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8592, 'frFR', 'Tu as réussi !  Les murmures des Deux Empereurs ont cessé.$B$BPrends ceci comme récompense.  Le simple fait de le voir inspirera la peur dans le cœur des Qiraji... cela leur rappellera leurs dirigeants tombés et celui qui les a tués.') ON DUPLICATE KEY UPDATE RewardText='Tu as réussi !  Les murmures des Deux Empereurs ont cessé.$B$BPrends ceci comme récompense.  Le simple fait de le voir inspirera la peur dans le cœur des Qiraji... cela leur rappellera leurs dirigeants tombés et celui qui les a tués.';
-- Quest 8593 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8593, 'frFR', 'M\'as-tu apporté les composants dont j\'ai besoin, $N ?') ON DUPLICATE KEY UPDATE CompletionText='M\'as-tu apporté les composants dont j\'ai besoin, $N ?';
-- Quest 8593 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8593, 'frFR', 'Oui... la peau du ver fera une excellente couche protectrice.  Combinée avec les parties les plus fortes des Qiraji que nous avons détruits en chemin, cela devrait faire une pièce d\'armure formidable.  Qu\'elle t\'aide à affronter les horreurs indicibles qui t\'attendent à l\'intérieur !') ON DUPLICATE KEY UPDATE RewardText='Oui... la peau du ver fera une excellente couche protectrice.  Combinée avec les parties les plus fortes des Qiraji que nous avons détruits en chemin, cela devrait faire une pièce d\'armure formidable.  Qu\'elle t\'aide à affronter les horreurs indicibles qui t\'attendent à l\'intérieur !';
-- Quest 8594 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8594, 'frFR', 'As-tu collecté les composants dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu collecté les composants dont j\'ai besoin ?';

-- Quest 8594 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8594, 'frFR', 'Avec les matériaux que vous apportez et à partir des écailles de nos ennemis Qiraji tombés, je vous fabrique ces épaulières, mortel.  Puissent-elles vous accorder la protection dont vous avez besoin et que leur vue inspire la peur à nos ennemis.') ON DUPLICATE KEY UPDATE RewardText='Avec les matériaux que vous apportez et à partir des écailles de nos ennemis Qiraji tombés, je vous fabrique ces épaulières, mortel.  Puissent-elles vous accorder la protection dont vous avez besoin et que leur vue inspire la peur à nos ennemis.';
-- Quest 8595 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8595, 'frFR', 'Tuer un seigneur Qiraji est un accomplissement notable pour un mortel, $n. Ils sont cependant nombreux et puissants. Continuez à les vaincre pour prouver votre valeur en tant que champion.') ON DUPLICATE KEY UPDATE CompletionText='Tuer un seigneur Qiraji est un accomplissement notable pour un mortel, $n. Ils sont cependant nombreux et puissants. Continuez à les vaincre pour prouver votre valeur en tant que champion.';
-- Quest 8596 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8596, 'frFR', 'Vous avez acquis les objets que j\'ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez acquis les objets que j\'ai demandés, $N?';
-- Quest 8596 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8596, 'frFR', 'Vous avez bien fait, <name>.  Vous avez prouvé que vous n\'êtes pas un mortel ordinaire.$B$BI vous donne ceci avec la confiance qu\'ils vous aideront à écraser les vilains qiraji.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, <name>.  Vous avez prouvé que vous n\'êtes pas un mortel ordinaire.$B$BI vous donne ceci avec la confiance qu\'ils vous aideront à écraser les vilains qiraji.';
-- Quest 8599 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8599, 'frFR', 'Quoi!?$B$B<Narain commence à s\'agiter.>$B$BEh bien, euh... Qu\'est-ce que tu veux que je fasse??? C\'est un poisson! UN POISSON je te dis! Et je suis un gnome. Ça ne pourrait jamais marcher.') ON DUPLICATE KEY UPDATE RewardText='Quoi!?$B$B<Narain commence à s\'agiter.>$B$BEh bien, euh... Qu\'est-ce que tu veux que je fasse??? C\'est un poisson! UN POISSON je te dis! Et je suis un gnome. Ça ne pourrait jamais marcher.';
-- Quest 8600 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8600, 'frFR', 'Il ne pouvait pas prendre autant de temps pour me trancher dix peaux de cuir robuste ! Peut-être devriez-vous aiguiser votre couteau d\'écorcheur ? Ou, peut-être que je me trompe et que vous les avez dans votre sac ?') ON DUPLICATE KEY UPDATE CompletionText='Il ne pouvait pas prendre autant de temps pour me trancher dix peaux de cuir robuste ! Peut-être devriez-vous aiguiser votre couteau d\'écorcheur ? Ou, peut-être que je me trompe et que vous les avez dans votre sac ?';
-- Quest 8600 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8600, 'frFR', 'Très bien, il semble que vous ayez fait un travail assez décent, bien que certaines de ces peaux aient l\'air un peu rêches sur les bords. Peu importe, la tâche est accomplie, et vous avez gagné votre récompense. Si vous tombez sur un autre tas de cuir robuste, assurez-vous de me les apporter au plus vite.') ON DUPLICATE KEY UPDATE RewardText='Très bien, il semble que vous ayez fait un travail assez décent, bien que certaines de ces peaux aient l\'air un peu rêches sur les bords. Peu importe, la tâche est accomplie, et vous avez gagné votre récompense. Si vous tombez sur un autre tas de cuir robuste, assurez-vous de me les apporter au plus vite.';
-- Quest 8601 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8601, 'frFR', 'Les préparatifs pour la guerre imminente à Ahn\'Qiraj progressent, $C. Cependant, pour nous assurer que nous ne prenions pas de retard, ou du moins que ce n\'est pas moi qui nous fait prendre de retard, je veux que vous rameniez un autre tas de cuir robuste. Votre attention rapide à cette affaire sera grandement appréciée, $N.') ON DUPLICATE KEY UPDATE CompletionText='Les préparatifs pour la guerre imminente à Ahn\'Qiraj progressent, $C. Cependant, pour nous assurer que nous ne prenions pas de retard, ou du moins que ce n\'est pas moi qui nous fait prendre de retard, je veux que vous rameniez un autre tas de cuir robuste. Votre attention rapide à cette affaire sera grandement appréciée, $N.';
-- Quest 8601 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8601, 'frFR', 'Entraînement, entraînement, entraînement. Un couteau bien affûté et la compétence pour l\'utiliser vous mèneront loin dans ce monde, $N. On dirait que les bords de ces peaux sont meilleurs que ceux de la dernière. Avez-vous acheté un nouveau couteau?$B$BDans tous les cas, nous vous remercions pour vos efforts. Votre don a été noté, et sera utilisé à bon escient, je vous l\'assure. Si vous vous retrouvez en possession de plus de cuir robuste, assurez-vous de revenir me parler, car j\'en aurai probablement besoin.') ON DUPLICATE KEY UPDATE RewardText='Entraînement, entraînement, entraînement. Un couteau bien affûté et la compétence pour l\'utiliser vous mèneront loin dans ce monde, $N. On dirait que les bords de ces peaux sont meilleurs que ceux de la dernière. Avez-vous acheté un nouveau couteau?$B$BDans tous les cas, nous vous remercions pour vos efforts. Votre don a été noté, et sera utilisé à bon escient, je vous l\'assure. Si vous vous retrouvez en possession de plus de cuir robuste, assurez-vous de revenir me parler, car j\'en aurai probablement besoin.';
-- Quest 8602 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8602, 'frFR', 'Avez-vous collecté les composants dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous collecté les composants dont j\'ai besoin ?';
-- Quest 8603 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8603, 'frFR', 'Dans sa demeure à Ahn\'Qiraj, C\'Thun attend dans un sommeil d\'horreur.') ON DUPLICATE KEY UPDATE CompletionText='Dans sa demeure à Ahn\'Qiraj, C\'Thun attend dans un sommeil d\'horreur.';
-- Quest 8603 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8603, 'frFR', 'Je ne m\'attendais pas à ce que vous reveniez de votre tentative, <name>.$B$BVous avez accompli un destin plus grand que celui de la plupart des êtres immortels.$B$BEn tuant C\'Thun, vous avez non seulement sauvé tout Azeroth, mais vous avez aussi fait basculer la balance des événements cosmiques au-delà de votre compréhension.$B$BAcceptez ces vêtements comme un symbole de la gloire et du fardeau qui en découlera en conséquence de vos actions.$B$BQue leur pouvoir vous aide dans les défis qui vous attendent, tueur de dieux!') ON DUPLICATE KEY UPDATE RewardText='Je ne m\'attendais pas à ce que vous reveniez de votre tentative, <name>.$B$BVous avez accompli un destin plus grand que celui de la plupart des êtres immortels.$B$BEn tuant C\'Thun, vous avez non seulement sauvé tout Azeroth, mais vous avez aussi fait basculer la balance des événements cosmiques au-delà de votre compréhension.$B$BAcceptez ces vêtements comme un symbole de la gloire et du fardeau qui en découlera en conséquence de vos actions.$B$BQue leur pouvoir vous aide dans les défis qui vous attendent, tueur de dieux!';
-- Quest 8604 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8604, 'frFR', 'Les lanceurs de dragues sont une menace sérieuse et doivent être traités rapidement !') ON DUPLICATE KEY UPDATE CompletionText='Les lanceurs de dragues sont une menace sérieuse et doivent être traités rapidement !';
-- Quest 8604 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8604, 'frFR', 'Vous avez ma sincère gratitude. Vos efforts pour aider Cenarion Hold ont montré un courage véritable.') ON DUPLICATE KEY UPDATE RewardText='Vous avez ma sincère gratitude. Vos efforts pour aider Cenarion Hold ont montré un courage véritable.';
-- Quest 8605 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8605, 'frFR', 'Ravi de vous revoir, $C. Nous travaillons toujours sur les préparatifs ici pour l\'effort de guerre, et je peux encore utiliser toute l\'aide que vous pouvez apporter en rassemblant des bandages de laine. Toute assistance sera grandement appréciée. J\'espère seulement que nos efforts seront suffisants. J\'ai perdu trop d\'âmes nobles sur les champs de bataille d\'hier pour ne pas faire tout ce qui est en mon pouvoir pour m\'assurer que cela ne se reproduise pas.') ON DUPLICATE KEY UPDATE CompletionText='Ravi de vous revoir, $C. Nous travaillons toujours sur les préparatifs ici pour l\'effort de guerre, et je peux encore utiliser toute l\'aide que vous pouvez apporter en rassemblant des bandages de laine. Toute assistance sera grandement appréciée. J\'espère seulement que nos efforts seront suffisants. J\'ai perdu trop d\'âmes nobles sur les champs de bataille d\'hier pour ne pas faire tout ce qui est en mon pouvoir pour m\'assurer que cela ne se reproduise pas.';

-- Quest 8605 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8605, 'frFR', 'Tu es un $C$ honorable, $N! Je veillerai à ce que ces bandages arrivent aux bonnes mains. Vous avez ma gratitude, et celle de la Horde.$B$BAllez en paix, et revenez-moi si vous vous retrouvez avec un surplus de bandages en laine. Nous pouvons utiliser toute l\'aide que nous pouvons obtenir ici.') ON DUPLICATE KEY UPDATE RewardText='Tu es un $C$ honorable, $N! Je veillerai à ce que ces bandages arrivent aux bonnes mains. Vous avez ma gratitude, et celle de la Horde.$B$BAllez en paix, et revenez-moi si vous vous retrouvez avec un surplus de bandages en laine. Nous pouvons utiliser toute l\'aide que nous pouvons obtenir ici.';
-- Quest 8607 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8607, 'frFR', 'Ne me décevez pas et ne me fasse pas passer pour un mauvais, $C! Revenez ici le plus rapidement possible avec les bandages en mageweave dont nous avons discuté.') ON DUPLICATE KEY UPDATE CompletionText='Ne me décevez pas et ne me fasse pas passer pour un mauvais, $C! Revenez ici le plus rapidement possible avec les bandages en mageweave dont nous avons discuté.';
-- Quest 8607 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8607, 'frFR', 'Surprenant, mais acceptable. Peut-être que j\'ai sous-estimé vos \'capacités\', $c. Peut-être. Vous avez accompli une tâche très simple, et pour cela, vous êtes récompensé de manière disproportionnée. Mais ne vous enivrez pas. Si vous voulez vraiment vous prouver votre valeur, vous devriez sortir et m\'apporter un autre paquet de bandages en mageweave.') ON DUPLICATE KEY UPDATE RewardText='Surprenant, mais acceptable. Peut-être que j\'ai sous-estimé vos \'capacités\', $c. Peut-être. Vous avez accompli une tâche très simple, et pour cela, vous êtes récompensé de manière disproportionnée. Mais ne vous enivrez pas. Si vous voulez vraiment vous prouver votre valeur, vous devriez sortir et m\'apporter un autre paquet de bandages en mageweave.';
-- Quest 8608 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8608, 'frFR', 'Vous êtes revenu ? Intéressant. Comme vous pouvez le voir, je suis toujours en train de collecter pour l\'effort de guerre d\'Ahn\'Qiraj. Ce qui signifie que je dois que vous sortiez à nouveau pour me ramener une pile de bandages en mageweave. J\'attends votre retour, $C.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu ? Intéressant. Comme vous pouvez le voir, je suis toujours en train de collecter pour l\'effort de guerre d\'Ahn\'Qiraj. Ce qui signifie que je dois que vous sortiez à nouveau pour me ramener une pile de bandages en mageweave. J\'attends votre retour, $C.';
-- Quest 8608 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8608, 'frFR', 'Étonnant, $C, vous l\'avez fait à nouveau ! Eh bien, on dit que j\'ai bon goût en ce que je choisis de placer à mon service. Très bien, votre contribution est notée et vous recevrez les avantages sociaux que vos efforts ont procuré. Je suggère cependant que vous retourniez chercher un autre paquet de bandages en mageweave si vous voulez vraiment prouver votre valeur.') ON DUPLICATE KEY UPDATE RewardText='Étonnant, $C, vous l\'avez fait à nouveau ! Eh bien, on dit que j\'ai bon goût en ce que je choisis de placer à mon service. Très bien, votre contribution est notée et vous recevrez les avantages sociaux que vos efforts ont procuré. Je suggère cependant que vous retourniez chercher un autre paquet de bandages en mageweave si vous voulez vraiment prouver votre valeur.';
-- Quest 8610 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8610, 'frFR', 'Le temps approche toujours pour que nous nous jetions tête baissée dans la conflagration d\'Ahn\'Qiraj, prêtre. Mais d\'abord, nous devons rassembler notre force et nous préparer pour survivre à l\'assaut des insectes et de leurs maîtres.$B$BSi vous êtes de retour, alors vous souhaitez certainement faire une autre contribution de bandages en runecloth à l\'effort de guerre ? Veuillez le faire dès que possible et revenez-moi une fois de plus.') ON DUPLICATE KEY UPDATE CompletionText='Le temps approche toujours pour que nous nous jetions tête baissée dans la conflagration d\'Ahn\'Qiraj, prêtre. Mais d\'abord, nous devons rassembler notre force et nous préparer pour survivre à l\'assaut des insectes et de leurs maîtres.$B$BSi vous êtes de retour, alors vous souhaitez certainement faire une autre contribution de bandages en runecloth à l\'effort de guerre ? Veuillez le faire dès que possible et revenez-moi une fois de plus.';
-- Quest 8610 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8610, 'frFR', 'C\'est un acte de générosité très désintéressé que vous accomplissez, $N. Un acte qui est susceptible de sauver la vie de nombreux combattants à Ahn\'Qiraj. Merci et sachez que vous avez l\'appréciation de la Horde pour votre don. Si vous créez, ou trouvez, plus de bandages en runecloth, veuillez en apporter à moi ici.') ON DUPLICATE KEY UPDATE RewardText='C\'est un acte de générosité très désintéressé que vous accomplissez, $N. Un acte qui est susceptible de sauver la vie de nombreux combattants à Ahn\'Qiraj. Merci et sachez que vous avez l\'appréciation de la Horde pour votre don. Si vous créez, ou trouvez, plus de bandages en runecloth, veuillez en apporter à moi ici.';
-- Quest 8611 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8611, 'frFR', 'Les sprite darters peuvent être des créatures dangereuses lorsqu\'elles sont provoquées. Faites attention lorsque vous les manipulez, $C. Et soyez encore plus prudent avec tout elfe de la nuit dans la zone. Les idiots importuns ont tendance à se trouver aussi dans les forêts.$B$BQuand vous aurez récupéré assez d\'ailes, faites-le moi savoir, je serai sûr de vous récompenser généreusement !') ON DUPLICATE KEY UPDATE CompletionText='Les sprite darters peuvent être des créatures dangereuses lorsqu\'elles sont provoquées. Faites attention lorsque vous les manipulez, $C. Et soyez encore plus prudent avec tout elfe de la nuit dans la zone. Les idiots importuns ont tendance à se trouver aussi dans les forêts.$B$BQuand vous aurez récupéré assez d\'ailes, faites-le moi savoir, je serai sûr de vous récompenser généreusement !';
-- Quest 8611 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8611, 'frFR', 'Merveilleux, $c! Ceux-ci feront l\'affaire. Il y en a assez pour faire une cape pour Korrin, et peut-être même plus ! Merci.$B$J\'espère que le voyage n\'a pas été trop dangereux ? La zone de Feralas n\'est pas connue pour être indulgente, mais vous avez manifestement fait suffisamment bien.$B$Merci encore, $c.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux, $c! Ceux-ci feront l\'affaire. Il y en a assez pour faire une cape pour Korrin, et peut-être même plus ! Merci.$B$J\'espère que le voyage n\'a pas été trop dangereux ? La zone de Feralas n\'est pas connue pour être indulgente, mais vous avez manifestement fait suffisamment bien.$B$Merci encore, $c.';
-- Quest 8612 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8612, 'frFR', 'Comme vous pouvez le voir, $C, nous devons encore emballer plus de nourriture pour les soldats. Je ne sais pas si vous avez déjà été en guerre, mais une fois que vous avez dépassé le choc initial du champ de bataille, vous pouvez avoir très faim. Vous avez bien travaillé la dernière fois, donc j\'attends que vous fassiez de même, si ce n\'est un peu plus rapidement, en me ramenant une autre pile de ces steaks de loup maigres.') ON DUPLICATE KEY UPDATE CompletionText='Comme vous pouvez le voir, $C, nous devons encore emballer plus de nourriture pour les soldats. Je ne sais pas si vous avez déjà été en guerre, mais une fois que vous avez dépassé le choc initial du champ de bataille, vous pouvez avoir très faim. Vous avez bien travaillé la dernière fois, donc j\'attends que vous fassiez de même, si ce n\'est un peu plus rapidement, en me ramenant une autre pile de ces steaks de loup maigres.';
-- Quest 8612 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8612, 'frFR', 'Ça sent que vous, ou quelqu\'un que vous connaissez, êtes un excellent cuisinier, $N. Ces steaks de loup maigres me donnent envie de saliver ; je suppose que quelques-uns qui disparaissent ne seront pas remarqués. Quoi qu\'il en soit, bon travail. Je m\'assurerai que quelqu\'un les emballera correctement pour qu\'ils ne pourrissent pas trop. $B$Si vous en trouvez plus, vous savez où me trouver.') ON DUPLICATE KEY UPDATE RewardText='Ça sent que vous, ou quelqu\'un que vous connaissez, êtes un excellent cuisinier, $N. Ces steaks de loup maigres me donnent envie de saliver ; je suppose que quelques-uns qui disparaissent ne seront pas remarqués. Quoi qu\'il en soit, bon travail. Je m\'assurerai que quelqu\'un les emballera correctement pour qu\'ils ne pourrissent pas trop. $B$Si vous en trouvez plus, vous savez où me trouver.';
-- Quest 8613 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8613, 'frFR', 'Les sprite darters peuvent être des créatures dangereuses lorsqu\'elles sont provoquées. Faites attention lorsque vous les manipulez, $C. Et soyez encore plus prudent avec tout elfe de la nuit dans la zone. Les idiots importuns ont tendance à se trouver aussi dans les forêts.$B$Quand vous aurez récupéré assez d\'ailes, faites-le moi savoir, je serai sûr de vous récompenser généreusement !') ON DUPLICATE KEY UPDATE CompletionText='Les sprite darters peuvent être des créatures dangereuses lorsqu\'elles sont provoquées. Faites attention lorsque vous les manipulez, $C. Et soyez encore plus prudent avec tout elfe de la nuit dans la zone. Les idiots importuns ont tendance à se trouver aussi dans les forêts.$B$Quand vous aurez récupéré assez d\'ailes, faites-le moi savoir, je serai sûr de vous récompenser généreusement !';
-- Quest 8613 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8613, 'frFR', 'Merveilleux, $c! Ceux-ci feront l\'affaire. Il y en a assez pour faire une cape pour Korrin, et peut-être même plus ! Merci.$B$J\'espère que le voyage n\'a pas été trop dangereux ? La zone de Feralas n\'est pas connue pour être indulgente, mais vous avez manifestement fait suffisamment bien.$B$Merci encore, $c.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux, $c! Ceux-ci feront l\'affaire. Il y en a assez pour faire une cape pour Korrin, et peut-être même plus ! Merci.$B$J\'espère que le voyage n\'a pas été trop dangereux ? La zone de Feralas n\'est pas connue pour être indulgente, mais vous avez manifestement fait suffisamment bien.$B$Merci encore, $c.';
-- Quest 8614 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8614, 'frFR', 'Comme vous pouvez le voir, nous avons encore besoin de beaucoup de poissons. Les combattants dans la prochaine Guerre d\'Ahn\'Qiraj vont avoir besoin de beaucoup à manger, donc j\'ai besoin de prendre tous les poissons jaunes mouchetés que je peux. Vous les pêchez, vous les cuisinez, et vous me les ramenez ici, et je vous donne mes remerciements, et ceux de la Horde.') ON DUPLICATE KEY UPDATE CompletionText='Comme vous pouvez le voir, nous avons encore besoin de beaucoup de poissons. Les combattants dans la prochaine Guerre d\'Ahn\'Qiraj vont avoir besoin de beaucoup à manger, donc j\'ai besoin de prendre tous les poissons jaunes mouchetés que je peux. Vous les pêchez, vous les cuisinez, et vous me les ramenez ici, et je vous donne mes remerciements, et ceux de la Horde.';
-- Quest 8614 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8614, 'frFR', 'C\'est la meilleure prise jusqu\'à présent, $N! Bon travail honnête là. Et pas de blagues ! Merci de venir pour ce poisson jaune moucheté ici mon. Reviens bientôt si tu cuisines-en d\'autres !') ON DUPLICATE KEY UPDATE RewardText='C\'est la meilleure prise jusqu\'à présent, $N! Bon travail honnête là. Et pas de blagues ! Merci de venir pour ce poisson jaune moucheté ici mon. Reviens bientôt si tu cuisines-en d\'autres !';

-- Quest 8615 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8615, 'frFR', 'Les sprites darters peuvent être des créatures dangereuses lorsqu\'elles sont provoquées. Faites attention lorsque vous les traitez, $C. Et soyez encore plus prudent avec tout elfe de la nuit dans la région. Les idiots importuns ont tendance à se promener aussi dans les forêts.$B$BLorsque vous aurez fini les ailes, faites-le moi savoir, je m\'assurerai de vous récompenser généreusement !') ON DUPLICATE KEY UPDATE CompletionText='Les sprites darters peuvent être des créatures dangereuses lorsqu\'elles sont provoquées. Faites attention lorsque vous les traitez, $C. Et soyez encore plus prudent avec tout elfe de la nuit dans la région. Les idiots importuns ont tendance à se promener aussi dans les forêts.$B$BLorsque vous aurez fini les ailes, faites-le moi savoir, je m\'assurerai de vous récompenser généreusement !';
-- Quest 8615 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8615, 'frFR', 'Merveilleux, $c! Ceux-ci feront l\'affaire. Il y en a assez pour confectionner une cape pour Korrin, et peut-être même plus ! Merci.$B$BI espère que le voyage n\'a pas été trop dangereux ? La région de Feralas n\'est pas connue pour être indulgente, mais vous avez manifestement fait suffisamment bien.$B$BMerci encore, $c.') ON DUPLICATE KEY UPDATE RewardText='Merveilleux, $c! Ceux-ci feront l\'affaire. Il y en a assez pour confectionner une cape pour Korrin, et peut-être même plus ! Merci.$B$BI espère que le voyage n\'a pas été trop dangereux ? La région de Feralas n\'est pas connue pour être indulgente, mais vous avez manifestement fait suffisamment bien.$B$BMerci encore, $c.';
-- Quest 8616 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8616, 'frFR', 'Le dernier lot de saumon cuit que vous avez donné à l\'effort de guerre avait l\'air très délicieux, $C. Je dois avouer que j\'ai été tenté d\'en prendre quelques-uns pour moi. Comme vous pouvez le voir, nous n\'avons pas encore atteint notre quota ici. J\'espère que vous êtes revenu parce que vous avez une autre pile de saumon cuit avec vous.') ON DUPLICATE KEY UPDATE CompletionText='Le dernier lot de saumon cuit que vous avez donné à l\'effort de guerre avait l\'air très délicieux, $C. Je dois avouer que j\'ai été tenté d\'en prendre quelques-uns pour moi. Comme vous pouvez le voir, nous n\'avons pas encore atteint notre quota ici. J\'espère que vous êtes revenu parce que vous avez une autre pile de saumon cuit avec vous.';
-- Quest 8616 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8616, 'frFR', 'Votre don de temps et d\'énergie à l\'effort de guerre dépasse tout ce qui est attendu, $n. Je vous assure que vos labeurs n\'ont pas passé inaperçus. Vous avez mes remerciements, et la gratitude de la Horde. Veuillez revenir vers moi si vous faites cuire un autre lot.') ON DUPLICATE KEY UPDATE RewardText='Votre don de temps et d\'énergie à l\'effort de guerre dépasse tout ce qui est attendu, $n. Je vous assure que vos labeurs n\'ont pas passé inaperçus. Vous avez mes remerciements, et la gratitude de la Horde. Veuillez revenir vers moi si vous faites cuire un autre lot.';
-- Quest 8619 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8619, 'frFR', 'C\'est bon de savoir que les gens de cette terre rendent encore hommage aux races anciennes. Je vous souhaite le meilleur, $N, et je vous offre ce jeton...') ON DUPLICATE KEY UPDATE RewardText='C\'est bon de savoir que les gens de cette terre rendent encore hommage aux races anciennes. Je vous souhaite le meilleur, $N, et je vous offre ce jeton...';
-- Quest 8620 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8620, 'frFR', 'Je me mets le pantalon comme vous - une jambe à la fois. Sauf que lorsque mon pantalon est mis, je fabrique des bouées d\'arcanite. Des bouées d\'arcanite, bébé !') ON DUPLICATE KEY UPDATE CompletionText='Je me mets le pantalon comme vous - une jambe à la fois. Sauf que lorsque mon pantalon est mis, je fabrique des bouées d\'arcanite. Des bouées d\'arcanite, bébé !';
-- Quest 8621 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8621, 'frFR', 'Vous avez acquis les objets que j\'ai demandés, $n?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez acquis les objets que j\'ai demandés, $n?';
-- Quest 8621 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8621, 'frFR', 'Vous avez bien fait, <name>.  Vous avez prouvé que vous n\'êtes pas un mortel ordinaire.$B$BI vous donne ceci avec la confiance qu\'il vous aidera à écraser les vile qiraji.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, <name>.  Vous avez prouvé que vous n\'êtes pas un mortel ordinaire.$B$BI vous donne ceci avec la confiance qu\'il vous aidera à écraser les vile qiraji.';
-- Quest 8622 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8622, 'frFR', 'Vous avez acquis les objets que j\'ai demandés, $n?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez acquis les objets que j\'ai demandés, $n?';
-- Quest 8622 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8622, 'frFR', 'Je ne m\'attendais pas à ce que vous reveniez de votre tentative, <name>.$B$BVous avez accompli un destin plus grand que celui de la plupart des êtres immortels.$B$BEn tuant C\'Thun, vous avez non seulement sauvé tout Azeroth, mais vous avez également fait basculer la balance des événements cosmiques au-delà de votre compréhension.$B$BAcceptez cette cuirasse comme un symbole de la gloire et du fardeau qui en découlera de vos actions.$B$BQue son pouvoir vous aide dans les défis qui vous attendent, tueur de dieux !') ON DUPLICATE KEY UPDATE RewardText='Je ne m\'attendais pas à ce que vous reveniez de votre tentative, <name>.$B$BVous avez accompli un destin plus grand que celui de la plupart des êtres immortels.$B$BEn tuant C\'Thun, vous avez non seulement sauvé tout Azeroth, mais vous avez également fait basculer la balance des événements cosmiques au-delà de votre compréhension.$B$BAcceptez cette cuirasse comme un symbole de la gloire et du fardeau qui en découlera de vos actions.$B$BQue son pouvoir vous aide dans les défis qui vous attendent, tueur de dieux !';
-- Quest 8623 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8623, 'frFR', 'Vous avez acquis les objets que j\'ai demandés, $n?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez acquis les objets que j\'ai demandés, $n?';
-- Quest 8623 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8623, 'frFR', 'Vous avez réussi !  Les murmures des Deux Empereurs ont cessé.$B$BPrenez ceci comme une récompense.  Le simple fait de le voir inspirera la peur dans les cœurs des Qiraji... cela leur rappellera leurs dirigeants tombés et celui qui les a tués.') ON DUPLICATE KEY UPDATE RewardText='Vous avez réussi !  Les murmures des Deux Empereurs ont cessé.$B$BPrenez ceci comme une récompense.  Le simple fait de le voir inspirera la peur dans les cœurs des Qiraji... cela leur rappellera leurs dirigeants tombés et celui qui les a tués.';
-- Quest 8624 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8624, 'frFR', 'Vous avez acquis les objets que j\'ai demandés, $n?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez acquis les objets que j\'ai demandés, $n?';
-- Quest 8624 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8624, 'frFR', 'Oui... la peau du ver fera une excellente couche protectrice.  Combinée aux meilleures parties des Qiraji que nous avons détruits en chemin, cela devrait faire une pièce d\'armure formidable.  Que cela vous aide à faire face aux horreurs indicibles qui vous attendent à l\'intérieur !') ON DUPLICATE KEY UPDATE RewardText='Oui... la peau du ver fera une excellente couche protectrice.  Combinée aux meilleures parties des Qiraji que nous avons détruits en chemin, cela devrait faire une pièce d\'armure formidable.  Que cela vous aide à faire face aux horreurs indicibles qui vous attendent à l\'intérieur !';
-- Quest 8625 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8625, 'frFR', 'Avez-vous collecté les composants dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous collecté les composants dont j\'ai besoin ?';

-- Quest 8625 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8625, 'frFR', 'À partir des matériaux que tu apportes et des écailles de nos ennemis Qiraji tombés, je te fabrique ces épaulières, mortel.  Qu\'elles t\'accordent la protection dont tu as besoin et que leur vue inspire la peur à nos ennemis.') ON DUPLICATE KEY UPDATE RewardText='À partir des matériaux que tu apportes et des écailles de nos ennemis Qiraji tombés, je te fabrique ces épaulières, mortel.  Qu\'elles t\'accordent la protection dont tu as besoin et que leur vue inspire la peur à nos ennemis.';
-- Quest 8626 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8626, 'frFR', 'Tu as acquis les objets que j\'ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='Tu as acquis les objets que j\'ai demandés, $N?';
-- Quest 8626 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8626, 'frFR', 'Tu as bien fait, <name>.  Tu as prouvé que tu n\'étais pas un mortel ordinaire.$B$BI te donne ceci avec la confiance qu\'il t\'aidera à écraser les vilains Qiraji.') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait, <name>.  Tu as prouvé que tu n\'étais pas un mortel ordinaire.$B$BI te donne ceci avec la confiance qu\'il t\'aidera à écraser les vilains Qiraji.';
-- Quest 8627 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8627, 'frFR', 'Dans son demeure à Ahn\'Qiraj, le terrible C\'Thun t\'attend dans son sommeil.') ON DUPLICATE KEY UPDATE CompletionText='Dans son demeure à Ahn\'Qiraj, le terrible C\'Thun t\'attend dans son sommeil.';
