INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8628, 'frFR', 'As-tu collecté les composants dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu collecté les composants dont j\'ai besoin ?';
-- Quest 8628 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8628, 'frFR', 'Tu as réussi !  Les murmures des Deux Empereurs ont cessé.$B$BPrends ceci comme récompense.  Le simple fait de le voir inspirera la peur dans le cœur des Qiraji... cela leur rappellera leurs dirigeants tombés et le mortel qui les a abattus.') ON DUPLICATE KEY UPDATE RewardText='Tu as réussi !  Les murmures des Deux Empereurs ont cessé.$B$BPrends ceci comme récompense.  Le simple fait de le voir inspirera la peur dans le cœur des Qiraji... cela leur rappellera leurs dirigeants tombés et le mortel qui les a abattus.';
-- Quest 8629 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8629, 'frFR', 'As-tu apporté les composants dont j\'ai besoin, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les composants dont j\'ai besoin, $N?';
-- Quest 8629 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8629, 'frFR', 'Oui... la peau du ver fera une excellente couche protectrice.  Combinée aux parties les plus solides des Qiraji que nous avons détruits en chemin, cela devrait faire une pièce d\'armure formidable.  Qu\'elle t\'aide à affronter les horreurs indicibles qui t\'attendent à l\'intérieur !') ON DUPLICATE KEY UPDATE RewardText='Oui... la peau du ver fera une excellente couche protectrice.  Combinée aux parties les plus solides des Qiraji que nous avons détruits en chemin, cela devrait faire une pièce d\'armure formidable.  Qu\'elle t\'aide à affronter les horreurs indicibles qui t\'attendent à l\'intérieur !';
