INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8630, 'frFR', 'As-tu collecté les composants dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu collecté les composants dont j\'ai besoin ?';
-- Quest 8630 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8630, 'frFR', 'À partir des matériaux que tu apportes et des écailles de nos ennemis Qiraji tombés, je te fabrique ces épaulières, mortel.  Qu\'elles t\'accordent la protection dont tu as besoin et que leur vue inspire la peur à nos ennemis.') ON DUPLICATE KEY UPDATE RewardText='À partir des matériaux que tu apportes et des écailles de nos ennemis Qiraji tombés, je te fabrique ces épaulières, mortel.  Qu\'elles t\'accordent la protection dont tu as besoin et que leur vue inspire la peur à nos ennemis.';
