-- Quest 8633 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8633, 'frFR', 'Je ne m\'attendais pas à ce que vous reveniez de votre tentative, <name>.$B$BVous avez accompli un destin plus grand que celui de la plupart des êtres immortels.$B$BEn tuant C\'Thun, vous avez non seulement sauvé tout Azeroth, mais vous avez également fait basculer la balance des événements cosmiques au-delà de votre compréhension.$B$BAcceptez ces robes comme un symbole de la gloire et du fardeau qui découleront de vos actions.$B$BQue leur pouvoir vous aide dans les défis qui vous attendent, tueur de dieux!') ON DUPLICATE KEY UPDATE RewardText='Je ne m\'attendais pas à ce que vous reveniez de votre tentative, <name>.$B$BVous avez accompli un destin plus grand que celui de la plupart des êtres immortels.$B$BEn tuant C\'Thun, vous avez non seulement sauvé tout Azeroth, mais vous avez également fait basculer la balance des événements cosmiques au-delà de votre compréhension.$B$BAcceptez ces robes comme un symbole de la gloire et du fardeau qui découleront de vos actions.$B$BQue leur pouvoir vous aide dans les défis qui vous attendent, tueur de dieux!';
-- Quest 8634 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8634, 'frFR', 'Vous avez acquis les objets que j\'ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez acquis les objets que j\'ai demandés, $N?';
-- Quest 8634 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8634, 'frFR', 'Vous avez bien fait, <name>.  Vous avez prouvé que vous n\'êtes pas un mortel ordinaire.$B$BI vous donne ceci avec la conviction qu\'il vous aidera à écraser les vile qiraji.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, <name>.  Vous avez prouvé que vous n\'êtes pas un mortel ordinaire.$B$BI vous donne ceci avec la conviction qu\'il vous aidera à écraser les vile qiraji.';
-- Quest 8635 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8635, 'frFR', 'Les batailles des âges passés sont les graines à partir desquelles les légendes poussent. Le vôtre est un temps de héros, jeune one. Que votre légende prenne racine, prospère.$B$BI vous souhaite bonne chance, $N, et vous offre ce jeton...') ON DUPLICATE KEY UPDATE RewardText='Les batailles des âges passés sont les graines à partir desquelles les légendes poussent. Le vôtre est un temps de héros, jeune one. Que votre légende prenne racine, prospère.$B$BI vous souhaite bonne chance, $N, et vous offre ce jeton...';
-- Quest 8636 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8636, 'frFR', 'La matière de la vie est destinée à mourir et à retourner à la terre, mais la matière de l\'esprit vit éternellement. Je vous souhaite bonne chance, $N, et vous offre ce jeton...') ON DUPLICATE KEY UPDATE RewardText='La matière de la vie est destinée à mourir et à retourner à la terre, mais la matière de l\'esprit vit éternellement. Je vous souhaite bonne chance, $N, et vous offre ce jeton...';
