INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8666, 'frFR', 'Je ne m\'attendais pas à ce que tu reviennes de ta tentative, <name>.$B$BTu as accompli un destin plus grand que celui de la plupart des êtres immortels.$B$BEn tu tuant C\'Thun, tu as non seulement sauvé tout Azeroth, mais tu as aussi fait basculer la balance des événements cosmiques au-delà de ta compréhension.$B$BAccepte cette cuirasse comme un symbole de la gloire et du fardeau qui découleront de tes actions.$B$BQue son pouvoir t\'aide dans les défis qui t\'attendent, tueur de dieux !') ON DUPLICATE KEY UPDATE RewardText='Je ne m\'attendais pas à ce que tu reviennes de ta tentative, <name>.$B$BTu as accompli un destin plus grand que celui de la plupart des êtres immortels.$B$BEn tu tuant C\'Thun, tu as non seulement sauvé tout Azeroth, mais tu as aussi fait basculer la balance des événements cosmiques au-delà de ta compréhension.$B$BAccepte cette cuirasse comme un symbole de la gloire et du fardeau qui découleront de tes actions.$B$BQue son pouvoir t\'aide dans les défis qui t\'attendent, tueur de dieux !';
-- Quest 8667 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8667, 'frFR', 'As-tu apporté les composants que j\'ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les composants que j\'ai demandés, $N?';
-- Quest 8667 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8667, 'frFR', 'Tu as réussi !  Les murmures des Deux Empereurs ont cessé.$B$BPrends ceci comme une récompense.  Le simple fait de le voir inspirera la peur dans les cœurs des Qiraji... cela leur rappellera leurs dirigeants tombés et le mortel qui les a tués.') ON DUPLICATE KEY UPDATE RewardText='Tu as réussi !  Les murmures des Deux Empereurs ont cessé.$B$BPrends ceci comme une récompense.  Le simple fait de le voir inspirera la peur dans les cœurs des Qiraji... cela leur rappellera leurs dirigeants tombés et le mortel qui les a tués.';
-- Quest 8668 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8668, 'frFR', 'As-tu apporté les composants dont j\'ai besoin, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu apporté les composants dont j\'ai besoin, $N?';
-- Quest 8668 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8668, 'frFR', 'Oui... la peau du ver fera une excellente couche protectrice.  Combinée aux meilleures parties des Qiraji que nous avons détruits en chemin, ceci devrait faire une pièce d\'armure formidable.  Qu\'elle t\'aide à faire face aux horreurs indicibles qui t\'attendent à l\'intérieur !') ON DUPLICATE KEY UPDATE RewardText='Oui... la peau du ver fera une excellente couche protectrice.  Combinée aux meilleures parties des Qiraji que nous avons détruits en chemin, ceci devrait faire une pièce d\'armure formidable.  Qu\'elle t\'aide à faire face aux horreurs indicibles qui t\'attendent à l\'intérieur !';
-- Quest 8669 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8669, 'frFR', 'As-tu collecté les composants dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu collecté les composants dont j\'ai besoin ?';
-- Quest 8669 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8669, 'frFR', 'À partir des matériaux que tu apportes et des écailles de nos ennemis Qiraji tombés, je te fabrique ces épaulières, mortel.  Qu\'elles t\'accordent la protection dont tu as besoin et que leur vue inspire la peur à nos ennemis.') ON DUPLICATE KEY UPDATE RewardText='À partir des matériaux que tu apportes et des écailles de nos ennemis Qiraji tombés, je te fabrique ces épaulières, mortel.  Qu\'elles t\'accordent la protection dont tu as besoin et que leur vue inspire la peur à nos ennemis.';
-- Quest 8670 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8670, 'frFR', 'Ton esprit brûle de vie, jeune $c. J\'accepte l\'hommage que tu rends, et j\'offre en retour ce jeton...') ON DUPLICATE KEY UPDATE RewardText='Ton esprit brûle de vie, jeune $c. J\'accepte l\'hommage que tu rends, et j\'offre en retour ce jeton...';
-- Quest 8671 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8671, 'frFR', 'Ton esprit brûle de vie, jeune $c. J\'accepte l\'hommage que tu rends, et j\'offre en retour ce jeton...') ON DUPLICATE KEY UPDATE RewardText='Ton esprit brûle de vie, jeune $c. J\'accepte l\'hommage que tu rends, et j\'offre en retour ce jeton...';
-- Quest 8672 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8672, 'frFR', 'Ton esprit brûle de vie, jeune $c. J\'accepte l\'hommage que tu rends, et j\'offre en retour ce jeton...') ON DUPLICATE KEY UPDATE RewardText='Ton esprit brûle de vie, jeune $c. J\'accepte l\'hommage que tu rends, et j\'offre en retour ce jeton...';
-- Quest 177 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (177, 'frFR', 'Magnifique ! Ça va marcher merveilleusement bien. Merci !') ON DUPLICATE KEY UPDATE RewardText='Magnifique ! Ça va marcher merveilleusement bien. Merci !';
-- Quest 348 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (348, 'frFR', '... mère ?$B$B...tellement froid...$B$B...dirige vers le tortueux néant...t-t-t-tiens moi maman...') ON DUPLICATE KEY UPDATE CompletionText='... mère ?$B$B...tellement froid...$B$B...dirige vers le tortueux néant...t-t-t-tiens moi maman...';
-- Quest 446 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (446, 'frFR', 'Félicitations, $N. Qu\'a Bethor à dire ?') ON DUPLICATE KEY UPDATE CompletionText='Félicitations, $N. Qu\'a Bethor à dire ?';
-- Quest 1366 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (1366, 'frFR', 'Comment est votre collection d\'oreilles, $N ? Grande ?') ON DUPLICATE KEY UPDATE CompletionText='Comment est votre collection d\'oreilles, $N ? Grande ?';
-- Quest 2976 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (2976, 'frFR', 'Dépêche-toi, $C, j\'ai beaucoup à terminer aujourd\'hui.') ON DUPLICATE KEY UPDATE CompletionText='Dépêche-toi, $C, j\'ai beaucoup à terminer aujourd\'hui.';
-- Quest 3564 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (3564, 'frFR', 'Ici... Portez... <hic> cela à Jediga. Bonne chance !') ON DUPLICATE KEY UPDATE `Details`='Ici... Portez... <hic> cela à Jediga. Bonne chance !';
-- Quest 4283 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (4283, 'frFR', '<Oralius parle dans une grande oreille d\'ogre coupée.>$B$BSteppes ardentes à contrôle, répondez contrôle.') ON DUPLICATE KEY UPDATE CompletionText='<Oralius parle dans une grande oreille d\'ogre coupée.>$B$BSteppes ardentes à contrôle, répondez contrôle.';
-- Quest 5044 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5044, 'frFR', 'Vos ennemis devraient vous craindre encore plus, $R. <snort>$B$Raconte-moi des histoires de ta ruse au combat quand nous nous verrons à nouveau -- que ce soit dans cette vie, ou la prochaine. <snort>') ON DUPLICATE KEY UPDATE RewardText='Vos ennemis devraient vous craindre encore plus, $R. <snort>$B$Raconte-moi des histoires de ta ruse au combat quand nous nous verrons à nouveau -- que ce soit dans cette vie, ou la prochaine. <snort>';

-- Quest 5045 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5045, 'frFR', 'Les guerriers de tous types <snort> ont besoin d\'un esprit fort. Il vous pousse à accomplir de plus grandes prouesses lorsque tout espoir est perdu. Ce n\'est pas inconnu pour le <snort> Razormane. Nous sommes une tribu spirituelle -- nous sommes plus fiers de notre lien avec Agamaggan que de notre prouesse <snort> au combat.$B$Apportez-moi 4 éclats de sang et je bénirai votre esprit pour le combat. <snort>') ON DUPLICATE KEY UPDATE CompletionText='Les guerriers de tous types <snort> ont besoin d\'un esprit fort. Il vous pousse à accomplir de plus grandes prouesses lorsque tout espoir est perdu. Ce n\'est pas inconnu pour le <snort> Razormane. Nous sommes une tribu spirituelle -- nous sommes plus fiers de notre lien avec Agamaggan que de notre prouesse <snort> au combat.$B$Apportez-moi 4 éclats de sang et je bénirai votre esprit pour le combat. <snort>';
-- Quest 5863 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5863, 'frFR', 'Je suis tellement inquiet ! Soyez prudent !') ON DUPLICATE KEY UPDATE CompletionText='Je suis tellement inquiet ! Soyez prudent !';
-- Quest 5882 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5882, 'frFR', 'Posséder un Phare de Cenarion permet de voir un éclat d\'âme corrompu sur ces bêtes souillées qui sont abattues pour le bien supérieur. Je transforme les éclats en un réactif utilisable qui sert à fabriquer la pommade de plante de Cenarion. Nous utiliserons cette pommade pour rendre les plantes corrompues saines à nouveau.$b$En échange de ces éclats, je vous donnerai quelques pommades de plante de Cenarion que j\'ai déjà préparées.') ON DUPLICATE KEY UPDATE CompletionText='Posséder un Phare de Cenarion permet de voir un éclat d\'âme corrompu sur ces bêtes souillées qui sont abattues pour le bien supérieur. Je transforme les éclats en un réactif utilisable qui sert à fabriquer la pommade de plante de Cenarion. Nous utiliserons cette pommade pour rendre les plantes corrompues saines à nouveau.$b$En échange de ces éclats, je vous donnerai quelques pommades de plante de Cenarion que j\'ai déjà préparées.';
-- Quest 5882 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5882, 'frFR', 'Très bien, voici vos pommades de plante de Cenarion. Explorez Felwood à la recherche de plantes corrompues, $N! Où qu\'elles soient, utilisez la pommade que je vous ai donnée pour les purifier.') ON DUPLICATE KEY UPDATE RewardText='Très bien, voici vos pommades de plante de Cenarion. Explorez Felwood à la recherche de plantes corrompues, $N! Où qu\'elles soient, utilisez la pommade que je vous ai donnée pour les purifier.';
-- Quest 5883 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5883, 'frFR', 'Si vous possédez un phare de Cenarion pendant que vous minez dans Felwood, vous pourrez voir le vitriol souillé qui corrompt une veine de métal brut. Je sais comment purifier ce vitriol et le transformer en un réactif qui sert à fabriquer la pommade de plante de Cenarion. Vous utiliserez ensuite cette pommade sur les plantes que vous trouvez dans la nature qui ont besoin d\'être sauvées.$b$Si vous avez collecté du vitriol souillé, je vous donnerai quelques pommades de plante de Cenarion que j\'ai déjà préparées.') ON DUPLICATE KEY UPDATE CompletionText='Si vous possédez un phare de Cenarion pendant que vous minez dans Felwood, vous pourrez voir le vitriol souillé qui corrompt une veine de métal brut. Je sais comment purifier ce vitriol et le transformer en un réactif qui sert à fabriquer la pommade de plante de Cenarion. Vous utiliserez ensuite cette pommade sur les plantes que vous trouvez dans la nature qui ont besoin d\'être sauvées.$b$Si vous avez collecté du vitriol souillé, je vous donnerai quelques pommades de plante de Cenarion que j\'ai déjà préparées.';
-- Quest 5883 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5883, 'frFR', 'Très bien, voici une pommade de plante de Cenarion. Si vous trouvez plus de vitriol en minant dans Felwood, n\'oubliez pas de le garder pour moi ! Plus vous en trouvez, plus je pourrai en fabriquer.') ON DUPLICATE KEY UPDATE RewardText='Très bien, voici une pommade de plante de Cenarion. Si vous trouvez plus de vitriol en minant dans Felwood, n\'oubliez pas de le garder pour moi ! Plus vous en trouvez, plus je pourrai en fabriquer.';
-- Quest 5884 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5884, 'frFR', 'Un phare de Cenarion permet à un herboriste expérimenté de repérer le rampant félin insidieux - un produit malfaisant de la corruption de Felwood. Mon travail ici m\'a enseigné la connaissance de la purification du rampant félin en un réactif purificateur... utilisé dans ce que nous appelons maintenant la pommade de plante de Cenarion.$b$Lorsque vous cueillez des herbes dans Felwood, vous devriez rencontrer le rampant félin tant que vous avez le phare. En échange de ce que vous m\'apportez, je vous donnerai une pommade de plante de Cenarion préfabriquée.') ON DUPLICATE KEY UPDATE CompletionText='Un phare de Cenarion permet à un herboriste expérimenté de repérer le rampant félin insidieux - un produit malfaisant de la corruption de Felwood. Mon travail ici m\'a enseigné la connaissance de la purification du rampant félin en un réactif purificateur... utilisé dans ce que nous appelons maintenant la pommade de plante de Cenarion.$b$Lorsque vous cueillez des herbes dans Felwood, vous devriez rencontrer le rampant félin tant que vous avez le phare. En échange de ce que vous m\'apportez, je vous donnerai une pommade de plante de Cenarion préfabriquée.';
-- Quest 5884 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5884, 'frFR', 'Excellent travail $N - chaque morceau de cela, une fois que nous l\'aurons purifié, nous aidera à reconquérir Felwood. Voici, prenez quelques doses de pommade de plante de Cenarion et allez dans la forêt. La reconquête de la terre sur la corruption n\'attend pas $R!') ON DUPLICATE KEY UPDATE RewardText='Excellent travail $N - chaque morceau de cela, une fois que nous l\'aurons purifié, nous aidera à reconquérir Felwood. Voici, prenez quelques doses de pommade de plante de Cenarion et allez dans la forêt. La reconquête de la terre sur la corruption n\'attend pas $R!';

-- Quest 5885 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5885, 'frFR', 'Un balise de Cenarion permettra à un skinner bien entraîné de repérer des morceaux de peau souillés provenant des bêtes capturées dans Felwood. Je transforme ces morceaux apparemment inutiles en une pâte épaisse qui sert d\'agent accélérateur pour la pommade de plante de Cenarion. Lorsque vous découpez vos proies ici dans Felwood, assurez-vous d\'avoir une balise sur vous ! $b$bLorsque vous ramassez des morceaux souillés, apportez-les-moi et je vous donnerai des pommades de plante de Cenarion que j\'ai déjà préparées.') ON DUPLICATE KEY UPDATE CompletionText='Un balise de Cenarion permettra à un skinner bien entraîné de repérer des morceaux de peau souillés provenant des bêtes capturées dans Felwood. Je transforme ces morceaux apparemment inutiles en une pâte épaisse qui sert d\'agent accélérateur pour la pommade de plante de Cenarion. Lorsque vous découpez vos proies ici dans Felwood, assurez-vous d\'avoir une balise sur vous ! $b$bLorsque vous ramassez des morceaux souillés, apportez-les-moi et je vous donnerai des pommades de plante de Cenarion que j\'ai déjà préparées.';
-- Quest 5885 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5885, 'frFR', 'C\'est exactement ce dont j\'ai besoin. Voici - prenez ces pommades de plante et utilisez-les pour récupérer Felwood de la corruption. Nous devons persévérer, $N!') ON DUPLICATE KEY UPDATE RewardText='C\'est exactement ce dont j\'ai besoin. Voici - prenez ces pommades de plante et utilisez-les pour récupérer Felwood de la corruption. Nous devons persévérer, $N!';
-- Quest 5886 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5886, 'frFR', 'Le pouvoir d\'un objet magique désenchanté se ressent dans l\'essence qu\'il crée. J\'ai trouvé un moyen de transformer l\'essence brute utilisée par les enchanteurs en un réactif approprié pour créer la pommade de plante de Cenarion. Vous n\'avez pas besoin d\'une balise de Cenarion pour cela ; tout objet suffisamment désenchanté qui donne des essences nether inférieures fonctionnera.$b$bJ\'ai juste besoin d\'une essence nether inférieure ; en échange, je vous donnerai des pommades de plante de Cenarion. L\'essence est extrêmement puissante - un peu fait certainement beaucoup !') ON DUPLICATE KEY UPDATE CompletionText='Le pouvoir d\'un objet magique désenchanté se ressent dans l\'essence qu\'il crée. J\'ai trouvé un moyen de transformer l\'essence brute utilisée par les enchanteurs en un réactif approprié pour créer la pommade de plante de Cenarion. Vous n\'avez pas besoin d\'une balise de Cenarion pour cela ; tout objet suffisamment désenchanté qui donne des essences nether inférieures fonctionnera.$b$bJ\'ai juste besoin d\'une essence nether inférieure ; en échange, je vous donnerai des pommades de plante de Cenarion. L\'essence est extrêmement puissante - un peu fait certainement beaucoup !';
-- Quest 5886 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5886, 'frFR', 'Voici quelques pommades de plante de Cenarion - je n\'ai besoin que d\'une essence nether inférieure pour cela, $N. L\'essence est de loin l\'objet le plus puissant que je puisse utiliser pour transformer des épées en charrues, si l\'on veut. Si vous avez besoin de plus de pommade, trouvez-moi ici !') ON DUPLICATE KEY UPDATE RewardText='Voici quelques pommades de plante de Cenarion - je n\'ai besoin que d\'une essence nether inférieure pour cela, $N. L\'essence est de loin l\'objet le plus puissant que je puisse utiliser pour transformer des épées en charrues, si l\'on veut. Si vous avez besoin de plus de pommade, trouvez-moi ici !';
-- Quest 5887 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5887, 'frFR', 'Posséder une balise de Cenarion permet de voir un éclat d\'âme corrompu sur ces bêtes souillées qui sont abattues pour le bien supérieur. Je broie les éclats en un réactif utilisable qui sert à faire la pommade de plante de Cenarion. Nous utiliserons cette pommade pour transformer les plantes corrompues en plantes saines à nouveau.$b$bEn échange de ces éclats, je vous donnerai des pommades de plante de Cenarion que j\'ai déjà préparées.') ON DUPLICATE KEY UPDATE CompletionText='Posséder une balise de Cenarion permet de voir un éclat d\'âme corrompu sur ces bêtes souillées qui sont abattues pour le bien supérieur. Je broie les éclats en un réactif utilisable qui sert à faire la pommade de plante de Cenarion. Nous utiliserons cette pommade pour transformer les plantes corrompues en plantes saines à nouveau.$b$bEn échange de ces éclats, je vous donnerai des pommades de plante de Cenarion que j\'ai déjà préparées.';
-- Quest 5887 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5887, 'frFR', 'Très bien alors, voici vos pommades de plante de Cenarion. Parcourez Felwood à la recherche de plantes corrompues, $N! Où qu\'elles soient, utilisez la pommade que je vous ai donnée pour les purifier.') ON DUPLICATE KEY UPDATE RewardText='Très bien alors, voici vos pommades de plante de Cenarion. Parcourez Felwood à la recherche de plantes corrompues, $N! Où qu\'elles soient, utilisez la pommade que je vous ai donnée pour les purifier.';
-- Quest 5888 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (5888, 'frFR', 'Si vous possédez une balise de Cenarion tout en minant dans Felwood, vous pourrez voir un vitriol souillé qui corrompt une veine de métal brut. Je sais comment purifier ce vitriol et le transformer en un réactif qui sert à faire la pommade de plante de Cenarion. Vous utiliserez ensuite cette pommade sur les plantes que vous trouvez dans la nature qui ont besoin d\'être sauvées.$B$BSi vous avez ramassé du vitriol souillé, je vous donnerai une pommade de plante de Cenarion que j\'ai déjà préparée.') ON DUPLICATE KEY UPDATE CompletionText='Si vous possédez une balise de Cenarion tout en minant dans Felwood, vous pourrez voir un vitriol souillé qui corrompt une veine de métal brut. Je sais comment purifier ce vitriol et le transformer en un réactif qui sert à faire la pommade de plante de Cenarion. Vous utiliserez ensuite cette pommade sur les plantes que vous trouvez dans la nature qui ont besoin d\'être sauvées.$B$BSi vous avez ramassé du vitriol souillé, je vous donnerai une pommade de plante de Cenarion que j\'ai déjà préparée.';
-- Quest 5888 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (5888, 'frFR', 'Très bien alors, voici une pommade de plante de Cenarion. Si vous trouvez plus de vitriol lorsque vous minez dans Felwood, n\'oubliez pas de le garder pour moi ! Plus vous en trouvez, plus je pourrai en faire.') ON DUPLICATE KEY UPDATE RewardText='Très bien alors, voici une pommade de plante de Cenarion. Si vous trouvez plus de vitriol lorsque vous minez dans Felwood, n\'oubliez pas de le garder pour moi ! Plus vous en trouvez, plus je pourrai en faire.';

