-- Quest 7499 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7499, 'frFR', 'Excellent travail, $R. Si vous trouvez d\'autres tomes, n\'hésitez pas à nous les rendre.$B$BAu fil du temps, nous avons tendance à changer et même à ajouter de nouvelles récompenses pour le retour des tomes manquants.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, $R. Si vous trouvez d\'autres tomes, n\'hésitez pas à nous les rendre.$B$BAu fil du temps, nous avons tendance à changer et même à ajouter de nouvelles récompenses pour le retour des tomes manquants.';
