-- Quest 7507 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7507, 'frFR', 'Ah, l\'une de nos plus grandes compilations. Celle-ci est introuvable depuis des éternités.') ON DUPLICATE KEY UPDATE CompletionText='Ah, l\'une de nos plus grandes compilations. Celle-ci est introuvable depuis des éternités.';
-- Quest 7507 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7507, 'frFR', 'Vous auriez pu obtenir beaucoup d\'or pour ce livre sur le marché noir, $N$. Surtout que le sceau protecteur a été brisé, laissant les secrets du dépeçage de dragon visibles à quiconque possède l\'intellect requis pour assimiler les connaissances contenues dans les pages sacrées.$B$BPeut-être qu\'une grande récompense est de mise... Eh bien, une récompense qui nécessitera un effort énorme pour être obtenue.$B$B<Lydros sourit.>') ON DUPLICATE KEY UPDATE RewardText='Vous auriez pu obtenir beaucoup d\'or pour ce livre sur le marché noir, $N$. Surtout que le sceau protecteur a été brisé, laissant les secrets du dépeçage de dragon visibles à quiconque possède l\'intellect requis pour assimiler les connaissances contenues dans les pages sacrées.$B$BPeut-être qu\'une grande récompense est de mise... Eh bien, une récompense qui nécessitera un effort énorme pour être obtenue.$B$B<Lydros sourit.>';
-- Quest 7508 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7508, 'frFR', 'Si vous parvenez à entrer dans le repaire du dragon, à chauffer la lame sous son souffle ardent, et finalement à la tremper dans son sang, je lierai la lame pour votre usage.') ON DUPLICATE KEY UPDATE RewardText='Si vous parvenez à entrer dans le repaire du dragon, à chauffer la lame sous son souffle ardent, et finalement à la tremper dans son sang, je lierai la lame pour votre usage.';
-- Quest 7509 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7509, 'frFR', 'Peut-être qu\'un jour, un autre la maniera.') ON DUPLICATE KEY UPDATE CompletionText='Peut-être qu\'un jour, un autre la maniera.';
-- Quest 7509 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7509, 'frFR', '<Lydros murmure quelque chose d\'inintelligible.>$B$BComme promis, $c$, la lame de Quel\'Serrar.') ON DUPLICATE KEY UPDATE RewardText='<Lydros murmure quelque chose d\'inintelligible.>$B$BComme promis, $c$, la lame de Quel\'Serrar.';
-- Quest 7541 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (7541, 'frFR', 'Il faudra du temps à nos érudits pour étudier le pendentif que vous nous avez apporté. Mais pour votre service à la Horde, je voudrais vous offrir un petit présent.$B$BMerci, $N$. Vos actes vous honorent, et nous.') ON DUPLICATE KEY UPDATE RewardText='Il faudra du temps à nos érudits pour étudier le pendentif que vous nous avez apporté. Mais pour votre service à la Horde, je voudrais vous offrir un petit présent.$B$BMerci, $N$. Vos actes vous honorent, et nous.';

-- Quest 7563 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (7563, 'frFR', 'As-tu vu les bêtes chouines, $N? La magie de ces créatures est forte, et elle se concentre dans le sang qui coule à travers leurs formes torturées.') ON DUPLICATE KEY UPDATE CompletionText='As-tu vu les bêtes chouines, $N? La magie de ces créatures est forte, et elle se concentre dans le sang qui coule à travers leurs formes torturées.';
-- Quest 8223 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8223, 'frFR', 'Merci encore, <name>. Voici vos tickets !') ON DUPLICATE KEY UPDATE RewardText='Merci encore, <name>. Voici vos tickets !';
-- Quest 8353 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8353, 'frFR', 'Trop drôle ! Bien joué, <name>! Voici votre récompense.$B$BJoyeux Hallow\'s End!') ON DUPLICATE KEY UPDATE RewardText='Trop drôle ! Bien joué, <name>! Voici votre récompense.$B$BJoyeux Hallow\'s End!';
