-- Quest 8358 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8358, 'frFR', 'Woo-woo! Bien joué, <name>! Voici votre récompense.$B$BJoyeux Hallow\'s End!') ON DUPLICATE KEY UPDATE RewardText='Woo-woo! Bien joué, <name>! Voici votre récompense.$B$BJoyeux Hallow\'s End!';
-- Quest 8366 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8366, 'frFR', '<name>! Tu es le meilleur!!!$B$Je suis sûr que le Cartel va me laisser tranquille maintenant que tu t\'es occupé de ces déchets de Southsea. Voyons voir, qu\'est-ce que je peux te donner en récompense ? Que dirais-tu d\'un peu de monnaie et tu choisis parmi ceci pour tes ennuis ?') ON DUPLICATE KEY UPDATE RewardText='<name>! Tu es le meilleur!!!$B$Je suis sûr que le Cartel va me laisser tranquille maintenant que tu t\'es occupé de ces déchets de Southsea. Voyons voir, qu\'est-ce que je peux te donner en récompense ? Que dirais-tu d\'un peu de monnaie et tu choisis parmi ceci pour tes ennuis ?';
-- Quest 8426 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8426, 'frFR', 'Excellent ! Tu as prouvé ta valeur en défendant nos opérations à Warsong Gulch ! Que la nouvelle de ton honneur se propage largement sur nos terres.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Tu as prouvé ta valeur en défendant nos opérations à Warsong Gulch ! Que la nouvelle de ton honneur se propage largement sur nos terres.';

-- Quest 8427 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8427, 'frFR', 'La bataille à Warsong Gulch contre les Sentinelles de Silverwing est d\'une grande importance. Sous prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laissez pas cela arriver, $N! Revenez-moi avec une preuve d\'avoir servi la Horde d\'une manière digne !') ON DUPLICATE KEY UPDATE CompletionText='La bataille à Warsong Gulch contre les Sentinelles de Silverwing est d\'une grande importance. Sous prétexte de protéger une forêt qui ne leur appartient pas, l\'Alliance cherche à priver la Horde de l\'une de nos plus grandes sources de bois.$B$BNe laissez pas cela arriver, $N! Revenez-moi avec une preuve d\'avoir servi la Horde d\'une manière digne !';
