INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8655, 'frFR', 'Vous avez bien fait, <name>.  Vous avez prouvé que vous n\'êtes pas un mortel ordinaire.$B$Je vous donne ceci avec la confiance qu\'ils vous aideront à écraser les vile qiraji.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, <name>.  Vous avez prouvé que vous n\'êtes pas un mortel ordinaire.$B$Je vous donne ceci avec la confiance qu\'ils vous aideront à écraser les vile qiraji.';
