-- Quest 8687 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8687, 'frFR', 'Excellent travail, <name>.  Sans leurs mineurs, le silithide aura du mal à réparer tout dommage infligé à la structure de leur ruche.  Je suppose que tu voudras une nouvelle tâche.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>.  Sans leurs mineurs, le silithide aura du mal à réparer tout dommage infligé à la structure de leur ruche.  Je suppose que tu voudras une nouvelle tâche.';
