INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8688, 'frFR', 'Les cieux, dans leurs innombrables étoiles, contiennent les réponses aux mystères terrestres, $N$. Puissent, alors, les sages et les chanceux lever les yeux et trouver la vérité ?') ON DUPLICATE KEY UPDATE RewardText='Les cieux, dans leurs innombrables étoiles, contiennent les réponses aux mystères terrestres, $N$. Puissent, alors, les sages et les chanceux lever les yeux et trouver la vérité ?';
