-- Quest 8713 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8713, 'frFR', 'Les cieux, dans leurs innombrables étoiles, détiennent les réponses aux mystères terrestres, $N. Peut-être, alors, que les sages et les chanceux lèvent les yeux et trouvent la vérité ?') ON DUPLICATE KEY UPDATE RewardText='Les cieux, dans leurs innombrables étoiles, détiennent les réponses aux mystères terrestres, $N. Peut-être, alors, que les sages et les chanceux lèvent les yeux et trouvent la vérité ?';
