-- Quest 8728 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8728, 'frFR', 'Les bouées d\'Arcanite ne se fabriquent pas tout seules, $N. Et NON, vous ne pouvez pas emprunter de l\'argent.') ON DUPLICATE KEY UPDATE CompletionText='Les bouées d\'Arcanite ne se fabriquent pas tout seules, $N. Et NON, vous ne pouvez pas emprunter de l\'argent.';
-- Quest 8729 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8729, 'frFR', 'Le temps presse, champion.') ON DUPLICATE KEY UPDATE CompletionText='Le temps presse, champion.';
-- Quest 8730 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8730, 'frFR', 'Un autre de nos héros est perdu au spawn de Deathwing. Nous serons maudits par cette souffrance pour toujours...') ON DUPLICATE KEY UPDATE CompletionText='Un autre de nos héros est perdu au spawn de Deathwing. Nous serons maudits par cette souffrance pour toujours...';

-- Quest 8731 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8731, 'frFR', 'Vous avez terminé votre devoir de terrain, $N? Le Capitaine Skullsplit peut être trouvé à l\'extérieur de Hive\'Regal.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez terminé votre devoir de terrain, $N? Le Capitaine Skullsplit peut être trouvé à l\'extérieur de Hive\'Regal.';
-- Quest 8731 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8731, 'frFR', 'Je peux dire que Krug n\'a guère d\'utilité pour les papiers. Il a signé ceci avec du sang de silithid ! $B$Très bien, <name>. J\'ai préparé un ensemble de tâches qui devraient tirer parti de vos compétences en tant que <class>. $B$Avec les efforts continus de vous et de personnes comme vous, notre ennemi sera bientôt écrasé !') ON DUPLICATE KEY UPDATE RewardText='Je peux dire que Krug n\'a guère d\'utilité pour les papiers. Il a signé ceci avec du sang de silithid ! $B$Très bien, <name>. J\'ai préparé un ensemble de tâches qui devraient tirer parti de vos compétences en tant que <class>. $B$Avec les efforts continus de vous et de personnes comme vous, notre ennemi sera bientôt écrasé !';
-- Quest 8732 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8732, 'frFR', 'Je suppose que vous voulez que ces papiers soient signés, $Gboy:girl;?') ON DUPLICATE KEY UPDATE CompletionText='Je suppose que vous voulez que ces papiers soient signés, $Gboy:girl;?';
-- Quest 8732 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8732, 'frFR', 'Dans les vieux jours, j\'aurais marqué votre front avec le sang de la créature pour marquer votre accomplissement ici. Thrall insiste pour que nous nous conformions aux demandes des Druides.$B$Voici, prenez ces papiers et retournez au Cenarion Hold. Je suis sûr qu\'ils auront un travail approprié pour vous.') ON DUPLICATE KEY UPDATE RewardText='Dans les vieux jours, j\'aurais marqué votre front avec le sang de la créature pour marquer votre accomplissement ici. Thrall insiste pour que nous nous conformions aux demandes des Druides.$B$Voici, prenez ces papiers et retournez au Cenarion Hold. Je suis sûr qu\'ils auront un travail approprié pour vous.';
-- Quest 8733 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8733, 'frFR', 'Le wisp est silencieux, sauf un faible bourdonnement. Étrangement, il est capable de communiquer avec vous par la pensée.') ON DUPLICATE KEY UPDATE RewardText='Le wisp est silencieux, sauf un faible bourdonnement. Étrangement, il est capable de communiquer avec vous par la pensée.';
-- Quest 8734 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8734, 'frFR', 'Il serait impossible de tirer Eranikus du Rêve s\'il refusait. Ses intentions, cependant, exigent qu\'il entre dans notre monde. Il cherche à détruire la manifestation vivante de Malfurion. Pour y parvenir avec succès signifierait la fin de l\'un des alliés les plus puissants du Rêve. Le Cauchemar consumerait entièrement tout ce qui resterait si Malfurion tombait...') ON DUPLICATE KEY UPDATE RewardText='Il serait impossible de tirer Eranikus du Rêve s\'il refusait. Ses intentions, cependant, exigent qu\'il entre dans notre monde. Il cherche à détruire la manifestation vivante de Malfurion. Pour y parvenir avec succès signifierait la fin de l\'un des alliés les plus puissants du Rêve. Le Cauchemar consumerait entièrement tout ce qui resterait si Malfurion tombait...';
-- Quest 8735 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8735, 'frFR', 'Êtes-vous prêt ? Le monde est-il prêt pour ce que nous sommes sur le point d\'invoquer ? Je ne sais pas... Je suis lié par le devoir à Malfurion. Devoir et honneur...') ON DUPLICATE KEY UPDATE RewardText='Êtes-vous prêt ? Le monde est-il prêt pour ce que nous sommes sur le point d\'invoquer ? Je ne sais pas... Je suis lié par le devoir à Malfurion. Devoir et honneur...';
-- Quest 8736 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8736, 'frFR', 'Il est racheté, $Gname>. Il retourne maintenant au Rêve pour réparer ce qu\'il a seul mal fait. Eranikus sera un allié puissant pour Malfurion et mon père.$B<br :>Ces armements sont pour vous, <name; donnés par Ysera elle-même. Vous feriez bien d\'en faire usage dans vos batailles contre les Qiraji.') ON DUPLICATE KEY UPDATE RewardText='Il est racheté, $Gname>. Il retourne maintenant au Rêve pour réparer ce qu\'il a seul mal fait. Eranikus sera un allié puissant pour Malfurion et mon père.$B<br :>Ces armements sont pour vous, <name; donnés par Ysera elle-même. Vous feriez bien d\'en faire usage dans vos batailles contre les Qiraji.';

-- Quest 8737 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8737, 'frFR', 'Bon travail, <name>.  Voici votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, <name>.  Voici votre prochaine mission.';
-- Quest 8738 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8738, 'frFR', 'Vous trouverez le scout Landion à l\'intérieur de Hive\'regal. Dépêchez-vous, $N! Le temps presse.') ON DUPLICATE KEY UPDATE CompletionText='Vous trouverez le scout Landion à l\'intérieur de Hive\'regal. Dépêchez-vous, $N! Le temps presse.';
-- Quest 8738 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8738, 'frFR', 'Vos efforts sont grandement appréciés, <name>.  Je lirai ces rapports de reconnaissance immédiatement, n\'hésitez pas à passer à votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Vos efforts sont grandement appréciés, <name>.  Je lirai ces rapports de reconnaissance immédiatement, n\'hésitez pas à passer à votre prochaine mission.';
-- Quest 8739 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8739, 'frFR', 'Vous trouverez le scout Jalia à l\'intérieur de Hive\'Ashi. Dépêchez-vous, $N! Le temps presse.') ON DUPLICATE KEY UPDATE CompletionText='Vous trouverez le scout Jalia à l\'intérieur de Hive\'Ashi. Dépêchez-vous, $N! Le temps presse.';
-- Quest 8739 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8739, 'frFR', 'Vos efforts sont grandement appréciés, $N. Je lirai ces rapports de reconnaissance immédiatement, n\'hésitez pas à passer à votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Vos efforts sont grandement appréciés, $N. Je lirai ces rapports de reconnaissance immédiatement, n\'hésitez pas à passer à votre prochaine mission.';
-- Quest 8740 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8740, 'frFR', 'Bien joué, <name>.  Les maraudeurs crépusculaires infligeaient un nombre inacceptable de pertes à nos patrouilles.  Voici votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name>.  Les maraudeurs crépusculaires infligeaient un nombre inacceptable de pertes à nos patrouilles.  Voici votre prochaine mission.';
-- Quest 8741 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8741, 'frFR', 'Vos exploits seront connus de tous, champion. Ils chanteront vos louanges d\'Orgrimmar aux confins des Mers du Sud. Tous sauront du champion du Vol de Bronze, $N.') ON DUPLICATE KEY UPDATE RewardText='Vos exploits seront connus de tous, champion. Ils chanteront vos louanges d\'Orgrimmar aux confins des Mers du Sud. Tous sauront du champion du Vol de Bronze, $N.';
-- Quest 8742 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8742, 'frFR', 'Un millénaire s\'est écoulé et comme c\'était prédestiné, un se tient devant moi. Celui qui mènera son peuple à un nouvel âge.$B$BLe Vieux Dieu tremble, $N. Oh oui, il craint votre foi. Brisez la prophétie de C\'Thun.$B$BIl sait que vous arrivez, champion - et avec vous vient la puissance de Kalimdor. Il vous suffit de me faire savoir quand vous êtes prêt et je vous accorderai le Sceptre des Sables Mouvants.') ON DUPLICATE KEY UPDATE CompletionText='Un millénaire s\'est écoulé et comme c\'était prédestiné, un se tient devant moi. Celui qui mènera son peuple à un nouvel âge.$B$BLe Vieux Dieu tremble, $N. Oh oui, il craint votre foi. Brisez la prophétie de C\'Thun.$B$BIl sait que vous arrivez, champion - et avec vous vient la puissance de Kalimdor. Il vous suffit de me faire savoir quand vous êtes prêt et je vous accorderai le Sceptre des Sables Mouvants.';

-- Quest 8742 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8742, 'frFR', 'Le Sceptre des Sables Mouvants est entier une fois de plus, $N.$B$BC\'est vous qui utilisez le sceptre. C\'est vous qui annoncez la prochaine ère de votre peuple./n/Vous devez attendre que les armées de la Horde et de l\'Alliance arrivent à Silithus avant de pouvoir faire sonner le Gong de la Scarabée.') ON DUPLICATE KEY UPDATE RewardText='Le Sceptre des Sables Mouvants est entier une fois de plus, $N.$B$BC\'est vous qui utilisez le sceptre. C\'est vous qui annoncez la prochaine ère de votre peuple./n/Vous devez attendre que les armées de la Horde et de l\'Alliance arrivent à Silithus avant de pouvoir faire sonner le Gong de la Scarabée.';
-- Quest 8743 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8743, 'frFR', 'Le Gong de la Scarabée plane menaçant devant vous. Armez-vous, $N; car une fois que le Gong de la Scarabée est sonné, les portes d\'Ahn\'Qiraj s\'ouvriront.$B$BDe la gueule affaissée de la bête ne peut venir que le chaos et la destruction. Défendez votre peuple!') ON DUPLICATE KEY UPDATE CompletionText='Le Gong de la Scarabée plane menaçant devant vous. Armez-vous, $N; car une fois que le Gong de la Scarabée est sonné, les portes d\'Ahn\'Qiraj s\'ouvriront.$B$BDe la gueule affaissée de la bête ne peut venir que le chaos et la destruction. Défendez votre peuple!';
-- Quest 8743 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8743, 'frFR', 'Du sol près du gong pousse un cristal spécial. Peut-être un favori de la Descendance.') ON DUPLICATE KEY UPDATE RewardText='Du sol près du gong pousse un cristal spécial. Peut-être un favori de la Descendance.';
-- Quest 8744 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8744, 'frFR', 'La tag sur ce présent indique ::$b$bPour $N,$b$bQue votre fête du Grand-Hiver soit joyeuse et éclatante!') ON DUPLICATE KEY UPDATE RewardText='La tag sur ce présent indique ::$b$bPour $N,$b$bQue votre fête du Grand-Hiver soit joyeuse et éclatante!';
-- Quest 8745 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8745, 'frFR', 'Salutations, champion. Je suis Jonathan, gardien du gong sacré et observateur éternel du Vol en Bronze.$B$BI ai été habilité par le Temps Immuable lui-même pour vous accorder un objet de votre choix à partir de son trésor intemporel. Puisse-t-il vous aider dans vos batailles contre C\'Thun.') ON DUPLICATE KEY UPDATE RewardText='Salutations, champion. Je suis Jonathan, gardien du gong sacré et observateur éternel du Vol en Bronze.$B$BI ai été habilité par le Temps Immuable lui-même pour vous accorder un objet de votre choix à partir de son trésor intemporel. Puisse-t-il vous aider dans vos batailles contre C\'Thun.';
-- Quest 8746 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8746, 'frFR', '$N! L\'avez-vous trouvé? Les notes dans le sac que je vous ai donné étaient-elles suffisantes pour localiser Metzen? Je déteste penser ce que ces brutes cruelles pourraient lui faire... mais nous ne pouvons pas nous permettre de payer un tel prix exorbitant!') ON DUPLICATE KEY UPDATE CompletionText='$N! L\'avez-vous trouvé? Les notes dans le sac que je vous ai donné étaient-elles suffisantes pour localiser Metzen? Je déteste penser ce que ces brutes cruelles pourraient lui faire... mais nous ne pouvons pas nous permettre de payer un tel prix exorbitant!';
-- Quest 8746 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8746, 'frFR', 'Vous avez réussi!  Hourra!$B$BMetzen est retourné dans les étables du Grand-Père Hiver - oui Metzen peut vraiment voler - il y a un instant!  La poussière a fait son effet; je le savais.  Vous avez sauvé la Fête du Voile d\'Hiver ainsi que les Pâturages de Smokywood d\'un désastre.  Merci, <name>.$B$BÉcoutez... à cause de ce que vous avez fait ici, je veux que vous ayez ceci.  C\'est quelque chose de TRÈS spécial; si vous avez un monture, je pense que vous allez adorer.  Joyeux Voile d\'Hiver!') ON DUPLICATE KEY UPDATE RewardText='Vous avez réussi!  Hourra!$B$BMetzen est retourné dans les étables du Grand-Père Hiver - oui Metzen peut vraiment voler - il y a un instant!  La poussière a fait son effet; je le savais.  Vous avez sauvé la Fête du Voile d\'Hiver ainsi que les Pâturages de Smokywood d\'un désastre.  Merci, <name>.$B$BÉcoutez... à cause de ce que vous avez fait ici, je veux que vous ayez ceci.  C\'est quelque chose de TRÈS spécial; si vous avez un monture, je pense que vous allez adorer.  Joyeux Voile d\'Hiver!';
-- Quest 8747 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8747, 'frFR', 'Impressionnant, petit. Vous avez traversé beaucoup de difficultés pour obtenir le favori du Vol en Bronze. Votre dévouement est noté.$b$bL\'anneau de sceau du défenseur offrira une protection supérieure contre les forces du mal.$b$bSoyez averti, une fois que vous aurez choisi votre chemin, vous n\'aurez aucun recours si vous changez d\'avis.') ON DUPLICATE KEY UPDATE CompletionText='Impressionnant, petit. Vous avez traversé beaucoup de difficultés pour obtenir le favori du Vol en Bronze. Votre dévouement est noté.$b$bL\'anneau de sceau du défenseur offrira une protection supérieure contre les forces du mal.$b$bSoyez averti, une fois que vous aurez choisi votre chemin, vous n\'aurez aucun recours si vous changez d\'avis.';

-- Quest 8748 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8748, 'frFR', 'Votre défense continue des enfants de Kalimdor a été reconnue. Donnez-moi votre anneau de sceau afin que je puisse en améliorer les pouvoirs.') ON DUPLICATE KEY UPDATE CompletionText='Votre défense continue des enfants de Kalimdor a été reconnue. Donnez-moi votre anneau de sceau afin que je puisse en améliorer les pouvoirs.';
-- Quest 8748 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8748, 'frFR', 'Votre ascension au sein de la Troupes est très impressionnante, $N. Que vous ne dévieriez jamais du chemin du protecteur !') ON DUPLICATE KEY UPDATE RewardText='Votre ascension au sein de la Troupes est très impressionnante, $N. Que vous ne dévieriez jamais du chemin du protecteur !';
-- Quest 8749 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8749, 'frFR', 'Vous honorez ma race, $N. Abattez les ennemis de Kalimdor ! Montrez-leur ce que signifie défigurer la terre de la lumière éternelle.$b$bVous avez gagné une autre amélioration. Donnez-moi votre anneau de sceau afin que je puisse renforcer son pouvoir.') ON DUPLICATE KEY UPDATE CompletionText='Vous honorez ma race, $N. Abattez les ennemis de Kalimdor ! Montrez-leur ce que signifie défigurer la terre de la lumière éternelle.$b$bVous avez gagné une autre amélioration. Donnez-moi votre anneau de sceau afin que je puisse renforcer son pouvoir.';
