-- Quest 8750 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8750, 'frFR', 'Une dédicace de cette ampleur est une rareté. Vous avez montré que votre volonté est inébranlable, $N. Vous serez grandement récompensé pour votre garde fidèle sur notre monde.$b$bDonnez-moi votre anneau de sceau afin que je puisse renforcer son enchantement.') ON DUPLICATE KEY UPDATE CompletionText='Une dédicace de cette ampleur est une rareté. Vous avez montré que votre volonté est inébranlable, $N. Vous serez grandement récompensé pour votre garde fidèle sur notre monde.$b$bDonnez-moi votre anneau de sceau afin que je puisse renforcer son enchantement.';
