-- Quest 8751 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8751, 'frFR', 'Jamais je n\'ai vu une telle ténacité ! Le Vol de Bronze vous accorde un dernier enchantement. Le Temps Immuable l\'a demandé lui-même !$B$BDonnez-moi votre anneau de sceau afin que je puisse faire les ajustements nécessaires.') ON DUPLICATE KEY UPDATE CompletionText='Jamais je n\'ai vu une telle ténacité ! Le Vol de Bronze vous accorde un dernier enchantement. Le Temps Immuable l\'a demandé lui-même !$B$BDonnez-moi votre anneau de sceau afin que je puisse faire les ajustements nécessaires.';
-- Quest 8751 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8751, 'frFR', 'Levez-vous, Protecteur de Kalimdor ! Levez-vous et soyez reconnu !') ON DUPLICATE KEY UPDATE RewardText='Levez-vous, Protecteur de Kalimdor ! Levez-vous et soyez reconnu !';

-- Quest 8752 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8752, 'frFR', 'Impressionnant, petit. Tu as beaucoup souffert pour obtenir la faveur du Vol de Bronze. Ton dévouement est noté.$b$bL\'anneau de sceau du conquérant améliorera grandement tes attaques physiques.$b$bAttention, une fois que tu auras choisi ton chemin, tu n\'auras aucun recours si tu changes d\'avis.') ON DUPLICATE KEY UPDATE CompletionText='Impressionnant, petit. Tu as beaucoup souffert pour obtenir la faveur du Vol de Bronze. Ton dévouement est noté.$b$bL\'anneau de sceau du conquérant améliorera grandement tes attaques physiques.$b$bAttention, une fois que tu auras choisi ton chemin, tu n\'auras aucun recours si tu changes d\'avis.';
