INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8753, 'frFR', 'Ta défense continue des enfants de Kalimdor a été reconnue. Donne-moi ton anneau de sceau afin que je puisse en améliorer les pouvoirs.') ON DUPLICATE KEY UPDATE CompletionText='Ta défense continue des enfants de Kalimdor a été reconnue. Donne-moi ton anneau de sceau afin que je puisse en améliorer les pouvoirs.';
