INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8757, 'frFR', 'Impressionnant, petit. Tu as beaucoup de peine à enduré pour obtenir la faveur du Vol de Bronze. Ton dévouement est noté.$b$bL\'anneau de sceau de l\'invocateur améliorera grandement tes capacités magiques et naturelles.$b$bAttention, une fois que tu auras choisi ton chemin, tu n\'auras aucun recours si tu changes d\'avis.') ON DUPLICATE KEY UPDATE CompletionText='Impressionnant, petit. Tu as beaucoup de peine à enduré pour obtenir la faveur du Vol de Bronze. Ton dévouement est noté.$b$bL\'anneau de sceau de l\'invocateur améliorera grandement tes capacités magiques et naturelles.$b$bAttention, une fois que tu auras choisi ton chemin, tu n\'auras aucun recours si tu changes d\'avis.';
