-- Quest 8762 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8762, 'frFR', '$N! Les notes dans le sac que je t\'ai donné étaient-elles suffisantes pour localiser Metzen ? Je déteste penser ce que ces brutes cruelles pourraient lui faire... mais il n\'y a aucun moyen que nous puissions payer un tel prix exorbitant pour une rançon !') ON DUPLICATE KEY UPDATE CompletionText='$N! Les notes dans le sac que je t\'ai donné étaient-elles suffisantes pour localiser Metzen ? Je déteste penser ce que ces brutes cruelles pourraient lui faire... mais il n\'y a aucun moyen que nous puissions payer un tel prix exorbitant pour une rançon !';
-- Quest 8762 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8762, 'frFR', 'Tu l\'as fait !  Hourra !$B$BMetzen est rentré dans les écuries du Grand-Père Hiver - oui, Metzen peut vraiment voler - il y a un instant !  La poussière a fait son effet ; je savais que ça marcherait.  Tu as sauvé la Fête du Voile d\'Hiver ainsi que les Pâturages de Smokywood d\'un désastre.  Merci, <name>.$B$BÉcoute... à cause de ce que tu as fait ici, je veux que tu aies ceci.  C\'est quelque chose de TRÈS spécial ; si tu as un monture, je pense que tu vas adorer.  Joyeux Voile d\'Hiver !') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait !  Hourra !$B$BMetzen est rentré dans les écuries du Grand-Père Hiver - oui, Metzen peut vraiment voler - il y a un instant !  La poussière a fait son effet ; je savais que ça marcherait.  Tu as sauvé la Fête du Voile d\'Hiver ainsi que les Pâturages de Smokywood d\'un désastre.  Merci, <name>.$B$BÉcoute... à cause de ce que tu as fait ici, je veux que tu aies ceci.  C\'est quelque chose de TRÈS spécial ; si tu as un monture, je pense que tu vas adorer.  Joyeux Voile d\'Hiver !';
-- Quest 8764 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8764, 'frFR', 'Champion, si tu décides de suivre un autre chemin, présente-moi ton anneau de sceau et une montagne de scarabées de nos ennemis dans Ahn\'Qiraj.') ON DUPLICATE KEY UPDATE CompletionText='Champion, si tu décides de suivre un autre chemin, présente-moi ton anneau de sceau et une montagne de scarabées de nos ennemis dans Ahn\'Qiraj.';
