INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8780, 'frFR', 'Merci, je les donnerai aux gars.') ON DUPLICATE KEY UPDATE RewardText='Merci, je les donnerai aux gars.';
-- Quest 8781 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8781, 'frFR', 'Oh, excellent ! Je n\'aurai plus à entendre de plaintes sur les lames émoussées. Merci, $N.') ON DUPLICATE KEY UPDATE RewardText='Oh, excellent ! Je n\'aurai plus à entendre de plaintes sur les lames émoussées. Merci, $N.';
-- Quest 8782 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8782, 'frFR', 'Ah, nous en avions besoin. Votre travail est apprécié, <name>.') ON DUPLICATE KEY UPDATE RewardText='Ah, nous en avions besoin. Votre travail est apprécié, <name>.';
-- Quest 8783 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8783, 'frFR', 'Ah, oui. Ces matériaux sont d\'excellente qualité. Merci, <name>.') ON DUPLICATE KEY UPDATE RewardText='Ah, oui. Ces matériaux sont d\'excellente qualité. Merci, <name>.';
-- Quest 8785 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8785, 'frFR', 'Ah, oui. Juste ce qu\'il me fallait ! J\'en ferai une concoction spéciale. Le silithide n\'aimera pas ça du tout !') ON DUPLICATE KEY UPDATE RewardText='Ah, oui. Juste ce qu\'il me fallait ! J\'en ferai une concoction spéciale. Le silithide n\'aimera pas ça du tout !';
-- Quest 8786 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8786, 'frFR', 'Excellent travail. Nous étions en pénurie de ces objets, $N.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail. Nous étions en pénurie de ces objets, $N.';
-- Quest 8787 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8787, 'frFR', 'Ah, oui... Je les distribuerai aux troupes, $N. La Légion d\'Orgrimmar vous remercie !') ON DUPLICATE KEY UPDATE RewardText='Ah, oui... Je les distribuerai aux troupes, $N. La Légion d\'Orgrimmar vous remercie !';
-- Quest 8788 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8788, 'frFR', 'Ce présent semble avoir été secoué plusieurs fois. L\'étiquette indique :$b$bPour un $r $c très spécial.') ON DUPLICATE KEY UPDATE RewardText='Ce présent semble avoir été secoué plusieurs fois. L\'étiquette indique :$b$bPour un $r $c très spécial.';

-- Quest 8789 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8789, 'frFR', 'Recherche ce que j\'ai demandé. Tu deviendras plus grand que la somme de tes parties, champion.') ON DUPLICATE KEY UPDATE CompletionText='Recherche ce que j\'ai demandé. Tu deviendras plus grand que la somme de tes parties, champion.';
-- Quest 8789 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8789, 'frFR', 'Infusées d\'Elementium, ces armes traverseront les Qiraji et leur Dieu avec une facilité incroyable.') ON DUPLICATE KEY UPDATE RewardText='Infusées d\'Elementium, ces armes traverseront les Qiraji et leur Dieu avec une facilité incroyable.';
-- Quest 8790 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8790, 'frFR', 'Tu les abattras et nous libéreras de ces liens.') ON DUPLICATE KEY UPDATE CompletionText='Tu les abattras et nous libéreras de ces liens.';
-- Quest 8790 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8790, 'frFR', 'Utilise l\'objet bien, <name>. Qu\'ils ressentent la douleur qu\'ils souhaitent tant infliger aux autres.') ON DUPLICATE KEY UPDATE RewardText='Utilise l\'objet bien, <name>. Qu\'ils ressentent la douleur qu\'ils souhaitent tant infliger aux autres.';
-- Quest 8792 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8792, 'frFR', 'Throm\'ka, $c! C\'est bon de voir tant de membres de la Horde, comme toi, $N, venir apporter leur soutien pour préparer la prochaine Guerre d\'Ahn\'Qiraj. Les efforts ici assureront que nous serons victorieux contre les Silithid et leurs maîtres maléfiques cachés à l\'intérieur d\'Ahn\'Qiraj.$b$bAlors maintenant que tu es là, assure-toi de parler aux divers collecteurs et d\'offrir ton assistance pour rassembler les matériaux auxquels tu es apte.') ON DUPLICATE KEY UPDATE RewardText='Throm\'ka, $c! C\'est bon de voir tant de membres de la Horde, comme toi, $N, venir apporter leur soutien pour préparer la prochaine Guerre d\'Ahn\'Qiraj. Les efforts ici assureront que nous serons victorieux contre les Silithid et leurs maîtres maléfiques cachés à l\'intérieur d\'Ahn\'Qiraj.$b$bAlors maintenant que tu es là, assure-toi de parler aux divers collecteurs et d\'offrir ton assistance pour rassembler les matériaux auxquels tu es apte.';
-- Quest 8793 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8793, 'frFR', 'Throm\'ka, $c! C\'est bon de voir tant de membres de la Horde, comme toi, $N, venir apporter leur soutien pour préparer la prochaine Guerre d\'Ahn\'Qiraj. Les efforts ici assureront que nous serons victorieux contre les Silithid et leurs maîtres maléfiques cachés à l\'intérieur d\'Ahn\'Qiraj.$b$bAlors maintenant que tu es là, assure-toi de parler aux divers collecteurs et d\'offrir ton assistance pour rassembler les matériaux auxquels tu es apte.') ON DUPLICATE KEY UPDATE RewardText='Throm\'ka, $c! C\'est bon de voir tant de membres de la Horde, comme toi, $N, venir apporter leur soutien pour préparer la prochaine Guerre d\'Ahn\'Qiraj. Les efforts ici assureront que nous serons victorieux contre les Silithid et leurs maîtres maléfiques cachés à l\'intérieur d\'Ahn\'Qiraj.$b$bAlors maintenant que tu es là, assure-toi de parler aux divers collecteurs et d\'offrir ton assistance pour rassembler les matériaux auxquels tu es apte.';
