INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8794, 'frFR', 'Throm\'ka, $c! C\'est bon de voir tant de membres de la Horde, comme toi, $N, venir apporter leur soutien pour préparer la prochaine Guerre d\'Ahn\'Qiraj. Les efforts ici assureront que nous serons victorieux contre les Silithid et leurs maîtres maléfiques cachés à l\'intérieur d\'Ahn\'Qiraj.$b$bAlors maintenant que tu es là, assure-toi de parler aux divers collecteurs et d\'offrir ton assistance pour rassembler les matériaux auxquels tu es apte.') ON DUPLICATE KEY UPDATE RewardText='Throm\'ka, $c! C\'est bon de voir tant de membres de la Horde, comme toi, $N, venir apporter leur soutien pour préparer la prochaine Guerre d\'Ahn\'Qiraj. Les efforts ici assureront que nous serons victorieux contre les Silithid et leurs maîtres maléfiques cachés à l\'intérieur d\'Ahn\'Qiraj.$b$bAlors maintenant que tu es là, assure-toi de parler aux divers collecteurs et d\'offrir ton assistance pour rassembler les matériaux auxquels tu es apte.';
-- Quest 8798 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8798, 'frFR', 'Dis ! Tu sais quoi ?! Tu es aussi ingénieur ! Alors, puisque tu m\'as aidé à donner une leçon à mes amis, je vais t\'apprendre à fabriquer ton propre yéti mécanique ! Maintenant, le plaisir peut durer pour toujours et toujours, et tu peux effrayer qui tu veux ! Pourvu que tu puisses trouver les composants pour le faire. $B$BQu\'en dis-tu, $N ? Veux-tu apprendre le secret pour fabriquer un yéti mécanique ?') ON DUPLICATE KEY UPDATE RewardText='Dis ! Tu sais quoi ?! Tu es aussi ingénieur ! Alors, puisque tu m\'as aidé à donner une leçon à mes amis, je vais t\'apprendre à fabriquer ton propre yéti mécanique ! Maintenant, le plaisir peut durer pour toujours et toujours, et tu peux effrayer qui tu veux ! Pourvu que tu puisses trouver les composants pour le faire. $B$BQu\'en dis-tu, $N ? Veux-tu apprendre le secret pour fabriquer un yéti mécanique ?';

-- Quest 8801 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8801, 'frFR', '$G Lord:Lady; $N, vous nous avez libérés de son emprise.') ON DUPLICATE KEY UPDATE CompletionText='$G Lord:Lady; $N, vous nous avez libérés de son emprise.';
-- Quest 8802 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8802, 'frFR', 'Le Maître vous laisse ceci, champion. De la cache intemporelle : une collection d\'artefacts couvrant des milliers d\'années - le choix vous revient.') ON DUPLICATE KEY UPDATE RewardText='Le Maître vous laisse ceci, champion. De la cache intemporelle : une collection d\'artefacts couvrant des milliers d\'années - le choix vous revient.';
-- Quest 8803 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8803, 'frFR', 'La note sur ce présent indique :$b$À $N,$b$En espérant que cela vous aidera à répandre des nouvelles chaleureuses et de la joie des fêtes à tout Azeroth.$b$De Grand-père Hiver') ON DUPLICATE KEY UPDATE RewardText='La note sur ce présent indique :$b$À $N,$b$En espérant que cela vous aidera à répandre des nouvelles chaleureuses et de la joie des fêtes à tout Azeroth.$b$De Grand-père Hiver';
