INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8810, 'frFR', 'Juste à temps. Ces fournitures sauveront des vies, $N. Votre travail est apprécié. Voici votre prochaine mission.') ON DUPLICATE KEY UPDATE RewardText='Juste à temps. Ces fournitures sauveront des vies, $N. Votre travail est apprécié. Voici votre prochaine mission.';

-- Quest 8811 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8811, 'frFR', 'Très bien - vos actes ont été enregistrés, et vous êtes dûment reconnu pour vos efforts. Continuez votre bon travail, $c.$B$BSi vous avez d\'autres sceaux à remettre, alors je peux vous aider davantage à ce sujet.') ON DUPLICATE KEY UPDATE RewardText='Très bien - vos actes ont été enregistrés, et vous êtes dûment reconnu pour vos efforts. Continuez votre bon travail, $c.$B$BSi vous avez d\'autres sceaux à remettre, alors je peux vous aider davantage à ce sujet.';
