-- Quest 8819 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8819, 'frFR', 'Excellent! C\'est un sacrifice non négligeable que vous avez fait pour obtenir ces signets, et vous serez récompensé pour votre service de manière appropriée. Ce sont des aventuriers comme vous, $N, qui font vraiment la différence.$B$BDites-moi si vous avez d\'autres signets à remettre ; je serai ravi de vous aider avec tout ce dont vous avez besoin d\'échanger.') ON DUPLICATE KEY UPDATE RewardText='Excellent! C\'est un sacrifice non négligeable que vous avez fait pour obtenir ces signets, et vous serez récompensé pour votre service de manière appropriée. Ce sont des aventuriers comme vous, $N, qui font vraiment la différence.$B$BDites-moi si vous avez d\'autres signets à remettre ; je serai ravi de vous aider avec tout ce dont vous avez besoin d\'échanger.';
