-- Quest 8829 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8829, 'frFR', 'Oui, je crois que cela suffira. Je vais les confectionner dans les couleurs portées par les émissaires du Marteau Crépusculaire. Je prie Elune que mes compétences puissent tromper nos ennemis une fois de plus.$b$bMais ne t\'inquiète pas de cela, tu as fait ta part et pour cela tu seras récompensé de manière appropriée. Tu es un allié loyal et digne, $N.') ON DUPLICATE KEY UPDATE RewardText='Oui, je crois que cela suffira. Je vais les confectionner dans les couleurs portées par les émissaires du Marteau Crépusculaire. Je prie Elune que mes compétences puissent tromper nos ennemis une fois de plus.$b$bMais ne t\'inquiète pas de cela, tu as fait ta part et pour cela tu seras récompensé de manière appropriée. Tu es un allié loyal et digne, $N.';
-- Quest 8830 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8830, 'frFR', 'Très bien - tes exploits ont été enregistrés, et tu es dûment reconnu pour tes efforts. Continue ton bon travail, $c.$B$BSi tu as d\'autres sceaux à remettre, alors je peux t\'aider davantage à ce sujet.') ON DUPLICATE KEY UPDATE RewardText='Très bien - tes exploits ont été enregistrés, et tu es dûment reconnu pour tes efforts. Continue ton bon travail, $c.$B$BSi tu as d\'autres sceaux à remettre, alors je peux t\'aider davantage à ce sujet.';
-- Quest 8831 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8831, 'frFR', 'Excellent ! C\'est un sacrifice non négligeable que tu as fait pour obtenir ces sceaux, et tu seras reconnu pour ton service de manière appropriée. Ce sont des aventuriers comme toi, $N, qui font vraiment la différence.$B$BDis-moi si tu as d\'autres sceaux à remettre ; je t\'aiderai volontiers avec tout ce dont tu as besoin d\'échanger.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! C\'est un sacrifice non négligeable que tu as fait pour obtenir ces sceaux, et tu seras reconnu pour ton service de manière appropriée. Ce sont des aventuriers comme toi, $N, qui font vraiment la différence.$B$BDis-moi si tu as d\'autres sceaux à remettre ; je t\'aiderai volontiers avec tout ce dont tu as besoin d\'échanger.';
