-- Quest 8845 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8845, 'frFR', 'Excellent! C\'est un sacrifice non négligeable que vous avez fait pour obtenir ces signets, et vous serez reconnu pour votre service de manière appropriée. Ce sont des aventuriers comme vous, $N$, qui font vraiment la différence.$B$Dites-moi si vous avez d\'autres signets à remettre ; je serai ravi de vous aider avec tout ce dont vous avez besoin d\'échanger.') ON DUPLICATE KEY UPDATE RewardText='Excellent! C\'est un sacrifice non négligeable que vous avez fait pour obtenir ces signets, et vous serez reconnu pour votre service de manière appropriée. Ce sont des aventuriers comme vous, $N$, qui font vraiment la différence.$B$Dites-moi si vous avez d\'autres signets à remettre ; je serai ravi de vous aider avec tout ce dont vous avez besoin d\'échanger.';
-- Quest 8846 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8846, 'frFR', 'Ah, ici pour des fournitures supplémentaires pour vous, c\'est ça ? Eh bien, je peux certainement comprendre le besoin de matériel supplémentaire... jetez un œil autour si vous avez besoin de preuves.$B$Je vous donnerai des fournitures supplémentaires, mais vous devrez me donner un nombre approprié de signets de commendation en échange. Vous n\'obtiendrez aucune reconnaissance pour remettre les signets de cette manière, mais vous pourriez trouver quelque chose d\'utile qui vous aidera à rester en vie lorsque la bataille aura finalement lieu.') ON DUPLICATE KEY UPDATE CompletionText='Ah, ici pour des fournitures supplémentaires pour vous, c\'est ça ? Eh bien, je peux certainement comprendre le besoin de matériel supplémentaire... jetez un œil autour si vous avez besoin de preuves.$B$Je vous donnerai des fournitures supplémentaires, mais vous devrez me donner un nombre approprié de signets de commendation en échange. Vous n\'obtiendrez aucune reconnaissance pour remettre les signets de cette manière, mais vous pourriez trouver quelque chose d\'utile qui vous aidera à rester en vie lorsque la bataille aura finalement lieu.';
-- Quest 8846 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8846, 'frFR', 'Eh bien, c\'est réglé ; voici vos fournitures, $C$. Si vous souhaitez faire un échange supplémentaire, alors je suis prêt à l\'autoriser. Donnez-moi juste le mot et je le ferai. $B$Continuez votre bon travail, $N$. Nous avons besoin de tout le matériel que nous pouvons rassembler si nous voulons gagner cette affaire. Si nous faisons tous notre part, alors la victoire sera nôtre à prendre !') ON DUPLICATE KEY UPDATE RewardText='Eh bien, c\'est réglé ; voici vos fournitures, $C$. Si vous souhaitez faire un échange supplémentaire, alors je suis prêt à l\'autoriser. Donnez-moi juste le mot et je le ferai. $B$Continuez votre bon travail, $N$. Nous avons besoin de tout le matériel que nous pouvons rassembler si nous voulons gagner cette affaire. Si nous faisons tous notre part, alors la victoire sera nôtre à prendre !';
