-- Quest 8852 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8852, 'frFR', 'Alors, c\'est réglé ; voici vos fournitures, $C. Si vous souhaitez faire un échange supplémentaire, je suis prêt à l\'autoriser. Donnez-moi juste le mot et je le ferai. $B$BContinuez comme ça, $N. Nous avons besoin de tout le matériel que nous pouvons rassembler si nous voulons gagner ce truc. Si nous faisons tous notre part, alors la victoire sera nôtre !') ON DUPLICATE KEY UPDATE RewardText='Alors, c\'est réglé ; voici vos fournitures, $C. Si vous souhaitez faire un échange supplémentaire, je suis prêt à l\'autoriser. Donnez-moi juste le mot et je le ferai. $B$BContinuez comme ça, $N. Nous avons besoin de tout le matériel que nous pouvons rassembler si nous voulons gagner ce truc. Si nous faisons tous notre part, alors la victoire sera nôtre !';
-- Quest 8853 [RequestItems]
