-- Quest 8855 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8855, 'frFR', 'Alors, c\'est réglé ; voici vos fournitures, $C. Si vous souhaitez faire un échange supplémentaire, alors je suis prêt à l\'autoriser. Donnez-moi juste le mot et je le ferai. $B$BContinuez comme ça, $N. Nous avons besoin de tout le matériel que nous pouvons rassembler si nous voulons gagner ce truc. Si nous faisons tous notre part, alors la victoire sera à nous !') ON DUPLICATE KEY UPDATE RewardText='Alors, c\'est réglé ; voici vos fournitures, $C. Si vous souhaitez faire un échange supplémentaire, alors je suis prêt à l\'autoriser. Donnez-moi juste le mot et je le ferai. $B$BContinuez comme ça, $N. Nous avons besoin de tout le matériel que nous pouvons rassembler si nous voulons gagner ce truc. Si nous faisons tous notre part, alors la victoire sera à nous !';
-- Quest 8857 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8857, 'frFR', 'Oh, les poulets que je vais fabriquer à partir de cette coquille merveilleuse ! Bien joué, mon $gboy:girl; !') ON DUPLICATE KEY UPDATE RewardText='Oh, les poulets que je vais fabriquer à partir de cette coquille merveilleuse ! Bien joué, mon $gboy:girl; !';
-- Quest 8858 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8858, 'frFR', 'Excellent. Nous pourrions certainement concevoir une armure incroyablement puissante à partir de ce chitine. Voici la richesse que l\'on vous avait promise.') ON DUPLICATE KEY UPDATE RewardText='Excellent. Nous pourrions certainement concevoir une armure incroyablement puissante à partir de ce chitine. Voici la richesse que l\'on vous avait promise.';
-- Quest 8859 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8859, 'frFR', 'Vous avez l\'air un peu lourd dans les bottes, ami.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez l\'air un peu lourd dans les bottes, ami.';

-- Quest 8859 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8859, 'frFR', 'Excellent et opportun ! Bien joué, $Glad:lass;.') ON DUPLICATE KEY UPDATE RewardText='Excellent et opportun ! Bien joué, $Glad:lass;.';
-- Quest 8861 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8861, 'frFR', 'Bonjour, $C! Êtes-vous venu à Thunder Bluff pour nos célébrations ? Ou êtes-vous ici pour reposer une patte fatiguée entre les chasses ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $C! Êtes-vous venu à Thunder Bluff pour nos célébrations ? Ou êtes-vous ici pour reposer une patte fatiguée entre les chasses ?';
-- Quest 8861 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8861, 'frFR', 'Oh, très bien !  Ces provisions aideront à nourrir tout notre peuple, ici pour célébrer la nouvelle année !$B$BI merci, <name>.  Je vous suis redevable.  S\'il vous plaît, prenez ces pièces... et écoutez mon conseil - buvez abondamment des tonneaux dehors, et rejoignez nos festois dans une danse de célébration !') ON DUPLICATE KEY UPDATE RewardText='Oh, très bien !  Ces provisions aideront à nourrir tout notre peuple, ici pour célébrer la nouvelle année !$B$BI merci, <name>.  Je vous suis redevable.  S\'il vous plaît, prenez ces pièces... et écoutez mon conseil - buvez abondamment des tonneaux dehors, et rejoignez nos festois dans une danse de célébration !';
-- Quest 8862 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8862, 'frFR', 'La bougie d\'Elune est un artefact de grande vénération pour les disciples du Festival Lunaire. Contenue dans la bougie se trouve la vraie lumière de la lune, prête à être libérée !$b$bCette lumière est inoffensive pour la plupart des créatures, mais vous verrez qu\'Omen et ses sbires sont brûlés et éblouis par elle.') ON DUPLICATE KEY UPDATE CompletionText='La bougie d\'Elune est un artefact de grande vénération pour les disciples du Festival Lunaire. Contenue dans la bougie se trouve la vraie lumière de la lune, prête à être libérée !$b$bCette lumière est inoffensive pour la plupart des créatures, mais vous verrez qu\'Omen et ses sbires sont brûlés et éblouis par elle.';
-- Quest 8862 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8862, 'frFR', 'Très bien alors - j\'accepte ces pièces d\'ascendance. Veuillez prendre la bougie d\'Elune avec ma bénédiction. Veuillez également profiter de ces feux d\'artifice offerts.$B$BQue votre Festival Lunaire soit joyeux et rempli de gaieté, $N.$B$BEt si vous choisissez d\'affronter Omen et ses sbires, vous trouverez la bougie d\'Elune très utile...') ON DUPLICATE KEY UPDATE RewardText='Très bien alors - j\'accepte ces pièces d\'ascendance. Veuillez prendre la bougie d\'Elune avec ma bénédiction. Veuillez également profiter de ces feux d\'artifice offerts.$B$BQue votre Festival Lunaire soit joyeux et rempli de gaieté, $N.$B$BEt si vous choisissez d\'affronter Omen et ses sbires, vous trouverez la bougie d\'Elune très utile...';
-- Quest 8863 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8863, 'frFR', 'Excellent - veuillez déguster ces dumplings avec mes compliments. Bien qu\'ils ne soient qu\'un petit signe d\'appréciation pour l\'honneur que vous vous êtes donné par vos actions, je pense que vous les apprécierez de toute façon.$B$BSi vous avez d\'autres pièces d\'ascendance, je suis prêt à vous offrir un large éventail d\'articles en échange.') ON DUPLICATE KEY UPDATE RewardText='Excellent - veuillez déguster ces dumplings avec mes compliments. Bien qu\'ils ne soient qu\'un petit signe d\'appréciation pour l\'honneur que vous vous êtes donné par vos actions, je pense que vous les apprécierez de toute façon.$B$BSi vous avez d\'autres pièces d\'ascendance, je suis prêt à vous offrir un large éventail d\'articles en échange.';
-- Quest 8864 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8864, 'frFR', 'J\'ai une sélection de robes qui pourraient vous intéresser. Ces robes ont été portées par le passé pendant le Festival Lunaire, et la sélection que j\'ai aujourd\'hui est peut-être la plus belle que j\'aie jamais vue. Chacune est fabriquée à la main avec les composants les plus fins et les plus doux.$B$BEn échange de quelques pièces d\'ascendance, je vous laisserai choisir l\'un des trois styles que j\'ai à garder pour vous. Est-ce acceptable pour vous ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ai une sélection de robes qui pourraient vous intéresser. Ces robes ont été portées par le passé pendant le Festival Lunaire, et la sélection que j\'ai aujourd\'hui est peut-être la plus belle que j\'aie jamais vue. Chacune est fabriquée à la main avec les composants les plus fins et les plus doux.$B$BEn échange de quelques pièces d\'ascendance, je vous laisserai choisir l\'un des trois styles que j\'ai à garder pour vous. Est-ce acceptable pour vous ?';
-- Quest 8864 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8864, 'frFR', 'Très bien alors - j\'accepte ces pièces d\'ascendance. Veuillez prendre votre robe avec ma bénédiction. Veuillez également profiter de ces feux d\'artifice offerts.$B$BComme vous avez honoré vos anciens, vous m\'honorez par votre simple présence. Merci, et que votre Festival Lunaire soit joyeux.') ON DUPLICATE KEY UPDATE RewardText='Très bien alors - j\'accepte ces pièces d\'ascendance. Veuillez prendre votre robe avec ma bénédiction. Veuillez également profiter de ces feux d\'artifice offerts.$B$BComme vous avez honoré vos anciens, vous m\'honorez par votre simple présence. Merci, et que votre Festival Lunaire soit joyeux.';

-- Quest 8865 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8865, 'frFR', 'Je suis heureux de vous informer que je dispose d\'une sélection fine de pantalon festifs disponibles pour vous... mais uniquement en échange de pièces d\'ascendance. Si la mode est importante pour vous, alors c\'est ce que vous cherchez ! Je vous assure que vous ne trouverez pas de pantalons comme ceux-ci ailleurs.$B$BEn échange de quelques pièces d\'ascendance, je vous laisserai choisir parmi les trois styles que j\'ai à garder pour vous. Est-ce acceptable pour vous ?') ON DUPLICATE KEY UPDATE CompletionText='Je suis heureux de vous informer que je dispose d\'une sélection fine de pantalon festifs disponibles pour vous... mais uniquement en échange de pièces d\'ascendance. Si la mode est importante pour vous, alors c\'est ce que vous cherchez ! Je vous assure que vous ne trouverez pas de pantalons comme ceux-ci ailleurs.$B$BEn échange de quelques pièces d\'ascendance, je vous laisserai choisir parmi les trois styles que j\'ai à garder pour vous. Est-ce acceptable pour vous ?';
-- Quest 8865 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8865, 'frFR', 'Très bien alors - j\'accepte ces pièces d\'ascendance. Veuillez prendre votre pantalon avec ma bénédiction. De plus, veuillez profiter de ces feux d\'artifice gratuits.$B$BSi vous avez plus de pièces d\'ascendance à échanger, alors parlez-m\'en à nouveau. J\'offrirai divers objets tout au long du Festival Lunaire.') ON DUPLICATE KEY UPDATE RewardText='Très bien alors - j\'accepte ces pièces d\'ascendance. Veuillez prendre votre pantalon avec ma bénédiction. De plus, veuillez profiter de ces feux d\'artifice gratuits.$B$BSi vous avez plus de pièces d\'ascendance à échanger, alors parlez-m\'en à nouveau. J\'offrirai divers objets tout au long du Festival Lunaire.';
-- Quest 8866 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8866, 'frFR', 'C\'est bon de savoir que les gens de cette terre rendent encore hommage aux anciennes races. Je vous souhaite le meilleur, $N, et vous offre ce jeton...') ON DUPLICATE KEY UPDATE RewardText='C\'est bon de savoir que les gens de cette terre rendent encore hommage aux anciennes races. Je vous souhaite le meilleur, $N, et vous offre ce jeton...';
-- Quest 8867 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8867, 'frFR', 'Avez-vous trouvé les lanceurs, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé les lanceurs, $N ?';
-- Quest 8876 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8876, 'frFR', 'Ah, très bien. Voici vos recettes, $N, et mon Elune vous bénit.') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien. Voici vos recettes, $N, et mon Elune vous bénit.';
-- Quest 8877 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8877, 'frFR', 'Voici, $N. Voici le schéma pour créer un lanceur de feux d\'artifice. Placez les lanceurs là où vous souhaitez célébrer, puis accueillez vos amis pour vous joindre à vous !') ON DUPLICATE KEY UPDATE RewardText='Voici, $N. Voici le schéma pour créer un lanceur de feux d\'artifice. Placez les lanceurs là où vous souhaitez célébrer, puis accueillez vos amis pour vous joindre à vous !';
-- Quest 8878 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8878, 'frFR', 'Voici les modèles, $N. Je suis sûr que vous trouverez le produit de cette connaissance tout à fait beau.') ON DUPLICATE KEY UPDATE RewardText='Voici les modèles, $N. Je suis sûr que vous trouverez le produit de cette connaissance tout à fait beau.';
-- Quest 8879 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8879, 'frFR', 'Très bien - j\'accepte ces pièces d\'ascendance. Voici vos recettes, $N. Puissiez-vous les utiliser pour répandre la gloire d\'Elune !') ON DUPLICATE KEY UPDATE RewardText='Très bien - j\'accepte ces pièces d\'ascendance. Voici vos recettes, $N. Puissiez-vous les utiliser pour répandre la gloire d\'Elune !';

-- Quest 8880 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8880, 'frFR', 'Voici, $N. Prends ces recettes et apprends leurs secrets. Je te souhaite bonne fortune, et j\'attends avec impatience de voir tes créations magnifiques.') ON DUPLICATE KEY UPDATE RewardText='Voici, $N. Prends ces recettes et apprends leurs secrets. Je te souhaite bonne fortune, et j\'attends avec impatience de voir tes créations magnifiques.';
-- Quest 8881 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8881, 'frFR', 'Les fusées à grappes larges nécessitent d\'immenses ressources et un savoir-faire pour être créées, mais leur brillance et leur beauté valent cet effort ! Apporte-moi des pièces d\'ascendance et je te donnerai la connaissance de leur fabrication.') ON DUPLICATE KEY UPDATE CompletionText='Les fusées à grappes larges nécessitent d\'immenses ressources et un savoir-faire pour être créées, mais leur brillance et leur beauté valent cet effort ! Apporte-moi des pièces d\'ascendance et je te donnerai la connaissance de leur fabrication.';
-- Quest 8881 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8881, 'frFR', 'Merci, $N. Voici la recette des fusées à grappes larges. Que tes produits apportent joie et chance à tous ceux qui les contemplent.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Voici la recette des fusées à grappes larges. Que tes produits apportent joie et chance à tous ceux qui les contemplent.';
-- Quest 8882 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8882, 'frFR', 'Les plus splendides feux d\'artifice doivent inclure des fusées à grappes, et ces fusées à grappes doivent être tirées depuis des lanceurs de grappes ! N\'est-il pas logique que tu apprennes les secrets de la fabrication des lanceurs de grappes ? Apporte-moi des pièces d\'ascendance et je te donnerai cette connaissance.') ON DUPLICATE KEY UPDATE CompletionText='Les plus splendides feux d\'artifice doivent inclure des fusées à grappes, et ces fusées à grappes doivent être tirées depuis des lanceurs de grappes ! N\'est-il pas logique que tu apprennes les secrets de la fabrication des lanceurs de grappes ? Apporte-moi des pièces d\'ascendance et je te donnerai cette connaissance.';
-- Quest 8882 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8882, 'frFR', 'Voici ton schéma. Étudie-le attentivement, et apprends...$B$BBonne chance, $N. Que tes célébrations rivalisent avec celles du Festival Lunaire lui-même !') ON DUPLICATE KEY UPDATE RewardText='Voici ton schéma. Étudie-le attentivement, et apprends...$B$BBonne chance, $N. Que tes célébrations rivalisent avec celles du Festival Lunaire lui-même !';
-- Quest 8883 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8883, 'frFR', '$Gname>, bienvenue à Nighthaven, hôte du Festival Lunaire !  Bien que notre village soit normalement isolé et coupé des peuples d\'Azeroth, pendant cette période de célébration, nous ouvrons nos bras et nos cœurs à tous.$B<br :>Profite bien de ta visite, <name, et parle-moi à nouveau, moi ou ma sœur, quand tu seras prêt.') ON DUPLICATE KEY UPDATE RewardText='$Gname>, bienvenue à Nighthaven, hôte du Festival Lunaire !  Bien que notre village soit normalement isolé et coupé des peuples d\'Azeroth, pendant cette période de célébration, nous ouvrons nos bras et nos cœurs à tous.$B<br :>Profite bien de ta visite, <name, et parle-moi à nouveau, moi ou ma sœur, quand tu seras prêt.';
-- Quest 8887 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8887, 'frFR', 'Bonjour, $C, tu es un régal pour les yeux. Je sais, c\'est fou que je sois ici, avec l\'ancre envahie par les Misérables. Velendris et ses rangers ont juré de me protéger à la condition que je parte d\'ici dès que j\'aurai récupéré ma cargaison.$B$BQu\'est-ce que tu as là... ça me semble vaguement familier ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $C, tu es un régal pour les yeux. Je sais, c\'est fou que je sois ici, avec l\'ancre envahie par les Misérables. Velendris et ses rangers ont juré de me protéger à la condition que je parte d\'ici dès que j\'aurai récupéré ma cargaison.$B$BQu\'est-ce que tu as là... ça me semble vaguement familier ?';
-- Quest 8887 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8887, 'frFR', 'Oh, toi, douce et douce <class> ! Je ne savais pas que ces dégoûtants murlocs de Grimscale avaient aussi piraté mes compas de navigation ! Sans eux, je n\'aurais aucune chance de naviguer à nouveau sur les mers une fois que nous aurons repris l\'ancre et réparé le navire.$B$BMerci beaucoup ! Tiens, prends cette pièce en signe de ma gratitude.') ON DUPLICATE KEY UPDATE RewardText='Oh, toi, douce et douce <class> ! Je ne savais pas que ces dégoûtants murlocs de Grimscale avaient aussi piraté mes compas de navigation ! Sans eux, je n\'aurais aucune chance de naviguer à nouveau sur les mers une fois que nous aurons repris l\'ancre et réparé le navire.$B$BMerci beaucoup ! Tiens, prends cette pièce en signe de ma gratitude.';

-- Quest 8892 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8892, 'frFR', 'As-tu donné une leçon à ces misérables ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu donné une leçon à ces misérables ?';
-- Quest 8893 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8893, 'frFR', 'Le Super Œuf-O-Matic est la dernière invention de Curgle Cranklehop. C\'est une pièce d\'ingénierie assez impressionnante.$B$BLe Super Œuf-O-Matic crache sauvagement lorsque vous approchez du panneau de contrôle.') ON DUPLICATE KEY UPDATE CompletionText='Le Super Œuf-O-Matic est la dernière invention de Curgle Cranklehop. C\'est une pièce d\'ingénierie assez impressionnante.$B$BLe Super Œuf-O-Matic crache sauvagement lorsque vous approchez du panneau de contrôle.';
-- Quest 8893 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8893, 'frFR', 'Vous placez l\'œuf de hippogriffe dans la machine. Une série de bips suit avec quelques bruits mécaniques étranges.$B$BIl semble que l\'Œufomètre ait pesé, mesuré et emballé votre œuf. Quelle rapidité !') ON DUPLICATE KEY UPDATE RewardText='Vous placez l\'œuf de hippogriffe dans la machine. Une série de bips suit avec quelques bruits mécaniques étranges.$B$BIl semble que l\'Œufomètre ait pesé, mesuré et emballé votre œuf. Quelle rapidité !';
-- Quest 8894 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8894, 'frFR', 'Alors, vous en avez pris soin ? Vous avez réglé un bon nombre de ces anomalies magiques ? Qu\'est-ce que je ferais si Magister Duskwither réapparaissait avec toutes ces choses rôdant ?') ON DUPLICATE KEY UPDATE CompletionText='Alors, vous en avez pris soin ? Vous avez réglé un bon nombre de ces anomalies magiques ? Qu\'est-ce que je ferais si Magister Duskwither réapparaissait avec toutes ces choses rôdant ?';
-- Quest 8901 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8901, 'frFR', 'Oh, et à quoi dois-je cette joie ?') ON DUPLICATE KEY UPDATE CompletionText='Oh, et à quoi dois-je cette joie ?';
-- Quest 8901 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8901, 'frFR', 'Les mots que Temma écrit pour moi. Mais, aussi beaucoup que ses mots me touchent, je ne peux pas considérer l\'amour d\'un tauren. En pensée, corps et esprit, nous sommes trop différents.$B$BC\'est bien que je n\'aie pas à recevoir ces pensées de lui en personne. Je ne supporterais pas de briser son cœur.') ON DUPLICATE KEY UPDATE RewardText='Les mots que Temma écrit pour moi. Mais, aussi beaucoup que ses mots me touchent, je ne peux pas considérer l\'amour d\'un tauren. En pensée, corps et esprit, nous sommes trop différents.$B$BC\'est bien que je n\'aie pas à recevoir ces pensées de lui en personne. Je ne supporterais pas de briser son cœur.';
-- Quest 8904 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8904, 'frFR', 'C\'est vrai. C\'est incroyable. Comment cela a-t-il pu arriver ? Laissez-moi réfléchir un instant. Il doit y avoir une raison derrière cela.') ON DUPLICATE KEY UPDATE RewardText='C\'est vrai. C\'est incroyable. Comment cela a-t-il pu arriver ? Laissez-moi réfléchir un instant. Il doit y avoir une raison derrière cela.';
-- Quest 8905 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8905, 'frFR', 'M\'avez-vous apporté ce que j\'ai demandé, $N ?') ON DUPLICATE KEY UPDATE CompletionText='M\'avez-vous apporté ce que j\'ai demandé, $N ?';

-- Quest 8905 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8905, 'frFR', 'Excellent ! Effectuons alors l\'échange. Il est difficile de me séparer de cette excellente armure, mais j\'ai peur de ne pas en avoir besoin de sitôt.$B$BSi vous êtes intéressé par l\'exécution de plus de travail pour moi, je pourrais être disposé à céder le reste des pièces.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Effectuons alors l\'échange. Il est difficile de me séparer de cette excellente armure, mais j\'ai peur de ne pas en avoir besoin de sitôt.$B$BSi vous êtes intéressé par l\'exécution de plus de travail pour moi, je pourrais être disposé à céder le reste des pièces.';
