INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8913, 'frFR', 'Ah, oui. Mux sera très heureux de ceci.$B$BCes brassards faisaient partie d\'un ensemble d\'armure plus vaste. Si vous êtes intéressé à me fournir une assistance supplémentaire, je serais disposé à envisager de me séparer du reste.') ON DUPLICATE KEY UPDATE RewardText='Ah, oui. Mux sera très heureux de ceci.$B$BCes brassards faisaient partie d\'un ensemble d\'armure plus vaste. Si vous êtes intéressé à me fournir une assistance supplémentaire, je serais disposé à envisager de me séparer du reste.';
