-- Quest 8921 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8921, 'frFR', 'Je comprends que les matériaux sont un peu chers... mais je vous promets que chacun d\'eux sera nécessaire !') ON DUPLICATE KEY UPDATE CompletionText='Je comprends que les matériaux sont un peu chers... mais je vous promets que chacun d\'eux sera nécessaire !';

-- Quest 8921 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8921, 'frFR', 'Ce sont précisément les matériaux dont j\'avais besoin.  Très opportun, <name>!$B$BDans quelques instants, j\'aurai votre distillateur prêt à l\'emploi!  En attendant, prenez ceci comme récompense pour m\'avoir aidé dans mon projet.') ON DUPLICATE KEY UPDATE RewardText='Ce sont précisément les matériaux dont j\'avais besoin.  Très opportun, <name>!$B$BDans quelques instants, j\'aurai votre distillateur prêt à l\'emploi!  En attendant, prenez ceci comme récompense pour m\'avoir aidé dans mon projet.';
-- Quest 8922 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8922, 'frFR', 'Excellent!  Juste au moment où j\'en manquais!$B$BTu dis que Deliana t\'a envoyé?') ON DUPLICATE KEY UPDATE RewardText='Excellent!  Juste au moment où j\'en manquais!$B$BTu dis que Deliana t\'a envoyé?';
-- Quest 8923 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8923, 'frFR', 'Excellent! Juste au moment où j\'en manquais!$B$BTu dis que Mokvar t\'a envoyé?') ON DUPLICATE KEY UPDATE RewardText='Excellent! Juste au moment où j\'en manquais!$B$BTu dis que Mokvar t\'a envoyé?';
-- Quest 8924 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8924, 'frFR', 'As-tu récolté l\'ectoplasme, $R?') ON DUPLICATE KEY UPDATE CompletionText='As-tu récolté l\'ectoplasme, $R?';
-- Quest 8924 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8924, 'frFR', 'Oui, ceux-ci feront l\'affaire!$B$BEn puisant dans les énergies surnaturelles contenues dans ces substances, nous pourrons contacter ceux dont les âmes ne ont pas encore quitté ce monde!') ON DUPLICATE KEY UPDATE RewardText='Oui, ceux-ci feront l\'affaire!$B$BEn puisant dans les énergies surnaturelles contenues dans ces substances, nous pourrons contacter ceux dont les âmes ne ont pas encore quitté ce monde!';
-- Quest 8925 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8925, 'frFR', 'As-tu trouvé le Seigneur de Magma, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé le Seigneur de Magma, $N?';
-- Quest 8925 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8925, 'frFR', 'Tu l\'as fait! Cela fournira certainement assez d\'énergie pour alimenter le révélateur de fantômes extra-dimensionnel!') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait! Cela fournira certainement assez d\'énergie pour alimenter le révélateur de fantômes extra-dimensionnel!';
-- Quest 8926 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8926, 'frFR', 'Es-tu prêt à effectuer l\'échange?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu prêt à effectuer l\'échange?';

-- Quest 8926 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8926, 'frFR', 'Vous avez tenu votre bout du marché, je tiendrai le mien.$B$BMais souviens-toi que je garde les meilleures pièces jusqu\'à ce que ton travail soit terminé.') ON DUPLICATE KEY UPDATE RewardText='Vous avez tenu votre bout du marché, je tiendrai le mien.$B$BMais souviens-toi que je garde les meilleures pièces jusqu\'à ce que ton travail soit terminé.';
-- Quest 8927 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8927, 'frFR', 'Vous êtes prêt à effectuer l\'échange ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes prêt à effectuer l\'échange ?';
-- Quest 8927 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8927, 'frFR', 'Notre accord demeure en vigueur. Souviens-toi simplement qu\'il ne s\'agit que d\'un avant-goût de ce qui t\'attend. Libère-moi de ce destin maudit et je te récompenserai avec des objets d\'une puissance véritablement grande.') ON DUPLICATE KEY UPDATE RewardText='Notre accord demeure en vigueur. Souviens-toi simplement qu\'il ne s\'agit que d\'un avant-goût de ce qui t\'attend. Libère-moi de ce destin maudit et je te récompenserai avec des objets d\'une puissance véritablement grande.';
-- Quest 8928 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8928, 'frFR', 'As-tu eu de la chance à trouver l\'imp dans le Gouffre de l\'Ombre ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu eu de la chance à trouver l\'imp dans le Gouffre de l\'Ombre ?';
-- Quest 8928 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8928, 'frFR', 'Tu l\'as fait !   Cette tige fera parfaitement l\'affaire.  Maintenant, il faut tout assembler...') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait !   Cette tige fera parfaitement l\'affaire.  Maintenant, il faut tout assembler...';
-- Quest 8929 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8929, 'frFR', 'Deliana, m\'as-tu contacté ? Je ferai de mon mieux pour t\'aider, mais d\'abord je dois te demander une grande faveur.') ON DUPLICATE KEY UPDATE RewardText='Deliana, m\'as-tu contacté ? Je ferai de mon mieux pour t\'aider, mais d\'abord je dois te demander une grande faveur.';
