-- Quest 8945 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8945, 'frFR', 'Merci de m\'avoir sauvée... J\'ai eu peur pour ma vie.  Veuillez accepter ceci comme un petit signe de ma gratitude.$B$BAnthion est... non... il ne peut pas être...') ON DUPLICATE KEY UPDATE RewardText='Merci de m\'avoir sauvée... J\'ai eu peur pour ma vie.  Veuillez accepter ceci comme un petit signe de ma gratitude.$B$BAnthion est... non... il ne peut pas être...';
-- Quest 8946 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8946, 'frFR', 'Ce médaillon... tu l\'as trouvé ! Je peux enfin reposer en paix.$B$Je répondrai maintenant à toutes les questions que tu pourrais avoir, $N. Mais dépêche-toi, mon temps dans ce monde n\'est pas long.') ON DUPLICATE KEY UPDATE RewardText='Ce médaillon... tu l\'as trouvé ! Je peux enfin reposer en paix.$B$Je répondrai maintenant à toutes les questions que tu pourrais avoir, $N. Mais dépêche-toi, mon temps dans ce monde n\'est pas long.';
-- Quest 8947 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8947, 'frFR', 'As-tu obtenu les matériaux que j\'ai demandés, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu les matériaux que j\'ai demandés, $N ?';
-- Quest 8947 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8947, 'frFR', 'Excellent.  Je vais les transmuer en quelque chose de plus adapté à nos besoins.') ON DUPLICATE KEY UPDATE RewardText='Excellent.  Je vais les transmuer en quelque chose de plus adapté à nos besoins.';
-- Quest 8948 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8948, 'frFR', 'Parle, étranger, ne vois-tu pas que je suis occupé ?') ON DUPLICATE KEY UPDATE CompletionText='Parle, étranger, ne vois-tu pas que je suis occupé ?';

-- Quest 8948 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8948, 'frFR', 'Anthion vous envoie, dites-vous ? Je croyais qu\'il était mort. J\'imagine que j\'ai entendu des choses étranges dans ma vie.$B$BTrès bien, alors. Qu\'attendez-vous de moi avec cette bannière ?') ON DUPLICATE KEY UPDATE RewardText='Anthion vous envoie, dites-vous ? Je croyais qu\'il était mort. J\'imagine que j\'ai entendu des choses étranges dans ma vie.$B$BTrès bien, alors. Qu\'attendez-vous de moi avec cette bannière ?';
-- Quest 8949 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8949, 'frFR', 'Avez-vous accompli le service que je vous ai demandé, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous accompli le service que je vous ai demandé, $N ?';
-- Quest 8949 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8949, 'frFR', 'Hmm... étrangement, je ne me sens pas mieux concernant la mort de mon frère aux mains de ces brutes.$B$BEh bien, vous avez tenu votre bout du marché.  Voyons ce que je peux faire pour vous.') ON DUPLICATE KEY UPDATE RewardText='Hmm... étrangement, je ne me sens pas mieux concernant la mort de mon frère aux mains de ces brutes.$B$BEh bien, vous avez tenu votre bout du marché.  Voyons ce que je peux faire pour vous.';
-- Quest 8950 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8950, 'frFR', 'Avez-vous rassemblé les matériaux dont j\'ai besoin, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous rassemblé les matériaux dont j\'ai besoin, $N ?';
-- Quest 8950 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8950, 'frFR', 'Oui, ceux-ci feront l\'affaire.  Une fois que j\'aurai fini, aucune force au monde ne pourra empêcher votre victime d\'accepter votre défi.') ON DUPLICATE KEY UPDATE RewardText='Oui, ceux-ci feront l\'affaire.  Une fois que j\'aurai fini, aucune force au monde ne pourra empêcher votre victime d\'accepter votre défi.';
-- Quest 8951 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8951, 'frFR', 'Vous êtes de retour, $N. Vous devez m\'en dire tout ce que vous avez découvert. Mais d\'abord, organisons votre récompense.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes de retour, $N. Vous devez m\'en dire tout ce que vous avez découvert. Mais d\'abord, organisons votre récompense.';
-- Quest 8951 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8951, 'frFR', 'Je n\'arrive pas à croire que nos vies sont toutes perdues à cause d\'un stupide médaillon !  Et vous êtes sûr qu\'Anthion a mentionné Bodley?$B$BEh bien, vous avez fait votre travail, alors réglons votre récompense.') ON DUPLICATE KEY UPDATE RewardText='Je n\'arrive pas à croire que nos vies sont toutes perdues à cause d\'un stupide médaillon !  Et vous êtes sûr qu\'Anthion a mentionné Bodley?$B$BEh bien, vous avez fait votre travail, alors réglons votre récompense.';
