INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8957, 'frFR', 'Cette malédiction nous a été infligée pour un simple médaillon. Lord Valthalak sait certainement comment garder une rancune.$B$BNous nous efforcerons de trouver les pièces restantes - espérons-le avant que je ne rencontre une mort prématurée. Mais avant cela, parlons de ta récompense.') ON DUPLICATE KEY UPDATE RewardText='Cette malédiction nous a été infligée pour un simple médaillon. Lord Valthalak sait certainement comment garder une rancune.$B$BNous nous efforcerons de trouver les pièces restantes - espérons-le avant que je ne rencontre une mort prématurée. Mais avant cela, parlons de ta récompense.';
