-- Quest 8960 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8960, 'frFR', 'Je suis si heureux que tu puisses me voir. Enfin quelqu\'un à qui parler !$B$BVoudriez-vous nous aider, <name>? Aider à annuler le tort que nous avons commis et à remettre les choses au pas ? Si c\'est vrai que tu as déjà la Pièce Supérieure de l\'Amulette de Lord Valthalak, alors je pense que je peux t\'indiquer la bonne direction pour acquérir les deux autres parties, les réunir et mettre fin à tout cela.$B$Oh, au fait, bonjour, je m\'appelle Bodley. Enchanté de te rencontrer !') ON DUPLICATE KEY UPDATE RewardText='Je suis si heureux que tu puisses me voir. Enfin quelqu\'un à qui parler !$B$BVoudriez-vous nous aider, <name>? Aider à annuler le tort que nous avons commis et à remettre les choses au pas ? Si c\'est vrai que tu as déjà la Pièce Supérieure de l\'Amulette de Lord Valthalak, alors je pense que je peux t\'indiquer la bonne direction pour acquérir les deux autres parties, les réunir et mettre fin à tout cela.$B$Oh, au fait, bonjour, je m\'appelle Bodley. Enchanté de te rencontrer !';

-- Quest 8961 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8961, 'frFR', 'C\'était notre folie... notre damnation d\'avoir accepté ce dernier travail. Si seulement nous n\'avions pas involontairement volé l\'esprit de Lord Valthalak, qui était contenu dans l\'amulette ; si seulement il n\'y avait pas eu ces membres de notre groupe de mercenaires qui avaient été si cupides et l\'avaient partagé entre eux. Je serais en vie aujourd\'hui, peut-être en trinquant à une bière, ou en faisant voler l\'un de mes enfants.$B$B$N, ne laisse pas l\'avarice des ignobles de notre ancienne compagnie de mercenaires être ta damnation également.') ON DUPLICATE KEY UPDATE CompletionText='C\'était notre folie... notre damnation d\'avoir accepté ce dernier travail. Si seulement nous n\'avions pas involontairement volé l\'esprit de Lord Valthalak, qui était contenu dans l\'amulette ; si seulement il n\'y avait pas eu ces membres de notre groupe de mercenaires qui avaient été si cupides et l\'avaient partagé entre eux. Je serais en vie aujourd\'hui, peut-être en trinquant à une bière, ou en faisant voler l\'un de mes enfants.$B$B$N, ne laisse pas l\'avarice des ignobles de notre ancienne compagnie de mercenaires être ta damnation également.';
-- Quest 8961 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8961, 'frFR', 'Je suis impressionné, <class>, mais il n\'y a pas de temps à perdre. Je vais te donner ta prochaine tâche, car tu devras encore acquérir quelques composants importants avant que nous puissions continuer.$B$BS\'adresse à moi à nouveau lorsque tu penses être prêt pour le défi qui t\'attend.') ON DUPLICATE KEY UPDATE RewardText='Je suis impressionné, <class>, mais il n\'y a pas de temps à perdre. Je vais te donner ta prochaine tâche, car tu devras encore acquérir quelques composants importants avant que nous puissions continuer.$B$BS\'adresse à moi à nouveau lorsque tu penses être prêt pour le défi qui t\'attend.';
-- Quest 8962 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8962, 'frFR', 'Es-tu déjà revenu, $C, avec ce que je t\'ai envoyé chercher ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu déjà revenu, $C, avec ce que je t\'ai envoyé chercher ?';
-- Quest 8962 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8962, 'frFR', 'Un travail bien fait, $N. J\'imprègnerai l\'essence des restes dans le brasero.$B$BIl ne reste plus qu\'à aller dans la partie inférieure de Blackrock Spire, dans la chambre où le Maître de Guerre Voone réside à Tazz\'Alaor, et utiliser le brasero pour invoquer l\'esprit corrompu de mon ancien compagnon, Mor Grayhoof. Il ne peut se reposer tant que la pièce de l\'amulette lui sera retirée.') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, $N. J\'imprègnerai l\'essence des restes dans le brasero.$B$BIl ne reste plus qu\'à aller dans la partie inférieure de Blackrock Spire, dans la chambre où le Maître de Guerre Voone réside à Tazz\'Alaor, et utiliser le brasero pour invoquer l\'esprit corrompu de mon ancien compagnon, Mor Grayhoof. Il ne peut se reposer tant que la pièce de l\'amulette lui sera retirée.';
-- Quest 8963 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8963, 'frFR', 'Es-tu déjà revenu, $C, avec ce que je t\'ai envoyé chercher ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu déjà revenu, $C, avec ce que je t\'ai envoyé chercher ?';
-- Quest 8963 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8963, 'frFR', 'Un travail bien fait, <name>. J\'imprègnerai l\'essence de la relique dans le brasero.$B$BIl ne reste plus qu\'à aller au Sanctuaire d\'Eldretharr dans l\'aile est de Dire Maul, et utiliser le brasero pour invoquer l\'esprit de mon ancien compagnon, Isalien. Son esprit a été corrompu par sa possession de la pièce de l\'amulette de Valthalak, et de la portion de son âme qu\'elle contient.') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, <name>. J\'imprègnerai l\'essence de la relique dans le brasero.$B$BIl ne reste plus qu\'à aller au Sanctuaire d\'Eldretharr dans l\'aile est de Dire Maul, et utiliser le brasero pour invoquer l\'esprit de mon ancien compagnon, Isalien. Son esprit a été corrompu par sa possession de la pièce de l\'amulette de Valthalak, et de la portion de son âme qu\'elle contient.';
-- Quest 8964 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8964, 'frFR', 'Es-tu déjà revenu, $C, avec ce que je t\'ai envoyé chercher ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu déjà revenu, $C, avec ce que je t\'ai envoyé chercher ?';
-- Quest 8964 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8964, 'frFR', 'Un travail bien fait, $N. J\'imprègnerai l\'essence de l\'épée dans le brasero.$B$BIl ne reste plus qu\'à entrer dans Le Trône Cramoisi à l\'intérieur De Bastion Écarlate à Stratholme, et utiliser le brasero pour invoquer les restes de mes anciens compagnons, Jarien et Sothos. Leurs âmes ont été davantage tordues par leur possession de la pièce de l\'amulette de Valthalak et de son esprit qu\'elle contient.') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, $N. J\'imprègnerai l\'essence de l\'épée dans le brasero.$B$BIl ne reste plus qu\'à entrer dans Le Trône Cramoisi à l\'intérieur De Bastion Écarlate à Stratholme, et utiliser le brasero pour invoquer les restes de mes anciens compagnons, Jarien et Sothos. Leurs âmes ont été davantage tordues par leur possession de la pièce de l\'amulette de Valthalak et de son esprit qu\'elle contient.';

-- Quest 8965 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8965, 'frFR', 'Alors, tu es revenu, $C, avec ce que je t\'ai envoyé chercher ?') ON DUPLICATE KEY UPDATE CompletionText='Alors, tu es revenu, $C, avec ce que je t\'ai envoyé chercher ?';
-- Quest 8965 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8965, 'frFR', 'Un travail bien fait, <name>. Je vais imprégner l\'essence des cendres dans le brasero.$B$BMaintenant, tout ce qui reste est d\'aller à Scholomance, à la chambre de Ras Frostwhisper, et d\'utiliser le brasero pour invoquer l\'esprit de mon ancien camarade, Kormok. Le morceau de l\'amulette, et l\'esprit de Valthalak à l\'intérieur, l\'a corrompu davantage, et il ne se reposera pas tant que tu ne l\'auras pas pris de force.') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, <name>. Je vais imprégner l\'essence des cendres dans le brasero.$B$BMaintenant, tout ce qui reste est d\'aller à Scholomance, à la chambre de Ras Frostwhisper, et d\'utiliser le brasero pour invoquer l\'esprit de mon ancien camarade, Kormok. Le morceau de l\'amulette, et l\'esprit de Valthalak à l\'intérieur, l\'a corrompu davantage, et il ne se reposera pas tant que tu ne l\'auras pas pris de force.';
-- Quest 8966 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8966, 'frFR', 'C\'est fait alors ? Tu as récupéré le morceau gauche de l\'amulette de Lord Valthalak et enfin mis au repos l\'esprit de mon ancien compagnon, Mor Grayhoof ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est fait alors ? Tu as récupéré le morceau gauche de l\'amulette de Lord Valthalak et enfin mis au repos l\'esprit de mon ancien compagnon, Mor Grayhoof ?';
-- Quest 8966 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8966, 'frFR', 'Tu as fait une grande chose, <name>. Un esprit repose en paix, mais il y a encore beaucoup de travail à faire avant que nous puissions tout laisser derrière nous.$B$BMalheureusement, je ne connais pas l\'emplacement de celui qui est mort avec le morceau droit de l\'amulette en sa possession. Mais ne crains pas ; de vivant, je m\'amusais de l\'art de la divination, alors j\'ai une autre tâche pour toi, qui va nous permettre de dénicher la dernière pièce.') ON DUPLICATE KEY UPDATE RewardText='Tu as fait une grande chose, <name>. Un esprit repose en paix, mais il y a encore beaucoup de travail à faire avant que nous puissions tout laisser derrière nous.$B$BMalheureusement, je ne connais pas l\'emplacement de celui qui est mort avec le morceau droit de l\'amulette en sa possession. Mais ne crains pas ; de vivant, je m\'amusais de l\'art de la divination, alors j\'ai une autre tâche pour toi, qui va nous permettre de dénicher la dernière pièce.';
-- Quest 8967 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8967, 'frFR', 'Tu n\'as pas déjà réglé le salut de l\'esprit d\'Isalien et la récupération du morceau gauche de l\'amulette de Lord Valthalak, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Tu n\'as pas déjà réglé le salut de l\'esprit d\'Isalien et la récupération du morceau gauche de l\'amulette de Lord Valthalak, $N ?';
-- Quest 8967 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8967, 'frFR', 'Merci, <name>, d\'avoir mis le repos à l\'esprit d\'Isalien. Maintenant, peut-être, elle trouvera la paix auprès de sa déesse. Mais, il y a encore beaucoup de travail devant nous si nous voulons sortir de ce joli pétrin dans lequel nous nous trouvons.$B$BMalheureusement, je ne connais pas l\'emplacement de celui qui est mort avec le morceau droit de l\'amulette en sa possession. Mais ne crains pas ; de vivant, je m\'amusais de l\'art de la divination, alors j\'ai une autre tâche pour toi, qui va nous permettre de dénicher la dernière pièce.') ON DUPLICATE KEY UPDATE RewardText='Merci, <name>, d\'avoir mis le repos à l\'esprit d\'Isalien. Maintenant, peut-être, elle trouvera la paix auprès de sa déesse. Mais, il y a encore beaucoup de travail devant nous si nous voulons sortir de ce joli pétrin dans lequel nous nous trouvons.$B$BMalheureusement, je ne connais pas l\'emplacement de celui qui est mort avec le morceau droit de l\'amulette en sa possession. Mais ne crains pas ; de vivant, je m\'amusais de l\'art de la divination, alors j\'ai une autre tâche pour toi, qui va nous permettre de dénicher la dernière pièce.';
-- Quest 8968 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8968, 'frFR', 'Cela signifie donc, $C, que tu as déjà mis au repos les âmes de ces deux idiots et récupéré le morceau gauche de l\'amulette de Lord Valthalak ?') ON DUPLICATE KEY UPDATE CompletionText='Cela signifie donc, $C, que tu as déjà mis au repos les âmes de ces deux idiots et récupéré le morceau gauche de l\'amulette de Lord Valthalak ?';
-- Quest 8968 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8968, 'frFR', 'Je suppose qu\'il est préférable que les âmes de ces deux aient finalement trouvé le repos, même si je ne les aimais pas lorsqu\'ils étaient vivants. En tout cas, nous avons ce que nous cherchions, et c\'est définitivement une bonne chose !$B$BMalheureusement, je ne connais pas l\'emplacement de celui qui est mort avec le morceau droit de l\'amulette en sa possession. Mais ne crains pas ; de vivant, je m\'amusais de l\'art de la divination, alors j\'ai une autre tâche pour toi, qui va nous permettre de dénicher la dernière pièce.') ON DUPLICATE KEY UPDATE RewardText='Je suppose qu\'il est préférable que les âmes de ces deux aient finalement trouvé le repos, même si je ne les aimais pas lorsqu\'ils étaient vivants. En tout cas, nous avons ce que nous cherchions, et c\'est définitivement une bonne chose !$B$BMalheureusement, je ne connais pas l\'emplacement de celui qui est mort avec le morceau droit de l\'amulette en sa possession. Mais ne crains pas ; de vivant, je m\'amusais de l\'art de la divination, alors j\'ai une autre tâche pour toi, qui va nous permettre de dénicher la dernière pièce.';

-- Quest 8969 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8969, 'frFR', 'Je vous félicite, $N, si vous êtes revenu avec la pièce gauche de l\'amulette. Sinon, cependant, veuillez vous en occuper car il n\'y a pas de temps à perdre, je vous l\'assure !') ON DUPLICATE KEY UPDATE CompletionText='Je vous félicite, $N, si vous êtes revenu avec la pièce gauche de l\'amulette. Sinon, cependant, veuillez vous en occuper car il n\'y a pas de temps à perdre, je vous l\'assure !';
-- Quest 8969 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8969, 'frFR', 'Bon travail, <name>! Kormok n\'était pas si mauvais pour un ogre, du moins pas tant qu\'il était en vie, alors j\'espère qu\'il obtient le reste qu\'il mérite. Mais, il y a plus de travail devant nous.$B$BMalheureusement, je ne connais pas l\'emplacement de celui qui est mort avec la pièce droite de l\'amulette en sa possession. Mais ne craignez rien ; de vivant, j\'étais un dabbler dans l\'art de la divination, alors j\'ai une autre tâche pour vous, qui va nous permettre de retrouver la pièce finale.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, <name>! Kormok n\'était pas si mauvais pour un ogre, du moins pas tant qu\'il était en vie, alors j\'espère qu\'il obtient le reste qu\'il mérite. Mais, il y a plus de travail devant nous.$B$BMalheureusement, je ne connais pas l\'emplacement de celui qui est mort avec la pièce droite de l\'amulette en sa possession. Mais ne craignez rien ; de vivant, j\'étais un dabbler dans l\'art de la divination, alors j\'ai une autre tâche pour vous, qui va nous permettre de retrouver la pièce finale.';
-- Quest 8970 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8970, 'frFR', 'Bloodkelp, $N, un gros tas de ça, c\'est ce dont j\'ai besoin pour alimenter mes sorts divinatoires. Vous allez probablement devoir prendre au moins quelques amis avec vous jusqu\'à Alcaz Island pour le ramasser... ces Strashaz sont une bande de salauds !') ON DUPLICATE KEY UPDATE CompletionText='Bloodkelp, $N, un gros tas de ça, c\'est ce dont j\'ai besoin pour alimenter mes sorts divinatoires. Vous allez probablement devoir prendre au moins quelques amis avec vous jusqu\'à Alcaz Island pour le ramasser... ces Strashaz sont une bande de salauds !';
-- Quest 8970 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8970, 'frFR', 'Pour être honnête, <name>, je suis surpris que vous soyez revenu en un morceau. Après tout, je suppose qu\'Alcaz Island est le moindre de vos soucis en ce moment.$B$BOk, donnez-moi un instant... la divination n\'est pas quelque chose auquel vous pouvez simplement claquer des doigts et attendre des réponses précises.') ON DUPLICATE KEY UPDATE RewardText='Pour être honnête, <name>, je suis surpris que vous soyez revenu en un morceau. Après tout, je suppose qu\'Alcaz Island est le moindre de vos soucis en ce moment.$B$BOk, donnez-moi un instant... la divination n\'est pas quelque chose auquel vous pouvez simplement claquer des doigts et attendre des réponses précises.';
-- Quest 8977 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8977, 'frFR', 'Excellent ! Vous avez bien fait, $N. Je ne suis pas sûr de faire confiance à l\'artisanat du gobelin, mais je n\'ai pas d\'autre choix.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Vous avez bien fait, $N. Je ne suis pas sûr de faire confiance à l\'artisanat du gobelin, mais je n\'ai pas d\'autre choix.';
-- Quest 8978 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8978, 'frFR', 'Vous êtes revenu avec le dispositif ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu avec le dispositif ?';
-- Quest 8978 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8978, 'frFR', 'Vous êtes revenu avec le dispositif !  Je suis impressionné par votre dévouement, <name>.  Excellent travail.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes revenu avec le dispositif !  Je suis impressionné par votre dévouement, <name>.  Excellent travail.';
-- Quest 8985 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8985, 'frFR', 'Êtes-vous déjà revenu alors, $C, avec ce que je vous ai envoyé pour ramasser ?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous déjà revenu alors, $C, avec ce que je vous ai envoyé pour ramasser ?';

-- Quest 8985 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8985, 'frFR', 'Un travail bien fait, $N. J\'imprègnerai l\'essence de la relique dans le brasero.$B$BIl ne reste plus qu\'à se rendre au Sanctuaire d\'Eldretharr dans l\'aile est de Dire Maul, et utiliser le brasero pour invoquer l\'esprit de mon ancienne camarade, Isalien. Son esprit a été corrompu par sa possession du morceau de l\'amulette de Valthalak, et de la portion de son âme qu\'elle contient.$B$Oh, au fait, j\'ai gardé du kelp sanguin de ton voyage à Alcaz Isle, alors j\'en ai fait des potions pour toi. Choisis ce que tu veux !') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, $N. J\'imprègnerai l\'essence de la relique dans le brasero.$B$BIl ne reste plus qu\'à se rendre au Sanctuaire d\'Eldretharr dans l\'aile est de Dire Maul, et utiliser le brasero pour invoquer l\'esprit de mon ancienne camarade, Isalien. Son esprit a été corrompu par sa possession du morceau de l\'amulette de Valthalak, et de la portion de son âme qu\'elle contient.$B$Oh, au fait, j\'ai gardé du kelp sanguin de ton voyage à Alcaz Isle, alors j\'en ai fait des potions pour toi. Choisis ce que tu veux !';
-- Quest 8986 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8986, 'frFR', 'Tu es déjà revenu, $C, avec ce que je t\'ai envoyé ramasser ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es déjà revenu, $C, avec ce que je t\'ai envoyé ramasser ?';
-- Quest 8986 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8986, 'frFR', 'Un travail bien fait, $N. J\'imprègnerai l\'essence des restes dans le brasero.$B$BIl ne reste plus qu\'à se rendre à la partie inférieure de Blackrock Spire, à la chambre où réside le Maître de Guerre Voone dans Tazz\'Alaor, et utiliser le brasero pour invoquer l\'esprit corrompu de mon ancienne camarade, Mor Grayhoof. Il ne pourra pas reposer tant que le morceau de l\'amulette ne sera pas retiré de lui.$B$Oh, au fait, j\'ai gardé du kelp sanguin de ton voyage à Alcaz Isle, alors j\'en ai fait des potions pour toi. Choisis ce que tu veux !') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, $N. J\'imprègnerai l\'essence des restes dans le brasero.$B$BIl ne reste plus qu\'à se rendre à la partie inférieure de Blackrock Spire, à la chambre où réside le Maître de Guerre Voone dans Tazz\'Alaor, et utiliser le brasero pour invoquer l\'esprit corrompu de mon ancienne camarade, Mor Grayhoof. Il ne pourra pas reposer tant que le morceau de l\'amulette ne sera pas retiré de lui.$B$Oh, au fait, j\'ai gardé du kelp sanguin de ton voyage à Alcaz Isle, alors j\'en ai fait des potions pour toi. Choisis ce que tu veux !';
-- Quest 8987 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8987, 'frFR', 'Tu es déjà revenu, $C, avec ce que je t\'ai envoyé ramasser ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es déjà revenu, $C, avec ce que je t\'ai envoyé ramasser ?';
-- Quest 8987 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8987, 'frFR', 'Un travail bien fait, $N. J\'imprègnerai l\'essence de l\'épée dans le brasero.$B$BIl ne reste plus qu\'à entrer dans Le Trône Cramoisi à l\'intérieur De la Bastion Écarlate à Stratholme, et utiliser le brasero pour invoquer les restes de mes anciennes camarades, Jarien et Sothos. Leurs âmes ont été encore plus tordues par leur possession du morceau de l\'amulette de Valthalak et de son esprit qu\'elle contient.$B$Oh, au fait, j\'ai gardé du kelp sanguin de ton voyage à Alcaz Isle, alors j\'en ai fait des potions pour toi. Choisis ce que tu veux !') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, $N. J\'imprègnerai l\'essence de l\'épée dans le brasero.$B$BIl ne reste plus qu\'à entrer dans Le Trône Cramoisi à l\'intérieur De la Bastion Écarlate à Stratholme, et utiliser le brasero pour invoquer les restes de mes anciennes camarades, Jarien et Sothos. Leurs âmes ont été encore plus tordues par leur possession du morceau de l\'amulette de Valthalak et de son esprit qu\'elle contient.$B$Oh, au fait, j\'ai gardé du kelp sanguin de ton voyage à Alcaz Isle, alors j\'en ai fait des potions pour toi. Choisis ce que tu veux !';
-- Quest 8988 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8988, 'frFR', 'Tu es déjà revenu, $C, avec ce que je t\'ai envoyé ramasser ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es déjà revenu, $C, avec ce que je t\'ai envoyé ramasser ?';
-- Quest 8988 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8988, 'frFR', 'Un travail bien fait, <name>. J\'imprègnerai l\'essence des cendres dans le brasero.$B$BIl ne reste plus qu\'à entrer à Scholomance, dans la chambre de Ras Frostwhisper, et utiliser le brasero pour invoquer l\'esprit de mon ancienne camarade, Kormok. Le morceau de l\'amulette, et l\'esprit de Valthalak qu\'elle contient, l\'a encore plus corrompu, et il ne reposera pas tant que tu ne l\'auras pas retiré de force.$B$Oh, au fait, j\'ai gardé du kelp sanguin de ton voyage à Alcaz Isle, alors j\'en ai fait des potions pour toi. Choisis ce que tu veux !') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, <name>. J\'imprègnerai l\'essence des cendres dans le brasero.$B$BIl ne reste plus qu\'à entrer à Scholomance, dans la chambre de Ras Frostwhisper, et utiliser le brasero pour invoquer l\'esprit de mon ancienne camarade, Kormok. Le morceau de l\'amulette, et l\'esprit de Valthalak qu\'elle contient, l\'a encore plus corrompu, et il ne reposera pas tant que tu ne l\'auras pas retiré de force.$B$Oh, au fait, j\'ai gardé du kelp sanguin de ton voyage à Alcaz Isle, alors j\'en ai fait des potions pour toi. Choisis ce que tu veux !';
-- Quest 8989 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8989, 'frFR', 'Alors c\'est fait ? Tu as récupéré le bon morceau de l\'amulette de Lord Valthalak, recombiné l\'amulette en un tout, et finalement mis au repos l\'esprit de mon ancien compagnon, Mor Grayhoof ?') ON DUPLICATE KEY UPDATE CompletionText='Alors c\'est fait ? Tu as récupéré le bon morceau de l\'amulette de Lord Valthalak, recombiné l\'amulette en un tout, et finalement mis au repos l\'esprit de mon ancien compagnon, Mor Grayhoof ?';

-- Quest 8989 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8989, 'frFR', 'Merci d\'avoir aidé Mor Grayhoof, <name>. Un autre esprit repose en paix, et nous avons maintenant l\'amulette réassemblée ! Mais nous avons encore le test le plus difficile devant nous.$B$BPour que le brasier soit accordé pour invoquer Lord Valthalak, il y a quelques autres objets qui doivent être collectés et ramenés jusqu\'à moi ici.') ON DUPLICATE KEY UPDATE RewardText='Merci d\'avoir aidé Mor Grayhoof, <name>. Un autre esprit repose en paix, et nous avons maintenant l\'amulette réassemblée ! Mais nous avons encore le test le plus difficile devant nous.$B$BPour que le brasier soit accordé pour invoquer Lord Valthalak, il y a quelques autres objets qui doivent être collectés et ramenés jusqu\'à moi ici.';
-- Quest 8990 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8990, 'frFR', 'Vous n\'avez certainement pas déjà réglé la salveté de l\'esprit d\'Isalien et la récupération de la bonne pièce de l\'amulette de Lord Valthalak, $N ? Assurez-vous de recombiner les pièces de l\'amulette avant de me la remettre.') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez certainement pas déjà réglé la salveté de l\'esprit d\'Isalien et la récupération de la bonne pièce de l\'amulette de Lord Valthalak, $N ? Assurez-vous de recombiner les pièces de l\'amulette avant de me la remettre.';
-- Quest 8990 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8990, 'frFR', 'Merci, $N, d\'avoir mis le repos à l\'esprit d\'Isalien. Maintenant, peut-être, elle trouvera la paix auprès de sa déesse. Et, nous avons l\'amulette réassemblée, également ! Mais nous avons encore le test le plus difficile devant nous.$B$BPour que le brasier soit accordé pour invoquer Lord Valthalak, il y a quelques autres objets qui doivent être collectés et ramenés jusqu\'à moi ici.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N, d\'avoir mis le repos à l\'esprit d\'Isalien. Maintenant, peut-être, elle trouvera la paix auprès de sa déesse. Et, nous avons l\'amulette réassemblée, également ! Mais nous avons encore le test le plus difficile devant nous.$B$BPour que le brasier soit accordé pour invoquer Lord Valthalak, il y a quelques autres objets qui doivent être collectés et ramenés jusqu\'à moi ici.';
-- Quest 8991 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8991, 'frFR', 'Cela signifie-t-il donc, $C, que vous avez déjà mis au repos les âmes de ces deux idiots et recombiné les pièces de l\'amulette de Lord Valthalak ?') ON DUPLICATE KEY UPDATE CompletionText='Cela signifie-t-il donc, $C, que vous avez déjà mis au repos les âmes de ces deux idiots et recombiné les pièces de l\'amulette de Lord Valthalak ?';
-- Quest 8991 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8991, 'frFR', 'Je suppose qu\'il est préférable que les âmes de ces deux aient finalement trouvé le repos, même si je ne les aimais pas tant qu\'ils étaient en vie. Quoi qu\'il en soit, nous avons ce que nous cherchions, et maintenant l\'amulette est réassemblée ! Mais nous avons encore le test le plus difficile devant nous.$B$BPour que le brasier soit accordé pour invoquer Lord Valthalak, il y a quelques autres objets qui doivent être collectés et ramenés jusqu\'à moi ici.') ON DUPLICATE KEY UPDATE RewardText='Je suppose qu\'il est préférable que les âmes de ces deux aient finalement trouvé le repos, même si je ne les aimais pas tant qu\'ils étaient en vie. Quoi qu\'il en soit, nous avons ce que nous cherchions, et maintenant l\'amulette est réassemblée ! Mais nous avons encore le test le plus difficile devant nous.$B$BPour que le brasier soit accordé pour invoquer Lord Valthalak, il y a quelques autres objets qui doivent être collectés et ramenés jusqu\'à moi ici.';
-- Quest 8992 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8992, 'frFR', 'Je vous félicite, $N, si vous êtes revenu avec l\'amulette complétée. Sinon, cependant, veuillez vous en occuper car il n\'y a pas de temps à perdre, je vous assure !') ON DUPLICATE KEY UPDATE CompletionText='Je vous félicite, $N, si vous êtes revenu avec l\'amulette complétée. Sinon, cependant, veuillez vous en occuper car il n\'y a pas de temps à perdre, je vous assure !';
-- Quest 8992 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8992, 'frFR', 'Bon travail, <name> ! Kormok n\'était pas si mauvais pour un ogre, au moins pas tant qu\'il était en vie, alors j\'espère qu\'il obtient le repos qu\'il mérite. Et maintenant nous avons l\'amulette complétée ! Mais nous avons encore le test le plus difficile devant nous.$B$BPour que le brasier soit accordé pour invoquer Lord Valthalak, il y a quelques autres objets qui doivent être collectés et ramenés jusqu\'à moi ici.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, <name> ! Kormok n\'était pas si mauvais pour un ogre, au moins pas tant qu\'il était en vie, alors j\'espère qu\'il obtient le repos qu\'il mérite. Et maintenant nous avons l\'amulette complétée ! Mais nous avons encore le test le plus difficile devant nous.$B$BPour que le brasier soit accordé pour invoquer Lord Valthalak, il y a quelques autres objets qui doivent être collectés et ramenés jusqu\'à moi ici.';
-- Quest 8993 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8993, 'frFR', 'Êtes-vous venu livrer un présent d\'amour et d\'adoration à votre leader préféré ?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous venu livrer un présent d\'amour et d\'adoration à votre leader préféré ?';

-- Quest 8994 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8994, 'frFR', 'Nous avons parcouru un long chemin, $N$, et je voulais juste dire que quoi qu\'il arrive, merci ! Vous vous êtes mis en danger mortel pour essayer d\'aider les membres survivants de notre compagnie de mercenaires, La Lame Voilée, et pour ce qui me concerne, vous êtes l\'un de nous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Nous avons parcouru un long chemin, $N$, et je voulais juste dire que quoi qu\'il arrive, merci ! Vous vous êtes mis en danger mortel pour essayer d\'aider les membres survivants de notre compagnie de mercenaires, La Lame Voilée, et pour ce qui me concerne, vous êtes l\'un de nous maintenant.';
-- Quest 8994 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8994, 'frFR', 'C\'est tout. Je vais extraire le métal des brassards et imprégner le brasero de ces composants finaux. Alors il sera prêt pour que vous invoquiez Lord Valthalak, et finalement que vous lui rendiez son amulette d\'esprit.$B$BVous avez parcouru une bonne distance, <name>, ne faiblissez pas maintenant que la fin est en vue !') ON DUPLICATE KEY UPDATE RewardText='C\'est tout. Je vais extraire le métal des brassards et imprégner le brasero de ces composants finaux. Alors il sera prêt pour que vous invoquiez Lord Valthalak, et finalement que vous lui rendiez son amulette d\'esprit.$B$BVous avez parcouru une bonne distance, <name>, ne faiblissez pas maintenant que la fin est en vue !';
-- Quest 8995 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8995, 'frFR', 'Quelle chance pour vous que je sache que vous ne faites pas partie du groupe d\'origine qui m\'a volé ceci.$B$BI vais récupérer ce qui est mien maintenant, mortel ! Donnez-moi l\'amulette !') ON DUPLICATE KEY UPDATE RewardText='Quelle chance pour vous que je sache que vous ne faites pas partie du groupe d\'origine qui m\'a volé ceci.$B$BI vais récupérer ce qui est mien maintenant, mortel ! Donnez-moi l\'amulette !';
-- Quest 8996 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8996, 'frFR', '$N$, vous êtes de retour et vous êtes toujours en vie ! Eh bien, au moins ça en fait un de nous.$B$BVous allez devoir m\'en parler !') ON DUPLICATE KEY UPDATE CompletionText='$N$, vous êtes de retour et vous êtes toujours en vie ! Eh bien, au moins ça en fait un de nous.$B$BVous allez devoir m\'en parler !';
-- Quest 8996 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8996, 'frFR', 'Il a vraiment dit tout ça ? Wow, je n\'arrive pas à croire qu\'il va annuler les assassins et les traqueurs spectraux, même s\'il a laissé entendre qu\'il pourrait nuire davantage à mes compagnons vivants à l\'avenir.$B$BC\'est un jour merveilleux, <name>rain ! Vous avez accompli ce que peu ont pu faire, et nous avez absous, au moins en partie, de certains de nos péchés passés.$B$BMerci ! En signe d\'appréciation, j\'aimerais vous donner ceci. Vous pouvez l\'utiliser pour invoquer des esprits aux mêmes lieux hantés que vous avez déjà, et quelques autres aussi.') ON DUPLICATE KEY UPDATE RewardText='Il a vraiment dit tout ça ? Wow, je n\'arrive pas à croire qu\'il va annuler les assassins et les traqueurs spectraux, même s\'il a laissé entendre qu\'il pourrait nuire davantage à mes compagnons vivants à l\'avenir.$B$BC\'est un jour merveilleux, <name>rain ! Vous avez accompli ce que peu ont pu faire, et nous avez absous, au moins en partie, de certains de nos péchés passés.$B$BMerci ! En signe d\'appréciation, j\'aimerais vous donner ceci. Vous pouvez l\'utiliser pour invoquer des esprits aux mêmes lieux hantés que vous avez déjà, et quelques autres aussi.';
-- Quest 8997 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8997, 'frFR', 'Je suis très heureux de vous voir revenir en sécurité, $N$. Vous avez l\'air bien, sinon un peu plus usé.$B$BVenez, parlez-moi de tout ce qui s\'est passé.') ON DUPLICATE KEY UPDATE RewardText='Je suis très heureux de vous voir revenir en sécurité, $N$. Vous avez l\'air bien, sinon un peu plus usé.$B$BVenez, parlez-moi de tout ce qui s\'est passé.';
-- Quest 8998 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8998, 'frFR', 'Je suis heureux de voir que vous avez survécu, $N$. Vous avez l\'air bien, sinon un peu plus aguerri.$B$BVenez, parlez-moi de tout ce qui s\'est passé.') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux de voir que vous avez survécu, $N$. Vous avez l\'air bien, sinon un peu plus aguerri.$B$BVenez, parlez-moi de tout ce qui s\'est passé.';
-- Quest 8999 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (8999, 'frFR', 'Conformément à notre accord, êtes-vous prêt à remettre vos pièces de Cœur Sauvage en échange de votre nouveau Collet et de votre Veste de Cœur Félin ?') ON DUPLICATE KEY UPDATE CompletionText='Conformément à notre accord, êtes-vous prêt à remettre vos pièces de Cœur Sauvage en échange de votre nouveau Collet et de votre Veste de Cœur Félin ?';

-- Quest 8999 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (8999, 'frFR', 'Tu vas me manquer, <name>. Je te dois une telle gratitude ; je pense que je ne pourrai jamais te la rendre.$B$BI j\'espère que tu apprécieras ton nouvel armure de tête et de poitrine, et qu\'elle te protégera longtemps.') ON DUPLICATE KEY UPDATE RewardText='Tu vas me manquer, <name>. Je te dois une telle gratitude ; je pense que je ne pourrai jamais te la rendre.$B$BI j\'espère que tu apprécieras ton nouvel armure de tête et de poitrine, et qu\'elle te protégera longtemps.';
