-- Quest 9007 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9007, 'frFR', 'Tu vas vraiment me manquer, $N. Il y a une dette que je te dois, que je ne pourrai peut-être jamais rembourser.$B$BProfite bien de ton nouvel armure de tête et de poitrine. Qu\'elle te protège longtemps, et qu\'elle t\'aide à atteindre un honneur encore plus grand !') ON DUPLICATE KEY UPDATE RewardText='Tu vas vraiment me manquer, $N. Il y a une dette que je te dois, que je ne pourrai peut-être jamais rembourser.$B$BProfite bien de ton nouvel armure de tête et de poitrine. Qu\'elle te protège longtemps, et qu\'elle t\'aide à atteindre un honneur encore plus grand !';
