-- Quest 9032 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9032, 'frFR', 'Je suis si heureux que vous puissiez me voir. Enfin quelqu\'un à qui parler !$B$BVoulez-vous nous aider, $N? Aider à réparer le tort que nous avons causé et remettre les choses au pas? Si c\'est vrai que vous avez déjà la Pièce Supérieure de l\'Amulette de Lord Valthalak, alors je pense que je peux vous indiquer la bonne direction pour acquérir les deux autres pièces, les réunir et mettre fin à tout cela.$B$Oh, au fait, bonjour, je m\'appelle Bodley. Enchanté de vous rencontrer !') ON DUPLICATE KEY UPDATE RewardText='Je suis si heureux que vous puissiez me voir. Enfin quelqu\'un à qui parler !$B$BVoulez-vous nous aider, $N? Aider à réparer le tort que nous avons causé et remettre les choses au pas? Si c\'est vrai que vous avez déjà la Pièce Supérieure de l\'Amulette de Lord Valthalak, alors je pense que je peux vous indiquer la bonne direction pour acquérir les deux autres pièces, les réunir et mettre fin à tout cela.$B$Oh, au fait, bonjour, je m\'appelle Bodley. Enchanté de vous rencontrer !';
-- Quest 9033 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9033, 'frFR', 'Devoir, honneur, dévouement... Qu\'est-ce que ces mots représentent pour vous ?') ON DUPLICATE KEY UPDATE CompletionText='Devoir, honneur, dévouement... Qu\'est-ce que ces mots représentent pour vous ?';
