INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9051, 'frFR', 'Merci, $N. Vous êtes brave et sage.$B$BTellez-moi, comment le dévilsaur a-t-il réagi à la toxine ?') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Vous êtes brave et sage.$B$BTellez-moi, comment le dévilsaur a-t-il réagi à la toxine ?';
