INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9067, 'frFR', 'Tu es un jeune $g très énergique, n\'est-ce pas ?$B$BTout cela semble très adéquat. Tu mérites certainement une compensation pour avoir rassemblé tout cela pour moi, et quelque chose d\'un peu plus, je pense./n/nOh, j\'ai presque oublié, voici une invitation à la fête.  Et, $C, la prochaine fois que tu passes, assure-toi de t\'habiller avec quelque chose d\'un peu plus... festif.') ON DUPLICATE KEY UPDATE RewardText='Tu es un jeune $g très énergique, n\'est-ce pas ?$B$BTout cela semble très adéquat. Tu mérites certainement une compensation pour avoir rassemblé tout cela pour moi, et quelque chose d\'un peu plus, je pense./n/nOh, j\'ai presque oublié, voici une invitation à la fête.  Et, $C, la prochaine fois que tu passes, assure-toi de t\'habiller avec quelque chose d\'un peu plus... festif.';
