-- Quest 9120 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9120, 'frFR', 'En toutes mes journées de vie, je n\'aurais jamais imaginé voir ceci...$b$b<Father Montoy semble baver.>$b$bOh oui, tu seras récompensé cher $g. Tu seras grandement récompensé. Donne-le ici. Maintenant !') ON DUPLICATE KEY UPDATE RewardText='En toutes mes journées de vie, je n\'aurais jamais imaginé voir ceci...$b$b<Father Montoy semble baver.>$b$bOh oui, tu seras récompensé cher $g. Tu seras grandement récompensé. Donne-le ici. Maintenant !';
-- Quest 9121 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9121, 'frFR', 'Aucun n\'est entré dans Naxxramas et est revenu pour raconter l\'histoire.') ON DUPLICATE KEY UPDATE CompletionText='Aucun n\'est entré dans Naxxramas et est revenu pour raconter l\'histoire.';

-- Quest 9121 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9121, 'frFR', 'Vous sentirez une légère piqûre, $N. Cette sensation signifie que ça fonctionne. Une fois terminé, vous pourrez entrer dans Naxxramas en posant le pied sur le portail runique à Plaguewood.') ON DUPLICATE KEY UPDATE RewardText='Vous sentirez une légère piqûre, $N. Cette sensation signifie que ça fonctionne. Une fois terminé, vous pourrez entrer dans Naxxramas en posant le pied sur le portail runique à Plaguewood.';
