-- Quest 9122 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9122, 'frFR', 'Vous sentirez une légère piqûre, <name>. Cette sensation signifie que ça fonctionne. Une fois terminé, vous pourrez entrer dans Naxxramas en posant le pied sur le portail runique à Plaguewood.') ON DUPLICATE KEY UPDATE RewardText='Vous sentirez une légère piqûre, <name>. Cette sensation signifie que ça fonctionne. Une fois terminé, vous pourrez entrer dans Naxxramas en posant le pied sur le portail runique à Plaguewood.';
