INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9123, 'frFR', 'Aucun n\'est entré dans Naxxramas et est revenu pour raconter l\'histoire.') ON DUPLICATE KEY UPDATE CompletionText='Aucun n\'est entré dans Naxxramas et est revenu pour raconter l\'histoire.';
