-- Quest 9125 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9125, 'frFR', 'Vous avez fait un travail exemplaire sur le premier paquet, $n. Si vous en avez d\'autres, je les prendrai maintenant. Pour chaque paquet que vous remettez, je vous récompenserai avec une autre insigne.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez fait un travail exemplaire sur le premier paquet, $n. Si vous en avez d\'autres, je les prendrai maintenant. Pour chaque paquet que vous remettez, je vous récompenserai avec une autre insigne.';
-- Quest 9125 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9125, 'frFR', 'Très excellent, <name>ü! Ceux-ci serviront certainement à bon escient.') ON DUPLICATE KEY UPDATE RewardText='Très excellent, <name>ü! Ceux-ci serviront certainement à bon escient.';
-- Quest 9127 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9127, 'frFR', 'Un homme de mon métier ne peut jamais avoir trop de fragments d\'os, $n. Chaque fois que vous avez un surplus de fragments, apportez-les-moi et je vous récompenserai avec une autre insigne.') ON DUPLICATE KEY UPDATE CompletionText='Un homme de mon métier ne peut jamais avoir trop de fragments d\'os, $n. Chaque fois que vous avez un surplus de fragments, apportez-les-moi et je vous récompenserai avec une autre insigne.';

-- Quest 9127 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9127, 'frFR', 'Mon rêve de devenir danseur professionnel à la disco de Gadgetzan est sur le point de devenir réalité ! Continue ton bon travail, $N.') ON DUPLICATE KEY UPDATE RewardText='Mon rêve de devenir danseur professionnel à la disco de Gadgetzan est sur le point de devenir réalité ! Continue ton bon travail, $N.';
-- Quest 9128 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9128, 'frFR', 'Je ne peux que te guider dans la bonne direction, $N.') ON DUPLICATE KEY UPDATE CompletionText='Je ne peux que te guider dans la bonne direction, $N.';
-- Quest 9128 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9128, 'frFR', 'Un travail bien fait, <name> ! Comme promis, l\'insigne est le tien. Mais souviens-toi, il y en a plus...') ON DUPLICATE KEY UPDATE RewardText='Un travail bien fait, <name> ! Comme promis, l\'insigne est le tien. Mais souviens-toi, il y en a plus...';
-- Quest 9129 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9129, 'frFR', 'Pour être honnête, j\'utilise les cœurs pour créer l\'armure de Feu-Givre. C\'est l\'armure utilisée par les mages qui combattent à Naxxramas. Sans toi et d\'autres comme toi, nous perdrions cette guerre sans aucun doute.$B$BCeci dit, apporte-moi plus de cœurs et je te donnerai plus d\'insignes.') ON DUPLICATE KEY UPDATE CompletionText='Pour être honnête, j\'utilise les cœurs pour créer l\'armure de Feu-Givre. C\'est l\'armure utilisée par les mages qui combattent à Naxxramas. Sans toi et d\'autres comme toi, nous perdrions cette guerre sans aucun doute.$B$BCeci dit, apporte-moi plus de cœurs et je te donnerai plus d\'insignes.';
-- Quest 9129 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9129, 'frFR', 'Tu nous rends un grand service, $N. Bien joué !') ON DUPLICATE KEY UPDATE RewardText='Tu nous rends un grand service, $N. Bien joué !';
-- Quest 9132 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9132, 'frFR', 'Pour chaque bras de fer de ferraille, je te donnerai un insigne - plus c\'est mieux. Maintenant, disparais de ma vue avant que je ne te coupe en deux !') ON DUPLICATE KEY UPDATE CompletionText='Pour chaque bras de fer de ferraille, je te donnerai un insigne - plus c\'est mieux. Maintenant, disparais de ma vue avant que je ne te coupe en deux !';
-- Quest 9132 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9132, 'frFR', 'C\'est tout ce que tu m\'as apporté ? Peut-être ne m\'as-tu pas entendu la première fois. J\'en veux PLUS !') ON DUPLICATE KEY UPDATE RewardText='C\'est tout ce que tu m\'as apporté ? Peut-être ne m\'as-tu pas entendu la première fois. J\'en veux PLUS !';
-- Quest 9135 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9135, 'frFR', '$C, de retour si vite ? Est-ce ce que je t\'ai envoyé ? Ça ne ressemble pas à tout ce que j\'ai demandé !') ON DUPLICATE KEY UPDATE CompletionText='$C, de retour si vite ? Est-ce ce que je t\'ai envoyé ? Ça ne ressemble pas à tout ce que j\'ai demandé !';

-- Quest 9135 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9135, 'frFR', 'Eh bien, je suppose que s\'il a dit que le reste arriverait rapidement par voie terrestre, alors je le crois sur parole. Il n\'a jamais manqué de fournir la marchandise par le passé.$B$BMerci, <name>. Tiens ce coin... il n\'a fait que tinter dans ma poche toute la journée.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, je suppose que s\'il a dit que le reste arriverait rapidement par voie terrestre, alors je le crois sur parole. Il n\'a jamais manqué de fournir la marchandise par le passé.$B$BMerci, <name>. Tiens ce coin... il n\'a fait que tinter dans ma poche toute la journée.';
-- Quest 9137 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9137, 'frFR', 'Pour chaque paquet de frondes que vous me livrez, je vous paierai avec votre choix d\'insigne de l\'Aube ou de la Croisade.$b$bLes insignes peuvent être remis au Quartier-Maître pour diverses récompenses.') ON DUPLICATE KEY UPDATE CompletionText='Pour chaque paquet de frondes que vous me livrez, je vous paierai avec votre choix d\'insigne de l\'Aube ou de la Croisade.$b$bLes insignes peuvent être remis au Quartier-Maître pour diverses récompenses.';
-- Quest 9137 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9137, 'frFR', 'Merci, $N. Votre travail est vital au succès de notre campagne contre la Horde.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Votre travail est vital au succès de notre campagne contre la Horde.';
-- Quest 9138 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9138, 'frFR', 'Avec votre aide, nous contiendrons le problème de la Horde, $c. Dar\'Khan sera traité !$B$BAvez-vous réglé le problème nerubien à Suncrown Village ?') ON DUPLICATE KEY UPDATE CompletionText='Avec votre aide, nous contiendrons le problème de la Horde, $c. Dar\'Khan sera traité !$B$BAvez-vous réglé le problème nerubien à Suncrown Village ?';
-- Quest 9139 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9139, 'frFR', 'J\'ai beaucoup appris sur le combat contre la Horde pendant le temps que j\'ai passé ici. Ils peuvent être repoussés, mais cela doit se faire par petits pas. La manière obscène dont ils peuvent prendre vos morts et les ajouter à leurs rangs en tant que nouvellement ressuscités rend impératif que vous ne fassiez aucune erreur en chemin.$B$BMaintenant, comment se passe le combat contre Goldenmist Village ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ai beaucoup appris sur le combat contre la Horde pendant le temps que j\'ai passé ici. Ils peuvent être repoussés, mais cela doit se faire par petits pas. La manière obscène dont ils peuvent prendre vos morts et les ajouter à leurs rangs en tant que nouvellement ressuscités rend impératif que vous ne fassiez aucune erreur en chemin.$B$BMaintenant, comment se passe le combat contre Goldenmist Village ?';
-- Quest 9140 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9140, 'frFR', '$C, Windrunner Village a-t-il été libéré ? Ces maëstères maudits au Sanctuaire du Soleil m\'ont harcelé pour obtenir ces restes de la Horde que je vous ai demandé de rassembler.$B$BNe t\'inquiète pas pour ça. Prends ton temps et fais le travail correctement. Je m\'occuperai des maëstères.') ON DUPLICATE KEY UPDATE CompletionText='$C, Windrunner Village a-t-il été libéré ? Ces maëstères maudits au Sanctuaire du Soleil m\'ont harcelé pour obtenir ces restes de la Horde que je vous ai demandé de rassembler.$B$BNe t\'inquiète pas pour ça. Prends ton temps et fais le travail correctement. Je m\'occuperai des maëstères.';
-- Quest 9142 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9142, 'frFR', 'Tu l\'as mérité, clochard. Maintenant, ne pleure pas sur tes ordres. Remplis-les ou détruis-les.') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as mérité, clochard. Maintenant, ne pleure pas sur tes ordres. Remplis-les ou détruis-les.';
-- Quest 9143 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9143, 'frFR', 'Tu as déjà ces oreilles de troll?$B$BTu sais, si nous pouvions obtenir de l\'aide de Tranquillien de temps en temps, ce ne serait pas un problème. Je suis juste content que tu sois là.') ON DUPLICATE KEY UPDATE CompletionText='Tu as déjà ces oreilles de troll?$B$BTu sais, si nous pouvions obtenir de l\'aide de Tranquillien de temps en temps, ce ne serait pas un problème. Je suis juste content que tu sois là.';

-- Quest 9143 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9143, 'frFR', 'J\'apprécie vos efforts, <class>! Merci. Nous pouvons dire que cette expédition et toutes les vies perdues lors de celle-ci n\'ont pas été en vain.') ON DUPLICATE KEY UPDATE RewardText='J\'apprécie vos efforts, <class>! Merci. Nous pouvons dire que cette expédition et toutes les vies perdues lors de celle-ci n\'ont pas été en vain.';
-- Quest 9147 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9147, 'frFR', 'Alors ? M\'avez-vous apporté ce dont j\'ai besoin ? Dépêchez-vous, ou le joli garçon Blood Elf est perdu !') ON DUPLICATE KEY UPDATE CompletionText='Alors ? M\'avez-vous apporté ce dont j\'ai besoin ? Dépêchez-vous, ou le joli garçon Blood Elf est perdu !';
-- Quest 9147 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9147, 'frFR', 'Juste à temps, <name>!  J\'étais sur le point de commencer à creuser un trou pour notre ami ici.$B$BMa potion semble fonctionner ; il arrive.$B$BHé, je pense qu\'il essaie d\'attirer ton attention.  Pourquoi ne pas lui parler ?') ON DUPLICATE KEY UPDATE RewardText='Juste à temps, <name>!  J\'étais sur le point de commencer à creuser un trou pour notre ami ici.$B$BMa potion semble fonctionner ; il arrive.$B$BHé, je pense qu\'il essaie d\'attirer ton attention.  Pourquoi ne pas lui parler ?';
-- Quest 9149 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9149, 'frFR', 'Avez-vous obtenu les spécimens que je vous ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous obtenu les spécimens que je vous ai demandés, $N?';
-- Quest 9150 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9150, 'frFR', 'Avez-vous obtenu les essences, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous obtenu les essences, $N?';
-- Quest 9152 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9152, 'frFR', 'Dès que j\'aurai le reste de mes fournitures. Je serai ouvert aux affaires. Les forces ici ne vont pas très loin si elles ne peuvent pas acheter ce dont elles ont besoin pour mener leurs activités.$B$BLes zones de guerre peuvent être des endroits si rentables, ne pensez-vous pas, $c? Maintenant, êtes-vous parvenu à vous battre jusqu\'à mon chariot à travers tous ces goules ?') ON DUPLICATE KEY UPDATE CompletionText='Dès que j\'aurai le reste de mes fournitures. Je serai ouvert aux affaires. Les forces ici ne vont pas très loin si elles ne peuvent pas acheter ce dont elles ont besoin pour mener leurs activités.$B$BLes zones de guerre peuvent être des endroits si rentables, ne pensez-vous pas, $c? Maintenant, êtes-vous parvenu à vous battre jusqu\'à mon chariot à travers tous ces goules ?';
-- Quest 9153 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9153, 'frFR', 'Il faudra du temps pour triompher de cette menace. Comment vous êtes-vous débrouillé, $N?') ON DUPLICATE KEY UPDATE CompletionText='Il faudra du temps pour triompher de cette menace. Comment vous êtes-vous débrouillé, $N?';
-- Quest 9153 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9153, 'frFR', 'Vous avez bien fait, $N. À travers ces défaites progressives, nous triompherons de cette menace renouvelée de la Horde.$B$BReposez-vous et rétablissez-vous, mais ensuite vous devrez retourner au front, de peur que nous ne perdions le terrain que nous avons gagné aujourd\'hui.$B$BPour vous aider dans vos batailles futures, nous mettrons à votre disposition certains de nos objets spéciaux en échange de plus de runes nécrotiques.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, $N. À travers ces défaites progressives, nous triompherons de cette menace renouvelée de la Horde.$B$BReposez-vous et rétablissez-vous, mais ensuite vous devrez retourner au front, de peur que nous ne perdions le terrain que nous avons gagné aujourd\'hui.$B$BPour vous aider dans vos batailles futures, nous mettrons à votre disposition certains de nos objets spéciaux en échange de plus de runes nécrotiques.';

-- Quest 9155 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9155, 'frFR', 'Avez-vous terminé votre tâche ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous terminé votre tâche ?';
-- Quest 9156 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9156, 'frFR', 'Vous avez quelque chose à me montrer ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez quelque chose à me montrer ?';
-- Quest 9157 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9157, 'frFR', 'Avez-vous obtenu les médaillons ? Les noyés hantent toujours ce lac !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous obtenu les médaillons ? Les noyés hantent toujours ce lac !';
-- Quest 9158 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9158, 'frFR', 'Avez-vous terminé la tâche que je vous ai demandée, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous terminé la tâche que je vous ai demandée, $N ?';
-- Quest 9159 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9159, 'frFR', 'Avez-vous terminé la tâche que je vous ai demandée, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous terminé la tâche que je vous ai demandée, $N ?';
-- Quest 9160 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9160, 'frFR', '$C. quel mot apportez-vous concernant An\'daroth et ce que les elfes de la nuit faisaient là ?') ON DUPLICATE KEY UPDATE CompletionText='$C. quel mot apportez-vous concernant An\'daroth et ce que les elfes de la nuit faisaient là ?';
-- Quest 9163 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9163, 'frFR', 'Comment vont nos efforts pour découvrir le complot des elfes de la nuit sur l\'île de Shalandis, $c ?') ON DUPLICATE KEY UPDATE CompletionText='Comment vont nos efforts pour découvrir le complot des elfes de la nuit sur l\'île de Shalandis, $c ?';
-- Quest 9165 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9165, 'frFR', '$GLe Commandant Metz reçoit le décret et le signe.>$B<br :>Excellent travail, <name. Remarquable même ! Prenez ceci comme un signe de notre appréciation. Pas de jeu de mots, crétin.') ON DUPLICATE KEY UPDATE RewardText='$GLe Commandant Metz reçoit le décret et le signe.>$B<br :>Excellent travail, <name. Remarquable même ! Prenez ceci comme un signe de notre appréciation. Pas de jeu de mots, crétin.';

-- Quest 9169 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9169, 'frFR', 'C\'est fini alors, $c? As-tu désactivé le cristal de lune des elfes de la nuit à An\'owyn?') ON DUPLICATE KEY UPDATE CompletionText='C\'est fini alors, $c? As-tu désactivé le cristal de lune des elfes de la nuit à An\'owyn?';
-- Quest 9169 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9169, 'frFR', 'C\'est un soulagement, $Gclass>! Je peux vous assurer que si vous n\'aviez pas désactivé ces orbes de divination, nous serions dans une position plus précaire que celle dans laquelle nous nous trouvons déjà! Penser, entouré d\'ennemis, et l\'un d\'eux capable d\'espionner chacun de nos mouvements!$B$BMais maintenant, nous n\'avons pas à nous inquiéter de cela grâce à vous! Voici, prenez ceci, je veux que vous soyez récompensé pour vos efforts et j\'ai juste quelques choses ici dont je n\'ai plus besoin.$B<br :>Merci encore, <name!') ON DUPLICATE KEY UPDATE RewardText='C\'est un soulagement, $Gclass>! Je peux vous assurer que si vous n\'aviez pas désactivé ces orbes de divination, nous serions dans une position plus précaire que celle dans laquelle nous nous trouvons déjà! Penser, entouré d\'ennemis, et l\'un d\'eux capable d\'espionner chacun de nos mouvements!$B$BMais maintenant, nous n\'avons pas à nous inquiéter de cela grâce à vous! Voici, prenez ceci, je veux que vous soyez récompensé pour vos efforts et j\'ai juste quelques choses ici dont je n\'ai plus besoin.$B<br :>Merci encore, <name!';
-- Quest 9170 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9170, 'frFR', 'As-tu réussi à rompre la chaîne de commandement du Fléau, $N? Les lieutenants de Dar\'Khan sont-ils morts?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à rompre la chaîne de commandement du Fléau, $N? Les lieutenants de Dar\'Khan sont-ils morts?';
-- Quest 9173 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9173, 'frFR', 'J\'espère que vous reviendrez vers moi avec des nouvelles que la Flèche du Vent a été purifiée de son infection du Fléau?') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que vous reviendrez vers moi avec des nouvelles que la Flèche du Vent a été purifiée de son infection du Fléau?';
-- Quest 9175 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9175, 'frFR', 'Vous dites que vous l\'avez trouvé sur l\'un des membres du Fléau à la Flèche du Vent et qu\'il y a une inscription dessus? Laissez-moi voir!$B$BVoici, prenez cette pièce pour un travail bien fait.') ON DUPLICATE KEY UPDATE RewardText='Vous dites que vous l\'avez trouvé sur l\'un des membres du Fléau à la Flèche du Vent et qu\'il y a une inscription dessus? Laissez-moi voir!$B$BVoici, prenez cette pièce pour un travail bien fait.';
-- Quest 9178 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9178, 'frFR', 'Oui, ceux-ci seront utiles pour les armes de baston de l\'infanterie.') ON DUPLICATE KEY UPDATE RewardText='Oui, ceux-ci seront utiles pour les armes de baston de l\'infanterie.';
-- Quest 9179 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9179, 'frFR', 'Plus d\'armure pour les troupes! Fantastique, <name>!') ON DUPLICATE KEY UPDATE RewardText='Plus d\'armure pour les troupes! Fantastique, <name>!';
-- Quest 9181 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9181, 'frFR', 'Ceux-ci devraient bien aller avec les pierres de poids denses que nous stockons.') ON DUPLICATE KEY UPDATE RewardText='Ceux-ci devraient bien aller avec les pierres de poids denses que nous stockons.';

-- Quest 9182 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9182, 'frFR', 'Ce ne sont pas aussi énormes que je l\'attendais. Quoi qu\'il en soit, un accord est un accord.') ON DUPLICATE KEY UPDATE RewardText='Ce ne sont pas aussi énormes que je l\'attendais. Quoi qu\'il en soit, un accord est un accord.';
-- Quest 9183 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9183, 'frFR', 'Je ne peux toujours pas croire que Metz s\'attende à ce que nos troupes portent cette camelote de mauvaise qualité pour se protéger contre les attaques glaciales de la Horde.') ON DUPLICATE KEY UPDATE RewardText='Je ne peux toujours pas croire que Metz s\'attende à ce que nos troupes portent cette camelote de mauvaise qualité pour se protéger contre les attaques glaciales de la Horde.';
-- Quest 9185 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9185, 'frFR', 'Les kits d\'armure robustes ont de nombreuses utilisations, $N. Ils ne servent PAS UNIQUEMENT à enfiler certaines pièces d\'armure pour une protection supplémentaire. Comme celui-ci, je vais l\'utiliser comme cache-pot.') ON DUPLICATE KEY UPDATE RewardText='Les kits d\'armure robustes ont de nombreuses utilisations, $N. Ils ne servent PAS UNIQUEMENT à enfiler certaines pièces d\'armure pour une protection supplémentaire. Comme celui-ci, je vais l\'utiliser comme cache-pot.';
-- Quest 9186 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9186, 'frFR', 'Ces ceintures sont en fait plus diables que les bandeaux - si vous pouvez croire qu\'une telle chose est possible.') ON DUPLICATE KEY UPDATE RewardText='Ces ceintures sont en fait plus diables que les bandeaux - si vous pouvez croire qu\'une telle chose est possible.';
-- Quest 9187 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9187, 'frFR', 'Les druides apprécieront certainement le savoir-faire qui a été mis dans la confection de ces pantalons. Merci beaucoup, $c.') ON DUPLICATE KEY UPDATE RewardText='Les druides apprécieront certainement le savoir-faire qui a été mis dans la confection de ces pantalons. Merci beaucoup, $c.';
-- Quest 9188 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9188, 'frFR', 'Je peux presque me voir dans ces choses ! C\'est fou.') ON DUPLICATE KEY UPDATE RewardText='Je peux presque me voir dans ces choses ! C\'est fou.';
-- Quest 9189 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9189, 'frFR', 'Salutations, $Gbrother:sister;. Quelle nouvelle apportez-vous ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $Gbrother:sister;. Quelle nouvelle apportez-vous ?';
-- Quest 9189 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9189, 'frFR', 'Je vois ici que l\'Ambassadeur Sunsorrow a de grands espoirs pour votre ascension continue en tant que crédit des sin\'dorei. Malheureusement, l\'affaire avec Lady Sylvanas. Ne vous en préoccupez pas, <name>, vous avez fait le bien en lui rendant son collier. Elle aurait dû être reconnaissante, mais c\'est ainsi la voie de la royauté.$B$BTant que vous êtes ici, si vous choisissez d\'aider aux tâches des Forsaken, soyez exemplaire. Vous ne voudriez pas nuire à notre nouveau lien avec la Horde, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE RewardText='Je vois ici que l\'Ambassadeur Sunsorrow a de grands espoirs pour votre ascension continue en tant que crédit des sin\'dorei. Malheureusement, l\'affaire avec Lady Sylvanas. Ne vous en préoccupez pas, <name>, vous avez fait le bien en lui rendant son collier. Elle aurait dû être reconnaissante, mais c\'est ainsi la voie de la royauté.$B$BTant que vous êtes ici, si vous choisissez d\'aider aux tâches des Forsaken, soyez exemplaire. Vous ne voudriez pas nuire à notre nouveau lien avec la Horde, n\'est-ce pas ?';

-- Quest 9190 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9190, 'frFR', 'Par la barbe de Bronzebeard ! Tu m\'as apporté des bottes en tissu de rune... J\'imagine que j\'ai perdu ce pari.') ON DUPLICATE KEY UPDATE RewardText='Par la barbe de Bronzebeard ! Tu m\'as apporté des bottes en tissu de rune... J\'imagine que j\'ai perdu ce pari.';
-- Quest 9191 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9191, 'frFR', 'Des bottes bénies ! Est-ce ce que je crois ? Les troupes se plaignent sans arrêt du manque d\'espace de stockage pour tout ce qui est nécessaire sur le terrain. L\'un d\'eux m\'a même dessiné un schéma - quel pleurniche...$B$BCelles-ci vont certainement aider à atténuer une partie des plaintes.') ON DUPLICATE KEY UPDATE RewardText='Des bottes bénies ! Est-ce ce que je crois ? Les troupes se plaignent sans arrêt du manque d\'espace de stockage pour tout ce qui est nécessaire sur le terrain. L\'un d\'eux m\'a même dessiné un schéma - quel pleurniche...$B$BCelles-ci vont certainement aider à atténuer une partie des plaintes.';
-- Quest 9192 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9192, 'frFR', 'Est-ce une bonne nouvelle, ou une mauvaise, ma chérie ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce une bonne nouvelle, ou une mauvaise, ma chérie ?';
-- Quest 9194 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9194, 'frFR', 'Tu n\'aurais pas dû ! Non sérieusement, tu n\'aurais pas dû. Je ne sais pas ce que Metz pense, mais personne ne portera ces robes dans Naxxramas.$B$B<Packmaster Stonebruiser soupire.>$B$BBah, un autre tas de déchets que je devrai faire transférer sur le front et un autre sermon que je devrai prendre de Chambers.') ON DUPLICATE KEY UPDATE RewardText='Tu n\'aurais pas dû ! Non sérieusement, tu n\'aurais pas dû. Je ne sais pas ce que Metz pense, mais personne ne portera ces robes dans Naxxramas.$B$B<Packmaster Stonebruiser soupire.>$B$BBah, un autre tas de déchets que je devrai faire transférer sur le front et un autre sermon que je devrai prendre de Chambers.';
-- Quest 9195 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9195, 'frFR', 'Maintenant, tu parles mon langage, $c. Des choses qui font BOUM !') ON DUPLICATE KEY UPDATE RewardText='Maintenant, tu parles mon langage, $c. Des choses qui font BOUM !';
-- Quest 9196 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9196, 'frFR', 'Ça a dû coûter un bon morceau de cuivre pour les fabriquer. J\'ai raison ou je raisonne, $N ?') ON DUPLICATE KEY UPDATE RewardText='Ça a dû coûter un bon morceau de cuivre pour les fabriquer. J\'ai raison ou je raisonne, $N ?';
-- Quest 9197 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9197, 'frFR', 'Pourquoi souris-tu ? Qu\'est-ce qui est si drôle ? Écoute, $Gmister:missy;, un coq de bataille gnomique est une unité très importante et ne doit pas être prise à la légère - JAMAIS. Nous les envoyons dans des zones qui pourraient être fortement infestées et ils nettoient tout insecte infecté ou larve de charogne qui pourrait encore voltiger. Tout le monde sait que les robots sont immunisés contre la peste.$B$Je parie que tu ne te sens pas si malin maintenant, n\'est-ce pas ? Gros imbécile...') ON DUPLICATE KEY UPDATE RewardText='Pourquoi souris-tu ? Qu\'est-ce qui est si drôle ? Écoute, $Gmister:missy;, un coq de bataille gnomique est une unité très importante et ne doit pas être prise à la légère - JAMAIS. Nous les envoyons dans des zones qui pourraient être fortement infestées et ils nettoient tout insecte infecté ou larve de charogne qui pourrait encore voltiger. Tout le monde sait que les robots sont immunisés contre la peste.$B$Je parie que tu ne te sens pas si malin maintenant, n\'est-ce pas ? Gros imbécile...';
-- Quest 9200 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9200, 'frFR', 'L\'utilité de celles-ci va de soi.') ON DUPLICATE KEY UPDATE RewardText='L\'utilité de celles-ci va de soi.';

-- Quest 9201 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9201, 'frFR', '<Packmaster Stonebruiser ouvre un des potions de protection arcanique supérieures et en prend une gorgée.>$B$BWOOT! Ça donne un coup de pied, bébé! Un coup de pied je dis!') ON DUPLICATE KEY UPDATE RewardText='<Packmaster Stonebruiser ouvre un des potions de protection arcanique supérieures et en prend une gorgée.>$B$BWOOT! Ça donne un coup de pied, bébé! Un coup de pied je dis!';
-- Quest 9202 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9202, 'frFR', 'Savez-vous ce que les troupes en première ligne appellent ça? Des prêtres en bouteille...$B$B<Packmaster Stonebruiser chante.>$B$B"Je suis votre prêtre en bouteille bébé... vous devez me boire de la bonne manière..."$B$BQu\'est-ce qui ne va pas, mademoiselle? C\'est une chanson très populaire dans ces parages.') ON DUPLICATE KEY UPDATE RewardText='Savez-vous ce que les troupes en première ligne appellent ça? Des prêtres en bouteille...$B$B<Packmaster Stonebruiser chante.>$B$B"Je suis votre prêtre en bouteille bébé... vous devez me boire de la bonne manière..."$B$BQu\'est-ce qui ne va pas, mademoiselle? C\'est une chanson très populaire dans ces parages.';
-- Quest 9203 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9203, 'frFR', 'Pas de commentaire.$B$B<Packmaster Stonebruiser vous lance un regard noir.>$B$J\'ai dit pas de commentaire! Maintenant, disparais de ma vue!') ON DUPLICATE KEY UPDATE RewardText='Pas de commentaire.$B$B<Packmaster Stonebruiser vous lance un regard noir.>$B$J\'ai dit pas de commentaire! Maintenant, disparais de ma vue!';
-- Quest 9204 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9204, 'frFR', 'Vous auriez pu utiliser ça pour autre chose, mais vous ne l\'avez pas fait, n\'est-ce pas? Il est inutile de pleurer sur ça maintenant, $N.') ON DUPLICATE KEY UPDATE RewardText='Vous auriez pu utiliser ça pour autre chose, mais vous ne l\'avez pas fait, n\'est-ce pas? Il est inutile de pleurer sur ça maintenant, $N.';
-- Quest 9205 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9205, 'frFR', 'Vous ne savez vraiment pas à quoi ça sert?$B$B<Packmaster Stonebruiser rit.>$B$BComme si j\'allais vous le dire!') ON DUPLICATE KEY UPDATE RewardText='Vous ne savez vraiment pas à quoi ça sert?$B$B<Packmaster Stonebruiser rit.>$B$BComme si j\'allais vous le dire!';
-- Quest 9206 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9206, 'frFR', 'Ça fait les meilleurs rouleaux d\'anguille du monde. C\'est ça - DANS LE MONDE.') ON DUPLICATE KEY UPDATE RewardText='Ça fait les meilleurs rouleaux d\'anguille du monde. C\'est ça - DANS LE MONDE.';
-- Quest 9211 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9211, 'frFR', 'Si ce n\'était pas pour ces gardes de l\'Aube d\'Argent, vous seriez une tache sur ce sol.') ON DUPLICATE KEY UPDATE CompletionText='Si ce n\'était pas pour ces gardes de l\'Aube d\'Argent, vous seriez une tache sur ce sol.';
-- Quest 9211 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9211, 'frFR', '<Mataus met l\'or dans sa poche.>$B$BProfitez des frais de réparation, $R. Naxxramas est \'méchant\' avec les non initiés.') ON DUPLICATE KEY UPDATE RewardText='<Mataus met l\'or dans sa poche.>$B$BProfitez des frais de réparation, $R. Naxxramas est \'méchant\' avec les non initiés.';

-- Quest 9213 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9213, 'frFR', '<Mataus bâille.>$B$BPars, insecte, lest tu aies quelque chose pour moi.') ON DUPLICATE KEY UPDATE CompletionText='<Mataus bâille.>$B$BPars, insecte, lest tu aies quelque chose pour moi.';
-- Quest 9213 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9213, 'frFR', '<Mataus glisse l\'or dans sa robe.>$B$BPourquoi restes-tu là, $R? Nos affaires sont terminées.') ON DUPLICATE KEY UPDATE RewardText='<Mataus glisse l\'or dans sa robe.>$B$BPourquoi restes-tu là, $R? Nos affaires sont terminées.';
-- Quest 9215 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9215, 'frFR', 'Ah, la tête de Kel\'gash sentait si mauvais. C\'est une belle pièce de travail, $Gclass>!$B$BAvec leur chef mort, les trolls de Shadowpine devraient être en plein désarroi. Combiné à vos efforts récents pour décimer leurs effectifs, ceci devrait être l\'occasion parfaite pour lancer notre contre-offensive contre eux et les exterminer définitivement.$B<br :>Je vous remercie, <name. Puis-je vous proposer l\'un de ceux-ci ?') ON DUPLICATE KEY UPDATE RewardText='Ah, la tête de Kel\'gash sentait si mauvais. C\'est une belle pièce de travail, $Gclass>!$B$BAvec leur chef mort, les trolls de Shadowpine devraient être en plein désarroi. Combiné à vos efforts récents pour décimer leurs effectifs, ceci devrait être l\'occasion parfaite pour lancer notre contre-offensive contre eux et les exterminer définitivement.$B<br :>Je vous remercie, <name. Puis-je vous proposer l\'un de ceux-ci ?';
-- Quest 9216 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9216, 'frFR', 'Avez-vous les cœurs de zombie que j\'ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les cœurs de zombie que j\'ai demandés, $N?';
-- Quest 9217 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9217, 'frFR', 'Vous avez apporté plus de cœurs de goule ? J\'en peux utiliser autant que vous pourrez collecter, $n.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez apporté plus de cœurs de goule ? J\'en peux utiliser autant que vous pourrez collecter, $n.';
-- Quest 9218 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9218, 'frFR', 'Avez-vous les échantillons que j\'ai demandés, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous les échantillons que j\'ai demandés, $N?';
-- Quest 9218 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9218, 'frFR', 'Prenez ceci, <name>.  Vous sentirez la différence immédiatement!$B$BN\'hésitez pas à apporter plus de poussière spinale; je peux en utiliser autant que vous pourrez fournir.  Effets secondaires?  Vous pourriez commencer à sentir vos articulations faire des siennes.  Rien de permanent, je vous assure!') ON DUPLICATE KEY UPDATE RewardText='Prenez ceci, <name>.  Vous sentirez la différence immédiatement!$B$BN\'hésitez pas à apporter plus de poussière spinale; je peux en utiliser autant que vous pourrez fournir.  Effets secondaires?  Vous pourriez commencer à sentir vos articulations faire des siennes.  Rien de permanent, je vous assure!';
-- Quest 9219 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9219, 'frFR', 'Vous avez procuré plus de poussière spinale? Je peux en utiliser autant que vous m\'apportez.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez procuré plus de poussière spinale? Je peux en utiliser autant que vous m\'apportez.';

-- Quest 9219 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9219, 'frFR', 'Cette poussière est aussi puissante que jamais, <name>. Continuez à m\'apporter si vous avez besoin de renforcer vos pouvoirs magiques contre la Horde.') ON DUPLICATE KEY UPDATE RewardText='Cette poussière est aussi puissante que jamais, <name>. Continuez à m\'apporter si vous avez besoin de renforcer vos pouvoirs magiques contre la Horde.';
