INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9220, 'frFR', 'Êtes-vous revenu de Deatholme victorieux, $N?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous revenu de Deatholme victorieux, $N?';
