-- Quest 9229 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9229, 'frFR', 'C\'est son anneau ! Mais il est détruit. Aucune autre preuve de Ramaladni n\'a été trouvée?$B$B<Korfax grimace.>$B$BCela n\'est pas un bon signe pour Ramaladni. L\'anneau, cependant... il pourrait être récupérable.') ON DUPLICATE KEY UPDATE RewardText='C\'est son anneau ! Mais il est détruit. Aucune autre preuve de Ramaladni n\'a été trouvée?$B$B<Korfax grimace.>$B$BCela n\'est pas un bon signe pour Ramaladni. L\'anneau, cependant... il pourrait être récupérable.';
-- Quest 9230 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9230, 'frFR', 'Des runes gelées pourraient probablement être trouvées à l\'intérieur de Naxxramas.') ON DUPLICATE KEY UPDATE CompletionText='Des runes gelées pourraient probablement être trouvées à l\'intérieur de Naxxramas.';

-- Quest 9230 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9230, 'frFR', 'Ramaladni lui-même n\'aurait pas pu faire mieux ! Voici l\'anneau, comme promis.') ON DUPLICATE KEY UPDATE RewardText='Ramaladni lui-même n\'aurait pas pu faire mieux ! Voici l\'anneau, comme promis.';
-- Quest 9232 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9232, 'frFR', 'Vous n\'avez pas rencontré Omarion, si ?') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas rencontré Omarion, si ?';
-- Quest 9232 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9232, 'frFR', '<Wilhelm essuie la sueur de son front.>$B$BC\'est un travail ardu ! Profite du pantalon, $c. Au moins, tu mourras avec une paire propre maintenant.') ON DUPLICATE KEY UPDATE RewardText='<Wilhelm essuie la sueur de son front.>$B$BC\'est un travail ardu ! Profite du pantalon, $c. Au moins, tu mourras avec une paire propre maintenant.';
-- Quest 9233 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9233, 'frFR', 'Il devait vraiment avoir perdu la tête en écrivant ça ! Omarion et moi - on était inséparables !$B$BAin fine, cela ouvre certainement de nouvelles possibilités, $N. Je suis maintenant en mesure de fabriquer plus d\'objets - moyennant un petit frais et des coûts de matériaux, bien sûr.') ON DUPLICATE KEY UPDATE RewardText='Il devait vraiment avoir perdu la tête en écrivant ça ! Omarion et moi - on était inséparables !$B$BAin fine, cela ouvre certainement de nouvelles possibilités, $N. Je suis maintenant en mesure de fabriquer plus d\'objets - moyennant un petit frais et des coûts de matériaux, bien sûr.';
