-- Quest 9248 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9248, 'frFR', 'Fandu-dath-belore ? Oh, pardonnez-moi, $N. Je ne vous ai pas reconnu. Avez-vous le sceptre ?') ON DUPLICATE KEY UPDATE CompletionText='Fandu-dath-belore ? Oh, pardonnez-moi, $N. Je ne vous ai pas reconnu. Avez-vous le sceptre ?';
-- Quest 9248 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9248, 'frFR', 'Ande\'thoras-ethil. Cela signifie : « Que vos troubles soient diminués », dans ma langue natale.$B$Portez le bandeau avec fierté et en bonne santé, <name>.') ON DUPLICATE KEY UPDATE RewardText='Ande\'thoras-ethil. Cela signifie : « Que vos troubles soient diminués », dans ma langue natale.$B$Portez le bandeau avec fierté et en bonne santé, <name>.';
-- Quest 9249 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9249, 'frFR', 'Venez, venez ! Si vous avez des tickets de la Foire de la Lune Noire que vous souhaitez échanger, dites-le moi ! Vous pouvez échanger des tickets de différentes valeurs contre des prix merveilleux et fantastiques. N\'ayez pas peur, essayez !') ON DUPLICATE KEY UPDATE CompletionText='Venez, venez ! Si vous avez des tickets de la Foire de la Lune Noire que vous souhaitez échanger, dites-le moi ! Vous pouvez échanger des tickets de différentes valeurs contre des prix merveilleux et fantastiques. N\'ayez pas peur, essayez !';
-- Quest 9249 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9249, 'frFR', 'Voici, voici !  Un prix digne d\'un roi !  Félicitations à vous, mon ami !$B$Si vous avez d\'autres tickets que vous souhaitez remettre, faites-le moi savoir !  Tant que la Foire de la Lune Noire est là, j\'échangerai vos tickets.') ON DUPLICATE KEY UPDATE RewardText='Voici, voici !  Un prix digne d\'un roi !  Félicitations à vous, mon ami !$B$Si vous avez d\'autres tickets que vous souhaitez remettre, faites-le moi savoir !  Tant que la Foire de la Lune Noire est là, j\'échangerai vos tickets.';
-- Quest 9250 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9250, 'frFR', 'Les archimages sont morts.$B$Ne pleurez pas leur départ, $N. Toutes ces choses sont fatales. Tout comme il était destiné que vous teniez le bâton du Gardien...') ON DUPLICATE KEY UPDATE RewardText='Les archimages sont morts.$B$Ne pleurez pas leur départ, $N. Toutes ces choses sont fatales. Tout comme il était destiné que vous teniez le bâton du Gardien...';

-- Quest 9251 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9251, 'frFR', 'Sous sa forme actuelle, le bâton est bien trop dangereux pour être entre les mains d\'un mortel.') ON DUPLICATE KEY UPDATE CompletionText='Sous sa forme actuelle, le bâton est bien trop dangereux pour être entre les mains d\'un mortel.';
-- Quest 9251 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9251, 'frFR', 'Il y a une créature en son sein... une créature qui n\'est pas de ce monde.') ON DUPLICATE KEY UPDATE RewardText='Il y a une créature en son sein... une créature qui n\'est pas de ce monde.';
-- Quest 9259 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9259, 'frFR', 'Ce chien galeux, Revilgaz, a proposé de pardonner à tout ancien des Bloodsails qui voudraient se retourner contre leur capitaine ! Ce vase a demandé que j\'aille loin de mes vieux potes et que j\'apporte leurs foulards en guise de preuve.$b$bJe n\'ai pas le cœur à faire ça, et je ne vous demanderai pas non plus de le faire. Apportez-moi du tissu de soie et de la teinture rouge et je ferai des répliques appropriées. Je dirai au Baron que vous êtes un traître, mais attention... les Bloodsails ne vont pas apprécier !') ON DUPLICATE KEY UPDATE CompletionText='Ce chien galeux, Revilgaz, a proposé de pardonner à tout ancien des Bloodsails qui voudraient se retourner contre leur capitaine ! Ce vase a demandé que j\'aille loin de mes vieux potes et que j\'apporte leurs foulards en guise de preuve.$b$bJe n\'ai pas le cœur à faire ça, et je ne vous demanderai pas non plus de le faire. Apportez-moi du tissu de soie et de la teinture rouge et je ferai des répliques appropriées. Je dirai au Baron que vous êtes un traître, mais attention... les Bloodsails ne vont pas apprécier !';
-- Quest 9259 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9259, 'frFR', 'Observons une minute de silence pour nos camarades tombés, $N.$B$B<Le Traître des Bloodsails vous sourit et vous fait un clin d\'œil.> $B$BÊtre un traître est une chose, assassiner ses propres potes... ça serait tout simplement détestable, hein !') ON DUPLICATE KEY UPDATE RewardText='Observons une minute de silence pour nos camarades tombés, $N.$B$B<Le Traître des Bloodsails vous sourit et vous fait un clin d\'œil.> $B$BÊtre un traître est une chose, assassiner ses propres potes... ça serait tout simplement détestable, hein !';
-- Quest 9266 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9266, 'frFR', 'Vous avez dû faire quelque chose de très mal à nous ou à nos amis, $n$. En tout cas, je suis là pour vous offrir un moyen de regagner notre bienveillance.$b$bComme vous le savez, Winterspring est assez froid. Avec tant de nous, des gobelins, venant d\'autres villes, nous pourrions avoir besoin d\'un coup de main pour nous tenir au chaud. Apportez-moi du tissu de rune et du charbon et je ferai bien votre dossier. Attention cependant, nos ennemis ne prendront pas bien votre aide.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez dû faire quelque chose de très mal à nous ou à nos amis, $n$. En tout cas, je suis là pour vous offrir un moyen de regagner notre bienveillance.$b$bComme vous le savez, Winterspring est assez froid. Avec tant de nous, des gobelins, venant d\'autres villes, nous pourrions avoir besoin d\'un coup de main pour nous tenir au chaud. Apportez-moi du tissu de rune et du charbon et je ferai bien votre dossier. Attention cependant, nos ennemis ne prendront pas bien votre aide.';
-- Quest 9266 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9266, 'frFR', 'Merci, $N$. Vous êtes sur une voie rapide pour vous racheter auprès de notre ville respectable.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N$. Vous êtes sur une voie rapide pour vous racheter auprès de notre ville respectable.';
-- Quest 9267 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9267, 'frFR', 'Vous feriez mieux de réfléchir à deux fois avant de mettre le pied à Ratchet, $n! Des rumeurs circulent sur vos méfaits.$b$bVous avez de la chance cependant, un navire vient d\'arriver avec de nombreux blessés suite à une rencontre avec les Buccaneers des Bloodsails. C\'est votre chance de prouver que vous n\'êtes pas un scoundrel complet. Aidez-nous en apportant du tissu de lin pour les bandages et des fioles vides pour les potions.') ON DUPLICATE KEY UPDATE CompletionText='Vous feriez mieux de réfléchir à deux fois avant de mettre le pied à Ratchet, $n! Des rumeurs circulent sur vos méfaits.$b$bVous avez de la chance cependant, un navire vient d\'arriver avec de nombreux blessés suite à une rencontre avec les Buccaneers des Bloodsails. C\'est votre chance de prouver que vous n\'êtes pas un scoundrel complet. Aidez-nous en apportant du tissu de lin pour les bandages et des fioles vides pour les potions.';
-- Quest 9267 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9267, 'frFR', 'Je suis heureux que vous voyiez l\'erreur de votre voie, <name>. Continuez d\'envoyer les fournitures ; nous ne vous oublierons pas si facilement !') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que vous voyiez l\'erreur de votre voie, <name>. Continuez d\'envoyer les fournitures ; nous ne vous oublierons pas si facilement !';

-- Quest 9268 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9268, 'frFR', 'Tu cherches à te faire des amis avec les gobelins de Tanaris à nouveau, $N? Nous avons besoin de matériaux pour des voiles et des canons pour repousser nos anciens ennemis, les Corsaires de Sang. Apporte-moi de la mageweave et du flux solide et nous partirons pour pardonner tes transgressions.') ON DUPLICATE KEY UPDATE CompletionText='Tu cherches à te faire des amis avec les gobelins de Tanaris à nouveau, $N? Nous avons besoin de matériaux pour des voiles et des canons pour repousser nos anciens ennemis, les Corsaires de Sang. Apporte-moi de la mageweave et du flux solide et nous partirons pour pardonner tes transgressions.';
-- Quest 9268 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9268, 'frFR', 'Continue, <name>. Nous, les gobelins, on n\'oublie pas ça facilement !') ON DUPLICATE KEY UPDATE RewardText='Continue, <name>. Nous, les gobelins, on n\'oublie pas ça facilement !';
-- Quest 9272 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9272, 'frFR', 'Yarrr... si tu as envie de profiter de la compagnie de ces vieux loup de mer expérimentés, tu ferais mieux d\'arrêter de te déguiser en larbin ! Tiens, mets quelque chose de décent avant que je ne te fasse passer par-dessus bord.$B$BÇa te ira mieux que ça n\'a jamais convenu à ce vieux chien, Red-Eyed Ben. Je l\'ai perdu dans une tempête diabolique en mer.$B$BWeux-les avec fierté, mon pote !') ON DUPLICATE KEY UPDATE RewardText='Yarrr... si tu as envie de profiter de la compagnie de ces vieux loup de mer expérimentés, tu ferais mieux d\'arrêter de te déguiser en larbin ! Tiens, mets quelque chose de décent avant que je ne te fasse passer par-dessus bord.$B$BÇa te ira mieux que ça n\'a jamais convenu à ce vieux chien, Red-Eyed Ben. Je l\'ai perdu dans une tempête diabolique en mer.$B$BWeux-les avec fierté, mon pote !';
-- Quest 9274 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9274, 'frFR', 'Tu as fait ce que je t\'ai demandé, $N?') ON DUPLICATE KEY UPDATE CompletionText='Tu as fait ce que je t\'ai demandé, $N?';
-- Quest 9275 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9275, 'frFR', 'N\'est-ce pas excitant ? Je suis vraiment fier de mon travail ; j\'espère que tu l\'apprécies, $c.$B$BAlors, j\'espère que tu as \'assaisonné\' la nourriture dans les camps de trolls à Zeb\'Nowa ?') ON DUPLICATE KEY UPDATE CompletionText='N\'est-ce pas excitant ? Je suis vraiment fier de mon travail ; j\'espère que tu l\'apprécies, $c.$B$BAlors, j\'espère que tu as \'assaisonné\' la nourriture dans les camps de trolls à Zeb\'Nowa ?';
-- Quest 9275 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9275, 'frFR', 'Ah, excellent ! Je savais qu\'un système de livraison $R$ serait l\'application la plus efficace du poison. Avec un peu de chance, les trolls de Shadowpine vont s\'en goinfrer avant de s\'écrouler. Ça devrait les débarrasser du dos des Farstriders, et moi de Tranquillien.$B$BCe fut un plaisir de travailler avec toi, <class> !') ON DUPLICATE KEY UPDATE RewardText='Ah, excellent ! Je savais qu\'un système de livraison $R$ serait l\'application la plus efficace du poison. Avec un peu de chance, les trolls de Shadowpine vont s\'en goinfrer avant de s\'écrouler. Ça devrait les débarrasser du dos des Farstriders, et moi de Tranquillien.$B$BCe fut un plaisir de travailler avec toi, <class> !';
-- Quest 9276 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9276, 'frFR', 'Comment se passe l\'attaque sur Zeb\'Tela ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe l\'attaque sur Zeb\'Tela ?';
-- Quest 9277 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9277, 'frFR', 'Ton assaut sur Zeb\'Nowa est déjà terminé ?') ON DUPLICATE KEY UPDATE CompletionText='Ton assaut sur Zeb\'Nowa est déjà terminé ?';

-- Quest 9278 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9278, 'frFR', 'Bonjour ! C\'est un plaisir de vous rencontrer !$B$Je vois que vous avez un bon d\'achat spécial. Donnez-le-moi et je vous offrirai quelque chose en échange.') ON DUPLICATE KEY UPDATE CompletionText='Bonjour ! C\'est un plaisir de vous rencontrer !$B$Je vois que vous avez un bon d\'achat spécial. Donnez-le-moi et je vous offrirai quelque chose en échange.';
-- Quest 9278 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9278, 'frFR', 'Vous êtes en effet un héros spécial, $N. Nous vous souhaitons la bienvenue dans le monde d\'Azeroth, et vous offrons l\'un de ces cadeaux uniques !') ON DUPLICATE KEY UPDATE RewardText='Vous êtes en effet un héros spécial, $N. Nous vous souhaitons la bienvenue dans le monde d\'Azeroth, et vous offrons l\'un de ces cadeaux uniques !';
-- Quest 9281 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9281, 'frFR', 'Avez-vous pris soin de l\'affaire dont nous avons discuté, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous pris soin de l\'affaire dont nous avons discuté, $N ?';
-- Quest 9283 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9283, 'frFR', 'Nous allons survivre à cela avec votre aide.') ON DUPLICATE KEY UPDATE CompletionText='Nous allons survivre à cela avec votre aide.';
-- Quest 9287 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9287, 'frFR', 'Je suis réjoui de votre initiative de me parler. Par le passé, j\'étais responsable de la formation des jeunes paladins lorsqu\'ils rejoignaient notre ordre. C\'est un devoir et un privilège que j\'assume humblement une fois de plus. Votre nom a été mentionné comme celui qui cherche à faire le bien au nom de la Lumière. Ce serait un honneur pour moi de vous guider dans vos premiers pas en tant que $c.$B$BAllons-nous commencer ?') ON DUPLICATE KEY UPDATE RewardText='Je suis réjoui de votre initiative de me parler. Par le passé, j\'étais responsable de la formation des jeunes paladins lorsqu\'ils rejoignaient notre ordre. C\'est un devoir et un privilège que j\'assume humblement une fois de plus. Votre nom a été mentionné comme celui qui cherche à faire le bien au nom de la Lumière. Ce serait un honneur pour moi de vous guider dans vos premiers pas en tant que $c.$B$BAllons-nous commencer ?';
-- Quest 9288 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9288, 'frFR', 'Je suis heureux que vous soyez venu me voir. Depuis quelque temps, je suis responsable de la formation de nos jeunes $cs, une responsabilité que j\'ai l\'intention de continuer dans ce nouveau monde. Je vous ai observé depuis un moment et ce serait un honneur pour moi de vous aider à vous former dans les voies de la $c.$BAllons-nous commencer ?') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que vous soyez venu me voir. Depuis quelque temps, je suis responsable de la formation de nos jeunes $cs, une responsabilité que j\'ai l\'intention de continuer dans ce nouveau monde. Je vous ai observé depuis un moment et ce serait un honneur pour moi de vous aider à vous former dans les voies de la $c.$BAllons-nous commencer ?';
-- Quest 9289 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9289, 'frFR', 'C\'est bien que vous cherchiez mes conseils. Pendant des siècles, j\'ai enseigné aux jeunes guerriers $R, donc je connais un peu tout sur la manière dont vous devriez commencer. Je vois en vous le potentiel d\'un grand $c, mais seulement si vous écoutez attentivement ce que j\'ai à vous enseigner.$B$Êtes-vous prêt à apprendre, jeune $c ?') ON DUPLICATE KEY UPDATE RewardText='C\'est bien que vous cherchiez mes conseils. Pendant des siècles, j\'ai enseigné aux jeunes guerriers $R, donc je connais un peu tout sur la manière dont vous devriez commencer. Je vois en vous le potentiel d\'un grand $c, mais seulement si vous écoutez attentivement ce que j\'ai à vous enseigner.$B$Êtes-vous prêt à apprendre, jeune $c ?';
-- Quest 9290 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9290, 'frFR', 'Je suis heureux que vous soyez venu chercher mes connaissances. Nous avons beaucoup à faire si vos compétences magiques doivent être affinées. Pendant plus d\'un centenaire, j\'ai enseigné les magies arcaniques, de glace et de feu, et je les ressens tout aussi fortement dans ce monde. Voulez-vous que je vous transmette ce que je sais ?') ON DUPLICATE KEY UPDATE RewardText='Je suis heureux que vous soyez venu chercher mes connaissances. Nous avons beaucoup à faire si vos compétences magiques doivent être affinées. Pendant plus d\'un centenaire, j\'ai enseigné les magies arcaniques, de glace et de feu, et je les ressens tout aussi fortement dans ce monde. Voulez-vous que je vous transmette ce que je sais ?';

-- Quest 9291 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9291, 'frFR', 'Cela me donne un grand espoir pour notre avenir que vous veniez chercher ma sagesse. Bien que j\'aie les mains pleines ici avec nos blessés, je ne suis pas si occupé que je ne puisse pas prendre un moment pour vous aider dans vos premiers pas en tant que $c. Parcourir la Lumière est le plus haut des appels, et un que je suis certain que vous êtes plus que prêt à entreprendre ! Parlez-moi à nouveau lorsque vous sentirez que vous êtes prêt à commencer votre entraînement.') ON DUPLICATE KEY UPDATE RewardText='Cela me donne un grand espoir pour notre avenir que vous veniez chercher ma sagesse. Bien que j\'aie les mains pleines ici avec nos blessés, je ne suis pas si occupé que je ne puisse pas prendre un moment pour vous aider dans vos premiers pas en tant que $c. Parcourir la Lumière est le plus haut des appels, et un que je suis certain que vous êtes plus que prêt à entreprendre ! Parlez-moi à nouveau lorsque vous sentirez que vous êtes prêt à commencer votre entraînement.';
-- Quest 9294 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9294, 'frFR', 'Plus tôt vous disperserez l\'agent au lac, moins de créatures natives seront mutées en buvant l\'eau, y compris nous !$B$Je suis désolé que nous ne puissions rien faire pour aider les pauvres créatures qui ont déjà été infectées. Si seulement mon équipement de laboratoire était intact.') ON DUPLICATE KEY UPDATE CompletionText='Plus tôt vous disperserez l\'agent au lac, moins de créatures natives seront mutées en buvant l\'eau, y compris nous !$B$Je suis désolé que nous ne puissions rien faire pour aider les pauvres créatures qui ont déjà été infectées. Si seulement mon équipement de laboratoire était intact.';
-- Quest 9311 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9311, 'frFR', 'Alors c\'est vrai... une partie d\'éclaireurs d\'elfes-sang-bleus ici à Ammen Vale ! Comment nous ont-ils suivis ?$B$J\'enverrai quelqu\'un immédiatement là-bas pour ramener Tolaan.') ON DUPLICATE KEY UPDATE CompletionText='Alors c\'est vrai... une partie d\'éclaireurs d\'elfes-sang-bleus ici à Ammen Vale ! Comment nous ont-ils suivis ?$B$J\'enverrai quelqu\'un immédiatement là-bas pour ramener Tolaan.';
-- Quest 9315 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9315, 'frFR', 'Un chef nerubien ? Aucune des missions d\'éclaireurs n\'a rapporté quoi que ce soit à propos de cet Anok\'suten !') ON DUPLICATE KEY UPDATE CompletionText='Un chef nerubien ? Aucune des missions d\'éclaireurs n\'a rapporté quoi que ce soit à propos de cet Anok\'suten !';
-- Quest 9319 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9319, 'frFR', 'Avez-vous trouvé votre chemin à travers l\'obscurité ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé votre chemin à travers l\'obscurité ?';
-- Quest 9319 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9319, 'frFR', 'Vous avez prouvé que vous n\'êtes pas entièrement inutile, mortel.') ON DUPLICATE KEY UPDATE RewardText='Vous avez prouvé que vous n\'êtes pas entièrement inutile, mortel.';
-- Quest 9322 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9322, 'frFR', 'Les flammes de Kalimdor brûlent-elles vivement ?') ON DUPLICATE KEY UPDATE CompletionText='Les flammes de Kalimdor brûlent-elles vivement ?';
-- Quest 9322 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9322, 'frFR', 'Votre esprit rayonne de la chaleur des feux de Kalimdor, ami. La chaleur n\'est-elle pas revigorante ? Une fois que le pouvoir vous quittera, peut-être que ceux-ci aideront à raviver le sentiment.') ON DUPLICATE KEY UPDATE RewardText='Votre esprit rayonne de la chaleur des feux de Kalimdor, ami. La chaleur n\'est-elle pas revigorante ? Une fois que le pouvoir vous quittera, peut-être que ceux-ci aideront à raviver le sentiment.';

-- Quest 9323 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9323, 'frFR', 'Il faudra du temps pour triompher de cette menace. Comment as-tu réussi, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Il faudra du temps pour triompher de cette menace. Comment as-tu réussi, $N ?';
-- Quest 9323 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9323, 'frFR', 'Ah, te voilà. Un peu plus fatigué, un peu plus poussiéreux, mais éclairé ! La chaleur nous touche tous durant cette saison et nous unit ; ton être même rayonne de la puissance des feux que tu as touchés. Ah, mais de nos jours, l\'illumination est prise comme une récompense assez maigre pour avoir été envoyé en mission, je suppose. Prends ceci, alors, et profite de la célébration.') ON DUPLICATE KEY UPDATE RewardText='Ah, te voilà. Un peu plus fatigué, un peu plus poussiéreux, mais éclairé ! La chaleur nous touche tous durant cette saison et nous unit ; ton être même rayonne de la puissance des feux que tu as touchés. Ah, mais de nos jours, l\'illumination est prise comme une récompense assez maigre pour avoir été envoyé en mission, je suppose. Prends ceci, alors, et profite de la célébration.';
-- Quest 9324 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9324, 'frFR', 'Tu es pratiquement en train de briller, $R. Qu\'est-ce que tu as là ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es pratiquement en train de briller, $R. Qu\'est-ce que tu as là ?';
-- Quest 9324 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9324, 'frFR', 'Qu\'est-ce que c\'est ? Si je ne me trompe pas, cette flamme a été prise du cœur même d\'Orgrimmar ! Les cœurs fiers des orcs et des trolls se reflètent dans sa chaleur brûlante. Quelle belle addition à notre collection -- quelle bravoure de ta part, de t\'introduire dans le repaire de l\'ennemi pour récupérer la flamme sacrée !') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est ? Si je ne me trompe pas, cette flamme a été prise du cœur même d\'Orgrimmar ! Les cœurs fiers des orcs et des trolls se reflètent dans sa chaleur brûlante. Quelle belle addition à notre collection -- quelle bravoure de ta part, de t\'introduire dans le repaire de l\'ennemi pour récupérer la flamme sacrée !';
-- Quest 9325 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9325, 'frFR', 'Tu es pratiquement en train de briller, $R. Qu\'est-ce que tu as là ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es pratiquement en train de briller, $R. Qu\'est-ce que tu as là ?';
-- Quest 9325 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9325, 'frFR', 'Si je ne me trompe pas, ce feu a été pris des falaises de Thunder Bluff ! Comme il chante avec la puissance des esprits ! Tu es un voleur notoire, $N. Prends ceci comme juste paiement pour ton talent. Maintenant, si seulement nous avions les flammes des trois villes...') ON DUPLICATE KEY UPDATE RewardText='Si je ne me trompe pas, ce feu a été pris des falaises de Thunder Bluff ! Comme il chante avec la puissance des esprits ! Tu es un voleur notoire, $N. Prends ceci comme juste paiement pour ton talent. Maintenant, si seulement nous avions les flammes des trois villes...';
-- Quest 9326 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9326, 'frFR', 'Tu es pratiquement en train de briller, $R. Qu\'est-ce que tu as là ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es pratiquement en train de briller, $R. Qu\'est-ce que tu as là ?';
-- Quest 9326 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9326, 'frFR', 'Hm... quel feu étrange ! Il est atténué, presque en train de couver, mais la chaleur est intense. Et tu l\'as reçu de la Cité Inférieure, dis-tu ? Fascinant. Avec les flammes des trois villes, qui sait ce que nous pourrions accomplir ?') ON DUPLICATE KEY UPDATE RewardText='Hm... quel feu étrange ! Il est atténué, presque en train de couver, mais la chaleur est intense. Et tu l\'as reçu de la Cité Inférieure, dis-tu ? Fascinant. Avec les flammes des trois villes, qui sait ce que nous pourrions accomplir ?';

-- Quest 9327 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9327, 'frFR', 'Je sais que nous, les Désespérés, apparaissons monstrueux à vos yeux, mais je vous assure que nous ne voulons aucun mal à votre peuple. Nous sommes ici à cause d\'un ennemi commun : Dar\'Khan le traître ! Il est revenu et commande maintenant les Scourge qui envahissent cette terre, de son fidèle, Deatholme, jusqu\'au sud.$B$Notre leader, Dame Sylvanas Ventenune, est originaire de ces terres, et était en fait une elfe. Elle a un historique avec Dar\'Khan et veut qu\'il soit mort autant que votre peuple.$B$Nous le vaincrons ensemble, <class>!') ON DUPLICATE KEY UPDATE RewardText='Je sais que nous, les Désespérés, apparaissons monstrueux à vos yeux, mais je vous assure que nous ne voulons aucun mal à votre peuple. Nous sommes ici à cause d\'un ennemi commun : Dar\'Khan le traître ! Il est revenu et commande maintenant les Scourge qui envahissent cette terre, de son fidèle, Deatholme, jusqu\'au sud.$B$Notre leader, Dame Sylvanas Ventenune, est originaire de ces terres, et était en fait une elfe. Elle a un historique avec Dar\'Khan et veut qu\'il soit mort autant que votre peuple.$B$Nous le vaincrons ensemble, <class>!';
-- Quest 9328 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9328, 'frFR', 'Vous cherchez à me parler, $c? Je ne me souviens pas avoir entendu parler d\'un rendez-vous.') ON DUPLICATE KEY UPDATE CompletionText='Vous cherchez à me parler, $c? Je ne me souviens pas avoir entendu parler d\'un rendez-vous.';
-- Quest 9329 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9329, 'frFR', 'Je sais que cela semble étrange, mais les Désespérés sont ici pour aider. Vous devriez parler à leur chef, l\'Exécuteur Supérieur Mavren. Il est dans la tour sur le côté ouest de la ville.$B$Et, $C, quand vous aurez fini de lui parler, revenez-moi ; j\'ai quelque chose de grave qui doit être réglé immédiatement !') ON DUPLICATE KEY UPDATE CompletionText='Je sais que cela semble étrange, mais les Désespérés sont ici pour aider. Vous devriez parler à leur chef, l\'Exécuteur Supérieur Mavren. Il est dans la tour sur le côté ouest de la ville.$B$Et, $C, quand vous aurez fini de lui parler, revenez-moi ; j\'ai quelque chose de grave qui doit être réglé immédiatement !';
-- Quest 9330 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9330, 'frFR', 'Vous êtes pratiquement en train de briller, $R. Qu\'avez-vous là ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes pratiquement en train de briller, $R. Qu\'avez-vous là ?';
-- Quest 9330 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9330, 'frFR', 'Et ce feu qui brûle si vivement... vous dites qu\'il vient de Stormwind ? Remarquable ! Cela a dû être une aventure formidable ! Je vous paierai pour cela, bien sûr. Si vous trouvez autre chose comme ça, assurez-vous de me reparler.') ON DUPLICATE KEY UPDATE RewardText='Et ce feu qui brûle si vivement... vous dites qu\'il vient de Stormwind ? Remarquable ! Cela a dû être une aventure formidable ! Je vous paierai pour cela, bien sûr. Si vous trouvez autre chose comme ça, assurez-vous de me reparler.';
-- Quest 9331 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9331, 'frFR', 'Vous êtes pratiquement en train de briller, $R. Qu\'avez-vous là ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes pratiquement en train de briller, $R. Qu\'avez-vous là ?';
-- Quest 9331 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9331, 'frFR', 'Cette flamme robuste doit venir des salles d\'Ironforge ; elle est aussi solide que les nains eux-mêmes. Une belle prise, $N. Si j\'avais les feux des autres villes... ah, mais laissez tomber. Voici votre paiement.') ON DUPLICATE KEY UPDATE RewardText='Cette flamme robuste doit venir des salles d\'Ironforge ; elle est aussi solide que les nains eux-mêmes. Une belle prise, $N. Si j\'avais les feux des autres villes... ah, mais laissez tomber. Voici votre paiement.';
-- Quest 9332 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9332, 'frFR', 'Vous êtes pratiquement en train de briller, $R. Qu\'avez-vous là ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes pratiquement en train de briller, $R. Qu\'avez-vous là ?';

-- Quest 9338 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9338, 'frFR', 'Même si vous n\'avez pas besoin des récompenses matérielles que nous offrons, ces badges témoignent toujours de notre confiance mutuelle et de notre amitié.$B$Apportez-les-moi. Je prendrai bonne note de votre service si votre performance dépasse les exigences du devoir.') ON DUPLICATE KEY UPDATE CompletionText='Même si vous n\'avez pas besoin des récompenses matérielles que nous offrons, ces badges témoignent toujours de notre confiance mutuelle et de notre amitié.$B$Apportez-les-moi. Je prendrai bonne note de votre service si votre performance dépasse les exigences du devoir.';
-- Quest 9338 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9338, 'frFR', 'Vous nous honorez, $N. Avec vos efforts continus, nous surmonterons tous les obstacles.') ON DUPLICATE KEY UPDATE RewardText='Vous nous honorez, $N. Avec vos efforts continus, nous surmonterons tous les obstacles.';
-- Quest 9339 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9339, 'frFR', 'Vous vous êtes prouvé, aujourd\'hui, $N.$b$Bien que je n\'aie guère plus à vous donner, j\'ai cette couronne ; un cadeau approprié pour un conquérant. Qu\'elle éclaire votre chemin.') ON DUPLICATE KEY UPDATE RewardText='Vous vous êtes prouvé, aujourd\'hui, $N.$b$Bien que je n\'aie guère plus à vous donner, j\'ai cette couronne ; un cadeau approprié pour un conquérant. Qu\'elle éclaire votre chemin.';
-- Quest 9340 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9340, 'frFR', 'Vous êtes revenu. La tâche est accomplie ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu. La tâche est accomplie ?';
-- Quest 9342 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9342, 'frFR', 'Merci pour votre aide, $N. Vous avez quelque chose de prévu pour faire travailler les pions ?') ON DUPLICATE KEY UPDATE RewardText='Merci pour votre aide, $N. Vous avez quelque chose de prévu pour faire travailler les pions ?';
-- Quest 9344 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9344, 'frFR', '<Grelag gémit en essayant de se relever.>$BI j\'aurais dû suivre le conseil de la Voyante Far, Regulkut, et attendre les gardes du corps qu\'elle allait m\'envoyer. J\'ai de la chance qu\'elle ait pensé à m\'envoyer quelqu\'un après moi.$BI je n\'aurais pas pu revenir à Thrallmar par moi-même. J\'ai fait de mon mieux pour ce voyage, mais sans mes provisions, les perspectives sont sombres.') ON DUPLICATE KEY UPDATE RewardText='<Grelag gémit en essayant de se relever.>$BI j\'aurais dû suivre le conseil de la Voyante Far, Regulkut, et attendre les gardes du corps qu\'elle allait m\'envoyer. J\'ai de la chance qu\'elle ait pensé à m\'envoyer quelqu\'un après moi.$BI je n\'aurais pas pu revenir à Thrallmar par moi-même. J\'ai fait de mon mieux pour ce voyage, mais sans mes provisions, les perspectives sont sombres.';
-- Quest 9352 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9352, 'frFR', 'Avez-vous découvert quelque chose ? Les elfes de la nuit sont derrière cela ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous découvert quelque chose ? Les elfes de la nuit sont derrière cela ?';
-- Quest 9355 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9355, 'frFR', 'Avez-vous réussi à dégager la route ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à dégager la route ?';

-- Quest 9362 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9362, 'frFR', 'Il n\'y a pas de temps à perdre ! As-tu la coquille ?') ON DUPLICATE KEY UPDATE CompletionText='Il n\'y a pas de temps à perdre ! As-tu la coquille ?';
-- Quest 9362 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9362, 'frFR', 'Je dois dire que cette coquille a une aura étrange.  Il semble tout à fait approprié que une partie de ta récompense pour l\'avoir récupérée soit de tester ses capacités magiques...') ON DUPLICATE KEY UPDATE RewardText='Je dois dire que cette coquille a une aura étrange.  Il semble tout à fait approprié que une partie de ta récompense pour l\'avoir récupérée soit de tester ses capacités magiques...';
-- Quest 9364 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9364, 'frFR', 'Splendide !  Splendide !$B$BMaintenant, nous sommes en mesure de reformer cette magie en un nouveau sort.  Voyez !') ON DUPLICATE KEY UPDATE RewardText='Splendide !  Splendide !$B$BMaintenant, nous sommes en mesure de reformer cette magie en un nouveau sort.  Voyez !';
-- Quest 9365 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9365, 'frFR', 'Tu t\'es prouvé, aujourd\'hui, $N.$b$bBien que je n\'aie guère plus à te donner, j\'ai cette couronne ; un cadeau approprié pour un conquérant. Qu\'elle t\'éclaire le chemin') ON DUPLICATE KEY UPDATE RewardText='Tu t\'es prouvé, aujourd\'hui, $N.$b$bBien que je n\'aie guère plus à te donner, j\'ai cette couronne ; un cadeau approprié pour un conquérant. Qu\'elle t\'éclaire le chemin';
-- Quest 9367 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9367, 'frFR', 'Excellent ! Il semble que nous ayons nommé des Gardiens de Flammes dignes cette année si les feux de joie sont aussi bien entretenus que tu le prétends. Merci de les avoir inspectés pour moi ; voici, prends ceci comme un petit signe de mon estime.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Il semble que nous ayons nommé des Gardiens de Flammes dignes cette année si les feux de joie sont aussi bien entretenus que tu le prétends. Merci de les avoir inspectés pour moi ; voici, prends ceci comme un petit signe de mon estime.';
-- Quest 9368 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9368, 'frFR', 'Excellent travail, $N. Avec les ombres détruites, il ne reste plus qu\'une question de temps avant que le Roi-Liche ne décide de rappeler ses nécropoles et de nous laisser en paix.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, $N. Avec les ombres détruites, il ne reste plus qu\'une question de temps avant que le Roi-Liche ne décide de rappeler ses nécropoles et de nous laisser en paix.';
-- Quest 9386 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9386, 'frFR', 'Tu as prouvé que tu n\'es pas entièrement inutile, mortel.') ON DUPLICATE KEY UPDATE RewardText='Tu as prouvé que tu n\'es pas entièrement inutile, mortel.';
-- Quest 9388 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9388, 'frFR', 'Les feux ne peuvent mourir tant que le festival n\'est pas terminé !') ON DUPLICATE KEY UPDATE CompletionText='Les feux ne peuvent mourir tant que le festival n\'est pas terminé !';

-- Quest 9388 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9388, 'frFR', 'Ahhh, ils brûlent toujours. Je suis content ; il ne faudrait pas que ces feux s\'éteignent avant leur temps. Tu as bien fait, $N$. Prends ceci avec ma bénédiction.') ON DUPLICATE KEY UPDATE RewardText='Ahhh, ils brûlent toujours. Je suis content ; il ne faudrait pas que ces feux s\'éteignent avant leur temps. Tu as bien fait, $N$. Prends ceci avec ma bénédiction.';
-- Quest 9389 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9389, 'frFR', 'Alors tu es revenu, et tu as vu les flammes émeraude du continent. Qu\'en penses-tu, mm ? Une vue rare et merveilleuse, c\'est certain. Je suis cependant conscient que des récompenses tangibles sont mieux appréciées... alors s\'il te plaît, prends ceci pour tes ennuis.') ON DUPLICATE KEY UPDATE RewardText='Alors tu es revenu, et tu as vu les flammes émeraude du continent. Qu\'en penses-tu, mm ? Une vue rare et merveilleuse, c\'est certain. Je suis cependant conscient que des récompenses tangibles sont mieux appréciées... alors s\'il te plaît, prends ceci pour tes ennuis.';
-- Quest 9398 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9398, 'frFR', 'Bienvenue de retour, $N$. As-tu accompli la tâche que je t\'ai demandée ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue de retour, $N$. As-tu accompli la tâche que je t\'ai demandée ?';
-- Quest 9399 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9399, 'frFR', 'Tu es revenu ! As-tu accompli ta tâche ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es revenu ! As-tu accompli ta tâche ?';
-- Quest 9402 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9402, 'frFR', 'Oh, bien joué... Je t\'avais dit de sauter dans un étang, et tu l\'as fait. Je peux imaginer ce que tu ferais si l\'un de tes bons amis te le demandait.$B$BSi tu veux une récompense pour tes efforts, c\'est ceci : ne lève pas un doigt sans savoir ce que ça t\'apporte. L\'esprit de $c$ est son plus grand atout. Souviens-en et essaie d\'utiliser le tien un peu plus.') ON DUPLICATE KEY UPDATE RewardText='Oh, bien joué... Je t\'avais dit de sauter dans un étang, et tu l\'as fait. Je peux imaginer ce que tu ferais si l\'un de tes bons amis te le demandait.$B$BSi tu veux une récompense pour tes efforts, c\'est ceci : ne lève pas un doigt sans savoir ce que ça t\'apporte. L\'esprit de $c$ est son plus grand atout. Souviens-en et essaie d\'utiliser le tien un peu plus.';
-- Quest 9403 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9403, 'frFR', 'Seule l\'eau des Chutes d\'Elrendar possède la pureté requise pour l\'utilisation avec la magie. L\'as-tu ?') ON DUPLICATE KEY UPDATE CompletionText='Seule l\'eau des Chutes d\'Elrendar possède la pureté requise pour l\'utilisation avec la magie. L\'as-tu ?';
-- Quest 9403 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9403, 'frFR', 'Voyons ce que tu m\'as apporté...$B$B$GIl tient le flacon à la lumière et l\'examine attentivement.>$B<br :>Oui, cela fera l\'affaire. Bien joué, <name.') ON DUPLICATE KEY UPDATE RewardText='Voyons ce que tu m\'as apporté...$B$B$GIl tient le flacon à la lumière et l\'examine attentivement.>$B<br :>Oui, cela fera l\'affaire. Bien joué, <name.';
-- Quest 9404 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9404, 'frFR', 'As-tu la branche vivante ? Donne-la rapidement !') ON DUPLICATE KEY UPDATE CompletionText='As-tu la branche vivante ? Donne-la rapidement !';

-- Quest 9404 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9404, 'frFR', 'Vous avez fait ce que j\'ai demandé, <name>, et vous pouvez prendre votre récompense maintenant.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait ce que j\'ai demandé, <name>, et vous pouvez prendre votre récompense maintenant.';
-- Quest 9421 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9421, 'frFR', 'Je suis Firmanvaar et vous êtes sage de me chercher. Il est de mon devoir de fournir des instructions aux chamans, surtout à ceux qui commencent tout juste à apprendre.$B$Le shamanisme est en train d\'être réappris parmi les draenais, $N. Vous êtes courageux de suivre son chemin car il n\'est pas populaire parmi votre espèce.$B$Je serai là quand vous sentirez être prêt pour un entraînement supplémentaire.') ON DUPLICATE KEY UPDATE RewardText='Je suis Firmanvaar et vous êtes sage de me chercher. Il est de mon devoir de fournir des instructions aux chamans, surtout à ceux qui commencent tout juste à apprendre.$B$Le shamanisme est en train d\'être réappris parmi les draenais, $N. Vous êtes courageux de suivre son chemin car il n\'est pas populaire parmi votre espèce.$B$Je serai là quand vous sentirez être prêt pour un entraînement supplémentaire.';
-- Quest 9422 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9422, 'frFR', 'Méfiez-vous des dangers du désert, $n. Avec l\'Alliance rôdant dans les dunes, chaque pas pourrait être votre dernier.') ON DUPLICATE KEY UPDATE CompletionText='Méfiez-vous des dangers du désert, $n. Avec l\'Alliance rôdant dans les dunes, chaque pas pourrait être votre dernier.';
-- Quest 9425 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9425, 'frFR', 'Mon Dieu, mon Dieu !  Un autre de mes frères arrive pour aider.  Bien !  Il y a beaucoup à faire pour soutenir nos nouveaux amis Forsakés, <class>.  Demandez autour de vous pour voir qui vous pouvez aider.$B$Je sais que vous allez les soutenir de votre plus grande capacité !') ON DUPLICATE KEY UPDATE RewardText='Mon Dieu, mon Dieu !  Un autre de mes frères arrive pour aider.  Bien !  Il y a beaucoup à faire pour soutenir nos nouveaux amis Forsakés, <class>.  Demandez autour de vous pour voir qui vous pouvez aider.$B$Je sais que vous allez les soutenir de votre plus grande capacité !';
-- Quest 9437 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9437, 'frFR', 'Avez-vous libéré Ithania et récupéré ma cargaison de ces corsaires glorifiés ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous libéré Ithania et récupéré ma cargaison de ces corsaires glorifiés ?';
-- Quest 9437 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9437, 'frFR', 'Bien joué, <name> ! Dès qu\'Ithania aura eu le temps de se reposer et que mes préparatifs seront terminés, nous quitterons ce désert boueux et nous dirigerons vers la civilisation.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name> ! Dès qu\'Ithania aura eu le temps de se reposer et que mes préparatifs seront terminés, nous quitterons ce désert boueux et nous dirigerons vers la civilisation.';
-- Quest 9439 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9439, 'frFR', 'Pour le bien de Sunstrider, ne me dévisagez pas ! C\'est déjà assez que je sois forcé de supporter ça ici dans mes vêtements souillés ! Après tout ce que j\'ai traversé, la dernière chose dont j\'ai besoin est d\'être regardé. Avez-vous réussi à récupérer mes possessions de ce trou dans le sol que ces Irons Noirs appellent une forteresse ?') ON DUPLICATE KEY UPDATE CompletionText='Pour le bien de Sunstrider, ne me dévisagez pas ! C\'est déjà assez que je sois forcé de supporter ça ici dans mes vêtements souillés ! Après tout ce que j\'ai traversé, la dernière chose dont j\'ai besoin est d\'être regardé. Avez-vous réussi à récupérer mes possessions de ce trou dans le sol que ces Irons Noirs appellent une forteresse ?';
-- Quest 9439 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9439, 'frFR', 'Vous êtes un miracle, <name> ! Je vous dis, je n\'ai jamais eu autant soif de changer de vêtements dans ma vie.$B$Et mon rapière ! Je me sentais carrément nu sans mon épée.$B$Vous êtes à louer et mérité une récompense pour vos efforts. Ne laissez jamais dire que Sarophas n\'a pas reconnu les petites gens qui l\'ont aidé en chemin !') ON DUPLICATE KEY UPDATE RewardText='Vous êtes un miracle, <name> ! Je vous dis, je n\'ai jamais eu autant soif de changer de vêtements dans ma vie.$B$Et mon rapière ! Je me sentais carrément nu sans mon épée.$B$Vous êtes à louer et mérité une récompense pour vos efforts. Ne laissez jamais dire que Sarophas n\'a pas reconnu les petites gens qui l\'ont aidé en chemin !';

-- Quest 9443 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9443, 'frFR', 'Une fois que tu auras récupéré son « marqueur », nous allons le modifier un peu ; le rendre meilleur.') ON DUPLICATE KEY UPDATE CompletionText='Une fois que tu auras récupéré son « marqueur », nous allons le modifier un peu ; le rendre meilleur.';
-- Quest 9443 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9443, 'frFR', 'La première étape est terminée. Donne-moi le Marque de l\'Éclaireur de Lumière et je le transformerai en quelque chose de plus approprié.$B$BAlors ma vengeance commencera sérieusement, <class>!') ON DUPLICATE KEY UPDATE RewardText='La première étape est terminée. Donne-moi le Marque de l\'Éclaireur de Lumière et je le transformerai en quelque chose de plus approprié.$B$BAlors ma vengeance commencera sérieusement, <class>!';
-- Quest 9446 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9446, 'frFR', 'Tu es censé marcher jusqu\'au Tombeau d\'Uther avec l\'Anachorite Truuen ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es censé marcher jusqu\'au Tombeau d\'Uther avec l\'Anachorite Truuen ?';
-- Quest 9446 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9446, 'frFR', 'L\'Éclaireur de Lumière est apparu devant toi ?  C\'est incroyable !  Et tu as rendu cela possible grâce à ton aide désintéressée à l\'anachorite.$B$BSi la moitié des histoires est vraie, Uther était un grand homme.  Et, comme lui, tu es un vrai héros pour tous les bons habitants d\'Azeroth, <name>!') ON DUPLICATE KEY UPDATE RewardText='L\'Éclaireur de Lumière est apparu devant toi ?  C\'est incroyable !  Et tu as rendu cela possible grâce à ton aide désintéressée à l\'anachorite.$B$BSi la moitié des histoires est vraie, Uther était un grand homme.  Et, comme lui, tu es un vrai héros pour tous les bons habitants d\'Azeroth, <name>!';
-- Quest 9448 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9448, 'frFR', 'Tu fais ce qui est juste, $c. Les Perdus ont tellement souffert déjà. Ils ne devraient pas subir cette indignité davantage.') ON DUPLICATE KEY UPDATE CompletionText='Tu fais ce qui est juste, $c. Les Perdus ont tellement souffert déjà. Ils ne devraient pas subir cette indignité davantage.';
-- Quest 9456 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9456, 'frFR', 'Nous ne pouvons pas risquer que cette contamination se propage. Les rapports que j\'ai entendus proviennent de la Veille de Sang et sont déjà mauvais. Cela doit être arrêté maintenant !') ON DUPLICATE KEY UPDATE CompletionText='Nous ne pouvons pas risquer que cette contamination se propage. Les rapports que j\'ai entendus proviennent de la Veille de Sang et sont déjà mauvais. Cela doit être arrêté maintenant !';
-- Quest 9460 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9460, 'frFR', 'Excellent ! Un objet aussi personnel porte un fort parfum des intrus--assez pour guider Whisper dans leurs rangs...') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Un objet aussi personnel porte un fort parfum des intrus--assez pour guider Whisper dans leurs rangs...';
-- Quest 9462 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9462, 'frFR', 'Juste à temps, $N. J\'espère que tu es prêt à continuer ton entraînement. Cette prochaine tâche sera difficile.') ON DUPLICATE KEY UPDATE RewardText='Juste à temps, $N. J\'espère que tu es prêt à continuer ton entraînement. Cette prochaine tâche sera difficile.';

-- Quest 9465 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9465, 'frFR', 'Vois-tu comment son feu ne s\'éteint jamais ? C\'est l\'œuvre de Hauteur. C\'est un symbole de son arrogance. Le feu est censé consumer ce qu\'il brûle puis mourir lui-même, pour renaître un autre jour.$B$BI vous aiderait à éteindre la torche, mais elle doit rester allumée pour que vous puissiez vous confronter à Hauteur. Nous la laisserons brûler un peu plus longtemps.') ON DUPLICATE KEY UPDATE RewardText='Vois-tu comment son feu ne s\'éteint jamais ? C\'est l\'œuvre de Hauteur. C\'est un symbole de son arrogance. Le feu est censé consumer ce qu\'il brûle puis mourir lui-même, pour renaître un autre jour.$B$BI vous aiderait à éteindre la torche, mais elle doit rester allumée pour que vous puissiez vous confronter à Hauteur. Nous la laisserons brûler un peu plus longtemps.';
-- Quest 9467 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9467, 'frFR', 'Ne me parle plus tant que tu n\'auras pas les cendres de Hauteur.') ON DUPLICATE KEY UPDATE CompletionText='Ne me parle plus tant que tu n\'auras pas les cendres de Hauteur.';
-- Quest 9467 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9467, 'frFR', 'C\'est une leçon précieuse que tu apprends ici aujourd\'hui. C\'est l\'histoire des fins et des nouveaux commencements.$B$BQuand nous avons parlé pour la première fois, je t\'ai dit que le feu n\'était pas seulement la destruction, mais aussi une force renouvelante des éléments. Par tes actions, tu as à la fois détruit et sauvé Hauteur, car il renaîtra de ses cendres.') ON DUPLICATE KEY UPDATE RewardText='C\'est une leçon précieuse que tu apprends ici aujourd\'hui. C\'est l\'histoire des fins et des nouveaux commencements.$B$BQuand nous avons parlé pour la première fois, je t\'ai dit que le feu n\'était pas seulement la destruction, mais aussi une force renouvelante des éléments. Par tes actions, tu as à la fois détruit et sauvé Hauteur, car il renaîtra de ses cendres.';
-- Quest 9468 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9468, 'frFR', 'Tu as l\'air un peu brûlé sur les bords. Comment s\'est déroulée ta communion avec la flamme, $C?') ON DUPLICATE KEY UPDATE CompletionText='Tu as l\'air un peu brûlé sur les bords. Comment s\'est déroulée ta communion avec la flamme, $C?';
-- Quest 9468 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9468, 'frFR', 'Tu as traversé le feu purificateur de la destruction et tu as été renouvelé, $N. Cela ne ressemble pas à la tribulation que le peuple $R est en train de subir. Et en sauvant Hauteur de lui-même, tu as sécurisé ton lien avec le feu élémentaire de ce monde.') ON DUPLICATE KEY UPDATE RewardText='Tu as traversé le feu purificateur de la destruction et tu as été renouvelé, $N. Cela ne ressemble pas à la tribulation que le peuple $R est en train de subir. Et en sauvant Hauteur de lui-même, tu as sécurisé ton lien avec le feu élémentaire de ce monde.';
-- Quest 9470 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9470, 'frFR', 'Es-tu revenu avec des nouvelles de la mort de la Doctrice Sorcière Mai\'jin ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu revenu avec des nouvelles de la mort de la Doctrice Sorcière Mai\'jin ?';
-- Quest 9471 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9471, 'frFR', 'As-tu réduit la population de silvermane ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réduit la population de silvermane ?';
-- Quest 9474 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9474, 'frFR', 'La Marque du Porteur de Lumière est un symbole puissant de la foi d\'Uther en la Lumière.') ON DUPLICATE KEY UPDATE CompletionText='La Marque du Porteur de Lumière est un symbole puissant de la foi d\'Uther en la Lumière.';

-- Quest 9474 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9474, 'frFR', 'Merci, <class>!  La récupération de ce symbole sacré signifie beaucoup pour moi et pour les autres qui honorent la mémoire d\'Uther Lightbringer.') ON DUPLICATE KEY UPDATE RewardText='Merci, <class>!  La récupération de ce symbole sacré signifie beaucoup pour moi et pour les autres qui honorent la mémoire d\'Uther Lightbringer.';
-- Quest 9484 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9484, 'frFR', 'Maîtrisez-vous le faucon-dragon ?') ON DUPLICATE KEY UPDATE CompletionText='Maîtrisez-vous le faucon-dragon ?';
-- Quest 9484 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9484, 'frFR', 'Résister aux nombreuses griffes et morsures du faucon-dragon est un signe de votre ténacité. Avez-vous la force d\'en apprendre davantage ?') ON DUPLICATE KEY UPDATE RewardText='Résister aux nombreuses griffes et morsures du faucon-dragon est un signe de votre ténacité. Avez-vous la force d\'en apprendre davantage ?';
-- Quest 9485 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9485, 'frFR', 'Maîtrisez-vous le bat-brume ?') ON DUPLICATE KEY UPDATE CompletionText='Maîtrisez-vous le bat-brume ?';
-- Quest 9485 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9485, 'frFR', 'Alors vous voyez $N, il ne me reste plus rien à vous enseigner pour le moment. Vous comprenez déjà ce que signifie se lier d\'amitié avec ceux que vous chassiez autrefois. Il ne vous reste plus qu\'à choisir un des alliés de la nature dont les traits correspondent aux vôtres.') ON DUPLICATE KEY UPDATE RewardText='Alors vous voyez $N, il ne me reste plus rien à vous enseigner pour le moment. Vous comprenez déjà ce que signifie se lier d\'amitié avec ceux que vous chassiez autrefois. Il ne vous reste plus qu\'à choisir un des alliés de la nature dont les traits correspondent aux vôtres.';
-- Quest 9486 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9486, 'frFR', 'Avez-vous chassé aux côtés du patte-printemps ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous chassé aux côtés du patte-printemps ?';
-- Quest 9486 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9486, 'frFR', 'Vous avez montré à la fois force et ténacité. Il reste l\'épreuve finale avant que vous puissiez domestiquer sans utiliser de magie.') ON DUPLICATE KEY UPDATE RewardText='Vous avez montré à la fois force et ténacité. Il reste l\'épreuve finale avant que vous puissiez domestiquer sans utiliser de magie.';
-- Quest 9487 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9487, 'frFR', 'Vous n\'êtes pas allé trop près des brutes, j\'espère ?') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'êtes pas allé trop près des brutes, j\'espère ?';

-- Quest 9487 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9487, 'frFR', 'Quel gaspillage, utiliser la magie pour construire des êtres de force physique.  J\'ai toujours pensé que c\'était pour ça que nous nous sommes alliés aux races inférieures, après tout.$B$BVous avez bien fait de les détruire pour que nous puissions utiliser ce qui reste à un but plus approprié.') ON DUPLICATE KEY UPDATE RewardText='Quel gaspillage, utiliser la magie pour construire des êtres de force physique.  J\'ai toujours pensé que c\'était pour ça que nous nous sommes alliés aux races inférieures, après tout.$B$BVous avez bien fait de les détruire pour que nous puissions utiliser ce qui reste à un but plus approprié.';
-- Quest 9488 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9488, 'frFR', 'La robe ne peut être terminée sans les fournitures nécessaires. Mais vous le saviez, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE CompletionText='La robe ne peut être terminée sans les fournitures nécessaires. Mais vous le saviez, n\'est-ce pas ?';
-- Quest 9488 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9488, 'frFR', 'Tu n\'as pas besoin de connaître les subtilités de la confection d\'une robe magique, <name>, tu dois juste savoir ce que tu dois m\'apporter.$B$BEt sois honnête, tu as apporté assez pour plusieurs robes.  Le profit que je vais réaliser devrait couvrir les coûts de fabrication de ta robe, et même assez pour m\'acheter quelque chose de joli.  Il semble que les remerciements t\'appartiennent !') ON DUPLICATE KEY UPDATE RewardText='Tu n\'as pas besoin de connaître les subtilités de la confection d\'une robe magique, <name>, tu dois juste savoir ce que tu dois m\'apporter.$B$BEt sois honnête, tu as apporté assez pour plusieurs robes.  Le profit que je vais réaliser devrait couvrir les coûts de fabrication de ta robe, et même assez pour m\'acheter quelque chose de joli.  Il semble que les remerciements t\'appartiennent !';
-- Quest 9489 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9489, 'frFR', 'As-tu donné de l\'espoir là où il manquait ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu donné de l\'espoir là où il manquait ?';
-- Quest 9489 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9489, 'frFR', 'Les rangers parlent déjà de tes bénédictions avec admiration et respect. Maintenant, tu peux voir comment la Lumière nous sert, nous permettant d\'aider les autres, mais seulement après nous être aidés nous-mêmes.') ON DUPLICATE KEY UPDATE RewardText='Les rangers parlent déjà de tes bénédictions avec admiration et respect. Maintenant, tu peux voir comment la Lumière nous sert, nous permettant d\'aider les autres, mais seulement après nous être aidés nous-mêmes.';
-- Quest 9491 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9491, 'frFR', 'Dis-moi que tu as trouvé l\'anneau. Il ne faudra pas longtemps avant que ce marchand trouve le sien $C.') ON DUPLICATE KEY UPDATE CompletionText='Dis-moi que tu as trouvé l\'anneau. Il ne faudra pas longtemps avant que ce marchand trouve le sien $C.';
-- Quest 9491 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9491, 'frFR', 'C\'est cet anneau, n\'est-ce pas ? Pas grand-chose à voir, mais tu sais ce qu\'on dit des trucs des elfes...$B$BEt n\'oublions pas ton paiement. N\'aie pas peur de le dépenser ici, chérie !') ON DUPLICATE KEY UPDATE RewardText='C\'est cet anneau, n\'est-ce pas ? Pas grand-chose à voir, mais tu sais ce qu\'on dit des trucs des elfes...$B$BEt n\'oublions pas ton paiement. N\'aie pas peur de le dépenser ici, chérie !';
-- Quest 9495 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9495, 'frFR', 'As-tu la preuve de la défaite de Kargath Bladefist ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu la preuve de la défaite de Kargath Bladefist ?';

-- Quest 9496 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9496, 'frFR', 'Une fois que les légionnaires de la Main Brisée auront été vaincus, nous pourrons commencer à progresser dans notre campagne contre la Horde Féline. Avez-vous accompli votre mission, $N?') ON DUPLICATE KEY UPDATE CompletionText='Une fois que les légionnaires de la Main Brisée auront été vaincus, nous pourrons commencer à progresser dans notre campagne contre la Horde Féline. Avez-vous accompli votre mission, $N?';
-- Quest 9500 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9500, 'frFR', 'Nous nous revoyons. J\'ai observé vos progrès de loin, $C, et je suis satisfait.$B$BIl est temps que vous communiez avec l\'élément eau, que vous appreniez ses mystères et que vous vous abandonniez à l\'eau afin que vous puissiez à votre tour apprendre à la maîtriser.') ON DUPLICATE KEY UPDATE RewardText='Nous nous revoyons. J\'ai observé vos progrès de loin, $C, et je suis satisfait.$B$BIl est temps que vous communiez avec l\'élément eau, que vous appreniez ses mystères et que vous vous abandonniez à l\'eau afin que vous puissiez à votre tour apprendre à la maîtriser.';
-- Quest 9502 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9502, 'frFR', 'Nous nous revoyons. J\'ai observé vos progrès de loin, $c, et je suis satisfait.$B$BIl est temps que vous communiez avec l\'élément eau, que vous appreniez ses mystères et que vous vous abandonniez à l\'eau afin que vous puissiez à votre tour apprendre à la maîtriser.') ON DUPLICATE KEY UPDATE RewardText='Nous nous revoyons. J\'ai observé vos progrès de loin, $c, et je suis satisfait.$B$BIl est temps que vous communiez avec l\'élément eau, que vous appreniez ses mystères et que vous vous abandonniez à l\'eau afin que vous puissiez à votre tour apprendre à la maîtriser.';
-- Quest 9503 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9503, 'frFR', 'Avez-vous collecté les essences maudites de mes malheureuses sœurs si tôt, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous collecté les essences maudites de mes malheureuses sœurs si tôt, $N?';
-- Quest 9503 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9503, 'frFR', 'Merci, $c. Cela devrait suffire pour que je puisse examiner cette corruption. Ensuite, nous aurons une meilleure idée de la marche à suivre.') ON DUPLICATE KEY UPDATE RewardText='Merci, $c. Cela devrait suffire pour que je puisse examiner cette corruption. Ensuite, nous aurons une meilleure idée de la marche à suivre.';
-- Quest 9504 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9504, 'frFR', 'Vous avez l\'eau pure des ruines ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez l\'eau pure des ruines ?';
-- Quest 9504 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9504, 'frFR', 'L\'eau se sépare facilement, mais mettez-en assez ensemble et elle créera une force imparable. Elle emporte la terre et le feu, et chasse facilement l\'air.$B$BNous sommes cette force imparable, $N, pas ceux qui ont empoisonné l\'Île Bloodmyst !') ON DUPLICATE KEY UPDATE RewardText='L\'eau se sépare facilement, mais mettez-en assez ensemble et elle créera une force imparable. Elle emporte la terre et le feu, et chasse facilement l\'air.$B$BNous sommes cette force imparable, $N, pas ceux qui ont empoisonné l\'Île Bloodmyst !';
-- Quest 9506 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9506, 'frFR', 'Comment ça se passe, étranger ?') ON DUPLICATE KEY UPDATE CompletionText='Comment ça se passe, étranger ?';

-- Quest 9508 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9508, 'frFR', 'C\'est fait alors ! La crise est écartée et vous avez mis en marche la restauration de l\'eau sur Bloodmyst Isle. Avec le temps, l\'eau, en conjonction avec les autres éléments, se guérira d\'elle-même.$B$BIl est regrettable que les elfes-sang ne puissent voir qu\'en contaminant leur environnement, ils s\'autodétruisent aussi !') ON DUPLICATE KEY UPDATE RewardText='C\'est fait alors ! La crise est écartée et vous avez mis en marche la restauration de l\'eau sur Bloodmyst Isle. Avec le temps, l\'eau, en conjonction avec les autres éléments, se guérira d\'elle-même.$B$BIl est regrettable que les elfes-sang ne puissent voir qu\'en contaminant leur environnement, ils s\'autodétruisent aussi !';
-- Quest 9509 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9509, 'frFR', 'Les éléments m\'ont parlé des grandes actions que vous avez accomplies. Venez, parlons-en.') ON DUPLICATE KEY UPDATE CompletionText='Les éléments m\'ont parlé des grandes actions que vous avez accomplies. Venez, parlons-en.';
-- Quest 9509 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9509, 'frFR', 'Vous vous êtes comporté avec une sagesse au-delà de votre âge, $N. Je peux sentir que l\'élément eau est satisfait de vos actions. Ce sera un grand honneur pour moi de prendre l\'eau pure que vous portez et d\'en combiner l\'essence dans votre nouveau totem d\'eau.$B$BSouvenez-vous bien des leçons de l\'eau en avançant et vous acquerrez une compréhension et une maîtrise encore plus grandes de l\'élément.') ON DUPLICATE KEY UPDATE RewardText='Vous vous êtes comporté avec une sagesse au-delà de votre âge, $N. Je peux sentir que l\'élément eau est satisfait de vos actions. Ce sera un grand honneur pour moi de prendre l\'eau pure que vous portez et d\'en combiner l\'essence dans votre nouveau totem d\'eau.$B$BSouvenez-vous bien des leçons de l\'eau en avançant et vous acquerrez une compréhension et une maîtrise encore plus grandes de l\'élément.';
-- Quest 9513 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9513, 'frFR', 'Vous faites le bien pour mon peuple, $N.') ON DUPLICATE KEY UPDATE CompletionText='Vous faites le bien pour mon peuple, $N.';
-- Quest 9516 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9516, 'frFR', 'Y a-t-il encore des démons debout ?') ON DUPLICATE KEY UPDATE CompletionText='Y a-t-il encore des démons debout ?';
-- Quest 9518 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9518, 'frFR', 'Tant que l\'Overseer Gorthak vit, je m\'y opposerai. Quelles nouvelles du camp des bûcherons ?') ON DUPLICATE KEY UPDATE CompletionText='Tant que l\'Overseer Gorthak vit, je m\'y opposerai. Quelles nouvelles du camp des bûcherons ?';
-- Quest 9521 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9521, 'frFR', 'Qu\'est-ce que tu as là, $C?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que tu as là, $C?';
-- Quest 9521 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9521, 'frFR', 'Merci d\'avoir livré ce rapport, $c. D\'après ce qu\'écrit le Sentinel Luciel, il semble que nos pires craintes se soient réalisées. À chaque avancée que nous faisons, la Horde semble plus déterminée à causer le plus de dégâts possible.$B$BNous ne pouvons pas reculer ; le destin de nos terres ancestrales est en jeu. Avec plus de gens comme vous sur les lignes de front, je suis certain que nous pourrions triompher. Voulez-vous vous joindre à notre combat ?') ON DUPLICATE KEY UPDATE RewardText='Merci d\'avoir livré ce rapport, $c. D\'après ce qu\'écrit le Sentinel Luciel, il semble que nos pires craintes se soient réalisées. À chaque avancée que nous faisons, la Horde semble plus déterminée à causer le plus de dégâts possible.$B$BNous ne pouvons pas reculer ; le destin de nos terres ancestrales est en jeu. Avec plus de gens comme vous sur les lignes de front, je suis certain que nous pourrions triompher. Voulez-vous vous joindre à notre combat ?';

-- Quest 9522 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9522, 'frFR', 'Nos éclaireurs elfes de la nuit rapportent que les préparatifs de l\'attaque sont peut-être toujours en cours. Ces dreadlords doivent mourir bientôt, $N!') ON DUPLICATE KEY UPDATE CompletionText='Nos éclaireurs elfes de la nuit rapportent que les préparatifs de l\'attaque sont peut-être toujours en cours. Ces dreadlords doivent mourir bientôt, $N!';
-- Quest 9526 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9526, 'frFR', 'Vous n\'avez pas encore planté toutes mes graines ?') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas encore planté toutes mes graines ?';
-- Quest 9529 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9529, 'frFR', 'En fixant la pierre, votre vision commence à tourbillonner...') ON DUPLICATE KEY UPDATE RewardText='En fixant la pierre, votre vision commence à tourbillonner...';
-- Quest 9532 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9532, 'frFR', 'J\'espère que vous pouvez voir que je suis bien sous couverture... du moins, je l\'étais.') ON DUPLICATE KEY UPDATE RewardText='J\'espère que vous pouvez voir que je suis bien sous couverture... du moins, je l\'étais.';
-- Quest 9534 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9534, 'frFR', 'N\'y a-t-il pas encore de démons debout ? Vous vous appelez un $r ? Ce n\'est pas le moment de faire une pause dans le combat !') ON DUPLICATE KEY UPDATE CompletionText='N\'y a-t-il pas encore de démons debout ? Vous vous appelez un $r ? Ce n\'est pas le moment de faire une pause dans le combat !';
-- Quest 9536 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9536, 'frFR', 'Ces dreadlords doivent mourir bientôt, $N!') ON DUPLICATE KEY UPDATE CompletionText='Ces dreadlords doivent mourir bientôt, $N!';
-- Quest 9536 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9536, 'frFR', 'La Légion Ardente ne fera plus jamais d\'esclaves des orcs, ou de toute autre race de la Horde !$B$Vous avez combattu bravement, <class>!  Vous avez le vrai cœur de la Horde qui bat en vous !  Vous nous donnez beaucoup d\'honneur !') ON DUPLICATE KEY UPDATE RewardText='La Légion Ardente ne fera plus jamais d\'esclaves des orcs, ou de toute autre race de la Horde !$B$Vous avez combattu bravement, <class>!  Vous avez le vrai cœur de la Horde qui bat en vous !  Vous nous donnez beaucoup d\'honneur !';
-- Quest 9538 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9538, 'frFR', 'Vous pouvez entendre un bourdonnement grave émanant du totem.') ON DUPLICATE KEY UPDATE CompletionText='Vous pouvez entendre un bourdonnement grave émanant du totem.';

-- Quest 9544 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9544, 'frFR', '[Furbolg] Ainsi la prophétie d\'Akida est vraie... Un héros nous a été livré.') ON DUPLICATE KEY UPDATE CompletionText='[Furbolg] Ainsi la prophétie d\'Akida est vraie... Un héros nous a été livré.';
-- Quest 9547 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9547, 'frFR', 'Et enfin nous arrivons à cela, le dernier des quatre grands éléments : l\'air. Vous croyez être assez sage pour continuer, $N?') ON DUPLICATE KEY UPDATE RewardText='Et enfin nous arrivons à cela, le dernier des quatre grands éléments : l\'air. Vous croyez être assez sage pour continuer, $N?';
-- Quest 9551 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9551, 'frFR', 'Et enfin nous arrivons à cela, le dernier des quatre grands éléments : l\'air. Vous croyez être assez sage pour continuer, $N?') ON DUPLICATE KEY UPDATE RewardText='Et enfin nous arrivons à cela, le dernier des quatre grands éléments : l\'air. Vous croyez être assez sage pour continuer, $N?';
-- Quest 9552 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9552, 'frFR', 'On m\'a murmuré dans les vents que vous viendriez, $c.$B$BFarseer Nobundo pense beaucoup de vous, et d\'après ce que j\'ai entendu de vos voyages, moi aussi.') ON DUPLICATE KEY UPDATE RewardText='On m\'a murmuré dans les vents que vous viendriez, $c.$B$BFarseer Nobundo pense beaucoup de vous, et d\'après ce que j\'ai entendu de vos voyages, moi aussi.';
-- Quest 9553 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9553, 'frFR', 'J\'attendais votre arrivée, $c. Vous venez chercher la sagesse, et quelque chose d\'autre je le sens.$B$BTrès bien, commençons.') ON DUPLICATE KEY UPDATE RewardText='J\'attendais votre arrivée, $c. Vous venez chercher la sagesse, et quelque chose d\'autre je le sens.$B$BTrès bien, commençons.';
-- Quest 9554 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9554, 'frFR', 'De retour si vite ? Vos cheveux semblent ébouriffés.$B$B<Nobundo sourit avec connaissance.>') ON DUPLICATE KEY UPDATE CompletionText='De retour si vite ? Vos cheveux semblent ébouriffés.$B$B<Nobundo sourit avec connaissance.>';
-- Quest 9554 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9554, 'frFR', 'Je suis fier de toi, $N. Tu as persévéré là où d\'autres ont faibli, et dans le processus, tu as acquis une plus grande compréhension des éléments et de toi-même. Souviens-toi de leurs leçons en parcourant la vie et tu en seras plus sage.$B$BMaintenant, donne-moi le tourbillon de Susurrus afin que je puisse l\'imprégner dans ton totem d\'air. Comme pour les autres totems, il servira à la fois de focus et de rappel de la connexion que tu as forgée avec les éléments.') ON DUPLICATE KEY UPDATE RewardText='Je suis fier de toi, $N. Tu as persévéré là où d\'autres ont faibli, et dans le processus, tu as acquis une plus grande compréhension des éléments et de toi-même. Souviens-toi de leurs leçons en parcourant la vie et tu en seras plus sage.$B$BMaintenant, donne-moi le tourbillon de Susurrus afin que je puisse l\'imprégner dans ton totem d\'air. Comme pour les autres totems, il servira à la fois de focus et de rappel de la connexion que tu as forgée avec les éléments.';
-- Quest 9582 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9582, 'frFR', '$GRuada hoche la tête solennellement.>$B$BAlors c\'est fait.$B<br :>Tu es prêt pour ta prochaine leçon, <name, mais ce ne sera pas moi qui te l\'enseignerai.') ON DUPLICATE KEY UPDATE RewardText='$GRuada hoche la tête solennellement.>$B$BAlors c\'est fait.$B<br :>Tu es prêt pour ta prochaine leçon, <name, mais ce ne sera pas moi qui te l\'enseignerai.';

-- Quest 9588 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9588, 'frFR', 'Quelle est cette lettre que tu as là, $C?') ON DUPLICATE KEY UPDATE CompletionText='Quelle est cette lettre que tu as là, $C?';
-- Quest 9588 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9588, 'frFR', 'Elle est signée par Illidan, tu dis ?! Donne-la-moi.$B$B$GNazgrel lit la lettre, puis une seconde fois, réfléchissant un instant avant de continuer.>$B$BCette nouvelle que tu apportes est en effet sinistre. Sachant cela, nous devons accélérer nos plans contre la Citadelle de la Flamme de l\'Enfer et ce Fourneau de Sang. Puisque tu as prouvé que tu pouvais faire le travail, je veux que tu dirige ces plans !$B$BCenturion Caza\'rez te donnera ta prochaine mission, bien que je soupçonne qu\'elle sera bien plus meurtrière que ta première.$B<br :>Lok\'tar ogar, <name!') ON DUPLICATE KEY UPDATE RewardText='Elle est signée par Illidan, tu dis ?! Donne-la-moi.$B$B$GNazgrel lit la lettre, puis une seconde fois, réfléchissant un instant avant de continuer.>$B$BCette nouvelle que tu apportes est en effet sinistre. Sachant cela, nous devons accélérer nos plans contre la Citadelle de la Flamme de l\'Enfer et ce Fourneau de Sang. Puisque tu as prouvé que tu pouvais faire le travail, je veux que tu dirige ces plans !$B$BCenturion Caza\'rez te donnera ta prochaine mission, bien que je soupçonne qu\'elle sera bien plus meurtrière que ta première.$B<br :>Lok\'tar ogar, <name!';
-- Quest 9591 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9591, 'frFR', 'As-tu réussi à maîtriser la magie du totem pour devenir ami avec un rampeur barbelé ? Ce sont de petites créatures pleines de vigueur !') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à maîtriser la magie du totem pour devenir ami avec un rampeur barbelé ? Ce sont de petites créatures pleines de vigueur !';
-- Quest 9591 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9591, 'frFR', 'Je suis sûr que la première chose que tu as apprise est à quel point le rampeur était insensible pendant le processus de liaison. C\'est des griffes jusqu\'à ce qu\'ils sachent que tu n\'es pas là pour les jeter dans une marmite bouillante.') ON DUPLICATE KEY UPDATE RewardText='Je suis sûr que la première chose que tu as apprise est à quel point le rampeur était insensible pendant le processus de liaison. C\'est des griffes jusqu\'à ce qu\'ils sachent que tu n\'es pas là pour les jeter dans une marmite bouillante.';
-- Quest 9592 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9592, 'frFR', 'Le marcheur de bois est un oiseau puissant, souvent mal jugé par les prédateurs avec des conséquences désastreuses.') ON DUPLICATE KEY UPDATE CompletionText='Le marcheur de bois est un oiseau puissant, souvent mal jugé par les prédateurs avec des conséquences désastreuses.';
-- Quest 9592 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9592, 'frFR', 'On dirait que le marcheur de bois n\'a pas arraché tes yeux.$B$B<Kella détourne le regard un instant.>$B$BPas comme si je pensais que cela se produirait, bien sûr !') ON DUPLICATE KEY UPDATE RewardText='On dirait que le marcheur de bois n\'a pas arraché tes yeux.$B$B<Kella détourne le regard un instant.>$B$BPas comme si je pensais que cela se produirait, bien sûr !';
-- Quest 9593 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9593, 'frFR', 'Le chasseur nocturne est essentiellement un gros chat avec des griffes acérées et un appétit pour la chair...') ON DUPLICATE KEY UPDATE CompletionText='Le chasseur nocturne est essentiellement un gros chat avec des griffes acérées et un appétit pour la chair...';
-- Quest 9593 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9593, 'frFR', 'Je dois dire, $N, tu as appris beaucoup plus vite que ce que j\'imaginais. On dirait que nous n\'aurons pas besoin d\'utiliser ce dernier totem de dressage. Et honnêtètement, je ne suis même pas sûr de ce que c\'est. Il semble être une sorte de lézard monstrueux avec des ailes et une longue queue. Bon, peut-être une autre fois !$B$BTu as assez d\'expérience pour essayer toi-même maintenant, sans l\'aide d\'un totem de dressage. Bonne chance !') ON DUPLICATE KEY UPDATE RewardText='Je dois dire, $N, tu as appris beaucoup plus vite que ce que j\'imaginais. On dirait que nous n\'aurons pas besoin d\'utiliser ce dernier totem de dressage. Et honnêtètement, je ne suis même pas sûr de ce que c\'est. Il semble être une sorte de lézard monstrueux avec des ailes et une longue queue. Bon, peut-être une autre fois !$B$BTu as assez d\'expérience pour essayer toi-même maintenant, sans l\'aide d\'un totem de dressage. Bonne chance !';

-- Quest 9594 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9594, 'frFR', 'Oui, $C? Qu\'est-ce que tu as là ?') ON DUPLICATE KEY UPDATE CompletionText='Oui, $C? Qu\'est-ce que tu as là ?';
-- Quest 9594 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9594, 'frFR', 'Tu as bien fait de m\'apporter ceci, <name>. Il s\'agit, sans aucun doute, d\'un fragment d\'armure d\'un felguard.$B$BAlors, c\'est comme je le craignais. Les satyres de Nazzivus renouent leurs contacts avec la Légion ardente. Si nous ne les arrêtons pas, les satyres et leurs alliés démoniaques nous submergeront. Je vais prévenir immédiatement le Harbinger Mikolaas.') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait de m\'apporter ceci, <name>. Il s\'agit, sans aucun doute, d\'un fragment d\'armure d\'un felguard.$B$BAlors, c\'est comme je le craignais. Les satyres de Nazzivus renouent leurs contacts avec la Légion ardente. Si nous ne les arrêtons pas, les satyres et leurs alliés démoniaques nous submergeront. Je vais prévenir immédiatement le Harbinger Mikolaas.';
-- Quest 9595 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9595, 'frFR', 'As-tu affronté tes cauchemars ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu affronté tes cauchemars ?';
-- Quest 9595 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9595, 'frFR', 'Avec chaque sort, tu dois te forcer à résister à son appât séduisant, l\'utilisant uniquement si nécessaire pour le bien. Espérons que le spectre t\'ait donné un aperçu de ce que tu pourrais devenir si tu étais imprudent -- un esclave sans esprit de la magie.') ON DUPLICATE KEY UPDATE RewardText='Avec chaque sort, tu dois te forcer à résister à son appât séduisant, l\'utilisant uniquement si nécessaire pour le bien. Espérons que le spectre t\'ait donné un aperçu de ce que tu pourrais devenir si tu étais imprudent -- un esclave sans esprit de la magie.';
-- Quest 9597 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (9597, 'frFR', '<NYI>Hé petiot, fais quelque chose d\'utile et va parler à Jonathan LeCraft.') ON DUPLICATE KEY UPDATE `Details`='<NYI>Hé petiot, fais quelque chose d\'utile et va parler à Jonathan LeCraft.';
-- Quest 9598 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9598, 'frFR', 'Tu as passé du temps à lire le livre, j\'espère?$B$BAlors, tu devrais être prêt à être testé. Il y a toujours des tâches à accomplir après le crash de l\'Exodar dans ces nouvelles terres : des actes de compassion et de compréhension... des gens qui ont besoin d\'aide... des créatures à abattre...$B$BEn prouvant que tu as la patience d\'aider les autres, surtout ceux qui sont moins fortunés, tu prouves que tu es un serviteur de la Lumière et de l\'esprit sain.') ON DUPLICATE KEY UPDATE RewardText='Tu as passé du temps à lire le livre, j\'espère?$B$BAlors, tu devrais être prêt à être testé. Il y a toujours des tâches à accomplir après le crash de l\'Exodar dans ces nouvelles terres : des actes de compassion et de compréhension... des gens qui ont besoin d\'aide... des créatures à abattre...$B$BEn prouvant que tu as la patience d\'aider les autres, surtout ceux qui sont moins fortunés, tu prouves que tu es un serviteur de la Lumière et de l\'esprit sain.';
-- Quest 9599 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9599, 'frFR', 'Merci $N! Je suis heureux que le Chaman Furbolg Jeune soit en paix.$B$BTu es vraiment béni par la Lumière! Par conséquent, tu dois l\'utiliser pour ramener la lumière en chacun!') ON DUPLICATE KEY UPDATE RewardText='Merci $N! Je suis heureux que le Chaman Furbolg Jeune soit en paix.$B$BTu es vraiment béni par la Lumière! Par conséquent, tu dois l\'utiliser pour ramener la lumière en chacun!';
-- Quest 9600 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9600, 'frFR', 'Toute vie vaut la peine d\'être sauvée, si elle ne s\'oppose pas à nous. Seuls nos ennemis doivent être mis au repos définitivement.') ON DUPLICATE KEY UPDATE CompletionText='Toute vie vaut la peine d\'être sauvée, si elle ne s\'oppose pas à nous. Seuls nos ennemis doivent être mis au repos définitivement.';

-- Quest 9600 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9600, 'frFR', 'Ne troublez pas l\'étonnement de ceux que vous avez aidés. Il est courant que ceux qui reviennent récemment au monde des vivants éprouvent de la désorientation, mais imaginez le choc de rencontrer un être étrange en même temps.$B$BLe jeune chaman est béni d\'avoir survécu à une leçon aussi rude grâce à vous, et il vous revient de pouvoir invoquer ce pouvoir comme vous l\'entendez.') ON DUPLICATE KEY UPDATE RewardText='Ne troublez pas l\'étonnement de ceux que vous avez aidés. Il est courant que ceux qui reviennent récemment au monde des vivants éprouvent de la désorientation, mais imaginez le choc de rencontrer un être étrange en même temps.$B$BLe jeune chaman est béni d\'avoir survécu à une leçon aussi rude grâce à vous, et il vous revient de pouvoir invoquer ce pouvoir comme vous l\'entendez.';
-- Quest 9605 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9605, 'frFR', 'Alors, vous retournez à Azure Watch avec ce paquet ? Aucun problème, <class>. Parlez-m\'en à nouveau et nous vous aiderons avec ces fournitures.') ON DUPLICATE KEY UPDATE RewardText='Alors, vous retournez à Azure Watch avec ce paquet ? Aucun problème, <class>. Parlez-m\'en à nouveau et nous vous aiderons avec ces fournitures.';
-- Quest 9608 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9608, 'frFR', 'Avez-vous exploré toute la Fonderie de Sang ? Qu\'avez-vous à me dire ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous exploré toute la Fonderie de Sang ? Qu\'avez-vous à me dire ?';
-- Quest 9609 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9609, 'frFR', 'Quoi ? Un draenei vous a envoyé d\'ici du Sanctuaire ? Quelle drôlerie.$B$BEh bien, je ne suis pas du genre à refuser une aide. Merci d\'être venu, $c!') ON DUPLICATE KEY UPDATE RewardText='Quoi ? Un draenei vous a envoyé d\'ici du Sanctuaire ? Quelle drôlerie.$B$BEh bien, je ne suis pas du genre à refuser une aide. Merci d\'être venu, $c!';
-- Quest 9612 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9612, 'frFR', 'Bien joué, <name>. Bien joué en effet ! Vous vous révélez être un $R - un cran au-dessus des autres de votre âge. Prenez ceci comme récompense !') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name>. Bien joué en effet ! Vous vous révélez être un $R - un cran au-dessus des autres de votre âge. Prenez ceci comme récompense !';
-- Quest 9617 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9617, 'frFR', '<name>, c\'est bien que vous soyez venu.  Notre liste d\'alliés se raréfie, et même ceux qui partagent notre cause ne sont pas entièrement d\'une confiance absolue.  C\'est pourquoi nous, les rangers, nous tournons vers la nature pour obtenir de l\'aide.$B$BParmi les alliés de la forêt, nous trouvons un lien profond qui ne connaît pas la tromperie.') ON DUPLICATE KEY UPDATE RewardText='<name>, c\'est bien que vous soyez venu.  Notre liste d\'alliés se raréfie, et même ceux qui partagent notre cause ne sont pas entièrement d\'une confiance absolue.  C\'est pourquoi nous, les rangers, nous tournons vers la nature pour obtenir de l\'aide.$B$BParmi les alliés de la forêt, nous trouvons un lien profond qui ne connaît pas la tromperie.';
-- Quest 9618 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9618, 'frFR', 'Avez-vous réussi à localiser Keltus ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à localiser Keltus ?';
-- Quest 9618 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9618, 'frFR', 'Tous ces rapports viennent de Keltus ? Il a été très occupé, c\'est certain.$B$BKeltus est un $c parmi les voleurs -- il suit rarement les ordres à la lettre, et prend souvent les choses en main ! Ne le prenez pas mal, cependant, car il est l\'un de mes espions les plus fiables et nous serions perdus sans lui.$B$BVous avez fait un travail exemplaire aujourd\'hui. Veuillez accepter cette lame et guidez-la dans le dos de notre ennemi.') ON DUPLICATE KEY UPDATE RewardText='Tous ces rapports viennent de Keltus ? Il a été très occupé, c\'est certain.$B$BKeltus est un $c parmi les voleurs -- il suit rarement les ordres à la lettre, et prend souvent les choses en main ! Ne le prenez pas mal, cependant, car il est l\'un de mes espions les plus fiables et nous serions perdus sans lui.$B$BVous avez fait un travail exemplaire aujourd\'hui. Veuillez accepter cette lame et guidez-la dans le dos de notre ennemi.';

-- Quest 9619 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9619, 'frFR', 'As-tu suivi le chemin révélé par la pierre du vide ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu suivi le chemin révélé par la pierre du vide ?';
-- Quest 9619 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9619, 'frFR', 'Je suis impressionné que tu sois là, <name>.  De nombreux apprentis ont péri au passage du marcheur du vide, ou même de la pierre du vide elle-même.$B$BLe marcheur du vide t\'appartient maintenant.  Utilise bien ton nouveau serviteur.') ON DUPLICATE KEY UPDATE RewardText='Je suis impressionné que tu sois là, <name>.  De nombreux apprentis ont péri au passage du marcheur du vide, ou même de la pierre du vide elle-même.$B$BLe marcheur du vide t\'appartient maintenant.  Utilise bien ton nouveau serviteur.';
-- Quest 9626 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9626, 'frFR', 'Tu es venu me voir, $r? Parle et sois bref. Je n\'ai pas le temps pour les formalités de ta race.') ON DUPLICATE KEY UPDATE CompletionText='Tu es venu me voir, $r? Parle et sois bref. Je n\'ai pas le temps pour les formalités de ta race.';
-- Quest 9626 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9626, 'frFR', '<Le chef de guerre commence à lire la lettre.>$B$BSylvanas est tenace.  Alors elle a envoyé l\'un des champions de Silvermoon... comment cela change-t-il quelque chose ?') ON DUPLICATE KEY UPDATE RewardText='<Le chef de guerre commence à lire la lettre.>$B$BSylvanas est tenace.  Alors elle a envoyé l\'un des champions de Silvermoon... comment cela change-t-il quelque chose ?';
-- Quest 9635 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9635, 'frFR', 'Tu as ces pièces ? J\'ai des choses à faire.') ON DUPLICATE KEY UPDATE CompletionText='Tu as ces pièces ? J\'ai des choses à faire.';
-- Quest 9637 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9637, 'frFR', 'As-tu obtenu les tomes que je recherche, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu les tomes que je recherche, $N?';
-- Quest 9637 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9637, 'frFR', 'Excellent, <name>.  J\'essaie d\'obtenir ces livres depuis très longtemps.  Il est fortuné que nous ayons pu nous être mutuellement utiles.') ON DUPLICATE KEY UPDATE RewardText='Excellent, <name>.  J\'essaie d\'obtenir ces livres depuis très longtemps.  Il est fortuné que nous ayons pu nous être mutuellement utiles.';
-- Quest 9642 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9642, 'frFR', 'Si tu as plus de fragments de cristal irradié, je serais heureux d\'échanger contre un autre de mes cristaux.') ON DUPLICATE KEY UPDATE CompletionText='Si tu as plus de fragments de cristal irradié, je serais heureux d\'échanger contre un autre de mes cristaux.';

-- Quest 9644 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9644, 'frFR', 'C\'est stupéfiant !  Non seulement vous avez ramené le Journal de Medivh, mais vous avez également récupéré un fragment de son essence même.$B$BAussi faible soit cette essence persistante, elle nous révélera des informations vitales sur Medivh.  Nous n\'oublierons pas cela, <class>.') ON DUPLICATE KEY UPDATE RewardText='C\'est stupéfiant !  Non seulement vous avez ramené le Journal de Medivh, mais vous avez également récupéré un fragment de son essence même.$B$BAussi faible soit cette essence persistante, elle nous révélera des informations vitales sur Medivh.  Nous n\'oublierons pas cela, <class>.';
-- Quest 9664 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9664, 'frFR', 'Lorsque les tours seront sous notre contrôle, nous serons bientôt en mesure d\'encercler les Désespérés. Après cela, il n\'y a plus qu\'une question de temps avant que nous puissions les écraser.') ON DUPLICATE KEY UPDATE CompletionText='Lorsque les tours seront sous notre contrôle, nous serons bientôt en mesure d\'encercler les Désespérés. Après cela, il n\'y a plus qu\'une question de temps avant que nous puissions les écraser.';
-- Quest 9665 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9665, 'frFR', 'Ils doivent être des fous de penser que nous leur permettrions d\'établir des bases si près de l\'une de nos capitales.$B$BNous saignerons leurs effectifs jusqu\'à ce qu\'ils battent en retraite vers le sud.') ON DUPLICATE KEY UPDATE CompletionText='Ils doivent être des fous de penser que nous leur permettrions d\'établir des bases si près de l\'une de nos capitales.$B$BNous saignerons leurs effectifs jusqu\'à ce qu\'ils battent en retraite vers le sud.';
-- Quest 9667 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9667, 'frFR', 'Je n\'ai pas beaucoup plus de temps, $N. Ils vont me tuer bientôt...') ON DUPLICATE KEY UPDATE CompletionText='Je n\'ai pas beaucoup plus de temps, $N. Ils vont me tuer bientôt...';
-- Quest 9671 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9671, 'frFR', 'Es-tu $N$? Il était temps ! J\'allais presque abandonner de te trouver !$B$BIl y a un message urgent qui t\'attend à la boîte aux lettres. La personne qui me l\'a donné était un amiral humain d\'Azuremyst. Amiral Odesy-quelque chose... le nom m\'échappe. Il a dit que tu saurais qui c\'était.$B$B<Hermesius hausse les épaules.>') ON DUPLICATE KEY UPDATE RewardText='Es-tu $N$? Il était temps ! J\'allais presque abandonner de te trouver !$B$BIl y a un message urgent qui t\'attend à la boîte aux lettres. La personne qui me l\'a donné était un amiral humain d\'Azuremyst. Amiral Odesy-quelque chose... le nom m\'échappe. Il a dit que tu saurais qui c\'était.$B$B<Hermesius hausse les épaules.>';
-- Quest 9673 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9673, 'frFR', 'Alors tu as appris un peu, n\'est-ce pas?$B$B<Halthenis vous regarde attentivement.>$B$BTu serviras la ville, et notre cause plus grande, bien avec tes compétences nouvellement acquises. Permets-moi un instant pour te montrer comment entraîner ton animal de compagnie à faire des tours intéressantes, comme éviscérer ton ennemi, et tu pourras partir.') ON DUPLICATE KEY UPDATE RewardText='Alors tu as appris un peu, n\'est-ce pas?$B$B<Halthenis vous regarde attentivement.>$B$BTu serviras la ville, et notre cause plus grande, bien avec tes compétences nouvellement acquises. Permets-moi un instant pour te montrer comment entraîner ton animal de compagnie à faire des tours intéressantes, comme éviscérer ton ennemi, et tu pourras partir.';
-- Quest 9675 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9675, 'frFR', 'Savoir nourrir et ressusciter ton animal de compagnie de la mort n\'est pas juste une "petite friandise" comme votre dernier maître l\'a si modestement dit. Encore plus, l\'entraînement permet à ton animal de compagnie de s\'améliorer d\'une manière qu\'il n\'aurait pas pu faire par lui-même.$B$J\'ai déjà beaucoup appris des furbolgs, alors fais attention et je te transmettrai les connaissances.') ON DUPLICATE KEY UPDATE RewardText='Savoir nourrir et ressusciter ton animal de compagnie de la mort n\'est pas juste une "petite friandise" comme votre dernier maître l\'a si modestement dit. Encore plus, l\'entraînement permet à ton animal de compagnie de s\'améliorer d\'une manière qu\'il n\'aurait pas pu faire par lui-même.$B$J\'ai déjà beaucoup appris des furbolgs, alors fais attention et je te transmettrai les connaissances.';
-- Quest 9676 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9676, 'frFR', 'Je vois la fierté gonfler dans ta poitrine. Tu t\'imagines déjà comme l\'un des Chevaliers de Sang.$B$BAvec le temps, tu gagneras ta place parmi nous. Mais d\'abord, tu dois apprendre à maîtriser et à dominer les pouvoirs de la Lumière, affûter tes compétences au combat et prouver ta dignité.$B$BTu dois être prêt à endurer le dérision, la peur et la répulsion de ceux dont tu jures de défendre. C\'est donc parmi ceux qui ne peuvent comprendre le prix du grand pouvoir qui les sauvegarde. Garde la tête haute et ton épée prête, $N$.') ON DUPLICATE KEY UPDATE RewardText='Je vois la fierté gonfler dans ta poitrine. Tu t\'imagines déjà comme l\'un des Chevaliers de Sang.$B$BAvec le temps, tu gagneras ta place parmi nous. Mais d\'abord, tu dois apprendre à maîtriser et à dominer les pouvoirs de la Lumière, affûter tes compétences au combat et prouver ta dignité.$B$BTu dois être prêt à endurer le dérision, la peur et la répulsion de ceux dont tu jures de défendre. C\'est donc parmi ceux qui ne peuvent comprendre le prix du grand pouvoir qui les sauvegarde. Garde la tête haute et ton épée prête, $N$.';

-- Quest 9677 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9677, 'frFR', 'Bienvenue, jeune initié. Le fait que vous ayez répondu à mon appel si promptement est un bon présage pour vous.$B$BMettons de côté les banalités, car elles sont mieux laissées aux courtisans et à leur espèce.$B$BVotre progrès rapide a attiré mon attention, $N$. Nous verrons si vous avez pris vos leçons à cœur.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue, jeune initié. Le fait que vous ayez répondu à mon appel si promptement est un bon présage pour vous.$B$BMettons de côté les banalités, car elles sont mieux laissées aux courtisans et à leur espèce.$B$BVotre progrès rapide a attiré mon attention, $N$. Nous verrons si vous avez pris vos leçons à cœur.';
-- Quest 9678 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9678, 'frFR', 'Que la Lumière se plie à votre volonté dans toutes vos entreprises.') ON DUPLICATE KEY UPDATE CompletionText='Que la Lumière se plie à votre volonté dans toutes vos entreprises.';
-- Quest 9678 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9678, 'frFR', 'Je sais ce qui doit vous traverser l\'esprit.$B$BOui, j\'ai envoyé Stillblade pour vous tuer.$B$BNe prenez pas offense, $N$; c\'était un test nécessaire. Les Chevaliers de Sang sont une fraternité, mais nous devons nous assurer que nos frères sont alertes et préparés en tout temps. Était-il nécessaire de prendre la vie de Stillblade pour vous faire passer le message?$B$BOui, et cela fait partie de votre entraînement autant qu\'un exercice d\'escrime.') ON DUPLICATE KEY UPDATE RewardText='Je sais ce qui doit vous traverser l\'esprit.$B$BOui, j\'ai envoyé Stillblade pour vous tuer.$B$BNe prenez pas offense, $N$; c\'était un test nécessaire. Les Chevaliers de Sang sont une fraternité, mais nous devons nous assurer que nos frères sont alertes et préparés en tout temps. Était-il nécessaire de prendre la vie de Stillblade pour vous faire passer le message?$B$BOui, et cela fait partie de votre entraînement autant qu\'un exercice d\'escrime.';
-- Quest 9680 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9680, 'frFR', 'Avez-vous récupéré le fragment d\'os dont j\'ai besoin, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous récupéré le fragment d\'os dont j\'ai besoin, $N$?';
-- Quest 9680 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9680, 'frFR', 'Excellent!  Bien que petit, ce fragment est rempli d\'énergie, je le sens!') ON DUPLICATE KEY UPDATE RewardText='Excellent!  Bien que petit, ce fragment est rempli d\'énergie, je le sens!';
-- Quest 9681 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9681, 'frFR', 'Bienvenue, jeune $c.$B$BLe pouvoir des Chevaliers de Sang provient d\'un être d\'une puissance immense.$B$B<Le magister fait signe vers le grand être captif au centre de la pièce.>$B$BN\'est-ce pas magnifique? C\'était un cadeau de notre cher Prince Kael\'thas, et c\'est le fondement de la maîtrise de la Lumière des Chevaliers de Sang. Cette créature nous envie son pouvoir, nous avons donc conçu une méthode pour l\'obtenir à nos propres conditions.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue, jeune $c.$B$BLe pouvoir des Chevaliers de Sang provient d\'un être d\'une puissance immense.$B$B<Le magister fait signe vers le grand être captif au centre de la pièce.>$B$BN\'est-ce pas magnifique? C\'était un cadeau de notre cher Prince Kael\'thas, et c\'est le fondement de la maîtrise de la Lumière des Chevaliers de Sang. Cette créature nous envie son pouvoir, nous avons donc conçu une méthode pour l\'obtenir à nos propres conditions.';
-- Quest 9684 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9684, 'frFR', 'Avez-vous parlé avec Magister Astalor Bloodsworn?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous parlé avec Magister Astalor Bloodsworn?';
-- Quest 9684 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9684, 'frFR', 'Bien fait, $N$. Les pouvoirs accordés par la Lumière ne viendront jamais \'naturellement\' aux Chevaliers de Sang, mais nous ne sommes pas si naïfs pour être déjoués par la volonté d\'un seul être, aussi puissant soit-il.$B$BNotre maîtrise de l\'arcane a ouvert ce chemin et ces pouvoirs pour vous, initié. Peu ont le cran ou l\'aptitude pour les manier, mais je sais que vous ne décevrez pas l\'Ordre.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, $N$. Les pouvoirs accordés par la Lumière ne viendront jamais \'naturellement\' aux Chevaliers de Sang, mais nous ne sommes pas si naïfs pour être déjoués par la volonté d\'un seul être, aussi puissant soit-il.$B$BNotre maîtrise de l\'arcane a ouvert ce chemin et ces pouvoirs pour vous, initié. Peu ont le cran ou l\'aptitude pour les manier, mais je sais que vous ne décevrez pas l\'Ordre.';

-- Quest 9685 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9685, 'frFR', 'Bienvenue à nouveau, initié. Maintenant que vous connaissez la vérité sur la source de notre pouvoir et que vous avez démontré votre habileté à l\'utiliser, je vous accorderai la capacité de ressusciter les tombés sur le champ de bataille.$B$BRestez fidèle à l\'ordre et excellez dans votre entraînement et vous continuerez à grandir en puissance.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue à nouveau, initié. Maintenant que vous connaissez la vérité sur la source de notre pouvoir et que vous avez démontré votre habileté à l\'utiliser, je vous accorderai la capacité de ressusciter les tombés sur le champ de bataille.$B$BRestez fidèle à l\'ordre et excellez dans votre entraînement et vous continuerez à grandir en puissance.';
-- Quest 9686 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9686, 'frFR', 'Un Chevalier de Sang préférerait mourir plutôt que de se soumettre à l\'ennemi. Souviens-toi de cela, $N.') ON DUPLICATE KEY UPDATE CompletionText='Un Chevalier de Sang préférerait mourir plutôt que de se soumettre à l\'ennemi. Souviens-toi de cela, $N.';
-- Quest 9686 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9686, 'frFR', 'Bien joué, $N! Vous vous êtes prouvé digne d\'un membre à part entière des Chevaliers de Sang et d\'une élévation au statut d\'adept. Cependant, il reste quelques tâches avant que votre induction puisse avoir lieu.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N! Vous vous êtes prouvé digne d\'un membre à part entière des Chevaliers de Sang et d\'une élévation au statut d\'adept. Cependant, il reste quelques tâches avant que votre induction puisse avoir lieu.';
-- Quest 9688 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9688, 'frFR', 'Cela me peine de regarder. S\'il vous plaît, ne parlons plus de cela.') ON DUPLICATE KEY UPDATE CompletionText='Cela me peine de regarder. S\'il vous plaît, ne parlons plus de cela.';
-- Quest 9689 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9689, 'frFR', 'Je vous recommande d\'apporter des alliés, $N.') ON DUPLICATE KEY UPDATE CompletionText='Je vous recommande d\'apporter des alliés, $N.';
-- Quest 9692 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9692, 'frFR', 'Avez-vous fait tout ce qui vous a été demandé ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous fait tout ce qui vous a été demandé ?';
-- Quest 9692 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9692, 'frFR', 'Excellent, $N. Tout est ici. Il ne reste plus qu\'à forger l\'arme.') ON DUPLICATE KEY UPDATE RewardText='Excellent, $N. Tout est ici. Il ne reste plus qu\'à forger l\'arme.';
-- Quest 9700 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9700, 'frFR', 'J\'ai entendu des rapports de créatures étranges apparaissant dans la zone. Que ce soient des animaux indigènes mutés ou de véritables anomalies du vide est quelque chose que vous devez découvrir.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai entendu des rapports de créatures étranges apparaissant dans la zone. Que ce soient des animaux indigènes mutés ou de véritables anomalies du vide est quelque chose que vous devez découvrir.';

-- Quest 9701 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9701, 'frFR', 'De retour si vite ? Votre observation des spores de Sporeggar est essentielle à mes recherches. J\'espère que vous n\'êtes pas du genre à précipiter les choses. Faites preuve de patience et assurez-vous d\'avoir exploré la totalité du Spawning Glen avant de me donner votre rapport final.') ON DUPLICATE KEY UPDATE CompletionText='De retour si vite ? Votre observation des spores de Sporeggar est essentielle à mes recherches. J\'espère que vous n\'êtes pas du genre à précipiter les choses. Faites preuve de patience et assurez-vous d\'avoir exploré la totalité du Spawning Glen avant de me donner votre rapport final.';
-- Quest 9706 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9706, 'frFR', 'Qu\'est-ce que tu as là, $N ? Est-ce un journal ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que tu as là, $N ? Est-ce un journal ?';
-- Quest 9707 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9707, 'frFR', 'Félicitations, $N. Atteindre le rang d\'adept n\'est pas rien, croyez-moi. J\'ai vu le nombre de personnes qui entrent dans ce bâtiment, et combien d\'entre elles durent assez longtemps pour me rendre avec ces matériaux.') ON DUPLICATE KEY UPDATE CompletionText='Félicitations, $N. Atteindre le rang d\'adept n\'est pas rien, croyez-moi. J\'ai vu le nombre de personnes qui entrent dans ce bâtiment, et combien d\'entre elles durent assez longtemps pour me rendre avec ces matériaux.';
-- Quest 9707 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9707, 'frFR', 'On dirait que vous avez tout ce dont j\'aurai besoin. Commençons !') ON DUPLICATE KEY UPDATE RewardText='On dirait que vous avez tout ce dont j\'aurai besoin. Commençons !';
-- Quest 9709 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9709, 'frFR', 'Vous avez tous les champignons dont nous avons besoin pour créer un nouveau jardin pour les seigneurs de la tourbière ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez tous les champignons dont nous avons besoin pour créer un nouveau jardin pour les seigneurs de la tourbière ?';
-- Quest 9709 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9709, 'frFR', 'Ceux-ci sont parfaits !  Oh, merci, <class>!$B$BVous avez été si soigneux de ne pas perturber l\'ordre naturel des choses, et nous avons recueilli tellement d\'informations en si peu de temps !$B$BMaintenant, voyons si notre petit plan pour cultiver une nouvelle source de nourriture pour les seigneurs de la tourbière va fonctionner.') ON DUPLICATE KEY UPDATE RewardText='Ceux-ci sont parfaits !  Oh, merci, <class>!$B$BVous avez été si soigneux de ne pas perturber l\'ordre naturel des choses, et nous avons recueilli tellement d\'informations en si peu de temps !$B$BMaintenant, voyons si notre petit plan pour cultiver une nouvelle source de nourriture pour les seigneurs de la tourbière va fonctionner.';
-- Quest 9710 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9710, 'frFR', 'Voici, $N. Utilisez-le bien au service de Silvermoon et de votre ordre.') ON DUPLICATE KEY UPDATE RewardText='Voici, $N. Utilisez-le bien au service de Silvermoon et de votre ordre.';
-- Quest 9714 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9714, 'frFR', 'Nous pouvons encore utiliser plus d\'hibiscus sanguin des shamblers, des géants de la tourbière et des chauves-souris des profondeurs du Coilfang Reservoir. Apportez-les-moi par bouquets de cinq et je vous en serai très reconnaissant.') ON DUPLICATE KEY UPDATE CompletionText='Nous pouvons encore utiliser plus d\'hibiscus sanguin des shamblers, des géants de la tourbière et des chauves-souris des profondeurs du Coilfang Reservoir. Apportez-les-moi par bouquets de cinq et je vous en serai très reconnaissant.';

-- Quest 9721 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9721, 'frFR', 'Nous discuterons bientôt du but de votre visite. Tout d\'abord, je dois dire que je suis sincèrement impressionné par votre service et votre talent à manier la Lumière.') ON DUPLICATE KEY UPDATE RewardText='Nous discuterons bientôt du but de votre visite. Tout d\'abord, je dois dire que je suis sincèrement impressionné par votre service et votre talent à manier la Lumière.';
-- Quest 9722 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9722, 'frFR', 'Le fait que vous ayez choisi d\'accepter mon offre en dit beaucoup de vous, $N$. Je vous souhaite bonne chance dans les tâches que je vais vous confier, mais je suis certain que vous vous prouverez plus que capable.$B$BI présenterai les tâches dans l\'ordre du plus facile au plus difficile et nous pourrons commencer lorsque vous serez prêt.') ON DUPLICATE KEY UPDATE RewardText='Le fait que vous ayez choisi d\'accepter mon offre en dit beaucoup de vous, $N$. Je vous souhaite bonne chance dans les tâches que je vais vous confier, mais je suis certain que vous vous prouverez plus que capable.$B$BI présenterai les tâches dans l\'ordre du plus facile au plus difficile et nous pourrons commencer lorsque vous serez prêt.';
-- Quest 9723 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9723, 'frFR', 'Avez-vous ramené les matériaux dont Magister Astalor a besoin ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous ramené les matériaux dont Magister Astalor a besoin ?';
-- Quest 9723 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9723, 'frFR', 'Excellent. Il semble que tout soit ici.$B$BNe vous inquiétez pas. Votre prochaine tâche comprendra de nombreuses occasions de manier à nouveau votre arme, je vous le promets.$B$BI ferai venir un initié pour tout remettre à Magister Astalor. Il n\'y a pas besoin de vous envoyer en mission aussi triviale quand il y a des choses plus importantes à faire.') ON DUPLICATE KEY UPDATE RewardText='Excellent. Il semble que tout soit ici.$B$BNe vous inquiétez pas. Votre prochaine tâche comprendra de nombreuses occasions de manier à nouveau votre arme, je vous le promets.$B$BI ferai venir un initié pour tout remettre à Magister Astalor. Il n\'y a pas besoin de vous envoyer en mission aussi triviale quand il y a des choses plus importantes à faire.';
-- Quest 9725 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9725, 'frFR', 'Bienvenue de retour, $N$. Avez-vous repoussé la Horde et ses charrettes de chair ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue de retour, $N$. Avez-vous repoussé la Horde et ses charrettes de chair ?';
-- Quest 9725 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9725, 'frFR', 'Vous avez bien fait de démontrer votre loyauté envers votre patrie et votre dévouement aux besoins de l\'ordre, $N$. J\'ai une dernière tâche pour vous avant que vous puissiez prétendre au titre de maître.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait de démontrer votre loyauté envers votre patrie et votre dévouement aux besoins de l\'ordre, $N$. J\'ai une dernière tâche pour vous avant que vous puissiez prétendre au titre de maître.';
-- Quest 9726 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9726, 'frFR', 'Avez-vous déjà rendu visite aux naga ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous déjà rendu visite aux naga ?';
-- Quest 9727 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9727, 'frFR', 'Avez-vous déjà rendu visite aux naga ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous déjà rendu visite aux naga ?';

-- Quest 9729 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9729, 'frFR', 'Fwhoor va bien ? As-tu récupéré l\'arche ?') ON DUPLICATE KEY UPDATE CompletionText='Fwhoor va bien ? As-tu récupéré l\'arche ?';
-- Quest 9730 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9730, 'frFR', 'Tu veux parler de la prime pour Haghazed ? Eh bien, est-il mort ? Il n\'y a pas grand-chose d\'autre à dire !') ON DUPLICATE KEY UPDATE CompletionText='Tu veux parler de la prime pour Haghazed ? Eh bien, est-il mort ? Il n\'y a pas grand-chose d\'autre à dire !';
-- Quest 9735 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9735, 'frFR', 'As-tu réussi à obtenir l\'eau ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à obtenir l\'eau ?';
-- Quest 9735 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9735, 'frFR', 'Hmm... c\'est une quantité assez faible. mais si nous faisons attention. cela devrait suffire. Tu vois. La Croisade Écarlate se croit dédiée à la Lumière. Je suppose qu\'ils le sont toujours, d\'une manière tordue, et c\'est exactement ce que j\'espère exploiter.$B$BLeur zèle malavisé a même souillé la bénédiction prononcée sur cette eau, la rendant idéale pour mon dessein.') ON DUPLICATE KEY UPDATE RewardText='Hmm... c\'est une quantité assez faible. mais si nous faisons attention. cela devrait suffire. Tu vois. La Croisade Écarlate se croit dédiée à la Lumière. Je suppose qu\'ils le sont toujours, d\'une manière tordue, et c\'est exactement ce que j\'espère exploiter.$B$BLeur zèle malavisé a même souillé la bénédiction prononcée sur cette eau, la rendant idéale pour mon dessein.';
-- Quest 9736 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9736, 'frFR', 'As-tu rassemblé les réactifs dont j\'aurai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu rassemblé les réactifs dont j\'aurai besoin ?';
-- Quest 9736 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9736, 'frFR', 'Maintenant que nous avons tous les réactifs, je peux préparer le mélange.$B$B<Un lent sourire se dessine sur le visage de Lady Liadrin.>$B$BTout s\'assemble parfaitement, $N. Une fois ceci terminé, je te donnerai les détails sur ce qui reste à faire.') ON DUPLICATE KEY UPDATE RewardText='Maintenant que nous avons tous les réactifs, je peux préparer le mélange.$B$B<Un lent sourire se dessine sur le visage de Lady Liadrin.>$B$BTout s\'assemble parfaitement, $N. Une fois ceci terminé, je te donnerai les détails sur ce qui reste à faire.';
-- Quest 9737 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9737, 'frFR', 'As-tu fait ce que je t\'ai demandé et livré mon message ? Les faux paladins du monde doivent sûrement savoir que leur temps est arrivé à son terme.') ON DUPLICATE KEY UPDATE CompletionText='As-tu fait ce que je t\'ai demandé et livré mon message ? Les faux paladins du monde doivent sûrement savoir que leur temps est arrivé à son terme.';
-- Quest 9737 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9737, 'frFR', 'Bien fait, $N. Tous ceux qui s\'opposeraient à nous feraient bien d\'écouter l\'avertissement que tu as délivré. Nos ennemis devraient savoir qu\'ils sont en péril, du plus petit soldat au plus puissant $Ghero:heroine;.$B$BTu as mérité ta place dans les rangs des maîtres. Ton dévouement et ta prouesse servent d\'exemple pour tous les Chevaliers de Sang. En symbole de ton nouveau statut, je t\'accorde la capacité d\'invoquer et de commander le charger thalassien.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, $N. Tous ceux qui s\'opposeraient à nous feraient bien d\'écouter l\'avertissement que tu as délivré. Nos ennemis devraient savoir qu\'ils sont en péril, du plus petit soldat au plus puissant $Ghero:heroine;.$B$BTu as mérité ta place dans les rangs des maîtres. Ton dévouement et ta prouesse servent d\'exemple pour tous les Chevaliers de Sang. En symbole de ton nouveau statut, je t\'accorde la capacité d\'invoquer et de commander le charger thalassien.';

-- Quest 9738 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9738, 'frFR', 'Avez-vous découvert l\'emplacement de mes quatre compagnons ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous découvert l\'emplacement de mes quatre compagnons ?';
-- Quest 9740 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9740, 'frFR', 'Vous devez éliminer leurs contrôleurs de portail avant de pouvoir détruire la porte elle-même !') ON DUPLICATE KEY UPDATE CompletionText='Vous devez éliminer leurs contrôleurs de portail avant de pouvoir détruire la porte elle-même !';
-- Quest 9741 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9741, 'frFR', 'Les créatures du vide se transforment en anomalies du vide. Pour être honnête, nous ne savons pas ce que sont ces créatures... le nom est plus une classification.') ON DUPLICATE KEY UPDATE CompletionText='Les créatures du vide se transforment en anomalies du vide. Pour être honnête, nous ne savons pas ce que sont ces créatures... le nom est plus une classification.';
-- Quest 9742 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9742, 'frFR', 'Avez-vous sauvé d\'autres sacs de spores, $R ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous sauvé d\'autres sacs de spores, $R ?';
-- Quest 9742 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9742, 'frFR', 'Oui !  Vous avez sauvé plus de sacs de spores.$B$BVous êtes différent des autres étrangers.  Je ferai savoir à mon peuple de vos exploits !$B$B<Cette quête est répétable jusqu\'à la réputation amicale.>') ON DUPLICATE KEY UPDATE RewardText='Oui !  Vous avez sauvé plus de sacs de spores.$B$BVous êtes différent des autres étrangers.  Je ferai savoir à mon peuple de vos exploits !$B$B<Cette quête est répétable jusqu\'à la réputation amicale.>';
-- Quest 9744 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9744, 'frFR', 'Vous avez tué de nombreux géants, mais il en reste encore beaucoup. Et ils attaquent toujours nos sacs de spores !') ON DUPLICATE KEY UPDATE CompletionText='Vous avez tué de nombreux géants, mais il en reste encore beaucoup. Et ils attaquent toujours nos sacs de spores !';
-- Quest 9746 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9746, 'frFR', 'Leur chef ne peut pas se cacher de nous pour toujours. Nous éliminerons systématiquement chaque cachette possible jusqu\'à ce que Sironas soit trouvé.') ON DUPLICATE KEY UPDATE CompletionText='Leur chef ne peut pas se cacher de nous pour toujours. Nous éliminerons systématiquement chaque cachette possible jusqu\'à ce que Sironas soit trouvé.';
-- Quest 9747 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9747, 'frFR', 'Vous êtes revenu ; sont morts Kataru et les esclavagistes d\'Umbrafen ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu ; sont morts Kataru et les esclavagistes d\'Umbrafen ?';

-- Quest 9751 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9751, 'frFR', 'As-tu entendu parler de la malédiction de sang, terre-à-terre ? Non, bien sûr que non. La malédiction de sang est ce qui a coulé tous ces navires. La partie gâtée et profanée de l\'eau ici est connue sous le nom de Récif Maudit par le Sang - une partie du monde que vous ne voulez jamais visiter. J\'y suis moi-même depuis 20 ans.$B$Bavardise ! Je suis mort sur ces côtes sauvages comme nourriture pour les dragons... Ah, mais c\'est une autre histoire pour un autre temps. Pour l\'instant, nous devons aider les pauvres âmes qui sont piégées dans ce récif.') ON DUPLICATE KEY UPDATE RewardText='As-tu entendu parler de la malédiction de sang, terre-à-terre ? Non, bien sûr que non. La malédiction de sang est ce qui a coulé tous ces navires. La partie gâtée et profanée de l\'eau ici est connue sous le nom de Récif Maudit par le Sang - une partie du monde que vous ne voulez jamais visiter. J\'y suis moi-même depuis 20 ans.$B$Bavardise ! Je suis mort sur ces côtes sauvages comme nourriture pour les dragons... Ah, mais c\'est une autre histoire pour un autre temps. Pour l\'instant, nous devons aider les pauvres âmes qui sont piégées dans ce récif.';
-- Quest 9755 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (9755, 'frFR', 'Nos tentatives d\'interrogatoire ont échoué lamentablement,$N. La torture est - bien sûr - hors de question. Ce dont nous avons besoin est d\'un draenei à l\'intérieur.$B$BI peux lancer un sort sur vous qui vous fera apparaître comme un elfe du sang et ajustera votre langue. Par subterfuge, nous pourrons obtenir les informations dont nous avons besoin des agents capturés.$B$Sous ce déguisement, je veux que vous obteniez toutes les informations possibles des prisonniers.$B$Et $N$, ne quittez pas la Veille de Sang tant que vous êtes déguisé, car le sort échouera.') ON DUPLICATE KEY UPDATE `Details`='Nos tentatives d\'interrogatoire ont échoué lamentablement,$N. La torture est - bien sûr - hors de question. Ce dont nous avons besoin est d\'un draenei à l\'intérieur.$B$BI peux lancer un sort sur vous qui vous fera apparaître comme un elfe du sang et ajustera votre langue. Par subterfuge, nous pourrons obtenir les informations dont nous avons besoin des agents capturés.$B$Sous ce déguisement, je veux que vous obteniez toutes les informations possibles des prisonniers.$B$Et $N$, ne quittez pas la Veille de Sang tant que vous êtes déguisé, car le sort échouera.';
-- Quest 9757 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9757, 'frFR', 'Commençons notre leçon immédiatement !') ON DUPLICATE KEY UPDATE RewardText='Commençons notre leçon immédiatement !';
-- Quest 9759 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9759, 'frFR', 'Vous avez sauvé tout Bloodmyst et Azuremyst, assurant le $R mode de vie sur Azeroth, <name>$! Pour cela, il n\'y a pas assez de remerciements, pas de récompense, rien d\'assez grand pour exprimer notre appréciation.$B$Pourtant, il y a encore tant de personnes qui ont été laissées sur Draenor qui ne peuvent être ici pour cet événement historique. Vous devez trouver votre chemin. Trouvez votre chemin vers l\'Outland, Héros d\'Argus. Ramenez notre peuple à la maison. À la terre que vous avez sauvée. À Azeroth...') ON DUPLICATE KEY UPDATE RewardText='Vous avez sauvé tout Bloodmyst et Azuremyst, assurant le $R mode de vie sur Azeroth, <name>$! Pour cela, il n\'y a pas assez de remerciements, pas de récompense, rien d\'assez grand pour exprimer notre appréciation.$B$Pourtant, il y a encore tant de personnes qui ont été laissées sur Draenor qui ne peuvent être ici pour cet événement historique. Vous devez trouver votre chemin. Trouvez votre chemin vers l\'Outland, Héros d\'Argus. Ramenez notre peuple à la maison. À la terre que vous avez sauvée. À Azeroth...';
-- Quest 9761 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9761, 'frFR', 'En voyez-vous un draenei exceptionnellement courageux et puissant par ici ?') ON DUPLICATE KEY UPDATE CompletionText='En voyez-vous un draenei exceptionnellement courageux et puissant par ici ?';
-- Quest 9762 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9762, 'frFR', 'Ces îles serviront de foyer à des milliers. La plupart de ces gens resteront ici toute leur vie. Si vous le souhaitiez, vous pourriez faire de même. Mais ce n\'est pas ce que vous voulez, n\'est-ce pas, $N?$B$B<Velen hoche la tête.>$B$Vous ferez beaucoup d\'autres grandes choses avant de passer. Vous devez embrasser votre destin et l\'affronter de front !$B$Avant de partir, je vous présente deux cadeaux : Ce tabard est porté uniquement par les plus vénérés de la Main d\'Argus et ce signet est porté par nos sages les plus avisés. Portez-les tous les deux avec fierté, $N.') ON DUPLICATE KEY UPDATE RewardText='Ces îles serviront de foyer à des milliers. La plupart de ces gens resteront ici toute leur vie. Si vous le souhaitiez, vous pourriez faire de même. Mais ce n\'est pas ce que vous voulez, n\'est-ce pas, $N?$B$B<Velen hoche la tête.>$B$Vous ferez beaucoup d\'autres grandes choses avant de passer. Vous devez embrasser votre destin et l\'affronter de front !$B$Avant de partir, je vous présente deux cadeaux : Ce tabard est porté uniquement par les plus vénérés de la Main d\'Argus et ce signet est porté par nos sages les plus avisés. Portez-les tous les deux avec fierté, $N.';
-- Quest 9763 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9763, 'frFR', 'Qu\'en est-il de Kalithresh ? Est-il mort, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'en est-il de Kalithresh ? Est-il mort, $N$?';
-- Quest 9764 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9764, 'frFR', 'Qu\'est-ce que tu as là, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que tu as là, $N$?';

-- Quest 9765 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9765, 'frFR', 'As-tu obtenu les armes que je recherche, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu les armes que je recherche, $N ?';
-- Quest 9766 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9766, 'frFR', 'Nous forgerons l\'acier des naga en armes pour les utiliser contre eux. Apporte-moi tous les équipements que tu arrives à récupérer de Coilfang Reservoir.') ON DUPLICATE KEY UPDATE CompletionText='Nous forgerons l\'acier des naga en armes pour les utiliser contre eux. Apporte-moi tous les équipements que tu arrives à récupérer de Coilfang Reservoir.';
-- Quest 9770 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9770, 'frFR', 'Je vois encore des marshfangs, $N. Tu ne peux pas avoir fini si tôt.') ON DUPLICATE KEY UPDATE CompletionText='Je vois encore des marshfangs, $N. Tu ne peux pas avoir fini si tôt.';
-- Quest 9783 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9783, 'frFR', 'Cela me fait mal de tuer les créatures de la Dead Mire, mais elles sont au-delà du salut. Le mieux que nous puissions faire est de travailler à restaurer la zone et de nourrir une nouvelle génération.') ON DUPLICATE KEY UPDATE CompletionText='Cela me fait mal de tuer les créatures de la Dead Mire, mais elles sont au-delà du salut. Le mieux que nous puissions faire est de travailler à restaurer la zone et de nourrir une nouvelle génération.';
-- Quest 9784 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9784, 'frFR', 'J\'aurais encore besoin de plus de parties végétales. Avec les lacs qui perdent leur eau, j\'ai l\'impression que le nombre d\'espèces invasives augmente. J\'ai besoin de plus de chiffres pour étayer ma théorie, cependant.') ON DUPLICATE KEY UPDATE CompletionText='J\'aurais encore besoin de plus de parties végétales. Avec les lacs qui perdent leur eau, j\'ai l\'impression que le nombre d\'espèces invasives augmente. J\'ai besoin de plus de chiffres pour étayer ma théorie, cependant.';
-- Quest 9785 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9785, 'frFR', 'As-tu parlé aux anciens, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu parlé aux anciens, $N ?';
-- Quest 9786 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9786, 'frFR', 'As-tu examiné les Ruines de Boha\'mu ? Peux-tu imaginer à quoi elles ressemblaient dans leur pleine splendeur ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu examiné les Ruines de Boha\'mu ? Peux-tu imaginer à quoi elles ressemblaient dans leur pleine splendeur ?';
-- Quest 9788 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9788, 'frFR', 'As-tu trouvé mes affaires, $N ? La grotte n\'est pas loin d\'Umbrafen, près de la frontière avec Nagrand.') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé mes affaires, $N ? La grotte n\'est pas loin d\'Umbrafen, près de la frontière avec Nagrand.';

-- Quest 9789 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9789, 'frFR', 'Les clefthoof de Nagrand sont un bon défi. J\'en ai récolté pas mal.$B$BComment ça se passe pour toi ?') ON DUPLICATE KEY UPDATE CompletionText='Les clefthoof de Nagrand sont un bon défi. J\'en ai récolté pas mal.$B$BComment ça se passe pour toi ?';
-- Quest 9791 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9791, 'frFR', 'As-tu réussi ta chasse au marshfang ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi ta chasse au marshfang ?';
-- Quest 9804 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9804, 'frFR', 'Utilise les cerises de Nagrand avant de trop t\'aventurer dans le lac.') ON DUPLICATE KEY UPDATE CompletionText='Utilise les cerises de Nagrand avant de trop t\'aventurer dans le lac.';
-- Quest 9806 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9806, 'frFR', 'Tu es de retour, $N. As-tu obtenu les spores fertiles ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour, $N. As-tu obtenu les spores fertiles ?';
-- Quest 9806 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9806, 'frFR', 'Ce sont de super spores, <name>ü !  Les Tallstalks sont vitaux pour reconstruire notre ville.  Et après tous les attaques du seigneur des marais que nous avons subies, nous sommes en assez pénurie.') ON DUPLICATE KEY UPDATE RewardText='Ce sont de super spores, <name>ü !  Les Tallstalks sont vitaux pour reconstruire notre ville.  Et après tous les attaques du seigneur des marais que nous avons subies, nous sommes en assez pénurie.';
-- Quest 9807 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9807, 'frFR', 'Nous pouvons toujours utiliser plus de spores fertiles, $R. Les Tallstalks sont des champignons incroyablement utiles. Pouvoir les cultiver nous permet de faire beaucoup de choses avec eux.') ON DUPLICATE KEY UPDATE CompletionText='Nous pouvons toujours utiliser plus de spores fertiles, $R. Les Tallstalks sont des champignons incroyablement utiles. Pouvoir les cultiver nous permet de faire beaucoup de choses avec eux.';
-- Quest 9808 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9808, 'frFR', 'As-tu trouvé des glowcaps, $N ? Ils sont littéralement partout dans le marais.$B$BTu peux repérer leur éclat vif de loin si tu fais attention.') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé des glowcaps, $N ? Ils sont littéralement partout dans le marais.$B$BTu peux repérer leur éclat vif de loin si tu fais attention.';
-- Quest 9809 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9809, 'frFR', 'Je prendrai plus de glowcaps si tu en as. Notre village peut toujours en avoir plus.') ON DUPLICATE KEY UPDATE CompletionText='Je prendrai plus de glowcaps si tu en as. Notre village peut toujours en avoir plus.';

-- Quest 9810 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9810, 'frFR', 'L\'Anneau de Terre aidera de toutes les manières possibles.') ON DUPLICATE KEY UPDATE CompletionText='L\'Anneau de Terre aidera de toutes les manières possibles.';
-- Quest 9811 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9811, 'frFR', 'Vous cherchez à me parler ? Je ne me souviens pas avoir entendu parler d\'un rendez-vous.') ON DUPLICATE KEY UPDATE CompletionText='Vous cherchez à me parler ? Je ne me souviens pas avoir entendu parler d\'un rendez-vous.';
-- Quest 9811 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9811, 'frFR', 'Alors vous avez tué Dar\'Khan, $R? Impressif. J\'ai le sentiment que mon peuple et le vôtre deviendront bientôt de très bons amis.') ON DUPLICATE KEY UPDATE RewardText='Alors vous avez tué Dar\'Khan, $R? Impressif. J\'ai le sentiment que mon peuple et le vôtre deviendront bientôt de très bons amis.';
-- Quest 9812 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9812, 'frFR', 'On m\'a dit qu\'un visiteur de Quel\'Thalas arrivait. Je m\'attendais à un elfe-sang, pour être honnête.$b$bQuelle nouvelle apportez-vous ?') ON DUPLICATE KEY UPDATE CompletionText='On m\'a dit qu\'un visiteur de Quel\'Thalas arrivait. Je m\'attendais à un elfe-sang, pour être honnête.$b$bQuelle nouvelle apportez-vous ?';
-- Quest 9812 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9812, 'frFR', 'C\'est fait alors. Le traître maudit a eu ce qu\'il méritait.$B$BVous avez été d\'un grand service aux elfes-sang et à la Horde. Dar\'khan était l\'excuse de Thrall pour leur refuser l\'entrée dans notre alliance. Vous avez ouvert la voie à une nouvelle Horde, $C.$B$BI vois aussi que Lor\'themar a des nouvelles supplémentaires qui amélioreront grandement ses relations avec Thrall. Excellent !') ON DUPLICATE KEY UPDATE RewardText='C\'est fait alors. Le traître maudit a eu ce qu\'il méritait.$B$BVous avez été d\'un grand service aux elfes-sang et à la Horde. Dar\'khan était l\'excuse de Thrall pour leur refuser l\'entrée dans notre alliance. Vous avez ouvert la voie à une nouvelle Horde, $C.$B$BI vois aussi que Lor\'themar a des nouvelles supplémentaires qui amélioreront grandement ses relations avec Thrall. Excellent !';
-- Quest 9813 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9813, 'frFR', '$GLe Chef de Guerre commence à lire la lettre.>$B$BAlors les elfes-sang se sont enfin débarrassés de leur petit problème. Il n\'est pas étonnant que cela ait nécessité votre aide ainsi que celle d\'un régiment entier de Désespérés pour que le travail soit fait.$B<br :><Le Chef de Guerre éclate de rire.$B$BI je suppose qu\'il n\'y a rien à faire. Au final, nous avons autant besoin d\'eux qu\'ils ont besoin de nous.') ON DUPLICATE KEY UPDATE RewardText='$GLe Chef de Guerre commence à lire la lettre.>$B$BAlors les elfes-sang se sont enfin débarrassés de leur petit problème. Il n\'est pas étonnant que cela ait nécessité votre aide ainsi que celle d\'un régiment entier de Désespérés pour que le travail soit fait.$B<br :><Le Chef de Guerre éclate de rire.$B$BI je suppose qu\'il n\'y a rien à faire. Au final, nous avons autant besoin d\'eux qu\'ils ont besoin de nous.';
-- Quest 9816 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9816, 'frFR', '<Le Docteur Sorcier Tor\'gash sourit.>$B$Les petits Perdus ont aimé leur cadeau ?') ON DUPLICATE KEY UPDATE CompletionText='<Le Docteur Sorcier Tor\'gash sourit.>$B$Les petits Perdus ont aimé leur cadeau ?';
-- Quest 9817 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9817, 'frFR', 'Vous êtes ici pour réclamer la prime pour Fyashe ? C\'est la meilleure nouvelle que j\'aie entendue aujourd\'hui.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes ici pour réclamer la prime pour Fyashe ? C\'est la meilleure nouvelle que j\'aie entendue aujourd\'hui.';

-- Quest 9823 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9823, 'frFR', 'La menace des Ango\'rosh plane au-dessus de nous. Avez-vous éliminé leur chef ?') ON DUPLICATE KEY UPDATE CompletionText='La menace des Ango\'rosh plane au-dessus de nous. Avez-vous éliminé leur chef ?';
-- Quest 9825 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9825, 'frFR', 'Avez-vous obtenu les essences fantomatiques dont j\'ai besoin, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous obtenu les essences fantomatiques dont j\'ai besoin, $N ?';
-- Quest 9828 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9828, 'frFR', 'Cela ressemble au basidium d\'un seigneur de marais, mais je n\'en ai jamais vu un dans cet état auparavant. J\'avais entendu dire que les géants de la Marais des Morts commençaient à dépérir, mais c\'est bien plus avancé que ce à quoi je m\'attendais.$B$La Marais des Morts était autrefois un lac comme les autres dans le marais, et il servait de lieu de reproduction pour les géants. Avec le recul des eaux, il semble que les changements empêchent les géants de se sporuler. Si cela continue, les géants pourraient disparaître entièrement.') ON DUPLICATE KEY UPDATE RewardText='Cela ressemble au basidium d\'un seigneur de marais, mais je n\'en ai jamais vu un dans cet état auparavant. J\'avais entendu dire que les géants de la Marais des Morts commençaient à dépérir, mais c\'est bien plus avancé que ce à quoi je m\'attendais.$B$La Marais des Morts était autrefois un lac comme les autres dans le marais, et il servait de lieu de reproduction pour les géants. Avec le recul des eaux, il semble que les changements empêchent les géants de se sporuler. Si cela continue, les géants pourraient disparaître entièrement.';
-- Quest 9831 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9831, 'frFR', 'Avez-vous obtenu le fragment, $c ? Vous feriez bien de ne pas perdre de temps à ce sujet') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous obtenu le fragment, $c ? Vous feriez bien de ne pas perdre de temps à ce sujet';
-- Quest 9832 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9832, 'frFR', 'Comment se passe votre recherche des fragments de clé, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe votre recherche des fragments de clé, $N ?';
-- Quest 9832 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9832, 'frFR', 'Vous avez les fragments.  C\'est très impressionnant, <name>.  Vous êtes certainement digne de détenir la clé de Karazhan.$B$Un petit problème demeure.') ON DUPLICATE KEY UPDATE RewardText='Vous avez les fragments.  C\'est très impressionnant, <name>.  Vous êtes certainement digne de détenir la clé de Karazhan.$B$Un petit problème demeure.';
-- Quest 9833 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9833, 'frFR', 'Avez-vous progressé dans la sécurisation des routes ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous progressé dans la sécurisation des routes ?';
-- Quest 9835 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9835, 'frFR', 'Comment se passe le combat contre les Ango\'rosh ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe le combat contre les Ango\'rosh ?';

-- Quest 9839 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9839, 'frFR', 'C\'est fait ? Avez-vous réglé le problème de l\'Archonte Gorefist ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est fait ? Avez-vous réglé le problème de l\'Archonte Gorefist ?';
-- Quest 9841 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9841, 'frFR', 'Le bruit semble s\'éloigner. Est-ce de l\'espoir ou avez-vous vraiment fait quelque chose au sujet du problème ?') ON DUPLICATE KEY UPDATE CompletionText='Le bruit semble s\'éloigner. Est-ce de l\'espoir ou avez-vous vraiment fait quelque chose au sujet du problème ?';
-- Quest 9844 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9844, 'frFR', 'J\'ai peur de demander, $N. Qu\'est-advenu de la situation à l\'intérieur de Karazhan ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ai peur de demander, $N. Qu\'est-advenu de la situation à l\'intérieur de Karazhan ?';
-- Quest 9845 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9845, 'frFR', 'Est-ce que c\'est sûr pour moi de remettre à pêcher ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce que c\'est sûr pour moi de remettre à pêcher ?';
-- Quest 9850 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9850, 'frFR', 'Vous pensez que les taureaux clefthoof vont simplement tomber morts à vos pieds ici devant le feu de camp ?') ON DUPLICATE KEY UPDATE CompletionText='Vous pensez que les taureaux clefthoof vont simplement tomber morts à vos pieds ici devant le feu de camp ?';
-- Quest 9854 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9854, 'frFR', 'Avez-vous appris la paix qui vient de connaître sa place dans la nature ? Êtes-vous le chasseur ou la proie ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous appris la paix qui vient de connaître sa place dans la nature ? Êtes-vous le chasseur ou la proie ?';
-- Quest 9855 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9855, 'frFR', 'Avez-vous appris à calmer le battement de votre cœur ? À être aussi immobile qu\'un lac calme et patient, attendant le bon moment pour abattre votre proie ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous appris à calmer le battement de votre cœur ? À être aussi immobile qu\'un lac calme et patient, attendant le bon moment pour abattre votre proie ?';
-- Quest 9857 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9857, 'frFR', 'Je vais juste rester allongé un peu plus longtemps. Je devrais aller bien bientôt.') ON DUPLICATE KEY UPDATE CompletionText='Je vais juste rester allongé un peu plus longtemps. Je devrais aller bien bientôt.';

-- Quest 9858 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9858, 'frFR', 'Je ne suppose pas...<cough>... que vous ayez réglé ces...<cough>... brouteurs de ronces ?') ON DUPLICATE KEY UPDATE CompletionText='Je ne suppose pas...<cough>... que vous ayez réglé ces...<cough>... brouteurs de ronces ?';
-- Quest 9858 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9858, 'frFR', '<cough>, <cough>... <name> ! Vous l\'avez fait. Il ne reste plus qu\'une seule chose à... faire alors.') ON DUPLICATE KEY UPDATE RewardText='<cough>, <cough>... <name> ! Vous l\'avez fait. Il ne reste plus qu\'une seule chose à... faire alors.';
-- Quest 9860 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9860, 'frFR', 'Alturus m\'a tout raconté, $Gname>. Ce n\'est pas la fin, cependant. Avec Karazhan resté scellé aux étrangers, c\'est une question de temps avant que la Légion ne renouvelle ses attaques pendant que nous restons impuissants sur la touche.$B$BÀ moins que vous n\'acceptiez la responsabilité que le destin vous a conférée, c\'est ça.$B$B$B<br :>Qu\'en dites-vous, <name>?') ON DUPLICATE KEY UPDATE RewardText='Alturus m\'a tout raconté, $Gname>. Ce n\'est pas la fin, cependant. Avec Karazhan resté scellé aux étrangers, c\'est une question de temps avant que la Légion ne renouvelle ses attaques pendant que nous restons impuissants sur la touche.$B$BÀ moins que vous n\'acceptiez la responsabilité que le destin vous a conférée, c\'est ça.$B$B$B<br :>Qu\'en dites-vous, <name>?';
-- Quest 9862 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9862, 'frFR', 'L\'esprit de l\'air affirme que les Murkblood recherchent quelque chose à Sunspring...') ON DUPLICATE KEY UPDATE CompletionText='L\'esprit de l\'air affirme que les Murkblood recherchent quelque chose à Sunspring...';
-- Quest 9865 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9865, 'frFR', 'Pour chacun de mes proches qu\'ils ont abattus, dix d\'entre eux doivent mourir !') ON DUPLICATE KEY UPDATE CompletionText='Pour chacun de mes proches qu\'ils ont abattus, dix d\'entre eux doivent mourir !';
-- Quest 9873 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9873, 'frFR', 'Souviens-toi, $N, Ortor est un chaman de grande puissance.') ON DUPLICATE KEY UPDATE CompletionText='Souviens-toi, $N, Ortor est un chaman de grande puissance.';
-- Quest 9875 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9875, 'frFR', 'Vous avez quelque chose à me montrer ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez quelque chose à me montrer ?';
-- Quest 9878 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9878, 'frFR', 'Les Murkblood sont une tribu nefaste de Brisés, $N. Ils peuvent ressembler aux Kurenai mais ils sont assurément des bêtes sauvages, des meurtriers.') ON DUPLICATE KEY UPDATE CompletionText='Les Murkblood sont une tribu nefaste de Brisés, $N. Ils peuvent ressembler aux Kurenai mais ils sont assurément des bêtes sauvages, des meurtriers.';

-- Quest 9882 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9882, 'frFR', 'As-tu récupéré les fragments de cristal que je t\'avais demandés, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu récupéré les fragments de cristal que je t\'avais demandés, $N ?';
-- Quest 9883 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9883, 'frFR', 'Tu as d\'autres fragments de cristal ? Assure-toi de ne prendre aucun qui est encore attaché à la montagne ; nous ne voudrions pas provoquer de problèmes avec les naaru.') ON DUPLICATE KEY UPDATE CompletionText='Tu as d\'autres fragments de cristal ? Assure-toi de ne prendre aucun qui est encore attaché à la montagne ; nous ne voudrions pas provoquer de problèmes avec les naaru.';
-- Quest 9884 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9884, 'frFR', 'Le Consortium est réputé pour prendre bien soin de ses amis. Au début de chaque mois, j\'aurai des gemmes prêtes pour toi en paiement de tes services.$B$BLa qualité des gemmes que tu recevras dépendra de ta loyauté envers nous. Nous espérons que tu feras le choix intelligent et que tu resteras avec nous.') ON DUPLICATE KEY UPDATE RewardText='Le Consortium est réputé pour prendre bien soin de ses amis. Au début de chaque mois, j\'aurai des gemmes prêtes pour toi en paiement de tes services.$B$BLa qualité des gemmes que tu recevras dépendra de ta loyauté envers nous. Nous espérons que tu feras le choix intelligent et que tu resteras avec nous.';
