INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9892, 'frFR', 'As-tu obtenu d\'autres perles de guerre ? Tu trouveras beaucoup d\'ogres dans le nord, près de la frontière avec Zangarmarsh.') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu d\'autres perles de guerre ? Tu trouveras beaucoup d\'ogres dans le nord, près de la frontière avec Zangarmarsh.';
