INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9893, 'frFR', 'Comment ces ogres te traitent-ils, $N ? Une bande difficile, n\'est-ce pas ?') ON DUPLICATE KEY UPDATE CompletionText='Comment ces ogres te traitent-ils, $N ? Une bande difficile, n\'est-ce pas ?';

-- Quest 9893 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9893, 'frFR', 'Cela nous permettra de rester en affaires en attendant que les Sha\'tar finissent les préparatifs qu\'ils doivent faire à l\'intérieur d\'Oshu\'gun.') ON DUPLICATE KEY UPDATE RewardText='Cela nous permettra de rester en affaires en attendant que les Sha\'tar finissent les préparatifs qu\'ils doivent faire à l\'intérieur d\'Oshu\'gun.';
