INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9894, 'frFR', 'Avez-vous localisé et traité Lord Klaq ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous localisé et traité Lord Klaq ?';
-- Quest 9899 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9899, 'frFR', 'Il n\'y a aucun moyen de changer son esprit, je le jure. Je pense que je vais devoir demander à Shadow Hunter Denjai un transfert vers Zabra\'jin.') ON DUPLICATE KEY UPDATE CompletionText='Il n\'y a aucun moyen de changer son esprit, je le jure. Je pense que je vais devoir demander à Shadow Hunter Denjai un transfert vers Zabra\'jin.';
