INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9900, 'frFR', 'Vous êtes revenu, $r. Gava\'xi est-il mort ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu, $r. Gava\'xi est-il mort ?';
-- Quest 9901 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9901, 'frFR', 'Avez-vous réussi à retrouver Sporewing ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à retrouver Sporewing ?';
-- Quest 9902 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9902, 'frFR', 'J\'ai honte de ne pas pouvoir faire plus pour aider mes frères et sœurs asservis. mais au moins nous avons évité des morts inutiles.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai honte de ne pas pouvoir faire plus pour aider mes frères et sœurs asservis. mais au moins nous avons évité des morts inutiles.';
-- Quest 9903 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9903, 'frFR', 'Avez-vous "retiré" le vieux Mragesh ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous "retiré" le vieux Mragesh ?';
-- Quest 9904 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9904, 'frFR', 'Je suppose que Terrorclaw ne vit plus ?') ON DUPLICATE KEY UPDATE CompletionText='Je suppose que Terrorclaw ne vit plus ?';

-- Quest 9905 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9905, 'frFR', 'Il y a longtemps, Maktu a peut-être utilisé la peau de Mragesh pour fabriquer une armure solide. Mragesh est bien trop vieux pour cela maintenant. La peau est trop molle pour une bonne armure.') ON DUPLICATE KEY UPDATE CompletionText='Il y a longtemps, Maktu a peut-être utilisé la peau de Mragesh pour fabriquer une armure solide. Mragesh est bien trop vieux pour cela maintenant. La peau est trop molle pour une bonne armure.';
-- Quest 9906 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9906, 'frFR', 'J\'envoie une petite équipe de recherche organisée pour le reste des villageois.') ON DUPLICATE KEY UPDATE CompletionText='J\'envoie une petite équipe de recherche organisée pour le reste des villageois.';
-- Quest 9907 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9907, 'frFR', 'Il faut leur rappeler que nous sommes une force à prendre au sérieux dans cette région.') ON DUPLICATE KEY UPDATE CompletionText='Il faut leur rappeler que nous sommes une force à prendre au sérieux dans cette région.';
-- Quest 9915 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9915, 'frFR', 'J\'ai toujours besoin de plus de paires de défenses d\'ivoire des élk sauvages qui parcourent cette terre. Malheureusement, mon budget ne pourra plus supporter votre part des bénéfices. Si vous continuez à me fournir ce dont j\'ai besoin, cependant, vous vous ingrâcissez auprès du Consortium.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai toujours besoin de plus de paires de défenses d\'ivoire des élk sauvages qui parcourent cette terre. Malheureusement, mon budget ne pourra plus supporter votre part des bénéfices. Si vous continuez à me fournir ce dont j\'ai besoin, cependant, vous vous ingrâcissez auprès du Consortium.';
-- Quest 9918 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9918, 'frFR', 'Il sera probablement endormi sur une crête.') ON DUPLICATE KEY UPDATE CompletionText='Il sera probablement endormi sur une crête.';
