INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9919, 'frFR', 'Vous avez quelque chose à me montrer, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez quelque chose à me montrer, $N ?';
