INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9921, 'frFR', 'Nous avons récemment repris Telaar. Nous ne le perdrons pas à nouveau !') ON DUPLICATE KEY UPDATE CompletionText='Nous avons récemment repris Telaar. Nous ne le perdrons pas à nouveau !';
-- Quest 9922 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9922, 'frFR', 'Méfiez-vous des élémentaires dans le bassin, $N.') ON DUPLICATE KEY UPDATE CompletionText='Méfiez-vous des élémentaires dans le bassin, $N.';

-- Quest 9923 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9923, 'frFR', 'Ce garçon...$B$B<Arechron secoue la tête avec désapprobation.>$B$BIl va me tuer.') ON DUPLICATE KEY UPDATE CompletionText='Ce garçon...$B$B<Arechron secoue la tête avec désapprobation.>$B$BIl va me tuer.';
-- Quest 9925 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9925, 'frFR', 'As-tu pris soin du spawn du vide, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu pris soin du spawn du vide, $N?';
-- Quest 9927 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9927, 'frFR', 'Peux-tu imaginer leur perplexité face à ce qui se passe, $R? Ce sera glorieux.') ON DUPLICATE KEY UPDATE RewardText='Peux-tu imaginer leur perplexité face à ce qui se passe, $R? Ce sera glorieux.';
-- Quest 9929 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9929, 'frFR', 'Au milieu des décombres du chariot et des marchandises du marchand, des traces étranges sont visibles. Les traces semblent provenir d\'un oiseau surdimensionné.$BEn vous rappelant ce que vous savez des arakkoa, vous concluez que la trace est assez grande pour appartenir à l\'un des peuples d\'oiseaux intelligents qui vivent dans la forêt. Pourquoi se seraient-ils mis à attaquer les marchands de la Horde ?') ON DUPLICATE KEY UPDATE RewardText='Au milieu des décombres du chariot et des marchandises du marchand, des traces étranges sont visibles. Les traces semblent provenir d\'un oiseau surdimensionné.$BEn vous rappelant ce que vous savez des arakkoa, vous concluez que la trace est assez grande pour appartenir à l\'un des peuples d\'oiseaux intelligents qui vivent dans la forêt. Pourquoi se seraient-ils mis à attaquer les marchands de la Horde ?';
-- Quest 9930 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9930, 'frFR', 'Au milieu des décombres du chariot et des marchandises du marchand, des traces étranges sont visibles. Les traces semblent provenir d\'un oiseau surdimensionné.$BEn vous rappelant ce que vous savez des arakkoa, vous concluez que la trace est assez grande pour appartenir à l\'un des peuples d\'oiseaux intelligents qui vivent dans la forêt. Pourquoi se seraient-ils mis à attaquer les marchands de l\'Alliance ?') ON DUPLICATE KEY UPDATE RewardText='Au milieu des décombres du chariot et des marchandises du marchand, des traces étranges sont visibles. Les traces semblent provenir d\'un oiseau surdimensionné.$BEn vous rappelant ce que vous savez des arakkoa, vous concluez que la trace est assez grande pour appartenir à l\'un des peuples d\'oiseaux intelligents qui vivent dans la forêt. Pourquoi se seraient-ils mis à attaquer les marchands de l\'Alliance ?';
