-- Quest 9941 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9941, 'frFR', 'En inspectant l\'impression sur les sacs, vous pouvez distinguer le nom de Deirom. Les arakkoa semblent avoir assez tenu à la cargaison du marchand pour l\'emmener loin de la charrette, mais où est le marchand disparu ?') ON DUPLICATE KEY UPDATE RewardText='En inspectant l\'impression sur les sacs, vous pouvez distinguer le nom de Deirom. Les arakkoa semblent avoir assez tenu à la cargaison du marchand pour l\'emmener loin de la charrette, mais où est le marchand disparu ?';
-- Quest 9942 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9942, 'frFR', 'En inspectant l\'impression sur les sacs, vous pouvez distinguer le nom de Dugar. Les arakkoa semblent avoir assez tenu à la cargaison du marchand pour l\'emmener loin de la charrette, mais où est le marchand disparu ?') ON DUPLICATE KEY UPDATE RewardText='En inspectant l\'impression sur les sacs, vous pouvez distinguer le nom de Dugar. Les arakkoa semblent avoir assez tenu à la cargaison du marchand pour l\'emmener loin de la charrette, mais où est le marchand disparu ?';
-- Quest 9943 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9943, 'frFR', '<Thander hoche la tête lorsque vous lui parlez de vos découvertes dans le hameau des arakkoa.>$BIl n\'y a aucun doute qu\'ils sont impliqués, alors. Mais pourquoi ?$BDeirom fait le voyage à Shattrath sans incident depuis un certain temps. Pourquoi les arakkoa choisiraient-ils ce voyage pour le prendre en otage ?') ON DUPLICATE KEY UPDATE RewardText='<Thander hoche la tête lorsque vous lui parlez de vos découvertes dans le hameau des arakkoa.>$BIl n\'y a aucun doute qu\'ils sont impliqués, alors. Mais pourquoi ?$BDeirom fait le voyage à Shattrath sans incident depuis un certain temps. Pourquoi les arakkoa choisiraient-ils ce voyage pour le prendre en otage ?';
-- Quest 9945 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9945, 'frFR', 'Ce n\'est qu\'une étape dans un long processus. Les ogres, comme les chiens, doivent voir la différence entre le bien et le mal. Leur dire ne sert à rien.') ON DUPLICATE KEY UPDATE CompletionText='Ce n\'est qu\'une étape dans un long processus. Les ogres, comme les chiens, doivent voir la différence entre le bien et le mal. Leur dire ne sert à rien.';

-- Quest 9947 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9947, 'frFR', 'Rokag hoche la tête lorsque vous lui parlez de vos découvertes dans le hameau arakkoa.$BIl n\'y a aucun doute qu\'ils sont impliqués, alors. Mais pourquoi?$BDugar fait ce voyage à Shattrath sans incident depuis un certain temps. Pourquoi les arakkoa choisiraient-ils de le prendre en otage pour ce voyage ?') ON DUPLICATE KEY UPDATE RewardText='Rokag hoche la tête lorsque vous lui parlez de vos découvertes dans le hameau arakkoa.$BIl n\'y a aucun doute qu\'ils sont impliqués, alors. Mais pourquoi?$BDugar fait ce voyage à Shattrath sans incident depuis un certain temps. Pourquoi les arakkoa choisiraient-ils de le prendre en otage pour ce voyage ?';
-- Quest 9948 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9948, 'frFR', 'Ungriz soupire.$B$Je sais que c\'est beaucoup à demander, $N; mais ramenez-les vivants...') ON DUPLICATE KEY UPDATE CompletionText='Ungriz soupire.$B$Je sais que c\'est beaucoup à demander, $N; mais ramenez-les vivants...';
-- Quest 9949 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9949, 'frFR', 'Bizarre, ces yeux ne sont pas exactement ceux auxquels je suis habitué. La manière dont les arakkoa utilisent leur magie est légèrement différente de la nôtre.$B$BIl semble que nous aurons besoin d\'une chose de plus si je veux pouvoir scruter les informations pour localiser Deirom.') ON DUPLICATE KEY UPDATE RewardText='Bizarre, ces yeux ne sont pas exactement ceux auxquels je suis habitué. La manière dont les arakkoa utilisent leur magie est légèrement différente de la nôtre.$B$BIl semble que nous aurons besoin d\'une chose de plus si je veux pouvoir scruter les informations pour localiser Deirom.';
-- Quest 9950 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9950, 'frFR', 'Rokag m\'a parlé de son plan. Vous avez les yeux ?') ON DUPLICATE KEY UPDATE CompletionText='Rokag m\'a parlé de son plan. Vous avez les yeux ?';
-- Quest 9950 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9950, 'frFR', 'Bizarre, ces yeux ne sont pas exactement ceux auxquels je suis habitué. La façon dont les arakkoa utilisent leur magie est légèrement différente de la nôtre.$B$BIl semble que nous aurons besoin d\'une chose de plus si je veux pouvoir scruter les informations pour localiser Dugar.') ON DUPLICATE KEY UPDATE RewardText='Bizarre, ces yeux ne sont pas exactement ceux auxquels je suis habitué. La façon dont les arakkoa utilisent leur magie est légèrement différente de la nôtre.$B$BIl semble que nous aurons besoin d\'une chose de plus si je veux pouvoir scruter les informations pour localiser Dugar.';
-- Quest 9951 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9951, 'frFR', 'Nous n\'aurions jamais dû les inviter à dîner. C\'est certain !$B$BOu, au moins, nous aurions dû insister pour quelques plats avant le dessert qu\'ils ont apporté.') ON DUPLICATE KEY UPDATE CompletionText='Nous n\'aurions jamais dû les inviter à dîner. C\'est certain !$B$BOu, au moins, nous aurions dû insister pour quelques plats avant le dessert qu\'ils ont apporté.';
-- Quest 9952 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9952, 'frFR', 'Oui, je connais Veil Shalas. Quel salaud, ça. Mais si votre ami est détenu là-bas, j\'imagine que nous allons devoir trouver un moyen de contourner leurs défenses.') ON DUPLICATE KEY UPDATE RewardText='Oui, je connais Veil Shalas. Quel salaud, ça. Mais si votre ami est détenu là-bas, j\'imagine que nous allons devoir trouver un moyen de contourner leurs défenses.';
-- Quest 9953 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9953, 'frFR', 'L\'influence de Veil Shalas domine ces régions. Si votre ami est détenu là-bas, j\'imagine que nous allons devoir trouver un moyen de contourner leurs défenses.') ON DUPLICATE KEY UPDATE RewardText='L\'influence de Veil Shalas domine ces régions. Si votre ami est détenu là-bas, j\'imagine que nous allons devoir trouver un moyen de contourner leurs défenses.';

-- Quest 9958 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9958, 'frFR', 'Leurs défenses sont bien plus sophistiquées que je ne le pensais, $N. C\'est un mauvais signe. Heureusement, pour chaque bon sort, il y a un contre-sort. C\'est juste une question de mettre la main sur ce contre.') ON DUPLICATE KEY UPDATE RewardText='Leurs défenses sont bien plus sophistiquées que je ne le pensais, $N. C\'est un mauvais signe. Heureusement, pour chaque bon sort, il y a un contre-sort. C\'est juste une question de mettre la main sur ce contre.';
