-- Quest 9975 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9975, 'frFR', 'Si le sort du talisman a fonctionné, alors vous devriez être prêt à vous aventurer dans Veil Shalas. J\'espère que votre sage arakkoa vous a dit la vérité quand il a dit que sa magie était plus forte que cette barrière. S\'il nous ment, vous et Deirom êtes en difficulté.') ON DUPLICATE KEY UPDATE RewardText='Si le sort du talisman a fonctionné, alors vous devriez être prêt à vous aventurer dans Veil Shalas. J\'espère que votre sage arakkoa vous a dit la vérité quand il a dit que sa magie était plus forte que cette barrière. S\'il nous ment, vous et Deirom êtes en difficulté.';
-- Quest 9976 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9976, 'frFR', 'Si le sort du talisman a fonctionné, alors vous devriez être prêt à vous aventurer dans Veil Shalas. J\'espère que votre sage arakkoa vous a dit la vérité quand il a dit que sa magie était plus forte que cette barrière. S\'il nous ment, vous et Dugar êtes en difficulté.') ON DUPLICATE KEY UPDATE RewardText='Si le sort du talisman a fonctionné, alors vous devriez être prêt à vous aventurer dans Veil Shalas. J\'espère que votre sage arakkoa vous a dit la vérité quand il a dit que sa magie était plus forte que cette barrière. S\'il nous ment, vous et Dugar êtes en difficulté.';
-- Quest 9977 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9977, 'frFR', 'Le combat est terminé lorsque vous ou votre adversaire êtes mort au sol.') ON DUPLICATE KEY UPDATE CompletionText='Le combat est terminé lorsque vous ou votre adversaire êtes mort au sol.';
-- Quest 9980 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9980, 'frFR', 'Je dois admettre, $N, je suis agréablement surpris. Quand Thander m\'a dit que Deirom était détenu dans Veil Shalas, j\'ai commencé à me demander s\'il nous était perdu pour de bon.$B$BC\'est une fois où je suis très heureux d\'avoir eu tort.$B$BVous pouvez parier que nous surveillerons de plus près les activités des arakkoa après cela.') ON DUPLICATE KEY UPDATE RewardText='Je dois admettre, $N, je suis agréablement surpris. Quand Thander m\'a dit que Deirom était détenu dans Veil Shalas, j\'ai commencé à me demander s\'il nous était perdu pour de bon.$B$BC\'est une fois où je suis très heureux d\'avoir eu tort.$B$BVous pouvez parier que nous surveillerons de plus près les activités des arakkoa après cela.';
-- Quest 9981 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9981, 'frFR', 'Je dois admettre, $N, je suis surpris. Quand nous avons appris que Dugar était détenu dans Veil Shalas, j\'ai commencé à me demander s\'il nous était perdu pour de bon.$B$BC\'est une fois où je suis heureux d\'avoir eu tort.$B$BVous pouvez parier que nous surveillerons de plus près les activités des arakkoa après cela.') ON DUPLICATE KEY UPDATE RewardText='Je dois admettre, $N, je suis surpris. Quand nous avons appris que Dugar était détenu dans Veil Shalas, j\'ai commencé à me demander s\'il nous était perdu pour de bon.$B$BC\'est une fois où je suis heureux d\'avoir eu tort.$B$BVous pouvez parier que nous surveillerons de plus près les activités des arakkoa après cela.';
-- Quest 9982 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9982, 'frFR', 'Mon apparence vous effraie-t-elle ? Savez-vous ce que je suis ?') ON DUPLICATE KEY UPDATE RewardText='Mon apparence vous effraie-t-elle ? Savez-vous ce que je suis ?';
-- Quest 9984 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9984, 'frFR', 'Je peux lire la plupart de ceci, assez pour avoir une idée générale. Celui qui a écrit ceci loue les \'progrès\' réalisés par Luanga et l\'encourage à continuer d\'interroger ses \'invités.\'$b$bPendant ce temps, il est dit : \'les préparatifs à Skettis se déroulent comme prévu\' et qu\'ils seront \'bientôt prêts à récupérer leurs terres ancestrales.\'$b$bJe ne connais pas ce \'Skettis\' mentionné par l\'auteur, mais où qu\'il soit, il semble que les arakkoa y assemblent une armée ! Thander doit être informé de cela immédiatement.') ON DUPLICATE KEY UPDATE RewardText='Je peux lire la plupart de ceci, assez pour avoir une idée générale. Celui qui a écrit ceci loue les \'progrès\' réalisés par Luanga et l\'encourage à continuer d\'interroger ses \'invités.\'$b$bPendant ce temps, il est dit : \'les préparatifs à Skettis se déroulent comme prévu\' et qu\'ils seront \'bientôt prêts à récupérer leurs terres ancestrales.\'$b$bJe ne connais pas ce \'Skettis\' mentionné par l\'auteur, mais où qu\'il soit, il semble que les arakkoa y assemblent une armée ! Thander doit être informé de cela immédiatement.';

-- Quest 9985 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9985, 'frFR', 'Je peux lire la plupart de ceci, juste assez pour avoir une idée générale. Celui qui a écrit ceci loue les \'progrès\' réalisés par Luanga et l\'encourage à continuer d\'interroger ses \'invités.\'$b$bParallèlement, il est dit que \'les préparatifs à Skettis se déroulent comme prévu\' et qu\'ils seront \'bientôt prêts à récupérer leurs terres ancestrales.\'$b$bJe ne connais pas ce \'Skettis\' mentionné par l\'auteur, mais où qu\'il soit, il semble que les arakkoa y assemblent une armée ! Rokag doit être informé de cela immédiatement.') ON DUPLICATE KEY UPDATE RewardText='Je peux lire la plupart de ceci, juste assez pour avoir une idée générale. Celui qui a écrit ceci loue les \'progrès\' réalisés par Luanga et l\'encourage à continuer d\'interroger ses \'invités.\'$b$bParallèlement, il est dit que \'les préparatifs à Skettis se déroulent comme prévu\' et qu\'ils seront \'bientôt prêts à récupérer leurs terres ancestrales.\'$b$bJe ne connais pas ce \'Skettis\' mentionné par l\'auteur, mais où qu\'il soit, il semble que les arakkoa y assemblent une armée ! Rokag doit être informé de cela immédiatement.';
-- Quest 9986 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9986, 'frFR', 'C\'est bon de te revoir, $N. As-tu fait ce que je t\'ai demandé ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est bon de te revoir, $N. As-tu fait ce que je t\'ai demandé ?';
-- Quest 9987 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9987, 'frFR', 'Bienvenue de retour, $N. As-tu réglé les dirigeants arakkoa ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue de retour, $N. As-tu réglé les dirigeants arakkoa ?';
-- Quest 9988 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9988, 'frFR', 'Ceux-ci fonctionneront, même si je suis sûr que les hommes commenceront à se plaindre du manque de variété bientôt. Que la Lumière leur interdit d\'être identiques !$B$B<Ros\'eleth halète avec une fausse horreur.>$B$Oh, non, nous ne pouvons pas faire ça !') ON DUPLICATE KEY UPDATE RewardText='Ceux-ci fonctionneront, même si je suis sûr que les hommes commenceront à se plaindre du manque de variété bientôt. Que la Lumière leur interdit d\'être identiques !$B$B<Ros\'eleth halète avec une fausse horreur.>$B$Oh, non, nous ne pouvons pas faire ça !';
-- Quest 9989 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (9989, 'frFR', 'Ceux-ci fonctionneront bien. Plus vous les avez collectés auprès d\'individus différents, plus ils m\'aideront lorsque j\'essaierai de contacter les esprits arakkoa. Merci pour ton aide, $N.') ON DUPLICATE KEY UPDATE RewardText='Ceux-ci fonctionneront bien. Plus vous les avez collectés auprès d\'individus différents, plus ils m\'aideront lorsque j\'essaierai de contacter les esprits arakkoa. Merci pour ton aide, $N.';
