INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (9991, 'frFR', 'Jamais volé sur le dos d\'un drake du Néant, hein ?') ON DUPLICATE KEY UPDATE CompletionText='Jamais volé sur le dos d\'un drake du Néant, hein ?';
