INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10000, 'frFR', 'J\'étais sur le point d\'envoyer un message à Rokag recommandant une attaque, mais je vois que ce ne sera pas nécessaire.') ON DUPLICATE KEY UPDATE CompletionText='J\'étais sur le point d\'envoyer un message à Rokag recommandant une attaque, mais je vois que ce ne sera pas nécessaire.';
