INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10002, 'frFR', 'L\'activité dans le camp continue de s\'intensifier. Avez-vous accompli votre mission ?') ON DUPLICATE KEY UPDATE CompletionText='L\'activité dans le camp continue de s\'intensifier. Avez-vous accompli votre mission ?';
