INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10003, 'frFR', 'Plus nous leur permettons de faire des préparatifs, plus il sera difficile de les éradiquer. Avez-vous tué le lien ?') ON DUPLICATE KEY UPDATE CompletionText='Plus nous leur permettons de faire des préparatifs, plus il sera difficile de les éradiquer. Avez-vous tué le lien ?';
