-- Quest 10014 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10014, 'frFR', 'Bon travail !$B$BLaissez-moi voir ces feuilles de code. J\'ai une idée et elle pourrait être assez folle pour fonctionner !') ON DUPLICATE KEY UPDATE RewardText='Bon travail !$B$BLaissez-moi voir ces feuilles de code. J\'ai une idée et elle pourrait être assez folle pour fonctionner !';
-- Quest 10015 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10015, 'frFR', 'Tu as ces codes ? Tu as vu ce qui est arrivé aux druides à la Clairière de Cenarion.$B$BVeux-tu que cela arrive à la Citadelle de Stonebreaker ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as ces codes ? Tu as vu ce qui est arrivé aux druides à la Clairière de Cenarion.$B$BVeux-tu que cela arrive à la Citadelle de Stonebreaker ?';
