-- Quest 10018 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10018, 'frFR', 'As-tu réussi à trouver toutes les peaux dont j\'ai besoin ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à trouver toutes les peaux dont j\'ai besoin ?';
