INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10018, 'frFR', 'C\'est parfait, <name> ! Je n\'aurais pas pu demander mieux.') ON DUPLICATE KEY UPDATE RewardText='C\'est parfait, <name> ! Je n\'aurais pas pu demander mieux.';
-- Quest 10019 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10019, 'frFR', 'De nombreux réfugiés ont encore besoin de traitement pour leurs blessures empoisonnées. As-tu apporté plus de sacs de venin pour que je puisse les utiliser, $N ?') ON DUPLICATE KEY UPDATE CompletionText='De nombreux réfugiés ont encore besoin de traitement pour leurs blessures empoisonnées. As-tu apporté plus de sacs de venin pour que je puisse les utiliser, $N ?';
-- Quest 10019 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10019, 'frFR', 'Je vous remercie, <name>.  Les naaru ont étendu leur protection à ces âmes malheureuses ; ce serait dommage qu\'elles arrivent à Shattrath et périssent à cause de leurs blessures antérieures.') ON DUPLICATE KEY UPDATE RewardText='Je vous remercie, <name>.  Les naaru ont étendu leur protection à ces âmes malheureuses ; ce serait dommage qu\'elles arrivent à Shattrath et périssent à cause de leurs blessures antérieures.';

-- Quest 10020 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10020, 'frFR', 'As-tu obtenu le sang, $N$? Sans lui, Zahlia pourrait ne jamais revoir son fils.') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu le sang, $N$? Sans lui, Zahlia pourrait ne jamais revoir son fils.';
