INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10021, 'frFR', 'As-tu terminé ta tâche, $N$?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé ta tâche, $N$?';
-- Quest 10024 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10024, 'frFR', 'As-tu obtenu les yeux de basilique pour l\'élixir de Voren\'thal?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu les yeux de basilique pour l\'élixir de Voren\'thal?';
-- Quest 10025 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10025, 'frFR', 'Il faut beaucoup d\'yeux de basilique pour faire même une petite dose de l\'élixir de Voren\'thal. M\'en apporter davantage gagnerait certainement la faveur des Voyants.') ON DUPLICATE KEY UPDATE CompletionText='Il faut beaucoup d\'yeux de basilique pour faire même une petite dose de l\'élixir de Voren\'thal. M\'en apporter davantage gagnerait certainement la faveur des Voyants.';
-- Quest 10026 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10026, 'frFR', 'As-tu dégagé les chasseurs de distorsion des environs de la forteresse?') ON DUPLICATE KEY UPDATE CompletionText='As-tu dégagé les chasseurs de distorsion des environs de la forteresse?';
-- Quest 10027 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10027, 'frFR', 'Keb\'ezil veut savoir s\'il est sûr de lancer une boule de feu sans s\'embarrasser à nouveau.$B$B<Le démon fait quelques bruits de cliquetis et le sorcier se tourne vers lui.>$B$BNon, ce n\'était pas mon éclair d\'ombre! Ramène-le, petit lutin surdimensionné!') ON DUPLICATE KEY UPDATE CompletionText='Keb\'ezil veut savoir s\'il est sûr de lancer une boule de feu sans s\'embarrasser à nouveau.$B$B<Le démon fait quelques bruits de cliquetis et le sorcier se tourne vers lui.>$B$BNon, ce n\'était pas mon éclair d\'ombre! Ramène-le, petit lutin surdimensionné!';
-- Quest 10031 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10031, 'frFR', '$N$? Qu\'est-ce qui te ramène chez moi? As-tu livré les os des tourmentés à Ramdor comme je l\'ai demandé?') ON DUPLICATE KEY UPDATE CompletionText='$N$? Qu\'est-ce qui te ramène chez moi? As-tu livré les os des tourmentés à Ramdor comme je l\'ai demandé?';
-- Quest 10033 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10033, 'frFR', 'Je suppose que tu cherches aussi la récompense du briseur d\'os?') ON DUPLICATE KEY UPDATE CompletionText='Je suppose que tu cherches aussi la récompense du briseur d\'os?';

-- Quest 10034 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10034, 'frFR', 'Est-ce le sang de bonelasher que je sens sur tes mains ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce le sang de bonelasher que je sens sur tes mains ?';
-- Quest 10036 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10036, 'frFR', 'L\'as-tu tué ? Torgos est mort ?!$B$BTu as des preuves ?') ON DUPLICATE KEY UPDATE CompletionText='L\'as-tu tué ? Torgos est mort ?!$B$BTu as des preuves ?';
-- Quest 10036 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10036, 'frFR', 'Je vous remercie, <name>!  Vous avez vengé ma vengeance, et comme promis, vous serez récompensé!$B$BChoisissez-en un de ceux-ci et utilisez-le bien!') ON DUPLICATE KEY UPDATE RewardText='Je vous remercie, <name>!  Vous avez vengé ma vengeance, et comme promis, vous serez récompensé!$B$BChoisissez-en un de ceux-ci et utilisez-le bien!';
-- Quest 10040 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10040, 'frFR', 'Tu as parlé à tous d\'eux ? Qu\'ont-ils dit ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as parlé à tous d\'eux ? Qu\'ont-ils dit ?';
-- Quest 10041 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10041, 'frFR', 'Tu as parlé à tous d\'eux ? Qu\'ont-ils dit ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as parlé à tous d\'eux ? Qu\'ont-ils dit ?';
-- Quest 10042 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10042, 'frFR', 'Eh bien, qu\'as-tu découvert, $glad:lass;?') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, qu\'as-tu découvert, $glad:lass;?';
-- Quest 10048 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10048, 'frFR', 'Il semble que vous ayez tout ce dont nous avons besoin. Je serai prêt à commencer dans un instant.$B$BMaintenant, je ne peux pas garantir que je trouverai quelque chose d\'utile, mais j\'essaierai de scruter des informations relatives à l\'endroit où les arakkoa ont emmené Deirom.') ON DUPLICATE KEY UPDATE RewardText='Il semble que vous ayez tout ce dont nous avons besoin. Je serai prêt à commencer dans un instant.$B$BMaintenant, je ne peux pas garantir que je trouverai quelque chose d\'utile, mais j\'essaierai de scruter des informations relatives à l\'endroit où les arakkoa ont emmené Deirom.';
-- Quest 10049 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10049, 'frFR', 'Il semble que vous ayez tout ce dont nous avons besoin. Je serai prêt à commencer dans un instant.$B$BMaintenant, je ne peux pas garantir que je trouverai quelque chose d\'utile, mais j\'essaierai de scruter des informations relatives à l\'endroit où les arakkoa ont emmené Dugar.') ON DUPLICATE KEY UPDATE RewardText='Il semble que vous ayez tout ce dont nous avons besoin. Je serai prêt à commencer dans un instant.$B$BMaintenant, je ne peux pas garantir que je trouverai quelque chose d\'utile, mais j\'essaierai de scruter des informations relatives à l\'endroit où les arakkoa ont emmené Dugar.';

-- Quest 10050 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10050, 'frFR', 'Ce que je vous ai demandé est une chose terrible à demander à qui que ce soit. Mais ce que vous devez comprendre, c\'est que beaucoup d\'hommes ne s\'approcheront pas des ruines. Les souvenirs et la douleur sont trop récents, mais nous ne pouvons pas laisser les esprits continuer à errer.$B$BPlus ils persistent, plus ils perdent leurs liens restants avec leur vie passée et se livrent à la malveillance.') ON DUPLICATE KEY UPDATE CompletionText='Ce que je vous ai demandé est une chose terrible à demander à qui que ce soit. Mais ce que vous devez comprendre, c\'est que beaucoup d\'hommes ne s\'approcheront pas des ruines. Les souvenirs et la douleur sont trop récents, mais nous ne pouvons pas laisser les esprits continuer à errer.$B$BPlus ils persistent, plus ils perdent leurs liens restants avec leur vie passée et se livrent à la malveillance.';
-- Quest 10057 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10057, 'frFR', 'Avez-vous réussi à vaincre les officiers des ruines ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à vaincre les officiers des ruines ?';
-- Quest 10059 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10059, 'frFR', 'Des flèches de charbon épais montrent des troupes convergeant sur Thrallmar depuis trois camps de orcs fel. Vous avez déjà éliminé la branche occidentale des forces, mais il semble que les orcs de Zeth\'Gor préparent bien plus qu\'un simple raid.') ON DUPLICATE KEY UPDATE RewardText='Des flèches de charbon épais montrent des troupes convergeant sur Thrallmar depuis trois camps de orcs fel. Vous avez déjà éliminé la branche occidentale des forces, mais il semble que les orcs de Zeth\'Gor préparent bien plus qu\'un simple raid.';
-- Quest 10060 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10060, 'frFR', 'Je commençais à me demander si le calme qui s\'était abattu sur Zeth\'Gor était le prélude à une grande attaque. Il semble que mes craintes fussent fondées.$B$B') ON DUPLICATE KEY UPDATE RewardText='Je commençais à me demander si le calme qui s\'était abattu sur Zeth\'Gor était le prélude à une grande attaque. Il semble que mes craintes fussent fondées.$B$B';
-- Quest 10065 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10065, 'frFR', 'Avez-vous réussi à éliminer certains des ravageurs dans la zone ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à éliminer certains des ravageurs dans la zone ?';
-- Quest 10067 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10067, 'frFR', 'Avez-vous commencé à éliminer les esprits de l\'eau souillée ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous commencé à éliminer les esprits de l\'eau souillée ?';
-- Quest 10075 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10075, 'frFR', 'Cette base était le principal centre de recherche draenéen pour l\'étude des cristaux naaru.$B$BCe que nous avons découvert est une véritable mine d\'or de notes de recherche sur les cristaux de la montagne "diamant", Oshu\'gun. Il semble que tout dans cette région porte en lui une poudre résiduelle des cristaux d\'Oshu\'gun. Si vous trouvez de la poudre en explorant cette région, ramenez-la-moi et je vous récompenserai avec un jeton d\'appréciation que vous pourrez utiliser pour faire des achats auprès du quartier-maître.') ON DUPLICATE KEY UPDATE CompletionText='Cette base était le principal centre de recherche draenéen pour l\'étude des cristaux naaru.$B$BCe que nous avons découvert est une véritable mine d\'or de notes de recherche sur les cristaux de la montagne "diamant", Oshu\'gun. Il semble que tout dans cette région porte en lui une poudre résiduelle des cristaux d\'Oshu\'gun. Si vous trouvez de la poudre en explorant cette région, ramenez-la-moi et je vous récompenserai avec un jeton d\'appréciation que vous pourrez utiliser pour faire des achats auprès du quartier-maître.';
