-- Quest 10079 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10079, 'frFR', 'Dites-moi que les secousses sont terminées et que mes gars peuvent retourner au travail... s\'il vous plaît ?') ON DUPLICATE KEY UPDATE CompletionText='Dites-moi que les secousses sont terminées et que mes gars peuvent retourner au travail... s\'il vous plaît ?';
-- Quest 10082 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10082, 'frFR', 'Vous n\'avez pas besoin d\'une potion pour voir les esprits, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Vous n\'avez pas besoin d\'une potion pour voir les esprits, $N$.';
-- Quest 10088 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10088, 'frFR', 'Enfin ! Maintenant, je suppose que vous n\'êtes pas prêt à frapper quelques pions à la tête, ou cela coûtera-t-il plus cher ?') ON DUPLICATE KEY UPDATE RewardText='Enfin ! Maintenant, je suppose que vous n\'êtes pas prêt à frapper quelques pions à la tête, ou cela coûtera-t-il plus cher ?';
-- Quest 10091 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10091, 'frFR', 'Oui ? Que puis-je faire pour vous, $C$?') ON DUPLICATE KEY UPDATE CompletionText='Oui ? Que puis-je faire pour vous, $C$?';
-- Quest 10095 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10095, 'frFR', '$N$, vous apportez des nouvelles du Labyrinthe des Ombres ? Le danger y est-il enfin écarté ?') ON DUPLICATE KEY UPDATE CompletionText='$N$, vous apportez des nouvelles du Labyrinthe des Ombres ? Le danger y est-il enfin écarté ?';
-- Quest 10096 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10096, 'frFR', 'Quoi ? Retour si vite ? Comment s\'est-il passé ?') ON DUPLICATE KEY UPDATE CompletionText='Quoi ? Retour si vite ? Comment s\'est-il passé ?';

-- Quest 10097 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10097, 'frFR', 'L\'as-tu trouvée, $N? Était-elle toujours retenue dans les couloirs?') ON DUPLICATE KEY UPDATE CompletionText='L\'as-tu trouvée, $N? Était-elle toujours retenue dans les couloirs?';
-- Quest 10099 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10099, 'frFR', 'J\'ai presque peur de demander. Te voir sortir de la mine vivant signifie deux choses : soit tu as tué le salaud, soit tu as perdu ton courage. Alors, c\'est quoi?') ON DUPLICATE KEY UPDATE CompletionText='J\'ai presque peur de demander. Te voir sortir de la mine vivant signifie deux choses : soit tu as tué le salaud, soit tu as perdu ton courage. Alors, c\'est quoi?';
-- Quest 10100 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10100, 'frFR', 'Espérons qu\'éliminer leur surveillant fera paniquer les restes et qu\'ils se briseront. Ce devrait être un nettoyage facile pour mes gars, une fois que j\'aurai trouvé un moyen de les garder éveillés, c\'est-à-dire.') ON DUPLICATE KEY UPDATE RewardText='Espérons qu\'éliminer leur surveillant fera paniquer les restes et qu\'ils se briseront. Ce devrait être un nettoyage facile pour mes gars, une fois que j\'aurai trouvé un moyen de les garder éveillés, c\'est-à-dire.';
-- Quest 10106 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10106, 'frFR', '$N, reviens-moi quand tu auras aidé à capturer chacun des forts!') ON DUPLICATE KEY UPDATE CompletionText='$N, reviens-moi quand tu auras aidé à capturer chacun des forts!';
-- Quest 10110 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10110, 'frFR', 'Reviens-moi après avoir aidé à capturer chaque fort!') ON DUPLICATE KEY UPDATE CompletionText='Reviens-moi après avoir aidé à capturer chaque fort!';
-- Quest 10115 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10115, 'frFR', 'As-tu vu ce que les Daggerfen ont fait? Maintenant tu comprends pourquoi nous devons les isoler des autres Perdus.') ON DUPLICATE KEY UPDATE CompletionText='As-tu vu ce que les Daggerfen ont fait? Maintenant tu comprends pourquoi nous devons les isoler des autres Perdus.';
-- Quest 10118 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10118, 'frFR', 'La seule chose que les Daggerfen comprennent, c\'est l\'action rapide et brutale. Ils devraient savoir que nous ne leur laisserons pas faire.') ON DUPLICATE KEY UPDATE CompletionText='La seule chose que les Daggerfen comprennent, c\'est l\'action rapide et brutale. Ils devraient savoir que nous ne leur laisserons pas faire.';
-- Quest 10121 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10121, 'frFR', 'Sans aucun doute, tu as vu les guerriers de la Légion parsemer le paysage lors de ta fuite du Portail Sombre. Bien que nous les ayons vaincus lors de la Bataille du Mont Hyjal il y a environ cinq ans, les démons maudits ne cessent juste de revenir pour plus. Si c\'est un défi qu\'ils désirent, alors la Horde répondra en sorte!$B$BNous, les orcs, avons plus qu\'un score à régler avec la Légion. Et toi, <name>? Dois-je te parler de notre ennemi?') ON DUPLICATE KEY UPDATE RewardText='Sans aucun doute, tu as vu les guerriers de la Légion parsemer le paysage lors de ta fuite du Portail Sombre. Bien que nous les ayons vaincus lors de la Bataille du Mont Hyjal il y a environ cinq ans, les démons maudits ne cessent juste de revenir pour plus. Si c\'est un défi qu\'ils désirent, alors la Horde répondra en sorte!$B$BNous, les orcs, avons plus qu\'un score à régler avec la Légion. Et toi, <name>? Dois-je te parler de notre ennemi?';

-- Quest 10123 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10123, 'frFR', 'Thrallmar est en sécurité tant que l\'arcaniste et ses mages de sang restent en première ligne.') ON DUPLICATE KEY UPDATE CompletionText='Thrallmar est en sécurité tant que l\'arcaniste et ses mages de sang restent en première ligne.';
-- Quest 10136 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10136, 'frFR', 'Le destin appelle, $N. Arazzius le Cruel a échappé à la justice assez longtemps. Que sa mort soit un message à tous ceux qui s\'opposeraient à la Horde. Vous êtes la prochaine.') ON DUPLICATE KEY UPDATE CompletionText='Le destin appelle, $N. Arazzius le Cruel a échappé à la justice assez longtemps. Que sa mort soit un message à tous ceux qui s\'opposeraient à la Horde. Vous êtes la prochaine.';
-- Quest 10138 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10138, 'frFR', 'Bien joué, $N. Ces ordres devraient enfin révéler l\'identité du cerveau derrière ces attaques.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N. Ces ordres devraient enfin révéler l\'identité du cerveau derrière ces attaques.';
-- Quest 10142 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10142, 'frFR', 'Honor Hold est en sécurité tant que les archers gardent nos cieux.') ON DUPLICATE KEY UPDATE CompletionText='Honor Hold est en sécurité tant que les archers gardent nos cieux.';
-- Quest 10159 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10159, 'frFR', 'Comment se passe votre tentative de dégager la colline de Thornfang ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe votre tentative de dégager la colline de Thornfang ?';
-- Quest 10164 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10164, 'frFR', 'Tu l\'as fait, <name>! Les esprits sont libérés !$B$BBien que je ne sois pas une manifestation matérielle, je suis toujours en mesure de vous récompenser avec des objets du monde des esprits. Utilisez-les avec prudence car de tels objets sont souvent volatils et peuvent causer de graves dommages à leur utilisateur.') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait, <name>! Les esprits sont libérés !$B$BBien que je ne sois pas une manifestation matérielle, je suis toujours en mesure de vous récompenser avec des objets du monde des esprits. Utilisez-les avec prudence car de tels objets sont souvent volatils et peuvent causer de graves dommages à leur utilisateur.';
-- Quest 10169 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10169, 'frFR', 'L\'odeur d\'herbes et d\'épices emplit l\'air autour du pot.') ON DUPLICATE KEY UPDATE CompletionText='L\'odeur d\'herbes et d\'épices emplit l\'air autour du pot.';
-- Quest 10169 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10169, 'frFR', 'Les tireurs d\'Aldor semblent distraits par leur exercice, vous laissant amplement le temps de mettre le contenu du flacon dans le ragoût.') ON DUPLICATE KEY UPDATE RewardText='Les tireurs d\'Aldor semblent distraits par leur exercice, vous laissant amplement le temps de mettre le contenu du flacon dans le ragoût.';

-- Quest 10183 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10183, 'frFR', 'Occupé, occupé. Pas de temps à perdre ! Il y a un vaisseau spatial à construire !$B$BQue voulez-vous ?') ON DUPLICATE KEY UPDATE CompletionText='Occupé, occupé. Pas de temps à perdre ! Il y a un vaisseau spatial à construire !$B$BQue voulez-vous ?';
-- Quest 10184 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10184, 'frFR', 'Cela me fait mal de savoir qu\'il y a si peu à faire pour nos camarades.') ON DUPLICATE KEY UPDATE CompletionText='Cela me fait mal de savoir qu\'il y a si peu à faire pour nos camarades.';
-- Quest 10185 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10185, 'frFR', 'Avez-vous réussi à éliminer quelques créatures de mana des ruines du village ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à éliminer quelques créatures de mana des ruines du village ?';
-- Quest 10189 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10189, 'frFR', 'Avez-vous obtenu les objets que je vous ai demandés, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous obtenu les objets que je vous ai demandés, $N ?';
-- Quest 10191 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10191, 'frFR', 'De retour si vite?$B$BEst-ce que tout va bien avec le Maxx A. Million Mk. V ?!') ON DUPLICATE KEY UPDATE CompletionText='De retour si vite?$B$BEst-ce que tout va bien avec le Maxx A. Million Mk. V ?!';
-- Quest 10193 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10193, 'frFR', 'Comment ça va, $N ? Des nouvelles ? Qu\'avez-vous fait pour moi récemment ?') ON DUPLICATE KEY UPDATE CompletionText='Comment ça va, $N ? Des nouvelles ? Qu\'avez-vous fait pour moi récemment ?';
-- Quest 10195 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10195, 'frFR', 'Ce sont super ! Ne soyez pas surpris si vous voyez un tas d\'hommes en chapeaux à plumes très bientôt !') ON DUPLICATE KEY UPDATE RewardText='Ce sont super ! Ne soyez pas surpris si vous voyez un tas d\'hommes en chapeaux à plumes très bientôt !';
-- Quest 10196 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10196, 'frFR', 'Merci, $N. Je vais les mettre à profit.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Je vais les mettre à profit.';

-- Quest 10198 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10198, 'frFR', 'Comment se passe l\'espionnage, $N? Tu ferais mieux de te dépêcher. Je m\'impatiente ici.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe l\'espionnage, $N? Tu ferais mieux de te dépêcher. Je m\'impatiente ici.';
-- Quest 10198 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10198, 'frFR', 'Manaforge Duro est en difficulté ?  Je suis sûr que Thalodien adorera entendre la nouvelle.  Terminons le travail ici d\'abord.') ON DUPLICATE KEY UPDATE RewardText='Manaforge Duro est en difficulté ?  Je suis sûr que Thalodien adorera entendre la nouvelle.  Terminons le travail ici d\'abord.';
-- Quest 10201 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10201, 'frFR', 'Eh bien, as-tu les résultats des tests ?') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, as-tu les résultats des tests ?';
-- Quest 10204 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10204, 'frFR', 'As-tu enquêté sur les gemmes de sang utilisées par les magisters de Sunfury, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu enquêté sur les gemmes de sang utilisées par les magisters de Sunfury, $N?';
-- Quest 10205 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10205, 'frFR', 'C\'est fini alors ? Warp-Raider Nesaad est mort ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est fini alors ? Warp-Raider Nesaad est mort ?';
-- Quest 10208 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10208, 'frFR', 'La Légion ne sera pas préparée à la surprise que tu as pour eux, hein $N?') ON DUPLICATE KEY UPDATE CompletionText='La Légion ne sera pas préparée à la surprise que tu as pour eux, hein $N?';
-- Quest 10211 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10211, 'frFR', 'Les histoires des hommes sont éphémères, $N. Les histoires des villes durent bien des années.') ON DUPLICATE KEY UPDATE CompletionText='Les histoires des hommes sont éphémères, $N. Les histoires des villes durent bien des années.';
-- Quest 10216 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10216, 'frFR', 'Cet appareil a plus d\'une douzaine de boutons, aucun d\'entre eux ne te semble familier.') ON DUPLICATE KEY UPDATE CompletionText='Cet appareil a plus d\'une douzaine de boutons, aucun d\'entre eux ne te semble familier.';

-- Quest 10220 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10220, 'frFR', 'As-tu enseigné aux Inébranlables les conséquences de défier les Abandonnés ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu enseigné aux Inébranlables les conséquences de défier les Abandonnés ?';
-- Quest 10222 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10222, 'frFR', 'C\'est fait, $N ? As-tu vengé les morts du Village de Kirin\'Var ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est fait, $N ? As-tu vengé les morts du Village de Kirin\'Var ?';
-- Quest 10223 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10223, 'frFR', 'As-tu terminé la tâche, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé la tâche, $N ?';
-- Quest 10232 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10232, 'frFR', 'J\'espère bien que tu es prêt pour ce combat avec la Légion Ardente.$B$BIl n\'y a pas beaucoup de choses que je déteste plus que ceux qui rompent un accord, ou <toux> les gnomes, mais les démons en sont certainement un !') ON DUPLICATE KEY UPDATE CompletionText='J\'espère bien que tu es prêt pour ce combat avec la Légion Ardente.$B$BIl n\'y a pas beaucoup de choses que je déteste plus que ceux qui rompent un accord, ou <toux> les gnomes, mais les démons en sont certainement un !';
-- Quest 10233 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10233, 'frFR', 'De la fumée s\'élève des fortifications de la Citadelle du Soleil-Fureur. Est-ce ton œuvre ?') ON DUPLICATE KEY UPDATE CompletionText='De la fumée s\'élève des fortifications de la Citadelle du Soleil-Fureur. Est-ce ton œuvre ?';
-- Quest 10238 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10238, 'frFR', 'As-tu encore sauvé mes pions ? Dépêche-toi, j\'ai peur qu\'ils soient mangés et qu\'ils ne soient probablement pas très bons. Si ils ont un goût vraiment mauvais, les orcs fêles pourraient devenir vraiment en colère contre moi.') ON DUPLICATE KEY UPDATE CompletionText='As-tu encore sauvé mes pions ? Dépêche-toi, j\'ai peur qu\'ils soient mangés et qu\'ils ne soient probablement pas très bons. Si ils ont un goût vraiment mauvais, les orcs fêles pourraient devenir vraiment en colère contre moi.';
-- Quest 10241 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10241, 'frFR', 'As-tu terminé ta tâche, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé ta tâche, $N ?';
-- Quest 10243 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10243, 'frFR', 'Les symboles défilant devant toi semblent étrangers et incompréhensibles.') ON DUPLICATE KEY UPDATE CompletionText='Les symboles défilant devant toi semblent étrangers et incompréhensibles.';

-- Quest 10245 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10245, 'frFR', 'Montrons ce que tu nous as apporté, $N.') ON DUPLICATE KEY UPDATE CompletionText='Montrons ce que tu nous as apporté, $N.';
-- Quest 10246 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10246, 'frFR', 'As-tu terminé ta tâche, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé ta tâche, $N?';
-- Quest 10249 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10249, 'frFR', '<name>ü!  Ou, je devrais dire Technicien Junior de 1ère Classe <name>ü?!  Oh diable, je me prends pour qui?  Sauter un grade n\'est pas une récompense suffisante pour ce que tu as fait.  Je vais te faire mon officier de première classe!$B$BTu nous as sauvés tous, et plus important encore le X-52 Nether-Rocket!  Je pourrais juste t\'embrasser... mais je ne le ferai pas.$B$BAu lieu de cela, laisse-moi te présenter la gratitude d\'Area 52.  Choisis ce que tu veux!') ON DUPLICATE KEY UPDATE RewardText='<name>ü!  Ou, je devrais dire Technicien Junior de 1ère Classe <name>ü?!  Oh diable, je me prends pour qui?  Sauter un grade n\'est pas une récompense suffisante pour ce que tu as fait.  Je vais te faire mon officier de première classe!$B$BTu nous as sauvés tous, et plus important encore le X-52 Nether-Rocket!  Je pourrais juste t\'embrasser... mais je ne le ferai pas.$B$BAu lieu de cela, laisse-moi te présenter la gratitude d\'Area 52.  Choisis ce que tu veux!';
-- Quest 10259 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10259, 'frFR', 'Merci, $N. Au milieu du chaos de la bataille, les héros brillent contre l\'obscurité. Ta lumière brille vrai!') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Au milieu du chaos de la bataille, les héros brillent contre l\'obscurité. Ta lumière brille vrai!';
-- Quest 10263 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10263, 'frFR', 'Bonjour, $R.$B$BTu ne serais pas disponible pour une mission de récupération d\'une importance capitale?') ON DUPLICATE KEY UPDATE RewardText='Bonjour, $R.$B$BTu ne serais pas disponible pour une mission de récupération d\'une importance capitale?';
