INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10270, 'frFR', 'Es-tu prêt à discuter d\'affaires maintenant, $N?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu prêt à discuter d\'affaires maintenant, $N?';
-- Quest 10270 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10270, 'frFR', 'Cette cellule d\'énergie devrait tenir pour nos besoins. Une fois que l\'argent commencera à rentrer, nous l\'améliorerons encore plus.$B$BAssez avec ces choses. Chaque moment passé à discuter se traduit par une perte de profit.') ON DUPLICATE KEY UPDATE RewardText='Cette cellule d\'énergie devrait tenir pour nos besoins. Une fois que l\'argent commencera à rentrer, nous l\'améliorerons encore plus.$B$BAssez avec ces choses. Chaque moment passé à discuter se traduit par une perte de profit.';

-- Quest 10271 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10271, 'frFR', 'Je suis certain que vous avez beaucoup de questions, toutes seront répondues en temps voulu.') ON DUPLICATE KEY UPDATE CompletionText='Je suis certain que vous avez beaucoup de questions, toutes seront répondues en temps voulu.';
-- Quest 10272 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10272, 'frFR', 'Avez-vous réussi à ramasser les œufs ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à ramasser les œufs ?';
-- Quest 10273 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10273, 'frFR', 'Ce Marid est un imbécile, ou je dirais, l\'était.') ON DUPLICATE KEY UPDATE CompletionText='Ce Marid est un imbécile, ou je dirais, l\'était.';
-- Quest 10274 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10274, 'frFR', 'Avez-vous défié et vaincu Veraku ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous défié et vaincu Veraku ?';
-- Quest 10276 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10276, 'frFR', 'Bonjour à nouveau, mon ami. Comment se passent vos efforts pour trouver le cristal ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour à nouveau, mon ami. Comment se passent vos efforts pour trouver le cristal ?';
-- Quest 10276 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10276, 'frFR', 'Au-delà de mes rêves les plus fous, je n\'aurais jamais pensé que vous pourriez récupérer le cristal !$B$Et ensuite me le donner !  Avez-vous une idée de sa puissance?$B$Votre désintéressement est inspirant et irréprochable, <name>!  Vous m\'avez beaucoup à faire réfléchir.') ON DUPLICATE KEY UPDATE RewardText='Au-delà de mes rêves les plus fous, je n\'aurais jamais pensé que vous pourriez récupérer le cristal !$B$Et ensuite me le donner !  Avez-vous une idée de sa puissance?$B$Votre désintéressement est inspirant et irréprochable, <name>!  Vous m\'avez beaucoup à faire réfléchir.';
-- Quest 10280 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10280, 'frFR', '<Le tintement musical du discours du naaru emplit votre esprit.>$B$Je sens que vous avez quelque chose de grande puissance avec vous, $R. Qu\'est-ce que vous m\'apportez ?') ON DUPLICATE KEY UPDATE CompletionText='<Le tintement musical du discours du naaru emplit votre esprit.>$B$Je sens que vous avez quelque chose de grande puissance avec vous, $R. Qu\'est-ce que vous m\'apportez ?';
-- Quest 10280 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10280, 'frFR', 'Vous avez récupéré le Chant de l\'Esprit !  C\'est le cristal ata\'mal que le Prophète Velen avait laissé derrière lui avec son peuple pour le garder en sécurité avant de partir en sa mission malheureuse vers l\'Exodar.$B$Ou bien qu\'il n\'avait pas prévu qu\'il tombe entre les mains de la Légion Ardente, même pour un court instant.$B$Ou peut-être qu\'il l\'a prévu ?  Il se peut qu\'il ait tout prévu, et l\'ait laissé là pour que vous récupériez le cristal et me le livriez ici?$B$Je sens que c\'est la vérité.  Vous êtes un grand héros de votre peuple, <name>!') ON DUPLICATE KEY UPDATE RewardText='Vous avez récupéré le Chant de l\'Esprit !  C\'est le cristal ata\'mal que le Prophète Velen avait laissé derrière lui avec son peuple pour le garder en sécurité avant de partir en sa mission malheureuse vers l\'Exodar.$B$Ou bien qu\'il n\'avait pas prévu qu\'il tombe entre les mains de la Légion Ardente, même pour un court instant.$B$Ou peut-être qu\'il l\'a prévu ?  Il se peut qu\'il ait tout prévu, et l\'ait laissé là pour que vous récupériez le cristal et me le livriez ici?$B$Je sens que c\'est la vérité.  Vous êtes un grand héros de votre peuple, <name>!';

-- Quest 10291 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10291, 'frFR', 'Nous avons déjà perdu de nombreux guerriers courageux dans ce désert maudit. Je n\'ai guère d\'intérêt à envoyer plus de recrues non testées au massacre.$B$B$GNazgrel vous fixe sévèrement à travers son masque de loup déchiré>$B<br :>Cependant, si le Général Krakork vous a envoyé chez moi, il a dû voir quelque chose en vous. Qu\'en dites-vous, <name? Allez-vous servir votre chef de guerre avec honneur ?') ON DUPLICATE KEY UPDATE RewardText='Nous avons déjà perdu de nombreux guerriers courageux dans ce désert maudit. Je n\'ai guère d\'intérêt à envoyer plus de recrues non testées au massacre.$B$B$GNazgrel vous fixe sévèrement à travers son masque de loup déchiré>$B<br :>Cependant, si le Général Krakork vous a envoyé chez moi, il a dû voir quelque chose en vous. Qu\'en dites-vous, <name? Allez-vous servir votre chef de guerre avec honneur ?';
-- Quest 10292 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10292, 'frFR', '<Zuben Elgenubi affiche ce qui pourrait être un sourire éthéré.>$B$BI j\'ai promis de n\'utiliser cette puissance de feu incroyable qu\'à bon escient. Au profit de ma marge bénéficiaire, c\'est-à-dire.') ON DUPLICATE KEY UPDATE RewardText='<Zuben Elgenubi affiche ce qui pourrait être un sourire éthéré.>$B$BI j\'ai promis de n\'utiliser cette puissance de feu incroyable qu\'à bon escient. Au profit de ma marge bénéficiaire, c\'est-à-dire.';
-- Quest 10297 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10297, 'frFR', 'Vous ne pouvez utiliser qu\'un balise chronologique par poche de temps.') ON DUPLICATE KEY UPDATE CompletionText='Vous ne pouvez utiliser qu\'un balise chronologique par poche de temps.';
