INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10299, 'frFR', 'Avez-vous réussi votre tâche, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi votre tâche, $N?';
-- Quest 10299 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10299, 'frFR', 'La Lumière vous sourit, <name>.  Nous avons tous prié pour votre succès.') ON DUPLICATE KEY UPDATE RewardText='La Lumière vous sourit, <name>.  Nous avons tous prié pour votre succès.';
-- Quest 10302 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10302, 'frFR', 'Je travaille sur une solution que je pense pouvoir être efficace avec les créatures étranges. J\'ai juste besoin de plus de temps.') ON DUPLICATE KEY UPDATE CompletionText='Je travaille sur une solution que je pense pouvoir être efficace avec les créatures étranges. J\'ai juste besoin de plus de temps.';
-- Quest 10303 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10303, 'frFR', 'Il y en a trop... Nous devons les réduire ou les survivants n\'auront aucune chance contre eux.') ON DUPLICATE KEY UPDATE CompletionText='Il y en a trop... Nous devons les réduire ou les survivants n\'auront aucune chance contre eux.';
-- Quest 10304 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10304, 'frFR', '<name>, c\'est ça ? J\'ai entendu de bonnes choses sur vous et le travail que vous avez accompli en peu de temps depuis votre arrivée.$B$BNous aurons certainement besoin de votre aide pour que les choses redeviennent normales. Zhanaa, là-bas, pourrait aussi avoir besoin de votre aide, je suis sûr.') ON DUPLICATE KEY UPDATE RewardText='<name>, c\'est ça ? J\'ai entendu de bonnes choses sur vous et le travail que vous avez accompli en peu de temps depuis votre arrivée.$B$BNous aurons certainement besoin de votre aide pour que les choses redeviennent normales. Zhanaa, là-bas, pourrait aussi avoir besoin de votre aide, je suis sûr.';

-- Quest 10308 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10308, 'frFR', 'Le Consortium s\'intéresse vivement à l\'éradication de tous les rebelles Zaxxis à la Tasque au sud.$B$B$C, si vous souhaitez vous faire plus bien voir auprès de nous, retournez là-bas et ramenez plus de leurs insignes d\'affiliation.') ON DUPLICATE KEY UPDATE CompletionText='Le Consortium s\'intéresse vivement à l\'éradication de tous les rebelles Zaxxis à la Tasque au sud.$B$B$C, si vous souhaitez vous faire plus bien voir auprès de nous, retournez là-bas et ramenez plus de leurs insignes d\'affiliation.';
-- Quest 10308 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10308, 'frFR', 'Traîtres, tous !$B$BBon travail, <class>!  Si vous vous retrouvez là-bas à nouveau, je cherche toujours à ajouter à ma collection de leurs insignes !') ON DUPLICATE KEY UPDATE RewardText='Traîtres, tous !$B$BBon travail, <class>!  Si vous vous retrouvez là-bas à nouveau, je cherche toujours à ajouter à ma collection de leurs insignes !';
