INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10313, 'frFR', 'Avez-vous effectué les mesures que j\'ai demandées, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous effectué les mesures que j\'ai demandées, $N ?';
-- Quest 10314 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10314, 'frFR', '<Custodian Dieworth examine les restes.>$B$BL\'appareil que vous décrivez ressemble à un focus nécromantique... J\'aurais dû savoir que ce mauvais apprenti en viendrait à ce point. Je pensais que sa formation l\'empêcherait d\'aller aussi loin, mais je suppose qu\'il m\'a prouvé le contraire.') ON DUPLICATE KEY UPDATE RewardText='<Custodian Dieworth examine les restes.>$B$BL\'appareil que vous décrivez ressemble à un focus nécromantique... J\'aurais dû savoir que ce mauvais apprenti en viendrait à ce point. Je pensais que sa formation l\'empêcherait d\'aller aussi loin, mais je suppose qu\'il m\'a prouvé le contraire.';
-- Quest 10315 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10315, 'frFR', 'Combien de néthermanciens avez-vous réussi à abattre ?') ON DUPLICATE KEY UPDATE CompletionText='Combien de néthermanciens avez-vous réussi à abattre ?';
