INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10318, 'frFR', 'Quelles nouvelles apportez-vous de Manaforge Ara ? Avez-vous affaire au contremaître Sundown ?') ON DUPLICATE KEY UPDATE CompletionText='Quelles nouvelles apportez-vous de Manaforge Ara ? Avez-vous affaire au contremaître Sundown ?';
