INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10320, 'frFR', 'Avez-vous détruit le lich de ce misérable Naberius ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous détruit le lich de ce misérable Naberius ?';
