-- Quest 10321 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10321, 'frFR', 'Excellent travail.  Seuls deux forges de mana restent actifs.$B$BBientôt Kael\'thas sera coupé de sa principale source de pouvoir.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail.  Seuls deux forges de mana restent actifs.$B$BBientôt Kael\'thas sera coupé de sa principale source de pouvoir.';
