INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10322, 'frFR', 'Vous êtes béni par les naaru, <name>.  Votre dévouement à la cause ne passera pas inaperçu ni sans récompense.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes béni par les naaru, <name>.  Votre dévouement à la cause ne passera pas inaperçu ni sans récompense.';
