-- Quest 10323 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10323, 'frFR', 'La Légion Ardente ?  Allié à Kael\'thas Sunstrider?$B$BCeci est une nouvelle grave.  Cela explique beaucoup de ce que nous avons vu ici et à Shadowmoon.$B$BNous devons envoyer un message à Shattrath City immédiatement.') ON DUPLICATE KEY UPDATE RewardText='La Légion Ardente ?  Allié à Kael\'thas Sunstrider?$B$BCeci est une nouvelle grave.  Cela explique beaucoup de ce que nous avons vu ici et à Shadowmoon.$B$BNous devons envoyer un message à Shattrath City immédiatement.';
-- Quest 10325 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10325, 'frFR', 'Portez-vous des insignes de nos ennemis, $N?') ON DUPLICATE KEY UPDATE CompletionText='Portez-vous des insignes de nos ennemis, $N?';
-- Quest 10326 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10326, 'frFR', 'Portez-vous plus d\'insignes de nos ennemis, $C? La Légion Ardente continue d\'être une menace et nous continuons à les traquer partout où nous les trouvons.') ON DUPLICATE KEY UPDATE CompletionText='Portez-vous plus d\'insignes de nos ennemis, $C? La Légion Ardente continue d\'être une menace et nous continuons à les traquer partout où nous les trouvons.';
-- Quest 10326 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10326, 'frFR', 'Vous continuez à prouver votre valeur, <name>.  Combattez les ennemis de la Lumière où que vous les trouviez ; vos actions seront bien récompensées.') ON DUPLICATE KEY UPDATE RewardText='Vous continuez à prouver votre valeur, <name>.  Combattez les ennemis de la Lumière où que vous les trouviez ; vos actions seront bien récompensées.';

-- Quest 10327 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10327, 'frFR', 'Je prendrai toutes les marques restantes que vous pourriez avoir. Ne vous inquiétez pas ; vos actions seront dûment notées.') ON DUPLICATE KEY UPDATE CompletionText='Je prendrai toutes les marques restantes que vous pourriez avoir. Ne vous inquiétez pas ; vos actions seront dûment notées.';
