INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10328, 'frFR', 'Avez-vous eu de la chance avec les briefings de Manaforge Duro ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous eu de la chance avec les briefings de Manaforge Duro ?';
-- Quest 10328 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10328, 'frFR', 'Excellent travail, <name> !  Voyons ce que l\'on peut apprendre de ces briefings.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name> !  Voyons ce que l\'on peut apprendre de ces briefings.';
