-- Quest 10330 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10330, 'frFR', 'Nous avons entendu tout le vacarme et étions sur le point de partir.  Content de voir que vous n\'avez pas trop souffert.') ON DUPLICATE KEY UPDATE RewardText='Nous avons entendu tout le vacarme et étions sur le point de partir.  Content de voir que vous n\'avez pas trop souffert.';
-- Quest 10332 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10332, 'frFR', '<Il semble y avoir des larmes dans les yeux de l\'apprenti alors qu\'il parle.>$B$BAvez-vous... affaire au Maître Rhonsus ?') ON DUPLICATE KEY UPDATE CompletionText='<Il semble y avoir des larmes dans les yeux de l\'apprenti alors qu\'il parle.>$B$BAvez-vous... affaire au Maître Rhonsus ?';
-- Quest 10336 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10336, 'frFR', 'Avez-vous tué tous les démons aux Ruines de Farahlon ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous tué tous les démons aux Ruines de Farahlon ?';
-- Quest 10341 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10341, 'frFR', 'Avez-vous terminé votre tâche, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous terminé votre tâche, $N ?';

-- Quest 10350 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10350, 'frFR', 'Ah, tu es enfin arrivé. Je suis Behomat, et je t\'instruirai dans les arts des <class>. Ruada m\'a parlé de ton combat contre le ravageur, et je suis impressionné. Et j\'ai un cadeau pour toi.$B$BCe que nous avons récupéré des décombres de l\'Exodar est peu, et doit être donné à ceux qui sont les plus aptes. Veuillez prendre une arme adaptée à votre style de combat et la porter avec la connaissance que vous avez acquise.$B$BEt en parlant de styles de combat, il est temps que tu apprennes quelque chose de nouveau.') ON DUPLICATE KEY UPDATE RewardText='Ah, tu es enfin arrivé. Je suis Behomat, et je t\'instruirai dans les arts des <class>. Ruada m\'a parlé de ton combat contre le ravageur, et je suis impressionné. Et j\'ai un cadeau pour toi.$B$BCe que nous avons récupéré des décombres de l\'Exodar est peu, et doit être donné à ceux qui sont les plus aptes. Veuillez prendre une arme adaptée à votre style de combat et la porter avec la connaissance que vous avez acquise.$B$BEt en parlant de styles de combat, il est temps que tu apprennes quelque chose de nouveau.';
-- Quest 10352 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10352, 'frFR', 'Si tu as soixante pièces de tissu de laine sur toi et que tu es prêt à les donner, je peux les prendre maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Si tu as soixante pièces de tissu de laine sur toi et que tu es prêt à les donner, je peux les prendre maintenant.';
-- Quest 10352 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10352, 'frFR', 'Merveilleux ! Nous vous remercions pour votre généreuse donation, $N!') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Nous vous remercions pour votre généreuse donation, $N!';
-- Quest 10353 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10353, 'frFR', 'Statut, créature ? Quel est ton statut ?') ON DUPLICATE KEY UPDATE CompletionText='Statut, créature ? Quel est ton statut ?';
-- Quest 10354 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10354, 'frFR', 'Un cadeau bienveillant tel que de la soie, je peux ajouter, augmenterait certainement ton statut local dans la communauté ! Si tu as soixante pièces de tissu de soie sur toi et que tu es prêt à les donner, je peux les prendre maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Un cadeau bienveillant tel que de la soie, je peux ajouter, augmenterait certainement ton statut local dans la communauté ! Si tu as soixante pièces de tissu de soie sur toi et que tu es prêt à les donner, je peux les prendre maintenant.';
-- Quest 10354 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10354, 'frFR', 'Merveilleux ! Nous vous remercions pour votre généreuse donation, $N!') ON DUPLICATE KEY UPDATE RewardText='Merveilleux ! Nous vous remercions pour votre généreuse donation, $N!';
-- Quest 10356 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10356, 'frFR', 'Si tu as soixante pièces de tissu de mageweave sur toi et que tu es prêt à les donner, je peux les prendre maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Si tu as soixante pièces de tissu de mageweave sur toi et que tu es prêt à les donner, je peux les prendre maintenant.';
-- Quest 10356 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10356, 'frFR', 'Nous vous remercions pour votre donation, $N.') ON DUPLICATE KEY UPDATE RewardText='Nous vous remercions pour votre donation, $N.';

-- Quest 10357 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10357, 'frFR', '$n, vous avez été un contributeur formidable à notre collecte de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critiqueement bas - le tissu de rune. Nous en avons un besoin absolument désespéré, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le tissu de rune que vous pouvez offrir. Nous accepterons initialement un don unique de soixante, et nous verrons ensuite.') ON DUPLICATE KEY UPDATE CompletionText='$n, vous avez été un contributeur formidable à notre collecte de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critiqueement bas - le tissu de rune. Nous en avons un besoin absolument désespéré, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le tissu de rune que vous pouvez offrir. Nous accepterons initialement un don unique de soixante, et nous verrons ensuite.';
-- Quest 10357 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10357, 'frFR', 'Nos remerciements pour votre don.$B$BSi vous continuez à offrir du tissu de rune, je m\'assurerai que les dirigeants de l\'Exodar entendent parler de vos bonnes actions.') ON DUPLICATE KEY UPDATE RewardText='Nos remerciements pour votre don.$B$BSi vous continuez à offrir du tissu de rune, je m\'assurerai que les dirigeants de l\'Exodar entendent parler de vos bonnes actions.';
-- Quest 10358 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10358, 'frFR', 'Quand vous êtes prêt à remettre la pile de tissu de rune, je l\'accepterai.') ON DUPLICATE KEY UPDATE CompletionText='Quand vous êtes prêt à remettre la pile de tissu de rune, je l\'accepterai.';
-- Quest 10358 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10358, 'frFR', 'Nous vous remercions pour vos efforts continus, <name>.') ON DUPLICATE KEY UPDATE RewardText='Nous vous remercions pour vos efforts continus, <name>.';
-- Quest 10359 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10359, 'frFR', 'Si vous avez les soixante pièces de tissu de laine sur vous et êtes prêt à les donner, je peux les prendre maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Si vous avez les soixante pièces de tissu de laine sur vous et êtes prêt à les donner, je peux les prendre maintenant.';
-- Quest 10359 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10359, 'frFR', 'Ah, tissu de laine. Je veillerai à ce que les autres entendent parler de votre don.') ON DUPLICATE KEY UPDATE RewardText='Ah, tissu de laine. Je veillerai à ce que les autres entendent parler de votre don.';
-- Quest 10360 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10360, 'frFR', 'Un cadeau bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les donner, je peux les prendre maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Un cadeau bienveillant tel que de la soie, je peux ajouter, augmenterait certainement votre réputation locale au sein de la communauté ! Si vous avez les soixante pièces de tissu de soie sur vous et êtes prêt à les donner, je peux les prendre maintenant.';
-- Quest 10360 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10360, 'frFR', 'Ah, tissu de soie. Je veillerai à ce que les autres entendent parler de votre don.') ON DUPLICATE KEY UPDATE RewardText='Ah, tissu de soie. Je veillerai à ce que les autres entendent parler de votre don.';

-- Quest 10361 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10361, 'frFR', 'Si vous avez soixante pièces de tissu de mageweave sur vous et que vous êtes prêt à les donner, je peux les prendre de vous maintenant.') ON DUPLICATE KEY UPDATE CompletionText='Si vous avez soixante pièces de tissu de mageweave sur vous et que vous êtes prêt à les donner, je peux les prendre de vous maintenant.';
-- Quest 10361 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10361, 'frFR', 'Ah, tissu de mageweave. Je veillerai à ce que les autres entendent parler de votre don.') ON DUPLICATE KEY UPDATE RewardText='Ah, tissu de mageweave. Je veillerai à ce que les autres entendent parler de votre don.';
-- Quest 10362 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10362, 'frFR', '$n, vous avez été un contributeur formidable à notre collecte de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critiqueement bas - le runecloth. Nous en avons un besoin absolument désespéré, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez consacrer. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons.') ON DUPLICATE KEY UPDATE CompletionText='$n, vous avez été un contributeur formidable à notre collecte de tissus. Alors que nous nous efforçons de reconstituer nos réserves, un type de tissu reste critiqueement bas - le runecloth. Nous en avons un besoin absolument désespéré, et nous espérons que vous pourrez nous aider comme vous l\'avez fait par le passé !$b$bSi vous êtes disposé, veuillez m\'apporter le runecloth que vous pouvez consacrer. Nous accepterons initialement un don unique de soixante, et ensuite nous verrons.';
-- Quest 10362 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10362, 'frFR', 'Runecloth, hmm ? Eh bien, tant que vous continuerez à l\'apporter, je continuerai à chanter vos louanges aux habitants de Silvermoon.') ON DUPLICATE KEY UPDATE RewardText='Runecloth, hmm ? Eh bien, tant que vous continuerez à l\'apporter, je continuerai à chanter vos louanges aux habitants de Silvermoon.';
-- Quest 10363 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10363, 'frFR', 'Quand vous serez prêt à remettre la pile de runecloth, je l\'accepterai.') ON DUPLICATE KEY UPDATE CompletionText='Quand vous serez prêt à remettre la pile de runecloth, je l\'accepterai.';
-- Quest 10363 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10363, 'frFR', 'Eh bien, eh bien. Encore plus de runecloth.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, eh bien. Encore plus de runecloth.';
-- Quest 10365 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10365, 'frFR', 'Avez-vous accompli la tâche que je vous ai demandée, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous accompli la tâche que je vous ai demandée, $N ?';
-- Quest 10365 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10365, 'frFR', 'La Légion Ardente est complice de Kael ?  Hah !  Voren\'thal va se régaler avec cette information.$B$BPensez-vous que les milliers de pèlerins venus d\'Azeroth veulent s\'allier à la Légion Ardente ?  Je ne pense pas !') ON DUPLICATE KEY UPDATE RewardText='La Légion Ardente est complice de Kael ?  Hah !  Voren\'thal va se régaler avec cette information.$B$BPensez-vous que les milliers de pèlerins venus d\'Azeroth veulent s\'allier à la Légion Ardente ?  Je ne pense pas !';

-- Quest 10366 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10366, 'frFR', '$N, je vous attendais.$B$BTullas a chanté vos louanges et je suis impatient de continuer votre entraînement sur le chemin de la Lumière. Quand vous serez prêt à débloquer une plus grande compréhension de vos capacités et de votre puissance, je vous guiderai.') ON DUPLICATE KEY UPDATE RewardText='$N, je vous attendais.$B$BTullas a chanté vos louanges et je suis impatient de continuer votre entraînement sur le chemin de la Lumière. Quand vous serez prêt à débloquer une plus grande compréhension de vos capacités et de votre puissance, je vous guiderai.';
-- Quest 10371 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10371, 'frFR', 'Hah ! Alors vous avez entendu parler de mon défi, n\'est-ce pas?$B$BAsseyez-vous et écoutez. Prenez une gorgée, et savourez-la... parce que ce pourrait être votre dernière.') ON DUPLICATE KEY UPDATE RewardText='Hah ! Alors vous avez entendu parler de mon défi, n\'est-ce pas?$B$BAsseyez-vous et écoutez. Prenez une gorgée, et savourez-la... parce que ce pourrait être votre dernière.';
-- Quest 10372 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10372, 'frFR', 'Je commençais à me demander si Zelanis avait reçu cette lettre.$B$BBien. Mettons-nous au travail.') ON DUPLICATE KEY UPDATE RewardText='Je commençais à me demander si Zelanis avait reçu cette lettre.$B$BBien. Mettons-nous au travail.';
-- Quest 10373 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10373, 'frFR', 'Bienvenue dans les Terres de la Plague, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde d\'Ombre à notre est, et puis encore plus à l\'est de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Terres de la Plague.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue dans les Terres de la Plague, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde d\'Ombre à notre est, et puis encore plus à l\'est de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Terres de la Plague.';
-- Quest 10374 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10374, 'frFR', 'Bienvenue dans les Terres de la Plague, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde d\'Ombre à notre est, et puis encore plus à l\'est de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Terres de la Plague.') ON DUPLICATE KEY UPDATE RewardText='Bienvenue dans les Terres de la Plague, héros. C\'est une des frontières les plus dangereuses d\'Azeroth, avec la menace imminente de la Horde d\'Ombre à notre est, et puis encore plus à l\'est de là. Je suis heureux d\'apprendre que l\'appel du devoir et le service à la Horde n\'ont pas été ignorés par vous !$B$BSi vous êtes prêt à vous salir les mains, alors il y a beaucoup à faire pour les héros volontaires et capables ici, à la lisière des Terres de la Plague.';
-- Quest 10379 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10379, 'frFR', 'Ah. bien, un autre est arrivé. Le temps peut ne pas m\'importe, mais pour vous, il est essentiel. Il y a beaucoup de choses pour que vous appreniez et beaucoup de choses que je souhaite vous enseigner. Vous devez simplement prouver votre valeur. Faites cela, et vous serez grandement récompensé.') ON DUPLICATE KEY UPDATE RewardText='Ah. bien, un autre est arrivé. Le temps peut ne pas m\'importe, mais pour vous, il est essentiel. Il y a beaucoup de choses pour que vous appreniez et beaucoup de choses que je souhaite vous enseigner. Vous devez simplement prouver votre valeur. Faites cela, et vous serez grandement récompensé.';
-- Quest 10380 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10380, 'frFR', 'Avez-vous réussi votre tâche, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi votre tâche, $N?';
-- Quest 10383 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (10383, 'frFR', 'Bonjour. Vous devriez savoir ce qu\'il advient de ces lapins.') ON DUPLICATE KEY UPDATE `Details`='Bonjour. Vous devriez savoir ce qu\'il advient de ces lapins.';

-- Quest 10389 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10389, 'frFR', 'Eh bien, $C - les terrorfiends ont-ils été vaincus ?') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, $C - les terrorfiends ont-ils été vaincus ?';
-- Quest 10391 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10391, 'frFR', 'La Légion pourrait commencer à nous bombarder à tout moment, $N! Vous devez détruire ces maudits canons !') ON DUPLICATE KEY UPDATE CompletionText='La Légion pourrait commencer à nous bombarder à tout moment, $N! Vous devez détruire ces maudits canons !';
-- Quest 10392 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10392, 'frFR', 'Dépêchez-vous, $N. Chaque seconde où ce portail de distorsion reste ouvert, un autre démon maudit est introduit dans ce monde !') ON DUPLICATE KEY UPDATE CompletionText='Dépêchez-vous, $N. Chaque seconde où ce portail de distorsion reste ouvert, un autre démon maudit est introduit dans ce monde !';
-- Quest 10392 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10392, 'frFR', 'Louez les anciens, vous l\'avez fait, <name>! La Légion a subi une terrible défaite - et Thrallmar est à nouveau en sécurité. Ah, si j\'avais une centaine de guerriers avec votre cœur et votre ruse, cette terre brisée serait déjà domptée ! Je vous salue.') ON DUPLICATE KEY UPDATE RewardText='Louez les anciens, vous l\'avez fait, <name>! La Légion a subi une terrible défaite - et Thrallmar est à nouveau en sécurité. Ah, si j\'avais une centaine de guerriers avec votre cœur et votre ruse, cette terre brisée serait déjà domptée ! Je vous salue.';
-- Quest 10394 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10394, 'frFR', 'Ne me dites pas que vous avez des doutes, $C ? Si ils terminent la construction de ce Camp de Forge, vous aurez plus à craindre que ces Reavers de Fel ! Allez-y !') ON DUPLICATE KEY UPDATE CompletionText='Ne me dites pas que vous avez des doutes, $C ? Si ils terminent la construction de ce Camp de Forge, vous aurez plus à craindre que ces Reavers de Fel ! Allez-y !';
-- Quest 10395 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10395, 'frFR', 'Qu\'est-ce qu\'il y a, $C ? Je sens que vous avez trouvé quelque chose qui parle d\'une doom à venir.') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qu\'il y a, $C ? Je sens que vous avez trouvé quelque chose qui parle d\'une doom à venir.';
-- Quest 10396 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10396, 'frFR', 'La Légion pourrait commencer à bombarder la Horde à tout moment, $N! Vous devez détruire ces maudits canons !') ON DUPLICATE KEY UPDATE CompletionText='La Légion pourrait commencer à bombarder la Horde à tout moment, $N! Vous devez détruire ces maudits canons !';
-- Quest 10400 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10400, 'frFR', 'Dites-moi, $N, l\'acte est-il accompli ? Le Seigneur de la Légion a-t-il été vaincu ?') ON DUPLICATE KEY UPDATE CompletionText='Dites-moi, $N, l\'acte est-il accompli ? Le Seigneur de la Légion a-t-il été vaincu ?';

-- Quest 10404 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10404, 'frFR', 'Vous avez porté un coup puissant aux ennemis de la Lumière, $N$. Vous avez mes remerciements ainsi que ceux d\'Aldor.') ON DUPLICATE KEY UPDATE RewardText='Vous avez porté un coup puissant aux ennemis de la Lumière, $N$. Vous avez mes remerciements ainsi que ceux d\'Aldor.';
-- Quest 10407 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10407, 'frFR', 'Avez-vous obtenu la pierre de téléportation de Socrethar, $N$?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous obtenu la pierre de téléportation de Socrethar, $N$?';
-- Quest 10407 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10407, 'frFR', 'Votre dévouement à notre cause est exemplaire, <name>. Avec la pierre de téléportation de Socrethar en notre possession, il ne reste qu\'une chose à faire.') ON DUPLICATE KEY UPDATE RewardText='Votre dévouement à notre cause est exemplaire, <name>. Avec la pierre de téléportation de Socrethar en notre possession, il ne reste qu\'une chose à faire.';
-- Quest 10408 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10408, 'frFR', 'Est... Est-il vraiment mort ? Détruit ?') ON DUPLICATE KEY UPDATE CompletionText='Est... Est-il vraiment mort ? Détruit ?';
-- Quest 10413 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10413, 'frFR', 'Hmm, tu as l\'air un peu sale... Qu\'est-ce que tu t\'es mijoté ?') ON DUPLICATE KEY UPDATE CompletionText='Hmm, tu as l\'air un peu sale... Qu\'est-ce que tu t\'es mijoté ?';
-- Quest 10413 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10413, 'frFR', 'QUOI!? Tu t\'es affronté à une horreur du vide ? Et tu as survécu ?! Incroyable!$B$BCet échantillon vaut son pesant d\'or. Une trouvaille pareille mérite une récompense.') ON DUPLICATE KEY UPDATE RewardText='QUOI!? Tu t\'es affronté à une horreur du vide ? Et tu as survécu ?! Incroyable!$B$BCet échantillon vaut son pesant d\'or. Une trouvaille pareille mérite une récompense.';
-- Quest 10414 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10414, 'frFR', 'Même la plus petite contribution à notre cause est notée, $N$. Nos ennemis sont nombreux, mais nous triompherons !') ON DUPLICATE KEY UPDATE CompletionText='Même la plus petite contribution à notre cause est notée, $N$. Nos ennemis sont nombreux, mais nous triompherons !';
-- Quest 10415 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10415, 'frFR', 'Qu\'as-tu fait pour nous récemment, $N$? La guerre contre Kael\'thas ne va pas se battre toute seule, tu sais ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'as-tu fait pour nous récemment, $N$? La guerre contre Kael\'thas ne va pas se battre toute seule, tu sais ?';

-- Quest 10415 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10415, 'frFR', 'Tous ceux qui s\'opposent à nous seront écrasés !$B$B<Cette quête peut être répétée jusqu\'à la réputation Honoré.>') ON DUPLICATE KEY UPDATE RewardText='Tous ceux qui s\'opposent à nous seront écrasés !$B$B<Cette quête peut être répétée jusqu\'à la réputation Honoré.>';
-- Quest 10416 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10416, 'frFR', 'As-tu obtenu un tome arcanique, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu un tome arcanique, $N?';
-- Quest 10418 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10418, 'frFR', 'As-tu mis les créatures hors de leur souffrance ? Ne vous méprenez pas, je suis vraiment un amoureux des animaux, mais pas quand les animaux mordent la main qui les nourrit et les abrite.') ON DUPLICATE KEY UPDATE CompletionText='As-tu mis les créatures hors de leur souffrance ? Ne vous méprenez pas, je suis vraiment un amoureux des animaux, mais pas quand les animaux mordent la main qui les nourrit et les abrite.';
-- Quest 10419 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10419, 'frFR', 'As-tu obtenu d\'autres tomes arcaniques, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu d\'autres tomes arcaniques, $N?';
-- Quest 10419 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10419, 'frFR', 'Le pouvoir contenu dans ce tome est immense.  Pourtant, il peut être facilement condensé en une seule rune par celui qui a un esprit clair.') ON DUPLICATE KEY UPDATE RewardText='Le pouvoir contenu dans ce tome est immense.  Pourtant, il peut être facilement condensé en une seule rune par celui qui a un esprit clair.';
-- Quest 10421 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10421, 'frFR', 'Es-tu tombé sur des armements démoniaques récemment ? Laisse la Lumière faire son œuvre, $N. Ne laisse pas ces objets maudits subsister dans ce monde.') ON DUPLICATE KEY UPDATE CompletionText='Es-tu tombé sur des armements démoniaques récemment ? Laisse la Lumière faire son œuvre, $N. Ne laisse pas ces objets maudits subsister dans ce monde.';
-- Quest 10436 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10436, 'frFR', 'As-tu nettoyé la zone d\'essai ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu nettoyé la zone d\'essai ?';
-- Quest 10446 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10446, 'frFR', 'Le Lieutenant Meridian nous tient au courant de la situation au Point de Flamewing. Tout va bien ?') ON DUPLICATE KEY UPDATE CompletionText='Le Lieutenant Meridian nous tient au courant de la situation au Point de Flamewing. Tout va bien ?';

-- Quest 10447 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10447, 'frFR', 'Le sergent Chawni nous tient au courant de la situation à Firewing Point. Tout va bien ?') ON DUPLICATE KEY UPDATE CompletionText='Le sergent Chawni nous tient au courant de la situation à Firewing Point. Tout va bien ?';
-- Quest 10450 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10450, 'frFR', 'Avez-vous affronté les mâcheurs d\'os, $N. J\'espère que leur sang a été versé en grande quantité !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous affronté les mâcheurs d\'os, $N. J\'espère que leur sang a été versé en grande quantité !';
-- Quest 10451 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10451, 'frFR', 'Louez la Mère Terre. Je suis certain que Wilda trouvera son chemin pour rentrer. Veuillez accepter ceci comme un signe de notre appréciation.') ON DUPLICATE KEY UPDATE RewardText='Louez la Mère Terre. Je suis certain que Wilda trouvera son chemin pour rentrer. Veuillez accepter ceci comme un signe de notre appréciation.';
-- Quest 10455 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10455, 'frFR', 'N\'ai-je pas dit la vérité ? Les lynx des bosquets sont devenus une menace non seulement pour ceux qui empruntent le chemin ici, mais aussi pour Sylvanaar elle-même.$B$BLeur mort est regrettable, mais le but de notre création du Bosquet Vivant est que Sylvanaar puisse être entourée d\'une région défensive de beauté et de tranquillité naturelle.') ON DUPLICATE KEY UPDATE CompletionText='N\'ai-je pas dit la vérité ? Les lynx des bosquets sont devenus une menace non seulement pour ceux qui empruntent le chemin ici, mais aussi pour Sylvanaar elle-même.$B$BLeur mort est regrettable, mais le but de notre création du Bosquet Vivant est que Sylvanaar puisse être entourée d\'une région défensive de beauté et de tranquillité naturelle.';
-- Quest 10460 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10460, 'frFR', 'Êtes-vous sûr de vouloir prendre ce chemin, $N? Ce n\'est pas une décision que vous devriez prendre à la légère.$B$BCe anneau est imprégné d\'une goutte du Puits d\'Éternité. Il grandira en puissance à mesure que vous vous prouverez à l\'Échelle des Sables.') ON DUPLICATE KEY UPDATE RewardText='Êtes-vous sûr de vouloir prendre ce chemin, $N? Ce n\'est pas une décision que vous devriez prendre à la légère.$B$BCe anneau est imprégné d\'une goutte du Puits d\'Éternité. Il grandira en puissance à mesure que vous vous prouverez à l\'Échelle des Sables.';
-- Quest 10461 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10461, 'frFR', 'Êtes-vous sûr de vouloir prendre ce chemin,$N? Ce n\'est pas une décision que vous devriez prendre à la légère.$B$BCe anneau est imprégné d\'une goutte du Puits d\'Éternité. Il grandira EN puissance à mesure que vous vous prouverez à l\'Échelle des Sables.') ON DUPLICATE KEY UPDATE RewardText='Êtes-vous sûr de vouloir prendre ce chemin,$N? Ce n\'est pas une décision que vous devriez prendre à la légère.$B$BCe anneau est imprégné d\'une goutte du Puits d\'Éternité. Il grandira EN puissance à mesure que vous vous prouverez à l\'Échelle des Sables.';
