-- Quest 10465 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10465, 'frFR', 'Vous continuez à nous servir bien, $N.') ON DUPLICATE KEY UPDATE CompletionText='Vous continuez à nous servir bien, $N.';
-- Quest 10465 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10465, 'frFR', 'Vous avez prouvé votre valeur, $R.  Jusqu\'à un certain point, au moins.$B$BLa faveur de la compagne principale de Nozdormu n\'est pas obtenue facilement.') ON DUPLICATE KEY UPDATE RewardText='Vous avez prouvé votre valeur, $R.  Jusqu\'à un certain point, au moins.$B$BLa faveur de la compagne principale de Nozdormu n\'est pas obtenue facilement.';
