INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10469, 'frFR', 'Vous êtes un allié digne de ce nom.  Plus vous grandissez en puissance, plus grandit le lien d\'éternité !') ON DUPLICATE KEY UPDATE RewardText='Vous êtes un allié digne de ce nom.  Plus vous grandissez en puissance, plus grandit le lien d\'éternité !';
