-- Quest 10471 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10471, 'frFR', 'Tu es un allié digne.  Plus tu grandis en puissance, plus grandit la bande de l\'éternité !') ON DUPLICATE KEY UPDATE RewardText='Tu es un allié digne.  Plus tu grandis en puissance, plus grandit la bande de l\'éternité !';
-- Quest 10472 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10472, 'frFR', 'Que le temps soit toujours de ton côté, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Que le temps soit toujours de ton côté, $N$.';
-- Quest 10472 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10472, 'frFR', 'Tu es un avec le temps, <name>.  Tu es un avec nous.$B$BVoyez !  Un pouvoir au-delà de la compréhension mortelle est libéré même de ce petit vestige du Puits de l\'Éternité.$B$BAccepte ce don afin que tous connaissent ton pacte avec l\'Échelle des Sables.... afin que tous connaissent ton pacte avec le temps lui-même !') ON DUPLICATE KEY UPDATE RewardText='Tu es un avec le temps, <name>.  Tu es un avec nous.$B$BVoyez !  Un pouvoir au-delà de la compréhension mortelle est libéré même de ce petit vestige du Puits de l\'Éternité.$B$BAccepte ce don afin que tous connaissent ton pacte avec l\'Échelle des Sables.... afin que tous connaissent ton pacte avec le temps lui-même !';
