INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10473, 'frFR', 'Que le temps soit toujours de ton côté, $N$.') ON DUPLICATE KEY UPDATE CompletionText='Que le temps soit toujours de ton côté, $N$.';
