-- Quest 10475 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10475, 'frFR', 'Vous êtes un avec le temps, <name>.  Vous êtes un avec nous.$B$BVoyez!  Un pouvoir au-delà de la compréhension mortelle est libéré même de ce petit vestige du Puits d\'Éternité.$B$BAcceptez ce don afin que tous connaissent votre pacte avec l\'Échelle des Sables... afin que tous connaissent votre pacte avec le temps lui-même!') ON DUPLICATE KEY UPDATE RewardText='Vous êtes un avec le temps, <name>.  Vous êtes un avec nous.$B$BVoyez!  Un pouvoir au-delà de la compréhension mortelle est libéré même de ce petit vestige du Puits d\'Éternité.$B$BAcceptez ce don afin que tous connaissent votre pacte avec l\'Échelle des Sables... afin que tous connaissent votre pacte avec le temps lui-même!';
-- Quest 10476 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10476, 'frFR', 'Eh bien, $N? Vous ne faites que parler ou vous avez quelque chose à me montrer?') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, $N? Vous ne faites que parler ou vous avez quelque chose à me montrer?';
-- Quest 10477 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10477, 'frFR', 'En avez-vous d\'autres perles de guerre d\'obsidienne, $n?') ON DUPLICATE KEY UPDATE CompletionText='En avez-vous d\'autres perles de guerre d\'obsidienne, $n?';
-- Quest 10478 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10478, 'frFR', 'Avez-vous obtenu plus de perles de guerre, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous obtenu plus de perles de guerre, $N?';
-- Quest 10478 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10478, 'frFR', 'Vous continuez de prouver votre force et votre honneur, <name>.') ON DUPLICATE KEY UPDATE RewardText='Vous continuez de prouver votre force et votre honneur, <name>.';
-- Quest 10479 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10479, 'frFR', 'Vous avez quelque chose à me montrer, $N?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez quelque chose à me montrer, $N?';
-- Quest 10482 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10482, 'frFR', 'Les Mâchoire-Os apparaissent en grand nombre, $N. Tuez-les ou les orcs fel pourraient nous submerger!') ON DUPLICATE KEY UPDATE CompletionText='Les Mâchoire-Os apparaissent en grand nombre, $N. Tuez-les ou les orcs fel pourraient nous submerger!';
-- Quest 10486 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10486, 'frFR', 'Notre survie ici dépend de notre capacité à concentrer nos efforts contre ceux qui comptent vraiment, pas les simples sanguinières ailées.$B$BVous êtes de retour, cela doit donc signifier que vous avez réglé le problème en question?') ON DUPLICATE KEY UPDATE CompletionText='Notre survie ici dépend de notre capacité à concentrer nos efforts contre ceux qui comptent vraiment, pas les simples sanguinières ailées.$B$BVous êtes de retour, cela doit donc signifier que vous avez réglé le problème en question?';

-- Quest 10490 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10490, 'frFR', 'Nous nous retrouvons. J\'ai observé tes progrès de loin, $c, et je suis satisfait.$B$BIl est temps que tu communiques avec l\'élément de l\'eau, pour en apprendre les mystères et te soumettre à l\'eau afin que tu puisses à ton tour apprendre à la maîtriser.') ON DUPLICATE KEY UPDATE RewardText='Nous nous retrouvons. J\'ai observé tes progrès de loin, $c, et je suis satisfait.$B$BIl est temps que tu communiques avec l\'élément de l\'eau, pour en apprendre les mystères et te soumettre à l\'eau afin que tu puisses à ton tour apprendre à la maîtriser.';
-- Quest 10491 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10491, 'frFR', 'Et enfin, nous arrivons à lui, le dernier des quatre grands éléments : l\'air. Te crois-tu assez sage pour continuer, $N?') ON DUPLICATE KEY UPDATE RewardText='Et enfin, nous arrivons à lui, le dernier des quatre grands éléments : l\'air. Te crois-tu assez sage pour continuer, $N?';
-- Quest 10492 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10492, 'frFR', 'M\'as-tu apporté ce que j\'ai demandé de toi, $N?') ON DUPLICATE KEY UPDATE CompletionText='M\'as-tu apporté ce que j\'ai demandé de toi, $N?';
-- Quest 10492 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10492, 'frFR', 'Excellent ! Faisons alors l\'échange. Il est difficile de me séparer de cette excellente armure, mais j\'ai peur de ne pas en avoir besoin de sitôt.$B$BSi tu souhaites faire plus de travail pour moi, je pourrais être disposé à me séparer du reste des pièces.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Faisons alors l\'échange. Il est difficile de me séparer de cette excellente armure, mais j\'ai peur de ne pas en avoir besoin de sitôt.$B$BSi tu souhaites faire plus de travail pour moi, je pourrais être disposé à me séparer du reste des pièces.';
-- Quest 10493 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10493, 'frFR', 'As-tu obtenu les objets dont j\'ai besoin, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu les objets dont j\'ai besoin, $N?';
-- Quest 10493 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10493, 'frFR', 'Ah, oui. Mux sera tout à fait satisfait de ceci.$B$BCes brassards faisaient partie d\'un ensemble d\'armure plus vaste. Si tu souhaites me fournir une assistance supplémentaire, je serais disposé à envisager de me séparer du reste.') ON DUPLICATE KEY UPDATE RewardText='Ah, oui. Mux sera tout à fait satisfait de ceci.$B$BCes brassards faisaient partie d\'un ensemble d\'armure plus vaste. Si tu souhaites me fournir une assistance supplémentaire, je serais disposé à envisager de me séparer du reste.';
-- Quest 10494 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10494, 'frFR', 'Es-tu prêt à effectuer l\'échange ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu prêt à effectuer l\'échange ?';
-- Quest 10494 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10494, 'frFR', 'Tu as tenu ta part de l\'accord, je tiendrai la mienne.$B$BN\'oublie cependant que je garde les meilleures pièces jusqu\'à ce que ton travail soit terminé.') ON DUPLICATE KEY UPDATE RewardText='Tu as tenu ta part de l\'accord, je tiendrai la mienne.$B$BN\'oublie cependant que je garde les meilleures pièces jusqu\'à ce que ton travail soit terminé.';

-- Quest 10495 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10495, 'frFR', 'Vous êtes prêt à effectuer l\'échange ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes prêt à effectuer l\'échange ?';
-- Quest 10495 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10495, 'frFR', 'Notre accord reste en vigueur. N\'oubliez pas, ce n\'est qu\'un avant-goût de ce qui vous attend. Libérez-moi de ce destin maudit et je vous récompenserai avec des objets d\'une puissance véritablement grande.') ON DUPLICATE KEY UPDATE RewardText='Notre accord reste en vigueur. N\'oubliez pas, ce n\'est qu\'un avant-goût de ce qui vous attend. Libérez-moi de ce destin maudit et je vous récompenserai avec des objets d\'une puissance véritablement grande.';
-- Quest 10496 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10496, 'frFR', 'Vous êtes de retour, $N. Vous devez m\'expliquer tout ce que vous avez découvert. Mais d\'abord, arrangeons votre récompense.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes de retour, $N. Vous devez m\'expliquer tout ce que vous avez découvert. Mais d\'abord, arrangeons votre récompense.';
-- Quest 10496 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10496, 'frFR', 'Je n\'arrive pas à croire que nos vies sont toutes perdues à cause d\'un stupide médaillon ! Et vous êtes sûr qu\'Anthion a mentionné Bodley?$B$BEh bien, vous avez fait votre travail, alors réglons votre récompense.') ON DUPLICATE KEY UPDATE RewardText='Je n\'arrive pas à croire que nos vies sont toutes perdues à cause d\'un stupide médaillon ! Et vous êtes sûr qu\'Anthion a mentionné Bodley?$B$BEh bien, vous avez fait votre travail, alors réglons votre récompense.';
-- Quest 10497 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10497, 'frFR', 'Vous êtes revenu et je vois dans vos yeux que vous avez beaucoup à me dire, $N. Prenons d\'abord soin de votre récompense.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu et je vois dans vos yeux que vous avez beaucoup à me dire, $N. Prenons d\'abord soin de votre récompense.';
-- Quest 10497 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10497, 'frFR', 'Cette malédiction nous a été infligée pour un simple médaillon. Lord Valthalak sait certainement comment garder une rancune.$B$BNous nous efforcerons de trouver les pièces restantes - espérons-le avant que je ne rencontre une mort prématurée. Mais avant cela, voyons votre récompense.') ON DUPLICATE KEY UPDATE RewardText='Cette malédiction nous a été infligée pour un simple médaillon. Lord Valthalak sait certainement comment garder une rancune.$B$BNous nous efforcerons de trouver les pièces restantes - espérons-le avant que je ne rencontre une mort prématurée. Mais avant cela, voyons votre récompense.';
-- Quest 10498 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10498, 'frFR', 'Conformément à notre accord, êtes-vous prêt à remettre vos pièces de Cœur Sauvage en échange de votre nouveau Chapeau et votre Nouveau Vêtement de Cœur Féral ?') ON DUPLICATE KEY UPDATE CompletionText='Conformément à notre accord, êtes-vous prêt à remettre vos pièces de Cœur Sauvage en échange de votre nouveau Chapeau et votre Nouveau Vêtement de Cœur Féral ?';
-- Quest 10498 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10498, 'frFR', 'Tu vas me manquer, $N. Je te dois une telle gratitude ; je crois que je ne pourrai jamais te la rendre.$B$J\'espère que vous apprécierez votre nouvelle armure de tête et de poitrine, et qu\'elle vous protégera longtemps.') ON DUPLICATE KEY UPDATE RewardText='Tu vas me manquer, $N. Je te dois une telle gratitude ; je crois que je ne pourrai jamais te la rendre.$B$J\'espère que vous apprécierez votre nouvelle armure de tête et de poitrine, et qu\'elle vous protégera longtemps.';

-- Quest 10499 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10499, 'frFR', 'Comme convenu, êtes-vous prêt à me remettre les pièces de votre Magister en échange de votre nouvelle Couronne et Robes de Sorcier ?') ON DUPLICATE KEY UPDATE CompletionText='Comme convenu, êtes-vous prêt à me remettre les pièces de votre Magister en échange de votre nouvelle Couronne et Robes de Sorcier ?';
-- Quest 10499 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10499, 'frFR', 'Tu vas vraiment me manquer, $N$. Il y a une dette que je te dois, que je ne pourrai peut-être jamais rembourser.$B$BProfite de ton nouvel armure de tête et de poitrine. Qu\'elle te protège longtemps, et qu\'elle t\'aide à atteindre un honneur encore plus grand !') ON DUPLICATE KEY UPDATE RewardText='Tu vas vraiment me manquer, $N$. Il y a une dette que je te dois, que je ne pourrai peut-être jamais rembourser.$B$BProfite de ton nouvel armure de tête et de poitrine. Qu\'elle te protège longtemps, et qu\'elle t\'aide à atteindre un honneur encore plus grand !';
-- Quest 10500 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10500, 'frFR', 'Throm\'ka, $c! C\'est bon de voir tant de membres de la Horde, comme toi, $N, venir offrir votre soutien pour jeter les bases de la prochaine Guerre d\'Ahn\'Qiraj. Les efforts ici garantiront que nous serons victorieux contre les Silithid et leurs maîtres maléfiques cachés à l\'intérieur d\'Ahn\'Qiraj.$b$bDonc, maintenant que vous êtes ici, assurez-vous de parler avec les divers collecteurs et d\'offrir votre assistance pour rassembler les matériaux pour lesquels vous êtes apte.') ON DUPLICATE KEY UPDATE RewardText='Throm\'ka, $c! C\'est bon de voir tant de membres de la Horde, comme toi, $N, venir offrir votre soutien pour jeter les bases de la prochaine Guerre d\'Ahn\'Qiraj. Les efforts ici garantiront que nous serons victorieux contre les Silithid et leurs maîtres maléfiques cachés à l\'intérieur d\'Ahn\'Qiraj.$b$bDonc, maintenant que vous êtes ici, assurez-vous de parler avec les divers collecteurs et d\'offrir votre assistance pour rassembler les matériaux pour lesquels vous êtes apte.';
-- Quest 10502 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10502, 'frFR', 'Nos éclaireurs ont signalé que les ogres Bloodmaul ont commencé à grimper le virage, qui mène à la Forêt Vivante depuis leur repaire.$B$BIl est regrettable que nous ne puissions pas trouver un moyen de vivre en paix avec les ogres, mais alors, quand y sommes-nous jamais parvenus ?') ON DUPLICATE KEY UPDATE CompletionText='Nos éclaireurs ont signalé que les ogres Bloodmaul ont commencé à grimper le virage, qui mène à la Forêt Vivante depuis leur repaire.$B$BIl est regrettable que nous ne puissions pas trouver un moyen de vivre en paix avec les ogres, mais alors, quand y sommes-nous jamais parvenus ?';
-- Quest 10503 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10503, 'frFR', 'Nos éclaireurs ont signalé que les ogres Bladespire ont établi un camp encore plus près du virage, qui mène depuis leur repaire jusqu\'à nous ici.$B$BIl est regrettable que nous ne puissions pas simplement assujettir ces déchets d\'ogres à notre volonté, mais s\'il s\'agit d\'un combat qu\'ils veulent, ils trouveront la Horde très accommodante.') ON DUPLICATE KEY UPDATE CompletionText='Nos éclaireurs ont signalé que les ogres Bladespire ont établi un camp encore plus près du virage, qui mène depuis leur repaire jusqu\'à nous ici.$B$BIl est regrettable que nous ne puissions pas simplement assujettir ces déchets d\'ogres à notre volonté, mais s\'il s\'agit d\'un combat qu\'ils veulent, ils trouveront la Horde très accommodante.';
-- Quest 10504 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10504, 'frFR', 'Bloodmaul ou Bladespire, peu importe. Tous les clans d\'ogres se battent les uns contre les autres, se disputant la domination qui vient avec le favori de Gruul le Tueur de Dragons.$B$BChacun est toujours notre ennemi, peu importe à qui ce favori est tombé.') ON DUPLICATE KEY UPDATE CompletionText='Bloodmaul ou Bladespire, peu importe. Tous les clans d\'ogres se battent les uns contre les autres, se disputant la domination qui vient avec le favori de Gruul le Tueur de Dragons.$B$BChacun est toujours notre ennemi, peu importe à qui ce favori est tombé.';
-- Quest 10505 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10505, 'frFR', 'Bladespire ou Bloodmaul, cela n\'a pas d\'importance. Tous les clans d\'ogres se battent les uns contre les autres, se disputant la domination qui vient avec le favori de Gruul le Tueur de Dragons.$B$BChacun est toujours notre ennemi, peu importe à qui ce favori est tombé, et nous les pousserons devant nous !') ON DUPLICATE KEY UPDATE CompletionText='Bladespire ou Bloodmaul, cela n\'a pas d\'importance. Tous les clans d\'ogres se battent les uns contre les autres, se disputant la domination qui vient avec le favori de Gruul le Tueur de Dragons.$B$BChacun est toujours notre ennemi, peu importe à qui ce favori est tombé, et nous les pousserons devant nous !';
-- Quest 10507 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10507, 'frFR', 'Vous êtes un individu d\'une puissance formidable, <name>.  Les Voyants sont heureux de vous compter comme un allié.$B$BAlors que la parole de l\'allégeance nouvelle de Kael se répand, plus de gens verront les choses de notre point de vue.  Le fait que nous puissions revendiquer une victoire aussi décisive contre les nouveaux maîtres de Kael\'thas nous place dans une situation très favorable.$B$BI n\'oublierai pas vos actes.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes un individu d\'une puissance formidable, <name>.  Les Voyants sont heureux de vous compter comme un allié.$B$BAlors que la parole de l\'allégeance nouvelle de Kael se répand, plus de gens verront les choses de notre point de vue.  Le fait que nous puissions revendiquer une victoire aussi décisive contre les nouveaux maîtres de Kael\'thas nous place dans une situation très favorable.$B$BI n\'oublierai pas vos actes.';

-- Quest 10508 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10508, 'frFR', 'As-tu obtenu la pierre de téléportation de Socrethar, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu la pierre de téléportation de Socrethar, $N?';
-- Quest 10508 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10508, 'frFR', 'Tu ne cesses de m\'étonner, <name>!  Heureusement que tu es de notre côté.') ON DUPLICATE KEY UPDATE RewardText='Tu ne cesses de m\'étonner, <name>!  Heureusement que tu es de notre côté.';
-- Quest 10517 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10517, 'frFR', 'Quel est ce vacarme? Est-ce toi qui t\'occupes de Gorr\'Dim?') ON DUPLICATE KEY UPDATE CompletionText='Quel est ce vacarme? Est-ce toi qui t\'occupes de Gorr\'Dim?';
-- Quest 10520 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10520, 'frFR', 'Eh bien, $C$... puisque tu as été informé que je menais moi-même cette recherche, tu es évidemment arrivé aussi vite que possible.$B$BMaintenant que tu es là, assure-toi de prêter attention la première fois que je te donne les détails; je n\'ai pas envie de me répéter.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, $C$... puisque tu as été informé que je menais moi-même cette recherche, tu es évidemment arrivé aussi vite que possible.$B$BMaintenant que tu es là, assure-toi de prêter attention la première fois que je te donne les détails; je n\'ai pas envie de me répéter.';
-- Quest 10524 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10524, 'frFR', 'Je ne crois pas mes yeux!  Si c\'est une sorte de tour de passe-passe, je me dépecterai la chair de tes os, <class>!$B$BDépêche-toi, laisse-moi examiner ces artefacts inestimables avant que tu ne les casses avec tes mains maladroites.') ON DUPLICATE KEY UPDATE RewardText='Je ne crois pas mes yeux!  Si c\'est une sorte de tour de passe-passe, je me dépecterai la chair de tes os, <class>!$B$BDépêche-toi, laisse-moi examiner ces artefacts inestimables avant que tu ne les casses avec tes mains maladroites.';
-- Quest 10529 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10529, 'frFR', '$N, c\'est bien que tu sois venu. Notre liste d\'alliés se raréfie, et même ceux qui partagent notre cause ne sont pas entièrement d\'une confiance absolue. C\'est pour cela que nous, les rangers, nous tournons vers la nature pour obtenir de l\'aide.$B$BAuprès des alliés de la forêt, nous trouvons un lien profond qui ne connaît pas la tromperie.') ON DUPLICATE KEY UPDATE RewardText='$N, c\'est bien que tu sois venu. Notre liste d\'alliés se raréfie, et même ceux qui partagent notre cause ne sont pas entièrement d\'une confiance absolue. C\'est pour cela que nous, les rangers, nous tournons vers la nature pour obtenir de l\'aide.$B$BAuprès des alliés de la forêt, nous trouvons un lien profond qui ne connaît pas la tromperie.';
-- Quest 10530 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10530, 'frFR', '$N, c\'est bien que tu sois venu. Notre liste d\'alliés se raréfie, et même ceux qui partagent notre cause ne sont pas entièrement d\'une confiance absolue. C\'est pour cela que nous, les rangers, nous tournons vers la nature pour obtenir de l\'aide.$B$BAuprès des alliés de la forêt, nous trouvons un lien profond qui ne connaît pas la tromperie.') ON DUPLICATE KEY UPDATE RewardText='$N, c\'est bien que tu sois venu. Notre liste d\'alliés se raréfie, et même ceux qui partagent notre cause ne sont pas entièrement d\'une confiance absolue. C\'est pour cela que nous, les rangers, nous tournons vers la nature pour obtenir de l\'aide.$B$BAuprès des alliés de la forêt, nous trouvons un lien profond qui ne connaît pas la tromperie.';
-- Quest 10538 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10538, 'frFR', 'As-tu le sang bouilli, $N? J\'ai hâte de l\'étudier sans interruption cette fois...') ON DUPLICATE KEY UPDATE CompletionText='As-tu le sang bouilli, $N? J\'ai hâte de l\'étudier sans interruption cette fois...';

-- Quest 10543 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10543, 'frFR', 'Tu crois que T\'chali aime être comme ça ? Non ! $B$BSo, m\'as-tu encore vengé ? Grimnok et Korgaah sont-ils morts ?') ON DUPLICATE KEY UPDATE CompletionText='Tu crois que T\'chali aime être comme ça ? Non ! $B$BSo, m\'as-tu encore vengé ? Grimnok et Korgaah sont-ils morts ?';
-- Quest 10548 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10548, 'frFR', 'Oh, wow.  Ce n\'est pas joli.  Je suis sûr que le marchand appréciera plus que moi.$B$BAs paiement, le marchand a offert d\'acheter l\'un de mes articles en stock spéciaux pour toi, alors choisis ton coup de cœur, beau gosse !') ON DUPLICATE KEY UPDATE RewardText='Oh, wow.  Ce n\'est pas joli.  Je suis sûr que le marchand appréciera plus que moi.$B$BAs paiement, le marchand a offert d\'acheter l\'un de mes articles en stock spéciaux pour toi, alors choisis ton coup de cœur, beau gosse !';
-- Quest 10551 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10551, 'frFR', 'Es-tu certain de ton choix, $N? Les Aldor t\'accueilleront comme un allié, mais les Scryers ne pardonneront pas facilement ta décision.') ON DUPLICATE KEY UPDATE RewardText='Es-tu certain de ton choix, $N? Les Aldor t\'accueilleront comme un allié, mais les Scryers ne pardonneront pas facilement ta décision.';
-- Quest 10552 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10552, 'frFR', 'Es-tu certain de ton choix, $N? Les Scryers t\'accueilleront comme un allié, mais les Aldor ne pardonneront pas facilement ta décision.') ON DUPLICATE KEY UPDATE RewardText='Es-tu certain de ton choix, $N? Les Scryers t\'accueilleront comme un allié, mais les Aldor ne pardonneront pas facilement ta décision.';
-- Quest 10557 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10557, 'frFR', 'N\'aie pas peur ! C\'est pour la science, et la science est douloureuse !') ON DUPLICATE KEY UPDATE CompletionText='N\'aie pas peur ! C\'est pour la science, et la science est douloureuse !';
-- Quest 10566 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10566, 'frFR', 'J\'attends avec impatience tes résultats, $N.') ON DUPLICATE KEY UPDATE CompletionText='J\'attends avec impatience tes résultats, $N.';
-- Quest 10577 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10577, 'frFR', 'Le déguisement est délicat. Presque toute action, à part marcher, perturbera la magie qui le maintient ensemble.') ON DUPLICATE KEY UPDATE CompletionText='Le déguisement est délicat. Presque toute action, à part marcher, perturbera la magie qui le maintient ensemble.';
-- Quest 10582 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10582, 'frFR', 'As-tu dégagé un chemin vers le Deathforge ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu dégagé un chemin vers le Deathforge ?';

-- Quest 10590 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10590, 'frFR', 'Le Fléau s\'est effondré sous votre arme ?') ON DUPLICATE KEY UPDATE CompletionText='Le Fléau s\'est effondré sous votre arme ?';
-- Quest 10590 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10590, 'frFR', 'Très bien, $N. Peut-être avez-vous une soif de vengeance après tout.') ON DUPLICATE KEY UPDATE RewardText='Très bien, $N. Peut-être avez-vous une soif de vengeance après tout.';
-- Quest 10592 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10592, 'frFR', 'Avez-vous quelque chose pour moi, $R?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous quelque chose pour moi, $R?';
-- Quest 10592 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10592, 'frFR', 'Ces pierres portent une souillure que je ne souhaite pas me souvenir, mais que je ne peux oublier. Vous mettez ma patience en danger en m\'apportant ceci.$B$BCependant, il est clair que votre cœur recherche la même vengeance que moi, et je vous aiderai avec des instructions.') ON DUPLICATE KEY UPDATE RewardText='Ces pierres portent une souillure que je ne souhaite pas me souvenir, mais que je ne peux oublier. Vous mettez ma patience en danger en m\'apportant ceci.$B$BCependant, il est clair que votre cœur recherche la même vengeance que moi, et je vous aiderai avec des instructions.';
-- Quest 10593 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10593, 'frFR', 'Étant donné que vous êtes en vie, je ne peux que supposer que vous avez eu la chance de recevoir la sagesse plutôt que la mort de Dame Sylvanas.') ON DUPLICATE KEY UPDATE CompletionText='Étant donné que vous êtes en vie, je ne peux que supposer que vous avez eu la chance de recevoir la sagesse plutôt que la mort de Dame Sylvanas.';
-- Quest 10593 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10593, 'frFR', 'La Reine Banshee vous a bien guidé. C\'est précisément ce dont j\'ai besoin pour combiner les fragments.$B$B<Mehlar observe la vigne s\'entrelacer à travers les fragments, les liant ensemble.>$B$BVoilà ! Scourgebane, je l\'appellerai. Soyez prudent lorsque vous l\'utiliserez, car il vous sert contre votre volonté.') ON DUPLICATE KEY UPDATE RewardText='La Reine Banshee vous a bien guidé. C\'est précisément ce dont j\'ai besoin pour combiner les fragments.$B$B<Mehlar observe la vigne s\'entrelacer à travers les fragments, les liant ensemble.>$B$BVoilà ! Scourgebane, je l\'appellerai. Soyez prudent lorsque vous l\'utiliserez, car il vous sert contre votre volonté.';
-- Quest 10600 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10600, 'frFR', 'Avez-vous dégagé un chemin vers le Forgeron de la Mort ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous dégagé un chemin vers le Forgeron de la Mort ?';
-- Quest 10605 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10605, 'frFR', 'Ah, un autre initié avide de pouvoir. Merveilleux !$B$BNe seriez-vous pas un $c si vous n\'aviez pas soif de pouvoir, maintenant, petit ? Allons-y.') ON DUPLICATE KEY UPDATE RewardText='Ah, un autre initié avide de pouvoir. Merveilleux !$B$BNe seriez-vous pas un $c si vous n\'aviez pas soif de pouvoir, maintenant, petit ? Allons-y.';

-- Quest 10607 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10607, 'frFR', 'Qu\'est-ce que ce $N$? Qu\'est-ce qu\'ils croient qu\'il fera? Où croient-ils qu\'il les mènera?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que ce $N$? Qu\'est-ce qu\'ils croient qu\'il fera? Où croient-ils qu\'il les mènera?';
-- Quest 10608 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10608, 'frFR', 'As-tu dégagé ces flayeurs de cristal de la Crête Chantante? Nous ne pouvons commencer mes recherches tant que tu ne l\'as pas fait.') ON DUPLICATE KEY UPDATE CompletionText='As-tu dégagé ces flayeurs de cristal de la Crête Chantante? Nous ne pouvons commencer mes recherches tant que tu ne l\'as pas fait.';
-- Quest 10612 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10612, 'frFR', 'Tu es de retour, donc j\'assume que l\'opération s\'est bien déroulée. Qu\'as-tu à me rapporter?') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour, donc j\'assume que l\'opération s\'est bien déroulée. Qu\'as-tu à me rapporter?';
-- Quest 10613 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10613, 'frFR', 'Tu es de retour, donc j\'assume que l\'opération s\'est bien déroulée. Qu\'as-tu à me rapporter?') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour, donc j\'assume que l\'opération s\'est bien déroulée. Qu\'as-tu à me rapporter?';
