INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10619, 'frFR', 'As-tu accompli la tâche que je t\'ai demandée, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu accompli la tâche que je t\'ai demandée, $N?';
-- Quest 10620 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10620, 'frFR', 'Ces traqueurs sont-ils dégagés? Nous avons eu quelques membres de notre personnel qui sont partis vers le nord.$B$BSi c\'est à cause des traqueurs, je veux m\'assurer que cela ne se reproduise pas.') ON DUPLICATE KEY UPDATE CompletionText='Ces traqueurs sont-ils dégagés? Nous avons eu quelques membres de notre personnel qui sont partis vers le nord.$B$BSi c\'est à cause des traqueurs, je veux m\'assurer que cela ne se reproduise pas.';
-- Quest 10622 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10622, 'frFR', 'As-tu fait ce que je t\'ai demandé, $N? La confiance n\'est pas facilement trouvée dans ces parages.') ON DUPLICATE KEY UPDATE CompletionText='As-tu fait ce que je t\'ai demandé, $N? La confiance n\'est pas facilement trouvée dans ces parages.';
