INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10626, 'frFR', 'As-tu capturé ces prototypes?') ON DUPLICATE KEY UPDATE CompletionText='As-tu capturé ces prototypes?';

-- Quest 10630 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10630, 'frFR', 'Est-il mort, déjà ? J\'ai trop peur de regarder.') ON DUPLICATE KEY UPDATE CompletionText='Est-il mort, déjà ? J\'ai trop peur de regarder.';
-- Quest 10631 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (10631, 'frFR', 'Prends mon déchiqueteur. Va dans la mine et récupère de la minerai.') ON DUPLICATE KEY UPDATE `Details`='Prends mon déchiqueteur. Va dans la mine et récupère de la minerai.';
-- Quest 10637 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10637, 'frFR', 'As-tu accompli la tâche que je t\'ai demandée ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu accompli la tâche que je t\'ai demandée ?';
-- Quest 10649 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10649, 'frFR', 'As-tu obtenu le livre, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu le livre, $N ?';
-- Quest 10649 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10649, 'frFR', 'J\'ai pu sentir la puissance du livre à des centaines de mètres.  La tentation de le garder est... très forte.') ON DUPLICATE KEY UPDATE RewardText='J\'ai pu sentir la puissance du livre à des centaines de mètres.  La tentation de le garder est... très forte.';
-- Quest 10650 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10650, 'frFR', 'Tu amènes cette abomination de livre à ce lieu saint ?  Tu ferais mieux d\'avoir une très bonne explication, <name>?') ON DUPLICATE KEY UPDATE RewardText='Tu amènes cette abomination de livre à ce lieu saint ?  Tu ferais mieux d\'avoir une très bonne explication, <name>?';
-- Quest 10651 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10651, 'frFR', 'As-tu accompli ce que je t\'ai demandé, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu accompli ce que je t\'ai demandé, $N ?';
-- Quest 10651 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10651, 'frFR', 'Excellent travail, <name>!  Ta victoire sur Varedis aura un impact énorme sur notre guerre contre Illidan.$B$BTu t\'es prouvé non seulement aux Aldor, mais à tout Outland.  Permets-moi de détruire ce qui reste de ce horrible livre.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>!  Ta victoire sur Varedis aura un impact énorme sur notre guerre contre Illidan.$B$BTu t\'es prouvé non seulement aux Aldor, mais à tout Outland.  Permets-moi de détruire ce qui reste de ce horrible livre.';

-- Quest 10653 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10653, 'frFR', 'Portez-vous des insignes de nos ennemis, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Portez-vous des insignes de nos ennemis, $N ?';
-- Quest 10653 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10653, 'frFR', 'Affronter les démons de la Légion ardente et les cultistes fous qui les vénèrent est une tâche herculéenne, <name>.  Vous avez fait preuve d\'un grand dévouement et d\'un grand courage.  Continuez ainsi et votre renommée parmi les Aldor continuera de grandir.') ON DUPLICATE KEY UPDATE RewardText='Affronter les démons de la Légion ardente et les cultistes fous qui les vénèrent est une tâche herculéenne, <name>.  Vous avez fait preuve d\'un grand dévouement et d\'un grand courage.  Continuez ainsi et votre renommée parmi les Aldor continuera de grandir.';
-- Quest 10654 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10654, 'frFR', 'Portez-vous plus d\'insignes de nos ennemis, $C ? La Légion ardente continue d\'être une menace et nous continuons à les traquer partout où nous les trouvons.') ON DUPLICATE KEY UPDATE CompletionText='Portez-vous plus d\'insignes de nos ennemis, $C ? La Légion ardente continue d\'être une menace et nous continuons à les traquer partout où nous les trouvons.';
-- Quest 10654 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10654, 'frFR', 'Vous continuez de prouver votre valeur, <name>.  Combattez les ennemis de la Lumière où que vous les trouviez ; vos actions seront récompensées.') ON DUPLICATE KEY UPDATE RewardText='Vous continuez de prouver votre valeur, <name>.  Combattez les ennemis de la Lumière où que vous les trouviez ; vos actions seront récompensées.';
-- Quest 10655 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10655, 'frFR', 'Je prendrai toutes les marques restantes que vous pourriez avoir. Ne vous inquiétez pas ; vos actions seront dûment notées.') ON DUPLICATE KEY UPDATE CompletionText='Je prendrai toutes les marques restantes que vous pourriez avoir. Ne vous inquiétez pas ; vos actions seront dûment notées.';
-- Quest 10658 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10658, 'frFR', 'Qu\'avez-vous fait pour nous récemment, $N ? La guerre contre Kael\'thas ne va pas se battre toute seule, vous savez ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'avez-vous fait pour nous récemment, $N ? La guerre contre Kael\'thas ne va pas se battre toute seule, vous savez ?';
-- Quest 10658 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10658, 'frFR', 'Excellent !  Cela montrera à Kael\'thas qu\'il ne doit pas sous-estimer notre puissance.') ON DUPLICATE KEY UPDATE RewardText='Excellent !  Cela montrera à Kael\'thas qu\'il ne doit pas sous-estimer notre puissance.';
-- Quest 10659 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10659, 'frFR', 'Même la plus petite contribution à notre cause est notée, $N. Nos ennemis sont nombreux, mais nous triompherons !') ON DUPLICATE KEY UPDATE CompletionText='Même la plus petite contribution à notre cause est notée, $N. Nos ennemis sont nombreux, mais nous triompherons !';

-- Quest 10662 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10662, 'frFR', 'Qu\'est-ce qui vous amène ici, $C? Je n\'ai pas beaucoup de visiteurs.') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui vous amène ici, $C? Je n\'ai pas beaucoup de visiteurs.';
-- Quest 10662 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10662, 'frFR', 'Ordinn vous a envoyé avec ceci?$B$B<Le forgeron examine les lingots.> $B$BIl avait raison. La plupart de la magie a disparu, mais je peux encore en sentir des traces. Avec un peu de travail et quelques ressources \'exotiques\', je peux vous forger une épée anti-démon puissante à partir de ce métal.') ON DUPLICATE KEY UPDATE RewardText='Ordinn vous a envoyé avec ceci?$B$B<Le forgeron examine les lingots.> $B$BIl avait raison. La plupart de la magie a disparu, mais je peux encore en sentir des traces. Avec un peu de travail et quelques ressources \'exotiques\', je peux vous forger une épée anti-démon puissante à partir de ce métal.';
-- Quest 10663 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10663, 'frFR', 'Qu\'est-ce qui vous amène ici, $C? Je n\'ai pas beaucoup de visiteurs.') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui vous amène ici, $C? Je n\'ai pas beaucoup de visiteurs.';
-- Quest 10663 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10663, 'frFR', '$GLe forgeron fronce les sourcils et examine les lingots.>$B<br :>Je vais être franc avec vous, <class. Je suis une relique d\'une époque où la coopération avec la Horde était impensable.$B$BI ne suis pas si aveugle que de voir que nous n\'avons pas d\'ennemis communs. Je vous aiderai à refondre l\'arme anti-démon, mais cela va demander beaucoup de travail et quelques ressources \'exotiques\'.') ON DUPLICATE KEY UPDATE RewardText='$GLe forgeron fronce les sourcils et examine les lingots.>$B<br :>Je vais être franc avec vous, <class. Je suis une relique d\'une époque où la coopération avec la Horde était impensable.$B$BI ne suis pas si aveugle que de voir que nous n\'avons pas d\'ennemis communs. Je vous aiderai à refondre l\'arme anti-démon, mais cela va demander beaucoup de travail et quelques ressources \'exotiques\'.';
-- Quest 10665 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10665, 'frFR', 'Avez-vous réussi à faire passer un manacell hors des Mécanar.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à faire passer un manacell hors des Mécanar.';
-- Quest 10667 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10667, 'frFR', 'Avez-vous sécurisé le limon souterrain?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous sécurisé le limon souterrain?';
-- Quest 10668 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10668, 'frFR', 'Le lieutenant Illidari est-il mort?') ON DUPLICATE KEY UPDATE CompletionText='Le lieutenant Illidari est-il mort?';
-- Quest 10670 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10670, 'frFR', 'Avez-vous réussi à arracher le joyau des mains d\'O\'mrogg?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à arracher le joyau des mains d\'O\'mrogg?';

-- Quest 10670 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10670, 'frFR', '<David Wayne tient le gemme, à la lumière, l\'admirant.>BC\'est absolument parfait, et c\'est exactement ce dont nous aurons besoin. Une gemme imparfaite mettrait en danger celui qui manierait l\'arme, tordant la magie contre lui.') ON DUPLICATE KEY UPDATE RewardText='<David Wayne tient le gemme, à la lumière, l\'admirant.>BC\'est absolument parfait, et c\'est exactement ce dont nous aurons besoin. Une gemme imparfaite mettrait en danger celui qui manierait l\'arme, tordant la magie contre lui.';
-- Quest 10672 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10672, 'frFR', 'Écoutez, je n\'ai ni le temps ni l\'inclination d\'expliquer ce que tout cela signifie. Identifiez simplement ces diémétradons.') ON DUPLICATE KEY UPDATE CompletionText='Écoutez, je n\'ai ni le temps ni l\'inclination d\'expliquer ce que tout cela signifie. Identifiez simplement ces diémétradons.';
-- Quest 10676 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10676, 'frFR', '<David essuie la sueur de son front.>BC\'est la majeure partie du travail qui est faite, mais pour fixer les magies, la lame doit maintenant être trempée.') ON DUPLICATE KEY UPDATE RewardText='<David essuie la sueur de son front.>BC\'est la majeure partie du travail qui est faite, mais pour fixer les magies, la lame doit maintenant être trempée.';
-- Quest 10679 [RequestItems]
