-- Quest 10679 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10679, 'frFR', 'Bien fait !B<Le forgeron examine la lame attentivement.>BJe dirais que c\'est une amélioration équitable par rapport aux armes grossières de la Légion avec lesquelles vous avez commencé. Cette lame ne fera pas seulement tomber les démons Illidari, mais elle agira aussi contre les sbires de la Légion.') ON DUPLICATE KEY UPDATE RewardText='Bien fait !B<Le forgeron examine la lame attentivement.>BJe dirais que c\'est une amélioration équitable par rapport aux armes grossières de la Légion avec lesquelles vous avez commencé. Cette lame ne fera pas seulement tomber les démons Illidari, mais elle agira aussi contre les sbires de la Légion.';
