INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10692, 'frFR', 'Tu as bien fait, <name>.  En tuant Varedis, tu as mis fin à l\'un des projets les plus dangereux d\'Illidan.$B$BTon nom passera certainement après cela.$B$BPermettez-moi de prendre ce qui reste du Livre des Noms de Fel.  Je m\'assurerai qu\'il soit correctement... éliminé.') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait, <name>.  En tuant Varedis, tu as mis fin à l\'un des projets les plus dangereux d\'Illidan.$B$BTon nom passera certainement après cela.$B$BPermettez-moi de prendre ce qui reste du Livre des Noms de Fel.  Je m\'assurerai qu\'il soit correctement... éliminé.';

