INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10710, 'frFR', 'Ne t\'inquiète pas, $n! L\'inquiétude n\'a jamais mené personne nulle part !') ON DUPLICATE KEY UPDATE CompletionText='Ne t\'inquiète pas, $n! L\'inquiétude n\'a jamais mené personne nulle part !';
