-- Quest 10714 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10714, 'frFR', '<Un esprit se pose sur l\'épaule de Rexxar tandis que Rexxar écoute attentivement.>$B$BC\'est donc les fils de Gruul qui sont derrière les actions des ogres. Ils commandent aux ogres de Bloodmaul de détruire Mok\'Nathal pour obtenir leur faveur.') ON DUPLICATE KEY UPDATE RewardText='<Un esprit se pose sur l\'épaule de Rexxar tandis que Rexxar écoute attentivement.>$B$BC\'est donc les fils de Gruul qui sont derrière les actions des ogres. Ils commandent aux ogres de Bloodmaul de détruire Mok\'Nathal pour obtenir leur faveur.';

