-- Quest 10725 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10725, 'frFR', 'Le sceau que vous détenez maintenant est aussi puissant que celui de n\'importe quel Archimage du Conseil. Portez-le où que vous alliez afin que les initiés puissent reconnaître votre allégeance. Portez-le où que vous alliez afin que son pouvoir puisse vous servir comme vous nous avez servi !') ON DUPLICATE KEY UPDATE RewardText='Le sceau que vous détenez maintenant est aussi puissant que celui de n\'importe quel Archimage du Conseil. Portez-le où que vous alliez afin que les initiés puissent reconnaître votre allégeance. Portez-le où que vous alliez afin que son pouvoir puisse vous servir comme vous nous avez servi !';
