-- Quest 10748 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10748, 'frFR', 'Vous avez déjà affaire à Maxnar l\'Ashmaw ? $B$Avez-vous du mal à le trouver ? D\'après ce que je comprends, si vous allez à droite une fois que vous entrez dans leurs cavernes, cela finira par faire un détour et vous mènera à lui.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez déjà affaire à Maxnar l\'Ashmaw ? $B$Avez-vous du mal à le trouver ? D\'après ce que je comprends, si vous allez à droite une fois que vous entrez dans leurs cavernes, cela finira par faire un détour et vous mènera à lui.';
