-- Quest 10770 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10770, 'frFR', 'Bientôt, je ferai le sommeil profond de la forêt. Avant d\'enfoncer mes racines et de fermer ces vieux yeux pour toujours, j\'espère savoir que ces imps misérables ont souffert et péri.') ON DUPLICATE KEY UPDATE CompletionText='Bientôt, je ferai le sommeil profond de la forêt. Avant d\'enfoncer mes racines et de fermer ces vieux yeux pour toujours, j\'espère savoir que ces imps misérables ont souffert et péri.';
