-- Quest 10786 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10786, 'frFR', 'Nous avons parcouru un long chemin en peu de temps, toi et moi. J\'ose dire que tu es le chasseur d\'ogres le plus compétent que j\'aie jamais connu.$B$BI j\'ai confiance que tu t\'occuperas des ogres de Boulder\'mok bientôt ?') ON DUPLICATE KEY UPDATE CompletionText='Nous avons parcouru un long chemin en peu de temps, toi et moi. J\'ose dire que tu es le chasseur d\'ogres le plus compétent que j\'aie jamais connu.$B$BI j\'ai confiance que tu t\'occuperas des ogres de Boulder\'mok bientôt ?';
-- Quest 10786 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10786, 'frFR', '$GTor\'chunk sourit à l\'histoire que tu lui racontes sur tes aventures à Boulder\'mok.>$B<br :>Ah, j\'aurais aimé être là avec toi. Laisse-moi te dire quelque chose, <name: n\'accepte jamais de devoir qui t\'empêche de la gloire du combat!$B$BHah! Après tout le nombre d\'ogres que tu as tués, en reste-t-il dans ces montagnes pour moi ?!') ON DUPLICATE KEY UPDATE RewardText='$GTor\'chunk sourit à l\'histoire que tu lui racontes sur tes aventures à Boulder\'mok.>$B<br :>Ah, j\'aurais aimé être là avec toi. Laisse-moi te dire quelque chose, <name: n\'accepte jamais de devoir qui t\'empêche de la gloire du combat!$B$BHah! Après tout le nombre d\'ogres que tu as tués, en reste-t-il dans ces montagnes pour moi ?!';
-- Quest 10787 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (10787, 'frFR', 'Nous devons faire quelque chose qui fera rage Goc si nous voulons l\'affronter.$B$BEt maintenant que tu as libéré &&&, je pense savoir ce qui fera l\'affaire!$B$BQuand tu seras prêt, dis-le-moi, et je demanderai à &&& de te faire voler jusqu\'à un des cadavres de dragon impalés sur les rochers à Dragons\' End.$B$BRécupère le cadavre et ramène-le-moi ici afin que nous puissions créer quelque chose qui est sûr de faire sortir Goc de sa cachette!') ON DUPLICATE KEY UPDATE `Details`='Nous devons faire quelque chose qui fera rage Goc si nous voulons l\'affronter.$B$BEt maintenant que tu as libéré &&&, je pense savoir ce qui fera l\'affaire!$B$BQuand tu seras prêt, dis-le-moi, et je demanderai à &&& de te faire voler jusqu\'à un des cadavres de dragon impalés sur les rochers à Dragons\' End.$B$BRécupère le cadavre et ramène-le-moi ici afin que nous puissions créer quelque chose qui est sûr de faire sortir Goc de sa cachette!';
-- Quest 10788 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10788, 'frFR', 'Alors, le voyageur du monde revient...$B$BI j\'espère que mon sarcasme est évident, $N, car tu m\'as beaucoup dérangé en me forçant à envoyer un appel. Considère que tu n\'es qu\'à un cheveu d\'un gardien du fel de l\'incinération, et ils n\'ont pas de cheveux.$B$BFais attention, ce n\'est pas une leçon que tu recevras deux fois.') ON DUPLICATE KEY UPDATE RewardText='Alors, le voyageur du monde revient...$B$BI j\'espère que mon sarcasme est évident, $N, car tu m\'as beaucoup dérangé en me forçant à envoyer un appel. Considère que tu n\'es qu\'à un cheveu d\'un gardien du fel de l\'incinération, et ils n\'ont pas de cheveux.$B$BFais attention, ce n\'est pas une leçon que tu recevras deux fois.';
-- Quest 10789 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10789, 'frFR', 'Oui, je le vois dans tes orbites. Tu as envie d\'en apprendre plus.$B$BTrès bien, c\'est une leçon dont nous allons tous deux profiter.') ON DUPLICATE KEY UPDATE RewardText='Oui, je le vois dans tes orbites. Tu as envie d\'en apprendre plus.$B$BTrès bien, c\'est une leçon dont nous allons tous deux profiter.';
-- Quest 10790 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10790, 'frFR', 'C\'est la connaissance interdite dont tu as soif, n\'est-ce pas ? Je peux te la donner...') ON DUPLICATE KEY UPDATE RewardText='C\'est la connaissance interdite dont tu as soif, n\'est-ce pas ? Je peux te la donner...';
-- Quest 10792 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10792, 'frFR', 'Zeth\'Gor doit brûler, $N! Parle-moi à nouveau lorsque ta tâche sera accomplie.') ON DUPLICATE KEY UPDATE CompletionText='Zeth\'Gor doit brûler, $N! Parle-moi à nouveau lorsque ta tâche sera accomplie.';
-- Quest 10794 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10794, 'frFR', 'Alors, tu veux travailler pour la Main Brisée ? On dirait que nous trouvons quelqu\'un de nouveau tous les jours.$B$BFais attention et je t\'expliquerai ce que tu dois faire.') ON DUPLICATE KEY UPDATE RewardText='Alors, tu veux travailler pour la Main Brisée ? On dirait que nous trouvons quelqu\'un de nouveau tous les jours.$B$BFais attention et je t\'expliquerai ce que tu dois faire.';

-- Quest 10795 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10795, 'frFR', 'Je ne peux pas exprimer assez fortement à quel point il est important que vous tuiez Dorgok le plus rapidement possible.') ON DUPLICATE KEY UPDATE CompletionText='Je ne peux pas exprimer assez fortement à quel point il est important que vous tuiez Dorgok le plus rapidement possible.';
-- Quest 10796 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10796, 'frFR', 'Avez-vous déjà détruit le Camp de Bloodmaul ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous déjà détruit le Camp de Bloodmaul ?';
-- Quest 10803 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10803, 'frFR', 'J\'ose dire que vous êtes le chasseur d\'ogres le plus compétent que j\'aie jamais connu.$B$BI je crois que vous vous occuperez des ogres de Boulder\'mok bientôt ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ose dire que vous êtes le chasseur d\'ogres le plus compétent que j\'aie jamais connu.$B$BI je crois que vous vous occuperez des ogres de Boulder\'mok bientôt ?';
-- Quest 10803 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10803, 'frFR', '$GLieutenant Fairweather sourit à l\'histoire que vous lui racontez de vos aventures à Boulder\'mok.>$B<br :>Ah, j\'aurais aimé être là avec toi. Laisse-moi te dire quelque chose, <name: n\'accepte jamais de devoir qui t\'empêche de la gloire du champ de bataille!$B$BHah! Après tout le nombre d\'ogres que tu as tués, en reste-t-il dans ces montagnes pour moi ?!') ON DUPLICATE KEY UPDATE RewardText='$GLieutenant Fairweather sourit à l\'histoire que vous lui racontez de vos aventures à Boulder\'mok.>$B<br :>Ah, j\'aurais aimé être là avec toi. Laisse-moi te dire quelque chose, <name: n\'accepte jamais de devoir qui t\'empêche de la gloire du champ de bataille!$B$BHah! Après tout le nombre d\'ogres que tu as tués, en reste-t-il dans ces montagnes pour moi ?!';
-- Quest 10804 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10804, 'frFR', 'Je ne peux pas les sauver par moi-même, $N!') ON DUPLICATE KEY UPDATE CompletionText='Je ne peux pas les sauver par moi-même, $N!';
-- Quest 10805 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10805, 'frFR', 'Avez-vous réussi à décimer les ogres de Bladespire à la Cachette de Gruul?$B$Ne viens pas me voir avec des excuses, $gboy:girl;! Fais le travail !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à décimer les ogres de Bladespire à la Cachette de Gruul?$B$Ne viens pas me voir avec des excuses, $gboy:girl;! Fais le travail !';
-- Quest 10807 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10807, 'frFR', 'Avez-vous terminé la tâche que je vous ai demandée, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous terminé la tâche que je vous ai demandée, $N?';
-- Quest 10809 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10809, 'frFR', 'Rapportez, $N. Est-ce le sang de Bleeding Hollow que je vois sur votre manche ? J\'espère que oui !') ON DUPLICATE KEY UPDATE CompletionText='Rapportez, $N. Est-ce le sang de Bleeding Hollow que je vois sur votre manche ? J\'espère que oui !';

-- Quest 10809 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10809, 'frFR', 'Ah, alors tu as abattu ce méchant, Kruush !  Bien joué, <name> !  Bien joué !  Sa mort démunira ces chevaliers-loup maudits.  En fait, j\'espère que tu en as abattu quelques-uns lors de ton excursion dans Zeth\'Gor !$B$BVoici ta récompense.  Tu as mérité chaque pièce !') ON DUPLICATE KEY UPDATE RewardText='Ah, alors tu as abattu ce méchant, Kruush !  Bien joué, <name> !  Bien joué !  Sa mort démunira ces chevaliers-loup maudits.  En fait, j\'espère que tu en as abattu quelques-uns lors de ton excursion dans Zeth\'Gor !$B$BVoici ta récompense.  Tu as mérité chaque pièce !';
-- Quest 10812 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10812, 'frFR', 'Le masque que tu tiens dans tes mains est un masque à gaz de Felsworn et d\'après son apparence, il n\'est pas endommagé. Le trouble que nous pouvons causer au Camp de la Forge : La colère est sans limites. Es-tu intéressé à nous aider, <name> ?') ON DUPLICATE KEY UPDATE RewardText='Le masque que tu tiens dans tes mains est un masque à gaz de Felsworn et d\'après son apparence, il n\'est pas endommagé. Le trouble que nous pouvons causer au Camp de la Forge : La colère est sans limites. Es-tu intéressé à nous aider, <name> ?';
-- Quest 10814 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10814, 'frFR', 'Permets-moi de finir de te raconter mon histoire.') ON DUPLICATE KEY UPDATE CompletionText='Permets-moi de finir de te raconter mon histoire.';
-- Quest 10816 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10816, 'frFR', 'Salut, $N. Quelle nouvelle apportes-tu ?') ON DUPLICATE KEY UPDATE CompletionText='Salut, $N. Quelle nouvelle apportes-tu ?';
-- Quest 10817 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10817, 'frFR', 'Salut, $N. Quelle nouvelle apportes-tu ?') ON DUPLICATE KEY UPDATE CompletionText='Salut, $N. Quelle nouvelle apportes-tu ?';
-- Quest 10820 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10820, 'frFR', 'Ma patience est lassante, pourquoi ne les as-tu pas finis ?') ON DUPLICATE KEY UPDATE CompletionText='Ma patience est lassante, pourquoi ne les as-tu pas finis ?';
-- Quest 10821 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10821, 'frFR', 'Cherches-tu à rejoindre ma liste de ceux qui sont jetables ? Prends ces clés et fais taire Doomcryer !') ON DUPLICATE KEY UPDATE CompletionText='Cherches-tu à rejoindre ma liste de ceux qui sont jetables ? Prends ces clés et fais taire Doomcryer !';
-- Quest 10822 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10822, 'frFR', 'Même la plus petite contribution à notre cause est notée, $N. Nos ennemis sont nombreux, mais nous triompherons !') ON DUPLICATE KEY UPDATE CompletionText='Même la plus petite contribution à notre cause est notée, $N. Nos ennemis sont nombreux, mais nous triompherons !';

-- Quest 10822 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10822, 'frFR', 'Victoire aux Voyants ! Les forces de Kael s\'effondreront bientôt.') ON DUPLICATE KEY UPDATE RewardText='Victoire aux Voyants ! Les forces de Kael s\'effondreront bientôt.';
-- Quest 10823 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10823, 'frFR', 'Qu\'avez-vous fait pour nous récemment, $N ? La guerre contre Kael\'thas ne va pas se battre toute seule, vous savez ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'avez-vous fait pour nous récemment, $N ? La guerre contre Kael\'thas ne va pas se battre toute seule, vous savez ?';
-- Quest 10823 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10823, 'frFR', 'Vous vous faites un nom, $N. Continuez comme ça.') ON DUPLICATE KEY UPDATE RewardText='Vous vous faites un nom, $N. Continuez comme ça.';
-- Quest 10827 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10827, 'frFR', 'Portez-vous plus de insignes de nos ennemis, $C ? La Légion Ardente continue d\'être une menace et nous les poursuivons partout où nous les trouvons.') ON DUPLICATE KEY UPDATE CompletionText='Portez-vous plus de insignes de nos ennemis, $C ? La Légion Ardente continue d\'être une menace et nous les poursuivons partout où nous les trouvons.';
-- Quest 10827 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10827, 'frFR', 'Vous continuez à prouver votre valeur, $N. Combattez les ennemis de la Lumière où que vous les trouviez ; vos actions seront bien récompensées.') ON DUPLICATE KEY UPDATE RewardText='Vous continuez à prouver votre valeur, $N. Combattez les ennemis de la Lumière où que vous les trouviez ; vos actions seront bien récompensées.';
-- Quest 10828 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10828, 'frFR', 'Je prendrai toutes les marques restantes que vous pourriez avoir. Ne vous inquiétez pas ; vos actions seront dûment notées.') ON DUPLICATE KEY UPDATE CompletionText='Je prendrai toutes les marques restantes que vous pourriez avoir. Ne vous inquiétez pas ; vos actions seront dûment notées.';
-- Quest 10828 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10828, 'frFR', 'Vous continuez à prouver votre valeur, $N.') ON DUPLICATE KEY UPDATE RewardText='Vous continuez à prouver votre valeur, $N.';
-- Quest 10830 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10830, 'frFR', 'Le mal qui habite les arbres commence à s\'infiltrer dans toute chose naturelle dans la forêt.$B$BVous devez agir rapidement, $N, avant que tout ne soit perdu !') ON DUPLICATE KEY UPDATE CompletionText='Le mal qui habite les arbres commence à s\'infiltrer dans toute chose naturelle dans la forêt.$B$BVous devez agir rapidement, $N, avant que tout ne soit perdu !';

-- Quest 10830 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10830, 'frFR', 'Le mal se retire du Bois du Corbeau !  Le sens-tu, <name>?$B$Vous nous avez sauvés, ainsi que toute la faune environnante, d\'une destruction certaine, petite créature !$B$Je garde quatre bagues magiques parmi mes branches pour de telles occasions, lorsque un héros se lève pour accomplir un grand exploit.$B$Vous êtes un tel héros !  Au nom de tout le Bois du Corbeau, nous vous remercions.') ON DUPLICATE KEY UPDATE RewardText='Le mal se retire du Bois du Corbeau !  Le sens-tu, <name>?$B$Vous nous avez sauvés, ainsi que toute la faune environnante, d\'une destruction certaine, petite créature !$B$Je garde quatre bagues magiques parmi mes branches pour de telles occasions, lorsque un héros se lève pour accomplir un grand exploit.$B$Vous êtes un tel héros !  Au nom de tout le Bois du Corbeau, nous vous remercions.';
-- Quest 10832 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10832, 'frFR', 'As-tu obtenu l\'échantillon de spectre du néant ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu l\'échantillon de spectre du néant ?';
-- Quest 10832 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10832, 'frFR', '<Gidge examine l\'essence du spectre du néant.>$B$Même un si petit échantillon de l\'essence de la créature rayonne de puissance. Peut-être ai-je mal compris ce qui se passe. Nous ne provoquons pas les spectres en puisant de l\'énergie dans l\'environnement. Au contraire, les spectres et l\'environnement sont la même chose !$B$N\'hésite pas à me faire savoir si tu fais d\'autres découvertes, maintenant que tu es un tailleur de feu d\'enchantement.') ON DUPLICATE KEY UPDATE RewardText='<Gidge examine l\'essence du spectre du néant.>$B$Même un si petit échantillon de l\'essence de la créature rayonne de puissance. Peut-être ai-je mal compris ce qui se passe. Nous ne provoquons pas les spectres en puisant de l\'énergie dans l\'environnement. Au contraire, les spectres et l\'environnement sont la même chose !$B$N\'hésite pas à me faire savoir si tu fais d\'autres découvertes, maintenant que tu es un tailleur de feu d\'enchantement.';
-- Quest 10833 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10833, 'frFR', 'As-tu utilisé le pouvoir du cristal pour approfondir ton attunement à l\'Autel des Ombres ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu utilisé le pouvoir du cristal pour approfondir ton attunement à l\'Autel des Ombres ?';
-- Quest 10833 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10833, 'frFR', 'Je peux voir que ta visite à l\'autel a été un succès. Il y a une différence subtile en toi que peu verront, mais il n\'y a aucun doute qu\'elle est là.') ON DUPLICATE KEY UPDATE RewardText='Je peux voir que ta visite à l\'autel a été un succès. Il y a une différence subtile en toi que peu verront, mais il n\'y a aucun doute qu\'elle est là.';
-- Quest 10836 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10836, 'frFR', 'C\'est fait ? J\'espère seulement que ce n\'est pas trop tard...') ON DUPLICATE KEY UPDATE CompletionText='C\'est fait ? J\'espère seulement que ce n\'est pas trop tard...';
-- Quest 10840 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10840, 'frFR', 'Combien d\'étheréens as-tu détruits ? J\'espère que ce sera suffisant pour les chasser du Tombeau des Lumières.') ON DUPLICATE KEY UPDATE CompletionText='Combien d\'étheréens as-tu détruits ? J\'espère que ce sera suffisant pour les chasser du Tombeau des Lumières.';
-- Quest 10843 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10843, 'frFR', 'Les Mok\'Nathal n\'acceptent pas l\'échec, ni les excuses. Soit tu vaincs ton ennemi, soit il te tue !$B$Puisque tu te tiens devant moi, tu as dû tuer Gnosh Brognat déjà.') ON DUPLICATE KEY UPDATE CompletionText='Les Mok\'Nathal n\'acceptent pas l\'échec, ni les excuses. Soit tu vaincs ton ennemi, soit il te tue !$B$Puisque tu te tiens devant moi, tu as dû tuer Gnosh Brognat déjà.';

-- Quest 10845 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10845, 'frFR', 'Bien que vous ne vous surpassiez pas à mes yeux, il n\'y a aucune honte à admettre que vous n\'êtes pas à la hauteur du défi de tuer la mère des dragons du Nether de Singing Ridge.$B$BEst-ce cela que vous êtes venu me dire ?') ON DUPLICATE KEY UPDATE CompletionText='Bien que vous ne vous surpassiez pas à mes yeux, il n\'y a aucune honte à admettre que vous n\'êtes pas à la hauteur du défi de tuer la mère des dragons du Nether de Singing Ridge.$B$BEst-ce cela que vous êtes venu me dire ?';
-- Quest 10846 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10846, 'frFR', 'Nous avons beaucoup d\'ennemis. Certains nous les avons choisis, et d\'autres, comme les Vehk\'nir, nous ne les avons pas choisis.$B$BQuoi qu\'il en soit, nous abattrons tous leurs chefs jusqu\'à ce qu\'aucun ne se tienne devant nous.') ON DUPLICATE KEY UPDATE CompletionText='Nous avons beaucoup d\'ennemis. Certains nous les avons choisis, et d\'autres, comme les Vehk\'nir, nous ne les avons pas choisis.$B$BQuoi qu\'il en soit, nous abattrons tous leurs chefs jusqu\'à ce qu\'aucun ne se tienne devant nous.';
-- Quest 10848 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10848, 'frFR', 'Le mal grandit dans Veil Rhaze. Éteins-le, $r.') ON DUPLICATE KEY UPDATE CompletionText='Le mal grandit dans Veil Rhaze. Éteins-le, $r.';
-- Quest 10850 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10850, 'frFR', 'Vous découvrez une ouverture par laquelle du carburant est chargé dans le prédateur de fel.') ON DUPLICATE KEY UPDATE CompletionText='Vous découvrez une ouverture par laquelle du carburant est chargé dans le prédateur de fel.';
-- Quest 10852 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10852, 'frFR', 'Je m\'ennuie, il n\'y a personne avec qui jouer. Avez-vous trouvé mes amis ?') ON DUPLICATE KEY UPDATE CompletionText='Je m\'ennuie, il n\'y a personne avec qui jouer. Avez-vous trouvé mes amis ?';
