INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10855, 'frFR', 'Avez-vous essayé ma petite expérience, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous essayé ma petite expérience, $N?';
-- Quest 10856 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10856, 'frFR', 'Comment ça va ? Avez-vous eu l\'occasion d\'apprendre une ou deux leçons à la Légion ?') ON DUPLICATE KEY UPDATE CompletionText='Comment ça va ? Avez-vous eu l\'occasion d\'apprendre une ou deux leçons à la Légion ?';
-- Quest 10861 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10861, 'frFR', 'Avez-vous fait ce qui était demandé ? Écrasez le mal avant qu\'il ne soit trop tard !') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous fait ce qui était demandé ? Écrasez le mal avant qu\'il ne soit trop tard !';

