INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10864, 'frFR', 'Le Voyant Démoniaque n\'est pas encore apaisé, $N. Revenez-moi après avoir récolté les âmes des orcs de la Main Brisée.') ON DUPLICATE KEY UPDATE CompletionText='Le Voyant Démoniaque n\'est pas encore apaisé, $N. Revenez-moi après avoir récolté les âmes des orcs de la Main Brisée.';
