INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10867, 'frFR', 'L\'avez-vous fait ? Les âmes de nos ancêtres sont-elles en sécurité, loin du mal des éthérés ?') ON DUPLICATE KEY UPDATE CompletionText='L\'avez-vous fait ? Les âmes de nos ancêtres sont-elles en sécurité, loin du mal des éthérés ?';
