-- Quest 10878 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10878, 'frFR', 'Avez-vous fait ce que je vous ai demandé, $N ? Je crains pour nos vies.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous fait ce que je vous ai demandé, $N ? Je crains pour nos vies.';

