INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10879, 'frFR', 'Ce n\'est pas le moment de bavarder, $N$. Nous sommes attaqués ! Retenez les envahisseurs !') ON DUPLICATE KEY UPDATE CompletionText='Ce n\'est pas le moment de bavarder, $N$. Nous sommes attaqués ! Retenez les envahisseurs !';
