-- Quest 10881 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10881, 'frFR', 'Avez-vous récupéré les reliques, $N$? Nous ne pouvons pas permettre au Conseil des Ombres d\'utiliser son pouvoir à des fins obscures.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous récupéré les reliques, $N$? Nous ne pouvons pas permettre au Conseil des Ombres d\'utiliser son pouvoir à des fins obscures.';
-- Quest 10882 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10882, 'frFR', '<A\'dal porte son attention sur vous, son regard est presque insupportable.>$B$BAndorrien, peut-être ne comprenez-vous pas l\'ampleur de votre mission ? Il n\'y a pas de temps à perdre... rassemblez un groupe de compatriotes et entrez dans Arcatraz.$B$Mettez fin à Harbinger Skyriss.') ON DUPLICATE KEY UPDATE CompletionText='<A\'dal porte son attention sur vous, son regard est presque insupportable.>$B$BAndorrien, peut-être ne comprenez-vous pas l\'ampleur de votre mission ? Il n\'y a pas de temps à perdre... rassemblez un groupe de compatriotes et entrez dans Arcatraz.$B$Mettez fin à Harbinger Skyriss.';
