INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10888, 'frFR', 'Vous vous êtes prouvé comme un être de grand pouvoir. Les naaru vous accordent l\'accès à Tempest Keep.') ON DUPLICATE KEY UPDATE RewardText='Vous vous êtes prouvé comme un être de grand pouvoir. Les naaru vous accordent l\'accès à Tempest Keep.';
-- Quest 10891 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10891, 'frFR', 'Bien sûr, je vous apprendrai à fabriquer une armure impériale ! Cela pourrait vous coûter un peu d\'or... sous forme de barres de thorium !') ON DUPLICATE KEY UPDATE RewardText='Bien sûr, je vous apprendrai à fabriquer une armure impériale ! Cela pourrait vous coûter un peu d\'or... sous forme de barres de thorium !';
