-- Quest 10893 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10893, 'frFR', 'Est-elle morte?$B$B$N, si nous voulons avoir une chance de gagner ici, nous avons besoin que vous semiez la confusion dans leurs rangs en tuant Draaca Longtail !') ON DUPLICATE KEY UPDATE CompletionText='Est-elle morte?$B$B$N, si nous voulons avoir une chance de gagner ici, nous avons besoin que vous semiez la confusion dans leurs rangs en tuant Draaca Longtail !';

-- Quest 10896 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10896, 'frFR', 'As-tu détruit le pire des infestations ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu détruit le pire des infestations ?';
-- Quest 10897 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10897, 'frFR', 'Es-tu sûr de toi, $N$? Se spécialiser dans les potions t\'empêchera de poursuivre d\'autres spécialisations.') ON DUPLICATE KEY UPDATE CompletionText='Es-tu sûr de toi, $N$? Se spécialiser dans les potions t\'empêchera de poursuivre d\'autres spécialisations.';
-- Quest 10899 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10899, 'frFR', 'Es-tu sûr de vouloir devenir un maître transmutateur ? Si tu te spécialises dans ce domaine, tu trouveras impossible de te spécialiser dans les potions ou les élixirs.') ON DUPLICATE KEY UPDATE CompletionText='Es-tu sûr de vouloir devenir un maître transmutateur ? Si tu te spécialises dans ce domaine, tu trouveras impossible de te spécialiser dans les potions ou les élixirs.';
-- Quest 10899 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10899, 'frFR', 'Excellent travail, <name>!  Ces transmutations sont parfaites sous tous les aspects!$B$BI t\'apprendra maintenant la manière dont le processus de transmutation alchimique peut conjurer de la matière à partir de rien!  Utilise bien tes connaissances, maître transmutateur.$B$BMaintenant, si tu veux bien m\'excuser, je dois aller voir un acheteur intéressé par la puissance primale.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>!  Ces transmutations sont parfaites sous tous les aspects!$B$BI t\'apprendra maintenant la manière dont le processus de transmutation alchimique peut conjurer de la matière à partir de rien!  Utilise bien tes connaissances, maître transmutateur.$B$BMaintenant, si tu veux bien m\'excuser, je dois aller voir un acheteur intéressé par la puissance primale.';
-- Quest 10900 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10900, 'frFR', 'Brûle-le, $R$. Brûle-tout! Ils ne méritent rien! M\'entends-tu! RIEN! Ils doivent payer pour ce qu\'ils ont fait. Pour ce qu\'ils continuent de faire.$B$BI tu tuerais Vashj moi-même si je pouvais me libérer de ces maudits liens.$B$BOu peut-être cherches-tu à faire le travail de Neptulon? Sa mort nous sert à tous les deux, peau-douce. M\'aideras-tu à former le bâton sacré.') ON DUPLICATE KEY UPDATE RewardText='Brûle-le, $R$. Brûle-tout! Ils ne méritent rien! M\'entends-tu! RIEN! Ils doivent payer pour ce qu\'ils ont fait. Pour ce qu\'ils continuent de faire.$B$BI tu tuerais Vashj moi-même si je pouvais me libérer de ces maudits liens.$B$BOu peut-être cherches-tu à faire le travail de Neptulon? Sa mort nous sert à tous les deux, peau-douce. M\'aideras-tu à former le bâton sacré.';
-- Quest 10902 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10902, 'frFR', 'Les essences! Les as-tu?') ON DUPLICATE KEY UPDATE CompletionText='Les essences! Les as-tu?';
-- Quest 10914 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10914, 'frFR', 'Tu l\'as fait, <name>! Grâce à toi, nous avons fait une nouvelle découverte...') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait, <name>! Grâce à toi, nous avons fait une nouvelle découverte...';
-- Quest 10915 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10915, 'frFR', 'Tu dois détruire le mal ancien avant qu\'il ne retrouve ses pouvoirs.') ON DUPLICATE KEY UPDATE CompletionText='Tu dois détruire le mal ancien avant qu\'il ne retrouve ses pouvoirs.';

-- Quest 10917 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10917, 'frFR', 'Tu as apporté les plumes que j\'ai demandées, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as apporté les plumes que j\'ai demandées, $N ?';
-- Quest 10918 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10918, 'frFR', 'Les chiens de Skettis gardent toujours un œil attentif sur nous, les exclus. Dès que l\'un de nous foule le sol de Shattrath, nous serons comme morts.$B$Apporte-moi plus de plumes comme preuve de ta victoire sur eux.') ON DUPLICATE KEY UPDATE CompletionText='Les chiens de Skettis gardent toujours un œil attentif sur nous, les exclus. Dès que l\'un de nous foule le sol de Shattrath, nous serons comme morts.$B$Apporte-moi plus de plumes comme preuve de ta victoire sur eux.';
-- Quest 10919 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10919, 'frFR', 'Fei Fei te regarde avec anticipation...') ON DUPLICATE KEY UPDATE CompletionText='Fei Fei te regarde avec anticipation...';
-- Quest 10920 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10920, 'frFR', 'Je sens le poison couler dans mes veines. Le cri du naaru m\'appelle, je vois la lumière. Les veuves de Dreadfang sont-elles vaincues ?') ON DUPLICATE KEY UPDATE CompletionText='Je sens le poison couler dans mes veines. Le cri du naaru m\'appelle, je vois la lumière. Les veuves de Dreadfang sont-elles vaincues ?';
-- Quest 10922 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10922, 'frFR', 'Tu es payé quand le travail est fait, $Gsonny:missy;.') ON DUPLICATE KEY UPDATE CompletionText='Tu es payé quand le travail est fait, $Gsonny:missy;.';
-- Quest 10927 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10927, 'frFR', 'J\'ai juré d\'avoir dit à Sentinel Moonwhisper de donner des ordres directs. Ne les obéis-tu pas ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ai juré d\'avoir dit à Sentinel Moonwhisper de donner des ordres directs. Ne les obéis-tu pas ?';
-- Quest 10928 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10928, 'frFR', 'J\'ai juré d\'avoir dit à Grunt Grahk de donner des ordres directs. Ne les obéis-tu pas ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ai juré d\'avoir dit à Grunt Grahk de donner des ordres directs. Ne les obéis-tu pas ?';
-- Quest 10937 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10937, 'frFR', 'Le maître d\'entraînement est-il mort ? Hmm, peut-être que mes éclaireurs ont tort ?') ON DUPLICATE KEY UPDATE CompletionText='Le maître d\'entraînement est-il mort ? Hmm, peut-être que mes éclaireurs ont tort ?';

-- Quest 10938 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10938, 'frFR', 'J\'ai vu que vous avez réussi à compléter un paquet de Bénédictions ! Félicitations !') ON DUPLICATE KEY UPDATE CompletionText='J\'ai vu que vous avez réussi à compléter un paquet de Bénédictions ! Félicitations !';
-- Quest 10940 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10940, 'frFR', 'J\'ai vu que vous avez réussi à compléter un paquet de Furies ! Félicitations !') ON DUPLICATE KEY UPDATE CompletionText='J\'ai vu que vous avez réussi à compléter un paquet de Furies ! Félicitations !';
-- Quest 10941 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10941, 'frFR', 'J\'ai vu que vous avez réussi à compléter un paquet de Folie ! Félicitations !') ON DUPLICATE KEY UPDATE CompletionText='J\'ai vu que vous avez réussi à compléter un paquet de Folie ! Félicitations !';
-- Quest 10944 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10944, 'frFR', 'Je vous remercie, <name>.  Olum est l\'un de mes amis les plus chers et le suiveur le plus digne de confiance.  Ses contributions ont été d\'une importance vitale pour nos plans.') ON DUPLICATE KEY UPDATE RewardText='Je vous remercie, <name>.  Olum est l\'un de mes amis les plus chers et le suiveur le plus digne de confiance.  Ses contributions ont été d\'une importance vitale pour nos plans.';
-- Quest 10946 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10946, 'frFR', 'La tâche est accomplie, $N ? Illidan n\'est pas un maître patient !') ON DUPLICATE KEY UPDATE CompletionText='La tâche est accomplie, $N ? Illidan n\'est pas un maître patient !';
-- Quest 10946 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10946, 'frFR', 'Vous avez bien fait, $Gname>.  Cela nous rapproche d\'un pas de détourner l\'attention d\'Illidan de nous et de...$B$B$B<br :>Il reste du travail à faire, <name.') ON DUPLICATE KEY UPDATE RewardText='Vous avez bien fait, $Gname>.  Cela nous rapproche d\'un pas de détourner l\'attention d\'Illidan de nous et de...$B$B$B<br :>Il reste du travail à faire, <name.';
-- Quest 10947 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10947, 'frFR', 'Avez-vous récupéré le phylactère, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous récupéré le phylactère, $N ?';
-- Quest 10947 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10947, 'frFR', 'Ma vision... tout devient clair maintenant.  Les pouvoirs que cet artefact a sur une âme.... pour la contenir... pour la siphonner en lui... J\'utiliserai ces pouvoirs pour récupérer ce qui m\'appartient !  Le moment est venu de porter le combat à Illidan !') ON DUPLICATE KEY UPDATE RewardText='Ma vision... tout devient clair maintenant.  Les pouvoirs que cet artefact a sur une âme.... pour la contenir... pour la siphonner en lui... J\'utiliserai ces pouvoirs pour récupérer ce qui m\'appartient !  Le moment est venu de porter le combat à Illidan !';

-- Quest 10959 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10959, 'frFR', 'C\'est comme il était prophétisé, $Gname$.  Un par un, les lieutenants d\'Illidan sont tombés... et maintenant le Traître lui-même a trouvé sa fin !$B<br :>Sachez ceci, <name: chaque décision qu\'Akama a prise et chaque moment de sa vie depuis l\'arrivée d\'Illidan, Akama a planifié ce moment.  Illidan est enfin mort et notre peuple... est libre !') ON DUPLICATE KEY UPDATE RewardText='C\'est comme il était prophétisé, $Gname$.  Un par un, les lieutenants d\'Illidan sont tombés... et maintenant le Traître lui-même a trouvé sa fin !$B<br :>Sachez ceci, <name: chaque décision qu\'Akama a prise et chaque moment de sa vie depuis l\'arrivée d\'Illidan, Akama a planifié ce moment.  Illidan est enfin mort et notre peuple... est libre !';
-- Quest 10960 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10960, 'frFR', 'Il y en a si peu qui sont assez doués pour canaliser une telle puissance depuis M\'uru. Voir cela chez un enfant est vraiment incroyable !$b$bC\'est sage de votre part de l\'amener devant moi.$b$bVous dites qu\'elle est orpheline dans la Cité de Shattrath ? Je veillerai à ce qu\'une pétition soit soumise à la matrone des orphelins là-bas afin qu\'elle puisse être confiée à notre garde pour un entraînement approprié. Elle nous appartient, ici.$b$bAssurez-vous de la garder en sécurité d\'ici là.') ON DUPLICATE KEY UPDATE RewardText='Il y en a si peu qui sont assez doués pour canaliser une telle puissance depuis M\'uru. Voir cela chez un enfant est vraiment incroyable !$b$bC\'est sage de votre part de l\'amener devant moi.$b$bVous dites qu\'elle est orpheline dans la Cité de Shattrath ? Je veillerai à ce qu\'une pétition soit soumise à la matrone des orphelins là-bas afin qu\'elle puisse être confiée à notre garde pour un entraînement approprié. Elle nous appartient, ici.$b$bAssurez-vous de la garder en sécurité d\'ici là.';
-- Quest 10961 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10961, 'frFR', 'Avez-vous apporté les ingrédients pour le breuvage ? Faites attention à ne pas me mettre de pollen, s\'il vous plaît. Je m\'éternue sans contrôle en sa présence.$B$B<Morthis renifle l\'indignité représentée par un éternuement.>') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous apporté les ingrédients pour le breuvage ? Faites attention à ne pas me mettre de pollen, s\'il vous plaît. Je m\'éternue sans contrôle en sa présence.$B$B<Morthis renifle l\'indignité représentée par un éternuement.>';
-- Quest 10961 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10961, 'frFR', 'Avez-vous apporté les ingrédients pour le breuvage ? Faites attention à ne pas me mettre de pollen, s\'il vous plaît. Je m\'éternue sans contrôle en sa présence.$B$B<Morthis accepte les herbes de votre part, les inspectant. Produisant un flacon, il commence à mélanger la potion.>$B$BCela ne prendra qu\'un instant, $N$. Ensuite, vous devez vous rendre à Moonglade.') ON DUPLICATE KEY UPDATE RewardText='Avez-vous apporté les ingrédients pour le breuvage ? Faites attention à ne pas me mettre de pollen, s\'il vous plaît. Je m\'éternue sans contrôle en sa présence.$B$B<Morthis accepte les herbes de votre part, les inspectant. Produisant un flacon, il commence à mélanger la potion.>$B$BCela ne prendra qu\'un instant, $N$. Ensuite, vous devez vous rendre à Moonglade.';
-- Quest 10962 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10962, 'frFR', 'Vous pensez vrai ce qu\'ils disent des Catacombes du Temps ?') ON DUPLICATE KEY UPDATE CompletionText='Vous pensez vrai ce qu\'ils disent des Catacombes du Temps ?';
-- Quest 10963 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10963, 'frFR', 'Si ce qu\'ils disent des Catacombes du Temps est vrai, alors c\'est un lieu de grand pouvoir.') ON DUPLICATE KEY UPDATE CompletionText='Si ce qu\'ils disent des Catacombes du Temps est vrai, alors c\'est un lieu de grand pouvoir.';
-- Quest 10964 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10964, 'frFR', '<Le druide sort de son sommeil, l\'air groggy et hagard. Son regard parcourt la pièce à la recherche de poursuivants invisibles.>$B$BMorthis?$B$BNon, vous n\'êtes pas Morthis... Qui êtes-vous, $R$, et pourquoi avez-vous interrompu mon repos?$B$B<Malgré l\'hostilité de la question, le Druide semble presque soulagé d\'avoir été réveillé.>') ON DUPLICATE KEY UPDATE RewardText='<Le druide sort de son sommeil, l\'air groggy et hagard. Son regard parcourt la pièce à la recherche de poursuivants invisibles.>$B$BMorthis?$B$BNon, vous n\'êtes pas Morthis... Qui êtes-vous, $R$, et pourquoi avez-vous interrompu mon repos?$B$B<Malgré l\'hostilité de la question, le Druide semble presque soulagé d\'avoir été réveillé.>';
-- Quest 10965 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10965, 'frFR', 'Dépêchez-vous, $r$. Si ces créatures s\'échappent du tombeau, Clintar Dreamwalker ne sera pas le seul en danger.') ON DUPLICATE KEY UPDATE CompletionText='Dépêchez-vous, $r$. Si ces créatures s\'échappent du tombeau, Clintar Dreamwalker ne sera pas le seul en danger.';

-- Quest 10966 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10966, 'frFR', 'C\'est bon de vous revoir, $C. J\'espère que vous et le jeune Dornaa avez passé un merveilleux moment ensemble ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est bon de vous revoir, $C. J\'espère que vous et le jeune Dornaa avez passé un merveilleux moment ensemble ?';
-- Quest 10967 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10967, 'frFR', 'C\'est bon de vous revoir, $C. J\'espère que vous et la jeune Salandria avez passé un merveilleux moment ensemble ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est bon de vous revoir, $C. J\'espère que vous et la jeune Salandria avez passé un merveilleux moment ensemble ?';
-- Quest 10971 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10971, 'frFR', 'Avez-vous récupéré des étiquettes d\'identification ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous récupéré des étiquettes d\'identification ?';
-- Quest 10972 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10972, 'frFR', 'J\'ai besoin de plus d\'étiquettes d\'identification, $N. Ce que j\'ai découvert jusqu\'à présent est que ce n\'est pas seulement un moyen de cataloguer les prisonniers, mais cela documente aussi des lieux !$B$BUne fois ce code brisé, nous serons en mesure de déterminer exactement où sont détenus tous nos alliés et de les libérer avec un minimum d\'action hostile.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai besoin de plus d\'étiquettes d\'identification, $N. Ce que j\'ai découvert jusqu\'à présent est que ce n\'est pas seulement un moyen de cataloguer les prisonniers, mais cela documente aussi des lieux !$B$BUne fois ce code brisé, nous serons en mesure de déterminer exactement où sont détenus tous nos alliés et de les libérer avec un minimum d\'action hostile.';
-- Quest 10973 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10973, 'frFR', 'Je sais que c\'est beaucoup demander, mais pensez aux vies qui pourraient être sauvées !') ON DUPLICATE KEY UPDATE CompletionText='Je sais que c\'est beaucoup demander, mais pensez aux vies qui pourraient être sauvées !';
-- Quest 10975 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10975, 'frFR', 'Nous sommes dans une impasse ici, $n. Les données que vous avez collectées nous ont donné suffisamment d\'informations pour sauver nos alliés détenus dans les plus petites prisons de Netherstorm, mais nous devons avancer et éradiquer les plus grandes menaces Ethereum ici à Bash\'ir\'s Landing.$b$bRejoignez la bataille contre les Ethereum ! Apportez les clés de prison Ethereum et je forgerai des clés de chambre de stase Ethereum pour que vous puissiez les utiliser sur les chambres de stase de Bash\'ir.') ON DUPLICATE KEY UPDATE CompletionText='Nous sommes dans une impasse ici, $n. Les données que vous avez collectées nous ont donné suffisamment d\'informations pour sauver nos alliés détenus dans les plus petites prisons de Netherstorm, mais nous devons avancer et éradiquer les plus grandes menaces Ethereum ici à Bash\'ir\'s Landing.$b$bRejoignez la bataille contre les Ethereum ! Apportez les clés de prison Ethereum et je forgerai des clés de chambre de stase Ethereum pour que vous puissiez les utiliser sur les chambres de stase de Bash\'ir.';
-- Quest 10976 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10976, 'frFR', 'Ce sera votre tâche la plus ardue, $N.') ON DUPLICATE KEY UPDATE CompletionText='Ce sera votre tâche la plus ardue, $N.';
-- Quest 10977 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10977, 'frFR', 'Je comprendrais si vous choisissiez de ne pas continuer, $N.') ON DUPLICATE KEY UPDATE CompletionText='Je comprendrais si vous choisissiez de ne pas continuer, $N.';

-- Quest 10978 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10978, 'frFR', 'Clintar vous a aidé à récupérer les reliques ?') ON DUPLICATE KEY UPDATE CompletionText='Clintar vous a aidé à récupérer les reliques ?';
-- Quest 10978 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10978, 'frFR', '<Morthis accepte les reliques de votre part tandis que vous décrivez vos expériences dans les tombeaux de charbon.> $B$BCeci est une nouvelle très troublante, $N$. Il y a eu de nombreuses perturbations étranges dans le Rêve d\'Émeraude, mais je ne me souviens d\'aucune mention de forces extérieures qui s\'y seraient mêlées. Êtes-vous certain que c\'est ce en quoi Clintar croit ?') ON DUPLICATE KEY UPDATE RewardText='<Morthis accepte les reliques de votre part tandis que vous décrivez vos expériences dans les tombeaux de charbon.> $B$BCeci est une nouvelle très troublante, $N$. Il y a eu de nombreuses perturbations étranges dans le Rêve d\'Émeraude, mais je ne me souviens d\'aucune mention de forces extérieures qui s\'y seraient mêlées. Êtes-vous certain que c\'est ce en quoi Clintar croit ?';
-- Quest 10980 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10980, 'frFR', '<Arthorn vous regarde avec espoir.> $B$BAvez-vous réussi à trouver des informations sur le livre ?') ON DUPLICATE KEY UPDATE CompletionText='<Arthorn vous regarde avec espoir.> $B$BAvez-vous réussi à trouver des informations sur le livre ?';
-- Quest 10980 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10980, 'frFR', 'N\'est-ce pas incroyable que même parmi les arakkoa, les cultistes aient été considérés comme des hérétiques ? Que les prêtres traditionnels les aient détestés au point de détruire leur texte sacré est incroyable ! Nous devons mettre la main sur ce livre, $N.$B$BC\'est la clé pour démêler le mystère du dieu corbeau et l\'empêcher de prendre le contrôle du Rêve d\'Émeraude.$B$BPeut-être que Morthis acceptera enfin de me prendre comme étudiant si nous réussissons !') ON DUPLICATE KEY UPDATE RewardText='N\'est-ce pas incroyable que même parmi les arakkoa, les cultistes aient été considérés comme des hérétiques ? Que les prêtres traditionnels les aient détestés au point de détruire leur texte sacré est incroyable ! Nous devons mettre la main sur ce livre, $N.$B$BC\'est la clé pour démêler le mystère du dieu corbeau et l\'empêcher de prendre le contrôle du Rêve d\'Émeraude.$B$BPeut-être que Morthis acceptera enfin de me prendre comme étudiant si nous réussissons !';
-- Quest 10981 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10981, 'frFR', 'Seuls les aventuriers les plus constants et aguerris accepteront cette offre, $n$. Si vous souhaitez affronter les horreurs de la deuxième chambre de stase dans les Tombeaux de Mana, je peux synthétiser une clé. Apportez-moi une marque du Roi du Nexus et je la ferai.') ON DUPLICATE KEY UPDATE CompletionText='Seuls les aventuriers les plus constants et aguerris accepteront cette offre, $n$. Si vous souhaitez affronter les horreurs de la deuxième chambre de stase dans les Tombeaux de Mana, je peux synthétiser une clé. Apportez-moi une marque du Roi du Nexus et je la ferai.';
-- Quest 10981 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10981, 'frFR', 'Comme promis, voici la clé de la chambre de stase personnelle de Shaffar.') ON DUPLICATE KEY UPDATE RewardText='Comme promis, voici la clé de la chambre de stase personnelle de Shaffar.';
-- Quest 10982 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10982, 'frFR', 'Vous avez fait beaucoup pour le Protectorat et le Consortium, $N$. Il est donc juste que le premier de nos nouvelles clés vous revienne. Avec cette clé, vous pourrez ouvrir la chambre de stase personnelle de Shaffar à tout moment sans avoir à dépenser la clé elle-même.$b$b<Ameer hoche la tête.> $b$bC\'est permanent et restera avec vous pour toujours.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait beaucoup pour le Protectorat et le Consortium, $N$. Il est donc juste que le premier de nos nouvelles clés vous revienne. Avec cette clé, vous pourrez ouvrir la chambre de stase personnelle de Shaffar à tout moment sans avoir à dépenser la clé elle-même.$b$b<Ameer hoche la tête.> $b$bC\'est permanent et restera avec vous pour toujours.';
-- Quest 10987 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10987, 'frFR', 'Avez-vous attrapé un faucon-mouche ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous attrapé un faucon-mouche ?';

-- Quest 10987 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10987, 'frFR', 'Bien joué ! Je suis toujours en train de faire en sorte que les faucons me fassent confiance, mais je sais assez à leur sujet pour entraîner celui-ci pour vos besoins.') ON DUPLICATE KEY UPDATE RewardText='Bien joué ! Je suis toujours en train de faire en sorte que les faucons me fassent confiance, mais je sais assez à leur sujet pour entraîner celui-ci pour vos besoins.';
-- Quest 10988 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10988, 'frFR', 'Avez-vous récupéré suffisamment du Livre du Corbeau pour que je puisse le reconstituer ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous récupéré suffisamment du Livre du Corbeau pour que je puisse le reconstituer ?';
-- Quest 10988 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10988, 'frFR', '<Arthorn accepte les fragments du Livre du Corbeau de votre part et commence à les assembler.>$B$Certains des caractères ont été effacés, mais je devrais pouvoir distinguer la plupart de ceci...') ON DUPLICATE KEY UPDATE RewardText='<Arthorn accepte les fragments du Livre du Corbeau de votre part et commence à les assembler.>$B$Certains des caractères ont été effacés, mais je devrais pouvoir distinguer la plupart de ceci...';
-- Quest 10990 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10990, 'frFR', '<Le faucon mignon semble parler avec la voix d\'Arthorn.>$B$Avez-vous réussi à libérer l\'essence de l\'esprit de l\'aigle ?') ON DUPLICATE KEY UPDATE CompletionText='<Le faucon mignon semble parler avec la voix d\'Arthorn.>$B$Avez-vous réussi à libérer l\'essence de l\'esprit de l\'aigle ?';
-- Quest 10990 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10990, 'frFR', '<Arthorn semble ressentir la puissance dans l\'essence récupérée à travers les sens du faucon mignon.>$B$Même après des milliers d\'années de captivité, le pouvoir de l\'aigle demeure fort. Si les autres essences sont aussi fortes que celle de l\'aigle, le dieu corbeau aura raison de vous craindre.') ON DUPLICATE KEY UPDATE RewardText='<Arthorn semble ressentir la puissance dans l\'essence récupérée à travers les sens du faucon mignon.>$B$Même après des milliers d\'années de captivité, le pouvoir de l\'aigle demeure fort. Si les autres essences sont aussi fortes que celle de l\'aigle, le dieu corbeau aura raison de vous craindre.';
-- Quest 10991 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10991, 'frFR', '<Une fois de plus, la voix d\'Arthorn émane du faucon mignon.>$B$Avez-vous l\'essence du faucon ?') ON DUPLICATE KEY UPDATE CompletionText='<Une fois de plus, la voix d\'Arthorn émane du faucon mignon.>$B$Avez-vous l\'essence du faucon ?';
-- Quest 10991 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10991, 'frFR', '<Le faucon mignon transmet fidèlement les paroles d\'Arthorn.>$B$Bien joué, $N$. J\'avais peur que la prison du faucon ait été détruite dans l\'explosion d\'Auchindoun. Nous sommes presque prêts à affronter Anzu, $N$. J\'adorerais vous accompagner, être là quand ce "god" tựproclamé sera renvoyé dans le puits qui l\'a engendré !') ON DUPLICATE KEY UPDATE RewardText='<Le faucon mignon transmet fidèlement les paroles d\'Arthorn.>$B$Bien joué, $N$. J\'avais peur que la prison du faucon ait été détruite dans l\'explosion d\'Auchindoun. Nous sommes presque prêts à affronter Anzu, $N$. J\'adorerais vous accompagner, être là quand ce "god" tựproclamé sera renvoyé dans le puits qui l\'a engendré !';
-- Quest 10992 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10992, 'frFR', 'Avez-vous vaincu le gardien du faucon et gagné son essence ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous vaincu le gardien du faucon et gagné son essence ?';

-- Quest 10992 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10992, 'frFR', 'Maintenant que nous avons toutes les essences, Morthis Whisperwing doit trouver un moyen de les combiner en un amulet que vous pourrez utiliser pour défier le dieu corbeau, le tirer du Rêve d\'Émeraude et le vaincre. Je vais lui envoyer mes notes sur les esprits dans l\'espoir qu\'il réalise la valeur de mon aperçu.$B$BChacun des esprits a béni un charme que j\'ai préparé pour vous.') ON DUPLICATE KEY UPDATE RewardText='Maintenant que nous avons toutes les essences, Morthis Whisperwing doit trouver un moyen de les combiner en un amulet que vous pourrez utiliser pour défier le dieu corbeau, le tirer du Rêve d\'Émeraude et le vaincre. Je vais lui envoyer mes notes sur les esprits dans l\'espoir qu\'il réalise la valeur de mon aperçu.$B$BChacun des esprits a béni un charme que j\'ai préparé pour vous.';
-- Quest 10993 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10993, 'frFR', 'J\'attends des nouvelles d\'Arthorn. Qu\'avez-vous découvert ?') ON DUPLICATE KEY UPDATE CompletionText='J\'attends des nouvelles d\'Arthorn. Qu\'avez-vous découvert ?';
-- Quest 10993 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10993, 'frFR', '<Morthis accepte le paquet, l\'ouvre pour découvrir les notes d\'Arthorn, et les lit sans commenter l\'auteur.>$B$BÀ un niveau, je suis soulagé de connaître enfin l\'identité de notre ennemi, mais cet Anzu est un être d\'une puissance considérable. Connaître la nature et le nom de votre adversaire est vital, mais nous ne sommes pas encore prêts à l\'affronter.') ON DUPLICATE KEY UPDATE RewardText='<Morthis accepte le paquet, l\'ouvre pour découvrir les notes d\'Arthorn, et les lit sans commenter l\'auteur.>$B$BÀ un niveau, je suis soulagé de connaître enfin l\'identité de notre ennemi, mais cet Anzu est un être d\'une puissance considérable. Connaître la nature et le nom de votre adversaire est vital, mais nous ne sommes pas encore prêts à l\'affronter.';
-- Quest 10994 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (10994, 'frFR', 'Vous avez l\'air d\'avoir traversé une épreuve. La pierre de lune était vraiment si difficile à trouver ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez l\'air d\'avoir traversé une épreuve. La pierre de lune était vraiment si difficile à trouver ?';
-- Quest 10994 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (10994, 'frFR', '<Morthis semble déchiré, désirant à la fois rire de votre histoire et se souvenir de la façon dont vous avez failli perdre la pierre de lune. Il se contente de fixer la pierre lumineuse.>$B$Je vais commencer à l\'infuser avec les essences de l\'esprit d\'oiseau. Bientôt, vous serez prêt à défier notre ennemi.') ON DUPLICATE KEY UPDATE RewardText='<Morthis semble déchiré, désirant à la fois rire de votre histoire et se souvenir de la façon dont vous avez failli perdre la pierre de lune. Il se contente de fixer la pierre lumineuse.>$B$Je vais commencer à l\'infuser avec les essences de l\'esprit d\'oiseau. Bientôt, vous serez prêt à défier notre ennemi.';
-- Quest 11001 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11001, 'frFR', 'Quelles nouvelles des Salles de Sethekk ? Avez-vous vaincu Anzu ?') ON DUPLICATE KEY UPDATE CompletionText='Quelles nouvelles des Salles de Sethekk ? Avez-vous vaincu Anzu ?';
-- Quest 11001 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11001, 'frFR', 'C\'est bon de vous revoir, $N. Votre triomphe sur le dieu corbeau compte bien plus que n\'importe quel test ou rite de passage que je pourrais vous infliger.$B$BVous vous êtes vraiment prouvé digne de la connaissance gardée par les Druides du Talon depuis d\'innombrables générations.') ON DUPLICATE KEY UPDATE RewardText='C\'est bon de vous revoir, $N. Votre triomphe sur le dieu corbeau compte bien plus que n\'importe quel test ou rite de passage que je pourrais vous infliger.$B$BVous vous êtes vraiment prouvé digne de la connaissance gardée par les Druides du Talon depuis d\'innombrables générations.';
-- Quest 11002 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11002, 'frFR', 'Pour la première fois - depuis ce dont je me souviens - il y a du silence.') ON DUPLICATE KEY UPDATE CompletionText='Pour la première fois - depuis ce dont je me souviens - il y a du silence.';

-- Quest 11003 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11003, 'frFR', 'Pour la première fois - depuis ce que je me souviens - il y a du silence.') ON DUPLICATE KEY UPDATE CompletionText='Pour la première fois - depuis ce que je me souviens - il y a du silence.';
-- Quest 11004 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11004, 'frFR', 'As-tu obtenu la poussière, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu la poussière, $N?';
-- Quest 11005 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11005, 'frFR', 'La tâche est accomplie, $N? Je tuerais ces maudits hommes-oiseaux moi-même si ce n\'était pas mes blessures.') ON DUPLICATE KEY UPDATE CompletionText='La tâche est accomplie, $N? Je tuerais ces maudits hommes-oiseaux moi-même si ce n\'était pas mes blessures.';
-- Quest 11006 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11006, 'frFR', 'Il semble que le commandant n\'était pas délirant après tout. Apporte-moi plus de poussière et je te préparerai un autre élixir.') ON DUPLICATE KEY UPDATE CompletionText='Il semble que le commandant n\'était pas délirant après tout. Apporte-moi plus de poussière et je te préparerai un autre élixir.';
-- Quest 11008 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11008, 'frFR', 'As-tu terminé ta mission ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé ta mission ?';
-- Quest 11011 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11011, 'frFR', 'Garde la pierre de lune avec toi, $N. Si tu soupçonnes qu\'Anzu rassemble ses forces pour tenter un autre retour dans ce monde, utilise-la pour le vaincre à nouveau.') ON DUPLICATE KEY UPDATE RewardText='Garde la pierre de lune avec toi, $N. Si tu soupçonnes qu\'Anzu rassemble ses forces pour tenter un autre retour dans ce monde, utilise-la pour le vaincre à nouveau.';
-- Quest 11012 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11012, 'frFR', 'Nos terres sont perdues. Nos enfants volés dans la nuit, forcés à l\'esclavage - ou pire...$B$B<La voix de Mordenai se tend.>$B$BLe temps est venu, mon allié. Le temps de reprendre ce qui fut une fois le nôtre est arrivé ! Tu t\'es prouvé un combattant capable et une âme compatissante.$B$BJureras-tu d\'aider la Volée du Dragon de Netherwing à reprendre nos terres et à reconstruire nos foyers ? Jureras-tu de veiller sur la volée et de permettre à la lignée de renaître ? Jure ceci et battons-nous pour notre foyer et nos proches !') ON DUPLICATE KEY UPDATE RewardText='Nos terres sont perdues. Nos enfants volés dans la nuit, forcés à l\'esclavage - ou pire...$B$B<La voix de Mordenai se tend.>$B$BLe temps est venu, mon allié. Le temps de reprendre ce qui fut une fois le nôtre est arrivé ! Tu t\'es prouvé un combattant capable et une âme compatissante.$B$BJureras-tu d\'aider la Volée du Dragon de Netherwing à reprendre nos terres et à reconstruire nos foyers ? Jureras-tu de veiller sur la volée et de permettre à la lignée de renaître ? Jure ceci et battons-nous pour notre foyer et nos proches !';
-- Quest 11019 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11019, 'frFR', 'Nous ne pensions pas te laisser affronter l\'armée des orcs fel tout seul, si ?$B$B<Les yeux de Yarzill scintillent d\'un bleu translucide.>$B$BOui, nous sommes là avec toi, $N. Pour chaque service que tu rends aux orcs fel dans ta quête pour récupérer les terres de Netherwing, nous serons à tes côtés pour nous assurer qu\'ils subissent un recul suffisant.$B$BTu devras rester discret afin de ne pas attirer d\'attention indésirable sur toi pendant tes missions de sabotage.') ON DUPLICATE KEY UPDATE RewardText='Nous ne pensions pas te laisser affronter l\'armée des orcs fel tout seul, si ?$B$B<Les yeux de Yarzill scintillent d\'un bleu translucide.>$B$BOui, nous sommes là avec toi, $N. Pour chaque service que tu rends aux orcs fel dans ta quête pour récupérer les terres de Netherwing, nous serons à tes côtés pour nous assurer qu\'ils subissent un recul suffisant.$B$BTu devras rester discret afin de ne pas attirer d\'attention indésirable sur toi pendant tes missions de sabotage.';

-- Quest 11021 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11021, 'frFR', 'Qu\'est-ce que tu m\'as apporté ?  Je ne peux pas déchiffrer l\'écriture sur ce tome, <name>... ma perte de sang... a dû brouiller ma vision.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que tu m\'as apporté ?  Je ne peux pas déchiffrer l\'écriture sur ce tome, <name>... ma perte de sang... a dû brouiller ma vision.';
-- Quest 11022 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11022, 'frFR', 'Mon bon homme, je suis heureux que vous ayez décidé de me parler à nouveau avant de partir.') ON DUPLICATE KEY UPDATE RewardText='Mon bon homme, je suis heureux que vous ayez décidé de me parler à nouveau avant de partir.';
-- Quest 11026 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11026, 'frFR', 'Nous espérons que vous avez utilisé le cristal d\'exil pour faire partir un tas de ces choses de la Légion des Flammes ?!') ON DUPLICATE KEY UPDATE CompletionText='Nous espérons que vous avez utilisé le cristal d\'exil pour faire partir un tas de ces choses de la Légion des Flammes ?!';
-- Quest 11027 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11027, 'frFR', 'Les démons de ce campous réparent le transporteur tout le temps. Gahk dit que fracasse les démons mieux cette fois !$b$bMais, Gahk a besoin d\'une autre rune sombre pour faire la rune sombre forgée par cristal.$b$bSi little $r n\'a pas de rune sombre, tu parles avec Kronk. Lui essaie de faire une rune sombre tous les jours ! Peut-être que tu en obtiendras une dans son sac à dos ?!') ON DUPLICATE KEY UPDATE CompletionText='Les démons de ce campous réparent le transporteur tout le temps. Gahk dit que fracasse les démons mieux cette fois !$b$bMais, Gahk a besoin d\'une autre rune sombre pour faire la rune sombre forgée par cristal.$b$bSi little $r n\'a pas de rune sombre, tu parles avec Kronk. Lui essaie de faire une rune sombre tous les jours ! Peut-être que tu en obtiendras une dans son sac à dos ?!';
-- Quest 11027 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11027, 'frFR', 'Haha, bien ! Gahk aime les runes sombres ! Tu prends la rune sombre forgée par cristal que Gahk a faite plus tôt.$B$B$N souviens-toi, contrôle le dégradeur, puis utilise le marteau pour fracasser le bouclier magique sur le transporteur de Shartuul. Lâche l\'autre démon et bats-le pour le contrôler aussi ! Puis fracasse et contrôle plus de démons jusqu\'à ce qu\'il n\'y en ait plus !$B$BDen tu sauves Ogri\'la !') ON DUPLICATE KEY UPDATE RewardText='Haha, bien ! Gahk aime les runes sombres ! Tu prends la rune sombre forgée par cristal que Gahk a faite plus tôt.$B$B$N souviens-toi, contrôle le dégradeur, puis utilise le marteau pour fracasser le bouclier magique sur le transporteur de Shartuul. Lâche l\'autre démon et bats-le pour le contrôler aussi ! Puis fracasse et contrôle plus de démons jusqu\'à ce qu\'il n\'y en ait plus !$B$BDen tu sauves Ogri\'la !';
-- Quest 11031 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11031, 'frFR', 'Vous avez renoncé à votre choix précédent ? Je suppose que je peux vous aider à l\'annuler. Au final, Dalaran se soucie plus de votre loyauté que de la manière dont vous choisissez de la montrer.$b$bCe ne sera pas bon marché. Et bien sûr, j\'aurai besoin de votre ancienne bague en retour.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez renoncé à votre choix précédent ? Je suppose que je peux vous aider à l\'annuler. Au final, Dalaran se soucie plus de votre loyauté que de la manière dont vous choisissez de la montrer.$b$bCe ne sera pas bon marché. Et bien sûr, j\'aurai besoin de votre ancienne bague en retour.';
-- Quest 11032 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11032, 'frFR', 'Vous avez renoncé à votre choix précédent ? Je suppose que je peux vous aider à l\'annuler. Au final, Dalaran se soucie plus de votre loyauté que de la manière dont vous choisissez de la montrer.$b$bCe ne sera pas bon marché. Et bien sûr, j\'aurai besoin de votre ancienne bague en retour.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez renoncé à votre choix précédent ? Je suppose que je peux vous aider à l\'annuler. Au final, Dalaran se soucie plus de votre loyauté que de la manière dont vous choisissez de la montrer.$b$bCe ne sera pas bon marché. Et bien sûr, j\'aurai besoin de votre ancienne bague en retour.';
-- Quest 11033 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11033, 'frFR', 'Vous avez renoncé à votre choix précédent ? Je suppose que je peux vous aider à l\'annuler. Au final, Dalaran se soucie plus de votre loyauté que de la manière dont vous choisissez de la montrer.$b$bCe ne sera pas bon marché. Et bien sûr, j\'aurai besoin de votre ancienne bague en retour.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez renoncé à votre choix précédent ? Je suppose que je peux vous aider à l\'annuler. Au final, Dalaran se soucie plus de votre loyauté que de la manière dont vous choisissez de la montrer.$b$bCe ne sera pas bon marché. Et bien sûr, j\'aurai besoin de votre ancienne bague en retour.';

-- Quest 11034 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11034, 'frFR', 'Vous avez changé d\'avis par rapport à votre choix précédent ? J\'imagine que je peux vous aider à l\'annuler. Au final, Dalaran se soucie plus de votre loyauté que de la manière dont vous choisissez de la montrer.$b$bCe ne sera pas bon marché. Et bien sûr, j\'aurai besoin de votre ancienne bague en retour.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez changé d\'avis par rapport à votre choix précédent ? J\'imagine que je peux vous aider à l\'annuler. Au final, Dalaran se soucie plus de votre loyauté que de la manière dont vous choisissez de la montrer.$b$bCe ne sera pas bon marché. Et bien sûr, j\'aurai besoin de votre ancienne bague en retour.';
-- Quest 11034 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11034, 'frFR', 'Prenez cette prochaine décision avec soin. Nous faisons de notre mieux pour accommoder nos alliés, mais même les ressources de Dalaran ont leurs limites.') ON DUPLICATE KEY UPDATE RewardText='Prenez cette prochaine décision avec soin. Nous faisons de notre mieux pour accommoder nos alliés, mais même les ressources de Dalaran ont leurs limites.';
-- Quest 11036 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11036, 'frFR', 'Est-ce la livraison d\'Old Orok ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce la livraison d\'Old Orok ?';
-- Quest 11047 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11047, 'frFR', '<Dama écoute la requête d\'Agadai.>$B$Je ne peux pas garantir qu\'il y aura des cavaliers-vent disponibles, mais je vais voir ce que je peux faire. Pour l\'instant, nous avons du mal à suivre la demande des autres acheteurs et des postes avancés.') ON DUPLICATE KEY UPDATE RewardText='<Dama écoute la requête d\'Agadai.>$B$Je ne peux pas garantir qu\'il y aura des cavaliers-vent disponibles, mais je vais voir ce que je peux faire. Pour l\'instant, nous avons du mal à suivre la demande des autres acheteurs et des postes avancés.';
-- Quest 11049 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11049, 'frFR', 'Neltharaku sera extrêmement satisfait, $N. Bon travail.') ON DUPLICATE KEY UPDATE RewardText='Neltharaku sera extrêmement satisfait, $N. Bon travail.';
-- Quest 11050 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11050, 'frFR', 'Nous n\'avons pas besoin que ces œufs tombent entre de mauvaises mains,$N. Apportez-moi tout œuf supplémentaire que vous trouverez.$B$BN\'oubliez pas de rester discret ET d\'éviter de susciter des soupçons !') ON DUPLICATE KEY UPDATE CompletionText='Nous n\'avons pas besoin que ces œufs tombent entre de mauvaises mains,$N. Apportez-moi tout œuf supplémentaire que vous trouverez.$B$BN\'oubliez pas de rester discret ET d\'éviter de susciter des soupçons !';
-- Quest 11053 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11053, 'frFR', 'J\'ai suivi vos activités de près, $Gname>. Vous vous êtes avéré être un atout inestimable pour Dragonmaw. Ceci dit, je vais vous promouvoir au poste de Surveillant. Ce rang s\'accompagne de nouvelles responsabilités que vous devez accomplir.$B<br :>Levez-vous, Surveillant <name! Levez-vous et cherchez ceux qui ont besoin de votre aide au camp de base.') ON DUPLICATE KEY UPDATE RewardText='J\'ai suivi vos activités de près, $Gname>. Vous vous êtes avéré être un atout inestimable pour Dragonmaw. Ceci dit, je vais vous promouvoir au poste de Surveillant. Ce rang s\'accompagne de nouvelles responsabilités que vous devez accomplir.$B<br :>Levez-vous, Surveillant <name! Levez-vous et cherchez ceux qui ont besoin de votre aide au camp de base.';
-- Quest 11054 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11054, 'frFR', 'Il y a des pions à discipliner, $N! Dépêchez-vous !') ON DUPLICATE KEY UPDATE CompletionText='Il y a des pions à discipliner, $N! Dépêchez-vous !';

-- Quest 11054 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11054, 'frFR', 'ARRR! Tu pourrais devenir un surveillant après tout. Ce lézard surdimensionné a été le fléau de tant d\'orcs !$B$B<Chief Overseer Mudlump commence à fabriquer l\'arme.>') ON DUPLICATE KEY UPDATE RewardText='ARRR! Tu pourrais devenir un surveillant après tout. Ce lézard surdimensionné a été le fléau de tant d\'orcs !$B$B<Chief Overseer Mudlump commence à fabriquer l\'arme.>';
-- Quest 11058 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11058, 'frFR', 'As-tu appris à utiliser la relique d\'apexis ? Nous et la Garde Céleste Sha\'tari juste au nord sommes intéressés par ce que tu en apprends.') ON DUPLICATE KEY UPDATE CompletionText='As-tu appris à utiliser la relique d\'apexis ? Nous et la Garde Céleste Sha\'tari juste au nord sommes intéressés par ce que tu en apprends.';
-- Quest 11059 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11059, 'frFR', 'Nous abhorrons la violence, mais au moins le construct que nous t\'avons envoyé n\'est pas un être vivant.$B$BS\'en parlant de ça, as-tu la tête ?') ON DUPLICATE KEY UPDATE CompletionText='Nous abhorrons la violence, mais au moins le construct que nous t\'avons envoyé n\'est pas un être vivant.$B$BS\'en parlant de ça, as-tu la tête ?';
-- Quest 11060 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11060, 'frFR', 'Les démons sont en train de rendre le Camp de Forge : Wrath plus grand. Bientôt, ils seront trop grands et nous écraseront. Tu les écrase d\'abord !$b$bLe transporteur de Shartuul est la clé, mais il est protégé par un bouclier magique et un démon appelé un dégradeur. Nous sommes puissants $c, et faisons une darkrune spéciale qui te donne le contrôle du dégradeur. $r donne à Gahk la darkrune, nous te donnons en échange la darkrune crystalforged.$b$bPrends le contrôle du dégradeur et possède autant de démons qui passent par la porte que tu peux pour les arrêter !') ON DUPLICATE KEY UPDATE CompletionText='Les démons sont en train de rendre le Camp de Forge : Wrath plus grand. Bientôt, ils seront trop grands et nous écraseront. Tu les écrase d\'abord !$b$bLe transporteur de Shartuul est la clé, mais il est protégé par un bouclier magique et un démon appelé un dégradeur. Nous sommes puissants $c, et faisons une darkrune spéciale qui te donne le contrôle du dégradeur. $r donne à Gahk la darkrune, nous te donnons en échange la darkrune crystalforged.$b$bPrends le contrôle du dégradeur et possède autant de démons qui passent par la porte que tu peux pour les arrêter !';
-- Quest 11061 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11061, 'frFR', 'Le flacon de ce sorcier est sûr de rendre mes gars plus intelligents qu\'ils ne le sont déjà, et cela devrait aider énormément avec ce qu\'ils devront faire une fois qu\'ils seront dans la Garde Céleste Sha\'tari.') ON DUPLICATE KEY UPDATE CompletionText='Le flacon de ce sorcier est sûr de rendre mes gars plus intelligents qu\'ils ne le sont déjà, et cela devrait aider énormément avec ce qu\'ils devront faire une fois qu\'ils seront dans la Garde Céleste Sha\'tari.';
-- Quest 11061 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11061, 'frFR', 'Nous ne pouvons te remercier assez, <name>!$B$BMaintenant, avec ces deux flacons, instables s\'ils soient, nous serons en mesure d\'envoyer l\'un de nos gars au Poste de Garde Céleste.$B$BIci, attends un instant et nous appellerons l\'un d\'eux.') ON DUPLICATE KEY UPDATE RewardText='Nous ne pouvons te remercier assez, <name>!$B$BMaintenant, avec ces deux flacons, instables s\'ils soient, nous serons en mesure d\'envoyer l\'un de nos gars au Poste de Garde Céleste.$B$BIci, attends un instant et nous appellerons l\'un d\'eux.';
-- Quest 11063 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11063, 'frFR', 'Alors tu veux rejoindre les Skybreakers, hein ? Tu t\'es certainement prouvé être un Dragonmaw capable, mais cela ne signifie rien dans les cieux d\'Outland. La question doit être posée : PEUX-TU VOLER?$B$BEt je ne parle pas seulement de pouvoir monter sur un drake du nether et livrer une cargaison de cristaux au fort comme ces crétins transporteurs. Je parle d\'être le meilleur... Le meilleur orc...$B$BVers l\'ouest, il y a six cavaliers. Vaincs-les tous et je te donnerai des ailes de Skybreaker.') ON DUPLICATE KEY UPDATE RewardText='Alors tu veux rejoindre les Skybreakers, hein ? Tu t\'es certainement prouvé être un Dragonmaw capable, mais cela ne signifie rien dans les cieux d\'Outland. La question doit être posée : PEUX-TU VOLER?$B$BEt je ne parle pas seulement de pouvoir monter sur un drake du nether et livrer une cargaison de cristaux au fort comme ces crétins transporteurs. Je parle d\'être le meilleur... Le meilleur orc...$B$BVers l\'ouest, il y a six cavaliers. Vaincs-les tous et je te donnerai des ailes de Skybreaker.';
-- Quest 11065 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11065, 'frFR', 'Tu as déjà capturé des rayons d\'éther ? Tu as l\'air d\'avoir des compétences avec la corde, donc ça ne devrait pas te prendre trop de temps.') ON DUPLICATE KEY UPDATE CompletionText='Tu as déjà capturé des rayons d\'éther ? Tu as l\'air d\'avoir des compétences avec la corde, donc ça ne devrait pas te prendre trop de temps.';

-- Quest 11065 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11065, 'frFR', 'Hourra !  Bon travail, <name>!  Ces rayons feront d\'excellents montures!$B$Restez, gamin... le Garde-ciel Sha\'tari peut toujours utiliser un homme de vos talents évidents!') ON DUPLICATE KEY UPDATE RewardText='Hourra !  Bon travail, <name>!  Ces rayons feront d\'excellents montures!$B$Restez, gamin... le Garde-ciel Sha\'tari peut toujours utiliser un homme de vos talents évidents!';
-- Quest 11067 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11067, 'frFR', 'Trope a vaincu certains de mes meilleurs cavaliers. Ne vous laissez pas berner par cette saleté.') ON DUPLICATE KEY UPDATE CompletionText='Trope a vaincu certains de mes meilleurs cavaliers. Ne vous laissez pas berner par cette saleté.';
-- Quest 11070 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11070, 'frFR', 'Mulverick est le cavalier le plus doué que j\'aie jamais vu. La seule chose qui le retient de la place de meilleur orc est son imprudence.') ON DUPLICATE KEY UPDATE CompletionText='Mulverick est le cavalier le plus doué que j\'aie jamais vu. La seule chose qui le retient de la place de meilleur orc est son imprudence.';
-- Quest 11071 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11071, 'frFR', 'La deuxième place n\'est pas si mauvaise, $N. Tu peux prendre la place de Mulverick dans l\'équipe...') ON DUPLICATE KEY UPDATE CompletionText='La deuxième place n\'est pas si mauvaise, $N. Tu peux prendre la place de Mulverick dans l\'équipe...';
-- Quest 11072 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11072, 'frFR', 'As-tu terminé ta tâche, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé ta tâche, $N?';
-- Quest 11072 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11072, 'frFR', 'Excellent! Prends ceci. J\'ai préparé ce paquet avec les objets que tu as obtenus. Ils te permettront d\'invoquer Terokk.$B$BBare, $N. C\'est le plus puissant arakkoa qui ait jamais existé. Ne le sous-estime pas!') ON DUPLICATE KEY UPDATE RewardText='Excellent! Prends ceci. J\'ai préparé ce paquet avec les objets que tu as obtenus. Ils te permettront d\'invoquer Terokk.$B$BBare, $N. C\'est le plus puissant arakkoa qui ait jamais existé. Ne le sous-estime pas!';
-- Quest 11073 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11073, 'frFR', 'C\'est fait, $N? Terokk a-t-il été vaincu?') ON DUPLICATE KEY UPDATE CompletionText='C\'est fait, $N? Terokk a-t-il été vaincu?';
-- Quest 11074 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11074, 'frFR', 'J\'exige un jeton de chacun des descendants des plus grands adversaires de Terokk. Ce n\'est qu\'alors que nous serons prêts à invoquer Terokk.') ON DUPLICATE KEY UPDATE CompletionText='J\'exige un jeton de chacun des descendants des plus grands adversaires de Terokk. Ce n\'est qu\'alors que nous serons prêts à invoquer Terokk.';

-- Quest 11077 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11077, 'frFR', 'Comment avance le problème d\'infestation de ces flayer ?') ON DUPLICATE KEY UPDATE CompletionText='Comment avance le problème d\'infestation de ces flayer ?';
-- Quest 11078 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11078, 'frFR', 'Comment se passe ta mission, $N ? Je ne vais pas te dire à quel point c\'est important pour notre capacité à voler par ici.') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe ta mission, $N ? Je ne vais pas te dire à quel point c\'est important pour notre capacité à voler par ici.';
-- Quest 11078 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11078, 'frFR', 'Oui !  Ces dents ont l\'air assez tranchantes pour couper presque tout !$B$BEt je t\'encourage, toi et tes amis, à continuer le bon travail !  Ces dragons sont des prédateurs féroces qui rendent le ciel entièrement dangereux.$B$Vous avez aussi remarqué les écailles de dragon.  J\'ai entendu dire qu\'elles étaient bonnes pour fabriquer des manteaux puissants si vous obtenez l\'une de leurs écailles.  Et si vous n\'êtes pas satisfait du manteau que vous obtenez, je serai prêt à vous échanger un cristal d\'apex contre celui-ci.') ON DUPLICATE KEY UPDATE RewardText='Oui !  Ces dents ont l\'air assez tranchantes pour couper presque tout !$B$BEt je t\'encourage, toi et tes amis, à continuer le bon travail !  Ces dragons sont des prédateurs féroces qui rendent le ciel entièrement dangereux.$B$Vous avez aussi remarqué les écailles de dragon.  J\'ai entendu dire qu\'elles étaient bonnes pour fabriquer des manteaux puissants si vous obtenez l\'une de leurs écailles.  Et si vous n\'êtes pas satisfait du manteau que vous obtenez, je serai prêt à vous échanger un cristal d\'apex contre celui-ci.';
-- Quest 11080 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11080, 'frFR', 'Avez-vous l\'émanation de la relique d\'apex à votre sujet ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous l\'émanation de la relique d\'apex à votre sujet ?';
-- Quest 11086 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11086, 'frFR', 'C\'est notre seigneur, après tout, qui a banni les démons d\'Outland et fermé leurs portails. Tous devraient se prosterner devant la magnificence d\'Illidan.') ON DUPLICATE KEY UPDATE CompletionText='C\'est notre seigneur, après tout, qui a banni les démons d\'Outland et fermé leurs portails. Tous devraient se prosterner devant la magnificence d\'Illidan.';
-- Quest 11096 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11096, 'frFR', 'As-tu terminé ta tâche, $n ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé ta tâche, $n ?';
-- Quest 11102 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11102, 'frFR', 'Tu as encore retiré leurs piles de boules de canon félles ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as encore retiré leurs piles de boules de canon félles ?';
-- Quest 11103 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11103, 'frFR', 'Le pouvoir dans votre anneau est malléable, bien que l\'inverser ne soit pas facile. Êtes-vous sûr de vouloir remplacer sa forme actuelle ?') ON DUPLICATE KEY UPDATE CompletionText='Le pouvoir dans votre anneau est malléable, bien que l\'inverser ne soit pas facile. Êtes-vous sûr de vouloir remplacer sa forme actuelle ?';

-- Quest 11103 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11103, 'frFR', 'Les sables du temps s\'écoulent facilement vers l\'avant. Ils peuvent être forcés de couler en arrière, mais avec une grande difficulté.') ON DUPLICATE KEY UPDATE RewardText='Les sables du temps s\'écoulent facilement vers l\'avant. Ils peuvent être forcés de couler en arrière, mais avec une grande difficulté.';
