INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11108, 'frFR', 'Vous avez eu une aventure assez folle, $n.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez eu une aventure assez folle, $n.';

-- Quest 11109 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11109, 'frFR', 'C\'est un honneur de vous rencontrer, $N$. Nous avons tous suivi de près vos aventures et nous vous sommes reconnaissants pour tout ce que vous avez fait pour la Dragonflight de Netherwing.$B$Si vous me choisissez comme compagnon, je vous emmènerai aux confins de ce monde et vous ramènerai. Quoi que vous m\'demandiez, je ferai de mon mieux pour y répondre.$B$Attention, vous ne pouvez en choisir qu\'un pour vos voyages en Outland. Une fois le choix fait, vous ne pourrez pas changer d\'avis.') ON DUPLICATE KEY UPDATE RewardText='C\'est un honneur de vous rencontrer, $N$. Nous avons tous suivi de près vos aventures et nous vous sommes reconnaissants pour tout ce que vous avez fait pour la Dragonflight de Netherwing.$B$Si vous me choisissez comme compagnon, je vous emmènerai aux confins de ce monde et vous ramènerai. Quoi que vous m\'demandiez, je ferai de mon mieux pour y répondre.$B$Attention, vous ne pouvez en choisir qu\'un pour vos voyages en Outland. Une fois le choix fait, vous ne pourrez pas changer d\'avis.';
-- Quest 11110 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11110, 'frFR', 'C\'est un honneur de vous rencontrer, $N$. Nous avons tous suivi de près vos aventures et nous vous sommes reconnaissants pour tout ce que vous avez fait pour la Dragonflight de Netherwing.$B$Si vous me choisissez comme compagnon, je vous emmènerai aux confins de ce monde et vous ramènerai. Quoi que vous m\'demandiez, je ferai de mon mieux pour y répondre.$B$Attention, vous ne pouvez en choisir qu\'un pour vos voyages en Outland. Une fois le choix fait, vous ne pourrez pas changer d\'avis.') ON DUPLICATE KEY UPDATE RewardText='C\'est un honneur de vous rencontrer, $N$. Nous avons tous suivi de près vos aventures et nous vous sommes reconnaissants pour tout ce que vous avez fait pour la Dragonflight de Netherwing.$B$Si vous me choisissez comme compagnon, je vous emmènerai aux confins de ce monde et vous ramènerai. Quoi que vous m\'demandiez, je ferai de mon mieux pour y répondre.$B$Attention, vous ne pouvez en choisir qu\'un pour vos voyages en Outland. Une fois le choix fait, vous ne pourrez pas changer d\'avis.';
