-- Quest 11117 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11117, 'frFR', 'Avez-vous bu assez pour voir les petits monstres ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous bu assez pour voir les petits monstres ?';
-- Quest 11117 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11117, 'frFR', 'Eh bien, regardez ça ! Vous avez une bonne poignée de wolpertingers, vous !$b$b<Il prend une grande gorgée de son mug.$b$bJe vais vous dire ce que je vais faire. Puisque vous êtes si précis, $c$, je vous laisserai en garder un pour vous !') ON DUPLICATE KEY UPDATE RewardText='Eh bien, regardez ça ! Vous avez une bonne poignée de wolpertingers, vous !$b$b<Il prend une grande gorgée de son mug.$b$bJe vais vous dire ce que je vais faire. Puisque vous êtes si précis, $c$, je vous laisserai en garder un pour vous !';

-- Quest 11118 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11118, 'frFR', 'Ces maudits elekks roses sont-ils partis ?') ON DUPLICATE KEY UPDATE CompletionText='Ces maudits elekks roses sont-ils partis ?';
-- Quest 11118 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11118, 'frFR', 'Bon travail ! Elekks roses... quelle idée absurde !') ON DUPLICATE KEY UPDATE RewardText='Bon travail ! Elekks roses... quelle idée absurde !';
-- Quest 11120 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11120, 'frFR', 'Tu as réglé ce petit problème dont on parlait ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as réglé ce petit problème dont on parlait ?';
-- Quest 11120 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11120, 'frFR', 'Tu as bien fait, gamin. Tiens, prends ça comme paiement pour le travail que tu as fait.') ON DUPLICATE KEY UPDATE RewardText='Tu as bien fait, gamin. Tiens, prends ça comme paiement pour le travail que tu as fait.';
-- Quest 11122 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11122, 'frFR', 'J\'ai besoin de ces fûts ! Alors, qu\'est-ce que tu attends ?!?!') ON DUPLICATE KEY UPDATE CompletionText='J\'ai besoin de ces fûts ! Alors, qu\'est-ce que tu attends ?!?!';
-- Quest 11122 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11122, 'frFR', 'Merci beaucoup pour ton aide ! Tant que le Festin de la Brasserie a lieu et que les Nains de Fer sont en train d\'attaquer, j\'aurai besoin d\'aide pour livrer des fûts. Alors, si tu veux travailler pour plus de tickets, viens me voir tous les jours.$B$BMais assez parlé de ça, je dois te payer pour le travail que tu viens de faire. Voici tes tickets, amuse-toi au Festin de la Brasserie !') ON DUPLICATE KEY UPDATE RewardText='Merci beaucoup pour ton aide ! Tant que le Festin de la Brasserie a lieu et que les Nains de Fer sont en train d\'attaquer, j\'aurai besoin d\'aide pour livrer des fûts. Alors, si tu veux travailler pour plus de tickets, viens me voir tous les jours.$B$BMais assez parlé de ça, je dois te payer pour le travail que tu viens de faire. Voici tes tickets, amuse-toi au Festin de la Brasserie !';
-- Quest 11126 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11126, 'frFR', 'As-tu chassé les agents déserteurs de Theramore ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu chassé les agents déserteurs de Theramore ?';
-- Quest 11129 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11129, 'frFR', 'Travail fantastique, <name> ! Kyle est rentré chez lui dès qu\'il a mangé et est allé directement au lit. Merci pour ton aide.') ON DUPLICATE KEY UPDATE RewardText='Travail fantastique, <name> ! Kyle est rentré chez lui dès qu\'il a mangé et est allé directement au lit. Merci pour ton aide.';

-- Quest 11130 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11130, 'frFR', '<Budd lit la note.>BAhh! Un ami de Griftah ? Bienvenue !BVous avez un timing impeccable, ami. Comme le veut le destin, j\'ai récemment perdu mes derniers partenaires. Tragique, vraiment, mais les grandes récompenses ont souvent un prix élevé. Il vaut mieux ne pas s\'attarder sur le négatif !BVous avez sans doute entendu parler de mes innombrables exploits et découvertes. Eh bien, tout cela n\'était rien comparé à ceci ! En vérité, nous sommes sur le point de faire l\'histoire ici à Zul\'Aman et, par décret du destin, vous êtes sur le devant de la scène !') ON DUPLICATE KEY UPDATE RewardText='<Budd lit la note.>BAhh! Un ami de Griftah ? Bienvenue !BVous avez un timing impeccable, ami. Comme le veut le destin, j\'ai récemment perdu mes derniers partenaires. Tragique, vraiment, mais les grandes récompenses ont souvent un prix élevé. Il vaut mieux ne pas s\'attarder sur le négatif !BVous avez sans doute entendu parler de mes innombrables exploits et découvertes. Eh bien, tout cela n\'était rien comparé à ceci ! En vérité, nous sommes sur le point de faire l\'histoire ici à Zul\'Aman et, par décret du destin, vous êtes sur le devant de la scène !';
-- Quest 11131 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11131, 'frFR', '$N, tu avais promis de sauver les enfants !') ON DUPLICATE KEY UPDATE CompletionText='$N, tu avais promis de sauver les enfants !';
