INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11145, 'frFR', 'As-tu réussi à libérer les prisonniers du Village de Blackhoof ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à libérer les prisonniers du Village de Blackhoof ?';
-- Quest 11147 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11147, 'frFR', 'As-tu laissé les raptors en liberté dans le Village de Blackhoof ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu laissé les raptors en liberté dans le Village de Blackhoof ?';
-- Quest 11153 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11153, 'frFR', 'On reparle, n\'est-ce pas ? Ça doit vouloir dire que tu l\'as fait ! Tu as montré à ces pirates de Northsea pourris une ou deux choses !bBPas vrai ?') ON DUPLICATE KEY UPDATE CompletionText='On reparle, n\'est-ce pas ? Ça doit vouloir dire que tu l\'as fait ! Tu as montré à ces pirates de Northsea pourris une ou deux choses !bBPas vrai ?';
