INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11156, 'frFR', 'As-tu fait des progrès pour arrêter les attaques des Grimtotem ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu fait des progrès pour arrêter les attaques des Grimtotem ?';
