INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11164, 'frFR', 'Youhou, c\'est pile c\'qu\'y m\'faut !BVoilà c\'que j\'t\'avais promis, $C.') ON DUPLICATE KEY UPDATE RewardText='Youhou, c\'est pile c\'qu\'y m\'faut !BVoilà c\'que j\'t\'avais promis, $C.';
-- Quest 11166 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11166, 'frFR', 'J\'espère que mes déguisements faits main t\'ont donné une protection adéquate à Zul\'aman.$B$BAs-tu exploré ces zones pour moi ? Ou dois-je commencer à chercher tes remplaçants ?') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que mes déguisements faits main t\'ont donné une protection adéquate à Zul\'aman.$B$BAs-tu exploré ces zones pour moi ? Ou dois-je commencer à chercher tes remplaçants ?';

-- Quest 11171 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11171, 'frFR', 'J\'espère que vous appréciez l\'ampleur de l\'opportunité que je vous ai donnée, Diedthreexs.$B$BAvez-vous encore réglé l\'affaire de Malacrass ?') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que vous appréciez l\'ampleur de l\'opportunité que je vous ai donnée, Diedthreexs.$B$BAvez-vous encore réglé l\'affaire de Malacrass ?';
-- Quest 11180 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11180, 'frFR', 'Qu\'avez-vous appris des esprits qui hantent cet endroit ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'avez-vous appris des esprits qui hantent cet endroit ?';
-- Quest 11182 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11182, 'frFR', 'Comment se portent vos efforts contre les gestionnaires indiscrets, petite ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se portent vos efforts contre les gestionnaires indiscrets, petite ?';
-- Quest 11184 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11184, 'frFR', 'Vous avez l\'air plutôt satisfait de vous-même. Vous venez réclamer la prime sur ce raptoir monstrueux ?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez l\'air plutôt satisfait de vous-même. Vous venez réclamer la prime sur ce raptoir monstrueux ?';
-- Quest 11186 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11186, 'frFR', 'Qu\'est-ce que tu portes, $c ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que tu portes, $c ?';
-- Quest 11188 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11188, 'frFR', 'Il est regrettable que le capitaine ait dû vous faire aller provoquer les proto-drakes. Bien qu\'ils semblent manquer de l\'intelligence de certains des dragons que nous connaissons, ils semblent néanmoins être des créatures nobles. Sans parler de la situation que cela nous place.$B$BDois-je demander si vous avez réglé la situation ?') ON DUPLICATE KEY UPDATE CompletionText='Il est regrettable que le capitaine ait dû vous faire aller provoquer les proto-drakes. Bien qu\'ils semblent manquer de l\'intelligence de certains des dragons que nous connaissons, ils semblent néanmoins être des créatures nobles. Sans parler de la situation que cela nous place.$B$BDois-je demander si vous avez réglé la situation ?';
-- Quest 11195 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11195, 'frFR', 'Hé, $N! J\'ai entendu dire que tu étais en train de t\'intégrer à l\'équipage de Budd. Tu ne regretteras pas ce coup, mon ami, je te le promets.$B$BQu\'est-ce que tu as là, mon ?') ON DUPLICATE KEY UPDATE CompletionText='Hé, $N! J\'ai entendu dire que tu étais en train de t\'intégrer à l\'équipage de Budd. Tu ne regretteras pas ce coup, mon ami, je te le promets.$B$BQu\'est-ce que tu as là, mon ?';
-- Quest 11195 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11195, 'frFR', 'Hé là, où est-ce que tu obtiens ça?$B$BNon, non, ne me dis pas - ça vient du Seigneur du Hex ! Tout est clair maintenant. Mojo puissant ! Le porteur de cette relique, peu importe les disgrâces qu\'il subit, est toujours honoré par ses pairs. Incroyable!$B$B<Alors que Griftah tient la poupée en l\'air, un petit charme rouillé tombe autour de son cou. Le troll commence à l\'abandonner, mais se tourne ensuite vers vous avec un éclat dans les yeux.>$B$Je n\'ai pas de pièces en ce moment, mon, mais tu es le bienvenu pour ceci...') ON DUPLICATE KEY UPDATE RewardText='Hé là, où est-ce que tu obtiens ça?$B$BNon, non, ne me dis pas - ça vient du Seigneur du Hex ! Tout est clair maintenant. Mojo puissant ! Le porteur de cette relique, peu importe les disgrâces qu\'il subit, est toujours honoré par ses pairs. Incroyable!$B$B<Alors que Griftah tient la poupée en l\'air, un petit charme rouillé tombe autour de son cou. Le troll commence à l\'abandonner, mais se tourne ensuite vers vous avec un éclat dans les yeux.>$B$Je n\'ai pas de pièces en ce moment, mon, mais tu es le bienvenu pour ceci...';

-- Quest 11202 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11202, 'frFR', 'Il est difficile de savoir depuis tout ce chemin d\'exactement ce qui se passe là-bas. Avez-vous réussi à mettre ces tanks de peste au bûcher ?') ON DUPLICATE KEY UPDATE CompletionText='Il est difficile de savoir depuis tout ce chemin d\'exactement ce qui se passe là-bas. Avez-vous réussi à mettre ces tanks de peste au bûcher ?';
-- Quest 11219 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11219, 'frFR', 'Les enfants de la Horde ont besoin de vous ! Ne les abandonnez pas !') ON DUPLICATE KEY UPDATE CompletionText='Les enfants de la Horde ont besoin de vous ! Ne les abandonnez pas !';
-- Quest 11219 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11219, 'frFR', 'Les incendies sont éteints ! Vous et votre brigade de pompiers avez été victorieux ! Ha ! $B$BL\'attaque du Chevalier Sans Tête a échoué, mais tant qu\'il et sa tête ne seront pas détruits ensemble, il reviendra.$B$Mais en attendant, prenons réconfort dans la sécurité que vous avez apportée à nos enfants. Je suis honoré d\'avoir vu votre travail courageux aujourd\'hui.') ON DUPLICATE KEY UPDATE RewardText='Les incendies sont éteints ! Vous et votre brigade de pompiers avez été victorieux ! Ha ! $B$BL\'attaque du Chevalier Sans Tête a échoué, mais tant qu\'il et sa tête ne seront pas détruits ensemble, il reviendra.$B$Mais en attendant, prenons réconfort dans la sécurité que vous avez apportée à nos enfants. Je suis honoré d\'avoir vu votre travail courageux aujourd\'hui.';
-- Quest 11221 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11221, 'frFR', 'Vous êtes de retour avec votre rapport, $n ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes de retour avec votre rapport, $n ?';
-- Quest 11222 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11222, 'frFR', '<Highlord Bolvar écoute pendant que vous livrez le message de Jaina.>$B$Êtes-vous certain ? C\'est une accusation très sérieuse...') ON DUPLICATE KEY UPDATE RewardText='<Highlord Bolvar écoute pendant que vous livrez le message de Jaina.>$B$Êtes-vous certain ? C\'est une accusation très sérieuse...';
-- Quest 11223 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11223, 'frFR', 'C\'est une excellente nouvelle, $N ! Je craignais que le highlord ne remette en question la véracité de nos informations, mais je vois maintenant que mon inquiétude était mal placée.$B$Vous serez bien récompensé pour vos efforts au nom de Theramore et de l\'Alliance.') ON DUPLICATE KEY UPDATE RewardText='C\'est une excellente nouvelle, $N ! Je craignais que le highlord ne remette en question la véracité de nos informations, mais je vois maintenant que mon inquiétude était mal placée.$B$Vous serez bien récompensé pour vos efforts au nom de Theramore et de l\'Alliance.';
-- Quest 11224 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11224, 'frFR', 'C\'est un coup dur pour nos efforts. Je ne veux même pas savoir ce qu\'ils ont découvert là-bas.$B$C\'est suffisant pour me garder éveillé la nuit juste en imaginant ce que cela pourrait être.') ON DUPLICATE KEY UPDATE CompletionText='C\'est un coup dur pour nos efforts. Je ne veux même pas savoir ce qu\'ils ont découvert là-bas.$B$C\'est suffisant pour me garder éveillé la nuit juste en imaginant ce que cela pourrait être.';
-- Quest 11227 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11227, 'frFR', 'Avez-vous déjà nourri ce petit farceur ici ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous déjà nourri ce petit farceur ici ?';

-- Quest 11231 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11231, 'frFR', 'Avec la libération des prisonniers de Gjalerbron, les vrykul ne pourront pas continuer leurs rites profanes.$B$BVous êtes notre seul espoir pour les arrêter.') ON DUPLICATE KEY UPDATE CompletionText='Avec la libération des prisonniers de Gjalerbron, les vrykul ne pourront pas continuer leurs rites profanes.$B$BVous êtes notre seul espoir pour les arrêter.';
-- Quest 11232 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11232, 'frFR', 'Les canons, $n. Quelqu\'un va s\'en occuper ?') ON DUPLICATE KEY UPDATE CompletionText='Les canons, $n. Quelqu\'un va s\'en occuper ?';
-- Quest 11233 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11233, 'frFR', 'Les dirigeants de l\'Alliance sont-ils morts, $N? Ne revenez pas tant que ce n\'est pas fait.') ON DUPLICATE KEY UPDATE CompletionText='Les dirigeants de l\'Alliance sont-ils morts, $N? Ne revenez pas tant que ce n\'est pas fait.';
-- Quest 11236 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11236, 'frFR', 'Êtes-vous sûr d\'avoir tué Mezhen et ses nécromanciens, $c?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous sûr d\'avoir tué Mezhen et ses nécromanciens, $c?';
-- Quest 11239 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11239, 'frFR', 'La Lumière Sainte se manifeste à travers vos actions et dans toutes choses.$B$BAucune créature, aucun lieu, peu importe à quel point il est mauvais, ne peut échapper à sa colère!') ON DUPLICATE KEY UPDATE CompletionText='La Lumière Sainte se manifeste à travers vos actions et dans toutes choses.$B$BAucune créature, aucun lieu, peu importe à quel point il est mauvais, ne peut échapper à sa colère!';
-- Quest 11242 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11242, 'frFR', 'Vous avez quelque chose pour moi, bon $N?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez quelque chose pour moi, bon $N?';
-- Quest 11242 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11242, 'frFR', 'Qu\'est-ce que c\'est ? Le tome de Thomas Thomson ? Mais c\'est le nom du Cavalier avant qu\'il ne soit maudit ! Est-ce que cela signifie qu\'il est enfin libre ? Est-ce que cela signifie qu\'il ne tourmentera plus les gens de bonne foi d\'Azeroth?$B$BQuel jour joyeux ! $N, votre exploit vivra longtemps parmi nous. Les enfants, et leurs enfants, chanteront votre nom!') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est ? Le tome de Thomas Thomson ? Mais c\'est le nom du Cavalier avant qu\'il ne soit maudit ! Est-ce que cela signifie qu\'il est enfin libre ? Est-ce que cela signifie qu\'il ne tourmentera plus les gens de bonne foi d\'Azeroth?$B$BQuel jour joyeux ! $N, votre exploit vivra longtemps parmi nous. Les enfants, et leurs enfants, chanteront votre nom!';
-- Quest 11243 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11243, 'frFR', 'Le destin du monde pourrait bien reposer sur nous.') ON DUPLICATE KEY UPDATE CompletionText='Le destin du monde pourrait bien reposer sur nous.';

-- Quest 11245 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11245, 'frFR', 'S\'approcher trop près de ces tours est une certitude de mort tant que ces lanceurs de sorts sont là.') ON DUPLICATE KEY UPDATE CompletionText='S\'approcher trop près de ces tours est une certitude de mort tant que ces lanceurs de sorts sont là.';
-- Quest 11246 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11246, 'frFR', 'Une chose que je sais avec certitude, c\'est que je ne veux pas voir ces gros bonhommes se relever après que nous les ayons abattus !') ON DUPLICATE KEY UPDATE CompletionText='Une chose que je sais avec certitude, c\'est que je ne veux pas voir ces gros bonhommes se relever après que nous les ayons abattus !';
-- Quest 11247 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11247, 'frFR', 'Puis-je suggérer que lorsque nous mettrons les bâtiments en feu, nous ne tardions pas trop à l\'intérieur ?') ON DUPLICATE KEY UPDATE CompletionText='Puis-je suggérer que lorsque nous mettrons les bâtiments en feu, nous ne tardions pas trop à l\'intérieur ?';
-- Quest 11250 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11250, 'frFR', 'J\'imagine que puisque vous êtes là, Skorn n\'est plus ?') ON DUPLICATE KEY UPDATE CompletionText='J\'imagine que puisque vous êtes là, Skorn n\'est plus ?';
-- Quest 11250 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11250, 'frFR', 'C\'est une nouvelle incroyablement bonne ! Je savais que tu pouvais y arriver, <name>!$B$BAu moins quelqu\'un ici peut produire des résultats !$B$BEh bien, cela mérite une récompense. Vas-y, choisis ce que tu veux ; le trésor est ouvert pour toi.') ON DUPLICATE KEY UPDATE RewardText='C\'est une nouvelle incroyablement bonne ! Je savais que tu pouvais y arriver, <name>!$B$BAu moins quelqu\'un ici peut produire des résultats !$B$BEh bien, cela mérite une récompense. Vas-y, choisis ce que tu veux ; le trésor est ouvert pour toi.';
-- Quest 11252 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11252, 'frFR', 'Content de voir que tu vas bien, $n.$b$bNous avons eu autant de victimes que nous pouvions gérer.') ON DUPLICATE KEY UPDATE CompletionText='Content de voir que tu vas bien, $n.$b$bNous avons eu autant de victimes que nous pouvions gérer.';
-- Quest 11252 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11252, 'frFR', 'Remarquable !$B$BCeci pourrait être le tour de chance que nous espérions tous.$B$BBien joué, <name>!') ON DUPLICATE KEY UPDATE RewardText='Remarquable !$B$BCeci pourrait être le tour de chance que nous espérions tous.$B$BBien joué, <name>!';
-- Quest 11255 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11255, 'frFR', 'Mets-y du cran, $n! Les vies des gens sont en jeu ici !') ON DUPLICATE KEY UPDATE CompletionText='Mets-y du cran, $n! Les vies des gens sont en jeu ici !';

-- Quest 11257 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11257, 'frFR', 'Ces vrykul ont des coutumes étranges, ne pensez-vous pas, $n?') ON DUPLICATE KEY UPDATE CompletionText='Ces vrykul ont des coutumes étranges, ne pensez-vous pas, $n?';
-- Quest 11258 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11258, 'frFR', 'Je suggère que lorsque nous mettrons les bâtiments en feu, nous ne restions pas à l\'intérieur. L\'esprit de feu ne nous épargnera pas dans sa soif de détruire.') ON DUPLICATE KEY UPDATE CompletionText='Je suggère que lorsque nous mettrons les bâtiments en feu, nous ne restions pas à l\'intérieur. L\'esprit de feu ne nous épargnera pas dans sa soif de détruire.';
-- Quest 11259 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11259, 'frFR', 'S\'approcher de ces tours est une mort certaine tant que ces lanceurs de sorts sont là-haut.') ON DUPLICATE KEY UPDATE CompletionText='S\'approcher de ces tours est une mort certaine tant que ces lanceurs de sorts sont là-haut.';
-- Quest 11263 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11263, 'frFR', 'Comment se passe le combat à Gjalerbron ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe le combat à Gjalerbron ?';
-- Quest 11265 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11265, 'frFR', 'Avec les prisonniers de Gjalerbron libérés, les vrykul ne pourront pas continuer leurs rituels.') ON DUPLICATE KEY UPDATE CompletionText='Avec les prisonniers de Gjalerbron libérés, les vrykul ne pourront pas continuer leurs rituels.';
-- Quest 11268 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11268, 'frFR', 'Avez-vous détruit les morts-vivants à Gjalerbron ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous détruit les morts-vivants à Gjalerbron ?';
-- Quest 11270 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11270, 'frFR', 'Je me fiche du nombre de géants, de dragons ou de kobolds que vous avez tués avant. Faites ce travail et revenez quand vous aurez fini.') ON DUPLICATE KEY UPDATE CompletionText='Je me fiche du nombre de géants, de dragons ou de kobolds que vous avez tués avant. Faites ce travail et revenez quand vous aurez fini.';
-- Quest 11272 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11272, 'frFR', 'C\'est bon de vous revoir, $n. À moins que vous n\'ayez pas encore tué cette aberration d\'elfe, dans ce cas, je m\'en irais si j\'étais vous.') ON DUPLICATE KEY UPDATE CompletionText='C\'est bon de vous revoir, $n. À moins que vous n\'ayez pas encore tué cette aberration d\'elfe, dans ce cas, je m\'en irais si j\'étais vous.';

-- Quest 11280 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11280, 'frFR', 'Alors, allez-y ! Notre petite expérience a fonctionné ? $B$BDid le proto-drake son snack ? Est-ce qu\'il s\'est dissous de l\'intérieur ?') ON DUPLICATE KEY UPDATE CompletionText='Alors, allez-y ! Notre petite expérience a fonctionné ? $B$BDid le proto-drake son snack ? Est-ce qu\'il s\'est dissous de l\'intérieur ?';
-- Quest 11281 [RequestItems]
