-- Quest 11282 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11282, 'frFR', 'Tu les as tués, les vrykuls ? Ils sont vraiment coriaces !') ON DUPLICATE KEY UPDATE CompletionText='Tu les as tués, les vrykuls ? Ils sont vraiment coriaces !';
-- Quest 11283 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11283, 'frFR', 'Tu as fini de tuer ? La ville de Winterskorn est juste en face !') ON DUPLICATE KEY UPDATE CompletionText='Tu as fini de tuer ? La ville de Winterskorn est juste en face !';
-- Quest 11285 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11285, 'frFR', 'Tu as fini de tout brûler ? Assure-toi de ne rien laisser non brûlé.') ON DUPLICATE KEY UPDATE CompletionText='Tu as fini de tout brûler ? Assure-toi de ne rien laisser non brûlé.';
-- Quest 11293 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11293, 'frFR', 'As-tu fini de répandre la nouvelle de Brewfest ? Mais plus important encore, as-tu fait savoir aux gens à propos des Barleybrews ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu fini de répandre la nouvelle de Brewfest ? Mais plus important encore, as-tu fait savoir aux gens à propos des Barleybrews ?';
-- Quest 11293 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11293, 'frFR', 'Bien joué ! Ce genre de cris va certainement nous apporter des clients.$B$BEt nous t\'avions promis une récompense, la voici. Les Barleybrews tiennent leur promesse.$B$Oh, et reviens un autre jour si tu veux aider à répandre la bonne réputation de Barleybrew.') ON DUPLICATE KEY UPDATE RewardText='Bien joué ! Ce genre de cris va certainement nous apporter des clients.$B$BEt nous t\'avions promis une récompense, la voici. Les Barleybrews tiennent leur promesse.$B$Oh, et reviens un autre jour si tu veux aider à répandre la bonne réputation de Barleybrew.';
-- Quest 11294 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11294, 'frFR', 'As-tu fait savoir à tout le monde que les Thunderbrews sont ici à Brewfest ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu fait savoir à tout le monde que les Thunderbrews sont ici à Brewfest ?';

-- Quest 11294 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11294, 'frFR', 'Bien joué ! Ça montrera à ces arrogants de Barleybrews.$B$BEh bien, nous vous avons promis une récompense et la voici. Nous, Thunderbrew, vous récompensons avec des prix, les Barleybrew vous récompensent avec des odeurs nauséabondes et des promesses en l\'air.$B$BVous avez choisi judicieusement.$B$BSi vous voulez continuer à faire le bon choix, passez un autre jour et aidez-nous à faire connaître le mot.') ON DUPLICATE KEY UPDATE RewardText='Bien joué ! Ça montrera à ces arrogants de Barleybrews.$B$BEh bien, nous vous avons promis une récompense et la voici. Nous, Thunderbrew, vous récompensons avec des prix, les Barleybrew vous récompensent avec des odeurs nauséabondes et des promesses en l\'air.$B$BVous avez choisi judicieusement.$B$BSi vous voulez continuer à faire le bon choix, passez un autre jour et aidez-nous à faire connaître le mot.';
-- Quest 11296 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11296, 'frFR', 'J\'espère que ma force de chasse est toujours en vie.$B$BLa piqûre des veuves est lente à être fatale. Elles aiment garder leurs victimes en vie assez longtemps pour que leurs bébés puissent se goinfrer lorsqu\'ils éclosent.') ON DUPLICATE KEY UPDATE CompletionText='J\'espère que ma force de chasse est toujours en vie.$B$BLa piqûre des veuves est lente à être fatale. Elles aiment garder leurs victimes en vie assez longtemps pour que leurs bébés puissent se goinfrer lorsqu\'ils éclosent.';
-- Quest 11305 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11305, 'frFR', 'Ça fera l\'affaire.  Il est temps de faire un vrai travail d\'apothicaire maintenant, <name>!') ON DUPLICATE KEY UPDATE RewardText='Ça fera l\'affaire.  Il est temps de faire un vrai travail d\'apothicaire maintenant, <name>!';
-- Quest 11307 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11307, 'frFR', 'La peste n\'a pas désintégré nos sujets ?  Êtes-vous certain, <name>??!$B$BIl doit y avoir un facteur externe que nous ne prenons pas en compte... peut-être les basses températures de ce climat ?  Peut-être... une mutation dans la souche !') ON DUPLICATE KEY UPDATE RewardText='La peste n\'a pas désintégré nos sujets ?  Êtes-vous certain, <name>??!$B$BIl doit y avoir un facteur externe que nous ne prenons pas en compte... peut-être les basses températures de ce climat ?  Peut-être... une mutation dans la souche !';
-- Quest 11310 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11310, 'frFR', 'Avez-vous fini le nettoyage à Halgrind ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous fini le nettoyage à Halgrind ?';
-- Quest 11311 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11311, 'frFR', 'Avez-vous éliminé les élémentaires ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous éliminé les élémentaires ?';
-- Quest 11314 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11314, 'frFR', 'Avez-vous réussi à guérir l\'une de mes sœurs en utilisant le pendentif ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à guérir l\'une de mes sœurs en utilisant le pendentif ?';
-- Quest 11315 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11315, 'frFR', 'Êtes-vous revenu de la Clairière Vibrante ?') ON DUPLICATE KEY UPDATE CompletionText='Êtes-vous revenu de la Clairière Vibrante ?';

-- Quest 11316 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11316, 'frFR', 'As-tu vu les horreurs du Clairière Tordue par toi-même ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu vu les horreurs du Clairière Tordue par toi-même ?';
-- Quest 11317 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11317, 'frFR', 'As-tu trouvé la paix intérieure au sanctuaire ? Ton tourment est-il disparu ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé la paix intérieure au sanctuaire ? Ton tourment est-il disparu ?';
-- Quest 11318 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11318, 'frFR', 'As-tu réussi à gérer la vitesse ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à gérer la vitesse ?';
-- Quest 11318 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11318, 'frFR', 'Bon travail ! Il faut du temps pour maîtriser ton ram. Mais une fois que tu l\'as fait, tu voudras que chaque ram soit un ram de course.$b$bQu\'est-ce que c\'est ? "Où est ma récompense ?" Ha Ha Ha... tu dois faire rouler le ram le plus rapide ! Tu veux plus ? Eh bien, que dirais-tu de ceci...$b$bTu as été récompensé par la chance d\'aider d\'autres personnes autour de Brewfest. Il y a beaucoup de travail et de récompenses pour un jeune et enthousiaste coureur de ram.') ON DUPLICATE KEY UPDATE RewardText='Bon travail ! Il faut du temps pour maîtriser ton ram. Mais une fois que tu l\'as fait, tu voudras que chaque ram soit un ram de course.$b$bQu\'est-ce que c\'est ? "Où est ma récompense ?" Ha Ha Ha... tu dois faire rouler le ram le plus rapide ! Tu veux plus ? Eh bien, que dirais-tu de ceci...$b$bTu as été récompensé par la chance d\'aider d\'autres personnes autour de Brewfest. Il y a beaucoup de travail et de récompenses pour un jeune et enthousiaste coureur de ram.';
-- Quest 11319 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11319, 'frFR', 'La Clairière Tordue est un endroit terrible. Je n\'aurais jamais imaginé que nos foyers pourraient devenir quelque chose d\'aussi répugnant.') ON DUPLICATE KEY UPDATE CompletionText='La Clairière Tordue est un endroit terrible. Je n\'aurais jamais imaginé que nos foyers pourraient devenir quelque chose d\'aussi répugnant.';
-- Quest 11321 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11321, 'frFR', 'Qu\'est-ce qui se passe, beauté ? Tu as quelque chose pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui se passe, beauté ? Tu as quelque chose pour moi ?';
-- Quest 11321 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11321, 'frFR', 'Aww, ce n\'est qu\'un bon d\'achat de stein... Peut-être que tu fais juste le difficile. Alors voici le stein de cette année pour toi.$B$BMais je soupçonne que je vais te voir beaucoup plus souvent. Après tout, si tu veux des billets de Brewfest à échanger, je suis ta fille...$B$Ou peut-être que je suis sa fille...$B$Booohhh.... ou la sienne...') ON DUPLICATE KEY UPDATE RewardText='Aww, ce n\'est qu\'un bon d\'achat de stein... Peut-être que tu fais juste le difficile. Alors voici le stein de cette année pour toi.$B$BMais je soupçonne que je vais te voir beaucoup plus souvent. Après tout, si tu veux des billets de Brewfest à échanger, je suis ta fille...$B$Ou peut-être que je suis sa fille...$B$Booohhh.... ou la sienne...';
-- Quest 11322 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11322, 'frFR', 'As-tu trouvé la paix intérieure au sanctuaire ? Ton tourment est-il disparu ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé la paix intérieure au sanctuaire ? Ton tourment est-il disparu ?';

