INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11332, 'frFR', 'Ces tanks de peste détruits, pourtant ? Une nouvelle peste plane au-dessus de nos têtes comme une mort certaine, $c!') ON DUPLICATE KEY UPDATE CompletionText='Ces tanks de peste détruits, pourtant ? Une nouvelle peste plane au-dessus de nos têtes comme une mort certaine, $c!';
