-- Quest 11360 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11360, 'frFR', 'Bonjour, $N. Avez-vous perfectionné vos techniques de lutte contre le feu ? N\'oubliez pas la zone d\'entraînement au nord !') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $N. Avez-vous perfectionné vos techniques de lutte contre le feu ? N\'oubliez pas la zone d\'entraînement au nord !';
