INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11361, 'frFR', 'Avez-vous éteint des incendies, $n ? La zone d\'entraînement est à l\'ouest de la sortie ouest de Razor Hill.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous éteint des incendies, $n ? La zone d\'entraînement est à l\'ouest de la sortie ouest de Razor Hill.';
