INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11361, 'frFR', 'Bien joué, $N ! Enfants, jetez un bon œil à ce $c. Grandissez en force et en courage comme lui et un jour vous aussi vous combattrez pour la Horde.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N ! Enfants, jetez un bon œil à ce $c. Grandissez en force et en courage comme lui et un jour vous aussi vous combattrez pour la Horde.';
