INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11364, 'frFR', 'Vous êtes revenu. Les centurions sont tous morts ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu. Les centurions sont tous morts ?';
