INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11367, 'frFR', 'Apportez-vous des nouvelles de la chute de Megalith ?') ON DUPLICATE KEY UPDATE CompletionText='Apportez-vous des nouvelles de la chute de Megalith ?';

-- Quest 11371 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11371, 'frFR', 'Comment se passe votre combat contre les myrmidons de Coilfang ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se passe votre combat contre les myrmidons de Coilfang ?';
-- Quest 11371 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11371, 'frFR', 'J\'espère que ce fut un combat digne de votre temps ? Certes, cette prime sera.$B$BRetournez demain et les vents auront murmuré une fois de plus à Mah\'duun.') ON DUPLICATE KEY UPDATE RewardText='J\'espère que ce fut un combat digne de votre temps ? Certes, cette prime sera.$B$BRetournez demain et les vents auront murmuré une fois de plus à Mah\'duun.';
-- Quest 11373 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11373, 'frFR', 'Peu de gens savent que la source de la magie de Shaffar réside uniquement dans son amulet. Sans elle, il est impuissant.$B$BAlors, si vous l\'avez, cela signifie qu\'il est mort.') ON DUPLICATE KEY UPDATE CompletionText='Peu de gens savent que la source de la magie de Shaffar réside uniquement dans son amulet. Sans elle, il est impuissant.$B$BAlors, si vous l\'avez, cela signifie qu\'il est mort.';
-- Quest 11374 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11374, 'frFR', 'Pouvez-vous imaginer être piégé dans un joyau pour l\'éternité ?') ON DUPLICATE KEY UPDATE CompletionText='Pouvez-vous imaginer être piégé dans un joyau pour l\'éternité ?';
-- Quest 11375 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11375, 'frFR', 'Je ne suis même pas certain de quelle forme un murmure doit prendre dans le monde physique, mais le professeur m\'assure que vous le saurez quand vous le verrez.$B$BPeut-être est-ce quelque chose qui ressemble à la boîte vocale du être ?') ON DUPLICATE KEY UPDATE CompletionText='Je ne suis même pas certain de quelle forme un murmure doit prendre dans le monde physique, mais le professeur m\'assure que vous le saurez quand vous le verrez.$B$BPeut-être est-ce quelque chose qui ressemble à la boîte vocale du être ?';
-- Quest 11376 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11376, 'frFR', 'Les instructeurs, ils sont tous morts ? Non?$B$BNe vous ai-je pas dit de ne pas revenir à moins que vous ne les ayez tous tués ?') ON DUPLICATE KEY UPDATE CompletionText='Les instructeurs, ils sont tous morts ? Non?$B$BNe vous ai-je pas dit de ne pas revenir à moins que vous ne les ayez tous tués ?';
-- Quest 11382 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11382, 'frFR', 'Si j\'étais vous, je ferais très attention au voyage dans le temps. Vous ne voudriez pas accidentellement faire quelque chose, comme tuer l\'un de vos ancêtres, et ensuite vous effacer accidentellement du présent !') ON DUPLICATE KEY UPDATE CompletionText='Si j\'étais vous, je ferais très attention au voyage dans le temps. Vous ne voudriez pas accidentellement faire quelque chose, comme tuer l\'un de vos ancêtres, et ensuite vous effacer accidentellement du présent !';
-- Quest 11383 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11383, 'frFR', 'Nous parlons, mais je sens que tous les seigneurs de la fêlure ne sont pas encore morts.$B$BRevenez quand ils le seront, $C.') ON DUPLICATE KEY UPDATE CompletionText='Nous parlons, mais je sens que tous les seigneurs de la fêlure ne sont pas encore morts.$B$BRevenez quand ils le seront, $C.';

-- Quest 11385 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11385, 'frFR', 'Comment se fait-il que nous parlions alors que les canaliseurs ne sont pas tous morts ?') ON DUPLICATE KEY UPDATE CompletionText='Comment se fait-il que nous parlions alors que les canaliseurs ne sont pas tous morts ?';
-- Quest 11387 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11387, 'frFR', '<Le traqueur du Nether penche la tête avec une confusion apparente face à votre présence.>$B$BLes destructeurs n\'ont pas tous été détruits.') ON DUPLICATE KEY UPDATE CompletionText='<Le traqueur du Nether penche la tête avec une confusion apparente face à votre présence.>$B$BLes destructeurs n\'ont pas tous été détruits.';
-- Quest 11389 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11389, 'frFR', 'Ne savez-vous pas comment atteindre Tempest Keep et l\'Arcatraz ? Par l\'Est à travers le Netherstorm puis volez ou tombez, le choix vous appartient.') ON DUPLICATE KEY UPDATE CompletionText='Ne savez-vous pas comment atteindre Tempest Keep et l\'Arcatraz ? Par l\'Est à travers le Netherstorm puis volez ou tombez, le choix vous appartient.';
-- Quest 11390 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11390, 'frFR', 'Eh ? Tu as fini avec tout ce transport ?') ON DUPLICATE KEY UPDATE CompletionText='Eh ? Tu as fini avec tout ce transport ?';
-- Quest 11391 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11391, 'frFR', 'Des gargouilles ?! Je les ai vues là-bas ! Tu t\'en es débarrassé de toutes?$B$BQu\'est-ce que le monde va devenir quand un nain ne peut même pas creuser sans être attaqué.') ON DUPLICATE KEY UPDATE CompletionText='Des gargouilles ?! Je les ai vues là-bas ! Tu t\'en es débarrassé de toutes?$B$BQu\'est-ce que le monde va devenir quand un nain ne peut même pas creuser sans être attaqué.';
-- Quest 11391 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11391, 'frFR', 'Jolie tir, l’as.$b$bVoilà votre paye. On remet ça demain, d’acc ?') ON DUPLICATE KEY UPDATE RewardText='Jolie tir, l’as.$b$bVoilà votre paye. On remet ça demain, d’acc ?';
-- Quest 11394 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11394, 'frFR', 'Je ne sais pas, $c, il ne semble pas que vous en ayez détruit assez.') ON DUPLICATE KEY UPDATE CompletionText='Je ne sais pas, $c, il ne semble pas que vous en ayez détruit assez.';
-- Quest 11394 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11394, 'frFR', '$GJaren semble très excité par votre succès, mais vous fait signe de garder votre conversation à voix basse.>$B<br :>Bon travail, <name! Mais il y a beaucoup de boue de Scourge sur vos affaires. Vous pourriez envisager de faire un petit plongeon dans le strait. C\'est froid, mais ça vous nettoiera rapidement.') ON DUPLICATE KEY UPDATE RewardText='$GJaren semble très excité par votre succès, mais vous fait signe de garder votre conversation à voix basse.>$B<br :>Bon travail, <name! Mais il y a beaucoup de boue de Scourge sur vos affaires. Vous pourriez envisager de faire un petit plongeon dans le strait. C\'est froid, mais ça vous nettoiera rapidement.';

-- Quest 11396 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11396, 'frFR', 'Je ne sais pas, $n. Je pense que tu dois en retirer quelques-unes de ces choses.') ON DUPLICATE KEY UPDATE CompletionText='Je ne sais pas, $n. Je pense que tu dois en retirer quelques-unes de ces choses.';
-- Quest 11396 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11396, 'frFR', 'Bien ! $B$B$GJaren regarde rapidement autour de lui pour s\'assurer que rien n\'a remarqué son accès de colère.>$B$BTrès bien, tu as certainement gagné le droit d\'en choisir une de ces choses que j\'ai trouvées en étant descendu ici.$B<br :>Et, <name, si jamais tu te retrouves à Steel Gate, donne mon amour à Irena et dis-lui que je vais bien.') ON DUPLICATE KEY UPDATE RewardText='Bien ! $B$B$GJaren regarde rapidement autour de lui pour s\'assurer que rien n\'a remarqué son accès de colère.>$B$BTrès bien, tu as certainement gagné le droit d\'en choisir une de ces choses que j\'ai trouvées en étant descendu ici.$B<br :>Et, <name, si jamais tu te retrouves à Steel Gate, donne mon amour à Irena et dis-lui que je vais bien.';
-- Quest 11397 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11397, 'frFR', 'C\'est intéressant, la dernière fois que j\'ai regardé, il ne semblait pas que tu en eusses détruit suffisamment. Peut-être pourrais-tu redoubler d\'efforts ?') ON DUPLICATE KEY UPDATE CompletionText='C\'est intéressant, la dernière fois que j\'ai regardé, il ne semblait pas que tu en eusses détruit suffisamment. Peut-être pourrais-tu redoubler d\'efforts ?';
-- Quest 11399 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11399, 'frFR', 'Tu n\'as toujours pas détruit assez de cristaux de scourging. Pas de récompense tant que tu ne l\'auras pas fait.') ON DUPLICATE KEY UPDATE CompletionText='Tu n\'as toujours pas détruit assez de cristaux de scourging. Pas de récompense tant que tu ne l\'auras pas fait.';
-- Quest 11400 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11400, 'frFR', 'Est-ce un tampon "Brasseur d\'honneur" que tu as en main ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce un tampon "Brasseur d\'honneur" que tu as en main ?';
-- Quest 11400 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11400, 'frFR', 'Bon travail, $N... tu as gagné la confiance des brasseurs du festival, ce qui te donne le droit d\'acheter un bélier de Brewfest.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, $N... tu as gagné la confiance des brasseurs du festival, ce qui te donne le droit d\'acheter un bélier de Brewfest.';
-- Quest 11403 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11403, 'frFR', 'Quoi ? Ce tome sacré appartenait autrefois à un paladin infâme de l\'Alliance. Était-il le Cavalier Sans Tête ? Est-ce que cela signifie que le Cavalier est vaincu?$B$BC\'est un jour glorieux, $N! Ta légende brillera, et puisse-t-elle durer le double des années du règne de terreur du Cavalier.') ON DUPLICATE KEY UPDATE RewardText='Quoi ? Ce tome sacré appartenait autrefois à un paladin infâme de l\'Alliance. Était-il le Cavalier Sans Tête ? Est-ce que cela signifie que le Cavalier est vaincu?$B$BC\'est un jour glorieux, $N! Ta légende brillera, et puisse-t-elle durer le double des années du règne de terreur du Cavalier.';
-- Quest 11407 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11407, 'frFR', 'As-tu fini de répandre la nouvelle de Brewfest ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu fini de répandre la nouvelle de Brewfest ?';

-- Quest 11407 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11407, 'frFR', 'Tu as tenu parole et nous as parlé de nos maîtres brasseurs. Merci. Nous t\'avions promis ces billets, et nous te les donnons avec plaisir. J\'imagine que les trolls sont un peu plus avares pour remettre leurs billets...$B$Reviens un autre jour pour nous aider à faire connaître Brewfest.') ON DUPLICATE KEY UPDATE RewardText='Tu as tenu parole et nous as parlé de nos maîtres brasseurs. Merci. Nous t\'avions promis ces billets, et nous te les donnons avec plaisir. J\'imagine que les trolls sont un peu plus avares pour remettre leurs billets...$B$Reviens un autre jour pour nous aider à faire connaître Brewfest.';
-- Quest 11408 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11408, 'frFR', 'As-tu fini de faire connaître Brewfest ? Mais plus important encore, as-tu parlé de la merveilleuse bière des trolls ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu fini de faire connaître Brewfest ? Mais plus important encore, as-tu parlé de la merveilleuse bière des trolls ?';
-- Quest 11408 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11408, 'frFR', 'Tu l\'as fait ! Nous devons nous préparer à l\'afflux de clients qui vont venir nous voir ! Merci !$B$Oh, c\'est vrai, et nous t\'avions promis une récompense. N\'oublie pas ça...$B$N\'hésite pas à repasser un autre jour pour nous aider à faire connaître davantage.') ON DUPLICATE KEY UPDATE RewardText='Tu l\'as fait ! Nous devons nous préparer à l\'afflux de clients qui vont venir nous voir ! Merci !$B$Oh, c\'est vrai, et nous t\'avions promis une récompense. N\'oublie pas ça...$B$N\'hésite pas à repasser un autre jour pour nous aider à faire connaître davantage.';
-- Quest 11409 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11409, 'frFR', 'Tu maîtrises les courses de rams ?') ON DUPLICATE KEY UPDATE CompletionText='Tu maîtrises les courses de rams ?';
-- Quest 11409 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11409, 'frFR', 'Hé, ce n\'était pas si mal... es-tu sûr de ne pas être un nain?$b$bIl y a donc beaucoup plus de courses à faire et ce n\'est pas seulement moi. Partout sur le terrain de Brewfest, tu trouveras des gens qui ont besoin d\'un bon coureur de ram. Alors va être utile.$b$bOh et n\'oublie pas, ces rams ont été obtenus légalement. Je veux juste être clair.') ON DUPLICATE KEY UPDATE RewardText='Hé, ce n\'était pas si mal... es-tu sûr de ne pas être un nain?$b$bIl y a donc beaucoup plus de courses à faire et ce n\'est pas seulement moi. Partout sur le terrain de Brewfest, tu trouveras des gens qui ont besoin d\'un bon coureur de ram. Alors va être utile.$b$bOh et n\'oublie pas, ces rams ont été obtenus légalement. Je veux juste être clair.';
-- Quest 11410 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11410, 'frFR', 'J\'ai hâte d\'essayer le nouvel appât.$b$As-tu eu du succès avec Frostfin ?') ON DUPLICATE KEY UPDATE CompletionText='J\'ai hâte d\'essayer le nouvel appât.$b$As-tu eu du succès avec Frostfin ?';
-- Quest 11411 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11411, 'frFR', '<Le chef écoute tandis que tu te présentes.>$B$Je suis le chef Ashtotem, et mon peuple est le taunka, et je parlerai vrai, étranger. Parmi mon peuple, la confiance s\'acquiert, elle ne se donne pas. Tu as mon autorisation de marcher parmi eux et d\'offrir ton aide. Le temps presse et certains d\'entre eux pourraient accueillir l\'aide d\'un étranger dans leurs préparatifs.') ON DUPLICATE KEY UPDATE RewardText='<Le chef écoute tandis que tu te présentes.>$B$Je suis le chef Ashtotem, et mon peuple est le taunka, et je parlerai vrai, étranger. Parmi mon peuple, la confiance s\'acquiert, elle ne se donne pas. Tu as mon autorisation de marcher parmi eux et d\'offrir ton aide. Le temps presse et certains d\'entre eux pourraient accueillir l\'aide d\'un étranger dans leurs préparatifs.';
-- Quest 11412 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11412, 'frFR', 'As-tu vu le désordre que ce gobelin a fait ? J\'espère que tu n\'as pas trop fait de hors-piste imprudent.') ON DUPLICATE KEY UPDATE CompletionText='As-tu vu le désordre que ce gobelin a fait ? J\'espère que tu n\'as pas trop fait de hors-piste imprudent.';

-- Quest 11412 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11412, 'frFR', 'Merci de votre aide ! Tant que le Festin de la Brasserie a lieu, que les Nains de Fer Noir attaquent et que notre fournisseur est coincé dans ce canyon, j\'aurai besoin d\'aide pour livrer des fûts. Alors, si tu veux travailler pour plus de tickets, parle-moi tous les jours.$B$BVoici les tickets que nous t\'avons promis. Amuse-toi !') ON DUPLICATE KEY UPDATE RewardText='Merci de votre aide ! Tant que le Festin de la Brasserie a lieu, que les Nains de Fer Noir attaquent et que notre fournisseur est coincé dans ce canyon, j\'aurai besoin d\'aide pour livrer des fûts. Alors, si tu veux travailler pour plus de tickets, parle-moi tous les jours.$B$BVoici les tickets que nous t\'avons promis. Amuse-toi !';
-- Quest 11413 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11413, 'frFR', 'Qu\'est-ce qui se passe, beauté ? Tu as quelque chose pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui se passe, beauté ? Tu as quelque chose pour moi ?';
-- Quest 11413 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11413, 'frFR', 'Qu\'est-ce que c\'est ? Un bon d\'achat de pinte ? Alors, tu aimes boire ? Super ! Après que je t\'ai donné cette pinte, va boire un verre ! Puis un autre. Peut-être un autre après ça... Puis, maintenant, c\'est important, viens me voir.$B$BLook, je sais que tu reviendras un jour. Si tu veux que tes tickets du Festin de la Brasserie soient échangés, ou que tes marques de Protecteur de Fûts soient échangées, tu dois me voir.$B$BDe toute façon, voici la pinte, et n\'oublie pas de me parler plus tard.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est ? Un bon d\'achat de pinte ? Alors, tu aimes boire ? Super ! Après que je t\'ai donné cette pinte, va boire un verre ! Puis un autre. Peut-être un autre après ça... Puis, maintenant, c\'est important, viens me voir.$B$BLook, je sais que tu reviendras un jour. Si tu veux que tes tickets du Festin de la Brasserie soient échangés, ou que tes marques de Protecteur de Fûts soient échangées, tu dois me voir.$B$BDe toute façon, voici la pinte, et n\'oublie pas de me parler plus tard.';
-- Quest 11415 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11415, 'frFR', '<Un grondement sourd monte de la gorge d\'Ulfang.>$B$BBjomolf et Varg ne sont pas morts !') ON DUPLICATE KEY UPDATE CompletionText='<Un grondement sourd monte de la gorge d\'Ulfang.>$B$BBjomolf et Varg ne sont pas morts !';
-- Quest 11421 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11421, 'frFR', 'Excellent travail, <name> ! Tu as éliminé une bonne partie de leurs cavaliers de dragon et tu as vraiment énervé leur direction.$B$BAimais-tu prêt à retourner à Valgarde et à rapporter les bonnes nouvelles à Zorek ? Si oui, j\'ai une idée folle !') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name> ! Tu as éliminé une bonne partie de leurs cavaliers de dragon et tu as vraiment énervé leur direction.$B$BAimais-tu prêt à retourner à Valgarde et à rapporter les bonnes nouvelles à Zorek ? Si oui, j\'ai une idée folle !';
-- Quest 11428 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11428, 'frFR', 'As-tu débarrassé la Clairière Tordue de Keeper Witherleaf ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu débarrassé la Clairière Tordue de Keeper Witherleaf ?';
-- Quest 11431 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11431, 'frFR', 'Tu étais assez ivre pour voir ces petits salauds ?') ON DUPLICATE KEY UPDATE CompletionText='Tu étais assez ivre pour voir ces petits salauds ?';
-- Quest 11431 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11431, 'frFR', 'Eh bien, regarde ça ! Tu as une bonne botte de wolpertingers, toi !$b$b<Il prend une grande gorgée de son tankard.>$b$bJe vais te dire ce que je vais faire. Puisque tu es si juste $c, je te laisserai en garder un pour toi !') ON DUPLICATE KEY UPDATE RewardText='Eh bien, regarde ça ! Tu as une bonne botte de wolpertingers, toi !$b$b<Il prend une grande gorgée de son tankard.>$b$bJe vais te dire ce que je vais faire. Puisque tu es si juste $c, je te laisserai en garder un pour toi !';

-- Quest 11432 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11432, 'frFR', '$N, je trouve peu plausible que vous ayez traité suffisamment de vrykul dormants. Revenez quand vous l\'aurez fait.') ON DUPLICATE KEY UPDATE CompletionText='$N, je trouve peu plausible que vous ayez traité suffisamment de vrykul dormants. Revenez quand vous l\'aurez fait.';
-- Quest 11433 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11433, 'frFR', 'Je trouve peu probable que vous ayez traité suffisamment de vrykul dormants. Revenez quand vous l\'aurez fait.') ON DUPLICATE KEY UPDATE CompletionText='Je trouve peu probable que vous ayez traité suffisamment de vrykul dormants. Revenez quand vous l\'aurez fait.';
-- Quest 11436 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11436, 'frFR', 'Vous êtes fou, <name>! Quel déchet se lancerait réellement d\'un canon à harpon comme moyen de transport?$B$BMais je suppose que vous devez être un peu fou pour faire ce que vous avez fait là-haut sur les falaises ! Travail fantastique ! Nous avons appris que le chef Dragonflayer, Ingvar, est furieux ! Peut-être qu\'un jour vous serez prêt à lui écraser le visage dans la poussière - au nom de notre chère Alliance.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes fou, <name>! Quel déchet se lancerait réellement d\'un canon à harpon comme moyen de transport?$B$BMais je suppose que vous devez être un peu fou pour faire ce que vous avez fait là-haut sur les falaises ! Travail fantastique ! Nous avons appris que le chef Dragonflayer, Ingvar, est furieux ! Peut-être qu\'un jour vous serez prêt à lui écraser le visage dans la poussière - au nom de notre chère Alliance.';
-- Quest 11437 [Details]
