INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11439, 'frFR', 'Bonjour, $n. Avez-vous perfectionné vos techniques de lutte contre le feu ? N\'oubliez pas la zone d\'entraînement au sud !') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $n. Avez-vous perfectionné vos techniques de lutte contre le feu ? N\'oubliez pas la zone d\'entraînement au sud !';
