-- Quest 11449 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11449, 'frFR', 'As-tu éteint des incendies, $n ? La zone d\'entraînement est à l\'ouest de Brill.') ON DUPLICATE KEY UPDATE CompletionText='As-tu éteint des incendies, $n ? La zone d\'entraînement est à l\'ouest de Brill.';

-- Quest 11449 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11449, 'frFR', 'Bien joué, $N. Enfants, jetez un bon œil à ce $c. Qu\'elle soit un bon exemple pour vous.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N. Enfants, jetez un bon œil à ce $c. Qu\'elle soit un bon exemple pour vous.';
-- Quest 11450 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11450, 'frFR', 'Avez-vous éteint des incendies, $n? La zone d\'entraînement est au sud de Falconwing Square.') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous éteint des incendies, $n? La zone d\'entraînement est au sud de Falconwing Square.';
-- Quest 11450 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11450, 'frFR', 'Bien joué, $N. Enfants, jetez un bon œil à ce $c. Qu\'elle soit un bel exemple pour que vous puissiez suivre.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N. Enfants, jetez un bon œil à ce $c. Qu\'elle soit un bel exemple pour que vous puissiez suivre.';
-- Quest 11454 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11454, 'frFR', 'C\'est une foutue honte, c\'est, vous qui vous amusez là-haut sans boire les meilleures des bières - les nôtres ! Est-ce qu\'on a eu une invitation à la compétition ? Bien sûr que non. Vous faites la guerre et soudain votre bière n\'est plus assez bonne ! Alors oui, on a cassé vos fûts un peu, et c\'est bien mérité ! $B$Bière... vu que vous avez traversé nos défenses et tout, peut-être pouvez-vous faire quelque chose pour moi...') ON DUPLICATE KEY UPDATE RewardText='C\'est une foutue honte, c\'est, vous qui vous amusez là-haut sans boire les meilleures des bières - les nôtres ! Est-ce qu\'on a eu une invitation à la compétition ? Bien sûr que non. Vous faites la guerre et soudain votre bière n\'est plus assez bonne ! Alors oui, on a cassé vos fûts un peu, et c\'est bien mérité ! $B$Bière... vu que vous avez traversé nos défenses et tout, peut-être pouvez-vous faire quelque chose pour moi...';
-- Quest 11458 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11458, 'frFR', 'Avez-vous fait ce que je vous ai demandé, $n?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous fait ce que je vous ai demandé, $n?';
-- Quest 11460 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11460, 'frFR', 'C\'est un exercice important, $n. Si vous voulez devenir fauconnier, vous devez apprendre à nourrir votre oiseau.') ON DUPLICATE KEY UPDATE CompletionText='C\'est un exercice important, $n. Si vous voulez devenir fauconnier, vous devez apprendre à nourrir votre oiseau.';
-- Quest 11478 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11478, 'frFR', 'Oui, ce n\'est rien que nous sachions déjà. Au moins Donny est toujours en vie.') ON DUPLICATE KEY UPDATE RewardText='Oui, ce n\'est rien que nous sachions déjà. Au moins Donny est toujours en vie.';
-- Quest 11485 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11485, 'frFR', 'Ne vous laissez pas dire de sottises par ces pessimistes !') ON DUPLICATE KEY UPDATE CompletionText='Ne vous laissez pas dire de sottises par ces pessimistes !';

-- Quest 11485 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11485, 'frFR', 'Vous êtes presque prêt à emmener cette œuvre d\'art sur le terrain, <name> !') ON DUPLICATE KEY UPDATE RewardText='Vous êtes presque prêt à emmener cette œuvre d\'art sur le terrain, <name> !';
-- Quest 11486 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11486, 'frFR', 'Vous avez visité les Ferrailleurs Noirs et cherché à arrêter leur sabotage ? Ils ont attaqué à nouveau il y a un moment. On dirait qu\'un mot de Ferrailleur Noir vaut autant que leur bière, hein ? $B$BMalgré tout, ce que vous avez fait est apprécié. Voici, prenez une tasse de la « bière » que vous avez ramenée des profondeurs de cette montagne comme récompense. Un travail qui donne soif, de vaincre tous ces Ferrailleurs Noirs !') ON DUPLICATE KEY UPDATE RewardText='Vous avez visité les Ferrailleurs Noirs et cherché à arrêter leur sabotage ? Ils ont attaqué à nouveau il y a un moment. On dirait qu\'un mot de Ferrailleur Noir vaut autant que leur bière, hein ? $B$BMalgré tout, ce que vous avez fait est apprécié. Voici, prenez une tasse de la « bière » que vous avez ramenée des profondeurs de cette montagne comme récompense. Un travail qui donne soif, de vaincre tous ces Ferrailleurs Noirs !';
-- Quest 11487 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11487, 'frFR', 'Vous avez visité les Ferrailleurs Noirs et cherché à arrêter leur sabotage, hein, gamin ? Ils ont attaqué à nouveau, vous savez. On dirait qu\'un mot de Ferrailleur Noir vaut autant que leur bière. $B$BMalgré tout, ce que vous avez fait pour aider est apprécié, je suppose. Voici, prenez une tasse de la « bière » que vous avez ramenée des profondeurs de cette montagne comme récompense. Non, sérieusement. C\'est le moins que je puisse faire.') ON DUPLICATE KEY UPDATE RewardText='Vous avez visité les Ferrailleurs Noirs et cherché à arrêter leur sabotage, hein, gamin ? Ils ont attaqué à nouveau, vous savez. On dirait qu\'un mot de Ferrailleur Noir vaut autant que leur bière. $B$BMalgré tout, ce que vous avez fait pour aider est apprécié, je suppose. Voici, prenez une tasse de la « bière » que vous avez ramenée des profondeurs de cette montagne comme récompense. Non, sérieusement. C\'est le moins que je puisse faire.';
-- Quest 11488 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11488, 'frFR', 'Je ne me souviens pas avoir commandé un service de nettoyage... pourquoi ? Je suis l\'Apothicaire Hummel. $B$B...attendez, qu\'est-ce que cela signifie ? Vous pensez que ces papiers sans importance peuvent m\'arrêter ? Ha !') ON DUPLICATE KEY UPDATE CompletionText='Je ne me souviens pas avoir commandé un service de nettoyage... pourquoi ? Je suis l\'Apothicaire Hummel. $B$B...attendez, qu\'est-ce que cela signifie ? Vous pensez que ces papiers sans importance peuvent m\'arrêter ? Ha !';
-- Quest 11489 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11489, 'frFR', 'Parfait ! Ça marche à merveille !') ON DUPLICATE KEY UPDATE RewardText='Parfait ! Ça marche à merveille !';
