INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11490, 'frFR', 'Regarde dans l\'orbe, mortel.') ON DUPLICATE KEY UPDATE CompletionText='Regarde dans l\'orbe, mortel.';
