INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11491, 'frFR', 'Ne t\'inquiète pas pour lui, $n$. Il va s\'en remettre...') ON DUPLICATE KEY UPDATE CompletionText='Ne t\'inquiète pas pour lui, $n$. Il va s\'en remettre...';
