INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11496, 'frFR', 'As-tu réactivé les protections cristallines, $n$ ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réactivé les protections cristallines, $n$ ?';

-- Quest 11496 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11496, 'frFR', 'Bon travail, $N$. Les wards retrouvent lentement leur puissance. Le sanctuaire sera le nôtre d\'ici peu !') ON DUPLICATE KEY UPDATE RewardText='Bon travail, $N$. Les wards retrouvent lentement leur puissance. Le sanctuaire sera le nôtre d\'ici peu !';
-- Quest 11502 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11502, 'frFR', 'Je vous remercie, <name>. Votre effort ne sera pas ignoré.') ON DUPLICATE KEY UPDATE RewardText='Je vous remercie, <name>. Votre effort ne sera pas ignoré.';
