-- Quest 11513 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11513, 'frFR', 'Ces cellules de mana sont vitales pour nos efforts. Nous aurons le portail vers l\'Île du Puits Solaire créé d\'ici peu !$b$bRevenez demain et je vous enverrai pour en acquérir davantage auprès de nos \'amis\' de Bash\'ir.') ON DUPLICATE KEY UPDATE RewardText='Ces cellules de mana sont vitales pour nos efforts. Nous aurons le portail vers l\'Île du Puits Solaire créé d\'ici peu !$b$bRevenez demain et je vous enverrai pour en acquérir davantage auprès de nos \'amis\' de Bash\'ir.';
