INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11517, 'frFR', 'Portanuus vous a envoyé ? Bien, nous n\'avons pas de temps à perdre !') ON DUPLICATE KEY UPDATE RewardText='Portanuus vous a envoyé ? Bien, nous n\'avons pas de temps à perdre !';
