INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11520, 'frFR', 'Sérieusement, $n$, je suis bien trop occupé pour des bavardages inutiles.$b$bFaites-moi savoir quand vous aurez ramassé ces racines.') ON DUPLICATE KEY UPDATE CompletionText='Sérieusement, $n$, je suis bien trop occupé pour des bavardages inutiles.$b$bFaites-moi savoir quand vous aurez ramassé ces racines.';

