-- Quest 11522 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (11522, 'frFR', '[PH]Pour quelle raison,(À DÉTERMINER),\n\nvous devez collecter 5 Racines de Razorthorn.$b$bCelles-ci ne se trouvent que dans un endroit isolé au Nord-Est de Shattrath, juste au sommet de la colline menant à la Péninsule de Hellfire.') ON DUPLICATE KEY UPDATE `Details`='[PH]Pour quelle raison,(À DÉTERMINER),\n\nvous devez collecter 5 Racines de Razorthorn.$b$bCelles-ci ne se trouvent que dans un endroit isolé au Nord-Est de Shattrath, juste au sommet de la colline menant à la Péninsule de Hellfire.';
