-- Quest 11531 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11531, 'frFR', '$GK. Lee regarde la pièce du moteur puis fixe le loin pendant un moment.>$B$BC\'est quelque chose de vraiment spécial.  Difficile de dire d\'où ça vient--comme si ça était tombé du ciel.  Je vais garder ça et vous payer pour vos ennuis.$B$BEntre nous deux cependant, je pense qu\'il est préférable que nous n\'en parlions à personne.$B<br :><K. Lee affiche son sourire le plus charmant.') ON DUPLICATE KEY UPDATE RewardText='$GK. Lee regarde la pièce du moteur puis fixe le loin pendant un moment.>$B$BC\'est quelque chose de vraiment spécial.  Difficile de dire d\'où ça vient--comme si ça était tombé du ciel.  Je vais garder ça et vous payer pour vos ennuis.$B$BEntre nous deux cependant, je pense qu\'il est préférable que nous n\'en parlions à personne.$B<br :><K. Lee affiche son sourire le plus charmant.';
