INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11532, 'frFR', 'Avez-vous accompli votre mission, $n?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous accompli votre mission, $n?';

