INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11532, 'frFR', 'Tu as un vrai talent, gamin. As-tu déjà pensé à rejoindre la Garde Céleste?$b$bI jest, $N. Nous avons besoin de toi ici si nous voulons prendre les quais prochainement.') ON DUPLICATE KEY UPDATE RewardText='Tu as un vrai talent, gamin. As-tu déjà pensé à rejoindre la Garde Céleste?$b$bI jest, $N. Nous avons besoin de toi ici si nous voulons prendre les quais prochainement.';
