INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11535, 'frFR', 'Excellent ! Nous nous approchons...$b$bBientôt je pourrai fabriquer une enclume, puis le vrai travail pourra commencer.') ON DUPLICATE KEY UPDATE RewardText='Excellent ! Nous nous approchons...$b$bBientôt je pourrai fabriquer une enclume, puis le vrai travail pourra commencer.';
