INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11538, 'frFR', 'Ton dévouement est exemplaire, $N. Nous prendrons l\'armurerie aux forces de la Légion en un rien de temps !') ON DUPLICATE KEY UPDATE RewardText='Ton dévouement est exemplaire, $N. Nous prendrons l\'armurerie aux forces de la Légion en un rien de temps !';
