INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11539, 'frFR', 'Excellent travail, $c. Les armées de Kael faibliront et une fois que nous prendrons le port, nous porterons le coup de grâce !') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, $c. Les armées de Kael faibliront et une fois que nous prendrons le port, nous porterons le coup de grâce !';
