-- Quest 11545 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11545, 'frFR', 'Vous êtes une âme vertueuse, $N. Il est facile d\'oublier les tombés au milieu du tumulte de la guerre et de l\'euphorie de la victoire. Les amis et les familles des morts vous remercient.') ON DUPLICATE KEY UPDATE RewardText='Vous êtes une âme vertueuse, $N. Il est facile d\'oublier les tombés au milieu du tumulte de la guerre et de l\'euphorie de la victoire. Les amis et les familles des morts vous remercient.';
-- Quest 11550 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11550, 'frFR', 'Kil\'jaeden s\'abat sur ce monde avec toute la force de la Légion Ardente. Si le rituel de summoning est complété, notre monde sera à nouveau plongé dans les tourments du chaos. Votre assistance sur l\'Île de Quel\'Danas est cruciale pour notre succès contre la Légion Ardente.$B$BNos mages travaillent à faire tomber les barrières bloquant l\'accès au Puits de Soleil. Faites votre part en combattant les forces de la Légion en aidant l\'Offensive du Soleil Brisée.') ON DUPLICATE KEY UPDATE RewardText='Kil\'jaeden s\'abat sur ce monde avec toute la force de la Légion Ardente. Si le rituel de summoning est complété, notre monde sera à nouveau plongé dans les tourments du chaos. Votre assistance sur l\'Île de Quel\'Danas est cruciale pour notre succès contre la Légion Ardente.$B$BNos mages travaillent à faire tomber les barrières bloquant l\'accès au Puits de Soleil. Faites votre part en combattant les forces de la Légion en aidant l\'Offensive du Soleil Brisée.';
-- Quest 11554 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11554, 'frFR', 'Votre aide dans l\'offensive n\'est pas passée inaperçue, $N. Les forces combinées des Aldor et des Voyants vous offrent leurs remerciements.') ON DUPLICATE KEY UPDATE RewardText='Votre aide dans l\'offensive n\'est pas passée inaperçue, $N. Les forces combinées des Aldor et des Voyants vous offrent leurs remerciements.';
-- Quest 11555 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11555, 'frFR', 'Vous continuez à vous prouver dans cette bataille la plus importante, $N. Veuillez accepter ceci comme un signe de notre gratitude continue.') ON DUPLICATE KEY UPDATE RewardText='Vous continuez à vous prouver dans cette bataille la plus importante, $N. Veuillez accepter ceci comme un signe de notre gratitude continue.';

-- Quest 11556 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11556, 'frFR', 'Nous n\'aurions pas pu arriver là où nous en sommes sans toi, $N. La puissance combinée d\'Aldor et des Voyants n\'est pas suffisante pour écraser la Légion et Kael. Nous sommes reconnaissants d\'avoir des alliés de ton calibre parmi nous.') ON DUPLICATE KEY UPDATE RewardText='Nous n\'aurions pas pu arriver là où nous en sommes sans toi, $N. La puissance combinée d\'Aldor et des Voyants n\'est pas suffisante pour écraser la Légion et Kael. Nous sommes reconnaissants d\'avoir des alliés de ton calibre parmi nous.';
-- Quest 11557 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11557, 'frFR', 'Tu es l\'un de nos meilleurs, $N. Ton nom sera connu dans nos rangs pendant longtemps. Veuillez accepter ce petit cadeau au nom de nos forces.') ON DUPLICATE KEY UPDATE RewardText='Tu es l\'un de nos meilleurs, $N. Ton nom sera connu dans nos rangs pendant longtemps. Veuillez accepter ce petit cadeau au nom de nos forces.';
-- Quest 11560 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11560, 'frFR', 'Si plus de têtards ne sont pas sauvés, ce que nous faisons n\'aura aucune importance : les murlocs de Winterfin n\'auront plus aucune chance d\'avenir !') ON DUPLICATE KEY UPDATE CompletionText='Si plus de têtards ne sont pas sauvés, ce que nous faisons n\'aura aucune importance : les murlocs de Winterfin n\'auront plus aucune chance d\'avenir !';
-- Quest 11561 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11561, 'frFR', 'Si tu as tué tant de traîtres de Winterfin, pourquoi est-ce que quand je regarde au-delà de l\'eau, j\'en vois encore trop ?') ON DUPLICATE KEY UPDATE CompletionText='Si tu as tué tant de traîtres de Winterfin, pourquoi est-ce que quand je regarde au-delà de l\'eau, j\'en vois encore trop ?';
