INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11592, 'frFR', 'Sang et tonnerre ! Vous avez sauvé nos relations naissantes avec les taunka.$B$BMerci d\'avoir rétabli la situation. Aka\'Magosh, <name> !') ON DUPLICATE KEY UPDATE RewardText='Sang et tonnerre ! Vous avez sauvé nos relations naissantes avec les taunka.$B$BMerci d\'avoir rétabli la situation. Aka\'Magosh, <name> !';
