INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11594, 'frFR', 'Bien joué, <class> ! Vous devez avoir beaucoup d\'expérience dans le combat contre les morts-vivants. Et, si ce n\'était pas le cas avant, vous en avez maintenant.$B$BVous en aurez besoin si vous voulez survivre à Northrend.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <class> ! Vous devez avoir beaucoup d\'expérience dans le combat contre les morts-vivants. Et, si ce n\'était pas le cas avant, vous en avez maintenant.$B$BVous en aurez besoin si vous voulez survivre à Northrend.';

