-- Quest 11864 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11864, 'frFR', 'Le démon a de nombreux noms et chaque nom a eu une signification particulière à un moment ou à un autre. Bien que les détails aient parfois été insignifiants, le résultat final était toujours le même : la mort.$B$BMais c\'est maintenant, près de cinquante ans après le début de tout, que les détails trouveront le diable et mèneront à sa chute.$B$BCette fois, nous l\'avons... Il n\'y aura pas d\'échappatoire pour Nesingwary.$B$BNorthrend sera le champ de bataille de notre guerre. Le chasseur deviendra la proie !') ON DUPLICATE KEY UPDATE RewardText='Le démon a de nombreux noms et chaque nom a eu une signification particulière à un moment ou à un autre. Bien que les détails aient parfois été insignifiants, le résultat final était toujours le même : la mort.$B$BMais c\'est maintenant, près de cinquante ans après le début de tout, que les détails trouveront le diable et mèneront à sa chute.$B$BCette fois, nous l\'avons... Il n\'y aura pas d\'échappatoire pour Nesingwary.$B$BNorthrend sera le champ de bataille de notre guerre. Le chasseur deviendra la proie !';
-- Quest 11867 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11867, 'frFR', 'Qu\'ils soient chercheurs de trésors ou chasseurs assoiffés de sang des terres désolées, tout être qui soutient Nesingwary et ose frapper notre faune bien-aimée sera considéré comme un ennemi de D.E.H.T.A.$B$BSi vous tuez ces sympathisants sales de Nesingwary, apportez-moi la preuve de leur mort et vous serez récompensé par une bénédiction des druides de D.E.H.T.A.') ON DUPLICATE KEY UPDATE CompletionText='Qu\'ils soient chercheurs de trésors ou chasseurs assoiffés de sang des terres désolées, tout être qui soutient Nesingwary et ose frapper notre faune bien-aimée sera considéré comme un ennemi de D.E.H.T.A.$B$BSi vous tuez ces sympathisants sales de Nesingwary, apportez-moi la preuve de leur mort et vous serez récompensé par une bénédiction des druides de D.E.H.T.A.';
