-- Quest 11978 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (11978, 'frFR', 'Sans armure et armes, nos nouveaux membres seront sans défense lors de leur périple vers le Marteau d\'Agmar.') ON DUPLICATE KEY UPDATE CompletionText='Sans armure et armes, nos nouveaux membres seront sans défense lors de leur périple vers le Marteau d\'Agmar.';
-- Quest 11978 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (11978, 'frFR', 'C\'est exactement ce dont nous avons besoin, <name>è ! Brandir les armes de la Horde soulèvera leur moral et leur donnera la protection dont ils ont besoin contre la Horde d\'Ombre.$B$Êtes-vous prêt pour la cérémonie d\'initiation?$B$B$B$BVous serez celui qui admet nos nouveaux alliés dans la Horde.') ON DUPLICATE KEY UPDATE RewardText='C\'est exactement ce dont nous avons besoin, <name>è ! Brandir les armes de la Horde soulèvera leur moral et leur donnera la protection dont ils ont besoin contre la Horde d\'Ombre.$B$Êtes-vous prêt pour la cérémonie d\'initiation?$B$B$B$BVous serez celui qui admet nos nouveaux alliés dans la Horde.';
