INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12013, 'frFR', 'Vous me prenez pour un imbécile ? Arcanimus continue de dévorer les âmes de mes frères et sœurs, $c!') ON DUPLICATE KEY UPDATE CompletionText='Vous me prenez pour un imbécile ? Arcanimus continue de dévorer les âmes de mes frères et sœurs, $c!';
