-- Quest 12020 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12020, 'frFR', 'Alors vous avez réussi à arrêter les Irons Noirs... en étant ivre aussi ? Ça, $c, c\'est vraiment l\'esprit de Brewfest ! J\'imagine qu\'en accord avec l\'esprit de Brewfest, vous voulez vos jetons de récompense.$b$bMerci pour votre aide, $N. Profitez du reste de Brewfest.') ON DUPLICATE KEY UPDATE RewardText='Alors vous avez réussi à arrêter les Irons Noirs... en étant ivre aussi ? Ça, $c, c\'est vraiment l\'esprit de Brewfest ! J\'imagine qu\'en accord avec l\'esprit de Brewfest, vous voulez vos jetons de récompense.$b$bMerci pour votre aide, $N. Profitez du reste de Brewfest.';
-- Quest 12022 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12022, 'frFR', 'Lancez-en un en arrière, puis lancez-en un en avant. S.T.O.U.T. peut prendre les coups, c\'est pour ça que je l\'ai construit.') ON DUPLICATE KEY UPDATE CompletionText='Lancez-en un en arrière, puis lancez-en un en avant. S.T.O.U.T. peut prendre les coups, c\'est pour ça que je l\'ai construit.';
-- Quest 12022 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12022, 'frFR', 'Vous savez ce que c\'était ? L\'ingénierie gnomique à son meilleur ! S.T.O.U.T. a encaissé les coups comme un champion !$b$bJe pense que vous êtes prêt maintenant à affronter les Irons Noirs s\'ils réapparaissent.') ON DUPLICATE KEY UPDATE RewardText='Vous savez ce que c\'était ? L\'ingénierie gnomique à son meilleur ! S.T.O.U.T. a encaissé les coups comme un champion !$b$bJe pense que vous êtes prêt maintenant à affronter les Irons Noirs s\'ils réapparaissent.';
