-- Quest 12191 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12191, 'frFR', 'Buvez à la tasse, puis jetez la tasse sur S.T.O.U.T. Je pense qu\'il peut encaisser les coups. Je ne l\'aurais pas construit si... euh... il ne pouvait pas !') ON DUPLICATE KEY UPDATE CompletionText='Buvez à la tasse, puis jetez la tasse sur S.T.O.U.T. Je pense qu\'il peut encaisser les coups. Je ne l\'aurais pas construit si... euh... il ne pouvait pas !';
-- Quest 12191 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12191, 'frFR', 'Wow... S.T.O.U.T. n\'a pas cédé... Hmm... Qui l\'aurait cru ? $b$bJe veux dire, hé, tu as réussi ! Ton tir est juste, ou au moins assez juste pour aider à garder le camp. Je pense que tu es prêt maintenant à affronter les Irons Noirs s\'ils réapparaissent.') ON DUPLICATE KEY UPDATE RewardText='Wow... S.T.O.U.T. n\'a pas cédé... Hmm... Qui l\'aurait cru ? $b$bJe veux dire, hé, tu as réussi ! Ton tir est juste, ou au moins assez juste pour aider à garder le camp. Je pense que tu es prêt maintenant à affronter les Irons Noirs s\'ils réapparaissent.';
-- Quest 12192 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12192, 'frFR', 'Alors vous avez réussi à arrêter les Irons Noirs... Et en étant ivre ? Ça, $c, est vraiment l\'esprit de Brewfest ! J\'imagine qu\'en accord avec l\'esprit de Brewfest, vous voulez vos jetons de prix.$B$BMerci de votre aide, $N. Profitez du reste de Brewfest.') ON DUPLICATE KEY UPDATE RewardText='Alors vous avez réussi à arrêter les Irons Noirs... Et en étant ivre ? Ça, $c, est vraiment l\'esprit de Brewfest ! J\'imagine qu\'en accord avec l\'esprit de Brewfest, vous voulez vos jetons de prix.$B$BMerci de votre aide, $N. Profitez du reste de Brewfest.';
-- Quest 12193 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12193, 'frFR', 'Qu\'est-ce qui se passe, beauté ? Tu as quelque chose pour moi ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui se passe, beauté ? Tu as quelque chose pour moi ?';
-- Quest 12193 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12193, 'frFR', 'Aww, ce n\'est qu\'un bon pour une pinte... Peut-être que tu fais juste la difficile. Alors voici la pinte de cette année pour toi.$b$bMais je soupçonne que je vais te revoir souvent. Après tout, si tu veux échanger des jetons de Brewfest, je suis ta fille...$b$bOu peut-être sa fille...$b$bOooohhh... ou sa...') ON DUPLICATE KEY UPDATE RewardText='Aww, ce n\'est qu\'un bon pour une pinte... Peut-être que tu fais juste la difficile. Alors voici la pinte de cette année pour toi.$b$bMais je soupçonne que je vais te revoir souvent. Après tout, si tu veux échanger des jetons de Brewfest, je suis ta fille...$b$bOu peut-être sa fille...$b$bOooohhh... ou sa...';
