-- Quest 12194 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12194, 'frFR', 'Qu\'est-ce que c\'est ? Un bon de stein ? Alors tu aimes boire ? Super ! Après que je t\'ai donné ce stein, va prendre quelques verres ! Puis quelques autres. Peut-être quelques autres après ça... Puis, maintenant, c\'est important, viens me voir.$b$bRegarde, je sais que tu reviendras un jour. Si tu veux que tes jetons de Festin de la Brasserie soient échangés, tu dois me voir.$b$bDe toute façon, voici le stein, et n\'oublie pas de me parler plus tard.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce que c\'est ? Un bon de stein ? Alors tu aimes boire ? Super ! Après que je t\'ai donné ce stein, va prendre quelques verres ! Puis quelques autres. Peut-être quelques autres après ça... Puis, maintenant, c\'est important, viens me voir.$b$bRegarde, je sais que tu reviendras un jour. Si tu veux que tes jetons de Festin de la Brasserie soient échangés, tu dois me voir.$b$bDe toute façon, voici le stein, et n\'oublie pas de me parler plus tard.';
-- Quest 12205 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12205, 'frFR', 'Es-tu ici pour me faire perdre mon temps, $Gboy:girl;, ou as-tu accompli ma vendetta contre l\'Assaut Scarlet ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu ici pour me faire perdre mon temps, $Gboy:girl;, ou as-tu accompli ma vendetta contre l\'Assaut Scarlet ?';
-- Quest 12206 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12206, 'frFR', 'Tu l\'as fait?$B$BHé, j\'ai oublié de te dire que tu ne devrais probablement pas laisser ça te toucher ! C\'est dégueulasse, et tu n\'arriveras jamais à enlever les taches, sans parler de passer un bon moment à guérir les morceaux de chair gonflés.') ON DUPLICATE KEY UPDATE CompletionText='Tu l\'as fait?$B$BHé, j\'ai oublié de te dire que tu ne devrais probablement pas laisser ça te toucher ! C\'est dégueulasse, et tu n\'arriveras jamais à enlever les taches, sans parler de passer un bon moment à guérir les morceaux de chair gonflés.';
