INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12264, 'frFR', 'Je ne peux m\'empêcher de me demander s\'ils sont assez naïfs pour penser que j\'accepterai cela ou s\'ils sont simplement suicidaires.') ON DUPLICATE KEY UPDATE CompletionText='Je ne peux m\'empêcher de me demander s\'ils sont assez naïfs pour penser que j\'accepterai cela ou s\'ils sont simplement suicidaires.';
-- Quest 12265 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12265, 'frFR', 'Le pouvoir gaspillé sur les faibles et les inutiles.$B$BMontre-moi un être digne de la vie et de la magie qui leur ont été offertes, et alors nous pourrons parler de gaspillage avant d\'éteindre leur présence.$B$BNe t\'inquiète pas, j\'attendrai.') ON DUPLICATE KEY UPDATE CompletionText='Le pouvoir gaspillé sur les faibles et les inutiles.$B$BMontre-moi un être digne de la vie et de la magie qui leur ont été offertes, et alors nous pourrons parler de gaspillage avant d\'éteindre leur présence.$B$BNe t\'inquiète pas, j\'attendrai.';
-- Quest 12267 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12267, 'frFR', 'Tu es un outil assez efficace, $c. Ton aide dans ce nettoyage est appréciée.') ON DUPLICATE KEY UPDATE CompletionText='Tu es un outil assez efficace, $c. Ton aide dans ce nettoyage est appréciée.';
-- Quest 12270 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12270, 'frFR', 'Ramène-moi ces déchiqueteurs, $c ?') ON DUPLICATE KEY UPDATE CompletionText='Ramène-moi ces déchiqueteurs, $c ?';
-- Quest 12274 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12274, 'frFR', 'Qu\'as-tu découvert ? As-tu déjà parlé avec lui ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'as-tu découvert ? As-tu déjà parlé avec lui ?';
-- Quest 12277 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12277, 'frFR', '<Quarterflash hoche la tête.>$B$BC\'était un bon gnome, l\'un de nos meilleurs. Slinkin va nous manquer.') ON DUPLICATE KEY UPDATE CompletionText='<Quarterflash hoche la tête.>$B$BC\'était un bon gnome, l\'un de nos meilleurs. Slinkin va nous manquer.';
-- Quest 12278 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12278, 'frFR', 'As-tu rempli tes formulaires d\'adhésion ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu rempli tes formulaires d\'adhésion ?';

-- Quest 12278 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12278, 'frFR', 'Vos papiers semblent en ordre. Bienvenue au club, $N!$B$BVous pouvez vous attendre à recevoir notre courrier au début de chaque mois. Si vous aimez ce que vous avez, passez nous voir et nous pourrons vous en vendre davantage. C\'est le club qui ne cesse de donner.') ON DUPLICATE KEY UPDATE RewardText='Vos papiers semblent en ordre. Bienvenue au club, $N!$B$BVous pouvez vous attendre à recevoir notre courrier au début de chaque mois. Si vous aimez ce que vous avez, passez nous voir et nous pourrons vous en vendre davantage. C\'est le club qui ne cesse de donner.';
-- Quest 12280 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12280, 'frFR', 'Merci, $N. Ça devrait me permettre de continuer… au moins jusqu\'à d\'main$b$bV\'là l\'pognon, comme promis.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N. Ça devrait me permettre de continuer… au moins jusqu\'à d\'main$b$bV\'là l\'pognon, comme promis.';
-- Quest 12284 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12284, 'frFR', 'Y a-t-il du sang de l\'Alliance sur votre arme, $r?') ON DUPLICATE KEY UPDATE CompletionText='Y a-t-il du sang de l\'Alliance sur votre arme, $r?';
-- Quest 12285 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12285, 'frFR', 'Dois-je dire à mes forces de commencer à se diriger vers le Marteau d\'Agmar?$B$BOu avez-vous réussi à tuer le haut général?') ON DUPLICATE KEY UPDATE CompletionText='Dois-je dire à mes forces de commencer à se diriger vers le Marteau d\'Agmar?$B$BOu avez-vous réussi à tuer le haut général?';
-- Quest 12285 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12285, 'frFR', 'Voyons-les la ramener à la vie sans sa tête!$B$B$GLe rire du haut exécuteur attire un nombre de regards furtifs.>$B<br :>Je suis un peu inquiet que vous ayez laissé s\'échapper ce grand amiral, mais vous êtes toujours le héros du jour, <name!$B$BChoisissez ce que vous voulez... vous l\'avez mérité!') ON DUPLICATE KEY UPDATE RewardText='Voyons-les la ramener à la vie sans sa tête!$B$B$GLe rire du haut exécuteur attire un nombre de regards furtifs.>$B<br :>Je suis un peu inquiet que vous ayez laissé s\'échapper ce grand amiral, mais vous êtes toujours le héros du jour, <name!$B$BChoisissez ce que vous voulez... vous l\'avez mérité!';
-- Quest 12286 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12286, 'frFR', 'Des seaux de bonbons comme celui-ci se trouvent dans les auberges de tous les royaumes. Allez-y... prenez-en !') ON DUPLICATE KEY UPDATE RewardText='Des seaux de bonbons comme celui-ci se trouvent dans les auberges de tous les royaumes. Allez-y... prenez-en !';
-- Quest 12288 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12288, 'frFR', 'Avez-vous soigné nos blessés, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous soigné nos blessés, $N?';
-- Quest 12291 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12291, 'frFR', 'J\'ai assez de murkweed pour faire plus d\'élixirs, $N.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai assez de murkweed pour faire plus d\'élixirs, $N.';

-- Quest 12295 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12295, 'frFR', 'C\'est un plaisir de te rencontrer, <name>!  Nous avions entendu parler de toi par ici.  Bienvenue à Silverbrook.$B$BCes piègeurs sont un bon groupe de gars et de filles.  Des gens robustes, ils connaissent bien le terrain.  Tu trouveras que c\'est une grande chose que nous les ayons finalement convaincus de rejoindre notre côté.') ON DUPLICATE KEY UPDATE RewardText='C\'est un plaisir de te rencontrer, <name>!  Nous avions entendu parler de toi par ici.  Bienvenue à Silverbrook.$B$BCes piègeurs sont un bon groupe de gars et de filles.  Des gens robustes, ils connaissent bien le terrain.  Tu trouveras que c\'est une grande chose que nous les ayons finalement convaincus de rejoindre notre côté.';
-- Quest 12299 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12299, 'frFR', 'Tu as fini avec ces crétins de Horde ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as fini avec ces crétins de Horde ?';
-- Quest 12300 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12300, 'frFR', 'Les gens de Silverbrook... ne sont pas ce qu\'ils semblent être.') ON DUPLICATE KEY UPDATE CompletionText='Les gens de Silverbrook... ne sont pas ce qu\'ils semblent être.';
-- Quest 12304 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12304, 'frFR', 'Tu ne vois pas maintenant, <class>? Ce sera la station de vacances de Northrend!$B$BQu\'est-ce que tu penses du nom, "Hansen\'s Cove", ou peut-être "<name Bay"? Plutôt accrocheur, tu ne trouves pas?') ON DUPLICATE KEY UPDATE RewardText='Tu ne vois pas maintenant, <class>? Ce sera la station de vacances de Northrend!$B$BQu\'est-ce que tu penses du nom, "Hansen\'s Cove", ou peut-être "<name Bay"? Plutôt accrocheur, tu ne trouves pas?';
-- Quest 12306 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12306, 'frFR', 'Tu as rempli tes formulaires d\'adhésion?') ON DUPLICATE KEY UPDATE CompletionText='Tu as rempli tes formulaires d\'adhésion?';
-- Quest 12306 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12306, 'frFR', 'Alors tu rejoins nos rangs, $N? Nous te traitons bien ici. Tu n\'obtiens le meilleur que si tu fais partie de ce club!$B$BNous t\'envoyons de la bière au début de chaque mois. Si tu aimes ce que tu as, et que tu veux plus, reviens ici. Nous nous assurons que tu reçoives plus de la bière que tu aimes.') ON DUPLICATE KEY UPDATE RewardText='Alors tu rejoins nos rangs, $N? Nous te traitons bien ici. Tu n\'obtiens le meilleur que si tu fais partie de ce club!$B$BNous t\'envoyons de la bière au début de chaque mois. Si tu aimes ce que tu as, et que tu veux plus, reviens ici. Nous nous assurons que tu reçoives plus de la bière que tu aimes.';
-- Quest 12308 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12308, 'frFR', 'Tu es revenu. J\'étais inquiet pour toi, $N.') ON DUPLICATE KEY UPDATE CompletionText='Tu es revenu. J\'étais inquiet pour toi, $N.';
-- Quest 12314 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12314, 'frFR', 'Bien joué, <name>! Sans leur chef, la Horde est faible et désorganisée. J\'ordonnerai à nos hommes d\'avancer.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, <name>! Sans leur chef, la Horde est faible et désorganisée. J\'ordonnerai à nos hommes d\'avancer.';

-- Quest 12315 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12315, 'frFR', 'As-tu éliminé le capitaine ennemi ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu éliminé le capitaine ennemi ?';
-- Quest 12318 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12318, 'frFR', 'Tu viens du camp de Brewfest ? Gloire ! Brewfest peut encore être sauvé. $B$B$N, Coren Direbrew doit être arrêté ! Nous ne pouvons pas le laisser saboter notre fête sacrée. Nos brassins doivent couler !') ON DUPLICATE KEY UPDATE RewardText='Tu viens du camp de Brewfest ? Gloire ! Brewfest peut encore être sauvé. $B$B$N, Coren Direbrew doit être arrêté ! Nous ne pouvons pas le laisser saboter notre fête sacrée. Nos brassins doivent couler !';
-- Quest 12323 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12323, 'frFR', 'As-tu fumé tous les gars de la Venture Company ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu fumé tous les gars de la Venture Company ?';
