INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12324, 'frFR', 'As-tu fumé tous les vermine de la Venture Company ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu fumé tous les vermine de la Venture Company ?';
-- Quest 12326 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12326, 'frFR', 'Je m\'appelle Cash. Ambo Cash. Et le plaisir est tout à vous.') ON DUPLICATE KEY UPDATE CompletionText='Je m\'appelle Cash. Ambo Cash. Et le plaisir est tout à vous.';
-- Quest 12330 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12330, 'frFR', 'Je suis heureux de te voir en entier.') ON DUPLICATE KEY UPDATE CompletionText='Je suis heureux de te voir en entier.';
