-- Quest 12412 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12412, 'frFR', 'Avez-vous terminé votre tâche ? Si ce n\'est pas le cas, qu\'êtes-vous ici ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous terminé votre tâche ? Si ce n\'est pas le cas, qu\'êtes-vous ici ?';
-- Quest 12413 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12413, 'frFR', 'Avez-vous terminé votre tâche, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous terminé votre tâche, $N ?';

-- Quest 12414 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12414, 'frFR', 'As-tu récupéré tous les chevaux dont nous aurons besoin ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu récupéré tous les chevaux dont nous aurons besoin ?';
-- Quest 12416 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12416, 'frFR', 'Je suis content que tu sois toujours avec nous, $r.') ON DUPLICATE KEY UPDATE CompletionText='Je suis content que tu sois toujours avec nous, $r.';
-- Quest 12417 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12417, 'frFR', 'J\'ai commencé à m\'inquiéter que la Horde dans le sanctuaire t\'ait réclamé. C\'est une bonne chose que tu sois encore en vie.') ON DUPLICATE KEY UPDATE CompletionText='J\'ai commencé à m\'inquiéter que la Horde dans le sanctuaire t\'ait réclamé. C\'est une bonne chose que tu sois encore en vie.';
-- Quest 12418 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12418, 'frFR', 'Tu es de retour ! As-tu fait ce que j\'ai demandé ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour ! As-tu fait ce que j\'ai demandé ?';
-- Quest 12420 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12420, 'frFR', 'As-tu rempli tes formulaires d\'adhésion ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu rempli tes formulaires d\'adhésion ?';
-- Quest 12420 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12420, 'frFR', 'Vos papiers semblent en ordre. Bienvenue au club, $N!$B$BVous pouvez vous attendre à recevoir notre courrier au début de chaque mois. Si vous aimez ce que vous avez reçu, passez nous voir et nous pouvons vous en vendre davantage. C\'est le club qui ne cesse de donner.') ON DUPLICATE KEY UPDATE RewardText='Vos papiers semblent en ordre. Bienvenue au club, $N!$B$BVous pouvez vous attendre à recevoir notre courrier au début de chaque mois. Si vous aimez ce que vous avez reçu, passez nous voir et nous pouvons vous en vendre davantage. C\'est le club qui ne cesse de donner.';
-- Quest 12421 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12421, 'frFR', 'As-tu rempli tes formulaires d\'adhésion ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu rempli tes formulaires d\'adhésion ?';
-- Quest 12421 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12421, 'frFR', 'Alors, tu rejoins nos rangs, $N ? Nous te traitons bien ici. Tu n\'obtiens que le meilleur quand tu fais partie de ce club!$b$bNous t\'envoyons de la bière au début de chaque mois. Si tu aimes ce que tu as reçu, et que tu veux plus, reviens ici. Nous nous assurons que tu reçoives plus de la bière que tu aimes.') ON DUPLICATE KEY UPDATE RewardText='Alors, tu rejoins nos rangs, $N ? Nous te traitons bien ici. Tu n\'obtiens que le meilleur quand tu fais partie de ce club!$b$bNous t\'envoyons de la bière au début de chaque mois. Si tu aimes ce que tu as reçu, et que tu veux plus, reviens ici. Nous nous assurons que tu reçoives plus de la bière que tu aimes.';

-- Quest 12427 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12427, 'frFR', 'Ce n\'est pas fini tant que toi ou l\'ours ne bascule pas, ami !') ON DUPLICATE KEY UPDATE CompletionText='Ce n\'est pas fini tant que toi ou l\'ours ne bascule pas, ami !';
-- Quest 12427 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12427, 'frFR', 'Bon travail, mec ! Voilà ta part.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, mec ! Voilà ta part.';
-- Quest 12432 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12432, 'frFR', 'Est-ce que le bois de l\'Alliance a déjà été brûlé, $c ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce que le bois de l\'Alliance a déjà été brûlé, $c ?';
-- Quest 12432 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12432, 'frFR', 'Ha hah ! Quelle aventure, hein <class>? Si nous ne pouvons pas contrôler les ressources ici, alors personne ne le pourra ! Quand ces petits nuisibles de l\'Alliance réaliseront-ils qu\'ils ne sont rien face à la puissance de la Horde ?') ON DUPLICATE KEY UPDATE RewardText='Ha hah ! Quelle aventure, hein <class>? Si nous ne pouvons pas contrôler les ressources ici, alors personne ne le pourra ! Quand ces petits nuisibles de l\'Alliance réaliseront-ils qu\'ils ne sont rien face à la puissance de la Horde ?';
