-- Quest 12491 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12491, 'frFR', 'Est-ce que c\'est la boisson de Coren Direbrew ? La bière qu\'il voulait plus que tout soumettre à Brewfest ? Eh bien, officiellement, nous ne pouvons pas reconnaître cette soumission, mais par respect pour un brasseur tombé, peut-être que je vais en prendre une gorgée...') ON DUPLICATE KEY UPDATE RewardText='Est-ce que c\'est la boisson de Coren Direbrew ? La bière qu\'il voulait plus que tout soumettre à Brewfest ? Eh bien, officiellement, nous ne pouvons pas reconnaître cette soumission, mais par respect pour un brasseur tombé, peut-être que je vais en prendre une gorgée...';
