INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12492, 'frFR', 'Hé $N, ton visage est tout taché ! Es-tu allé aux Profondeurs de Blackrock ?') ON DUPLICATE KEY UPDATE CompletionText='Hé $N, ton visage est tout taché ! Es-tu allé aux Profondeurs de Blackrock ?';
-- Quest 12492 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12492, 'frFR', 'Ah, donc Direbrew a finalement soumis sa bière. Quelle pitié qu\'il ait dû mourir pour le faire...$B$Bah, bon. Santé, hein ?') ON DUPLICATE KEY UPDATE RewardText='Ah, donc Direbrew a finalement soumis sa bière. Quelle pitié qu\'il ait dû mourir pour le faire...$B$Bah, bon. Santé, hein ?';
