INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12552, 'frFR', 'Non, $c, tu n\'as pas tout à fait fini. Je sais pertinemment qu\'il y a encore des nécromanciens qui rôdent à Kolramas.') ON DUPLICATE KEY UPDATE CompletionText='Non, $c, tu n\'as pas tout à fait fini. Je sais pertinemment qu\'il y a encore des nécromanciens qui rôdent à Kolramas.';
-- Quest 12555 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12555, 'frFR', 'Tu es sûr d\'en avoir abattu assez ? Est-ce que j\'ai l\'air de vouloir la peste ?!') ON DUPLICATE KEY UPDATE CompletionText='Tu es sûr d\'en avoir abattu assez ? Est-ce que j\'ai l\'air de vouloir la peste ?!';
-- Quest 12555 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12555, 'frFR', 'Hourra ! Tu es le meilleur, <name>!$B$BI n\'attendait pas d\'être pulvérisé par des trucs de Scourge, c\'est certain ! J\'imagine que ça va être difficile pour ces stupides nerubiens de répandre leur mal maintenant!$B$BQu\'en dis-tu si je te donne quelque chose pour m\'avoir sauvé la mise ?') ON DUPLICATE KEY UPDATE RewardText='Hourra ! Tu es le meilleur, <name>!$B$BI n\'attendait pas d\'être pulvérisé par des trucs de Scourge, c\'est certain ! J\'imagine que ça va être difficile pour ces stupides nerubiens de répandre leur mal maintenant!$B$BQu\'en dis-tu si je te donne quelque chose pour m\'avoir sauvé la mise ?';
