-- Quest 12559 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12559, 'frFR', 'Tu es de retour, petit. Je commençais à m\'inquiéter pour ton bien-être.') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour, petit. Je commençais à m\'inquiéter pour ton bien-être.';
-- Quest 12561 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12561, 'frFR', 'Ne perds pas mon temps, mortel. Les créations des titans doivent être défendues !') ON DUPLICATE KEY UPDATE CompletionText='Ne perds pas mon temps, mortel. Les créations des titans doivent être défendues !';
