INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12562, 'frFR', 'Si je peux suggérer, tu devrais t\'occuper de quelques autres de ces liants d\'eau Drakkari.') ON DUPLICATE KEY UPDATE CompletionText='Si je peux suggérer, tu devrais t\'occuper de quelques autres de ces liants d\'eau Drakkari.';

