INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12570, 'frFR', 'Qui es-tu ? Tu sens le chien-homme.') ON DUPLICATE KEY UPDATE CompletionText='Qui es-tu ? Tu sens le chien-homme.';
-- Quest 12576 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12576, 'frFR', 'Ils veulent toujours se battre ! Nous ne voulons pas se battre, mais nous devons protéger les choses sacrées.') ON DUPLICATE KEY UPDATE CompletionText='Ils veulent toujours se battre ! Nous ne voulons pas se battre, mais nous devons protéger les choses sacrées.';
-- Quest 12578 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12578, 'frFR', 'Soo-say trébuche un peu, mais il n\'est pas stupide. Je pense cependant qu\'il a été trop indulgent... les chien-hommes ne vont pas s\'arrêter ou nous laisser tranquilles. La seule façon de les arrêter est de les tuer... il n\'y a pas de "paix."$B$B<Moodle gonfle la poitrine et pointe du doigt.>$B$BC\'est ce que je fais bien.') ON DUPLICATE KEY UPDATE CompletionText='Soo-say trébuche un peu, mais il n\'est pas stupide. Je pense cependant qu\'il a été trop indulgent... les chien-hommes ne vont pas s\'arrêter ou nous laisser tranquilles. La seule façon de les arrêter est de les tuer... il n\'y a pas de "paix."$B$B<Moodle gonfle la poitrine et pointe du doigt.>$B$BC\'est ce que je fais bien.';
-- Quest 12580 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12580, 'frFR', 'J\'aurais aimé savoir à quel point les piliers et les pierres étaient importants plus tôt... peut-être aurais-je pu l\'empêcher.') ON DUPLICATE KEY UPDATE CompletionText='J\'aurais aimé savoir à quel point les piliers et les pierres étaient importants plus tôt... peut-être aurais-je pu l\'empêcher.';
-- Quest 12582 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12582, 'frFR', 'Je sais que tu n\'étais pas un traître comme le disaient les autres. Nous chassons ensemble... je te connais mieux qu\'eux tous. Merci de m\'avoir sauvé.$b$bÇa peut paraître drôle... je ne suis pas un grand fan des grands-bouches... mais même moi, je me sens un peu mal pour le grand-bouche qui meurt comme ça... un combat juste est bien mieux... ils se battent assez bien qu\'ils méritent un combat juste.$b$bTu veux être ami avec Frenzyheart à nouveau ? Je pense que je peux les convaincre que tu m\'as sauvé et que tu as bien géré les grands-bouches. Je ne veux pas que tu me fasses passer pour stupide cependant, alors tu es sûr ?') ON DUPLICATE KEY UPDATE RewardText='Je sais que tu n\'étais pas un traître comme le disaient les autres. Nous chassons ensemble... je te connais mieux qu\'eux tous. Merci de m\'avoir sauvé.$b$bÇa peut paraître drôle... je ne suis pas un grand fan des grands-bouches... mais même moi, je me sens un peu mal pour le grand-bouche qui meurt comme ça... un combat juste est bien mieux... ils se battent assez bien qu\'ils méritent un combat juste.$b$bTu veux être ami avec Frenzyheart à nouveau ? Je pense que je peux les convaincre que tu m\'as sauvé et que tu as bien géré les grands-bouches. Je ne veux pas que tu me fasses passer pour stupide cependant, alors tu es sûr ?';
-- Quest 12584 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12584, 'frFR', 'Oui, $c?$b$bDis-moi que tu as la saronite que nous avons demandé au Capitaine Rupert d\'acquérir ?') ON DUPLICATE KEY UPDATE CompletionText='Oui, $c?$b$bDis-moi que tu as la saronite que nous avons demandé au Capitaine Rupert d\'acquérir ?';
