INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12604, 'frFR', 'Vous avez fait un excellent temps lors de cette patrouille. Il semble que vous puissiez nous être utile après tout.$b$bComme promis, voici quelque chose d\'extra pour vos efforts.$b$bContinuez votre bon travail, $N.$b$bRelâché.') ON DUPLICATE KEY UPDATE RewardText='Vous avez fait un excellent temps lors de cette patrouille. Il semble que vous puissiez nous être utile après tout.$b$bComme promis, voici quelque chose d\'extra pour vos efforts.$b$bContinuez votre bon travail, $N.$b$bRelâché.';
