INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12643, 'frFR', '$GStefan passe au crible les composants fétides.>$B$BEh bien, ce n\'est pas parfait, mais ça fera l\'affaire.$B<br :>Maintenant, préparez-vous, <class. C\'est là que ça devient bon....') ON DUPLICATE KEY UPDATE RewardText='$GStefan passe au crible les composants fétides.>$B$BEh bien, ce n\'est pas parfait, mais ça fera l\'affaire.$B<br :>Maintenant, préparez-vous, <class. C\'est là que ça devient bon....';

