INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12647, 'frFR', 'Si tu ne mets pas fin à ma souffrance bientôt, $N, tout peut être perdu.') ON DUPLICATE KEY UPDATE CompletionText='Si tu ne mets pas fin à ma souffrance bientôt, $N, tout peut être perdu.';
-- Quest 12659 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12659, 'frFR', 'Ahunae sait qu\'il n\'y a aucun moyen que $N prenne autant des Heb\'Drakkar si vite.') ON DUPLICATE KEY UPDATE CompletionText='Ahunae sait qu\'il n\'y a aucun moyen que $N prenne autant des Heb\'Drakkar si vite.';
-- Quest 12661 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12661, 'frFR', 'As-tu gagné la confiance de leur commandant, $N ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu gagné la confiance de leur commandant, $N ?';
