INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12662, 'frFR', 'Il n\'est pas mort. Je peux encore l\'entendre hurler d\'ici !') ON DUPLICATE KEY UPDATE CompletionText='Il n\'est pas mort. Je peux encore l\'entendre hurler d\'ici !';
-- Quest 12665 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12665, 'frFR', 'Quel est le délai, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Quel est le délai, $N ?';
-- Quest 12668 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12668, 'frFR', 'Pourquoi reviens-tu alors que ta tâche n\'est pas encore terminée ? Ne réalises-tu pas que je peux te détruire d\'un simple pensée?$B$BVa maintenant, petit $r. Accomplis ce que je t\'ai commandé !') ON DUPLICATE KEY UPDATE CompletionText='Pourquoi reviens-tu alors que ta tâche n\'est pas encore terminée ? Ne réalises-tu pas que je peux te détruire d\'un simple pensée?$B$BVa maintenant, petit $r. Accomplis ce que je t\'ai commandé !';
-- Quest 12669 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12669, 'frFR', 'S\'il te plaît, $N, dis-moi que tu n\'as pas révélé ton identité....') ON DUPLICATE KEY UPDATE CompletionText='S\'il te plaît, $N, dis-moi que tu n\'as pas révélé ton identité....';

-- Quest 12669 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12669, 'frFR', 'Bon travail, <name>!$B$Diluer ces chaudrons non seulement sauvera des vies, mais ralentira aussi la croissance de la Horde dans cette région.$B$BMaintenant, dis-moi ce que tu as appris de la stratégie de Drakuru à Zul\'Drak.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, <name>!$B$Diluer ces chaudrons non seulement sauvera des vies, mais ralentira aussi la croissance de la Horde dans cette région.$B$BMaintenant, dis-moi ce que tu as appris de la stratégie de Drakuru à Zul\'Drak.';
-- Quest 12673 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12673, 'frFR', 'Tu as mis mes subordonnés en ordre, $n?') ON DUPLICATE KEY UPDATE CompletionText='Tu as mis mes subordonnés en ordre, $n?';
-- Quest 12674 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12674, 'frFR', 'TU CROIS QUE JE SUIS UN FOUL?$B$BILS NE SONT PAS MORTS!') ON DUPLICATE KEY UPDATE CompletionText='TU CROIS QUE JE SUIS UN FOUL?$B$BILS NE SONT PAS MORTS!';
-- Quest 12676 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12676, 'frFR', 'As-tu réussi à nettoyer ces wagons de la Horde, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu réussi à nettoyer ces wagons de la Horde, $N?';
-- Quest 12680 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12680, 'frFR', 'Tu ne veux pas marcher pour toujours, n\'est-ce pas?') ON DUPLICATE KEY UPDATE CompletionText='Tu ne veux pas marcher pour toujours, n\'est-ce pas?';
-- Quest 12685 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12685, 'frFR', 'Qu\'est-ce qui t\'amène à moi, $N?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui t\'amène à moi, $N?';
-- Quest 12686 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12686, 'frFR', 'Darmuk a-t-il payé son échec, $n?') ON DUPLICATE KEY UPDATE CompletionText='Darmuk a-t-il payé son échec, $n?';
-- Quest 12687 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12687, 'frFR', 'Tu dois prendre le char de la mort de force, $c!') ON DUPLICATE KEY UPDATE CompletionText='Tu dois prendre le char de la mort de force, $c!';

-- Quest 12689 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12689, 'frFR', 'Salut ! Je suis vraiment content de te revoir !$b$bJe savais qu\'on était amis. Je le savais ! Tu es un bon ami. Pas seulement pour nous, mais pour tous les Oracles.$b$bJ\'ai vu que tu as bien donné une bonne gifle à ce petit homme-chiot ! Une chose non-vivante a dit qu\'il était ton ami avant ? Je ne sais pas ça. Tu as fini avec les petits hommes-chiots, hein ? Juste ami Oracle maintenant?$b$bJe sais que tu as choisi le bon ! Merci de nous avoir sauvés ! Merci, merci !') ON DUPLICATE KEY UPDATE RewardText='Salut ! Je suis vraiment content de te revoir !$b$bJe savais qu\'on était amis. Je le savais ! Tu es un bon ami. Pas seulement pour nous, mais pour tous les Oracles.$b$bJ\'ai vu que tu as bien donné une bonne gifle à ce petit homme-chiot ! Une chose non-vivante a dit qu\'il était ton ami avant ? Je ne sais pas ça. Tu as fini avec les petits hommes-chiots, hein ? Juste ami Oracle maintenant?$b$bJe sais que tu as choisi le bon ! Merci de nous avoir sauvés ! Merci, merci !';
-- Quest 12698 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12698, 'frFR', 'Une petite note : les mineurs ne deviennent pas toujours des goules. Parfois, ils se transforment en esprits enragés, déterminés à te tuer.') ON DUPLICATE KEY UPDATE CompletionText='Une petite note : les mineurs ne deviennent pas toujours des goules. Parfois, ils se transforment en esprits enragés, déterminés à te tuer.';
-- Quest 12703 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12703, 'frFR', 'Tellement de grands-bouches à tuer ! Tellement amusant, hein ?') ON DUPLICATE KEY UPDATE CompletionText='Tellement de grands-bouches à tuer ! Tellement amusant, hein ?';
-- Quest 12705 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12705, 'frFR', 'Merci de m\'avoir aidé, peau sèche. Tu es très bon pour nous.') ON DUPLICATE KEY UPDATE CompletionText='Merci de m\'avoir aidé, peau sèche. Tu es très bon pour nous.';
-- Quest 12707 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12707, 'frFR', 'Quoi ? Tu as déjà fini?$B$As-tu rendu justice laineuse à ces pauvres trolls de glace ?') ON DUPLICATE KEY UPDATE CompletionText='Quoi ? Tu as déjà fini?$B$As-tu rendu justice laineuse à ces pauvres trolls de glace ?';
-- Quest 12708 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12708, 'frFR', 'Certainement, tu n\'aurais pas pu t\'occuper de tous les guerriers tiki enchantés si rapidement ?') ON DUPLICATE KEY UPDATE CompletionText='Certainement, tu n\'aurais pas pu t\'occuper de tous les guerriers tiki enchantés si rapidement ?';
-- Quest 12710 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12710, 'frFR', 'Es-tu allé voir mes créations, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Es-tu allé voir mes créations, $N ?';
-- Quest 12711 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12711, 'frFR', 'Au sommet de la boîte aux lettres se trouvent plusieurs lettres et parchemins illisibles. Inutiles...$B$BPeut-être devrais-tu regarder à l\'intérieur ?') ON DUPLICATE KEY UPDATE RewardText='Au sommet de la boîte aux lettres se trouvent plusieurs lettres et parchemins illisibles. Inutiles...$B$BPeut-être devrais-tu regarder à l\'intérieur ?';

-- Quest 12713 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12713, 'frFR', 'As-tu affronté Drakuru en bataille, $n?') ON DUPLICATE KEY UPDATE CompletionText='As-tu affronté Drakuru en bataille, $n?';
-- Quest 12728 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12728, 'frFR', 'As-tu déjà collecté les données des Cavernes de Winterfin, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu déjà collecté les données des Cavernes de Winterfin, $N?';
-- Quest 12729 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12729, 'frFR', 'As-tu ce qui est requis, $N?') ON DUPLICATE KEY UPDATE CompletionText='As-tu ce qui est requis, $N?';
-- Quest 12730 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12730, 'frFR', 'Je ne peux t\'offrir que la chaleur de mes paroles et l\'encouragement qui en découle.$B$BPrends le temps dont tu as besoin pour te préparer, mais je t\'implore de ne pas prendre trop de temps, sinon le prophète finira par nous descendre.') ON DUPLICATE KEY UPDATE CompletionText='Je ne peux t\'offrir que la chaleur de mes paroles et l\'encouragement qui en découle.$B$BPrends le temps dont tu as besoin pour te préparer, mais je t\'implore de ne pas prendre trop de temps, sinon le prophète finira par nous descendre.';
-- Quest 12733 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12733, 'frFR', 'As-tu terminé le Défi de la Mort ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu terminé le Défi de la Mort ?';
-- Quest 12735 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12735, 'frFR', 'Joues-tu encore la chanson de purification, $N?') ON DUPLICATE KEY UPDATE CompletionText='Joues-tu encore la chanson de purification, $N?';
-- Quest 12740 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12740, 'frFR', 'Si tu es revenu ici pour me parler, pourquoi vois-je toujours mon peuple succomber à sa mort ?') ON DUPLICATE KEY UPDATE CompletionText='Si tu es revenu ici pour me parler, pourquoi vois-je toujours mon peuple succomber à sa mort ?';
-- Quest 12752 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12752, 'frFR', 'Salutations, $gbrother:sister;. Tu peux être venu au nom de l\'Aube Argentée, mais ce n\'est pas pour cela que tu es ici -- tu es ici pour aider ton peuple à mériter le respect que nous méritons tant. Comme tout forsaken le confirmera, le fin justifie les moyens, et notre recherche sur le remède à la peste zombie est ce proverbe en pratique...') ON DUPLICATE KEY UPDATE RewardText='Salutations, $gbrother:sister;. Tu peux être venu au nom de l\'Aube Argentée, mais ce n\'est pas pour cela que tu es ici -- tu es ici pour aider ton peuple à mériter le respect que nous méritons tant. Comme tout forsaken le confirmera, le fin justifie les moyens, et notre recherche sur le remède à la peste zombie est ce proverbe en pratique...';

-- Quest 12753 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12753, 'frFR', '$gFrère:Sœur; $r, je suis fier de me tenir à vos côtés durant nos jours de besoin. Que vous soyez béni, et que l\'alliance entre $r et humain dure mille ans.') ON DUPLICATE KEY UPDATE RewardText='$gFrère:Sœur; $r, je suis fier de me tenir à vos côtés durant nos jours de besoin. Que vous soyez béni, et que l\'alliance entre $r et humain dure mille ans.';
-- Quest 12759 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12759, 'frFR', 'Un peu désordonné ! Mais tellement amusant.') ON DUPLICATE KEY UPDATE CompletionText='Un peu désordonné ! Mais tellement amusant.';
-- Quest 12761 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12761, 'frFR', 'Très puissant. Les chiots ne connaissent pas la puissance des Grands. Chiots stupides.') ON DUPLICATE KEY UPDATE CompletionText='Très puissant. Les chiots ne connaissent pas la puissance des Grands. Chiots stupides.';
-- Quest 12769 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12769, 'frFR', 'De retour si vite, $n$?$B$BVargastrasz a envoyé un message avant vous. Merci pour ce que vous avez fait au Sanctuaire du Dragon Rubis.') ON DUPLICATE KEY UPDATE RewardText='De retour si vite, $n$?$B$BVargastrasz a envoyé un message avant vous. Merci pour ce que vous avez fait au Sanctuaire du Dragon Rubis.';
-- Quest 12777 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12777, 'frFR', 'Mon cœur déborde de Lumière de vous voir, un noble $r, venir à notre aide. Que vous soyez béni, bon $c!') ON DUPLICATE KEY UPDATE RewardText='Mon cœur déborde de Lumière de vous voir, un noble $r, venir à notre aide. Que vous soyez béni, bon $c!';
-- Quest 12782 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12782, 'frFR', 'Quel bel spécimen vous êtes. Nous avons beaucoup d\'expériences à réaliser et notre réserve de volontaires est presque en faillite. Alors, elfe, comme l\'implique le nom de votre race... Avez-vous du sang à donner ? Le sang frais est un sang bienvenu...') ON DUPLICATE KEY UPDATE RewardText='Quel bel spécimen vous êtes. Nous avons beaucoup d\'expériences à réaliser et notre réserve de volontaires est presque en faillite. Alors, elfe, comme l\'implique le nom de votre race... Avez-vous du sang à donner ? Le sang frais est un sang bienvenu...';
-- Quest 12783 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12783, 'frFR', 'Quel bel spécimen robuste vous êtes. Nous avons beaucoup d\'expériences à réaliser et notre réserve de volontaires est presque en faillite. Le sang frais est un sang bienvenu, et la rage dans votre sang pourrait alimenter des heures de recherche.') ON DUPLICATE KEY UPDATE RewardText='Quel bel spécimen robuste vous êtes. Nous avons beaucoup d\'expériences à réaliser et notre réserve de volontaires est presque en faillite. Le sang frais est un sang bienvenu, et la rage dans votre sang pourrait alimenter des heures de recherche.';
-- Quest 12785 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12785, 'frFR', 'Bienvenue à Orgrimmar, $n$. La Grand Apothicaire Putress vous a envoyé un message... avez-vous le cerveau infecté ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue à Orgrimmar, $n$. La Grand Apothicaire Putress vous a envoyé un message... avez-vous le cerveau infecté ?';

-- Quest 12785 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12785, 'frFR', 'Ah, très bien. Les maladies que cette tête pourrie porte sont mortelles, mais nous ne devons pas fuir le danger ou ce que nous trouvons désagréable. Un jour, $N, tu apprendras que la damnation est le chemin du salut...') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien. Les maladies que cette tête pourrie porte sont mortelles, mais nous ne devons pas fuir le danger ou ce que nous trouvons désagréable. Un jour, $N, tu apprendras que la damnation est le chemin du salut...';
-- Quest 12787 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12787, 'frFR', 'Salutations, $n$. Tu viens de Shattrath ? Tu as des instructions de l\'Apothicaire Grand Putress ?') ON DUPLICATE KEY UPDATE CompletionText='Salutations, $n$. Tu viens de Shattrath ? Tu as des instructions de l\'Apothicaire Grand Putress ?';
-- Quest 12787 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12787, 'frFR', 'Ah, quel bel spécimen tu es. La maladie, -- les maladies -- dansant à travers ton cerveau doivent t\'offrir des visions si sublimes. Nous passerons de longues nuits en conversation, toi et moi, et je prendrai de toi tes pensées tandis que j\'extrais lentement la chair de ton crâne.$b$bN\'aie pas peur, petit. La connaissance tirée de ton sacrifice sera grandiose. Tu es un cadeau pour les forsakés ; tu annonceras un nouvel âge de respect pour nous parmi les peuples de ce monde. Ta place dans notre histoire est assurée...') ON DUPLICATE KEY UPDATE RewardText='Ah, quel bel spécimen tu es. La maladie, -- les maladies -- dansant à travers ton cerveau doivent t\'offrir des visions si sublimes. Nous passerons de longues nuits en conversation, toi et moi, et je prendrai de toi tes pensées tandis que j\'extrais lentement la chair de ton crâne.$b$bN\'aie pas peur, petit. La connaissance tirée de ton sacrifice sera grandiose. Tu es un cadeau pour les forsakés ; tu annonceras un nouvel âge de respect pour nous parmi les peuples de ce monde. Ta place dans notre histoire est assurée...';
-- Quest 12788 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12788, 'frFR', 'Bienvenue à Silvermoon, $n$. L\'Apothicaire Grand Putress a envoyé un message avant toi... as-tu le cerveau infecté ?') ON DUPLICATE KEY UPDATE CompletionText='Bienvenue à Silvermoon, $n$. L\'Apothicaire Grand Putress a envoyé un message avant toi... as-tu le cerveau infecté ?';
-- Quest 12788 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12788, 'frFR', 'Ah, très bien. Les maladies que cette tête pourrie porte sont mortelles, mais nous ne devons pas fuir le danger ou ce que nous trouvons désagréable. Un jour, $N, tu apprendras que la damnation est le chemin du salut...') ON DUPLICATE KEY UPDATE RewardText='Ah, très bien. Les maladies que cette tête pourrie porte sont mortelles, mais nous ne devons pas fuir le danger ou ce que nous trouvons désagréable. Un jour, $N, tu apprendras que la damnation est le chemin du salut...';
-- Quest 12790 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12790, 'frFR', 'Je sens que tu n\'as pas encore testé les deux cristaux de téléportation.$B$BC\'est bon, prends ton temps.') ON DUPLICATE KEY UPDATE CompletionText='Je sens que tu n\'as pas encore testé les deux cristaux de téléportation.$B$BC\'est bon, prends ton temps.';
-- Quest 12805 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12805, 'frFR', 'As-tu récupéré l\'énergie des élémentaires, $N$?') ON DUPLICATE KEY UPDATE CompletionText='As-tu récupéré l\'énergie des élémentaires, $N$?';
-- Quest 12808 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12808, 'frFR', '$gFrère:Sœur; $r, je suis fier de me tenir avec toi durant nos jours de besoin. Béni sois-tu, et que les yeux avisés de ta race aident à trouver un chemin vers notre salut..') ON DUPLICATE KEY UPDATE RewardText='$gFrère:Sœur; $r, je suis fier de me tenir avec toi durant nos jours de besoin. Béni sois-tu, et que les yeux avisés de ta race aident à trouver un chemin vers notre salut..';

-- Quest 12809 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12809, 'frFR', 'Bonjour, $n! Regardez-vous! Je vois que vous avez grandi précisément de un virgule sept trois microespans depuis la dernière fois que je vous ai vu. Les airs d\'Outland vous ont affecté, j\'en suis certain.') ON DUPLICATE KEY UPDATE CompletionText='Bonjour, $n! Regardez-vous! Je vois que vous avez grandi précisément de un virgule sept trois microespans depuis la dernière fois que je vous ai vu. Les airs d\'Outland vous ont affecté, j\'en suis certain.';
-- Quest 12809 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12809, 'frFR', 'Incroyablement immaculé! Cet appareil stocke l\'énergie de la Lumière à des niveaux dépassant ceux de toute source connue! Oh, les applications possibles me font frissonner les moustaches et grimper les orteils. Ho ho! L\'actionneur géno-anti-nocturne photo-dispersif que je pourrais construire avec ceci transformerait le crépuscule en aube! Les Scourge ne sauront pas ce qui les frappe. Nous les détruirons tous d\'un seul coup de levier!') ON DUPLICATE KEY UPDATE RewardText='Incroyablement immaculé! Cet appareil stocke l\'énergie de la Lumière à des niveaux dépassant ceux de toute source connue! Oh, les applications possibles me font frissonner les moustaches et grimper les orteils. Ho ho! L\'actionneur géno-anti-nocturne photo-dispersif que je pourrais construire avec ceci transformerait le crépuscule en aube! Les Scourge ne sauront pas ce qui les frappe. Nous les détruirons tous d\'un seul coup de levier!';
-- Quest 12811 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12811, 'frFR', 'Quel spécimen fin et robuste vous êtes. Nous avons beaucoup d\'expériences à réaliser et notre réserve de volontaires est presque en faillite. Du sang neuf est un sang bienvenu en effet, et votre sang primaire pourrait alimenter des heures de recherche.') ON DUPLICATE KEY UPDATE RewardText='Quel spécimen fin et robuste vous êtes. Nous avons beaucoup d\'expériences à réaliser et notre réserve de volontaires est presque en faillite. Du sang neuf est un sang bienvenu en effet, et votre sang primaire pourrait alimenter des heures de recherche.';
-- Quest 12814 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12814, 'frFR', 'Qu\'est-ce qui a pris tant de temps? Leurs griffons sont-ils lents? Nous devrons faire quelque chose à ce sujet.') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui a pris tant de temps? Leurs griffons sont-ils lents? Nous devrons faire quelque chose à ce sujet.';
-- Quest 12820 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12820, 'frFR', 'Vous avez aussi quelques-uns de leurs grossiers amis snobold, j\'espère?') ON DUPLICATE KEY UPDATE CompletionText='Vous avez aussi quelques-uns de leurs grossiers amis snobold, j\'espère?';
-- Quest 12822 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12822, 'frFR', 'Rien ne fait plus peur à l\'ennemi qu\'un sapeur gobelin!') ON DUPLICATE KEY UPDATE CompletionText='Rien ne fait plus peur à l\'ennemi qu\'un sapeur gobelin!';
-- Quest 12823 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12823, 'frFR', 'Ce paquet explosif est mon bébé... il m\'a pris des semaines à le perfectionner. DES SEMAINES!$B$C\'est long... d\'accord.') ON DUPLICATE KEY UPDATE CompletionText='Ce paquet explosif est mon bébé... il m\'a pris des semaines à le perfectionner. DES SEMAINES!$B$C\'est long... d\'accord.';
-- Quest 12829 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12829, 'frFR', 'Faites attention près de ce distributeur! Ces choses sont dangereuses.') ON DUPLICATE KEY UPDATE CompletionText='Faites attention près de ce distributeur! Ces choses sont dangereuses.';

-- Quest 12832 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12832, 'frFR', 'Je suppose que tout s\'est bien passé dans la caverne ? Tore a été correct avec toi ?') ON DUPLICATE KEY UPDATE CompletionText='Je suppose que tout s\'est bien passé dans la caverne ? Tore a été correct avec toi ?';
-- Quest 12832 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12832, 'frFR', 'Merci d\'avoir aidé notre mineur là-bas, <name>! Je devrais pouvoir préparer un antidote sans problème.$B$BSi tu tombes à nouveau sur Tore, dis-lui qu\'elle est une idiote pour moi, d\'accord ?') ON DUPLICATE KEY UPDATE RewardText='Merci d\'avoir aidé notre mineur là-bas, <name>! Je devrais pouvoir préparer un antidote sans problème.$B$BSi tu tombes à nouveau sur Tore, dis-lui qu\'elle est une idiote pour moi, d\'accord ?';
-- Quest 12836 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12836, 'frFR', 'J\'aime Ricket parce qu\'elle est tellement délicieuse!$B$BOh, salut encore ! Comment se passe le contrôle des nuisibles ?') ON DUPLICATE KEY UPDATE CompletionText='J\'aime Ricket parce qu\'elle est tellement délicieuse!$B$BOh, salut encore ! Comment se passe le contrôle des nuisibles ?';
-- Quest 12840 [RequestItems]
