-- Quest 12849 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12849, 'frFR', 'Dans la Salle du Commandement, vous trouverez les écoles de sang, de glace et d\'immonde. Chaque école a un entraîneur qui peut vous fournir des connaissances dans les diverses arts noirs.$B$BI, Lord Thorval, est le directeur de l\'école de sang. Lady Alistra règne sur l\'immonde et l\'archiliche, Amal\'thazad, détient le domaine de la glace.$B$BVous devez revenir ici chaque fois que vous gagnez de la puissance et que vous vous entraînez !') ON DUPLICATE KEY UPDATE RewardText='Dans la Salle du Commandement, vous trouverez les écoles de sang, de glace et d\'immonde. Chaque école a un entraîneur qui peut vous fournir des connaissances dans les diverses arts noirs.$B$BI, Lord Thorval, est le directeur de l\'école de sang. Lady Alistra règne sur l\'immonde et l\'archiliche, Amal\'thazad, détient le domaine de la glace.$B$BVous devez revenir ici chaque fois que vous gagnez de la puissance et que vous vous entraînez !';
