INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12851, 'frFR', 'Avez-vous survécu au combat, $N?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous survécu au combat, $N?';
-- Quest 12856 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12856, 'frFR', 'Votre mission a-t-elle été un succès, $gbrother:sister;?') ON DUPLICATE KEY UPDATE CompletionText='Votre mission a-t-elle été un succès, $gbrother:sister;?';
-- Quest 12865 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12865, 'frFR', 'Ces oiseaux nous sont loyaux depuis longtemps... nous nous entendons assez bien.') ON DUPLICATE KEY UPDATE CompletionText='Ces oiseaux nous sont loyaux depuis longtemps... nous nous entendons assez bien.';
-- Quest 12866 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12866, 'frFR', 'Des nuisibles persistants... on ne parvient jamais à se débarrasser d\'eux tous. Ils se reproduisent comme des lapins.') ON DUPLICATE KEY UPDATE CompletionText='Des nuisibles persistants... on ne parvient jamais à se débarrasser d\'eux tous. Ils se reproduisent comme des lapins.';
-- Quest 12868 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12868, 'frFR', 'Il fait trop froid ici les nuisibles habituels... nous avons des harpies. Quelle chance.') ON DUPLICATE KEY UPDATE CompletionText='Il fait trop froid ici les nuisibles habituels... nous avons des harpies. Quelle chance.';
-- Quest 12874 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12874, 'frFR', 'Vous êtes revenu vers moi. Êtes-vous revenu vers moi victorieux ?') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu vers moi. Êtes-vous revenu vers moi victorieux ?';
