INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12876, 'frFR', 'Les éclaireurs avaient-ils raison ? Y avait-il des nains là-dessous ?') ON DUPLICATE KEY UPDATE CompletionText='Les éclaireurs avaient-ils raison ? Y avait-il des nains là-dessous ?';

-- Quest 12879 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12879, 'frFR', 'Quelqu\'un utilise la Forge de la Volonté pour créer cette armée... Ulduar n\'est plus en sécurité. $R, as-tu récupéré le noyau ?') ON DUPLICATE KEY UPDATE CompletionText='Quelqu\'un utilise la Forge de la Volonté pour créer cette armée... Ulduar n\'est plus en sécurité. $R, as-tu récupéré le noyau ?';
-- Quest 12887 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12887, 'frFR', 'L\'Oculaire tient toujours ! Thassarian a été un imbécile de te faire confiance.$B$BQui que tu sois, ne reviens pas tant qu\'il n\'est pas détruit. Ma position ici ne doit pas être compromise !') ON DUPLICATE KEY UPDATE CompletionText='L\'Oculaire tient toujours ! Thassarian a été un imbécile de te faire confiance.$B$BQui que tu sois, ne reviens pas tant qu\'il n\'est pas détruit. Ma position ici ne doit pas être compromise !';
-- Quest 12892 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12892, 'frFR', 'L\'Oculaire tient toujours ! Koltira a été une imbécile de te faire confiance.$B$BQui que tu sois, ne reviens pas tant qu\'il n\'est pas détruit. Ma position ici ne doit pas être compromise !') ON DUPLICATE KEY UPDATE CompletionText='L\'Oculaire tient toujours ! Koltira a été une imbécile de te faire confiance.$B$BQui que tu sois, ne reviens pas tant qu\'il n\'est pas détruit. Ma position ici ne doit pas être compromise !';
