-- Quest 12896 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12896, 'frFR', 'Je te demande, $N, pourquoi nous parlerions-nous à nouveau si le Général Lightsbane existe encore ?') ON DUPLICATE KEY UPDATE CompletionText='Je te demande, $N, pourquoi nous parlerions-nous à nouveau si le Général Lightsbane existe encore ?';
-- Quest 12904 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12904, 'frFR', 'Tu fais le bien du monde, ami. Ces monstres doivent être arrêtés !') ON DUPLICATE KEY UPDATE CompletionText='Tu fais le bien du monde, ami. Ces monstres doivent être arrêtés !';
-- Quest 12906 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12906, 'frFR', 'C\'est fait ? J\'espère que tu n\'as pas tué trop de ces cochonneries. Nous avons besoin de main-d\'œuvre.') ON DUPLICATE KEY UPDATE CompletionText='C\'est fait ? J\'espère que tu n\'as pas tué trop de ces cochonneries. Nous avons besoin de main-d\'œuvre.';
-- Quest 12907 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12907, 'frFR', 'Tu es de retour. As-tu tué le cochon insubordonné ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour. As-tu tué le cochon insubordonné ?';

-- Quest 12913 [Details]
INSERT INTO quest_template_locale (ID, locale, `Details`) VALUES (12913, 'frFR', '<Brann commence à gesticuler violemment et à pérorer dans sa langue natale.>$B$BRuk MogOth red a mogoth ta eft Thros-garE Haldir.$B$BKha gor ruk khaz ta ke ruk hrim eft thros-am-kha ruk kost-um havar go kost.$B$BA modoss hine ruk bergum eft thros-am-kha ga eft Haldir ke loch Thon we lo gefrunon ta mitta.$B$BGar Ruk dagUm loch angor-magi ta har ruk!$B$B<Après quelques instants, vous réalisez que cette conversation ne mène à rien. Peut-être que le chaman, Moteha Né-du-vent, au point d\'impact de Grom\'arsh, saura quoi faire.>') ON DUPLICATE KEY UPDATE `Details`='<Brann commence à gesticuler violemment et à pérorer dans sa langue natale.>$B$BRuk MogOth red a mogoth ta eft Thros-garE Haldir.$B$BKha gor ruk khaz ta ke ruk hrim eft thros-am-kha ruk kost-um havar go kost.$B$BA modoss hine ruk bergum eft thros-am-kha ga eft Haldir ke loch Thon we lo gefrunon ta mitta.$B$BGar Ruk dagUm loch angor-magi ta har ruk!$B$B<Après quelques instants, vous réalisez que cette conversation ne mène à rien. Peut-être que le chaman, Moteha Né-du-vent, au point d\'impact de Grom\'arsh, saura quoi faire.>';
-- Quest 12916 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12916, 'frFR', 'Je suis un géant de ma parole, petit.') ON DUPLICATE KEY UPDATE CompletionText='Je suis un géant de ma parole, petit.';
-- Quest 12918 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12918, 'frFR', 'Vous êtes très généreux. Le moins que je puisse faire est de vous apprendre les compétences de la perfection des gemmes.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes très généreux. Le moins que je puisse faire est de vous apprendre les compétences de la perfection des gemmes.';
-- Quest 12918 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12918, 'frFR', 'Celles-ci sont parfaites pour réapprovisionner mon stock. Non seulement je vous apprendrai l\'art de la perfection du taille de gemmes, mais je taille l\'une d\'entre elles dans sa forme parfaite que vous pouvez avoir en récompense.') ON DUPLICATE KEY UPDATE RewardText='Celles-ci sont parfaites pour réapprovisionner mon stock. Non seulement je vous apprendrai l\'art de la perfection du taille de gemmes, mais je taille l\'une d\'entre elles dans sa forme parfaite que vous pouvez avoir en récompense.';
-- Quest 12919 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (12919, 'frFR', 'Qu\'est-ce qui se passe ? Nos ennemis sont-ils morts ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui se passe ? Nos ennemis sont-ils morts ?';
-- Quest 12919 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (12919, 'frFR', 'Incroyable ! Ce sera une histoire pour les âges, <name> ! Un homme est monté sur la tête du roi des géants de tempête et a décimé une armée entière de la Horde d\'Ombre !$B$BEt j\'étais là pour tout voir se passer...') ON DUPLICATE KEY UPDATE RewardText='Incroyable ! Ce sera une histoire pour les âges, <name> ! Un homme est monté sur la tête du roi des géants de tempête et a décimé une armée entière de la Horde d\'Ombre !$B$BEt j\'étais là pour tout voir se passer...';
