-- Quest 13141 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13141, 'frFR', 'Lumière bénie ! Nous avons pris le sommet ! Enfin, la construction du Keep of Justice peut commencer. Highlord Fordring et les chevaliers sont déjà en route vers notre nouvelle base. Vous devez les rejoindre là-bas, <name> !') ON DUPLICATE KEY UPDATE RewardText='Lumière bénie ! Nous avons pris le sommet ! Enfin, la construction du Keep of Justice peut commencer. Highlord Fordring et les chevaliers sont déjà en route vers notre nouvelle base. Vous devez les rejoindre là-bas, <name> !';
