-- Quest 13143 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13143, 'frFR', 'Je suis sûr que leurs maîtres ne les laissent pas tranquilles, mais il n\'y a aucun moyen que ces choses oublient les leçons que nous leur avons infligées. Elles craindront ces sigils tant qu\'elles rampent sur cette terre.') ON DUPLICATE KEY UPDATE CompletionText='Je suis sûr que leurs maîtres ne les laissent pas tranquilles, mais il n\'y a aucun moyen que ces choses oublient les leçons que nous leur avons infligées. Elles craindront ces sigils tant qu\'elles rampent sur cette terre.';
