INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13204, 'frFR', 'Avez-vous une idée de ce que vous avez emporté, <class>?$B$BLes bêtes de la caverne que vous avez récoltées n\'ont pas de méthode traditionnelle pour excréter leurs déchets. Vous voudriez vous laver les mains...$B$BMerci pour l\'intention, mais si vous en trouvez d\'autres, veuillez les garder pour vous.') ON DUPLICATE KEY UPDATE RewardText='Avez-vous une idée de ce que vous avez emporté, <class>?$B$BLes bêtes de la caverne que vous avez récoltées n\'ont pas de méthode traditionnelle pour excréter leurs déchets. Vous voudriez vous laver les mains...$B$BMerci pour l\'intention, mais si vous en trouvez d\'autres, veuillez les garder pour vous.';
