INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13240, 'frFR', '<L\'archimage hoche la tête avant même que tu ne dises un mot.>$b$bJe sais. Tu as détruit les constructions comme je l\'avais prévu et tu as ensuite pu affronter Varos Cloudstrider.$b$bExcellente performance, $N!') ON DUPLICATE KEY UPDATE RewardText='<L\'archimage hoche la tête avant même que tu ne dises un mot.>$b$bJe sais. Tu as détruit les constructions comme je l\'avais prévu et tu as ensuite pu affronter Varos Cloudstrider.$b$bExcellente performance, $N!';

-- Quest 13241 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13241, 'frFR', 'L\'archimage presse ses doigts contre ses tempes et se concentre.$B$BLes berserkers ne sont pas encore tués. Écoute mon avertissement, $N$. Tu dois faire ça !') ON DUPLICATE KEY UPDATE CompletionText='L\'archimage presse ses doigts contre ses tempes et se concentre.$B$BLes berserkers ne sont pas encore tués. Écoute mon avertissement, $N$. Tu dois faire ça !';
-- Quest 13243 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13243, 'frFR', 'Le temps est toujours une ressource précieuse, mais encore plus dans ce cas, $N$. S\'il te plaît, occupe-toi des agents Infinis avant qu\'il ne soit trop tard !') ON DUPLICATE KEY UPDATE CompletionText='Le temps est toujours une ressource précieuse, mais encore plus dans ce cas, $N$. S\'il te plaît, occupe-toi des agents Infinis avant qu\'il ne soit trop tard !';
-- Quest 13243 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13243, 'frFR', 'Nous sommes sauvés pour l\'instant. Merci.$b$bMalheureusement, en raison de la nature de leur ingérence, les Infinis auront presque une opportunité illimitée de le faire à nouveau.$b$bCe que je peux discerner, c\'est qu\'à l\'avenir, tu es au cœur de la lutte pour les arrêter, $N$ !') ON DUPLICATE KEY UPDATE RewardText='Nous sommes sauvés pour l\'instant. Merci.$b$bMalheureusement, en raison de la nature de leur ingérence, les Infinis auront presque une opportunité illimitée de le faire à nouveau.$b$bCe que je peux discerner, c\'est qu\'à l\'avenir, tu es au cœur de la lutte pour les arrêter, $N$ !';
-- Quest 13244 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13244, 'frFR', 'Même moi, je ne peux pas discerner pourquoi nous sommes debout ici à parler alors que tu n\'as pas encore éliminé la menace des avant-gardes de titane.') ON DUPLICATE KEY UPDATE CompletionText='Même moi, je ne peux pas discerner pourquoi nous sommes debout ici à parler alors que tu n\'as pas encore éliminé la menace des avant-gardes de titane.';
-- Quest 13247 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13247, 'frFR', 'Le gardien de la loi a-t-il été traité, $c$ ?b$bJe n\'ai pas besoin de te rappeler que Malygos tente d\'arrêter l\'utilisation de toute magie dans le monde, et que le vol de dragon bleu tue quiconque sait l\'utiliser sans se tourner de leur côté ?') ON DUPLICATE KEY UPDATE CompletionText='Le gardien de la loi a-t-il été traité, $c$ ?b$bJe n\'ai pas besoin de te rappeler que Malygos tente d\'arrêter l\'utilisation de toute magie dans le monde, et que le vol de dragon bleu tue quiconque sait l\'utiliser sans se tourner de leur côté ?';
-- Quest 13256 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13256, 'frFR', 'En y réfléchissant, pourquoi t\'es-tu téléporté dans une prison pour t\'en échapper ? C\'est le seul endroit le plus sûr de la ville.$b$bJe pense que les bleus sont devenus fous !') ON DUPLICATE KEY UPDATE CompletionText='En y réfléchissant, pourquoi t\'es-tu téléporté dans une prison pour t\'en échapper ? C\'est le seul endroit le plus sûr de la ville.$b$bJe pense que les bleus sont devenus fous !';
-- Quest 13256 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13256, 'frFR', 'Le danger est passé et les autres prisonniers qui s\'étaient échappés sont à nouveau emprisonnés.$b$bDalaran te doit une gratitude, $N$ !b$bMaintenant, j\'ai besoin d\'aller parler à quelqu\'un de la raison pour laquelle il était si facile de contourner les protections anti-téléportation de la ville à l\'intérieur de la prison ?!') ON DUPLICATE KEY UPDATE RewardText='Le danger est passé et les autres prisonniers qui s\'étaient échappés sont à nouveau emprisonnés.$b$bDalaran te doit une gratitude, $N$ !b$bMaintenant, j\'ai besoin d\'aller parler à quelqu\'un de la raison pour laquelle il était si facile de contourner les protections anti-téléportation de la ville à l\'intérieur de la prison ?!';
-- Quest 13264 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13264, 'frFR', 'Tu vois, <class>?$B$L\'ingéniosité peut parfois défier les chances contre un ennemi apparemment écrasant.') ON DUPLICATE KEY UPDATE RewardText='Tu vois, <class>?$B$L\'ingéniosité peut parfois défier les chances contre un ennemi apparemment écrasant.';

-- Quest 13265 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13265, 'frFR', 'Les humanoïdes des terres du nord portent des vêtements qui peuvent être transformés en tissu si vous savez comment.$b$bPour quelques pièces d\'or, je suis prêt à vous apprendre l\'art du Récupération de Tissu qui vous donnera du tissu frostweave supplémentaire des humanoïdes de Northrend que vous tuez.') ON DUPLICATE KEY UPDATE CompletionText='Les humanoïdes des terres du nord portent des vêtements qui peuvent être transformés en tissu si vous savez comment.$b$bPour quelques pièces d\'or, je suis prêt à vous apprendre l\'art du Récupération de Tissu qui vous donnera du tissu frostweave supplémentaire des humanoïdes de Northrend que vous tuez.';
-- Quest 13268 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13268, 'frFR', 'Vous avez l\'air de quelqu\'un qui connaît son chemin avec une aiguille et un fil, alors peut-être que je peux vous aider.$B$BLes humanoïdes du nord portent des vêtements qui peuvent être rapidement transformés en tissu si vous savez comment.$B$BPour quelques pièces d\'or, je suis prêt à vous apprendre l\'art du Récupération de Tissu qui vous donnera du tissu supplémentaire des humanoïdes de Northrend.') ON DUPLICATE KEY UPDATE CompletionText='Vous avez l\'air de quelqu\'un qui connaît son chemin avec une aiguille et un fil, alors peut-être que je peux vous aider.$B$BLes humanoïdes du nord portent des vêtements qui peuvent être rapidement transformés en tissu si vous savez comment.$B$BPour quelques pièces d\'or, je suis prêt à vous apprendre l\'art du Récupération de Tissu qui vous donnera du tissu supplémentaire des humanoïdes de Northrend.';
