INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13548, 'frFR', 'Des seaux de bonbons comme celui-ci se trouvent dans les auberges de tous les royaumes. Allez-y... prenez-en !') ON DUPLICATE KEY UPDATE RewardText='Des seaux de bonbons comme celui-ci se trouvent dans les auberges de tous les royaumes. Allez-y... prenez-en !';
-- Quest 13549 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13549, 'frFR', 'Non, ce n\'est pas acceptable. Veuillez revenir lorsque vous aurez les femelles léopards et ours dont j\'aurai besoin pour le difficile voyage de retour.') ON DUPLICATE KEY UPDATE CompletionText='Non, ce n\'est pas acceptable. Veuillez revenir lorsque vous aurez les femelles léopards et ours dont j\'aurai besoin pour le difficile voyage de retour.';
-- Quest 13549 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13549, 'frFR', 'De très beaux spécimens, <name> ! Ceux-ci sont sûrs de fournir de nombreuses heures de spéculation curieuse parmi mes collègues chez moi.') ON DUPLICATE KEY UPDATE RewardText='De très beaux spécimens, <name> ! Ceux-ci sont sûrs de fournir de nombreuses heures de spéculation curieuse parmi mes collègues chez moi.';

-- Quest 13559 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13559, 'frFR', 'Aucun tribut ordinaire n\'était assez bon pour le grand Hodir lorsqu\'il errait parmi les géants de glace.$B$BIl n\'est peut-être plus parmi nous, mais nous avons maintenu la tradition d\'offrir un tribut à sa force et à sa sagesse. Il serait bon pour votre renommée de prendre part à cette tradition, petit $c.') ON DUPLICATE KEY UPDATE CompletionText='Aucun tribut ordinaire n\'était assez bon pour le grand Hodir lorsqu\'il errait parmi les géants de glace.$B$BIl n\'est peut-être plus parmi nous, mais nous avons maintenu la tradition d\'offrir un tribut à sa force et à sa sagesse. Il serait bon pour votre renommée de prendre part à cette tradition, petit $c.';
-- Quest 13571 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13571, 'frFR', 'Au-dessus de la puanteur aigre et non lavée, vous sentez une odeur familière ! Il semble que ce vieux aventurier ait un vrai amour pour le kungaloosh.$b$bEn regardant à travers les barreaux, vous pouvez à peine distinguer la recette écrite sur son bras....') ON DUPLICATE KEY UPDATE RewardText='Au-dessus de la puanteur aigre et non lavée, vous sentez une odeur familière ! Il semble que ce vieux aventurier ait un vrai amour pour le kungaloosh.$b$bEn regardant à travers les barreaux, vous pouvez à peine distinguer la recette écrite sur son bras....';
