-- Quest 13662 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (13662, 'frFR', 'Vous avez gravi les échelons de la hiérarchie corporative de la Fraternité, $r. Nous commençons à vous accorder une faveur. Quel accomplissement !$B$BSi vous êtes intéressé par plus de travail et par gagner plus de respect parmi nous, écoutez bien.$B$BNous pouvons raffiner le flux ardent en ajoutant un simple résidu de Fer Noir au mélange. Le résidu de Fer Noir se trouve dans les Profondeurs de Blackrock.$B$BBringez-moi tout le résidu de Fer Noir que vous trouvez !') ON DUPLICATE KEY UPDATE CompletionText='Vous avez gravi les échelons de la hiérarchie corporative de la Fraternité, $r. Nous commençons à vous accorder une faveur. Quel accomplissement !$B$BSi vous êtes intéressé par plus de travail et par gagner plus de respect parmi nous, écoutez bien.$B$BNous pouvons raffiner le flux ardent en ajoutant un simple résidu de Fer Noir au mélange. Le résidu de Fer Noir se trouve dans les Profondeurs de Blackrock.$B$BBringez-moi tout le résidu de Fer Noir que vous trouvez !';
