-- Quest 13737 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (13737, 'frFR', 'Je t\'accueille comme champion du tournoi, $Gname>. En tant que champion, tu pourras concourir au grand championnat du tournoi. Tu peux également choisir de devenir un vaillant avec la délégation d\'une autre ville de la Horde et, avec le temps, un champion pour cette ville également.$B<br :>Tous les champions doivent être assistés d\'un écuyer, <name, et tu ne fais pas exception. Permets-moi d\'en désigner un de nos pour t\'accompagner au combat. Il portera fièrement le étendard de toute ville qui t\'a nommé champion.') ON DUPLICATE KEY UPDATE RewardText='Je t\'accueille comme champion du tournoi, $Gname>. En tant que champion, tu pourras concourir au grand championnat du tournoi. Tu peux également choisir de devenir un vaillant avec la délégation d\'une autre ville de la Horde et, avec le temps, un champion pour cette ville également.$B<br :>Tous les champions doivent être assistés d\'un écuyer, <name, et tu ne fais pas exception. Permets-moi d\'en désigner un de nos pour t\'accompagner au combat. Il portera fièrement le étendard de toute ville qui t\'a nommé champion.';
