-- Quest 14177 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14177, 'frFR', 'Ah, plus de Pain des Morts délicieux, merci !$B$BS\'il vous plaît, prenez ceci en retour... un petit quelque chose d\'amusant pour les fêtes.') ON DUPLICATE KEY UPDATE RewardText='Ah, plus de Pain des Morts délicieux, merci !$B$BS\'il vous plaît, prenez ceci en retour... un petit quelque chose d\'amusant pour les fêtes.';
