-- Quest 14179 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14179, 'frFR', 'Nous nous sommes rapprochés d\'une victoire totale sur la Horde. Nous ne pouvons pas permettre à l\'ennemi d\'obtenir un pied-point dans ce monde ou un autre.') ON DUPLICATE KEY UPDATE RewardText='Nous nous sommes rapprochés d\'une victoire totale sur la Horde. Nous ne pouvons pas permettre à l\'ennemi d\'obtenir un pied-point dans ce monde ou un autre.';

