INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14182, 'frFR', 'Tu es de retour ! Apportes-tu des nouvelles de victoire ?') ON DUPLICATE KEY UPDATE CompletionText='Tu es de retour ! Apportes-tu des nouvelles de victoire ?';
-- Quest 14182 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14182, 'frFR', 'Tu nous apportes un honneur, $N. Nous devons montrer à l\'ennemi que nous les combattreons où que nous les trouvions.') ON DUPLICATE KEY UPDATE RewardText='Tu nous apportes un honneur, $N. Nous devons montrer à l\'ennemi que nous les combattreons où que nous les trouvions.';
