-- Quest 14199 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14199, 'frFR', 'Le Chevalier Noir est-il apparu de manière inattendue comme l\'avait prédit Timear ?') ON DUPLICATE KEY UPDATE CompletionText='Le Chevalier Noir est-il apparu de manière inattendue comme l\'avait prédit Timear ?';

-- Quest 14203 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14203, 'frFR', 'Le vin n\'est aussi bon que la personne qui le boit, je le dis toujours.') ON DUPLICATE KEY UPDATE CompletionText='Le vin n\'est aussi bon que la personne qui le boit, je le dis toujours.';
-- Quest 14349 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14349, 'frFR', 'Le Grand Croisé siège en toute sécurité dans la Bastion Écarlate tandis que ses forces déferlent sur nos terres, profanent nos structures et monuments et massacrent notre peuple.$B$BIl est temps de nous débarrasser de ce fléau. Tu deviendras l\'instrument de notre jugement.') ON DUPLICATE KEY UPDATE RewardText='Le Grand Croisé siège en toute sécurité dans la Bastion Écarlate tandis que ses forces déferlent sur nos terres, profanent nos structures et monuments et massacrent notre peuple.$B$BIl est temps de nous débarrasser de ce fléau. Tu deviendras l\'instrument de notre jugement.';
-- Quest 14350 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14350, 'frFR', 'Réussis maintenant et tu auras presque gagné mon respect, $C.') ON DUPLICATE KEY UPDATE CompletionText='Réussis maintenant et tu auras presque gagné mon respect, $C.';
-- Quest 14350 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14350, 'frFR', '<Nathanos rit.>$B$BExcellent ! Enfin ! Une occasion de détruire l\'Oracle Écarlate !') ON DUPLICATE KEY UPDATE RewardText='<Nathanos rit.>$B$BExcellent ! Enfin ! Une occasion de détruire l\'Oracle Écarlate !';
-- Quest 14351 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14351, 'frFR', 'Pourquoi n\'es-tu pas sur le champ de bataille, $c?') ON DUPLICATE KEY UPDATE CompletionText='Pourquoi n\'es-tu pas sur le champ de bataille, $c?';
-- Quest 14351 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14351, 'frFR', 'Alors tu es le $c qui a traversé les forces de l\'Alliance dans les Collines de Hillsbrad ? J\'ai déjà entendu ton nom. Les nouvelles circulent vite.$B$BLa Horde peut utiliser quelqu\'un comme toi si tu continues comme ça, $N.$B$BNous devons garder un œil sur toutes les menaces autour de nous, mais avec ce roi qui les dirige, les humains continueront d\'être un problème. Tu as confirmé qu\'il y a assez de force dans la Horde pour mettre fin à cette menace à temps.') ON DUPLICATE KEY UPDATE RewardText='Alors tu es le $c qui a traversé les forces de l\'Alliance dans les Collines de Hillsbrad ? J\'ai déjà entendu ton nom. Les nouvelles circulent vite.$B$BLa Horde peut utiliser quelqu\'un comme toi si tu continues comme ça, $N.$B$BNous devons garder un œil sur toutes les menaces autour de nous, mais avec ce roi qui les dirige, les humains continueront d\'être un problème. Tu as confirmé qu\'il y a assez de force dans la Horde pour mettre fin à cette menace à temps.';
-- Quest 14352 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14352, 'frFR', 'Que veux-tu, $N? Cela doit être important.') ON DUPLICATE KEY UPDATE CompletionText='Que veux-tu, $N? Cela doit être important.';
-- Quest 14352 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14352, 'frFR', 'J\'ai vu l\'insigne sur ce parchemin auparavant pendant mon temps à Northrend. Tu dis que c\'était sur cette vieille femme qui dirige les cochons à Razorfen Kraul?$B$Je maudirai si je laisse le Fléau prendre pied ici. Celui qui a écrit ceci - ce Malcin - est un des serviteurs du Roi-Lich, évidemment, et cela fait de lui une cible. Ta cible.$B$BIls ne prendront pas Kalimdor.') ON DUPLICATE KEY UPDATE RewardText='J\'ai vu l\'insigne sur ce parchemin auparavant pendant mon temps à Northrend. Tu dis que c\'était sur cette vieille femme qui dirige les cochons à Razorfen Kraul?$B$Je maudirai si je laisse le Fléau prendre pied ici. Celui qui a écrit ceci - ce Malcin - est un des serviteurs du Roi-Lich, évidemment, et cela fait de lui une cible. Ta cible.$B$BIls ne prendront pas Kalimdor.';

-- Quest 14353 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14353, 'frFR', 'Supposément, ce Malcin est en dehors de Razorfen Downs. Il n\'y a aucun doute, il doit mourir.$b$bMes contacts à Orgrimmar me disent que leurs éclaireurs ont trouvé des signes de la Plague là-bas. Les quilboar montrent aussi des signes d\'être maudits ; ils sont beaucoup plus puissants. Ce que les Scourge font là-bas doit cesser. Maintenant.$b$bTrouvez ce Malcin et tuez-le. Rapportez-vous ici quand il sera mort.') ON DUPLICATE KEY UPDATE CompletionText='Supposément, ce Malcin est en dehors de Razorfen Downs. Il n\'y a aucun doute, il doit mourir.$b$bMes contacts à Orgrimmar me disent que leurs éclaireurs ont trouvé des signes de la Plague là-bas. Les quilboar montrent aussi des signes d\'être maudits ; ils sont beaucoup plus puissants. Ce que les Scourge font là-bas doit cesser. Maintenant.$b$bTrouvez ce Malcin et tuez-le. Rapportez-vous ici quand il sera mort.';
-- Quest 14353 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14353, 'frFR', 'Bon travail, <class>!$B$BVous avez fait fière la Horde en empêchant les Scourge de s\'établir sur notre sol. Un tel acte mérite une récompense, et les Forsaken ont suffisamment de choses que je suis sûr qu\'ils peuvent nous accorder.$B$BNous ne savons pas tout ce qu\'ils ont fait dans les Downs, mais nous allons le découvrir. Ils ne peuvent pas se faufiler dans le noir pour toujours.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, <class>!$B$BVous avez fait fière la Horde en empêchant les Scourge de s\'établir sur notre sol. Un tel acte mérite une récompense, et les Forsaken ont suffisamment de choses que je suis sûr qu\'ils peuvent nous accorder.$B$BNous ne savons pas tout ce qu\'ils ont fait dans les Downs, mais nous allons le découvrir. Ils ne peuvent pas se faufiler dans le noir pour toujours.';
-- Quest 14355 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14355, 'frFR', 'Je suis sûr que Sylvanas sera heureuse que ce problème soit réglé, $N. La tâche que je t\'ai donnée n\'était pas facile, mais tu te tiens là, victorieux. Cela commande le respect, et ce que tu as fait ne sera pas oublié.') ON DUPLICATE KEY UPDATE RewardText='Je suis sûr que Sylvanas sera heureuse que ce problème soit réglé, $N. La tâche que je t\'ai donnée n\'était pas facile, mais tu te tiens là, victorieux. Cela commande le respect, et ce que tu as fait ne sera pas oublié.';
-- Quest 14356 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14356, 'frFR', 'As-tu sécurisé les livres ? Ils doivent rester hors de mauvaises mains.') ON DUPLICATE KEY UPDATE CompletionText='As-tu sécurisé les livres ? Ils doivent rester hors de mauvaises mains.';
-- Quest 14356 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14356, 'frFR', 'Bien, <class>. Tu as bien fait. Je les garderai à l\'abri des regards ; la dernière chose dont nous avons besoin est qu\'un puissant Conseil des Ombres se relève à nouveau.$B$BReviens me voir dans le futur ; il y a toujours quelque chose à faire par ici, apparemment, et j\'pourrais avoir besoin d\'un autre homme capable.') ON DUPLICATE KEY UPDATE RewardText='Bien, <class>. Tu as bien fait. Je les garderai à l\'abri des regards ; la dernière chose dont nous avons besoin est qu\'un puissant Conseil des Ombres se relève à nouveau.$B$BReviens me voir dans le futur ; il y a toujours quelque chose à faire par ici, apparemment, et j\'pourrais avoir besoin d\'un autre homme capable.';
-- Quest 14409 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14409, 'frFR', 'Il semble que j\'aie le temps de parler. À quoi cela se rapporte-t-il ?') ON DUPLICATE KEY UPDATE CompletionText='Il semble que j\'aie le temps de parler. À quoi cela se rapporte-t-il ?';
-- Quest 14418 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14418, 'frFR', 'Hmm, c\'est intéressant. Les Chasseurs de Mort ont rempli leurs devoirs admirablement en traquant cela.$B$BD\'après ce que je comprends, vous méritez également des félicitations pour votre performance. J\'espère que cela deviendra une routine pour vous, $N, mes Chasseurs de Mort ont toujours besoin d\'un bon homme.') ON DUPLICATE KEY UPDATE RewardText='Hmm, c\'est intéressant. Les Chasseurs de Mort ont rempli leurs devoirs admirablement en traquant cela.$B$BD\'après ce que je comprends, vous méritez également des félicitations pour votre performance. J\'espère que cela deviendra une routine pour vous, $N, mes Chasseurs de Mort ont toujours besoin d\'un bon homme.';
-- Quest 14419 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14419, 'frFR', 'Bonjour. Quelque chose que je peux faire pour vous ?') ON DUPLICATE KEY UPDATE CompletionText='Bonjour. Quelque chose que je peux faire pour vous ?';

-- Quest 14419 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14419, 'frFR', 'Ah, oui, je m\'attendais à toi. Je ne doute pas que nos connaissances mutuelles sont satisfaites par les informations que j\'ai fournies jusqu\'à présent?$B$BI je suppose qu\'il est inutile de te demander, je doute qu\'ils t\'encombrent de cette connaissance. Pourquoi faire autant confiance au messager, hein?') ON DUPLICATE KEY UPDATE RewardText='Ah, oui, je m\'attendais à toi. Je ne doute pas que nos connaissances mutuelles sont satisfaites par les informations que j\'ai fournies jusqu\'à présent?$B$BI je suppose qu\'il est inutile de te demander, je doute qu\'ils t\'encombrent de cette connaissance. Pourquoi faire autant confiance au messager, hein?';
-- Quest 14420 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14420, 'frFR', 'Bien joué, $N. Tu as réussi la première partie de ce test. J\'espère qu\'Andron n\'a pas entendu parler de tes activités, et nous pourrons le convaincre que tu es, en fait, le messager qu\'il attend.') ON DUPLICATE KEY UPDATE RewardText='Bien joué, $N. Tu as réussi la première partie de ce test. J\'espère qu\'Andron n\'a pas entendu parler de tes activités, et nous pourrons le convaincre que tu es, en fait, le messager qu\'il attend.';
-- Quest 14421 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14421, 'frFR', 'Eh bien, c\'est certainement plus d\'informations que je ne le soupçonnais obtenir d\'Andron. Donne-moi un instant pour les parcourir, avant de te confier ta prochaine tâche.') ON DUPLICATE KEY UPDATE RewardText='Eh bien, c\'est certainement plus d\'informations que je ne le soupçonnais obtenir d\'Andron. Donne-moi un instant pour les parcourir, avant de te confier ta prochaine tâche.';
-- Quest 14443 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14443, 'frFR', 'Qu\'est-ce que tu as là ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que tu as là ?';
-- Quest 14457 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14457, 'frFR', 'As-tu trouvé quelque chose d\'utile sur cet agent ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu trouvé quelque chose d\'utile sur cet agent ?';
-- Quest 14483 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14483, 'frFR', 'T\'es-tu occupé de ces vilains machiavéliques ?') ON DUPLICATE KEY UPDATE CompletionText='T\'es-tu occupé de ces vilains machiavéliques ?';
-- Quest 14488 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (14488, 'frFR', 'Je ne me souviens pas avoir commandé un service de nettoyage... oui, je suis l\'Apothicaire Hummel.$b$b...attends, qu\'est-ce que cela signifie ? Tu penses que ces papiers sans importance peuvent m\'arrêter ? Hah !') ON DUPLICATE KEY UPDATE CompletionText='Je ne me souviens pas avoir commandé un service de nettoyage... oui, je suis l\'Apothicaire Hummel.$b$b...attends, qu\'est-ce que cela signifie ? Tu penses que ces papiers sans importance peuvent m\'arrêter ? Hah !';
-- Quest 14488 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (14488, 'frFR', 'Ce que nous faisons ici ne te regarde pas...') ON DUPLICATE KEY UPDATE RewardText='Ce que nous faisons ici ne te regarde pas...';

