INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (20438, 'frFR', 'Shandy a-t-elle pu vous aider à obtenir une tabard de Sunreaver ?') ON DUPLICATE KEY UPDATE CompletionText='Shandy a-t-elle pu vous aider à obtenir une tabard de Sunreaver ?';
