INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24220, 'frFR', 'Excellente nouvelle, $c! Si nos déploiements tactiques continuent d\'être aussi réussis, la Horde fera un repli complet d\'ici peu.') ON DUPLICATE KEY UPDATE RewardText='Excellente nouvelle, $c! Si nos déploiements tactiques continuent d\'être aussi réussis, la Horde fera un repli complet d\'ici peu.';
