INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24225, 'frFR', 'La Horde vous doit beaucoup, $N. Vous avez rendu votre peuple fier par votre courage à défendre nos terres.') ON DUPLICATE KEY UPDATE RewardText='La Horde vous doit beaucoup, $N. Vous avez rendu votre peuple fier par votre courage à défendre nos terres.';
