INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24226, 'frFR', 'Vous avez apporté une grande honneur à la Horde, $N. Votre victoire aujourd\'hui assurera mille victoires demain !') ON DUPLICATE KEY UPDATE RewardText='Vous avez apporté une grande honneur à la Horde, $N. Votre victoire aujourd\'hui assurera mille victoires demain !';
-- Quest 24426 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24426, 'frFR', 'Il n\'y a pas plus grand honneur que d\'expulser les envahisseurs des territoires de la Horde. Nous saluons votre grand courage à avoir aidé nos forces aujourd\'hui !') ON DUPLICATE KEY UPDATE RewardText='Il n\'y a pas plus grand honneur que d\'expulser les envahisseurs des territoires de la Horde. Nous saluons votre grand courage à avoir aidé nos forces aujourd\'hui !';
-- Quest 24427 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24427, 'frFR', 'Juste ce que je voulais entendre ! Une victoire dans la Vallée d\'Alterac - même temporaire - est cruciale pour notre stratégie globale contre la Horde.') ON DUPLICATE KEY UPDATE RewardText='Juste ce que je voulais entendre ! Une victoire dans la Vallée d\'Alterac - même temporaire - est cruciale pour notre stratégie globale contre la Horde.';
