INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24442, 'frFR', 'Qu\'avez-vous trouvé, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'avez-vous trouvé, $N ?';
-- Quest 24442 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24442, 'frFR', '$GMariel accepte les ordres et le cristal de vision capturé et examine les deux.>$B<br :>Bon travail, <name, et réflexion rapide. Je suis sûr que le vol de cette bibelot ne les ralentira pas longtemps, mais je pense que vous nous avez acheté le temps d\'avertir les dirigeants de la Horde et de l\'Alliance des attaques imminentes.') ON DUPLICATE KEY UPDATE RewardText='$GMariel accepte les ordres et le cristal de vision capturé et examine les deux.>$B<br :>Bon travail, <name, et réflexion rapide. Je suis sûr que le vol de cette bibelot ne les ralentira pas longtemps, mais je pense que vous nous avez acheté le temps d\'avertir les dirigeants de la Horde et de l\'Alliance des attaques imminentes.';

-- Quest 24451 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24451, 'frFR', 'Excellent travail. Maintenant que c\'est entre nos mains, nous devons l\'amener à Myralion Sunblaze le plus tôt possible. Nous ne pouvons pas risquer que le Pacte d\'Argent nous prenne le livre à nouveau.$B$Je ramènerai ce tabard à Shandy et je m\'assurerai qu\'il soit bien compensé pour son aide. Une fois que le livre sera entre les mains de Myralion, le Pacte d\'Argent ne sera plus une menace.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail. Maintenant que c\'est entre nos mains, nous devons l\'amener à Myralion Sunblaze le plus tôt possible. Nous ne pouvons pas risquer que le Pacte d\'Argent nous prenne le livre à nouveau.$B$Je ramènerai ce tabard à Shandy et je m\'assurerai qu\'il soit bien compensé pour son aide. Une fois que le livre sera entre les mains de Myralion, le Pacte d\'Argent ne sera plus une menace.';
-- Quest 24454 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24454, 'frFR', 'Nous attendions votre retour. Qu\'est-ce qui vous a retenu ?') ON DUPLICATE KEY UPDATE CompletionText='Nous attendions votre retour. Qu\'est-ce qui vous a retenu ?';
-- Quest 24461 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24461, 'frFR', 'Avez-vous pu reconstruire Quel\'Delar ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous pu reconstruire Quel\'Delar ?';
-- Quest 24476 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24476, 'frFR', 'Tant que l\'épée n\'est pas trempée, elle sera inutile.') ON DUPLICATE KEY UPDATE CompletionText='Tant que l\'épée n\'est pas trempée, elle sera inutile.';
-- Quest 24480 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24480, 'frFR', 'Qu\'est-ce qui s\'est passé dans les Salles de Réflexion ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui s\'est passé dans les Salles de Réflexion ?';
-- Quest 24500 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24500, 'frFR', 'Nous devons transmettre cette information à l\'Alliance ! Cela pourrait bien être la clé de la défaite d\'Arthas.') ON DUPLICATE KEY UPDATE CompletionText='Nous devons transmettre cette information à l\'Alliance ! Cela pourrait bien être la clé de la défaite d\'Arthas.';
-- Quest 24510 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24510, 'frFR', '<name>è! Je suis si heureux que tu sois venu.$B$Nous avons eu une chance rare d\'explorer la Citadelle de Glace, mais nous devons agir vite si nous voulons éviter l\'attention d\'Arthas.') ON DUPLICATE KEY UPDATE RewardText='<name>è! Je suis si heureux que tu sois venu.$B$Nous avons eu une chance rare d\'explorer la Citadelle de Glace, mais nous devons agir vite si nous voulons éviter l\'attention d\'Arthas.';
-- Quest 24511 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24511, 'frFR', 'Bien vu, <class>è!$B$Le Pit de Saron se trouve devant nous, et si nos éclaireurs ont raison, au-delà se trouvent les Salles de Réflexion. C\'est là qu\'Arthas baisse sa garde, et c\'est là que nous espérons trouver un indice de sa faiblesse... et une voie vers une vengeance attendue depuis trop longtemps.') ON DUPLICATE KEY UPDATE RewardText='Bien vu, <class>è!$B$Le Pit de Saron se trouve devant nous, et si nos éclaireurs ont raison, au-delà se trouvent les Salles de Réflexion. C\'est là qu\'Arthas baisse sa garde, et c\'est là que nous espérons trouver un indice de sa faiblesse... et une voie vers une vengeance attendue depuis trop longtemps.';

-- Quest 24535 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24535, 'frFR', 'As-tu visité le sol où Thalorien est tombé en défendant le Puits solaire ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu visité le sol où Thalorien est tombé en défendant le Puits solaire ?';
-- Quest 24535 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24535, 'frFR', 'J\'avoue ne pas m\'attendre à ce que l\'esprit de Thalorien vous reconnaisse comme l\'héritier de Quel\'Delar, mais je me soumets à son jugement. Vous pouvez entrer dans le Puits solaire, mais je vous rappelle que vous êtes un invité dans notre lieu le plus sacré, et vous devriez agir en conséquence.') ON DUPLICATE KEY UPDATE RewardText='J\'avoue ne pas m\'attendre à ce que l\'esprit de Thalorien vous reconnaisse comme l\'héritier de Quel\'Delar, mais je me soumets à son jugement. Vous pouvez entrer dans le Puits solaire, mais je vous rappelle que vous êtes un invité dans notre lieu le plus sacré, et vous devriez agir en conséquence.';
-- Quest 24536 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24536, 'frFR', 'Tu analyses cette puanteur, gamin ?') ON DUPLICATE KEY UPDATE CompletionText='Tu analyses cette puanteur, gamin ?';
-- Quest 24541 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24541, 'frFR', 'Ils t\'ont donné une caisse à livrer ?') ON DUPLICATE KEY UPDATE CompletionText='Ils t\'ont donné une caisse à livrer ?';
-- Quest 24545 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24545, 'frFR', 'En t\'approchant, la flamme de la forge semble brûler encore plus avidement...') ON DUPLICATE KEY UPDATE CompletionText='En t\'approchant, la flamme de la forge semble brûler encore plus avidement...';
-- Quest 24545 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24545, 'frFR', 'Un profond sentiment de crainte vous submerge tandis que la flamme dévore les objets.') ON DUPLICATE KEY UPDATE RewardText='Un profond sentiment de crainte vous submerge tandis que la flamme dévore les objets.';
-- Quest 24548 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24548, 'frFR', 'As-tu obtenu les éclats du trône gelé, $C ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu obtenu les éclats du trône gelé, $C ?';
-- Quest 24548 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24548, 'frFR', 'Ceux-ci devraient suffire, <class>.$B$BSpeake à moi lorsque le Bord de l\'Ombre aura été entièrement renforcé et j\'essaierai de l\'achever.') ON DUPLICATE KEY UPDATE RewardText='Ceux-ci devraient suffire, <class>.$B$BSpeake à moi lorsque le Bord de l\'Ombre aura été entièrement renforcé et j\'essaierai de l\'achever.';

-- Quest 24549 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24549, 'frFR', 'Félicitations, <class>.$B$Malgré des chances insurmontables, vous avez traversé la tempête.$B$Je crois que vous trouverez une récompense proportionnelle à votre conviction...') ON DUPLICATE KEY UPDATE RewardText='Félicitations, <class>.$B$Malgré des chances insurmontables, vous avez traversé la tempête.$B$Je crois que vous trouverez une récompense proportionnelle à votre conviction...';
-- Quest 24553 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24553, 'frFR', 'Qu\'est-ce qui s\'est passé pendant votre séjour dans le Puits de Soleil ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui s\'est passé pendant votre séjour dans le Puits de Soleil ?';
-- Quest 24553 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24553, 'frFR', 'C\'est incroyable, <name>. Vous y êtes parvenu ! Tous les quel\'dorei ont entendu parler de Thalorien Chasseur d\'Aube et de Quel\'Delar, mais personne n\'a jamais pensé que l\'épée serait restaurée.') ON DUPLICATE KEY UPDATE RewardText='C\'est incroyable, <name>. Vous y êtes parvenu ! Tous les quel\'dorei ont entendu parler de Thalorien Chasseur d\'Aube et de Quel\'Delar, mais personne n\'a jamais pensé que l\'épée serait restaurée.';
-- Quest 24554 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24554, 'frFR', '<Myralion prend le manche de votre main et examine l\'artefact.>$B$C\'est venu de la citadelle ? Qu\'est-ce qu\'elle faisait là ? Cette lame n\'est certainement pas de fabrication des Scourge.$B$Des armes de cette qualité ne peuvent être fabriquées que par quelques créatures d\'Azeroth. Nous devrons les consulter pour voir si elles peuvent nous aider à l\'identifier.') ON DUPLICATE KEY UPDATE RewardText='<Myralion prend le manche de votre main et examine l\'artefact.>$B$C\'est venu de la citadelle ? Qu\'est-ce qu\'elle faisait là ? Cette lame n\'est certainement pas de fabrication des Scourge.$B$Des armes de cette qualité ne peuvent être fabriquées que par quelques créatures d\'Azeroth. Nous devrons les consulter pour voir si elles peuvent nous aider à l\'identifier.';
-- Quest 24555 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24555, 'frFR', 'Nous devons récupérer ce livre auprès du Pacte d\'Argent. Sans ce livre de Krasus, nous avons peu de chances de résoudre le mystère de l\'épée dans Icecrown ou de débloquer son pouvoir.') ON DUPLICATE KEY UPDATE RewardText='Nous devons récupérer ce livre auprès du Pacte d\'Argent. Sans ce livre de Krasus, nous avons peu de chances de résoudre le mystère de l\'épée dans Icecrown ou de débloquer son pouvoir.';
-- Quest 24556 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24556, 'frFR', 'Shandy a-t-elle pu vous aider à obtenir un tabard du Pacte d\'Argent ?') ON DUPLICATE KEY UPDATE CompletionText='Shandy a-t-elle pu vous aider à obtenir un tabard du Pacte d\'Argent ?';
-- Quest 24556 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24556, 'frFR', 'Je savais que Shandy trouverait un moyen de faire fonctionner les choses. Laissez-moi le faire enchanter et le préparer pour que vous puissiez l\'utiliser. Avec un peu de chance, le propriétaire du tabard ne saura même pas qu\'il manque et Shandy couvrira le reste de nos traces.') ON DUPLICATE KEY UPDATE RewardText='Je savais que Shandy trouverait un moyen de faire fonctionner les choses. Laissez-moi le faire enchanter et le préparer pour que vous puissiez l\'utiliser. Avec un peu de chance, le propriétaire du tabard ne saura même pas qu\'il manque et Shandy couvrira le reste de nos traces.';
-- Quest 24557 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24557, 'frFR', 'Avez-vous trouvé quelque chose d\'utile sur cet agent ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous trouvé quelque chose d\'utile sur cet agent ?';

-- Quest 24557 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24557, 'frFR', '$GMagister Hathorel lit les ordres capturés.>$B<br :>L\'agent que vous avez intercepté était censé livrer le tome de Wyrmrest à Icecrown, après avoir rencontré un Arcaniste Tybalin à l\'intérieur de l\'Enclave d\'Argent. Nous devons récupérer ce livre, <name, et nous n\'avons qu\'une seule chance avant qu\'il ne quitte la ville. Nous devons agir vite.') ON DUPLICATE KEY UPDATE RewardText='$GMagister Hathorel lit les ordres capturés.>$B<br :>L\'agent que vous avez intercepté était censé livrer le tome de Wyrmrest à Icecrown, après avoir rencontré un Arcaniste Tybalin à l\'intérieur de l\'Enclave d\'Argent. Nous devons récupérer ce livre, <name, et nous n\'avons qu\'une seule chance avant qu\'il ne quitte la ville. Nous devons agir vite.';
-- Quest 24558 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24558, 'frFR', 'Nous attendions votre retour. Qu\'est-ce qui vous a retenu ?') ON DUPLICATE KEY UPDATE CompletionText='Nous attendions votre retour. Qu\'est-ce qui vous a retenu ?';
-- Quest 24558 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24558, 'frFR', '<Myralion accepte le lourd livre et commence à le feuilleter.>$B$BCes symboles sur la lame semblaient familiers et il n\'est pas étonnant maintenant. C\'est certainement une lame de dragon, offerte à une des races mortelles, mais quelle est cette lame, et comment est-elle arrivée à Icecrown ?') ON DUPLICATE KEY UPDATE RewardText='<Myralion accepte le lourd livre et commence à le feuilleter.>$B$BCes symboles sur la lame semblaient familiers et il n\'est pas étonnant maintenant. C\'est certainement une lame de dragon, offerte à une des races mortelles, mais quelle est cette lame, et comment est-elle arrivée à Icecrown ?';
-- Quest 24559 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24559, 'frFR', 'Avez-vous réussi à reconstruire Quel\'Delar ?') ON DUPLICATE KEY UPDATE CompletionText='Avez-vous réussi à reconstruire Quel\'Delar ?';
-- Quest 24559 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24559, 'frFR', 'Vous avez refait la lame de Quel\'Delar en défi de la proclamation de cette Reine de Sang Lana\'thel ! Maintenant, la lame doit être trempée avant que nous puissions lui montrer la folie de ses paroles.') ON DUPLICATE KEY UPDATE RewardText='Vous avez refait la lame de Quel\'Delar en défi de la proclamation de cette Reine de Sang Lana\'thel ! Maintenant, la lame doit être trempée avant que nous puissions lui montrer la folie de ses paroles.';
-- Quest 24560 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24560, 'frFR', 'Tant que l\'épée n\'est pas trempée, elle sera inutile.') ON DUPLICATE KEY UPDATE CompletionText='Tant que l\'épée n\'est pas trempée, elle sera inutile.';
-- Quest 24560 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24560, 'frFR', 'Le trempage de l\'épée aurait dû restaurer la lame. Pourquoi cela n\'a-t-il pas fonctionné ?') ON DUPLICATE KEY UPDATE RewardText='Le trempage de l\'épée aurait dû restaurer la lame. Pourquoi cela n\'a-t-il pas fonctionné ?';
-- Quest 24561 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24561, 'frFR', 'Qu\'est-ce qui s\'est passé dans les Halls de Réflexion ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui s\'est passé dans les Halls de Réflexion ?';

-- Quest 24561 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24561, 'frFR', 'Comment le mal peut-il prendre racine dans une telle épée ? Je n\'aurais pas pensé cela possible si la preuve n\'était pas là devant mes yeux. Si la création du plus grand des dragonkind pouvait être corrompue et se retourner contre eux, pourquoi pas une simple épée ? $B$BJe crois qu\'Uther a raison. Tu dois suivre son conseil rapidement, <name>.') ON DUPLICATE KEY UPDATE RewardText='Comment le mal peut-il prendre racine dans une telle épée ? Je n\'aurais pas pensé cela possible si la preuve n\'était pas là devant mes yeux. Si la création du plus grand des dragonkind pouvait être corrompue et se retourner contre eux, pourquoi pas une simple épée ? $B$BJe crois qu\'Uther a raison. Tu dois suivre son conseil rapidement, <name>.';
-- Quest 24562 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24562, 'frFR', 'J\'espère que tu comprends que je ne peux pas simplement t\'admettre au Puits du Soleil, <name>. C\'est le lieu le plus sacré connu des sin\'dorei et nous venons tout juste de reprendre le contrôle dessus.$B$BTu allumerais l\'espoir de notre peuple avec des histoires de Quel\'Delar ? Sans preuve de la vérité de tes affirmations, je ne vois aucune raison de te croire sur parole.') ON DUPLICATE KEY UPDATE RewardText='J\'espère que tu comprends que je ne peux pas simplement t\'admettre au Puits du Soleil, <name>. C\'est le lieu le plus sacré connu des sin\'dorei et nous venons tout juste de reprendre le contrôle dessus.$B$BTu allumerais l\'espoir de notre peuple avec des histoires de Quel\'Delar ? Sans preuve de la vérité de tes affirmations, je ne vois aucune raison de te croire sur parole.';
-- Quest 24563 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24563, 'frFR', 'Tu portes vraiment Quel\'Delar. C\'est un grand jour pour tout Quel\'Thalas et les sin\'dorei. Tu as mon autorisation d\'entrer au Puits du Soleil et de terminer la restauration de l\'épée. Garde la tête haute, <name>. Les enfants de Silvermoon ont rêvé de ce jour depuis des années.') ON DUPLICATE KEY UPDATE RewardText='Tu portes vraiment Quel\'Delar. C\'est un grand jour pour tout Quel\'Thalas et les sin\'dorei. Tu as mon autorisation d\'entrer au Puits du Soleil et de terminer la restauration de l\'épée. Garde la tête haute, <name>. Les enfants de Silvermoon ont rêvé de ce jour depuis des années.';
-- Quest 24564 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24564, 'frFR', 'Qu\'est-ce qui s\'est passé à l\'intérieur du Puits du Soleil ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce qui s\'est passé à l\'intérieur du Puits du Soleil ?';
-- Quest 24564 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24564, 'frFR', 'Est-ce que je vois vraiment l\'arme de Thalorien Dawnseeker ? C\'est un jour merveilleux pour les Sunreavers et pour tous les sin\'dorei !') ON DUPLICATE KEY UPDATE RewardText='Est-ce que je vois vraiment l\'arme de Thalorien Dawnseeker ? C\'est un jour merveilleux pour les Sunreavers et pour tous les sin\'dorei !';
