INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24576, 'frFR', 'Tu l\'as trouvé, ou il s\'est enfoui sous une pierre ?') ON DUPLICATE KEY UPDATE CompletionText='Tu l\'as trouvé, ou il s\'est enfoui sous une pierre ?';
