INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24595, 'frFR', 'C\'est incroyable, <name>. Tu l\'as vraiment fait ! Tous les quel\'dorei ont entendu parler de Thalorien Dawnseeker et de Quel\'Delar, mais personne n\'a jamais pensé que l\'épée serait restaurée.') ON DUPLICATE KEY UPDATE RewardText='C\'est incroyable, <name>. Tu l\'as vraiment fait ! Tous les quel\'dorei ont entendu parler de Thalorien Dawnseeker et de Quel\'Delar, mais personne n\'a jamais pensé que l\'épée serait restaurée.';
