-- Quest 24629 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24629, 'frFR', 'Ce parfum ne va pas se vaporiser tout seul, vous savez.$B$BAllez-y !') ON DUPLICATE KEY UPDATE CompletionText='Ce parfum ne va pas se vaporiser tout seul, vous savez.$B$BAllez-y !';
-- Quest 24629 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24629, 'frFR', 'Excellent travail, <name>! Les gens vont se précipiter pour acheter les parfums Crown maintenant qu\'ils ont eu la chance de goûter leurs merveilles.$B$BVoici un petit quelque chose pour nous aider.') ON DUPLICATE KEY UPDATE RewardText='Excellent travail, <name>! Les gens vont se précipiter pour acheter les parfums Crown maintenant qu\'ils ont eu la chance de goûter leurs merveilles.$B$BVoici un petit quelque chose pour nous aider.';

-- Quest 24635 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24635, 'frFR', 'Le parfum ne va pas se donner tout seul, tu sais.$B$BCommence à vaporiser !') ON DUPLICATE KEY UPDATE CompletionText='Le parfum ne va pas se donner tout seul, tu sais.$B$BCommence à vaporiser !';
-- Quest 24635 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24635, 'frFR', 'Bon travail, <name>! Les gens vont acheter des parfums Crown par caisse maintenant qu\'ils ont eu la chance d\'en essayer.$B$BVoici un petit quelque chose pour nous aider.') ON DUPLICATE KEY UPDATE RewardText='Bon travail, <name>! Les gens vont acheter des parfums Crown par caisse maintenant qu\'ils ont eu la chance d\'en essayer.$B$BVoici un petit quelque chose pour nous aider.';
-- Quest 24636 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24636, 'frFR', 'Tu sais, ces chocolats ne vont pas se lancer sur les gens.$B$BTu dois te mettre au travail !') ON DUPLICATE KEY UPDATE CompletionText='Tu sais, ces chocolats ne vont pas se lancer sur les gens.$B$BTu dois te mettre au travail !';
-- Quest 24636 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24636, 'frFR', 'Beau travail, <name>! Les gens vont se bousculer pour avoir des chocolats Crown maintenant qu\'ils ont eu la chance de goûter ces douceurs sucrées et romantiques.$B$BVoici un petit quelque chose pour nous aider.') ON DUPLICATE KEY UPDATE RewardText='Beau travail, <name>! Les gens vont se bousculer pour avoir des chocolats Crown maintenant qu\'ils ont eu la chance de goûter ces douceurs sucrées et romantiques.$B$BVoici un petit quelque chose pour nous aider.';
-- Quest 24638 [OfferReward]
