-- Quest 24743 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24743, 'frFR', 'Écoute bien, $c$. En acceptant cette arme, ton destin est scellé.$B$BVaincs-le ou succombe.$B$BI t\'ai placé sur ce chemin. Tu es donc ma responsabilité personnelle. Si tu échoues, je suis tenu de te délivrer de cette vie.$B$BSouviens-toi de mes paroles, $r$, et ne faillis pas.') ON DUPLICATE KEY UPDATE RewardText='Écoute bien, $c$. En acceptant cette arme, ton destin est scellé.$B$BVaincs-le ou succombe.$B$BI t\'ai placé sur ce chemin. Tu es donc ma responsabilité personnelle. Si tu échoues, je suis tenu de te délivrer de cette vie.$B$BSouviens-toi de mes paroles, $r$, et ne faillis pas.';
-- Quest 24745 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24745, 'frFR', 'Tu t\'es occupé de ces vilains mal intentionnés ?') ON DUPLICATE KEY UPDATE CompletionText='Tu t\'es occupé de ces vilains mal intentionnés ?';
