INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24749, 'frFR', 'Bien fait, <class>.$B$BL\'achèvement de notre travail approche.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, <class>.$B$BL\'achèvement de notre travail approche.';
-- Quest 24756 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24756, 'frFR', 'Bien fait, <class>.$B$BShadowmourne est bientôt à portée.') ON DUPLICATE KEY UPDATE RewardText='Bien fait, <class>.$B$BShadowmourne est bientôt à portée.';

-- Quest 24757 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24757, 'frFR', 'La hache a bu sa coupe, $R$, et la forge est presque prête pour la création de Shadowmourne...') ON DUPLICATE KEY UPDATE RewardText='La hache a bu sa coupe, $R$, et la forge est presque prête pour la création de Shadowmourne...';
-- Quest 24792 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24792, 'frFR', 'Fantastique. L\'aide est exactement ce dont j\'ai besoin.') ON DUPLICATE KEY UPDATE RewardText='Fantastique. L\'aide est exactement ce dont j\'ai besoin.';
