INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24793, 'frFR', 'Fantastique. L\'aide est exactement ce dont j\'ai besoin.') ON DUPLICATE KEY UPDATE RewardText='Fantastique. L\'aide est exactement ce dont j\'ai besoin.';
-- Quest 24795 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24795, 'frFR', 'Est-ce vrai que vous avez restauré Quel\'Delar ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce vrai que vous avez restauré Quel\'Delar ?';
-- Quest 24795 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24795, 'frFR', 'Qu\'une arme d\'une telle puissance ait été rachetée des griffes du mal est un grand présage en ces temps, <name>. Avec Quel\'Delar et les alliés du Pacte d\'Argent à nos côtés, le Roi-Liche aura de bonnes raisons de craindre.$B$BLa croisade maintient un arsenal d\'armes exceptionnelles pour nos alliés les plus forts. Permettez-moi de vous offrir votre choix parmi elles en échange de la confiance que vous nous accordez pour le soin de Quel\'Delar.') ON DUPLICATE KEY UPDATE RewardText='Qu\'une arme d\'une telle puissance ait été rachetée des griffes du mal est un grand présage en ces temps, <name>. Avec Quel\'Delar et les alliés du Pacte d\'Argent à nos côtés, le Roi-Liche aura de bonnes raisons de craindre.$B$BLa croisade maintient un arsenal d\'armes exceptionnelles pour nos alliés les plus forts. Permettez-moi de vous offrir votre choix parmi elles en échange de la confiance que vous nous accordez pour le soin de Quel\'Delar.';
-- Quest 24796 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24796, 'frFR', 'Est-ce vrai que vous avez restauré Quel\'Delar ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce vrai que vous avez restauré Quel\'Delar ?';
-- Quest 24796 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24796, 'frFR', 'Ceci n\'est rien de moins qu\'un accomplissement incroyable, <name>. Le jour où Thalorien et Anasterian sont tombés, le jour où Quel\'Delar a été perdu, fut l\'un des plus sombres de ma vie. Voir Quel\'Delar restauré... c\'est au-delà des mots.$B$BSans aucun doute, vous êtes destiné à être le véritable porteur de la lame. La magie de Quel\'Delar adapte déjà la lame à vos compétences et à vos forces.') ON DUPLICATE KEY UPDATE RewardText='Ceci n\'est rien de moins qu\'un accomplissement incroyable, <name>. Le jour où Thalorien et Anasterian sont tombés, le jour où Quel\'Delar a été perdu, fut l\'un des plus sombres de ma vie. Voir Quel\'Delar restauré... c\'est au-delà des mots.$B$BSans aucun doute, vous êtes destiné à être le véritable porteur de la lame. La magie de Quel\'Delar adapte déjà la lame à vos compétences et à vos forces.';
-- Quest 24798 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24798, 'frFR', 'Est-ce vrai que vous avez restauré Quel\'Delar ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce vrai que vous avez restauré Quel\'Delar ?';

-- Quest 24798 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24798, 'frFR', 'Qu\'une arme d\'une telle puissance ait été délivrée des griffes du mal est un grand présage en ces temps, <name>. Avec Quel\'Delar et des alliés Sunreaver loyaux à nos côtés, le Roi-Liche aura de bonnes raisons de craindre.$B$BLa croisade maintient un arsenal d\'armes exceptionnelles pour nos alliés les plus forts. Permettez-moi de vous offrir votre choix parmi elles en échange de la confiance que vous nous accordez pour la garde de Quel\'Delar.') ON DUPLICATE KEY UPDATE RewardText='Qu\'une arme d\'une telle puissance ait été délivrée des griffes du mal est un grand présage en ces temps, <name>. Avec Quel\'Delar et des alliés Sunreaver loyaux à nos côtés, le Roi-Liche aura de bonnes raisons de craindre.$B$BLa croisade maintient un arsenal d\'armes exceptionnelles pour nos alliés les plus forts. Permettez-moi de vous offrir votre choix parmi elles en échange de la confiance que vous nous accordez pour la garde de Quel\'Delar.';
-- Quest 24799 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24799, 'frFR', 'Est-ce vrai que vous avez restauré Quel\'Delar ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce vrai que vous avez restauré Quel\'Delar ?';
-- Quest 24799 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24799, 'frFR', 'Qu\'une arme d\'une telle puissance ait été délivrée des griffes du mal est un grand présage en ces temps, <name>. Avec Quel\'Delar et des alliés Sunreaver loyaux à nos côtés, le Roi-Liche aura de bonnes raisons de craindre.$B$BLa croisade maintient un arsenal d\'armes exceptionnelles pour nos alliés les plus forts. Permettez-moi de vous offrir votre choix parmi elles en échange de la confiance que vous nous accordez pour la garde de Quel\'Delar.') ON DUPLICATE KEY UPDATE RewardText='Qu\'une arme d\'une telle puissance ait été délivrée des griffes du mal est un grand présage en ces temps, <name>. Avec Quel\'Delar et des alliés Sunreaver loyaux à nos côtés, le Roi-Liche aura de bonnes raisons de craindre.$B$BLa croisade maintient un arsenal d\'armes exceptionnelles pour nos alliés les plus forts. Permettez-moi de vous offrir votre choix parmi elles en échange de la confiance que vous nous accordez pour la garde de Quel\'Delar.';
-- Quest 24800 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24800, 'frFR', 'Est-ce vrai que vous avez restauré Quel\'Delar ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce vrai que vous avez restauré Quel\'Delar ?';
-- Quest 24800 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24800, 'frFR', 'Quel\'Delar ressuscite, tout comme nous, les sin\'dorei, nous sommes ressuscités des cendres de la défaite et de la trahison. Le cœur et l\'arme de Thalorien Dawnseeker sont avec vous, $Gname>.$B<br :>Je vois que la lame commence déjà à s\'adapter à vos forces, <name. Tenez votre tête haute et gardez toujours Quel\'Delar à vos côtés.') ON DUPLICATE KEY UPDATE RewardText='Quel\'Delar ressuscite, tout comme nous, les sin\'dorei, nous sommes ressuscités des cendres de la défaite et de la trahison. Le cœur et l\'arme de Thalorien Dawnseeker sont avec vous, $Gname>.$B<br :>Je vois que la lame commence déjà à s\'adapter à vos forces, <name. Tenez votre tête haute et gardez toujours Quel\'Delar à vos côtés.';
-- Quest 24801 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24801, 'frFR', 'Est-ce vrai que vous avez restauré Quel\'Delar ?') ON DUPLICATE KEY UPDATE CompletionText='Est-ce vrai que vous avez restauré Quel\'Delar ?';
-- Quest 24801 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24801, 'frFR', 'Quel\'Delar ressuscite, tout comme les sin\'dorei sont ressuscités des cendres de la défaite et de la trahison. Pourtant, d\'une manière ou d\'une autre, l\'arme de Thalorien Dawnseeker a choisi de servir un étranger.$B$BSoyez tranquille, <name>. Je ne cherche pas à diminuer votre accomplissement, car vous avez fait ce que aucun de mes frères n\'a pu faire, même si je ne sais pas pourquoi. Vous êtes clairement destiné à en être le porteur ; la lame s\'adapte déjà à vos capacités. Menez Quel\'Delar avec fierté contre nos ennemis communs.') ON DUPLICATE KEY UPDATE RewardText='Quel\'Delar ressuscite, tout comme les sin\'dorei sont ressuscités des cendres de la défaite et de la trahison. Pourtant, d\'une manière ou d\'une autre, l\'arme de Thalorien Dawnseeker a choisi de servir un étranger.$B$BSoyez tranquille, <name>. Je ne cherche pas à diminuer votre accomplissement, car vous avez fait ce que aucun de mes frères n\'a pu faire, même si je ne sais pas pourquoi. Vous êtes clairement destiné à en être le porteur ; la lame s\'adapte déjà à vos capacités. Menez Quel\'Delar avec fierté contre nos ennemis communs.';
-- Quest 24803 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24803, 'frFR', 'Les Kalu\'ak ont une longue tradition d\'affinement de nos compétences en pêche en les mettant à l\'épreuve chaque semaine.$B$BLa première personne à attraper et à m\'apporter un requin à pointe noire sera récompensée généreusement, et sera connue comme le plus grand pêcheur du nord... au moins pour quelques jours.$B$BLe plat préféré du requin à pointe noire est le poisson-sucker nain. Essayez de pêcher le requin à pointe noire là où vous pêcheriez normalement le poisson-sucker.') ON DUPLICATE KEY UPDATE CompletionText='Les Kalu\'ak ont une longue tradition d\'affinement de nos compétences en pêche en les mettant à l\'épreuve chaque semaine.$B$BLa première personne à attraper et à m\'apporter un requin à pointe noire sera récompensée généreusement, et sera connue comme le plus grand pêcheur du nord... au moins pour quelques jours.$B$BLe plat préféré du requin à pointe noire est le poisson-sucker nain. Essayez de pêcher le requin à pointe noire là où vous pêcheriez normalement le poisson-sucker.';

-- Quest 24803 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24803, 'frFR', 'Ne reste pas là ! Donne-moi le requin et je te déclare le vainqueur !') ON DUPLICATE KEY UPDATE RewardText='Ne reste pas là ! Donne-moi le requin et je te déclare le vainqueur !';
-- Quest 24805 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24805, 'frFR', 'Salut. Tu as du temps de libre ? J\'aurais besoin de quelqu\'un comme toi.') ON DUPLICATE KEY UPDATE RewardText='Salut. Tu as du temps de libre ? J\'aurais besoin de quelqu\'un comme toi.';
-- Quest 24806 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24806, 'frFR', 'J\'ai peur qu\'on ait déjà un gagnant pour aujourd\'hui, jeune $N. Cependant, si tu apportes un requin, je m\'assurerai qu\'il soit relâché dans les eaux, et je pourrais te réserver une petite surprise...') ON DUPLICATE KEY UPDATE CompletionText='J\'ai peur qu\'on ait déjà un gagnant pour aujourd\'hui, jeune $N. Cependant, si tu apportes un requin, je m\'assurerai qu\'il soit relâché dans les eaux, et je pourrais te réserver une petite surprise...';
-- Quest 24806 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24806, 'frFR', 'J\'ai peur qu\'on ait déjà un gagnant pour aujourd\'hui, jeune $N. Cependant, si tu apportes un requin, je m\'assurerai qu\'il soit relâché dans les eaux, et je pourrais te réserver une petite surprise...') ON DUPLICATE KEY UPDATE RewardText='J\'ai peur qu\'on ait déjà un gagnant pour aujourd\'hui, jeune $N. Cependant, si tu apportes un requin, je m\'assurerai qu\'il soit relâché dans les eaux, et je pourrais te réserver une petite surprise...';
-- Quest 24815 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24815, 'frFR', 'Pour expier les péchés que j\'ai commis en tant que Chevalier de la Mort du Roi-Liche, je me suis consacré à créer des bagues de grand pouvoir pour que nos frères et sœurs puissent les utiliser dans la lutte.$B$BTu t\'es prouvé être un allié précieux dans la lutte contre la Horde, $N. Alors que ton dévouement continue, je peux améliorer le design original de la bague.$B$BChoisis ton chemin avec soin. Un changement de cœur aura un prix.') ON DUPLICATE KEY UPDATE RewardText='Pour expier les péchés que j\'ai commis en tant que Chevalier de la Mort du Roi-Liche, je me suis consacré à créer des bagues de grand pouvoir pour que nos frères et sœurs puissent les utiliser dans la lutte.$B$BTu t\'es prouvé être un allié précieux dans la lutte contre la Horde, $N. Alors que ton dévouement continue, je peux améliorer le design original de la bague.$B$BChoisis ton chemin avec soin. Un changement de cœur aura un prix.';
-- Quest 24819 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24819, 'frFR', 'Tu cherches à changer le chemin que tu empruntes, $N ?') ON DUPLICATE KEY UPDATE CompletionText='Tu cherches à changer le chemin que tu empruntes, $N ?';
