-- Quest 24829 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24829, 'frFR', 'Tu es un vrai champion de notre cause, <name>.  Personne ne peut se vanter d\'être plus dévoué à la lutte que toi.$B$BL\'ennemi ne parle de ton nom qu\'en chuchotant, car il sait que tu es une force à prendre au sérieux.$B$Accepte ce humble cadeau comme une récompense pour tes nombreux triomphes.') ON DUPLICATE KEY UPDATE RewardText='Tu es un vrai champion de notre cause, <name>.  Personne ne peut se vanter d\'être plus dévoué à la lutte que toi.$B$BL\'ennemi ne parle de ton nom qu\'en chuchotant, car il sait que tu es une force à prendre au sérieux.$B$Accepte ce humble cadeau comme une récompense pour tes nombreux triomphes.';
