-- Quest 24857 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24857, 'frFR', 'Tu as un air inquiet, $N$. Quelle nouvelle apportes-tu ?') ON DUPLICATE KEY UPDATE CompletionText='Tu as un air inquiet, $N$. Quelle nouvelle apportes-tu ?';
-- Quest 24857 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24857, 'frFR', 'C\'est assez alarmant en effet ! Mais avec cette information, nous pouvons faire appel à nos frères du Village de Bloodhoof pour aider à déjouer l\'attaque. Tu as sauvé la vie de nombreux taurens, $N$.') ON DUPLICATE KEY UPDATE RewardText='C\'est assez alarmant en effet ! Mais avec cette information, nous pouvons faire appel à nos frères du Village de Bloodhoof pour aider à déjouer l\'attaque. Tu as sauvé la vie de nombreux taurens, $N$.';
-- Quest 24869 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24869, 'frFR', 'Merci, $N$!$B$BI te dois une dette de gratitude d\'avoir sauvé un ami que je croyais perdu à jamais aux griffes du Culte. Et la Crusade Argent te doit une dette pour les renseignements inestimables que Darnavan apporte avec lui de son temps à parcourir les couloirs de cette Citadelle en tant que membre du Culte.$B$BPrends ceci comme un signe de cette appréciation, et que la Lumière te soutienne alors que tu traces un chemin à travers cet endroit terrible.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N$!$B$BI te dois une dette de gratitude d\'avoir sauvé un ami que je croyais perdu à jamais aux griffes du Culte. Et la Crusade Argent te doit une dette pour les renseignements inestimables que Darnavan apporte avec lui de son temps à parcourir les couloirs de cette Citadelle en tant que membre du Culte.$B$BPrends ceci comme un signe de cette appréciation, et que la Lumière te soutienne alors que tu traces un chemin à travers cet endroit terrible.';
-- Quest 24870 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24870, 'frFR', 'Le géant est mort ? Pour la Horde !$B$BLa voie vers l\'avant et vers le haut est dégagée. Prends une partie de ces butins de bataille comme signe de notre gratitude, et nous boirons ensemble en célébration une fois que le Trône Gelé aura été réduit en poussière !') ON DUPLICATE KEY UPDATE RewardText='Le géant est mort ? Pour la Horde !$B$BLa voie vers l\'avant et vers le haut est dégagée. Prends une partie de ces butins de bataille comme signe de notre gratitude, et nous boirons ensemble en célébration une fois que le Trône Gelé aura été réduit en poussière !';
-- Quest 24871 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24871, 'frFR', 'Le géant est mort ? Louez la Lumière !$B$BLa voie vers l\'avant et vers le haut est dégagée. Prends une partie de ces butins de bataille comme signe de notre gratitude, et nous boirons ensemble en célébration une fois que le Trône Gelé aura été réduit en poussière !') ON DUPLICATE KEY UPDATE RewardText='Le géant est mort ? Louez la Lumière !$B$BLa voie vers l\'avant et vers le haut est dégagée. Prends une partie de ces butins de bataille comme signe de notre gratitude, et nous boirons ensemble en célébration une fois que le Trône Gelé aura été réduit en poussière !';
-- Quest 24872 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24872, 'frFR', 'Qu\'as-tu là dans tes mains, mortel ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'as-tu là dans tes mains, mortel ?';
-- Quest 24872 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24872, 'frFR', '<Kalecgos soupire>$B$BTant de souffrance, tant de destruction inutile. Ce ne sont pas des temps cléments pour mes frères et sœurs. Mais grâce à tes efforts, braves aventuriers, cette âme assombrie mais toujours noble peut trouver la paix enfin.$B$BReste maintenant, Sindragosa. Tu es chez toi....') ON DUPLICATE KEY UPDATE RewardText='<Kalecgos soupire>$B$BTant de souffrance, tant de destruction inutile. Ce ne sont pas des temps cléments pour mes frères et sœurs. Mais grâce à tes efforts, braves aventuriers, cette âme assombrie mais toujours noble peut trouver la paix enfin.$B$BReste maintenant, Sindragosa. Tu es chez toi....';
-- Quest 24873 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24873, 'frFR', 'Finalement, nous avons des spécimens vivants à étudier ! Tu as aidé à sauver d\'innombrables vies ce jour-là, $N.$B$BPrends ceci comme un signe de remerciement pour cet acte grandiose.') ON DUPLICATE KEY UPDATE RewardText='Finalement, nous avons des spécimens vivants à étudier ! Tu as aidé à sauver d\'innombrables vies ce jour-là, $N.$B$BPrends ceci comme un signe de remerciement pour cet acte grandiose.';

-- Quest 24874 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24874, 'frFR', 'Ouf, je pensais que j\'allais y passer ! J\'ai entendu parler d\'un rituel de résurrection dans ces Salles et je suis entré pour jeter un œil de plus près, mais l\'un de ces maudits vampires m\'a repéré. Ils m\'ont pendu ici, drainant mon énergie vitale et espérant que je craquerais et révélerais nos plans d\'attaque. Comme si je savais ce que Tirion a prévu !$b$bPrenez ces butins de guerre comme un petit signe de gratitude pour avoir sauvé ma vie.') ON DUPLICATE KEY UPDATE RewardText='Ouf, je pensais que j\'allais y passer ! J\'ai entendu parler d\'un rituel de résurrection dans ces Salles et je suis entré pour jeter un œil de plus près, mais l\'un de ces maudits vampires m\'a repéré. Ils m\'ont pendu ici, drainant mon énergie vitale et espérant que je craquerais et révélerais nos plans d\'attaque. Comme si je savais ce que Tirion a prévu !$b$bPrenez ces butins de guerre comme un petit signe de gratitude pour avoir sauvé ma vie.';
-- Quest 24875 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24875, 'frFR', 'Merci, $N!$B$BI vous dois une dette de gratitude pour avoir sauvé un ami que je croyais perdu à jamais aux griffes de la Culte. Et la Crusade Argent vous doit une dette pour l\'intelligence inestimable que Darnavan apporte avec lui de son temps à parcourir les salles de cette Citadelle en tant que membre de la Culte.$B$BPrenez ceci comme un signe de cette appréciation, et que la Lumière vous soutienne alors que vous tracez un chemin à travers cet endroit terrible.') ON DUPLICATE KEY UPDATE RewardText='Merci, $N!$B$BI vous dois une dette de gratitude pour avoir sauvé un ami que je croyais perdu à jamais aux griffes de la Culte. Et la Crusade Argent vous doit une dette pour l\'intelligence inestimable que Darnavan apporte avec lui de son temps à parcourir les salles de cette Citadelle en tant que membre de la Culte.$B$BPrenez ceci comme un signe de cette appréciation, et que la Lumière vous soutienne alors que vous tracez un chemin à travers cet endroit terrible.';
-- Quest 24876 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24876, 'frFR', 'Le géant est mort ? Louez la Lumière !$B$BLa voie vers l\'avant et vers le haut est dégagée. Prenez une partie de ces butins de bataille comme un signe de notre gratitude, et nous boirons ensemble en célébration une fois que le Trône Gelé aura été réduit en poussière !') ON DUPLICATE KEY UPDATE RewardText='Le géant est mort ? Louez la Lumière !$B$BLa voie vers l\'avant et vers le haut est dégagée. Prenez une partie de ces butins de bataille comme un signe de notre gratitude, et nous boirons ensemble en célébration une fois que le Trône Gelé aura été réduit en poussière !';
-- Quest 24877 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24877, 'frFR', 'Le géant est mort ? Pour la Horde !$B$BLa voie vers l\'avant et vers le haut est dégagée. Prenez une partie de ces butins de bataille comme un signe de notre gratitude, et nous boirons ensemble en célébration une fois que le Trône Gelé aura été réduit en poussière !') ON DUPLICATE KEY UPDATE RewardText='Le géant est mort ? Pour la Horde !$B$BLa voie vers l\'avant et vers le haut est dégagée. Prenez une partie de ces butins de bataille comme un signe de notre gratitude, et nous boirons ensemble en célébration une fois que le Trône Gelé aura été réduit en poussière !';
-- Quest 24878 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24878, 'frFR', 'Finalement, nous avons des spécimens vivants à étudier ! Vous avez aidé à sauver d\'innombrables vies aujourd\'hui, $N.$B$BPrenez ceci comme un signe de remerciement pour ce grand acte.') ON DUPLICATE KEY UPDATE RewardText='Finalement, nous avons des spécimens vivants à étudier ! Vous avez aidé à sauver d\'innombrables vies aujourd\'hui, $N.$B$BPrenez ceci comme un signe de remerciement pour ce grand acte.';
-- Quest 24879 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24879, 'frFR', 'Ouf, je pensais que j\'allais y passer ! J\'ai entendu parler d\'un rituel de résurrection dans ces Salles et je suis entré pour jeter un œil de plus près, mais l\'un de ces maudits vampires m\'a repéré. Ils m\'ont pendu ici, drainant mon énergie vitale et espérant que je craquerais et révélerais nos plans d\'attaque. Comme si je savais ce que Tirion a prévu !$b$bPrenez ces butins de guerre comme un petit signe de gratitude pour avoir sauvé ma vie.') ON DUPLICATE KEY UPDATE RewardText='Ouf, je pensais que j\'allais y passer ! J\'ai entendu parler d\'un rituel de résurrection dans ces Salles et je suis entré pour jeter un œil de plus près, mais l\'un de ces maudits vampires m\'a repéré. Ils m\'ont pendu ici, drainant mon énergie vitale et espérant que je craquerais et révélerais nos plans d\'attaque. Comme si je savais ce que Tirion a prévu !$b$bPrenez ces butins de guerre comme un petit signe de gratitude pour avoir sauvé ma vie.';
-- Quest 24880 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24880, 'frFR', 'Qu\'avez-vous là dans vos mains, mortel ?') ON DUPLICATE KEY UPDATE CompletionText='Qu\'avez-vous là dans vos mains, mortel ?';
-- Quest 24880 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24880, 'frFR', '<Kalecgos soupire>$B$BTant de souffrance, tant de destruction inutile. Ce ne sont pas des temps cléments pour mes frères et sœurs. Mais grâce à vos efforts, braves aventuriers, cette âme assombrie mais toujours noble peut trouver la paix enfin.$B$Reste en paix, Sindragosa. Tu es chez toi....') ON DUPLICATE KEY UPDATE RewardText='<Kalecgos soupire>$B$BTant de souffrance, tant de destruction inutile. Ce ne sont pas des temps cléments pour mes frères et sœurs. Mais grâce à vos efforts, braves aventuriers, cette âme assombrie mais toujours noble peut trouver la paix enfin.$B$Reste en paix, Sindragosa. Tu es chez toi....';

-- Quest 24912 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24912, 'frFR', 'Éloigne-toi, <class>, et tiens-toi droit.') ON DUPLICATE KEY UPDATE RewardText='Éloigne-toi, <class>, et tiens-toi droit.';
-- Quest 24915 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (24915, 'frFR', 'Qu\'est-ce que tu tiens, $c?$B$BÇa m\'appelle, suscitant des sentiments que je croyais depuis longtemps morts.') ON DUPLICATE KEY UPDATE CompletionText='Qu\'est-ce que tu tiens, $c?$B$BÇa m\'appelle, suscitant des sentiments que je croyais depuis longtemps morts.';
-- Quest 24915 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24915, 'frFR', 'Impossible...$B$BPère, est-ce toi?!$B$BTu m\'as rendu un grand service, héros. Je t\'offre les rênes de mon fidèle destrier. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.') ON DUPLICATE KEY UPDATE RewardText='Impossible...$B$BPère, est-ce toi?!$B$BTu m\'as rendu un grand service, héros. Je t\'offre les rênes de mon fidèle destrier. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.';
-- Quest 24916 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24916, 'frFR', 'Qu\'est-ce... comment as-tu réussi à obtenir ça!?$B$BTu m\'as rendu un grand service, héros. Mon cœur ne pouvait supporter de garder ce médaillon, mais je vais y placer un enchantement qui pourrait t\'être utile. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.') ON DUPLICATE KEY UPDATE RewardText='Qu\'est-ce... comment as-tu réussi à obtenir ça!?$B$BTu m\'as rendu un grand service, héros. Mon cœur ne pouvait supporter de garder ce médaillon, mais je vais y placer un enchantement qui pourrait t\'être utile. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.';
-- Quest 24917 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24917, 'frFR', 'Oui. Je connais cette lame... et je la chérirai toujours - un moment de temps qui sera perdu à jamais.$B$BTu m\'as rendu un grand service, héros. Je t\'offre un cadeau des nains des Froid. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.') ON DUPLICATE KEY UPDATE RewardText='Oui. Je connais cette lame... et je la chérirai toujours - un moment de temps qui sera perdu à jamais.$B$BTu m\'as rendu un grand service, héros. Je t\'offre un cadeau des nains des Froid. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.';
-- Quest 24918 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24918, 'frFR', '<Sylvanas réfléchit silencieusement un instant avant de te regarder à nouveau.>$B$BTu m\'as rendu un grand service, héros. Je t\'offre le don de la Reine Banshee. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.') ON DUPLICATE KEY UPDATE RewardText='<Sylvanas réfléchit silencieusement un instant avant de te regarder à nouveau.>$B$BTu m\'as rendu un grand service, héros. Je t\'offre le don de la Reine Banshee. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.';
-- Quest 24919 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (24919, 'frFR', '<Uther fixe la médaille, sans voix un instant.>$B$BLa médaille d\'Arthas.$B$BJe me souviens bien du jour où je la lui ai présentée...$B$BTu m\'as rendu un grand service, héros. Mon âme peut maintenant reposer en paix. Je t\'offre un souvenir perdu dans le temps. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.') ON DUPLICATE KEY UPDATE RewardText='<Uther fixe la médaille, sans voix un instant.>$B$BLa médaille d\'Arthas.$B$BJe me souviens bien du jour où je la lui ai présentée...$B$BTu m\'as rendu un grand service, héros. Mon âme peut maintenant reposer en paix. Je t\'offre un souvenir perdu dans le temps. Fais-en comme tu veux, mais n\'oublie pas ceux qui t\'ont aidé dans cet exploit monumental.';
-- Quest 25055 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25055, 'frFR', 'As-tu soumis les éléments ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu soumis les éléments ?';

-- Quest 25092 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25092, 'frFR', 'As-tu soumis les éléments ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu soumis les éléments ?';
-- Quest 25092 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25092, 'frFR', 'Bien joué $N$. Mais pour chaque élément soumis, un autre prend sa place. La solution que nous avons ici n\'est qu\'un pansement. J\'espère que mes frères de l\'Anneau de Terre font plus de progrès.') ON DUPLICATE KEY UPDATE RewardText='Bien joué $N$. Mais pour chaque élément soumis, un autre prend sa place. La solution que nous avons ici n\'est qu\'un pansement. J\'espère que mes frères de l\'Anneau de Terre font plus de progrès.';
-- Quest 25180 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25180, 'frFR', 'As-tu rencontré le coursier ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu rencontré le coursier ?';
