INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25181, 'frFR', 'As-tu rencontré le coursier ?') ON DUPLICATE KEY UPDATE CompletionText='As-tu rencontré le coursier ?';
-- Quest 25199 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25199, 'frFR', 'Tu es arrivé en entier ? Tu as plus d\'engrenages que je ne le pensais, $N !') ON DUPLICATE KEY UPDATE RewardText='Tu es arrivé en entier ? Tu as plus d\'engrenages que je ne le pensais, $N !';
-- Quest 25212 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25212, 'frFR', 'Travail fantastique !$B$BLes données que j\'ai reçues montrent que les niveaux de radiation sont entièrement dans la plage de sécurité de nos combinaisons. C\'est une excellente nouvelle !') ON DUPLICATE KEY UPDATE RewardText='Travail fantastique !$B$BLes données que j\'ai reçues montrent que les niveaux de radiation sont entièrement dans la plage de sécurité de nos combinaisons. C\'est une excellente nouvelle !';
-- Quest 25228 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25228, 'frFR', 'Eh bien, as-tu trouvé quelque chose ?') ON DUPLICATE KEY UPDATE CompletionText='Eh bien, as-tu trouvé quelque chose ?';
-- Quest 25229 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25229, 'frFR', 'C\'est le meilleur groupe de pilotes potentiels que tu pouvais trouver?$B$BOk, eh bien, je vais voir ce que je peux faire. Je suis connu pour transformer même la plus grosse pile d\'engrenages noueux en une machine de combat bien huilée et je ne m\'attends à rien de moins avec ce lot.$B$BEh bien, je suppose qu\'il est temps de travailler !') ON DUPLICATE KEY UPDATE RewardText='C\'est le meilleur groupe de pilotes potentiels que tu pouvais trouver?$B$BOk, eh bien, je vais voir ce que je peux faire. Je suis connu pour transformer même la plus grosse pile d\'engrenages noueux en une machine de combat bien huilée et je ne m\'attends à rien de moins avec ce lot.$B$BEh bien, je suppose qu\'il est temps de travailler !';

