-- Quest 25283 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25283, 'frFR', 'Dis-moi lequel fonctionne, d\'accord?') ON DUPLICATE KEY UPDATE CompletionText='Dis-moi lequel fonctionne, d\'accord?';
-- Quest 25283 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25283, 'frFR', 'Oh là là. Leurs réactions étaient si différentes?$b$bPas tout à fait ce à quoi je m\'attendais, mais je crois que j\'ai un discours qui fera l\'affaire.$b$bLaisse-moi juste trouver où je l\'ai mis...') ON DUPLICATE KEY UPDATE RewardText='Oh là là. Leurs réactions étaient si différentes?$b$bPas tout à fait ce à quoi je m\'attendais, mais je crois que j\'ai un discours qui fera l\'affaire.$b$bLaisse-moi juste trouver où je l\'ai mis...';
-- Quest 25285 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25285, 'frFR', 'Hé, regarde ça! Tu n\'as pas été réduit en miettes!') ON DUPLICATE KEY UPDATE RewardText='Hé, regarde ça! Tu n\'as pas été réduit en miettes!';
-- Quest 25286 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25286, 'frFR', 'Toby a fini le discours? Laisse-moi voir...$b<Lit le discours> Pompage de pistons! Quel discours fantastique! Je savais que Toby était un bon écrivain, mais celui-ci est peut-être le meilleur qu\'il ait jamais écrit.$bJe pense qu\'il est temps de te mettre au combat.') ON DUPLICATE KEY UPDATE RewardText='Toby a fini le discours? Laisse-moi voir...$b<Lit le discours> Pompage de pistons! Quel discours fantastique! Je savais que Toby était un bon écrivain, mais celui-ci est peut-être le meilleur qu\'il ait jamais écrit.$bJe pense qu\'il est temps de te mettre au combat.';
-- Quest 25287 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25287, 'frFR', 'C\'est la version finale, alors? Laisse-moi jeter un œil...') ON DUPLICATE KEY UPDATE RewardText='C\'est la version finale, alors? Laisse-moi jeter un œil...';

-- Quest 25289 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25289, 'frFR', 'Hmm... donc le servo de la jambe gauche activait-il la jambe droite ? Mais j\'ai vu la jambe gauche bouger...$B$BEh, détails. J\'y reviendrai plus tard, mais deux des trois éléments ont fonctionné : Ce n\'est pas si mal !$B$BMerci de m\'avoir aidé avec ça, $N.') ON DUPLICATE KEY UPDATE RewardText='Hmm... donc le servo de la jambe gauche activait-il la jambe droite ? Mais j\'ai vu la jambe gauche bouger...$B$BEh, détails. J\'y reviendrai plus tard, mais deux des trois éléments ont fonctionné : Ce n\'est pas si mal !$B$BMerci de m\'avoir aidé avec ça, $N.';
-- Quest 25295 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25295, 'frFR', 'Hmm... donc les balles avaient pas mal de dispersion?$B$BPour certains, cela peut être un problème... moi, cependant, je vois ça comme une bénédiction déguisée !$B$BNos ennemis vont courir partout, donc avec un peu de dispersion, les conducteurs de chars n\'auront pas besoin de viser en avance !') ON DUPLICATE KEY UPDATE RewardText='Hmm... donc les balles avaient pas mal de dispersion?$B$BPour certains, cela peut être un problème... moi, cependant, je vois ça comme une bénédiction déguisée !$B$BNos ennemis vont courir partout, donc avec un peu de dispersion, les conducteurs de chars n\'auront pas besoin de viser en avance !';
-- Quest 25347 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25347, 'frFR', 'Vous êtes revenu enfin. Je commençais à penser que vous vous étiez définitivement associé aux cultistes.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu enfin. Je commençais à penser que vous vous étiez définitivement associé aux cultistes.';
-- Quest 25393 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25393, 'frFR', 'Maudits ! Nous avons dû reculer. Mais Thermaplugg a perdu, et il le sait... il ne s\'est fait que gagner du temps. Nous tenons la surface, et quand le rayonnement se dissipera, nous assiégerons et récupérerons Gnomeregan avec une force deux fois plus grande.') ON DUPLICATE KEY UPDATE RewardText='Maudits ! Nous avons dû reculer. Mais Thermaplugg a perdu, et il le sait... il ne s\'est fait que gagner du temps. Nous tenons la surface, et quand le rayonnement se dissipera, nous assiégerons et récupérerons Gnomeregan avec une force deux fois plus grande.';
-- Quest 25417 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25417, 'frFR', 'Vous êtes revenu enfin. Je commençais à penser que vous vous étiez définitivement associé aux cultistes.') ON DUPLICATE KEY UPDATE CompletionText='Vous êtes revenu enfin. Je commençais à penser que vous vous étiez définitivement associé aux cultistes.';
-- Quest 25444 [RequestItems]
INSERT INTO quest_request_items_locale (ID, locale, CompletionText) VALUES (25444, 'frFR', 'Tu aides avec les grenouilles ou pas ?') ON DUPLICATE KEY UPDATE CompletionText='Tu aides avec les grenouilles ou pas ?';
-- Quest 25445 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25445, 'frFR', '$N, tu serais un guerrier formidable et un camarade féroce pour les trolls Darkspear. Les Îles d\'Écho sont NOUS maintenant et nous n\'y serions pas arrivés sans toi.$B$BPrends cette cape. Porte-la avec fierté. Tu serais un membre de la tribu maintenant !$B$BEn un temps, les trolls auront une maison à nouveau et nous te remercions pour ça.') ON DUPLICATE KEY UPDATE RewardText='$N, tu serais un guerrier formidable et un camarade féroce pour les trolls Darkspear. Les Îles d\'Écho sont NOUS maintenant et nous n\'y serions pas arrivés sans toi.$B$BPrends cette cape. Porte-la avec fierté. Tu serais un membre de la tribu maintenant !$B$BEn un temps, les trolls auront une maison à nouveau et nous te remercions pour ça.';
-- Quest 25446 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25446, 'frFR', 'Je commence déjà à voir ce que les grenouilles voient. Tu as fait ça parfaitement, $N. Maintenant, Vol\'jin et moi verrons ce que Zalazane prévoit.') ON DUPLICATE KEY UPDATE RewardText='Je commence déjà à voir ce que les grenouilles voient. Tu as fait ça parfaitement, $N. Maintenant, Vol\'jin et moi verrons ce que Zalazane prévoit.';

-- Quest 25461 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25461, 'frFR', 'J\'ai trouvé de bons. Je les entraîne dur et nous ne nous arrêterons pas tant que nous n\'aurons pas chassé Zalazane de nos îles.') ON DUPLICATE KEY UPDATE RewardText='J\'ai trouvé de bons. Je les entraîne dur et nous ne nous arrêterons pas tant que nous n\'aurons pas chassé Zalazane de nos îles.';
-- Quest 25470 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25470, 'frFR', 'Les grenouilles de Vanira disent la vérité, n\'est-ce pas ? Ce tigre est un druide et un allié ? Nous ne pourrions espérer un meilleur résultat. C\'est un bon présage pour la bataille à venir.') ON DUPLICATE KEY UPDATE RewardText='Les grenouilles de Vanira disent la vérité, n\'est-ce pas ? Ce tigre est un druide et un allié ? Nous ne pourrions espérer un meilleur résultat. C\'est un bon présage pour la bataille à venir.';
-- Quest 25495 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25495, 'frFR', 'Enfin, tout est prêt. Maintenant, nous montrons à Zalazane ce qui arrive à ceux qui défient les Darkspears !') ON DUPLICATE KEY UPDATE RewardText='Enfin, tout est prêt. Maintenant, nous montrons à Zalazane ce qui arrive à ceux qui défient les Darkspears !';
-- Quest 25500 [OfferReward]
INSERT INTO quest_offer_reward_locale (ID, locale, RewardText) VALUES (25500, 'frFR', 'C\'est le discours de Toby ? Fantastique !$bRecrue, tu as fait tout ce que nous pouvions demander et l\'Armée Gnomeregan te remercie !$bNous envoyons une équipe d\'assaut à Gnomeregan maintenant et cela n\'aurait pas été possible sans ton aide. Pour toute ton aide, nous aimerions que tu rejoignes les Réserves Gnomeregan !$bÇa ne paie pas très bien, mais tu as ce casque élégant. Garde-le, tu pourrais en avoir besoin un jour !') ON DUPLICATE KEY UPDATE RewardText='C\'est le discours de Toby ? Fantastique !$bRecrue, tu as fait tout ce que nous pouvions demander et l\'Armée Gnomeregan te remercie !$bNous envoyons une équipe d\'assaut à Gnomeregan maintenant et cela n\'aurait pas été possible sans ton aide. Pour toute ton aide, nous aimerions que tu rejoignes les Réserves Gnomeregan !$bÇa ne paie pas très bien, mais tu as ce casque élégant. Garde-le, tu pourrais en avoir besoin un jour !';

